INSERT INTO games (rank, id, title, consoleName, consoleId, totalPlayers, casualPlayers, hardcorePlayers, numAchievements, points, genre, developer, publisher, released, description, icon, boxArt, titleScreen, screenshot, rating) VALUES
  (1, 6049, 'Super Mario Sunshine', 'GameCube', 16, 11371, 11371, 11371, 148, 0, '3D Platforming, Collect-a-thon', NULL, 'Nintendo', '2002-07-19', 'Super Mario Sunshine is a 2002 platform game developed and published by Nintendo for the GameCube. It is the second 3D game in the Super Mario series, following Super Mario 64 (1996). The game was directed by Yoshiaki Koizumi and Kenta Usui, produced by series creators Shigeru Miyamoto and Takashi Tezuka, written by Makoto Wada, and scored by Koji Kondo and Shinobu Tanaka.', 'https://media.retroachievements.org/Images/081263.png', 'https://media.retroachievements.org/Images/047388.png', 'https://media.retroachievements.org/Images/081264.png', 'https://media.retroachievements.org/Images/082249.png', 5),
  (2, 7693, 'Mario Kart: Double Dash!!', 'GameCube', 16, 8903, 8903, 8903, 65, 0, 'Kart Racing', 'Nintendo', 'Nintendo', '2003-11-07', 'Mario Kart: Double Dash!! is a 2003 kart racing video game developed and published by Nintendo for the GameCube. It is the fourth main entry in the Mario Kart series. Similar to previous titles, Double Dash challenges Mario series player characters to race against each other on 16 Mario-themed tracks. The game introduced a number of gameplay features, such as having two riders per kart.', 'https://media.retroachievements.org/Images/091536.png', 'https://media.retroachievements.org/Images/090181.png', 'https://media.retroachievements.org/Images/090182.png', 'https://media.retroachievements.org/Images/090183.png', 5),
  (3, 9190, 'The Legend of Zelda: The Wind Waker', 'GameCube', 16, 5216, 5216, 5216, 126, 0, 'Action-Adventure', NULL, 'Nintendo', '2002-12-13', 'The Legend of Zelda: The Wind Waker is an action-adventure game developed and published by Nintendo for the GameCube. An installment in The Legend of Zelda series, it was released in Japan on December 13, 2002, in North America on March 24, 2003, and in Europe on May 2, 2003.', 'https://media.retroachievements.org/Images/099022.png', 'https://media.retroachievements.org/Images/050398.png', 'https://media.retroachievements.org/Images/099572.png', 'https://media.retroachievements.org/Images/099571.png', 4.9),
  (4, 4325, 'Luigi''s Mansion', 'GameCube', 16, 4560, 4560, 4560, 49, 0, 'Action-Adventure, Horror', 'Nintendo', 'Nintendo', '2001-09-14', 'Luigi''s Mansion is a 2001 action-adventure game developed and published by Nintendo. The game was a launch title for the GameCube and was the first game in the Mario franchise to be released for the console; it was released in Japan on September 14, 2001, in North America on November 18, 2001, in Europe on May 3, 2002, and in Australia on May 17, 2002. It is the third video game in which Luigi is the main character instead of Mario, after Mario Is Missing! and Luigi''s Hammer Toss. Players control him as he explores a haunted mansion to rescue Mario and battles ghosts by capturing them through a vacuum cleaner supplied by Professor E. Gadd.', 'https://media.retroachievements.org/Images/113364.png', 'https://media.retroachievements.org/Images/099093.png', 'https://media.retroachievements.org/Images/089021.png', 'https://media.retroachievements.org/Images/089022.png', 4.9),
  (5, 2901, 'Animal Crossing', 'GameCube', 16, 4480, 4480, 4480, 117, 0, 'Life Simulation', 'Nintendo', 'Nintendo', '2001-12-14', 'Animal Crossing is a social simulation video game series developed and published by Nintendo. It was created by Katsuya Eguchi and Hisashi Nogami. The player character is a human who lives in a village inhabited by various anthropomorphic animals and can engage in various activities such as fishing, insect catching, and fossil hunting. The series is known for its open-ended gameplay, humorous dialogue, hourly music, and use of the console''s internal clock and calendar to simulate real passage of time.', 'https://media.retroachievements.org/Images/089222.png', 'https://media.retroachievements.org/Images/094803.png', 'https://media.retroachievements.org/Images/094801.png', 'https://media.retroachievements.org/Images/094802.png', 4.9),
  (6, 4000, 'Paper Mario: The Thousand-Year Door', 'GameCube', 16, 3948, 3948, 3948, 123, 0, 'Turn-Based RPG', 'Intelligent Systems', 'Nintendo', '2004-10-11', 'Paper Mario: The Thousand-Year Door is a 2004 role-playing video game developed by Intelligent Systems and published by Nintendo for the GameCube. The Thousand-Year Door is the second game in the Paper Mario series following Paper Mario, and is part of the larger Mario franchise. In the game, when Mario and Princess Peach get involved in the search for a mystic treasure that holds great fortune, Peach is kidnapped by an alien group called the X-Nauts; Mario sets out to find the treasure and save the princess.', 'https://media.retroachievements.org/Images/114344.png', 'https://media.retroachievements.org/Images/095801.png', 'https://media.retroachievements.org/Images/095791.png', 'https://media.retroachievements.org/Images/095792.png', 4.8),
  (7, 6151, 'Kirby Air Ride', 'GameCube', 16, 3908, 3908, 3908, 203, 0, 'Kart Racing', 'HAL Laboratory', 'Nintendo', '2003-07-11', 'Kirby Air Ride is a 2003 racing video game developed by HAL Laboratory and published by Nintendo for the GameCube. A spin-off of the Kirby series, the player controls Kirby or his multicolored counterparts as they compete in races. The game supports up to four players, and was the first GameCube title to support LAN play using broadband adapters and up to four GameCube systems.', 'https://media.retroachievements.org/Images/117530.png', 'https://media.retroachievements.org/Images/070618.png', 'https://media.retroachievements.org/Images/034732.png', 'https://media.retroachievements.org/Images/034731.png', 4.8),
  (8, 3154, 'Metroid Prime', 'GameCube', 16, 3528, 3528, 3528, 62, 0, 'Metroidvania, 3D Platforming, First-Person Shooter', 'Retro Studios', 'Nintendo', '2002-11-18', 'Metroid Prime is a 2002 action-adventure game developed by Retro Studios and published by Nintendo for the GameCube. It is the fifth main installment in the Metroid franchise. It was the first Metroid game to use 3D computer graphics and a first-person perspective. It was released in North America in November 2002 and in Japan and Europe the following year. Along with the Game Boy Advance game Metroid Fusion, Prime marked the return of the Metroid series after an eight-year hiatus following Super Metroid (1994).', 'https://media.retroachievements.org/Images/117057.png', 'https://media.retroachievements.org/Images/070320.png', 'https://media.retroachievements.org/Images/089093.png', 'https://media.retroachievements.org/Images/089096.png', 4.8),
  (9, 7423, 'Pokémon Colosseum', 'GameCube', 16, 3489, 3489, 3489, 84, 0, NULL, 'Genius Sonority', NULL, '2003-11-21', 'Pokémon Colosseum is a role-playing video game developed by Genius Sonority and published by The Pokémon Company and Nintendo for the GameCube. A spin-off of the Pokémon series, it was released on November 21, 2003, in Japan, March 22, 2004, in North America and May 14, 2004, in Europe. Unlike previous titles'' random encounters with Pokémon, Colosseum allows the player to steal (snag) the Pokémon of other Pokémon Trainers. The game also features single-player and multiplayer battle modes.', 'https://media.retroachievements.org/Images/068145.png', 'https://media.retroachievements.org/Images/072735.png', 'https://media.retroachievements.org/Images/081381.png', 'https://media.retroachievements.org/Images/081382.png', 4.8),
  (10, 15540, 'Pikmin', 'GameCube', 16, 3272, 3272, 3272, 44, 0, 'Real-Time Strategy', 'Nintendo', 'Nintendo', '2001-10-26', 'Pikmin is a real-time strategy and puzzle video game series created by Shigeru Miyamoto, and developed and published by Nintendo. The games focus on directing a horde of plant-like creatures called Pikmin to collect items by destroying obstacles, avoiding hazards, and fighting fauna that are hazardous to both the player character and the Pikmin.', 'https://media.retroachievements.org/Images/097988.png', 'https://media.retroachievements.org/Images/065141.png', 'https://media.retroachievements.org/Images/065140.png', 'https://media.retroachievements.org/Images/065142.png', 4.8),
  (11, 2199, 'The Simpsons: Hit & Run', 'GameCube', 16, 2698, 2698, 2698, 80, 0, '3D Platforming, Sandbox', 'Radical Entertainment', 'Vivendi Universal Games', '2003-09-16', 'The Simpsons: Hit & Run is a 2003 action-adventure game developed by Radical Entertainment and published by Vivendi Universal Games. It is based on the American animated sitcom The Simpsons, and is the twenty-second installment in The Simpsons series of video games.', 'https://media.retroachievements.org/Images/086944.png', 'https://media.retroachievements.org/Images/086943.png', 'https://media.retroachievements.org/Images/086941.png', 'https://media.retroachievements.org/Images/086942.png', 4.8),
  (12, 28930, '~Hack~ Super Mario Eclipse', 'GameCube', 16, 2602, 2602, 2602, 122, 0, '3D Platforming, Collect-a-thon', 'Eclipse Team', 'Hack - Super Mario Sunshine', '2024-08-26', 'The GameCube is Nintendo''s fourth home video game console, released during the sixth generation of video games. It is the successor to the Nintendo 64, and was first launched in Japan on September 14, 2001, followed by a launch in North America on November 18, 2001, and a launch in the PAL regions in May 2002. The successor to the GameCube is the Wii, which was first released in North America on November 19, 2006, and is backward compatible with GameCube games, memory cards, and controllers. Although later models would remove the controller ports and memory card slots required for backwards compatibility, they can be hardware modded back in. There are 651 games on this list. It is organized alphabetically by the games'' localized English titles, or by rōmaji transliterations when exclusive to Japan. For a list of games that were announced or in development for the GameCube but never released, see the list of cancelled GameCube games.', 'https://media.retroachievements.org/Images/124575.png', 'https://media.retroachievements.org/Images/101458.png', 'https://media.retroachievements.org/Images/101363.png', 'https://media.retroachievements.org/Images/101364.png', 4.8),
  (13, 6605, 'WarioWare, Inc.: Mega Party Game$!', 'GameCube', 16, 2503, 2503, 2503, 43, 0, 'Minigames', 'Intelligent Systems, Nintendo', 'Nintendo', '2003-10-17', 'WarioWare, Inc.: Mega Party Game$! is a 2003 party video game developed by Nintendo R&D1 and Intelligent Systems and published by Nintendo for the GameCube. It is a remake of WarioWare, Inc.: Mega Microgames!, and the second installment in the WarioWare series, the game translates the microgame gameplay of Mega Microgames! to be playable in a multiplayer environment. It comes with eight special multiplayer modes for up to four players that all involve the known microgames in some way.', 'https://media.retroachievements.org/Images/075446.png', 'https://media.retroachievements.org/Images/069828.png', 'https://media.retroachievements.org/Images/081266.png', 'https://media.retroachievements.org/Images/081267.png', 4.8),
  (14, 9699, 'F-Zero GX', 'GameCube', 16, 2387, 2387, 2387, 147, 0, 'Arcade Racing', 'Amusement Vision', 'Nintendo', '2003-08-26', 'F-Zero GX is a 2003 racing game developed by Amusement Vision, a division of Sega, and published by Nintendo for the GameCube. It was released in Japan on July 25, 2003, North America on August 25, Australia on October 24, and Europe on October 31. Sega also released an arcade version, F-Zero AX, which uses the Triforce arcade system board.', 'https://media.retroachievements.org/Images/081531.png', 'https://media.retroachievements.org/Images/094796.png', 'https://media.retroachievements.org/Images/081166.png', 'https://media.retroachievements.org/Images/081167.png', 4.8),
  (15, 2259, 'Wario World', 'GameCube', 16, 2281, 2281, 2281, 88, 0, NULL, NULL, 'Nintendo', '2003-06-20', 'Wario World is a 2003 platform game developed by Treasure and published by Nintendo for the GameCube. The player controls Wario as he attempts to regain his treasure and castle from the evil sentient gem, Black Jewel. The gameplay sees Wario progressing through a series of 3D linear levels in a bid to find collectibles and defeat enemies in order to progress.', 'https://media.retroachievements.org/Images/115275.png', 'https://media.retroachievements.org/Images/069420.png', 'https://media.retroachievements.org/Images/089254.png', 'https://media.retroachievements.org/Images/089253.png', 4.8),
  (16, 3779, 'Sonic Adventure 2: Battle', 'GameCube', 16, 2234, 2234, 2234, 340, 0, NULL, 'Sonic Team', 'Sega', '2001-12-20', 'Sonic Adventure 2 is a 2001 platform game developed by Sonic Team USA and published by Sega for the Dreamcast. It features two good-vs-evil stories: Sonic the Hedgehog, Miles Tails Prower, and Knuckles the Echidna attempt to save the world, while Shadow the Hedgehog, Doctor Eggman, and Rouge the Bat attempt to conquer it. The stories are divided into three gameplay styles: fast-paced platforming for Sonic and Shadow, third-person shooting for Tails and Eggman, and exploration-based treasure hunting for Knuckles and Rouge. Like previous Sonic the Hedgehog games, the player completes levels while collecting rings and defeating enemies. Outside the main gameplay, they can interact with Chao, a virtual pet, and compete in multiplayer battles.', 'https://media.retroachievements.org/Images/115618.png', 'https://media.retroachievements.org/Images/089080.png', 'https://media.retroachievements.org/Images/100413.png', 'https://media.retroachievements.org/Images/100414.png', 4.8),
  (17, 2356, 'Resident Evil 4', 'GameCube', 16, 2042, 2042, 2042, 151, 0, 'Survival Horror, Third-Person Shooter', 'Capcom', 'Capcom', '2005-01-11', 'Resident Evil 4 is a 2005 survival horror game developed and published by Capcom for the GameCube. It is the fourth main installment in the Resident Evil series. Players control the special agent Leon S. Kennedy on a mission to rescue the president of the United States''s daughter, Ashley Graham, who has been abducted by a religious cult in rural Spain. Leon fights hordes of enemies infected by a mind-controlling parasite and reunites with the female spy and mercenary Ada Wong. In a departure from the fixed camera angles and slower gameplay of previous Resident Evil games, Resident Evil 4 features a dynamic camera system and action-oriented gameplay.', 'https://media.retroachievements.org/Images/089552.png', 'https://media.retroachievements.org/Images/089623.png', 'https://media.retroachievements.org/Images/082806.png', 'https://media.retroachievements.org/Images/082807.png', 4.7),
  (18, 25431, 'Chibi-Robo!', 'GameCube', 16, 2004, 2004, 2004, 90, 0, '3D Platforming, Adventure', 'Skip', 'Nintendo', '2005-06-23', 'Chibi-Robo!  is a series of adventure video games developed by Skip Ltd. and published by Nintendo. The franchise follows a series of tiny robotic units known as Chibi-Robo, whose purpose is to spread Happiness. Recurring game elements of the franchise include monitoring Chibi-Robo''s battery usage at all times, and cleaning Chibi-Robo''s nearby environment through a variety of methods in order to collect Happy Points, the game''s collectible representation of the happiness the players instill in others. While the primary purpose of a Chibi-Robo is to assist humans, they have also been shown to assist animals, sentient alien life, and even living toys.', 'https://media.retroachievements.org/Images/100108.png', 'https://media.retroachievements.org/Images/081367.png', 'https://media.retroachievements.org/Images/090063.png', 'https://media.retroachievements.org/Images/090064.png', 4.7),
  (19, 3535, 'Metal Gear Solid: The Twin Snakes', 'GameCube', 16, 1988, 1988, 1988, 123, 0, 'Action-Adventure, Stealth', 'Silicon Knights', 'Konami', '2004-03-09', 'Metal Gear Solid: The Twin Snakes is a 2004 action-adventure stealth game developed by Konami and Silicon Knights and published by Konami for the GameCube. It is a remake of 1998''s Metal Gear Solid.', 'https://media.retroachievements.org/Images/088924.png', 'https://media.retroachievements.org/Images/088933.png', 'https://media.retroachievements.org/Images/088936.png', 'https://media.retroachievements.org/Images/088937.png', 4.7),
  (20, 11202, 'The Legend of Zelda: Ocarina of Time - Master Quest', 'GameCube', 16, 1879, 1879, 1879, 128, 0, 'Action-Adventure', NULL, 'Nintendo', '2002-02-28', 'The Legend of Zelda is a video game series created by Japanese game designers Shigeru Miyamoto and Takashi Tezuka. It is primarily developed and published by Nintendo, but some installments and re-releases have been outsourced to Flagship, Grezzo, and Tantalus Media.', 'https://media.retroachievements.org/Images/048069.png', 'https://media.retroachievements.org/Images/110748.png', 'https://media.retroachievements.org/Images/043177.png', 'https://media.retroachievements.org/Images/043178.png', 4.7),
  (21, 6253, 'Super Monkey Ball 2', 'GameCube', 16, 1854, 1854, 1854, 158, 0, NULL, 'Amusement Vision', 'Sega', '2002-08-26', 'Super Monkey Ball 2 is a 2002 platform video game developed by Amusement Vision and published by Sega for the GameCube. It is the second installment in the Super Monkey Ball series, and the first installment to have a storyline and to be exclusively released on a home console.', 'https://media.retroachievements.org/Images/089484.png', 'https://media.retroachievements.org/Images/089487.png', 'https://media.retroachievements.org/Images/089473.png', 'https://media.retroachievements.org/Images/089486.png', 4.7),
  (22, 3536, 'Soulcalibur II', 'GameCube', 16, 1846, 1846, 1846, 125, 0, '3D Fighting', 'Namco, Project Soul', 'Namco', '2003-08-27', 'Soulcalibur II is a 2002 fighting game developed and published by Namco. It is the third installment in the Soulcalibur series of weapon-based fighting games as the sequel to Soulcalibur (1998). Originally intended to be released on Sega''s NAOMI arcade board, the game was built on the Namco System 246 board before being ported to the PlayStation 2, GameCube, and Xbox home consoles.', 'https://media.retroachievements.org/Images/090977.png', 'https://media.retroachievements.org/Images/094806.png', 'https://media.retroachievements.org/Images/084105.png', 'https://media.retroachievements.org/Images/084106.png', 4.7),
  (23, 2708, 'Mario Golf: Toadstool Tour', 'GameCube', 16, 1768, 1768, 1768, 73, 0, NULL, NULL, NULL, '2003-07-29', 'Mario Golf: Toadstool Tour, is a 2003 sports video game developed by Camelot Software Planning and published by Nintendo for the GameCube. It is the sequel to the 1999 Nintendo 64 title Mario Golf, and is the third game in the Mario Golf series. It was released in North America on July 28, 2003, in Japan on September 5, 2003, and in PAL regions in 2004.', 'https://media.retroachievements.org/Images/089937.png', 'https://media.retroachievements.org/Images/088868.png', 'https://media.retroachievements.org/Images/088866.png', 'https://media.retroachievements.org/Images/088867.png', 4.7),
  (24, 8231, 'Fire Emblem: Path of Radiance', 'GameCube', 16, 1751, 1751, 1751, 72, 0, 'Tactical RPG', 'Intelligent Systems', 'Nintendo', '2005-10-17', 'Fire Emblem: Path of Radiance is a 2005 tactical role-playing game developed by Intelligent Systems and Nintendo SPD, and published by Nintendo for the GameCube. It is the ninth main installment in the Fire Emblem series, and the third to be released in the west. As with previous installments, gameplay revolves around positioning characters on a battlefield to defeat an opposing force. If characters are defeated in battle, they are removed from the rest of the game.', 'https://media.retroachievements.org/Images/100081.png', 'https://media.retroachievements.org/Images/036334.png', 'https://media.retroachievements.org/Images/036332.png', 'https://media.retroachievements.org/Images/036333.png', 4.7),
  (25, 25450, 'Mario Party 4', 'GameCube', 16, 1637, 1637, 1637, 58, 0, 'Board Game, Party', 'Hudson Soft', 'Nintendo', '2002-10-21', 'Mario Party 4 is a 2002 party video game developed by Hudson Soft and published by Nintendo for the GameCube. It is the fourth installment in the Mario Party series and the first one to be released for GameCube. Like the previous games in the series, it features eight playable characters from the Mario franchise—Mario, Luigi, Princess Peach, Yoshi, Wario, Donkey Kong, Princess Daisy, and Waluigi—competing in a board game, with the objective of each of the six game boards being to earn the most Stars. Besides the standard multiplayer mode, the game also features a single-player campaign in which the player plays the game with artificial intelligence-controlled players.', 'https://media.retroachievements.org/Images/081241.png', 'https://media.retroachievements.org/Images/081240.png', 'https://media.retroachievements.org/Images/081238.png', 'https://media.retroachievements.org/Images/081239.png', 4.7),
  (26, 25476, 'Super Mario Strikers', 'GameCube', 16, 1628, 1628, 1628, 40, 0, NULL, 'Next Level Games', NULL, '2005-11-18', 'Super Mario Strikers, is a 2005 sports video game developed by Next Level Games and published by Nintendo for the GameCube. The game was released in Europe on November 18, 2005, North America on December 5, 2005, Japan on January 19, 2006, and Australia on April 6, 2006. The game''s developers had worked on NHL Hitz Pro before development of Strikers, which served as an influence for the fast-paced and physical nature of the game. This was also the last Mario game to be released on the GameCube in Japan and North America.', 'https://media.retroachievements.org/Images/089007.png', 'https://media.retroachievements.org/Images/088997.png', 'https://media.retroachievements.org/Images/088995.png', 'https://media.retroachievements.org/Images/088996.png', 4.7),
  (27, 25453, 'Mario Superstar Baseball', 'GameCube', 16, 1560, 1560, 1560, 120, 0, NULL, NULL, NULL, '2005-07-21', 'Mario Superstar Baseball is a 2005 sports video game developed by Namco and published by Nintendo for the GameCube. The game was created in the vein of other Mario sports games such as Mario Golf: Toadstool Tour and Mario Power Tennis. A sequel, Mario Super Sluggers, was released for the Wii in 2008.', 'https://media.retroachievements.org/Images/094778.png', 'https://media.retroachievements.org/Images/094793.png', 'https://media.retroachievements.org/Images/089144.png', 'https://media.retroachievements.org/Images/089146.png', 4.7),
  (28, 3792, 'Mario Power Tennis', 'GameCube', 16, 1526, 1526, 1526, 235, 0, NULL, NULL, NULL, '2004-10-28', 'Mario Power Tennis is a 2004 sports video game developed by Camelot Software Planning and published by Nintendo for the GameCube. It is the sequel to the Nintendo 64 title Mario Tennis, and is the third installment of the Mario Tennis series. The game was ported for the Wii in 2009 as part of the New Play Control! series, and was also re-released as a Nintendo Selects title in 2012. A companion handheld game, Mario Tennis: Power Tour, was also released on Game Boy Advance around the same time as the original GameCube release, bearing the same title as Power Tennis in Europe.', 'https://media.retroachievements.org/Images/094985.png', 'https://media.retroachievements.org/Images/115471.png', 'https://media.retroachievements.org/Images/088386.png', 'https://media.retroachievements.org/Images/089185.png', 4.7),
  (29, 8329, 'Star Fox Adventures', 'GameCube', 16, 1495, 1495, 1495, 53, 0, NULL, NULL, NULL, '2002-09-23', 'Star Fox Adventures is a 2002 action-adventure game developed by Rare and published by Nintendo for the GameCube. The game''s story is set eight years after the events of Star Fox 64 (1997), with players taking control of Fox McCloud, who is sent on a mission to visit a planet in the Lylat System and prevent its destruction. Gameplay is divided between Adventure Mode, in which players explore environments while defeating enemies, solving puzzles, and collecting items, and Arwing Mode, which features rail shooter segments.', 'https://media.retroachievements.org/Images/100460.png', 'https://media.retroachievements.org/Images/088942.png', 'https://media.retroachievements.org/Images/088945.png', 'https://media.retroachievements.org/Images/088947.png', 4.7),
  (30, 9510, 'Super Monkey Ball', 'GameCube', 16, 1475, 1475, 1475, 77, 0, '3D Platforming', 'Amusement Vision', 'Sega', '2001-09-14', 'Super Monkey Ball is a series of platform video games initially developed by Amusement Vision and published by Sega. The series debuted in 2001 with the arcade game Monkey Ball, which was ported to GameCube as Super Monkey Ball later that year. Several sequels and ports have been released.', 'https://media.retroachievements.org/Images/068475.png', 'https://media.retroachievements.org/Images/094805.png', 'https://media.retroachievements.org/Images/089474.png', 'https://media.retroachievements.org/Images/089475.png', 4.7),
  (31, 3176, 'Resident Evil 2', 'GameCube', 16, 1396, 1396, 1396, 172, 0, 'Survival Horror', 'Capcom, TOSE', 'Capcom', '2003-01-14', 'Resident Evil 2 is a 1998 survival horror video game developed and published by Capcom for the PlayStation. It is the second main installment in the Resident Evil series. The player controls rookie cop Leon S. Kennedy and college student Claire Redfield, who must escape Raccoon City after its citizens are transformed into zombies by a biological weapon two months after the events of the original Resident Evil. The gameplay focuses on exploration, puzzles, and combat; the main difference from its predecessor are the branching paths, with each player character having unique storylines, partners and obstacles.', 'https://media.retroachievements.org/Images/103945.png', 'https://media.retroachievements.org/Images/050794.png', 'https://media.retroachievements.org/Images/082815.png', 'https://media.retroachievements.org/Images/082814.png', 4.7),
  (32, 14817, 'Pikmin 2', 'GameCube', 16, 1380, 1380, 1380, 113, 0, 'Real-Time Strategy', 'Nintendo', 'Nintendo', '2004-04-29', 'Pikmin 2 is a 2004 real-time strategy puzzle video game developed and published by Nintendo for the GameCube. It is the direct sequel to the 2001 game Pikmin and the second game in the Pikmin series. In the game, Captain Olimar returns to the Pikmin planet to collect valuable treasure after learning that the company he works for—Hocotate Freight—is on the verge of bankruptcy.', 'https://media.retroachievements.org/Images/110402.png', 'https://media.retroachievements.org/Images/099615.png', 'https://media.retroachievements.org/Images/067945.png', 'https://media.retroachievements.org/Images/068403.png', 4.7),
  (33, 25472, 'Star Fox: Assault', 'GameCube', 16, 1320, 1320, 1320, 58, 0, NULL, 'Namco', 'Nintendo', '2005-02-14', 'Star Fox: Assault is a 2005 third-person shooter game developed by Namco and published by Nintendo for the GameCube. It is the fourth released title in the Star Fox series. The game was released on 15 February 2005 in North America, on 24 February 2005 in Japan, on 29 April 2005 in Europe, and on 16 June 2005 in Australia.', 'https://media.retroachievements.org/Images/089933.png', 'https://media.retroachievements.org/Images/089911.png', 'https://media.retroachievements.org/Images/089935.png', 'https://media.retroachievements.org/Images/089936.png', 4.7),
  (34, 3353, 'LEGO Star Wars: The Video Game', 'GameCube', 16, 1298, 1298, 1298, 44, 0, 'Action-Adventure', 'Traveller''s Tales', 'Eidos Interactive, LucasArts | Lucasfilm', '2005-10-25', 'Lego Star Wars: The Video Game is a 2005 action-adventure video game based on the line of Lego construction toys of the same name, and the first installment in the Lego video game franchise developed by Traveller''s Tales, which would develop many future Lego titles from that point on. It was first released on 29 March 2005. It is a Lego video game adaptation of the prequel trilogy of George Lucas’ movie franchise of the same name: The Phantom Menace, Attack of the Clones and Revenge of the Sith, with a bonus level from A New Hope.', 'https://media.retroachievements.org/Images/087587.png', 'https://media.retroachievements.org/Images/082913.png', 'https://media.retroachievements.org/Images/082914.png', 'https://media.retroachievements.org/Images/082915.png', 4.7),
  (35, 3780, 'Pokémon XD: Gale of Darkness', 'GameCube', 16, 1269, 1269, 1269, 151, 0, 'Turn-Based RPG', 'Genius Sonority', 'Nintendo, The Pokémon Company', '2005-08-04', 'Pokémon XD: Gale of Darkness is a role-playing video game in the Pokémon series developed by Genius Sonority and published by The Pokémon Company and Nintendo. It was released for the GameCube on August 4, 2005, in Japan; October 3, 2005, in North America; November 10, 2005, in Australia; and November 18, 2005, in Europe. Pokémon XD is the successor to the GameCube title Pokémon Colosseum and takes place in Orre, the setting of Pokémon Colosseum''s adventure mode. All of the Game Boy Advance Pokémon games can connect to this game through trading and Battle Mode.', 'https://media.retroachievements.org/Images/068144.png', 'https://media.retroachievements.org/Images/072736.png', 'https://media.retroachievements.org/Images/081292.png', 'https://media.retroachievements.org/Images/081293.png', 4.7),
  (36, 25435, 'Dance Dance Revolution: Mario Mix', 'GameCube', 16, 1265, 1265, 1265, 77, 0, 'Rhythm', 'Konami', 'Nintendo', '2005-07-14', 'Dance Dance Revolution: Mario Mix, known in Europe and Australia as Dancing Stage Mario Mix, is a 2005 music video game co-developed by Konami and Hudson Soft and published by Nintendo for the GameCube. It is the first Dance Dance Revolution game to be released on a Nintendo video game console outside Japan. The game was released in Japan on July 14, 2005, North America on October 24, 2005, Europe on October 28, 2005, and Australia on November 24, 2005.', 'https://media.retroachievements.org/Images/094790.png', 'https://media.retroachievements.org/Images/094791.png', 'https://media.retroachievements.org/Images/088977.png', 'https://media.retroachievements.org/Images/098632.png', 4.7),
  (37, 15690, 'SpongeBob SquarePants: Battle for Bikini Bottom', 'GameCube', 16, 1226, 1226, 1226, 61, 0, '3D Platforming, Collect-a-thon', 'Heavy Iron Studios', 'THQ', '2003-10-31', 'SpongeBob SquarePants: Battle for Bikini Bottom is a 2003 platform game based on the Nickelodeon animated series SpongeBob SquarePants, developed by Heavy Iron Studios and published by THQ for the GameCube, PlayStation 2 and Xbox. Separate versions, developed by Vicarious Visions and AWE Games respectively, were released for the Game Boy Advance and Windows. While the versions released for consoles were 3D platform games, the Windows version of the game is a mini-game compilation, and the Game Boy Advance version is a 2D platformer.', 'https://media.retroachievements.org/Images/096388.png', 'https://media.retroachievements.org/Images/084111.png', 'https://media.retroachievements.org/Images/084112.png', 'https://media.retroachievements.org/Images/084113.png', 4.7),
  (38, 3781, 'Pokémon Channel', 'GameCube', 16, 1186, 1186, 1186, 31, 0, 'Pet Simulation, Point-and-Click Adventure', 'Ambrella', 'Nintendo', '2003-07-18', 'Pokémon Channel, released in Japan as Pokémon Channel ~Together with Pikachu!~, is a 2003 video game in the Pokémon series developed by Ambrella and published by The Pokémon Company and Nintendo for the GameCube. The player''s goal is to help Professor Oak refine and promote his TV network through watching broadcasts with the mouse-like Pikachu. The game contains elements of the adventure, digital pet, and simulation genres. The player can explore full 3D environments, have Pikachu converse with other Pokémon, and collect various items.', 'https://media.retroachievements.org/Images/120663.png', 'https://media.retroachievements.org/Images/072734.png', 'https://media.retroachievements.org/Images/090012.png', 'https://media.retroachievements.org/Images/090014.png', 4.7),
  (39, 28381, 'Mario Party 6', 'GameCube', 16, 1112, 1112, 1112, 139, 0, 'Board Game, Party', 'Hudson Soft', 'Nintendo', '2004-11-18', 'Mario Party 6 is a 2004 party video game developed by Hudson Soft and published by Nintendo for the GameCube. It is the sixth installment in the Mario Party series, the third title in the series for the GameCube, and the first GameCube game to make use of a microphone add-on. The game was released in Japan on November 18, 2004, in North America on December 6, 2004, in Europe on March 18, 2005, and in Australia on September 15, 2005.', 'https://media.retroachievements.org/Images/112221.png', 'https://media.retroachievements.org/Images/091269.png', 'https://media.retroachievements.org/Images/091271.png', 'https://media.retroachievements.org/Images/091270.png', 4.7),
  (40, 3783, 'Viewtiful Joe', 'GameCube', 16, 1020, 1020, 1020, 65, 0, 'Beat ''em Up', 'Capcom Production Studio 4', 'Capcom', '2003-06-26', 'Viewtiful Joe  is a side scrolling beat ''em up video game franchise created by Japanese game designer Hideki Kamiya. It is primarily developed and published by Capcom and its subsidiary Clover Studio.', 'https://media.retroachievements.org/Images/090639.png', 'https://media.retroachievements.org/Images/081175.png', 'https://media.retroachievements.org/Images/089285.png', 'https://media.retroachievements.org/Images/089286.png', 4.6),
  (41, 3358, 'Resident Evil', 'GameCube', 16, 1006, 1006, 1006, 114, 0, 'Survival Horror', 'Capcom', 'Capcom', '2002-03-22', 'Resident Evil, known as Biohazard  in Japan, is a Japanese horror game series and media franchise created by Capcom. It consists of survival horror, third-person shooter and first-person games, with players typically surviving in environments inhabited by zombies and other mutated creatures. The franchise has expanded into media including a live-action film series, animated films, television series, comic books, novels, audiobooks, and merchandise. Resident Evil is among the highest-grossing horror franchises of all time, and is Capcom''s best-selling franchise, with over 170 million copies sold worldwide as of March 2025. Individual installments of the series have been critically acclaimed and have received several awards, and many characters from the series such as Leon S. Kennedy and Albert Wesker have been described as video game icons.', 'https://media.retroachievements.org/Images/081178.png', 'https://media.retroachievements.org/Images/050867.png', 'https://media.retroachievements.org/Images/081181.png', 'https://media.retroachievements.org/Images/089249.png', 4.6),
  (42, 2198, 'The Legend of Zelda: Collector''s Edition', 'GameCube', 16, 943, 943, 943, 391, 0, 'Action-Adventure, Compilation', 'Nintendo', 'Nintendo', '2003-11-07', 'The Legend of Zelda: The Wind Waker is an action-adventure game developed and published by Nintendo for the GameCube. An installment in The Legend of Zelda series, it was released in Japan on December 13, 2002, in North America on March 24, 2003, and in Europe on May 2, 2003.', 'https://media.retroachievements.org/Images/103269.png', 'https://media.retroachievements.org/Images/050399.png', 'https://media.retroachievements.org/Images/103276.png', 'https://media.retroachievements.org/Images/103277.png', 4.6),
  (43, 7777, 'Killer7', 'GameCube', 16, 920, 920, 920, 77, 0, 'Action-Adventure, Rail Shooter', 'Capcom, Grasshopper Manufacture', 'Capcom', '2005-07-07', 'Killer7 is a 2005 action-adventure game developed by Grasshopper Manufacture and Capcom and published by Capcom for the GameCube and PlayStation 2. The game was written and directed by Goichi Suda and produced by Hiroyuki Kobayashi.', 'https://media.retroachievements.org/Images/093417.png', 'https://media.retroachievements.org/Images/093418.png', 'https://media.retroachievements.org/Images/093415.png', 'https://media.retroachievements.org/Images/093416.png', 4.6),
  (44, 6336, 'Magical Mirror Starring Mickey Mouse', 'GameCube', 16, 863, 863, 863, 45, 0, 'Point-and-Click Adventure', 'Capcom', 'Nintendo', '2002-08-09', 'Disney''s Magical Mirror Starring Mickey Mouse is a point-and-click adventure video game developed by Capcom and published by Nintendo under license from Disney Interactive for the GameCube. It follows the titular character Mickey Mouse as he explores a mansion within a mirror world, collecting 12 mirror shards in order to escape while a playful ghost taunts him throughout his journey.', 'https://media.retroachievements.org/Images/117529.png', 'https://media.retroachievements.org/Images/088827.png', 'https://media.retroachievements.org/Images/088826.png', 'https://media.retroachievements.org/Images/088825.png', 4.6),
  (45, 25452, 'Mario Party 7', 'GameCube', 16, 833, 833, 833, 139, 0, 'Board Game, Party', 'Hudson Soft', 'Nintendo', '2005-11-07', 'Mario Party 7 is a 2005 party video game developed by Hudson Soft and published by Nintendo for the GameCube. It is the seventh main installment in the Mario Party series, as well as the fourth and final game in the series to be released for the GameCube. The game was released in North America on November 7, 2005; in Japan on November 10, 2005; in the United Kingdom on January 27, 2006; and in Europe on February 10, 2006.', 'https://media.retroachievements.org/Images/111795.png', 'https://media.retroachievements.org/Images/081184.png', 'https://media.retroachievements.org/Images/081185.png', 'https://media.retroachievements.org/Images/081186.png', 4.6),
  (46, 7683, 'Metroid Prime 2: Echoes', 'GameCube', 16, 804, 804, 804, 68, 0, 'Metroidvania, 3D Platforming, First-Person Shooter', 'Retro Studios', 'Nintendo', '2004-11-15', 'Metroid Prime 2: Echoes is a 2004 action-adventure game developed by Retro Studios and published by Nintendo for the GameCube. The sequel to Metroid Prime (2002), Echoes is the sixth main installment in the Metroid franchise. It was released in North America, Europe and Australia in 2004. In Japan, it was released in May 2005 as Metroid Prime 2: Dark Echoes.', 'https://media.retroachievements.org/Images/119612.png', 'https://media.retroachievements.org/Images/090053.png', 'https://media.retroachievements.org/Images/090043.png', 'https://media.retroachievements.org/Images/090044.png', 4.6),
  (47, 25456, 'Naruto: Clash of Ninja', 'GameCube', 16, 804, 804, 804, 26, 0, '3D Fighting', 'Raizing | Eighting', 'Tomy', '2003-04-11', 'Naruto: Clash of Ninja, released in Japan as Naruto: Gekitō Ninja Taisen! , is a series of 3D cel-shaded fighting games based on the manga and anime series Naruto by Masashi Kishimoto. They are developed by Eighting and published by D3 Publisher and Tomy. The series began with four GameCube games, with the first two available internationally and the last two released exclusively in Japan, before splitting into two parallel Wii-exclusive follow-up series: the Gekitō Ninja Taisen EX tetralogy released exclusively in Japan and its international counterpart, the Clash of Ninja: Revolution trilogy. The two Wii series share the same gameplay mechanics, but differ with respect to content and characters, with the international Revolution series being based on a localized version of the Naruto anime series. The first half of the original series and the entire Revolution trilogy are available in North America and Europe, the first two Revolution games are available in Australasia and all games in the series except the Revolution trilogy are available in Japan.', 'https://media.retroachievements.org/Images/088925.png', 'https://media.retroachievements.org/Images/088963.png', 'https://media.retroachievements.org/Images/088961.png', 'https://media.retroachievements.org/Images/088962.png', 4.6),
  (48, 6870, 'Resident Evil 3: Nemesis', 'GameCube', 16, 794, 794, 794, 71, 0, 'Survival Horror', 'Capcom, TOSE', 'Capcom', '2003-01-15', 'Resident Evil 3: Nemesis is a 1999 survival horror video game developed and published by Capcom originally for the PlayStation. It is the third main installment in the Resident Evil series and takes place almost concurrently with the events of Resident Evil 2. The player must control former elite agent Jill Valentine as she escapes from Raccoon City, which has been overrun by zombies. The game uses the same engine as its predecessors and features 3D models over pre-rendered backgrounds with fixed camera angles. Choices through the game affect how the story unfolds and which ending is achieved.', 'https://media.retroachievements.org/Images/107816.png', 'https://media.retroachievements.org/Images/082811.png', 'https://media.retroachievements.org/Images/082813.png', 'https://media.retroachievements.org/Images/082812.png', 4.6),
  (49, 28371, '~Hack~ Shadow the Hedgehog: Reloaded', 'GameCube', 16, 785, 785, 785, 71, 0, '3D Platforming, Collect-a-thon', 'LimblessVector, dreamsyntax', 'Hack - Shadow the Hedgehog', '2024-07-01', 'Unlicensed developers and fans have created unofficial Sonic media, especially video games, relating to the Sonic the Hedgehog franchise. These products include video games, video game mods, ROM hacks, comics, and animations. They are part of the wider Sonic fandom.', 'https://media.retroachievements.org/Images/089186.png', 'https://media.retroachievements.org/Images/100472.png', 'https://media.retroachievements.org/Images/089050.png', 'https://media.retroachievements.org/Images/089053.png', 4.6),
  (50, 25486, 'Ultimate Spider-Man', 'GameCube', 16, 775, 775, 775, 40, 0, 'Action-Adventure, Sandbox', 'Treyarch', 'Activision', '2005-09-22', 'Ultimate Spider-Man is a superhero comic book series that was published by Marvel Comics from 2000 to 2011. The series is a modernized re-imagining of Marvel''s long-running Spider-Man comic book franchise as part of the company''s Ultimate Marvel imprint. Ultimate Spider-Man exists alongside other revamped Marvel characters in Ultimate Marvel titles including Ultimate X-Men, Ultimate Fantastic Four and The Ultimates in the fictional setting of Earth-1610.', 'https://media.retroachievements.org/Images/092553.png', 'https://media.retroachievements.org/Images/100060.png', 'https://media.retroachievements.org/Images/100058.png', 'https://media.retroachievements.org/Images/100059.png', 4.6),
  (51, 6343, 'The Simpsons: Road Rage', 'GameCube', 16, 765, 765, 765, 59, 0, 'Arcade Racing', 'Radical Entertainment', 'Electronic Arts', '2001-12-19', 'The Simpsons: Road Rage is a 2001 racing video game based on the animated television series The Simpsons, and is part of a series of games based on the show. It was released for PlayStation 2, Xbox and GameCube. A Game Boy Advance version was released in 2003.', 'https://media.retroachievements.org/Images/123510.png', 'https://media.retroachievements.org/Images/110615.png', 'https://media.retroachievements.org/Images/110613.png', 'https://media.retroachievements.org/Images/110614.png', 4.6),
  (52, 3337, 'LEGO Star Wars II: The Original Trilogy', 'GameCube', 16, 762, 762, 762, 76, 0, 'Action-Adventure', 'Traveller''s Tales', 'LucasArts | Lucasfilm', '2006-09-12', 'Lego Star Wars II: The Original Trilogy is a 2006 Lego-themed action-adventure game developed by Traveller''s Tales and published by LucasArts and TT Games Publishing, and is the sequel to Lego Star Wars: The Video Game (2005). Part of the Lego Star Wars series, it is based on George Lucas''s movie franchise of the same name and The Lego Group''s Lego Star Wars construction toy line. It follows the events of the first three original Star Wars films: A New Hope (1977), The Empire Strikes Back (1980), and Return of the Jedi (1983). The game allows players to assume the roles of over 50 Lego versions of characters from the film series; customized characters can also be created. Camera movement was improved from its predecessor, and the concept of vehicle levels was explored more thoroughly. The game was revealed at American International Toy Fair. Promotions for the game were set up at chain stores across the United States.', 'https://media.retroachievements.org/Images/121889.png', 'https://media.retroachievements.org/Images/062654.png', 'https://media.retroachievements.org/Images/082917.png', 'https://media.retroachievements.org/Images/082916.png', 4.6),
  (53, 28426, '1080° Avalanche', 'GameCube', 16, 747, 747, 747, 66, 0, 'Extreme Sports - Snowboarding', 'Nintendo', 'Nintendo', '2003-11-28', '1080° Avalanche is a snowboarding video game developed by Nintendo Software Technology and published by Nintendo for the GameCube. It was released on November 28, 2003, in Europe, on December 1, 2003, in North America, and on January 22, 2004, in Japan. Avalanche is a sequel to the 1998 video game 1080° Snowboarding for the Nintendo 64. In contrast to similar snowboarding games such as the SSX series, the game emphasizes more on the speed of downhill racing than stunts and tricks.', 'https://media.retroachievements.org/Images/089564.png', 'https://media.retroachievements.org/Images/089194.png', 'https://media.retroachievements.org/Images/089197.png', 'https://media.retroachievements.org/Images/089198.png', 4.6),
  (54, 25426, 'Billy Hatcher and the Giant Egg', 'GameCube', 16, 711, 711, 711, 39, 0, NULL, NULL, NULL, '2003-10-09', 'Billy Hatcher and the Giant Egg is a platform game developed by Sonic Team and published by Sega for the GameCube in 2003. A port for Microsoft Windows was released in Europe in 2006 by Mindscape. The game received mixed reviews.', 'https://media.retroachievements.org/Images/097438.png', 'https://media.retroachievements.org/Images/081363.png', 'https://media.retroachievements.org/Images/089103.png', 'https://media.retroachievements.org/Images/089104.png', 4.6),
  (55, 6354, 'Shadow the Hedgehog', 'GameCube', 16, 668, 668, 668, 112, 0, '3D Platforming', 'Sonic Team', 'Sega', '2005-11-18', 'Shadow the Hedgehog is a character created by the Japanese game developers Takashi Iizuka, Shiro Maekawa, and Kazuyuki Hoshino. He is a major character in Sega''s Sonic the Hedgehog franchise. Shadow is an anthropomorphic black hedgehog created by Professor Gerald Robotnik, the grandfather of Doctor Eggman. Shadow shares design traits and attributes with Sonic the Hedgehog. He is an antihero who has good intentions but will do whatever it takes to accomplish his goals, putting him at odds with Sonic.', 'https://media.retroachievements.org/Images/100252.png', 'https://media.retroachievements.org/Images/089131.png', 'https://media.retroachievements.org/Images/100307.png', 'https://media.retroachievements.org/Images/100306.png', 4.6),
  (56, 25457, 'Naruto: Clash of Ninja 2', 'GameCube', 16, 666, 666, 666, 77, 0, '3D Fighting', 'Raizing | Eighting', 'Tomy', '2003-12-04', 'Naruto: Clash of Ninja, released in Japan as Naruto: Gekitō Ninja Taisen! , is a series of 3D cel-shaded fighting games based on the manga and anime series Naruto by Masashi Kishimoto. They are developed by Eighting and published by D3 Publisher and Tomy. The series began with four GameCube games, with the first two available internationally and the last two released exclusively in Japan, before splitting into two parallel Wii-exclusive follow-up series: the Gekitō Ninja Taisen EX tetralogy released exclusively in Japan and its international counterpart, the Clash of Ninja: Revolution trilogy. The two Wii series share the same gameplay mechanics, but differ with respect to content and characters, with the international Revolution series being based on a localized version of the Naruto anime series. The first half of the original series and the entire Revolution trilogy are available in North America and Europe, the first two Revolution games are available in Australasia and all games in the series except the Revolution trilogy are available in Japan.', 'https://media.retroachievements.org/Images/089044.png', 'https://media.retroachievements.org/Images/089076.png', 'https://media.retroachievements.org/Images/089077.png', 'https://media.retroachievements.org/Images/089251.png', 4.6),
  (57, 6981, 'Tales of Symphonia', 'GameCube', 16, 650, 650, 650, 294, 0, 'Action RPG', 'Namco Tales Studio', 'Namco', '2004-07-13', 'Tales of Symphonia is an action role-playing video game developed by Namco Tales Studio and published by Namco for the GameCube. The fifth main installment of the Tales series, it was released in Japan on August 29, 2003, in North America on July 13, 2004, and in Europe on November 19, 2004. In Japan, the game was ported for the PlayStation 2 with additional content and was released on September 22, 2004.', 'https://media.retroachievements.org/Images/092333.png', 'https://media.retroachievements.org/Images/079725.png', 'https://media.retroachievements.org/Images/079726.png', 'https://media.retroachievements.org/Images/079727.png', 4.6),
  (58, 25473, 'Star Wars Jedi Knight II: Jedi Outcast', 'GameCube', 16, 635, 635, 635, 213, 0, 'First-Person Shooter', 'Vicarious Visions', 'LucasArts | Lucasfilm', '2002-11-20', 'Star Wars Jedi Knight II: Jedi Outcast is a 2002 first and third-person shooter video game developed by Raven Software for Windows and Mac OS. Westlake Interactive ported the game to Mac OS X, while the Xbox and GameCube versions were ported by Vicarious Visions; most versions were published by Activision and LucasArts, with only the Mac OS version published by Aspyr. The game is a sequel to 1997''s Star Wars Jedi Knight: Dark Forces II, and the third main installment in the Star Wars: Jedi Knight series. The single-player campaign, set in the fictional Star Wars expanded universe two years after the Mysteries of the Sith expansion for Dark Forces II, follows returning protagonist Kyle Katarn, a mercenary working for the New Republic and former Jedi who cut his connection to the Force. Katarn must return to his Jedi ways to stop a branch of the Imperial Remnant led by the Dark Jedi Desann from empowering their army with the Force.', 'https://media.retroachievements.org/Images/089001.png', 'https://media.retroachievements.org/Images/088993.png', 'https://media.retroachievements.org/Images/089440.png', 'https://media.retroachievements.org/Images/088998.png', 4.6),
  (59, 2731, 'Ikaruga', 'GameCube', 16, 616, 616, 616, 53, 0, 'Shoot ''em Up, Bullet Hell', 'Treasure', 'Infogrames', '2003-01-16', 'Ikaruga  is a bullet hell shoot ''em up developed by Treasure. It is the spiritual sequel to Radiant Silvergun (1998) and was originally released in Japanese arcades in December 2001. The story follows a rebel pilot named Shinra as he battles an enemy nation using a specially designed fighter called the Ikaruga which can flip between two polarities, black and white. This polarity mechanism is the game''s key feature and the foundation for its stage and enemy design. All enemies and bullets in the game are either black or white. Bullets which are the same color as the player are absorbed while the others will kill the player. The game features both single-player and cooperative modes.', 'https://media.retroachievements.org/Images/088928.png', 'https://media.retroachievements.org/Images/088871.png', 'https://media.retroachievements.org/Images/088869.png', 'https://media.retroachievements.org/Images/088870.png', 4.6),
  (60, 6928, 'Mega Man X Collection', 'GameCube', 16, 607, 607, 607, 407, 0, 'Action, 2D Platforming, Compilation, Kart Racing', 'Capcom', 'Capcom', '2006-01-10', 'Mega Man X Collection is a compilation of video games developed by Capcom. Released on January 10, 2006, exclusively in North America for GameCube and PlayStation 2, Mega Man X Collection contains the first six games in the Mega Man X series, which originated on the Super Nintendo Entertainment System and made its way primarily onto various 32-bit consoles. All six games are action platformers in which the player traverses a series of stages and gains the special weapons of defeated bosses.', 'https://media.retroachievements.org/Images/089033.png', 'https://media.retroachievements.org/Images/089032.png', 'https://media.retroachievements.org/Images/089029.png', 'https://media.retroachievements.org/Images/089031.png', 4.6),
  (61, 25488, 'Winnie the Pooh''s Rumbly Tumbly Adventure', 'GameCube', 16, 594, 594, 594, 18, 0, NULL, 'Phoenix Entertainment', NULL, '2005-02-08', 'Winnie the Pooh''s Rumbly Tumbly Adventure is a 2005 action-adventure game developed by French company Phoenix Interactive and published by Ubisoft.', 'https://media.retroachievements.org/Images/100973.png', 'https://media.retroachievements.org/Images/100969.png', 'https://media.retroachievements.org/Images/100966.png', 'https://media.retroachievements.org/Images/100967.png', 4.6),
  (62, 28368, 'Scooby-Doo! Night of 100 Frights', 'GameCube', 16, 590, 590, 590, 48, 0, '3D Platforming', 'Heavy Iron Studios', 'THQ', '2002-05-20', 'Scooby-Doo! Night of 100 Frights is a 3D platform game developed by Heavy Iron Studios and published by THQ for the PlayStation 2, GameCube, and Xbox. The game was released in May 2002 in North America and was released later that year in PAL regions. It was the first Scooby-Doo! video game on sixth-generation consoles. The PlayStation 2 version became a Greatest Hits title in May 2003. The next Scooby-Doo game to be released for consoles was Scooby-Doo! Mystery Mayhem.', 'https://media.retroachievements.org/Images/107761.png', 'https://media.retroachievements.org/Images/099660.png', 'https://media.retroachievements.org/Images/089024.png', 'https://media.retroachievements.org/Images/089023.png', 4.6),
  (63, 6850, 'Lost Kingdoms', 'GameCube', 16, 584, 584, 584, 53, 0, 'Action RPG, Card Game', 'FromSoftware', 'Activision', '2002-04-25', 'Lost Kingdoms is a 2002 action role-playing game developed by FromSoftware and published by Activision. The game was released in Japan in April, in North America in May, and in Europe in August. Lost Kingdoms is a card-based action role-playing game where battles are fought in real-time. A sequel, Lost Kingdoms II, was released in 2003.', 'https://media.retroachievements.org/Images/091288.png', 'https://media.retroachievements.org/Images/091287.png', 'https://media.retroachievements.org/Images/091285.png', 'https://media.retroachievements.org/Images/091286.png', 4.6),
  (64, 25451, 'Mario Party 5', 'GameCube', 16, 575, 575, 575, 55, 0, 'Board Game, Party', 'Hudson Soft', 'Nintendo', '2003-11-11', 'Mario Party 5 is a 2003 party video game developed by Hudson Soft and published by Nintendo for the GameCube. It is the fifth installment in the Mario Party series, and the second game in the series to be released for the GameCube. The game is set in the fictional Dream Depot, consisting of seven game boards. The single-player Story game mode involves the player winning multiple games against the Koopa Kids to prevent Bowser from conquering the Dream Depot. The main multiplayer game mode consists of four characters from the Mario series playing a board game, with each board having a set theme. The game also features several minigames, which are played after every set of turns. Mario Party 5 introduces the Super Duel mode to the franchise, which requires players to assemble and control custom made battle vehicles which can be used in combat against other machines. The game features 10 playable characters, with playable debuts to the series from Toad, Boo, and Koopa Kid.', 'https://media.retroachievements.org/Images/111752.png', 'https://media.retroachievements.org/Images/094792.png', 'https://media.retroachievements.org/Images/090633.png', 'https://media.retroachievements.org/Images/090632.png', 4.6),
  (65, 9915, 'Wave Race: Blue Storm', 'GameCube', 16, 571, 571, 571, 62, 0, 'Extreme Sports - Watercross', 'Nintendo', 'Nintendo', '2001-09-14', 'Wave Race: Blue Storm is a jetski racing video game developed and published by Nintendo for the GameCube in late 2001. It is the sequel to the 1996 Nintendo 64 game Wave Race 64, and the third in the series that started with the 1992 Game Boy game Wave Race.', 'https://media.retroachievements.org/Images/089891.png', 'https://media.retroachievements.org/Images/099545.png', 'https://media.retroachievements.org/Images/099544.png', 'https://media.retroachievements.org/Images/099543.png', 4.6),
  (66, 2466, 'Resident Evil 0', 'GameCube', 16, 570, 570, 570, 84, 0, 'Survival Horror', 'Capcom', 'Capcom', '2002-11-12', 'Resident Evil Zero is a 2002 survival horror game developed and published by Capcom for the GameCube. It is a prequel to Resident Evil (1996), following S.T.A.R.S. officer Rebecca Chambers and convict Billy Coen as they explore an abandoned training facility for employees of the pharmaceutical company Umbrella in the outskirts of Raccoon City. The gameplay is similar to other Resident Evil games, but adds the ability to switch between characters to solve puzzles and use unique abilities.', 'https://media.retroachievements.org/Images/092882.png', 'https://media.retroachievements.org/Images/050868.png', 'https://media.retroachievements.org/Images/082817.png', 'https://media.retroachievements.org/Images/082816.png', 4.6),
  (67, 30035, 'Beyblade V-Force: Super Tournament Battle', 'GameCube', 16, 520, 520, 520, 34, 0, NULL, NULL, NULL, '2002-12-19', 'Beyblade: Super Tournament Battle, also known as Beyblade V-Force: Super Tournament Battle and Bakuten Shoot Beyblade 2002: Nettou! Magne-tag Battle! in Japan is a Beyblade 2002 role-playing video game. The game was released originally on December 19, 2002 in Japan and was later released in the west in 2003. It is based on the Beyblade V-Force season.', 'https://media.retroachievements.org/Images/098681.png', 'https://media.retroachievements.org/Images/098635.png', 'https://media.retroachievements.org/Images/099095.png', 'https://media.retroachievements.org/Images/099097.png', 4.5),
  (68, 6871, 'Resident Evil CODE: Veronica X', 'GameCube', 16, 507, 507, 507, 115, 0, 'Survival Horror', 'Capcom, TOSE', 'Capcom', '2003-08-07', 'Resident Evil Zero is a 2002 survival horror game developed and published by Capcom for the GameCube. It is a prequel to Resident Evil (1996), following S.T.A.R.S. officer Rebecca Chambers and convict Billy Coen as they explore an abandoned training facility for employees of the pharmaceutical company Umbrella in the outskirts of Raccoon City. The gameplay is similar to other Resident Evil games, but adds the ability to switch between characters to solve puzzles and use unique abilities.', 'https://media.retroachievements.org/Images/100151.png', 'https://media.retroachievements.org/Images/082810.png', 'https://media.retroachievements.org/Images/082809.png', 'https://media.retroachievements.org/Images/082808.png', 4.5),
  (69, 28369, '~Hack~ Samus Goes to the Fridge to Get a Glass of Milk 3D', 'GameCube', 16, 483, 483, 483, 10, 0, NULL, 'Hacker - kkzero', 'Hack - Metroid Prime', '2021-06-17', NULL, 'https://media.retroachievements.org/Images/098921.png', 'https://media.retroachievements.org/Images/098920.png', 'https://media.retroachievements.org/Images/088929.png', 'https://media.retroachievements.org/Images/088926.png', 4.5),
  (70, 25429, 'Bust-A-Move 3000', 'GameCube', 16, 481, 481, 481, 44, 0, NULL, 'Taito', 'Ubisoft', '2002-12-03', 'Super Puzzle Bobble , released as Super Bust-A-Move in Europe and North America, is a puzzle video game in the Puzzle Bobble series. It was developed by Taito, and released on November 27, 2000 by Acclaim Entertainment for the PlayStation 2, and by CyberFront and EON Digital Entertainment for Windows in 2001. It was later ported to the Game Boy Advance that same year, the Japanese version under the name Super Puzzle Bobble Advance . It was re-released in Japan for the PlayStation 2 in 2004 as part of Super Puzzle Bobble DX , which is Volume 62 of the Japan-exclusive Simple 2000 Series. This compilation includes a few graphical enhancements.', 'https://media.retroachievements.org/Images/093160.png', 'https://media.retroachievements.org/Images/091981.png', 'https://media.retroachievements.org/Images/093049.png', 'https://media.retroachievements.org/Images/093050.png', 4.5),
  (71, 25434, 'Custom Robo', 'GameCube', 16, 476, 476, 476, 83, 0, NULL, 'Noise, StudioFAKE', NULL, '2004-03-04', 'Custom Robo is an action role-playing video game series developed by Noise and published by Nintendo.', 'https://media.retroachievements.org/Images/097547.png', 'https://media.retroachievements.org/Images/090018.png', 'https://media.retroachievements.org/Images/090017.png', 'https://media.retroachievements.org/Images/101279.png', 4.5),
  (72, 28598, 'GT Cube', 'GameCube', 16, 460, 460, 460, 85, 0, 'Racing Simulation', 'MTO', 'MTO', '2003-06-20', 'GT Cube is a racing game sequel to GT Advance 3: Pro Concept Racing released in 2003 by MTO for GameCube. The game was re-released as GT Pro Series for Wii in 2006.', 'https://media.retroachievements.org/Images/089680.png', 'https://media.retroachievements.org/Images/089676.png', 'https://media.retroachievements.org/Images/089677.png', 'https://media.retroachievements.org/Images/089678.png', 4.5),
  (73, 32657, '~Hack~ Pikmin 1²', 'GameCube', 16, 452, 452, 452, 77, 0, NULL, 'Pikhacker', 'Hack - Pikmin 2', '2024-12-28', 'Pikmin is a 2001 real-time strategy puzzle video game developed and published by Nintendo for the GameCube. The game was created and produced by Shigeru Miyamoto, and is the first entry in the Pikmin series. The game''s story focuses on an alien pilot, Captain Olimar, who crash lands on a mysterious planet and must make use of a native species called Pikmin to find his ship''s missing parts in order to escape within 30 days. Players take control of Olimar and direct the different varieties of Pikmin to explore the game''s various levels, overcoming obstacles and hostile creatures, in order to find and recover the missing ship parts.', 'https://media.retroachievements.org/Images/109113.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/109129.png', 'https://media.retroachievements.org/Images/109130.png', 4.5),
  (74, 6916, 'Spider-Man 2', 'GameCube', 16, 447, 447, 447, 57, 0, 'Action-Adventure, Sandbox', 'Treyarch', 'Activision, Taito', '2004-06-28', 'Spider-Man 2 is a 2004 American superhero film based on the Marvel Comics character Spider-Man. Directed by Sam Raimi and written by Alvin Sargent from a story conceived by Michael Chabon and the writing team of Alfred Gough and Miles Millar, it is the second installment in Raimi''s Spider-Man trilogy, following the 2002 film. The film stars Tobey Maguire as Peter Parker / Spider-Man, alongside Kirsten Dunst, James Franco, Alfred Molina, Rosemary Harris, and Donna Murphy. Peter Parker fights to stop scientist Dr. Otto Octavius from recreating a dangerous experiment, while also dealing with a personal crisis.', 'https://media.retroachievements.org/Images/101294.png', 'https://media.retroachievements.org/Images/084110.png', 'https://media.retroachievements.org/Images/084109.png', 'https://media.retroachievements.org/Images/084108.png', 4.5),
  (75, 25493, 'Kururin Squash!', 'GameCube', 16, 439, 439, 439, 66, 0, 'Puzzle', 'Raizing | Eighting', 'Nintendo', '2004-10-14', 'Kururin Squash! is a 2004 puzzle video game developed by Eighting and published by Nintendo for the GameCube. It was released exclusively in Japan on October 14, 2004. Kururin Squash! is the third and final game in the Kururin series as well as the first entry on a home console, following the release of Kuru Kuru Kururin (2001) and Kururin Paradise (2002) on the Game Boy Advance. The game uses 3D graphics, with 2D artwork of its characters being used on cardboard cutouts outside of gameplay.', 'https://media.retroachievements.org/Images/123976.png', 'https://media.retroachievements.org/Images/081368.png', 'https://media.retroachievements.org/Images/090061.png', 'https://media.retroachievements.org/Images/090062.png', 4.5),
  (76, 7724, 'Rayman 3: Hoodlum Havoc', 'GameCube', 16, 432, 432, 432, 76, 0, NULL, NULL, NULL, '2003-02-21', 'Rayman 3: Hoodlum Havoc is a 2003 platform game developed and published by Ubi Soft, and the third major installment in the Rayman series. It follows Rayman in his quest to stop an evil Black Lum named André from taking over the world with his army of hoodlum soldiers, which includes finding a cure for his best friend Globox after he accidentally swallows André. It was released for the GameCube, PlayStation 2, Xbox and Microsoft Windows, and on OS X by Feral Interactive in 2004. It was also released for the Game Boy Advance, N-Gage and mobile phones as a 2D platformer.', 'https://media.retroachievements.org/Images/067120.png', 'https://media.retroachievements.org/Images/091511.png', 'https://media.retroachievements.org/Images/091510.png', 'https://media.retroachievements.org/Images/091509.png', 4.5),
  (77, 15543, 'Skies of Arcadia Legends', 'GameCube', 16, 428, 428, 428, 180, 0, NULL, 'Overworks', 'Sega', '2003-01-29', 'Skies of Arcadia is a 2000 role-playing video game developed by Overworks and published by Sega for the Dreamcast. Players control Vyse, a young air pirate, and his friends as they attempt to stop the Valuan Empire from reviving ancient weapons with the potential to destroy the world.', 'https://media.retroachievements.org/Images/089482.png', 'https://media.retroachievements.org/Images/034007.png', 'https://media.retroachievements.org/Images/034005.png', 'https://media.retroachievements.org/Images/034008.png', 4.5),
  (78, 13727, 'Donkey Konga (USA)', 'GameCube', 16, 427, 427, 427, 82, 0, 'Rhythm', 'Namco', 'Nintendo', '2004-09-27', 'Donkey Konga is a series of rhythm video games developed by Namco and published by Nintendo for the GameCube. A spin-off of the Donkey Kong series, they are played with a special controller called the DK Bongos that resemble two small bongo drums, but can optionally be played with the standard GameCube controllers.', 'https://media.retroachievements.org/Images/089809.png', 'https://media.retroachievements.org/Images/089808.png', 'https://media.retroachievements.org/Images/089729.png', 'https://media.retroachievements.org/Images/089730.png', 4.5),
  (79, 31187, '~Hack~ Paper Mario: The Tower of Trials', 'GameCube', 16, 421, 421, 421, 80, 0, NULL, 'jdaster64', NULL, '2024-10-21', 'Super Mario Bros. is a 1985 platform game developed and published by Nintendo for the Nintendo Entertainment System (NES). Directed and produced by Shigeru Miyamoto, it is the successor to the 1983 arcade game Mario Bros. and the first game in the Super Mario series. Players control Mario, or his brother Luigi in the multiplayer mode, to traverse the Mushroom Kingdom to rescue Princess Toadstool from King Koopa. They traverse side-scrolling stages while avoiding hazards such as enemies and pits and collecting power-ups such as the Super Mushroom, Fire Flower, and Starman.', 'https://media.retroachievements.org/Images/103655.png', 'https://media.retroachievements.org/Images/105579.png', 'https://media.retroachievements.org/Images/103480.png', 'https://media.retroachievements.org/Images/103772.png', 4.5),
  (80, 7054, 'Battalion Wars', 'GameCube', 16, 415, 415, 415, 48, 0, 'Real-Time Strategy', 'Kuju Entertainment', 'Nintendo', '2005-09-19', 'Battalion Wars, released as Assault!! Famicom Wars in Japan, is a 2005 real-time tactics game developed by Kuju London and published by Nintendo for the GameCube. The player controls a vast array of units ranging from infantry, armoured divisions and aircraft, completing missions through a mixture of unit management and strategic planning. In the game''s story, the player operates as a commander of a battalion, who initially take part in a conflict between two nations that culminates in an eventual alliance between them, in response to a surprise attack by a third nation.', 'https://media.retroachievements.org/Images/088971.png', 'https://media.retroachievements.org/Images/094795.png', 'https://media.retroachievements.org/Images/088968.png', 'https://media.retroachievements.org/Images/088970.png', 4.5),
  (81, 3885, 'Final Fantasy Crystal Chronicles', 'GameCube', 16, 404, 404, 404, 138, 0, 'Action RPG', 'Square Enix', 'Nintendo', '2004-02-09', 'Final Fantasy Crystal Chronicles is a series of video games within the Final Fantasy franchise developed by Square Enix. Beginning in 2003 with the game for the GameCube, the series has predominantly been released on Nintendo gaming hardware and covers multiple genres, including action role-playing. The Crystal Chronicles series takes place in an unnamed world inhabited by four tribes. Recurring themes include creating objects from memory and the importance of family. The gameplay, which has always been aimed at as wide an audience as possible within a genre, generally involves either multiple players or a large group working together.', 'https://media.retroachievements.org/Images/089284.png', 'https://media.retroachievements.org/Images/073234.png', 'https://media.retroachievements.org/Images/089282.png', 'https://media.retroachievements.org/Images/089283.png', 4.5),
  (82, 25444, 'Godzilla: Destroy All Monsters Melee', 'GameCube', 16, 389, 389, 389, 53, 0, '3D Fighting', 'Pipeworks Software', 'Atari', '2002-10-08', 'Godzilla: Destroy All Monsters Melee is a fighting game based on Toho''s Godzilla franchise. It was developed by Pipeworks Software and published by Infogrames under the Atari brand for GameCube in 2002. A companion game developed by WayForward Technologies for Game Boy Advance, Godzilla: Domination!, was released in November of the same year. Destroy All Monsters Melee was later released for Xbox in 2003, featuring additional content and enhanced graphics.', 'https://media.retroachievements.org/Images/098641.png', 'https://media.retroachievements.org/Images/087187.png', 'https://media.retroachievements.org/Images/097977.png', 'https://media.retroachievements.org/Images/097978.png', 4.5),
  (83, 29177, 'Bloody Roar: Primal Fury', 'GameCube', 16, 384, 384, 384, 47, 0, NULL, NULL, NULL, '2002-03-19', 'Bloody Roar Extreme, or Bloody Roar: Primal Fury as it is known outside of its Japan release for the GameCube, is a fighting game developed by Eighting released in 2002 for the Nintendo GameCube. It was later ported to Microsoft''s Xbox under the original moniker of Bloody Roar Extreme in 2003.', 'https://media.retroachievements.org/Images/094007.png', 'https://media.retroachievements.org/Images/094031.png', 'https://media.retroachievements.org/Images/094003.png', 'https://media.retroachievements.org/Images/098228.png', 4.5),
  (84, 7003, 'Burnout', 'GameCube', 16, 381, 381, 381, 27, 0, 'Arcade Racing', 'Criterion Games', 'Acclaim', '2002-04-30', 'Burnout is a 2001 racing video game developed by Criterion Games and published by Acclaim Entertainment. It was released for the PlayStation 2 in 2001 and GameCube and Xbox in 2002. It is the first instalment in the Burnout series.', 'https://media.retroachievements.org/Images/116509.png', 'https://media.retroachievements.org/Images/095624.png', 'https://media.retroachievements.org/Images/100653.png', 'https://media.retroachievements.org/Images/100654.png', 4.5),
  (85, 8577, 'Harvest Moon: Magical Melody', 'GameCube', 16, 376, 376, 376, 138, 0, NULL, NULL, NULL, '2005-03-28', 'Harvest Moon: Magical Melody  is a social simulation video game for the GameCube developed by Marvelous Interactive. It is an updated version of Bokujō Monogatari: Shiawase no Uta , which was released on March 3, 2005 in Japan. The updated GameCube version was released in the United States by Natsume Inc. on March 28, 2006.', 'https://media.retroachievements.org/Images/120788.png', 'https://media.retroachievements.org/Images/088983.png', 'https://media.retroachievements.org/Images/089015.png', 'https://media.retroachievements.org/Images/089030.png', 4.5),
  (86, 30151, '~Hack~ Luigi''s Mansion Beta Restoration', 'GameCube', 16, 361, 361, 361, 7, 0, NULL, 'Portable Productions', 'Hack - Luigi''s Mansion', '2023-10-20', 'The Grand Chalet, also known as Grand Chalet de Rossinière, Grande Demeure, Grande Maison or Chalet Balthus, is a historic chalet in Rossinière, the French part of Switzerland. It is listed as a Swiss heritage site of national significance. The French name Le Grand Chalet means The Big Chalet, in the sense of: The biggest house in town.', 'https://media.retroachievements.org/Images/119405.png', 'https://media.retroachievements.org/Images/119315.png', 'https://media.retroachievements.org/Images/099381.png', 'https://media.retroachievements.org/Images/099380.png', 4.5),
  (87, 1442, 'Bomberman Generation', 'GameCube', 16, 360, 360, 360, 75, 0, NULL, NULL, NULL, '2002-06-04', 'Bomberman Generation is a 2002 video game released for the GameCube. It was followed up by Bomberman Jetters.', 'https://media.retroachievements.org/Images/091995.png', 'https://media.retroachievements.org/Images/088981.png', 'https://media.retroachievements.org/Images/089276.png', 'https://media.retroachievements.org/Images/089277.png', 4.5),
  (88, 29749, 'Disney''s Extreme Skate Adventure', 'GameCube', 16, 348, 348, 348, 118, 0, 'Extreme Sports - Skateboarding', 'Toys for Bob', 'Activision', '2003-09-02', 'Disney''s Extreme Skate Adventure is a 2003 skateboarding game developed by Toys for Bob for the PlayStation 2, GameCube, and Xbox, and Vicarious Visions for the Game Boy Advance, and published by Activision. The game features characters and stages licensed from Disney''s The Lion King and Tarzan, and Pixar''s Toy Story franchises.', 'https://media.retroachievements.org/Images/101296.png', 'https://media.retroachievements.org/Images/096129.png', 'https://media.retroachievements.org/Images/096127.png', 'https://media.retroachievements.org/Images/096128.png', 4.5),
  (89, 28385, 'Bleach GC: Tasogare ni Mamieru Shinigami', 'GameCube', 16, 336, 336, 336, 16, 0, NULL, 'Polygon Magic', NULL, '2005-12-08', 'There are several video games based on Tite Kubo''s manga and anime series Bleach. The titles consist mostly of side-scrolling fighters, but also include other genres such as strategy role-playing games and action role-playing games. Most of the games retell the plot of the manga, following Ichigo Kurosaki and his friends. Some games, however, have veered from the source material and incorporated original stories and characters. The games have been released on a variety of home and handheld consoles.', 'https://media.retroachievements.org/Images/089148.png', 'https://media.retroachievements.org/Images/089147.png', 'https://media.retroachievements.org/Images/089119.png', 'https://media.retroachievements.org/Images/089118.png', 4.5),
  (90, 30157, 'Universal Studios Theme Park Adventure', 'GameCube', 16, 336, 336, 336, 26, 0, 'Adventure, Minigames', 'Nai''a Digital Works', 'Kemco', '2001-12-07', 'Universal Studios Theme Parks Adventure, known in Japan as Universal Studios Japan Adventure , is a 2001 party video game developed by Nai''a Digital Works and published by Kemco for the GameCube. Set at the Universal Studios Japan park, the object of the game is to complete several mini-games loosely based on the real-life attractions Back to the Future: The Ride, Jaws, Jurassic Park River Adventure, E.T. Adventure, Backdraft, Wild, Wild, Wild West Stunt Show, and Waterworld. The player is required to collect trash located in the park to be able to ride the themed rides; the player is also encouraged to wear merchandise based on the respective franchises and complete movie quizzes in which they must answer trivia questions about the Universal Studios films.', 'https://media.retroachievements.org/Images/099467.png', 'https://media.retroachievements.org/Images/099468.png', 'https://media.retroachievements.org/Images/099465.png', 'https://media.retroachievements.org/Images/099466.png', 4.5),
  (91, 25417, 'P.N.03', 'GameCube', 16, 332, 332, 332, 43, 0, 'Third-Person Shooter', 'Capcom', 'Capcom', '2003-03-27', 'P.N.03 is a 2003 third-person shooter developed and published by Capcom for the GameCube. Set in a space colony compound, the game follows a female mercenary fighting against berserk robots. Gameplay focuses on defensive tactics and includes abilities that can be upgraded.', 'https://media.retroachievements.org/Images/121378.png', 'https://media.retroachievements.org/Images/089494.png', 'https://media.retroachievements.org/Images/090058.png', 'https://media.retroachievements.org/Images/090059.png', 4.5),
  (92, 28372, 'Shrek Extra Large', 'GameCube', 16, 318, 318, 318, 29, 0, '3D Platforming', 'Digital Illusions', 'TDK Mediactive', '2002-10-30', 'Shrek is a 2001 platform video game developed by Digital Illusions Canada and published by TDK Mediactive for the Xbox, based on the 2001 film Shrek. The game was released on November 15, 2001, as one of 22 North American launch titles for the Xbox and March 27, 2002, in Europe, with a United Kingdom release following on March 29. A reworked version of the game, titled Shrek: Extra Large, was released for the GameCube on October 30, 2002, in North America and on October 24, 2003, in Europe. Shrek: Extra Large uses the same engine and game mechanics as the original Xbox release, but with an altered story and different levels.', 'https://media.retroachievements.org/Images/089855.png', 'https://media.retroachievements.org/Images/093520.png', 'https://media.retroachievements.org/Images/100232.png', 'https://media.retroachievements.org/Images/100233.png', 4.5),
  (93, 28384, 'The Chronicles of Narnia: The Lion, the Witch and the Wardrobe', 'GameCube', 16, 317, 317, 317, 73, 0, 'Action-Adventure', 'Traveller''s Tales', 'Buena Vista Games', '2005-11-14', 'The Chronicles of Narnia: The Lion, the Witch and the Wardrobe is a 2005 high fantasy film directed by Andrew Adamson, who co-wrote the screenplay with Ann Peacock and the writing team of Christopher Markus and Stephen McFeely, based on the 1950 novel The Lion, the Witch and the Wardrobe, the first published and second chronological novel in the children''s book series The Chronicles of Narnia by C. S. Lewis. The film is the first installment in The Chronicles of Narnia film series. It was produced by Walt Disney Pictures and Walden Media, and distributed by Buena Vista Pictures Distribution.', 'https://media.retroachievements.org/Images/094798.png', 'https://media.retroachievements.org/Images/094797.png', 'https://media.retroachievements.org/Images/094800.png', 'https://media.retroachievements.org/Images/094799.png', 4.5),
  (94, 25424, 'Barnyard', 'GameCube', 16, 308, 308, 308, 87, 0, 'Adventure, Minigames', 'Blue Tongue Entertainment', 'THQ', '2006-08-01', 'A barnyard or farmyard is an enclosed or open yard adjoining a barn, and, typically, related farm buildings, including a farmhouse. Enclosed barnyards are usually formed by a combination of fences and farm structures.', 'https://media.retroachievements.org/Images/100189.png', 'https://media.retroachievements.org/Images/091254.png', 'https://media.retroachievements.org/Images/100342.png', 'https://media.retroachievements.org/Images/100341.png', 4.5),
  (95, 7032, 'Crash Bandicoot: The Wrath of Cortex', 'GameCube', 16, 306, 306, 306, 110, 0, '3D Platforming', 'Eurocom, Traveller''s Tales', 'Universal Interactive', '2002-09-17', 'Crash Bandicoot: The Wrath of Cortex is a 2001 platform game developed by Traveller''s Tales and published by Universal Interactive. It was first released for the PlayStation 2 and later ported to the Xbox, and GameCube, with Eurocom developing the GameCube version. It is the fourth main installment and the sixth overall in the Crash Bandicoot video game series, being the first of the series to not be released solely for a PlayStation console.', 'https://media.retroachievements.org/Images/096210.png', 'https://media.retroachievements.org/Images/096016.png', 'https://media.retroachievements.org/Images/096014.png', 'https://media.retroachievements.org/Images/096015.png', 4.5),
  (96, 28604, 'Donkey Konga (Europe)', 'GameCube', 16, 278, 278, 278, 71, 0, 'Rhythm', 'Namco', 'Nintendo', '2004-10-15', 'Donkey Konga is a series of rhythm video games developed by Namco and published by Nintendo for the GameCube. A spin-off of the Donkey Kong series, they are played with a special controller called the DK Bongos that resemble two small bongo drums, but can optionally be played with the standard GameCube controllers.', 'https://media.retroachievements.org/Images/089894.png', 'https://media.retroachievements.org/Images/089868.png', 'https://media.retroachievements.org/Images/089726.png', 'https://media.retroachievements.org/Images/089727.png', 4.5),
  (97, 6915, 'Spider-Man', 'GameCube', 16, 278, 278, 278, 133, 0, 'Action-Adventure', 'Treyarch', 'Activision', '2002-04-16', 'Spider-Man is a superhero in American comic books published by Marvel Comics. Created by writer-editor Stan Lee and artist Steve Ditko, he first appeared in the anthology comic book Amazing Fantasy #15 in the Silver Age of Comic Books. Widely regarded as one of the most popular and commercially successful superheroes, he has been featured in comic books, television shows, films, video games, novels, and plays.', 'https://media.retroachievements.org/Images/088912.png', 'https://media.retroachievements.org/Images/094788.png', 'https://media.retroachievements.org/Images/094787.png', 'https://media.retroachievements.org/Images/094789.png', 4.5),
  (98, 8489, 'Baten Kaitos: Eternal Wings and the Lost Ocean', 'GameCube', 16, 276, 276, 276, 171, 0, 'Turn-Based RPG', 'Monolith Soft', 'Bandai Namco', '2003-12-05', 'Baten Kaitos: Eternal Wings and the Lost Ocean is a role-playing video game developed by Monolith Soft and tri-Crescendo and published by Namco for the GameCube. It was released in Japan in 2003, North America in 2004 and PAL territories in 2005. The player assumes the role of a guardian spirit – an unseen player avatar – who guides protagonist Kalas and his party of companions in an adventure across an aerial floating island-based kingdom in the clouds. The game is focused around the concept of Magnus – magical cards that capture the essence of items found in the in-game world. The concept is used as a plot device, for in-game item management, and as a basis for the card-themed battle system. The game was noted for its unique battle system, which included aspects of turn-based and action-based battle systems, collectible card games, and poker.', 'https://media.retroachievements.org/Images/099497.png', 'https://media.retroachievements.org/Images/090475.png', 'https://media.retroachievements.org/Images/090477.png', 'https://media.retroachievements.org/Images/090478.png', 4.5),
  (99, 30245, 'Ed, Edd n Eddy: The Mis-Edventures', 'GameCube', 16, 276, 276, 276, 25, 0, '3D Platforming', 'Artificial Mind and Movement', 'Midway', '2005-10-31', 'Ed, Edd n Eddy: The Mis-Edventures is a 2005 video game developed by Artificial Mind and Movement and published by Midway. Based on the Cartoon Network animated television series Ed, Edd n Eddy. It uses 3D platformer gameplay on home console and PC versions whereas the Game Boy Advance version is a 2D side-scrolling video game. The game''s plot is loosely structured around six different stories with two bonus levels, each involving a scam by the titular trio to acquire enough money to buy jawbreakers, a plot that mirrors that of the animated series.', 'https://media.retroachievements.org/Images/100216.png', 'https://media.retroachievements.org/Images/112849.png', 'https://media.retroachievements.org/Images/112847.png', 'https://media.retroachievements.org/Images/112848.png', 4.5),
  (100, 25442, 'Go! Go! Hypergrind', 'GameCube', 16, 274, 274, 274, 102, 0, 'Extreme Sports - Skateboarding', 'Atlus', 'Atlus', '2003-11-18', 'Go! Go! Hypergrind is a 2003 skateboarding video game developed by Poponchi and published by Atlus USA for the GameCube. It was released only in North America on November 18, 2003. Development was led by Poponchi, a small group of developers at Atlus, with animation studio Spümcø of The Ren & Stimpy Show fame serving as a collaborative art design firm for the game, with founder John Kricfalusi acting as an executive producer. Despite being developed in Japan, it was never released in the region.', 'https://media.retroachievements.org/Images/091293.png', 'https://media.retroachievements.org/Images/089614.png', 'https://media.retroachievements.org/Images/089613.png', 'https://media.retroachievements.org/Images/089612.png', 4.4),
  (101, 3829, 'Beyond Good & Evil', 'GameCube', 16, 273, 273, 273, 47, 0, 'Action-Adventure', 'Ubisoft', 'Ubisoft', '2003-12-11', 'Beyond Good & Evil is a 2003 action-adventure game developed by Ubisoft Montpellier and published by Ubisoft for PlayStation 2, Windows, Xbox, and GameCube. The story follows the adventures of Jade, an investigative reporter, martial artist, and spy working with a resistance movement to reveal a sinister alien conspiracy. Players control Jade and other allies, solving puzzles, fighting enemies, obtaining photographic evidence and, later in the game, travelling to space.', 'https://media.retroachievements.org/Images/102108.png', 'https://media.retroachievements.org/Images/089127.png', 'https://media.retroachievements.org/Images/084099.png', 'https://media.retroachievements.org/Images/084098.png', 4.4),
  (102, 30287, 'Disney''s Hide & Sneak', 'GameCube', 16, 273, 273, 273, 11, 0, NULL, NULL, NULL, '2003-11-30', 'Disney''s Hide and Sneak is an action-adventure game released in 2003 by Capcom for the GameCube. It follows Mickey Mouse and his girlfriend Minnie Mouse as they fight their way through an army of UFO-shaped aliens and rescue the other from a mushroom-shaped alien named Lu-Lu.', 'https://media.retroachievements.org/Images/123484.png', 'https://media.retroachievements.org/Images/103240.png', 'https://media.retroachievements.org/Images/103238.png', 'https://media.retroachievements.org/Images/103239.png', 4.4),
  (103, 24915, 'Hunter: The Reckoning', 'GameCube', 16, 273, 273, 273, 83, 0, 'Hack & Slash', 'High Voltage Software', 'Virgin Interactive, Interplay Entertainment', '2002-11-19', 'Hunter: The Reckoning is a horror tabletop role-playing game, and the sixth main game in the World of Darkness series. It was originally released by White Wolf Publishing in November 1999 as part of their Year of the Reckoning line. A second edition, based on the Vampire: The Masquerade 5th edition ruleset, was released in 2022 by Renegade Game Studios. It is supported by a series of supplementary books which expand the game''s setting and describe types of characters.', 'https://media.retroachievements.org/Images/081634.png', 'https://media.retroachievements.org/Images/102858.png', 'https://media.retroachievements.org/Images/103212.png', 'https://media.retroachievements.org/Images/103481.png', 4.4),
  (104, 28658, '~Hack~ Pikmin 251', 'GameCube', 16, 264, 264, 264, 83, 0, 'Real-Time Strategy', 'PikHacker', 'Hack - Pikmin 2', '2019-09-25', 'The Nintendo GameCube is a home video game console developed and marketed by Nintendo. It was released in Japan on September 14, 2001, in North America on November 18, 2001, and in Europe on May 3, 2002. It is Nintendo''s fourth major home console, succeeding the Nintendo 64, and competed with Sony''s PlayStation 2 and Microsoft''s Xbox in the sixth generation of game consoles.', 'https://media.retroachievements.org/Images/110885.png', 'https://media.retroachievements.org/Images/095017.png', 'https://media.retroachievements.org/Images/091085.png', 'https://media.retroachievements.org/Images/100668.png', 4.4),
  (105, 28373, 'Dragon Ball Z: Budokai 2', 'GameCube', 16, 259, 259, 259, 89, 0, '3D Fighting', 'Dimps', 'Atari', '2004-12-15', 'Dragon Ball Z: Budokai 2, released as Dragon Ball Z2  in Japan, is a fighting video game developed by Dimps based upon the anime and manga series, Dragon Ball Z, and a sequel to Dragon Ball Z: Budokai. It released for the PlayStation 2 in 2003 and for the GameCube in 2004 and was published in Japan and Europe by Bandai and in North America, Australia and South Africa by Atari SA.', 'https://media.retroachievements.org/Images/110437.png', 'https://media.retroachievements.org/Images/099794.png', 'https://media.retroachievements.org/Images/099799.png', 'https://media.retroachievements.org/Images/099798.png', 4.4),
  (106, 30125, 'Mega Man X: Command Mission', 'GameCube', 16, 249, 249, 249, 88, 0, NULL, NULL, NULL, '2004-07-29', 'Mega Man X: Command Mission, known in Japan as Rockman X: Command Mission (ロックマンＸコマンドミッション), is a 2004 role-playing video game developed by Capcom for the PlayStation 2 and GameCube. The game is a spin-off of the Mega Man X franchise. It was released in Japan on July 29, 2004, with releases in North America and PAL regions following in September and November.', 'https://media.retroachievements.org/Images/099083.png', 'https://media.retroachievements.org/Images/099081.png', 'https://media.retroachievements.org/Images/100111.png', 'https://media.retroachievements.org/Images/100112.png', 4.4),
  (107, 28265, 'Digimon World 4', 'GameCube', 16, 247, 247, 247, 108, 0, 'Action RPG', 'Bandai', 'Bandai', '2005-01-06', 'Digimon World 4, known as Digimon World X  in Japan, is an action role-playing game for PlayStation 2, GameCube, and Xbox developed by BEC and published by Bandai as part of their Digimon franchise. Unlike previous games in the Digimon World series, it features action-based hack and slash gameplay and supports up to four players. Each player plays as either an Agumon, a Veemon, a Guilmon, and a Dorumon. The game is loosely based on the 2005 Digital Monster X-Evolution film, even using footage from the movie itself. Only the PlayStation 2 version was released in the PAL region.', 'https://media.retroachievements.org/Images/122265.png', 'https://media.retroachievements.org/Images/092358.png', 'https://media.retroachievements.org/Images/092359.png', 'https://media.retroachievements.org/Images/092360.png', 4.4),
  (108, 3802, 'Metal Arms: Glitch in the System', 'GameCube', 16, 245, 245, 245, 164, 0, 'Third-Person Shooter, Action-Adventure', 'Swingin'' Ape Studios', 'Vivendi Universal Games', '2003-11-18', 'Metal Arms: Glitch in the System is a third-person shooter action-adventure video game, developed by American team Swingin'' Ape Studios, published by Vivendi Universal Games and their subsidiary Sierra Entertainment and released in 2003. The game follows a robot named Glitch as he joins forces with the Droids in their fight against General Corrosive and his Milbots.', 'https://media.retroachievements.org/Images/104016.png', 'https://media.retroachievements.org/Images/103827.png', 'https://media.retroachievements.org/Images/093259.png', 'https://media.retroachievements.org/Images/093260.png', 4.4),
  (109, 28374, '~Hack~ Luigi''s Mansion: Sweet Home', 'GameCube', 16, 243, 243, 243, 14, 0, 'Action-Adventure, Horror', 'Catley', 'Hack - Luigi''s Mansion', '2022-10-31', 'The GameCube is Nintendo''s fourth home video game console, released during the sixth generation of video games. It is the successor to the Nintendo 64, and was first launched in Japan on September 14, 2001, followed by a launch in North America on November 18, 2001, and a launch in the PAL regions in May 2002. The successor to the GameCube is the Wii, which was first released in North America on November 19, 2006, and is backward compatible with GameCube games, memory cards, and controllers. Although later models would remove the controller ports and memory card slots required for backwards compatibility, they can be hardware modded back in. There are 651 games on this list. It is organized alphabetically by the games'' localized English titles, or by rōmaji transliterations when exclusive to Japan. For a list of games that were announced or in development for the GameCube but never released, see the list of cancelled GameCube games.', 'https://media.retroachievements.org/Images/089082.png', 'https://media.retroachievements.org/Images/094000.png', 'https://media.retroachievements.org/Images/089014.png', 'https://media.retroachievements.org/Images/088932.png', 4.4),
  (110, 28854, '~Hack~ Super Mario Sunshine Arcade 2', 'GameCube', 16, 228, 228, 228, 44, 0, '3D Platforming, Collect-a-thon', 'Augs SMSHacks', 'Hack - Super Mario Sunshine', '2019-10-20', 'This is a list of video games for the GameCube video game console that have sold or shipped at least one million copies. The best-selling game on the GameCube is Super Smash Bros. Melee. First released in Japan on November 21, 2001, it went on to sell just over 7.4 million units worldwide. The second best-selling game was Mario Kart: Double Dash, selling 6.88 million units. Super Mario Sunshine is the console''s third best-selling game, with 5.91 million units.', 'https://media.retroachievements.org/Images/091609.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/091543.png', 'https://media.retroachievements.org/Images/092551.png', 4.4),
  (111, 6837, 'Doshin the Giant', 'GameCube', 16, 226, 226, 226, 35, 0, 'Real-Time Strategy', 'Param', 'Nintendo', '2002-03-14', 'Doshin the Giant is a god simulation game developed by Param and published by RandnetDD for the 64DD. It was originally released in Japan on December 1, 1999, as a launch title for the peripheral. A soundtrack by Tatsuhiko Asano was released on CD by Media Factory, early the next year. Both of these received positive reviews. An expansion pack was released five months later called Kyojin no Doshin Kaihō Sensen Chibikko Chikko Daishūgou, which takes a very different perspective of the game, featuring short animated clips that the player can unlock after playing the original game. Doshin the Giant was upgraded graphically for its re-release on the GameCube in Japan on March 14, 2002, and Europe on September 20, 2002. The GameCube version was published by Nintendo and received positive reviews.', 'https://media.retroachievements.org/Images/099101.png', 'https://media.retroachievements.org/Images/090070.png', 'https://media.retroachievements.org/Images/090071.png', 'https://media.retroachievements.org/Images/090072.png', 4.4),
  (112, 30150, '~Hack~ Mario Kart: Double Dash!! Plus', 'GameCube', 16, 220, 220, 220, 358, 0, NULL, 'That1loser4', NULL, '2024-03-12', 'The GameCube has limited support for online gaming. Nintendo never commissioned any servers to interface with the console, but allowed other publishers to do so. The only games released with internet-based gameplay modes were Phantasy Star Online, Phantasy Star Online Episode III: C.A.R.D. Revolution, and Homeland. Nintendo also published three racing games with local area network (LAN) support: 1080° Avalanche, Kirby Air Ride, and Mario Kart: Double Dash!!. Using network functions requires the official broadband or modem adapter since the console does not have out of the box network capabilities.', 'https://media.retroachievements.org/Images/106371.png', 'https://media.retroachievements.org/Images/116378.png', 'https://media.retroachievements.org/Images/116377.png', 'https://media.retroachievements.org/Images/116376.png', 4.4),
  (113, 25454, 'Mega Man Network Transmission', 'GameCube', 16, 215, 215, 215, 50, 0, '2D Platforming, Metroidvania', 'Arika', 'Capcom', '2003-03-03', 'Mega Man Network Transmission is a 2003 action-platform video game developed by Arika and published by Capcom for the GameCube video game console. The game was first released in Japan on March 6, 2003, and in North America and PAL regions the following June as Arika''s only GameCube game. Network Transmission is part of the Mega Man Battle Network series, which originated on the Game Boy Advance (GBA) handheld and takes place in an alternate timeline to the main Mega Man series.', 'https://media.retroachievements.org/Images/093034.png', 'https://media.retroachievements.org/Images/081170.png', 'https://media.retroachievements.org/Images/081172.png', 'https://media.retroachievements.org/Images/081173.png', 4.4),
  (114, 28263, 'Radirgy GeneriC', 'GameCube', 16, 215, 215, 215, 53, 0, 'Shoot ''em Up, Bullet Hell', 'Milestone', 'Milestone', '2006-05-25', 'Radirgy is a shoot ''em up video game developed by MileStone Inc. and released for the Sega NAOMI arcade platform in 2005. The story follows schoolgirl Shizuru Kamigusa in an age filled with radio waves which she is allergic to. She must save her father, who is developing a remedy for her sickness, from terrorists who have taken control of his company. The game features bullet hell gameplay elements and a distinct cel shaded graphical style.', 'https://media.retroachievements.org/Images/088957.png', 'https://media.retroachievements.org/Images/088952.png', 'https://media.retroachievements.org/Images/088948.png', 'https://media.retroachievements.org/Images/088951.png', 4.4),
  (115, 30216, 'Gotcha Force', 'GameCube', 16, 214, 214, 214, 70, 0, 'Third-Person Shooter', 'Capcom', 'Capcom', '2003-11-27', 'Gotcha Force  is a fighting / third-person shooter video game developed and published by Capcom for the GameCube in 2003. It consists primarily of collecting gacha toys and battling with them.', 'https://media.retroachievements.org/Images/100262.png', 'https://media.retroachievements.org/Images/100263.png', 'https://media.retroachievements.org/Images/100265.png', 'https://media.retroachievements.org/Images/100264.png', 4.4),
  (116, 25484, 'Turok: Evolution', 'GameCube', 16, 212, 212, 212, 72, 0, 'First-Person Shooter', 'Acclaim', 'Acclaim', '2002-09-01', 'Turok: Evolution is a first-person shooter game in the Turok series. A prequel to Turok: Dinosaur Hunter (1997), it was developed by Acclaim Studios Austin and published by Acclaim Entertainment. It was released for the PlayStation 2, Xbox and GameCube in 2002, alongside a handheld version for the Game Boy Advance. A port of the home console game was released for Windows in 2003, for the European market.', 'https://media.retroachievements.org/Images/096422.png', 'https://media.retroachievements.org/Images/088795.png', 'https://media.retroachievements.org/Images/097979.png', 'https://media.retroachievements.org/Images/097980.png', 4.4),
  (117, 24163, 'Star Wars: The Clone Wars', 'GameCube', 16, 207, 207, 207, 52, 0, 'Action', 'Pandemic Studios', 'LucasArts | Lucasfilm', '2002-10-29', 'Star Wars: The Clone Wars is an American CGI animated television series created by George Lucas and produced by Lucasfilm Animation. Set between Star Wars: Episode II – Attack of the Clones (2002) and Star Wars: Episode III – Revenge of the Sith (2005), it follows Jedi Knights Anakin Skywalker, Obi-Wan Kenobi, and Anakin''s Padawan, Ahsoka Tano as they lead the Galactic Republic''s clone army against the Separatist Alliance, commanded by Count Dooku during the Clone Wars.', 'https://media.retroachievements.org/Images/088361.png', 'https://media.retroachievements.org/Images/094794.png', 'https://media.retroachievements.org/Images/089225.png', 'https://media.retroachievements.org/Images/089224.png', 4.4),
  (118, 3342, 'Baldur''s Gate: Dark Alliance', 'GameCube', 16, 205, 205, 205, 72, 0, 'Action RPG', 'Snowblind Studios, High Voltage Software', 'Interplay Entertainment, Black Isle Studios', '2002-11-20', 'Baldur''s Gate: Dark Alliance is a 2001 action role-playing video game developed by Snowblind Studios and published by Interplay Entertainment subsidiary Black Isle Studios for the PlayStation 2 and the Xbox consoles, with High Voltage Software handling the GameCube port and Magic Pockets developing the Game Boy Advance version. CD Projekt was developing a version for Microsoft Windows, which was ultimately cancelled.', 'https://media.retroachievements.org/Images/114465.png', 'https://media.retroachievements.org/Images/112167.png', 'https://media.retroachievements.org/Images/112163.png', 'https://media.retroachievements.org/Images/112164.png', 4.4),
  (119, 30713, '~Hack~ Luigi''s Mansion: Halloween Haunt', 'GameCube', 16, 200, 200, 200, 15, 0, 'Action-Adventure, Horror', 'Colby', NULL, '2022-10-31', 'Luigi''s Mansion: Dark Moon is a 2013 action-adventure game developed by Next Level Games and published by Nintendo for the Nintendo 3DS. It is the second installment in the Luigi''s Mansion series, following Luigi''s Mansion (2001). The story follows Luigi as he explores Evershade Valley, capturing ghosts using a specialized vacuum cleaner invented by Professor E. Gadd. In order to restore peace to Evershade Valley, Luigi must collect the pieces of the Dark Moon and recapture the main antagonist, King Boo.', 'https://media.retroachievements.org/Images/116190.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/100938.png', 'https://media.retroachievements.org/Images/100936.png', 4.4),
  (120, 28605, 'Donkey Konga (Japan)', 'GameCube', 16, 198, 198, 198, 105, 0, 'Rhythm', 'Namco', 'Nintendo', '2003-12-12', 'Donkey Konga is a series of rhythm video games developed by Namco and published by Nintendo for the GameCube. A spin-off of the Donkey Kong series, they are played with a special controller called the DK Bongos that resemble two small bongo drums, but can optionally be played with the standard GameCube controllers.', 'https://media.retroachievements.org/Images/089895.png', 'https://media.retroachievements.org/Images/089869.png', 'https://media.retroachievements.org/Images/089731.png', 'https://media.retroachievements.org/Images/089732.png', 4.4),
  (121, 30221, 'Dragon Ball Z: Budokai', 'GameCube', 16, 198, 198, 198, 122, 0, '3D Fighting', 'Dimps', 'Atari', '2003-10-28', 'Dragon Ball Z: Budokai, known as in Japan as simply Dragon Ball Z, is a series of fighting video games based on the anime series Dragon Ball Z, itself part of the larger Dragon Ball franchise.', 'https://media.retroachievements.org/Images/110428.png', 'https://media.retroachievements.org/Images/099789.png', 'https://media.retroachievements.org/Images/100299.png', 'https://media.retroachievements.org/Images/100300.png', 4.4),
  (122, 30368, '18 Wheeler: American Pro Trucker', 'GameCube', 16, 196, 196, 196, 22, 0, 'Arcade Racing', 'Sega', 'Sega', '2002-02-20', '18 Wheeler: American Pro Trucker is an arcade game developed by Sega AM2 and distributed by Sega. The game was released in arcades in 1999 and ported to the Dreamcast in 2000. It was released for the PlayStation 2 in 2001 and GameCube in 2002 by Acclaim Entertainment. Sega followed up on the success of 18 Wheeler with a sequel, The King of Route 66, which was released in the arcades in 2002 and ported to the PlayStation 2. This was one of the final arcade games to be ported to the Dreamcast after its discontinuation, before Sega became a third-party developer.', 'https://media.retroachievements.org/Images/110484.png', 'https://media.retroachievements.org/Images/110483.png', 'https://media.retroachievements.org/Images/110482.png', 'https://media.retroachievements.org/Images/110481.png', 4.4),
  (123, 3178, 'Harvest Moon: A Wonderful Life', 'GameCube', 16, 196, 196, 196, 230, 0, 'Life Simulation', 'Marvelous Interactive', 'Natsume', '2003-09-12', 'Harvest Moon: A Wonderful Life is a video game that was released in Japan in September 2003 and March 2004 in North America for the GameCube. It was developed and published by Marvelous Interactive in Japan, while Natsume Inc. published it worldwide), and is part of the long-running Story of Seasons video game series. The GameCube version offers connectivity with the Game Boy Advance game, Harvest Moon: Friends of Mineral Town.', 'https://media.retroachievements.org/Images/120496.png', 'https://media.retroachievements.org/Images/089380.png', 'https://media.retroachievements.org/Images/098636.png', 'https://media.retroachievements.org/Images/098637.png', 4.4),
  (124, 3774, 'TimeSplitters: Future Perfect', 'GameCube', 16, 191, 191, 191, 128, 0, 'First-Person Shooter', 'Free Radical Design', 'Electronic Arts', '2005-03-21', 'TimeSplitters: Future Perfect is a 2005 first-person shooter video game developed by Free Radical Design and published by Electronic Arts for the GameCube, PlayStation 2, and Xbox.', 'https://media.retroachievements.org/Images/116784.png', 'https://media.retroachievements.org/Images/107513.png', 'https://media.retroachievements.org/Images/110867.png', 'https://media.retroachievements.org/Images/110868.png', 4.4),
  (125, 25460, 'Odama', 'GameCube', 16, 188, 188, 188, 42, 0, NULL, 'Vivarium', NULL, '2006-03-31', 'Odama is a video game for the GameCube developed by Vivarium and Studiofake and published by Nintendo for the GameCube. The game was produced and designed by Seaman creator Yoot Saito. It is the penultimate GameCube game to be published by Nintendo, followed by The Legend of Zelda: Twilight Princess.', 'https://media.retroachievements.org/Images/082274.png', 'https://media.retroachievements.org/Images/081366.png', 'https://media.retroachievements.org/Images/082272.png', 'https://media.retroachievements.org/Images/082273.png', 4.4),
  (126, 25464, 'Pokémon Box: Ruby & Sapphire', 'GameCube', 16, 188, 188, 188, 188, 0, 'Other', 'Game Freak, Nintendo', 'Nintendo, The Pokémon Company', '2003-05-30', 'Pokémon Ruby Version and Pokémon Sapphire Version are 2002 role-playing video games developed by Game Freak and published by The Pokémon Company and Nintendo for the Game Boy Advance. They are the first installments in the third generation of the Pokémon video game series, also known as the advanced generation. After years of Nintendo being the sole publisher of the franchise in all regions, The Pokémon Company co-published the games for the first time since the establishment of the joint-owned company in 1998. They were first released in Japan in late 2002, and internationally in 2003. Pokémon Emerald, a third version, was released two years later in each region. Remakes of the two games, titled Pokémon Omega Ruby and Alpha Sapphire, were released for the Nintendo 3DS worldwide in November 2014, exactly twelve years to the date of the original Ruby and Sapphire release date, with the exception of Europe, where it released a week later.', 'https://media.retroachievements.org/Images/106161.png', 'https://media.retroachievements.org/Images/106164.png', 'https://media.retroachievements.org/Images/106162.png', 'https://media.retroachievements.org/Images/106163.png', 4.4),
  (127, 25459, 'Nickelodeon Party Blast', 'GameCube', 16, 176, 176, 176, 32, 0, 'Party', 'Data Design Interactive', 'Infogrames', '2002-12-06', 'Nickelodeon Party Blast is a party video game developed by English developer Data Design Interactive and published by Infogrames Interactive. Party Blast was released for Xbox, Windows, and GameCube in 2002. A PlayStation 2 version of the game was planned to be released, but it was cancelled for unknown reasons, though leftovers, such as a model of a DualShock 2 controller, can still be found in all versions of the game''s files. The game features characters from Nicktoons, including SpongeBob SquarePants, Rugrats, The Wild Thornberrys, Rocket Power, Invader Zim, and The Adventures of Jimmy Neutron, Boy Genius, with CatDog as the hosts.', 'https://media.retroachievements.org/Images/089273.png', 'https://media.retroachievements.org/Images/089243.png', 'https://media.retroachievements.org/Images/089367.png', 'https://media.retroachievements.org/Images/089368.png', 4.4),
  (128, 25483, 'Tube Slider: The Championship of Future Formula', 'GameCube', 16, 166, 166, 166, 38, 0, 'Racing', 'Nd Cube', 'NEC', '2003-04-15', 'Tube Slider is a 2003 racing video game developed by NDcube and published by NEC Interchannel for the GameCube. It was released only in North America; a Japanese release was planned but canceled for unknown reasons. The game takes place on Earth in the middle of the 21st century, where a new sport based around tube sliding was born out of people''s desire for speed and competition after motorsports were abolished. The player can choose between one of eight futuristic formula vehicles, each one varying in terms of performance, and race against computer-controlled opponents across ten tracks divided into three sessions.', 'https://media.retroachievements.org/Images/094820.png', 'https://media.retroachievements.org/Images/094819.png', 'https://media.retroachievements.org/Images/094822.png', 'https://media.retroachievements.org/Images/094821.png', 4.4),
  (129, 25437, 'Darkened Skye', 'GameCube', 16, 161, 161, 161, 45, 0, 'Action-Adventure', 'Boston Animation', 'Simon & Schuster Interactive', '2002-11-12', 'Darkened Skye is a 2002 action-adventure game developed by Boston Animation. The game was also packaged with Outlaw Golf. Its title character is a young woman named Skye who lives in a fantasy realm searching for her mother. She can perform magic using Skittles candies as well as use her staff as a melee weapon; her staff becomes an energy weapon when used in conjunction with the Skittles. The game was released for Microsoft Windows and GameCube in North America in 2002 and the PAL regions in 2003.', 'https://media.retroachievements.org/Images/093254.png', 'https://media.retroachievements.org/Images/093255.png', 'https://media.retroachievements.org/Images/093251.png', 'https://media.retroachievements.org/Images/099079.png', 4.4),
  (130, 29803, 'Spawn: Armageddon', 'GameCube', 16, 146, 146, 146, 100, 0, 'Action-Adventure', 'Point of View', 'Namco', '2003-11-21', 'Spawn: Armageddon is a 2003 action-adventure game released for the PlayStation 2, Xbox and GameCube video game consoles. It is inspired by issues 1 through 99 of the Spawn comic book series.', 'https://media.retroachievements.org/Images/097995.png', 'https://media.retroachievements.org/Images/097448.png', 'https://media.retroachievements.org/Images/097451.png', 'https://media.retroachievements.org/Images/097452.png', 4.4),
  (131, 25467, 'Road Trip: The Arcade Edition', 'GameCube', 16, 145, 145, 145, 47, 0, NULL, NULL, NULL, '2002-12-19', 'Road Trip: The Arcade Edition, known as Gadget Racers in Europe and Choro Q! in Japan, is a racing video game released in 2002 by Takara. It is based mainly upon Road Trip Adventure, a predecessor, however was only sold for the PlayStation 2. Allowing this, weapons were added to a more racing perspective to make it an arcade version. It involves toy cars known in as Choro-Q or Penny Racers.', 'https://media.retroachievements.org/Images/095345.png', 'https://media.retroachievements.org/Images/094747.png', 'https://media.retroachievements.org/Images/094743.png', 'https://media.retroachievements.org/Images/094752.png', 4.4),
  (132, 30443, 'TMNT', 'GameCube', 16, 142, 142, 142, 92, 0, 'Beat ''em Up', 'Ubisoft', 'Ubisoft', '2007-03-20', 'Teenage Mutant Ninja Turtles (TMNT) is an American media franchise created by comic book artists Kevin Eastman and Peter Laird. It follows Leonardo, Donatello, Raphael and Michelangelo, four anthropomorphic turtle brothers trained in ninjutsu who fight evil in New York City. The franchise encompasses printed media, television series, feature films, video games, and merchandise.', 'https://media.retroachievements.org/Images/115415.png', 'https://media.retroachievements.org/Images/115287.png', 'https://media.retroachievements.org/Images/115296.png', 'https://media.retroachievements.org/Images/115294.png', 4.4),
  (133, 24974, 'Egg Mania: Eggstreme Madness', 'GameCube', 16, 137, 137, 137, 11, 0, NULL, 'HotGen', NULL, '2002-09-11', 'Egg Mania: Eggstreme Madness, also known as Eggo Mania in PAL territories, is a puzzle video game released in 2002 by HotGen. It was released for PlayStation 2, Xbox, GameCube, and Game Boy Advance.', 'https://media.retroachievements.org/Images/097533.png', 'https://media.retroachievements.org/Images/097532.png', 'https://media.retroachievements.org/Images/097530.png', 'https://media.retroachievements.org/Images/097531.png', 4.3),
  (134, 3340, 'TimeSplitters 2', 'GameCube', 16, 135, 135, 135, 222, 0, 'First-Person Shooter', 'Free Radical Design', 'Eidos Interactive', '2002-10-15', 'TimeSplitters 2 is a first-person shooter video game, developed by Free Radical Design, published by Eidos Interactive, and released in October 2002 for PlayStation 2, Xbox and GameCube. The game''s story focuses on the efforts of a space marine who seeks to recover powerful time crystals from a race of alien mutants called TimeSplitters, which leads them to taking on the form of an individual dealing with their own problems across different time periods between the 19th and 25th century. The developers focused on expanding the story element following 2000''s TimeSplitters, and features influences from various film genres, including horror, action and science fiction.', 'https://media.retroachievements.org/Images/116557.png', 'https://media.retroachievements.org/Images/107498.png', 'https://media.retroachievements.org/Images/115390.png', 'https://media.retroachievements.org/Images/115391.png', 4.3),
  (135, 30123, 'Neighbours from Hell', 'GameCube', 16, 131, 131, 131, 68, 0, 'Puzzle, Strategy', 'JoWooD Vienna', 'JoWooD Vienna', '2005-03-04', 'Neighbours from Hell is a puzzle strategy game developed and published by JoWood Productions. It was originally released for Windows in 2003, with later releases for GameCube, Xbox, Android and iOS.', 'https://media.retroachievements.org/Images/099091.png', 'https://media.retroachievements.org/Images/099236.png', 'https://media.retroachievements.org/Images/102804.png', 'https://media.retroachievements.org/Images/102806.png', 4.3),
  (136, 28607, 'Donkey Konga 2 (USA)', 'GameCube', 16, 129, 129, 129, 246, 0, 'Rhythm', 'Namco', 'Nintendo', '2005-05-09', 'Donkey Konga is a series of rhythm video games developed by Namco and published by Nintendo for the GameCube. A spin-off of the Donkey Kong series, they are played with a special controller called the DK Bongos that resemble two small bongo drums, but can optionally be played with the standard GameCube controllers.', 'https://media.retroachievements.org/Images/100547.png', 'https://media.retroachievements.org/Images/102736.png', 'https://media.retroachievements.org/Images/089721.png', 'https://media.retroachievements.org/Images/089722.png', 4.3),
  (137, 30120, 'Samurai Jack: The Shadow of Aku', 'GameCube', 16, 128, 128, 128, 62, 0, 'Action-Adventure', 'Adrenium Games', 'Sega', '2004-03-26', 'Samurai Jack: The Shadow of Aku is an action-adventure video game released in 2004 by Adrenium Games and published by Sega and based on the Samurai Jack animated television series on Cartoon Network. It is the second game based on the series after Samurai Jack: The Amulet of Time on the Game Boy Advance a year prior. The series'' original voice actors, including Phil LaMarr, Mako Iwamatsu, Jeff Bennett, John DiMaggio, and Jennifer Hale, reprised their respective roles for the game. The game was released for the PlayStation 2 and GameCube. An Xbox version of the game was planned, but never released, even though it was included on the official Xbox 360 Backwards Compatibility list.', 'https://media.retroachievements.org/Images/114907.png', 'https://media.retroachievements.org/Images/114881.png', 'https://media.retroachievements.org/Images/114301.png', 'https://media.retroachievements.org/Images/114302.png', 4.3),
  (138, 29873, '~Hack~ Friday Night Pikmin', 'GameCube', 16, 126, 126, 126, 30, 0, NULL, 'PikHacker', NULL, '2021-08-08', 'The following is a comprehensive index of all games released in 2023, sorted chronologically by release date, and divided by quarter. Information regarding developer, publisher, operating system, genre, and type of release is provided where available', 'https://media.retroachievements.org/Images/123326.png', 'https://media.retroachievements.org/Images/100488.png', 'https://media.retroachievements.org/Images/100489.png', 'https://media.retroachievements.org/Images/100490.png', 4.3),
  (139, 30280, 'Zatch Bell! Mamodo Battles', 'GameCube', 16, 126, 126, 126, 48, 0, '3D Fighting', NULL, 'Bandai', '2005-03-24', 'Zatch Bell! Mamodo Battles, known in Japan as Konjiki no Gash Bell!! Yuujou Tag Battle 2!!, is a 3D fighting game released in 2005 by Bandai. It is based on the Zatch Bell! anime and manga series by Makoto Raiku.', 'https://media.retroachievements.org/Images/103008.png', 'https://media.retroachievements.org/Images/103007.png', 'https://media.retroachievements.org/Images/102972.png', 'https://media.retroachievements.org/Images/102985.png', 4.3),
  (140, 30552, 'Pitfall: The Lost Expedition', 'GameCube', 16, 125, 125, 125, 49, 0, '3D Platforming, Metroidvania', 'Edge of Reality', 'Activision', '2004-02-19', 'Pitfall: The Lost Expedition is an action-adventure video game developed by Edge of Reality and published by Activision. Part of the Pitfall! series, it was released for the GameCube, PlayStation 2 and Xbox in 2004. An abridged version for the Game Boy Advance by Torus Games was released alongside the console versions. A Windows version developed by Beenox was released later that year. The game was also released on October 7, 2008 on the Wii as Pitfall: The Big Adventure, with it being released under the brand Fun4All in Europe. It was followed in 2012 by Pitfall! for mobile devices.', 'https://media.retroachievements.org/Images/114636.png', 'https://media.retroachievements.org/Images/114635.png', 'https://media.retroachievements.org/Images/109471.png', 'https://media.retroachievements.org/Images/109472.png', 4.3),
  (141, 30053, 'Charlie''s Angels', 'GameCube', 16, 122, 122, 122, 40, 0, 'Beat ''em Up', 'Neko Entertainment', 'Ubisoft', '2003-07-08', 'Charlie''s Angels is an American crime drama television series created by Ivan Goff and Ben Roberts for ABC. It originally aired from September 22, 1976, to June 24, 1981, airing for five seasons consisting of 115 episodes. It was produced by Spelling-Goldberg Productions. The show follows the crime-fighting adventures of three women working at a private detective agency in Los Angeles, California, and originally starred Kate Jackson, Farrah Fawcett, and Jaclyn Smith in the leading roles and John Forsythe providing the voice of their boss, the unseen Charlie Townsend, who directed the crime-fighting operations of the Angels over a speakerphone. There were a few casting changes: after the departure of Fawcett at the end of season 1, Cheryl Ladd joined in season 2 and remained in the show till the ending. When Jackson departed at the end of season 3, Shelley Hack joined for season 4, and she was subsequently replaced by Tanya Roberts in season 5.', 'https://media.retroachievements.org/Images/098731.png', 'https://media.retroachievements.org/Images/124824.png', 'https://media.retroachievements.org/Images/098722.png', 'https://media.retroachievements.org/Images/098725.png', 4.3),
  (142, 25466, 'Ribbit King', 'GameCube', 16, 121, 121, 121, 48, 0, NULL, 'Infinity, Jamsworks', 'Bandai', '2003-07-11', 'Ribbit King is a 2003 sports video game developed by Infinity and Jamsworks and published by Bandai for the GameCube and PlayStation 2. The game is based on the fictional sport of Frolf (ケロフ), which is a golf-like game that is played with frogs. The frogs sit on catapults, which the player whacks with a hammer to send the frog flying into the air. It is the successor to Kero Kero King, released only in Japan in 2000 for the PlayStation.', 'https://media.retroachievements.org/Images/100415.png', 'https://media.retroachievements.org/Images/100443.png', 'https://media.retroachievements.org/Images/100461.png', 'https://media.retroachievements.org/Images/100462.png', 4.3),
  (143, 25428, 'Bomberman Jetters', 'GameCube', 16, 118, 118, 118, 42, 0, '3D Platforming, Action', 'Hudson Soft', 'Majesco Entertainment', '2002-12-19', 'Bomberman Jetters is a 2002 Japanese anime television series produced by NAS and TV Tokyo and animated by Studio Deen. It is based on the Bomberman video game series created by Hudson Soft. The series has also spawned two manga adaptations and four video games, one of which was released internationally.', 'https://media.retroachievements.org/Images/099910.png', 'https://media.retroachievements.org/Images/098946.png', 'https://media.retroachievements.org/Images/098944.png', 'https://media.retroachievements.org/Images/098945.png', 4.3),
  (144, 30993, '~Hack~ Pikmin 2: Caveless Edition', 'GameCube', 16, 117, 117, 117, 27, 0, 'Real-Time Strategy', 'Bugabread', 'Hack - Pikmin 2', '2023-09-08', NULL, 'https://media.retroachievements.org/Images/110406.png', 'https://media.retroachievements.org/Images/102900.png', 'https://media.retroachievements.org/Images/109746.png', 'https://media.retroachievements.org/Images/109879.png', 4.3),
  (145, 30317, 'X-Men: Next Dimension', 'GameCube', 16, 110, 110, 110, 99, 0, '3D Fighting', 'Paradox Development', 'Activision', '2002-10-15', 'X-Men: Next Dimension is a fighting game, released in 2002 for the PlayStation 2, Xbox and GameCube video game consoles. It is the third installment in the X-Men: Mutant Academy fighting game series, following X-Men: Mutant Academy and X-Men: Mutant Academy 2.', 'https://media.retroachievements.org/Images/107803.png', 'https://media.retroachievements.org/Images/107782.png', 'https://media.retroachievements.org/Images/108350.png', 'https://media.retroachievements.org/Images/108351.png', 4.3),
  (146, 34511, '~Hack~ Pikmin 2: Regrown', 'GameCube', 16, 105, 105, 105, 74, 0, NULL, 'Rakton, Regrown Team', NULL, '2024-08-27', NULL, 'https://media.retroachievements.org/Images/117445.png', 'https://media.retroachievements.org/Images/117412.png', 'https://media.retroachievements.org/Images/120289.png', 'https://media.retroachievements.org/Images/120290.png', 4.3),
  (147, 30211, 'One Piece: Grand Battle', 'GameCube', 16, 104, 104, 104, 50, 0, NULL, 'Ganbarion', NULL, '2005-03-17', 'One Piece: Grand Battle is a fighting game made in Japan based on the manga series One Piece and its anime adaptation. It is the fourth and final game in One Piece''s Grand Battle series and the nineteenth One Piece video game released. The game was released in Japan as One Piece: Grand Battle! Rush. The English version uses the intro from the TV series.', 'https://media.retroachievements.org/Images/106480.png', 'https://media.retroachievements.org/Images/103747.png', 'https://media.retroachievements.org/Images/103595.png', 'https://media.retroachievements.org/Images/103596.png', 4.3),
  (148, 25485, 'Ultimate Muscle: Legends vs. New Generation', 'GameCube', 16, 98, 98, 98, 36, 0, 'Sports - Wrestling', 'AKI | syn Sophia', 'Bandai', '2002-11-22', 'Ultimate Muscle: Legends vs. New Generation, known in Japan as Kinnikuman Nisei New Generation vs. Legends , is a wrestling video game based on the anime and manga, Ultimate Muscle. It was developed in Japan by AKI Corporation and released in Japan and North America only on the GameCube. It spawned two new expansions: Galactic Wrestling: Featuring Ultimate Muscle, released only on PlayStation 2 in 2004, and Kinnikuman Muscle Generations , released in Japan on February 2, 2006 for the PlayStation Portable. This article contains explanations on the PlayStation 2 and PSP versions as well. In this game, the Choujins from the Kinnikuman (Legends) reappear via 3D Polygon and compete against the Nisei Choujins in their younger bodies.', 'https://media.retroachievements.org/Images/109564.png', 'https://media.retroachievements.org/Images/108553.png', 'https://media.retroachievements.org/Images/110557.png', 'https://media.retroachievements.org/Images/110558.png', 4.3),
  (149, 30330, 'Naruto: Gekitou Ninja Taisen! 4', 'GameCube', 16, 95, 95, 95, 135, 0, '3D Fighting', 'Raizing | Eighting', 'Tomy', '2005-11-21', 'Naruto: Clash of Ninja, released in Japan as Naruto: Gekitō Ninja Taisen! , is a series of 3D cel-shaded fighting games based on the manga and anime series Naruto by Masashi Kishimoto. They are developed by Eighting and published by D3 Publisher and Tomy. The series began with four GameCube games, with the first two available internationally and the last two released exclusively in Japan, before splitting into two parallel Wii-exclusive follow-up series: the Gekitō Ninja Taisen EX tetralogy released exclusively in Japan and its international counterpart, the Clash of Ninja: Revolution trilogy. The two Wii series share the same gameplay mechanics, but differ with respect to content and characters, with the international Revolution series being based on a localized version of the Naruto anime series. The first half of the original series and the entire Revolution trilogy are available in North America and Europe, the first two Revolution games are available in Australasia and all games in the series except the Revolution trilogy are available in Japan.', 'https://media.retroachievements.org/Images/107346.png', 'https://media.retroachievements.org/Images/100781.png', 'https://media.retroachievements.org/Images/107358.png', 'https://media.retroachievements.org/Images/109774.png', 4.3),
  (150, 25499, 'Battle Stadium D.O.N', 'GameCube', 16, 94, 94, 94, 121, 0, 'Platform Fighting', 'Raizing | Eighting', 'Bandai', '2006-07-20', 'Battle Stadium D.O.N (バトルスタジアムＤＯＮ) is a 2006 Japanese crossover fighting game developed by Eighting and Q Entertainment and published by Namco Bandai Games for the GameCube and PlayStation 2. The D.O.N. in the game''s title is derived from Dragon Ball Z, One Piece, and Naruto, the three manga series published by Weekly Shōnen Jump upon which the game is based. Both versions of the game received a rating of 26 out of 40 from Weekly Famitsu.', 'https://media.retroachievements.org/Images/113387.png', 'https://media.retroachievements.org/Images/113775.png', 'https://media.retroachievements.org/Images/113386.png', 'https://media.retroachievements.org/Images/113774.png', 4.3),
  (151, 30329, 'Naruto: Gekitou Ninja Taisen! 3', 'GameCube', 16, 90, 90, 90, 93, 0, '3D Fighting', 'Raizing | Eighting', 'Tomy', '2004-11-20', 'Naruto: Clash of Ninja, released in Japan as Naruto: Gekitō Ninja Taisen! , is a series of 3D cel-shaded fighting games based on the manga and anime series Naruto by Masashi Kishimoto. They are developed by Eighting and published by D3 Publisher and Tomy. The series began with four GameCube games, with the first two available internationally and the last two released exclusively in Japan, before splitting into two parallel Wii-exclusive follow-up series: the Gekitō Ninja Taisen EX tetralogy released exclusively in Japan and its international counterpart, the Clash of Ninja: Revolution trilogy. The two Wii series share the same gameplay mechanics, but differ with respect to content and characters, with the international Revolution series being based on a localized version of the Naruto anime series. The first half of the original series and the entire Revolution trilogy are available in North America and Europe, the first two Revolution games are available in Australasia and all games in the series except the Revolution trilogy are available in Japan.', 'https://media.retroachievements.org/Images/101802.png', 'https://media.retroachievements.org/Images/100782.png', 'https://media.retroachievements.org/Images/102579.png', 'https://media.retroachievements.org/Images/102580.png', 4.3),
  (152, 30281, 'Zatch Bell! Mamodo Fury', 'GameCube', 16, 90, 90, 90, 53, 0, NULL, 'Mechanic Arms', NULL, '2006-09-19', 'Zatch Bell! Mamodo Fury  is a fighting game released on the PlayStation 2. The original Japanese version was published by Bandai at the end of 2004, after merging with Namco but before the formation of Namco Bandai Games. The subsequent international releases and the GameCube versions were published under Namco Bandai Games. The game is based on the Zatch Bell! franchise.', 'https://media.retroachievements.org/Images/103216.png', 'https://media.retroachievements.org/Images/103213.png', 'https://media.retroachievements.org/Images/103374.png', 'https://media.retroachievements.org/Images/103373.png', 4.3),
  (153, 25423, 'Aquaman: Battle of Atlantis', 'GameCube', 16, 85, 85, 85, 35, 0, 'Action-Adventure', 'Lucky Chicken', 'TDK Mediactive', '2003-07-23', 'Atlantis, sometimes also called the Kingdom of Atlantis or the Atlantean Empire, is a fictional civilization appearing in American comic books published by DC Comics, and based upon Plato''s references to the island of Atlantis in Timaeus and Critias. First appearing in More Fun Comics #87, the setting is often associated with the hero Aquaman. Within the DC Universe, Atlantis houses various aquatic-based human lifeforms whose biological adaptations often originate from both environmental changes – after Atlantis sunk in a cataclysmic event – and influence from its magical origins. Considered a superpower, Atlantis is often stated to be among the oldest and most sophisticated civilizations in the fictional universe, and to possess significant technological and magical capabilities. Historically a hereditary monarchy, many stories involving Atlantis as a setting focuses on conflicts regarding its succession of leaders, diplomatic relations with the global world, and its fictional cultural heritage.', 'https://media.retroachievements.org/Images/098948.png', 'https://media.retroachievements.org/Images/098849.png', 'https://media.retroachievements.org/Images/098942.png', 'https://media.retroachievements.org/Images/098943.png', 4.3),
  (154, 1362, 'Baten Kaitos Origins', 'GameCube', 16, 82, 82, 82, 177, 0, 'Turn-Based RPG, Collectible Card Game', 'Monolith Soft', 'Nintendo', '2006-02-23', 'Baten Kaitos Origins, released in Japan as Baten Kaitos II, is a 2006 role-playing video game developed by Monolith Soft and Tri-Crescendo and published by Nintendo for the GameCube. It was released in February 2006 in Japan, and in North America in September 2006. It is a prequel to Baten Kaitos: Eternal Wings and the Lost Ocean (2003). Similar to the first entry, the player assume the role of a guardian spirit – an unseen player avatar – who guides protagonist Sagi and his party of companions in an adventure across an aerial floating island-based kingdom in the clouds. The game retains the original''s focus around the concept of Magnus – magical cards that capture the essence of items found in the in-game world, where the concept is still used as a plot device, for in-game item management, and as a basis for the card-themed battle system, albeit with minor tweaks. A remaster was released with its predecessor as Baten Kaitos I & II HD Remaster for the Nintendo Switch on September 15, 2023 and on Windows through Steam on June 18, 2024 by series owner Bandai Namco Entertainment under license from Nintendo.', 'https://media.retroachievements.org/Images/099107.png', 'https://media.retroachievements.org/Images/088988.png', 'https://media.retroachievements.org/Images/090992.png', 'https://media.retroachievements.org/Images/090993.png', 4.3),
  (155, 25477, 'Swingerz Golf', 'GameCube', 16, 76, 76, 76, 244, 0, NULL, NULL, NULL, '2002-10-23', 'The GameCube is Nintendo''s fourth home video game console, released during the sixth generation of video games. It is the successor to the Nintendo 64, and was first launched in Japan on September 14, 2001, followed by a launch in North America on November 18, 2001, and a launch in the PAL regions in May 2002. The successor to the GameCube is the Wii, which was first released in North America on November 19, 2006, and is backward compatible with GameCube games, memory cards, and controllers. Although later models would remove the controller ports and memory card slots required for backwards compatibility, they can be hardware modded back in. There are 651 games on this list. It is organized alphabetically by the games'' localized English titles, or by rōmaji transliterations when exclusive to Japan. For a list of games that were announced or in development for the GameCube but never released, see the list of cancelled GameCube games.', 'https://media.retroachievements.org/Images/089161.png', 'https://media.retroachievements.org/Images/088966.png', 'https://media.retroachievements.org/Images/088964.png', 'https://media.retroachievements.org/Images/088965.png', 4.3),
  (156, 28378, '~Homebrew~ Xeno Crisis', 'GameCube', 16, 73, 73, 73, 64, 0, 'Twin Stick Shooter', 'Bitmap Bureau', 'Bitmap Bureau', '2023-04-01', 'Xeno Crisis is a 2019 multidirectional shooter homebrew video game developed and published by Bitmap Bureau for the Sega Mega Drive/Genesis, Linux, macOS, Microsoft Windows, Nintendo Switch, PlayStation 4, and Xbox One. It was later ported to Dreamcast, PlayStation Vita, Neo Geo, Neo Geo CD, Nintendo 64, GameCube, Super Nintendo Entertainment System, and Game Boy Advance. The premise takes place in Outpost 88, a scientific research facility overrun by aliens. The facility sent a distress signal, leading Commander Darius dispatching space marines John Marsh and Sarah Ridley to confront the aliens. Gameplay revolves around players defeating enemies, rescuing survivors, collecting in-game currency for upgrades, and facing against bosses.', 'https://media.retroachievements.org/Images/093582.png', 'https://media.retroachievements.org/Images/114098.png', 'https://media.retroachievements.org/Images/100353.png', 'https://media.retroachievements.org/Images/100354.png', 4.3),
  (157, 30396, 'NHL Hitz 20-02', 'GameCube', 16, 73, 73, 73, 28, 0, NULL, 'EA Black Box', 'Midway', '2001-09-27', 'NHL Hitz 2002 is an arcade-style ice hockey video game released by Midway in September 2001 for PlayStation 2 and November for GameCube and Xbox. It is the first game of the NHL Hitz series. Midway launched the game along with NFL Blitz.', 'https://media.retroachievements.org/Images/110897.png', 'https://media.retroachievements.org/Images/104984.png', 'https://media.retroachievements.org/Images/110628.png', 'https://media.retroachievements.org/Images/110629.png', 4.3),
  (158, 29779, '~Hack~ Pikmin 216', 'GameCube', 16, 72, 72, 72, 67, 0, NULL, 'Teddiursayoshi', NULL, '2023-12-31', 'The Nintendo 64 is a video game console released by Nintendo in 1996. The console was a moderate success with 32.93 millions units sold; it was three times as much as one competitor, the Sega Saturn, but only a third of the sales of its other competitor, the original PlayStation. Third party game developers cancelled multiple games for the system, with commonly-cited reasons including its lower sales numbers compared to the PlayStation, its unconventional controller, and Nintendo''s decision to stick with the game cartridge format, which was more costly to produce and featured far less storage than the PlayStation''s CD-ROMs. Additionally, the brief lifespan and commercial failure of the 64DD, a Japan-only Nintendo 64 add-on, led to many of its games being cancelled, reworked for release on the standard Nintendo 64, or ported to its successor, the GameCube. This list documents games that were announced for the Nintendo 64 at some point, but did not end up being released for it in any capacity. It also documents cancelled 64DD games, as well as unreleased 64DD-specific versions of other Nintendo 64 games.', 'https://media.retroachievements.org/Images/109203.png', 'https://media.retroachievements.org/Images/096938.png', 'https://media.retroachievements.org/Images/096607.png', 'https://media.retroachievements.org/Images/096771.png', 4.3),
  (159, 29173, 'Rogue Ops', 'GameCube', 16, 67, 67, 67, 35, 0, 'Stealth', 'Bits Studios', 'Kemco', '2003-10-28', 'The GameCube is Nintendo''s fourth home video game console, released during the sixth generation of video games. It is the successor to the Nintendo 64, and was first launched in Japan on September 14, 2001, followed by a launch in North America on November 18, 2001, and a launch in the PAL regions in May 2002. The successor to the GameCube is the Wii, which was first released in North America on November 19, 2006, and is backward compatible with GameCube games, memory cards, and controllers. Although later models would remove the controller ports and memory card slots required for backwards compatibility, they can be hardware modded back in. There are 651 games on this list. It is organized alphabetically by the games'' localized English titles, or by rōmaji transliterations when exclusive to Japan. For a list of games that were announced or in development for the GameCube but never released, see the list of cancelled GameCube games.', 'https://media.retroachievements.org/Images/094823.png', 'https://media.retroachievements.org/Images/093778.png', 'https://media.retroachievements.org/Images/094825.png', 'https://media.retroachievements.org/Images/094824.png', 4.2),
  (160, 32108, '~Hack~ SpongeBob and the Pit of 100 Trials', 'GameCube', 16, 66, 66, 66, 11, 0, '3D Platforming', 'Gravity', NULL, '2023-08-02', 'A platformer is a subgenre of action game in which the core objective is to move the player character between points in an environment. Platform games are characterized by levels with uneven terrain and suspended platforms that require jumping and climbing to traverse. Other acrobatic maneuvers may factor into the gameplay, such as swinging from vines or grappling hooks, jumping off walls, gliding through the air, or bouncing from springboards or trampolines.', 'https://media.retroachievements.org/Images/110456.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/109692.png', 'https://media.retroachievements.org/Images/109691.png', 4.2),
  (161, 31898, '~Hack~ Super Doot Sunshine', 'GameCube', 16, 52, 52, 52, 345, 0, '3D Platforming, Collect-a-thon', 'warspyking', 'Hack - Super Mario Sunshine', '2023-09-25', 'Kaizo  is a philosophy of game design, specifically platforming games, distinguished by a high degree of strictness placed upon the player''s intended actions and movements through a level. This emphasis on precision, which manifests in the form of extremely-precise character movement, requires the player to use high levels of skill and knowledge of the game''s physics and engine in order to accomplish tasks. The philosophy is most closely associated with ROM hacks of Super Mario World and with custom levels created in Super Mario Maker and Super Mario Maker 2, but has been cited as an influence in other fan-made and original game designs.', 'https://media.retroachievements.org/Images/123632.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/105127.png', 'https://media.retroachievements.org/Images/105128.png', 4.2),
  (162, 30342, 'Black & Bruised', 'GameCube', 16, 52, 52, 52, 62, 0, 'Sports - Boxing', 'Digital Fiction', 'Majesco Entertainment', '2003-01-28', 'The GameCube is Nintendo''s fourth home video game console, released during the sixth generation of video games. It is the successor to the Nintendo 64, and was first launched in Japan on September 14, 2001, followed by a launch in North America on November 18, 2001, and a launch in the PAL regions in May 2002. The successor to the GameCube is the Wii, which was first released in North America on November 19, 2006, and is backward compatible with GameCube games, memory cards, and controllers. Although later models would remove the controller ports and memory card slots required for backwards compatibility, they can be hardware modded back in. There are 651 games on this list. It is organized alphabetically by the games'' localized English titles, or by rōmaji transliterations when exclusive to Japan. For a list of games that were announced or in development for the GameCube but never released, see the list of cancelled GameCube games.', 'https://media.retroachievements.org/Images/100210.png', 'https://media.retroachievements.org/Images/105877.png', 'https://media.retroachievements.org/Images/106129.png', 'https://media.retroachievements.org/Images/106130.png', 4.2),
  (163, 6958, 'Tomb Raider: Legend', 'GameCube', 16, 49, 49, 49, 47, 0, 'Action-Adventure, Cinematic Platforming', 'Nixxes Software', 'Eidos Interactive', '2006-11-14', 'Tomb Raider: Legend is a 2006 action-adventure video game developed by Crystal Dynamics and published by Eidos Interactive. It is the seventh main entry in the Tomb Raider series, and is described as a reimagining of the series and its protagonist Lara Croft. The game was released in 2006 for PlayStation 2, Windows, Xbox, Xbox 360, PlayStation Portable, GameCube, Game Boy Advance, Nintendo DS, and mobile phones. A PlayStation 3 port was released in 2011 as part of The Tomb Raider Trilogy.', 'https://media.retroachievements.org/Images/090873.png', 'https://media.retroachievements.org/Images/090872.png', 'https://media.retroachievements.org/Images/090870.png', 'https://media.retroachievements.org/Images/090871.png', 4.2),
  (164, 30473, 'Cocoto Funfair', 'GameCube', 16, 45, 45, 45, 14, 0, 'Gallery Shooter', 'Neko Entertainment', 'Bigben Interactive', '2006-04-07', 'The GameCube is Nintendo''s fourth home video game console, released during the sixth generation of video games. It is the successor to the Nintendo 64, and was first launched in Japan on September 14, 2001, followed by a launch in North America on November 18, 2001, and a launch in the PAL regions in May 2002. The successor to the GameCube is the Wii, which was first released in North America on November 19, 2006, and is backward compatible with GameCube games, memory cards, and controllers. Although later models would remove the controller ports and memory card slots required for backwards compatibility, they can be hardware modded back in. There are 651 games on this list. It is organized alphabetically by the games'' localized English titles, or by rōmaji transliterations when exclusive to Japan. For a list of games that were announced or in development for the GameCube but never released, see the list of cancelled GameCube games.', 'https://media.retroachievements.org/Images/101575.png', 'https://media.retroachievements.org/Images/113979.png', 'https://media.retroachievements.org/Images/114024.png', 'https://media.retroachievements.org/Images/114841.png', 4.2),
  (165, 30543, 'Muppets Party Cruise', 'GameCube', 16, 45, 45, 45, 79, 0, 'Party, Board Game', 'Mass Media', 'TDK Mediactive', '2003-11-13', 'Muppets Party Cruise is a 2003 party video game, based on The Muppets franchise, developed by Mass Media and published by TDK Mediactive for the PlayStation 2 and GameCube.', 'https://media.retroachievements.org/Images/116295.png', 'https://media.retroachievements.org/Images/114978.png', 'https://media.retroachievements.org/Images/115107.png', 'https://media.retroachievements.org/Images/115108.png', 4.2),
  (166, 33481, '~Hack~ Bad-Boon Strikes Back v4.0', 'GameCube', 16, 44, 44, 44, 51, 0, '3D Platforming', 'KartingKoopa', 'Hack - Super Monkey Ball 2', '2023-08-12', NULL, 'https://media.retroachievements.org/Images/110930.png', 'https://media.retroachievements.org/Images/110933.png', 'https://media.retroachievements.org/Images/110932.png', 'https://media.retroachievements.org/Images/110931.png', 4.2),
  (167, 31185, '~Hack~ dart monkey 1.5143', 'GameCube', 16, 37, 37, 37, 27, 0, '3D Platforming', 'SHK', 'Hack - Super Monkey Ball 2', '2024-04-01', NULL, 'https://media.retroachievements.org/Images/110848.png', 'https://media.retroachievements.org/Images/110851.png', 'https://media.retroachievements.org/Images/110845.png', 'https://media.retroachievements.org/Images/110846.png', 4.2),
  (168, 32112, '~Hack~ Floating Block Forever', 'GameCube', 16, 28, 28, 28, 13, 0, '3D Platforming', 'Eyepie', NULL, '2023-03-13', 'Fez is a 2012 indie puzzle-platform game developed by Polytron Corporation and published by Trapdoor. The player-character Gomez receives a fez that reveals his two-dimensional (2D) world to be one of four sides of a three-dimensional (3D) world. The player rotates between these four 2D views to realign platforms and solve puzzles. The objective is to collect cubes and cube fragments to restore order to the universe.', 'https://media.retroachievements.org/Images/124647.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/124612.png', 'https://media.retroachievements.org/Images/124613.png', 4.1),
  (169, 30888, '~Hack~ Resident Evil 2: Zombie Crisis', 'GameCube', 16, 27, 27, 27, 32, 0, NULL, 'Hunter Beta2', 'Hack - Resident Evil 2', '2021-05-28', 'Resident Evil 2 is a 1998 survival horror video game developed and published by Capcom for the PlayStation. It is the second main installment in the Resident Evil series. The player controls rookie cop Leon S. Kennedy and college student Claire Redfield, who must escape Raccoon City after its citizens are transformed into zombies by a biological weapon two months after the events of the original Resident Evil. The gameplay focuses on exploration, puzzles, and combat; the main difference from its predecessor are the branching paths, with each player character having unique storylines, partners and obstacles.', 'https://media.retroachievements.org/Images/101715.png', 'https://media.retroachievements.org/Images/104938.png', 'https://media.retroachievements.org/Images/101664.png', 'https://media.retroachievements.org/Images/101665.png', 4.1),
  (170, 28264, 'Super Bubble Pop', 'GameCube', 16, 27, 27, 27, 40, 0, NULL, 'Runecraft', 'Jaleco', '2003-01-03', 'Super Bubble Pop is a puzzle video game released in 2002 by Runecraft.', 'https://media.retroachievements.org/Images/107518.png', 'https://media.retroachievements.org/Images/088152.png', 'https://media.retroachievements.org/Images/089162.png', 'https://media.retroachievements.org/Images/107517.png', 4.1),
  (171, 25448, 'Judge Dredd: Dredd vs. Death', 'GameCube', 16, 25, 25, 25, 65, 0, 'First-Person Shooter', 'Rebellion', 'Evolved Games', '2003-12-12', 'Judge Dredd: Dredd vs. Death is a first-person shooter video game based on the Judge Dredd character from the 2000 AD comic series, developed by Rebellion Developments.', 'https://media.retroachievements.org/Images/121362.png', 'https://media.retroachievements.org/Images/113091.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/000002.png', 4.1),
  (172, 36636, '~Hack~ Metroid Prime: Double Trouble', 'GameCube', 16, 16, 16, 16, 34, 0, 'Metroidvania, 3D Platforming, First-Person Shooter', 'Fantaselion', 'Hack - Metroid Prime', '2021-06-01', 'The Nintendo GameCube is a home video game console developed and marketed by Nintendo. It was released in Japan on September 14, 2001, in North America on November 18, 2001, and in Europe on May 3, 2002. It is Nintendo''s fourth major home console, succeeding the Nintendo 64, and competed with Sony''s PlayStation 2 and Microsoft''s Xbox in the sixth generation of game consoles.', 'https://media.retroachievements.org/Images/120769.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/120767.png', 'https://media.retroachievements.org/Images/120768.png', 4),
  (173, 30122, 'Metal Gear Solid: The Twin Snakes - Special Disc', 'GameCube', 16, 13, 13, 13, 43, 0, 'Stealth', 'Konami', 'Konami', '2004-03-11', 'Metal Gear Solid: The Twin Snakes is a 2004 action-adventure stealth game developed by Konami and Silicon Knights and published by Konami for the GameCube. It is a remake of 1998''s Metal Gear Solid.', 'https://media.retroachievements.org/Images/099073.png', 'https://media.retroachievements.org/Images/099070.png', 'https://media.retroachievements.org/Images/099071.png', 'https://media.retroachievements.org/Images/099072.png', 4);
INSERT INTO games (rank, id, title, consoleName, consoleId, totalPlayers, casualPlayers, hardcorePlayers, numAchievements, points, genre, developer, publisher, released, description, icon, boxArt, titleScreen, screenshot, rating) VALUES
  (1, 668, 'Pokémon Emerald Version', 'Game Boy Advance', 5, 35078, 35078, 35078, 197, 0, 'Turn-Based RPG', 'Game Freak', 'Nintendo', '2004-09-16', 'Pokémon Emerald Version is a 2004 role-playing video game developed by Game Freak and published by The Pokémon Company and Nintendo for the Game Boy Advance. It was first released in Japan in 2004, and was later released internationally in 2005. It is the fifth version, after both Pokémon Ruby and Sapphire and Pokémon FireRed and LeafGreen, and is the final game of the third generation of the Pokémon video game series.', 'https://media.retroachievements.org/Images/104473.png', 'https://media.retroachievements.org/Images/014406.png', 'https://media.retroachievements.org/Images/005442.png', 'https://media.retroachievements.org/Images/077264.png', 5),
  (2, 534, 'Metroid: Zero Mission', 'Game Boy Advance', 5, 31244, 31244, 31244, 55, 0, 'Metroidvania', NULL, 'Nintendo', '2004-02-09', 'Metroid: Zero Mission is a 2004 action-adventure game developed and published by Nintendo for the Game Boy Advance. It is a remake of the original Metroid (1986), with updated visuals and gameplay.', 'https://media.retroachievements.org/Images/093574.png', 'https://media.retroachievements.org/Images/096231.png', 'https://media.retroachievements.org/Images/000655.png', 'https://media.retroachievements.org/Images/065313.png', 5),
  (3, 510, 'Castlevania: Aria of Sorrow', 'Game Boy Advance', 5, 28476, 28476, 28476, 66, 0, '2D Platforming, Action RPG, Metroidvania', 'Konami', 'Konami', '2003-05-06', 'Castlevania: Aria of Sorrow is a 2003 action role-playing game developed by Konami Computer Entertainment Tokyo and published by Konami for the Game Boy Advance. It is the 20th main entry in the Castlevania series, as well as the third and final game produced for the system. Producer Koji Igarashi, who had led the production teams for previous Castlevania games, led Aria of Sorrow''s development as well. Michiru Yamane returned to compose the music alongside Takashi Yoshida and Soshiro Hokkai. Director Junichi Murakami was new to the Castlevania series.', 'https://media.retroachievements.org/Images/085857.png', 'https://media.retroachievements.org/Images/071775.png', 'https://media.retroachievements.org/Images/071777.png', 'https://media.retroachievements.org/Images/071776.png', 5),
  (4, 515, 'Pokémon FireRed Version', 'Game Boy Advance', 5, 25947, 25947, 25947, 61, 0, 'Turn-Based RPG', 'Game Freak', 'Nintendo', '2004-01-29', 'Pokémon FireRed Version and Pokémon LeafGreen Version are 2004 remakes of the 1996 role-playing video games Pokémon Red and Blue. They were developed by Game Freak and published by The Pokémon Company and Nintendo for the Game Boy Advance. FireRed and LeafGreen were first released in Japan in January 2004 and in North America and Europe in September and October 2004, respectively. The games are part of the third generation of the Pokémon video game series and hold the distinction of being the first enhanced remakes of previous games within the franchise.', 'https://media.retroachievements.org/Images/105044.png', 'https://media.retroachievements.org/Images/001918.png', 'https://media.retroachievements.org/Images/001917.png', 'https://media.retroachievements.org/Images/111883.png', 4.9),
  (5, 559, 'The Legend of Zelda: The Minish Cap', 'Game Boy Advance', 5, 21579, 21579, 21579, 66, 0, 'Action-Adventure', 'Capcom', 'Nintendo', '2004-11-04', 'The Legend of Zelda: The Minish Cap is a 2004 action-adventure game developed by Capcom and Flagship and published by Nintendo for the Game Boy Advance. The twelfth entry in The Legend of Zelda series, The Minish Cap was released for the Game Boy Advance in Japan and Europe in 2004 and in North America and Australia the following year.', 'https://media.retroachievements.org/Images/113471.png', 'https://media.retroachievements.org/Images/000156.png', 'https://media.retroachievements.org/Images/033839.png', 'https://media.retroachievements.org/Images/000049.png', 4.9),
  (6, 770, 'Kirby: Nightmare in Dream Land', 'Game Boy Advance', 5, 19218, 19218, 19218, 70, 0, NULL, 'HAL Laboratory', 'Nintendo', '2002-10-25', 'Kirby''s Adventure is a 1993 platform game developed by HAL Laboratory and published by Nintendo for the Nintendo Entertainment System (NES). It is the second game in the Kirby series after Kirby''s Dream Land (1992) on the Game Boy and the first to include the Copy Ability, which allows the main character Kirby to gain new powers by eating certain enemies. The game centers around Kirby traveling across Dream Land to repair the Star Rod after King Dedede breaks it apart and gives the pieces to his minions.', 'https://media.retroachievements.org/Images/122187.png', 'https://media.retroachievements.org/Images/124461.png', 'https://media.retroachievements.org/Images/033745.png', 'https://media.retroachievements.org/Images/002594.png', 4.9),
  (7, 802, 'WarioWare, Inc.: Mega Microgame$!', 'Game Boy Advance', 5, 18393, 18393, 18393, 47, 0, 'Minigames', NULL, 'Nintendo', '2003-03-21', 'WarioWare, Inc.: Mega Microgames!, known as WarioWare, Inc.: Minigame Mania in PAL regions, is a 2003 action game developed and published by Nintendo for the Game Boy Advance. The debut title in the WarioWare series, the game is about rapid completion of "microgames", short minigames given to the player consecutively and with increasing speed per each game complete. The game''s concept was inspired by the "Sound Bomber" mode of Mario Artist: Polygon Studio for the Nintendo 64DD. Many of the music tracks and sound effects were recycled from Wario Land 4. The game was produced by Takehiro Izushi and directed by Hirofumi Matsuoka. Matsuoka was also the director of Polygon Studio. Mega Microgames! was released in 2003; in Japan in March, in North America and Europe in May and in Australia in June.', 'https://media.retroachievements.org/Images/105321.png', 'https://media.retroachievements.org/Images/089239.png', 'https://media.retroachievements.org/Images/109611.png', 'https://media.retroachievements.org/Images/109612.png', 4.8),
  (8, 793, 'Sonic Advance', 'Game Boy Advance', 5, 18115, 18115, 18115, 58, 0, '2D Platforming', 'Dimps, Sonic Team', 'Sega, THQ', '2001-12-20', 'Sonic Advance is a 2001 platform game developed by Sonic Team and Dimps and published by Sega for the Game Boy Advance. It was one of the first Sonic the Hedgehog games to be released on a Nintendo console along with Sonic Adventure 2: Battle on the GameCube, and was produced in commemoration of the series'' tenth anniversary. The story follows Sonic, Tails, Knuckles, and Amy as they journey to stop Doctor Eggman from taking over the world. Controlling a character, players are tasked with completing each level, defeating Eggman and his robot army, and collecting the seven Chaos Emeralds.', 'https://media.retroachievements.org/Images/044233.png', 'https://media.retroachievements.org/Images/119088.png', 'https://media.retroachievements.org/Images/003925.png', 'https://media.retroachievements.org/Images/064085.png', 4.8),
  (9, 17530, '~Hack~ Pokémon Unbound', 'Game Boy Advance', 5, 16333, 16333, 16333, 129, 0, 'Turn-Based RPG', 'Skeli', NULL, '2020-12-01', 'The following is a list of notable vehicle racing video games. The genre first emerged in the mid- to late 1970s.', 'https://media.retroachievements.org/Images/073204.png', 'https://media.retroachievements.org/Images/067057.png', 'https://media.retroachievements.org/Images/069748.png', 'https://media.retroachievements.org/Images/042903.png', 4.8),
  (10, 771, 'Mario & Luigi: Superstar Saga', 'Game Boy Advance', 5, 15368, 15368, 15368, 85, 0, 'Turn-Based RPG', 'AlphaDream', 'Nintendo', '2003-11-17', 'Mario & Luigi: Superstar Saga is a 2003 role-playing video game developed by AlphaDream and published by Nintendo for the Game Boy Advance. It is the first game in the Mario & Luigi series. The story follows Mario and Luigi as they travel to the Beanbean Kingdom in order to combat Cackletta and Fawful, who stole Princess Peach''s voice for the purpose of harnessing the power of a special artifact called the Beanstar.', 'https://media.retroachievements.org/Images/116411.png', 'https://media.retroachievements.org/Images/014492.png', 'https://media.retroachievements.org/Images/071816.png', 'https://media.retroachievements.org/Images/002111.png', 4.8),
  (11, 745, 'Castlevania: Circle of the Moon', 'Game Boy Advance', 5, 15104, 15104, 15104, 109, 0, '2D Platforming, Metroidvania', 'Konami', 'Konami', '2001-03-21', 'Castlevania: Circle of the Moon, titled Castlevania in PAL regions, is a 2001 action role-playing game developed and published by Konami for the Game Boy Advance handheld game console. The game was developed as a stand-alone title in the Castlevania series and as a launch title for the Game Boy Advance.', 'https://media.retroachievements.org/Images/105343.png', 'https://media.retroachievements.org/Images/072393.png', 'https://media.retroachievements.org/Images/071781.png', 'https://media.retroachievements.org/Images/071782.png', 4.8),
  (12, 789, 'Pokémon Pinball: Ruby & Sapphire', 'Game Boy Advance', 5, 14227, 14227, 14227, 54, 0, 'Pinball', 'Jupiter', 'Nintendo', '2003-08-01', 'Pokémon Pinball: Ruby & Sapphire is a 2003 pinball game developed by Jupiter and published by The Pokémon Company and Nintendo for the Game Boy Advance handheld game console. It was first revealed at E3 2003. The North American release was done to coincide with the fifth anniversary of the North American release of Pokémon Red and Blue. It is based on Pokémon Ruby and Sapphire, and is a sequel to Pokémon Pinball for the Game Boy Color. In some ways, it plays like a traditional pinball game, where the objective is to get a high score by keeping the ball in play as long as possible and hitting bumpers. In keeping with the theme of Pokémon, it features Pokémon collection, where while the players play pinball, they must also capture the eponymous creatures.', 'https://media.retroachievements.org/Images/092736.png', 'https://media.retroachievements.org/Images/000660.png', 'https://media.retroachievements.org/Images/000658.png', 'https://media.retroachievements.org/Images/077265.png', 4.8),
  (13, 769, 'Kirby & The Amazing Mirror', 'Game Boy Advance', 5, 13512, 13512, 13512, 54, 0, '2D Platforming, Metroidvania', 'HAL Laboratory, Flagship, Dimps', 'Nintendo', '2004-04-15', 'Kirby & The Amazing Mirror is a 2004 platform game developed by HAL Laboratory, Flagship and Dimps and published by Nintendo for the Game Boy Advance. The seventh mainline Kirby entry, the game is notable for its unique Metroidvania playstyle and being the first in the genre to support cooperative four-player multiplayer, and follows Kirby as he goes on a journey through the Mirror Dimension to reassemble a mirror after Dark Meta Knight traps Meta Knight inside it.', 'https://media.retroachievements.org/Images/042405.png', 'https://media.retroachievements.org/Images/014483.png', 'https://media.retroachievements.org/Images/118666.png', 'https://media.retroachievements.org/Images/118667.png', 4.8),
  (14, 580, 'The Legend of Zelda: A Link to the Past & Four Swords', 'Game Boy Advance', 5, 13240, 13240, 13240, 62, 0, 'Action-Adventure', 'Capcom', 'Nintendo', '2003-12-02', 'The Legend of Zelda: A Link to the Past and Four Swords is a 2002 action-adventure game compilation developed by Nintendo R&D2 and Flagship and published by Nintendo for the Game Boy Advance. The game was released in December 2002 in North America and in March 2003 in Japan and Europe. The cartridge contains a modified port of A Link to the Past, originally released for the Super Nintendo Entertainment System in 1991, and an original multiplayer-only game titled Four Swords, which serves as the ninth installment in The Legend of Zelda series.', 'https://media.retroachievements.org/Images/063671.png', 'https://media.retroachievements.org/Images/022503.png', 'https://media.retroachievements.org/Images/033841.png', 'https://media.retroachievements.org/Images/000078.png', 4.8),
  (15, 767, 'Golden Sun', 'Game Boy Advance', 5, 12203, 12203, 12203, 60, 0, 'Turn-Based RPG', 'Camelot Software Planning', 'Nintendo', '2001-11-11', 'Golden Sun is a series of fantasy role-playing video games developed by Camelot Software Planning and published by Nintendo. It follows the story of a group of magically attuned "adepts" who are charged with preventing the potentially destructive power of alchemy from being released as it was in the past. Players navigate characters through the game''s world by defeating enemies, solving puzzles, and completing assigned missions to complete the storyline.', 'https://media.retroachievements.org/Images/059231.png', 'https://media.retroachievements.org/Images/067993.png', 'https://media.retroachievements.org/Images/033743.png', 'https://media.retroachievements.org/Images/006544.png', 4.7),
  (16, 526, 'Crash Bandicoot: The Huge Adventure', 'Game Boy Advance', 5, 9246, 9246, 9246, 74, 0, '2D Platforming', 'Vicarious Visions', 'Universal Interactive', '2002-02-26', 'Crash Bandicoot: The Huge Adventure is a 2002 platform game developed by Vicarious Visions and published by Universal Interactive for the Game Boy Advance. It is the seventh installment in the Crash Bandicoot video game series, the first Crash Bandicoot game not to be released on a PlayStation console, and the first Crash Bandicoot game to be released on a handheld console. The game''s story centers on a plot to shrink the Earth by the main antagonist, Doctor Neo Cortex, through the use of a gigantic weapon named the "Planetary Minimizer". The protagonist of the story, Crash Bandicoot, must gather Crystals in order to power a device that will return the Earth to its proper size, defeating Cortex and his minions along the way.', 'https://media.retroachievements.org/Images/081317.png', 'https://media.retroachievements.org/Images/096395.png', 'https://media.retroachievements.org/Images/004381.png', 'https://media.retroachievements.org/Images/070480.png', 4.7),
  (17, 782, 'Mega Man Zero', 'Game Boy Advance', 5, 8811, 8811, 8811, 44, 0, '2D Platforming, Action', 'Inti Creates', 'Capcom', '2002-04-26', 'Mega Man Zero is a hack and slash platform game series in Capcom''s Mega Man video game franchise. It was developed by Inti Creates, with Co-Producer Keiji Inafune and Director Yoshinori Kawano. The series consists of four games that were first released on the Game Boy Advance and later on the Nintendo DS and the Virtual Console.', 'https://media.retroachievements.org/Images/025922.png', 'https://media.retroachievements.org/Images/001879.png', 'https://media.retroachievements.org/Images/001877.png', 'https://media.retroachievements.org/Images/001878.png', 4.7),
  (18, 677, 'Mother 3', 'Game Boy Advance', 5, 8772, 8772, 8772, 132, 0, 'Turn-Based RPG', 'Brownie Brown, HAL Laboratory', 'Nintendo', '2006-04-20', 'Mother 3 is a 2006 role-playing video game developed by Brownie Brown and HAL Laboratory and published by Nintendo for the Game Boy Advance. It is the third and final entry in the Mother series. The game follows Lucas, a young boy with psychic abilities, and a party of characters as they attempt to prevent a mysterious invading army from corrupting and destroying the world.', 'https://media.retroachievements.org/Images/122954.png', 'https://media.retroachievements.org/Images/046366.png', 'https://media.retroachievements.org/Images/001812.png', 'https://media.retroachievements.org/Images/001813.png', 4.7),
  (19, 5068, 'Alien Hominid', 'Game Boy Advance', 5, 8472, 8472, 8472, 26, 0, 'Run & Gun', 'Tuna Technologies', 'Zoo Digital Publishing | Zushi Games', '2006-02-03', 'Alien Hominid is a run and gun video game developed by The Behemoth and first released as a Flash game on the multimedia website Newgrounds on August 7, 2002. It was originally developed in Adobe Flash by programmer and Newgrounds founder, Tom Fulp, and animator and artist, Dan Paladin. An expanded console version released on the PlayStation 2, GameCube and Xbox across 2004 and 2005. A port for the Game Boy Advance, developed by Tuna Technologies, was released in 2006 for PAL regions. A high-definition version titled Alien Hominid 360 was released for Xbox 360 via Xbox Live Arcade in 2007. Another remaster, Alien Hominid HD, was released for Windows, Nintendo Switch, Xbox One and Xbox Series X/S alongside its sequel, Alien Hominid Invasion, in 2023, and again in 2025 for PlayStation 4 and PlayStation 5.', 'https://media.retroachievements.org/Images/067756.png', 'https://media.retroachievements.org/Images/014430.png', 'https://media.retroachievements.org/Images/003123.png', 'https://media.retroachievements.org/Images/003125.png', 4.7),
  (20, 750, 'Donkey Kong Country', 'Game Boy Advance', 5, 7911, 7911, 7911, 80, 0, '2D Platforming', 'Rare', 'Nintendo', '2003-06-09', 'Donkey Kong Country, known in Japan as Super Donkey Kong, is a 1994 platform game developed by Rare and published by Nintendo for the Super Nintendo Entertainment System (SNES). It follows the gorilla Donkey Kong and his nephew Diddy Kong as they set out to recover their stolen banana hoard from the crocodile King K. Rool and his army, the Kremlings. The player traverses 40 side-scrolling levels as they jump between platforms and avoid obstacles. They collect items, ride minecarts and animals, defeat enemies and bosses, and find secret bonus stages. In multiplayer modes, two players work cooperatively or race.', 'https://media.retroachievements.org/Images/072187.png', 'https://media.retroachievements.org/Images/014451.png', 'https://media.retroachievements.org/Images/083145.png', 'https://media.retroachievements.org/Images/083146.png', 4.6),
  (21, 2816, 'Pokémon Mystery Dungeon: Red Rescue Team', 'Game Boy Advance', 5, 7204, 7204, 7204, 128, 0, 'Roguelike', 'Chunsoft', 'Nintendo', '2005-11-17', 'Pokémon Mystery Dungeon: Blue Rescue Team and Pokémon Mystery Dungeon: Red Rescue Team are a matched pair of Pokémon video games for the Nintendo DS and Game Boy Advance, respectively. The games were developed by Chunsoft and published by The Pokémon Company and Nintendo. Red Rescue Team was the last Pokémon game released for the Game Boy Advance. The two versions are mostly identical, with Blue Rescue Team taking advantage of the dual-screen features and increased graphical and sound capabilities of the Nintendo DS. The game has six Pokémon exclusive to each version. Mystery Dungeon is quite different than the main-line games, as in the Mystery Dungeon games, you play as a Pokémon, as opposed to playing as a trainer.', 'https://media.retroachievements.org/Images/050264.png', 'https://media.retroachievements.org/Images/021995.png', 'https://media.retroachievements.org/Images/068561.png', 'https://media.retroachievements.org/Images/068563.png', 4.6),
  (22, 2445, 'Mario Pinball Land', 'Game Boy Advance', 5, 7195, 7195, 7195, 68, 0, 'Pinball', 'Fuse Games | Silverball Studios', 'Nintendo', '2004-08-26', 'Mario Pinball Land, known in Europe and Japan as Super Mario Ball, is a 2004 pinball video game developed by Fuse Games and published by Nintendo for the Game Boy Advance. It is a spin-off of the Super Mario series. The game was later re-released for the Wii U Virtual Console.', 'https://media.retroachievements.org/Images/034679.png', 'https://media.retroachievements.org/Images/071266.png', 'https://media.retroachievements.org/Images/003675.png', 'https://media.retroachievements.org/Images/003676.png', 4.6),
  (23, 554, 'Fire Emblem: The Blazing Blade', 'Game Boy Advance', 5, 6965, 6965, 6965, 87, 0, 'Tactical RPG', 'Intelligent Systems', 'Nintendo', '2003-11-03', 'Fire Emblem: The Blazing Blade, also known simply as Fire Emblem, is a 2003 tactical role-playing game developed by Intelligent Systems and published by Nintendo for the Game Boy Advance. It is the seventh installment in the Fire Emblem series, the second to be released for the platform after Fire Emblem: The Binding Blade, and the first to be localized for international audiences. It was released in Japan and North America in 2003, and in Europe and Australia in 2004.', 'https://media.retroachievements.org/Images/042758.png', 'https://media.retroachievements.org/Images/089241.png', 'https://media.retroachievements.org/Images/033779.png', 'https://media.retroachievements.org/Images/005927.png', 4.6),
  (24, 790, 'Pokémon Ruby Version', 'Game Boy Advance', 5, 6964, 6964, 6964, 49, 0, NULL, NULL, NULL, '2002-11-21', 'Pokémon Ruby Version and Pokémon Sapphire Version are 2002 role-playing video games developed by Game Freak and published by The Pokémon Company and Nintendo for the Game Boy Advance. They are the first installments in the third generation of the Pokémon video game series, also known as the "advanced generation". After years of Nintendo being the sole publisher of the franchise in all regions, The Pokémon Company co-published the games for the first time since the establishment of the joint-owned company in 1998. They were first released in Japan in late 2002, and internationally in 2003. Pokémon Emerald, a third version, was released two years later in each region. Remakes of the two games, titled Pokémon Omega Ruby and Alpha Sapphire, were released for the Nintendo 3DS worldwide in November 2014, exactly twelve years to the date of the original Ruby and Sapphire release date, with the exception of Europe, where it released a week later.', 'https://media.retroachievements.org/Images/104260.png', 'https://media.retroachievements.org/Images/077260.png', 'https://media.retroachievements.org/Images/014934.png', 'https://media.retroachievements.org/Images/077261.png', 4.6),
  (25, 1376, 'Dragon Ball: Advanced Adventure', 'Game Boy Advance', 5, 6669, 6669, 6669, 44, 0, '2D Platforming, Beat ''em Up', 'Dimps', 'Atari, Bandai, Banpresto', '2004-11-18', 'Dragon Ball: Advanced Adventure is a 2004 video game released for Game Boy Advance based on the Dragon Ball franchise.', 'https://media.retroachievements.org/Images/051641.png', 'https://media.retroachievements.org/Images/112816.png', 'https://media.retroachievements.org/Images/009003.png', 'https://media.retroachievements.org/Images/009004.png', 4.6),
  (26, 557, 'Sonic Advance 2', 'Game Boy Advance', 5, 6456, 6456, 6456, 40, 0, '2D Platforming', 'Dimps, Sonic Team', 'Sega, THQ', '2002-12-19', 'Sonic Advance 2 is a 2002 platform game developed by Dimps and published by Sega for the Game Boy Advance. It is an installment in the Sonic the Hedgehog series and the sequel to 2001''s Sonic Advance. The story follows Sonic as he sets out to save his friends and retrieve the seven magical Chaos Emeralds from Dr. Eggman. Gameplay consists of the player completing various levels as one of five characters, each with their own unique attributes. After each zone is completed, the player faces Dr. Eggman in a boss battle.', 'https://media.retroachievements.org/Images/044234.png', 'https://media.retroachievements.org/Images/119087.png', 'https://media.retroachievements.org/Images/003937.png', 'https://media.retroachievements.org/Images/108905.png', 4.6),
  (27, 505, 'Super Mario Advance', 'Game Boy Advance', 5, 6344, 6344, 6344, 81, 0, '2D Platforming', 'Nintendo', 'Nintendo, iQue', '2001-03-21', 'Super Mario Advance is a 2001 platform game developed and published by Nintendo as a launch title for the Game Boy Advance (GBA). It is an enhanced remake of the NES video game Super Mario Bros. 2 (1988), using the graphical style of Super Mario All-Stars (1993). Players control Mario, Luigi, Peach, or Toad as they travel through the seven worlds of Subcon to save the kingdom from the evil toad Wart. It contains several additions, including voice clips for all playable characters, giant renditions of objects, and a multiplayer mode based on the original Mario Bros. arcade game.', 'https://media.retroachievements.org/Images/035249.png', 'https://media.retroachievements.org/Images/110910.png', 'https://media.retroachievements.org/Images/108511.png', 'https://media.retroachievements.org/Images/002834.png', 4.6),
  (28, 762, 'Final Fantasy I & II: Dawn of Souls', 'Game Boy Advance', 5, 6096, 6096, 6096, 69, 0, NULL, 'Square Enix', 'Nintendo, Square Enix', '2004-11-29', 'Final Fantasy is a 1987 role-playing video game developed and published by Square for the Nintendo Entertainment System. It is the first game in Square''s Final Fantasy series, created by Hironobu Sakaguchi. The story follows four youths called the Warriors of Light, who each carry one of their world''s four elemental crystals which have been darkened by the four Elemental Fiends. Together, they quest to defeat these evil forces, restore light to the crystals, and save their world.', 'https://media.retroachievements.org/Images/059662.png', 'https://media.retroachievements.org/Images/014469.png', 'https://media.retroachievements.org/Images/006118.png', 'https://media.retroachievements.org/Images/006119.png', 4.6),
  (29, 794, 'Sonic Advance 3', 'Game Boy Advance', 5, 6054, 6054, 6054, 63, 0, '2D Platforming', 'Dimps, Sonic Team', 'Sega, THQ', '2004-01-01', 'Sonic Advance 3 is a 2004 platform game developed by Sonic Team and Dimps and published by Sega for the Game Boy Advance. It is part of the Sonic the Hedgehog series, and the final sequel to Sonic Advance 2. The game stars the characters Sonic, Tails, Knuckles, Amy, and Cream as they seek to keep Doctor Eggman and his robot assistant Gemerl from building empires on each of seven chunks Eggman has divided the Earth into.', 'https://media.retroachievements.org/Images/044235.png', 'https://media.retroachievements.org/Images/045495.png', 'https://media.retroachievements.org/Images/003387.png', 'https://media.retroachievements.org/Images/003781.png', 4.6),
  (30, 758, 'Dragon Ball Z: The Legacy of Goku', 'Game Boy Advance', 5, 5762, 5762, 5762, 39, 0, 'Action RPG', 'Webfoot Technologies', 'Infogrames', '2002-05-14', 'Dragon Ball Z: The Legacy of Goku is a series of video games for the Game Boy Advance, based on the anime series Dragon Ball Z and part of the Dragon Ball video game series. All three games are action role-playing games. The first game, Dragon Ball Z: The Legacy of Goku, was developed by Webfoot Technologies and released in 2002. The game was followed by two sequels: Dragon Ball Z: The Legacy of Goku II, released in 2003, and Dragon Ball Z: Buu''s Fury, released in 2004. Buu''s Fury was re-released in 2006 as part of a Game Boy Advance two-pack, which includes Dragon Ball GT: Transformation on the same cartridge. In 2016, Webfoot Technologies claimed to be starting development of another sequel.', 'https://media.retroachievements.org/Images/093870.png', 'https://media.retroachievements.org/Images/095540.png', 'https://media.retroachievements.org/Images/095161.png', 'https://media.retroachievements.org/Images/095162.png', 4.6),
  (31, 791, 'Pokémon Sapphire Version', 'Game Boy Advance', 5, 4941, 4941, 4941, 49, 0, NULL, NULL, NULL, '2002-11-21', 'Pokémon Ruby Version and Pokémon Sapphire Version are 2002 role-playing video games developed by Game Freak and published by The Pokémon Company and Nintendo for the Game Boy Advance. They are the first installments in the third generation of the Pokémon video game series, also known as the "advanced generation". After years of Nintendo being the sole publisher of the franchise in all regions, The Pokémon Company co-published the games for the first time since the establishment of the joint-owned company in 1998. They were first released in Japan in late 2002, and internationally in 2003. Pokémon Emerald, a third version, was released two years later in each region. Remakes of the two games, titled Pokémon Omega Ruby and Alpha Sapphire, were released for the Nintendo 3DS worldwide in November 2014, exactly twelve years to the date of the original Ruby and Sapphire release date, with the exception of Europe, where it released a week later.', 'https://media.retroachievements.org/Images/104257.png', 'https://media.retroachievements.org/Images/077257.png', 'https://media.retroachievements.org/Images/077263.png', 'https://media.retroachievements.org/Images/077262.png', 4.5),
  (32, 519, 'Final Fantasy Tactics Advance', 'Game Boy Advance', 5, 4771, 4771, 4771, 138, 0, 'Tactical RPG', 'Square Enix', 'Nintendo', '2003-09-08', 'Final Fantasy Tactics Advance is a 2003 tactical role-playing game developed by Square for the Game Boy Advance, and published by Square in Japan and Nintendo internationally. A successor to Final Fantasy Tactics (1997), the story follows the trials of some children from the town of St. Ivalice after a magical book transforms their home into a fantasy realm of the same name. Gameplay has player teams fighting in turn-based combat on a grid, with units using a themed Job system. A new feature is a "Law" system, which places random limitations on player action during battles.', 'https://media.retroachievements.org/Images/070805.png', 'https://media.retroachievements.org/Images/014472.png', 'https://media.retroachievements.org/Images/002838.png', 'https://media.retroachievements.org/Images/002980.png', 4.5),
  (33, 5081, 'Aladdin', 'Game Boy Advance', 5, 4662, 4662, 4662, 39, 0, '2D Platforming', 'Disney Interactive Studios', 'Capcom', '2004-09-28', 'Aladdin is a Middle-Eastern folk tale. It is one of the best-known tales associated with One Thousand and One Nights, despite not being part of the original text; it was added by the Frenchman Antoine Galland, based on a folk tale that he heard from the Syrian storyteller Hanna Diyab.', 'https://media.retroachievements.org/Images/121440.png', 'https://media.retroachievements.org/Images/096964.png', 'https://media.retroachievements.org/Images/009281.png', 'https://media.retroachievements.org/Images/009282.png', 4.5),
  (34, 30894, '~Hack~ Pokémon Emerald Seaglass', 'Game Boy Advance', 5, 4612, 4612, 4612, 68, 0, NULL, 'Nemo622', NULL, '2024-08-23', NULL, 'https://media.retroachievements.org/Images/101849.png', 'https://media.retroachievements.org/Images/120406.png', 'https://media.retroachievements.org/Images/104743.png', 'https://media.retroachievements.org/Images/104744.png', 4.5),
  (35, 30137, '~Hack~ Pokémon Emerald Rogue V2', 'Game Boy Advance', 5, 4360, 4360, 4360, 260, 0, 'Roguelike, Turn-Based RPG', 'Pokabbie', 'Hack - Pokemon Emerald Version', '2024-07-02', 'Nintendo is a Japanese multinational video game company headquartered in Kyoto. It develops, publishes, and manufactures both video games and video game consoles. The history of Nintendo began in 1889 when craftsman Fusajiro Yamauchi founded the company to produce handmade hanafuda playing cards. After venturing into various lines of business and becoming a public company, Nintendo began producing toys in the 1960s, and later video games.', 'https://media.retroachievements.org/Images/099243.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/099241.png', 'https://media.retroachievements.org/Images/099242.png', 4.5),
  (36, 4033, 'Rhythm Tengoku', 'Game Boy Advance', 5, 4331, 4331, 4331, 36, 0, 'Rhythm', NULL, 'Nintendo', '2006-08-03', 'Rhythm Tengoku is a 2006 rhythm game developed and published by Nintendo for the Game Boy Advance. It was originally released on August 3, 2006, as the last first-party game to be released for the console. The game began as an idea created by its composer and supervisor Tsunku, who proposed it to Nintendo due to his belief that they could do a better job with it than he could. An arcade version of the game was reprogrammed and published by Sega on September 20, 2007. Both versions were released in Japan exclusively. The game was the first in the Rhythm Heaven series which spawned three international sequels; Rhythm Heaven, Rhythm Heaven Fever, and Rhythm Heaven Megamix, with a fourth sequel, Rhythm Heaven Groove, set for release in 2026.', 'https://media.retroachievements.org/Images/047000.png', 'https://media.retroachievements.org/Images/002417.png', 'https://media.retroachievements.org/Images/002415.png', 'https://media.retroachievements.org/Images/002418.png', 4.5),
  (37, 2171, 'Mario Tennis: Power Tour', 'Game Boy Advance', 5, 4247, 4247, 4247, 58, 0, 'Sports - Tennis, Role-Playing Game', 'Camelot Software Planning', 'Nintendo', '2005-12-05', 'Mario Tennis: Power Tour, known as Mario Power Tennis in Europe, is a 2005 role-playing sports game developed by Camelot Software Planning and published by Nintendo for the Game Boy Advance. It is the sequel to the Game Boy Color version of Mario Tennis. While it is the handheld companion to Mario Power Tennis, released on GameCube, with the European release sharing its title, Power Tour lacks connectivity with Power Tennis, unlike how its predecessor features connectivity with its console counterpart on Nintendo 64. Power Tour was re-released on the Wii U''s Virtual Console in 2014.', 'https://media.retroachievements.org/Images/116617.png', 'https://media.retroachievements.org/Images/014496.png', 'https://media.retroachievements.org/Images/117351.png', 'https://media.retroachievements.org/Images/117352.png', 4.5),
  (38, 528, 'Doom', 'Game Boy Advance', 5, 4014, 4014, 4014, 83, 0, 'First-Person Shooter', 'id Software, David A. Palmer Productions', 'Activision', '2001-10-28', 'Doom is an American media franchise created by John Carmack, John Romero, Adrian Carmack, Kevin Cloud, and Tom Hall. The series usually focuses on the exploits of an unnamed space marine operating under the auspices of the Union Aerospace Corporation (UAC), who fights hordes of demons and the undead to save Earth from an apocalyptic invasion.', 'https://media.retroachievements.org/Images/035909.png', 'https://media.retroachievements.org/Images/014455.png', 'https://media.retroachievements.org/Images/088173.png', 'https://media.retroachievements.org/Images/088172.png', 4.5),
  (39, 514, 'Metal Slug Advance', 'Game Boy Advance', 5, 3911, 3911, 3911, 23, 0, 'Run & Gun', 'Noise Factory', 'SNK', '2004-11-12', 'Metal Slug Advance is a run and gun video game for the Game Boy Advance handheld system created by SNK Playmore in 2004, and is canon to the Metal Slug series.', 'https://media.retroachievements.org/Images/049736.png', 'https://media.retroachievements.org/Images/069381.png', 'https://media.retroachievements.org/Images/001032.png', 'https://media.retroachievements.org/Images/001033.png', 4.5),
  (40, 2188, 'Sonic Battle', 'Game Boy Advance', 5, 3874, 3874, 3874, 30, 0, 'Arena Fighting', 'Sega, Sonic Team', 'THQ', '2003-12-03', 'Sonic Battle is a 2003 Fighting game developed by Sonic Team and published by Sega for the Game Boy Advance. It is the second fighting game in the Sonic the Hedgehog series, the first game being Sonic the Fighters. It was released in Japan in December 2003 and in North America and Europe in early 2004. The game received an indifferent response from critics.', 'https://media.retroachievements.org/Images/042714.png', 'https://media.retroachievements.org/Images/111785.png', 'https://media.retroachievements.org/Images/007053.png', 'https://media.retroachievements.org/Images/007054.png', 4.5),
  (41, 5077, 'Gunstar Super Heroes', 'Game Boy Advance', 5, 3854, 3854, 3854, 57, 0, 'Run & Gun', 'Treasure', 'Sega', '2005-10-06', 'Gunstar Super Heroes is a run and gun video game for the Game Boy Advance developed by Treasure and published by Sega in 2005. It is the sequel to the 1993 Sega Genesis game Gunstar Heroes, with the story taking place after the events of the original game and featuring an expanded combat system over its predecessor.', 'https://media.retroachievements.org/Images/079539.png', 'https://media.retroachievements.org/Images/005855.png', 'https://media.retroachievements.org/Images/033780.png', 'https://media.retroachievements.org/Images/005856.png', 4.5),
  (42, 759, 'Dragon Ball Z: The Legacy of Goku II', 'Game Boy Advance', 5, 3549, 3549, 3549, 57, 0, 'Action RPG', 'Webfoot Technologies', 'Atari', '2003-06-17', 'Dragon Ball Z: The Legacy of Goku is a series of video games for the Game Boy Advance, based on the anime series Dragon Ball Z and part of the Dragon Ball video game series. All three games are action role-playing games. The first game, Dragon Ball Z: The Legacy of Goku, was developed by Webfoot Technologies and released in 2002. The game was followed by two sequels: Dragon Ball Z: The Legacy of Goku II, released in 2003, and Dragon Ball Z: Buu''s Fury, released in 2004. Buu''s Fury was re-released in 2006 as part of a Game Boy Advance two-pack, which includes Dragon Ball GT: Transformation on the same cartridge. In 2016, Webfoot Technologies claimed to be starting development of another sequel.', 'https://media.retroachievements.org/Images/093985.png', 'https://media.retroachievements.org/Images/095539.png', 'https://media.retroachievements.org/Images/095164.png', 'https://media.retroachievements.org/Images/095165.png', 4.5),
  (43, 3706, 'Final Fight One', 'Game Boy Advance', 5, 3445, 3445, 3445, 28, 0, 'Beat ''em Up', 'Capcom', 'Capcom, Ubisoft', '2001-05-25', 'Final Fight is a 1989 beat ''em up game developed and published by Capcom for arcades. It is the seventh title released for the CP System hardware. Set in the fictional Metro City, the player controls one of three street fighters: former pro wrestler and city mayor Mike Haggar, expert brawler Cody Travers, and modern-day ninja Guy. The trio set out to rescue Jessica when she is kidnapped by the Mad Gear Gang.', 'https://media.retroachievements.org/Images/062590.png', 'https://media.retroachievements.org/Images/014474.png', 'https://media.retroachievements.org/Images/008117.png', 'https://media.retroachievements.org/Images/008118.png', 4.4),
  (44, 760, 'Drill Dozer', 'Game Boy Advance', 5, 3331, 3331, 3331, 56, 0, '2D Platforming, Action', 'Game Freak', 'Nintendo', '2006-02-06', 'Drill Dozer is a platformer video game developed by Game Freak and published by Nintendo for the Game Boy Advance (GBA). Directed by Ken Sugimori, the game stars Jill and her mech Drill Dozer, which has a drill that the player can rotate in both directions to fight enemies, drill into certain surfaces, and screw objects. Sugimori aimed to make an action game that does not use traditional types of combat, and was inspired by the concept of a tokusatsu monster who could drill through anything. He also wished to make the drill not just pushing a button, but instead using one of two buttons to activate the drill. When drilling, the built-in rumble pack will activate, a feature suggested by Nintendo.', 'https://media.retroachievements.org/Images/046590.png', 'https://media.retroachievements.org/Images/014464.png', 'https://media.retroachievements.org/Images/009457.png', 'https://media.retroachievements.org/Images/009458.png', 4.4),
  (45, 4206, 'Sword of Mana', 'Game Boy Advance', 5, 3308, 3308, 3308, 101, 0, 'Action RPG', 'Brownie Brown, Square Enix', 'Nintendo, Square Enix', '2003-12-01', 'Sword of Mana, originally released in Japan as Shin''yaku: Seiken Densetsu , is a 2003 action role-playing game developed by Square Enix and Brownie Brown and published by Square Enix and Nintendo for the Game Boy Advance. It is an enhanced remake of the first game in the Mana series, the Game Boy game Seiken Densetsu: Final Fantasy Gaiden, which was released as Final Fantasy Adventure in North America and as Mystic Quest in Europe. Sword of Mana was the fifth release in the series. Set in a high fantasy universe, the game follows an unnamed hero and heroine as they seek to defeat the Dark Lord and defend the Mana Tree from enemies who wish to misuse its power.', 'https://media.retroachievements.org/Images/123002.png', 'https://media.retroachievements.org/Images/064088.png', 'https://media.retroachievements.org/Images/008166.png', 'https://media.retroachievements.org/Images/008173.png', 4.4),
  (46, 2588, 'Summon Night: Swordcraft Story', 'Game Boy Advance', 5, 3187, 3187, 3187, 36, 0, NULL, 'Flight-Plan', 'Atlus', '2006-07-26', 'Summon Night: Swordcraft Story , is a 2003 action role-playing game developed by Flight-Plan for the Game Boy Advance. It is a spinoff of the Summon Night series of games. It was first released in Japan in April 2003, published by Banpresto. An English localized version was released in North America by Atlus in July 2006. A sequel, Summon Night: Swordcraft Story 2, was released in Japan in August 2004, and North America in October 2006.', 'https://media.retroachievements.org/Images/121536.png', 'https://media.retroachievements.org/Images/007653.png', 'https://media.retroachievements.org/Images/010288.png', 'https://media.retroachievements.org/Images/010289.png', 4.4),
  (47, 14408, '~Hack~ Pokémon FireRed: Rocket Edition', 'Game Boy Advance', 5, 3174, 3174, 3174, 42, 0, 'Turn-Based RPG', 'colonelsalt', NULL, '2020-04-09', 'Pokémon FireRed Version and Pokémon LeafGreen Version are 2004 remakes of the 1996 role-playing video games Pokémon Red and Blue. They were developed by Game Freak and published by The Pokémon Company and Nintendo for the Game Boy Advance. FireRed and LeafGreen were first released in Japan in January 2004 and in North America and Europe in September and October 2004, respectively. The games are part of the third generation of the Pokémon video game series and hold the distinction of being the first enhanced remakes of previous games within the franchise.', 'https://media.retroachievements.org/Images/122420.png', 'https://media.retroachievements.org/Images/114819.png', 'https://media.retroachievements.org/Images/033001.png', 'https://media.retroachievements.org/Images/033002.png', 4.4),
  (48, 533, 'Mario Kart: Super Circuit', 'Game Boy Advance', 5, 3107, 3107, 3107, 94, 0, 'Kart Racing', 'Intelligent Systems', 'Nintendo', '2001-08-26', 'Mario Kart: Super Circuit is a 2001 kart racing game for the Game Boy Advance (GBA). It is the third Mario Kart game and retains its predecessors'' gameplay: as a Mario franchise character, the player races opponents around tracks based on locales from the Super Mario platform games. Tracks contain obstacles and power-ups that respectively hamper and aid the player''s progress. Super Circuit includes various single-player and multiplayer game modes, including a Grand Prix racing mode and a last man standing battle mode.', 'https://media.retroachievements.org/Images/066821.png', 'https://media.retroachievements.org/Images/069295.png', 'https://media.retroachievements.org/Images/006425.png', 'https://media.retroachievements.org/Images/006426.png', 4.4),
  (49, 1416, 'Grand Theft Auto Advance', 'Game Boy Advance', 5, 3059, 3059, 3059, 41, 0, 'Action-Adventure', 'Digital Eclipse', 'Rockstar Games', '2004-10-26', 'Grand Theft Auto Advance is a 2004 action-adventure game developed by Digital Eclipse and published by Rockstar Games. The eighth entry in the Grand Theft Auto series, it was released for the Game Boy Advance in October 2004. The game takes place in Liberty City, the same setting used for Grand Theft Auto III, to which it serves as a prequel. The story, set one year before Grand Theft Auto III, follows small-time criminal Mike''s quest for revenge after his partner''s supposed death, which leads him to become entangled in a world of organised crime, gang warfare, and corruption.', 'https://media.retroachievements.org/Images/089901.png', 'https://media.retroachievements.org/Images/014480.png', 'https://media.retroachievements.org/Images/001019.png', 'https://media.retroachievements.org/Images/096539.png', 4.4),
  (50, 5255, 'Sonic Pinball Party', 'Game Boy Advance', 5, 3027, 3027, 3027, 103, 0, 'Pinball', 'Sonic Team, Jupiter', 'Sega', '2003-06-03', 'Sonic Pinball Party is a video game released for the Game Boy Advance in 2003. It is a celebration of sorts for Sonic Team featuring many references to its previous games, mostly prominently Sonic the Hedgehog, Nights into Dreams, and Samba De Amigo. There was also a release on a Twin Pack cartridge bundled with Sonic Battle and Sonic Advance respectively in 2005.', 'https://media.retroachievements.org/Images/113163.png', 'https://media.retroachievements.org/Images/071408.png', 'https://media.retroachievements.org/Images/025946.png', 'https://media.retroachievements.org/Images/033826.png', 4.4),
  (51, 5234, 'Super Mario Advance 3: Yoshi''s Island', 'Game Boy Advance', 5, 3001, 3001, 3001, 66, 0, '2D Platforming', NULL, 'Nintendo', '2002-09-20', 'Super Mario World 2: Yoshi''s Island is a 1995 platform game developed and published by Nintendo for the Super Nintendo Entertainment System (SNES). The player controls Yoshi dinosaurs on their quest to reunite baby Mario with his brother Luigi, who has been kidnapped by the wizard Kamek. Yoshi runs and jumps to reach the end of the level while solving puzzles and collecting items with Mario''s help.', 'https://media.retroachievements.org/Images/121554.png', 'https://media.retroachievements.org/Images/110912.png', 'https://media.retroachievements.org/Images/008562.png', 'https://media.retroachievements.org/Images/008561.png', 4.4),
  (52, 787, 'Naruto: Ninja Council', 'Game Boy Advance', 5, 2967, 2967, 2967, 44, 0, '2D Platforming, Beat ''em Up', 'Aspect', 'D3 Publisher, Tomy', '2006-03-07', 'The Naruto: Ninja Council series, known in Japan as Naruto: Saikyō Ninja Daikesshū , is a series of action games based on the manga and anime series Naruto by Masashi Kishimoto. They are developed by Aspect Co. and published by Tomy. Various installments of the series have appeared on both Nintendo''s Game Boy Advance and Nintendo DS, the first two games in the series available for the former while the rest are available on the latter.', 'https://media.retroachievements.org/Images/094961.png', 'https://media.retroachievements.org/Images/024187.png', 'https://media.retroachievements.org/Images/001036.png', 'https://media.retroachievements.org/Images/001037.png', 4.4),
  (53, 764, 'Final Fantasy V: Advance', 'Game Boy Advance', 5, 2947, 2947, 2947, 172, 0, NULL, 'TOSE', 'Nintendo, Square Enix', '2006-11-06', 'Final Fantasy V is a 1992 role-playing video game developed and published by Square for the Super Famicom. It is the fifth main installment of the Final Fantasy series. The game begins as a wanderer named Bartz investigates a fallen meteor. There, he encounters several characters, one of whom reveals the danger facing the four Crystals that control the world''s elements. These Crystals act as a seal on Exdeath, an evil sorcerer. Bartz and his party must keep the Crystals from being exploited by Exdeath''s influence and prevent his resurgence.', 'https://media.retroachievements.org/Images/086246.png', 'https://media.retroachievements.org/Images/069383.png', 'https://media.retroachievements.org/Images/005289.png', 'https://media.retroachievements.org/Images/005290.png', 4.4),
  (54, 5004, 'Yu-Gi-Oh! The Eternal Duelist Soul', 'Game Boy Advance', 5, 2913, 2913, 2913, 39, 0, 'Collectible Card Game', 'Konami', 'Konami', '2002-10-15', 'Yu-Gi-Oh! The Eternal Duelist Soul is a card battle video game based on the Yu-Gi-Oh! franchise. It was developed and published by Konami and released on July 5, 2001 in Japan, October 16, 2002 in the United States for Game Boy Advance. It features a single-player campaign against opponents from the Yu-Gi-Oh! anime as well as a multiplayer head-to-head mode.', 'https://media.retroachievements.org/Images/056423.png', 'https://media.retroachievements.org/Images/002796.png', 'https://media.retroachievements.org/Images/002794.png', 'https://media.retroachievements.org/Images/002795.png', 4.4),
  (55, 16209, '~Homebrew~ Celeste Classic', 'Game Boy Advance', 5, 2850, 2850, 2850, 39, 0, '2D Platforming', 'JeffRuLz', 'JeffRuLz', '2019-08-02', 'Celeste is a 2018 platform video game developed and published by indie studio Maddy Makes Games. The player controls the player character Madeline, a young woman with anxiety and depression, who endeavors to climb Celeste Mountain, a fictional version of Mount Celeste. During her climb, she encounters several characters, including a personification of her self-doubt nicknamed "Badeline", who attempts to stop her from reaching the mountain''s summit.', 'https://media.retroachievements.org/Images/088036.png', 'https://media.retroachievements.org/Images/117819.png', 'https://media.retroachievements.org/Images/115239.png', 'https://media.retroachievements.org/Images/115247.png', 4.4),
  (56, 5719, 'LEGO Star Wars: The Video Game', 'Game Boy Advance', 5, 2750, 2750, 2750, 45, 0, 'Action-Adventure', 'Griptonite Games', 'Eidos Interactive, LucasArts | Lucasfilm', '2005-03-29', 'Lego Star Wars: The Video Game is a 2005 action-adventure video game based on the line of Lego construction toys of the same name, and the first installment in the Lego video game franchise developed by Traveller''s Tales, which would develop many future Lego titles from that point on. It was first released on 29 March 2005. It is a Lego video game adaptation of the prequel trilogy of George Lucas’ movie franchise of the same name: The Phantom Menace, Attack of the Clones and Revenge of the Sith, with a bonus level from A New Hope.', 'https://media.retroachievements.org/Images/087606.png', 'https://media.retroachievements.org/Images/014489.png', 'https://media.retroachievements.org/Images/004771.png', 'https://media.retroachievements.org/Images/004772.png', 4.4),
  (57, 5127, 'Crash Nitro Kart', 'Game Boy Advance', 5, 2659, 2659, 2659, 68, 0, 'Kart Racing', 'Vicarious Visions', 'Universal Interactive', '2003-11-11', 'Crash Nitro Kart is a 2003 kart racing game developed by Vicarious Visions and published by Universal Interactive for the PlayStation 2, Xbox, and GameCube. It is the second racing game in the Crash Bandicoot series after Crash Team Racing and the first game in the series to feature full motion videos. The game''s plot centers on the abduction of Crash Bandicoot, along with other characters in the series, by the ruthless dictator Emperor Velo XXVII, who threatens to destroy the Earth if they refuse to race in his gigantic coliseum for the entertainment of his subjects.', 'https://media.retroachievements.org/Images/081321.png', 'https://media.retroachievements.org/Images/096968.png', 'https://media.retroachievements.org/Images/003368.png', 'https://media.retroachievements.org/Images/003369.png', 4.4),
  (58, 2482, 'Fire Emblem: The Sacred Stones', 'Game Boy Advance', 5, 2626, 2626, 2626, 114, 0, 'Tactical RPG', 'Intelligent Systems', 'Nintendo', '2005-11-04', 'Fire Emblem: The Sacred Stones is a tactical role-playing game developed by Intelligent Systems, and published by Nintendo for the Game Boy Advance handheld video game console in 2004 for Japan and 2005 in the West. It is the eighth entry in the Fire Emblem series, the second to be released outside Japan, and the third and final title to be developed for the Game Boy Advance after The Binding Blade and its prequel The Blazing Blade.', 'https://media.retroachievements.org/Images/102614.png', 'https://media.retroachievements.org/Images/089240.png', 'https://media.retroachievements.org/Images/012409.png', 'https://media.retroachievements.org/Images/007175.png', 4.4),
  (59, 748, 'Classic NES Series: The Legend of Zelda', 'Game Boy Advance', 5, 2601, 2601, 2601, 97, 0, 'Action-Adventure', 'Nintendo', 'Nintendo', '2004-02-14', 'The Legend of Zelda is a 1986 action-adventure game developed and published by Nintendo for the Family Computer Disk System. It is the first game in the Legend of Zelda series. It is set in the fantasy land of Hyrule and centers on an elf-like boy named Link, who aims to collect the eight fragments of the Triforce of Wisdom to rescue Princess Zelda from Ganon. The player controls Link from a top-down perspective and navigates the overworld and dungeons, collecting weapons, defeating enemies and uncovering secrets. It was designed and directed by Shigeru Miyamoto and Takashi Tezuka, being in development alongside Super Mario Bros. that released the previous year.', 'https://media.retroachievements.org/Images/060253.png', 'https://media.retroachievements.org/Images/026379.png', 'https://media.retroachievements.org/Images/088566.png', 'https://media.retroachievements.org/Images/001396.png', 4.4),
  (60, 506, 'Advance Wars', 'Game Boy Advance', 5, 2584, 2584, 2584, 92, 0, 'Turn-Based Strategy', 'Intelligent Systems', 'Nintendo', '2001-09-10', 'Advance Wars is a turn-based strategy video game developed by Intelligent Systems and published by Nintendo for the Game Boy Advance. It is the seventh title in the Wars series of video games, and the first in the Advance Wars sub-series. The game takes place on a fictional continent, where two nations, Orange Star and Blue Moon, have been fighting each other for years. The conflict enters a new stage when an Orange Star commanding officer named Andy is accused of attacking the armies of two other nations, Yellow Comet and Green Earth, without reason, resulting in a worldwide war.', 'https://media.retroachievements.org/Images/052963.png', 'https://media.retroachievements.org/Images/014431.png', 'https://media.retroachievements.org/Images/033766.png', 'https://media.retroachievements.org/Images/002529.png', 4.4),
  (61, 27584, '~Homebrew~ Goodboy Galaxy', 'Game Boy Advance', 5, 2513, 2513, 2513, 125, 0, 'Metroidvania', 'Goodboy Galaxy', 'itch.io, First Press Games', '2023-11-28', 'Goodboy Galaxy is a 2023 action-adventure game developed for the Game Boy Advance in celebration of its 20th anniversary by Rik Nicol and Jeremy Clarke. It is the first full commercial Game Boy Advance release in over 13 years. The game was also released for the PC and Evercade. Development is ongoing for the Nintendo Switch.', 'https://media.retroachievements.org/Images/086185.png', 'https://media.retroachievements.org/Images/086905.png', 'https://media.retroachievements.org/Images/086186.png', 'https://media.retroachievements.org/Images/086187.png', 4.4),
  (62, 21360, '~Hack~ Pokémon Emerald Rogue', 'Game Boy Advance', 5, 2447, 2447, 2447, 83, 0, 'Roguelike, Turn-Based RPG', 'Pokabbie', 'Hack - Pokemon Emerald Version', '2022-08-22', 'This is a list of games released on the Game Boy Advance handheld video game system. The number of licensed games in this list is 1538, organized alphabetically by the games'' localized English titles, or, when Japan-exclusive, their rōmaji transliterations. This list does not include Game Boy Advance Video releases.', 'https://media.retroachievements.org/Images/099244.png', 'https://media.retroachievements.org/Images/066833.png', 'https://media.retroachievements.org/Images/066832.png', 'https://media.retroachievements.org/Images/066831.png', 4.4),
  (63, 754, 'Dragon Ball Z: Buu''s Fury', 'Game Boy Advance', 5, 2413, 2413, 2413, 59, 0, 'Action RPG', 'Webfoot Technologies', 'Atari', '2004-09-14', 'Dragon Ball Z: The Legacy of Goku is a series of video games for the Game Boy Advance, based on the anime series Dragon Ball Z and part of the Dragon Ball video game series. All three games are action role-playing games. The first game, Dragon Ball Z: The Legacy of Goku, was developed by Webfoot Technologies and released in 2002. The game was followed by two sequels: Dragon Ball Z: The Legacy of Goku II, released in 2003, and Dragon Ball Z: Buu''s Fury, released in 2004. Buu''s Fury was re-released in 2006 as part of a Game Boy Advance two-pack, which includes Dragon Ball GT: Transformation on the same cartridge. In 2016, Webfoot Technologies claimed to be starting development of another sequel.', 'https://media.retroachievements.org/Images/094340.png', 'https://media.retroachievements.org/Images/095541.png', 'https://media.retroachievements.org/Images/003297.png', 'https://media.retroachievements.org/Images/003296.png', 4.4),
  (64, 9848, 'Action Man: Robot Atak', 'Game Boy Advance', 5, 2375, 2375, 2375, 51, 0, 'Action, 2D Platforming', 'Magic Pockets', 'Atari', '2004-09-24', 'Action Man: Robot Atak is a 2004 American animated superhero film based on the Hasbro toy line Action Man. The film was produced by Arcana Digital and directed by John Moffett, Steven Burch and Chris Woods. Released to tie-in with the line of Action Man toys released in 2004, Robot Atak was the first in a trilogy of direct-to-video films and was followed by a sequel in 2005, Action Man: X Missions - The Movie.', 'https://media.retroachievements.org/Images/048949.png', 'https://media.retroachievements.org/Images/015646.png', 'https://media.retroachievements.org/Images/082237.png', 'https://media.retroachievements.org/Images/082239.png', 4.4),
  (65, 33063, '~Hack~ Pokémon Odyssey', 'Game Boy Advance', 5, 2346, 2346, 2346, 90, 0, 'Turn-Based RPG', 'Yggdrasil Project', 'Hack - Pokemon FireRed and LeafGreen Versions', '2025-06-12', 'This is a list of games released on the Game Boy Advance handheld video game system. The number of licensed games in this list is 1538, organized alphabetically by the games'' localized English titles, or, when Japan-exclusive, their rōmaji transliterations. This list does not include Game Boy Advance Video releases.', 'https://media.retroachievements.org/Images/108871.png', 'https://media.retroachievements.org/Images/113428.png', 'https://media.retroachievements.org/Images/108876.png', 'https://media.retroachievements.org/Images/108877.png', 4.4),
  (66, 801, 'WarioWare: Twisted!', 'Game Boy Advance', 5, 2344, 2344, 2344, 50, 0, 'Minigames', 'Intelligent Systems', 'Nintendo', '2004-10-14', 'WarioWare: Twisted! is an action video game developed by Nintendo and Intelligent Systems and published by Nintendo for the Game Boy Advance. It was released on October 14, 2004 in Japan; May 19, 2005 in Australia; and May 23, 2005 in North America. The third game in the WarioWare series and the seventh in the Wario series overall, Twisted! was the last Wario game to be released on a Game Boy family system, having been released after the launch of the Nintendo DS.', 'https://media.retroachievements.org/Images/034675.png', 'https://media.retroachievements.org/Images/004477.png', 'https://media.retroachievements.org/Images/004476.png', 'https://media.retroachievements.org/Images/004499.png', 4.4),
  (67, 20277, 'Super Mario Advance 4: Super Mario Bros. 3', 'Game Boy Advance', 5, 2285, 2285, 2285, 83, 0, NULL, NULL, NULL, '2003-07-11', 'Super Mario Advance 4: Super Mario Bros. 3 is a 2003 platform game developed and published by Nintendo for the Game Boy Advance. It was released in Japan, and later released in Europe, North America, and Australia. It is an enhanced remake of the NES video game Super Mario Bros. 3, and is based on the remake found in Super Mario All-Stars for the Super Nintendo Entertainment System. Players control either Mario or Luigi as they travel through the eight kingdoms of the Mushroom World to rescue Princess Peach from Bowser. The game was revealed at Nintendo''s conference at the E3 2003 convention. It contains several enhancements, including the addition of Mario and Luigi''s voices by Charles Martinet, the ability to scan e-Cards into Nintendo''s e-Reader to add certain content, and a multiplayer mode based on the original arcade game Mario Bros.. The game also allows players to save replays of their gameplay.', 'https://media.retroachievements.org/Images/060733.png', 'https://media.retroachievements.org/Images/110841.png', 'https://media.retroachievements.org/Images/060736.png', 'https://media.retroachievements.org/Images/060735.png', 4.4),
  (68, 9957, 'The Pinball of the Dead', 'Game Boy Advance', 5, 2274, 2274, 2274, 44, 0, NULL, NULL, NULL, '2002-06-18', 'The Pinball of the Dead is a pinball video game developed by Sega''s Wow Entertainment division and published by Sega. It was released for the Game Boy Advance in 2002 and 2003. Based on Sega''s The House of the Dead series of light gun games, particularly The House of the Dead and The House of the Dead 2, the game contains three tables and includes a "Challenge" mode. Full-motion video sequences and audio samples from previous games were also added. The game was first announced during the 2001 Nintendo Space World. Composer Hitoshi Sakimoto was involved with making the game''s music.', 'https://media.retroachievements.org/Images/049625.png', 'https://media.retroachievements.org/Images/061668.png', 'https://media.retroachievements.org/Images/061666.png', 'https://media.retroachievements.org/Images/061667.png', 4.3),
  (69, 4106, 'Rayman Advance', 'Game Boy Advance', 5, 2253, 2253, 2253, 58, 0, '2D Platforming', 'Digital Eclipse', 'Ubisoft', '2001-06-11', 'Rayman is a 1995 platform game developed by Ubi Pictures and published by Ubi Soft. The player controls Rayman, who must pursue Mr Dark to recover the Great Protoon that used to keep the balance between nature and the people of Rayman''s valley. The player must navigate the valley, defeat enemies with abilities gained throughout the game, and free captured Electoons, while also encountering a boss at the end of each thematic world.', 'https://media.retroachievements.org/Images/123320.png', 'https://media.retroachievements.org/Images/123464.png', 'https://media.retroachievements.org/Images/005179.png', 'https://media.retroachievements.org/Images/005198.png', 4.3),
  (70, 2138, 'Double Dragon Advance', 'Game Boy Advance', 5, 2188, 2188, 2188, 53, 0, 'Beat ''em Up', 'Million, S-NEO, Paon', 'Atlus', '2003-11-14', 'Double Dragon Advance is a 2003 beat ''em up video game developed by Japanese studio Million and published by Atlus for the Game Boy Advance. It is a remake of Technōs Japan''s 1987 arcade game Double Dragon and incorporates elements from its sequels and home versions.', 'https://media.retroachievements.org/Images/064413.png', 'https://media.retroachievements.org/Images/014457.png', 'https://media.retroachievements.org/Images/048197.png', 'https://media.retroachievements.org/Images/082468.png', 4.3),
  (71, 529, 'Mario vs. Donkey Kong', 'Game Boy Advance', 5, 2160, 2160, 2160, 34, 0, NULL, NULL, 'Nintendo', '2004-11-19', 'Mario vs. Donkey Kong is a 2004 puzzle-platform game developed by Nintendo Software Technology and published by Nintendo for the Game Boy Advance. The game is the spiritual successor to Donkey Kong, which was released in 1994 for the Game Boy.', 'https://media.retroachievements.org/Images/024372.png', 'https://media.retroachievements.org/Images/014498.png', 'https://media.retroachievements.org/Images/001023.png', 'https://media.retroachievements.org/Images/001024.png', 4.3),
  (72, 6946, 'Bookworm', 'Game Boy Advance', 5, 2099, 2099, 2099, 57, 0, NULL, 'PopCap Games', 'Majesco Entertainment, PopCap Games', '2004-04-28', 'A bookworm or bibliophile is an individual who loves and frequently reads or collects books. Bibliophilia or bibliophilism is the love of books.', 'https://media.retroachievements.org/Images/075934.png', 'https://media.retroachievements.org/Images/019397.png', 'https://media.retroachievements.org/Images/019395.png', 'https://media.retroachievements.org/Images/019396.png', 4.3),
  (73, 5117, 'Yu-Gi-Oh! The Sacred Cards', 'Game Boy Advance', 5, 2023, 2023, 2023, 64, 0, 'Collectible Card Game', 'Konami', 'Konami', '2002-01-01', 'Yu-Gi-Oh! The Sacred Cards is a Game Boy Advance game based on the Yu-Gi-Oh! anime, developed and published by Konami. It was first released in Japan on July 4, 2002. It was released in North America the following year and in Europe the year after that.', 'https://media.retroachievements.org/Images/096892.png', 'https://media.retroachievements.org/Images/024015.png', 'https://media.retroachievements.org/Images/004534.png', 'https://media.retroachievements.org/Images/082173.png', 4.3),
  (74, 752, 'Donkey Kong Country 3', 'Game Boy Advance', 5, 1965, 1965, 1965, 27, 0, '2D Platforming', 'Rare', 'Nintendo', '2005-11-07', 'Donkey Kong Country 3: Dixie Kong''s Double Trouble!  is a 1996 platform Collectathon developed by Rare and published by Nintendo for the Super Nintendo Entertainment System (SNES). It is the third installment of the Donkey Kong Country series, and serves as a sequel to 1995''s Donkey Kong Country 2: Diddy''s Kong Quest. It was also re-released for the Game Boy Advance (GBA) in 2005. The game was made available to download on the Wii''s Virtual Console service in 2007, as well as for the Wii U''s Virtual Console in 2014.', 'https://media.retroachievements.org/Images/069873.png', 'https://media.retroachievements.org/Images/014453.png', 'https://media.retroachievements.org/Images/004275.png', 'https://media.retroachievements.org/Images/004276.png', 4.3),
  (75, 4970, 'Dr. Mario & Puzzle League', 'Game Boy Advance', 5, 1908, 1908, 1908, 63, 0, NULL, 'TOSE', 'Nintendo', '2005-11-04', 'Dr. Mario is a 1990 puzzle video game developed and published by Nintendo for the Nintendo Entertainment System and Game Boy. A spin-off of the Mario series, it is a falling block puzzle game in which the player''s objective is to destroy the viruses populating the on-screen playing field by using colored capsules that are automatically tossed into the field by Dr. Mario. The player manipulates the falling capsules, to align the same colors, which destroys viruses. The player progresses through the game by eliminating all the viruses on the screen in each level. The game was produced by Gunpei Yokoi and programmed by Takahiro Harada, with the soundtrack composed by Hirokazu Tanaka.', 'https://media.retroachievements.org/Images/060392.png', 'https://media.retroachievements.org/Images/060263.png', 'https://media.retroachievements.org/Images/060251.png', 'https://media.retroachievements.org/Images/060252.png', 4.3),
  (76, 2592, 'Golden Sun: The Lost Age', 'Game Boy Advance', 5, 1903, 1903, 1903, 97, 0, 'Turn-Based RPG', 'Camelot Software Planning', 'Nintendo', '2003-04-14', 'Golden Sun: The Lost Age is a 2002 role-playing video game for the Game Boy Advance, developed by Camelot Software Planning and published by Nintendo. It is the second installment in the Golden Sun series and was released on June 28, 2002 in Japan, and in 2003 in North America and Europe.', 'https://media.retroachievements.org/Images/059249.png', 'https://media.retroachievements.org/Images/059420.png', 'https://media.retroachievements.org/Images/006638.png', 'https://media.retroachievements.org/Images/006639.png', 4.3),
  (77, 3700, 'Who Wants to Be a Millionaire', 'Game Boy Advance', 5, 1884, 1884, 1884, 6, 0, 'Game Show', 'Hothouse Creations', 'Zoo Digital Publishing | Zushi Games', '2002-10-18', 'Who Wants to Be a Millionaire? (WWTBAM) is an international television game show franchise of British origin, created by David Briggs, Mike Whitehill and Steven Knight. In its format, currently owned and licensed by Sony Pictures Television, contestants tackle a series of multiple-choice questions to win large cash prizes in a format that twists on many game show genre conventions – only one contestant plays at a time. Similar to radio quizzes, contestants are given the question before deciding whether to answer and have no time limit to answer questions. The cash prize increases as they tackle questions that become increasingly difficult, with the maximum offered in most variants of the format being an aspirational value in the respective local currency, such as £1 million in the British version, €1 million in most European versions, $1 million in the American version and ₹75 million in the Indian version.', 'https://media.retroachievements.org/Images/071846.png', 'https://media.retroachievements.org/Images/050280.png', 'https://media.retroachievements.org/Images/050277.png', 'https://media.retroachievements.org/Images/050278.png', 4.3),
  (78, 12748, '~Prototype~ Resident Evil 2', 'Game Boy Advance', 5, 1832, 1832, 1832, 11, 0, 'Survival Horror', 'Raylight Studios', 'Capcom', NULL, 'Resident Evil 2 is a 1998 survival horror video game developed and published by Capcom for the PlayStation. It is the second main installment in the Resident Evil series. The player controls rookie cop Leon S. Kennedy and college student Claire Redfield, who must escape Raccoon City after its citizens are transformed into zombies by a biological weapon two months after the events of the original Resident Evil. The gameplay focuses on exploration, puzzles, and combat; the main difference from its predecessor are the branching paths, with each player character having unique storylines, partners and obstacles.', 'https://media.retroachievements.org/Images/101590.png', 'https://media.retroachievements.org/Images/036161.png', 'https://media.retroachievements.org/Images/101542.png', 'https://media.retroachievements.org/Images/101543.png', 4.3),
  (79, 784, 'Mega Man Zero 4', 'Game Boy Advance', 5, 1827, 1827, 1827, 52, 0, '2D Platforming, Action', 'Inti Creates', 'Capcom', '2005-04-21', 'Mega Man Zero 4 is a 2005 hack and slash platform game developed by Inti Creates and published by Capcom for the Game Boy Advance. It is the fourth and final installment of the Mega Man Zero subseries of the Mega Man franchise and is set several months after the events of Mega Man Zero 3.', 'https://media.retroachievements.org/Images/124431.png', 'https://media.retroachievements.org/Images/005028.png', 'https://media.retroachievements.org/Images/033794.png', 'https://media.retroachievements.org/Images/005210.png', 4.3),
  (80, 548, 'Naruto: Ninja Council 2', 'Game Boy Advance', 5, 1808, 1808, 1808, 23, 0, '2D Platforming, Beat ''em Up', 'Aspect, Tomy', 'D3 Publisher, Tomy', '2006-10-04', 'The Naruto: Ninja Council series, known in Japan as Naruto: Saikyō Ninja Daikesshū , is a series of action games based on the manga and anime series Naruto by Masashi Kishimoto. They are developed by Aspect Co. and published by Tomy. Various installments of the series have appeared on both Nintendo''s Game Boy Advance and Nintendo DS, the first two games in the series available for the former while the rest are available on the latter.', 'https://media.retroachievements.org/Images/055814.png', 'https://media.retroachievements.org/Images/003880.png', 'https://media.retroachievements.org/Images/001040.png', 'https://media.retroachievements.org/Images/001041.png', 4.3),
  (81, 783, 'Mega Man Zero 2', 'Game Boy Advance', 5, 1765, 1765, 1765, 45, 0, '2D Platforming, Action', 'Inti Creates', 'Capcom', '2003-10-14', 'Mega Man Zero 2 is a 2003 hack and slash platform game developed by Inti Creates and published by Capcom for the Game Boy Advance (GBA) handheld game console. It is the second video game in the Mega Man Zero subseries of Mega Man video games.', 'https://media.retroachievements.org/Images/124432.png', 'https://media.retroachievements.org/Images/003326.png', 'https://media.retroachievements.org/Images/033795.png', 'https://media.retroachievements.org/Images/004953.png', 4.3),
  (82, 6643, '~Hack~ Pokémon Ultra Violet Version', 'Game Boy Advance', 5, 1734, 1734, 1734, 29, 0, 'Turn-Based RPG', 'LocksmithArmy', NULL, '2013-07-02', 'The third generation (generation III) of the Pokémon franchise features 386 fictional species of creatures and 135 Pokémon introduced to the core video game series in the 2002 Game Boy Advance games Pokémon Ruby and Sapphire, and later in the 2004 game Pokémon Emerald. These games were accompanied by the television series Pokémon Advanced, which aired from November 21, 2002, until August 28, 2003, in Japan.', 'https://media.retroachievements.org/Images/042470.png', 'https://media.retroachievements.org/Images/008888.png', 'https://media.retroachievements.org/Images/008625.png', 'https://media.retroachievements.org/Images/008627.png', 4.3),
  (83, 5245, '~Hack~ Pokémon AshGray Version', 'Game Boy Advance', 5, 1720, 1720, 1720, 139, 0, 'Turn-Based RPG', 'Metapod23', NULL, '2015-03-03', 'The Nintendo Switch is a video game console developed by Nintendo and released worldwide in most regions on March 3, 2017. Released in the middle of the eighth generation of home consoles, the Switch succeeded the Wii U and competed with Sony''s PlayStation 4 and Microsoft''s Xbox One; it also competes with the ninth-generation consoles, the PlayStation 5 and Xbox Series X/S.', 'https://media.retroachievements.org/Images/090474.png', 'https://media.retroachievements.org/Images/007953.png', 'https://media.retroachievements.org/Images/025681.png', 'https://media.retroachievements.org/Images/008763.png', 4.3),
  (84, 4703, 'Shining Soul', 'Game Boy Advance', 5, 1716, 1716, 1716, 63, 0, 'Action RPG', 'Nex Entertainment, Grasshopper Manufacture', 'Sega, Atlus', '2002-03-28', 'Shining Soul is an action role-playing game for the Game Boy Advance. It is part of the Shining series. Shining Soul is a reboot of the Shining series. The game was followed by a sequel, Shining Soul II, in 2003. Both games were re-released in Japan in early 2006 as part of the Game Boy Advance "Value Selection".', 'https://media.retroachievements.org/Images/074707.png', 'https://media.retroachievements.org/Images/014901.png', 'https://media.retroachievements.org/Images/014902.png', 'https://media.retroachievements.org/Images/014900.png', 4.3),
  (85, 5520, 'Pac-Man Collection', 'Game Boy Advance', 5, 1678, 1678, 1678, 71, 0, NULL, 'Mass Media', 'Namco', '2001-07-12', 'Pac-Man Collection is a 2001 video game compilation developed by Mass Media and published by Namco for the Game Boy Advance. It includes four titles in the Pac-Man series — the original Pac-Man (1980), Pac-Mania (1987), Pac-Attack (1993), and Pac-Man Arrangement (1996), the latter of which was originally exclusive to the arcade game Namco Classic Collection Vol. 2. Each game includes customizable features such as the ability to alter the number of starting lives or difficulty, with all being stripped of multiplayer features.', 'https://media.retroachievements.org/Images/065959.png', 'https://media.retroachievements.org/Images/066664.png', 'https://media.retroachievements.org/Images/008234.png', 'https://media.retroachievements.org/Images/008233.png', 4.3),
  (86, 5987, 'Hamtaro: Ham-Ham Heartbreak', 'Game Boy Advance', 5, 1649, 1649, 1649, 35, 0, 'Action', 'Pax Softnica', 'Nintendo', '2003-04-08', 'Hamtaro: Ham-Ham Heartbreak is a video game in the Hamtaro game series for Game Boy Advance developed by Pax Softnica and published by Nintendo, as the sequel to Tottoko Hamutaro: Tomodachi Daisakusen Dechu and Hamtaro: Ham-Hams Unite!. It was the second Hamtaro game released in America and Europe, but the third released in Japan. It was released in Japan on May 3, 2002, in North America on April 7, 2003, in Australia on May 30, 2003, and in Europe on June 27, 2003. Hamtaro: Ham-Ham Heartbreak was followed by Hamtaro: Rainbow Rescue.', 'https://media.retroachievements.org/Images/059649.png', 'https://media.retroachievements.org/Images/009537.png', 'https://media.retroachievements.org/Images/033783.png', 'https://media.retroachievements.org/Images/009546.png', 4.3),
  (87, 5080, 'Tim Burton''s The Nightmare Before Christmas: The Pumpkin King', 'Game Boy Advance', 5, 1643, 1643, 1643, 71, 0, 'Metroidvania', 'TOSE', 'Buena Vista Games, D3 Publisher', '2005-09-08', 'Tim Burton''s The Nightmare Before Christmas: The Pumpkin King is a 2005 platform game developed by Tose for the Game Boy Advance. The game was published by D3 Publisher in Japan, and by Buena Vista Games internationally. A prequel to the 1993 stop motion animated film The Nightmare Before Christmas, it tells the story of Jack Skellington''s first encounter with Oogie Boogie, and how he claimed the title of "The Pumpkin King".', 'https://media.retroachievements.org/Images/046730.png', 'https://media.retroachievements.org/Images/014426.png', 'https://media.retroachievements.org/Images/003207.png', 'https://media.retroachievements.org/Images/003212.png', 4.3),
  (88, 4879, 'Fire Emblem: Fuuin no Tsurugi', 'Game Boy Advance', 5, 1637, 1637, 1637, 70, 0, 'Tactical RPG', 'Intelligent Systems', 'Nintendo', '2002-03-29', 'Fire Emblem: The Binding Blade is a 2002 tactical role-playing game developed by Intelligent Systems and published by Nintendo for the Game Boy Advance (GBA). It is the sixth entry in the Fire Emblem series, the first title produced for the system, and the first title to appear on a handheld console.', 'https://media.retroachievements.org/Images/076394.png', 'https://media.retroachievements.org/Images/014475.png', 'https://media.retroachievements.org/Images/006218.png', 'https://media.retroachievements.org/Images/006220.png', 4.3),
  (89, 8701, 'Classic NES Series: Castlevania', 'Game Boy Advance', 5, 1635, 1635, 1635, 26, 0, '2D Platforming', 'Konami', 'Nintendo', '2004-08-10', 'Castlevania, known in Japan as Akumajō Dracula, is a 1986 platform game developed and published by Konami. It was originally released in Japan for the Famicom Disk System in September 1986, before being ported to cartridge format and released in North America for the Nintendo Entertainment System (NES) in 1987 and in Europe in 1988. It was also re-issued for the Family Computer in cartridge format in 1993. It is the first installment in the Castlevania series.', 'https://media.retroachievements.org/Images/112767.png', 'https://media.retroachievements.org/Images/072394.png', 'https://media.retroachievements.org/Images/060254.png', 'https://media.retroachievements.org/Images/060255.png', 4.3),
  (90, 532, 'Mario Golf: Advance Tour', 'Game Boy Advance', 5, 1614, 1614, 1614, 70, 0, 'Sports - Golf, Role-Playing Game', 'Camelot Software Planning', 'Nintendo', '2004-06-22', 'Mario Golf: Advance Tour is a 2004 sports role-playing video game developed by Camelot Software Planning and published by Nintendo for the Game Boy Advance. The game is the sequel to the Game Boy Color version of Mario Golf and the Game Boy Advance counterpart of Mario Golf: Toadstool Tour.', 'https://media.retroachievements.org/Images/029865.png', 'https://media.retroachievements.org/Images/071183.png', 'https://media.retroachievements.org/Images/033787.png', 'https://media.retroachievements.org/Images/003638.png', 4.3),
  (91, 7128, 'Elf: The Movie', 'Game Boy Advance', 5, 1604, 1604, 1604, 19, 0, 'Action Adventure', 'Jolliford Management Limited', 'Crave Entertainment', '2004-01-01', 'Elf is a 2003 American Christmas comedy film directed by Jon Favreau and written by David Berenbaum. It stars Will Ferrell as Buddy the Elf, a human raised by Santa''s elves, who learns about his origins and heads to New York City to meet his biological father. James Caan, Zooey Deschanel, Mary Steenburgen, Ed Asner and Bob Newhart appear in supporting roles.', 'https://media.retroachievements.org/Images/049698.png', 'https://media.retroachievements.org/Images/006760.png', 'https://media.retroachievements.org/Images/006759.png', 'https://media.retroachievements.org/Images/006763.png', 4.3),
  (92, 572, 'Magical Quest 3 Starring Mickey & Donald', 'Game Boy Advance', 5, 1525, 1525, 1525, 57, 0, '2D Platforming', 'Capcom', 'Capcom', '2005-06-14', 'Disney''s Magical Quest is a Disney platform game trilogy released by Capcom. The games star Mickey Mouse and either Minnie Mouse or Donald Duck, who must defeat Pete. The gameplay is similar amongst all games in the series: the player must move as in a typical platform game, defeating enemies either by jumping on them or by grabbing and throwing blocks at them.', 'https://media.retroachievements.org/Images/108392.png', 'https://media.retroachievements.org/Images/014449.png', 'https://media.retroachievements.org/Images/008357.png', 'https://media.retroachievements.org/Images/008356.png', 4.3),
  (93, 5312, 'The King of Fighters EX2: Howling Blood', 'Game Boy Advance', 5, 1523, 1523, 1523, 46, 0, '2D Fighting', 'Marvelous Interactive', 'Atlus, Acclaim, Marvelous Interactive', '2003-12-11', 'The King of Fighters EX 2 Howling Blood is a fighting game developed by Marvelous Entertainment for Nintendo''s Game Boy Advance. It is a spin-off of SNK''s The King of Fighters series and acts as a sequel to The King of Fighters EX: Neo Blood. Despite taking graphics, characters and audio from The King of Fighters 2000, the game features an original storyline that focuses on Kyo Kusanagi and his allies in stopping the revival of the demon Yamata no Orochi from Heavenly Kings. It was announced for a 2003 release in the same console. The game was also ported to the N-Gage under the name The King of Fighters Extreme. Hudson Soft developed the game, and it was published by Nokia in Europe.', 'https://media.retroachievements.org/Images/079760.png', 'https://media.retroachievements.org/Images/007124.png', 'https://media.retroachievements.org/Images/007121.png', 'https://media.retroachievements.org/Images/118218.png', 4.3),
  (94, 625, 'Mega Man Zero 3', 'Game Boy Advance', 5, 1514, 1514, 1514, 53, 0, '2D Platforming, Action', 'Inti Creates', 'Capcom', '2004-10-05', 'Mega Man Zero 3 is a 2004 hack and slash platform game developed by Inti Creates and published by Capcom for the Game Boy Advance (GBA) handheld game console. It is the third video game in the Mega Man Zero series of Mega Man video games. The European version featured a completely different logo, which was also used on various other Mega Man titles.', 'https://media.retroachievements.org/Images/042926.png', 'https://media.retroachievements.org/Images/039503.png', 'https://media.retroachievements.org/Images/033796.png', 'https://media.retroachievements.org/Images/039504.png', 4.3),
  (95, 2412, 'Yu-Gi-Oh! Worldwide Edition: Stairway to the Destined Duel', 'Game Boy Advance', 5, 1514, 1514, 1514, 79, 0, NULL, 'Konami', 'Konami', '2003-04-15', 'Yu-Gi-Oh! Worldwide Edition: Stairway to the Destined Duel, later released in Japan as Yu-Gi-Oh! Duel Monsters International , is a Game Boy Advance game developed and published by Konami in 2003. It is a modified version of Yu-Gi-Oh! Duel Monsters 6 Expert 2, previously released for the Game Boy Advance in 2001, and adapts the "Battle City" story arc of the original Yu-Gi-Oh! series. The game was re-released in 2025 as part of the Yu-Gi-Oh! Early Days Collection game compilation.', 'https://media.retroachievements.org/Images/057886.png', 'https://media.retroachievements.org/Images/024090.png', 'https://media.retroachievements.org/Images/008895.png', 'https://media.retroachievements.org/Images/008896.png', 4.3),
  (96, 509, 'Bomberman Tournament', 'Game Boy Advance', 5, 1499, 1499, 1499, 56, 0, 'Action RPG', 'Hudson Soft', 'Activision', '2001-04-27', 'Bomberman Tournament is a game in the Bomberman series for the Game Boy Advance. The game contains a multiplayer battle mode between linked Game Boy Advance consoles. The player and up to three others can compete in any of the game''s eight multiplayer battle arenas, each of which has its own unique gameplay twist.', 'https://media.retroachievements.org/Images/052576.png', 'https://media.retroachievements.org/Images/003285.png', 'https://media.retroachievements.org/Images/002717.png', 'https://media.retroachievements.org/Images/002718.png', 4.3),
  (97, 18985, '~Hack~ Pokémon Sword and Shield Ultimate Plus', 'Game Boy Advance', 5, 1496, 1496, 1496, 102, 0, NULL, 'PCL.G, Jeanstars & Phantonomy', NULL, '2024-10-18', 'The third generation (generation III) of the Pokémon franchise features 386 fictional species of creatures and 135 Pokémon introduced to the core video game series in the 2002 Game Boy Advance games Pokémon Ruby and Sapphire, and later in the 2004 game Pokémon Emerald. These games were accompanied by the television series Pokémon Advanced, which aired from November 21, 2002, until August 28, 2003, in Japan.', 'https://media.retroachievements.org/Images/104747.png', 'https://media.retroachievements.org/Images/101735.png', 'https://media.retroachievements.org/Images/101739.png', 'https://media.retroachievements.org/Images/101740.png', 4.2),
  (98, 4201, 'Harry Potter and the Sorcerer''s Stone', 'Game Boy Advance', 5, 1480, 1480, 1480, 34, 0, 'Action-Adventure', 'Griptonite Games', 'Electronic Arts', '2001-11-15', 'Harry Potter and the Philosopher''s Stone is a fantasy novel by British author J. K. Rowling. It is the first novel in the Harry Potter series and was Rowling''s debut novel. It follows Harry Potter, a young wizard who discovers his magical heritage on his eleventh birthday when he receives a letter of acceptance from Hogwarts School of Witchcraft and Wizardry. With the help of his friends, Ron Weasley and Hermione Granger, Harry unravels a mystery involving the dark wizard Lord Voldemort.', 'https://media.retroachievements.org/Images/124569.png', 'https://media.retroachievements.org/Images/020817.png', 'https://media.retroachievements.org/Images/020816.png', 'https://media.retroachievements.org/Images/020818.png', 4.2),
  (99, 2543, 'Konami Krazy Racers', 'Game Boy Advance', 5, 1472, 1472, 1472, 68, 0, 'Kart Racing', 'KCEK', 'Konami', '2001-03-21', 'Konami Krazy Racers is a 2001 kart-themed racing video game developed and published by Konami for the Game Boy Advance. Released as a launch title for the system, Konami Krazy Racers makes use of a variety of characters and concepts from several of Konami''s franchises, including Castlevania, Metal Gear, and Gradius. It plays similarly to the Mario Kart series, with eight characters per circuit and offensive/defensive items placed at predetermined points in the tracks. Konami Krazy Racers received mostly positive reviews. It was later released through the Virtual Console for the Wii U in 2015.', 'https://media.retroachievements.org/Images/107129.png', 'https://media.retroachievements.org/Images/065794.png', 'https://media.retroachievements.org/Images/014313.png', 'https://media.retroachievements.org/Images/014314.png', 4.2),
  (100, 4872, 'Breath of Fire', 'Game Boy Advance', 5, 1470, 1470, 1470, 68, 0, 'Turn-Based RPG', 'Capcom', 'Capcom', '2001-12-31', 'Breath of Fire is a role-playing video game series developed by Capcom. It originated on the Super Nintendo Entertainment System in 1993. The series has recurring characters and ambiguous continuity; though each game is its own self-contained story, the names of the two lead characters are usually Ryu and Nina.', 'https://media.retroachievements.org/Images/104995.png', 'https://media.retroachievements.org/Images/033806.png', 'https://media.retroachievements.org/Images/044276.png', 'https://media.retroachievements.org/Images/044275.png', 4.2),
  (101, 4964, '~Hack~ Pokémon Liquid Crystal Version', 'Game Boy Advance', 5, 1457, 1457, 1457, 74, 0, 'Turn-Based RPG', 'Linkandzelda, Zeikku', NULL, '2007-04-01', 'The Game Boy Advance SP is a 32-bit handheld game console made by Nintendo. It was released in Japan on February 14, 2003, and in international markets in March. The SP is an upgraded version of the Game Boy Advance with a more compact clamshell design.', 'https://media.retroachievements.org/Images/110367.png', 'https://media.retroachievements.org/Images/044490.png', 'https://media.retroachievements.org/Images/009132.png', 'https://media.retroachievements.org/Images/009131.png', 4.2),
  (102, 4853, 'Harvest Moon: Friends of Mineral Town', 'Game Boy Advance', 5, 1455, 1455, 1455, 150, 0, 'Life Simulation', 'Marvelous Interactive', 'Natsume', '2003-04-18', 'Harvest Moon: Friends of Mineral Town is a video game for the Game Boy Advance, developed and published by Marvelous Interactive. It is the first Game Boy Advance game of the Story of Seasons series, and is a remake of Harvest Moon: Back to Nature. It was first released in Japan in April 2003, in North America in November 2003, and in Europe in March 2004. Many critics praised it as the best entry of the series, combining elements from the best-selling console entries and introducing many notable series staples. It was later released on the Virtual Console for the Wii U in June 2015.', 'https://media.retroachievements.org/Images/120932.png', 'https://media.retroachievements.org/Images/006281.png', 'https://media.retroachievements.org/Images/006279.png', 'https://media.retroachievements.org/Images/006280.png', 4.2),
  (103, 6184, 'The Sims: Bustin'' Out', 'Game Boy Advance', 5, 1442, 1442, 1442, 50, 0, 'Life Simulation', 'Griptonite Games', 'Electronic Arts', '2003-12-02', 'The Sims Bustin'' Out is a 2003 social simulation video game developed by Maxis and published by Electronic Arts for the Game Boy Advance, GameCube, PlayStation 2 and Xbox, with a port for the N-Gage following in 2004. It is the second title in The Sims console series, and the first title not to be concurrently released for Microsoft Windows.', 'https://media.retroachievements.org/Images/066855.png', 'https://media.retroachievements.org/Images/008305.png', 'https://media.retroachievements.org/Images/066854.png', 'https://media.retroachievements.org/Images/008967.png', 4.2),
  (104, 763, 'Final Fantasy IV: Advance', 'Game Boy Advance', 5, 1440, 1440, 1440, 95, 0, NULL, 'TOSE', 'Nintendo', '2005-12-12', 'Final Fantasy IV, titled Final Fantasy II in its initial North American release, is a 1991 role-playing video game developed and published by Square for the Super Nintendo Entertainment System. It is the fourth main installment of the Final Fantasy series. The game''s story follows Cecil Harvey, a dark knight, as he tries to prevent the sorcerer Golbez from seizing powerful crystals and destroying the world. He is joined on this quest by a frequently changing group of allies. Final Fantasy IV introduced innovations that became staples of the Final Fantasy series and role-playing games in general. Its "Active Time Battle" system was used in five subsequent Final Fantasy games, and unlike prior games in the series, Final Fantasy IV gave each character their own unchangeable character class — although at a few points in the story, members of the cast change or evolve their vocation to suit the narrative.', 'https://media.retroachievements.org/Images/070792.png', 'https://media.retroachievements.org/Images/014471.png', 'https://media.retroachievements.org/Images/033778.png', 'https://media.retroachievements.org/Images/002914.png', 4.2),
  (105, 766, 'Game & Watch Gallery 4', 'Game Boy Advance', 5, 1439, 1439, 1439, 67, 0, 'Compilation', 'TOSE', 'Nintendo', '2002-10-28', 'Game & Watch Gallery 4, known as Game & Watch Gallery Advance in Europe and Australia and Game Boy Gallery 4 in Japan, is a video game developed by Tose and published by Nintendo for the Game Boy Advance in October 2002. It is the fifth and final game in the Game & Watch Gallery series, and contains 11 remastered games from the Game & Watch line of Nintendo handheld games, several of which were featured in previous series entries.', 'https://media.retroachievements.org/Images/113333.png', 'https://media.retroachievements.org/Images/014477.png', 'https://media.retroachievements.org/Images/007152.png', 'https://media.retroachievements.org/Images/007153.png', 4.2),
  (106, 7274, 'Pac-Man Pinball Advance', 'Game Boy Advance', 5, 1429, 1429, 1429, 37, 0, 'Pinball', 'Human Soft', 'Namco, Zoo Digital Publishing | Zushi Games', '2005-05-02', 'Pac-Man Pinball Advance is a pinball video game developed by Hungarian studio Human Soft and published by Namco Hometek for the Game Boy Advance. It was released in North America on May 3, 2005. It is part of the Pac-Man video game franchise.', 'https://media.retroachievements.org/Images/122950.png', 'https://media.retroachievements.org/Images/007110.png', 'https://media.retroachievements.org/Images/007111.png', 'https://media.retroachievements.org/Images/007112.png', 4.2),
  (107, 4203, 'Spyro: Season of Ice', 'Game Boy Advance', 5, 1406, 1406, 1406, 35, 0, '2.5D Platforming', 'Digital Eclipse', 'Universal Interactive', '2001-10-29', 'Spyro: Season of Ice is a 2001 platform game developed by Digital Eclipse and published by Universal Interactive Studios for the Game Boy Advance. It acts as an alternate sequel to the first three games along with Spyro 2: Season of Flame and Spyro: Attack of the Rhynocs.', 'https://media.retroachievements.org/Images/071269.png', 'https://media.retroachievements.org/Images/006568.png', 'https://media.retroachievements.org/Images/006566.png', 'https://media.retroachievements.org/Images/006567.png', 4.2),
  (108, 4200, 'Harry Potter and the Prisoner of Azkaban', 'Game Boy Advance', 5, 1402, 1402, 1402, 54, 0, 'Role-Playing', 'Griptonite Games', 'Electronic Arts', '2004-05-25', 'Harry Potter and the Prisoner of Azkaban is a fantasy novel by British author J. K. Rowling. The third novel in the Harry Potter series, it follows the young wizard Harry Potter during his third year at Hogwarts School of Witchcraft and Wizardry. With his friends Ron Weasley and Hermione Granger, Harry investigates Sirius Black, an escaped prisoner who is believed to be one of Lord Voldemort''s allies.', 'https://media.retroachievements.org/Images/023013.png', 'https://media.retroachievements.org/Images/020819.png', 'https://media.retroachievements.org/Images/020820.png', 'https://media.retroachievements.org/Images/020821.png', 4.2),
  (109, 5093, 'Mario Party Advance', 'Game Boy Advance', 5, 1402, 1402, 1402, 63, 0, 'Board Game, Minigames', 'Hudson Soft', 'Nintendo', '2005-01-13', 'Mario Party Advance is a 2005 party video game developed by Hudson Soft and published by Nintendo for the Game Boy Advance. It is the first handheld game in the Mario Party series and the seventh entry in the series overall. The game was released in Japan on January 13, 2005, North America on March 28, 2005, Europe on June 10, 2005, and Australia on September 15, 2005. The game was re-released on the Virtual Console for the Wii U in 2014.', 'https://media.retroachievements.org/Images/087672.png', 'https://media.retroachievements.org/Images/111786.png', 'https://media.retroachievements.org/Images/003219.png', 'https://media.retroachievements.org/Images/003220.png', 4.2),
  (110, 2598, 'One Piece', 'Game Boy Advance', 5, 1389, 1389, 1389, 38, 0, '2D Platforming, Action-Adventure', 'Dimps', 'Bandai', '2005-09-07', 'One Piece is a Japanese manga series written and illustrated by Eiichiro Oda. It follows the adventures of Monkey D. Luffy and his crew, the Straw Hat Pirates, as he explores the Grand Line in search of the mythical treasure known as the "One Piece" to become the next King of the Pirates.', 'https://media.retroachievements.org/Images/121444.png', 'https://media.retroachievements.org/Images/001581.png', 'https://media.retroachievements.org/Images/001578.png', 'https://media.retroachievements.org/Images/001579.png', 4.2),
  (111, 527, 'Shaman King: Master of Spirits', 'Game Boy Advance', 5, 1372, 1372, 1372, 66, 0, 'Metroidvania', 'Konami', 'Konami', '2004-11-09', 'Shaman King: Master of Spirits is a Metroidvania video game developed by Konami Computer Entertainment Japan and published by Konami. This is the first Shaman King game that was developed for the Game Boy Advance in America. It was developed to accompany the English dub by 4kids Entertainment.', 'https://media.retroachievements.org/Images/114103.png', 'https://media.retroachievements.org/Images/083763.png', 'https://media.retroachievements.org/Images/033749.png', 'https://media.retroachievements.org/Images/003330.png', 4.2),
  (112, 5030, 'Digimon Battle Spirit', 'Game Boy Advance', 5, 1365, 1365, 1365, 34, 0, 'Platform Fighting', 'Dimps', 'Bandai', '2003-01-13', 'Digimon Battle Spirit is a fighting video game originally published by Bandai and developed by Dimps for the Japanese-only WonderSwan Color handheld system under the name Digimon Tamers: Battle Spirit . It was later ported to Nintendo''s Game Boy Advance for international releases in North America and Europe two years later.', 'https://media.retroachievements.org/Images/104143.png', 'https://media.retroachievements.org/Images/026233.png', 'https://media.retroachievements.org/Images/026234.png', 'https://media.retroachievements.org/Images/026236.png', 4.2),
  (113, 5057, 'The Urbz: Sims in the City', 'Game Boy Advance', 5, 1353, 1353, 1353, 90, 0, 'Life Simulation', 'Griptonite Games', 'Electronic Arts', '2004-11-09', 'The Urbz: Sims in the City is a 2004 life simulation video game developed by Maxis and published by Electronic Arts for the Game Boy Advance, GameCube, PlayStation 2, Xbox, and Nintendo DS. It is the third Sims game for consoles, and the second not to be released for Microsoft Windows, after a planned PC port and sequel were both cancelled due to mediocre sales. The next release for consoles and handhelds was the console port of The Sims 2.', 'https://media.retroachievements.org/Images/036497.png', 'https://media.retroachievements.org/Images/015773.png', 'https://media.retroachievements.org/Images/015771.png', 'https://media.retroachievements.org/Images/015772.png', 4.2),
  (114, 2531, 'Doom II', 'Game Boy Advance', 5, 1337, 1337, 1337, 52, 0, 'First-Person Shooter', 'Torus Games', 'Activision', '2002-10-28', 'Doom II, also known as Doom II: Hell on Earth, is a 1994 first-person shooter game developed and published by id Software for MS-DOS. It was also released on Mac OS the following year. Unlike the original Doom, which was initially only available through shareware and mail order, Doom II was sold in stores, making it the first game in the Doom franchise to be released initially in stores.', 'https://media.retroachievements.org/Images/053767.png', 'https://media.retroachievements.org/Images/014456.png', 'https://media.retroachievements.org/Images/009168.png', 'https://media.retroachievements.org/Images/009169.png', 4.2),
  (115, 2179, 'Mega Man & Bass', 'Game Boy Advance', 5, 1318, 1318, 1318, 74, 0, '2D Platforming', 'Capcom', 'Capcom', '2002-08-10', 'Mega Man & Bass is a 1998 action game developed and published by Capcom. It is a spin-off game in the original Mega Man series, and was originally released in Japan for the Super Famicom on April 24, 1998. It was later ported to the Game Boy Advance in 2002, and released internationally the following year.', 'https://media.retroachievements.org/Images/028134.png', 'https://media.retroachievements.org/Images/000849.png', 'https://media.retroachievements.org/Images/122428.png', 'https://media.retroachievements.org/Images/122429.png', 4.2),
  (116, 5114, 'Yu-Gi-Oh! World Championship Tournament 2004', 'Game Boy Advance', 5, 1302, 1302, 1302, 80, 0, 'Strategy–Trading Card Game', 'Konami', 'Konami', '2004-02-10', 'Yu-Gi-Oh! World Championship Tournament 2004, known in Japan as Yu-Gi-Oh! Duel Monsters Expert 3, is a card battle video game based on the Yu-Gi-Oh! franchise. This game was released for the Game Boy Advance system in 2004, and was re-released in 2025 as part of the Yu-Gi-Oh! Early Days Collection game compilation.', 'https://media.retroachievements.org/Images/103758.png', 'https://media.retroachievements.org/Images/003300.png', 'https://media.retroachievements.org/Images/003303.png', 'https://media.retroachievements.org/Images/003304.png', 4.2),
  (117, 7159, 'The Polar Express', 'Game Boy Advance', 5, 1294, 1294, 1294, 24, 0, 'Action-Adventure', 'Tantalus Interactive', 'THQ', '2004-01-01', 'The Polar Express is a 1985 fantasy children''s picture book written and illustrated by American author Chris Van Allsburg. The book is now widely considered to be a classic Christmas story for young children. It was praised for its detailed illustrations and calm, relaxing storyline. For the work, Van Allsburg won the annual Caldecott Medal for illustration of an American children''s picture book in 1986, his second after Jumanji.', 'https://media.retroachievements.org/Images/105604.png', 'https://media.retroachievements.org/Images/077245.png', 'https://media.retroachievements.org/Images/006878.png', 'https://media.retroachievements.org/Images/006879.png', 4.2),
  (118, 3681, 'Lady Sia', 'Game Boy Advance', 5, 1278, 1278, 1278, 57, 0, '2D Platforming', 'RFX Interactive', 'TDK Mediactive', '2001-10-16', 'Lady Sia is a platform game with action-adventure elements made by RFX Interactive for the Game Boy Advance. It was published by TDK Mediactive, released in the USA on October 15, 2001, and released in Europe on October 19, 2001. Lady Sia is one of the few original games produced by RFX Interactive. The game takes place in a fantasy world where the player assumes the role of the She-Ra/Xena-esque warrior princess, Lady Sia. It is her task to defeat the T''soas, a race of creatures created by the evil warlock Onimen who has declared war on the other realms. Her quest leads her through four different realms, the last one being the home continent of the T''soas themselves. A sequel was planned for the GameCube and GBA in 2003 but was cancelled due to TDK Mediactive being purchased by Take-Two Interactive that same year.', 'https://media.retroachievements.org/Images/083613.png', 'https://media.retroachievements.org/Images/096226.png', 'https://media.retroachievements.org/Images/019009.png', 'https://media.retroachievements.org/Images/019010.png', 4.2),
  (119, 503, 'Tetris Worlds', 'Game Boy Advance', 5, 1246, 1246, 1246, 35, 0, NULL, '3d6 Games', 'THQ', '2001-09-05', 'Tetris Worlds is a version of the video game Tetris. Originally released in 2001 for Microsoft Windows and Game Boy Advance, it was later released for Xbox, GameCube, and PlayStation 2 in 2002. In 2003, an Xbox Live version titled Tetris Worlds Online and a single-disc compilation version were released for the Xbox. The latter was bundled with Xbox systems.', 'https://media.retroachievements.org/Images/109837.png', 'https://media.retroachievements.org/Images/007462.png', 'https://media.retroachievements.org/Images/026407.png', 'https://media.retroachievements.org/Images/026408.png', 4.2),
  (120, 18464, 'Classic NES Series: Metroid', 'Game Boy Advance', 5, 1236, 1236, 1236, 34, 0, '2D Platforming, Metroidvania', 'Nintendo', 'Nintendo', '2004-08-10', 'Metroid is a 1986 action-adventure game developed and published by Nintendo. The first installment in the Metroid series, it was originally released in Japan for the Family Computer Disk System in August 1986. North America received a release in August 1987 on the Nintendo Entertainment System, with the European release following in January 1988. Set on the planet Zebes, the story follows Samus Aran as she attempts to retrieve the predatory Metroid organisms that were stolen by Space Pirates, who plan to replicate the Metroids by exposing them to beta rays and then use them as biological weapons to destroy Samus and all who oppose them.', 'https://media.retroachievements.org/Images/079410.png', 'https://media.retroachievements.org/Images/096967.png', 'https://media.retroachievements.org/Images/052655.png', 'https://media.retroachievements.org/Images/052656.png', 4.2),
  (121, 3653, 'Klonoa: Empire of Dreams', 'Game Boy Advance', 5, 1216, 1216, 1216, 15, 0, '2D Platforming', 'Now Production', 'Infogrames, Namco', '2001-07-19', 'Klonoa: Empire of Dreams is a 2001 puzzle-platform game published by Namco for the Game Boy Advance. Falling somewhere between Klonoa: Door to Phantomile and Klonoa 2: Lunatea''s Veil, Empire of Dreams takes place in the new realm in the Klonoa series, the Empire of Jillius.', 'https://media.retroachievements.org/Images/077323.png', 'https://media.retroachievements.org/Images/014485.png', 'https://media.retroachievements.org/Images/033786.png', 'https://media.retroachievements.org/Images/004462.png', 4.2),
  (122, 3618, 'Crash Bandicoot Purple: Ripto''s Rampage', 'Game Boy Advance', 5, 1179, 1179, 1179, 57, 0, '2D Platforming, Minigames', 'Vicarious Visions', 'Vivendi Universal Games', '2004-06-03', 'Crash Bandicoot Purple: Ripto''s Rampage and Spyro Orange: The Cortex Conspiracy are two 2004 action games developed by Vicarious Visions and published by Vivendi Universal Games for the Game Boy Advance. The games are a crossover between the Crash Bandicoot and Spyro series, and are the fourth installments of each series made for the GBA. The story follows Crash Bandicoot and Spyro the Dragon as they team up and set out to thwart the alliance of their respective enemies Doctor Neo Cortex and Ripto. In a departure from the series'' usual format, the gameplay of both titles is based heavily on minigames.', 'https://media.retroachievements.org/Images/040178.png', 'https://media.retroachievements.org/Images/014442.png', 'https://media.retroachievements.org/Images/005803.png', 'https://media.retroachievements.org/Images/005811.png', 4.2),
  (123, 6818, 'Sonic the Hedgehog: Genesis', 'Game Boy Advance', 5, 1169, 1169, 1169, 25, 0, '2D Platforming', 'Sega', 'Sega', '2006-11-14', 'Sonic the Hedgehog is a Japanese video game series and media franchise created by the Japanese developers Yuji Naka, Naoto Ohshima, and Hirokazu Yasuhara for Sega. The franchise follows Sonic, an anthropomorphic blue hedgehog with supersonic speed, who battles the mad scientist Doctor Eggman and his robot army. The main Sonic the Hedgehog games are platformers mostly developed by Sonic Team; other games, developed by various studios, include spin-offs in the racing, fighting, party and sports genres. The franchise also incorporates printed media, animations, films, and merchandise.', 'https://media.retroachievements.org/Images/071905.png', 'https://media.retroachievements.org/Images/015209.png', 'https://media.retroachievements.org/Images/015207.png', 'https://media.retroachievements.org/Images/015208.png', 4.2),
  (124, 22659, '~Homebrew~ Sips', 'Game Boy Advance', 5, 1129, 1129, 1129, 10, 0, 'Incremental', 'Jono Shields', 'Jono Shields', '2023-02-22', 'SİPER (Trench) is a high to medium air defense surface-to-air missile (SAM) system. Designed to defend against any type of airborne threat, it can engage aircraft, cruise missiles, air-to-ground missiles and unmanned aerial vehicles (UAVs). It was jointly developed in Turkey by the companies Roketsan, Aselsan and the research institute TÜBİTAK SAGE.', 'https://media.retroachievements.org/Images/121562.png', 'https://media.retroachievements.org/Images/087377.png', 'https://media.retroachievements.org/Images/068857.png', 'https://media.retroachievements.org/Images/068858.png', 4.2),
  (125, 2595, 'Mother 1+2', 'Game Boy Advance', 5, 1111, 1111, 1111, 181, 0, 'Compilation, Turn-Based RPG', 'APE | Creatures, HAL Laboratory', 'Nintendo', '2003-06-20', 'Mother is a video game series that consists of three role-playing video games: Mother (1989), known as EarthBound Beginnings outside Japan, for the Family Computer; Mother 2 (1994), known as EarthBound outside Japan, for the Super Nintendo Entertainment System; and Mother 3 (2006) for the Game Boy Advance.', 'https://media.retroachievements.org/Images/121262.png', 'https://media.retroachievements.org/Images/022816.png', 'https://media.retroachievements.org/Images/022817.png', 'https://media.retroachievements.org/Images/022818.png', 4.2),
  (126, 26278, 'Who Wants to Be a Millionaire: Junior', 'Game Boy Advance', 5, 1103, 1103, 1103, 7, 0, 'Game Show, Trivia', 'Hothouse Creations', 'Zoo Digital Publishing | Zushi Games', '2005-09-30', 'This is a list of games released on the Game Boy Advance handheld video game system. The number of licensed games in this list is 1538, organized alphabetically by the games'' localized English titles, or, when Japan-exclusive, their rōmaji transliterations. This list does not include Game Boy Advance Video releases.', 'https://media.retroachievements.org/Images/083705.png', 'https://media.retroachievements.org/Images/083700.png', 'https://media.retroachievements.org/Images/083701.png', 'https://media.retroachievements.org/Images/083704.png', 4.2),
  (127, 5501, 'SpongeBob SquarePants: SuperSponge', 'Game Boy Advance', 5, 1070, 1070, 1070, 12, 0, '2D Platforming', 'Climax Studios', 'THQ', '2001-11-08', 'SpongeBob SquarePants: SuperSponge is a 2001 platform game based on the Nickelodeon animated television series SpongeBob SquarePants. Developed by Climax Development and published by THQ, it was released for the PlayStation on September 20, 2001, and for the Game Boy Advance on November 8, 2001.', 'https://media.retroachievements.org/Images/071506.png', 'https://media.retroachievements.org/Images/014370.png', 'https://media.retroachievements.org/Images/123183.png', 'https://media.retroachievements.org/Images/123184.png', 4.2),
  (128, 6011, 'Mr. Driller 2', 'Game Boy Advance', 5, 1069, 1069, 1069, 42, 0, 'Puzzle', 'Namco', 'Namco', '2001-03-21', 'Mr. Driller 2 is a 2000 puzzle video game developed and published by Namco for arcades. It is the second game in the Mr. Driller series, and was later ported to the Game Boy Advance and Windows in 2001 and 2002. The game introduces two new characters to the series, Puchi, and Anna.', 'https://media.retroachievements.org/Images/088319.png', 'https://media.retroachievements.org/Images/014610.png', 'https://media.retroachievements.org/Images/033747.png', 'https://media.retroachievements.org/Images/022013.png', 4.2),
  (129, 2585, 'Super Street Fighter II Turbo Revival', 'Game Boy Advance', 5, 1060, 1060, 1060, 36, 0, '2D Fighting', 'Capcom', 'Capcom', '2001-10-30', 'Super Street Fighter II Turbo, released in Japan as Super Street Fighter II X: Grand Master Challenge, is a 1994 fighting game developed and published by Capcom for arcades. It is the fifth installment in the Street Fighter II sub-series of Street Fighter games, following Super Street Fighter II (1993). Like its predecessor, it ran on the CP System II hardware.', 'https://media.retroachievements.org/Images/104583.png', 'https://media.retroachievements.org/Images/014335.png', 'https://media.retroachievements.org/Images/001564.png', 'https://media.retroachievements.org/Images/001565.png', 4.2),
  (130, 4690, 'Iridion 3D', 'Game Boy Advance', 5, 1039, 1039, 1039, 32, 0, 'Rail Shooter', 'Shin''en Multimedia', 'Majesco Entertainment', '2001-05-29', 'Iridion 3D is a quasi-3D rail shooter video game developed by Shin''en Multimedia. A launch title for the Game Boy Advance portable game console, it was released in North America on June 11, 2001 and in Europe on September 21. The player controls a single starship defending Earth from the alien Iridion. The game spans seven levels from Earth to the aliens'' home planet, each following a linear path that culminate with a boss.', 'https://media.retroachievements.org/Images/032753.png', 'https://media.retroachievements.org/Images/008658.png', 'https://media.retroachievements.org/Images/008655.png', 'https://media.retroachievements.org/Images/008656.png', 4.2),
  (131, 6161, 'Scurge: Hive', 'Game Boy Advance', 5, 1018, 1018, 1018, 46, 0, 'Metroidvania', 'Orbital Media', 'SouthPeak Interactive', '2006-10-31', 'Scurge: Hive is an action-adventure video game by Orbital Media released for the Game Boy Advance and Nintendo DS in 2006. The game follows the protagonist Jenosa Arma, a bounty huntress tasked with hunting a parasitic lifeform called the "Scurge" an alien entity capable of rapidly adapting to and infecting biological, mechanical, and digital systems, including the player. Throughout the game, Jenosa Arma will have to battle various forms of the Scurge virus and race against the clock as the parasite slowly takes over Jenosa''s body. The gameplay takes place in an isometric perspective.', 'https://media.retroachievements.org/Images/042512.png', 'https://media.retroachievements.org/Images/098498.png', 'https://media.retroachievements.org/Images/033753.png', 'https://media.retroachievements.org/Images/040297.png', 4.2),
  (132, 29025, '~Homebrew~ Apotris', 'Game Boy Advance', 5, 1011, 1011, 1011, 53, 0, NULL, 'Apostolos Kouzoukos', 'Apostolos Kouzoukos', '2022-05-04', NULL, 'https://media.retroachievements.org/Images/099287.png', 'https://media.retroachievements.org/Images/096180.png', 'https://media.retroachievements.org/Images/096719.png', 'https://media.retroachievements.org/Images/096720.png', 4.2),
  (133, 5441, 'Baldur''s Gate: Dark Alliance', 'Game Boy Advance', 5, 987, 987, 987, 39, 0, 'Action RPG, Hack & Slash', 'Magic Pockets', 'Destination Software', '2004-02-10', 'Baldur''s Gate: Dark Alliance is a 2001 action role-playing video game developed by Snowblind Studios and published by Interplay Entertainment subsidiary Black Isle Studios for the PlayStation 2 and the Xbox consoles, with High Voltage Software handling the GameCube port and Magic Pockets developing the Game Boy Advance version. CD Projekt was developing a version for Microsoft Windows, which was ultimately cancelled.', 'https://media.retroachievements.org/Images/114463.png', 'https://media.retroachievements.org/Images/008029.png', 'https://media.retroachievements.org/Images/124751.png', 'https://media.retroachievements.org/Images/124752.png', 4.2),
  (134, 22834, '~Hack~ Castlevania: Aria of Sorrow Reprise', 'Game Boy Advance', 5, 985, 985, 985, 49, 0, NULL, 'Xanthus', NULL, '2023-02-19', 'Castlevania is a video game series created and published by Konami. The series debuted in Japan on September 26, 1986, with Akumajō Dracula , which was later released as Castlevania in the United States and PAL. Titles in the series have been released on numerous video game consoles, handheld game consoles, and personal computer platforms, and several have been re-released on multiple platforms and included as part of compilation packages.', 'https://media.retroachievements.org/Images/117260.png', 'https://media.retroachievements.org/Images/087378.png', 'https://media.retroachievements.org/Images/069434.png', 'https://media.retroachievements.org/Images/069435.png', 4.2),
  (135, 7854, 'X-Men: Reign of Apocalypse', 'Game Boy Advance', 5, 959, 959, 959, 32, 0, 'Beat ''em Up', 'Digital Eclipse', 'Activision', '2001-09-25', 'X-Men: Reign of Apocalypse is a 2001 beat ''em up game developed by Digital Eclipse and published by Activision for the Game Boy Advance. Players control the X-Men as they attempt to find the missing Professor X and stop Apocalypse from devastating the world.', 'https://media.retroachievements.org/Images/084491.png', 'https://media.retroachievements.org/Images/008179.png', 'https://media.retroachievements.org/Images/008182.png', 'https://media.retroachievements.org/Images/008180.png', 4.1),
  (136, 2155, 'TMNT', 'Game Boy Advance', 5, 957, 957, 957, 38, 0, NULL, 'Ubisoft Montreal', 'Ubisoft', '2007-03-20', 'Teenage Mutant Ninja Turtles (TMNT) is an American media franchise created by comic book artists Kevin Eastman and Peter Laird. It follows Leonardo, Donatello, Raphael and Michelangelo, four anthropomorphic turtle brothers trained in ninjutsu who fight evil in New York City. The franchise encompasses printed media, television series, feature films, video games, and merchandise.', 'https://media.retroachievements.org/Images/116863.png', 'https://media.retroachievements.org/Images/049479.png', 'https://media.retroachievements.org/Images/008688.png', 'https://media.retroachievements.org/Images/008689.png', 4.1),
  (137, 9595, '~Hack~ Pokémon Adventure: Red Chapter', 'Game Boy Advance', 5, 954, 954, 954, 134, 0, 'Turn-Based RPG', 'Aethestode', NULL, '2019-01-30', '  This is a list of video game franchises, organized alphabetically. All entries include multiple video games, not counting ports or altered re-releases.', 'https://media.retroachievements.org/Images/123771.png', 'https://media.retroachievements.org/Images/026042.png', 'https://media.retroachievements.org/Images/026044.png', 'https://media.retroachievements.org/Images/026043.png', 4.1),
  (138, 17561, '~Hack~ Samus Goes to the Fridge to Get a Glass of Milk', 'Game Boy Advance', 5, 954, 954, 954, 7, 0, NULL, 'Hacker - kkzero', 'Hack - Metroid Fusion', '2020-03-02', NULL, 'https://media.retroachievements.org/Images/045271.png', 'https://media.retroachievements.org/Images/043089.png', 'https://media.retroachievements.org/Images/043085.png', 'https://media.retroachievements.org/Images/043086.png', 4.1),
  (139, 6663, 'Star Wars - Episode III: Revenge of the Sith', 'Game Boy Advance', 5, 953, 953, 953, 73, 0, 'Action, Adventure', 'Ubisoft', 'Ubisoft', '2005-05-04', 'Star Wars: Episode III – Revenge of the Sith is an action video game based on the 2005 film of the same name. It was released on May 5, 2005, for the PlayStation 2, Xbox, Game Boy Advance, Nintendo DS, and Symbian OS. For the Xbox 360''s backwards compatible lineup, Revenge of the Sith is one out of the 400+ backwards compatible games for the 360. As part of the PlayStation 2 classics program, the PlayStation 2 version was re-released in Europe on the PlayStation Network on February 11, 2015, and in North America on April 28, 2015 for PlayStation 3. Meanwhile, the Xbox version was also added to the backwards compatibility list for the Xbox One and Xbox Series X/S on November 15, 2021. A PlayStation Portable version was in development, but was cancelled. It received mixed reviews from critics.', 'https://media.retroachievements.org/Images/044088.png', 'https://media.retroachievements.org/Images/007981.png', 'https://media.retroachievements.org/Images/044102.png', 'https://media.retroachievements.org/Images/044101.png', 4.1),
  (140, 5179, 'Sigma Star Saga', 'Game Boy Advance', 5, 920, 920, 920, 89, 0, NULL, 'WayForward', 'Namco', '2005-08-16', 'Sigma Star Saga is a 2005 hybrid science fiction role-playing-space-shooter developed by WayForward Technologies and published by Namco Hometek for the Game Boy Advance. The player explores a standard 2-D overworld, but is transported into space for side-scrolling shooter random battles. The story focus on a space pilot named Ian Recker who goes undercover against Earth''s enemies, the Krill, in a battle to save the planet.', 'https://media.retroachievements.org/Images/076983.png', 'https://media.retroachievements.org/Images/009652.png', 'https://media.retroachievements.org/Images/009654.png', 'https://media.retroachievements.org/Images/009655.png', 4.1),
  (141, 29837, 'Who Wants to Be a Millionaire: 2nd Edition', 'Game Boy Advance', 5, 913, 913, 913, 7, 0, 'Game Show, Trivia', 'Hothouse Creations', 'Zoo Digital Publishing | Zushi Games', '2004-10-15', 'This is a list of games released on the Game Boy Advance handheld video game system. The number of licensed games in this list is 1538, organized alphabetically by the games'' localized English titles, or, when Japan-exclusive, their rōmaji transliterations. This list does not include Game Boy Advance Video releases.', 'https://media.retroachievements.org/Images/097735.png', 'https://media.retroachievements.org/Images/097548.png', 'https://media.retroachievements.org/Images/097550.png', 'https://media.retroachievements.org/Images/097549.png', 4.1),
  (142, 796, 'Spyro 2: Season of Flame', 'Game Boy Advance', 5, 904, 904, 904, 46, 0, '2.5D Platforming', 'Digital Eclipse', 'Universal Interactive', '2002-09-25', 'Spyro 2: Season of Flame is a 2002 platform game developed by Digital Eclipse and published by Universal Interactive for the Game Boy Advance. It is the fifth installment in the Spyro video game series and a sequel to Spyro: Season of Ice. The game''s story centers on the abduction of the Dragon Realm''s fireflies at the hands of the Rhynocs, causing the dragons to lose their ability to breathe fire. The protagonist of the story, Spyro the Dragon, must recover the fireflies and uncover the culprit behind the firefly theft.', 'https://media.retroachievements.org/Images/071270.png', 'https://media.retroachievements.org/Images/040526.png', 'https://media.retroachievements.org/Images/004307.png', 'https://media.retroachievements.org/Images/004311.png', 4.1),
  (143, 8010, '~Homebrew~ Flappy Bird', 'Game Boy Advance', 5, 861, 861, 861, 11, 0, 'Endless Runner', 'Jay Van Hutten', 'Jay Van Hutten', '2014-12-29', 'Flappy Bird is a 2013 casual mobile game developed by Vietnamese video game artist and programmer Dong Nguyen, under his game development company .Gears. The game is a side-scroller where the player controls a bird, Faby, attempting to fly between columns of green pipes without hitting them. The player''s score is determined by the number of pipes they pass. Nguyen created the game over a period of several days, using the bird from a cancelled game made in 2012.', 'https://media.retroachievements.org/Images/043921.png', 'https://media.retroachievements.org/Images/044597.png', 'https://media.retroachievements.org/Images/043917.png', 'https://media.retroachievements.org/Images/043918.png', 4.1),
  (144, 5119, 'Tokyo Xtreme Racer Advance', 'Game Boy Advance', 5, 837, 837, 837, 41, 0, 'Arcade Racing', 'David A. Palmer Productions', 'Crave Entertainment', '2005-04-20', 'This is a list of games released on the Game Boy Advance handheld video game system. The number of licensed games in this list is 1538, organized alphabetically by the games'' localized English titles, or, when Japan-exclusive, their rōmaji transliterations. This list does not include Game Boy Advance Video releases.', 'https://media.retroachievements.org/Images/095550.png', 'https://media.retroachievements.org/Images/053479.png', 'https://media.retroachievements.org/Images/053477.png', 'https://media.retroachievements.org/Images/053482.png', 4.1),
  (145, 29874, '~Demo~ WarioWare, Inc.: Trial Version', 'Game Boy Advance', 5, 811, 811, 811, 8, 0, 'Minigames', 'Nintendo', 'Nintendo', '2003-05-30', 'WarioWare: Touched! is a 2004 action game developed by Nintendo SPD and Intelligent Systems and published by Nintendo for the Nintendo DS. The fourth installment of the WarioWare series, and the first of three on the Nintendo DS, the game involves rapidly completing "microgames" — simple minigames lasting extremely short periods of time — as quickly as possible. The microgames are exclusively controlled with the Nintendo DS''s touchscreen and microphone.', 'https://media.retroachievements.org/Images/098061.png', 'https://media.retroachievements.org/Images/098114.png', 'https://media.retroachievements.org/Images/098072.png', 'https://media.retroachievements.org/Images/098073.png', 4.1),
  (146, 2509, 'River City Ransom EX', 'Game Boy Advance', 5, 811, 811, 811, 49, 0, 'Beat ''em Up', 'Million', 'Atlus', '2004-05-26', 'Downtown Nekketsu Monogatari, released as River City Ransom in North America and Street Gangs in PAL regions, is a 1989 action-adventure beat ''em up video game developed and published by Technōs Japan for the Nintendo Entertainment System. It is the third installment of the Kunio-kun series released for the NES, preceded by Renegade and Super Dodge Ball, and the first to be developed specifically for the system.', 'https://media.retroachievements.org/Images/054766.png', 'https://media.retroachievements.org/Images/008717.png', 'https://media.retroachievements.org/Images/002772.png', 'https://media.retroachievements.org/Images/017130.png', 4.1),
  (147, 2540, 'The Simpsons: Road Rage', 'Game Boy Advance', 5, 808, 808, 808, 36, 0, 'Arcade Racing', 'Radical Entertainment, Fox Interactive, Altron', 'Electronic Arts, THQ', '2001-11-24', 'The Simpsons: Road Rage is a 2001 racing video game based on the animated television series The Simpsons, and is part of a series of games based on the show. It was released for PlayStation 2, Xbox and GameCube. A Game Boy Advance version was released in 2003.', 'https://media.retroachievements.org/Images/120850.png', 'https://media.retroachievements.org/Images/016112.png', 'https://media.retroachievements.org/Images/016110.png', 'https://media.retroachievements.org/Images/016111.png', 4.1),
  (148, 5491, 'Digimon Battle Spirit 2', 'Game Boy Advance', 5, 805, 805, 805, 45, 0, 'Platform Fighting', 'Dimps', 'Bandai', '2003-09-24', 'Digimon Battle Spirit 2 is a fighting video game released for WonderSwan Color in 2002 and Game Boy Advance in 2004. It was developed by Dimps and published by Bandai based on the fourth season of the Digimon anime, Digimon Frontier. It was originally released in Japan for the WonderSwan Color handheld in December 2002 with the title Digimon Frontier: Battle Spirit . It was later ported to the Game Boy Advance for the Western market, released in North America in September 2003, and Europe in August 2004.', 'https://media.retroachievements.org/Images/104474.png', 'https://media.retroachievements.org/Images/026240.png', 'https://media.retroachievements.org/Images/026237.png', 'https://media.retroachievements.org/Images/026239.png', 4.1),
  (149, 2506, 'Teenage Mutant Ninja Turtles', 'Game Boy Advance', 5, 800, 800, 800, 29, 0, NULL, 'Konami', 'Konami', '2003-10-31', 'Teenage Mutant Ninja Turtles (TMNT) is an American media franchise created by comic book artists Kevin Eastman and Peter Laird. It follows Leonardo, Donatello, Raphael and Michelangelo, four anthropomorphic turtle brothers trained in ninjutsu who fight evil in New York City. The franchise encompasses printed media, television series, feature films, video games, and merchandise.', 'https://media.retroachievements.org/Images/104018.png', 'https://media.retroachievements.org/Images/007567.png', 'https://media.retroachievements.org/Images/007578.png', 'https://media.retroachievements.org/Images/007580.png', 4.1),
  (150, 5284, 'Spider-Man', 'Game Boy Advance', 5, 799, 799, 799, 40, 0, 'Action', 'Digital Eclipse Software', 'Activision', '2002-04-16', 'Spider-Man is a superhero in American comic books published by Marvel Comics. Created by writer-editor Stan Lee and artist Steve Ditko, he first appeared in the anthology comic book Amazing Fantasy #15 in the Silver Age of Comic Books. Widely regarded as one of the most popular and commercially successful superheroes, he has been featured in comic books, television shows, films, video games, novels, and plays.', 'https://media.retroachievements.org/Images/034056.png', 'https://media.retroachievements.org/Images/023488.png', 'https://media.retroachievements.org/Images/023489.png', 'https://media.retroachievements.org/Images/023490.png', 4.1),
  (151, 4723, 'Medabots: Metabee Version', 'Game Boy Advance', 5, 797, 797, 797, 36, 0, 'Role-Playing Game', 'Natsume', 'Natsume', '2003-03-31', 'Medabots, known in Japan as Medarot , is a Japanese role-playing video game franchise created by Rin Horuma (Horumarin) and currently owned by Imagineer. The main series of RPGs focus on collecting and battling with the titular robots. The bulk of the games releases have been on Nintendo platforms, including the Game Boy, GameCube, and the DS, and 3DS handhelds.', 'https://media.retroachievements.org/Images/041429.png', 'https://media.retroachievements.org/Images/002555.png', 'https://media.retroachievements.org/Images/003171.png', 'https://media.retroachievements.org/Images/003176.png', 4.1),
  (152, 7095, 'Shining Soul II', 'Game Boy Advance', 5, 791, 791, 791, 52, 0, 'Action RPG', 'Grasshopper Manufacture, Nex Entertainment', 'Atlus', '2004-04-20', 'Shining Soul II is an action role-playing game for the Game Boy Advance. It was developed by Grasshopper Manufacture, as the sequel to Shining Soul and part of the Shining series. The game was originally scheduled to be released on February 24, 2004, before it was delayed by two months.', 'https://media.retroachievements.org/Images/046731.png', 'https://media.retroachievements.org/Images/014903.png', 'https://media.retroachievements.org/Images/007244.png', 'https://media.retroachievements.org/Images/007245.png', 4.1),
  (153, 7202, 'The Lord of the Rings: The Two Towers', 'Game Boy Advance', 5, 781, 781, 781, 44, 0, 'Action RPG', 'Griptonite Games', 'Electronic Arts', '2002-11-08', 'The Lord of the Rings: The Two Towers is a 2002 epic fantasy film directed by Peter Jackson from a screenplay by Fran Walsh, Philippa Boyens, Stephen Sinclair, and Jackson, based on 1954''s The Two Towers, the second volume of the novel The Lord of the Rings by J. R. R. Tolkien. The sequel to 2001''s The Lord of the Rings: The Fellowship of the Ring, the film is the second instalment in The Lord of the Rings trilogy. It features an ensemble cast including Elijah Wood, Ian McKellen, Liv Tyler, Viggo Mortensen, Sean Astin, Cate Blanchett, John Rhys-Davies, Bernard Hill, Christopher Lee, Billy Boyd, Dominic Monaghan, Orlando Bloom, Hugo Weaving, Miranda Otto, David Wenham, Brad Dourif, Karl Urban, and Andy Serkis. Continuing the plot of the previous film, it intercuts three storylines: Frodo and Sam continue their journey toward Mordor to destroy the One Ring, now allied with Gollum, the ring''s untrustworthy former bearer. Merry and Pippin escape their orc captors, meet Treebeard the Ent, and help to plan an attack on Isengard, the fortress of Sauron''s vassal, the treacherous wizard Saruman. Aragorn, Legolas, and Gimli come to the war-torn nation of Rohan and are reunited with the resurrected Gandalf, before joining king Théoden to fight Saruman''s army at the Battle of Helm''s Deep.', 'https://media.retroachievements.org/Images/084114.png', 'https://media.retroachievements.org/Images/020850.png', 'https://media.retroachievements.org/Images/020848.png', 'https://media.retroachievements.org/Images/042091.png', 4.1),
  (154, 535, 'Super Puzzle Fighter II Turbo', 'Game Boy Advance', 5, 778, 778, 778, 25, 0, NULL, 'Capcom', 'Capcom', '2003-03-31', 'Super Puzzle Fighter II Turbo, released in Japan as Super Puzzle Fighter II X, is a 1996 tile-matching puzzle video game developed and published by Capcom for arcades. The game''s title is a play on Super Street Fighter II Turbo, as there were no other Puzzle Fighter games at the time, and the game includes music and interface elements spoofing the Street Fighter Alpha and Darkstalkers games. It was a response to Compile and Sega''s Puyo Puyo 2 that had been sweeping the Japanese arcade scene.', 'https://media.retroachievements.org/Images/123106.png', 'https://media.retroachievements.org/Images/001563.png', 'https://media.retroachievements.org/Images/033742.png', 'https://media.retroachievements.org/Images/001561.png', 4.1),
  (155, 4204, 'Spyro: Attack of the Rhynocs', 'Game Boy Advance', 5, 775, 775, 775, 64, 0, '2.5D Platforming, Collect-a-thon, Metroidvania', 'Digital Eclipse', 'Universal Interactive', '2003-10-28', 'Spyro: Attack of the Rhynocs is a 2003 platform game developed by Digital Eclipse and published by Universal Interactive for the Game Boy Advance. It was the last Spyro game to be released under the Universal Interactive label, which would be phased out shortly after the game''s release. It was also the final Spyro game to be developed by Digital Eclipse, who would be replaced for the next major handheld entries by Amaze Entertainment.', 'https://media.retroachievements.org/Images/071271.png', 'https://media.retroachievements.org/Images/049129.png', 'https://media.retroachievements.org/Images/008115.png', 'https://media.retroachievements.org/Images/009550.png', 4.1),
  (156, 8677, 'Classic NES Series: Donkey Kong', 'Game Boy Advance', 5, 774, 774, 774, 20, 0, '2D Platforming, Arcade', 'Nintendo', 'Nintendo', '2004-02-14', 'Donkey Kong Country, known in Japan as Super Donkey Kong, is a 1994 platform game developed by Rare and published by Nintendo for the Super Nintendo Entertainment System (SNES). It follows the gorilla Donkey Kong and his nephew Diddy Kong as they set out to recover their stolen banana hoard from the crocodile King K. Rool and his army, the Kremlings. The player traverses 40 side-scrolling levels as they jump between platforms and avoid obstacles. They collect items, ride minecarts and animals, defeat enemies and bosses, and find secret bonus stages. In multiplayer modes, two players work cooperatively or race.', 'https://media.retroachievements.org/Images/115153.png', 'https://media.retroachievements.org/Images/042606.png', 'https://media.retroachievements.org/Images/042603.png', 'https://media.retroachievements.org/Images/042604.png', 4.1),
  (157, 8915, 'Dora the Explorer: Dora''s World Adventure', 'Game Boy Advance', 5, 764, 764, 764, 19, 0, 'Adventure, Educational', 'Black Lantern Studios', 'Global Star Software', '2006-10-02', 'Game Boy Advance Video was a format for putting full color, full-motion videos onto Game Boy Advance ROM cartridges. These videos are playable using the Game Boy Advance system''s screen and sound hardware. They were all published by Majesco Entertainment, except for the Pokémon Game Boy Advance Video cartridges, which were published by Nintendo. Most cartridges were developed by DC Studios, Inc., except for the few labelled "Movie Pak" which were developed by 4Kids Entertainment''s subsidiary 4Kids Technology, Inc. The video cartridges are colored white for easy identification and are sold as Game Boy Advance Video Paks; these offer the same 240×160 resolution as standard Game Boy Advance games, except for the Shrek and Shark Tale pack, which is at 112p.', 'https://media.retroachievements.org/Images/115972.png', 'https://media.retroachievements.org/Images/016947.png', 'https://media.retroachievements.org/Images/084412.png', 'https://media.retroachievements.org/Images/084413.png', 4.1),
  (158, 5910, 'The Incredibles', 'Game Boy Advance', 5, 762, 762, 762, 21, 0, 'Beat ''em Up', 'Helixe', 'THQ', '2004-09-28', 'The Incredibles is a 2004 American animated superhero film written and directed by Brad Bird. Produced by Pixar Animation Studios for Walt Disney Pictures, it stars the voices of Craig T. Nelson, Holly Hunter, Sarah Vowell, Spencer Fox, Jason Lee, Samuel L. Jackson, and Elizabeth Peña. Set in a retro-futuristic version of the 1960s, the film follows Bob (Nelson) and Helen Parr (Hunter), a superhero couple respectively known as Mr. Incredible and Elastigirl, who hide their powers in accordance with a government mandate that outlawed superheroes, and attempt to live a quiet suburban life with their three children. However, Bob''s desire to help people draws the entire family into a confrontation with a vengeful fan-turned-foe.', 'https://media.retroachievements.org/Images/071603.png', 'https://media.retroachievements.org/Images/057804.png', 'https://media.retroachievements.org/Images/057802.png', 'https://media.retroachievements.org/Images/057803.png', 4.1),
  (159, 12963, '3 Game Pack!: The Game of Life + Payday + Yahtzee', 'Game Boy Advance', 5, 755, 755, 755, 25, 0, 'Board Game', 'Black Lantern Studios', 'Destination Software', '2005-11-07', 'This is a list of games released on the Game Boy Advance handheld video game system. The number of licensed games in this list is 1538, organized alphabetically by the games'' localized English titles, or, when Japan-exclusive, their rōmaji transliterations. This list does not include Game Boy Advance Video releases.', 'https://media.retroachievements.org/Images/060096.png', 'https://media.retroachievements.org/Images/018160.png', 'https://media.retroachievements.org/Images/018161.png', 'https://media.retroachievements.org/Images/018162.png', 4.1),
  (160, 773, 'Mega Man Battle Network 2', 'Game Boy Advance', 5, 751, 751, 751, 80, 0, 'Action RPG', 'Capcom', 'Capcom', '2002-06-17', 'Mega Man Battle Network 2 is a 2001 tactical role-playing game developed by Capcom for the Game Boy Advance (GBA) handheld game console. It is the second game in the Mega Man Battle Network series, and a sequel to the first game; it follows Lan Hikari and his NetNavi MegaMan.EXE as they attempt to take down the new NetCrime syndicate Gospel.', 'https://media.retroachievements.org/Images/086570.png', 'https://media.retroachievements.org/Images/039574.png', 'https://media.retroachievements.org/Images/033799.png', 'https://media.retroachievements.org/Images/039575.png', 4.1),
  (161, 3701, 'Duke Nukem Advance', 'Game Boy Advance', 5, 747, 747, 747, 62, 0, 'First-Person Shooter', 'Torus Games', 'Take-Two Interactive', '2002-08-12', 'Duke Nukem Advance is a 2002 video game in the Duke Nukem series, released for the Game Boy Advance. Although it is a first-person shooter and many of the graphics and sounds have been ported from Duke Nukem 3D, the game has an original storyline and levels, and can thus be considered to be a spin-off of 3D.', 'https://media.retroachievements.org/Images/092793.png', 'https://media.retroachievements.org/Images/014465.png', 'https://media.retroachievements.org/Images/004271.png', 'https://media.retroachievements.org/Images/004272.png', 4.1),
  (162, 5116, 'Yu-Gi-Oh! 7 Trials to Glory: World Championship Tournament 2005', 'Game Boy Advance', 5, 740, 740, 740, 40, 0, 'Collectible Card Game', 'Konami', 'Konami', '2004-12-30', '   The following is a list of video games developed and published by Konami, based on Kazuki Takahashi''s Yu-Gi-Oh! manga and anime franchise, along with its spin-off series. With some exceptions, the majority of the games follow the card battle gameplay of the real-life Yu-Gi-Oh! Trading Card Game. There are 59 in total.', 'https://media.retroachievements.org/Images/061105.png', 'https://media.retroachievements.org/Images/108534.png', 'https://media.retroachievements.org/Images/007218.png', 'https://media.retroachievements.org/Images/007270.png', 4.1),
  (163, 1420, 'Super Ghouls ''n Ghosts', 'Game Boy Advance', 5, 737, 737, 737, 60, 0, NULL, 'Capcom', 'Capcom', '2002-09-23', 'Super Ghouls ''n Ghosts, known as Chō Makaimura in Japan, is a 1991 platform video game developed and published by Capcom for the Super Nintendo Entertainment System. The third installment in the Ghosts ''n Goblins series and the first not to be released for arcades, it again depicts knight Arthur saving Princess Guinevere and the kingdom from Emperor Sardius, who has cast a spell that has revived the Ghoul Realm.', 'https://media.retroachievements.org/Images/052636.png', 'https://media.retroachievements.org/Images/017207.png', 'https://media.retroachievements.org/Images/048223.png', 'https://media.retroachievements.org/Images/048226.png', 4.1),
  (164, 9226, 'Wolfenstein 3D', 'Game Boy Advance', 5, 721, 721, 721, 28, 0, 'First-Person Shooter', 'id Software', 'BAM! Entertainment', '2002-04-02', 'Wolfenstein 3D is a 1992 first-person shooter game developed by id Software and published by Apogee Software and FormGen for MS-DOS. It was inspired by the 1981 Muse Software video game Castle Wolfenstein, and is the third installment in the Wolfenstein series. In Wolfenstein 3D, the player assumes the role of Allied spy William "B.J." Blazkowicz during World War II as he escapes from the Nazi German prison Castle Wolfenstein and carries out a series of crucial missions against the Nazis. The player traverses each of the game''s levels to find an elevator to the next level or kill a final boss, fighting Nazi soldiers, dogs, and other enemies with a knife and a variety of guns.', 'https://media.retroachievements.org/Images/064379.png', 'https://media.retroachievements.org/Images/094843.png', 'https://media.retroachievements.org/Images/094844.png', 'https://media.retroachievements.org/Images/094842.png', 4.1),
  (165, 4197, 'Harry Potter and the Chamber of Secrets', 'Game Boy Advance', 5, 709, 709, 709, 30, 0, 'Action, Adventure', 'Eurocom', 'Electronic Arts', '2002-11-14', 'Harry Potter and the Chamber of Secrets is a fantasy novel by British author J. K. Rowling. The second novel in the Harry Potter series, it chronicles Harry Potter''s second year at Hogwarts School of Witchcraft and Wizardry. After several residents of the school are attacked and magically immobilised, Harry and his friends Ron and Hermione investigate.', 'https://media.retroachievements.org/Images/114342.png', 'https://media.retroachievements.org/Images/020807.png', 'https://media.retroachievements.org/Images/020814.png', 'https://media.retroachievements.org/Images/020815.png', 4.1),
  (166, 6209, 'Guilty Gear X Advance Edition', 'Game Boy Advance', 5, 703, 703, 703, 54, 0, '2D Fighting', 'Arc System Works', 'Sammy', '2002-08-29', 'Guilty Gear X, subtitled By Your Side in Japan, is a fighting game developed by Arc System Works and published by Sammy Studios. The second installment of the Guilty Gear series, Guilty Gear X was developed over a period of about two years after the first game''s success. It was released in July 2000 for Japanese arcades, re-released on Dreamcast in December 2000, and later ported to PlayStation 2 in November 2001 and Game Boy Advance in January 2002.', 'https://media.retroachievements.org/Images/070045.png', 'https://media.retroachievements.org/Images/007277.png', 'https://media.retroachievements.org/Images/007278.png', 'https://media.retroachievements.org/Images/007280.png', 4.1),
  (167, 5764, '~Hack~ Castlevania: Aria of Sorrow Alter', 'Game Boy Advance', 5, 699, 699, 699, 64, 0, 'Metroidvania', 'Kseptuple', NULL, '2019-03-31', 'Castlevania: Circle of the Moon, titled Castlevania in PAL regions, is a 2001 action role-playing game developed and published by Konami for the Game Boy Advance handheld game console. The game was developed as a stand-alone title in the Castlevania series and as a launch title for the Game Boy Advance.', 'https://media.retroachievements.org/Images/024703.png', 'https://media.retroachievements.org/Images/024702.png', 'https://media.retroachievements.org/Images/024700.png', 'https://media.retroachievements.org/Images/024701.png', 4.1),
  (168, 6407, 'Nicktoons: Battle for Volcano Island', 'Game Boy Advance', 5, 675, 675, 675, 16, 0, '2D Platforming', 'Halfbrick Studios', 'THQ', '2006-01-01', 'Nicktoons: Battle for Volcano Island is an action-adventure video game developed by Blue Tongue Entertainment, Halfbrick (GBA), Natsume (DS), published by THQ, and it is the sequel to the 2005 video game Nicktoons Unite!. The game was first released on October 24, 2006.', 'https://media.retroachievements.org/Images/121939.png', 'https://media.retroachievements.org/Images/014597.png', 'https://media.retroachievements.org/Images/122154.png', 'https://media.retroachievements.org/Images/014595.png', 4.1),
  (169, 4092, 'Shaman King: Master of Spirits 2', 'Game Boy Advance', 5, 666, 666, 666, 55, 0, 'Metroidvania', 'KCEJ', 'Konami', '2005-08-02', 'Shaman King: Master of Spirits 2 is the sequel to the Game Boy Advance game Shaman King: Master of Spirits that had been released in 2004. Konami decided to make a sequel to this game, released on August 2, 2005, in the United States and Europe.', 'https://media.retroachievements.org/Images/114112.png', 'https://media.retroachievements.org/Images/003345.png', 'https://media.retroachievements.org/Images/003343.png', 'https://media.retroachievements.org/Images/003344.png', 4.1),
  (170, 6289, 'Donald Duck Advance!', 'Game Boy Advance', 5, 657, 657, 657, 30, 0, '2D Platforming', 'Disney Interactive Studios', 'Ubisoft', '2001-11-15', 'Donald Duck: Goin'' Quackers is a 2000 platform game developed and published by Ubi Soft for various consoles and Windows-based personal computers. A version with the same title was released for the Game Boy Color, before it was retitled Donald Duck Advance for the Game Boy Advance. Reviews praised the music, backgrounds and animations, noting the short length and low difficulty as more fun for children.', 'https://media.retroachievements.org/Images/125240.png', 'https://media.retroachievements.org/Images/097504.png', 'https://media.retroachievements.org/Images/097502.png', 'https://media.retroachievements.org/Images/097503.png', 4.1),
  (171, 5747, 'The Lost Vikings', 'Game Boy Advance', 5, 653, 653, 653, 28, 0, NULL, 'Mass Media', 'Mass Media', '2003-01-01', 'The Lost Vikings is a 1993 puzzle-platform game developed by Silicon & Synapse and published by Interplay Productions. In the game, the player controls three separate vikings with different abilities. The three vikings must work together to finish each level and find their way back home.', 'https://media.retroachievements.org/Images/064700.png', 'https://media.retroachievements.org/Images/096971.png', 'https://media.retroachievements.org/Images/004621.png', 'https://media.retroachievements.org/Images/004622.png', 4.1),
  (172, 5720, 'LEGO Star Wars II: The Original Trilogy', 'Game Boy Advance', 5, 644, 644, 644, 54, 0, 'Action-Adventure', 'Amaze Entertainment', 'LucasArts | Lucasfilm', '2006-09-12', 'Lego Star Wars II: The Original Trilogy is a 2006 Lego-themed action-adventure game developed by Traveller''s Tales and published by LucasArts and TT Games Publishing, and is the sequel to Lego Star Wars: The Video Game (2005). Part of the Lego Star Wars series, it is based on George Lucas''s movie franchise of the same name and The Lego Group''s Lego Star Wars construction toy line. It follows the events of the first three original Star Wars films: A New Hope (1977), The Empire Strikes Back (1980), and Return of the Jedi (1983). The game allows players to assume the roles of over 50 Lego versions of characters from the film series; customized characters can also be created. Camera movement was improved from its predecessor, and the concept of "vehicle levels" was explored more thoroughly. The game was revealed at American International Toy Fair. Promotions for the game were set up at chain stores across the United States.', 'https://media.retroachievements.org/Images/064198.png', 'https://media.retroachievements.org/Images/004775.png', 'https://media.retroachievements.org/Images/004776.png', 'https://media.retroachievements.org/Images/004777.png', 4),
  (173, 9301, 'Frogger''s Adventures: Temple of the Frog', 'Game Boy Advance', 5, 638, 638, 638, 26, 0, '2.5D Platforming', 'Konami', 'Konami', '2001-11-22', 'Frogger''s Adventures: Temple of the Frog is a 2001 platform video game developed and published by Konami for the Game Boy Advance. It was followed by Frogger''s Adventures 2: The Lost Wand in 2002 for the same console. In 2003, another game titled Frogger''s Adventures: The Rescue appeared for PlayStation 2, GameCube and Windows.', 'https://media.retroachievements.org/Images/067742.png', 'https://media.retroachievements.org/Images/061358.png', 'https://media.retroachievements.org/Images/061359.png', 'https://media.retroachievements.org/Images/061357.png', 4),
  (174, 6950, 'Jet Grind Radio', 'Game Boy Advance', 5, 623, 623, 623, 68, 0, '2.5D Platforming, Extreme Sports - Inline Skating', 'Vicarious Visions', 'Sega, THQ', '2003-06-26', 'Jet Set Radio is a 2000 action-platform video game developed by Smilebit and published by Sega for the Dreamcast. The player controls a member of the GG''s, a youth gang that uses inline skates to traverse Tokyo while spraying graffiti, challenging rival gangs, and evading authorities.', 'https://media.retroachievements.org/Images/052346.png', 'https://media.retroachievements.org/Images/052362.png', 'https://media.retroachievements.org/Images/052358.png', 'https://media.retroachievements.org/Images/052361.png', 4),
  (175, 8038, '~Homebrew~ Sushi the Cat', 'Game Boy Advance', 5, 620, 620, 620, 7, 0, '2D Platforming', 'N3TKAT', 'N3TKAT', '2007-11-12', 'Earthworm Jim is a 1994 run and gun platform game developed by Shiny Entertainment, featuring an earthworm named Jim, who wears a robotic suit and battles the forces of evil. The game was released for the Sega Genesis and Super Nintendo Entertainment System, before being subsequently ported to several other video game consoles.', 'https://media.retroachievements.org/Images/051052.png', 'https://media.retroachievements.org/Images/051314.png', 'https://media.retroachievements.org/Images/052002.png', 'https://media.retroachievements.org/Images/052003.png', 4),
  (176, 5029, 'Tactics Ogre: The Knight of Lodis', 'Game Boy Advance', 5, 613, 613, 613, 87, 0, 'Tactical RPG', 'Quest', 'Atlus', '2002-05-07', 'Tactics Ogre: The Knight of Lodis is a tactical role-playing game developed by Quest Corporation and published by Nintendo for the Game Boy Advance (GBA). It was released in Japan in 2001, and in North America by Atlus USA in 2002. It is a spin-off of Tactics Ogre (1995), acting as a prequel to the rest of the Ogre Battle series. It was the last video game developed by Quest before their acquisition by Square.', 'https://media.retroachievements.org/Images/066976.png', 'https://media.retroachievements.org/Images/010137.png', 'https://media.retroachievements.org/Images/033741.png', 'https://media.retroachievements.org/Images/025129.png', 4),
  (177, 25306, '~Homebrew~ Neo Racing Genesis', 'Game Boy Advance', 5, 611, 611, 611, 7, 0, 'Arcade Racing', 'Dan Prati', NULL, '2001-12-27', 'The following is a list of notable vehicle racing video games. The genre first emerged in the mid- to late 1970s.', 'https://media.retroachievements.org/Images/079052.png', 'https://media.retroachievements.org/Images/087381.png', 'https://media.retroachievements.org/Images/079051.png', 'https://media.retroachievements.org/Images/079053.png', 4),
  (178, 749, 'Classic NES Series: Zelda II: The Adventure of Link', 'Game Boy Advance', 5, 606, 606, 606, 29, 0, 'Action RPG', 'Nintendo', 'Nintendo', '2004-08-10', 'Zelda II: The Adventure of Link is a 1987 action role-playing game developed and published by Nintendo. It is the second installment in the Legend of Zelda series, and was released in Japan for the Famicom Disk System on January 14, 1987, less than a year after the Japanese release and seven months before the North American release of the original The Legend of Zelda. Zelda II was released in North America and the PAL region for the Nintendo Entertainment System in late 1988, almost two years after its initial release in Japan.', 'https://media.retroachievements.org/Images/045977.png', 'https://media.retroachievements.org/Images/001384.png', 'https://media.retroachievements.org/Images/001389.png', 'https://media.retroachievements.org/Images/001390.png', 4),
  (179, 7191, 'The Lord of the Rings: The Return of the King', 'Game Boy Advance', 5, 595, 595, 595, 57, 0, 'Action RPG', 'Griptonite Games', 'Electronic Arts', '2003-11-05', 'The Lord of the Rings: The Return of the King is a 2003 epic fantasy film directed by Peter Jackson from a screenplay he wrote with Fran Walsh and Philippa Boyens. It is based on 1955''s The Return of the King, the third volume of the novel The Lord of the Rings by J. R. R. Tolkien. The sequel to 2002''s  The Lord of the Rings: The Two Towers, the film is the final instalment in The Lord of the Rings trilogy. It has an ensemble cast including Elijah Wood, Ian McKellen, Liv Tyler, Viggo Mortensen, Sean Astin, Cate Blanchett, John Rhys-Davies, Bernard Hill, Billy Boyd, Dominic Monaghan, Orlando Bloom, Hugo Weaving, Miranda Otto, David Wenham, Karl Urban, John Noble, Andy Serkis, Ian Holm, and Sean Bean. Continuing the plot of the previous film, Frodo and Sam follow Gollum towards Mount Doom to destroy the One Ring, unaware of Gollum''s intentions to betray the duo to take the Ring for himself, while Merry, Pippin, Gandalf, Aragorn, Legolas, Gimli and their allies join forces against Sauron and his legions from Mordor.', 'https://media.retroachievements.org/Images/053150.png', 'https://media.retroachievements.org/Images/053151.png', 'https://media.retroachievements.org/Images/008493.png', 'https://media.retroachievements.org/Images/008491.png', 4),
  (180, 2190, 'Yu-Gi-Oh! GX: Duel Academy', 'Game Boy Advance', 5, 595, 595, 595, 41, 0, 'Collectible Card Game', 'Konami', 'Konami', '2006-01-10', 'This is a list of games released on the Game Boy Advance handheld video game system. The number of licensed games in this list is 1538, organized alphabetically by the games'' localized English titles, or, when Japan-exclusive, their rōmaji transliterations. This list does not include Game Boy Advance Video releases.', 'https://media.retroachievements.org/Images/094383.png', 'https://media.retroachievements.org/Images/024089.png', 'https://media.retroachievements.org/Images/026285.png', 'https://media.retroachievements.org/Images/003132.png', 4),
  (181, 16160, '~Hack~ Hypno''s Lullaby', 'Game Boy Advance', 5, 593, 593, 593, 8, 0, 'Turn-Based RPG', '7G06', NULL, '2012-12-09', 'Twitch Plays Pokémon (TPP) is a social experiment and channel on the video game live streaming website Twitch, consisting of a crowdsourced attempt to play Game Freak''s and Nintendo''s Pokémon video games by parsing commands sent by users through the channel''s chat room. It holds the Guinness World Record for having "the most users to input a command to play a live streamed videogame" with 1,165,140 participants.', 'https://media.retroachievements.org/Images/088908.png', 'https://media.retroachievements.org/Images/033128.png', 'https://media.retroachievements.org/Images/033130.png', 'https://media.retroachievements.org/Images/033131.png', 4),
  (182, 5564, 'Yu Yu Hakusho: Ghost Files - Tournament Tactics', 'Game Boy Advance', 5, 587, 587, 587, 60, 0, 'Tactical RPG', 'Sensory Sweep Studios', 'Atari', '2004-01-01', 'YuYu Hakusho  is a Japanese manga series written and illustrated by Yoshihiro Togashi. It was serialized in Shueisha''s shōnen manga magazine Weekly Shōnen Jump from December 1990 to July 1994. It consists of 175 chapters collected in 19 tankōbon volumes.', 'https://media.retroachievements.org/Images/085611.png', 'https://media.retroachievements.org/Images/085112.png', 'https://media.retroachievements.org/Images/113691.png', 'https://media.retroachievements.org/Images/113692.png', 4),
  (183, 4707, 'Shining Force: Resurrection of the Dark Dragon', 'Game Boy Advance', 5, 585, 585, 585, 72, 0, 'Tactical RPG', 'Amusement Vision', 'Sega, Atlus', '2004-06-08', 'Shining Force: The Legacy of Great Intention, commonly referred to as Shining Force, is a 1992 turn-based tactical role-playing game developed by Climax Entertainment and Sonic! Software Planning and published by Sega for the Sega Genesis. It is the second entry of the Shining series, following 1991''s Shining in the Darkness. While primarily a traditional fantasy-themed game, it contains some science fiction elements.', 'https://media.retroachievements.org/Images/082398.png', 'https://media.retroachievements.org/Images/018295.png', 'https://media.retroachievements.org/Images/018293.png', 'https://media.retroachievements.org/Images/018294.png', 4),
  (184, 7644, 'Avatar: The Last Airbender', 'Game Boy Advance', 5, 583, 583, 583, 46, 0, 'Action-Adventure', 'Halfbrick Studios', 'THQ', '2006-10-10', 'Avatar: The Last Airbender, also known as Avatar: The Legend of Aang in some regions, is an American animated fantasy action television series created by Michael Dante DiMartino and Bryan Konietzko. Produced by Nickelodeon Animation Studio, it originally aired on Nickelodeon for three seasons from February 2005 to July 2008.', 'https://media.retroachievements.org/Images/076401.png', 'https://media.retroachievements.org/Images/023527.png', 'https://media.retroachievements.org/Images/023531.png', 'https://media.retroachievements.org/Images/023532.png', 4),
  (185, 6141, 'Crash of the Titans', 'Game Boy Advance', 5, 579, 579, 579, 56, 0, '2D Platforming', 'Amaze Entertainment', 'Sierra Entertainment', '2007-10-04', 'Crash of the Titans is a 2007 platform game developed by Radical Entertainment and published by Vivendi Games for the PlayStation 2, PlayStation Portable, Wii and Xbox 360. The sixth mainline game in the Crash Bandicoot series, it was the last to be published by Vivendi Games before Activision merged with the company the following year. Amaze Entertainment developed two separate versions of the game: one for the Nintendo DS and one for the Game Boy Advance. The game is the fourteenth installment in the Crash Bandicoot video game series, and the sixth game in the main franchise.', 'https://media.retroachievements.org/Images/122803.png', 'https://media.retroachievements.org/Images/096969.png', 'https://media.retroachievements.org/Images/006712.png', 'https://media.retroachievements.org/Images/033827.png', 4),
  (186, 9877, '~Hack~ Pokémon Theta Emerald Renev', 'Game Boy Advance', 5, 577, 577, 577, 138, 0, 'Turn-Based RPG', 'LCCoolJ95', 'Hack - Pokemon Emerald Version', '2018-01-01', NULL, 'https://media.retroachievements.org/Images/031416.png', 'https://media.retroachievements.org/Images/044483.png', 'https://media.retroachievements.org/Images/029377.png', 'https://media.retroachievements.org/Images/016122.png', 4),
  (187, 774, 'Mega Man Battle Network 3: Blue Version', 'Game Boy Advance', 5, 575, 575, 575, 79, 0, 'Action RPG', 'Capcom', 'Capcom', '2003-06-24', 'Mega Man Battle Network is a tactical role-playing video game series created by Masahiro Yasuma and developed and published by Capcom as a spin-off of the Mega Man series. Released in 2001 for the Game Boy Advance, it takes place in an alternate continuity of Mega Man where computers and networking technology was the main focus on scientific advancement, rather than robotics. There are a total of six mainline games, alongside several spin-offs.', 'https://media.retroachievements.org/Images/102929.png', 'https://media.retroachievements.org/Images/039350.png', 'https://media.retroachievements.org/Images/033800.png', 'https://media.retroachievements.org/Images/039349.png', 4),
  (188, 12786, 'Dora the Explorer: The Search for Pirate Pig''s Treasure', 'Game Boy Advance', 5, 572, 572, 572, 37, 0, 'Adventure', 'Cinegroupe', 'NewKidCo', '2002-12-13', 'This is a list of games released on the Game Boy Advance handheld video game system. The number of licensed games in this list is 1538, organized alphabetically by the games'' localized English titles, or, when Japan-exclusive, their rōmaji transliterations. This list does not include Game Boy Advance Video releases.', 'https://media.retroachievements.org/Images/016907.png', 'https://media.retroachievements.org/Images/016906.png', 'https://media.retroachievements.org/Images/016905.png', 'https://media.retroachievements.org/Images/016908.png', 4),
  (189, 6087, 'Pocky & Rocky with Becky', 'Game Boy Advance', 5, 551, 551, 551, 36, 0, NULL, 'Altron', 'Natsume', '2001-10-05', 'Pocky & Rocky with Becky, known in Japan as Kiki Kaikai Advance (奇々怪界あどばんす), is a shoot ''em up video game for the Game Boy Advance handheld game console where the player may control either Pocky, Rocky, or Becky, the latter originating from the spin-off KiKi KaiKai: Dotou-hen, as they attempt to defeat a ghostly hydra who escaped his seal. The player character takes two hits to lose a life, but only one in Japan. While prior entries were developed by Taito, this game was developed and published by Altron in Japan, and published by Natsume Inc. in North America.', 'https://media.retroachievements.org/Images/122421.png', 'https://media.retroachievements.org/Images/049833.png', 'https://media.retroachievements.org/Images/049811.png', 'https://media.retroachievements.org/Images/049812.png', 4),
  (190, 9842, '~Hack~ Super Metroid: GBA Edition', 'Game Boy Advance', 5, 548, 548, 548, 46, 0, 'Metroidvania', 'The Brothers Crafters', 'Hack - Metroid: Zero Mission', '2020-12-15', 'Metroid is an action-adventure game franchise created by Nintendo. The player controls the bounty hunter Samus Aran, who protects the galaxy from Space Pirates and their attempts to harness the power of the parasitic Metroid creatures. Metroid combines the platforming of Super Mario Bros. and the exploration of The Legend of Zelda with a science fiction setting and an emphasis on nonlinear gameplay. Most Metroid games are side-scrolling, while the 3D games use a first-person perspective. Players battle hostile alien enemies and obtain power-ups as they progress through the game world, with few non-player characters.', 'https://media.retroachievements.org/Images/060092.png', 'https://media.retroachievements.org/Images/051199.png', 'https://media.retroachievements.org/Images/042049.png', 'https://media.retroachievements.org/Images/042050.png', 4),
  (191, 24054, 'SpongeBob''s Atlantis SquarePantis', 'Game Boy Advance', 5, 548, 548, 548, 29, 0, '2D Platforming', 'Altron', 'THQ', '2007-10-23', 'SpongeBob''s Atlantis SquarePantis is the first television film and the 92nd episode of the American animated television series SpongeBob SquarePants, and a 2007 made-for-television musical comedy film directed by Andrew Overtoom. It first aired on Nickelodeon in the United States on November 12, 2007, serving as the twelfth episode of the fifth season of the American animated television series SpongeBob SquarePants. It released again on November 23, 2007 with Patchy segments. In the special, SpongeBob and Patrick discover a half of an ancient medallion that helps them and their friends get to the lost city of Atlantis. It was written by Casey Alexander, Zeus Cervas, Steven Banks, and Dani Michaeli. British musician and actor David Bowie guest starred as the voice of Lord Royal Highness. Upon release, it attracted an estimated 9.22 million viewers, becoming the most watched episode of the entire series. Despite this, it received mixed reviews from critics and audiences alike, while the Patchy subplot received mixed to negative reviews.', 'https://media.retroachievements.org/Images/116267.png', 'https://media.retroachievements.org/Images/071379.png', 'https://media.retroachievements.org/Images/071377.png', 'https://media.retroachievements.org/Images/071378.png', 4),
  (192, 4738, 'The King of Fighters EX: Neo Blood', 'Game Boy Advance', 5, 545, 545, 545, 28, 0, '2D Fighting', 'SNK', 'SNK', '2002-01-01', 'The King of Fighters EX: Neo Blood is a fighting game developed by Playmore and Artoon in 2002 for Nintendo''s Game Boy Advance. Despite being based on The King of Fighters ''99 in terms of systems and design, the game features different playable characters with an original storyline involving Kyo Kusanagi and his friends being the protagonist of a new "King of Fighters" tournament set by crimelord Geese Howard. The game offers several returning characters with Kyo''s ally Moe Habana being a new character. Despite SNK going bankrupt, there were no issues with the development of the game, with Marvelous Entertainment developing it. The game received positive response by critics for its controls and cast and was followed by a sequel titled The King of Fighters EX2: Howling Blood in 2003.', 'https://media.retroachievements.org/Images/079759.png', 'https://media.retroachievements.org/Images/006970.png', 'https://media.retroachievements.org/Images/006967.png', 'https://media.retroachievements.org/Images/006968.png', 4),
  (193, 4881, 'DemiKids: Dark Version', 'Game Boy Advance', 5, 542, 542, 542, 81, 0, 'Turn-Based RPG', 'Multimedia Intelligence Transfer', 'Atlus', '2003-10-07', 'Shin Megami Tensei: Devil Children, also known as DemiKids, is a series of role-playing video games primarily developed by Multimedia Intelligence Transfer and published by Atlus. It is a spin-off from Atlus'' Megami Tensei franchise, and began in 2000 with the Game Boy Color games Black Book and Red Book. Five more role-playing games and three games in other genres were released until 2004, followed by no new releases until the 2011 social game Shin Megami Tensei: Devil Children. In addition to the games, the series has been adapted into manga, anime, and a trading card game, and two soundtrack albums have been released by First Smile Entertainment.', 'https://media.retroachievements.org/Images/082326.png', 'https://media.retroachievements.org/Images/007855.png', 'https://media.retroachievements.org/Images/033773.png', 'https://media.retroachievements.org/Images/007854.png', 4),
  (194, 6620, 'Zooo: Action Puzzle Game', 'Game Boy Advance', 5, 541, 541, 541, 22, 0, 'Tile Matching', 'Buddiez', 'Ignition Entertainment', '2003-10-31', 'This is a list of games released on the Game Boy Advance handheld video game system. The number of licensed games in this list is 1538, organized alphabetically by the games'' localized English titles, or, when Japan-exclusive, their rōmaji transliterations. This list does not include Game Boy Advance Video releases.', 'https://media.retroachievements.org/Images/036704.png', 'https://media.retroachievements.org/Images/107671.png', 'https://media.retroachievements.org/Images/036701.png', 'https://media.retroachievements.org/Images/036702.png', 4),
  (195, 6772, 'Scooby-Doo! Unmasked', 'Game Boy Advance', 5, 537, 537, 537, 28, 0, '2D Platforming', 'Artificial Mind and Movement', 'THQ', '2005-09-12', 'Scooby-Doo! Unmasked is a platform game based on the Scooby-Doo franchise. It was developed by Artificial Mind and Movement and published by THQ for the Xbox, PlayStation 2, GameCube, Game Boy Advance, and Nintendo DS.', 'https://media.retroachievements.org/Images/108667.png', 'https://media.retroachievements.org/Images/011165.png', 'https://media.retroachievements.org/Images/011167.png', 'https://media.retroachievements.org/Images/011168.png', 4),
  (196, 761, 'Earthworm Jim', 'Game Boy Advance', 5, 531, 531, 531, 59, 0, '2D Platforming', 'Shiny Entertainment, Game Titan', 'Interplay Entertainment', '2001-06-10', 'Earthworm Jim is a series of platform games featuring an earthworm named Jim who wears a robotic suit and battles the forces of evil. The series is noted for its platforming and shooting gameplay, surreal humor, and edgy art style. Four games were released in the series: Earthworm Jim, Earthworm Jim 2, Earthworm Jim 3D, and Earthworm Jim: Menace 2 the Galaxy, with the first game released in 1994. The series had lain dormant for almost a decade before Gameloft remade the original game in HD for PlayStation Network and Xbox Live Arcade in 2010. Interplay announced Earthworm Jim 4 in 2008; little to no information surfaced until May 2019 and August 2020, and development was believed cancelled by the rights owners by 2023, as it had never left pre-planning stages.', 'https://media.retroachievements.org/Images/121734.png', 'https://media.retroachievements.org/Images/093959.png', 'https://media.retroachievements.org/Images/089684.png', 'https://media.retroachievements.org/Images/089685.png', 4),
  (197, 2589, 'Summon Night: Swordcraft Story 2', 'Game Boy Advance', 5, 530, 530, 530, 81, 0, NULL, 'Flight-Plan', 'Atlus', '2006-10-17', 'Summon Night: Swordcraft Story 2  is a 2004 action role-playing game developed by Flight-Plan for the Game Boy Advance. It is part of the Summon Night series of games, and is the sequel to Summon Night: Swordcraft Story. The game was first released in Japan by Banpresto in August 2004, and in North America by Atlus in October 2006. The game received generally favorable reviews. It was followed by Summon Night Swordcraft Story 3: Stone of Beginnings, released in December 2005.', 'https://media.retroachievements.org/Images/122120.png', 'https://media.retroachievements.org/Images/011161.png', 'https://media.retroachievements.org/Images/011162.png', 'https://media.retroachievements.org/Images/011163.png', 4),
  (198, 6759, 'Denki Blocks!', 'Game Boy Advance', 5, 525, 525, 525, 33, 0, NULL, 'Rage Software', 'Majesco Entertainment', '2001-10-30', 'Denki Blocks! is a puzzle video game developed by Denki and originally released in 2001 by Rage Games for Sky Gamestar and the Game Boy Color and Game Boy Advance. In the game, players manoeuvre different coloured blocks around a grid to join those of the same colour together. The game features versus modes for multiple players. Denki Blocks! was ported to the PlayStation Portable in 2011 by Tiger Games, and to Android the same year and iOS in 2010.', 'https://media.retroachievements.org/Images/116149.png', 'https://media.retroachievements.org/Images/014443.png', 'https://media.retroachievements.org/Images/116148.png', 'https://media.retroachievements.org/Images/006659.png', 4),
  (199, 2172, 'Mortal Kombat: Deadly Alliance', 'Game Boy Advance', 5, 525, 525, 525, 57, 0, '3D Fighting', 'Midway', 'Midway', '2002-11-20', 'Mortal Kombat: Deadly Alliance is a 2002 fighting game developed and published by Midway for the Xbox, PlayStation 2 (PS2), GameCube, and Game Boy Advance (GBA). It was the first all-new Mortal Kombat fighting game produced exclusively for home consoles, with no preceding arcade release. It is the fifth main installment in the Mortal Kombat franchise and a sequel to 1997''s Mortal Kombat 4. Its story focuses on the eponymous alliance between sorcerers Quan Chi and Shang Tsung and their schemes to revive an ancient army to conquer Outworld and Earthrealm. The game is the only main installment not to feature series protagonist Liu Kang as a playable character. It is also the first game in the canon series to not have the involvement of co-creator John Tobias, who had left Midway in 1999 to pursue other interests.', 'https://media.retroachievements.org/Images/073151.png', 'https://media.retroachievements.org/Images/012070.png', 'https://media.retroachievements.org/Images/012074.png', 'https://media.retroachievements.org/Images/012075.png', 4),
  (200, 4909, 'Mega Man Battle Chip Challenge', 'Game Boy Advance', 5, 523, 523, 523, 32, 0, NULL, 'Inti Creates', 'Capcom', '2004-03-03', 'Mega Man Battle Chip Challenge, known in Japan as Rockman EXE Battle Chip GP, is a video game developed by Inti Creates and published by Capcom for the Game Boy Advance (GBA) handheld game console. It is a spin-off title in the Mega Man Battle Network series. The game saw a simultaneous August 8, 2003 release in Japan on the WonderSwan Color and Swan Crystal titled Rockman EXE N1 Battle. The GBA version was localized in North America and Europe the following March. The game was released on the Wii U''s Virtual Console on July 30, 2014 in Japan, with both the North American and PAL region release occurring in August 2014.', 'https://media.retroachievements.org/Images/038243.png', 'https://media.retroachievements.org/Images/040305.png', 'https://media.retroachievements.org/Images/003046.png', 'https://media.retroachievements.org/Images/003047.png', 4);
INSERT INTO games (rank, id, title, consoleName, consoleId, totalPlayers, casualPlayers, hardcorePlayers, numAchievements, points, genre, developer, publisher, released, description, icon, boxArt, titleScreen, screenshot, rating) VALUES
  (1, 5371, 'The Legend of Zelda: Link''s Awakening DX', 'Game Boy Color', 6, 17387, 17387, 17387, 110, 0, 'Action-Adventure', 'Nintendo', 'Nintendo', '1998-12-12', 'The Legend of Zelda: Link''s Awakening DX is a 1998 action-adventure game developed and published by Nintendo for the Game Boy Color. The game is a colorized version of the 1993 Game Boy title The Legend of Zelda: Link''s Awakening, in which protagonist Link must fight monsters, explore dungeons and solve puzzles to escape from Koholint Island. The DX version of Link''s Awakening features gameplay additions including a color-themed dungeon and support for the Game Boy Printer.', 'https://media.retroachievements.org/Images/046977.png', 'https://media.retroachievements.org/Images/005961.png', 'https://media.retroachievements.org/Images/005959.png', 'https://media.retroachievements.org/Images/005960.png', 5),
  (2, 810, 'Pokémon Crystal Version', 'Game Boy Color', 6, 12586, 12586, 12586, 113, 0, 'Turn-Based RPG', 'Game Freak', 'Nintendo', '2000-12-14', 'Pokémon Crystal Version is a role-playing video game developed by Game Freak and published by Nintendo for the Game Boy Color, released in Japan in December 2000 and internationally throughout 2001. Serving as an enhanced edition of the 1999 titles Pokémon Gold and Silver, it is the final entry in the second generation of the Pokémon game series. The game introduced several new features, including additional story elements, a Battle Tower area, the option to play as a female protagonist, animated Pokémon sprites during battles, and various minor improvements. The Japanese version of the game also utilized the capabilities of the Mobile Adapter GB, a peripheral that allowed players to trade and battle over cell phones and a paid subscription service called "Mobile System GB". These enhancements were made possible by the Game Boy Color''s improved hardware, making Crystal the first game in the series to be incompatible with the original Game Boy.', 'https://media.retroachievements.org/Images/105173.png', 'https://media.retroachievements.org/Images/024029.png', 'https://media.retroachievements.org/Images/007161.png', 'https://media.retroachievements.org/Images/014324.png', 4.9),
  (3, 4939, 'Tetris DX', 'Game Boy Color', 6, 8775, 8775, 8775, 39, 0, NULL, NULL, 'Nintendo', '1998-10-21', 'Tetris DX is a 1998 video game developed and published by Nintendo for the Game Boy Color. It is a version of the game Tetris and a colorised version of the 1989 port of the game, introducing new gameplay modes, save games, and multiplayer using the Game Link Cable. DX was released as a launch title for the Game Boy Color in October 1998. Upon release, the game received a positive reception, with praise directed towards its gameplay additions. Following release, critics praised the game as one of the best titles for the Game Boy Color.', 'https://media.retroachievements.org/Images/109627.png', 'https://media.retroachievements.org/Images/003691.png', 'https://media.retroachievements.org/Images/003688.png', 'https://media.retroachievements.org/Images/003690.png', 4.9),
  (4, 725, 'Pokémon Pinball', 'Game Boy Color', 6, 7984, 7984, 7984, 78, 0, 'Pinball', 'Jupiter', 'Nintendo', '1999-04-14', 'Pokémon Pinball is a pinball-based Pokémon spin-off video game for the Game Boy Color. It was released in Japan on April 14, 1999, and in North America on June 29, 1999. In it, the ball is a Poké Ball, and most of the objects on the table are Pokémon-related.', 'https://media.retroachievements.org/Images/024809.png', 'https://media.retroachievements.org/Images/005502.png', 'https://media.retroachievements.org/Images/005503.png', 'https://media.retroachievements.org/Images/005501.png', 4.8),
  (5, 676, 'The Legend of Zelda: Oracle of Seasons', 'Game Boy Color', 6, 6826, 6826, 6826, 59, 0, 'Action-Adventure', 'Capcom', 'Nintendo', '2001-02-27', 'The Legend of Zelda: Oracle of Seasons and The Legend of Zelda: Oracle of Ages are 2001 action-adventure games developed by Flagship and published by Nintendo for the Game Boy Color. They are the seventh and eighth installments in the Legend of Zelda series.', 'https://media.retroachievements.org/Images/108279.png', 'https://media.retroachievements.org/Images/022647.png', 'https://media.retroachievements.org/Images/000070.png', 'https://media.retroachievements.org/Images/023377.png', 4.8),
  (6, 727, 'Pokémon Trading Card Game', 'Game Boy Color', 6, 4752, 4752, 4752, 35, 0, 'Strategy, Collectible Card Game', 'Hudson Soft', 'Media Factory', '1998-12-18', 'The Pokémon Trading Card Game , abbreviated as PTCG or Pokémon TCG, is a tabletop and collectible card game developed by Creatures Inc. based on the Pokémon franchise. Originally published in Japan by Media Factory in 1996, publishing worldwide is currently handled by The Pokémon Company. In the United States and also by Gopu, Pokémon TCG publishing was originally licensed to Wizards of the Coast, the producer of Magic: The Gathering. Wizards published eight expansion sets between 1998 and 2003, after which point licensing was transferred to The Pokémon Company.', 'https://media.retroachievements.org/Images/091409.png', 'https://media.retroachievements.org/Images/025779.png', 'https://media.retroachievements.org/Images/001771.png', 'https://media.retroachievements.org/Images/001772.png', 4.7),
  (7, 520, 'Metal Gear Solid: Ghost Babel', 'Game Boy Color', 6, 4421, 4421, 4421, 106, 0, 'Stealth', 'Konami', 'Konami', '2000-04-27', 'Metal Gear Solid, released in Japan as Metal Gear: Ghost Babel, is a 2000 action-adventure stealth game developed and published by Konami for the Game Boy Color. The game began development after Konami Computer Entertainment Japan were commissioned by Konami''s European branch to develop a portable adaptation of their 1998 PlayStation game of the same title. However, the Game Boy Color version is not a port of the original PlayStation version, nor does it adapt the same story, but instead takes place in an alternative continuity set seven years after the events of the original Metal Gear (1987). Tose assisted on the development. The game is set to be re-released for the first time via Metal Gear Solid: Master Collection Vol. 2 under its Japanese name.', 'https://media.retroachievements.org/Images/115935.png', 'https://media.retroachievements.org/Images/004437.png', 'https://media.retroachievements.org/Images/118045.png', 'https://media.retroachievements.org/Images/118046.png', 4.7),
  (8, 14221, 'Wario Land II', 'Game Boy Color', 6, 4188, 4188, 4188, 39, 0, '2D Platforming', NULL, 'Nintendo', '1998-10-21', 'Wario Land II, known in Japan as Wario Land 2: The Stolen Treasure, is a 1998 platform game developed and published by Nintendo for the Game Boy. Players control Wario as he sets out to recover his stolen treasure from Captain Syrup.', 'https://media.retroachievements.org/Images/112389.png', 'https://media.retroachievements.org/Images/045708.png', 'https://media.retroachievements.org/Images/113531.png', 'https://media.retroachievements.org/Images/113532.png', 4.7),
  (9, 722, 'Pokémon Silver Version', 'Game Boy Color', 6, 4133, 4133, 4133, 75, 0, NULL, NULL, NULL, '1999-11-21', 'Pokémon Gold Version and Pokémon Silver Version are 1999 role-playing video games developed by Game Freak and published by Nintendo for the Game Boy Color. They are the first installments in the second generation of the Pokémon video game series. They were released in Japan in 1999, Australia and North America in 2000, and Europe in 2001.', 'https://media.retroachievements.org/Images/105171.png', 'https://media.retroachievements.org/Images/000824.png', 'https://media.retroachievements.org/Images/028684.png', 'https://media.retroachievements.org/Images/028685.png', 4.7),
  (10, 3818, 'Dragon Quest I & II', 'Game Boy Color', 6, 3846, 3846, 3846, 73, 0, 'Compilation, Turn-Based RPG', 'TOSE', 'Enix', '2000-09-23', 'Dragon Quest, previously published as Dragon Warrior in North America until 2005, is a series of role-playing video games created by Japanese game designer Yuji Horii, character designer Akira Toriyama, and composer Koichi Sugiyama and published by Square Enix. Since its inception, development of games in the series have been outsourced to a plethora of external companies until the tenth installment, with localized remakes and ports of later installments for the Nintendo DS, Nintendo 3DS, and Nintendo Switch being published by Nintendo outside of Japan. With its first game published in 1986, there are eleven main-series games, along with numerous spin-off games. In addition, there have been numerous manga, anime and novels published under the franchise, with nearly every game in the main series having a related adaptation.', 'https://media.retroachievements.org/Images/093949.png', 'https://media.retroachievements.org/Images/007624.png', 'https://media.retroachievements.org/Images/007625.png', 'https://media.retroachievements.org/Images/033863.png', 4.7),
  (11, 713, 'Mega Man Xtreme', 'Game Boy Color', 6, 3434, 3434, 3434, 44, 0, '2D Platforming', 'Capcom', 'Capcom', '2000-10-20', 'Mega Man Xtreme is a 2000 platform game developed and published by Capcom for the Game Boy Color. It is a spin-off title in the Mega Man X series of video games that originated on the Super Nintendo Entertainment System. Mega Man Xtreme takes place within the series timeline during the 22nd century, in which a group of "Maverick" androids called the "Shadow Hunters" hack into the world''s "Mother Computer" system, destabilize all of the networks, and allow other Mavericks to cause rampant destruction all over the world. The heroic "Maverick Hunter" X is tasked with going into cyberspace to relive his past missions and put a stop to the group''s plans.', 'https://media.retroachievements.org/Images/023366.png', 'https://media.retroachievements.org/Images/101634.png', 'https://media.retroachievements.org/Images/002546.png', 'https://media.retroachievements.org/Images/002547.png', 4.7),
  (12, 5062, '1942', 'Game Boy Color', 6, 3362, 3362, 3362, 18, 0, 'Shoot ''em Up', NULL, 'Capcom', '2000-05-01', '1942 (MCMXLII) was a common year starting on Thursday of the Gregorian calendar, the 1942nd year of the Common Era (CE) and Anno Domini (AD) designations, the 942nd year of the 2nd millennium, the 42nd year of the 20th century, and the 3rd year of the 1940s decade. ', 'https://media.retroachievements.org/Images/063512.png', 'https://media.retroachievements.org/Images/025219.png', 'https://media.retroachievements.org/Images/063872.png', 'https://media.retroachievements.org/Images/063873.png', 4.7),
  (13, 726, 'Pokémon Puzzle Challenge', 'Game Boy Color', 6, 2641, 2641, 2641, 62, 0, 'Tile Matching', 'Intelligent Systems', 'Nintendo', '2000-09-21', 'Pokémon Puzzle Challenge is a puzzle video game developed by Intelligent Systems and published by Nintendo for the Game Boy Color. It was released in Japan on September 21, 2000; in North America on December 4, 2000; and in PAL regions on June 15, 2001, it is the second Pokémon-themed entry in the Puzzle League series. While its Nintendo 64 counterpart Pokémon Puzzle League is visually based on the Pokemon anime, Puzzle Challenge instead draws inspiration from the Pokémon Gold and Silver games. The game features multiple modes of play and support for competitive play between two players. Puzzle Challenge was later digitally re-released via the Nintendo 3DS''s Virtual Console line on November 6, 2014.', 'https://media.retroachievements.org/Images/070464.png', 'https://media.retroachievements.org/Images/026318.png', 'https://media.retroachievements.org/Images/006025.png', 'https://media.retroachievements.org/Images/006026.png', 4.6),
  (14, 741, 'Wario Land 3', 'Game Boy Color', 6, 2324, 2324, 2324, 106, 0, '2D Platforming', NULL, 'Nintendo', '2000-03-21', 'Wario Land 3, known in Japan as Wario Land 3: Mysterious Music Box, is a 2000 platform game developed by Nintendo R&D1 and published by Nintendo for the Game Boy Color. The game''s plot centers around Wario who must free a mysterious figure who is trapped inside a music box. The game was released in Japan on March 21, 2000, Europe on April 14, 2000, and North America on May 30, 2000.', 'https://media.retroachievements.org/Images/112290.png', 'https://media.retroachievements.org/Images/001507.png', 'https://media.retroachievements.org/Images/113601.png', 'https://media.retroachievements.org/Images/113602.png', 4.6),
  (15, 4129, 'Frogger', 'Game Boy Color', 6, 1880, 1880, 1880, 12, 0, 'Arcade', 'Morning Star Multimedia', 'Majesco Entertainment', '1998-12-31', 'Frogger is a 1981 action video game developed by Konami and published by Sega for arcades. It was released in North America by Sega/Gremlin. The object of the game is to direct five frogs to their homes by dodging traffic on a busy road, then crossing a river by jumping on floating logs, turtles, and alligators.', 'https://media.retroachievements.org/Images/073198.png', 'https://media.retroachievements.org/Images/008056.png', 'https://media.retroachievements.org/Images/044698.png', 'https://media.retroachievements.org/Images/044699.png', 4.6),
  (16, 1403, 'Mario Golf', 'Game Boy Color', 6, 1759, 1759, 1759, 44, 0, 'Sports - Golf', 'Camelot Software Planning', 'Nintendo', '1999-08-10', '  There have been numerous sports games featuring Mario characters, based, among others, on tennis, golf, baseball, soccer, and various sports featured in the Olympic Games.', 'https://media.retroachievements.org/Images/080115.png', 'https://media.retroachievements.org/Images/079813.png', 'https://media.retroachievements.org/Images/007086.png', 'https://media.retroachievements.org/Images/008375.png', 4.6),
  (17, 5043, 'Mario Tennis', 'Game Boy Color', 6, 1726, 1726, 1726, 70, 0, 'Sports - Tennis', 'Camelot Software Planning', 'Nintendo', '2000-11-01', 'Mario Tennis is a 2000 sports video game developed by Camelot Software Planning and published by Nintendo for the Nintendo 64 (N64). Following Mario''s Tennis, it is the second game in the Mario Tennis series. The game is known for being the debut game of Luigi''s arch-rival, Waluigi, and the re-introduction of Princess Daisy and Birdo.', 'https://media.retroachievements.org/Images/080421.png', 'https://media.retroachievements.org/Images/014522.png', 'https://media.retroachievements.org/Images/014526.png', 'https://media.retroachievements.org/Images/014527.png', 4.5),
  (18, 697, 'Dragon Quest III', 'Game Boy Color', 6, 1699, 1699, 1699, 138, 0, 'Turn-Based RPG', 'TOSE', 'Enix', '2000-12-08', 'Dragon Quest III: The Seeds of Salvation, titled Dragon Warrior III when initially localized to North America, is a 1988 role-playing video game developed by Chunsoft and published by Enix. It is the third installment in the Dragon Quest series and was first released for the Family Computer (Famicom) in Japan and later for the Nintendo Entertainment System (NES) in North America. The game saw an enhanced remake for the Super Famicom in 1996 and the Game Boy Color in 2001, and a port to mobile phones and the Wii in 2009 and 2011. A version of the game for Android and iOS was released in Japan on September 25, 2014, and worldwide as Dragon Quest III: The Seeds of Salvation on December 4, 2014. It was the first time the game was given an official English subtitle. Later in 2021, another remake of the game titled Dragon Quest III HD-2D Remake, based on the HD-2D graphical style of Octopath Traveler (2018), was announced during the franchise''s 35th anniversary livestream. The remake was released on November 14th, 2024 for Nintendo Switch, PlayStation 5, Windows, and Xbox Series consoles.', 'https://media.retroachievements.org/Images/067978.png', 'https://media.retroachievements.org/Images/007628.png', 'https://media.retroachievements.org/Images/059408.png', 'https://media.retroachievements.org/Images/059947.png', 4.5),
  (19, 8569, 'Mr. Driller', 'Game Boy Color', 6, 1636, 1636, 1636, 12, 0, 'Puzzle', 'Namco', 'Namco', '2000-08-02', 'Mr. Driller is a puzzle video game franchise created by Yasuhito Nagaoka and Hideo Yoshizawa for Namco. The eponymous first game was released in 1999 for arcades and several home consoles, such as the PlayStation. Gameplay in the series consists of controlling Susumu Hori, the titular Mr. Driller, or one of his friends and destroying colorful formations of blocks to make it to the bottom of a well. In order to survive, players need to collect air capsules to replenish their depleting oxygen and avoid being crushed by falling blocks.', 'https://media.retroachievements.org/Images/086250.png', 'https://media.retroachievements.org/Images/083139.png', 'https://media.retroachievements.org/Images/083137.png', 'https://media.retroachievements.org/Images/083138.png', 4.5),
  (20, 7107, 'Bomberman Max: Blue Champion', 'Game Boy Color', 6, 1558, 1558, 1558, 40, 0, 'Puzzle', 'Hudson Soft', 'Vatical Entertainment', '2000-05-14', 'Bomberman Max: Blue Champion and Bomberman Max: Red Challenger are video games released for the Game Boy Color on May 9, 2000. The game was followed by Bomberman Max 2 which was released for the Game Boy Advance on June 4, 2002. There are two versions called Bomberman Max: Blue Champion and Bomberman Max: Red Challenger. In Blue Champion the playable character is Bomberman where in Red Challenger the playable character is Max.', 'https://media.retroachievements.org/Images/051740.png', 'https://media.retroachievements.org/Images/007088.png', 'https://media.retroachievements.org/Images/044822.png', 'https://media.retroachievements.org/Images/044823.png', 4.5),
  (21, 13389, '~Hack~ Crystal Clear', 'Game Boy Color', 6, 1502, 1502, 1502, 195, 0, 'Turn-Based RPG', 'ShockSlayer', 'Hack - Pokemon Crystal Version', '2019-08-03', 'Pokémon Crystal Version is a role-playing video game developed by Game Freak and published by Nintendo for the Game Boy Color, released in Japan in December 2000 and internationally throughout 2001. Serving as an enhanced edition of the 1999 titles Pokémon Gold and Silver, it is the final entry in the second generation of the Pokémon game series. The game introduced several new features, including additional story elements, a Battle Tower area, the option to play as a female protagonist, animated Pokémon sprites during battles, and various minor improvements. The Japanese version of the game also utilized the capabilities of the Mobile Adapter GB, a peripheral that allowed players to trade and battle over cell phones and a paid subscription service called "Mobile System GB". These enhancements were made possible by the Game Boy Color''s improved hardware, making Crystal the first game in the series to be incompatible with the original Game Boy.', 'https://media.retroachievements.org/Images/066026.png', 'https://media.retroachievements.org/Images/026913.png', 'https://media.retroachievements.org/Images/019682.png', 'https://media.retroachievements.org/Images/027061.png', 4.5),
  (22, 16597, '~Prototype~ Pokémon Picross', 'Game Boy Color', 6, 1502, 1502, 1502, 17, 0, 'Nonogram', 'Jupiter', 'Nintendo', '1999-01-01', 'Pokémon Picross  is a freemium puzzle video game featuring Pokémon characters developed by Jupiter Corporation and published by Nintendo and The Pokémon Company for the Nintendo 3DS. The title is part of the "Picross" nonogram series that use number-based grid puzzles to reveal pictures. It was released as a downloadable title on the Nintendo 3DS eShop worldwide in December 2015.', 'https://media.retroachievements.org/Images/121546.png', 'https://media.retroachievements.org/Images/051333.png', 'https://media.retroachievements.org/Images/037089.png', 'https://media.retroachievements.org/Images/037090.png', 4.5),
  (23, 2501, 'Astérix & Obélix', 'Game Boy Color', 6, 1449, 1449, 1449, 46, 0, '2D Platforming', 'Bit Managers', 'Infogrames', '1999-01-01', 'Asterix is a French comic album series about a Gaulish village which, thanks to a magic potion that enhances strength, resists the forces of Julius Caesar''s Roman Republic Army in the time after the Gallic Wars. Many adventures take the titular hero Asterix and his friend Obelix to Rome and beyond.', 'https://media.retroachievements.org/Images/048473.png', 'https://media.retroachievements.org/Images/008760.png', 'https://media.retroachievements.org/Images/044704.png', 'https://media.retroachievements.org/Images/044705.png', 4.5),
  (24, 3608, 'Dragon Quest Monsters', 'Game Boy Color', 6, 1435, 1435, 1435, 64, 0, 'Turn-Based RPG', 'TOSE', 'Eidos Interactive', '1998-09-25', 'Dragon Quest Monsters is a spin-off series of the Dragon Quest games. Primarily developed by Tose and published by Square Enix, it sets the player in a medieval/fantasy world filled with magic, monsters, and knights. Unlike the original Dragon Quest games, the player''s character does not do any of the fighting in battles; the player must instead rely on capturing, breeding, and raising monsters to do the fighting for them. The concept originated from Dragon Quest V (1992). The character and monster designs are by Dragon Ball creator Akira Toriyama. The series spans several handheld gaming systems, and each game has received positive reviews from critics. The series'' gameplay has been compared to Pokémon.', 'https://media.retroachievements.org/Images/086568.png', 'https://media.retroachievements.org/Images/037700.png', 'https://media.retroachievements.org/Images/007285.png', 'https://media.retroachievements.org/Images/007287.png', 4.5),
  (25, 5185, '10-Pin Bowling', 'Game Boy Color', 6, 1405, 1405, 1405, 6, 0, 'Sports - Bowling', 'Morning Star Multimedia', 'Majesco Entertainment', '1999-08-01', 'Tenpin bowling is a type of bowling in which a bowler rolls a bowling ball down a wood or synthetic lane toward ten pins positioned evenly in four rows in an equilateral triangle. The goal is to knock down all ten pins on the first delivery, or failing that, on the second delivery. While most people approach modern tenpin bowling as a simple recreational pastime, those who bowl competitively, especially at the highest levels, consider it a demanding sport requiring precision and skill. A 15-foot (5 m) long approach area is used by the bowler to impart speed and apply side rotation to the bowling ball and is separated from the lane by a foul line. Crossing this foul line is detectable via sensors and results in a score of zero for the delivery in league or tournament play. The 41.5-inch-wide (105 cm), 60-foot-long (18 m) lane is bordered along its length by gutters (channels) that collect errant balls. The lane''s long and narrow shape limits straight-line ball paths to angles that are shallower than the ideal entry angle(s) for achieving strikes; accordingly, bowlers impart side rotation to hook (curve) the ball into the pins to increase the likelihood of striking.', 'https://media.retroachievements.org/Images/036471.png', 'https://media.retroachievements.org/Images/036076.png', 'https://media.retroachievements.org/Images/036075.png', 'https://media.retroachievements.org/Images/036510.png', 4.5),
  (26, 3607, 'Street Fighter Alpha: Warriors'' Dreams', 'Game Boy Color', 6, 1400, 1400, 1400, 30, 0, '2D Fighting', 'Crawfish Interactive', 'Capcom', '2000-03-24', 'Street Fighter Alpha: Warriors'' Dreams, known as Street Fighter Zero in Japan, Asia, South America, and Oceania, is a 1995 fighting game developed and published by Capcom for arcades. It was the first all-new Street Fighter game produced by Capcom since 1991''s Street Fighter II. Plotwise, it serves as a prequel to Street Fighter II and thus features younger versions of established characters, as well as characters from the original Street Fighter and Final Fight.', 'https://media.retroachievements.org/Images/079116.png', 'https://media.retroachievements.org/Images/007512.png', 'https://media.retroachievements.org/Images/007509.png', 'https://media.retroachievements.org/Images/007510.png', 4.5),
  (27, 5133, 'Resident Evil: Gaiden', 'Game Boy Color', 6, 1233, 1233, 1233, 34, 0, 'Action-Adventure, Survival Horror', 'Capcom, M4', 'Capcom, Virgin Interactive', '2001-12-14', 'Resident Evil Gaiden is a 2001 action-adventure game developed by M4 for the Game Boy Color. It was published by Capcom in Japan and North America, and by Virgin Interactive in Europe. Receiving generally mixed reviews by critics, the game marks a departure from other entries in the series, insofar as areas are explored with the playable character seen from a top-down perspective and with battles fought in first-person view. The story revolves around a viral outbreak on a passenger ship and has Leon S. Kennedy and Barry Burton return as protagonists. This game is non-canon, as its plot is contradicted by the main series in key parts, and its events are ignored.', 'https://media.retroachievements.org/Images/034861.png', 'https://media.retroachievements.org/Images/047498.png', 'https://media.retroachievements.org/Images/003392.png', 'https://media.retroachievements.org/Images/003393.png', 4.5),
  (28, 14165, 'Sesame Street: Elmo''s ABCs', 'Game Boy Color', 6, 1213, 1213, 1213, 6, 0, 'Educational', 'Bonsai Entertainment', 'NewKidCo', '1999-03-01', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/042255.png', 'https://media.retroachievements.org/Images/042039.png', 'https://media.retroachievements.org/Images/053887.png', 'https://media.retroachievements.org/Images/053888.png', 4.5),
  (29, 537, 'Rayman', 'Game Boy Color', 6, 1207, 1207, 1207, 34, 0, '2D Platforming', 'Ubisoft', 'Ubisoft', '2000-03-29', 'Rayman is a franchise of platformer video games, created by video game designer Michel Ancel for Ubisoft. Since the release of Rayman in 1995, the series has produced a total of 45 games across multiple platforms.', 'https://media.retroachievements.org/Images/110514.png', 'https://media.retroachievements.org/Images/056859.png', 'https://media.retroachievements.org/Images/001015.png', 'https://media.retroachievements.org/Images/001016.png', 4.5),
  (30, 9725, 'Wendy: Every Witch Way', 'Game Boy Color', 6, 1205, 1205, 1205, 37, 0, '2D Platforming', 'WayForward', 'TDK Mediactive', '2001-08-28', 'Wendy: Every Witch Way is an action platform video game published by TDK Mediactive and developed by WayForward Technologies for the Game Boy Color in 2001. The game centers on Wendy the Good Little Witch from the Casper the Friendly Ghost series. Wendy accidentally opens her aunts'' chest containing magical stones, which upset the gravity of a floating castle that crashes onto her house. The player controls Wendy through four worlds with sixteen levels, with each world having three side-scrolling levels and one horizontal shooter stage. Inserting the game in the Game Boy Advance unlocks a new world exclusive to the console.', 'https://media.retroachievements.org/Images/109829.png', 'https://media.retroachievements.org/Images/022910.png', 'https://media.retroachievements.org/Images/029387.png', 'https://media.retroachievements.org/Images/022907.png', 4.5),
  (31, 4912, 'Mega Man Xtreme 2', 'Game Boy Color', 6, 1155, 1155, 1155, 44, 0, '2D Platforming', 'Capcom', 'Capcom', '2001-07-19', 'Mega Man Xtreme 2 is a 2001 platform game developed and published by Capcom for the Game Boy Color. It is a spin-off title in the Mega Man X series and a follow-up to Mega Man Xtreme, which was released the previous year. Mega Man Xtreme 2 is set in the 22nd century between the events of Mega Man X3 and Mega Man X4. The DNA souls of robots known as "Reploids" are being stolen and used to create an army of undead "Mavericks". The "Maverick Hunters" X and Zero quickly spring into action with the help of their young ally Iris.', 'https://media.retroachievements.org/Images/023367.png', 'https://media.retroachievements.org/Images/002568.png', 'https://media.retroachievements.org/Images/102856.png', 'https://media.retroachievements.org/Images/102857.png', 4.5),
  (32, 24124, '~Homebrew~ Slender: The 8 Pages', 'Game Boy Color', 6, 1150, 1150, 1150, 9, 0, NULL, 'JWG.LLC', 'itch.io', '2021-11-14', 'Slender: The Eight Pages, originally titled Slender, is a first-person survival horror game based on Slender Man, a well-known creepypasta. Influenced by the web series Marble Hornets, it was developed by independent developer Mark J. Hadley using the Unity game engine and was released in June 2012 by his one-man studio, Parsec Productions. He drew inspiration from Amnesia: The Dark Descent''s atmosphere and imagery, though opted for random encounters, rather than Amnesia’s linear design, which Hadley felt diminished its sense of horror.', 'https://media.retroachievements.org/Images/071726.png', 'https://media.retroachievements.org/Images/071725.png', 'https://media.retroachievements.org/Images/084370.png', 'https://media.retroachievements.org/Images/084373.png', 4.5),
  (33, 7687, 'Caterpillar Construction Zone', 'Game Boy Color', 6, 1139, 1139, 1139, 15, 0, 'Job Simulation', 'Realtime Associates', 'Mattel', '2000-01-01', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/122051.png', 'https://media.retroachievements.org/Images/032119.png', 'https://media.retroachievements.org/Images/032118.png', 'https://media.retroachievements.org/Images/032117.png', 4.5),
  (34, 13427, 'Sesame Street: Elmo''s 123s', 'Game Boy Color', 6, 1119, 1119, 1119, 6, 0, 'Educational', 'Bonsai Entertainment', 'NewKidCo', '1999-03-01', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/116382.png', 'https://media.retroachievements.org/Images/042036.png', 'https://media.retroachievements.org/Images/059337.png', 'https://media.retroachievements.org/Images/059338.png', 4.5),
  (35, 22589, '~Homebrew~ A 20 Second Platformer', 'Game Boy Color', 6, 987, 987, 987, 6, 0, '2D Platforming', 'allalonegamez', 'itch.io', '2022-11-24', 'Little Nicky is a 2000 licensed platform game developed by Digital Eclipse and published by Ubisoft for the Game Boy Color. Based on the comedy film of the same name, the game was released exclusively in North America. The player controls the half-demon/angel Nicky and utilizes his demonic powers in order to traverse 24 levels inspired by events from the titular film. Outside of the main game, the player can also partake in five different minigames. Critical reception towards the game was mixed, with many reviewers praising its visuals and risqué elements, while a myriad of reactions were given towards the game''s audio and gameplay.', 'https://media.retroachievements.org/Images/092885.png', 'https://media.retroachievements.org/Images/083276.png', 'https://media.retroachievements.org/Images/071830.png', 'https://media.retroachievements.org/Images/071831.png', 4.4),
  (36, 5065, 'Pac-Man: Special Color Edition', 'Game Boy Color', 6, 982, 982, 982, 50, 0, 'Arcade, Maze Chase', 'Namco', 'Namco', '1999-08-01', 'Pac-Man is a video game series and media franchise developed, published and owned by Bandai Namco Entertainment, a video game publisher that was previously known as Namco. Entries have been developed by a wide array of other video game companies, including Midway Games, Atari and Mass Media, Inc., and was created by Toru Iwatani. The first entry in the series was released in arcades in 1980 by Namco, and published by Midway Games in North America. Most Pac-Man games are maze chase games, but it has also delved into other genres, such as platformers, racing, and sports. Several games in the series were released for a multitude of home consoles and are included in many Bandai Namco video game compilations.', 'https://media.retroachievements.org/Images/071502.png', 'https://media.retroachievements.org/Images/051552.png', 'https://media.retroachievements.org/Images/070424.png', 'https://media.retroachievements.org/Images/070423.png', 4.4),
  (37, 6385, 'Crystalis', 'Game Boy Color', 6, 972, 972, 972, 57, 0, NULL, NULL, 'Nintendo', '2000-06-26', 'Crystalis is a 1990 action role-playing video game developed and published by SNK for the Nintendo Entertainment System. A port for the Game Boy Color developed by Nintendo Software Technology and published by Nintendo was released in 2000.', 'https://media.retroachievements.org/Images/083493.png', 'https://media.retroachievements.org/Images/045607.png', 'https://media.retroachievements.org/Images/065197.png', 'https://media.retroachievements.org/Images/065198.png', 4.4),
  (38, 30725, '~Homebrew~ Hatsune Miku Bomb Squad', 'Game Boy Color', 6, 970, 970, 970, 6, 0, NULL, 'birdup', 'birdup', '2024-08-07', 'This is a list of notable video game companies that have made games for either computers, video game consoles, handheld or mobile devices, and includes companies that currently exist as well as now-defunct companies.', 'https://media.retroachievements.org/Images/101115.png', 'https://media.retroachievements.org/Images/101118.png', 'https://media.retroachievements.org/Images/101116.png', 'https://media.retroachievements.org/Images/101117.png', 4.4),
  (39, 16191, '~Hack~ Pokémon Polished Crystal', 'Game Boy Color', 6, 966, 966, 966, 173, 0, 'Turn-Based RPG', 'Rangi', 'Hack - Pokemon Crystal Version', '2016-09-20', '1998 saw many sequels and prequels in video games, such as The Legend of Zelda: Ocarina of Time, Metal Gear Solid, Resident Evil 2, Crash Bandicoot: Warped, F-Zero X, Fallout 2, Gex: Enter the Gecko, Marvel vs. Capcom: Clash of Super Heroes, Panzer Dragoon Saga, Return to Krondor, Sonic Adventure, Soulcalibur, Street Fighter Alpha 3, and Tomb Raider III, along with new titles such as Banjo-Kazooie, Dance Dance Revolution, Half-Life, MediEvil, Parasite Eve, Radiant Silvergun, Spyro the Dragon, StarCraft and Xenogears. In Japan, Sega released the Dreamcast which was the first console of the sixth generation and also the company''s last major console.', 'https://media.retroachievements.org/Images/123087.png', 'https://media.retroachievements.org/Images/033006.png', 'https://media.retroachievements.org/Images/123588.png', 'https://media.retroachievements.org/Images/123589.png', 4.4),
  (40, 9491, '~Hack~ Pokémon Prism Version', 'Game Boy Color', 6, 964, 964, 964, 94, 0, NULL, 'Koolboyman, RainbowDevs', NULL, '2016-12-19', 'Pokémon Prism is a fanmade video game based on the Pokémon series. A ROM hack of Pokémon Crystal (2000), it was developed by Adam Vierra, also known by his online pseudonym "Koolboyman", alongside a team of numerous developers. The game is a sequel to his prior hack, Pokémon Brown (2004), and centers on the child of Lance, a boss of Pokémon Gold and Silver (1999), as the protagonist. The premise follows the protagonist as they find themselves in the region of Naljo after an earthquake and attempt to defeat Naljo''s Pokémon League.', 'https://media.retroachievements.org/Images/113781.png', 'https://media.retroachievements.org/Images/015728.png', 'https://media.retroachievements.org/Images/025790.png', 'https://media.retroachievements.org/Images/032725.png', 4.4),
  (41, 31200, '~Homebrew~ Super Mario Bros. Mini', 'Game Boy Color', 6, 934, 934, 934, 75, 0, '2D Platforming', 'Mico27', 'itch.io', '2024-10-26', 'Super Mario Bros. Deluxe is a 1999 platform game developed and published by Nintendo for the Game Boy Color. It is a largely unaltered port of the 1985 Super Mario Bros., originally released for the Nintendo Entertainment System (NES), with an unlockable version of its 1986 Japanese sequel, Super Mario Bros.: The Lost Levels. The game also introduces several new features, including a single-player and two-player race mode, a challenge mode for individual levels, and various toys and collectibles, some of which utilize the functionality of the Game Boy Printer.', 'https://media.retroachievements.org/Images/103697.png', 'https://media.retroachievements.org/Images/103700.png', 'https://media.retroachievements.org/Images/103692.png', 'https://media.retroachievements.org/Images/103693.png', 4.4),
  (42, 4893, 'Conker''s Pocket Tales', 'Game Boy Color', 6, 933, 933, 933, 35, 0, 'Action-Adventure', 'Rare', 'Nintendo', '1999-06-08', 'Conker''s Pocket Tales is a 1999 action-adventure game developed and published by Rare for the Game Boy Color. It is the first game in the Conker series and follows the story of Conker the Squirrel as he retrieves his stolen birthday presents and rescues his girlfriend Berri, who has been kidnapped by the Evil Acorn. The cartridge is dual-format, allowing it to also run on the original Game Boy with some gameplay differences.', 'https://media.retroachievements.org/Images/114693.png', 'https://media.retroachievements.org/Images/064301.png', 'https://media.retroachievements.org/Images/002714.png', 'https://media.retroachievements.org/Images/002713.png', 4.4),
  (43, 5021, 'Donkey Kong Country', 'Game Boy Color', 6, 913, 913, 913, 38, 0, '2D Platforming', 'Rare', 'Nintendo', '2000-11-05', 'Donkey Kong Country, known in Japan as Super Donkey Kong, is a 1994 platform game developed by Rare and published by Nintendo for the Super Nintendo Entertainment System (SNES). It follows the gorilla Donkey Kong and his nephew Diddy Kong as they set out to recover their stolen banana hoard from the crocodile King K. Rool and his army, the Kremlings. The player traverses 40 side-scrolling levels as they jump between platforms and avoid obstacles. They collect items, ride minecarts and animals, defeat enemies and bosses, and find secret bonus stages. In multiplayer modes, two players work cooperatively or race.', 'https://media.retroachievements.org/Images/046978.png', 'https://media.retroachievements.org/Images/015523.png', 'https://media.retroachievements.org/Images/015524.png', 'https://media.retroachievements.org/Images/015525.png', 4.4),
  (44, 4056, 'Legend of the River King GBC', 'Game Boy Color', 6, 910, 910, 910, 57, 0, 'Sports - Fishing', 'Marvelous Interactive', 'Natsume, Marvelous Interactive', '1999-11-01', 'Harvest Moon 2 GBC, released in Japan as Bokujō Monogatari GB2 (牧場物語GB2), is a farming simulation video game for the Game Boy Color developed and published by Victor Interactive Software, and the second portable game in the Story of Seasons series. The object of the game is to cultivate a farm to prevent the land from being used to build an amusement park. As with the previous game, the player may choose to play as a boy or a girl.', 'https://media.retroachievements.org/Images/036380.png', 'https://media.retroachievements.org/Images/036091.png', 'https://media.retroachievements.org/Images/044542.png', 'https://media.retroachievements.org/Images/044543.png', 4.4),
  (45, 4933, 'Shadowgate Classic', 'Game Boy Color', 6, 853, 853, 853, 33, 0, 'Dungeon Crawl, Point-and-Click Adventure', 'Infinite Ventures', 'Nintendo', '1999-01-01', 'Shadowgate is a 1987 point-and-click adventure game developed by ICOM Simulations and published by Mindscape for the Macintosh as part of the MacVenture series. The game takes place in the Castle Shadowgate, residence of the evil Warlock Lord. The player, as the "last of a great line of hero-kings", is tasked with saving the world by defeating the Warlock Lord, who is attempting to summon the demon Behemoth out of Hell. The original Macintosh version was only in black-and-white, but color versions of the game were later released for the Amiga and Atari ST, and in 1989 for the Nintendo Entertainment System. The game was generally well-received, and was followed by several sequels and remakes for various systems.', 'https://media.retroachievements.org/Images/064429.png', 'https://media.retroachievements.org/Images/021896.png', 'https://media.retroachievements.org/Images/003245.png', 'https://media.retroachievements.org/Images/003243.png', 4.4),
  (46, 2818, 'Harry Potter and the Chamber of Secrets', 'Game Boy Color', 6, 841, 841, 841, 72, 0, NULL, 'Griptonite Games', 'Electronic Arts', '2002-11-01', 'Harry Potter and the Chamber of Secrets is a fantasy novel by British author J. K. Rowling. The second novel in the Harry Potter series, it chronicles Harry Potter''s second year at Hogwarts School of Witchcraft and Wizardry. After several residents of the school are attacked and magically immobilised, Harry and his friends Ron and Hermione investigate.', 'https://media.retroachievements.org/Images/085763.png', 'https://media.retroachievements.org/Images/007709.png', 'https://media.retroachievements.org/Images/020296.png', 'https://media.retroachievements.org/Images/020297.png', 4.4),
  (47, 19541, '~Homebrew~ Castlevania: Circle of the Moon - GBC Edition', 'Game Boy Color', 6, 832, 832, 832, 7, 0, 'Metroidvania', 'Ryan Marcham', 'Ryan Marcham', '2022-04-28', 'The following is a comprehensive index of all games released in 2023, sorted chronologically by release date, and divided by quarter. Information regarding developer, publisher, operating system, genre, and type of release is provided where available', 'https://media.retroachievements.org/Images/088301.png', 'https://media.retroachievements.org/Images/058030.png', 'https://media.retroachievements.org/Images/057544.png', 'https://media.retroachievements.org/Images/069974.png', 4.4),
  (48, 5594, 'Dragon Ball Z: Legendary Super Warriors', 'Game Boy Color', 6, 793, 793, 793, 81, 0, 'Card Game, Turn-Based RPG', 'Flight-Plan', 'Banpresto, Infogrames', '2002-06-28', 'Dragon Ball Z: Legendary Super Warriors is a turn-based fighting game released for the Game Boy Color. It is played with the use of in-game cards for attacks, techniques and support items. The game''s story takes place from the start of Dragon Ball Z, the Saiyan Saga, and runs until the end of the Buu Saga. The game includes two extra stories involving Future Trunks''s timeline.', 'https://media.retroachievements.org/Images/121631.png', 'https://media.retroachievements.org/Images/121092.png', 'https://media.retroachievements.org/Images/120941.png', 'https://media.retroachievements.org/Images/120942.png', 4.4),
  (49, 4871, 'Centipede', 'Game Boy Color', 6, 735, 735, 735, 17, 0, 'Arcade, Shoot ''em Up', 'Accolade', 'Majesco Entertainment', '1998-11-30', 'Centipedes are predatory arthropods belonging to the class Chilopoda of the subphylum Myriapoda, an arthropod group which includes millipedes and other multi-legged animals. Centipedes are elongated segmented (metameric) animals with one pair of legs per body segment. All centipedes are venomous and can inflict painful stings, injecting their venom through pincer-like appendages known as forcipules or toxicognaths, which are actually modified legs instead of fangs. Despite the name, no species of centipede has exactly 100 legs; the number of pairs of legs is an odd number that ranges from 15 pairs to 191 pairs.', 'https://media.retroachievements.org/Images/056480.png', 'https://media.retroachievements.org/Images/010910.png', 'https://media.retroachievements.org/Images/010912.png', 'https://media.retroachievements.org/Images/010922.png', 4.4),
  (50, 5067, 'Pong: The Next Level', 'Game Boy Color', 6, 728, 728, 728, 18, 0, 'Arcade', 'Morning Star Multimedia', 'Hasbro Interactive', '1999-12-01', 'Pong: The Next Level is a 1999 table tennis video game serving as a remake of the 1972 Atari game Pong. It was developed by Supersonic Software and published by Hasbro Interactive for the PlayStation and Microsoft Windows, and was later ported to Game Boy Color and Mac OS.', 'https://media.retroachievements.org/Images/021495.png', 'https://media.retroachievements.org/Images/021513.png', 'https://media.retroachievements.org/Images/021515.png', 'https://media.retroachievements.org/Images/021516.png', 4.4),
  (51, 4126, 'WWF Betrayal', 'Game Boy Color', 6, 725, 725, 725, 15, 0, 'Wrestling', 'WayForward', 'THQ', '2001-08-07', 'WWF Betrayal is a beat ''em up on the Game Boy Color based on the World Wrestling Federation (WWF). It was the third and last WWF game released to the Game Boy Color and one of a few games based on the promotion that was of a different genre than the regular professional wrestling games usually produced.', 'https://media.retroachievements.org/Images/077219.png', 'https://media.retroachievements.org/Images/026380.png', 'https://media.retroachievements.org/Images/026381.png', 'https://media.retroachievements.org/Images/026382.png', 4.4),
  (52, 4131, 'Sesame Street Sports', 'Game Boy Color', 6, 695, 695, 695, 18, 0, '2D Platforming', 'Bonsai Entertainment', 'NewKidCo', '2001-11-15', ' There have been a variety of Sesame Street video games released for video game platforms. Most of the Sesame Street video games were published and developed by NewKidCo.', 'https://media.retroachievements.org/Images/043448.png', 'https://media.retroachievements.org/Images/041808.png', 'https://media.retroachievements.org/Images/052117.png', 'https://media.retroachievements.org/Images/052118.png', 4.4),
  (53, 4928, 'SpongeBob SquarePants: Legend of the Lost Spatula', 'Game Boy Color', 6, 677, 677, 677, 30, 0, '2D Platforming, Action', 'Vicarious Visions', 'THQ', '2001-03-15', 'SpongeBob SquarePants: Legend of the Lost Spatula is a 2001 platform action video game developed by Vicarious Visions and published by THQ for the Game Boy Color handheld game console. It is the first video game to be based on SpongeBob SquarePants. The game''s story centers on SpongeBob SquarePants, a sea sponge who lives in the undersea town of Bikini Bottom and works for Mr. Krabs as the fry cook of the Krusty Krab fast food restaurant. SpongeBob is destined to become the ocean''s greatest fry cook, and must embark on a quest to retrieve a golden spatula from the Flying Dutchman, a pirate ghost. The game features platforming-style gameplay, as well as many characters from the television series.', 'https://media.retroachievements.org/Images/105968.png', 'https://media.retroachievements.org/Images/007930.png', 'https://media.retroachievements.org/Images/033882.png', 'https://media.retroachievements.org/Images/033868.png', 4.4),
  (54, 1351, 'Scooby-Doo! Classic Creep Capers', 'Game Boy Color', 6, 672, 672, 672, 15, 0, 'Point-and-Click Adventure', 'Digital Eclipse', 'THQ', '2001-02-12', 'Scooby-Doo! Classic Creep Capers is an adventure game published by THQ for the Nintendo 64 and Game Boy Color, based on the Hanna-Barbera cartoon Scooby-Doo, Where Are You!. The Nintendo 64 version, developed by Terraglyph Interactive Studios, was released in November 2000, while the Game Boy Color version was developed by Digital Eclipse Software, and released in February 2001. A PlayStation version, identical to the Nintendo 64 version, had been in development by Terraglyph Interactive Studios but was later cancelled.', 'https://media.retroachievements.org/Images/084492.png', 'https://media.retroachievements.org/Images/070630.png', 'https://media.retroachievements.org/Images/070635.png', 'https://media.retroachievements.org/Images/070636.png', 4.4),
  (55, 18962, '~Homebrew~ Opossum Country', 'Game Boy Color', 6, 671, 671, 671, 6, 0, 'Horror', 'Ben Jelter', 'Ben Jelter', '2020-12-14', 'Opossums are members of the marsupial order Didelphimorphia endemic to the Americas. The largest order of marsupials in the Western Hemisphere, it comprises 126 species in 18 genera. Opossums originated in South America and entered North America in the Great American Interchange following the connection of North and South America in the late Cenozoic.', 'https://media.retroachievements.org/Images/068476.png', 'https://media.retroachievements.org/Images/111660.png', 'https://media.retroachievements.org/Images/111661.png', 'https://media.retroachievements.org/Images/111662.png', 4.4),
  (56, 4923, 'Survival Kids', 'Game Boy Color', 6, 647, 647, 647, 39, 0, 'Action RPG, Survival', 'Konami', 'Konami', '1999-10-01', 'Survival Kids, known as Stranded Kids in Europe, is a 1999 survival video game developed and published by Konami for the Game Boy Color. The gameplay revolves around surviving on a deserted island, and features an open-ended structure that presents the player with multiple ways to progress. It is the first in the Survival Kids series in Japan, which goes under the name Lost in Blue in North America and Europe.', 'https://media.retroachievements.org/Images/064496.png', 'https://media.retroachievements.org/Images/002679.png', 'https://media.retroachievements.org/Images/002680.png', 'https://media.retroachievements.org/Images/002712.png', 4.4),
  (57, 11673, 'Microsoft: The Best of Entertainment Pack', 'Game Boy Color', 6, 632, 632, 632, 27, 0, 'Minigames', 'Microsoft, Saffire Corporation, Cryo Interactive', 'Microsoft', '2001-05-30', 'Microsoft Entertainment Pack, also known as Windows Entertainment Pack or simply WEP, is a collection of 16-bit casual computer games for Windows. There were four Entertainment Packs released between 1990 and 1992. These games were somewhat unusual for the time, in that they would not run under MS-DOS. In 1994, a compilation of selected games from the previous four Entertainment Packs was released called The Best of Microsoft Entertainment Pack. A Game Boy Color version was released in 2001.', 'https://media.retroachievements.org/Images/017989.png', 'https://media.retroachievements.org/Images/017987.png', 'https://media.retroachievements.org/Images/017984.png', 'https://media.retroachievements.org/Images/017985.png', 4.4),
  (58, 10659, 'Barbie: Ocean Discovery', 'Game Boy Color', 6, 611, 611, 611, 21, 0, 'Puzzle / Action / Exploration', 'Realtime Associates', 'Mattel', '1999-05-01', 'Barbie, a fashion doll manufactured by American toy and entertainment company Mattel, has starred in numerous video games on PC, various console systems, IOS, and Android. Some games are adaptations of Barbie films or TV series, while others feature original storylines and concepts.', 'https://media.retroachievements.org/Images/120964.png', 'https://media.retroachievements.org/Images/040522.png', 'https://media.retroachievements.org/Images/014665.png', 'https://media.retroachievements.org/Images/014664.png', 4.3),
  (59, 5151, 'Harvest Moon GBC', 'Game Boy Color', 6, 605, 605, 605, 47, 0, 'Life Simulation', 'Marvelous Interactive', 'Natsume', '1998-12-31', 'Harvest Moon GB  is the second game in the Story of Seasons series of video games, and was developed and published by Victor Interactive Software. Harvest Moon GB is the first portable Harvest Moon game, developed for the Game Boy. A Game Boy Color version was released later under the name Harvest Moon GBC. The Game Boy Color version was later released on the 3DS Virtual Console in 2013.', 'https://media.retroachievements.org/Images/051639.png', 'https://media.retroachievements.org/Images/064743.png', 'https://media.retroachievements.org/Images/003473.png', 'https://media.retroachievements.org/Images/003479.png', 4.3),
  (60, 6494, 'Pocket Bomberman', 'Game Boy Color', 6, 595, 595, 595, 15, 0, 'Action', 'Hudson Soft', 'Nintendo', '1998-12-14', 'Pocket Bomberman is a platform video game developed by Hudson Soft and originally released for the Game Boy in 1997. It was re-released as a launch title for the Game Boy Color in 1998.', 'https://media.retroachievements.org/Images/044111.png', 'https://media.retroachievements.org/Images/007920.png', 'https://media.retroachievements.org/Images/009445.png', 'https://media.retroachievements.org/Images/007922.png', 4.3),
  (61, 6135, 'Beatmania GB', 'Game Boy Color', 6, 579, 579, 579, 70, 0, 'Rhythm', 'Konami', 'Konami', '1999-03-01', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/047951.png', 'https://media.retroachievements.org/Images/005053.png', 'https://media.retroachievements.org/Images/004990.png', 'https://media.retroachievements.org/Images/004991.png', 4.3),
  (62, 11149, 'Hello Kitty no Magical Museum', 'Game Boy Color', 6, 579, 579, 579, 9, 0, 'Puzzle', 'Atelier Double', 'Imagineer', '1999-04-28', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/053496.png', 'https://media.retroachievements.org/Images/053489.png', 'https://media.retroachievements.org/Images/053490.png', 'https://media.retroachievements.org/Images/053491.png', 4.3),
  (63, 6081, '~Hack~ Pokémon Pinball Generations', 'Game Boy Color', 6, 565, 565, 565, 67, 0, 'Pinball', 'RainbowDevs', NULL, '2019-01-19', 'Pokémon Red Version and Pokémon Blue Version are 1996 role-playing video games (RPGs) developed by Game Freak and published by Nintendo for the Game Boy. They are the first installments of the Pokémon video game series, and were first released in Japan as Pocket Monsters Red and Pocket Monsters Green, followed by the special edition Pocket Monsters Blue later that year. The games were released internationally in 1998 and 1999 as Pokémon Red and Pokémon Blue, while an enhanced version, Pokémon Yellow Version: Special Pikachu Edition, was released in Japan in 1998 and in other regions in 1999 and 2000.', 'https://media.retroachievements.org/Images/084083.png', 'https://media.retroachievements.org/Images/082931.png', 'https://media.retroachievements.org/Images/082936.png', 'https://media.retroachievements.org/Images/085959.png', 4.3),
  (64, 3819, 'John Romero''s Daikatana', 'Game Boy Color', 6, 548, 548, 548, 22, 0, 'Action-Adventure', 'Will', 'Kemco', '2000-09-29', 'John Romero''s Daikatana, better known as simply Daikatana, is a 2000 first-person shooter action role-playing game developed by Ion Storm and published by Eidos Interactive for Windows. A port to the Nintendo 64 was released the same year by Kemco. Players control a swordsmaster who travels through various time periods using the eponymous Daikatana, a powerful sword tied to the fate of the world.', 'https://media.retroachievements.org/Images/063217.png', 'https://media.retroachievements.org/Images/016042.png', 'https://media.retroachievements.org/Images/044897.png', 'https://media.retroachievements.org/Images/044893.png', 4.3),
  (65, 6080, 'Daffy Duck: Fowl Play', 'Game Boy Color', 6, 544, 544, 544, 24, 0, '2D Platforming', 'Santaclaus', 'Sunsoft', '1999-12-01', 'Daffy Duck: Fowl Play is a 2D platform video game featuring the Looney Tunes character Daffy Duck. It was released for the Game Boy Color in 1999 in North America and 2000 in Japan and Europe.', 'https://media.retroachievements.org/Images/042771.png', 'https://media.retroachievements.org/Images/011018.png', 'https://media.retroachievements.org/Images/033856.png', 'https://media.retroachievements.org/Images/033857.png', 4.3),
  (66, 13182, 'Top Gear Pocket 2', 'Game Boy Color', 6, 541, 541, 541, 86, 0, 'Racing', 'Vision Works', 'Vatical Entertainment', '2000-01-01', 'Top Gear Pocket 2, known in Europe as Top Gear Rally 2, is a racing video game developed by Kemco and released for the Game Boy Color handheld console, released on December 17, 1999 in Japan and in 2000 across other regions. It is a sequel to Top Gear Pocket.', 'https://media.retroachievements.org/Images/061109.png', 'https://media.retroachievements.org/Images/061106.png', 'https://media.retroachievements.org/Images/061107.png', 'https://media.retroachievements.org/Images/061108.png', 4.3),
  (67, 4193, 'Monsters, Inc.', 'Game Boy Color', 6, 534, 534, 534, 15, 0, '2D Platforming', 'Vicarious Visions', 'THQ', '2001-10-01', 'Monsters, Inc. is a 2001 American animated comedy film produced by Pixar Animation Studios for Walt Disney Pictures, and starring the voices of John Goodman, Billy Crystal, Steve Buscemi, James Coburn, Jennifer Tilly, and Mary Gibbs. Directed by Pete Docter, and written by Andrew Stanton and Daniel Gerson, the film centers on two monsters, the hairy James P. "Sulley" Sullivan (Goodman) and his one-eyed partner and best friend Mike Wazowski (Crystal), who are employed at the titular energy-producing factory Monsters, Inc., which generates power by scaring human children. However, the monster world believes that the children are toxic, and when a little human girl, Boo (Gibbs), sneaks into the factory, the duo must safely return her home while evading discovery.', 'https://media.retroachievements.org/Images/044845.png', 'https://media.retroachievements.org/Images/051581.png', 'https://media.retroachievements.org/Images/002203.png', 'https://media.retroachievements.org/Images/044397.png', 4.3),
  (68, 12950, 'Hollywood Pinball', 'Game Boy Color', 6, 515, 515, 515, 85, 0, 'Pinball', 'Tarantula Studios', 'Take-Two Interactive', '1999-01-01', 'Hollywood Pinball is a 1999 pinball video game developed by Tarantula Studios, first published by Take-Two Interactive Software in the EU for Game Boy Color in 1999. Hollywood Pinball was unreleased within the United States.', 'https://media.retroachievements.org/Images/063202.png', 'https://media.retroachievements.org/Images/018185.png', 'https://media.retroachievements.org/Images/018186.png', 'https://media.retroachievements.org/Images/018187.png', 4.3),
  (69, 15635, 'Super Robot Pinball', 'Game Boy Color', 6, 515, 515, 515, 44, 0, 'Pinball', NULL, 'Media Factory', '2001-02-23', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/065603.png', 'https://media.retroachievements.org/Images/064728.png', 'https://media.retroachievements.org/Images/030248.png', 'https://media.retroachievements.org/Images/030249.png', 4.3),
  (70, 4921, 'Asteroids', 'Game Boy Color', 6, 506, 506, 506, 34, 0, NULL, 'Syrox Developments', 'Activision', '1999-09-01', 'An asteroid is a minor planet—an object larger than a meteoroid that is neither a planet nor an identified comet—that orbits within the inner Solar System or is co-orbital with Jupiter. Asteroids are rocky, metallic, or icy bodies with no atmosphere, and are broadly classified into C-type (carbonaceous), M-type (metallic), or S-type (silicaceous). The size and shape of asteroids vary significantly, ranging from small rubble piles under a kilometer across to Ceres, a dwarf planet almost 1000 km in diameter. A body is classified as a comet, not an asteroid, if it shows a coma (tail) when warmed by solar radiation, although recent observations suggest a continuum between these types of bodies.', 'https://media.retroachievements.org/Images/025466.png', 'https://media.retroachievements.org/Images/067093.png', 'https://media.retroachievements.org/Images/025464.png', 'https://media.retroachievements.org/Images/025465.png', 4.3),
  (71, 5105, 'Dragon Quest Monsters 2', 'Game Boy Color', 6, 482, 482, 482, 61, 0, 'Turn-Based RPG', 'TOSE', 'Enix', '2001-03-09', 'Dragon Warrior Monsters 2, known in Japan as Dragon Quest Monsters 2 , is a role-playing video game published by Enix for the Game Boy Color. It is the second Dragon Warrior Monsters game for the Game Boy Color and features two different versions of the same game, Cobi''s Journey and Tara''s Adventure. Both games were remade in 2002 for the PlayStation in a compilation game called Dragon Quest Monsters 1+2 and released only in Japan. The Nintendo 3DS version combined both games into one and was released only in Japan in 2014 with the title Dragon Quest Monsters 2: Iru and Luca''s Marvelous Mysterious Key. The 3DS version was later brought to iOS, Android on August 6, 2020, in Japan.', 'https://media.retroachievements.org/Images/086569.png', 'https://media.retroachievements.org/Images/042483.png', 'https://media.retroachievements.org/Images/042479.png', 'https://media.retroachievements.org/Images/042480.png', 4.3),
  (72, 8571, 'Batman Beyond: Return of the Joker', 'Game Boy Color', 6, 479, 479, 479, 10, 0, 'Beat ''em Up', 'Kemco', 'Ubisoft', '2000-11-20', 'Batman Beyond: Return of the Joker is a 2000 American direct-to-video animated superhero film produced by Warner Bros. Animation and distributed by Warner Bros. Home Entertainment. It is the third film in the DC Animated Universe and is based on the animated series Batman Beyond while also serving as a continuation of and resolving plot points from Batman: The Animated Series and The New Batman Adventures. The film features the DC Comics Batmen Bruce Wayne and Terry McGinnis, as they try to unravel the mysterious return of the former''s archenemy, the Joker, preparing a climactic showdown with the villain.', 'https://media.retroachievements.org/Images/113443.png', 'https://media.retroachievements.org/Images/042666.png', 'https://media.retroachievements.org/Images/066977.png', 'https://media.retroachievements.org/Images/066978.png', 4.3),
  (73, 22124, '~Homebrew~ Blinky''s Revenge', 'Game Boy Color', 6, 461, 461, 461, 6, 0, 'Maze Chase', 'László Rajcsányi', 'László Rajcsányi', '2022-06-21', ' This is a list of fictional crocodiles and alligators from literature, mascots and emblems of teams and organizations, comics, films, animations and video games.', 'https://media.retroachievements.org/Images/118223.png', 'https://media.retroachievements.org/Images/106173.png', 'https://media.retroachievements.org/Images/106175.png', 'https://media.retroachievements.org/Images/106176.png', 4.3),
  (74, 5061, '102 Dalmatians: Puppies to the Rescue', 'Game Boy Color', 6, 455, 455, 455, 36, 0, '2D Platforming', 'Digital Eclipse', 'Activision', '2000-12-06', '102 Dalmatians: Puppies to the Rescue is a 2000 platform game, loosely based on the 2000 film 102 Dalmatians. It was developed by Toys for Bob and published by Eidos Interactive for PlayStation and Dreamcast while Disney Interactive published the Windows version. The Game Boy Color version was developed by Digital Eclipse and published by Activision.', 'https://media.retroachievements.org/Images/060696.png', 'https://media.retroachievements.org/Images/060800.png', 'https://media.retroachievements.org/Images/060799.png', 'https://media.retroachievements.org/Images/060815.png', 4.3),
  (75, 7109, 'Buffy the Vampire Slayer', 'Game Boy Color', 6, 447, 447, 447, 18, 0, NULL, 'GameBrains', NULL, '2000-09-19', 'Buffy the Vampire Slayer is an American supernatural horror drama television series created by Joss Whedon. The show''s concept is based on the 1992 film written by Whedon, although they are separate and distinct productions. Whedon served as executive producer and showrunner of the series under his production company Mutant Enemy Productions. It aired on The WB from March 10, 1997, to May 22, 2001, and later on UPN from October 2, 2001, to May 20, 2003.', 'https://media.retroachievements.org/Images/113126.png', 'https://media.retroachievements.org/Images/097212.png', 'https://media.retroachievements.org/Images/073439.png', 'https://media.retroachievements.org/Images/073438.png', 4.3),
  (76, 4647, 'Rayman 2', 'Game Boy Color', 6, 443, 443, 443, 54, 0, '2D Platforming', 'Ubisoft', 'Ubisoft', '2002-01-01', 'Rayman 2: The Great Escape is a 1999 platform game developed by Ubi Pictures and published by Ubi Soft for the Nintendo 64, Windows, Dreamcast and PlayStation. The game centers on the titular character Rayman, who is tasked with saving the fantastical land of the Fairy Glade from an army of robotic pirates led by Admiral Razorbeard.', 'https://media.retroachievements.org/Images/071847.png', 'https://media.retroachievements.org/Images/014328.png', 'https://media.retroachievements.org/Images/033881.png', 'https://media.retroachievements.org/Images/033869.png', 4.3),
  (77, 6524, 'Bionic Commando: Elite Forces', 'Game Boy Color', 6, 438, 438, 438, 49, 0, '2D Platforming, Metroidvania', 'Nintendo', 'Nintendo', '2000-01-01', 'Bionic Commando: Elite Forces is a 2000 platform video game developed by Nintendo Software Technology and published by Nintendo for the Game Boy Color. It is an installment of Capcom''s Bionic Commando series developed under license by Nintendo, and was the first title to be developed by its Redmond-based first-party studio Nintendo Software Technology. It is the sequel to the Game Boy version of Bionic Commando. It was not released in Europe until November 2014 when it was released for the Nintendo 3DS Virtual Console in Europe.', 'https://media.retroachievements.org/Images/019006.png', 'https://media.retroachievements.org/Images/095872.png', 'https://media.retroachievements.org/Images/019003.png', 'https://media.retroachievements.org/Images/019004.png', 4.3),
  (78, 2370, '~Prototype~ Resident Evil', 'Game Boy Color', 6, 429, 429, 429, 19, 0, 'Survival Horror', 'HotGen Studios', 'Capcom', NULL, 'Resident Evil, known as Biohazard  in Japan, is a Japanese horror game series and media franchise created by Capcom. It consists of survival horror, third-person shooter and first-person games, with players typically surviving in environments inhabited by zombies and other mutated creatures. The franchise has expanded into media including a live-action film series, animated films, television series, comic books, novels, audiobooks, and merchandise. Resident Evil is among the highest-grossing horror franchises of all time, and is Capcom''s best-selling franchise, with over 170 million copies sold worldwide as of March 2025. Individual installments of the series have been critically acclaimed and have received several awards, and many characters from the series such as Leon S. Kennedy and Albert Wesker have been described as video game icons.', 'https://media.retroachievements.org/Images/040116.png', 'https://media.retroachievements.org/Images/045393.png', 'https://media.retroachievements.org/Images/016487.png', 'https://media.retroachievements.org/Images/016486.png', 4.3),
  (79, 4950, 'Antz', 'Game Boy Color', 6, 418, 418, 418, 28, 0, '2D Platforming', 'CLCE & Planet', 'Infogrames', '1999-09-24', 'Antz is a 1998 American animated adventure comedy film directed by Eric Darnell and Tim Johnson, and written by Todd Alcott, Chris Weitz and Paul Weitz, with additional sequences directed by Lawrence Guterman. Produced by DreamWorks Animation and PDI, the film features an ensemble voice cast, including Woody Allen, Sharon Stone, Jennifer Lopez, Sylvester Stallone, Christopher Walken, Dan Aykroyd, Anne Bancroft, Danny Glover and Gene Hackman. Some of the main characters share facial similarities with the actors who voice them. The film involves an anxious worker ant, Z, who falls in love with Princess Bala. When the arrogant General Mandible attempts to seize control of the ant colony, Z must combine his desire for purpose with his inner strength to save everyone.', 'https://media.retroachievements.org/Images/048931.png', 'https://media.retroachievements.org/Images/007023.png', 'https://media.retroachievements.org/Images/007021.png', 'https://media.retroachievements.org/Images/007022.png', 4.3),
  (80, 12804, 'Meitantei Conan: Karakuri Jiin Satsujin Jiken', 'Game Boy Color', 6, 414, 414, 414, 12, 0, NULL, NULL, NULL, '2000-02-25', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/017556.png', 'https://media.retroachievements.org/Images/017150.png', 'https://media.retroachievements.org/Images/017148.png', 'https://media.retroachievements.org/Images/017149.png', 4.3),
  (81, 4671, 'The Powerpuff Girls: Bad Mojo Jojo', 'Game Boy Color', 6, 414, 414, 414, 42, 0, '2D Platforming', 'Sennari Interactive', 'BAM! Entertainment', '2000-11-14', 'The Powerpuff Girls: Bad Mojo Jojo is a 2000 platform game developed by Sennari Interactive and published by Bay Area Multimedia for the Game Boy Color. It is based on Cartoon Network animated series The Powerpuff Girls.', 'https://media.retroachievements.org/Images/088583.png', 'https://media.retroachievements.org/Images/022186.png', 'https://media.retroachievements.org/Images/002209.png', 'https://media.retroachievements.org/Images/022189.png', 4.3),
  (82, 7130, 'Dance Dance Revolution GB', 'Game Boy Color', 6, 408, 408, 408, 70, 0, 'Rhythm', 'Now Production', 'Konami', '2000-08-03', ' The Dance Dance Revolution series started in 1998 and has grown to a large set of games in the franchise. This list of Dance Dance Revolution games documents games released, including systems, formats, and regions for which the games were released.', 'https://media.retroachievements.org/Images/061325.png', 'https://media.retroachievements.org/Images/017858.png', 'https://media.retroachievements.org/Images/017856.png', 'https://media.retroachievements.org/Images/017857.png', 4.3),
  (83, 8630, 'BattleTanx', 'Game Boy Color', 6, 405, 405, 405, 32, 0, 'Vehicular Combat', 'The 3DO Company', 'Lucky Chicken Games', '2000-04-01', 'BattleTanx is a 1998 action game released for the Nintendo 64, produced by The 3DO Company. The game was followed by a 1999 sequel, titled BattleTanx: Global Assault.', 'https://media.retroachievements.org/Images/066987.png', 'https://media.retroachievements.org/Images/023845.png', 'https://media.retroachievements.org/Images/066990.png', 'https://media.retroachievements.org/Images/066991.png', 4.3),
  (84, 4192, 'Monkey Puncher', 'Game Boy Color', 6, 393, 393, 393, 33, 0, 'Management Simulation, Pet Simulation', 'Taito', 'Event Horizon Software', '2000-03-24', 'Monkey Puncher  is a video game for the Game Boy Color, developed by Atelier Double, and released in December 2000. The game''s goal is to train a monkey to fight in organised boxing matches in order to save the main character''s father and sibling.', 'https://media.retroachievements.org/Images/105118.png', 'https://media.retroachievements.org/Images/047647.png', 'https://media.retroachievements.org/Images/047645.png', 'https://media.retroachievements.org/Images/047646.png', 4.3),
  (85, 4922, 'Warlocked', 'Game Boy Color', 6, 389, 389, 389, 54, 0, 'Real-Time Strategy', 'Bits Studios', 'Nintendo', '2000-07-24', 'Warlocked is a real-time strategy video game developed by Bits Studios and published by Nintendo for the Game Boy Color. It was solely released in North America on July 24, 2000. Choosing between human and beast factions, the player plays through twelve scenarios from each faction, gathering resources, building fortresses, and managing troops to defeat the opposing force.', 'https://media.retroachievements.org/Images/002782.png', 'https://media.retroachievements.org/Images/002681.png', 'https://media.retroachievements.org/Images/002815.png', 'https://media.retroachievements.org/Images/002781.png', 4.3),
  (86, 24391, '~Homebrew~ Retro Quiz Tower: JAM Edition', 'Game Boy Color', 6, 376, 376, 376, 6, 0, NULL, 'Rubenretro', 'Rubenretro', '2023-05-20', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/112764.png', 'https://media.retroachievements.org/Images/073662.png', 'https://media.retroachievements.org/Images/112690.png', 'https://media.retroachievements.org/Images/112691.png', 4.2),
  (87, 16252, '~Hack~ Pokémon Fool''s Gold', 'Game Boy Color', 6, 374, 374, 374, 124, 0, 'Turn-Based RPG', 'Kingbigb0y, Froqpond, G.eeb', 'Hack - Pokemon Crystal Version', '2020-04-01', '2001 saw many sequels and prequels in video games, such as Madden NFL 2002, NBA Live 2002, NBA 2K2, WWF Smackdown! Just Bring It, Capcom vs. SNK 2, Crazy Taxi 2, Dead or Alive 3, Final Fantasy X, Gran Turismo 3: A-Spec, Grand Theft Auto III, Metal Gear Solid 2: Sons of Liberty, Myst III: Exile, Silent Hill 2, Sonic Adventure 2, SSX Tricky, Super Smash Bros. Melee, Tekken 4, Tony Hawk''s Pro Skater 3, and Virtua Fighter 4. New intellectual properties include Phoenix Wright: Ace Attorney, Advance Wars, Animal Crossing, Burnout, Gothic, Black & White, Devil May Cry, Fatal Frame, Ghost Recon, Halo: Combat Evolved, Jak and Daxter, Max Payne, Oni, Onimusha: Warlords, Operation Flashpoint, Pikmin, Pro Evolution Soccer, Red Faction, Serious Sam, and Tropico.', 'https://media.retroachievements.org/Images/090889.png', 'https://media.retroachievements.org/Images/034135.png', 'https://media.retroachievements.org/Images/034132.png', 'https://media.retroachievements.org/Images/034133.png', 4.2),
  (88, 5143, 'Harvest Moon 3 GBC', 'Game Boy Color', 6, 364, 364, 364, 57, 0, 'Life Simulation', 'Marvelous Interactive', 'Natsume', '2000-09-29', 'Harvest Moon 3 GBC  is a farm simulation video game for the Game Boy Color developed and published by Victor Interactive Software, part of the long-running Story of Seasons series of video games. The game was released for the Nintendo 3DS via Virtual Console in North America on December 11, 2014.', 'https://media.retroachievements.org/Images/087833.png', 'https://media.retroachievements.org/Images/003441.png', 'https://media.retroachievements.org/Images/003436.png', 'https://media.retroachievements.org/Images/003440.png', 4.2),
  (89, 4080, 'Alfred''s Adventure', 'Game Boy Color', 6, 363, 363, 363, 33, 0, '2D Platforming', 'SCi Games | Sales Curve Interactive', 'Rockstar Games', '2000-09-01', 'Alfred Chicken is a platform video game developed by Twilight and published by Mindscape for the Game Boy. It was later ported to the Amiga, Amiga CD32, NES, and Super NES in 1993 and February 1994, in Europe and North America, respectively. A Europe-exclusive remake of the game, entitled Alfred''s Adventure, was developed by Möbius Entertainment and released by SCi for Game Boy Color in June 2000. Another remake, named Alfred Chicken, was also developed by King Monkey, a division of Möbius Entertainment, and released by Sony Computer Entertainment for PlayStation in 2002. Rockstar Games does not own the title''s rights, despite buying Möbius later on, as Jason McGann personally held the rights.', 'https://media.retroachievements.org/Images/049212.png', 'https://media.retroachievements.org/Images/005877.png', 'https://media.retroachievements.org/Images/005878.png', 'https://media.retroachievements.org/Images/044693.png', 4.2),
  (90, 18707, '~Homebrew~ ~Demo~ Mina the Hollower GBC Demake', 'Game Boy Color', 6, 362, 362, 362, 6, 0, 'Action-Adventure', 'Jan Klečka', 'Jan Klečka', '2022-02-25', NULL, 'https://media.retroachievements.org/Images/111710.png', 'https://media.retroachievements.org/Images/054307.png', 'https://media.retroachievements.org/Images/054305.png', 'https://media.retroachievements.org/Images/054306.png', 4.2),
  (91, 6136, 'Motocross Maniacs 2', 'Game Boy Color', 6, 360, 360, 360, 43, 0, 'Extreme Sports - Motocross', 'Konami Computer Entertainment Osaka', 'Konami', '1999-09-10', 'Motocross Maniacs 2 is a 1999 racing game for the Game Boy Color, developed and published by Konami. A sequel to the 1989 Game Boy title Motocross Maniacs, the game is a racing game in which the player drives across a side-scrolling motocross course.', 'https://media.retroachievements.org/Images/071375.png', 'https://media.retroachievements.org/Images/004993.png', 'https://media.retroachievements.org/Images/004994.png', 'https://media.retroachievements.org/Images/004995.png', 4.2),
  (92, 7638, 'Aladdin', 'Game Boy Color', 6, 353, 353, 353, 35, 0, '2D Platforming', 'Crawfish Interactive', ' Disney Interactive Studios, Ubisoft', '2000-11-07', 'Aladdin is a Middle-Eastern folk tale. It is one of the best-known tales associated with One Thousand and One Nights, despite not being part of the original text; it was added by the Frenchman Antoine Galland, based on a folk tale that he heard from the Syrian storyteller Hanna Diyab.', 'https://media.retroachievements.org/Images/096418.png', 'https://media.retroachievements.org/Images/094813.png', 'https://media.retroachievements.org/Images/091213.png', 'https://media.retroachievements.org/Images/091214.png', 4.2),
  (93, 10849, 'Buzz Lightyear of Star Command', 'Game Boy Color', 6, 349, 349, 349, 27, 0, 'Action / Racing', 'Traveller''s Tales', 'Activision', '2000-11-01', 'Buzz Lightyear of Star Command is an American animated science fiction comedy television series produced by Walt Disney Television Animation. It is a spin-off of Pixar''s Toy Story franchise. The series was preceded by the direct-to-video film Buzz Lightyear of Star Command: The Adventure Begins, and aired on ABC and UPN from October 2, 2000, to January 13, 2001. While the series is 2D animated, Pixar animated the CGI opening title sequence.', 'https://media.retroachievements.org/Images/114100.png', 'https://media.retroachievements.org/Images/014668.png', 'https://media.retroachievements.org/Images/014667.png', 'https://media.retroachievements.org/Images/014669.png', 4.2),
  (94, 33577, '~Homebrew~ Fable: 20th Anniversary Demake', 'Game Boy Color', 6, 339, 339, 339, 6, 0, 'Adventure', 'james222', 'james222', '2024-10-17', 'The Chocobo  is a fictional species created for the Final Fantasy franchise by Square Enix. A galliform bird commonly having yellow feathers, they were first introduced in Final Fantasy II (1988), and have since featured in some capacity in nearly every Final Fantasy title, usually as a means of transport. Chocobos or chocobo-themed characters have played story roles in multiple titles, notably in Final Fantasy V and XIII. A recurring Chocobo also acts as protagonist of the Chocobo spin-off series.', 'https://media.retroachievements.org/Images/111512.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/111513.png', 'https://media.retroachievements.org/Images/111514.png', 4.2),
  (95, 6536, 'Looney Tunes Collector: Alert!', 'Game Boy Color', 6, 326, 326, 326, 17, 0, 'Action-Adventure', 'Infogrames', 'Infogrames, Syscom', '2000-06-24', 'Looney Tunes Collector: Martian Alert! is a Looney Tunes game developed and published by Infogrames for the Game Boy Color in 2000.', 'https://media.retroachievements.org/Images/105174.png', 'https://media.retroachievements.org/Images/015136.png', 'https://media.retroachievements.org/Images/047946.png', 'https://media.retroachievements.org/Images/047947.png', 4.2),
  (96, 2502, 'Lufia: The Legend Returns', 'Game Boy Color', 6, 316, 316, 316, 59, 0, 'Turn-Based RPG', 'Neverland', 'Natsume', '2001-09-20', 'Lufia: The Legend Returns is a role-playing video game for the Game Boy Color developed by Neverland and published by Taito, Natsume Inc., and Ubi Soft in Japan, North America, and Europe, respectively, in 2001. It is the third game in the Lufia series and the first one to appear on a handheld gaming system.', 'https://media.retroachievements.org/Images/107710.png', 'https://media.retroachievements.org/Images/002671.png', 'https://media.retroachievements.org/Images/002670.png', 'https://media.retroachievements.org/Images/044410.png', 4.2),
  (97, 16218, 'The Smurfs'' Nightmare', 'Game Boy Color', 6, 315, 315, 315, 60, 0, '2D Platforming', 'Velez & Dubail', 'Infogrames', '1999-01-01', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/067943.png', 'https://media.retroachievements.org/Images/033113.png', 'https://media.retroachievements.org/Images/033109.png', 'https://media.retroachievements.org/Images/033111.png', 4.2),
  (98, 29687, '~Homebrew~ The Best Text Adventure', 'Game Boy Color', 6, 314, 314, 314, 9, 0, 'Text Adventure', 'Stephen Allen, Matte Trucks', 'Shining Kitten Games', '2023-01-01', 'Dragon Quest, titled Dragon Warrior when initially localized to North America, is a 1986 role-playing video game developed by Chunsoft and published by Enix for the Nintendo Entertainment System. It was originally released in Japan in May 1986 and by Nintendo in North America in August 1989. It is the first game in the Dragon Quest video game series. Dragon Quest has been ported and remade for several video game platforms. As of 2019, it has been ported to MSX, MSX2, PC-9801, Super Famicom, Game Boy Color, mobile phones, and Nintendo Switch. The player controls the hero character who is charged with saving the Kingdom of Alefgard and rescuing its princess from the evil Dragonlord. Dragon Warrior''s story became the second part in a trilogy, with several spinoff anime and manga series.', 'https://media.retroachievements.org/Images/095562.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/095563.png', 'https://media.retroachievements.org/Images/095564.png', 4.2),
  (99, 26399, 'Käpt''n Blaubär: Die verrückte Schatzsuche', 'Game Boy Color', 6, 313, 313, 313, 18, 0, NULL, 'Shin''en Multimedia', 'Ravensburger Interactive Media', '2001-01-10', 'Käpt''n Blaubär is a fictional character created by novelist and comic artist Walter Moers. He is an anthropomorphic talking bear with blue fur who originally appeared in the German children''s television program Die Sendung mit der Maus, has since then appeared in a film, a novel, a stage musical and various other media, all of which chronicle the character''s life as a sailor and adventurer. Outside of Germany, Captain Bluebear is best known for being the protagonist of Moers'' novel The 13½ Lives of Captain Bluebear.', 'https://media.retroachievements.org/Images/089479.png', 'https://media.retroachievements.org/Images/089470.png', 'https://media.retroachievements.org/Images/089477.png', 'https://media.retroachievements.org/Images/089478.png', 4.2),
  (100, 28796, '~Homebrew~ Days Without', 'Game Boy Color', 6, 308, 308, 308, 8, 0, 'Survival Horror', 'Elvies', 'Elvies', '2023-01-01', 'Overcome is the fourth studio album by the American heavy metal band All That Remains. It was released on September 16, 2008. Overcome is the first album with drummer Jason Costa.', 'https://media.retroachievements.org/Images/092886.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/090021.png', 'https://media.retroachievements.org/Images/090022.png', 4.2),
  (101, 4125, 'Metal Walker', 'Game Boy Color', 6, 303, 303, 303, 27, 0, NULL, 'Capcom', 'Capcom', '2001-02-06', 'Metal Walker, known as Bakusou Senki Metal Walker GB: Kotetsu no Yuujou  in Japan, is a role-playing video game for the Game Boy Color, developed and published by Capcom. Many critics likened the game to the Pokémon series, but praised the game''s unique qualities. In Japan, the game inspired merchandise based on the Metal Walker robots.', 'https://media.retroachievements.org/Images/066852.png', 'https://media.retroachievements.org/Images/019015.png', 'https://media.retroachievements.org/Images/019013.png', 'https://media.retroachievements.org/Images/019014.png', 4.2),
  (102, 4100, 'Azure Dreams', 'Game Boy Color', 6, 300, 300, 300, 55, 0, 'Roguelike', 'Konami', 'Konami', '1999-08-05', 'Azure Dreams is a roguelike role-playing video game developed by Konami Computer Entertainment Tokyo and published by Konami for the PlayStation. A Game Boy Color game with the same name was developed by Konami Computer Entertainment Nagoya and released two years later. A spiritual sequel, Tao''s Adventure: Curse of the Demon Seal, was released on the Nintendo DS in 2005.', 'https://media.retroachievements.org/Images/066585.png', 'https://media.retroachievements.org/Images/066067.png', 'https://media.retroachievements.org/Images/002667.png', 'https://media.retroachievements.org/Images/006626.png', 4.2),
  (103, 29578, 'Trip World DX', 'Game Boy Color', 6, 300, 300, 300, 35, 0, '2D Platforming', 'Limited Run Games, Sunsoft', 'Limited Run Games', '2023-11-30', 'Trip World is a 1992 platform game developed and published by Sunsoft for the Game Boy. It was released in Japan in 1992. The game''s plot centers around the bunny-like being Yakopoo and his quest to retrieve the flower of peace so that peace will return to his disarranged world. The protagonist''s trademark ability is to shapeshift into different forms.', 'https://media.retroachievements.org/Images/109251.png', 'https://media.retroachievements.org/Images/094952.png', 'https://media.retroachievements.org/Images/094951.png', 'https://media.retroachievements.org/Images/094950.png', 4.2),
  (104, 29790, '~Homebrew~ My Saturday Grounded', 'Game Boy Color', 6, 292, 292, 292, 6, 0, 'Adventure', 'Tustin2121', 'itch.io', '2021-09-28', 'Donkey Kong is a video game series and media franchise created by the Japanese game designer Shigeru Miyamoto for Nintendo. It follows the adventures of Donkey Kong, a large, powerful gorilla, and other members of the Kong family of apes. Donkey Kong games include the original arcade game trilogy by Nintendo R&D1; the Donkey Kong Country series by Rare and Retro Studios; and the Mario vs. Donkey Kong series by Nintendo Software Technology. Various studios have developed spin-offs in genres such as edutainment, puzzle, racing, and rhythm. The franchise also incorporates animation, printed media, theme parks, and merchandise.', 'https://media.retroachievements.org/Images/098028.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/096803.png', 'https://media.retroachievements.org/Images/096804.png', 4.2),
  (105, 8926, '~Unlicensed~ Terrifying 911', 'Game Boy Color', 6, 292, 292, 292, 29, 0, 'Run & Gun', 'Hitek', 'Hitek / Li Cheng', '2002-01-01', 'Terrifier is a 2016 American independent slasher film written, edited, co-produced, and directed by Damien Leone. The film stars Jenna Kanell, Samantha Scaffidi, Catherine Corcoran, and David Howard Thornton. The plot centers on partygoer Tara Heyes (Kanell) and her sister Victoria (Scaffidi), who become targets of the enigmatic serial killer known only as Art the Clown (Thornton) on Halloween night.', 'https://media.retroachievements.org/Images/063338.png', 'https://media.retroachievements.org/Images/053108.png', 'https://media.retroachievements.org/Images/062834.png', 'https://media.retroachievements.org/Images/049859.png', 4.2),
  (106, 17429, '~Hack~ Pokémon Gold 97: Reforged | Pokémon Silver 97: Reforged', 'Game Boy Color', 6, 280, 280, 280, 28, 0, 'Turn-Based RPG', 'SourApple', 'Hack - Pokemon Crystal Version', '2020-12-29', '  This is a list of video game remakes and remasters and includes remakes as well as remasters of video games. It does not include clones and enhanced ports.', 'https://media.retroachievements.org/Images/066027.png', 'https://media.retroachievements.org/Images/051337.png', 'https://media.retroachievements.org/Images/041775.png', 'https://media.retroachievements.org/Images/041776.png', 4.2),
  (107, 6342, 'NSYNC: Get to the Show', 'Game Boy Color', 6, 280, 280, 280, 16, 0, 'Minigames', 'Stunt Puppy Entertainment', 'Infogrames', '2001-12-13', 'NSYNC was an American vocal group and pop boy band formed by Chris Kirkpatrick in Orlando, Florida, in 1995 and launched in Germany by BMG Ariola Munich. The group consisted of Kirkpatrick, JC Chasez, Joey Fatone, Justin Timberlake, and Jason Galasso who soon left and was replaced by Lance Bass. Their debut album NSYNC was successfully released to European countries in 1997 and later entered the American market with the single "I Want You Back".', 'https://media.retroachievements.org/Images/054927.png', 'https://media.retroachievements.org/Images/054953.png', 'https://media.retroachievements.org/Images/037619.png', 'https://media.retroachievements.org/Images/037620.png', 4.2),
  (108, 3632, 'Dexter''s Laboratory: Robot Rampage', 'Game Boy Color', 6, 276, 276, 276, 26, 0, 'Action', 'Altron', 'Bay Area Multimedia', '2000-11-14', 'Dexter''s Laboratory: Robot Rampage is an action video game published by Bay Area Multimedia for the Game Boy Color and released in the United States on November 28, 2000. It is a graphically redesigned version of the game Elevator Action EX, also developed by Altron, with characters from the American animated television series Dexter''s Laboratory from Cartoon Network.', 'https://media.retroachievements.org/Images/062617.png', 'https://media.retroachievements.org/Images/034276.png', 'https://media.retroachievements.org/Images/034278.png', 'https://media.retroachievements.org/Images/034277.png', 4.2),
  (109, 4702, 'Die Original Moorhuhnjagd', 'Game Boy Color', 6, 276, 276, 276, 12, 0, 'Gallery Shooter', 'Witan Entertainment BV', 'Ravensburger', '2000-11-08', 'Crazy Chicken, sometimes known as Chicken Hunter or Moorhen, is a shooting gallery video game franchise. While originally intended to merely serve as a small-scale advertising game, the first game''s unintended online release and subsequent distribution as shareware were followed by an unprecedented surge in popularity, making it Germany''s most popular computer game in the early 2000s and enabling Crazy Chicken to develop into a multi-platform franchise with a variety of spin-offs and merchandise.', 'https://media.retroachievements.org/Images/072537.png', 'https://media.retroachievements.org/Images/021695.png', 'https://media.retroachievements.org/Images/021696.png', 'https://media.retroachievements.org/Images/021711.png', 4.2),
  (110, 29774, '~Homebrew~ Borbo''s Quest', 'Game Boy Color', 6, 272, 272, 272, 9, 0, 'Adventure', 'FrogSoft', 'FrogSoft', '2020-12-20', NULL, 'https://media.retroachievements.org/Images/096605.png', 'https://media.retroachievements.org/Images/096606.png', 'https://media.retroachievements.org/Images/096594.png', 'https://media.retroachievements.org/Images/096597.png', 4.2),
  (111, 8497, 'Mortal Kombat 4', 'Game Boy Color', 6, 272, 272, 272, 26, 0, '2D Fighting', 'Digital Eclipse', 'Midway', '1998-12-12', 'Mortal Kombat 4 is a 1997 fighting game developed and published by Midway for arcades. It is the fourth main installment in the Mortal Kombat franchise, and a sequel to 1995''s Mortal Kombat 3. It is also the first title in the series to use 3D computer graphics, as well as the last in the series to have an arcade release. The game was ported to the PlayStation, Nintendo 64, Microsoft Windows, and Game Boy Color in 1998, followed by an updated version, titled Mortal Kombat Gold, for the Dreamcast in 1999.', 'https://media.retroachievements.org/Images/123572.png', 'https://media.retroachievements.org/Images/060737.png', 'https://media.retroachievements.org/Images/033877.png', 'https://media.retroachievements.org/Images/033873.png', 4.2),
  (112, 5155, 'Harvest Moon 2 GBC', 'Game Boy Color', 6, 260, 260, 260, 53, 0, 'Life Simulation', 'Marvelous Interactive', 'Natsume', '1999-08-16', 'Harvest Moon 2 GBC, released in Japan as Bokujō Monogatari GB2 (牧場物語GB2), is a farming simulation video game for the Game Boy Color developed and published by Victor Interactive Software, and the second portable game in the Story of Seasons series. The object of the game is to cultivate a farm to prevent the land from being used to build an amusement park. As with the previous game, the player may choose to play as a boy or a girl.', 'https://media.retroachievements.org/Images/059691.png', 'https://media.retroachievements.org/Images/003481.png', 'https://media.retroachievements.org/Images/003480.png', 'https://media.retroachievements.org/Images/003483.png', 4.2),
  (113, 686, 'Bugs Bunny: Crazy Castle 3', 'Game Boy Color', 6, 256, 256, 256, 16, 0, NULL, 'Kemco', 'Nintendo', '1999-01-29', 'Bugs Bunny: Crazy Castle 3  is a platform game developed by Kemco as part of the Crazy Castle series. It was originally released in Japan as a Game Boy title in July 1997 called Soreyuke!! Kid: Go! Go! Kid  starring the character Kid Klown. The title was later remade on the Game Boy Color to include colorized graphics and characters from the Looney Tunes series, which was released in Japan in January 1999 by Kemco, and later that year in North America and Europe by Nintendo. It replaces Honey Bunny with Lola Bunny as Bugs'' love interest to be rescued. It was followed by a sequel, Bugs Bunny in Crazy Castle 4, in 2000.', 'https://media.retroachievements.org/Images/054345.png', 'https://media.retroachievements.org/Images/005227.png', 'https://media.retroachievements.org/Images/005230.png', 'https://media.retroachievements.org/Images/005231.png', 4.2),
  (114, 12951, 'Nicktoons Racing', 'Game Boy Color', 6, 256, 256, 256, 29, 0, 'Kart Racing', 'Pipe Dream Interactive', 'Hasbro Interactive', '2000-12-07', 'Nicktoons Racing is a racing video game developed by Software Creations for the PlayStation and Microsoft Windows. An abridged version was developed by Pipe Dream for the Game Boy Color in 2000, while Crawfish Interactive developed another abridged version for the Game Boy Advance in 2002. An arcade version developed by Chicago Gaming was released in 2003.', 'https://media.retroachievements.org/Images/116383.png', 'https://media.retroachievements.org/Images/040661.png', 'https://media.retroachievements.org/Images/040631.png', 'https://media.retroachievements.org/Images/040632.png', 4.2),
  (115, 6167, 'Pop''n Music GB', 'Game Boy Color', 6, 256, 256, 256, 123, 0, 'Rhythm', 'Konami', 'Konami', '2000-03-30', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/061000.png', 'https://media.retroachievements.org/Images/005061.png', 'https://media.retroachievements.org/Images/005060.png', 'https://media.retroachievements.org/Images/005077.png', 4.2),
  (116, 3650, 'Mr. Nutz', 'Game Boy Color', 6, 253, 253, 253, 13, 0, '2D Platforming', 'Planet Interactive', 'Infogrames', '1999-11-01', 'Mr. Nutz (ミスターナッツ) is a 2D side-scrolling platform game published by Ocean Software. It was released for the Super Nintendo Entertainment System in late 1993 in Europe and in North America and Japan in 1994. In 1994, it was released for the Mega Drive as Ocean''s first Sega game, and on the Game Boy. It was also released on the Sega Channel in 1995, the Game Boy Color in 1999, and remade for the Game Boy Advance in 2001.', 'https://media.retroachievements.org/Images/043241.png', 'https://media.retroachievements.org/Images/017512.png', 'https://media.retroachievements.org/Images/043942.png', 'https://media.retroachievements.org/Images/043943.png', 4.2),
  (117, 6531, 'The Flintstones: Burgertime in Bedrock', 'Game Boy Color', 6, 250, 250, 250, 27, 0, NULL, 'Conspiracy Entertainment', 'Swing! Entertainment, Classified Games', '2000-12-01', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/031111.png', 'https://media.retroachievements.org/Images/031108.png', 'https://media.retroachievements.org/Images/031106.png', 'https://media.retroachievements.org/Images/031107.png', 4.2),
  (118, 31934, '~Homebrew~ Combo Fishing', 'Game Boy Color', 6, 248, 248, 248, 26, 0, 'Sports - Fishing', 'WilbosWorld', 'WilbosWorld', '2024-11-01', 'The following is a list of notable vehicle racing video games. The genre first emerged in the mid- to late 1970s.', 'https://media.retroachievements.org/Images/105177.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/104981.png', 'https://media.retroachievements.org/Images/104982.png', 4.2),
  (119, 4731, 'Magi Nation', 'Game Boy Color', 6, 246, 246, 246, 66, 0, NULL, 'Interactive Imagination', 'Interactive Imagination', '2001-01-01', 'Magi Nation is a 2001 video game for the Game Boy Color developed by American studio Interactive Imagination. It is based on the collectible card game Magi-Nation Duel.', 'https://media.retroachievements.org/Images/097866.png', 'https://media.retroachievements.org/Images/002673.png', 'https://media.retroachievements.org/Images/002672.png', 'https://media.retroachievements.org/Images/019007.png', 4.2),
  (120, 3625, 'M&M''s Minis Madness', 'Game Boy Color', 6, 243, 243, 243, 12, 0, '2D Platforming', 'Pipe Dream Interactive', 'Majesco Entertainment', '2000-12-08', ' This is a list of video games related to the M&M''s brand.', 'https://media.retroachievements.org/Images/106415.png', 'https://media.retroachievements.org/Images/019919.png', 'https://media.retroachievements.org/Images/044694.png', 'https://media.retroachievements.org/Images/044695.png', 4.2),
  (121, 2500, 'Oddworld Adventures II', 'Game Boy Color', 6, 243, 243, 243, 55, 0, 'Cinematic Platforming', 'Saffire', 'Atari', '2000-01-19', 'Oddworld: Abe''s Exoddus is a platform video game developed by Oddworld Inhabitants and published by GT Interactive. Although the game is a sequel to the video game Oddworld: Abe''s Oddysee, it is considered a spin-off title in the Oddworld series, and not part of the Oddworld Quintology. It was released in November 1998 for the PlayStation video game console and in December 1998 for Microsoft Windows. A Game Boy Color version, titled Oddworld Adventures 2, was released in 2000. The PlayStation version was re-released on the PlayStation Network in October 2009.', 'https://media.retroachievements.org/Images/018752.png', 'https://media.retroachievements.org/Images/008100.png', 'https://media.retroachievements.org/Images/018751.png', 'https://media.retroachievements.org/Images/018750.png', 4.2),
  (122, 14166, 'LEGO Island 2: The Brickster''s Revenge', 'Game Boy Color', 6, 239, 239, 239, 13, 0, 'Action-Adventure', 'Crawfish Interactive', 'LEGO Interactive | LEGO Media', '2001-03-30', 'Lego Island 2: The Brickster''s Revenge is a 2001 action-adventure video game developed by Silicon Dreams Studio and published by Lego Software. It is the sequel to Lego Island and was followed by Island Xtreme Stunts.', 'https://media.retroachievements.org/Images/041476.png', 'https://media.retroachievements.org/Images/026308.png', 'https://media.retroachievements.org/Images/026316.png', 'https://media.retroachievements.org/Images/026307.png', 4.2),
  (123, 4919, 'Quest: Brian''s Journey', 'Game Boy Color', 6, 239, 239, 239, 24, 0, 'Turn-Based RPG', 'Atelier Double', 'Sunsoft, Imagineer', '2000-01-15', 'Quest: Brian''s Journey is a 2000 role-playing video game published in North America by Sunsoft for the Game Boy Color. The game''s title screen instead displays the title as Quest RPG: Brian''s Journey.', 'https://media.retroachievements.org/Images/053956.png', 'https://media.retroachievements.org/Images/050758.png', 'https://media.retroachievements.org/Images/002638.png', 'https://media.retroachievements.org/Images/002821.png', 4.2),
  (124, 18594, 'Dancing Furby', 'Game Boy Color', 6, 238, 238, 238, 25, 0, 'Rhythm', 'TOSE', 'Tomy', '1999-12-24', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/053428.png', 'https://media.retroachievements.org/Images/053424.png', 'https://media.retroachievements.org/Images/053425.png', 'https://media.retroachievements.org/Images/053427.png', 4.2),
  (125, 14356, 'Tony Hawk''s Pro Skater', 'Game Boy Color', 6, 234, 234, 234, 12, 0, 'Extreme Sports - Skateboarding', 'Natsume', 'Activision', '2000-01-01', 'Tony Hawk''s Pro Skater, released as Tony Hawk''s Skateboarding in the United Kingdom, Australia, New Zealand, and parts of Europe, is a 1999 skateboarding video game developed by Neversoft and published by Activision. It is the first installment in the Tony Hawk''s series. It was released for the PlayStation on September 29, 1999 and was later ported to the Nintendo 64, Game Boy Color, Dreamcast, and N-Gage.', 'https://media.retroachievements.org/Images/041161.png', 'https://media.retroachievements.org/Images/041162.png', 'https://media.retroachievements.org/Images/041159.png', 'https://media.retroachievements.org/Images/041160.png', 4.2),
  (126, 25072, '~Hack~ Pokémon TCG Neo', 'Game Boy Color', 6, 232, 232, 232, 23, 0, 'Collectible Card Game', 'Cataclyptic', NULL, '2023-01-15', 'This is a list of video games with mechanics based on collectible card games. It includes games which directly simulate collectible card games, arcade games integrated with physical collectible card games, and video games in other genres which utilize elements of deck-building or card battling as a significant portion of their game mechanics. It does not include games which only feature card collecting or card battling as a minigame, nor does it include games which simulate traditional card games such as solitaire or poker.', 'https://media.retroachievements.org/Images/078094.png', 'https://media.retroachievements.org/Images/122432.png', 'https://media.retroachievements.org/Images/078172.png', 'https://media.retroachievements.org/Images/078173.png', 4.2),
  (127, 16089, 'Medarot 3: Kabuto Version', 'Game Boy Color', 6, 232, 232, 232, 149, 0, NULL, NULL, 'Imagineer', '2000-07-23', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/106988.png', 'https://media.retroachievements.org/Images/106979.png', 'https://media.retroachievements.org/Images/107439.png', 'https://media.retroachievements.org/Images/108517.png', 4.2),
  (128, 20036, '~Homebrew~ Postie', 'Game Boy Color', 6, 229, 229, 229, 6, 0, '2D Platforming', 'invertedHat', 'invertedHat', '2022-05-29', 'Postie, formerly Postie Plus, is a New Zealand clothing store chain. It was founded in 1909 by Thomas Dellaca. As of October 2022, Postie has 61 stores as well as an online platform. Together with Australian retailer Best & Less, it forms the Best & Less Group.', 'https://media.retroachievements.org/Images/059539.png', 'https://media.retroachievements.org/Images/059542.png', 'https://media.retroachievements.org/Images/059540.png', 'https://media.retroachievements.org/Images/059541.png', 4.2),
  (129, 6181, 'Dance Dance Revolution GB: Disney Mix', 'Game Boy Color', 6, 226, 226, 226, 61, 0, 'Rhythm', 'Now Production', 'Konami', '2001-03-29', 'Below is a list of video games based on Walt Disney Animation Studios shorts and features.', 'https://media.retroachievements.org/Images/057759.png', 'https://media.retroachievements.org/Images/017878.png', 'https://media.retroachievements.org/Images/017876.png', 'https://media.retroachievements.org/Images/017877.png', 4.1),
  (130, 30935, '~Homebrew~ Noble Blood', 'Game Boy Color', 6, 225, 225, 225, 8, 0, NULL, 'Conan', 'Conan', '2023-10-24', 'Dragon Quest, titled Dragon Warrior when initially localized to North America, is a 1986 role-playing video game developed by Chunsoft and published by Enix for the Nintendo Entertainment System. It was originally released in Japan in May 1986 and by Nintendo in North America in August 1989. It is the first game in the Dragon Quest video game series. Dragon Quest has been ported and remade for several video game platforms. As of 2019, it has been ported to MSX, MSX2, PC-9801, Super Famicom, Game Boy Color, mobile phones, and Nintendo Switch. The player controls the hero character who is charged with saving the Kingdom of Alefgard and rescuing its princess from the evil Dragonlord. Dragon Warrior''s story became the second part in a trilogy, with several spinoff anime and manga series.', 'https://media.retroachievements.org/Images/102468.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/102466.png', 'https://media.retroachievements.org/Images/102467.png', 4.1),
  (131, 12842, 'Dance Dance Revolution GB2', 'Game Boy Color', 6, 225, 225, 225, 71, 0, 'Rhythm', 'Now Production', 'Konami', '2000-11-16', ' The Dance Dance Revolution series started in 1998 and has grown to a large set of games in the franchise. This list of Dance Dance Revolution games documents games released, including systems, formats, and regions for which the games were released.', 'https://media.retroachievements.org/Images/061326.png', 'https://media.retroachievements.org/Images/017870.png', 'https://media.retroachievements.org/Images/017864.png', 'https://media.retroachievements.org/Images/017868.png', 4.1),
  (132, 28238, '~Homebrew~ The Mist', 'Game Boy Color', 6, 223, 223, 223, 12, 0, NULL, 'Yliader', 'itch.io', '2022-04-13', 'The Mist is a science fiction psychological horror cosmic horror novella by American author Stephen King. Originally written in the summer of 1976, the story was first published by Viking Press in 1980 as part of the Dark Forces anthology, an edited version was subsequently included in King''s 1985 collection Skeleton Crew.', 'https://media.retroachievements.org/Images/092887.png', 'https://media.retroachievements.org/Images/093741.png', 'https://media.retroachievements.org/Images/087800.png', 'https://media.retroachievements.org/Images/087797.png', 4.1),
  (133, 13082, 'Moorhen 3: ... The Chicken Chase!', 'Game Boy Color', 6, 221, 221, 221, 16, 0, 'Gallery Shooter', 'Sproing, Similis', 'Ubisoft', '2002-07-11', 'Crazy Chicken, sometimes known as Chicken Hunter or Moorhen, is a shooting gallery video game franchise. While originally intended to merely serve as a small-scale advertising game, the first game''s unintended online release and subsequent distribution as shareware were followed by an unprecedented surge in popularity, making it Germany''s most popular computer game in the early 2000s and enabling Crazy Chicken to develop into a multi-platform franchise with a variety of spin-offs and merchandise.', 'https://media.retroachievements.org/Images/036397.png', 'https://media.retroachievements.org/Images/036399.png', 'https://media.retroachievements.org/Images/036435.png', 'https://media.retroachievements.org/Images/036436.png', 4.1),
  (134, 6171, 'Beatmania GB2: GotchaMix', 'Game Boy Color', 6, 217, 217, 217, 95, 0, 'Rhythm', 'Konami', 'Konami', '1999-11-01', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/054090.png', 'https://media.retroachievements.org/Images/005054.png', 'https://media.retroachievements.org/Images/005055.png', 'https://media.retroachievements.org/Images/005057.png', 4.1),
  (135, 4246, 'Qix Adventure', 'Game Boy Color', 6, 214, 214, 214, 42, 0, 'Action-Puzzle', 'Coconuts Japan Entertainment', 'Taito', '1999-10-22', 'Qix Adventure is a 1999 video game developed by Coconuts Japan Entertainment and published by Taito for the Game Boy Color. An English port of the game was developed by Evolution Entertainment for the United Kingdom in 2000. The game is a puzzle game based on the 1981 Taito title Qix, with additional story elements.', 'https://media.retroachievements.org/Images/067630.png', 'https://media.retroachievements.org/Images/017649.png', 'https://media.retroachievements.org/Images/017646.png', 'https://media.retroachievements.org/Images/017650.png', 4.1),
  (136, 11582, 'Dance Dance Revolution GB3', 'Game Boy Color', 6, 212, 212, 212, 81, 0, 'Rhythm', 'Now Production', 'Konami', '2001-03-15', ' The Dance Dance Revolution series started in 1998 and has grown to a large set of games in the franchise. This list of Dance Dance Revolution games documents games released, including systems, formats, and regions for which the games were released.', 'https://media.retroachievements.org/Images/061327.png', 'https://media.retroachievements.org/Images/017873.png', 'https://media.retroachievements.org/Images/017872.png', 'https://media.retroachievements.org/Images/017874.png', 4.1),
  (137, 3637, 'Samurai Kid', 'Game Boy Color', 6, 212, 212, 212, 58, 0, NULL, 'Biox', 'Koei | Tecmo', '2001-02-02', 'Fujimaru of the Wind: The Childhood of a Ninja , also known as Samurai Kid, is a Japanese anime series produced by Toei Animation. 65 episodes aired from 7 June 1964 until 31 August 1965. It tells the story of a ninja''s pupil that controlled the wind.', 'https://media.retroachievements.org/Images/049333.png', 'https://media.retroachievements.org/Images/051023.png', 'https://media.retroachievements.org/Images/049334.png', 'https://media.retroachievements.org/Images/049335.png', 4.1),
  (138, 24117, '~Homebrew~ TUNIC', 'Game Boy Color', 6, 210, 210, 210, 10, 0, 'Action-Adventure', 'MintFerret', 'itch.io', '2023-01-20', 'The Legend of Zelda is a video game series created by Japanese game designers Shigeru Miyamoto and Takashi Tezuka. It is primarily developed and published by Nintendo, but some installments and re-releases have been outsourced to Flagship, Grezzo, and Tantalus Media.', 'https://media.retroachievements.org/Images/072016.png', 'https://media.retroachievements.org/Images/071987.png', 'https://media.retroachievements.org/Images/071997.png', 'https://media.retroachievements.org/Images/071988.png', 4.1),
  (139, 8228, '~Unlicensed~ Zook Hero Z', 'Game Boy Color', 6, 209, 209, 209, 41, 0, '2D Platforming', 'Vast Fame', 'Li Cheng', '1999-01-01', 'Numerous notable people have had some form of mood disorder. This is a list of people accompanied by verifiable sources associating them with some form of bipolar disorder, including cyclothymia, based on their own public statements; this discussion is sometimes tied to the larger topic of creativity and mental illness. In the case of dead people only, individuals with a speculative or retrospective diagnosis should only be listed if they are accompanied by a source reflective of the mainstream, academic view. Individuals should not be added to this list unless the disorder is regularly and commonly mentioned in mainstream, reliable sources.', 'https://media.retroachievements.org/Images/050272.png', 'https://media.retroachievements.org/Images/008404.png', 'https://media.retroachievements.org/Images/107127.png', 'https://media.retroachievements.org/Images/107128.png', 4.1),
  (140, 4097, 'Alice in Wonderland', 'Game Boy Color', 6, 209, 209, 209, 45, 0, '2D Platforming', 'Digital Eclipse', 'Disney Interactive Studios', '2000-10-04', 'Alice''s Adventures in Wonderland is an 1865 English children''s novel by Lewis Carroll, a mathematics don at the University of Oxford. It details the story of a girl named Alice who falls through a rabbit hole into a fantasy world of anthropomorphic creatures. It is seen as an example of the literary nonsense genre. The artist John Tenniel provided 42 wood-engraved illustrations for the book.', 'https://media.retroachievements.org/Images/069065.png', 'https://media.retroachievements.org/Images/023822.png', 'https://media.retroachievements.org/Images/023826.png', 'https://media.retroachievements.org/Images/023827.png', 4.1),
  (141, 25233, 'Space Invaders', 'Game Boy Color', 6, 207, 207, 207, 24, 0, 'Shoot ''em Up', 'Crawfish Interactive', 'Activision', '1999-10-27', 'Space Invaders is a 1978 shoot ''em up video game developed and published by Taito for arcades. It was released in Japan in April 1978, and released overseas by Midway Manufacturing later that year. Space Invaders was the first video game with endless gameplay and the first fixed shooter, setting the template for the genre. The goal is to defeat waves of descending aliens with a horizontally moving laser cannon to earn as many points as possible.', 'https://media.retroachievements.org/Images/078387.png', 'https://media.retroachievements.org/Images/078384.png', 'https://media.retroachievements.org/Images/078385.png', 'https://media.retroachievements.org/Images/078386.png', 4.1),
  (142, 4190, 'Driver: You Are The Wheelman', 'Game Boy Color', 6, 204, 204, 204, 41, 0, 'Action, Arcade Racing', 'Crawfish Interactive', 'Infogrames', '2000-05-16', 'Driver is an action driving video game and the first installment in the Driver series. Developed by Reflections Interactive and published by GT Interactive, it was released on the PlayStation on 25 June 1999, and was ported to Microsoft Windows on 1 October 1999, and to Classic Mac OS on 12 December 2000 by Abersoft Limited.', 'https://media.retroachievements.org/Images/103085.png', 'https://media.retroachievements.org/Images/102603.png', 'https://media.retroachievements.org/Images/102601.png', 'https://media.retroachievements.org/Images/102600.png', 4.1),
  (143, 25708, '~Homebrew~ Feed IT Souls', 'Game Boy Color', 6, 202, 202, 202, 20, 0, '2D Platforming', 'Gumpy Function', 'itch.io', '2023-09-11', 'Kobe Bean Bryant was an American professional basketball player. A shooting guard, he spent his entire 20-year career with the Los Angeles Lakers in the National Basketball Association (NBA). Widely regarded as one of the greatest and most influential players in the sport''s history, Bryant won five NBA championships and was an 18-time All-Star, four-time All-Star MVP, 15-time member of the All-NBA Team, 12-time member of the All-Defensive Team, the 2008 NBA Most Valuable Player (MVP), two-time NBA Finals MVP, and two-time scoring champion. He ranks fourth in league all-time regular season and postseason scoring. Bryant was posthumously named to the NBA 75th Anniversary Team in 2021 and was a two-time inductee to the Naismith Memorial Basketball Hall of Fame, as a player in 2020 and as a member of the 2008 U.S. Olympic team in 2025.', 'https://media.retroachievements.org/Images/082360.png', 'https://media.retroachievements.org/Images/085169.png', 'https://media.retroachievements.org/Images/082358.png', 'https://media.retroachievements.org/Images/082359.png', 4.1),
  (144, 11206, 'Barbie: Pet Rescue', 'Game Boy Color', 6, 202, 202, 202, 22, 0, NULL, 'HotGen Studios', NULL, '2001-09-01', 'Barbie, a fashion doll manufactured by American toy and entertainment company Mattel, has starred in numerous video games on PC, various console systems, IOS, and Android. Some games are adaptations of Barbie films or TV series, while others feature original storylines and concepts.', 'https://media.retroachievements.org/Images/120984.png', 'https://media.retroachievements.org/Images/076154.png', 'https://media.retroachievements.org/Images/076152.png', 'https://media.retroachievements.org/Images/076153.png', 4.1),
  (145, 13091, 'Ballistic', 'Game Boy Color', 6, 198, 198, 198, 15, 0, NULL, 'Mitchell', 'Infogrames', '1999-01-01', 'Puzz Loop is an arcade tile-matching puzzle game developed by Mitchell Corporation and released in 1998 in Japan and North America and 1999 in Europe. It was later ported to the Game Boy Color, PlayStation and Samsung Nuon DVD players under the name Ballistic. The original Puzz Loop game was also known by this title. In 2008, publisher Hudson Soft released the game on App Store for the iPhone and iPod Touch. There was a Neo Geo Pocket Color version of the game initially planned to be published by SNK, but cancelled due to bankruptcy of the original incarnation of the company.', 'https://media.retroachievements.org/Images/110176.png', 'https://media.retroachievements.org/Images/019453.png', 'https://media.retroachievements.org/Images/110174.png', 'https://media.retroachievements.org/Images/110175.png', 4.1),
  (146, 6169, 'Pop ''n Music GB: Animation Melody', 'Game Boy Color', 6, 198, 198, 198, 96, 0, 'Rhythm', 'Konami', 'Konami', '2000-07-09', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/072267.png', 'https://media.retroachievements.org/Images/005083.png', 'https://media.retroachievements.org/Images/005082.png', 'https://media.retroachievements.org/Images/009531.png', 4.1),
  (147, 7708, 'Legend of the River King 2', 'Game Boy Color', 6, 197, 197, 197, 76, 0, 'Sports - Fishing', 'Marvelous Interactive', 'Natsume', '2001-04-17', 'River King or Harvest Fishing (PAL), and originally released in English as Legend of the River King, is a fishing-themed role playing video game series by Marvelous. The series has releases over 6 video game systems. Of these, 4 have been released in America.', 'https://media.retroachievements.org/Images/081097.png', 'https://media.retroachievements.org/Images/008019.png', 'https://media.retroachievements.org/Images/008018.png', 'https://media.retroachievements.org/Images/008020.png', 4.1),
  (148, 7304, 'Magical Tetris Challenge', 'Game Boy Color', 6, 195, 195, 195, 18, 0, NULL, 'Capcom', 'Capcom', '1999-11-12', 'Magical Tetris Challenge is a 1998 puzzle video game developed and published by Capcom for arcades. It was ported to the Nintendo 64, Game Boy Color and PlayStation. It is a version of Tetris featuring Disney characters. It is one of the few Nintendo 64 games to be entirely in 2D, in addition to being Capcom''s first game for the console. The Japanese arcade cabinet and cover art was done by Kenichi Sudo, while the North American cover art was done by Robert Griggs.', 'https://media.retroachievements.org/Images/041043.png', 'https://media.retroachievements.org/Images/007185.png', 'https://media.retroachievements.org/Images/007183.png', 'https://media.retroachievements.org/Images/007184.png', 4.1),
  (149, 6337, 'Robopon: Sun Version', 'Game Boy Color', 6, 193, 193, 193, 22, 0, 'Turn-Based RPG', 'Hudson Soft, Red', 'Hudson Soft, Atlus', '1998-12-04', 'Robopon Sun, Star and Moon Versions are handheld role-playing video games for Nintendo''s Game Boy Color. Of the three games, only Sun was released in North America in December 2000 by Atlus, while their original Japan releases were by Hudson Soft. The games focus on a boy, named Cody by default, and his adventures on his island with his robotic friends. They mostly resemble the Pokémon series of video games, but also bear similarities to the Super Nintendo Entertainment System game Robotrek, published by Enix.', 'https://media.retroachievements.org/Images/033790.png', 'https://media.retroachievements.org/Images/023929.png', 'https://media.retroachievements.org/Images/023920.png', 'https://media.retroachievements.org/Images/023921.png', 4.1),
  (150, 22353, '~Homebrew~ Hime''s Quest', 'Game Boy Color', 6, 192, 192, 192, 35, 0, 'Action-Adventure', 'Poppy Works', 'Crunchyroll | Limited Run Games', '2023-01-25', 'The Game Boy portable system has a library of games, which were released in plastic ROM cartridges. The Game Boy first launched in Japan on April 21, 1989, with Super Mario Land, Alleyway, Baseball, and Yakuman. For the North American launches, Tetris and Tennis were also featured, while Yakuman was never released outside of Japan. The last games to be published for the system were the Japan-only titles Shikakui Atama o Maruku Suru: Kanji no Tatsujin and Shikakui Atama o Maruku Suru: Keisan no Tatsujin, both released on March 30, 2001.', 'https://media.retroachievements.org/Images/068576.png', 'https://media.retroachievements.org/Images/068583.png', 'https://media.retroachievements.org/Images/068571.png', 'https://media.retroachievements.org/Images/068572.png', 4.1),
  (151, 4058, 'Looney Tunes: Twouble!', 'Game Boy Color', 6, 192, 192, 192, 26, 0, '2.5D Platforming, Puzzle', 'Bit Managers', 'Infogrames', '1998-12-01', 'Sylvester & Tweety: Breakfast on the Run, known as Looney Tunes: Twouble! in North America, is a 2D and isometric, pseudo-3D platform video game developed by Bit Managers and published by Infogrames for the Game Boy Color in 1998. It features the Looney Tunes characters Sylvester and Tweety. Other Looney Tunes include Bugs Bunny, Daffy Duck, Granny, Hector the Bulldog, Taz, Pepé Le Pew and Marvin the Martian.', 'https://media.retroachievements.org/Images/061702.png', 'https://media.retroachievements.org/Images/059604.png', 'https://media.retroachievements.org/Images/059603.png', 'https://media.retroachievements.org/Images/059602.png', 4.1),
  (152, 30882, '~Homebrew~ Little Dungeon Renovator', 'Game Boy Color', 6, 190, 190, 190, 10, 0, NULL, 'MashinN', 'MashinN', '2023-09-14', 'Tegel Manor is a 1977 fantasy role-playing game adventure published by Judges Guild.', 'https://media.retroachievements.org/Images/111692.png', 'https://media.retroachievements.org/Images/103841.png', 'https://media.retroachievements.org/Images/111677.png', 'https://media.retroachievements.org/Images/111678.png', 4.1),
  (153, 17975, 'Das Geheimnis der Happy Hippo-Insel', 'Game Boy Color', 6, 190, 190, 190, 12, 0, '2D Platforming', 'KRITZELKRATZ 3000', 'Infogrames', '2001-05-17', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/048559.png', 'https://media.retroachievements.org/Images/048557.png', 'https://media.retroachievements.org/Images/048556.png', 'https://media.retroachievements.org/Images/048560.png', 4.1),
  (154, 7450, 'Return of the Ninja', 'Game Boy Color', 6, 189, 189, 189, 15, 0, '2D Platforming', 'Natsume', 'Natsume', '2001-03-30', 'Return of the Ninja is a platform game with stealth elements developed by Act Japan and published by Natsume Inc. for the Game Boy Color in 2001 as a spiritual successor to 1990''s Shadow of the Ninja.', 'https://media.retroachievements.org/Images/089679.png', 'https://media.retroachievements.org/Images/033010.png', 'https://media.retroachievements.org/Images/089804.png', 'https://media.retroachievements.org/Images/033011.png', 4.1),
  (155, 22849, '~Hack~ The Legend of Zelda: Archipelago', 'Game Boy Color', 6, 184, 184, 184, 14, 0, NULL, 'Nobody', 'Hack - The Legend of Zelda: Oracle of Ages', '2020-06-05', 'The Legend of Zelda is a video game franchise created by video game designers Shigeru Miyamoto and Takashi Tezuka and mainly developed and published by Nintendo. The universe of the Legend of Zelda series consists of various lands, the most predominant being Hyrule. The franchise is set within a fantasy world reminiscent of medieval Europe which consists of several recurring locations, races and creatures. The world was also partially inspired by Miyamoto and designer Hidemaro Fujibayashi''s home town, Kyoto. The most prominent race in the series are the Hylians, a humanoid race with elfin features identifiable by their long, pointed ears. The series'' lore contains a creation myth, several fictional alphabets, the most prominent being Hylian, and a fictional almost-universal currency, the rupee. The games involve the protagonists Link and Princess Zelda battling monsters to save the various lands they are in, and defeat a villain, which is often the series'' main antagonist, Ganon. Link is usually the main player character in these settings, but players primarily play as Zelda in 2024''s Echoes of Wisdom. Nintendo developed the series'' lore into a timeline that spans thousands of years across its history.', 'https://media.retroachievements.org/Images/069603.png', 'https://media.retroachievements.org/Images/069618.png', 'https://media.retroachievements.org/Images/069616.png', 'https://media.retroachievements.org/Images/069617.png', 4.1),
  (156, 9269, '~Hack~ Pokémon Kalos Crystal', 'Game Boy Color', 6, 181, 181, 181, 81, 0, 'Turn-Based RPG', 'Azure Keys', 'Hack - Pokemon Crystal Version', '2018-01-01', 'Pokémon is a series of role-playing video games developed by Game Freak and published by Nintendo and The Pokémon Company. Over the years, a number of spin-off games based on the series have also been developed by multiple companies. While the main series consists of RPGs, spin-off games encompass other genres, such as action role-playing, puzzle, fighting, and digital pet games. Most Pokémon video games have been developed exclusively for Nintendo handheld and home consoles, dating from the Game Boy to the Nintendo Switch 2.', 'https://media.retroachievements.org/Images/091204.png', 'https://media.retroachievements.org/Images/059364.png', 'https://media.retroachievements.org/Images/058913.png', 'https://media.retroachievements.org/Images/058914.png', 4.1),
  (157, 6009, 'Barbie: Fashion Pack Games', 'Game Boy Color', 6, 181, 181, 181, 8, 0, 'Minigames', 'Hyperspace Cowgirls', 'Mattel', '2000-08-15', 'Barbie, a fashion doll manufactured by American toy and entertainment company Mattel, has starred in numerous video games on PC, various console systems, IOS, and Android. Some games are adaptations of Barbie films or TV series, while others feature original storylines and concepts.', 'https://media.retroachievements.org/Images/118235.png', 'https://media.retroachievements.org/Images/118233.png', 'https://media.retroachievements.org/Images/118232.png', 'https://media.retroachievements.org/Images/118231.png', 4.1),
  (158, 2499, 'Noddy and the Birthday Party', 'Game Boy Color', 6, 180, 180, 180, 20, 0, '2D Platforming, Educational', 'Tiertex Design Studios', 'BBC Multimedia', '2000-12-30', 'Noddy and the Birthday Party is a children''s video game released only in Europe for the Game Boy Color in 2000. It was developed by Tiertex Design Studios and published by BBC Multimedia. The game is based on the character Noddy by Enid Blyton, as well as the fictional universe in which he resides. The focus of the plot and gameplay is the preparation of the character Big-Ears'' upcoming birthday party. The game received mixed to negative reviews from critics.', 'https://media.retroachievements.org/Images/075532.png', 'https://media.retroachievements.org/Images/072481.png', 'https://media.retroachievements.org/Images/055397.png', 'https://media.retroachievements.org/Images/055393.png', 4.1),
  (159, 13053, 'Monopoly', 'Game Boy Color', 6, 179, 179, 179, 35, 0, 'Board Game', 'Sculptured Software | Iguana West', 'Majesco Entertainment', '1998-12-11', 'A monopoly is a market in which one person or company is the only supplier of a particular good or service. A monopoly is characterized by a lack of economic competition to produce a particular thing, a lack of viable substitute goods, and the possibility of a high monopoly price well above the seller''s marginal cost that leads to a high monopoly profit. The verb monopolise or monopolize refers to the process by which a company gains the ability to raise prices or exclude competitors. In economics, a monopoly is a single seller. In law, a monopoly is a business entity that has significant market power, that is, the power to charge overly high prices, which is associated with unfair price raises. Although monopolies may be big businesses, size is not a characteristic of a monopoly. A small business may still have the power to raise prices in a small industry.', 'https://media.retroachievements.org/Images/060627.png', 'https://media.retroachievements.org/Images/060037.png', 'https://media.retroachievements.org/Images/060035.png', 'https://media.retroachievements.org/Images/060038.png', 4.1),
  (160, 31955, '~Homebrew~ ~Demo~ The New Adventures of Sonic the Hedgehog', 'Game Boy Color', 6, 177, 177, 177, 16, 0, '2D Platforming', 'Oasys', 'Oasys', '2024-08-13', 'Disney''s Aladdin is a 1993 side-scrolling platformer video game developed by Virgin Games and published by Sega for the Sega Genesis. The game is based on the 1992 Walt Disney Animation Studios film of the same name, and features the titular Aladdin navigating settings and scenarios from the film.', 'https://media.retroachievements.org/Images/110539.png', 'https://media.retroachievements.org/Images/110478.png', 'https://media.retroachievements.org/Images/110476.png', 'https://media.retroachievements.org/Images/110477.png', 4.1),
  (161, 4940, 'Xtreme Sports', 'Game Boy Color', 6, 176, 176, 176, 36, 0, 'Extreme Sports', 'WayForward', 'Infogrames', '2000-06-28', 'X-Treme Sports was a Canadian English language category 2 television channel owned by Canwest Media Inc., a division of Canwest Global Communications. X-Treme Sports aired a variety of programming primarily related to extreme sports.', 'https://media.retroachievements.org/Images/060938.png', 'https://media.retroachievements.org/Images/095587.png', 'https://media.retroachievements.org/Images/095500.png', 'https://media.retroachievements.org/Images/095499.png', 4.1),
  (162, 8402, 'Toy Story 2', 'Game Boy Color', 6, 175, 175, 175, 46, 0, '2D Platforming', 'Tiertex Design Studios', 'THQ', '1999-11-01', 'Toy Story 2 is a 1999 American animated adventure comedy film produced by Pixar Animation Studios for Walt Disney Pictures. It is the second installment in Pixar''s Toy Story franchise and the sequel to the original 1995 film. The film was directed by John Lasseter from a screenplay by Andrew Stanton, Rita Hsiao, Doug Chamberlin, and Chris Webb. Tom Hanks, Tim Allen, Don Rickles, Jim Varney, Wallace Shawn, John Ratzenberger, Annie Potts, R. Lee Ermey, John Morris, Laurie Metcalf and Jeff Pidgeon reprise their roles from the first Toy Story film, with newcomers Joan Cusack, Kelsey Grammer, Wayne Knight, Estelle Harris, and Jodi Benson joining the cast. In the film, Woody is stolen by a greedy toy collector, prompting Buzz Lightyear and his friends to save him, but Woody is then tempted by the idea of immortality in a museum.', 'https://media.retroachievements.org/Images/054343.png', 'https://media.retroachievements.org/Images/050870.png', 'https://media.retroachievements.org/Images/050855.png', 'https://media.retroachievements.org/Images/050856.png', 4.1),
  (163, 20371, '~Homebrew~ Super Jacked Up Tomato Face Johnson', 'Game Boy Color', 6, 174, 174, 174, 14, 0, '2D Platforming', 'Gumpy Function', 'Gumpy Function', '2022-05-29', 'The Mummy is a 1999 American action-adventure film written and directed by Stephen Sommers, starring Brendan Fraser, Rachel Weisz, John Hannah, and Arnold Vosloo as the reanimated mummy. It is a loose remake of the 1932 film. The Mummy follows adventurer and treasure hunter Rick O''Connell as he travels to Hamunaptra, the City of the Dead, with librarian Evelyn Carnahan and her older brother Jonathan, where they accidentally awaken Imhotep, a cursed high priest with supernatural powers.', 'https://media.retroachievements.org/Images/061190.png', 'https://media.retroachievements.org/Images/061235.png', 'https://media.retroachievements.org/Images/061191.png', 'https://media.retroachievements.org/Images/061192.png', 4.1),
  (164, 14123, 'Yu-Gi-Oh! Duel Monsters II: Dark Duel Stories', 'Game Boy Color', 6, 174, 174, 174, 68, 0, 'Collectible Card Game', 'Konami', 'Konami', '1999-07-08', '   The following is a list of video games developed and published by Konami, based on Kazuki Takahashi''s Yu-Gi-Oh! manga and anime franchise, along with its spin-off series. With some exceptions, the majority of the games follow the card battle gameplay of the real-life Yu-Gi-Oh! Trading Card Game. There are 59 in total.', 'https://media.retroachievements.org/Images/092435.png', 'https://media.retroachievements.org/Images/024082.png', 'https://media.retroachievements.org/Images/024080.png', 'https://media.retroachievements.org/Images/024081.png', 4.1),
  (165, 3671, 'Pooh and Tigger''s Hunny Safari', 'Game Boy Color', 6, 172, 172, 172, 32, 0, '2D Platforming', 'Digital Eclipse', 'Electronic Arts, Ubisoft', '2001-12-01', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/067800.png', 'https://media.retroachievements.org/Images/067803.png', 'https://media.retroachievements.org/Images/067801.png', 'https://media.retroachievements.org/Images/067802.png', 4.1),
  (166, 4526, 'Beatmania GB: GotchaMix 2', 'Game Boy Color', 6, 171, 171, 171, 133, 0, 'Rhythm', 'Konami', 'Konami', '2000-09-28', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/122217.png', 'https://media.retroachievements.org/Images/060849.png', 'https://media.retroachievements.org/Images/060847.png', 'https://media.retroachievements.org/Images/060848.png', 4.1),
  (167, 6556, 'Woody Woodpecker: Escape from Buzz Buzzard Park', 'Game Boy Color', 6, 171, 171, 171, 40, 0, '2D Platforming', 'Planet Interactive', 'Cryo Interactive, DreamCatcher Interactive', '2001-06-07', 'Woody Woodpecker: Escape from Buzz Buzzard Park is a set of two video games based on the animated series The New Woody Woodpecker Show. One is for PlayStation 2 and Windows, and the other is for the Game Boy Color.', 'https://media.retroachievements.org/Images/060180.png', 'https://media.retroachievements.org/Images/118857.png', 'https://media.retroachievements.org/Images/124114.png', 'https://media.retroachievements.org/Images/124115.png', 4.1),
  (168, 6251, '~Hack~ The Legend of Zelda: Hard Awakening DX', 'Game Boy Color', 6, 168, 168, 168, 15, 0, 'Action-Adventure', 'Jeville', 'Hack - The Legend of Zelda: Link''s Awakening', '2013-04-05', 'The Legend of Zelda: Link''s Awakening is a 1993 action-adventure game developed and published by Nintendo for the Game Boy. It is the first installment in The Legend of Zelda series to be released on a handheld game console. Link''s Awakening is one of the few Zelda games not to take place in the land of Hyrule, and it does not feature Princess Zelda or the Triforce relic. Instead, the protagonist Link begins the game stranded on Koholint Island, a place guarded by a whale-like deity called the Wind Fish. Assuming the role of Link, the player fights monsters and solves puzzles while searching for eight musical instruments that will awaken the sleeping Wind Fish and allow him to escape from the island.', 'https://media.retroachievements.org/Images/025126.png', 'https://media.retroachievements.org/Images/042279.png', 'https://media.retroachievements.org/Images/005509.png', 'https://media.retroachievements.org/Images/005510.png', 4.1),
  (169, 11165, 'Bugs Bunny and Lola Bunny: Operation Carrot Patch', 'Game Boy Color', 6, 165, 165, 165, 18, 0, '2D Platforming', 'Velez & Dubail Dev. Team', 'Infogrames', '1999-01-01', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/015109.png', 'https://media.retroachievements.org/Images/015108.png', 'https://media.retroachievements.org/Images/015106.png', 'https://media.retroachievements.org/Images/015107.png', 4.1),
  (170, 8539, '~Unlicensed~ Donkey Kong 5: The Journey of Over Time and Space', 'Game Boy Color', 6, 162, 162, 162, 42, 0, NULL, 'Sintax', 'BBD', '2001-01-01', 'Disney''s Aladdin is a 1993 side-scrolling platformer video game developed by Virgin Games and published by Sega for the Sega Genesis. The game is based on the 1992 Walt Disney Animation Studios film of the same name, and features the titular Aladdin navigating settings and scenarios from the film.', 'https://media.retroachievements.org/Images/047608.png', 'https://media.retroachievements.org/Images/008599.png', 'https://media.retroachievements.org/Images/008600.png', 'https://media.retroachievements.org/Images/042561.png', 4.1),
  (171, 30128, '~Homebrew~ Enceladus', 'Game Boy Color', 6, 161, 161, 161, 7, 0, '2D Platforming', 'Marco Windrich, Dominik Zimmer', 'Marco Windrich, Dominik Zimmer', '2023-09-12', 'Enceladus is the sixth-largest moon of Saturn and the 18th largest in the Solar System. It is about 500 kilometres in diameter, about a tenth of that of Saturn''s largest moon, Titan. It is covered by clean, freshly deposited snow hundreds of meters thick, making it one of the most reflective bodies of the Solar System. Consequently, its surface temperature at noon reaches only −198 °C, far colder than a light-absorbing body would be. Despite its small size, Enceladus has a wide variety of surface features, ranging from old, heavily cratered regions to young, tectonically deformed terrain.', 'https://media.retroachievements.org/Images/112090.png', 'https://media.retroachievements.org/Images/099114.png', 'https://media.retroachievements.org/Images/099111.png', 'https://media.retroachievements.org/Images/099112.png', 4.1),
  (172, 32799, 'Deer Hunter', 'Game Boy Color', 6, 161, 161, 161, 13, 0, 'Sports - Hunting', 'Morning Star Multimedia', 'Vatical Entertainment', '1999-12-22', 'Deer Hunter is a series of hunting simulation video games. Originally available for Windows platform published by WizardWorks, it has since been published on MacOS, Game Boy Color, PlayStation 2, and mobile phones. The first Deer Hunter game was an early success in the casual game market.', 'https://media.retroachievements.org/Images/112401.png', 'https://media.retroachievements.org/Images/112400.png', 'https://media.retroachievements.org/Images/106262.png', 'https://media.retroachievements.org/Images/124984.png', 4.1),
  (173, 29047, '~Homebrew~ Hollow Knight Silksong', 'Game Boy Color', 6, 160, 160, 160, 16, 0, 'Metroidvania', 'Elvies', 'Elvies', '2021-07-28', 'Hollow Knight: Silksong is a 2025 Metroidvania game developed and published by Australian independent developer Team Cherry. The sequel to Hollow Knight (2017), it was released on 4 September 2025 for Linux, macOS, Nintendo Switch, Nintendo Switch 2, PlayStation 4, PlayStation 5, Windows, Xbox One, and Xbox Series X/S.', 'https://media.retroachievements.org/Images/111197.png', 'https://media.retroachievements.org/Images/119810.png', 'https://media.retroachievements.org/Images/093103.png', 'https://media.retroachievements.org/Images/093102.png', 4.1),
  (174, 22650, '~Homebrew~ Repugnant Bounty', 'Game Boy Color', 6, 160, 160, 160, 30, 0, 'Metroidvania', 'Starlab', 'Starlab', '2022-12-23', 'Jonah Woodson Hex is a fictional antihero appearing in American comic books published by DC Comics. The character was created by writer John Albano and artist Tony DeZuniga. Hex is a surly and cynical bounty hunter whose face is scarred on the right side. Despite his poor reputation and personality, Hex is bound by a personal code of honor to protect and avenge the innocent.', 'https://media.retroachievements.org/Images/070057.png', 'https://media.retroachievements.org/Images/070058.png', 'https://media.retroachievements.org/Images/069557.png', 'https://media.retroachievements.org/Images/070024.png', 4.1),
  (175, 18811, '~Homebrew~ Go Catch ''Em', 'Game Boy Color', 6, 158, 158, 158, 29, 0, 'Action', 'Health Potion Studios', 'Health Potion Studios', '2022-02-25', 'Xena: Warrior Princess is a hack and slash video game developed by Universal Studios Digital Arts and co-published by Electronic Arts and Universal Interactive Studios for the PlayStation in 1999. A Game Boy Color version was developed and published by Titus Interactive in 2001. Each version is based on the television series of the same name, which aired from 1995 to 2001.', 'https://media.retroachievements.org/Images/113263.png', 'https://media.retroachievements.org/Images/113257.png', 'https://media.retroachievements.org/Images/113259.png', 'https://media.retroachievements.org/Images/113258.png', 4.1),
  (176, 33660, '~Homebrew~ Oshinui Tune', 'Game Boy Color', 6, 157, 157, 157, 14, 0, 'Shoot ''em Up', 'megamittz', 'megamittz', '2025-05-07', NULL, 'https://media.retroachievements.org/Images/112810.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/112779.png', 'https://media.retroachievements.org/Images/112778.png', 4.1),
  (177, 8461, 'Spider-Man 2: The Sinister Six', 'Game Boy Color', 6, 153, 153, 153, 19, 0, 'Action, 2D Platforming', 'Torus Games', 'Activision', '2001-05-30', 'Spider-Man 2: The Sinister Six is a 2001 platform video game based on the Marvel Comics character Spider-Man. It was developed by Torus Games and published by Activision for the Game Boy Color. It was released on May 18, 2001, and is a sequel to Spider-Man (2000).', 'https://media.retroachievements.org/Images/067970.png', 'https://media.retroachievements.org/Images/015539.png', 'https://media.retroachievements.org/Images/067540.png', 'https://media.retroachievements.org/Images/015538.png', 4.1),
  (178, 30985, 'Sylvanian Melodies: Mori no Nakama to Odori Masho!', 'Game Boy Color', 6, 147, 147, 147, 31, 0, NULL, NULL, 'Epoch', '2000-03-17', 'Sylvanian Families  is a line of collectible anthropomorphic animal figurines made of flocked plastic. They were created by the Japanese gaming company Epoch in 1985 and distributed worldwide by a number of companies.', 'https://media.retroachievements.org/Images/102834.png', 'https://media.retroachievements.org/Images/102779.png', 'https://media.retroachievements.org/Images/102786.png', 'https://media.retroachievements.org/Images/102787.png', 4.1),
  (179, 6104, 'Towers: Lord Baniff''s Deceit', 'Game Boy Color', 6, 147, 147, 147, 41, 0, 'CRPG, Dungeon Crawl', 'JV Enterprises', 'Telegames, Vatical Entertainment', '1999-01-01', 'Towers: Lord Baniff''s Deceit is a first-person role-playing video game originally developed and published by JV Enterprises for the Atari ST in 1993. It is the first entry in the Towers series. In the game, players assume the role of adventurers tasked with finding Lord Baniff in his Tower, who has not been heard from by the people of Lamini. The title was later ported to both MS-DOS and Game Boy Color, each featuring various differences compared to the original release. It was met with mixed reception from critics across all platforms. A sequel, Towers II: Plight of the Stargazer, was released in 1995 for the Atari Falcon.', 'https://media.retroachievements.org/Images/057679.png', 'https://media.retroachievements.org/Images/057680.png', 'https://media.retroachievements.org/Images/057677.png', 'https://media.retroachievements.org/Images/057678.png', 4.1),
  (180, 7210, 'Star Wars - Episode I: Racer', 'Game Boy Color', 6, 144, 144, 144, 27, 0, 'Arcade Racing', 'LucasArts | Lucasfilm, Pax Softnica', 'Nintendo', '1999-12-01', 'Star Wars Episode I: Racer is a 1999 racing video game developed and published by LucasArts. It is based on the podracing sequence in the film Star Wars: Episode I – The Phantom Menace. The game features all of the racers and race course on Tatooine from The Phantom Menace. It adds several new courses, on Tatooine and various planets. The game has several single player modes, including a tournament mode. The format of multiplayer mode varies by platform. Jake Lloyd and Lewis MacLeod, who portrayed Anakin Skywalker and Sebulba in The Phantom Menace, reprise their film roles in the game.', 'https://media.retroachievements.org/Images/069456.png', 'https://media.retroachievements.org/Images/091362.png', 'https://media.retroachievements.org/Images/105149.png', 'https://media.retroachievements.org/Images/105150.png', 4.1),
  (181, 8337, 'Montezuma''s Return', 'Game Boy Color', 6, 139, 139, 139, 21, 0, '2D Platformer', 'Tarantula Studios', 'Take-Two Interactive', '1998-12-01', 'Montezuma''s Return! is a 1997 action/adventure video game and the sequel to the original Parker Brothers game Montezuma''s Revenge. While the original game was a 2D platform game, the sequel was a 3D first-person puzzle platformer. According to Steve Bergenholtz, the Utopia Technologies spokesperson, the musical score was written by a TV and film veteran. A port for Nintendo 64 was in the works but was cancelled.', 'https://media.retroachievements.org/Images/062143.png', 'https://media.retroachievements.org/Images/059745.png', 'https://media.retroachievements.org/Images/059747.png', 'https://media.retroachievements.org/Images/059748.png', 4.1),
  (182, 29775, '~Homebrew~ Wishing Sarah', 'Game Boy Color', 6, 137, 137, 137, 21, 0, 'Adventure', 'Asteristic Game Studio', 'Asteristic Game Studio', '2020-05-12', 'Donkey Kong is a video game series and media franchise created by the Japanese game designer Shigeru Miyamoto for Nintendo. It follows the adventures of Donkey Kong, a large, powerful gorilla, and other members of the Kong family of apes. Donkey Kong games include the original arcade game trilogy by Nintendo R&D1; the Donkey Kong Country series by Rare and Retro Studios; and the Mario vs. Donkey Kong series by Nintendo Software Technology. Various studios have developed spin-offs in genres such as edutainment, puzzle, racing, and rhythm. The franchise also incorporates animation, printed media, theme parks, and merchandise.', 'https://media.retroachievements.org/Images/096775.png', 'https://media.retroachievements.org/Images/096774.png', 'https://media.retroachievements.org/Images/096595.png', 'https://media.retroachievements.org/Images/096596.png', 4.1),
  (183, 28383, '~Homebrew~ Remote Control Shuriken', 'Game Boy Color', 6, 136, 136, 136, 6, 0, NULL, 'Health Potion Studios', 'itch.io', '2021-10-16', 'Ninja Crusaders is a side-scrolling action game released by Sammy Corporation for the Nintendo Entertainment System in 1990. The player takes control of one of two ninjas who are tasked at thwarting an alien invasion. The game has been compared to Tecmo''s Ninja Gaiden series.', 'https://media.retroachievements.org/Images/089036.png', 'https://media.retroachievements.org/Images/089083.png', 'https://media.retroachievements.org/Images/089034.png', 'https://media.retroachievements.org/Images/089035.png', 4),
  (184, 14039, 'Perfect Dark', 'Game Boy Color', 6, 134, 134, 134, 34, 0, 'Stealth, Third-Person Shooter', 'Rare', 'Rareware Limited', '2000-08-28', 'Perfect Dark is a 2000 first-person shooter game developed and published by Rare for the Nintendo 64. The first game of the Perfect Dark series, it follows Joanna Dark, an agent of the Carrington Institute research centre, as she attempts to stop an extraterrestrial conspiracy by rival corporation dataDyne. The game features a campaign mode where the player must complete a series of levels to progress through the story, as well as a range of multiplayer options, including a co-operative mode and traditional deathmatch settings with computer-controlled bots.', 'https://media.retroachievements.org/Images/115215.png', 'https://media.retroachievements.org/Images/089666.png', 'https://media.retroachievements.org/Images/091489.png', 'https://media.retroachievements.org/Images/093995.png', 4),
  (185, 15925, 'Loppi Puzzle Magazine: Kangaeru Puzzle Soukangou', 'Game Boy Color', 6, 133, 133, 133, 10, 0, NULL, 'Success, Game Studio', 'Success', '2001-08-01', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/052400.png', 'https://media.retroachievements.org/Images/052241.png', 'https://media.retroachievements.org/Images/052401.png', 'https://media.retroachievements.org/Images/052402.png', 4),
  (186, 6791, 'Gex 3: Deep Pocket Gecko', 'Game Boy Color', 6, 131, 131, 131, 24, 0, '2D Platforming', 'David A. Palmer Productions', 'Eidos Interactive', '1999-12-01', 'Gex 3: Deep Pocket Gecko is a 1999 platformer video game developed by David A. Palmer IMS Productions and published by Eidos Interactive for the Game Boy Color. It is part of the Gex of games, where the player controls a gecko named Gex through a series of television and film-themed 2D side-scrolling levels where he collects various items to progress through the game. In the game, Gex is trying to reach Agent Xtra who has been kidnapped and must reach his long-standing enemy Rez-Raker to do so.', 'https://media.retroachievements.org/Images/045851.png', 'https://media.retroachievements.org/Images/005982.png', 'https://media.retroachievements.org/Images/005983.png', 'https://media.retroachievements.org/Images/005994.png', 4),
  (187, 7666, 'Hot Wheels: Stunt Track Driver', 'Game Boy Color', 6, 131, 131, 131, 24, 0, 'Arcade Racing', 'Lucky Chicken Games', 'Mattel', '2000-01-01', 'Hot Wheels Stunt Track Driver is a racing video game developed by Semi Logic Entertainments and published by Mattel Media for Microsoft Windows. It is based on the Hot Wheels toy franchise, and was released on October 15, 1998. A Game Boy Color version, developed by Lucky Chicken Games, was released in 2000.', 'https://media.retroachievements.org/Images/025592.png', 'https://media.retroachievements.org/Images/025593.png', 'https://media.retroachievements.org/Images/025590.png', 'https://media.retroachievements.org/Images/025591.png', 4),
  (188, 3647, 'MIB: Men in Black - The Series', 'Game Boy Color', 6, 130, 130, 130, 15, 0, '2D Platforming', 'Tiertex Design Studios', 'Crave Entertainment', '1999-03-01', 'Men in Black: The Series is an action platform video game developed by Tiertex Design Studios and published by Crave Entertainment for the Game Boy Color (GBC) on December 14, 1998. The game is based on the animated television series of the same name, and was followed by a sequel titled Men in Black 2: The Series, released for the Game Boy Color in 2000.', 'https://media.retroachievements.org/Images/045912.png', 'https://media.retroachievements.org/Images/023360.png', 'https://media.retroachievements.org/Images/023361.png', 'https://media.retroachievements.org/Images/023363.png', 4),
  (189, 4302, 'The Fish Files', 'Game Boy Color', 6, 128, 128, 128, 33, 0, 'Point-and-Click Adventure', '7th Sense', 'Microids', '2001-11-29', 'The Fish Files is a 2001 adventure game developed by the Italian team 7th Sense and published by MC2-Microïds on the Game Boy Color.', 'https://media.retroachievements.org/Images/022751.png', 'https://media.retroachievements.org/Images/022752.png', 'https://media.retroachievements.org/Images/026384.png', 'https://media.retroachievements.org/Images/022750.png', 4),
  (190, 12864, 'Meitantei Conan: Kigantou Hihou Densetsu', 'Game Boy Color', 6, 127, 127, 127, 11, 0, NULL, NULL, NULL, '2000-05-31', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/073581.png', 'https://media.retroachievements.org/Images/017553.png', 'https://media.retroachievements.org/Images/017554.png', 'https://media.retroachievements.org/Images/019720.png', 4),
  (191, 28190, '~Homebrew~ The Mandalorian - Chapter 3: The Sin', 'Game Boy Color', 6, 122, 122, 122, 10, 0, 'Action', 'Eric C. Wilder', 'itch.io', '2021-01-01', '"Chapter 3: The Sin" is the third episode of the first season of the American streaming television series The Mandalorian. It was written by the series'' showrunner Jon Favreau and directed by Deborah Chow. The episode takes place in the Star Wars universe five years after the events of Return of the Jedi (1983). In the episode, the Mandalorian successfully delivers the Child to the Client. However, the Mandalorian feeling guilty of handing over the Child decides to rescue the latter. This causes the two to become fugitives from the Guild, forcing them to leave Nevarro and go into hiding.', 'https://media.retroachievements.org/Images/093505.png', 'https://media.retroachievements.org/Images/093499.png', 'https://media.retroachievements.org/Images/093503.png', 'https://media.retroachievements.org/Images/093504.png', 4),
  (192, 711, 'LEGO Stunt Rally', 'Game Boy Color', 6, 122, 122, 122, 20, 0, 'Arcade Racing', 'Graphic State', 'LEGO Interactive | LEGO Media', '2000-12-29', 'Lego Stunt Rally is a 2000 racing game themed around the Lego line of construction toys. The Windows version was developed by Intelligent Games and published by Lego Media.', 'https://media.retroachievements.org/Images/055741.png', 'https://media.retroachievements.org/Images/018080.png', 'https://media.retroachievements.org/Images/101085.png', 'https://media.retroachievements.org/Images/101086.png', 4),
  (193, 26179, '~Homebrew~ Octopus Stressus', 'Game Boy Color', 6, 121, 121, 121, 7, 0, NULL, 'allalonegamez', 'allalonegamez', '2023-04-23', NULL, 'https://media.retroachievements.org/Images/084169.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/084167.png', 'https://media.retroachievements.org/Images/084168.png', 4),
  (194, 17359, 'Atlantis: The Lost Empire', 'Game Boy Color', 6, 118, 118, 118, 27, 0, '2D Platforming', 'Eurocom', 'THQ', '2001-07-30', 'Atlantis: The Lost Empire is a 2001 American animated science fiction adventure film directed by Gary Trousdale and Kirk Wise, produced by Don Hahn, and written by Tab Murphy. Produced by Walt Disney Feature Animation, it stars Michael J. Fox, James Garner, Cree Summer, Don Novello, Phil Morris, Claudia Christian, Jacqueline Obradors, Florence Stanley, David Ogden Stiers, John Mahoney, Jim Varney, Corey Burton and Leonard Nimoy. Set in 1914, it follows young linguist Milo Thatch, who gains possession of a sacred book, which he believes will guide him and a crew of mercenaries to the lost city of Atlantis.', 'https://media.retroachievements.org/Images/043864.png', 'https://media.retroachievements.org/Images/041053.png', 'https://media.retroachievements.org/Images/041028.png', 'https://media.retroachievements.org/Images/041029.png', 4),
  (195, 4646, 'Mickey''s Speedway USA', 'Game Boy Color', 6, 118, 118, 118, 202, 0, 'Kart Racing', 'Rare', 'Nintendo', '2001-03-23', 'Mickey''s Speedway USA is a kart racing game developed by Rare and published by Nintendo for the Nintendo 64 and Game Boy Color. It is Rare and Nintendo''s second collaboration with Disney Interactive following Mickey''s Racing Adventure (1999), and features characters from the Mickey Mouse universe racing across the United States. The Nintendo 64 game released in November 2000 to mixed reception, while the Game Boy Color version followed in March 2001.', 'https://media.retroachievements.org/Images/112013.png', 'https://media.retroachievements.org/Images/022174.png', 'https://media.retroachievements.org/Images/022175.png', 'https://media.retroachievements.org/Images/022176.png', 4),
  (196, 5042, 'Monster Rancher Explorer', 'Game Boy Color', 6, 115, 115, 115, 31, 0, NULL, 'Tecmo', 'Koei | Tecmo', '2000-09-29', 'Monster Rancher Explorer is a 2000 puzzle game developed by Graphic Research and published by Tecmo for the Game Boy Color. It features the same gameplay elements as Solomon''s Key but includes Monster Rancher characters.', 'https://media.retroachievements.org/Images/064809.png', 'https://media.retroachievements.org/Images/002987.png', 'https://media.retroachievements.org/Images/040698.png', 'https://media.retroachievements.org/Images/002984.png', 4),
  (197, 4972, 'Revelations: The Demon Slayer', 'Game Boy Color', 6, 115, 115, 115, 31, 0, 'Turn-Based RPG', 'Access, Multimedia Intelligence Transfer', 'Atlus', '1999-03-19', 'Revelations : The Demon Slayer  is a role-playing video game developed by Access and Multimedia Intelligence Transfer, and published by Atlus, Index and Sega, initially released on Game Boy on December 25, 1992 in Japan under the name ‘''Megami Tensei Gaiden: Last Bible’''. It is the first color RPG for Game Boy Color released in North America.', 'https://media.retroachievements.org/Images/091552.png', 'https://media.retroachievements.org/Images/002677.png', 'https://media.retroachievements.org/Images/002678.png', 'https://media.retroachievements.org/Images/008334.png', 4),
  (198, 4301, 'Fix and Foxi - Episode 1: Lupo', 'Game Boy Color', 6, 110, 110, 110, 12, 0, '2D Platforming', 'Similis Software', 'Ravensburger', '2000-01-01', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/039490.png', 'https://media.retroachievements.org/Images/024035.png', 'https://media.retroachievements.org/Images/024033.png', 'https://media.retroachievements.org/Images/024034.png', 4),
  (199, 9169, 'Moomin''s Tale', 'Game Boy Color', 6, 108, 108, 108, 16, 0, NULL, 'Pixel', 'Sunsoft', '2000-09-30', 'The Moomins are the central characters in a series of novels, short stories, picture books, and a comic strip by the Finnish writer and illustrator Tove Jansson, originally published in Swedish by the Finnish publisher Schildts. They are a family of white, round fairy-tale characters with large snouts that make them resemble the hippopotamus. However, despite this resemblance, the Moomin family are trolls who live in a house in Moominvalley.', 'https://media.retroachievements.org/Images/069454.png', 'https://media.retroachievements.org/Images/101352.png', 'https://media.retroachievements.org/Images/120618.png', 'https://media.retroachievements.org/Images/120619.png', 4),
  (200, 15926, 'Loppi Puzzle Magazine: Kangaeru Puzzle Dai-2-gou', 'Game Boy Color', 6, 106, 106, 106, 10, 0, NULL, 'Success', 'Success', '2001-10-01', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/052239.png', 'https://media.retroachievements.org/Images/052240.png', 'https://media.retroachievements.org/Images/052404.png', 'https://media.retroachievements.org/Images/052403.png', 4);
INSERT INTO games (rank, id, title, consoleName, consoleId, totalPlayers, casualPlayers, hardcorePlayers, numAchievements, points, genre, developer, publisher, released, description, icon, boxArt, titleScreen, screenshot, rating) VALUES
  (1, 11750, 'Metal Slug: Super Vehicle-001', 'Arcade', 27, 13017, 13017, 13017, 32, 0, 'Run & Gun', 'Nazca', 'SNK', '1996-04-01', 'Metal Slug is a 1996 run and gun video game developed by Nazca Corporation and originally released by SNK for the Neo Geo MVS arcade system. Set in 2028, the game follows Peregrine Falcon Strike Force soldiers Marco Rossi and Tarma Roving as they seek to overthrow a coup d''état by the Rebel Army, led by Donald Morden.', 'https://media.retroachievements.org/Images/049652.png', 'https://media.retroachievements.org/Images/016022.png', 'https://media.retroachievements.org/Images/016020.png', 'https://media.retroachievements.org/Images/016021.png', 5),
  (2, 11763, 'Cadillacs and Dinosaurs', 'Arcade', 27, 8353, 8353, 8353, 44, 0, NULL, 'Capcom', 'Capcom', '1993-04-01', 'Cadillacs and Dinosaurs, released in Japan as Cadillacs Kyouryuu Shinseiki , is a 1993 side-scrolling beat ''em up arcade game by Capcom, based on the comic book series Xenozoic Tales. The game was produced as a tie-in to the short-lived Cadillacs and Dinosaurs animated series which was aired during the same year the game was released. A version for the Capcom Power System Changer was planned and previewed but never released.', 'https://media.retroachievements.org/Images/101998.png', 'https://media.retroachievements.org/Images/016000.png', 'https://media.retroachievements.org/Images/016008.png', 'https://media.retroachievements.org/Images/016006.png', 4.9),
  (3, 11795, 'Street Fighter III: 3rd Strike - Fight for the Future', 'Arcade', 27, 6307, 6307, 6307, 46, 0, '2D Fighting', 'Capcom', 'Capcom', '1999-05-01', 'Street Fighter III: 3rd Strike - Fight for the Future is a 1999 fighting game developed and published by Capcom for arcades. It is the second and final updated version of Street Fighter III, following Street Fighter III: 2nd Impact. Like its predecessors, it runs on the CP System III hardware.', 'https://media.retroachievements.org/Images/065554.png', 'https://media.retroachievements.org/Images/016038.png', 'https://media.retroachievements.org/Images/016036.png', 'https://media.retroachievements.org/Images/016037.png', 4.8),
  (4, 11770, 'Metal Slug X: Super Vehicle-001', 'Arcade', 27, 6129, 6129, 6129, 37, 0, 'Run & Gun', 'SNK', 'SNK', '1999-03-01', 'Metal Slug 2 is a run and gun arcade game developed by SNK. It was originally released in 1998 for the Neo-Geo MVS arcade platform as the sequel to the 1996 game Metal Slug. The original version of the game had extensive slowdown and performance issues, eventually leading SNK to release a modified version in 1999, titled Metal Slug X: Super Vehicle-001 (メタルスラッグX). It has been ported to the Neo Geo CD, PlayStation, Virtual Console, iOS and Android, and to the Wii, PlayStation Portable and PlayStation 2. The game added several new features to the gameplay of the original Metal Slug, such as new weapons, vehicles and the ability to transform the character. It received generally positive reviews and was followed by Metal Slug 3, released in 2000.', 'https://media.retroachievements.org/Images/049658.png', 'https://media.retroachievements.org/Images/015990.png', 'https://media.retroachievements.org/Images/015937.png', 'https://media.retroachievements.org/Images/015938.png', 4.8),
  (5, 11727, 'Final Fight', 'Arcade', 27, 5945, 5945, 5945, 49, 0, 'Beat ''em Up', 'Capcom', 'Capcom', '1989-12-01', 'Final Fight is a series of beat ''em up video games by Japanese publisher Capcom, which began with the arcade release of Final Fight in 1989. Set in the fictional Metro City, within the Street Fighter universe, the games focus on a group of heroic vigilantes who fight against the control and various threats of criminal gangs, primarily the Mad Gear Gang. The series has sold 3.2 million units worldwide as of June 30, 2023.', 'https://media.retroachievements.org/Images/106799.png', 'https://media.retroachievements.org/Images/016661.png', 'https://media.retroachievements.org/Images/016659.png', 'https://media.retroachievements.org/Images/062589.png', 4.8),
  (6, 11825, 'Metal Slug 2: Super Vehicle-001/II', 'Arcade', 27, 5786, 5786, 5786, 36, 0, 'Run & Gun', 'SNK', 'SNK', '1998-02-01', 'Metal Slug 2 is a run and gun arcade game developed by SNK. It was originally released in 1998 for the Neo-Geo MVS arcade platform as the sequel to the 1996 game Metal Slug. The original version of the game had extensive slowdown and performance issues, eventually leading SNK to release a modified version in 1999, titled Metal Slug X: Super Vehicle-001 (メタルスラッグX). It has been ported to the Neo Geo CD, PlayStation, Virtual Console, iOS and Android, and to the Wii, PlayStation Portable and PlayStation 2. The game added several new features to the gameplay of the original Metal Slug, such as new weapons, vehicles and the ability to transform the character. It received generally positive reviews and was followed by Metal Slug 3, released in 2000.', 'https://media.retroachievements.org/Images/086571.png', 'https://media.retroachievements.org/Images/016064.png', 'https://media.retroachievements.org/Images/016062.png', 'https://media.retroachievements.org/Images/016063.png', 4.7),
  (7, 11726, 'Captain Commando', 'Arcade', 27, 4501, 4501, 4501, 54, 0, 'Beat ''em Up', 'Capcom', 'Capcom', '1991-11-01', 'Captain Commando is a 1991 beat ''em up game developed and published by Capcom for arcades. It was the seventeenth game produced for the company''s CP System hardware. The game stars the titular superhero, who was originally conceived as a fictional spokesman used by Capcom USA in the company''s console games during the late 1980s. The game was included in Capcom Beat ''Em Up Bundle compilation title, which was released digitally for Nintendo Switch, PlayStation 4, Xbox One, and Windows in September 2018.', 'https://media.retroachievements.org/Images/028296.png', 'https://media.retroachievements.org/Images/028254.png', 'https://media.retroachievements.org/Images/028256.png', 'https://media.retroachievements.org/Images/028257.png', 4.7),
  (8, 11787, 'The Punisher', 'Arcade', 27, 4387, 4387, 4387, 50, 0, 'Beat ''em Up', 'Capcom', 'Capcom', '1993-01-01', 'The Punisher is an antihero appearing in American comic books published by Marvel Comics. The character was created by writer Gerry Conway and artists John Romita Sr. and Ross Andru.', 'https://media.retroachievements.org/Images/016671.png', 'https://media.retroachievements.org/Images/016637.png', 'https://media.retroachievements.org/Images/016669.png', 'https://media.retroachievements.org/Images/016670.png', 4.7),
  (9, 11820, 'Alien vs. Predator', 'Arcade', 27, 4130, 4130, 4130, 48, 0, NULL, 'Capcom', 'Capcom', '1994-05-20', 'Alien vs. Predator is a science fiction action horror media franchise created by comic book writers Randy Stradley and Chris Warner. The series is a crossover between, and part of, the larger Alien and Predator franchises, depicting the two species — Xenomorph (Alien) and Yautja (Predator) — as being in conflict with one another.', 'https://media.retroachievements.org/Images/018851.png', 'https://media.retroachievements.org/Images/018884.png', 'https://media.retroachievements.org/Images/018883.png', 'https://media.retroachievements.org/Images/018882.png', 4.6),
  (10, 11943, 'Donkey Kong', 'Arcade', 27, 4063, 4063, 4063, 18, 0, '2D Platforming, Arcade', NULL, 'Nintendo', '1981-07-09', 'Donkey Kong is a video game series and media franchise created by the Japanese game designer Shigeru Miyamoto for Nintendo. It follows the adventures of Donkey Kong, a large, powerful gorilla, and other members of the Kong family of apes. Donkey Kong games include the original arcade game trilogy by Nintendo R&D1; the Donkey Kong Country series by Rare and Retro Studios; and the Mario vs. Donkey Kong series by Nintendo Software Technology. Various studios have developed spin-offs in genres such as edutainment, puzzle, racing, and rhythm. The franchise also incorporates animation, printed media, theme parks, and merchandise.', 'https://media.retroachievements.org/Images/122436.png', 'https://media.retroachievements.org/Images/036163.png', 'https://media.retroachievements.org/Images/036164.png', 'https://media.retroachievements.org/Images/036165.png', 4.6),
  (11, 11771, 'Metal Slug 3', 'Arcade', 27, 3763, 3763, 3763, 71, 0, 'Run & Gun', 'SNK', 'SNK', '2000-05-01', 'Metal Slug 3 is a run and gun video game developed by SNK. It was originally released in 2000 for the Neo-Geo MVS arcade platform as the sequel to Metal Slug 2/Metal Slug X. The music of the game was developed by Noise Factory.', 'https://media.retroachievements.org/Images/049654.png', 'https://media.retroachievements.org/Images/021974.png', 'https://media.retroachievements.org/Images/016013.png', 'https://media.retroachievements.org/Images/016012.png', 4.6),
  (12, 11757, 'The King of Fighters ''98: The Slugfest', 'Arcade', 27, 3633, 3633, 3633, 97, 0, '2D Fighting', 'SNK', 'SNK', '1998-07-01', 'The King of Fighters ''98 , subtitled Dream Match Never Ends in Japan or The Slugfest elsewhere, is a 1998 fighting game developed and published by SNK for the Neo Geo systems. It is the fifth game in The King of Fighters series and was advertised by SNK as a special edition of the series, as it features most of the characters who appeared in the previous games from KOF ''94 to ''97. The game provides no storyline in contrast to the previous games and instead is labelled as a dream match like its subtitle, where the player selects a team composed of three characters to participate in The King of Fighters tournament until reaching the boss Rugal Bernstein, even though the character dies in The King of Fighters ''95. Two fighting styles can be selected to fight and several characters have alternate versions to select with their classic moves from previous games.', 'https://media.retroachievements.org/Images/120961.png', 'https://media.retroachievements.org/Images/016426.png', 'https://media.retroachievements.org/Images/016411.png', 'https://media.retroachievements.org/Images/032666.png', 4.6),
  (13, 12026, 'Metal Slug 4', 'Arcade', 27, 3578, 3578, 3578, 65, 0, 'Run & Gun', 'Mega Enterprise', 'SNK', '2002-03-01', 'Metal Slug 4 is a run and gun arcade game for the Neo-Geo console/arcade platform, developed by Mega Enterprise along with Noise Factory and Playmore. It was released in 2002 for the Neo-Geo MVS arcade platform, and is the fourth game in the Metal Slug series. Two years later, Playmore published Metal Slug 4 for consoles.', 'https://media.retroachievements.org/Images/049656.png', 'https://media.retroachievements.org/Images/029460.png', 'https://media.retroachievements.org/Images/022089.png', 'https://media.retroachievements.org/Images/022090.png', 4.6),
  (14, 12192, 'Pac-Man', 'Arcade', 27, 3413, 3413, 3413, 21, 0, 'Maze Chase', 'Namco', 'Namco, Midway', '1980-05-22', 'Pac-Man, originally titled Puck Man in Japan, is a 1980 maze video game developed and published by Namco for arcades. It was released in Japan on May 22, 1980 and by Midway Manufacturing in North America in August 1980. The player controls Pac-Man, who must eat all the dots inside an enclosed maze while avoiding four colored ghosts. Eating large flashing dots called Power Pellets causes the ghosts to temporarily turn blue and vulnerable, allowing Pac-Man to eat the ghosts for bonus points.', 'https://media.retroachievements.org/Images/039726.png', 'https://media.retroachievements.org/Images/038818.png', 'https://media.retroachievements.org/Images/038815.png', 'https://media.retroachievements.org/Images/038816.png', 4.6),
  (15, 11975, 'Altered Beast', 'Arcade', 27, 3312, 3312, 3312, 25, 0, NULL, 'Sega', 'Sega', '1988-08-01', 'Altered Beast is a 1988 beat ''em up video game developed by Team Shinobi and published by Sega for arcades. Set in Ancient Greece, the game follows a Roman centurion who is resurrected by the Olympian god Zeus to rescue his daughter Athena from Neff, the demonic ruler of the underworld. By collecting three power-ups in a level, the player character can transform into one of five mythical beasts.', 'https://media.retroachievements.org/Images/040187.png', 'https://media.retroachievements.org/Images/027298.png', 'https://media.retroachievements.org/Images/027296.png', 'https://media.retroachievements.org/Images/027297.png', 4.6),
  (16, 11903, 'Ghouls ''n Ghosts', 'Arcade', 27, 3194, 3194, 3194, 55, 0, NULL, 'Capcom', 'Capcom', '1988-12-01', 'Ghouls ''n Ghosts, known as Dai Makaimura in Japan, is a 1988 platform game developed and published by Capcom for arcades. It is the sequel to 1985''s Ghosts ''n Goblins, and the second game in the Ghosts ''n Goblins series.', 'https://media.retroachievements.org/Images/119127.png', 'https://media.retroachievements.org/Images/032351.png', 'https://media.retroachievements.org/Images/032354.png', 'https://media.retroachievements.org/Images/032353.png', 4.6),
  (17, 14976, 'Mortal Kombat', 'Arcade', 27, 3026, 3026, 3026, 35, 0, '2D Fighting', 'Midway', 'Midway', '1992-10-08', 'Mortal Kombat is an American media franchise centered on a series of fighting video games originally developed by Midway Games in 1992.', 'https://media.retroachievements.org/Images/036812.png', 'https://media.retroachievements.org/Images/030937.png', 'https://media.retroachievements.org/Images/029345.png', 'https://media.retroachievements.org/Images/029346.png', 4.5),
  (18, 12211, 'Teenage Mutant Ninja Turtles: Turtles in Time', 'Arcade', 27, 2960, 2960, 2960, 31, 0, 'Beat ''em Up', 'Konami', 'Konami', '1991-03-01', 'Teenage Mutant Ninja Turtles (TMNT) is an American media franchise created by comic book artists Kevin Eastman and Peter Laird. It follows Leonardo, Donatello, Raphael and Michelangelo, four anthropomorphic turtle brothers trained in ninjutsu who fight evil in New York City. The franchise encompasses printed media, television series, feature films, video games, and merchandise.', 'https://media.retroachievements.org/Images/101616.png', 'https://media.retroachievements.org/Images/028706.png', 'https://media.retroachievements.org/Images/075426.png', 'https://media.retroachievements.org/Images/075427.png', 4.5),
  (19, 12154, 'Golden Axe', 'Arcade', 27, 2936, 2936, 2936, 32, 0, 'Beat ''em Up', 'Sega', 'Sega', '1989-01-01', 'Golden Axe  is a series of side-scrolling beat ''em up arcade video games developed by Sega. The series takes place in a medieval fantasy world where several heroes have the task of recovering the legendary Golden Axe, the mainstay element of the series.', 'https://media.retroachievements.org/Images/036853.png', 'https://media.retroachievements.org/Images/032938.png', 'https://media.retroachievements.org/Images/030228.png', 'https://media.retroachievements.org/Images/030232.png', 4.5),
  (20, 12210, 'Teenage Mutant Ninja Turtles', 'Arcade', 27, 2902, 2902, 2902, 29, 0, 'Beat ''em Up', 'Konami', 'Konami', '1989-11-15', 'Teenage Mutant Ninja Turtles (TMNT) is an American media franchise created by comic book artists Kevin Eastman and Peter Laird. It follows Leonardo, Donatello, Raphael and Michelangelo, four anthropomorphic turtle brothers trained in ninjutsu who fight evil in New York City. The franchise encompasses printed media, television series, feature films, video games, and merchandise.', 'https://media.retroachievements.org/Images/101615.png', 'https://media.retroachievements.org/Images/028202.png', 'https://media.retroachievements.org/Images/033249.png', 'https://media.retroachievements.org/Images/033227.png', 4.5),
  (21, 11806, 'Marvel vs. Capcom: Clash of Super Heroes', 'Arcade', 27, 2893, 2893, 2893, 92, 0, '2D Fighting', 'Capcom', 'Capcom', '1998-01-01', 'Marvel vs. Capcom: Clash of Super Heroes is a 1998 crossover fighting game developed and published by Capcom for the CP System II arcade system. It is the third installment in the Marvel vs. Capcom series, which features characters from Capcom''s video game franchises and characters from Marvel Comics. Unlike the series'' previous entry, Marvel Super Heroes vs. Street Fighter (1997), this sequel features characters from numerous Capcom video game franchises, rather than strictly Street Fighter characters. While the gameplay is largely identical to its predecessor, Clash of Super Heroes removes the traditional character assist system and introduces the Variable Cross attack.', 'https://media.retroachievements.org/Images/106812.png', 'https://media.retroachievements.org/Images/036230.png', 'https://media.retroachievements.org/Images/016016.png', 'https://media.retroachievements.org/Images/016017.png', 4.5),
  (22, 13796, 'Neo Turf Masters', 'Arcade', 27, 2875, 2875, 2875, 25, 0, 'Sports - Golf', 'Nazca', 'Nazca', '1996-01-01', 'Neo Turf Masters is a golf video game by Nazca for the Neo Geo, released in 1996. This is also one of the first two titles by Nazca before being acquired by SNK; the other series being the popular Metal Slug.', 'https://media.retroachievements.org/Images/029954.png', 'https://media.retroachievements.org/Images/029955.png', 'https://media.retroachievements.org/Images/022152.png', 'https://media.retroachievements.org/Images/022153.png', 4.5),
  (23, 11971, 'Aliens', 'Arcade', 27, 2844, 2844, 2844, 38, 0, NULL, 'Konami', 'Konami', '1990-03-01', 'Alien vs. Predator (エイリアンVSプレデター) is a 1994 beat ''em up video game developed and released by Capcom for the CPS-2 arcade game system. It is based on the science fiction franchise of the same name. Introducing an original fighter to the game: Lt. Kurosawa, the players take control of up to three from the selection of four cyborgs and Predator characters in a battle against the Xenomorph hordes and rogue human soldiers.', 'https://media.retroachievements.org/Images/059994.png', 'https://media.retroachievements.org/Images/019654.png', 'https://media.retroachievements.org/Images/019652.png', 'https://media.retroachievements.org/Images/019653.png', 4.5),
  (24, 12323, 'Neo Drift Out: New Technology', 'Arcade', 27, 2841, 2841, 2841, 25, 0, 'Arcade Racing', 'Visco', 'Visco', '1996-03-01', 'Neo Drift Out: New Technology is a 1996 rallying video game developed by Visco Corporation for the Neo Geo and Neo Geo CD. It is the fourth title in the Drift Out series. Though it follows Super Drift Out: World Rally Championships, it is closer to the earlier Drift Out ''94: The Hard Order.', 'https://media.retroachievements.org/Images/033493.png', 'https://media.retroachievements.org/Images/033494.png', 'https://media.retroachievements.org/Images/020918.png', 'https://media.retroachievements.org/Images/022149.png', 4.5),
  (25, 11800, 'Ms. Pac-Man', 'Arcade', 27, 2657, 2657, 2657, 27, 0, 'Maze Chase', 'General Computer Corporation, Midway', 'Midway', '1982-01-13', 'Ms. Pac-Man is a 1982 maze video game developed by General Computer Corporation (GCC) and published by Midway Manufacturing for arcades. It is a sequel to Pac-Man (1980), and the first entry in the series to not be made by Namco. Controlling the title character, Pac-Man''s wife, the player is tasked with eating all of the pellets in an enclosed maze while avoiding four colored ghosts. Eating the larger power pellets lets the player eat the ghosts, which turn blue and flee.', 'https://media.retroachievements.org/Images/058762.png', 'https://media.retroachievements.org/Images/051061.png', 'https://media.retroachievements.org/Images/051063.png', 'https://media.retroachievements.org/Images/051062.png', 4.5),
  (26, 11960, '1942', 'Arcade', 27, 2598, 2598, 2598, 27, 0, 'Shoot ''em Up', 'Capcom', 'Capcom', '1984-12-01', '1942 (MCMXLII) was a common year starting on Thursday of the Gregorian calendar, the 1942nd year of the Common Era (CE) and Anno Domini (AD) designations, the 942nd year of the 2nd millennium, the 42nd year of the 20th century, and the 3rd year of the 1940s decade.', 'https://media.retroachievements.org/Images/087811.png', 'https://media.retroachievements.org/Images/025220.png', 'https://media.retroachievements.org/Images/025244.png', 'https://media.retroachievements.org/Images/025245.png', 4.5),
  (27, 12027, 'Metal Slug 5', 'Arcade', 27, 2559, 2559, 2559, 39, 0, 'Run & Gun', 'SNK', 'SNK', '2003-11-01', 'Metal Slug 5 is a run and gun arcade game for the Neo-Geo, created by SNK Playmore. It was released in 2003 for the MVS arcade platform and is the fifth game in the Metal Slug series. The game was developed by Noise Factory/SNK Playmore, after Korean company Mega Enterprise had directed Metal Slug 4. It was the last Metal Slug released on the Neo Geo.', 'https://media.retroachievements.org/Images/049657.png', 'https://media.retroachievements.org/Images/016361.png', 'https://media.retroachievements.org/Images/016359.png', 'https://media.retroachievements.org/Images/016360.png', 4.5),
  (28, 12247, 'Puzzle Bobble (Neo Geo)', 'Arcade', 27, 2524, 2524, 2524, 14, 0, NULL, 'Taito', 'Taito', '1994-12-01', 'Puzzle Bobble, formerly known internationally as Bust-A-Move, is a 1994 tile-matching video game developed and published by Taito for arcades. It is based on the 1986 arcade game Bubble Bobble, featuring characters and themes from that game. Its characteristically cute Japanese animation and music, along with its play mechanics and level designs, made it successful as an arcade title and spawned several sequels and ports to home systems.', 'https://media.retroachievements.org/Images/077439.png', 'https://media.retroachievements.org/Images/016681.png', 'https://media.retroachievements.org/Images/016679.png', 'https://media.retroachievements.org/Images/016680.png', 4.5),
  (29, 11984, 'Astérix', 'Arcade', 27, 2504, 2504, 2504, 61, 0, 'Beat ''em Up', 'Konami', 'Konami', '1992-01-01', 'Asterix is a French comic album series about a Gaulish village which, thanks to a magic potion that enhances strength, resists the forces of Julius Caesar''s Roman Republic Army in the time after the Gallic Wars. Many adventures take the titular hero Asterix and his friend Obelix to Rome and beyond.', 'https://media.retroachievements.org/Images/111496.png', 'https://media.retroachievements.org/Images/026011.png', 'https://media.retroachievements.org/Images/026013.png', 'https://media.retroachievements.org/Images/026012.png', 4.5),
  (30, 11933, 'X-Men', 'Arcade', 27, 2469, 2469, 2469, 31, 0, 'Beat ''em Up', 'Konami', 'Konami', '1992-01-31', 'The X-Men are a superhero team in American comic books published by Marvel Comics. Created by writer/editor Stan Lee and artist/co-plotter Jack Kirby, the team first appeared in The X-Men #1. Although initially cancelled in 1970 due to low sales, following its 1975 revival and subsequent direction under writer Chris Claremont, it became one of Marvel Comics''s most recognizable and successful franchises. They have appeared in numerous books, television shows, 20th Century Fox''s X-Men films, and video games. The X-Men title may refer to the superhero team itself, the eponymous comic series, or the broader franchise, which includes various solo titles and team books, such as the New Mutants, Excalibur, and X-Force.', 'https://media.retroachievements.org/Images/018913.png', 'https://media.retroachievements.org/Images/018912.png', 'https://media.retroachievements.org/Images/018910.png', 'https://media.retroachievements.org/Images/018911.png', 4.5),
  (31, 12035, 'The King of Fighters 2002', 'Arcade', 27, 2415, 2415, 2415, 134, 0, '2D Fighting', 'Eolith, SNK', 'Eolith, SNK', '2002-10-01', 'The King of Fighters 2002: Challenge to Ultimate Battle (KOF 2002, or KOF ''02) is a 2002 arcade fighting video game developed by Eolith and published by Playmore, the spiritual successor to the original SNK, for the Neo Geo. It is the ninth title in The King of Fighters series and the second one to be produced by Eolith. Similarly to The King of Fighters ''98, it brings together characters from various SNK franchises and has a diverse roster of fighters.', 'https://media.retroachievements.org/Images/109236.png', 'https://media.retroachievements.org/Images/016475.png', 'https://media.retroachievements.org/Images/016464.png', 'https://media.retroachievements.org/Images/016484.png', 4.5),
  (32, 13767, 'Cyber-Lip', 'Arcade', 27, 2392, 2392, 2392, 48, 0, NULL, 'SNK', 'SNK', '1990-11-01', 'Cyber-Lip is a run and gun video game released in arcades by SNK in 1990 for the Neo Geo MVS. It was released for the Neo Geo AES home console in 1991.', 'https://media.retroachievements.org/Images/062607.png', 'https://media.retroachievements.org/Images/029870.png', 'https://media.retroachievements.org/Images/021975.png', 'https://media.retroachievements.org/Images/021976.png', 4.5),
  (33, 11991, 'Bad Dudes vs. DragonNinja', 'Arcade', 27, 2362, 2362, 2362, 55, 0, 'Beat ''em Up', 'Data East', 'Data East', '1988-01-01', 'Shinobi vs. Dragon Ninja is a song by the Welsh rock band Lostprophets. The song was released in 2001 as the first single from the band''s debut studio album, The Fake Sound of Progress. It was the only charting single on the Billboard charts from the album, and was still on the band''s tour setlist until they broke up in 2013.', 'https://media.retroachievements.org/Images/052574.png', 'https://media.retroachievements.org/Images/036839.png', 'https://media.retroachievements.org/Images/036836.png', 'https://media.retroachievements.org/Images/036837.png', 4.5),
  (34, 16525, 'Metal Slug 6', 'Arcade', 27, 2307, 2307, 2307, 35, 0, 'Run & Gun', 'Noise Factory', 'Sega, SNK', '2006-02-24', 'Metal Slug 6 is a run and gun video game for the Sammy Atomiswave arcade platform in the Metal Slug series. It was released in 2006.', 'https://media.retroachievements.org/Images/065561.png', 'https://media.retroachievements.org/Images/044150.png', 'https://media.retroachievements.org/Images/049506.png', 'https://media.retroachievements.org/Images/044149.png', 4.5),
  (35, 12138, 'Galaga', 'Arcade', 27, 2222, 2222, 2222, 17, 0, 'Shoot ''em Up', 'Namco', 'Midway', '1981-01-01', 'Galaga is a 1981 fixed shooter video game developed and published by Namco for Japanese and European arcades; it was distributed by Midway Manufacturing in North America. It is the sequel to 1979''s Galaxian, and the second game in the Galaxian series. Controlling a starship, the player is tasked with destroying the Galaga forces in each stage while avoiding enemies and projectiles. Some enemies can capture a player''s ship via a tractor beam, which can be rescued by another ship to give the player a dual fighter with additional firepower.', 'https://media.retroachievements.org/Images/096926.png', 'https://media.retroachievements.org/Images/033523.png', 'https://media.retroachievements.org/Images/033525.png', 'https://media.retroachievements.org/Images/033526.png', 4.5),
  (36, 12814, 'DonPachi', 'Arcade', 27, 2163, 2163, 2163, 47, 0, 'Shoot ''em Up, Bullet Hell', NULL, 'Atlus', '1995-11-01', 'DoDonPachi is a 1997 vertically scrolling bullet hell video game developed by Cave and published by Atlus. It was the second game developed by Cave, and the sixth on Cave''s first-generation arcade hardware. As with its predecessor DonPachi, the title is both a Japanese term for expressing the sound of gunfire, and a term that relates to bees.', 'https://media.retroachievements.org/Images/107000.png', 'https://media.retroachievements.org/Images/031380.png', 'https://media.retroachievements.org/Images/031378.png', 'https://media.retroachievements.org/Images/031379.png', 4.4),
  (37, 11932, 'Sunset Riders', 'Arcade', 27, 2054, 2054, 2054, 20, 0, NULL, 'Konami', 'Konami', '1991-09-01', 'Sunset Riders is a 1991 run and gun video game developed and published by Konami for arcades. It was released in North America in October 1991 and Japan in November 1991. It is set in the American Old West, where the player(s) take control of bounty hunters who are seeking the rewards offered for various criminals.', 'https://media.retroachievements.org/Images/123568.png', 'https://media.retroachievements.org/Images/035473.png', 'https://media.retroachievements.org/Images/035474.png', 'https://media.retroachievements.org/Images/035475.png', 4.4),
  (38, 11905, 'Nightmare in the Dark', 'Arcade', 27, 2025, 2025, 2025, 43, 0, '2D Platforming', 'AM Factory', 'Gavaking, Eleven', '2000-01-01', 'Nightmare in the Dark is a platform arcade game developed by AM Factory, with the assistance of Paon, and released by Eleven/Gavaking on January 27, 2000. The game never received an official release for either the Neo Geo AES (home) or Neo Geo CD platforms. It concerns the story of a grave keeper discovering graves being desecrated and his attempt to prevent the graverobbers from inflicting further damage.', 'https://media.retroachievements.org/Images/033374.png', 'https://media.retroachievements.org/Images/018674.png', 'https://media.retroachievements.org/Images/018673.png', 'https://media.retroachievements.org/Images/018675.png', 4.4),
  (39, 11758, 'Art of Fighting', 'Arcade', 27, 2004, 2004, 2004, 27, 0, '2D Fighting', 'SNK', 'SNK', '1992-09-24', 'Art of Fighting, known in Japan as Dragon & Tiger Fist, is a series of fighting video games created by Japanese game designer Hiroshi Matsumoto. Originally released for the Neo Geo platform in the early 1990s, it is the second fighting game franchise created by SNK, following the Fatal Fury series, and is set in the same fictional universe. The original Art of Fighting was released in 1992, followed by two sequels: Art of Fighting 2 in 1994 and Art of Fighting 3: The Path of the Warrior in 1996. A new Art of Fighting game is currently in development. The trilogy primarily focus on two martial artists known as Ryo Sakazaki and Robert Garcia as they use their Kyokugenryu Karate to face enemies in their quests explored in the trilogy of games. Such skills are obtained across bonus from the first game while they become integrated in the two sequels with new characters becoming playable.', 'https://media.retroachievements.org/Images/106171.png', 'https://media.retroachievements.org/Images/016606.png', 'https://media.retroachievements.org/Images/016604.png', 'https://media.retroachievements.org/Images/016605.png', 4.4),
  (40, 11935, 'OutRun', 'Arcade', 27, 1994, 1994, 1994, 18, 0, 'Arcade Racing', 'Sega', 'Sega', '1986-09-20', 'Out Run is 1986 racing video game developed and published by Sega for arcades. It is known for its pioneering hardware and graphics, nonlinear gameplay, a selectable soundtrack with music composed by Hiroshi Kawaguchi, and the hydraulic motion simulator deluxe arcade cabinet. The goal is to avoid traffic and reach one of five destinations before time runs out.', 'https://media.retroachievements.org/Images/051079.png', 'https://media.retroachievements.org/Images/051084.png', 'https://media.retroachievements.org/Images/051082.png', 'https://media.retroachievements.org/Images/051083.png', 4.4),
  (41, 11954, '1941: Counter Attack', 'Arcade', 27, 1979, 1979, 1979, 28, 0, 'Shoot ''em Up', 'Capcom', 'Capcom', '1990-02-01', '1941: Counter Attack is a 1990 vertically scrolling shooter video game developed and published by Capcom for arcades. It is the prequel to 1942, and the third game in the 194X series. It was ported to the SuperGrafx in 1991 and to GameTap. It was released on Capcom Classics Collection Remixed for the PlayStation Portable and Capcom Classics Collection Vol. 2 for PlayStation 2 and Xbox. It was followed by 19XX: The War Against Destiny in 1996.', 'https://media.retroachievements.org/Images/095176.png', 'https://media.retroachievements.org/Images/025224.png', 'https://media.retroachievements.org/Images/025252.png', 'https://media.retroachievements.org/Images/025253.png', 4.4),
  (42, 13762, 'Burning Fight', 'Arcade', 27, 1963, 1963, 1963, 34, 0, 'Beat ''em Up', 'SNK', 'SNK', '1991-04-01', 'Burning Fight is a 1991 beat ''em up video game developed and published by SNK for arcades on the Neo Geo MVS system. Introduced to capture a share in the then-popular beat ''em ups market, it was meant to compete with Technōs'' Double Dragon, the leader of the genre at the time. Three years after its release in the arcades and on the Neo Geo AES, it was released on Neo Geo CD as the only other home version.', 'https://media.retroachievements.org/Images/032965.png', 'https://media.retroachievements.org/Images/032933.png', 'https://media.retroachievements.org/Images/021951.png', 'https://media.retroachievements.org/Images/021952.png', 4.4),
  (43, 12543, 'League Bowling', 'Arcade', 27, 1941, 1941, 1941, 25, 0, 'Sports - Bowling', 'SNK', 'SNK', '1990-12-10', 'League Bowling is a sports arcade game released in 1990 by SNK for the Neo Geo console and arcade systems. The players controls characters with red and blue hair and can select balls from 8 to 15 pounds. It is the only bowling game released on the Neo Geo.', 'https://media.retroachievements.org/Images/052902.png', 'https://media.retroachievements.org/Images/030279.png', 'https://media.retroachievements.org/Images/022070.png', 'https://media.retroachievements.org/Images/022071.png', 4.4),
  (44, 12031, 'The King of Fighters ''97', 'Arcade', 27, 1932, 1932, 1932, 112, 0, '2D Fighting', 'SNK', 'SNK', '1997-07-01', 'The King of Fighters ''97, often shortened as KOF ''97, is a 1997 fighting video game developed and published by SNK for its Neo Geo multi-video system (MVS) arcade platform and its Advanced Entertainment System (AES) home console. It is the fourth game in The King of Fighters (KOF) series. The game was ported to the Neo Geo CD console and released worldwide; it was also ported to the PlayStation and Sega Saturn consoles in Japan. KOF ''97 is the last game in the Orochi Saga storyline, which began in The King of Fighters ''95. The new tournament focuses on the servants of the demon Yamata no Orochi, also known as the Will of Gaia, who plan to revive their master by gathering energy and sacrifices from the fighters in the KOF tournament. KOF ''97 introduced many new playable characters to the series, including five brand new characters, two existing characters from SNK''s Fatal Fury series, as well as several alternate versions of new and existing characters, such as Orochi Yashiro and Orochi Leona.', 'https://media.retroachievements.org/Images/109345.png', 'https://media.retroachievements.org/Images/016425.png', 'https://media.retroachievements.org/Images/016409.png', 'https://media.retroachievements.org/Images/016416.png', 4.4),
  (45, 12248, 'Puzzle Bobble 2 (Neo Geo)', 'Arcade', 27, 1927, 1927, 1927, 60, 0, NULL, 'Taito', 'Taito', '1999-09-01', 'Puzzle Bobble 2 is a tile-matching video game by Taito. The first sequel to Puzzle Bobble, it is also known in Europe and North America as Bust-A-Move Again for arcades and Bust-A-Move 2: Arcade Edition for home consoles. Released into the arcades in 1995, home conversions followed for the PlayStation, Sega Saturn, Nintendo 64, and Windows platforms. The game was included in Taito Legends 2, but the US arcade version was included in the US PS2 version instead. Further ports for the Nintendo Switch, PlayStation 4, and Xbox One were released by City Connection alongside Puzzle Bobble 3 in February 2023.', 'https://media.retroachievements.org/Images/032927.png', 'https://media.retroachievements.org/Images/022233.png', 'https://media.retroachievements.org/Images/022234.png', 'https://media.retroachievements.org/Images/022235.png', 4.4),
  (46, 12274, 'Street Fighter III: New Generation', 'Arcade', 27, 1906, 1906, 1906, 88, 0, '2D Fighting', 'Capcom', 'Capcom', '1997-02-01', 'Street Fighter III: New Generation  is a 1997 fighting game in Capcom''s Street Fighter series, originally released as a coin-operated arcade game. The sequel to Street Fighter II (1991), it initially discarded every previous character except for Ryu and Ken, introducing an all-new roster led by Alex. Likewise, a new antagonist named Gill took over M. Bison''s role from the previous games as the new boss character.', 'https://media.retroachievements.org/Images/065723.png', 'https://media.retroachievements.org/Images/047573.png', 'https://media.retroachievements.org/Images/031292.png', 'https://media.retroachievements.org/Images/031293.png', 4.4),
  (47, 11895, 'Wild West C.O.W.-Boys of Moo Mesa', 'Arcade', 27, 1877, 1877, 1877, 42, 0, NULL, 'Konami', 'Konami', '1992-11-01', 'Wild West C.O.W.-Boys of Moo Mesa is a 1992 American animated television series created by comic book artist Ryan Brown, known for his work on Teenage Mutant Ninja Turtles. It aired as part of ABC''s Saturday morning lineup.', 'https://media.retroachievements.org/Images/032973.png', 'https://media.retroachievements.org/Images/032976.png', 'https://media.retroachievements.org/Images/032977.png', 'https://media.retroachievements.org/Images/032978.png', 4.4),
  (48, 12266, 'Marvel Super Heroes vs. Street Fighter', 'Arcade', 27, 1845, 1845, 1845, 70, 0, '2D Fighting', 'Capcom', 'Capcom', '1997-06-25', 'Marvel Super Heroes  is a 1995 fighting game developed and published by Capcom. Originally released for arcades on the CPS-2 arcade system, it was ported to the Sega Saturn and PlayStation in 1997. The game, alongside Marvel vs. Capcom: Clash of Super Heroes, was also included in the Marvel vs. Capcom Origins compilation, released digitally for the PlayStation 3 and Xbox 360 in 2012.', 'https://media.retroachievements.org/Images/106811.png', 'https://media.retroachievements.org/Images/016285.png', 'https://media.retroachievements.org/Images/016283.png', 'https://media.retroachievements.org/Images/016284.png', 4.4),
  (49, 12394, 'Contra', 'Arcade', 27, 1810, 1810, 1810, 22, 0, 'Run & Gun', 'Konami', 'Konami', '1987-01-01', 'Contra is a 1987 run and gun game developed and published by Konami for arcades. A home version was released for the Nintendo Entertainment System in 1988, along with ports for various home computer formats, including the MSX2. The arcade and computer versions were localized as Gryzor in Europe, and the NES version as Probotector in the PAL region.', 'https://media.retroachievements.org/Images/108513.png', 'https://media.retroachievements.org/Images/059065.png', 'https://media.retroachievements.org/Images/058205.png', 'https://media.retroachievements.org/Images/058204.png', 4.4),
  (50, 12241, 'Magician Lord', 'Arcade', 27, 1787, 1787, 1787, 59, 0, '2D Platforming, Action', 'ADK', 'ADK', '1990-04-26', 'Magician Lord is a 1990 action-platform video game developed by Alpha Denshi and published by SNK for arcades on the Neo Geo MVS system. It was one of the launch titles for the MVS, as well as its home counterpart, the Neo Geo AES, which launched in 1991. The player controls Elta, a magician who embarks on a journey to recover the stolen magic tomes from the evil sorcerer Gal and his followers before Az Atorse, the god of destruction, is revived and destroys the land of Cadacis and the world.', 'https://media.retroachievements.org/Images/052904.png', 'https://media.retroachievements.org/Images/115486.png', 'https://media.retroachievements.org/Images/022076.png', 'https://media.retroachievements.org/Images/022077.png', 4.4),
  (51, 11752, 'Garou: Mark of the Wolves', 'Arcade', 27, 1780, 1780, 1780, 96, 0, '2D Fighting', 'SNK', 'SNK', '1999-11-11', 'Garou: Mark of the Wolves is a 1999 fighting game developed and published by SNK, originally for the Neo Geo and then as Fatal Fury: Mark of the Wolves for the Dreamcast. It is the sixth main installment in the Fatal Fury series. Though released a year after Real Bout Fatal Fury 2: The Newcomers (1998), the game is canonically a sequel to Real Bout Fatal Fury (1995), taking place a decade after the events of that game. Ten years after combatant Terry Bogard kills crimelord Geese Howard in The King of Fighters tournament, he and his adoptive son, Rock Howard, enter into a South Town tournament known as Maximum Mayhem to learn about the Howard legacy. The game features 14 characters, all new, with the exception of Terry Bogard. As a fighting game, the game employs two innovative mechanics, the first known as T.O.P, which provides players with powerful attacks when their health is within a certain range, and the second known as Just Defend, which provides players with various advantages if they block attacks at precise moments.', 'https://media.retroachievements.org/Images/114442.png', 'https://media.retroachievements.org/Images/017122.png', 'https://media.retroachievements.org/Images/016454.png', 'https://media.retroachievements.org/Images/016455.png', 4.4),
  (52, 12111, 'Elevator Action Returns', 'Arcade', 27, 1774, 1774, 1774, 24, 0, NULL, 'Taito', NULL, '1995-02-01', 'Elevator Action is a 1983 shooter platform video game developed and published by Taito for arcades. The player assumes the role of a secret agent infiltrating a 30-story building from the roof, then descending to ground level via elevators and stairways. Enemy agents emerge from closed doors and shoot at the player. The goal is to collect secret documents from specially marked rooms, then exit to a waiting getaway car. It runs on the Taito SJ System arcade system.', 'https://media.retroachievements.org/Images/066015.png', 'https://media.retroachievements.org/Images/063728.png', 'https://media.retroachievements.org/Images/019264.png', 'https://media.retroachievements.org/Images/019265.png', 4.4),
  (53, 11822, 'Marvel Super Heroes', 'Arcade', 27, 1766, 1766, 1766, 43, 0, '2D Fighting', 'Capcom', 'Capcom', '1995-01-01', 'Marvel Super Heroes  is a 1995 fighting game developed and published by Capcom. Originally released for arcades on the CPS-2 arcade system, it was ported to the Sega Saturn and PlayStation in 1997. The game, alongside Marvel vs. Capcom: Clash of Super Heroes, was also included in the Marvel vs. Capcom Origins compilation, released digitally for the PlayStation 3 and Xbox 360 in 2012.', 'https://media.retroachievements.org/Images/106809.png', 'https://media.retroachievements.org/Images/016033.png', 'https://media.retroachievements.org/Images/016031.png', 'https://media.retroachievements.org/Images/016032.png', 4.4),
  (54, 12271, 'Super Street Fighter II: The New Challengers', 'Arcade', 27, 1756, 1756, 1756, 45, 0, '2D Fighting', 'Capcom', 'Capcom', '1993-09-10', 'Super Street Fighter II: The New Challengers is a 1993 fighting game developed and published by Capcom for arcades. It is the fourth game in the Street Fighter II sub-series of Street Fighter games, following Street Fighter II Turbo (1992). It refines and balances the existing character roster from the previous versions, and introduces four new characters, including Fei Long, Cammy, T. Hawk, and Dee Jay. It is the first game on Capcom''s CP System II hardware, with more sophisticated graphics and audio over the original CP System hardware used in previous versions of Street Fighter II.', 'https://media.retroachievements.org/Images/120548.png', 'https://media.retroachievements.org/Images/029164.png', 'https://media.retroachievements.org/Images/095496.png', 'https://media.retroachievements.org/Images/095497.png', 4.4),
  (55, 11996, 'Buster Bros.', 'Arcade', 27, 1716, 1716, 1716, 113, 0, 'Action', 'Mitchell', 'Mitchell, Capcom', '1989-11-29', 'Buster Bros. Collection is a video game developed by Mitchell Corporation and published by Capcom for the PlayStation.', 'https://media.retroachievements.org/Images/069898.png', 'https://media.retroachievements.org/Images/070050.png', 'https://media.retroachievements.org/Images/069891.png', 'https://media.retroachievements.org/Images/070049.png', 4.4),
  (56, 13770, 'Eight Man', 'Arcade', 27, 1680, 1680, 1680, 30, 0, 'Beat ''em Up', 'Pallas', 'SNK', '1991-09-01', '8 Man , Eightman (エイトマン), or 8th Man is a manga and superhero anime created in 1963 by science fiction writer Kazumasa Hirai and manga artist Jiro Kuwata. 8 Man is considered Japan''s earliest cyborg superhero, predating Kamen Rider.', 'https://media.retroachievements.org/Images/038444.png', 'https://media.retroachievements.org/Images/038442.png', 'https://media.retroachievements.org/Images/021987.png', 'https://media.retroachievements.org/Images/021988.png', 4.4),
  (57, 11983, 'Armored Warriors', 'Arcade', 27, 1630, 1630, 1630, 26, 0, 'Beat ''em Up', 'Capcom', 'Capcom', '1994-10-24', 'Armored Warriors, known in Japan as Powered Gear: Strategic Variant Armor Equipment, is a 1994 beat ''em up video game developed and published by Capcom for arcades.', 'https://media.retroachievements.org/Images/065295.png', 'https://media.retroachievements.org/Images/065017.png', 'https://media.retroachievements.org/Images/037069.png', 'https://media.retroachievements.org/Images/037070.png', 4.4),
  (58, 12084, 'Dungeons & Dragons: Tower of Doom', 'Arcade', 27, 1629, 1629, 1629, 30, 0, 'Beat ''em Up', 'Capcom', 'Capcom', '1994-01-01', 'Dungeons & Dragons: Tower of Doom, published in 1994, is the first of two arcade games created by Capcom based on the Dungeons & Dragons tabletop role-playing game and set in the Mystara campaign setting. It is a side scrolling beat ''em up with role-playing video game elements for one to four players. The game was also released on the Sega Saturn, packaged with its sequel, Dungeons & Dragons: Shadow over Mystara, under the title Dungeons & Dragons Collection, although the Saturn version limited the gameplay to only two players. In 2013, both games were re-released for PlayStation 3, Windows, Xbox 360 and Wii U as Dungeons & Dragons: Chronicles of Mystara.', 'https://media.retroachievements.org/Images/122042.png', 'https://media.retroachievements.org/Images/025283.png', 'https://media.retroachievements.org/Images/025284.png', 'https://media.retroachievements.org/Images/025285.png', 4.4),
  (59, 12601, 'Ghost Pilots', 'Arcade', 27, 1608, 1608, 1608, 32, 0, 'Shoot ''em Up', 'SNK', 'SNK', '1991-01-25', 'Ghost Pilots is a vertically scrolling shooter arcade video game released in 1991 by SNK. It has elements similar to Capcom''s 194X series, but the player controls a seaplane.', 'https://media.retroachievements.org/Images/088117.png', 'https://media.retroachievements.org/Images/088118.png', 'https://media.retroachievements.org/Images/022038.png', 'https://media.retroachievements.org/Images/101091.png', 4.4),
  (60, 11767, 'Shock Troopers', 'Arcade', 27, 1559, 1559, 1559, 55, 0, NULL, 'Saurus', 'SNK', '1997-11-01', 'Shock Troopers is a run and gun arcade game developed by Saurus and published by SNK in 1997 for the Neo-Geo arcade MVS platform. Gameplay involves taking command of one or three soldiers in an eight-way shooter. A second game in the series, Shock Troopers: 2nd Squad, followed up in 1998.', 'https://media.retroachievements.org/Images/040086.png', 'https://media.retroachievements.org/Images/016994.png', 'https://media.retroachievements.org/Images/016892.png', 'https://media.retroachievements.org/Images/016893.png', 4.3),
  (61, 11794, 'Mega Man: The Power Battle', 'Arcade', 27, 1557, 1557, 1557, 60, 0, '2D Fighting', 'Capcom', 'Capcom', '1995-10-06', 'Mega Man: The Power Battle is a 1995 fighting game developed and published by Capcom for arcades. A spin-off title for the Mega Man series, it features Mega Man and his allies fighting Doctor Wily and his rebuilt Robot Masters in a series of boss battles. The game was followed by a sequel, Mega Man 2: The Power Fighters, in 1996. Both games have since received home releases through various video game compilations.', 'https://media.retroachievements.org/Images/029567.png', 'https://media.retroachievements.org/Images/018917.png', 'https://media.retroachievements.org/Images/018915.png', 'https://media.retroachievements.org/Images/018916.png', 4.3),
  (62, 13648, 'Battle Garegga', 'Arcade', 27, 1525, 1525, 1525, 30, 0, 'Shoot ''em Up', 'Raizing | Eighting', 'Raizing | Eighting', '1996-02-01', 'Battle Garegga is a vertically scrolling shooter arcade video game developed by Raizing and published by Eighting in 1996. A port to the Saturn was published in 1998. An updated version, Battle Garegga Rev.2016 was released in 2016. It was followed by a spiritual successor, Battle Bakraid, in 1999.', 'https://media.retroachievements.org/Images/066365.png', 'https://media.retroachievements.org/Images/058176.png', 'https://media.retroachievements.org/Images/021414.png', 'https://media.retroachievements.org/Images/021415.png', 4.3),
  (63, 11801, 'Blue''s Journey', 'Arcade', 27, 1523, 1523, 1523, 97, 0, '2D Platforming', 'ADK', 'ADK', '1991-03-01', 'Blue''s Journey is a side-scrolling platform game released by Alpha Denshi in 1990 on SNK''s Neo Geo MVS arcade system and their AES home system. It was ported to the Neo Geo CD in 1994. It was rereleased on the Wii''s Virtual Console in Europe on November 9, 2007, followed by North America on November 12, 2007.', 'https://media.retroachievements.org/Images/043224.png', 'https://media.retroachievements.org/Images/043226.png', 'https://media.retroachievements.org/Images/021945.png', 'https://media.retroachievements.org/Images/043225.png', 4.3),
  (64, 12183, 'Hook', 'Arcade', 27, 1505, 1505, 1505, 89, 0, 'Beat ''em Up', 'Irem', 'Irem', '1992-12-01', 'A hook is a tool consisting of a length of material, typically metal, that contains a portion that is curved/bent back or has a deeply grooved indentation, which serves to grab, latch or in any way attach itself onto another object. The hook''s design allows traction forces to be relayed through the curved/indented portion to and from the proximal end of the hook, which is either a straight shaft or a ring for attachment to a thread, rope or chain, providing a reversible attachment between two objects.', 'https://media.retroachievements.org/Images/039733.png', 'https://media.retroachievements.org/Images/030987.png', 'https://media.retroachievements.org/Images/030986.png', 'https://media.retroachievements.org/Images/030985.png', 4.3),
  (65, 11765, 'Baseball Stars 2', 'Arcade', 27, 1504, 1504, 1504, 43, 0, 'Sports - Baseball', 'SNK', 'SNK', '1992-04-01', 'Baseball Stars 2 is a baseball sports arcade game released by SNK in 1992 for the Neo-Geo console. A less detailed console version was released for the NES by Romstar the same year.', 'https://media.retroachievements.org/Images/041768.png', 'https://media.retroachievements.org/Images/016997.png', 'https://media.retroachievements.org/Images/017006.png', 'https://media.retroachievements.org/Images/017007.png', 4.3),
  (66, 11780, 'Dungeons & Dragons: Shadow Over Mystara', 'Arcade', 27, 1503, 1503, 1503, 51, 0, 'Beat ''em Up', 'Capcom', 'Capcom', '1996-02-01', 'Dungeons & Dragons: Shadow over Mystara is a 1996 beat ''em up game developed and published by Capcom for arcades. It is a sequel to Dungeons & Dragons: Tower of Doom. The game is set in the Dungeons & Dragons campaign setting of Mystara.', 'https://media.retroachievements.org/Images/122043.png', 'https://media.retroachievements.org/Images/025286.png', 'https://media.retroachievements.org/Images/025288.png', 'https://media.retroachievements.org/Images/025287.png', 4.3),
  (67, 12366, 'RoboCop', 'Arcade', 27, 1501, 1501, 1501, 43, 0, NULL, 'Data East', 'Data East', '1988-01-01', 'RoboCop is a 1987 American science fiction action film directed by Paul Verhoeven and written by Edward Neumeier and Michael Miner. The film stars Peter Weller, Nancy Allen, Daniel O''Herlihy, Ronny Cox, Kurtwood Smith, and Miguel Ferrer. Set in a crime-ridden Detroit in the near future, RoboCop centers on police officer Alex Murphy (Weller) who is murdered by a gang of criminals and revived by the megacorporation Omni Consumer Products as the cyborg law enforcer RoboCop. Unaware of his former life, RoboCop executes a campaign against crime while coming to terms with the lingering fragments of his humanity.', 'https://media.retroachievements.org/Images/051955.png', 'https://media.retroachievements.org/Images/034893.png', 'https://media.retroachievements.org/Images/050626.png', 'https://media.retroachievements.org/Images/050627.png', 4.3),
  (68, 13794, 'Mutation Nation', 'Arcade', 27, 1487, 1487, 1487, 29, 0, 'Beat ''em Up', 'SNK', 'SNK', '1992-03-01', 'Mutation Nation is a beat ''em up arcade video game that was developed and released by SNK for the Neo Geo in 1992.', 'https://media.retroachievements.org/Images/033279.png', 'https://media.retroachievements.org/Images/033278.png', 'https://media.retroachievements.org/Images/022145.png', 'https://media.retroachievements.org/Images/022146.png', 4.3),
  (69, 14978, 'Mortal Kombat II', 'Arcade', 27, 1486, 1486, 1486, 43, 0, '2D Fighting', 'Midway', 'Midway', '1993-04-03', 'Mortal Kombat II is a 1993 fighting game developed and published by Midway for arcades. It was later ported to multiple home systems, including MS-DOS, Amiga, Game Boy, Game Gear, Sega Genesis, 32X, Sega Saturn, Super NES, and PlayStation, by Probe Software and Sculptured Software, and published by Acclaim Entertainment.', 'https://media.retroachievements.org/Images/122179.png', 'https://media.retroachievements.org/Images/030490.png', 'https://media.retroachievements.org/Images/030935.png', 'https://media.retroachievements.org/Images/030936.png', 4.3),
  (70, 12023, 'Bubble Bobble', 'Arcade', 27, 1453, 1453, 1453, 91, 0, '2D Platforming', 'Taito', 'Electrocoin, Romstar, Taito', '1986-09-01', 'Bubble Bobble is a platform game series originally developed and published by Taito. The first entry in the series, Bubble Bobble, was released in 1986 as an arcade cabinet. In most entries in the series, players control two dragons named Bub and Bob. This was followed by many sequels in both the main Bubble Bobble series, as well as the spin-off Rainbow Islands and Puzzle Bobble series. They were published for and ported to a wide variety of arcade and home video game consoles. The most recent release in the series is Bubble Bobble Sugar Dungeons in 2025.', 'https://media.retroachievements.org/Images/086846.png', 'https://media.retroachievements.org/Images/057562.png', 'https://media.retroachievements.org/Images/057560.png', 'https://media.retroachievements.org/Images/057561.png', 4.3),
  (71, 11959, '64th. Street: A Detective Story', 'Arcade', 27, 1448, 1448, 1448, 15, 0, 'Beat ''em Up', 'C.P. Brain', 'Jaleco', '1991-01-01', '64th Street: A Detective Story is a 1992 beat ''em up video game developed by CP.Brain and published by Jaleco for arcades. It was released in Japan in March 1992 and in North America the same year. The two main characters are private detectives, who fight gangs through six stages to rescue a rich man''s daughter who has been kidnapped.', 'https://media.retroachievements.org/Images/050582.png', 'https://media.retroachievements.org/Images/050736.png', 'https://media.retroachievements.org/Images/050580.png', 'https://media.retroachievements.org/Images/050579.png', 4.3),
  (72, 11768, 'Shock Troopers: 2nd Squad', 'Arcade', 27, 1434, 1434, 1434, 45, 0, NULL, 'Saurus', 'Saurus', '1998-10-01', 'Shock Troopers: 2nd Squad is a run and gun arcade game developed by Saurus and published by SNK in 1998 for the Neo-Geo arcade and home platform. Despite its title, it has no connection with the first Shock Troopers game. 2nd Squad was re-released for the Wii''s Virtual Console service for North America in 2012. SNK Playmore released it for iOS, Linux and Windows via Humble Bundle and Steam in 2016.', 'https://media.retroachievements.org/Images/040175.png', 'https://media.retroachievements.org/Images/016995.png', 'https://media.retroachievements.org/Images/016903.png', 'https://media.retroachievements.org/Images/016904.png', 4.3),
  (73, 11993, 'Battle Circuit', 'Arcade', 27, 1423, 1423, 1423, 48, 0, 'Beat ''em Up', 'Capcom', 'Capcom', '1997-03-19', 'The history of video games began in the 1950s and 1960s as computer scientists began designing simple games and simulations on minicomputers and mainframes. Spacewar! was developed by Massachusetts Institute of Technology (MIT) student hobbyists in 1962 as one of the first such games on a video display. The first consumer video game hardware was released in the early 1970s. The first home video game console was the Magnavox Odyssey, and the first arcade video games were Computer Space and Pong. After its home console conversions, numerous companies sprang up to capture Pong''s success in both the arcade and the home by cloning the game, causing a series of boom and bust cycles due to oversaturation and lack of innovation.', 'https://media.retroachievements.org/Images/073731.png', 'https://media.retroachievements.org/Images/065022.png', 'https://media.retroachievements.org/Images/069928.png', 'https://media.retroachievements.org/Images/069930.png', 4.3),
  (74, 13808, 'Robo Army', 'Arcade', 27, 1418, 1418, 1418, 26, 0, 'Beat ''em Up', 'SNK', 'SNK', '1991-10-30', 'Robo Army is a beat ''em up video game developed and published by SNK that was released for Neo Geo arcades and home consoles in 1991 and the Neo Geo CD in 1995.', 'https://media.retroachievements.org/Images/077448.png', 'https://media.retroachievements.org/Images/039393.png', 'https://media.retroachievements.org/Images/022256.png', 'https://media.retroachievements.org/Images/022257.png', 4.3),
  (75, 12032, 'The King of Fighters ''99: Millennium Battle', 'Arcade', 27, 1406, 1406, 1406, 74, 0, '2D Fighting', 'SNK', 'SNK', '1999-07-22', 'The King of Fighters ''99: Millennium Battle, also called KOF ''99, is a 1999 fighting game developed and published by SNK for the Neo Geo MVS arcade and home consoles in 1999. It is the sixth installment in The King of Fighters series following The King of Fighters ''98, introducing a new story arc known as the NESTS Chronicles which is centered around a young man named K'', who is formerly associated with a mysterious organization known only as NESTS. The game introduces several changes to the established KOF format, most notably an assisting character labeled Striker. The game was ported to the Neo Geo CD and the PlayStation. Dreamcast and Microsoft Windows versions were also released under the title The King of Fighters'' 99: Evolution whose stages were remodeled in 3D.', 'https://media.retroachievements.org/Images/120962.png', 'https://media.retroachievements.org/Images/016424.png', 'https://media.retroachievements.org/Images/016412.png', 'https://media.retroachievements.org/Images/016418.png', 4.3),
  (76, 17678, 'Spider-Man: The Videogame', 'Arcade', 27, 1388, 1388, 1388, 9, 0, 'Beat ''em Up', 'Sega', 'Sega', '1991-09-01', 'Spider-Man: The Video Game, also known as Spider-Man, is a 1991 arcade video game developed by Sega based on the Marvel Comics character Spider-Man.', 'https://media.retroachievements.org/Images/107611.png', 'https://media.retroachievements.org/Images/046461.png', 'https://media.retroachievements.org/Images/046459.png', 'https://media.retroachievements.org/Images/046462.png', 4.3),
  (77, 11853, 'Shinobi', 'Arcade', 27, 1349, 1349, 1349, 28, 0, NULL, 'Sega', 'Sega', '1987-11-01', 'A ninja , shinobi no mono  or shinobi  was a spy and infiltrator in pre-modern Japan. Antecedents may have existed as early as the 12th century. There is little evidence that they were assassins.', 'https://media.retroachievements.org/Images/110100.png', 'https://media.retroachievements.org/Images/057191.png', 'https://media.retroachievements.org/Images/019173.png', 'https://media.retroachievements.org/Images/019174.png', 4.3),
  (78, 13784, 'King of the Monsters', 'Arcade', 27, 1347, 1347, 1347, 49, 0, 'Fighting (Kaiju, Wrestling)', 'SNK', 'SNK', '1991-02-01', 'King of the Monsters is a fighting game developed by SNK, released for arcades in Japan in 1991, and ported to the Neo Geo AES later that same year. The game features playable giant monsters that are reminiscent of characters from kaiju and tokusatsu films.', 'https://media.retroachievements.org/Images/033265.png', 'https://media.retroachievements.org/Images/033264.png', 'https://media.retroachievements.org/Images/022055.png', 'https://media.retroachievements.org/Images/022056.png', 4.3),
  (79, 14654, 'Ultimate Mortal Kombat 3', 'Arcade', 27, 1334, 1334, 1334, 65, 0, '2D Fighting', 'Midway', 'Midway', '1995-11-06', 'Ultimate Mortal Kombat 3 is a 1995 fighting game developed and published by Midway for arcades. Part of the Mortal Kombat series, it is a standalone update of 1995''s earlier Mortal Kombat 3 with an altered gameplay system and some new features, as well as additional characters like the returning favorites Reptile, Kitana, Jade and Scorpion, who were missing from Mortal Kombat 3.', 'https://media.retroachievements.org/Images/122181.png', 'https://media.retroachievements.org/Images/055562.png', 'https://media.retroachievements.org/Images/027506.png', 'https://media.retroachievements.org/Images/027507.png', 4.3),
  (80, 11946, 'Mario Bros.', 'Arcade', 27, 1329, 1329, 1329, 22, 0, '2D Platforming', NULL, 'Nintendo', '1983-07-14', 'Mario Bros. is a 1983 platform game developed and published by Nintendo for arcades. It was designed by Shigeru Miyamoto and Gunpei Yokoi, Nintendo''s chief engineer. Players control Italian twin brother plumbers Mario and Luigi as they exterminate turtle-like creatures, giant flies, and crabs emerging from the sewers of New York City by knocking them upside-down and kicking them away. The Famicom/NES version was the first game to be developed by Intelligent Systems. It is part of the Mario franchise and the first spin-off of the Donkey Kong series.', 'https://media.retroachievements.org/Images/060942.png', 'https://media.retroachievements.org/Images/019366.png', 'https://media.retroachievements.org/Images/019363.png', 'https://media.retroachievements.org/Images/019364.png', 4.3),
  (81, 12261, 'Street Fighter', 'Arcade', 27, 1320, 1320, 1320, 39, 0, '2D Fighting', 'Capcom', 'Capcom', '1987-08-30', 'Street Fighter is a Japanese media franchise centered on a series of fighting games developed and published by Capcom. The first game in the series was released in 1987, followed by the other six main games in the series, various spin-offs and crossovers, and numerous appearances in other media. Its best-selling 1991 release, Street Fighter II, established many of the conventions of the one-on-one fighting genre.', 'https://media.retroachievements.org/Images/070391.png', 'https://media.retroachievements.org/Images/115504.png', 'https://media.retroachievements.org/Images/049573.png', 'https://media.retroachievements.org/Images/049574.png', 4.3),
  (82, 12380, 'Strikers 1945', 'Arcade', 27, 1301, 1301, 1301, 39, 0, 'Shoot ''em Up', 'Psikyo', 'Psikyo', '1995-01-01', 'Strikers 1945 (ストライカーズ1945), also known as Striker 1945, is a vertically scrolling shoot ''em up bullet hell arcade game developed and published by Psikyo in 1995. In Japan, it was ported to the PlayStation and Sega Saturn by Atlus in 1996; later was also released as part of Psikyo Shooting Collection Vol. 1: Strikers 1945 I & II by Taito for the PlayStation 2. The game was followed by Strikers 1945 II in 1997, and Strikers 1945 III in 1999, as well as the second title remake called Strikers 1945 Plus.', 'https://media.retroachievements.org/Images/068029.png', 'https://media.retroachievements.org/Images/025230.png', 'https://media.retroachievements.org/Images/025228.png', 'https://media.retroachievements.org/Images/025229.png', 4.3),
  (83, 12139, 'Galaxian', 'Arcade', 27, 1296, 1296, 1296, 24, 0, 'Shoot ''em Up', 'Namco', 'Midway', '1979-10-01', 'Galaxian is a 1979 fixed shooter video game developed and published by Namco for arcades during early video games'' golden age. The player assumes control of the Galaxip starfighter in its mission to protect Earth from waves of aliens. Gameplay involves destroying each formation of aliens, who dive down towards the player in an attempt to hit them.', 'https://media.retroachievements.org/Images/119282.png', 'https://media.retroachievements.org/Images/073953.png', 'https://media.retroachievements.org/Images/033527.png', 'https://media.retroachievements.org/Images/033528.png', 4.3),
  (84, 15015, 'Centipede', 'Arcade', 27, 1290, 1290, 1290, 40, 0, 'Shoot ''em Up', 'Atari', 'Atari', '1981-06-15', 'Centipedes are predatory arthropods belonging to the class Chilopoda of the subphylum Myriapoda, an arthropod group which includes millipedes and other multi-legged animals. Centipedes are elongated segmented (metameric) animals with one pair of legs per body segment. All centipedes are venomous and can inflict painful stings, injecting their venom through pincer-like appendages known as forcipules or toxicognaths, which are actually modified legs instead of fangs. Despite the name, no species of centipede has exactly 100 legs; the number of pairs of legs is an odd number that ranges from 15 pairs to 191 pairs.', 'https://media.retroachievements.org/Images/103392.png', 'https://media.retroachievements.org/Images/085580.png', 'https://media.retroachievements.org/Images/085579.png', 'https://media.retroachievements.org/Images/086284.png', 4.3),
  (85, 12005, 'Detana!! TwinBee', 'Arcade', 27, 1290, 1290, 1290, 40, 0, 'Shoot ''em Up', 'Konami', 'Konami', '1991-02-01', 'Detana!! TwinBee, released in Europe as Bells & Whistles, is a 1991 vertically scrolling shooter video game developed and published by Konami for arcades. It is the fifth entry in the TwinBee series and the second to be released for arcades following the original TwinBee. Set several years after the events of TwinBee, players assume the role of Light and Pastel taking control of TwinBee and WinBee to defeat invading forces of the evil alien Iva and save planet Meru after receiving an SOS message sent by Princess Melora.', 'https://media.retroachievements.org/Images/052612.png', 'https://media.retroachievements.org/Images/052964.png', 'https://media.retroachievements.org/Images/052587.png', 'https://media.retroachievements.org/Images/052588.png', 4.3),
  (86, 11942, 'X-Men vs. Street Fighter', 'Arcade', 27, 1259, 1259, 1259, 55, 0, '2D Fighting', 'Capcom', 'Capcom', '1996-09-01', 'X-Men vs. Street Fighter is a 1996 crossover fighting game developed and published by Capcom. It is Capcom''s third fighting game to feature Marvel Comics characters, following X-Men: Children of the Atom (1994) and Marvel Super Heroes (1995), and the first installment in the Marvel vs. Capcom series. As the title suggests, the game includes characters from Marvel''s X-Men franchise and the cast from Capcom''s Street Fighter series. Originally released for arcades in 1996, it was ported to the Sega Saturn in 1997 and the PlayStation in 1998. The original arcade version is included in the compilation Marvel vs. Capcom Fighting Collection: Arcade Classics, released for the Nintendo Switch, PlayStation 4 and Windows in 2024.', 'https://media.retroachievements.org/Images/106810.png', 'https://media.retroachievements.org/Images/016185.png', 'https://media.retroachievements.org/Images/016182.png', 'https://media.retroachievements.org/Images/016183.png', 4.3),
  (87, 11858, 'Bang Bead', 'Arcade', 27, 1241, 1241, 1241, 17, 0, 'Sports - Ball & Paddle', 'Visco', 'Visco', '2000-01-01', 'Japanese video game company SNK began developing and publishing video games in 1978. SNK''s first video games were released on dedicated arcade boards throughout the 1980s. In the 1990s and early 2000s, most of their games were released on their proprietary hardware, including the Neo Geo and Neo Geo Pocket Color. Since the mid-2000s, SNK has released games on other company platforms.', 'https://media.retroachievements.org/Images/088064.png', 'https://media.retroachievements.org/Images/099018.png', 'https://media.retroachievements.org/Images/021939.png', 'https://media.retroachievements.org/Images/021940.png', 4.3),
  (88, 4845, 'Pretty Soldier Sailor Moon', 'Arcade', 27, 1220, 1220, 1220, 30, 0, 'Beat ''em Up', 'Gazelle', 'Banpresto', '1995-03-22', 'Pretty Soldier Sailor Moon is a side-scrolling beat ''em up arcade video game developed by Gazelle and released on March 22, 1995. It was published by Banpresto. It is the first game to be created by Gazelle, one of the offshoots of defunct developer Toaplan that were founded after they declared bankruptcy in 1994, and one of the few titles based upon Naoko Takeuchi''s Sailor Moon shōjo manga and anime series that had an official international release, and it also has been compared with other titles in the same genre such as Capcom''s Final Fight and Technōs Japan''s Double Dragon.', 'https://media.retroachievements.org/Images/068543.png', 'https://media.retroachievements.org/Images/031271.png', 'https://media.retroachievements.org/Images/029089.png', 'https://media.retroachievements.org/Images/029097.png', 4.3),
  (89, 15000, 'Batman', 'Arcade', 27, 1215, 1215, 1215, 19, 0, 'Beat ''em Up', 'Atari', 'Atari', '1991-04-01', 'Batman is a superhero who appears in American comic books published by DC Comics. Batman was created by writer Bill Finger and artist Bob Kane, and debuted in the 27th issue of the comic book Detective Comics on March 30, 1939. In the DC Universe, Batman is the alias of Bruce Wayne, a wealthy American playboy, philanthropist, and industrialist who resides in the fictional Gotham City. Originally a millionaire, later versions of the character depict him as a billionaire. His origin story features him swearing vengeance against criminals after witnessing the murder of his parents, Thomas and Martha, as a child, a vendetta tempered by the ideal of justice. He trains himself physically and intellectually, crafts a bat-inspired persona, and monitors the Gotham streets at night. Kane, Finger, and other creators accompanied Batman with supporting characters, including his sidekicks Robin and Batgirl; allies Alfred Pennyworth and James Gordon; love interest and occasional adversary Catwoman; as well as foes such as the Penguin, the Riddler, Two-Face, and his archenemy, the Joker.', 'https://media.retroachievements.org/Images/052559.png', 'https://media.retroachievements.org/Images/030277.png', 'https://media.retroachievements.org/Images/030276.png', 'https://media.retroachievements.org/Images/030278.png', 4.3),
  (90, 12033, 'The King of Fighters 2000', 'Arcade', 27, 1214, 1214, 1214, 90, 0, '2D Fighting', 'SNK', 'SNK', '2000-07-01', 'The King of Fighters 2000 is a 2000 fighting video game developed and produced by SNK and released for the Neo Geo arcade and home consoles. It is the seventh installment in The King of Fighters series for the Neo Geo, and the final game in the series SNK produced before the original company''s bankruptcy. The game was ported to the Dreamcast in Japan and the PlayStation 2 in 2002. The game, a sequel to The King of Fighters ''99, focuses on a tournament held by the commander of the Hikari military forces, Heidern, who seeks to interrogate the missing K'' and Maxima in order to learn about their former group, the NESTS cartel. The gameplay retains the Striker system of the previous games in the series involving assisting characters, but was modified to generate more combos.', 'https://media.retroachievements.org/Images/109347.png', 'https://media.retroachievements.org/Images/016470.png', 'https://media.retroachievements.org/Images/016462.png', 'https://media.retroachievements.org/Images/016469.png', 4.3),
  (91, 12030, 'The King of Fighters ''96', 'Arcade', 27, 1208, 1208, 1208, 96, 0, '2D Fighting', 'SNK', 'SNK', '1996-07-01', 'The King of Fighters ''96 (KOF ''96) is a fighting game released by SNK for the Neo Geo arcade and home consoles in 1996. It is the third game in The King of Fighters series, following The King of Fighters ''95. Unlike its predecessors, it features more emphasis on hand-to-hand combat rather than projectile moves. The plot follows a new King of Fighters tournament created by Chizuru Kagura, the heir of the Yata Clan, who wants to find and recruit the protagonist, Kyo Kusanagi, who defeated the previous host Rugal Bernstein. She seeks to recruit him to ask him and his bitter rival, Iori Yagami, to help her in the sealing of the Orochi demon like her predecessors. The final boss of the game is Goenitz, one of the servants of Orochi. Developers made several changes to the cast when compared to The King of Fighters ''95, with special focus on a Boss Team composed of famous villains from their other two IPs, Fatal Fury and Art of Fighting.', 'https://media.retroachievements.org/Images/120960.png', 'https://media.retroachievements.org/Images/016421.png', 'https://media.retroachievements.org/Images/016410.png', 'https://media.retroachievements.org/Images/016415.png', 4.3),
  (92, 12082, 'Double Dragon', 'Arcade', 27, 1202, 1202, 1202, 16, 0, 'Beat ''em Up', 'Technos Japan', 'Taito', '1987-01-01', 'Double Dragon  is a beat ''em up video game series originally developed and published by Technōs Japan. It began with the release of the arcade game Double Dragon in 1987. The series features twin martial artists, Billy and Jimmy Lee, as they fight against various adversaries and rivals.', 'https://media.retroachievements.org/Images/049791.png', 'https://media.retroachievements.org/Images/055660.png', 'https://media.retroachievements.org/Images/054631.png', 'https://media.retroachievements.org/Images/054632.png', 4.3),
  (93, 12149, 'Ghosts ''n Goblins', 'Arcade', 27, 1198, 1198, 1198, 42, 0, NULL, 'Capcom', 'Capcom', '1985-09-01', 'Ghosts ''n Goblins, known in Japan as Makaimura , is a series of run-and-gun platform video games developed and owned by Capcom. The first entry in the series was Ghosts ''n Goblins, released in arcades on July 7, 1985. The series has subsequently been ported to and released on a variety of personal computers, game consoles and mobile platforms and spawned several sequels and spin-offs.', 'https://media.retroachievements.org/Images/119126.png', 'https://media.retroachievements.org/Images/050116.png', 'https://media.retroachievements.org/Images/032357.png', 'https://media.retroachievements.org/Images/044934.png', 4.3),
  (94, 12661, 'Double Dragon (Neo-Geo)', 'Arcade', 27, 1195, 1195, 1195, 38, 0, '2D Fighting', 'Technōs Japan', 'Technōs Japan', '1995-02-01', 'Double Dragon  is a beat ''em up video game series originally developed and published by Technōs Japan. It began with the release of the arcade game Double Dragon in 1987. The series features twin martial artists, Billy and Jimmy Lee, as they fight against various adversaries and rivals.', 'https://media.retroachievements.org/Images/120099.png', 'https://media.retroachievements.org/Images/048755.png', 'https://media.retroachievements.org/Images/063513.png', 'https://media.retroachievements.org/Images/048756.png', 4.3),
  (95, 13566, 'Pachinko Sexy Reaction', 'Arcade', 27, 1187, 1187, 1187, 15, 0, 'Casino, Pachinko', 'Sammy', 'Sammy', '1998-01-01', 'The Sega Saturn is a 32-bit fifth-generation home video game console that was developed by Sega and first released on November 22, 1994. Its games are in CD-ROM format, and its game library contains several arcade ports as well as original titles. There are 1028 games on this list not including non-game software and compilations of Saturn games. 775 of those games were released as Japan-only exclusives, which makes up 75% of the list. For games that were announced or in development for the Saturn, but never released, see the list of cancelled Sega Saturn games.', 'https://media.retroachievements.org/Images/034082.png', 'https://media.retroachievements.org/Images/034109.png', 'https://media.retroachievements.org/Images/021172.png', 'https://media.retroachievements.org/Images/034083.png', 4.3),
  (96, 11979, 'U.N. Squadron', 'Arcade', 27, 1173, 1173, 1173, 52, 0, 'Shoot ''em Up', 'Capcom', 'Capcom', '1989-08-01', 'U.N. Squadron, released in Japan as Area 88, is a 1989 side-scrolling shooter video game developed and published by Capcom for arcades. It was based on the manga series of the same name, though the North American release omits all references to the manga. Their mission is to stop a terrorist group known as Project 4. It was ported to multiple platforms including the Super Nintendo Entertainment System and was followed by a spiritual successor, Carrier Air Wing.', 'https://media.retroachievements.org/Images/061639.png', 'https://media.retroachievements.org/Images/061309.png', 'https://media.retroachievements.org/Images/061344.png', 'https://media.retroachievements.org/Images/061342.png', 4.3),
  (97, 17469, 'SegaSonic the Hedgehog', 'Arcade', 27, 1170, 1170, 1170, 40, 0, '2.5D Platforming', NULL, 'Sega', '1993-06-01', 'SegaSonic the Hedgehog is a 1993 arcade game in the Sonic the Hedgehog series by Sega. Controlling Sonic the Hedgehog and his friends Mighty the Armadillo and Ray the Flying Squirrel, the player must escape an island after they are kidnapped by the villain, Doctor Eggman. The game uses an isometric perspective. Players use a trackball to move the characters while dodging obstacles and collecting rings. The game was developed by Sega''s arcade division, Sega AM3. It is one of four Sonic games with the SegaSonic name and was inspired by the 1984 game Marble Madness.', 'https://media.retroachievements.org/Images/108435.png', 'https://media.retroachievements.org/Images/049039.png', 'https://media.retroachievements.org/Images/049031.png', 'https://media.retroachievements.org/Images/049032.png', 4.3),
  (98, 13250, 'Night Slashers', 'Arcade', 27, 1158, 1158, 1158, 32, 0, 'Beat ''em Up', 'Data East', 'Data East', '1993-09-01', 'Night Slashers (ナイトスラッシャーズ) is a 1993 beat ''em up game developed and published by Data East for arcades. A remake for major platforms was licensed to Forever Entertainment, developed by Storm Trident, and released in September 2024.', 'https://media.retroachievements.org/Images/113579.png', 'https://media.retroachievements.org/Images/019178.png', 'https://media.retroachievements.org/Images/019179.png', 'https://media.retroachievements.org/Images/019180.png', 4.2),
  (99, 13815, 'Super Sidekicks 3: The Next Glory', 'Arcade', 27, 1158, 1158, 1158, 21, 0, NULL, 'SNK', 'SNK', '1995-03-01', 'Super Sidekicks 3: The Next Glory is a 1995 soccer arcade video game developed and published by SNK. It is the third installment in the Super Sidekicks series, succeeding Super Sidekicks 2: The World Championship (1994). Featuring an arcade-style approach to soccer like its predecessors, the game allows players to choose any of the available game modes to compete with AI-controlled rivals or other human players with their preferred team. Though first launched for the MVS hardware, the title was ported for Neo Geo AES and Neo Geo CD, in addition of being re-released through compilations and download services for various consoles. It proved popular among players and garnered positive reception from critics, but most reviewers noted that it felt more an update than a true successor to Super Sidekicks 2. It was followed by The Ultimate 11: SNK Football Championship in 1996.', 'https://media.retroachievements.org/Images/067066.png', 'https://media.retroachievements.org/Images/067065.png', 'https://media.retroachievements.org/Images/068062.png', 'https://media.retroachievements.org/Images/068063.png', 4.2),
  (100, 11760, 'Zed Blade', 'Arcade', 27, 1149, 1149, 1149, 43, 0, 'Shoot ''em Up', 'NMK', 'NMK', '1994-09-01', 'Arcade Archives is a series of emulated arcade games developed and published by Hamster Corporation. A sub-series called ACA Neo Geo focuses on re-releasing SNK''s Neo Geo titles in their original MVS arcade format, unlike many services that attempt to emulate the console versions. Individual games are released in a weekly format. Another sub-series called Console Archives focuses on releasing home console video games.', 'https://media.retroachievements.org/Images/032828.png', 'https://media.retroachievements.org/Images/032829.png', 'https://media.retroachievements.org/Images/022360.png', 'https://media.retroachievements.org/Images/022361.png', 4.2),
  (101, 12526, 'Space Invaders', 'Arcade', 27, 1125, 1125, 1125, 22, 0, 'Shoot ''em Up', NULL, 'LAI Games, Midway, Taito', '1978-04-19', 'Space Invaders is a 1978 shoot ''em up video game developed and published by Taito for arcades. It was released in Japan in April 1978, and released overseas by Midway Manufacturing later that year. Space Invaders was the first video game with endless gameplay and the first fixed shooter, setting the template for the genre. The goal is to defeat waves of descending aliens with a horizontally moving laser cannon to earn as many points as possible.', 'https://media.retroachievements.org/Images/069896.png', 'https://media.retroachievements.org/Images/066548.png', 'https://media.retroachievements.org/Images/069779.png', 'https://media.retroachievements.org/Images/069781.png', 4.2),
  (102, 12816, 'Goal! Goal! Goal!', 'Arcade', 27, 1120, 1120, 1120, 50, 0, 'Sports - Football | Soccer', 'Visco', 'Visco', '1995-01-01', 'Goal! Goal! Goal! is a football/soccer video game developed by Visco and published by SNK in 1995 for the Neo-Geo console.', 'https://media.retroachievements.org/Images/063175.png', 'https://media.retroachievements.org/Images/017138.png', 'https://media.retroachievements.org/Images/017141.png', 'https://media.retroachievements.org/Images/028322.png', 4.2),
  (103, 12028, 'The King of Fighters ''94', 'Arcade', 27, 1109, 1109, 1109, 49, 0, NULL, 'SNK', 'SNK', '1994-08-01', 'The King of Fighters ''94 is a fighting game released in 1994, developed and published by SNK for the Neo Geo MVS arcade system, AES, and CD home consoles. It is a crossover game, featuring characters from SNK’s earlier titles, including Fatal Fury and Art of Fighting, updated versions of characters from Ikari Warriors and Psycho Soldier, and new, original characters. The story centers around the tournament organized by the antagonist Rugal Bernstein.', 'https://media.retroachievements.org/Images/109363.png', 'https://media.retroachievements.org/Images/016419.png', 'https://media.retroachievements.org/Images/016407.png', 'https://media.retroachievements.org/Images/016413.png', 4.2),
  (104, 12165, 'GunForce II', 'Arcade', 27, 1108, 1108, 1108, 28, 0, 'Run & Gun', 'Irem', 'Irem', '1994-09-01', 'GunForce II is a run and gun arcade video game developed and originally published by Irem in September 1994. It is the sequel to the original GunForce and one of the last arcade games, if not the last to be released by the company before ceasing development of video games in the same year, after which a group of employees from the gaming division of Irem would go on to form Nazca Corporation due to being tired of the company''s inactivity.', 'https://media.retroachievements.org/Images/063750.png', 'https://media.retroachievements.org/Images/030974.png', 'https://media.retroachievements.org/Images/030972.png', 'https://media.retroachievements.org/Images/063648.png', 4.2),
  (105, 21889, 'Deathsmiles', 'Arcade', 27, 1107, 1107, 1107, 48, 0, 'Shoot ''em Up, Bullet Hell', 'CAVE Interactive', 'AMI', '2007-10-19', 'Deathsmiles  is a horizontally scrolling shooter arcade video game by Japanese developer Cave, released in late 2007. It has heavy occult and gothic influences. It is the second Cave shooter to be played using a horizontally-oriented monitor. It was the first Cave shooter released in North America on a console, and the first one in Europe. Cave has also released it for iOS. A sequel, Deathsmiles II, was released to Japanese arcades on May 14, 2009. A compilation of both Deathsmiles I and Deathsmiles II was released for PlayStation 4, Xbox One and Nintendo Switch in Japan on December 16, 2021.', 'https://media.retroachievements.org/Images/113433.png', 'https://media.retroachievements.org/Images/091983.png', 'https://media.retroachievements.org/Images/084828.png', 'https://media.retroachievements.org/Images/091984.png', 4.2),
  (106, 12163, 'Gunbird', 'Arcade', 27, 1107, 1107, 1107, 19, 0, 'Shoot ''em Up', 'Psikyo', 'Psikyo, Jaleco', '1993-03-22', 'Gunbird (ガンバード) is a vertically scrolling shooter developed by Psikyo and released as an arcade video game in 1994. In the US, it was published by Jaleco. It has been re-released multiple times, including on the Sega Saturn, PlayStation, Steam, Nintendo Switch, PlayStation 4 and Xbox One. When originally localized outside Japan by XS Games, Gunbird was retitled Mobile Light Force. The game was followed by Gunbird 2 in 1998 and was included in Gunbird Special Edition for PlayStation 2.', 'https://media.retroachievements.org/Images/077869.png', 'https://media.retroachievements.org/Images/077922.png', 'https://media.retroachievements.org/Images/077867.png', 'https://media.retroachievements.org/Images/077868.png', 4.2),
  (107, 11805, 'Street Fighter Alpha: Warriors'' Dreams', 'Arcade', 27, 1107, 1107, 1107, 44, 0, '2D Fighting', 'Capcom', 'Capcom', '1995-01-01', 'Street Fighter Alpha: Warriors'' Dreams, known as Street Fighter Zero in Japan, Asia, South America, and Oceania, is a 1995 fighting game developed and published by Capcom for arcades. It was the first all-new Street Fighter game produced by Capcom since 1991''s Street Fighter II. Plotwise, it serves as a prequel to Street Fighter II and thus features younger versions of established characters, as well as characters from the original Street Fighter and Final Fight.', 'https://media.retroachievements.org/Images/016030.png', 'https://media.retroachievements.org/Images/016029.png', 'https://media.retroachievements.org/Images/016027.png', 'https://media.retroachievements.org/Images/016028.png', 4.2),
  (108, 12538, 'Magical Drop III', 'Arcade', 27, 1089, 1089, 1089, 54, 0, 'Tile Matching', 'Data East', 'Data East', '1997-02-25', 'Magical Drop III is a 1997 puzzle video game developed and published by Data East for the Neo Geo arcade and home platforms. It was later ported to Sega Saturn, PlayStation, Neo Geo Pocket Color, Game Boy Color, Windows, and Zeebo. It is the third entry in the Magical Drop series. In the game, the player takes control of one of several characters, battling against computer-controlled opponents. Gameplay is similar to previous entries albeit with further additions; the objective is to clear the screen of constantly advancing colored ''drops'' via a character placed at the bottom of the playfield, which can grab drops and make them disappear by putting drops as a column of three or more of the same color. The player can also participate in a board-style adventure mode, while two players can play against each other in a competitive versus mode.', 'https://media.retroachievements.org/Images/077204.png', 'https://media.retroachievements.org/Images/076382.png', 'https://media.retroachievements.org/Images/099432.png', 'https://media.retroachievements.org/Images/099795.png', 4.2),
  (109, 17540, 'Battletoads', 'Arcade', 27, 1077, 1077, 1077, 55, 0, 'Beat ''em Up, Action', 'Rare', 'Electronic Arts', '1994-01-01', 'Battletoads is a video game franchise by Rare that began with the original beat ''em up game Battletoads in 1991. Starring three anthropomorphic toads named after skin conditions, Rash, Zitz, and Pimple, the series was created to rival the Teenage Mutant Ninja Turtles games series. The original Battletoads game for the NES was renowned for its extreme difficulty, but still received a cult following, spawning sequels for various platforms including a crossover with the Double Dragon series and a modern reboot after a 25-year gap in releases. In each of the games, the objective is to defeat the toads'' nemesis the Dark Queen and her army of space mutants.', 'https://media.retroachievements.org/Images/048857.png', 'https://media.retroachievements.org/Images/042978.png', 'https://media.retroachievements.org/Images/042980.png', 'https://media.retroachievements.org/Images/042979.png', 4.2),
  (110, 12514, 'Toki', 'Arcade', 27, 1070, 1070, 1070, 24, 0, '2D Platforming', 'TAD', 'TAD', '1989-01-01', 'Toki Pona is a philosophical and artistic constructed language designed for its small vocabulary, simplicity, and ease of acquisition. It was created by Canadian translator and polyglot Sonja Lang with the stated purpose of simplifying her thoughts and communication. The first drafts were published online in 2001, while the complete form was published in the 2014 book Toki Pona: The Language of Good. Lang also released a supplementary dictionary, the Toki Pona Dictionary, in July 2021, describing the language as used by its community of speakers. In 2024, a third book was released, a Toki Pona adaptation of The Wonderful Wizard of Oz, written in Sitelen Pona.', 'https://media.retroachievements.org/Images/042097.png', 'https://media.retroachievements.org/Images/035639.png', 'https://media.retroachievements.org/Images/035638.png', 'https://media.retroachievements.org/Images/035637.png', 4.2),
  (111, 16492, 'Blood Bros.', 'Arcade', 27, 1069, 1069, 1069, 32, 0, 'Gallery Shooter', 'TAD', 'TAD', '1990-01-01', 'Blood Bros. is a 1990 arcade game developed and published by TAD Corporation in Japan and Europe, and later published in North America by Fabtek. It is a spiritual sequel to the 1988 game Cabal, with almost identical mechanics. A bootleg of Blood Bros. is known as West Story.', 'https://media.retroachievements.org/Images/036082.png', 'https://media.retroachievements.org/Images/036080.png', 'https://media.retroachievements.org/Images/036081.png', 'https://media.retroachievements.org/Images/035754.png', 4.2),
  (112, 11751, 'Blazing Star', 'Arcade', 27, 1061, 1061, 1061, 50, 0, 'Shoot ''em Up', 'Yumekobo', 'SNK', '1998-01-01', 'Blazing Star is a 1998 horizontally scrolling shooter video game developed by Yumekobo and published by SNK for the Neo Geo arcade and home systems. It is a follow-up to Pulstar (1995), and features side-scrolling action similar to its predecessor and different ships with varying characteristics. It was made less challenging than its predecessor, and the graphic quality was improved upon.', 'https://media.retroachievements.org/Images/016053.png', 'https://media.retroachievements.org/Images/016046.png', 'https://media.retroachievements.org/Images/016586.png', 'https://media.retroachievements.org/Images/016587.png', 4.2),
  (113, 12230, 'Super Gem Fighter: Mini Mix', 'Arcade', 27, 1052, 1052, 1052, 50, 0, '2D Fighting', 'Capcom', 'Capcom', '1997-09-01', 'Super Gem Fighter Mini Mix, also released as Pocket Fighter  in Japan, is a 1997 fighting game developed and published by Capcom for arcades. The game uses the same super deformed character designs previously used in Super Puzzle Fighter II Turbo, a puzzle game by Capcom. It was ported in 1998 to the PlayStation, which retained the Pocket Fighter title for its North American and PAL releases, and then the Sega Saturn and WonderSwan, both in Japan only.', 'https://media.retroachievements.org/Images/108609.png', 'https://media.retroachievements.org/Images/037751.png', 'https://media.retroachievements.org/Images/037750.png', 'https://media.retroachievements.org/Images/037747.png', 4.2),
  (114, 12029, 'The King of Fighters ''95', 'Arcade', 27, 1052, 1052, 1052, 57, 0, '2D Fighting', 'SNK', 'SNK', '1995-07-01', 'The King of Fighters ''95 (KOF ''95) is a 1995 fighting video game developed and published by SNK for the Neo Geo arcade system. It is the sequel to The King of Fighters ''94, and the second installment in The King of Fighters series. The game features a similar cast to KOF ''94 with the exception of the USA Team, which was replaced by the Rival Team. The plot features a new King of Fighters tournament once again promoted by the criminal Rugal Bernstein, who seeks revenge against the protagonist Kyo Kusanagi, who defeated him in last year''s tournament. KOF ''95 marks the first appearance of the fighter Iori Yagami, who becomes Kyo''s rival in the series.', 'https://media.retroachievements.org/Images/120959.png', 'https://media.retroachievements.org/Images/016420.png', 'https://media.retroachievements.org/Images/016408.png', 'https://media.retroachievements.org/Images/016414.png', 4.2),
  (115, 11900, 'Mega Man 2: The Power Fighters', 'Arcade', 27, 1051, 1051, 1051, 91, 0, '2D Fighting', 'Capcom', 'Capcom', '1996-08-01', 'Mega Man 2: The Power Fighters is a 1996 fighting game developed and published by Capcom for arcades. A spin-off of the Mega Man series, it is the direct sequel to Mega Man: The Power Battle released the previous year. Both games have since received home releases through various video game compilations.', 'https://media.retroachievements.org/Images/035106.png', 'https://media.retroachievements.org/Images/020122.png', 'https://media.retroachievements.org/Images/019737.png', 'https://media.retroachievements.org/Images/019736.png', 4.2),
  (116, 5645, 'Gaia Crusaders', 'Arcade', 27, 1037, 1037, 1037, 52, 0, 'Beat ''em Up', 'Noise Factory', 'Noise Factory', '1999-07-01', 'This is a list of notable video game companies that have made games for either computers, video game consoles, handheld or mobile devices, and includes companies that currently exist as well as now-defunct companies.', 'https://media.retroachievements.org/Images/038853.png', 'https://media.retroachievements.org/Images/038854.png', 'https://media.retroachievements.org/Images/029093.png', 'https://media.retroachievements.org/Images/029103.png', 4.2),
  (117, 13802, 'Samurai Shodown', 'Arcade', 27, 993, 993, 993, 54, 0, '2D Fighting', 'SNK', 'SNK', '1993-07-01', 'Samurai Shodown, known in Japan as Samurai Spirits, is a fighting game series by SNK. The series began in 1993 and is known for being one of the earliest in the genre with a primary focus on weapon-based combat.', 'https://media.retroachievements.org/Images/108414.png', 'https://media.retroachievements.org/Images/024968.png', 'https://media.retroachievements.org/Images/022214.png', 'https://media.retroachievements.org/Images/022215.png', 4.2),
  (118, 12175, 'Hang-On', 'Arcade', 27, 969, 969, 969, 20, 0, 'Racing', 'Sega', 'Sega', '1985-01-01', 'Hang-On is a 1985 racing video game developed and published by Sega for arcades. In the game, the player controls a motorcycle against time and other computer-controlled bikes. It was one of the first arcade games to use 16-bit graphics and uses the Super Scaler arcade system board, created with design input from Yu Suzuki, as technology to simulate 3D effects. The deluxe cabinet version also introduced a motion-controlled arcade cabinet, where the player''s body movement on a large motorbike-shaped cabinet corresponds with the player character''s movements on screen.', 'https://media.retroachievements.org/Images/053130.png', 'https://media.retroachievements.org/Images/054620.png', 'https://media.retroachievements.org/Images/054619.png', 'https://media.retroachievements.org/Images/054618.png', 4.2),
  (119, 11772, 'Street Fighter II: Champion Edition', 'Arcade', 27, 965, 965, 965, 35, 0, '2D Fighting', 'Capcom', 'Capcom', '1991-01-01', 'Street Fighter II: Champion Edition, released as Street Fighter II Dash in Japan, is a 1992 fighting game developed and published by Capcom for arcades. It is the first of several updated versions of Street Fighter II (1991), and part of the Street Fighter series. The main changes are the addition of the four grand masters as playable characters and mirror matches. The fighting techniques of the eight main characters from the original game were further balanced for competitive play.', 'https://media.retroachievements.org/Images/065742.png', 'https://media.retroachievements.org/Images/016395.png', 'https://media.retroachievements.org/Images/016381.png', 'https://media.retroachievements.org/Images/016388.png', 4.2),
  (120, 12364, 'Riot City', 'Arcade', 27, 964, 964, 964, 77, 0, 'Beat ''em Up', 'Westone', 'Sega', '1991-01-01', 'Riot City (ライオットシティ) is a 1991 2D beat ''em up arcade game developed by Westone and published by Sega.', 'https://media.retroachievements.org/Images/077526.png', 'https://media.retroachievements.org/Images/039242.png', 'https://media.retroachievements.org/Images/039240.png', 'https://media.retroachievements.org/Images/039241.png', 4.2),
  (121, 12002, 'Black Tiger', 'Arcade', 27, 954, 954, 954, 42, 0, '2D Platforming', 'Capcom', 'Capcom, Romstar', '1987-08-01', 'Black Tiger, known in Japan as Black Dragon, is a 1987 platform game developed and published by Capcom for arcades.', 'https://media.retroachievements.org/Images/072244.png', 'https://media.retroachievements.org/Images/057124.png', 'https://media.retroachievements.org/Images/057121.png', 'https://media.retroachievements.org/Images/057122.png', 4.2),
  (122, 11945, 'Donkey Kong 3', 'Arcade', 27, 941, 941, 941, 25, 0, NULL, NULL, 'Nintendo', '1983-01-01', 'Donkey Kong 3 is a 1983 shoot ''em up video game developed and published by Nintendo for arcades. It is the third installment in the Donkey Kong series, following 1982''s Donkey Kong Jr. It was ported to the Family Computer in 1984, then in North America for the Nintendo Entertainment System in 1986. The gameplay departs from previous Donkey Kong games, and it stars an exterminator named Stanley instead of Mario. The game was a modest financial success in Japan, but its commercial failure in the United States was later cited by commentators as contributing to a period of reduced activity for the series until the release of Donkey Kong (1994) and Donkey Kong Country.', 'https://media.retroachievements.org/Images/035742.png', 'https://media.retroachievements.org/Images/036712.png', 'https://media.retroachievements.org/Images/036713.png', 'https://media.retroachievements.org/Images/036714.png', 4.2),
  (123, 12751, 'DoDonPachi', 'Arcade', 27, 940, 940, 940, 53, 0, 'Shoot ''em Up, Bullet Hell', 'CAVE Interactive', 'Atlus', '1997-02-05', 'DoDonPachi is a 1997 vertically scrolling bullet hell video game developed by Cave and published by Atlus. It was the second game developed by Cave, and the sixth on Cave''s first-generation arcade hardware. As with its predecessor DonPachi, the title is both a Japanese term for expressing the sound of gunfire, and a term that relates to bees.', 'https://media.retroachievements.org/Images/057056.png', 'https://media.retroachievements.org/Images/056386.png', 'https://media.retroachievements.org/Images/057057.png', 'https://media.retroachievements.org/Images/057828.png', 4.2),
  (124, 12734, 'Super Sidekicks 2: The World Championship', 'Arcade', 27, 937, 937, 937, 23, 0, 'Sports - Football | Soccer', 'SNK', 'SNK', '1994-04-01', 'Super Sidekicks 2: The World Championship is a 1994 soccer arcade video game developed and published by SNK. It is the second installment in the Super Sidekicks series and the third soccer game released for Neo Geo MVS, preceding the original Super Sidekicks (1992). Featuring an arcade-style approach to soccer as its predecessor, the game allows players to choose any of the available game modes with AI-controlled opponents or other human players with the team of their choosing. Its gameplay uses a simplified three-button configuration.', 'https://media.retroachievements.org/Images/077485.png', 'https://media.retroachievements.org/Images/067064.png', 'https://media.retroachievements.org/Images/016673.png', 'https://media.retroachievements.org/Images/016672.png', 4.2),
  (125, 11812, 'Street Fighter Alpha 3', 'Arcade', 27, 929, 929, 929, 98, 0, '2D Fighting', 'Capcom', 'Capcom', '1998-08-01', 'Street Fighter Alpha 3, released as Street Fighter Zero 3 in Japan, Asia, South America, and Oceania, is a 1998 fighting game developed and published by Capcom for arcades. It is the third and final installment in the Street Fighter Alpha series, and runs on the same CP System II hardware as previous Alpha games. Alpha 3 further expanded the playable fighter roster from Street Fighter Alpha 2 and added new features such as selectable fighting styles called isms.', 'https://media.retroachievements.org/Images/061601.png', 'https://media.retroachievements.org/Images/016392.png', 'https://media.retroachievements.org/Images/057674.png', 'https://media.retroachievements.org/Images/057675.png', 4.2),
  (126, 12491, 'SegaSonic Cosmo Fighter Galaxy Patrol', 'Arcade', 27, 926, 926, 926, 11, 0, NULL, NULL, NULL, '1993-03-01', 'Sonic the Hedgehog is a video game series. It is published by Sega, with entries developed by Sega, Sonic Team, Traveller''s Tales, Dimps, SIMS Co., Ltd., BioWare, Hardlight, Aspect, Sumo Digital, Gameloft, Gamefam Studios, Arzest, and Rovio Entertainment. The series debuted in 1991 with the video game, Sonic the Hedgehog, released for the Mega Drive video game console. In its earliest history, most Sonic the Hedgehog games had been platform games released for Sega video game consoles and handheld game consoles (handhelds), dating from the Sega Genesis to the Sega Dreamcast. However, some of the original games were ported into versions on newer third-party home consoles and developed by various companies. As of March 2011, the series has collectively sold 89 million copies worldwide across both the platform games and spin-offs.', 'https://media.retroachievements.org/Images/108339.png', 'https://media.retroachievements.org/Images/062243.png', 'https://media.retroachievements.org/Images/062240.png', 'https://media.retroachievements.org/Images/062241.png', 4.2),
  (127, 15003, 'Tapper', 'Arcade', 27, 915, 915, 915, 15, 0, 'Action', 'Marvin Glass and Associates', 'Midway, Sega', '1984-02-01', 'Jacob Paul Tapper is an American journalist. He is the lead Washington anchor for CNN, hosts the weekday television news show The Lead with Jake Tapper, and co-hosts the Sunday morning public affairs program State of the Union.', 'https://media.retroachievements.org/Images/060809.png', 'https://media.retroachievements.org/Images/124750.png', 'https://media.retroachievements.org/Images/034266.png', 'https://media.retroachievements.org/Images/034267.png', 4.2),
  (128, 12008, 'Blade Master', 'Arcade', 27, 912, 912, 912, 56, 0, 'Beat ''em Up', 'Irem', 'Irem', '1991-01-01', 'Blade Master is a 1991 hack and slash video game developed and published by Irem for arcades. Two selectable heroes, Roy and Arnold, try to save their land from hordes of monsters. There are items to break and power-ups to collect, typical of this genre in the 1990s.', 'https://media.retroachievements.org/Images/038426.png', 'https://media.retroachievements.org/Images/037608.png', 'https://media.retroachievements.org/Images/037606.png', 'https://media.retroachievements.org/Images/037607.png', 4.2),
  (129, 15039, 'Berzerk', 'Arcade', 27, 904, 904, 904, 10, 0, NULL, 'Stern Electronics', 'Stern Electronics', '1980-11-12', 'Berzerk is a song by American rapper Eminem. The song, released on August 27, 2013, is the first single from Eminem''s eighth studio album The Marshall Mathers LP 2. The song was produced by Rick Rubin and samples Billy Squier''s The Stroke, as well as the Beastie Boys'' Fight for Your Right, taken from their 1986 debut album Licensed to Ill, which Rubin had also produced, and Naughty by Nature''s Feel Me Flow. The song was heavily downloaded in its first week of release, resulting in the song debuting at number three on the US Billboard Hot 100.', 'https://media.retroachievements.org/Images/101489.png', 'https://media.retroachievements.org/Images/093845.png', 'https://media.retroachievements.org/Images/093843.png', 'https://media.retroachievements.org/Images/093844.png', 4.2),
  (130, 12560, 'Wonder Boy', 'Arcade', 27, 903, 903, 903, 28, 0, 'Action', NULL, NULL, '1986-01-01', 'Wonder Boy is a 1986 platform game developed by Escape and published by Sega for arcades. It was later ported to the SG-1000, Master System and Game Gear video game consoles by Sega, and to the ZX Spectrum, Commodore 64 and Amstrad CPC home computers by Activision. The game is also known as Super Wonder Boy  for its Sega Mark III release in Japan and Revenge of Drancon for its Game Gear release in North America. A high definition remake of the game, titled Wonder Boy Returns, was developed by CFK and released on Steam on October 12, 2016.', 'https://media.retroachievements.org/Images/024668.png', 'https://media.retroachievements.org/Images/024667.png', 'https://media.retroachievements.org/Images/024665.png', 'https://media.retroachievements.org/Images/024666.png', 4.2),
  (131, 12774, 'Red Earth', 'Arcade', 27, 897, 897, 897, 35, 0, '2D Fighting', 'Capcom', 'Capcom', '1996-11-21', 'Red Earth, released in Japan as Warzard , is a 1996 fighting game developed and published by Capcom for arcades. It was the first game for Capcom''s CP System III hardware, the same hardware which Street Fighter III and its derivatives ran on. Red Earth received its first home console port as a part of the Capcom Fighting Collection in June 2022 for PlayStation 4, Xbox One, Nintendo Switch, and PC.', 'https://media.retroachievements.org/Images/098330.png', 'https://media.retroachievements.org/Images/065070.png', 'https://media.retroachievements.org/Images/065072.png', 'https://media.retroachievements.org/Images/065071.png', 4.2),
  (132, 12342, 'Prehistoric Isle in 1930', 'Arcade', 27, 893, 893, 893, 27, 0, 'Shoot ''em Up', 'SNK', 'SNK', '1989-05-01', 'Prehistoric Isle is a 1989 scrolling shooter arcade video game originally developed and published by SNK. Set during the 1930s, where ships at The Bahamas mysteriously disappeared, players assume the role of U.S. Marine pilots taking control of biplanes in a reconnaissance assignment at Greenhell Isle, a fictional island inhabited by dinosaurs and creatures thought to be extinct. Headed by a director under the pseudonym of Yah!, the game was developed by most of the same team that would later work on several projects for the Neo Geo platforms at SNK. First launched in arcades, the title has since been re-released through download services and compilations for various consoles. It received positive reception since its initial arcade release from critics who praised the visuals, sound design, gameplay and originality. A sequel, Prehistoric Isle 2, was released in 1999 for the Neo Geo MVS but garnered less success than its predecessor.', 'https://media.retroachievements.org/Images/035448.png', 'https://media.retroachievements.org/Images/035425.png', 'https://media.retroachievements.org/Images/035423.png', 'https://media.retroachievements.org/Images/035424.png', 4.2),
  (133, 12052, 'Cabal', 'Arcade', 27, 891, 891, 891, 34, 0, 'Gallery Shooter', 'TAD', 'Fabtek', '1988-09-01', 'A cabal is a group of people who are united in some close design, usually to promote their private views or interests in an ideology, a state, or another community, often by intrigue and usually without the knowledge of those who are outside their group. The use of this term usually carries negative connotations of political purpose, conspiracy and secrecy. It can also refer to a secret plot or a clique, or it may be used as a verb.', 'https://media.retroachievements.org/Images/036126.png', 'https://media.retroachievements.org/Images/036125.png', 'https://media.retroachievements.org/Images/036123.png', 'https://media.retroachievements.org/Images/036124.png', 4.2),
  (134, 12114, 'ESP Ra.De.', 'Arcade', 27, 891, 891, 891, 36, 0, 'Shoot ''em Up', 'CAVE Interactive', 'Atlus', '1998-04-14', 'ESP Ra.De. is a 1998 bullet hell vertically scrolling shooter originally developed by Cave as an arcade video game and co-published by Atlus and Nihon System in Japan. Set in the year 2018, players assume the role from one of the three ESPers to overthrow Lady Garra and her Yaska syndicate from taking over Tokyo.', 'https://media.retroachievements.org/Images/080597.png', 'https://media.retroachievements.org/Images/039343.png', 'https://media.retroachievements.org/Images/039341.png', 'https://media.retroachievements.org/Images/039342.png', 4.2),
  (135, 11836, 'Willow', 'Arcade', 27, 890, 890, 890, 24, 0, '2D Platforming', 'Capcom', 'Capcom', '1988-01-01', 'Willows, also called sallows and osiers, of the genus Salix, comprise around 350 species of typically deciduous trees and shrubs. They are primarily found on moist soils in cold and temperate regions.', 'https://media.retroachievements.org/Images/047625.png', 'https://media.retroachievements.org/Images/016144.png', 'https://media.retroachievements.org/Images/016145.png', 'https://media.retroachievements.org/Images/016146.png', 4.2),
  (136, 12792, 'Last Resort', 'Arcade', 27, 872, 872, 872, 23, 0, 'Shoot ''em Up', 'SNK', 'SNK', '1992-03-01', 'Last Resort is a 1992 horizontally scrolling shooter video game developed and published by SNK for the Neo Geo MVS arcade system. It was ported to the Neo Geo AES and Neo Geo CD consoles, and was later re-released as part of SNK Arcade Classics Vol. 1 for the PlayStation 2, PlayStation Portable, and Wii. In 2017, it was re-released for the Nintendo Switch, PlayStation 4, and Xbox One as part of the ACA Neo Geo series.', 'https://media.retroachievements.org/Images/033962.png', 'https://media.retroachievements.org/Images/033963.png', 'https://media.retroachievements.org/Images/022068.png', 'https://media.retroachievements.org/Images/022069.png', 4.2),
  (137, 12173, 'Gyruss', 'Arcade', 27, 867, 867, 867, 23, 0, 'Shoot ''em Up', 'Konami', 'Konami', '1983-01-01', 'Gyruss  is a 1983 tube shooter video game developed and published by Konami for Japanese arcades. It was initially licensed to Centuri in North America for dedicated machines before Konami released their own self-distributed conversion kits for the game. Parker Brothers released ports for the Atari 2600, Atari 5200, Atari 8-bit computers, ColecoVision and Commodore 64 in 1984. An enhanced version for the Famicom Disk System was released in 1988, followed by the Nintendo Entertainment System in 1989.', 'https://media.retroachievements.org/Images/035482.png', 'https://media.retroachievements.org/Images/035890.png', 'https://media.retroachievements.org/Images/035888.png', 'https://media.retroachievements.org/Images/035889.png', 4.2),
  (138, 12180, 'Hammerin'' Harry', 'Arcade', 27, 867, 867, 867, 23, 0, '2D Platforming', 'Irem', 'Irem', '1990-12-01', 'Hammerin'' Harry, known in Japan as Daiku no Gen-san , is a series of platforming video games developed and published by Irem in 1990. The titles were developed and published for the arcades, Famicom, Game Boy, Super Famicom and Sony PSP platforms. The series is centered around the titular Harry, a hammer-wielding carpenter who protects his hometown of Beranme from the corrupt construction companies that mean to tear it down.', 'https://media.retroachievements.org/Images/090490.png', 'https://media.retroachievements.org/Images/030984.png', 'https://media.retroachievements.org/Images/030982.png', 'https://media.retroachievements.org/Images/030983.png', 4.2),
  (139, 11774, 'Aero Fighters 2 (AES)', 'Arcade', 27, 865, 865, 865, 42, 0, 'Shoot ''em Up', 'Video System', 'SNK', '1994-07-18', 'Aero Fighters 2 is a 1994 vertically scrolling shooter video game developed by Video System and published by SNK for the Neo Geo MVS arcade system. It is the second installment of the Aero Fighters series, followed by the sequel Aero Fighters 3 (1995) and the spin-off Aero Fighters Assault (1997).', 'https://media.retroachievements.org/Images/117822.png', 'https://media.retroachievements.org/Images/021862.png', 'https://media.retroachievements.org/Images/021864.png', 'https://media.retroachievements.org/Images/021863.png', 4.2),
  (140, 12442, 'Superman', 'Arcade', 27, 861, 861, 861, 8, 0, 'Beat ''em Up', 'Taito', 'Taito', '1989-02-01', 'Superman is a superhero who appears in American comic books published by DC Comics. Superman was created by writer Jerry Siegel and artist Joe Shuster, and debuted in issue #1 of Action Comics, published in the United States on April 18, 1938. Superman has been regularly published in American comic books since then, and has been adapted to other media including radio serials, novels, films, television shows, theater, and video games. Superman is the archetypal superhero: he wears an outlandish costume, uses a codename, and fights evil and averts disasters with the aid of extraordinary abilities. Although there are earlier characters who arguably fit this definition, it was Superman who popularized the superhero genre and established its conventions. He was the best-selling superhero in American comic books up until the 1980s and remains the highest grossing superhero if one considers the entire history of the genre.', 'https://media.retroachievements.org/Images/055703.png', 'https://media.retroachievements.org/Images/056333.png', 'https://media.retroachievements.org/Images/021082.png', 'https://media.retroachievements.org/Images/021083.png', 4.2),
  (141, 12152, 'G.I. Joe: A Real American Hero', 'Arcade', 27, 860, 860, 860, 22, 0, 'Rail Shooter', 'Konami', 'Konami', '1992-01-01', 'G.I. Joe: A Real American Hero is a military-themed line of action figures and toys in Hasbro''s G.I. Joe franchise. The toyline lasted from 1982 to 1994, producing well over 500 figures and 250 vehicles and playsets. The line reappeared in 1997 and has continued in one form or another to the present day. It was supported by two animated series as well as a major comic series published by Marvel Comics.', 'https://media.retroachievements.org/Images/019157.png', 'https://media.retroachievements.org/Images/019156.png', 'https://media.retroachievements.org/Images/019154.png', 'https://media.retroachievements.org/Images/019613.png', 4.2),
  (142, 14880, 'Demon Front', 'Arcade', 27, 859, 859, 859, 32, 0, NULL, 'IGS', 'IGS', '2002-06-25', 'Demon Front is a side-scrolling run and gun arcade game released in 2002 by International Games System. It shares many characteristics with the Metal Slug series.', 'https://media.retroachievements.org/Images/035897.png', 'https://media.retroachievements.org/Images/035815.png', 'https://media.retroachievements.org/Images/035895.png', 'https://media.retroachievements.org/Images/035896.png', 4.2),
  (143, 11927, 'Michael Jackson''s Moonwalker', 'Arcade', 27, 855, 855, 855, 17, 0, 'Beat ''em Up', 'Sega', 'Sega', '1990-07-20', 'In 1990, several video games based on the 1988 Michael Jackson film Moonwalker, all named Michael Jackson''s Moonwalker, were released. Sega developed two beat ''em ups, one released in arcades and another released for the Sega Genesis and Master System consoles. U.S. Gold also published various games for home computers. Each of the games'' plots loosely follows the Smooth Criminal segment of the film, in which Jackson rescues kidnapped children from the evil Mr. Big, and incorporates synthesized versions of some of the musician''s songs. Following Moonwalker, Jackson collaborated with Sega on several other video games.', 'https://media.retroachievements.org/Images/049915.png', 'https://media.retroachievements.org/Images/047923.png', 'https://media.retroachievements.org/Images/047918.png', 'https://media.retroachievements.org/Images/047919.png', 4.2),
  (144, 28948, 'Muchi Muchi Pork!', 'Arcade', 27, 847, 847, 847, 28, 0, 'Shoot ''em Up, Bullet Hell', 'CAVE Interactive', 'AMI', '2007-04-26', 'Muchi Muchi Pork!  is a 2007 arcade bullet hell cute ''em up developed by CAVE, and published by AMI. It was also ported to the Xbox 360 as part of the Muchi Muchi Pork!/Pink Sweets compilation disc produced by CAVE in February 2011.', 'https://media.retroachievements.org/Images/119089.png', 'https://media.retroachievements.org/Images/092230.png', 'https://media.retroachievements.org/Images/092231.png', 'https://media.retroachievements.org/Images/092232.png', 4.2),
  (145, 12075, 'Darius', 'Arcade', 27, 843, 843, 843, 40, 0, 'Shoot ''em Up', NULL, NULL, '1987-01-01', 'Darius is a 1987 horizontally scrolling shooter video game developed and published by Taito for arcades. Players control a starship named the Silver Hawk in its mission to destroy the Belser empire before they wipe out the planet Darius. Its gameplay involves traversing through a series of scrolling levels while destroying enemies and collecting power-up icons. It is notable for its unique three-screen panoramic display.', 'https://media.retroachievements.org/Images/109230.png', 'https://media.retroachievements.org/Images/096331.png', 'https://media.retroachievements.org/Images/096329.png', 'https://media.retroachievements.org/Images/096330.png', 4.2),
  (146, 13819, 'Thrash Rally', 'Arcade', 27, 823, 823, 823, 18, 0, 'Arcade Racing', 'ADK', 'ADK', '1991-11-01', 'Thrash Rally is a racing game developed by Alpha Denshi and released by SNK for the Neo Geo system. It was released by SNK on December 20, 1991, and was followed by Over Top, a spiritual successor, in 1996.', 'https://media.retroachievements.org/Images/041575.png', 'https://media.retroachievements.org/Images/041576.png', 'https://media.retroachievements.org/Images/022336.png', 'https://media.retroachievements.org/Images/022337.png', 4.1),
  (147, 12219, 'Mighty! Pang', 'Arcade', 27, 820, 820, 820, 62, 0, 'Action', 'Mitchell', 'Mitchell, Capcom', '2000-11-01', 'Pang, originally released in Japan as Pomping World and known in North America as Buster Bros., is a 1989 action game co-produced by Mitchell Corporation and Capcom for arcades. Mitchell handled the game''s domestic and most worldwide distribution, while Capcom handled the bulk of development, and distributed the game in North American territories.', 'https://media.retroachievements.org/Images/096382.png', 'https://media.retroachievements.org/Images/024659.png', 'https://media.retroachievements.org/Images/024657.png', 'https://media.retroachievements.org/Images/024658.png', 4.1),
  (148, 18684, 'Gun Survivor 2 BIOHAZARD CODE: Veronica', 'Arcade', 27, 815, 815, 815, 41, 0, 'First-Person Shooter, Horror', 'Capcom', 'Capcom', '2001-07-01', 'Resident Evil Survivor 2 – Code: Veronica is a light gun shooter video game developed by Namco and published by Capcom as part of the Resident Evil series. The arcade version was developed in conjunction with Namco for the arcade machines. The game was released for Sega NAOMI and PlayStation 2. It was released on the PlayStation 2 on November 7, 2001, in Japan and in Europe on March 22, 2002. Whilst the PlayStation 2 release is a light gun shooter, the NAOMI arcade release features no lightgun technology whatsoever, instead deferring control of each player entirely to a three-axis joystick in the shape of a gun. The game is the second installment in the Gun Survivor series and the sequel to Resident Evil Survivor. The game is adapted from Resident Evil – Code: Veronica and features enemies and characters from that game, and enemies from Resident Evil 2 and 3. It was followed by Dino Stalker which is a spin-off of Dino Crisis, and has no ties to Resident Evil.', 'https://media.retroachievements.org/Images/071840.png', 'https://media.retroachievements.org/Images/055606.png', 'https://media.retroachievements.org/Images/054002.png', 'https://media.retroachievements.org/Images/054001.png', 4.1),
  (149, 28949, 'Akai Katana', 'Arcade', 27, 810, 810, 810, 26, 0, 'Shoot ''em Up, Bullet Hell', 'CAVE Interactive', 'CAVE Interactive', '2010-08-20', 'Akai Katana is a horizontally scrolling shooter bullet hell developed by Cave and released in Japan on August 20, 2010 for arcades. A port to the Xbox 360 with additional game modes, Akai Katana Shin, followed on May 26, 2011. Rising Star Games published the console release in North America and Europe on May 15, 2012 simply as Akai Katana.', 'https://media.retroachievements.org/Images/120905.png', 'https://media.retroachievements.org/Images/092233.png', 'https://media.retroachievements.org/Images/098914.png', 'https://media.retroachievements.org/Images/098915.png', 4.1),
  (150, 15791, 'Gunbarich', 'Arcade', 27, 806, 806, 806, 27, 0, 'Action (Ball & Paddle)', 'Psikyo', 'Psikyo', '2001-06-01', 'Psikyo  was a Japanese video game developer and publisher known for its shoot ''em ups. It was founded in 1992 by former Video System staff who worked on the Aero Fighters series. Psikyo was mainly an arcade game developer, and ported some of their games to home consoles as well.', 'https://media.retroachievements.org/Images/035753.png', 'https://media.retroachievements.org/Images/035706.png', 'https://media.retroachievements.org/Images/031595.png', 'https://media.retroachievements.org/Images/032173.png', 4.1),
  (151, 12383, 'Sly Spy', 'Arcade', 27, 790, 790, 790, 26, 0, NULL, 'Data East', 'Data East', '1989-07-01', 'Sly Spy, known in Japan as Secret Agent  and known in Europe as Sly Spy: Secret Agent, is an arcade video game developed by Data East and published in 1989. Despite not being a licensed James Bond game, Sly Spy contains references to the series.', 'https://media.retroachievements.org/Images/042389.png', 'https://media.retroachievements.org/Images/019263.png', 'https://media.retroachievements.org/Images/019260.png', 'https://media.retroachievements.org/Images/019261.png', 4.1),
  (152, 12236, 'Snow Bros.: Nick & Tom', 'Arcade', 27, 786, 786, 786, 22, 0, NULL, 'Toaplan', 'Toaplan, Romstar, Dooyong', '1990-04-01', 'Snow Bros. is a 1990 platform video game developed and published by Toaplan for Japanese arcades; it was distributed by Romstar in North America and Europe. Players control snowman twins Nick and Tom as they travel through 50 stages, using snowballs as weapons while navigating obstacles and battling monsters in order to rescue the princesses Puripuri and Puchipuchi. The game was later ported to multiple platforms, each one by different third-party developers and featuring several changes or additions. Versions for various microcomputers were in development, but were never officially released.', 'https://media.retroachievements.org/Images/021730.png', 'https://media.retroachievements.org/Images/021717.png', 'https://media.retroachievements.org/Images/021714.png', 'https://media.retroachievements.org/Images/021715.png', 4.1),
  (153, 15017, 'Night Driver', 'Arcade', 27, 781, 781, 781, 6, 0, 'Racing', 'Atari', 'Atari', '1976-10-01', 'Night Driver is a 1976 racing video game developed and published by Atari, Inc. for arcades. It is one of the earliest first-person racing video games and is commonly believed to be one of the first published video games to feature real-time first-person graphics. Night Driver has a black and white display with the hood of the player''s car painted on a plastic overlay. The road is rendered as scaled rectangles representing pylons that line the edges.', 'https://media.retroachievements.org/Images/054477.png', 'https://media.retroachievements.org/Images/054478.png', 'https://media.retroachievements.org/Images/054475.png', 'https://media.retroachievements.org/Images/054476.png', 4.1),
  (154, 11813, 'Three Wonders | Wonder 3', 'Arcade', 27, 777, 777, 777, 66, 0, 'Minigames', 'Capcom', 'Capcom', '1991-07-01', 'A one-hit wonder is a musical artist who is successful with one hit song, but without a comparable subsequent hit. The term may also be applied to an artist who is remembered for only one hit despite other successes. This article contains artists known primarily for one hit song in the United States, who are regarded as one-hit wonders by at least two sources in media even though the artist may have had multiple hits abroad.', 'https://media.retroachievements.org/Images/016271.png', 'https://media.retroachievements.org/Images/016274.png', 'https://media.retroachievements.org/Images/016272.png', 'https://media.retroachievements.org/Images/016273.png', 4.1),
  (155, 13825, 'World Heroes Perfect', 'Arcade', 27, 768, 768, 768, 74, 0, '2D Fighting', 'ADK', 'SNK', '1995-05-01', 'World Heroes Perfect is a 1995 fighting arcade game developed and published by ADK with the assistance of SNK. It was originally released for the Neo Geo MVS arcade cabinet on 25 May 1995. It is the fourth and final title of the World Heroes series.', 'https://media.retroachievements.org/Images/041287.png', 'https://media.retroachievements.org/Images/041286.png', 'https://media.retroachievements.org/Images/022358.png', 'https://media.retroachievements.org/Images/022359.png', 4.1),
  (156, 14887, 'Ketsui: Kizuna Jigoku Tachi', 'Arcade', 27, 763, 763, 763, 22, 0, 'Shoot ''em Up', 'CAVE Interactive', 'AMI', '2003-01-01', 'Ketsui: Kizuna Jigoku Tachi  is a 2003 vertical shoot ''em up arcade game by Cave, released in Japanese arcades. A Nintendo DS boss rush version was released in October 2008 in Japan. It included a Superplay DVD featuring a world record scoring run by a top ranked player. The arcade game was ported to the Xbox 360 and released in 2010. A special version of Dodonpachi Daifukkatsu Black Label was released on the Xbox 360 in 2011, which is a crossover with Ketsui, featuring the ship, re-arranged music and scoring system from Ketsui on top of the Dodonpachi Daifukkatsu Black Label scoring system.', 'https://media.retroachievements.org/Images/092900.png', 'https://media.retroachievements.org/Images/096805.png', 'https://media.retroachievements.org/Images/097943.png', 'https://media.retroachievements.org/Images/097944.png', 4.1),
  (157, 13251, 'Captain America and the Avengers', 'Arcade', 27, 747, 747, 747, 24, 0, 'Beat ''em Up', 'Data East', 'Data East', '1991-10-01', 'Captain America and the Avengers is a 1991 beat ''em up video game developed and published by Data East for arcades. It features the Avengers team of Marvel Comics characters in a side-scrolling brawling and shooting adventure to defeat the evil Red Skull. The game received ports for the Sega Genesis/Mega Drive, Super Nintendo Entertainment System, Game Boy and Game Gear. A different Data East game was released for the Nintendo Entertainment System.', 'https://media.retroachievements.org/Images/104980.png', 'https://media.retroachievements.org/Images/019184.png', 'https://media.retroachievements.org/Images/019182.png', 'https://media.retroachievements.org/Images/019183.png', 4.1),
  (158, 13761, 'Breaker''s', 'Arcade', 27, 739, 739, 739, 33, 0, '2D Fighting', 'Visco', 'Visco', '1996-03-01', 'Breakout is a 1976 action video game developed and published by Atari, Inc. for arcades; in Japan, it was released by Namco. The game was designed by Nolan Bushnell and Steve Bristow and prototyped via discrete logic chips by Steve Wozniak with assistance from Steve Jobs. In the game, eight rows of bricks line the top portion of the screen, and the player''s goal is to destroy the bricks by repeatedly bouncing a ball off a paddle into them. The concept was predated by Ramtek''s Clean Sweep (1974), but the game''s designers were influenced by Atari''s own Pong (1972). The arcade version of Breakout uses a monochrome display underneath a translucent colored overlay.', 'https://media.retroachievements.org/Images/119920.png', 'https://media.retroachievements.org/Images/027996.png', 'https://media.retroachievements.org/Images/021947.png', 'https://media.retroachievements.org/Images/021948.png', 4.1),
  (159, 13811, 'Soccer Brawl', 'Arcade', 27, 735, 735, 735, 30, 0, 'Sports (Football / Soccer)', 'SNK', 'SNK', '1992-02-01', 'Brawl Stars is a multiplayer online battle arena and hero shooter video game developed and published by Finnish video game company Supercell. The game was released worldwide on 12 December 2018, on iOS and Android platforms. The game features a variety of game modes, each with a distinctive objective. Players are able to choose from a large selection of unlockable characters, called Brawlers, who each have different abilities and playstyles.', 'https://media.retroachievements.org/Images/032846.png', 'https://media.retroachievements.org/Images/032845.png', 'https://media.retroachievements.org/Images/022278.png', 'https://media.retroachievements.org/Images/022279.png', 4.1),
  (160, 11985, 'Alien Storm', 'Arcade', 27, 731, 731, 731, 22, 0, NULL, 'Sega', 'Sega', '1990-04-25', 'Alien Storm (エイリアンストーム) is a beat ''em up shooter released as an arcade video game by Sega in 1990. It was ported to the Genesis/Mega Drive and Master System. The Mega Drive version was re-released on Wii''s Virtual Console in 2007 and was also included on Sonic''s Ultimate Genesis Collection for Xbox 360 and PlayStation 3. The game was also re-released on the Nintendo Classics service in 2022.', 'https://media.retroachievements.org/Images/123055.png', 'https://media.retroachievements.org/Images/096267.png', 'https://media.retroachievements.org/Images/096268.png', 'https://media.retroachievements.org/Images/096269.png', 4.1),
  (161, 11941, 'Dyna Gear', 'Arcade', 27, 724, 724, 724, 17, 0, 'Run & Gun', 'Scarab', 'Sammy', '1994-01-01', 'Bomberman, also known as Dyna Blaster in Europe, is a 1990 action maze video game developed and published by Hudson Soft for the TurboGrafx-16. An entry in the Bomberman franchise, it is a reimagining of the first game in the series. The game was later ported to home computers, each one featuring changes compared to the original version. Conversions for other platforms were in development but never released. The game garnered positive reception from critics since its initial release on the TurboGrafx-16 and later on home computers.', 'https://media.retroachievements.org/Images/063423.png', 'https://media.retroachievements.org/Images/063422.png', 'https://media.retroachievements.org/Images/063421.png', 'https://media.retroachievements.org/Images/063420.png', 4.1),
  (162, 11955, 'Strider', 'Arcade', 27, 715, 715, 715, 22, 0, NULL, 'Capcom', 'Capcom', '1989-01-01', 'Strider, released in Japan as Strider Hiryū, is a 1989 hack and slash platform game developed and published by Capcom for arcades. Set in a dystopian future where Earth is ruled by the tyrannical Grandmaster Meio, it follows the titular Strider named Hiryu as he attempts to end his tyrannical reign for good. The game resulted from cooperation between Capcom and manga publisher Moto Kikaku. It marked the video game debut of Strider Hiryu, after the character was introduced in the 1988 manga Strider Hiryu.', 'https://media.retroachievements.org/Images/065284.png', 'https://media.retroachievements.org/Images/028716.png', 'https://media.retroachievements.org/Images/067695.png', 'https://media.retroachievements.org/Images/067696.png', 4.1),
  (163, 13859, 'Espgaluda', 'Arcade', 27, 711, 711, 711, 27, 0, 'Shoot ''em Up, Bullet Hell', 'CAVE Interactive', 'AMI', '2003-10-15', 'Espgaluda II (エスプガルーダII) is a bullet hell shoot''em up originally released by Cave in the arcades in 2005 as a sequel to Espgaluda. An Xbox 360 release, titled Espgaluda II Black Label, was released in 2010 in Japan. It was released in September 2021 for the Nintendo Switch worldwide.', 'https://media.retroachievements.org/Images/081244.png', 'https://media.retroachievements.org/Images/093956.png', 'https://media.retroachievements.org/Images/081256.png', 'https://media.retroachievements.org/Images/081255.png', 4.1),
  (164, 13853, 'Sengoku Blade: Sengoku Ace Episode II', 'Arcade', 27, 708, 708, 708, 59, 0, 'Shoot ''em Up', 'Psikyo', 'Psikyo', '1996-04-01', 'Tengai, known as Sengoku Blade in Japan, is a horizontally scrolling shoot ''em up video game released for arcade machines in 1996 by Psikyo as a sequel to their 1993 shooter Sengoku Ace. A home console version was also released for the Sega Saturn. The game was ported years later to the PlayStation 2, and again for iOS and Android devices and the Nintendo Switch, Windows, PlayStation 4 and Xbox One. The game is set in a historical fantasy version of the Sengoku period of Japanese history, featuring demons, magic and steam-powered robotics.', 'https://media.retroachievements.org/Images/062938.png', 'https://media.retroachievements.org/Images/062889.png', 'https://media.retroachievements.org/Images/022498.png', 'https://media.retroachievements.org/Images/022499.png', 4.1),
  (165, 12533, 'Twinkle Star Sprites', 'Arcade', 27, 701, 701, 701, 34, 0, 'Shoot ''em Up', 'ADK', 'SNK', '1996-11-25', 'Twinkle Star Sprites is a 1996 scrolling shooter arcade game developed by ADK and published by SNK. It was ADK''s last production for the Neo Geo. Two players are each in separate, side-by-side, vertically scrolling levels. Combinations of shots and timed power-ups damage the other player. These attacks also serve as counters to the opponent''s attack.', 'https://media.retroachievements.org/Images/115711.png', 'https://media.retroachievements.org/Images/062789.png', 'https://media.retroachievements.org/Images/022343.png', 'https://media.retroachievements.org/Images/022344.png', 4.1),
  (166, 11804, 'Vendetta', 'Arcade', 27, 682, 682, 682, 41, 0, 'Beat ''em Up', 'Konami', 'Konami', '1991-01-01', 'Vendetta, known in Japan as Crime Fighters 2, is a 1991 beat ''em up video game developed and published by Konami for arcades. It was released in Japan in July 1991 and in North America in September 1991. It is a sequel to Konami''s 1989 game Crime Fighters, although it was marketed internationally as a stand-alone game with no previous connections. Hamster Corporation released the game as part of their Arcade Archives series for the Nintendo Switch and PlayStation 4 in July 2021.', 'https://media.retroachievements.org/Images/066678.png', 'https://media.retroachievements.org/Images/066040.png', 'https://media.retroachievements.org/Images/066041.png', 'https://media.retroachievements.org/Images/066042.png', 4.1),
  (167, 12255, 'Street Fighter II Turbo: Hyper Fighting', 'Arcade', 27, 680, 680, 680, 26, 0, '2D Fighting', 'Capcom', 'Capcom', '1992-12-01', 'Street Fighter II Turbo: Hyper Fighting, released as Street Fighter II Dash Turbo in Japan, is a 1992 fighting game developed and published by Capcom for arcades. It is the third arcade version of Street Fighter II, part of the Street Fighter franchise, following Street Fighter II: Champion Edition, and was initially released as an enhancement kit for that game. Released less than a year after the previous installment, Hyper Fighting introduced a faster playing speed and new special moves for certain characters, as well as further refinement to the character balance.', 'https://media.retroachievements.org/Images/116918.png', 'https://media.retroachievements.org/Images/016396.png', 'https://media.retroachievements.org/Images/016382.png', 'https://media.retroachievements.org/Images/016389.png', 4.1),
  (168, 13758, 'Andro Dunos', 'Arcade', 27, 671, 671, 671, 32, 0, 'Shoot ''em Up', 'Visco', 'Visco', '1992-06-15', 'Andro Dunos is a scrolling shooter arcade video game developed by Visco Corporation and originally published by SNK on June 15, 1992. It is the first title to be created by Visco for both the Neo Geo MVS (arcade) and Neo Geo AES (home) platforms. Andro Dunos, along with 1996''s Breakers are the only two Visco developed games to be officially licensed for distribution on the Neo Geo AES platform. All other Visco games were only released on the Neo Geo MVS arcade platform.', 'https://media.retroachievements.org/Images/099452.png', 'https://media.retroachievements.org/Images/088058.png', 'https://media.retroachievements.org/Images/021932.png', 'https://media.retroachievements.org/Images/021933.png', 4.1),
  (169, 15882, 'Tetris: The Absolute - The Grand Master 2 Plus', 'Arcade', 27, 670, 670, 670, 84, 0, NULL, 'Arika', 'Arika', '2001-01-01', 'Tetris: The Grand Master  is a series of puzzle arcade video games created by Arika.', 'https://media.retroachievements.org/Images/080117.png', 'https://media.retroachievements.org/Images/044302.png', 'https://media.retroachievements.org/Images/031749.png', 'https://media.retroachievements.org/Images/031753.png', 4.1),
  (170, 12343, 'Prehistoric Isle 2', 'Arcade', 27, 668, 668, 668, 27, 0, 'Shoot ''em Up', 'Yumekobo', 'Yumekobo', '1999-09-27', 'Prehistoric Isle 2 is a 1999 scrolling shooter arcade video game co-developed by Saurus and Yumekobo and published by SNK. It is the sequel to the original Prehistoric Isle, which was developed and released earlier in 1989 by SNK. In the game, players take control of helicopters to shoot at dinosaurs while rescuing people. Although first launched in arcades, the title has since been re-released through download services for various consoles. It received mixed reception since its initial arcade release and garnered less success than its predecessor.', 'https://media.retroachievements.org/Images/097733.png', 'https://media.retroachievements.org/Images/088191.png', 'https://media.retroachievements.org/Images/022231.png', 'https://media.retroachievements.org/Images/022230.png', 4.1),
  (171, 17496, 'Jurassic Park', 'Arcade', 27, 666, 666, 666, 9, 0, NULL, 'Sega', 'Sega', '1994-02-01', 'Jurassic Park is a 1993 American science fiction film directed by Steven Spielberg and written by Michael Crichton and David Koepp, based on Crichton''s 1990 novel. Starring Sam Neill, Laura Dern, Jeff Goldblum, Richard Attenborough, Bob Peck, Martin Ferrero, BD Wong, Samuel L. Jackson, Wayne Knight, Joseph Mazzello, and Ariana Richards, the film is set on the fictional island of Isla Nublar near Costa Rica, where wealthy businessman John Hammond (Attenborough) and a team of genetic scientists have created a wildlife park of de-extinct dinosaurs. When industrial sabotage leads to a catastrophic shutdown of the park''s power facilities and security precautions, a small group of visitors struggle to survive and escape the now perilous island.', 'https://media.retroachievements.org/Images/093193.png', 'https://media.retroachievements.org/Images/042568.png', 'https://media.retroachievements.org/Images/042569.png', 'https://media.retroachievements.org/Images/042570.png', 4.1),
  (172, 15758, 'Crazy Kong', 'Arcade', 27, 664, 664, 664, 42, 0, '2D Platforming, Arcade', 'Falcon', 'Falcon', '1981-01-01', 'Crazy Kong  is an arcade video game developed by Falcon, released in 1981 and similar to Nintendo''s Donkey Kong. Although commonly believed to be a bootleg version, it was officially licensed for operation only in Japan when Nintendo could not keep up with domestic demand, and is based on different hardware. It retains all the gameplay elements of Donkey Kong, but its graphics were redrawn and re-colorized. Falcon breached their contract by exporting the cabinets overseas, leading Nintendo to revoke the license in January 1982. Like the original game, Crazy Kong had bootleg versions under such titles as Congorilla, Big Kong, Donkey King and Monkey Donkey.', 'https://media.retroachievements.org/Images/122437.png', 'https://media.retroachievements.org/Images/068205.png', 'https://media.retroachievements.org/Images/068579.png', 'https://media.retroachievements.org/Images/068580.png', 4.1),
  (173, 11949, 'Punch-Out!!', 'Arcade', 27, 664, 664, 664, 22, 0, 'Sports - Boxing', 'Nintendo', 'Nintendo', '1984-02-17', 'Super Punch-Out!! is a boxing video game developed and published by Nintendo for the Super Nintendo Entertainment System (SNES). It was released on October 24, 1994 in North America and again in the same region in 1996. It was released in the United Kingdom on February 10, 1995 for the same console and in Japan in 1998 for the Super Famicom through the Nintendo Power flash RAM cartridge series. The game is also included in the GameCube version of Fight Night Round 2 as an extra game due to the inclusion of Little Mac in the game. The game was released for the Wii''s Virtual Console in Europe on March 20, 2009, in North America on March 30, 2009, and in Japan on July 7, 2009. The game was also released on the New Nintendo 3DS eShop on May 5, 2016. Nintendo re-released Super Punch-Out!! in the United States in September 2017 as part of the company''s Super NES Classic Edition. It is the fourth game in the Punch-Out!! series, taking place after the Punch-Out!! game for the Nintendo Entertainment System (NES).', 'https://media.retroachievements.org/Images/121548.png', 'https://media.retroachievements.org/Images/124357.png', 'https://media.retroachievements.org/Images/019349.png', 'https://media.retroachievements.org/Images/060835.png', 4.1),
  (174, 11754, 'The King of Fighters 2003', 'Arcade', 27, 662, 662, 662, 58, 0, '2D Fighting', 'SNK', 'SNK', '2003-03-11', 'The King of Fighters 2003 (KOF 2003, or KOF ''03) is a 2003 fighting video game developed and published by SNK Playmore for the Neo Geo arcade and home platforms. It is the tenth game in The King of Fighters series, and the last entry released for the Neo Geo, which had served as the primary platform for the series since The King of Fighters ''94. It was ported to the PlayStation 2 and Xbox, and was released on both consoles in North America in a two-in-one bundle with the preceding game in the series, The King of Fighters 2002. Character designs and artwork were handled by artist Falcoon.', 'https://media.retroachievements.org/Images/109162.png', 'https://media.retroachievements.org/Images/016473.png', 'https://media.retroachievements.org/Images/016465.png', 'https://media.retroachievements.org/Images/016468.png', 4.1),
  (175, 11798, 'Street Fighter Alpha 2', 'Arcade', 27, 641, 641, 641, 49, 0, '2D Fighting', 'Capcom', 'Capcom', '1996-01-01', 'Street Fighter Alpha 2, known as Street Fighter Zero 2 in Japan, Asia, South America, and Oceania, is a 1996 fighting game developed and published by Capcom for arcades. The game is the sequel to the previous year''s Street Fighter Alpha: Warriors'' Dreams and features a number of improvements, such as new attacks, stages, endings, and gameplay features. It was ported to the PlayStation, Sega Saturn and Super Nintendo home consoles globally in 1996, and later a Windows port. It was followed by Street Fighter Alpha 3 in 1998.', 'https://media.retroachievements.org/Images/050132.png', 'https://media.retroachievements.org/Images/016393.png', 'https://media.retroachievements.org/Images/016380.png', 'https://media.retroachievements.org/Images/016385.png', 4.1),
  (176, 12481, 'Pac-Mania', 'Arcade', 27, 634, 634, 634, 35, 0, 'Maze Chase', 'Namco', NULL, '1987-12-01', 'Pac-Mania is a 1987 maze video game developed and published by Namco for Japanese arcades; it was licensed to Atari Games for release in North America. In the game, the player controls Pac-Man as he must eat all of the dots while avoiding the colored ghosts that chase him in the maze. Eating large flashing Power Pellets will allow Pac-Man to eat the ghosts for bonus points, which lasts for a short period of time. A new feature to this game allows Pac-Man to jump over the ghosts to evade capture. It is the ninth title in the Pac-Man video game series and was the last one developed for arcades up until the release of Pac-Man Arrangement in 1996. Development was directed by Pac-Man creator Tōru Iwatani.', 'https://media.retroachievements.org/Images/092335.png', 'https://media.retroachievements.org/Images/088580.png', 'https://media.retroachievements.org/Images/088487.png', 'https://media.retroachievements.org/Images/088488.png', 4.1),
  (177, 12040, 'The Last Blade', 'Arcade', 27, 629, 629, 629, 66, 0, '2D Fighting', 'SNK', 'SNK', '1997-12-05', 'The Last Blade is a fighting game developed and released by SNK for the Neo Geo system in 1997. It was also ported to several home systems. A sequel, The Last Blade 2, was released in 1998. A second sequel, The Last Blade: Beyond the Destiny, was released in 2000.', 'https://media.retroachievements.org/Images/122040.png', 'https://media.retroachievements.org/Images/040223.png', 'https://media.retroachievements.org/Images/022064.png', 'https://media.retroachievements.org/Images/040328.png', 4.1),
  (178, 12310, 'Mr. Do!', 'Arcade', 27, 628, 628, 628, 22, 0, 'Maze Chase', 'Universal', 'Universal', '1982-01-01', 'Mr. Do! is a 1982 maze video game developed by Universal. It is the first arcade video game to be released as a conversion kit for other cabinets; Taito published the conversion kit in Japan. The game was inspired by Namco''s Dig Dug, released earlier in 1982. Mr. Do! was a commercial success in Japan and North America, selling 30,000 arcade units in the US, and it was followed by several arcade sequels.', 'https://media.retroachievements.org/Images/124334.png', 'https://media.retroachievements.org/Images/039624.png', 'https://media.retroachievements.org/Images/039623.png', 'https://media.retroachievements.org/Images/039625.png', 4.1),
  (179, 12766, 'Aero Fighters 3', 'Arcade', 27, 625, 625, 625, 46, 0, 'Shoot ''em Up', 'Video System', 'SNK', '1995-10-12', 'Aero Fighters 3 is a 1995 vertically scrolling shooter video game developed and published by Video System for the Neo Geo MVS arcade system in Japan; it was distributed by SNK in North America and Europe. It was later ported to the Neo Geo AES and Neo Geo CD home consoles; the Neo Geo AES version was not released in North America. The game was later re-released for PlayStation 4, Xbox One, and Nintendo Switch in 2018 by the eventual copyright holder for the game, Hamster Corporation.', 'https://media.retroachievements.org/Images/120531.png', 'https://media.retroachievements.org/Images/088053.png', 'https://media.retroachievements.org/Images/021926.png', 'https://media.retroachievements.org/Images/021927.png', 4.1),
  (180, 11829, 'Mars Matrix: Hyper Solid Shooting', 'Arcade', 27, 625, 625, 625, 29, 0, 'Shoot ''em Up', 'Takumi', NULL, '2000-06-01', 'Mars Matrix: Hyper Solid Shooting, or simply Mars Matrix , is a 2000 vertically scrolling shooter arcade game developed by Takumi, published by Capcom, and run on their CPS-2 arcade system board. Mars Matrix was later ported to the Dreamcast video game console in 2001. The arcade version uses a horizontally aligned monitor, despite being a vertically scrolling game.', 'https://media.retroachievements.org/Images/083152.png', 'https://media.retroachievements.org/Images/017015.png', 'https://media.retroachievements.org/Images/017011.png', 'https://media.retroachievements.org/Images/017013.png', 4.1),
  (181, 28669, 'Deathsmiles: Mega Black Label', 'Arcade', 27, 624, 624, 624, 61, 0, 'Shoot ''em Up, Bullet Hell', 'CAVE Interactive', 'AMI', '2008-10-06', 'Deathsmiles  is a horizontally scrolling shooter arcade video game by Japanese developer Cave, released in late 2007. It has heavy occult and gothic influences. It is the second Cave shooter to be played using a horizontally-oriented monitor. It was the first Cave shooter released in North America on a console, and the first one in Europe. Cave has also released it for iOS. A sequel, Deathsmiles II, was released to Japanese arcades on May 14, 2009. A compilation of both Deathsmiles I and Deathsmiles II was released for PlayStation 4, Xbox One and Nintendo Switch in Japan on December 16, 2021.', 'https://media.retroachievements.org/Images/094642.png', 'https://media.retroachievements.org/Images/091985.png', 'https://media.retroachievements.org/Images/094643.png', 'https://media.retroachievements.org/Images/094644.png', 4.1),
  (182, 13567, 'Pachinko Sexy Reaction 2', 'Arcade', 27, 603, 603, 603, 10, 0, 'Casino, Pachinko', 'Sammy', 'Sammy', '1999-01-01', 'The Sega Saturn is a 32-bit fifth-generation home video game console that was developed by Sega and first released on November 22, 1994. Its games are in CD-ROM format, and its game library contains several arcade ports as well as original titles. There are 1028 games on this list not including non-game software and compilations of Saturn games. 775 of those games were released as Japan-only exclusives, which makes up 75% of the list. For games that were announced or in development for the Saturn, but never released, see the list of cancelled Sega Saturn games.', 'https://media.retroachievements.org/Images/034174.png', 'https://media.retroachievements.org/Images/051324.png', 'https://media.retroachievements.org/Images/021171.png', 'https://media.retroachievements.org/Images/034147.png', 4),
  (183, 13384, 'Zombie Raid', 'Arcade', 27, 603, 603, 603, 23, 0, 'Rail Shooter', 'Sammy', 'Sammy', '1995-01-01', 'Zombie Raid is a screen scrolling, horror-themed light gun shooter game released for the arcade by American Sammy in January 1995.', 'https://media.retroachievements.org/Images/106437.png', 'https://media.retroachievements.org/Images/019659.png', 'https://media.retroachievements.org/Images/106438.png', 'https://media.retroachievements.org/Images/106439.png', 4),
  (184, 22131, 'DoDonPachi DaiFukkatsu Black Label', 'Arcade', 27, 599, 599, 599, 60, 0, 'Bullet Hell, Shoot ''em Up', 'CAVE Interactive', 'DEGICA', '2010-01-20', 'DoDonPachi Resurrection, known in Japan as DoDonPachi DaiFukkatsu , is the fifth arcade game in Cave''s DonPachi series, published in 2008. The game was unveiled at AOU2008 Amusement EXPO.', 'https://media.retroachievements.org/Images/110860.png', 'https://media.retroachievements.org/Images/110861.png', 'https://media.retroachievements.org/Images/066687.png', 'https://media.retroachievements.org/Images/110859.png', 4),
  (185, 11948, 'Arm Wrestling', 'Arcade', 27, 598, 598, 598, 15, 0, 'Action', 'Nintendo', 'Nintendo', '1985-05-01', 'Arm wrestling is a strength sport in which two participants, facing each other with their bent elbows placed on a flat surface and hands firmly gripped, each attempt to pin their opponent''s hand by forcing it to the surface. In popular culture, arm wrestling is commonly interpreted as a display of physical dominance, symbolizing superior strength and toughness between two individuals.', 'https://media.retroachievements.org/Images/050156.png', 'https://media.retroachievements.org/Images/036382.png', 'https://media.retroachievements.org/Images/019348.png', 'https://media.retroachievements.org/Images/036383.png', 4),
  (186, 15009, 'Asteroids', 'Arcade', 27, 596, 596, 596, 12, 0, NULL, 'Atari', 'Atari', '1979-11-01', 'An asteroid is a minor planet—an object larger than a meteoroid that is neither a planet nor an identified comet—that orbits within the inner Solar System or is co-orbital with Jupiter. Asteroids are rocky, metallic, or icy bodies with no atmosphere, and are broadly classified into C-type (carbonaceous), M-type (metallic), or S-type (silicaceous). The size and shape of asteroids vary significantly, ranging from small rubble piles under a kilometer across to Ceres, a dwarf planet almost 1000 km in diameter. A body is classified as a comet, not an asteroid, if it shows a coma (tail) when warmed by solar radiation, although recent observations suggest a continuum between these types of bodies.', 'https://media.retroachievements.org/Images/108929.png', 'https://media.retroachievements.org/Images/033985.png', 'https://media.retroachievements.org/Images/033986.png', 'https://media.retroachievements.org/Images/033987.png', 4),
  (187, 11860, 'Windjammers', 'Arcade', 27, 591, 591, 591, 18, 0, 'Sports (Flying Disc)', 'Data East', 'Data East', '1994-02-17', 'Windjammers is a sports arcade game released by Data East on the Neo Geo arcade system in 1994. The game mechanics are essentially the same as Pong or air hockey, where players continuously shoot a flying disc at the goal zone of the opponent attempting to score. The game can be played against the computer or in a 2 player versus. Dotemu ported the game to PlayStation 4 and PlayStation Vita in August 2017, Nintendo Switch in October 2018, and iiRcade in February 2021. Dotemu would later develop and publish a sequel, Windjammers 2, which was released on PlayStation 4, Xbox One, Nintendo Switch, PC and Google Stadia on January 20, 2022.', 'https://media.retroachievements.org/Images/078318.png', 'https://media.retroachievements.org/Images/029797.png', 'https://media.retroachievements.org/Images/020837.png', 'https://media.retroachievements.org/Images/020838.png', 4),
  (188, 18013, 'Alien 3: The Gun', 'Arcade', 27, 588, 588, 588, 15, 0, NULL, 'Sega', 'Sega', '1993-09-01', 'Alien 3: The Gun is a 1993 rail shooter arcade video game released by Sega. It is based on the film Alien 3, but focuses on two space Marines.', 'https://media.retroachievements.org/Images/096321.png', 'https://media.retroachievements.org/Images/049078.png', 'https://media.retroachievements.org/Images/049076.png', 'https://media.retroachievements.org/Images/049077.png', 4),
  (189, 12242, 'Super Puzzle Fighter II Turbo', 'Arcade', 27, 585, 585, 585, 39, 0, NULL, 'Capcom', 'Capcom', '1996-05-31', 'Super Puzzle Fighter II Turbo, released in Japan as Super Puzzle Fighter II X, is a 1996 tile-matching puzzle video game developed and published by Capcom for arcades. The game''s title is a play on Super Street Fighter II Turbo, as there were no other Puzzle Fighter games at the time, and the game includes music and interface elements spoofing the Street Fighter Alpha and Darkstalkers games. It was a response to Compile and Sega''s Puyo Puyo 2 that had been sweeping the Japanese arcade scene.', 'https://media.retroachievements.org/Images/019678.png', 'https://media.retroachievements.org/Images/078676.png', 'https://media.retroachievements.org/Images/078674.png', 'https://media.retroachievements.org/Images/078675.png', 4),
  (190, 13799, 'Ninja Master''s: Haou Ninou Chou', 'Arcade', 27, 583, 583, 583, 60, 0, '2D Fighting', 'ADK, Hamster', 'SNK', '1996-05-26', NULL, 'https://media.retroachievements.org/Images/040209.png', 'https://media.retroachievements.org/Images/040199.png', 'https://media.retroachievements.org/Images/022160.png', 'https://media.retroachievements.org/Images/022161.png', 4),
  (191, 11870, 'Cotton: Fantastic Night Dreams', 'Arcade', 27, 580, 580, 580, 28, 0, 'Shoot ''em Up', 'Success', 'Sega', '1991-03-01', 'Cotton: Fantastic Night Dreams is a 1991 scrolling shooter video game developed by Success and published by Sega for Japanese arcades. The first installment in the Cotton series, players assume the role of the young witch Cotton who, alongside her fairy companion Silk, sets out on her broomstick on a quest to defeat several monsters and get her Willow candy. Its gameplay mainly consists of shooting mixed with role-playing elements using a main two-button configuration. It ran on the Sega System 16 hardware.', 'https://media.retroachievements.org/Images/059015.png', 'https://media.retroachievements.org/Images/019248.png', 'https://media.retroachievements.org/Images/019244.png', 'https://media.retroachievements.org/Images/019245.png', 4),
  (192, 12724, 'Real Bout Fatal Fury', 'Arcade', 27, 580, 580, 580, 54, 0, '2D Fighting', 'SNK', 'SNK', '1995-12-21', 'Real Bout Fatal Fury is a 1995 fighting game developed and published by SNK for the Neo Geo arcade and home platforms. It is the fourth mainline installment in the Fatal Fury series, following Fatal Fury 3: Road to the Final Victory, and the first game of the Real Bout sub-series.', 'https://media.retroachievements.org/Images/114366.png', 'https://media.retroachievements.org/Images/065100.png', 'https://media.retroachievements.org/Images/016607.png', 'https://media.retroachievements.org/Images/066770.png', 4),
  (193, 12452, 'Alien Sector', 'Arcade', 27, 564, 564, 564, 21, 0, 'Shoot ''em Up', 'Namco', 'Namco', '1985-05-25', 'Baraduke, renamed Alien Sector in some regions, is a run and gun video game released for arcades by Namco in 1985. A home version was published for the X68000 in 1995.', 'https://media.retroachievements.org/Images/095397.png', 'https://media.retroachievements.org/Images/095396.png', 'https://media.retroachievements.org/Images/019330.png', 'https://media.retroachievements.org/Images/095395.png', 4),
  (194, 12214, 'Knights of the Round', 'Arcade', 27, 557, 557, 557, 57, 0, 'Beat ''em Up', 'Capcom', 'Capcom', '1991-11-27', 'Knights of the Round is a 1991 beat ''em up game developed and published by Capcom for arcades. Based loosely on the legend of King Arthur and the Knights of the Round Table, the game features an action role-playing-like level advancement system, with fighters automatically being upgraded to new weapons and armor as they advance through the game. The arcade version of the game was included in the compilations Capcom Beat ''Em Up Bundle (2018) and Capcom Arcade 2nd Stadium (2022).', 'https://media.retroachievements.org/Images/101834.png', 'https://media.retroachievements.org/Images/022809.png', 'https://media.retroachievements.org/Images/022807.png', 'https://media.retroachievements.org/Images/022810.png', 4),
  (195, 12860, 'Raiden II', 'Arcade', 27, 549, 549, 549, 41, 0, 'Shoot ''em Up', 'Seibu Kaihatsu', 'Fabtek', '1993-11-01', 'Raiden II  is a 1993 vertically scrolling shooter arcade video game developed and published by Seibu Kaihatsu. It is the second game in the Raiden series which started with Raiden in 1990.', 'https://media.retroachievements.org/Images/096843.png', 'https://media.retroachievements.org/Images/096457.png', 'https://media.retroachievements.org/Images/030208.png', 'https://media.retroachievements.org/Images/030209.png', 4),
  (196, 12067, 'Crime City', 'Arcade', 27, 540, 540, 540, 18, 0, NULL, 'Taito', 'Taito', '1989-09-01', 'True Crime: New York City is a 2005 action-adventure video game developed by Luxoflux for PlayStation 2. It was ported to GameCube and Xbox by Exakt Entertainment, to Microsoft Windows by Aspyr, and to mobile by Hands-On Mobile. It was published on all systems by Activision. The PlayStation 2, Xbox and GameCube versions were released in November 2005, the PC version in March 2006, and the mobile version in March 2007. It is the second and final entry in the True Crime franchise, after the 2003 game, True Crime: Streets of LA.', 'https://media.retroachievements.org/Images/079303.png', 'https://media.retroachievements.org/Images/019259.png', 'https://media.retroachievements.org/Images/019256.png', 'https://media.retroachievements.org/Images/019257.png', 4),
  (197, 11944, 'Donkey Kong Junior', 'Arcade', 27, 533, 533, 533, 22, 0, '2D Platforming, Arcade', 'Nintendo', 'Nintendo', '1982-08-01', 'Donkey Kong Jr. is a 1982 platform game developed and published by Nintendo for arcades. It is the sequel to 1981''s Donkey Kong, but with the roles reversed compared to its predecessor: Mario is now the villain and Donkey Kong Jr. is trying to save his kidnapped father. After its initial release in arcades, the game was ported to a variety of home consoles, including the Famicom/Nintendo Entertainment System. The game''s title is written as Donkey Kong Junior in the North American arcade version and various conversions to non-Nintendo systems.', 'https://media.retroachievements.org/Images/035728.png', 'https://media.retroachievements.org/Images/115860.png', 'https://media.retroachievements.org/Images/036409.png', 'https://media.retroachievements.org/Images/036410.png', 4),
  (198, 11896, 'Pooyan', 'Arcade', 27, 524, 524, 524, 23, 0, 'Shoot ''em Up', 'Konami', 'Konami', '1982-01-01', 'Pooyan is a 1982 fixed shooter video game developed and published by Konami for arcades. It was released in North America by Stern Electronics. The player controls Mama, a pig whose babies have been kidnapped by a group of wolves. It was later ported to home consoles and personal computers.', 'https://media.retroachievements.org/Images/035603.png', 'https://media.retroachievements.org/Images/037783.png', 'https://media.retroachievements.org/Images/037780.png', 'https://media.retroachievements.org/Images/037781.png', 4),
  (199, 15020, 'Defender', 'Arcade', 27, 519, 519, 519, 37, 0, 'Shoot ''em Up', 'Williams Entertainment', 'Williams Entertainment', '1981-02-01', 'An arcade video game is an arcade game that takes player input from its controls, processes it through electrical or computerized components, and displays output to an electronic monitor or similar display. All arcade video games are coin-operated or accept other means of payment, housed in an arcade cabinet, and located in amusement arcades alongside other kinds of arcade games. Until the early 2000s, arcade video games were the largest and most technologically advanced segment of the video game industry.', 'https://media.retroachievements.org/Images/070479.png', 'https://media.retroachievements.org/Images/071807.png', 'https://media.retroachievements.org/Images/070477.png', 'https://media.retroachievements.org/Images/070478.png', 4),
  (200, 12359, 'Rambo III', 'Arcade', 27, 519, 519, 519, 8, 0, 'Rail Shooter', 'Taito', 'Taito', '1989-01-01', 'Rambo III is a 1988 American war action film starring Sylvester Stallone as Vietnam War veteran John Rambo. Directed by Peter MacDonald, the script was co-written by Stallone and Sheldon Lettich. It is a sequel to Rambo: First Blood Part II (1985) and the third installment in the Rambo film series. Richard Crenna reprises his role as Colonel Sam Trautman.', 'https://media.retroachievements.org/Images/059522.png', 'https://media.retroachievements.org/Images/058858.png', 'https://media.retroachievements.org/Images/021013.png', 'https://media.retroachievements.org/Images/021014.png', 4);
INSERT INTO games (rank, id, title, consoleName, consoleId, totalPlayers, casualPlayers, hardcorePlayers, numAchievements, points, genre, developer, publisher, released, description, icon, boxArt, titleScreen, screenshot, rating) VALUES
  (1, 10003, 'Super Mario 64', 'Nintendo 64', 2, 48917, 48917, 48917, 114, 0, '3D Platforming, Collect-a-thon', NULL, 'Nintendo', '1996-06-23', 'Super Mario 64 is a 1996 platform game developed and published by Nintendo for the Nintendo 64. It is the first Super Mario game to feature 3D gameplay, combining traditional Super Mario gameplay, visual style, and characters in a large open world. In the game, Bowser invades Princess Peach''s castle, kidnaps her, and hides the castle''s sources of protection, the Power Stars, in many different worlds inside magical paintings. As Mario, the player traverses levels and collects Power Stars to unlock areas of Princess Peach''s castle, to reach Bowser and rescue Princess Peach.', 'https://media.retroachievements.org/Images/112471.png', 'https://media.retroachievements.org/Images/048358.png', 'https://media.retroachievements.org/Images/048653.png', 'https://media.retroachievements.org/Images/048652.png', 5),
  (2, 10082, 'Super Smash Bros.', 'Nintendo 64', 2, 19010, 19010, 19010, 59, 0, 'Platform Fighting', 'HAL Laboratory', 'Nintendo', '1999-01-21', 'Super Smash Bros. is a series of platform fighting video games published by Nintendo. Created by Masahiro Sakurai, the Super Smash Bros. series is a crossover featuring many characters from other video game series created by Nintendo and other developers. Its gameplay is distinct from traditional fighting games, with players aiming to knock each other off of stages after accumulating damage with numerous attacks. The games have also featured a variety of side modes, including single-player story modes.', 'https://media.retroachievements.org/Images/121474.png', 'https://media.retroachievements.org/Images/091209.png', 'https://media.retroachievements.org/Images/010637.png', 'https://media.retroachievements.org/Images/010638.png', 4.8),
  (3, 10113, 'The Legend of Zelda: Ocarina of Time', 'Nintendo 64', 2, 11045, 11045, 11045, 97, 0, 'Action-Adventure', NULL, 'Nintendo', '1998-11-21', 'The Legend of Zelda: Ocarina of Time is a 1998 action-adventure game developed and published by Nintendo for the Nintendo 64. It was the first Legend of Zelda game with 3D graphics. It was released in Japan and North America in November 1998 and in PAL regions the following month.', 'https://media.retroachievements.org/Images/022051.png', 'https://media.retroachievements.org/Images/048366.png', 'https://media.retroachievements.org/Images/010929.png', 'https://media.retroachievements.org/Images/010930.png', 4.7),
  (4, 10210, 'Banjo-Kazooie', 'Nintendo 64', 2, 9477, 9477, 9477, 60, 0, '3D Platforming, Collect-a-thon', 'Rare', 'Nintendo', '1998-06-29', 'Banjo-Kazooie is a platform game series developed by the British studio Rare. The games focus on the two title characters―Banjo, a male brown bear; and Kazooie, a large female breegull who is typically seen riding in Banjo''s backpack―both of whom are controlled by the player. The games generally involve the pair in conflict with the evil witch Gruntilda Winkybunion. The eponymous first game in the series was released in 1998 to critical acclaim and was followed by Banjo-Tooie (2000), Banjo-Kazooie: Nuts & Bolts (2008), Banjo-Kazooie: Grunty''s Revenge (2003), and Banjo-Pilot (2005), a spinoff kart racing game.', 'https://media.retroachievements.org/Images/091553.png', 'https://media.retroachievements.org/Images/065117.png', 'https://media.retroachievements.org/Images/011034.png', 'https://media.retroachievements.org/Images/011031.png', 4.7),
  (5, 10679, 'The Legend of Zelda: Majora''s Mask', 'Nintendo 64', 2, 9144, 9144, 9144, 96, 0, 'Action-Adventure', 'Nintendo', 'Nintendo', '2000-10-26', 'The Legend of Zelda: Majora''s Mask is a 2000 action-adventure game developed and published by Nintendo for the Nintendo 64. It is the second game in The Legend of Zelda series to use 3D graphics, following Ocarina of Time (1998). Designed by a creative team led by Eiji Aonuma, Yoshiaki Koizumi, and Shigeru Miyamoto, Majora''s Mask was completed in less than two years. It features enhanced graphics and several gameplay changes, but reuses elements and character models from Ocarina of Time, a creative decision made necessary by time constraints.', 'https://media.retroachievements.org/Images/045842.png', 'https://media.retroachievements.org/Images/048359.png', 'https://media.retroachievements.org/Images/015426.png', 'https://media.retroachievements.org/Images/015427.png', 4.7),
  (6, 10075, 'Donkey Kong 64', 'Nintendo 64', 2, 8934, 8934, 8934, 128, 0, '3D Platforming, Collect-a-thon', 'Rare', 'Nintendo', '1999-11-24', 'Donkey Kong 64 is a 1999 platform game developed by Rare and published by Nintendo for the Nintendo 64. It is the first Donkey Kong game to feature 3D gameplay. As the gorilla Donkey Kong, the player explores themed levels to collect items and rescue his kidnapped family members from King K. Rool. The player completes minigames and puzzles as five playable Kong characters—each with their own special abilities—to receive bananas and other collectibles. In multiplayer modes, up to four players can compete in deathmatch and last man standing games.', 'https://media.retroachievements.org/Images/110715.png', 'https://media.retroachievements.org/Images/070527.png', 'https://media.retroachievements.org/Images/024244.png', 'https://media.retroachievements.org/Images/024245.png', 4.7),
  (7, 10246, 'Kirby 64: The Crystal Shards', 'Nintendo 64', 2, 7951, 7951, 7951, 38, 0, '2.5D Platforming', 'HAL Laboratory', 'Nintendo', '2000-03-24', 'Kirby 64: The Crystal Shards is a 2000 platform game developed by HAL Laboratory and published by Nintendo for the Nintendo 64 (N64). It is the first Kirby game to feature 3D computer graphics and follows Kirby as he attempts to reassemble a sacred crystal shattered by Dark Matter. Gameplay is viewed from a 2.5D perspective and is similar to previous Kirby titles; the player traverses levels and obtains powers by eating enemies. Kirby 64 introduces Power Combos, the ability to mix powers to create more powerful ones. In a multiplayer mode, up to four players can compete in three minigames.', 'https://media.retroachievements.org/Images/073571.png', 'https://media.retroachievements.org/Images/048365.png', 'https://media.retroachievements.org/Images/011126.png', 'https://media.retroachievements.org/Images/011127.png', 4.7),
  (8, 10202, 'Diddy Kong Racing', 'Nintendo 64', 2, 7471, 7471, 7471, 94, 0, 'Collect-a-thon, Kart Racing', 'Rare', 'Nintendo', '1997-11-24', 'Diddy Kong Racing is a 1997 kart racing game developed and published by Rare for the Nintendo 64. The game revolves around Diddy Kong and his friends'' attempt to defeat the intergalactic antagonist, a wizard pig named Wizpig, through winning a series of races. The player takes control of any of the featured characters throughout the game. Diddy Kong Racing features five worlds with four racetracks each, and the ability to drive a car, hovercraft, or pilot an aeroplane.', 'https://media.retroachievements.org/Images/040625.png', 'https://media.retroachievements.org/Images/040626.png', 'https://media.retroachievements.org/Images/011105.png', 'https://media.retroachievements.org/Images/011106.png', 4.7),
  (9, 10073, 'GoldenEye 007', 'Nintendo 64', 2, 7292, 7292, 7292, 141, 0, 'First-Person Shooter', 'Rare', 'Nintendo', '1997-08-25', 'GoldenEye 007 is a 1997 first-person shooter game developed by Rare and published by Nintendo for the Nintendo 64. It is based on the 1995 James Bond film GoldenEye, with the player controlling the secret agent James Bond to prevent a criminal syndicate from using a satellite weapon. They navigate a series of levels to complete objectives, such as recovering or destroying objects, while shooting enemies. In a multiplayer mode, up to four players compete in several deathmatch scenarios via split-screen.', 'https://media.retroachievements.org/Images/022585.png', 'https://media.retroachievements.org/Images/066357.png', 'https://media.retroachievements.org/Images/011101.png', 'https://media.retroachievements.org/Images/011103.png', 4.7),
  (10, 10248, 'Star Fox 64', 'Nintendo 64', 2, 5351, 5351, 5351, 50, 0, 'Rail Shooter', NULL, 'Nintendo', '1997-07-01', 'Star Fox 64, known as Lylat Wars in the PAL regions, is a 1997 rail shooter game developed and published by Nintendo for the Nintendo 64. It is the second installment in the Star Fox series and a reboot of the original Star Fox for the Super Nintendo Entertainment System.', 'https://media.retroachievements.org/Images/093951.png', 'https://media.retroachievements.org/Images/048362.png', 'https://media.retroachievements.org/Images/014375.png', 'https://media.retroachievements.org/Images/014379.png', 4.6),
  (11, 10173, 'Yoshi''s Story', 'Nintendo 64', 2, 4703, 4703, 4703, 93, 0, '2D Platforming, Collect-a-thon', 'Nintendo', 'Nintendo', '1998-03-01', 'Yoshi''s Story is a 1997 platform game published and developed by Nintendo for the Nintendo 64. It was released in Japan in December 1997, and worldwide the following year. The game has been subsequently re-released on the Wii, Wii U, and Nintendo Switch.', 'https://media.retroachievements.org/Images/044181.png', 'https://media.retroachievements.org/Images/048368.png', 'https://media.retroachievements.org/Images/011212.png', 'https://media.retroachievements.org/Images/011211.png', 4.6),
  (12, 10263, 'Mario Party', 'Nintendo 64', 2, 3481, 3481, 3481, 56, 0, 'Board Game, Party', 'Hudson Soft', 'Nintendo', '1998-12-18', 'Mario Party is a series of party video games created by Hudson Soft and owned by Nintendo. It features characters from the Mario franchise in which up to four local players or computer-controlled characters compete in a board game interspersed with minigames. Designed by Shigeru Miyamoto, and directed by Kenji Kikuchi, the games are currently developed by Nintendo Cube and published by Nintendo, being previously developed by Hudson Soft. The series is known for its party game elements, including the often unpredictable multiplayer game modes that allow play with up to four, and sometimes eight, human players or CPUs.', 'https://media.retroachievements.org/Images/040160.png', 'https://media.retroachievements.org/Images/011086.png', 'https://media.retroachievements.org/Images/011084.png', 'https://media.retroachievements.org/Images/011085.png', 4.5),
  (13, 10617, 'Wave Race 64', 'Nintendo 64', 2, 3228, 3228, 3228, 73, 0, 'Racing', NULL, 'Nintendo', '1996-09-27', 'Wave Race 64 is a 1996 racing video game developed and published by Nintendo for the Nintendo 64. It is the second entry in the Wave Race series following the 1992 Game Boy game Wave Race. Gameplay involves the player racing on a personal watercraft on a variety of courses while successfully manoeuvring the vehicle around various buoys. A multiplayer mode where two players can compete against each other on a chosen course is also included. The game supports the Controller Pak, which allows players to transfer saved data from one game cartridge to another. The game is presented in a letterboxed 14:9 aspect ratio.', 'https://media.retroachievements.org/Images/019034.png', 'https://media.retroachievements.org/Images/019035.png', 'https://media.retroachievements.org/Images/019036.png', 'https://media.retroachievements.org/Images/019037.png', 4.5),
  (14, 10667, 'Castlevania', 'Nintendo 64', 2, 3024, 3024, 3024, 52, 0, 'Action-Adventure, 3D Platforming', 'Konami', 'Konami', '1999-01-26', 'Castlevania, known in Japan as Akumajō Dracula, is a gothic horror action-adventure video game series and media franchise created by Hitoshi Akamatsu and published by Konami. The series is largely set in the castle of Count Dracula, who wages an eternal war against humanity and comes into conflict with the world''s vampire hunters, principally including the Belmont clan, wielders of the mystical whip known as the "Vampire Killer."', 'https://media.retroachievements.org/Images/091411.png', 'https://media.retroachievements.org/Images/070351.png', 'https://media.retroachievements.org/Images/070353.png', 'https://media.retroachievements.org/Images/070352.png', 4.5),
  (15, 10133, 'F-Zero X', 'Nintendo 64', 2, 2892, 2892, 2892, 74, 0, 'Arcade Racing', NULL, 'Nintendo', '1998-07-14', 'F-Zero X is a 1998 racing game developed and published by Nintendo for the Nintendo 64. It is the sequel to the original F-Zero (1990), and the first F-Zero game with 3D graphics. It has a steep learning curve and its gameplay experience is similar to that of the original. The F-Zero X Expansion Kit, an expansion pack for the 64DD featuring 12 more tracks and track and vehicle editors, was released in Japan in 2000.', 'https://media.retroachievements.org/Images/046476.png', 'https://media.retroachievements.org/Images/048360.png', 'https://media.retroachievements.org/Images/014763.png', 'https://media.retroachievements.org/Images/014764.png', 4.5),
  (16, 10211, 'Banjo-Tooie', 'Nintendo 64', 2, 2874, 2874, 2874, 110, 0, '3D Platforming, Collect-a-thon', 'Rare', 'Nintendo', '2000-11-20', 'Banjo-Tooie is a 2000 platform game developed by Rare and published by Nintendo for the Nintendo 64 console. It is the second game in the Banjo-Kazooie series and the sequel to Banjo-Kazooie. The game follows the returning protagonists Banjo and Kazooie as they attempt to stop the plans of the witch Gruntilda and two of her sisters, who intend to vaporise the inhabitants of the game''s island setting. The game features worlds significantly larger than those of its predecessor, requiring the player to complete challenges such as solving puzzles, jumping over obstacles, collecting items, and defeating opponents. It also includes a Widescreen format, and a multiplayer mode in which up to four players can compete in several minigames repurposed from the main campaign.', 'https://media.retroachievements.org/Images/091555.png', 'https://media.retroachievements.org/Images/096336.png', 'https://media.retroachievements.org/Images/018548.png', 'https://media.retroachievements.org/Images/019194.png', 4.5),
  (17, 10181, 'Pokémon Stadium', 'Nintendo 64', 2, 2700, 2700, 2700, 72, 0, 'Turn-Based Strategy', 'HAL Laboratory', 'Nintendo', '1999-04-30', 'Pokémon Stadium is a 1999 strategy video game developed and published by Nintendo for the Nintendo 64. The gameplay revolves around a 3D turn-based battling system using the 151 Pokémon from the Game Boy games Pokémon Red, Blue, and Yellow, with several in-game challenges for players to overcome. The game includes four "Cups", each of which is a series of three-on-three Pokémon battles against an ordered lineup of opponents. The "Gym Leader Castle" mode involves battles against several boss opponents who appeared in the Game Boy games. Pokémon Stadium also features mini-games and numerous features available through its compatibility with Pokémon Red, Blue, and Yellow. Using the Transfer Pak accessory that was bundled with the game, players are able to view, organize, store, trade, and battle using Pokémon uploaded from Pokémon Red, Blue, and Yellow.', 'https://media.retroachievements.org/Images/026595.png', 'https://media.retroachievements.org/Images/010940.png', 'https://media.retroachievements.org/Images/011020.png', 'https://media.retroachievements.org/Images/011021.png', 4.5),
  (18, 10270, 'Pokémon Puzzle League', 'Nintendo 64', 2, 2677, 2677, 2677, 52, 0, NULL, NULL, 'Nintendo', '2000-09-25', 'Pokémon Puzzle League is a puzzle video game in the Puzzle League series developed by Nintendo Software Technology and published by Nintendo for the Nintendo 64. Released in North America on September 25, 2000, and in Europe on March 2, 2001, its Puzzle League-based gameplay has a focus on puzzle-based strategy in the game''s grid-based format. To advance to new levels, players are required to combat the game''s trainers and gym leaders, similar to the ones featured in Pokémon Red, Blue, and Yellow. One of several games based on the Pokémon anime, it features lead protagonist Ash Ketchum, his Pikachu, his companions Brock and Misty, the Kanto Gym Leaders, and other characters from the series.', 'https://media.retroachievements.org/Images/109181.png', 'https://media.retroachievements.org/Images/014333.png', 'https://media.retroachievements.org/Images/016162.png', 'https://media.retroachievements.org/Images/016163.png', 4.5),
  (19, 10648, 'Star Wars: Rogue Squadron', 'Nintendo 64', 2, 2516, 2516, 2516, 49, 0, 'Action, Shooter', 'Factor 5, LucasArts | Lucasfilm', 'LucasArts | Lucasfilm', '1998-12-07', 'Star Wars: Rogue Squadron or Star Wars: Rogue Squadron 3D is an arcade-style flight action game co-developed by Factor 5 and LucasArts. The first of the Rogue Squadron trilogy, it was published by LucasArts and Nintendo and released for Microsoft Windows and Nintendo 64 in December 1998. The game''s story was influenced by the Star Wars: X-wing – Rogue Squadron comics and is set in the fictional Star Wars galaxy, taking place primarily between events in the films Star Wars and The Empire Strikes Back. The player controls Luke Skywalker, commander of the elite X-wing pilots known as Rogue Squadron. As the game progresses, Skywalker and Rogue Squadron fight the Galactic Empire in 16 missions across various planets.', 'https://media.retroachievements.org/Images/111879.png', 'https://media.retroachievements.org/Images/019616.png', 'https://media.retroachievements.org/Images/019617.png', 'https://media.retroachievements.org/Images/045695.png', 4.5),
  (20, 10259, 'Mario Golf', 'Nintendo 64', 2, 2026, 2026, 2026, 115, 0, 'Sports - Golf', 'Camelot Software Planning', 'Nintendo', '1999-06-30', '  There have been numerous sports games featuring Mario characters, based, among others, on tennis, golf, baseball, soccer, and various sports featured in the Olympic Games.', 'https://media.retroachievements.org/Images/027468.png', 'https://media.retroachievements.org/Images/011029.png', 'https://media.retroachievements.org/Images/011027.png', 'https://media.retroachievements.org/Images/011028.png', 4.4),
  (21, 10110, 'Perfect Dark', 'Nintendo 64', 2, 1996, 1996, 1996, 130, 0, 'First-Person Shooter, Stealth', 'Rare', 'Rare', '2000-05-22', 'Perfect Dark is a 2000 first-person shooter game developed and published by Rare for the Nintendo 64. The first game of the Perfect Dark series, it follows Joanna Dark, an agent of the Carrington Institute research centre, as she attempts to stop an extraterrestrial conspiracy by rival corporation dataDyne. The game features a campaign mode where the player must complete a series of levels to progress through the story, as well as a range of multiplayer options, including a co-operative mode and traditional deathmatch settings with computer-controlled bots.', 'https://media.retroachievements.org/Images/107798.png', 'https://media.retroachievements.org/Images/011065.png', 'https://media.retroachievements.org/Images/011062.png', 'https://media.retroachievements.org/Images/011064.png', 4.4),
  (22, 10264, 'Mario Party 2', 'Nintendo 64', 2, 1967, 1967, 1967, 45, 0, 'Board Game, Party', 'Hudson Soft', 'Nintendo', '1999-12-17', 'Mario Party 2 is a 1999 party video game developed by Hudson Soft and published by Nintendo for the Nintendo 64. The second game in the Mario Party series, it was released in Japan on December 17, 1999, North America on January 24, 2000, and in PAL regions on October 13, 2000. The game received mostly positive reviews from critics, who praised the improvements over the original, as well as the multiplayer and minigames, but criticized the lack of originality, while graphics received a mixed to positive response.', 'https://media.retroachievements.org/Images/040217.png', 'https://media.retroachievements.org/Images/014654.png', 'https://media.retroachievements.org/Images/014651.png', 'https://media.retroachievements.org/Images/028446.png', 4.4),
  (23, 10162, 'Blast Corps', 'Nintendo 64', 2, 1957, 1957, 1957, 24, 0, 'Action, Puzzle', 'Rare', 'Nintendo', '1997-02-28', 'Blast Corps is an action game developed by Rare and published by Nintendo for the Nintendo 64. The player uses vehicles to destroy buildings in the path of a runaway nuclear missile carrier. In the game''s 57 levels, the player solves puzzles by transferring between vehicles to move objects and bridge gaps. It was released in March 1997 in Japan and North America. A wider release followed at the end of that year.', 'https://media.retroachievements.org/Images/125239.png', 'https://media.retroachievements.org/Images/014502.png', 'https://media.retroachievements.org/Images/010784.png', 'https://media.retroachievements.org/Images/010787.png', 4.4),
  (24, 17500, '~Hack~ B3313', 'Nintendo 64', 2, 1880, 1880, 1880, 298, 0, '3D Platforming, Collect-a-thon', 'chrisrlillo', 'Hack - Super Mario 64', '2021-04-26', 'Super Mario 64 is a 1996 platform game developed and published by Nintendo for the Nintendo 64. It is the first Super Mario game to feature 3D gameplay, combining traditional Super Mario gameplay, visual style, and characters in a large open world. In the game, Bowser invades Princess Peach''s castle, kidnaps her, and hides the castle''s sources of protection, the Power Stars, in many different worlds inside magical paintings. As Mario, the player traverses levels and collects Power Stars to unlock areas of Princess Peach''s castle, to reach Bowser and rescue Princess Peach.', 'https://media.retroachievements.org/Images/068471.png', 'https://media.retroachievements.org/Images/068468.png', 'https://media.retroachievements.org/Images/068470.png', 'https://media.retroachievements.org/Images/068469.png', 4.4),
  (25, 15964, '~Hack~ Smash Remix', 'Nintendo 64', 2, 1775, 1775, 1775, 201, 0, 'Platform Fighting', 'Smash Remix Team', 'Hack - Super Smash Bros.', '2020-12-18', 'Mortal Kombat is an American media franchise centered on a series of fighting video games originally developed by Midway Games in 1992.', 'https://media.retroachievements.org/Images/121623.png', 'https://media.retroachievements.org/Images/101880.png', 'https://media.retroachievements.org/Images/035261.png', 'https://media.retroachievements.org/Images/035258.png', 4.4),
  (26, 10108, 'Mario Party 3', 'Nintendo 64', 2, 1722, 1722, 1722, 72, 0, 'Board Game, Party', 'Hudson Soft', 'Nintendo', '2000-12-07', 'Mario Party 3 is a 2000 party video game developed by Hudson Soft and published by Nintendo for the Nintendo 64. The third installment in the Mario Party series, it was first released in Japan on December 7, 2000, in North America on May 7, 2001, in Australia on September 3, 2001, and in Europe on November 16, 2001. As with the previous installments, the player chooses between eight playable characters: Mario, Luigi, Princess Peach, Yoshi, Wario, and Donkey Kong from the first two games, alongside newcomers Princess Daisy and Waluigi. The game introduces duel maps, where two players try to lower each other''s stamina to zero using non-player characters such as Chain Chomps.', 'https://media.retroachievements.org/Images/040226.png', 'https://media.retroachievements.org/Images/011082.png', 'https://media.retroachievements.org/Images/011080.png', 'https://media.retroachievements.org/Images/026385.png', 4.4),
  (27, 10153, 'Star Wars: Shadows of the Empire', 'Nintendo 64', 2, 1663, 1663, 1663, 38, 0, 'Action', 'LucasArts | Lucasfilm', 'Nintendo, LucasArts | Lucasfilm', '1996-12-03', 'Star Wars: Shadows of the Empire is a 1996 multimedia project created by Lucasfilm. The idea was to create a story set between the films The Empire Strikes Back and Return of the Jedi, and to explore all commercial possibilities of a full motion picture release without actually making a film. The venture was intended to reinvigorate interest in the franchise ahead of the theatrical Special Editions of the Star Wars trilogy released the following year.', 'https://media.retroachievements.org/Images/055047.png', 'https://media.retroachievements.org/Images/010757.png', 'https://media.retroachievements.org/Images/010755.png', 'https://media.retroachievements.org/Images/010756.png', 4.4),
  (28, 12984, 'The New Tetris', 'Nintendo 64', 2, 1654, 1654, 1654, 27, 0, 'Falling Block Puzzle', 'H2O Entertainment', 'Nintendo', '1999-07-31', 'The New Tetris is a 1999 puzzle video game developed by H2O Entertainment and Blue Planet Software and published by Nintendo for the Nintendo 64. An entry in the Tetris series, it showcases scenic fly-bys of structures, such as the Sphinx, the Pantheon, Saint Basil''s Cathedral, a Mayan temple, and others, rendered in real-time. Achieving this level of quality was relatively challenging for the Nintendo 64 hardware. The New Tetris features a multiplayer mode with up to four players and an electronic dance music soundtrack by Neil Voss, who also composed the music for Tetrisphere.', 'https://media.retroachievements.org/Images/052609.png', 'https://media.retroachievements.org/Images/018277.png', 'https://media.retroachievements.org/Images/018278.png', 'https://media.retroachievements.org/Images/018279.png', 4.4),
  (29, 10238, 'Road Rash 64', 'Nintendo 64', 2, 1648, 1648, 1648, 52, 0, 'Racing', 'Pacific Coast Power and Light', 'THQ', '1999-01-01', 'Road Rash 64 is a 1999 racing game developed by Pacific Coast Power and Light and published by THQ for the Nintendo 64. The game is the fifth of seven entries in the Road Rash series of video games, the only entry to be published by THQ and the only entry to be released for the Nintendo 64 platform.', 'https://media.retroachievements.org/Images/083611.png', 'https://media.retroachievements.org/Images/044926.png', 'https://media.retroachievements.org/Images/044928.png', 'https://media.retroachievements.org/Images/044927.png', 4.4),
  (30, 10258, 'Pokémon Stadium 2', 'Nintendo 64', 2, 1617, 1617, 1617, 109, 0, 'Turn-Based Strategy', 'HAL Laboratory', 'Nintendo', '2000-12-14', 'Pokémon Stadium 2, known in Japan as Pokémon Stadium Gold & Silver, is a strategy video game developed and published by Nintendo for the Nintendo 64. It is the third game in the Pokémon Stadium series, following prior releases Pocket Monsters Stadium and Pokémon Stadium. It features all 251 Pokémon from the first and second generations of the franchise, and allows for players to battle either with other players or against computer-controlled opponents. Like its predecessor, Pokémon Stadium 2 is compatible with the Transfer Pak accessory, allowing players to use Pokémon trained in the three original Game Boy Pokémon games and the three Game Boy Color games.', 'https://media.retroachievements.org/Images/115110.png', 'https://media.retroachievements.org/Images/011026.png', 'https://media.retroachievements.org/Images/011022.png', 'https://media.retroachievements.org/Images/011024.png', 4.4),
  (31, 10077, 'Resident Evil 2', 'Nintendo 64', 2, 1460, 1460, 1460, 120, 0, 'Survival Horror', 'Capcom', 'Capcom', '1999-11-16', 'Resident Evil 2 is a 1998 survival horror video game developed and published by Capcom for the PlayStation. It is the second main installment in the Resident Evil series. The player controls rookie cop Leon S. Kennedy and college student Claire Redfield, who must escape Raccoon City after its citizens are transformed into zombies by a biological weapon two months after the events of the original Resident Evil. The gameplay focuses on exploration, puzzles, and combat; the main difference from its predecessor are the branching paths, with each player character having unique storylines, partners and obstacles.', 'https://media.retroachievements.org/Images/069061.png', 'https://media.retroachievements.org/Images/016137.png', 'https://media.retroachievements.org/Images/010870.png', 'https://media.retroachievements.org/Images/010872.png', 4.4),
  (32, 27577, '~Hack~ Shotgun Mario 64', 'Nintendo 64', 2, 1387, 1387, 1387, 64, 0, '3D Platforming', 'Dan_GPTV', 'Hack - Super Mario 64', '2023-10-22', 'Celeste 64: Fragments of the Mountain is a 2024 3D platformer video game developed and published by Canadian indie studio Extremely OK Games for Linux, macOS and Microsoft Windows. The game was developed during a week-long game jam, in which it released in celebration of the sixth anniversary of the 2018 video game Celeste. The game released January 29, 2024, acting as semi-sequel to that game and a continuation to its narrative.', 'https://media.retroachievements.org/Images/086766.png', 'https://media.retroachievements.org/Images/105646.png', 'https://media.retroachievements.org/Images/087056.png', 'https://media.retroachievements.org/Images/087055.png', 4.4),
  (33, 10085, 'Cruis''n USA', 'Nintendo 64', 2, 1361, 1361, 1361, 43, 0, 'Arcade Racing', 'Williams', 'Nintendo', '1996-10-31', 'Cruis''n USA is a racing video game developed by TV Games Inc. and published by Nintendo. It was first released in arcades in 1994 by Midway Games, with a port to the Nintendo 64 developed by Leland Interactive Media released in 1996. It is the first game in the Cruis''n series, and features races set in locations across the Continental United States.', 'https://media.retroachievements.org/Images/044270.png', 'https://media.retroachievements.org/Images/010998.png', 'https://media.retroachievements.org/Images/010995.png', 'https://media.retroachievements.org/Images/010996.png', 4.4),
  (34, 10116, 'Mortal Kombat 4', 'Nintendo 64', 2, 1354, 1354, 1354, 130, 0, '3D Fighting', 'Eurocom', 'Midway', '1998-06-23', 'Mortal Kombat 4 is a 1997 fighting game developed and published by Midway for arcades. It is the fourth main installment in the Mortal Kombat franchise, and a sequel to 1995''s Mortal Kombat 3. It is also the first title in the series to use 3D computer graphics, as well as the last in the series to have an arcade release. The game was ported to the PlayStation, Nintendo 64, Microsoft Windows, and Game Boy Color in 1998, followed by an updated version, titled Mortal Kombat Gold, for the Dreamcast in 1999.', 'https://media.retroachievements.org/Images/123570.png', 'https://media.retroachievements.org/Images/042460.png', 'https://media.retroachievements.org/Images/042458.png', 'https://media.retroachievements.org/Images/012068.png', 4.4),
  (35, 10148, 'Army Men: Sarge''s Heroes', 'Nintendo 64', 2, 1337, 1337, 1337, 65, 0, 'Third-Person Shooter', 'The 3DO Company', 'The 3DO Company', '1999-09-28', 'Army Men: Sarge''s Heroes is a 1999 third-person shooter video game and the fourth entry in The 3DO Company''s Army Men series, which are based on the green plastic figures of the same name. Its Nintendo 64 and PlayStation versions were developed and published by The 3DO Company. The port for the Dreamcast was developed by Saffire and published by Midway, while another for Microsoft Windows was published by GT Interactive.', 'https://media.retroachievements.org/Images/107432.png', 'https://media.retroachievements.org/Images/079976.png', 'https://media.retroachievements.org/Images/015292.png', 'https://media.retroachievements.org/Images/015293.png', 4.3),
  (36, 10256, 'Mickey''s Speedway USA', 'Nintendo 64', 2, 1308, 1308, 1308, 72, 0, 'Kart Racing', 'Rare', 'Nintendo', '2000-11-13', 'Mickey''s Speedway USA is a kart racing game developed by Rare and published by Nintendo for the Nintendo 64 and Game Boy Color. It is Rare and Nintendo''s second collaboration with Disney Interactive following Mickey''s Racing Adventure (1999), and features characters from the Mickey Mouse universe racing across the United States. The Nintendo 64 game released in November 2000 to mixed reception, while the Game Boy Color version followed in March 2001.', 'https://media.retroachievements.org/Images/112014.png', 'https://media.retroachievements.org/Images/018506.png', 'https://media.retroachievements.org/Images/028670.png', 'https://media.retroachievements.org/Images/028671.png', 4.3),
  (37, 10309, 'Glover', 'Nintendo 64', 2, 1287, 1287, 1287, 49, 0, '3D Platforming, Collect-a-thon', 'Blitz Games', 'Hasbro Interactive', '1998-11-16', 'Glover is a 1998 puzzle-platformer developed by Interactive Studios and published by Hasbro Interactive for the Nintendo 64 and Windows in 1998, and for the PlayStation in 1999. The game follows a magical, four-fingered glove named Glover in his quest to restore the Crystal Kingdom by retrieving crystals that were lost.', 'https://media.retroachievements.org/Images/069876.png', 'https://media.retroachievements.org/Images/025061.png', 'https://media.retroachievements.org/Images/025064.png', 'https://media.retroachievements.org/Images/099202.png', 4.3),
  (38, 10120, 'Bomberman 64', 'Nintendo 64', 2, 1242, 1242, 1242, 69, 0, 'Action, Puzzle', 'Hudson Soft', 'Nintendo', '1997-09-26', 'Bomberman 64 is a video game developed and published by Hudson Soft as "Baku Bomberman" in Japan, and published by Nintendo as "Bomberman 64" in North America and Europe for the Nintendo 64. In Japan the "Bomberman 64" name was chosen for another game, the fourth Japanese Bomberman entry in the series. The 1997 game was released in Europe and North America in November and December 1997, respectively. While the game never saw a release on the Wii''s Virtual Console service, it was released on the Wii U Virtual Console in both Europe and North America in March 2017 followed by Japan in June 2017.', 'https://media.retroachievements.org/Images/053933.png', 'https://media.retroachievements.org/Images/011136.png', 'https://media.retroachievements.org/Images/011137.png', 'https://media.retroachievements.org/Images/011138.png', 4.3),
  (39, 10328, 'South Park', 'Nintendo 64', 2, 1219, 1219, 1219, 53, 0, 'First-Person Shooter', 'Iguana Entertainment', 'Acclaim', '1998-12-12', 'South Park is an American animated sitcom created by Trey Parker and Matt Stone for Comedy Central. The series revolves around four boys—Stan Marsh, Kyle Broflovski, Eric Cartman, and Kenny McCormick—and their adventures in and around the titular Colorado town. South Park also features many recurring characters. The series became infamous for its profanity and dark, surreal humor that satirizes a large range of subject matter.', 'https://media.retroachievements.org/Images/088517.png', 'https://media.retroachievements.org/Images/011926.png', 'https://media.retroachievements.org/Images/011927.png', 'https://media.retroachievements.org/Images/011928.png', 4.3),
  (40, 10157, 'Harvest Moon 64', 'Nintendo 64', 2, 1190, 1190, 1190, 80, 0, 'Life Simulation', 'Marvelous Interactive', 'Natsume', '1999-02-05', 'Harvest Moon 64, released in Japan as Bokujō Monogatari 2 (牧場物語2), is a 1999 farm simulation video game developed by Victor Interactive Software for the Nintendo 64 console. It was published by Victor Interactive in Japan and by Natsume Inc. in North America. It is the third game in the Story of Seasons series.', 'https://media.retroachievements.org/Images/109404.png', 'https://media.retroachievements.org/Images/010767.png', 'https://media.retroachievements.org/Images/010765.png', 'https://media.retroachievements.org/Images/010766.png', 4.3),
  (41, 10093, 'Hexen', 'Nintendo 64', 2, 1179, 1179, 1179, 66, 0, 'First-Person Shooter', 'Software Creations', 'Atari', '1997-05-31', 'Hexen: Beyond Heretic is a 1995 first-person shooter video game developed by Raven Software and published by id Software for MS-DOS. It is the sequel to 1994''s Heretic, and the second game in Raven Software''s "Serpent Riders" trilogy, which culminated with Hexen II. The title comes from the German noun Hexen, which means "witches", and/or the verb hexen, which means "to cast a spell". Game producer John Romero stated that a third, unreleased game in this series was to be called Hecatomb.', 'https://media.retroachievements.org/Images/055046.png', 'https://media.retroachievements.org/Images/014510.png', 'https://media.retroachievements.org/Images/010999.png', 'https://media.retroachievements.org/Images/011000.png', 4.3),
  (42, 16231, 'Donald Duck: Goin'' Quackers', 'Nintendo 64', 2, 1163, 1163, 1163, 64, 0, '3D Platforming', 'Ubisoft', 'Ubisoft', '2000-12-08', 'Donald Duck: Goin'' Quackers is a 2000 platform game developed and published by Ubi Soft for various consoles and Windows-based personal computers. A version with the same title was released for the Game Boy Color, before it was retitled Donald Duck Advance for the Game Boy Advance. Reviews praised the music, backgrounds and animations, noting the short length and low difficulty as more fun for children.', 'https://media.retroachievements.org/Images/113851.png', 'https://media.retroachievements.org/Images/033332.png', 'https://media.retroachievements.org/Images/033330.png', 'https://media.retroachievements.org/Images/033331.png', 4.3),
  (43, 10080, 'Doom 64', 'Nintendo 64', 2, 1162, 1162, 1162, 88, 0, 'First-Person Shooter', 'Midway', 'Midway', '1997-03-31', 'Doom 64 is a 1997 first-person shooter game developed and published by Midway Games for the Nintendo 64. It is the second spin-off in id Software''s Doom series after Final Doom (1996), and the fourth game in the series overall.', 'https://media.retroachievements.org/Images/010650.png', 'https://media.retroachievements.org/Images/066513.png', 'https://media.retroachievements.org/Images/010646.png', 'https://media.retroachievements.org/Images/010647.png', 4.3),
  (44, 10166, 'Cruis''n World', 'Nintendo 64', 2, 1157, 1157, 1157, 76, 0, 'Arcade Racing', 'Eurocom', 'Nintendo', '1998-09-28', 'Cruis''n World is a 1996 racing game developed by Midway Games and published by Nintendo. It is the sequel to the 1994 arcade racer Cruis''n USA. A port for the Nintendo 64 developed by Eurocom was released in 1998, and was the best received of the Cruis''n ports.', 'https://media.retroachievements.org/Images/073208.png', 'https://media.retroachievements.org/Images/064742.png', 'https://media.retroachievements.org/Images/010788.png', 'https://media.retroachievements.org/Images/010789.png', 4.3),
  (45, 10081, 'Mystical Ninja Starring Goemon', 'Nintendo 64', 2, 1149, 1149, 1149, 44, 0, '3D Platforming', 'Konami', 'Konami', '1997-08-07', 'Mystical Ninja Starring Goemon is a 1997 platform action-adventure game developed by Konami Computer Entertainment Osaka and published by Konami for the Nintendo 64. The second Ganbare Goemon game released in North America and Europe, and the twelfth mainline installment overall, follows The Legend of the Mystical Ninja and features hybrid elements of platform games and action-adventure games.', 'https://media.retroachievements.org/Images/094020.png', 'https://media.retroachievements.org/Images/050419.png', 'https://media.retroachievements.org/Images/016081.png', 'https://media.retroachievements.org/Images/016082.png', 4.3),
  (46, 30, 'Jet Force Gemini', 'Nintendo 64', 2, 1125, 1125, 1125, 63, 0, 'Collect-a-thon, Third-Person Shooter', 'Rare', 'Rare', '1999-09-01', 'Jet Force Gemini is a 1999 third-person shooter game developed and published by Rare for the Nintendo 64. The game follows the story of three members of a galactic law enforcement team as they try to stop a horde of drones led by an insectoid called Mizar. It features a single-player mode where the player must explore a galaxy and save Tribals, a race of survivors who have been enslaved and imprisoned by Mizar, and places strong emphasis on shooting large numbers of enemies while dodging their attacks. The game includes a multiplayer mode where two to four players can compete in traditional deathmatch games.', 'https://media.retroachievements.org/Images/112099.png', 'https://media.retroachievements.org/Images/051950.png', 'https://media.retroachievements.org/Images/020099.png', 'https://media.retroachievements.org/Images/017046.png', 4.3),
  (47, 10546, '~Hack~ Super Mario 74', 'Nintendo 64', 2, 1097, 1097, 1097, 58, 0, '3D Platforming', 'Hacker - Lugmillord', 'Hack - Super Mario 64', '2011-06-27', 'Super Mario 64 is a 1996 platform game developed and published by Nintendo for the Nintendo 64. It is the first Super Mario game to feature 3D gameplay, combining traditional Super Mario gameplay, visual style, and characters in a large open world. In the game, Bowser invades Princess Peach''s castle, kidnaps her, and hides the castle''s sources of protection, the Power Stars, in many different worlds inside magical paintings. As Mario, the player traverses levels and collects Power Stars to unlock areas of Princess Peach''s castle, to reach Bowser and rescue Princess Peach.', 'https://media.retroachievements.org/Images/085735.png', 'https://media.retroachievements.org/Images/017494.png', 'https://media.retroachievements.org/Images/017493.png', 'https://media.retroachievements.org/Images/085736.png', 4.3),
  (48, 10912, 'Hot Wheels: Turbo Racing', 'Nintendo 64', 2, 1093, 1093, 1093, 63, 0, 'Arcade Racing', 'Stormfront Studios', 'Electronic Arts', '1999-08-31', 'Hot Wheels Turbo Racing is a racing video game released for the Nintendo 64 and PlayStation in 1999. It features 40 cars based on the Hot Wheels series of toys. It also features Kyle Petty''s 1999 NASCAR stock car, as it was sponsored by Hot Wheels. The game features music from artists like Primus, Metallica, The Reverend Horton Heat and Mix Master Mike.', 'https://media.retroachievements.org/Images/073192.png', 'https://media.retroachievements.org/Images/022299.png', 'https://media.retroachievements.org/Images/022300.png', 'https://media.retroachievements.org/Images/022301.png', 4.3),
  (49, 10331, 'WWF No Mercy', 'Nintendo 64', 2, 1074, 1074, 1074, 36, 0, 'Sports - Wrestling', 'AKI Corporation', 'THQ', '2000-11-17', 'WWE No Mercy, also known as NXT No Mercy since 2023, is a professional wrestling event produced by WWE, a professional wrestling promotion based in Connecticut. The first No Mercy was held on May 16, 1999, in Manchester, England, and was the only No Mercy event produced in the United Kingdom. A second No Mercy was then held in October that year in Cleveland, Ohio, United States. Beginning with this second event, No Mercy became the annual October pay-per-view (PPV) until 2008. The event was then discontinued and replaced by Hell in a Cell in 2009. After eight years, No Mercy was reinstated in October 2016. However, No Mercy was again discontinued after the September 2017 event, as WWE reduced the amount of yearly PPVs held after they had ended the production of brand-exclusive PPVs following WrestleMania 34 in 2018. In 2023, WWE again revived the event, this time for its developmental brand, NXT, in September.', 'https://media.retroachievements.org/Images/054255.png', 'https://media.retroachievements.org/Images/012048.png', 'https://media.retroachievements.org/Images/012047.png', 'https://media.retroachievements.org/Images/012049.png', 4.3),
  (50, 10135, '007: The World Is Not Enough', 'Nintendo 64', 2, 1036, 1036, 1036, 100, 0, 'First-Person Shooter', 'Eurocom', 'Electronic Arts', '2000-11-01', 'The World Is Not Enough is a 2000 first-person shooter video game developed by Eurocom and published by Electronic Arts. It is based on the 1999 film of the same name. It was released for the Nintendo 64 in North America on October 17, 2000 and in Europe on December 8, 2000. The game was also released for the PlayStation in November. The game features a single-player campaign in which players assume the role of secret agent James Bond as he fights to stop a terrorist from triggering a nuclear meltdown in the waters of Istanbul. It includes a split-screen multiplayer mode where up to four players can compete in different types of deathmatch and objective-based games.', 'https://media.retroachievements.org/Images/071854.png', 'https://media.retroachievements.org/Images/071811.png', 'https://media.retroachievements.org/Images/023342.png', 'https://media.retroachievements.org/Images/023344.png', 4.3),
  (51, 10329, 'Rampage 2: Universal Tour', 'Nintendo 64', 2, 1030, 1030, 1030, 25, 0, 'Action', 'Avalanche Software', 'Midway', '1999-03-01', 'Rampage 2: Universal Tour is a 1999 action game developed by Avalanche Software and published by Midway. It is the third game in the Rampage series and a sequel to 1997''s Rampage World Tour.', 'https://media.retroachievements.org/Images/098726.png', 'https://media.retroachievements.org/Images/014515.png', 'https://media.retroachievements.org/Images/011934.png', 'https://media.retroachievements.org/Images/041267.png', 4.3),
  (52, 10871, 'Magical Tetris Challenge', 'Nintendo 64', 2, 1025, 1025, 1025, 34, 0, NULL, 'Capcom', 'Capcom', '1998-11-20', 'Magical Tetris Challenge is a 1998 puzzle video game developed and published by Capcom for arcades. It was ported to the Nintendo 64, Game Boy Color and PlayStation. It is a version of Tetris featuring Disney characters. It is one of the few Nintendo 64 games to be entirely in 2D, in addition to being Capcom''s first game for the console. The Japanese arcade cabinet and cover art was done by Kenichi Sudo, while the North American cover art was done by Robert Griggs.', 'https://media.retroachievements.org/Images/047644.png', 'https://media.retroachievements.org/Images/014730.png', 'https://media.retroachievements.org/Images/014731.png', 'https://media.retroachievements.org/Images/014732.png', 4.3),
  (53, 10199, 'Snowboard Kids', 'Nintendo 64', 2, 1005, 1005, 1005, 25, 0, 'Extreme Sports - Snowboarding, Kart Racing', 'Racjin | Racdym', 'Atlus', '1998-02-01', 'Snowboard Kids , is a snowboarding video game for the Nintendo 64. It was developed by Racdym and published by Atlus. Many reviewers compared its style to that of the Mario Kart series. An enhanced port, Snowboard Kids Plus, was released in Japan in January 1999 for the PlayStation.', 'https://media.retroachievements.org/Images/085925.png', 'https://media.retroachievements.org/Images/014516.png', 'https://media.retroachievements.org/Images/010970.png', 'https://media.retroachievements.org/Images/010971.png', 4.3),
  (54, 10448, 'WCW/nWo Revenge', 'Nintendo 64', 2, 999, 999, 999, 42, 0, 'Sports - Wrestling', 'Asmik Ace Entertainment/AKI Corporation', 'THQ', '1998-10-26', 'WCW/nWo Revenge is a professional wrestling video game developed by Asmik Ace Entertainment and AKI Corporation and released by THQ in 1998 for the Nintendo 64 game console. It is the sequel to 1997''s WCW vs. nWo: World Tour. Like its predecessor, Revenge features AKI''s proprietary grappling system; as well as heavily improved graphics, a championship mode, and a large roster of wrestlers.', 'https://media.retroachievements.org/Images/082170.png', 'https://media.retroachievements.org/Images/027568.png', 'https://media.retroachievements.org/Images/044132.png', 'https://media.retroachievements.org/Images/044133.png', 4.3),
  (55, 10298, 'Tarzan', 'Nintendo 64', 2, 992, 992, 992, 45, 0, '2.5D Platforming', 'Eurocom', 'Activision', '2000-01-31', 'Tarzan is a fictional character, a feral child raised in the Congo Basin by the Mangani great apes; he later experiences civilization, only to reject it and return to the wild as a heroic adventurer.', 'https://media.retroachievements.org/Images/059289.png', 'https://media.retroachievements.org/Images/011925.png', 'https://media.retroachievements.org/Images/077248.png', 'https://media.retroachievements.org/Images/077249.png', 4.3),
  (56, 10509, '~Hack~ Super Mario 64: Randomizer', 'Nintendo 64', 2, 980, 980, 980, 34, 0, '3D Platforming, Collect-a-thon', 'ArthurTilly, JoshDuMan, Hacker - Kaze Emanuar, nim', NULL, '2019-03-29', 'Super Mario 64 is a 1996 platform game developed and published by Nintendo for the Nintendo 64. It is the first Super Mario game to feature 3D gameplay, combining traditional Super Mario gameplay, visual style, and characters in a large open world. In the game, Bowser invades Princess Peach''s castle, kidnaps her, and hides the castle''s sources of protection, the Power Stars, in many different worlds inside magical paintings. As Mario, the player traverses levels and collects Power Stars to unlock areas of Princess Peach''s castle, to reach Bowser and rescue Princess Peach.', 'https://media.retroachievements.org/Images/117531.png', 'https://media.retroachievements.org/Images/093710.png', 'https://media.retroachievements.org/Images/093707.png', 'https://media.retroachievements.org/Images/093708.png', 4.3),
  (57, 12733, '~Hack~ Super Mario 64: Last Impact', 'Nintendo 64', 2, 973, 973, 973, 57, 0, '3D Platforming', 'Hacker - Kaze Emanuar', 'Hack - Super Mario 64', '2016-09-30', 'Super Mario 64 is a 1996 platform game developed and published by Nintendo for the Nintendo 64. It is the first Super Mario game to feature 3D gameplay, combining traditional Super Mario gameplay, visual style, and characters in a large open world. In the game, Bowser invades Princess Peach''s castle, kidnaps her, and hides the castle''s sources of protection, the Power Stars, in many different worlds inside magical paintings. As Mario, the player traverses levels and collects Power Stars to unlock areas of Princess Peach''s castle, to reach Bowser and rescue Princess Peach.', 'https://media.retroachievements.org/Images/069710.png', 'https://media.retroachievements.org/Images/018306.png', 'https://media.retroachievements.org/Images/039419.png', 'https://media.retroachievements.org/Images/017467.png', 4.3),
  (58, 10115, 'Mega Man 64', 'Nintendo 64', 2, 972, 972, 972, 61, 0, 'Action-Adventure, Third-Person Shooter', 'Capcom', 'Capcom', '2001-01-10', 'Mega Man Legends is a 1997 action-adventure game released by Capcom. It is the first game in the Mega Man Legends sub-series of Mega Man games from Capcom, and the second major 3D polygonal Mega Man title in the franchise, following Mega Man: Battle & Chase. It was released for the PlayStation in 1997 in Japan, and in 1998 in North America. A Nintendo 64 port was released in 2000 with the same title, but it was renamed Mega Man 64 for the North American release in 2001. It was also ported to Windows in 2001, and to the PlayStation Portable in 2005, the latter only in Japan. Its most recent release was as a PS one Classic on the North American PlayStation Network in 2015.', 'https://media.retroachievements.org/Images/010690.png', 'https://media.retroachievements.org/Images/010689.png', 'https://media.retroachievements.org/Images/010687.png', 'https://media.retroachievements.org/Images/010688.png', 4.3),
  (59, 10559, '~Hack~ The Legend of Banjo-Kazooie: The Jiggies of Time', 'Nintendo 64', 2, 935, 935, 935, 37, 0, '3D Platforming, Collect-a-thon', 'Hacker - Kurko Mods', 'Hack - Banjo-Kazooie', '2020-07-23', 'Banjo-Kazooie is a 1998 platform game developed by Rare and published by Nintendo for the Nintendo 64. Controlling the player characters, the bear Banjo and the bird Kazooie, the player attempts to save Banjo''s kidnapped sister Tooty from the witch Gruntilda. The player explores nine nonlinear worlds to gather items and progress. Using Banjo and Kazooie''s traversal and combat abilities, they complete challenges such as solving puzzles, jumping over obstacles, and defeating bosses.', 'https://media.retroachievements.org/Images/112578.png', 'https://media.retroachievements.org/Images/035827.png', 'https://media.retroachievements.org/Images/035819.png', 'https://media.retroachievements.org/Images/035823.png', 4.3),
  (60, 10118, 'Toy Story 2: Buzz Lightyear to the Rescue!', 'Nintendo 64', 2, 933, 933, 933, 63, 0, '3D Platforming, Collect-a-thon', NULL, 'Activision', '1999-11-30', 'Toy Story 2: Buzz Lightyear to the Rescue is a 1999 platform game developed by Traveller''s Tales and published by Activision and Disney Interactive. Based on Disney/Pixar''s 1999 computer animated film Toy Story 2, it was released for the Nintendo 64, PlayStation, Microsoft Windows, and Macintosh in late 1999, while a Dreamcast version followed in 2000. The computer versions were released under the title Disney/Pixar''s Action Game, Toy Story 2. A different version, a side-scrolling platform game titled Toy Story 2, was also released for the Game Boy Color in 1999.', 'https://media.retroachievements.org/Images/103350.png', 'https://media.retroachievements.org/Images/049037.png', 'https://media.retroachievements.org/Images/019557.png', 'https://media.retroachievements.org/Images/019556.png', 4.3),
  (61, 10285, 'Bomberman Hero', 'Nintendo 64', 2, 920, 920, 920, 43, 0, '3D Platforming, Action', 'AI', 'Hudson Soft, Nintendo', '1998-04-30', 'Bomberman Hero is a platform video game developed by A.I Co., Ltd. and published by Hudson Soft for the Nintendo 64. It is the second Bomberman game to be released on the system, following Bomberman 64 (1997). It is notable for being a dramatic deviation from previous Bomberman titles, featuring predominant platforming gameplay as opposed to the series'' traditional top-down strategy gameplay.', 'https://media.retroachievements.org/Images/074332.png', 'https://media.retroachievements.org/Images/011147.png', 'https://media.retroachievements.org/Images/011148.png', 'https://media.retroachievements.org/Images/011146.png', 4.3),
  (62, 10182, 'Turok: Dinosaur Hunter', 'Nintendo 64', 2, 899, 899, 899, 52, 0, 'First-Person Shooter', 'Iguana Entertainment', 'Acclaim', '1997-02-28', 'Turok: Dinosaur Hunter is a first-person shooter video game developed by Iguana Entertainment and published by Acclaim Entertainment. It was released in 1997 in North America and Europe for the Nintendo 64 and Microsoft Windows, and is an adaptation of the Valiant Comics comic book series of the same name. The player controls Turok, a Native American warrior who must stop the evil Campaigner from conquering the universe with an ancient and powerful weapon.', 'https://media.retroachievements.org/Images/020130.png', 'https://media.retroachievements.org/Images/011072.png', 'https://media.retroachievements.org/Images/011068.png', 'https://media.retroachievements.org/Images/011075.png', 4.3),
  (63, 10337, 'Spider-Man', 'Nintendo 64', 2, 894, 894, 894, 37, 0, '3D Platforming, Beat ''em Up', 'Edge of Reality', 'Activision', '2000-11-21', 'Spider-Man is a superhero in American comic books published by Marvel Comics. Created by writer-editor Stan Lee and artist Steve Ditko, he first appeared in the anthology comic book Amazing Fantasy #15 in the Silver Age of Comic Books. Widely regarded as one of the most popular and commercially successful superheroes, he has been featured in comic books, television shows, films, video games, novels, and plays.', 'https://media.retroachievements.org/Images/107338.png', 'https://media.retroachievements.org/Images/012410.png', 'https://media.retroachievements.org/Images/019554.png', 'https://media.retroachievements.org/Images/019555.png', 4.3),
  (64, 10136, '1080° Snowboarding', 'Nintendo 64', 2, 886, 886, 886, 39, 0, 'Extreme Sports - Snowboarding', NULL, 'Nintendo', '1998-03-31', '1080° Snowboarding is a snowboarding video game developed and published by Nintendo for the Nintendo 64 in 1998. In the game, players control one of five snowboarders from a third-person perspective, using a combination of buttons to jump and perform tricks across eight levels.', 'https://media.retroachievements.org/Images/011233.png', 'https://media.retroachievements.org/Images/034964.png', 'https://media.retroachievements.org/Images/011234.png', 'https://media.retroachievements.org/Images/011235.png', 4.3),
  (65, 10129, 'Fighting Force 64', 'Nintendo 64', 2, 884, 884, 884, 90, 0, 'Beat ''em Up', 'Core Design', 'Crave Entertainment', '1999-04-30', 'Fighting Force is a beat ''em up video game developed by Core Design and published in 1997 by Eidos Interactive for PlayStation and Windows. A Nintendo 64 version was published by Crave Entertainment in 1999. The Japanese version for the PlayStation was published by Electronic Arts Victor. Announced by Core shortly after the success of Tomb Raider, Fighting Force was highly anticipated but met with mixed reviews. It was followed by Fighting Force 2.', 'https://media.retroachievements.org/Images/063155.png', 'https://media.retroachievements.org/Images/014507.png', 'https://media.retroachievements.org/Images/011045.png', 'https://media.retroachievements.org/Images/011046.png', 4.3),
  (66, 10124, 'Tony Hawk''s Pro Skater', 'Nintendo 64', 2, 872, 872, 872, 35, 0, 'Extreme Sports - Skateboarding', 'Edge of Reality', 'Activision', '2000-02-01', 'Tony Hawk''s Pro Skater, released as Tony Hawk''s Skateboarding in the United Kingdom, Australia, New Zealand, and parts of Europe, is a 1999 skateboarding video game developed by Neversoft and published by Activision. It is the first installment in the Tony Hawk''s series. It was released for the PlayStation on September 29, 1999 and was later ported to the Nintendo 64, Game Boy Color, Dreamcast, and N-Gage.', 'https://media.retroachievements.org/Images/115224.png', 'https://media.retroachievements.org/Images/071343.png', 'https://media.retroachievements.org/Images/017042.png', 'https://media.retroachievements.org/Images/017044.png', 4.3),
  (67, 16504, '~Hack~ The Legend of Zelda: The Missing Link', 'Nintendo 64', 2, 871, 871, 871, 16, 0, 'Action-Adventure', 'Hacker - Kaze Emanuar, CDi-Falls, Zel', 'Hack - The Legend of Zelda: Ocarina of Time', '2020-07-25', 'The Legend of Zelda is a video game series created by Japanese game designers Shigeru Miyamoto and Takashi Tezuka. It is primarily developed and published by Nintendo, but some installments and re-releases have been outsourced to Flagship, Grezzo, and Tantalus Media.', 'https://media.retroachievements.org/Images/036028.png', 'https://media.retroachievements.org/Images/036009.png', 'https://media.retroachievements.org/Images/035982.png', 'https://media.retroachievements.org/Images/036010.png', 4.3),
  (68, 10269, 'Rayman 2: The Great Escape', 'Nintendo 64', 2, 863, 863, 863, 49, 0, '3D Platforming, Collect-a-thon', 'Ubisoft', 'Ubisoft', '1999-11-06', 'Rayman 2: The Great Escape is a 1999 platform game developed by Ubi Pictures and published by Ubi Soft for the Nintendo 64, Windows, Dreamcast and PlayStation. The game centers on the titular character Rayman, who is tasked with saving the fantastical land of the Fairy Glade from an army of robotic pirates led by Admiral Razorbeard.', 'https://media.retroachievements.org/Images/064754.png', 'https://media.retroachievements.org/Images/014327.png', 'https://media.retroachievements.org/Images/091524.png', 'https://media.retroachievements.org/Images/091523.png', 4.3),
  (69, 17494, '~Hack~ Banjo-Kazooie: Nostalgia 64', 'Nintendo 64', 2, 838, 838, 838, 48, 0, '3D Platforming, Collect-a-thon', 'Hacker - Kurko Mods', 'Hack - Banjo-Kazooie', '2025-05-16', 'Banjo-Kazooie is a 1998 platform game developed by Rare and published by Nintendo for the Nintendo 64. Controlling the player characters, the bear Banjo and the bird Kazooie, the player attempts to save Banjo''s kidnapped sister Tooty from the witch Gruntilda. The player explores nine nonlinear worlds to gather items and progress. Using Banjo and Kazooie''s traversal and combat abilities, they complete challenges such as solving puzzles, jumping over obstacles, and defeating bosses.', 'https://media.retroachievements.org/Images/112116.png', 'https://media.retroachievements.org/Images/112226.png', 'https://media.retroachievements.org/Images/111802.png', 'https://media.retroachievements.org/Images/111803.png', 4.3),
  (70, 10347, 'Quake 64', 'Nintendo 64', 2, 814, 814, 814, 95, 0, 'First-Person Shooter', 'Midway Studios', 'Midway', '1998-03-24', 'Quake is a 1996 first-person shooter video game developed by id Software and published by GT Interactive. The first game in the Quake series, it was originally released for MS-DOS and Windows, followed by Classic Mac OS, Linux, and Saturn in 1997 and Nintendo 64 in 1998.', 'https://media.retroachievements.org/Images/020238.png', 'https://media.retroachievements.org/Images/036508.png', 'https://media.retroachievements.org/Images/036506.png', 'https://media.retroachievements.org/Images/036507.png', 4.3),
  (71, 10216, 'Quest 64', 'Nintendo 64', 2, 807, 807, 807, 32, 0, 'Turn-Based RPG', 'Imagineer', 'THQ', '1998-06-01', 'Quest 64 is a role-playing video game (RPG) developed by Imagineer for the Nintendo 64. It was released in North America in June 1998 by THQ, Europe in September 1998 by Konami and Japan in July 1999 by Imagineer. It is the first role-playing video game released for the system in North America.', 'https://media.retroachievements.org/Images/066089.png', 'https://media.retroachievements.org/Images/014514.png', 'https://media.retroachievements.org/Images/011871.png', 'https://media.retroachievements.org/Images/011872.png', 4.3),
  (72, 10168, 'LEGO Racers', 'Nintendo 64', 2, 800, 800, 800, 53, 0, 'Kart Racing', 'High Voltage Software', 'LEGO Interactive | LEGO Media', '1999-10-12', 'Lego Racers is a 1999 Lego-themed kart racing video game developed by High Voltage Software and published by Lego Media for Microsoft Windows, followed by console ports to Nintendo 64 and PlayStation. Set in the fictional "Legoland" universe, the single-player mode follows various minifigure characters competing in a racing competition created by a fictional racing champion called Rocket Racer.', 'https://media.retroachievements.org/Images/063603.png', 'https://media.retroachievements.org/Images/010796.png', 'https://media.retroachievements.org/Images/010794.png', 'https://media.retroachievements.org/Images/010795.png', 4.3),
  (73, 10685, 'Sesame Street: Elmo''s Letter Adventure', 'Nintendo 64', 2, 800, 800, 800, 16, 0, 'Educational', 'Realtime Associates', 'NewKidCo', '1999-11-15', ' There have been a variety of Sesame Street video games released for video game platforms. Most of the Sesame Street video games were published and developed by NewKidCo.', 'https://media.retroachievements.org/Images/116921.png', 'https://media.retroachievements.org/Images/047409.png', 'https://media.retroachievements.org/Images/042796.png', 'https://media.retroachievements.org/Images/045349.png', 4.3),
  (74, 20279, '~Hack~ The Preservation Project', 'Nintendo 64', 2, 792, 792, 792, 8, 0, NULL, 'Fluvian, MarioNova', 'Hack - Super Mario 64', '2022-06-08', ' The Nintendo 64 is a video game console released by Nintendo in 1996. The console was a moderate success with 32.93 millions units sold; it was three times as much as one competitor, the Sega Saturn, but only a third of the sales of its other competitor, the original PlayStation. Third party game developers cancelled multiple games for the system, with commonly-cited reasons including its lower sales numbers compared to the PlayStation, its unconventional controller, and Nintendo''s decision to stick with the game cartridge format, which was more costly to produce and featured far less storage than the PlayStation''s CD-ROMs. Additionally, the brief lifespan and commercial failure of the 64DD, a Japan-only Nintendo 64 add-on, led to many of its games being cancelled, reworked for release on the standard Nintendo 64, or ported to its successor, the GameCube. This list documents games that were announced for the Nintendo 64 at some point, but did not end up being released for it in any capacity. It also documents cancelled 64DD games, as well as unreleased 64DD-specific versions of other Nintendo 64 games.', 'https://media.retroachievements.org/Images/121472.png', 'https://media.retroachievements.org/Images/067966.png', 'https://media.retroachievements.org/Images/067968.png', 'https://media.retroachievements.org/Images/067969.png', 4.3),
  (75, 14897, '~Hack~ Super Mario 64: Splitscreen Multiplayer', 'Nintendo 64', 2, 776, 776, 776, 29, 0, '3D Platforming, Collect-a-thon', 'Hacker - Kaze Emanuar', 'Hack - Super Mario 64', '2020-01-16', 'The following is a list of video games that feature cooperative gameplay, either as a primary or secondary gameplay mode.', 'https://media.retroachievements.org/Images/112472.png', 'https://media.retroachievements.org/Images/029212.png', 'https://media.retroachievements.org/Images/029862.png', 'https://media.retroachievements.org/Images/029925.png', 4.2),
  (76, 10198, 'Goemon''s Great Adventure', 'Nintendo 64', 2, 773, 773, 773, 86, 0, '2D Platforming', 'Konami', 'Konami', '1998-12-23', 'Goemon''s Great Adventure, known as Mystical Ninja 2 Starring Goemon in Europe, is a video game developed and released by Konami for the Nintendo 64 on December 23, 1998. It is the fourth game in the Ganbare Goemon series released in North America and Europe, as well as the fourteenth and latest overall mainline installment, following Mystical Ninja Starring Goemon, released two years earlier. Featuring platform gameplay in 2.5D, it returns the series to a side-scrolling format.', 'https://media.retroachievements.org/Images/047181.png', 'https://media.retroachievements.org/Images/011156.png', 'https://media.retroachievements.org/Images/011149.png', 'https://media.retroachievements.org/Images/011152.png', 4.2),
  (77, 10186, 'Ridge Racer 64', 'Nintendo 64', 2, 744, 744, 744, 40, 0, 'Arcade Racing', 'Namco', 'Nintendo', '2000-02-01', 'Ridge Racer 64 is a 2000 racing video game developed by Nintendo Software Technology and published by Nintendo for the Nintendo 64. It is the first title of Namco''s Ridge Racer series to not be on arcades or a PlayStation console, with Namco licensing the series to Nintendo to develop the game. In 2004, the game was remade for the Nintendo DS as Ridge Racer DS, which uses the system''s features such as the touch-screen and wireless multi-player. Additionally, Gina Cavalli from R: Racing Evolution replaced Reiko Nagase as the mascot in the DS version. The N64 version received its first official re-release on the Nintendo Classics service on January 31, 2025; followed by a Japanese release in May 16, 2025.', 'https://media.retroachievements.org/Images/115803.png', 'https://media.retroachievements.org/Images/015092.png', 'https://media.retroachievements.org/Images/017050.png', 'https://media.retroachievements.org/Images/017051.png', 4.2),
  (78, 11569, '~Hack~ Super Mario 64: Chaos Edition', 'Nintendo 64', 2, 737, 737, 737, 117, 0, '3D Platforming', NULL, 'Hack - Super Mario 64', '2020-09-27', 'Super Mario 64 is a 1996 platform game developed and published by Nintendo for the Nintendo 64. It is the first Super Mario game to feature 3D gameplay, combining traditional Super Mario gameplay, visual style, and characters in a large open world. In the game, Bowser invades Princess Peach''s castle, kidnaps her, and hides the castle''s sources of protection, the Power Stars, in many different worlds inside magical paintings. As Mario, the player traverses levels and collects Power Stars to unlock areas of Princess Peach''s castle, to reach Bowser and rescue Princess Peach.', 'https://media.retroachievements.org/Images/111702.png', 'https://media.retroachievements.org/Images/038525.png', 'https://media.retroachievements.org/Images/038524.png', 'https://media.retroachievements.org/Images/038523.png', 4.2),
  (79, 10159, 'Castlevania: Legacy of Darkness', 'Nintendo 64', 2, 732, 732, 732, 43, 0, 'Action-Adventure, 3D Platforming', 'Konami', 'Konami', '1999-11-30', 'Castlevania: Legacy of Darkness is a 1999 action-adventure game developed and published by Konami for the Nintendo 64. A prequel and expanded version of Castlevania, also released on the Nintendo 64 earlier the same year, it contains a revision of the original game with improved graphics, added villains, and alternate versions of some levels.', 'https://media.retroachievements.org/Images/091412.png', 'https://media.retroachievements.org/Images/071793.png', 'https://media.retroachievements.org/Images/071794.png', 'https://media.retroachievements.org/Images/071795.png', 4.2),
  (80, 10326, 'Bust-A-Move ''99', 'Nintendo 64', 2, 728, 728, 728, 143, 0, NULL, 'Taito', 'Acclaim', '1999-04-30', 'Puzzle Bobble 3 is an action puzzle video game developed by Taito. The second sequel to Puzzle Bobble, it was released for arcades in September 1996 and later ported to the Sega Saturn, PlayStation, Game Boy, Nintendo 64 and Microsoft Windows. Like its predecessors, the player is tasked with shooting balls at groups of balls, creating groups of three or more, which are then removed from play. Further ports for the Nintendo Switch, PlayStation 4 and Xbox One were released in February 2023 by City Connection alongside Puzzle Bobble 2.', 'https://media.retroachievements.org/Images/097072.png', 'https://media.retroachievements.org/Images/012269.png', 'https://media.retroachievements.org/Images/011931.png', 'https://media.retroachievements.org/Images/011932.png', 4.2),
  (81, 10170, 'Beetle Adventure Racing!', 'Nintendo 64', 2, 717, 717, 717, 37, 0, 'Arcade Racing', 'Paradigm Entertainment, Electronic Arts', 'Electronic Arts', '1999-01-01', 'Beetle Adventure Racing! is a racing game released for the Nintendo 64 in 1999. It was developed by Paradigm Entertainment and EA Canada, and published by Electronic Arts. Each vehicle in the game is a Volkswagen New Beetle, which was released the previous year. The gameplay involves racing other players on unlocked tracks, finding and destroying crates, and collecting colored ladybugs while battling other players. The single-player championship offers three circuits and a secret bonus circuit with new vehicles and tracks available upon completion.', 'https://media.retroachievements.org/Images/000000.png', 'https://media.retroachievements.org/Images/066421.png', 'https://media.retroachievements.org/Images/010802.png', 'https://media.retroachievements.org/Images/010803.png', 4.2),
  (82, 17312, '~Hack~ Breaking the Barrier', 'Nintendo 64', 2, 709, 709, 709, 13, 0, '3D Platforming', 'Marionova64', 'Hack - Super Mario 64', '2020-08-05', 'The history of video games began in the 1950s and 1960s as computer scientists began designing simple games and simulations on minicomputers and mainframes. Spacewar! was developed by Massachusetts Institute of Technology (MIT) student hobbyists in 1962 as one of the first such games on a video display. The first consumer video game hardware was released in the early 1970s. The first home video game console was the Magnavox Odyssey, and the first arcade video games were Computer Space and Pong. After its home console conversions, numerous companies sprang up to capture Pong''s success in both the arcade and the home by cloning the game, causing a series of boom and bust cycles due to oversaturation and lack of innovation.', 'https://media.retroachievements.org/Images/040841.png', 'https://media.retroachievements.org/Images/045649.png', 'https://media.retroachievements.org/Images/040838.png', 'https://media.retroachievements.org/Images/040839.png', 4.2),
  (83, 22859, 'Clay Fighter 63 1/3', 'Nintendo 64', 2, 680, 680, 680, 38, 0, '3D Fighting', 'Interplay Entertainment', 'Interplay Entertainment', '1997-10-21', 'ClayFighter 63⅓ is a 1997 fighting game developed and published by Interplay Productions for the Nintendo 64. It is the third installment in the ClayFighter series. The title is a parody of the 64 suffix common in Nintendo 64 games, and a reference to Naked Gun 33 1/3.', 'https://media.retroachievements.org/Images/072015.png', 'https://media.retroachievements.org/Images/071834.png', 'https://media.retroachievements.org/Images/071832.png', 'https://media.retroachievements.org/Images/071833.png', 4.2),
  (84, 10457, 'Cruis''n Exotica', 'Nintendo 64', 2, 680, 680, 680, 102, 0, 'Arcade Racing', 'Gratuitous Games', 'Midway', '2000-10-16', 'Cruis''n Exotica is a 1999 racing game developed and published by Midway Games for arcades. The game is a sequel to Cruis''n World and is the third entry in Nintendo''s Cruis''n series. A port to the Nintendo 64 developed by Gratuitous Games was released in 2000, along with a Game Boy Color version developed by Crawfish Interactive.', 'https://media.retroachievements.org/Images/054763.png', 'https://media.retroachievements.org/Images/054293.png', 'https://media.retroachievements.org/Images/054291.png', 'https://media.retroachievements.org/Images/054292.png', 4.2),
  (85, 10586, 'Clay Fighter: Sculptor''s Cut', 'Nintendo 64', 2, 674, 674, 674, 44, 0, '3D Fighting', 'Interplay Entertainment', 'Interplay Entertainment', '1998-05-15', 'ClayFighter 63⅓ is a 1997 fighting game developed and published by Interplay Productions for the Nintendo 64. It is the third installment in the ClayFighter series. The title is a parody of the 64 suffix common in Nintendo 64 games, and a reference to Naked Gun 33 1/3.', 'https://media.retroachievements.org/Images/069062.png', 'https://media.retroachievements.org/Images/047500.png', 'https://media.retroachievements.org/Images/069056.png', 'https://media.retroachievements.org/Images/069057.png', 4.2),
  (86, 10459, 'Sesame Street: Elmo''s Number Journey', 'Nintendo 64', 2, 672, 672, 672, 18, 0, 'Educational', 'Realtime Associates', 'NewKidCo', '1999-11-30', ' There have been a variety of Sesame Street video games released for video game platforms. Most of the Sesame Street video games were published and developed by NewKidCo.', 'https://media.retroachievements.org/Images/115204.png', 'https://media.retroachievements.org/Images/042079.png', 'https://media.retroachievements.org/Images/045281.png', 'https://media.retroachievements.org/Images/067494.png', 4.2),
  (87, 10271, 'Re-Volt', 'Nintendo 64', 2, 665, 665, 665, 144, 0, 'Kart Racing', 'Acclaim', 'Acclaim', '1999-07-31', 'Re-Volt is a 1999 racing video game designed by Paul Phippen and Simon Harrison. It was developed by Acclaim Studios London and published by Acclaim Entertainment for Microsoft Windows, Nintendo 64, PlayStation and Dreamcast.', 'https://media.retroachievements.org/Images/124206.png', 'https://media.retroachievements.org/Images/024510.png', 'https://media.retroachievements.org/Images/024511.png', 'https://media.retroachievements.org/Images/024512.png', 4.2),
  (88, 14658, '~Hack~ Super Mario 64 Land', 'Nintendo 64', 2, 662, 662, 662, 97, 0, '3D Platforming', 'Hacker - Kaze Emanuar', 'Hack - Super Mario 64', '2019-11-11', 'Super Mario 64 is a 1996 platform game developed and published by Nintendo for the Nintendo 64. It is the first Super Mario game to feature 3D gameplay, combining traditional Super Mario gameplay, visual style, and characters in a large open world. In the game, Bowser invades Princess Peach''s castle, kidnaps her, and hides the castle''s sources of protection, the Power Stars, in many different worlds inside magical paintings. As Mario, the player traverses levels and collects Power Stars to unlock areas of Princess Peach''s castle, to reach Bowser and rescue Princess Peach.', 'https://media.retroachievements.org/Images/027511.png', 'https://media.retroachievements.org/Images/029595.png', 'https://media.retroachievements.org/Images/027803.png', 'https://media.retroachievements.org/Images/027818.png', 4.2),
  (89, 32649, '~Hack~ Mario in the Multiverse', 'Nintendo 64', 2, 648, 648, 648, 56, 0, '3D Platforming, Collect-a-thon', 'rovertronic', 'Hack - Super Mario 64', '2024-12-24', 'Eternal Darkness: Sanity''s Requiem is a 2002 survival horror game developed by Silicon Knights and published by Nintendo for the GameCube. It was produced and directed by Denis Dyack. The game follows the story of several characters across a period of two millennia and four different locations on Earth, as they contend with an ancient evil who seeks to enslave humanity. The gameplay distinguishes itself with unique "sanity effects", visual and audial effects that confuse the player and often break the fourth wall.', 'https://media.retroachievements.org/Images/105955.png', 'https://media.retroachievements.org/Images/105954.png', 'https://media.retroachievements.org/Images/105951.png', 'https://media.retroachievements.org/Images/105952.png', 4.2),
  (90, 10119, 'Sin and Punishment', 'Nintendo 64', 2, 625, 625, 625, 74, 0, 'Rail Shooter', 'Treasure', 'Nintendo', '2000-11-21', 'Sin and Punishment is a rail shooter video game co-developed by Treasure and Nintendo for the Nintendo 64, and released in Japan in 2000. Its story takes place in the near future of 2007 when war breaks out as humanity is struggling with a global famine. The player takes on the roles of Saki and Airan as they fight to save Earth from destruction. The game employs a unique scheme that uses both the D-pad and control stick on the Nintendo 64 controller, allowing players to maneuver the character while simultaneously aiming the targeting reticle. To progress the game, the player must shoot at enemies and projectiles while dodging attacks to survive.', 'https://media.retroachievements.org/Images/093936.png', 'https://media.retroachievements.org/Images/065251.png', 'https://media.retroachievements.org/Images/015875.png', 'https://media.retroachievements.org/Images/015876.png', 4.2),
  (91, 10407, 'Buck Bumble', 'Nintendo 64', 2, 622, 622, 622, 55, 0, NULL, 'Argonaut Games', 'Ubisoft', '1998-11-18', 'Buck Bumble is a 1998 third-person shooter video game developed by Argonaut Software and published by UbiSoft for the Nintendo 64. A special Buck Bumble rumble pack was packaged with the UK version. The game''s premise centers around anthropomorphic insects that were created as a result of a chemical spill in London, which are split into two factions at war.', 'https://media.retroachievements.org/Images/036016.png', 'https://media.retroachievements.org/Images/046370.png', 'https://media.retroachievements.org/Images/036017.png', 'https://media.retroachievements.org/Images/036018.png', 4.2),
  (92, 10114, 'Mortal Kombat Trilogy', 'Nintendo 64', 2, 619, 619, 619, 45, 0, '2D Fighting', 'Midway', 'Williams Entertainment', '1996-11-01', 'Mortal Kombat Trilogy is a 1996 fighting game released by Midway as the second and final update to Mortal Kombat 3 for the PlayStation, Nintendo 64, Sega Saturn and PCs. Further versions were also released for the Game.com and R-Zone. It features a similar basic gameplay system and the same story as Ultimate Mortal Kombat 3, but adds characters and stages restored from Mortal Kombat and Mortal Kombat II. New additions to the game included the "Aggressor" bar and the Brutality mechanic. The game was met with mixed to positive reviews upon release.', 'https://media.retroachievements.org/Images/019539.png', 'https://media.retroachievements.org/Images/010683.png', 'https://media.retroachievements.org/Images/017832.png', 'https://media.retroachievements.org/Images/017833.png', 4.2),
  (93, 14671, '~Hack~ Paper Mario: Black Pit', 'Nintendo 64', 2, 617, 617, 617, 82, 0, 'Turn-Based RPG', 'elDexter', 'Hack - Paper Mario', '2021-07-11', 'Mario Party is a series of party video games created by Hudson Soft and owned by Nintendo. It features characters from the Mario franchise in which up to four local players or computer-controlled characters compete in a board game interspersed with minigames. Designed by Shigeru Miyamoto, and directed by Kenji Kikuchi, the games are currently developed by Nintendo Cube and published by Nintendo, being previously developed by Hudson Soft. The series is known for its party game elements, including the often unpredictable multiplayer game modes that allow play with up to four, and sometimes eight, human players or CPUs.', 'https://media.retroachievements.org/Images/045967.png', 'https://media.retroachievements.org/Images/068171.png', 'https://media.retroachievements.org/Images/045585.png', 'https://media.retroachievements.org/Images/045587.png', 4.2),
  (94, 14157, '~Hack~ Waluigi''s Taco Stand', 'Nintendo 64', 2, 616, 616, 616, 10, 0, '3D Platforming', 'Hacker - Kaze Emanuar', 'Hack - Super Mario 64', '2018-08-12', NULL, 'https://media.retroachievements.org/Images/024242.png', 'https://media.retroachievements.org/Images/025120.png', 'https://media.retroachievements.org/Images/024240.png', 'https://media.retroachievements.org/Images/025121.png', 4.2),
  (95, 17582, '~Hack~ Super Mario 64: Sonic Edition Plus', 'Nintendo 64', 2, 593, 593, 593, 71, 0, '3D Platforming, Collect-a-thon', 'Gamebun', 'Hack - Super Mario 64', '2021-05-01', 'The Super Nintendo Entertainment System, known in Japan as the Super Famicom (SFC), is a home video game console developed and marketed by Nintendo. It was released in Japan on November 21, 1990, in North America on August 23, 1991, and internationally throughout 1992. It was Nintendo''s second programmable home console, following the Nintendo Entertainment System (NES). A fourth-generation console, the SNES primarily competed with Sega''s Genesis in the console war, a fierce battle for market share in the United States and Europe.', 'https://media.retroachievements.org/Images/104136.png', 'https://media.retroachievements.org/Images/101856.png', 'https://media.retroachievements.org/Images/043422.png', 'https://media.retroachievements.org/Images/043423.png', 4.2),
  (96, 10158, 'Destruction Derby 64', 'Nintendo 64', 2, 587, 587, 587, 44, 0, 'Vehicular Combat', 'Looking Glass Studios', 'THQ', '1999-09-30', 'Destruction Derby 64 is a vehicular combat racing video game developed by Looking Glass Studios and published by THQ, under license from Psygnosis. It is the third installment in the Destruction Derby series, released on 30 September 1999 in North America and 12 October 1999 in Europe for the Nintendo 64.', 'https://media.retroachievements.org/Images/010834.png', 'https://media.retroachievements.org/Images/014504.png', 'https://media.retroachievements.org/Images/010770.png', 'https://media.retroachievements.org/Images/010771.png', 4.2),
  (97, 17838, '~Hack~ All Bosses', 'Nintendo 64', 2, 577, 577, 577, 12, 0, '3D Platforming', 'Hacker - Kaze Emanuar', 'Hack - Super Mario 64', '2020-11-25', 'Banjo-Kazooie is a 1998 platform game developed by Rare and published by Nintendo for the Nintendo 64. Controlling the player characters, the bear Banjo and the bird Kazooie, the player attempts to save Banjo''s kidnapped sister Tooty from the witch Gruntilda. The player explores nine nonlinear worlds to gather items and progress. Using Banjo and Kazooie''s traversal and combat abilities, they complete challenges such as solving puzzles, jumping over obstacles, and defeating bosses.', 'https://media.retroachievements.org/Images/070137.png', 'https://media.retroachievements.org/Images/051334.png', 'https://media.retroachievements.org/Images/045636.png', 'https://media.retroachievements.org/Images/045637.png', 4.2),
  (98, 10272, 'StarCraft 64', 'Nintendo 64', 2, 565, 565, 565, 76, 0, 'Real-Time Strategy', 'Blizzard Entertainment', 'Blizzard Entertainment', '2000-06-12', 'StarCraft is a real-time strategy video game developed and published by Blizzard Entertainment for Microsoft Windows. The first installment of the video game series of the same name, it was released in 1998. A Classic Mac OS version was released in 1999, and a Nintendo 64 port co-developed with Mass Media and published by Nintendo was released in 2000.', 'https://media.retroachievements.org/Images/051791.png', 'https://media.retroachievements.org/Images/014423.png', 'https://media.retroachievements.org/Images/014360.png', 'https://media.retroachievements.org/Images/014424.png', 4.2),
  (99, 29579, '~Hack~ SM64: Decades Later', 'Nintendo 64', 2, 563, 563, 563, 99, 0, '3D Platforming', 'Hacker - BroDute, aglab2', 'Hack - Super Mario 64', '2024-03-29', 'Super Mario 64 is a 1996 platform game developed and published by Nintendo for the Nintendo 64. It is the first Super Mario game to feature 3D gameplay, combining traditional Super Mario gameplay, visual style, and characters in a large open world. In the game, Bowser invades Princess Peach''s castle, kidnaps her, and hides the castle''s sources of protection, the Power Stars, in many different worlds inside magical paintings. As Mario, the player traverses levels and collects Power Stars to unlock areas of Princess Peach''s castle, to reach Bowser and rescue Princess Peach.', 'https://media.retroachievements.org/Images/098021.png', 'https://media.retroachievements.org/Images/097971.png', 'https://media.retroachievements.org/Images/097731.png', 'https://media.retroachievements.org/Images/097732.png', 4.2),
  (100, 10137, 'A Bug''s Life', 'Nintendo 64', 2, 562, 562, 562, 84, 0, '3D Platforming', 'Traveller''s Tales', 'Activision', '1999-04-30', 'A Bug''s Life is a 1998 American animated comedy film produced by Pixar Animation Studios for Walt Disney Pictures. It was directed by John Lasseter, written by Andrew Stanton, Donald McEnery, and Bob Shaw, from a story conceived by Lasseter, Stanton, and Joe Ranft, and stars the voices of Dave Foley, Kevin Spacey, Julia Louis-Dreyfus, and Hayden Panettiere. In the film, a misfit anthropomorphic ant named Flik looks for "tough warriors" to save his ant colony from a protection racket run by a gang of grasshoppers. However, the "warriors" he brings back are a troupe of Circus Bugs. The film''s plot was initially inspired by Aesop''s fable The Ant and the Grasshopper.', 'https://media.retroachievements.org/Images/067485.png', 'https://media.retroachievements.org/Images/058191.png', 'https://media.retroachievements.org/Images/058226.png', 'https://media.retroachievements.org/Images/058225.png', 4.2),
  (101, 10489, 'Namco Museum 64', 'Nintendo 64', 2, 556, 556, 556, 64, 0, 'Compilation, Arcade', 'Mass Media', 'Namco', '1999-11-29', 'Namco Museum is a series of video game compilations developed and published by Bandai Namco Entertainment for home video game consoles. The first title in the series, Namco Museum Vol. 1, was released for the PlayStation in 1995. Entries in the series have been released for multiple platforms, including the Game Boy Advance, PlayStation 2, PlayStation Portable, Nintendo DS and Xbox 360. the latest being Namco Museum Archives Vol. 2, released in 2020.', 'https://media.retroachievements.org/Images/072246.png', 'https://media.retroachievements.org/Images/018291.png', 'https://media.retroachievements.org/Images/018834.png', 'https://media.retroachievements.org/Images/018835.png', 4.2),
  (102, 10394, 'Ms. Pac-Man Maze Madness', 'Nintendo 64', 2, 555, 555, 555, 40, 0, 'Collect-a-thon, Maze Chase', 'Mass Media', 'Namco', '2000-11-12', 'Ms. Pac-Man Maze Madness is a 2000 maze video game developed and published by Namco Hometek for the PlayStation. It was later released for the Nintendo 64, Dreamcast, and Game Boy Advance. A remake of General Computer Corporation''s Ms. Pac-Man (1982), players control the titular character in her quest to stop a witch named Mesmerelda from stealing the Gems of Virtue. The game was well-received upon release, with critics applauding its simplicity and faithfulness to the arcade original. A sequel was in development around 2006 but was cancelled for unknown reasons.', 'https://media.retroachievements.org/Images/065894.png', 'https://media.retroachievements.org/Images/065944.png', 'https://media.retroachievements.org/Images/024915.png', 'https://media.retroachievements.org/Images/024916.png', 4.2),
  (103, 12767, '~Hack~ Super Mario 64: Ocarina of Time', 'Nintendo 64', 2, 554, 554, 554, 39, 0, '3D Platforming, Collect-a-thon', 'Hacker - Kaze Emanuar', 'Hack - Super Mario 64', '2018-03-26', 'Mario Kart 64 is a 1996 kart racing game for the Nintendo 64 (N64). Developed and published by Nintendo, it is the second installment in the Mario Kart series after 1992''s Super Mario Kart. The game retains the gameplay of its predecessor: the player, controlling a Mario franchise character, races opponents around tracks based on locales from the Super Mario platform games. Tracks contain obstacles to slow the player down and item boxes which give the player power-ups to aid in their progress. Mario Kart 64 contains different single-player and local multiplayer game modes, including a Grand Prix racing mode and a last man standing battle mode.', 'https://media.retroachievements.org/Images/112585.png', 'https://media.retroachievements.org/Images/042736.png', 'https://media.retroachievements.org/Images/016779.png', 'https://media.retroachievements.org/Images/016865.png', 4.2),
  (104, 10452, 'Bio F.R.E.A.K.S.', 'Nintendo 64', 2, 544, 544, 544, 47, 0, '3D Fighting', 'Midway', 'Midway', '1998-05-19', 'Bio F.R.E.A.K.S. is a 3D fighting video game released by Midway in 1998. It was originally planned for arcades. Prototypes of the game were tested at arcades, but the final arcade release was canceled and the game was later released for the PlayStation, Nintendo 64 and Microsoft Windows.', 'https://media.retroachievements.org/Images/064331.png', 'https://media.retroachievements.org/Images/067721.png', 'https://media.retroachievements.org/Images/067720.png', 'https://media.retroachievements.org/Images/067719.png', 4.2),
  (105, 17700, '~Hack~ Mario Party 64', 'Nintendo 64', 2, 515, 515, 515, 20, 0, '3D Platforming', 'MrComit', 'Hack - Super Mario 64', '2020-02-16', 'Mario Party is a 1998 party video game developed by Hudson Soft and published by Nintendo for the Nintendo 64. The game was targeted at a young audience. Mario creator Shigeru Miyamoto served as development supervisor. The game was released in Japan on December 18, 1998, North America on February 8, 1999, and in PAL regions on March 9, 1999. It received mostly positive critical reviews for its multiplayer mode, concept, and music; disapproval of its slow pacing; and mixed reviews of its graphics. It is the first installment in the Mario Party series and was followed by Mario Party 2 in 1999. The game received its first official re-release on the Nintendo Classics service in 2022. Content from this game was remastered as part of Mario Party: The Top 100 for the Nintendo 3DS, Mario Party Superstars and Super Mario Party Jamboree for the Nintendo Switch.', 'https://media.retroachievements.org/Images/044563.png', 'https://media.retroachievements.org/Images/045838.png', 'https://media.retroachievements.org/Images/044366.png', 'https://media.retroachievements.org/Images/044367.png', 4.2),
  (106, 10683, 'Hybrid Heaven', 'Nintendo 64', 2, 512, 512, 512, 99, 0, 'Action RPG', 'Konami', 'Konami', '1999-09-01', 'Hybrid Heaven is a 1999 action role playing game developed by Konami Computer Entertainment Osaka and published by Konami for Nintendo 64. This game is most notable for its peculiar mix of genres: it has aspects of both role-playing video games and action-adventure games. It is also one of the few Nintendo 64 titles to support a widescreen mode.', 'https://media.retroachievements.org/Images/020806.png', 'https://media.retroachievements.org/Images/066798.png', 'https://media.retroachievements.org/Images/066799.png', 'https://media.retroachievements.org/Images/066865.png', 4.2),
  (107, 12732, '~Hack~ Super Mario 64: Sapphire', 'Nintendo 64', 2, 502, 502, 502, 13, 0, '3D Platforming', 'Nebula', 'Hack - Super Mario 64', '2017-12-10', 'Nintendo has developed eight home video game consoles and multiple portable consoles for use with external media, as well as dedicated consoles and other hardware for their consoles. As of September 19, 2025, Nintendo has sold over 869.95 million hardware units.', 'https://media.retroachievements.org/Images/025042.png', 'https://media.retroachievements.org/Images/023484.png', 'https://media.retroachievements.org/Images/023485.png', 'https://media.retroachievements.org/Images/023486.png', 4.2),
  (108, 10646, 'Scooby-Doo! Classic Creep Capers', 'Nintendo 64', 2, 498, 498, 498, 20, 0, 'Adventure', 'TerraGlyph Interactive Studios', 'THQ', '2000-11-30', 'Scooby-Doo! Classic Creep Capers is an adventure game published by THQ for the Nintendo 64 and Game Boy Color, based on the Hanna-Barbera cartoon Scooby-Doo, Where Are You!. The Nintendo 64 version, developed by Terraglyph Interactive Studios, was released in November 2000, while the Game Boy Color version was developed by Digital Eclipse Software, and released in February 2001. A PlayStation version, identical to the Nintendo 64 version, had been in development by Terraglyph Interactive Studios but was later cancelled.', 'https://media.retroachievements.org/Images/082474.png', 'https://media.retroachievements.org/Images/023155.png', 'https://media.retroachievements.org/Images/023156.png', 'https://media.retroachievements.org/Images/023157.png', 4.2),
  (109, 13831, '~Hack~ Super Mario Bros. 64', 'Nintendo 64', 2, 475, 475, 475, 40, 0, '3D Platforming', 'Hacker - Kaze Emanuar', 'Hack - Super Mario 64', '2018-12-21', 'Super Mario 64 is a 1996 platform game developed and published by Nintendo for the Nintendo 64. It is the first Super Mario game to feature 3D gameplay, combining traditional Super Mario gameplay, visual style, and characters in a large open world. In the game, Bowser invades Princess Peach''s castle, kidnaps her, and hides the castle''s sources of protection, the Power Stars, in many different worlds inside magical paintings. As Mario, the player traverses levels and collects Power Stars to unlock areas of Princess Peach''s castle, to reach Bowser and rescue Princess Peach.', 'https://media.retroachievements.org/Images/067928.png', 'https://media.retroachievements.org/Images/022410.png', 'https://media.retroachievements.org/Images/069194.png', 'https://media.retroachievements.org/Images/069125.png', 4.2),
  (110, 10172, 'Tetrisphere', 'Nintendo 64', 2, 455, 455, 455, 39, 0, NULL, 'H2O Interactive', 'Nintendo', '1997-08-11', 'Tetrisphere is a puzzle video game developed by H2O Entertainment and published by Nintendo for the Nintendo 64. It was released in North America on August 11, 1997, and in PAL regions in February 1998. The game, originally titled Phear, was initially intended for release on the Atari Jaguar in early 1995 but was reworked into a Tetris game for the N64 after Nintendo, a licensee for The Tetris Company, obtained the publishing rights.', 'https://media.retroachievements.org/Images/060090.png', 'https://media.retroachievements.org/Images/052884.png', 'https://media.retroachievements.org/Images/052882.png', 'https://media.retroachievements.org/Images/052883.png', 4.2),
  (111, 33246, '~Hack~ BAZR', 'Nintendo 64', 2, 454, 454, 454, 61, 0, '3D Platforming, Roguelike', 'anonymous_moose, furyiousfight, spk', 'Hack - Super Mario 64', '2025-02-11', 'The Lega Calcio Serie A, commonly known as Lega Serie A, is the league that runs the major professional football competitions in Italy, most prominently the Serie A; the top division of Italian football.', 'https://media.retroachievements.org/Images/111634.png', 'https://media.retroachievements.org/Images/115414.png', 'https://media.retroachievements.org/Images/109782.png', 'https://media.retroachievements.org/Images/111545.png', 4.2),
  (112, 22000, '~Hack~ Chao Bandstand', 'Nintendo 64', 2, 447, 447, 447, 15, 0, '3D Platforming', 'Gamebun', NULL, '2021-08-05', 'La Femme Nikita is a Canadian action-drama television series based on the French film of the same name by Luc Besson. The series stars Peta Wilson as the titular character. It was co-produced by Jay Firestone of Fireworks Entertainment and Warner Bros. Domestic Television Distribution. It was created and adapted for television by Joel Surnow and Robert Cochran. The series was telecast in the United States on the USA Network cable channel on Monday, January 13, 1997 at 10pm, and ran for five seasons until March 4, 2001. The series was also aired in Canada on the over-the-air CTV Television Network. La Femme Nikita was the highest-rated drama on American basic cable during its first two seasons. It was also distributed in some other countries.', 'https://media.retroachievements.org/Images/066224.png', 'https://media.retroachievements.org/Images/066319.png', 'https://media.retroachievements.org/Images/066125.png', 'https://media.retroachievements.org/Images/066126.png', 4.1),
  (113, 23761, '~Hack~ The Legend of Zelda: The Sealed Palace', 'Nintendo 64', 2, 442, 442, 442, 100, 0, 'Action-Adventure', 'Jinnosuke, Shoopey, Col0Korn', 'Hack - The Legend of Zelda: Ocarina of Time', '2023-03-23', 'Nintendo is a Japanese multinational video game company headquartered in Kyoto. It develops, publishes, and manufactures both video games and video game consoles. The history of Nintendo began in 1889 when craftsman Fusajiro Yamauchi founded the company to produce handmade hanafuda playing cards. After venturing into various lines of business and becoming a public company, Nintendo began producing toys in the 1960s, and later video games.', 'https://media.retroachievements.org/Images/071750.png', 'https://media.retroachievements.org/Images/091011.png', 'https://media.retroachievements.org/Images/071723.png', 'https://media.retroachievements.org/Images/071724.png', 4.1),
  (114, 10614, 'Shadowgate 64: Trials of the Four Towers', 'Nintendo 64', 2, 442, 442, 442, 42, 0, 'Adventure', 'Infinite Ventures', 'Kemco', '1999-06-09', 'Shadowgate 64: Trials of the Four Towers, also known simply as Shadowgate 64, is a 1999 adventure game developed by TNS Co., Ltd. and Infinite Ventures and published by Kemco for Nintendo 64. It is a sequel to the original Shadowgate.', 'https://media.retroachievements.org/Images/037093.png', 'https://media.retroachievements.org/Images/033044.png', 'https://media.retroachievements.org/Images/033042.png', 'https://media.retroachievements.org/Images/033043.png', 4.1),
  (115, 10392, 'South Park Rally', 'Nintendo 64', 2, 434, 434, 434, 61, 0, 'Kart Racing', 'Tantalus Interactive', 'Acclaim', '2000-03-01', 'South Park Rally is a kart-style racing video game released in early 2000 based on the American animated sitcom South Park published by Acclaim Entertainment and released for the PlayStation, Microsoft Windows, Nintendo 64, and Dreamcast. Gameplay follows the player in a competitive racing championship set in the fictional town of South Park. Players are given the options for multiplayer, arcade, or championship modes, but only the championship unlocks extra features. Competition begins in South Park''s 1st Rally, a circuit race around four checkpoints in the downtown area of South Park. Races get gradually more diverse, with more locations, racers, and elements added as the game progresses.', 'https://media.retroachievements.org/Images/071842.png', 'https://media.retroachievements.org/Images/016564.png', 'https://media.retroachievements.org/Images/016562.png', 'https://media.retroachievements.org/Images/016563.png', 4.1),
  (116, 10121, 'Duke Nukem 64', 'Nintendo 64', 2, 430, 430, 430, 132, 0, 'First-Person Shooter', 'Apogee Software | 3D Realms, Eurocom', 'Atari', '1997-11-14', 'Duke Nukem 3D is a 1996 first-person shooter game developed by 3D Realms and published by FormGen for MS-DOS. It is a sequel to the platform games Duke Nukem and Duke Nukem II, published by 3D Realms.', 'https://media.retroachievements.org/Images/020240.png', 'https://media.retroachievements.org/Images/098495.png', 'https://media.retroachievements.org/Images/010775.png', 'https://media.retroachievements.org/Images/010895.png', 4.1),
  (117, 17367, '~Hack~ Roblox 64', 'Nintendo 64', 2, 422, 422, 422, 7, 0, '3D Platforming', 'SwiftySky', 'Hack - Super Mario 64', '2018-08-22', 'The video game industry in the United States is one of the fastest-growing entertainment industries in the country. The American video game industry is the largest video game industry in the world. According to a 2020 study released by the Entertainment Software Association (ESA), the yearly economic output of the American video game industry in 2019 was $90.3 billion, supporting over 429,000 American jobs. With an average yearly salary of about $121,000, the latter figure includes over 143,000 individuals who are directly employed by the video game business. Additionally, activities connected to the video game business generate $12.6 billion in federal, state, and local taxes each year. The World Economic Forum estimates that, by 2025, the American gaming industry will reach $42.3 billion while the worldwide gaming industry will possibly reach US$270 billion. The United States is one of the nations with the largest influence in the video game industry, with video games representing a significant part of its economy.', 'https://media.retroachievements.org/Images/041148.png', 'https://media.retroachievements.org/Images/051326.png', 'https://media.retroachievements.org/Images/041142.png', 'https://media.retroachievements.org/Images/041147.png', 4.1),
  (118, 25613, '~Hack~ SM64: Beyond the Cursed Mirror', 'Nintendo 64', 2, 422, 422, 422, 78, 0, NULL, 'rovertronic', NULL, '2023-05-05', NULL, 'https://media.retroachievements.org/Images/081966.png', 'https://media.retroachievements.org/Images/084189.png', 'https://media.retroachievements.org/Images/084190.png', 'https://media.retroachievements.org/Images/084191.png', 4.1),
  (119, 17812, '~Hack~ Mario and the Mystic Purple Stars', 'Nintendo 64', 2, 420, 420, 420, 28, 0, '3D Platforming, Collect-a-thon', 'Progji', 'Hack - Super Mario 64', '2020-11-19', 'The following is a comprehensive index of all games released in 2025, sorted chronologically by release date, and divided by quarter. Information regarding developer, publisher, operating system, genre and type of release is provided where available', 'https://media.retroachievements.org/Images/048694.png', 'https://media.retroachievements.org/Images/056054.png', 'https://media.retroachievements.org/Images/048727.png', 'https://media.retroachievements.org/Images/045451.png', 4.1),
  (120, 19551, '~Hack~ Super Mario 64: Through the Ages', 'Nintendo 64', 2, 419, 419, 419, 68, 0, NULL, NULL, 'Hack - Super Mario 64', '2022-04-30', 'Super Mario 64 is a 1996 platform game developed and published by Nintendo for the Nintendo 64. It is the first Super Mario game to feature 3D gameplay, combining traditional Super Mario gameplay, visual style, and characters in a large open world. In the game, Bowser invades Princess Peach''s castle, kidnaps her, and hides the castle''s sources of protection, the Power Stars, in many different worlds inside magical paintings. As Mario, the player traverses levels and collects Power Stars to unlock areas of Princess Peach''s castle, to reach Bowser and rescue Princess Peach.', 'https://media.retroachievements.org/Images/104561.png', 'https://media.retroachievements.org/Images/059039.png', 'https://media.retroachievements.org/Images/057647.png', 'https://media.retroachievements.org/Images/057646.png', 4.1),
  (121, 10607, 'Chameleon Twist', 'Nintendo 64', 2, 410, 410, 410, 32, 0, '3D Platforming', 'Japan System Supply', 'Sunsoft', '1997-11-30', 'Chameleon Twist is a 1997 video game developed by Japan System Supply, published by Japan System Supply in Japan, and published by Sunsoft in North America and Europe for the Nintendo 64.', 'https://media.retroachievements.org/Images/029672.png', 'https://media.retroachievements.org/Images/015027.png', 'https://media.retroachievements.org/Images/015028.png', 'https://media.retroachievements.org/Images/015058.png', 4.1),
  (122, 10530, 'WCW vs. nWo: World Tour', 'Nintendo 64', 2, 407, 407, 407, 31, 0, 'Sports - Wrestling', 'Asmik Ace Entertainment, AKI Corporation', 'THQ', '1997-11-01', 'WCW vs. nWo: World Tour is a professional wrestling video game released in 1997 for the Nintendo 64 game console. Released at the peak of World Championship Wrestling''s (WCW) dominance in the Monday Night War, World Tour was THQ''s first foray into the N64 wrestling scene and is a semi-sequel to the lesser known WCW vs. the World for the PlayStation. It is the second best-selling wrestling game for the N64 console.', 'https://media.retroachievements.org/Images/015111.png', 'https://media.retroachievements.org/Images/015110.png', 'https://media.retroachievements.org/Images/015068.png', 'https://media.retroachievements.org/Images/044134.png', 4.1),
  (123, 10627, 'South Park: Chef''s Luv Shack', 'Nintendo 64', 2, 404, 404, 404, 75, 0, 'Trivia, Party', 'Acclaim', 'Acclaim', '1999-10-12', 'South Park: Chef''s Luv Shack is a 2D game show-style party video game and is a sequel to the 1998 video game South Park, itself based on the American animated sitcom of the same name. Developed by Acclaim Studios Austin and published by Acclaim Entertainment, it was released in 1999 for the Dreamcast, Microsoft Windows, PlayStation and Nintendo 64. Its gameplay involves minigames and the ability to play against other players in a challenge for the most points. It also involves trivia questions about South Park and other topics.', 'https://media.retroachievements.org/Images/071670.png', 'https://media.retroachievements.org/Images/057196.png', 'https://media.retroachievements.org/Images/057194.png', 'https://media.retroachievements.org/Images/057195.png', 4.1),
  (124, 10171, 'Tetris 64', 'Nintendo 64', 2, 401, 401, 401, 40, 0, 'Falling Block Puzzle', 'Amtex', 'SETA', '1998-11-13', 'Tetris 64 is a 1998 puzzle video game developed by Amtex and published by SETA for the Nintendo 64. Released exclusively in Japan, it came packaged with the "Bio Sensor", a unique accessory which alters the gameplay based on the player''s heart rate.', 'https://media.retroachievements.org/Images/098365.png', 'https://media.retroachievements.org/Images/025506.png', 'https://media.retroachievements.org/Images/025503.png', 'https://media.retroachievements.org/Images/025504.png', 4.1),
  (125, 14447, '~Hack~ Super Mario 64: The Green Comet', 'Nintendo 64', 2, 400, 400, 400, 32, 0, '3D Platforming', 'Arthurtilly', 'Hack - Super Mario 64', '2019-01-14', 'Paper Mario is a video game series and part of the Mario franchise, developed by Intelligent Systems and published by Nintendo. It combines elements from the role-playing, action-adventure, and puzzle genres. Players control a paper cutout version of Mario, usually with allies, on a quest to defeat the antagonist. The series consists of six games and one spin-off; the first, Paper Mario (2000), was released for the Nintendo 64, and the most recent, a 2024 remake of 2004''s Paper Mario: The Thousand-Year Door, for the Nintendo Switch.', 'https://media.retroachievements.org/Images/047936.png', 'https://media.retroachievements.org/Images/047671.png', 'https://media.retroachievements.org/Images/047627.png', 'https://media.retroachievements.org/Images/047629.png', 4.1),
  (126, 13113, 'Puyo Puyo Sun 64', 'Nintendo 64', 2, 398, 398, 398, 29, 0, NULL, 'Compile', 'Compile', '1997-10-31', 'Puyo Puyo Sun  is the third installment of the Puyo Puyo series, and the sequel to Puyo Puyo 2, made in 1996 by Compile. After the highly acclaimed success of its predecessor, Compile took a slightly more retro approach, so players had a more original feel to the game over that of 2.', 'https://media.retroachievements.org/Images/121321.png', 'https://media.retroachievements.org/Images/056034.png', 'https://media.retroachievements.org/Images/018984.png', 'https://media.retroachievements.org/Images/018985.png', 4.1),
  (127, 11647, '~Hack~ Super Mario 64: The Green Stars', 'Nintendo 64', 2, 388, 388, 388, 54, 0, NULL, 'Kampel125', 'Hack - Super Mario 64', '2013-07-21', 'Super Mario 64 is a 1996 platform game developed and published by Nintendo for the Nintendo 64. It is the first Super Mario game to feature 3D gameplay, combining traditional Super Mario gameplay, visual style, and characters in a large open world. In the game, Bowser invades Princess Peach''s castle, kidnaps her, and hides the castle''s sources of protection, the Power Stars, in many different worlds inside magical paintings. As Mario, the player traverses levels and collects Power Stars to unlock areas of Princess Peach''s castle, to reach Bowser and rescue Princess Peach.', 'https://media.retroachievements.org/Images/052022.png', 'https://media.retroachievements.org/Images/026852.png', 'https://media.retroachievements.org/Images/023255.png', 'https://media.retroachievements.org/Images/023256.png', 4.1),
  (128, 10127, 'Duke Nukem: Zero Hour', 'Nintendo 64', 2, 386, 386, 386, 106, 0, 'Third-Person Shooter', 'Eurocom', 'GT Interactive Software', '1999-08-01', 'Duke Nukem: Zero Hour is a 1999 third-person shooter game in the Duke Nukem series, developed by Eurocom and published by GT Interactive for the Nintendo 64. The game uses a relatively large 32 megabyte cartridge and can also use the Expansion Pak to improve graphics, though this slows down the frame rate. It features a 4-player split-screen multiplayer mode that uses a first-person view.', 'https://media.retroachievements.org/Images/066261.png', 'https://media.retroachievements.org/Images/011039.png', 'https://media.retroachievements.org/Images/011035.png', 'https://media.retroachievements.org/Images/068219.png', 4.1),
  (129, 10223, 'Gex 3: Deep Cover Gecko', 'Nintendo 64', 2, 383, 383, 383, 55, 0, '3D Platforming, Collect-a-thon', 'Gratuitous Games', 'Crave Entertainment', '1999-09-28', 'Gex 3: Deep Cover Gecko is a 1999 platform game developed by Crystal Dynamics and published by Eidos Interactive for the PlayStation. It is part of the Gex video game series, and was released in 1999, followed by ports for the Nintendo 64. Its protagonist, Gex, is a wisecracking, pop culture enthusiast voiced by Danny John-Jules in the UK and European releases and comedian Dana Gould, reprising his role from former Gex games, for the American release. The gameplay is set in Gex''s secret hideout, Mission Control a overworld, which is overseen by Gex''s butler, Alfred the Turtle. Playboy model Marliece Andrada plays Gex''s kidnapped companion, Agent Xtra, the only live-action character, who is featured in brief full-motion video sequences on the PlayStation version. The plot follows Gex''s return to the Media Dimension to rescue Agent Xtra from Rez, Gex''s arch-nemesis from the previous games.', 'https://media.retroachievements.org/Images/109678.png', 'https://media.retroachievements.org/Images/014508.png', 'https://media.retroachievements.org/Images/010964.png', 'https://media.retroachievements.org/Images/010962.png', 4.1),
  (130, 25610, '~Hack~ Paper Mario: TTYD64', 'Nintendo 64', 2, 381, 381, 381, 208, 0, 'Turn-Based RPG', 'elDexter', 'Hack - Paper Mario', '2023-08-13', NULL, 'https://media.retroachievements.org/Images/083844.png', 'https://media.retroachievements.org/Images/085911.png', 'https://media.retroachievements.org/Images/085912.png', 'https://media.retroachievements.org/Images/085913.png', 4.1),
  (131, 22459, '~Hack~ The Quest For Milk 64', 'Nintendo 64', 2, 379, 379, 379, 9, 0, '3D Platforming', 'Deathray9000', 'Hack - Super Mario 64', '2022-09-07', 'Conker''s Bad Fur Day is a 2001 platform game developed by Rare and published by Rare in North America and by THQ in Europe for the Nintendo 64. The game follows Conker, a greedy, hard-drinking red squirrel who must return home to his girlfriend, Berri, after an evening of heavily drinking at the local pub. Most of the game requires the player to complete a linear sequence of challenges that involve jumping over obstacles, solving puzzles, and fighting enemies. A multiplayer mode in which up to four players can compete against each other in seven different game types is also included. It is the second installment in the Conker series, after Conker''s Pocket Tales (1999).', 'https://media.retroachievements.org/Images/114410.png', 'https://media.retroachievements.org/Images/068397.png', 'https://media.retroachievements.org/Images/068394.png', 'https://media.retroachievements.org/Images/068396.png', 4.1),
  (132, 29843, '~Hack~ The Legend of Zelda: Ultimate Trial', 'Nintendo 64', 2, 377, 377, 377, 81, 0, NULL, 'Ultimate Trial''s Team', NULL, '2024-05-24', 'Link is a character and the protagonist of Nintendo''s video game franchise The Legend of Zelda. He was created by Japanese video game designer Shigeru Miyamoto. Link was introduced as the hero of the original The Legend of Zelda video game in 1986 and has appeared in a total of 21 entries in the series, as well as a number of spin-offs. Common elements in the series include Link travelling through Hyrule whilst exploring dungeons, battling creatures, and solving puzzles until he eventually defeats the series'' primary antagonist, Ganon, and saves Princess Zelda.', 'https://media.retroachievements.org/Images/097877.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/097736.png', 'https://media.retroachievements.org/Images/097786.png', 4.1),
  (133, 10587, 'Monopoly', 'Nintendo 64', 2, 377, 377, 377, 16, 0, 'Board Game', 'Mind''s Eye Productions', 'Hasbro Interactive', '1999-12-18', 'A monopoly is a market in which one person or company is the only supplier of a particular good or service. A monopoly is characterized by a lack of economic competition to produce a particular thing, a lack of viable substitute goods, and the possibility of a high monopoly price well above the seller''s marginal cost that leads to a high monopoly profit. The verb monopolise or monopolize refers to the process by which a company gains the ability to raise prices or exclude competitors. In economics, a monopoly is a single seller. In law, a monopoly is a business entity that has significant market power, that is, the power to charge overly high prices, which is associated with unfair price raises. Although monopolies may be big businesses, size is not a characteristic of a monopoly. A small business may still have the power to raise prices in a small industry.', 'https://media.retroachievements.org/Images/078339.png', 'https://media.retroachievements.org/Images/017514.png', 'https://media.retroachievements.org/Images/017515.png', 'https://media.retroachievements.org/Images/017517.png', 4.1),
  (134, 27401, '~Homebrew~ Portal 64', 'Nintendo 64', 2, 375, 375, 375, 25, 0, 'Action, Puzzle', 'lambertjamesd', 'lambertjamesd', '2023-01-01', 'Mario Kart 64 is a 1996 kart racing game for the Nintendo 64 (N64). Developed and published by Nintendo, it is the second installment in the Mario Kart series after 1992''s Super Mario Kart. The game retains the gameplay of its predecessor: the player, controlling a Mario franchise character, races opponents around tracks based on locales from the Super Mario platform games. Tracks contain obstacles to slow the player down and item boxes which give the player power-ups to aid in their progress. Mario Kart 64 contains different single-player and local multiplayer game modes, including a Grand Prix racing mode and a last man standing battle mode.', 'https://media.retroachievements.org/Images/109991.png', 'https://media.retroachievements.org/Images/086166.png', 'https://media.retroachievements.org/Images/086164.png', 'https://media.retroachievements.org/Images/086165.png', 4.1),
  (135, 17507, '~Hack~ Kirby 64: Whispy''s Trials', 'Nintendo 64', 2, 374, 374, 374, 12, 0, '2.5D Platforming', 'jesusyoshi54', 'Hack - Kirby 64 - The Crystal Shards', '2020-10-04', NULL, 'https://media.retroachievements.org/Images/124333.png', 'https://media.retroachievements.org/Images/113748.png', 'https://media.retroachievements.org/Images/052714.png', 'https://media.retroachievements.org/Images/098039.png', 4.1),
  (136, 10255, 'Shadow Man', 'Nintendo 64', 2, 373, 373, 373, 74, 0, 'Action, Survival Horror', 'Acclaim', 'Acclaim', '1999-07-31', 'Shadow Man is a 1999 action-adventure video game developed by Acclaim Studios Teesside and published by Acclaim Entertainment. It is based on the Shadow Man comic book series published by Valiant Comics. The game was released for Nintendo 64, Microsoft Windows, and PlayStation on August 31, 1999, with a Dreamcast version following on December 1.', 'https://media.retroachievements.org/Images/055462.png', 'https://media.retroachievements.org/Images/012742.png', 'https://media.retroachievements.org/Images/012746.png', 'https://media.retroachievements.org/Images/012747.png', 4.1),
  (137, 27596, '~Hack~ Wario''s Hint Art', 'Nintendo 64', 2, 368, 368, 368, 51, 0, '3D Platforming', 'Lawnmowerman', 'Hack - Super Mario 64', '2022-11-21', 'Wario Land 3, known in Japan as Wario Land 3: Mysterious Music Box, is a 2000 platform game developed by Nintendo R&D1 and published by Nintendo for the Game Boy Color. The game''s plot centers around Wario who must free a mysterious figure who is trapped inside a music box. The game was released in Japan on March 21, 2000, Europe on April 14, 2000, and North America on May 30, 2000.', 'https://media.retroachievements.org/Images/106495.png', 'https://media.retroachievements.org/Images/106190.png', 'https://media.retroachievements.org/Images/100000.png', 'https://media.retroachievements.org/Images/100001.png', 4.1),
  (138, 10429, 'Fighters Destiny', 'Nintendo 64', 2, 365, 365, 365, 75, 0, '3D Fighting', 'Opus, Anchor', 'Imagineer, Ocean', '1998-01-26', 'Fighters Destiny, known in Japan as Fighting Cup, is a 1998 video game developed by Genki alongside Opus Corp and Anchor Inc for the Nintendo 64. It closely models the 3D fighting game standards of the time but integrates a unique point scoring system. The game''s generic characters and unoriginal presentation have been panned by critics, but reviewers praised its point system and consider it to be one of the best fighting games on the Nintendo 64. It was followed by a sequel, Fighter Destiny 2, released in 2000.', 'https://media.retroachievements.org/Images/120787.png', 'https://media.retroachievements.org/Images/066556.png', 'https://media.retroachievements.org/Images/080486.png', 'https://media.retroachievements.org/Images/080487.png', 4.1),
  (139, 34305, '~Hack~ Mario Breaks EVERY BONE IN HIS BODY', 'Nintendo 64', 2, 364, 364, 364, 7, 0, '3D Platforming', 'CowQuack', 'Hack - Super Mario 64', '2024-03-27', 'The 1990s was the third decade in the industry''s history. It was a decade of marked innovation in video gaming. It was a decade of transition from sprite-based graphics to full-fledged 3D graphics and it gave rise to several genres of video games including, but not limited to, the first-person shooter, real-time strategy, survival horror, and MMO. Arcade games, although still very popular in the early 1990s, began to decline as home consoles became more common. The fourth, fifth and sixth generation of video game consoles went on sale, including the Sega Genesis, Super Nintendo, Sega Saturn, PlayStation, Nintendo 64, Game Boy Color and the Sega Dreamcast. Notable games released in the 1990s included Super Mario World, Sonic the Hedgehog, Street Fighter II, Mortal Kombat, Doom, Wolfenstein 3D, Quake, Final Fantasy VII, Half-Life, Super Mario 64, Pokémon Red, Blue, and Yellow, GoldenEye 007, The Legend of Zelda: Ocarina of Time, Super Metroid, Castlevania: Symphony of the Night, Metal Gear Solid, Resident Evil, StarCraft, Tomb Raider, Gran Turismo, Super Mario Kart, Crash Bandicoot, Spyro the Dragon, Tony Hawk''s Pro Skater, Age of Empires, Civilization, Myst, and Soulcalibur.', 'https://media.retroachievements.org/Images/115448.png', 'https://media.retroachievements.org/Images/115453.png', 'https://media.retroachievements.org/Images/115450.png', 'https://media.retroachievements.org/Images/115451.png', 4.1),
  (140, 10330, 'Bomberman 64: The Second Attack!', 'Nintendo 64', 2, 361, 361, 361, 50, 0, 'Action, Puzzle', 'Hudson Soft', 'Vatical Entertainment', '1999-12-03', 'Bomberman 64: The Second Attack! is a 1999 action video game, the sequel to 1997''s Bomberman 64.', 'https://media.retroachievements.org/Images/111878.png', 'https://media.retroachievements.org/Images/111789.png', 'https://media.retroachievements.org/Images/036034.png', 'https://media.retroachievements.org/Images/036033.png', 4.1),
  (141, 10517, 'Top Gear Rally', 'Nintendo 64', 2, 359, 359, 359, 52, 0, 'Rally Racing', 'Boss Game Studios', 'Midway', '1997-01-01', 'Top Gear Rally is a 1997 racing video game developed by Boss Game Studios and released for the Nintendo 64. A follow-up to Kemco''s original Top Gear game, it features a championship mode where a single player must complete six seasons of two to four races, as well as a multiplayer mode where two players may compete against each other via a split-screen display. The game''s tracks combine both road and off-road surfaces and can be played in different weather conditions, including night, fog, rain, and snow. Players may customize their car with different tire grips and adjust its suspension stiffness and steering sensitivity. An option that allows players to custom paint their cars is also included.', 'https://media.retroachievements.org/Images/055460.png', 'https://media.retroachievements.org/Images/017964.png', 'https://media.retroachievements.org/Images/017965.png', 'https://media.retroachievements.org/Images/017963.png', 4.1),
  (142, 10486, 'Mission: Impossible', 'Nintendo 64', 2, 358, 358, 358, 37, 0, 'Action-Adventure', 'Infogrames', 'Ocean Software', '1998-01-01', 'Mission: Impossible is an American multimedia franchise based on a fictional secret espionage agency known as the Impossible Missions Force (IMF). The 1966 TV series ran for seven seasons and was revived in 1988 for two seasons. It inspired a series of theatrical motion pictures starring Tom Cruise beginning in 1996.', 'https://media.retroachievements.org/Images/077322.png', 'https://media.retroachievements.org/Images/046537.png', 'https://media.retroachievements.org/Images/034941.png', 'https://media.retroachievements.org/Images/034939.png', 4.1),
  (143, 10515, 'Tom and Jerry in Fists of Furry', 'Nintendo 64', 2, 356, 356, 356, 36, 0, 'Arena Fighting', 'VIS Entertainment', 'Ubisoft, NewKidCo', '2000-11-12', 'Tom and Jerry in Fists of Furry is a fighting video game for the Nintendo 64 and Microsoft Windows. It was developed by VIS Interactive and published by NewKidCo on November 12, 2000. It is based on the animated short film series of Tom and Jerry.', 'https://media.retroachievements.org/Images/026284.png', 'https://media.retroachievements.org/Images/018274.png', 'https://media.retroachievements.org/Images/026283.png', 'https://media.retroachievements.org/Images/018273.png', 4.1),
  (144, 14486, '~Hack~ Zelda 64: Dawn & Dusk', 'Nintendo 64', 2, 344, 344, 344, 15, 0, 'Action-Adventure', 'Captain Seedy-Eye', 'Hack - The Legend of Zelda: Ocarina of Time', '2019-09-23', 'Nintendo is a Japanese multinational video game company headquartered in Kyoto. It develops, publishes, and manufactures both video games and video game consoles. The history of Nintendo began in 1889 when craftsman Fusajiro Yamauchi founded the company to produce handmade hanafuda playing cards. After venturing into various lines of business and becoming a public company, Nintendo began producing toys in the 1960s, and later video games.', 'https://media.retroachievements.org/Images/050121.png', 'https://media.retroachievements.org/Images/049481.png', 'https://media.retroachievements.org/Images/027005.png', 'https://media.retroachievements.org/Images/027004.png', 4.1),
  (145, 18183, '~Hack~ The Legend of Zelda: Ocarina of Time - Spaceworld ''97 BETA Experience', 'Nintendo 64', 2, 340, 340, 340, 16, 0, 'Action-Adventure', 'Zel', 'Hack - The Legend of Zelda: Ocarina of Time', '2021-11-21', 'The 64DD is a peripheral developed by Nintendo to expand the capabilities of the Nintendo 64 with rewritable magnetic disks and online connectivity. Announced in 1995 before the Nintendo 64''s 1996 launch, it faced multiple delays before its release in Japan on December 11, 1999. The "64" references both the Nintendo 64 console and the 64 MB storage capacity of the disks, while "DD" stands for "disk drive" or "dynamic drive". Despite its innovative features, it struggled to gain traction and was discontinued after a short-lived run in Japan.', 'https://media.retroachievements.org/Images/050300.png', 'https://media.retroachievements.org/Images/050291.png', 'https://media.retroachievements.org/Images/050293.png', 'https://media.retroachievements.org/Images/050299.png', 4.1),
  (146, 10149, 'Army Men: Sarge''s Heroes 2', 'Nintendo 64', 2, 336, 336, 336, 59, 0, 'Third-Person Shooter', 'The 3DO Company', 'The 3DO Company', '2000-09-26', 'Army Men: Sarge''s Heroes 2 is a 2000 third-person shooter video game developed and published by The 3DO Company for the Nintendo 64, Game Boy Color, PlayStation, and PlayStation 2. The game is a direct sequel to Army Men: Sarge''s Heroes (1999). Unlike the previous game which was more dark in tone, this game has more of a lighthearted storyline.', 'https://media.retroachievements.org/Images/100395.png', 'https://media.retroachievements.org/Images/010749.png', 'https://media.retroachievements.org/Images/034959.png', 'https://media.retroachievements.org/Images/079537.png', 4.1),
  (147, 22554, '~Hack~ Mario Aimlessly Drives a Car Around the City 64', 'Nintendo 64', 2, 327, 327, 327, 9, 0, NULL, 'CowQuack', 'Hack - Super Mario 64', '2021-04-14', 'Donald Miller was an American serial killer who murdered one woman and later four gay men in Los Angeles County, California, from 1977 to 1981. He was convicted and sentenced to death for four of these killings in 1983, but died awaiting execution in 2005.', 'https://media.retroachievements.org/Images/068443.png', 'https://media.retroachievements.org/Images/104871.png', 'https://media.retroachievements.org/Images/069036.png', 'https://media.retroachievements.org/Images/069035.png', 4.1),
  (148, 17857, '~Hack~ Star Revenge 0: Galaxy of Origins', 'Nintendo 64', 2, 326, 326, 326, 56, 0, '3D Platforming, Collect-a-thon', NULL, 'Hack - Super Mario 64', '2020-08-15', 'Star Wars: Rogue Squadron or Star Wars: Rogue Squadron 3D is an arcade-style flight action game co-developed by Factor 5 and LucasArts. The first of the Rogue Squadron trilogy, it was published by LucasArts and Nintendo and released for Microsoft Windows and Nintendo 64 in December 1998. The game''s story was influenced by the Star Wars: X-wing – Rogue Squadron comics and is set in the fictional Star Wars galaxy, taking place primarily between events in the films Star Wars and The Empire Strikes Back. The player controls Luke Skywalker, commander of the elite X-wing pilots known as Rogue Squadron. As the game progresses, Skywalker and Rogue Squadron fight the Galactic Empire in 16 missions across various planets.', 'https://media.retroachievements.org/Images/083814.png', 'https://media.retroachievements.org/Images/062871.png', 'https://media.retroachievements.org/Images/062869.png', 'https://media.retroachievements.org/Images/062870.png', 4.1),
  (149, 10333, 'San Francisco Rush 2049', 'Nintendo 64', 2, 321, 321, 321, 65, 0, 'Arcade Racing', 'Midway', 'Midway', '2000-09-05', 'San Francisco Rush 2049 is a 1999 racing video game developed and manufactured by Atari Games for arcades, later ported to home systems. It is the third game in the Rush series as the sequel to San Francisco Rush: Extreme Racing and Rush 2: Extreme Racing USA as well as the last to be set in the city of San Francisco. An updated version with fixes and more tracks was later released subtitled Tournament Edition.', 'https://media.retroachievements.org/Images/064758.png', 'https://media.retroachievements.org/Images/044716.png', 'https://media.retroachievements.org/Images/044718.png', 'https://media.retroachievements.org/Images/044717.png', 4.1),
  (150, 14664, '~Hack~ Super Mario and the Cursed Castles', 'Nintendo 64', 2, 320, 320, 320, 58, 0, NULL, 'Foxen', 'Hack - Super Mario 64', '2019-06-06', 'Paper Mario is a video game series and part of the Mario franchise, developed by Intelligent Systems and published by Nintendo. It combines elements from the role-playing, action-adventure, and puzzle genres. Players control a paper cutout version of Mario, usually with allies, on a quest to defeat the antagonist. The series consists of six games and one spin-off; the first, Paper Mario (2000), was released for the Nintendo 64, and the most recent, a 2024 remake of 2004''s Paper Mario: The Thousand-Year Door, for the Nintendo Switch.', 'https://media.retroachievements.org/Images/027589.png', 'https://media.retroachievements.org/Images/027590.png', 'https://media.retroachievements.org/Images/027539.png', 'https://media.retroachievements.org/Images/027541.png', 4.1),
  (151, 19486, '~Hack~ Banjo-Kazooie: Gruntilda''s Mask', 'Nintendo 64', 2, 318, 318, 318, 14, 0, NULL, 'Hacker - Kurko Mods', NULL, '2019-01-01', 'Banjo-Kazooie is a 1998 platform game developed by Rare and published by Nintendo for the Nintendo 64. Controlling the player characters, the bear Banjo and the bird Kazooie, the player attempts to save Banjo''s kidnapped sister Tooty from the witch Gruntilda. The player explores nine nonlinear worlds to gather items and progress. Using Banjo and Kazooie''s traversal and combat abilities, they complete challenges such as solving puzzles, jumping over obstacles, and defeating bosses.', 'https://media.retroachievements.org/Images/061483.png', 'https://media.retroachievements.org/Images/061480.png', 'https://media.retroachievements.org/Images/061484.png', 'https://media.retroachievements.org/Images/061485.png', 4.1),
  (152, 10087, 'Rampage: World Tour', 'Nintendo 64', 2, 309, 309, 309, 33, 0, 'Action, Arcade', 'Saffire', 'Midway', '1998-03-30', 'Rampage World Tour is a 1997 action video game developed by Game Refuge and published by Midway Games for arcades. It is the sequel to 1986''s Rampage, and was designed by Brian Colin and Jeff Nauman, who designed the original game. Ports were released for the PlayStation, Sega Saturn, Nintendo 64, Game Boy Color, and Microsoft Windows. It was re-released on Midway Arcade Treasures 2 and included in Rampage: Total Destruction.', 'https://media.retroachievements.org/Images/072387.png', 'https://media.retroachievements.org/Images/010671.png', 'https://media.retroachievements.org/Images/010668.png', 'https://media.retroachievements.org/Images/010669.png', 4.1),
  (153, 16509, '~Hack~ The Legend of Zelda: Master of Time', 'Nintendo 64', 2, 303, 303, 303, 45, 0, 'Action-Adventure', 'doncamilo', 'Hack - The Legend of Zelda: Ocarina of Time', '2020-07-30', 'The Legend of Zelda: Ocarina of Time is a 1998 action-adventure game developed and published by Nintendo for the Nintendo 64. It was the first Legend of Zelda game with 3D graphics. It was released in Japan and North America in November 1998 and in PAL regions the following month.', 'https://media.retroachievements.org/Images/040364.png', 'https://media.retroachievements.org/Images/036149.png', 'https://media.retroachievements.org/Images/040363.png', 'https://media.retroachievements.org/Images/040365.png', 4.1),
  (154, 10532, 'Wipeout 64', 'Nintendo 64', 2, 300, 300, 300, 50, 0, 'Racing', 'Psygnosis | Studio Liverpool', 'Midway', '1998-01-01', 'Wipeout 64 is a 1998 racing video game developed by Psygnosis and published by Midway Games for the Nintendo 64. It is the third game in the Wipeout series and remains the only one published on a Nintendo console. At the time of the game''s release, developer Psygnosis had been owned for five years by Sony Computer Entertainment, for whose hardware all subsequent Wipeout games have been released exclusively.', 'https://media.retroachievements.org/Images/052007.png', 'https://media.retroachievements.org/Images/018263.png', 'https://media.retroachievements.org/Images/052005.png', 'https://media.retroachievements.org/Images/052006.png', 4.1),
  (155, 23760, '~Hack~ The Magical Lands', 'Nintendo 64', 2, 293, 293, 293, 32, 0, NULL, 'Papra Mayro 46', NULL, '2023-02-02', 'Glover is a 1998 puzzle-platformer developed by Interactive Studios and published by Hasbro Interactive for the Nintendo 64 and Windows in 1998, and for the PlayStation in 1999. The game follows a magical, four-fingered glove named Glover in his quest to restore the Crystal Kingdom by retrieving crystals that were lost.', 'https://media.retroachievements.org/Images/071887.png', 'https://media.retroachievements.org/Images/071121.png', 'https://media.retroachievements.org/Images/071153.png', 'https://media.retroachievements.org/Images/071154.png', 4.1),
  (156, 10926, 'Mortal Kombat Mythologies: Sub-Zero', 'Nintendo 64', 2, 287, 287, 287, 56, 0, 'Action-Adventure, 2D Fighting', 'Midway', 'Midway', '1997-10-01', 'Mortal Kombat Mythologies: Sub-Zero is a 1997 action-adventure game developed and published by Midway for the PlayStation and Nintendo 64. A spin-off of the Mortal Kombat franchise, it is the first installment not to be a fighting game. Set before the first game in the series, it follows Bi-Han, the elder Sub-Zero, in his quest to find Shinnok''s amulet. It also serves as a prequel to Mortal Kombat 4, which was released the same year, introducing characters and story elements that would be used by the fourth main installment. Mythologies is the final game in the series to use digitized actors.', 'https://media.retroachievements.org/Images/036553.png', 'https://media.retroachievements.org/Images/037889.png', 'https://media.retroachievements.org/Images/037890.png', 'https://media.retroachievements.org/Images/038037.png', 4.1),
  (157, 10360, 'San Francisco Rush: Extreme Racing', 'Nintendo 64', 2, 286, 286, 286, 50, 0, 'Arcade Racing', 'Midway', 'Midway', '1997-11-08', 'San Francisco Rush: Extreme Racing is a 1996 racing video game developed and published by Atari Games for arcades. It was ported to home consoles under the Midway label, beginning with the Nintendo 64 in 1997 and the PlayStation and Windows in 1998. An updated version named San Francisco Rush The Rock: Alcatraz Edition was released with more tracks and cars. It was a critical and commercial hit, and became the first in the Rush series, followed by San Francisco Rush 2049 (1999), bounded by the non-arcade Rush 2: Extreme Racing USA (1998).', 'https://media.retroachievements.org/Images/023348.png', 'https://media.retroachievements.org/Images/023345.png', 'https://media.retroachievements.org/Images/023346.png', 'https://media.retroachievements.org/Images/023347.png', 4.1),
  (158, 25317, '~Hack~ Only Up! 64', 'Nintendo 64', 2, 281, 281, 281, 25, 0, NULL, NULL, NULL, '2023-10-30', 'WWF WrestleMania 2000 is a professional wrestling video game released in 1999 on the Nintendo 64 (N64) console. It was based on the World Wrestling Federation''s annual pay-per-view, WrestleMania. Despite the fact that this game is based upon WrestleMania 2000, the game was released five months prior to the actual PPV itself, therefore resulting in the game using the stage design from the 1999 event, WrestleMania XV, instead. Released at the height of the WWF''s Attitude Era, WrestleMania 2000 was the first WWF game released by THQ. The WWF ended its long relationship with Acclaim Entertainment after witnessing the video game success of its competitor, World Championship Wrestling (WCW), on behalf of THQ. WrestleMania 2000 shares its game engine with the Japan-only release Virtual Pro Wrestling 2: Ōdō Keishō.', 'https://media.retroachievements.org/Images/079526.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/079523.png', 'https://media.retroachievements.org/Images/079524.png', 4.1),
  (159, 17468, '~Hack~ Mario''s Vacation Course', 'Nintendo 64', 2, 280, 280, 280, 8, 0, '3D Platforming', 'Renou', 'Hack - Super Mario 64', '2021-04-16', 'Super Mario is a platform game series developed and published by Nintendo and starring their mascot, Mario. The series was created by Japanese game designer Shigeru Miyamoto and is the flagship series of the greater Mario franchise. At least one Super Mario game has been released for every major Nintendo video game console. A limited number of Super Mario games have also released on non-Nintendo gaming platforms.', 'https://media.retroachievements.org/Images/074071.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/071199.png', 'https://media.retroachievements.org/Images/071200.png', 4.1),
  (160, 10307, 'Space Station Silicon Valley', 'Nintendo 64', 2, 280, 280, 280, 68, 0, '3D Platforming', 'Rockstar North', 'Take-Two Interactive', '1998-10-21', 'Space Station Silicon Valley is a platform video game developed by DMA Design and published by Take-Two Interactive. It was originally released for the Nintendo 64 in October 1998. An adaptation of the game for Game Boy Color was developed by Tarantula Studios and released in 1999. A PlayStation port, developed by Runecraft, was released in 2000, under the name Evo''s Space Adventures. Players control Evo, a robot reduced to a crawling microchip after a ship crash, and are tasked with taking control of animals to solve puzzles and defeat enemies.', 'https://media.retroachievements.org/Images/113172.png', 'https://media.retroachievements.org/Images/066072.png', 'https://media.retroachievements.org/Images/011372.png', 'https://media.retroachievements.org/Images/011371.png', 4.1),
  (161, 20051, '~Hack~ Gourmet Guy''s 1000 IQ Food Quiz', 'Nintendo 64', 2, 277, 277, 277, 8, 0, 'Turn-Based RPG', 'Wrymouth', 'Hack - Paper Mario', '2022-06-18', '   The Japanese children''s manga series Doraemon was written and illustrated by Fujiko F. Fujio. In December 1969, it was serialized in various children''s manga magazines published by Shogakukan.', 'https://media.retroachievements.org/Images/059727.png', 'https://media.retroachievements.org/Images/059733.png', 'https://media.retroachievements.org/Images/059730.png', 'https://media.retroachievements.org/Images/059732.png', 4.1),
  (162, 10265, 'Body Harvest', 'Nintendo 64', 2, 277, 277, 277, 65, 0, 'Action-Adventure, Third-Person Shooter', 'Rockstar North', 'Midway, Gremlin Interactive', '1998-09-30', 'Body Harvest is a 1998 action-adventure video game developed by DMA Design and published by Gremlin Interactive for the Nintendo 64. It was intended to be a launch title for the system, but was delayed due to its original publisher, Nintendo, having issues with the game''s violent themes; they eventually dropped the game, leaving DMA to find a new publisher. Gremlin would later acquire the rights to the game and released it in Europe, while Midway Games released it in North America.', 'https://media.retroachievements.org/Images/051739.png', 'https://media.retroachievements.org/Images/011091.png', 'https://media.retroachievements.org/Images/011089.png', 'https://media.retroachievements.org/Images/011090.png', 4.1),
  (163, 10473, 'Killer Instinct Gold', 'Nintendo 64', 2, 277, 277, 277, 78, 0, '2D Fighting', 'Rare', 'Nintendo', '1996-11-01', 'Killer Instinct Gold is a 1996 fighting game developed by Rare and published by Nintendo for the Nintendo 64. It is based on the arcade game Killer Instinct 2. Players control characters who fight on a 2D plane set against a 3D background. Players press buttons to punch and kick their opponent in chains of successive hits, known as combos. Large combo successions lead to stronger attacks and brutal, stylistic finisher moves underscored by an announcer. Characters—including a gargoyle, a ninja, and a femme fatale—fight in settings such as a jungle and a spaceship. Killer Instinct Gold includes the arcade release''s characters, combos, and 3D, pre-rendered environments, but excludes its full-motion video sequences and some voice-overs due to restrictions of the cartridge media format. The Gold release adds a training mode, camera views, and improved audiovisuals.', 'https://media.retroachievements.org/Images/073831.png', 'https://media.retroachievements.org/Images/080754.png', 'https://media.retroachievements.org/Images/017261.png', 'https://media.retroachievements.org/Images/017262.png', 4.1),
  (164, 14695, '~Hack~ ~Demo~ The Legend of Peach', 'Nintendo 64', 2, 271, 271, 271, 6, 0, NULL, 'Melonspeedruns', NULL, '2021-12-09', 'Princess Peach is a character in Nintendo''s Mario franchise. She was created by Shigeru Miyamoto and introduced in the 1985 original Super Mario Bros. game as Princess Toadstool. She is the princess regnant and head of state of the Mushroom Kingdom, where she resides in her castle along with Toads. Since her debut, she has appeared in the majority of Mario video games as the main female character and the romantic interest of Mario.', 'https://media.retroachievements.org/Images/116456.png', 'https://media.retroachievements.org/Images/111396.png', 'https://media.retroachievements.org/Images/111399.png', 'https://media.retroachievements.org/Images/111400.png', 4.1),
  (165, 19490, '~Hack~ Banjo-Kazooie: How the Gruntch Stole Christmas', 'Nintendo 64', 2, 267, 267, 267, 10, 0, '3D Platforming, Collect-a-thon', 'Hacker - Kurko Mods', 'Hack - Banjo-Kazooie', '2021-12-22', NULL, 'https://media.retroachievements.org/Images/087092.png', 'https://media.retroachievements.org/Images/087061.png', 'https://media.retroachievements.org/Images/087058.png', 'https://media.retroachievements.org/Images/087063.png', 4.1),
  (166, 16760, '~Hack~ Another Mario Adventure', 'Nintendo 64', 2, 263, 263, 263, 69, 0, NULL, 'aglab2 et al.', 'Hack - Super Mario 64', '2020-08-21', 'Paper Mario is a 2000 role-playing video game developed by Intelligent Systems and published by Nintendo for the Nintendo 64 home video game console. Paper Mario is the first game in the Paper Mario series. First released in Japan in 2000 and then internationally in 2001, Paper Mario was later re-released for Nintendo''s Wii Virtual Console in July 2007, the Wii U Virtual Console in April 2015, and the Nintendo Classics service on December 10, 2021.', 'https://media.retroachievements.org/Images/060684.png', 'https://media.retroachievements.org/Images/060566.png', 'https://media.retroachievements.org/Images/060540.png', 'https://media.retroachievements.org/Images/060541.png', 4.1),
  (167, 14036, '~Hack~ Star Revenge 1: Star Takeover', 'Nintendo 64', 2, 263, 263, 263, 36, 0, '3D Platforming', 'Hacker - BroDute', 'Hack - Super Mario 64', '2012-09-03', 'This is a list of video games considered controversial. The list includes games that have earned controversies for violence, sexual content, racism, and review bombing from fans. Some of the video games on this list have been banned or regionally censored.', 'https://media.retroachievements.org/Images/078809.png', 'https://media.retroachievements.org/Images/024306.png', 'https://media.retroachievements.org/Images/023627.png', 'https://media.retroachievements.org/Images/023709.png', 4.1),
  (168, 14331, '~Hack~ Super Mario Fallen Stars', 'Nintendo 64', 2, 260, 260, 260, 18, 0, NULL, 'Skillux', 'Hack - Super Mario 64', '2013-03-01', 'Super Mario is a platform game series developed and published by Nintendo and starring their mascot, Mario. The series was created by Japanese game designer Shigeru Miyamoto and is the flagship series of the greater Mario franchise. At least one Super Mario game has been released for every major Nintendo video game console. A limited number of Super Mario games have also released on non-Nintendo gaming platforms.', 'https://media.retroachievements.org/Images/025176.png', 'https://media.retroachievements.org/Images/025005.png', 'https://media.retroachievements.org/Images/025000.png', 'https://media.retroachievements.org/Images/025002.png', 4.1),
  (169, 10520, 'Turok 2: Seeds of Evil', 'Nintendo 64', 2, 258, 258, 258, 42, 0, 'First-Person Shooter', 'Iguana Entertainment', 'Acclaim', '1998-12-21', 'Turok 2: Seeds of Evil is a first-person shooter video game developed by Iguana Entertainment and published by Acclaim Entertainment. It was released for the Nintendo 64 console in 1998 and ported to Microsoft Windows computers in 1999. Seeds of Evil is the second game in the Turok video game series and a sequel to Turok: Dinosaur Hunter. The game follows the story of a Turok and his efforts to stop a powerful alien entity from escaping the confines of his Lightship. A different game set in the same fictional universe, also titled Turok 2: Seeds of Evil, was released for the Game Boy Color alongside the Nintendo 64 game.', 'https://media.retroachievements.org/Images/015809.png', 'https://media.retroachievements.org/Images/015806.png', 'https://media.retroachievements.org/Images/015807.png', 'https://media.retroachievements.org/Images/015808.png', 4),
  (170, 34006, '~Hack~ Hero of Law', 'Nintendo 64', 2, 251, 251, 251, 48, 0, 'Mystery, Visual Novel', 'Hacker - Newer Team', 'Hack - The Legend of Zelda: Ocarina of Time', '2025-06-28', 'The Legend of Zelda is a video game series created by Japanese game designers Shigeru Miyamoto and Takashi Tezuka. It is primarily developed and published by Nintendo, but some installments and re-releases have been outsourced to Flagship, Grezzo, and Tantalus Media.', 'https://media.retroachievements.org/Images/115365.png', 'https://media.retroachievements.org/Images/115407.png', 'https://media.retroachievements.org/Images/115041.png', 'https://media.retroachievements.org/Images/115283.png', 4),
  (171, 30717, '~Hack~ The Legend of Zelda: Time Lost', 'Nintendo 64', 2, 248, 248, 248, 62, 0, NULL, 'StoneeBadLuck', NULL, '2024-08-08', 'The Legend of Zelda: Ocarina of Time is a 1998 action-adventure game developed and published by Nintendo for the Nintendo 64. It was the first Legend of Zelda game with 3D graphics. It was released in Japan and North America in November 1998 and in PAL regions the following month.', 'https://media.retroachievements.org/Images/101484.png', 'https://media.retroachievements.org/Images/106009.png', 'https://media.retroachievements.org/Images/101289.png', 'https://media.retroachievements.org/Images/101475.png', 4),
  (172, 20029, '~Hack~ Cooking Princess', 'Nintendo 64', 2, 247, 247, 247, 12, 0, 'Cooking Simulation', 'elDexter', 'Hack - Paper Mario', '2022-06-18', 'Homebrew is a term for software produced by hobbyists for proprietary video game consoles, which are not intended to be user-programmable.', 'https://media.retroachievements.org/Images/060611.png', 'https://media.retroachievements.org/Images/060612.png', 'https://media.retroachievements.org/Images/059905.png', 'https://media.retroachievements.org/Images/059906.png', 4),
  (173, 10165, 'Indiana Jones and the Infernal Machine', 'Nintendo 64', 2, 246, 246, 246, 77, 0, 'Action-Adventure', 'Factor 5, LucasArts | Lucasfilm', 'LucasArts | Lucasfilm', '2000-12-15', 'Indiana Jones and the Infernal Machine is a 1999 action-adventure video game developed and published by LucasArts. The first 3D installment in the series, its gameplay focuses on solving puzzles, fighting enemies, and completing various platforming sections. The story is set in 1947, after the events of Indiana Jones and the Iron Phoenix, and puts the eponymous protagonist, the adventurer Indiana Jones, against the Soviet Union. In a race for a mythological Babylonian power source, he joins forces with the Central Intelligence Agency and collects four pieces of the Infernal Machine, an ancient device that allegedly opens a portal to another dimension.', 'https://media.retroachievements.org/Images/099146.png', 'https://media.retroachievements.org/Images/023930.png', 'https://media.retroachievements.org/Images/099144.png', 'https://media.retroachievements.org/Images/099145.png', 4),
  (174, 14663, '~Hack~ Super Mario 64: Peach''s Memory', 'Nintendo 64', 2, 245, 245, 245, 25, 0, '3D Platforming, Collect-a-thon', 'Daniel EDC', 'Hack - Super Mario 64', '2019-08-21', 'Super Mario 64 is a 1996 platform game developed and published by Nintendo for the Nintendo 64. It is the first Super Mario game to feature 3D gameplay, combining traditional Super Mario gameplay, visual style, and characters in a large open world. In the game, Bowser invades Princess Peach''s castle, kidnaps her, and hides the castle''s sources of protection, the Power Stars, in many different worlds inside magical paintings. As Mario, the player traverses levels and collects Power Stars to unlock areas of Princess Peach''s castle, to reach Bowser and rescue Princess Peach.', 'https://media.retroachievements.org/Images/027669.png', 'https://media.retroachievements.org/Images/027670.png', 'https://media.retroachievements.org/Images/027538.png', 'https://media.retroachievements.org/Images/027664.png', 4),
  (175, 17501, '~Hack~ Star Revenge 1.5: Star Takeover Redone', 'Nintendo 64', 2, 241, 241, 241, 60, 0, '3D Platforming', 'Hacker - BroDute', 'Hack - Super Mario 64', '2015-08-14', 'Paramount Pictures Corporation, commonly known as Paramount Pictures or simply Paramount, is an American film production and distribution company and the flagship namesake subsidiary of Paramount Skydance. Founded on May 8, 1912, it is the sixth-oldest global film studio and the second-oldest in the United States behind Universal Pictures, and it is one of the Big Five studios located within the city limits of Los Angeles.', 'https://media.retroachievements.org/Images/058012.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/058010.png', 'https://media.retroachievements.org/Images/058011.png', 4),
  (176, 11437, '~Hack~ Super Mario 64: Halloween Mayhem', 'Nintendo 64', 2, 241, 241, 241, 8, 0, '3D Platforming', 'Hacker - Kaze Emanuar, Kinopio', 'Hack - Super Mario 64', '2014-10-31', '   Consolevania is a Scottish internet television with a magazine format, dedicated to video game reviews, gaming features, and comedy sketches based on gaming culture. The show''s format was adapted for mainstream television as the BBC Scotland show videoGaiden, featuring the same creative team, while episodes of Consolevania continued to be produced and distributed online as time permitted.', 'https://media.retroachievements.org/Images/064972.png', 'https://media.retroachievements.org/Images/025048.png', 'https://media.retroachievements.org/Images/025045.png', 'https://media.retroachievements.org/Images/025046.png', 4),
  (177, 14739, '~Hack~ Paper Mario: Master Quest', 'Nintendo 64', 2, 239, 239, 239, 68, 0, 'Turn-Based RPG', 'Emperor_Thamz, Rain, JaThePlayer, Brotenko,Purseit', 'Hack - Paper Mario', '2019-04-20', 'Paper Mario is a video game series and part of the Mario franchise, developed by Intelligent Systems and published by Nintendo. It combines elements from the role-playing, action-adventure, and puzzle genres. Players control a paper cutout version of Mario, usually with allies, on a quest to defeat the antagonist. The series consists of six games and one spin-off; the first, Paper Mario (2000), was released for the Nintendo 64, and the most recent, a 2024 remake of 2004''s Paper Mario: The Thousand-Year Door, for the Nintendo Switch.', 'https://media.retroachievements.org/Images/101844.png', 'https://media.retroachievements.org/Images/028298.png', 'https://media.retroachievements.org/Images/028297.png', 'https://media.retroachievements.org/Images/105225.png', 4),
  (178, 17748, '~Hack~ Super Mario Sunshine 64', 'Nintendo 64', 2, 238, 238, 238, 20, 0, '3D Platforming', 'Team Cornersoft', 'Hack - Super Mario 64', '2020-02-13', 'Super Mario 64 is a 1996 platform game developed and published by Nintendo for the Nintendo 64. It is the first Super Mario game to feature 3D gameplay, combining traditional Super Mario gameplay, visual style, and characters in a large open world. In the game, Bowser invades Princess Peach''s castle, kidnaps her, and hides the castle''s sources of protection, the Power Stars, in many different worlds inside magical paintings. As Mario, the player traverses levels and collects Power Stars to unlock areas of Princess Peach''s castle, to reach Bowser and rescue Princess Peach.', 'https://media.retroachievements.org/Images/046584.png', 'https://media.retroachievements.org/Images/045309.png', 'https://media.retroachievements.org/Images/044855.png', 'https://media.retroachievements.org/Images/045660.png', 4),
  (179, 10652, '~Hack~ Paper Mario: Pro Mode', 'Nintendo 64', 2, 237, 237, 237, 75, 0, 'Turn-Based RPG', 'Clover', 'Hack - Paper Mario', '2017-07-17', 'Paper Mario is a 2000 role-playing video game developed by Intelligent Systems and published by Nintendo for the Nintendo 64 home video game console. Paper Mario is the first game in the Paper Mario series. First released in Japan in 2000 and then internationally in 2001, Paper Mario was later re-released for Nintendo''s Wii Virtual Console in July 2007, the Wii U Virtual Console in April 2015, and the Nintendo Classics service on December 10, 2021.', 'https://media.retroachievements.org/Images/112153.png', 'https://media.retroachievements.org/Images/024945.png', 'https://media.retroachievements.org/Images/024940.png', 'https://media.retroachievements.org/Images/024946.png', 4),
  (180, 13387, '~Hack~ Banjo-Kazooie: Gruntylvania', 'Nintendo 64', 2, 233, 233, 233, 7, 0, NULL, 'Hacker - Kurko Mods', NULL, '2022-10-01', NULL, 'https://media.retroachievements.org/Images/084682.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/084679.png', 'https://media.retroachievements.org/Images/084680.png', 4),
  (181, 35528, '~Hack~ The Slideverse', 'Nintendo 64', 2, 229, 229, 229, 20, 0, '3D Platforming', 'JakeDower', 'Hack - Super Mario 64', '2024-04-01', NULL, 'https://media.retroachievements.org/Images/119651.png', 'https://media.retroachievements.org/Images/119649.png', 'https://media.retroachievements.org/Images/119648.png', 'https://media.retroachievements.org/Images/119647.png', 4),
  (182, 10126, 'Tony Hawk''s Pro Skater 3', 'Nintendo 64', 2, 229, 229, 229, 49, 0, 'Extreme Sports - Skateboarding', 'Neversoft, Edge of Reality', 'Activision', '2002-08-20', 'Tony Hawk''s Pro Skater 3 is a 2001 skateboarding video game and the third installment in the Tony Hawk''s series. It was published by Activision under the Activision O2 label in 2001 for the PlayStation, PlayStation 2, Game Boy Color and GameCube. In 2002, it was published for the Xbox, Game Boy Advance, Windows, Mac OS, and the Nintendo 64. It was the final official release for the Nintendo 64 and the only game that was released for the system in 2002, the first game released for the PlayStation 2 supporting online play and was a launch title for the GameCube in North America and PAL regions.', 'https://media.retroachievements.org/Images/047928.png', 'https://media.retroachievements.org/Images/011060.png', 'https://media.retroachievements.org/Images/011057.png', 'https://media.retroachievements.org/Images/011058.png', 4),
  (183, 10471, '~Hack~ The Legend of Banjo-Kazooie: The Bear Waker Deluxe', 'Nintendo 64', 2, 228, 228, 228, 12, 0, '3D Platforming', 'Hacker - Kurko Mods', 'Hack - Banjo-Kazooie', '2019-01-01', ' This is a list of Xbox 360 games (A-L) that were released via retail disc, digital download or as part of the Xbox Live Arcade program.', 'https://media.retroachievements.org/Images/046318.png', 'https://media.retroachievements.org/Images/044076.png', 'https://media.retroachievements.org/Images/101485.png', 'https://media.retroachievements.org/Images/044103.png', 4),
  (184, 11530, 'Dance Dance Revolution: Disney Dancing Museum', 'Nintendo 64', 2, 226, 226, 226, 44, 0, 'Rhythm', 'Konami', 'Disney Interactive Studios', '2000-11-30', ' The Dance Dance Revolution series started in 1998 and has grown to a large set of games in the franchise. This list of Dance Dance Revolution games documents games released, including systems, formats, and regions for which the games were released.', 'https://media.retroachievements.org/Images/044306.png', 'https://media.retroachievements.org/Images/018372.png', 'https://media.retroachievements.org/Images/018373.png', 'https://media.retroachievements.org/Images/018374.png', 4),
  (185, 14625, '~Hack~ Mario''s Little Odyssey', 'Nintendo 64', 2, 223, 223, 223, 14, 0, '3D Platforming', 'Hacker - Kaze Emanuar', 'Hack - Super Mario 64', '2018-07-10', 'Super Mario is a platform game series developed and published by Nintendo and starring their mascot, Mario. The series was created by Japanese game designer Shigeru Miyamoto and is the flagship series of the greater Mario franchise. At least one Super Mario game has been released for every major Nintendo video game console. A limited number of Super Mario games have also released on non-Nintendo gaming platforms.', 'https://media.retroachievements.org/Images/027295.png', 'https://media.retroachievements.org/Images/042738.png', 'https://media.retroachievements.org/Images/027273.png', 'https://media.retroachievements.org/Images/027284.png', 4),
  (186, 14694, '~Hack~ Super Melee Adventure 64', 'Nintendo 64', 2, 222, 222, 222, 15, 0, '3D Platforming, Collect-a-thon', 'Hacker - Pasta Power', 'Hack - Super Mario 64', '2019-01-01', 'Super Smash Bros. is a 1999 crossover fighting game developed by HAL Laboratory and published by Nintendo for the Nintendo 64. It is the first game in the Super Smash Bros. series and was released in Japan on January 21, 1999; in North America on April 26, 1999; and in Europe on November 19, 1999. It was later released for the iQue Player in China on November 15, 2005.', 'https://media.retroachievements.org/Images/027887.png', 'https://media.retroachievements.org/Images/027888.png', 'https://media.retroachievements.org/Images/027817.png', 'https://media.retroachievements.org/Images/027886.png', 4),
  (187, 10466, 'Forsaken 64', 'Nintendo 64', 2, 220, 220, 220, 63, 0, 'First-Person Shooter', 'Iguana Entertainment', 'Acclaim', '1998-04-30', 'Forsaken is a 1998 shooter video game developed by Probe Entertainment and published by Acclaim Entertainment. It was released for Microsoft Windows and PlayStation, with a port to the Nintendo 64 developed by Iguana UK releasing the same year as Forsaken 64.', 'https://media.retroachievements.org/Images/047208.png', 'https://media.retroachievements.org/Images/025502.png', 'https://media.retroachievements.org/Images/025499.png', 'https://media.retroachievements.org/Images/097783.png', 4),
  (188, 10125, 'Tony Hawk''s Pro Skater 2', 'Nintendo 64', 2, 219, 219, 219, 35, 0, 'Extreme Sports - Skateboarding', 'Neversoft, Edge of Reality', 'Activision', '2001-08-21', 'Tony Hawk''s Pro Skater 2 is a 2000 skateboarding video game developed by Neversoft for PlayStation and Natsume for Game Boy Color. Published by Activision, it is the second installment in the Tony Hawk''s series of sports games, and was released for the PlayStation in 2000, with subsequent ports to Windows and Dreamcast alongside a distinct version for Game Boy Color the same year. In 2001, the game was ported to Mac OS, Mac OS X, Nintendo 64, and Xbox, alongside a separate version for Game Boy Advance by Vicarious Visions. The game was later ported to Windows Mobile and Windows Phone devices in 2006 and to iPhone OS devices in 2010.', 'https://media.retroachievements.org/Images/041741.png', 'https://media.retroachievements.org/Images/011051.png', 'https://media.retroachievements.org/Images/011049.png', 'https://media.retroachievements.org/Images/011050.png', 4),
  (189, 10332, 'WWF WrestleMania 2000', 'Nintendo 64', 2, 219, 219, 219, 39, 0, 'Sports - Wrestling', 'AKI | syn Sophia', 'THQ', '1999-10-31', 'WrestleMania 2000, also known as WrestleMania 16, was a professional wrestling pay-per-view (PPV) event produced by the World Wrestling Federation. It was the 16th annual WrestleMania, and took place on April 2, 2000, at the Arrowhead Pond of Anaheim in Anaheim, California. This was the second WrestleMania at this venue, after WrestleMania XII in 1996. A total of nine matches were contested on the event''s card.', 'https://media.retroachievements.org/Images/012052.png', 'https://media.retroachievements.org/Images/012053.png', 'https://media.retroachievements.org/Images/012051.png', 'https://media.retroachievements.org/Images/012055.png', 4),
  (190, 29859, '~Hack~ Banjo-Kongzooie', 'Nintendo 64', 2, 212, 212, 212, 16, 0, '3D Platforming, Collect-a-thon', 'GloriousLiar', 'Hack - Donkey Kong 64', '2023-03-20', NULL, 'https://media.retroachievements.org/Images/098053.png', 'https://media.retroachievements.org/Images/103163.png', 'https://media.retroachievements.org/Images/097925.png', 'https://media.retroachievements.org/Images/097927.png', 4),
  (191, 15805, '~Prototype~ Tamiya Racing 64', 'Nintendo 64', 2, 211, 211, 211, 8, 0, 'Racing', 'Looking Glass Studios', 'Looking Glass Studios', '2012-04-05', 'Over the years, the Tamiya Corporation has created a huge number of notable product lines. This article attempts to list them.', 'https://media.retroachievements.org/Images/031575.png', 'https://media.retroachievements.org/Images/031578.png', 'https://media.retroachievements.org/Images/031576.png', 'https://media.retroachievements.org/Images/031577.png', 4),
  (192, 10430, 'Rugrats: Scavenger Hunt', 'Nintendo 64', 2, 209, 209, 209, 31, 0, 'Board Game', 'Realtime Associates', 'THQ', '1999-06-29', 'Rugrats: Scavenger Hunt is a 1999 party video game developed by Realtime Associates and published by THQ for the Nintendo 64. The game is based on the Nickelodeon animated television series Rugrats. It features the original voices from the Rugrats cast reprising their roles as Tommy Pickles, Chuckie Finster, and Phil and Lil DeVille as well as supporting characters Grandpa Lou, Didi and Stu Pickles, Susie Carmichael, Reptar, and series antagonist Angelica Pickles.', 'https://media.retroachievements.org/Images/063753.png', 'https://media.retroachievements.org/Images/026391.png', 'https://media.retroachievements.org/Images/026392.png', 'https://media.retroachievements.org/Images/026394.png', 4),
  (193, 31886, '~Hack~ Banjo-Kazooie: New Snow Glow Village', 'Nintendo 64', 2, 207, 207, 207, 12, 0, '3D Platforming, Collect-a-thon', 'Hacker - Kurko Mods, Koolboymon, Skill', 'Hack - Banjo-Kazooie', '2022-12-24', 'The following is a list of albums, EPs, and mixtapes released in the second half of 2021. These albums are (1) original, i.e. excluding reissues, remasters, and compilations of previously released recordings, and (2) notable, defined as having received significant coverage from reliable sources independent of the subject.', 'https://media.retroachievements.org/Images/105740.png', 'https://media.retroachievements.org/Images/105737.png', 'https://media.retroachievements.org/Images/105738.png', 'https://media.retroachievements.org/Images/105739.png', 4),
  (194, 10561, '~Hack~ Luigi''s Mansion 64', 'Nintendo 64', 2, 206, 206, 206, 37, 0, '3D Platforming', 'Lincrash', 'Hack - Super Mario 64', '2015-05-31', 'Nintendo Classics is a line of emulated retro games distributed by Nintendo for the Nintendo Switch and Nintendo Switch 2. Launched in 2018, subscribers of the Nintendo Switch Online service have access to games for the Nintendo Entertainment System (NES), Super Nintendo Entertainment System (SNES), Game Boy (GB) and Game Boy Color (GBC). A more expensive subscription tier, titled "Expansion Pack", was introduced in 2021. Through this tier, players can also access Nintendo 64 (N64), Sega Genesis (GEN), Game Boy Advance (GBA), and Virtual Boy (VB) games, with GameCube (GCN) exclusively available on Nintendo Switch 2. Each console''s library is accessed through a dedicated app, with new games being added on an irregular basis. Games are accessible as long as the user has an active subscription, and a user must connect to the internet at least once a week to continue to access services while offline.', 'https://media.retroachievements.org/Images/049691.png', 'https://media.retroachievements.org/Images/049385.png', 'https://media.retroachievements.org/Images/049382.png', 'https://media.retroachievements.org/Images/049383.png', 4),
  (195, 10325, 'WWF War Zone', 'Nintendo 64', 2, 206, 206, 206, 64, 0, 'Sports - Wrestling', 'Sculptured Software | Iguana West', 'Acclaim', '1998-08-11', 'WWF War Zone is a professional wrestling video game developed by Iguana West and released by Acclaim Entertainment in 1998 for the PlayStation, Nintendo 64, and Game Boy. The game features wrestlers from the World Wrestling Federation (WWF) and was the first graphical 3D game based on the WWF.', 'https://media.retroachievements.org/Images/070694.png', 'https://media.retroachievements.org/Images/070695.png', 'https://media.retroachievements.org/Images/070692.png', 'https://media.retroachievements.org/Images/070693.png', 4),
  (196, 10574, 'Custom Robo', 'Nintendo 64', 2, 205, 205, 205, 40, 0, '3D Arena Battler RPG', 'Noise', 'Nintendo', '1999-12-08', 'Custom Robo is an action role-playing video game series developed by Noise and published by Nintendo.', 'https://media.retroachievements.org/Images/062605.png', 'https://media.retroachievements.org/Images/015978.png', 'https://media.retroachievements.org/Images/015977.png', 'https://media.retroachievements.org/Images/015997.png', 4),
  (197, 30934, '~Hack~ Banjo-Kazooie: Bubbling Bog Brewery Redone', 'Nintendo 64', 2, 204, 204, 204, 7, 0, '3D Platforming, Collect-a-thon', 'Hacker - Kurko Mods', 'Hack - Banjo-Kazooie', '2023-10-31', NULL, 'https://media.retroachievements.org/Images/103195.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/102464.png', 'https://media.retroachievements.org/Images/102465.png', 4),
  (198, 16228, '~Hack~ SimpleFlips'' 8th Hacking Competition: Creepypasta', 'Nintendo 64', 2, 199, 199, 199, 53, 0, '3D Platforming', 'Various', 'Hack - Super Mario 64', '2019-05-20', NULL, 'https://media.retroachievements.org/Images/033337.png', 'https://media.retroachievements.org/Images/033338.png', 'https://media.retroachievements.org/Images/033463.png', 'https://media.retroachievements.org/Images/033316.png', 4),
  (199, 19485, '~Hack~ Banjo-Kazooie: Cheato''s Challenges', 'Nintendo 64', 2, 198, 198, 198, 16, 0, '3D Platforming, Collect-a-thon', NULL, 'Hack - Banjo-Kazooie', '2022-03-01', 'Banjo-Kazooie is a 1998 platform game developed by Rare and published by Nintendo for the Nintendo 64. Controlling the player characters, the bear Banjo and the bird Kazooie, the player attempts to save Banjo''s kidnapped sister Tooty from the witch Gruntilda. The player explores nine nonlinear worlds to gather items and progress. Using Banjo and Kazooie''s traversal and combat abilities, they complete challenges such as solving puzzles, jumping over obstacles, and defeating bosses.', 'https://media.retroachievements.org/Images/063461.png', 'https://media.retroachievements.org/Images/066509.png', 'https://media.retroachievements.org/Images/063460.png', 'https://media.retroachievements.org/Images/063406.png', 4),
  (200, 36253, '~Hack~ Mario Adventure 2', 'Nintendo 64', 2, 196, 196, 196, 137, 0, NULL, 'aglab2', NULL, '2025-10-17', 'Paper Mario is a 2000 role-playing video game developed by Intelligent Systems and published by Nintendo for the Nintendo 64 home video game console. Paper Mario is the first game in the Paper Mario series. First released in Japan in 2000 and then internationally in 2001, Paper Mario was later re-released for Nintendo''s Wii Virtual Console in July 2007, the Wii U Virtual Console in April 2015, and the Nintendo Classics service on December 10, 2021.', 'https://media.retroachievements.org/Images/123212.png', 'https://media.retroachievements.org/Images/121743.png', 'https://media.retroachievements.org/Images/120316.png', 'https://media.retroachievements.org/Images/120319.png', 4);
INSERT INTO games (rank, id, title, consoleName, consoleId, totalPlayers, casualPlayers, hardcorePlayers, numAchievements, points, genre, developer, publisher, released, description, icon, boxArt, titleScreen, screenshot, rating) VALUES
  (1, 7212, 'Pokémon HeartGold Version | Pokémon SoulSilver Version', 'Nintendo DS', 18, 10107, 10107, 10107, 136, 0, 'Turn-Based RPG', 'Game Freak', 'Nintendo', '2009-09-12', 'Pokémon is a Japanese series of creature collector role-playing video games developed by Game Freak and published by Nintendo and The Pokémon Company under the Pokémon franchise. It was created by Satoshi Tajiri with assistance from Ken Sugimori. The first games, Pocket Monsters Red and Green, were released in 1996 in Japan for the Game Boy, later released outside of Japan as Pokémon Red Version and Blue Version. The main series of role-playing video games (RPGs), referred as the "core series" by their developers, has continued on each generation of Nintendo''s handhelds. The most recently released core series game, Pokémon Legends: Z-A was released on October 16, 2025 for both the Nintendo Switch and the Nintendo Switch 2.', 'https://media.retroachievements.org/Images/063592.png', 'https://media.retroachievements.org/Images/036144.png', 'https://media.retroachievements.org/Images/036139.png', 'https://media.retroachievements.org/Images/036140.png', 5),
  (2, 5522, 'Castlevania: Dawn of Sorrow', 'Nintendo DS', 18, 7727, 7727, 7727, 68, 0, 'Metroidvania, 2D Platforming', 'Konami', 'Konami', '2005-08-25', 'Castlevania: Dawn of Sorrow is a 2005 action role-playing game developed and published by Konami. It is part of Konami''s Castlevania video game series and the first Castlevania game released on the Nintendo DS. The game is the sequel to Castlevania: Aria of Sorrow and incorporates many elements from its predecessor.', 'https://media.retroachievements.org/Images/106339.png', 'https://media.retroachievements.org/Images/071783.png', 'https://media.retroachievements.org/Images/071784.png', 'https://media.retroachievements.org/Images/071785.png', 4.9),
  (3, 14806, 'Sonic Rush', 'Nintendo DS', 18, 6027, 6027, 6027, 34, 0, '2D Platforming', 'Sega, Dimps, Sonic Team', 'Sega', '2005-11-15', 'Sonic Rush is a 2005 platform game developed by Sonic Team and Dimps for the Nintendo DS as part of Sega''s Sonic the Hedgehog series. It was released on November 15, 2005, in North America, November 18 in the PAL region, and November 23 in Japan, and was the final game in the mainline Sonic series to be produced by Yuji Naka before his departure from Sega. It was the first Sonic game with the English 4Kids cast, instead of the cast first seen in Sonic Adventure. It is a 2D platform game, similar to earlier games in the series like Sonic Advance, as well as later ones like Sonic Mania. Levels in the game are side-scrolling and displayed using both of the DS''s screens. However, boss battles, the main characters, and a special stage are rendered in 3D, creating a 2.5D effect. The game''s storyline follows the intertwining adventures of the series'' main character, Sonic the Hedgehog and a new character, Blaze the Cat. They respectively battle Doctor Eggman and his doppelgänger Eggman Nega at certain points.', 'https://media.retroachievements.org/Images/034807.png', 'https://media.retroachievements.org/Images/028955.png', 'https://media.retroachievements.org/Images/028910.png', 'https://media.retroachievements.org/Images/038169.png', 4.9),
  (4, 14763, 'Kirby Super Star Ultra', 'Nintendo DS', 18, 5744, 5744, 5744, 50, 0, '2D Platforming', 'HAL Laboratory', 'Nintendo', '2008-09-22', 'Kirby Super Star Ultra is a 2008 anthology platform game developed by HAL Laboratory and published by Nintendo for the Nintendo DS. The game is an enhanced remake of Kirby Super Star, originally released for the Super Nintendo Entertainment System in 1996, to commemorate the Kirby series'' 15th anniversary. The remake retains all game modes found in the original and adds four major new ones, along with adding updated visuals and full-motion video cutscenes.', 'https://media.retroachievements.org/Images/123005.png', 'https://media.retroachievements.org/Images/124460.png', 'https://media.retroachievements.org/Images/028627.png', 'https://media.retroachievements.org/Images/028628.png', 4.9),
  (5, 11732, 'Pokémon Platinum Version', 'Nintendo DS', 18, 5548, 5548, 5548, 101, 0, NULL, NULL, NULL, '2008-09-13', 'Pokémon is a Japanese series of creature collector role-playing video games developed by Game Freak and published by Nintendo and The Pokémon Company under the Pokémon franchise. It was created by Satoshi Tajiri with assistance from Ken Sugimori. The first games, Pocket Monsters Red and Green, were released in 1996 in Japan for the Game Boy, later released outside of Japan as Pokémon Red Version and Blue Version. The main series of role-playing video games (RPGs), referred as the "core series" by their developers, has continued on each generation of Nintendo''s handhelds. The most recently released core series game, Pokémon Legends: Z-A was released on October 16, 2025 for both the Nintendo Switch and the Nintendo Switch 2.', 'https://media.retroachievements.org/Images/104787.png', 'https://media.retroachievements.org/Images/016546.png', 'https://media.retroachievements.org/Images/028629.png', 'https://media.retroachievements.org/Images/046971.png', 4.9),
  (6, 9983, 'Super Mario 64 DS', 'Nintendo DS', 18, 5352, 5352, 5352, 191, 0, '3D Platforming, Collect-a-thon', NULL, 'Nintendo', '2004-11-21', 'Super Mario 64 DS is an enhanced remake of the 1996 platform game Super Mario 64, developed and published by Nintendo for the Nintendo DS handheld game console. As with the original title, the game''s plot centers on rescuing Princess Peach from Bowser. Players start the game with Yoshi as the playable character and gain access to Mario, Luigi, and Wario as the story progresses.', 'https://media.retroachievements.org/Images/070042.png', 'https://media.retroachievements.org/Images/027923.png', 'https://media.retroachievements.org/Images/028674.png', 'https://media.retroachievements.org/Images/028769.png', 4.8),
  (7, 9878, 'Tetris DS', 'Nintendo DS', 18, 5061, 5061, 5061, 102, 0, NULL, NULL, 'Nintendo', '2006-03-20', 'Tetris DS is a puzzle video game developed and published by Nintendo. It was released for the Nintendo DS on March 20, 2006, in North America, April 13, 2006, in Australia, April 21, 2006, in Europe, and April 27, 2006, in Japan. An installment of the Tetris franchise, the game supports up to ten players locally, and supported online multiplayer of up to four players using Nintendo Wi-Fi Connection prior to its discontinuation.', 'https://media.retroachievements.org/Images/059744.png', 'https://media.retroachievements.org/Images/043276.png', 'https://media.retroachievements.org/Images/043278.png', 'https://media.retroachievements.org/Images/043277.png', 4.8),
  (8, 16211, 'Pokémon White Version', 'Nintendo DS', 18, 4188, 4188, 4188, 73, 0, NULL, NULL, NULL, '2010-09-18', 'Pokémon Black Version and Pokémon White Version are 2010 role-playing video games developed by Game Freak and published by The Pokémon Company and Nintendo for the Nintendo DS. They are the first installments in the fifth generation of the Pokémon video game series. First released in Japan on 18 September 2010, they were later released in Europe, North America and Australia in 2011. Sequels to Black and White, Pokémon Black 2 and Pokémon White 2, were released for the Nintendo DS in 2012.', 'https://media.retroachievements.org/Images/104481.png', 'https://media.retroachievements.org/Images/032988.png', 'https://media.retroachievements.org/Images/033230.png', 'https://media.retroachievements.org/Images/033229.png', 4.8),
  (9, 12711, 'Mario Kart DS', 'Nintendo DS', 18, 4183, 4183, 4183, 100, 0, 'Kart Racing', NULL, 'Nintendo', '2005-11-14', 'Mario Kart DS is a 2005 kart racing game developed and published by Nintendo for the Nintendo DS handheld game console. Like other games in the series, Mario Kart DS features characters from the Mario series and pits them against each other as they race in karts on tracks based on locations in the Mario series. It was released in November 2005 in North America, Europe, and Australia, and on December 8, 2005, in Japan, and rereleased for the Wii U''s Virtual Console in North America and PAL regions in April 2015 and in Japan in May 2016. The game is the fifth main entry in the Mario Kart series, and the first playable via the Nintendo Wi-Fi Connection online service.', 'https://media.retroachievements.org/Images/072928.png', 'https://media.retroachievements.org/Images/028717.png', 'https://media.retroachievements.org/Images/028624.png', 'https://media.retroachievements.org/Images/028623.png', 4.8),
  (10, 12747, 'Phoenix Wright: Ace Attorney', 'Nintendo DS', 18, 3283, 3283, 3283, 83, 0, 'Visual Novel', 'Capcom', 'Capcom', '2005-10-12', 'Phoenix Wright: Ace Attorney is a visual novel adventure game developed and published by Capcom. It was released in 2001 for the Game Boy Advance in Japan and has been ported to multiple platforms. The 2005 Nintendo DS version, titled Gyakuten Saiban Yomigaeru Gyakuten in Japan, introduced an English language option, and was the first time the game was released in North America and Europe. It is the first entry in the Ace Attorney series; several sequels and spin-offs were produced, while this game has seen further ports and remasters for computers, game consoles, and mobile devices.', 'https://media.retroachievements.org/Images/060426.png', 'https://media.retroachievements.org/Images/030508.png', 'https://media.retroachievements.org/Images/053621.png', 'https://media.retroachievements.org/Images/053629.png', 4.7),
  (11, 14700, 'Kirby: Squeak Squad', 'Nintendo DS', 18, 3187, 3187, 3187, 86, 0, '2D Platforming', 'Flagship, HAL Laboratory', 'Nintendo', '2006-11-02', 'Kirby: Squeak Squad is a 2006  platform game developed by HAL Laboratory and Flagship and published by Nintendo for the Nintendo DS. It is one of the mainline installment entries of the Kirby series and the second Kirby game released for the system. The game was released in Japan and North America in 2006 and in Europe, Australia, and South Korea in 2007. The game was later re-released for the Wii U''s Virtual Console on June 25, 2015.', 'https://media.retroachievements.org/Images/111488.png', 'https://media.retroachievements.org/Images/027844.png', 'https://media.retroachievements.org/Images/043283.png', 'https://media.retroachievements.org/Images/043284.png', 4.7),
  (12, 14853, 'Pokémon Mystery Dungeon: Explorers of Sky', 'Nintendo DS', 18, 2933, 2933, 2933, 128, 0, 'Roguelike', 'Chunsoft', 'Nintendo', '2009-04-18', 'Pokémon Mystery Dungeon: Explorers of Sky is an enhanced version of Pokémon Mystery Dungeon: Explorers of Time and Explorers of Darkness released for the Nintendo DS in 2009, developed by Chunsoft and published by The Pokémon Company and Nintendo. Referred to as the definitive edition to the aforementioned games, additional features include the addition of the missing Generation IV Pokémon, further character development for a few side characters in content known as Special Episodes, and a few quality of life improvement for options, items, and other gameplay and system related features.', 'https://media.retroachievements.org/Images/042484.png', 'https://media.retroachievements.org/Images/039517.png', 'https://media.retroachievements.org/Images/039514.png', 'https://media.retroachievements.org/Images/039515.png', 4.7),
  (13, 9407, 'Castlevania: Portrait of Ruin', 'Nintendo DS', 18, 2873, 2873, 2873, 88, 0, 'Metroidvania, 2D Platforming', 'Konami', 'Konami', '2006-12-05', 'Castlevania: Portrait of Ruin is a 2006 action role-playing game developed and published by Konami for the Nintendo DS handheld system. The game is the first in the Castlevania series to feature a cooperative multiplayer gameplay mode and the first handheld entry to have English voice-overs, outside of its original Japanese release.', 'https://media.retroachievements.org/Images/105113.png', 'https://media.retroachievements.org/Images/071799.png', 'https://media.retroachievements.org/Images/071801.png', 'https://media.retroachievements.org/Images/071800.png', 4.7),
  (14, 9518, 'Professor Layton and the Curious Village', 'Nintendo DS', 18, 2838, 2838, 2838, 42, 0, NULL, NULL, NULL, '2007-02-15', 'Professor Layton and the Curious Village is a puzzle adventure video game for the Nintendo DS system. It was developed and published by Level-5 in Japan and published by Nintendo worldwide. It was released in Japan in 2007 and worldwide the following year. It was re-released in Australia using the British English localisation and European artwork to replace the previously released North American localisation. Curious Village is the first game in the Professor Layton series, followed by Professor Layton and the Diabolical Box. An enhanced mobile port of Curious Village featuring additional cutscenes, subtitled "HD for Mobile", was released in 2018.', 'https://media.retroachievements.org/Images/068336.png', 'https://media.retroachievements.org/Images/027863.png', 'https://media.retroachievements.org/Images/028672.png', 'https://media.retroachievements.org/Images/028673.png', 4.7),
  (15, 7010, 'Castlevania: Order of Ecclesia', 'Nintendo DS', 18, 2747, 2747, 2747, 94, 0, 'Metroidvania, 2D Platforming', 'Konami', 'Konami', '2008-10-21', 'Castlevania: Order of Ecclesia is a 2008 action role-playing game and the third Nintendo DS installment of the Castlevania franchise. It was directed by Akihiro Minakata, with producer Koji Igarashi returning. The plot involves Shanoa, who is part of an organization set to defeat Dracula after the Belmont clan has vanished.', 'https://media.retroachievements.org/Images/106340.png', 'https://media.retroachievements.org/Images/071796.png', 'https://media.retroachievements.org/Images/071798.png', 'https://media.retroachievements.org/Images/071797.png', 4.7),
  (16, 12718, 'Plants vs. Zombies', 'Nintendo DS', 18, 2652, 2652, 2652, 64, 0, 'Tower Defense', 'TOSE, PopCap Games', 'PopCap Games', '2011-01-18', 'Plants vs. Zombies is a video game franchise created by George Fan. The series follows the affiliates of David "Crazy Dave" Blazing as they use his plants to defend against a zombie invasion, led by Dr. Edgar George Zomboss. The first game, Plants vs. Zombies (2009), was developed by PopCap Seattle and released by PopCap Games before being acquired by Electronic Arts (EA). After PopCap Games'' acquisition, EA expanded the game into a franchise with games on many different platforms, including a comic book series written by Paul Tobin and published by Dark Horse Comics.', 'https://media.retroachievements.org/Images/074637.png', 'https://media.retroachievements.org/Images/034121.png', 'https://media.retroachievements.org/Images/034188.png', 'https://media.retroachievements.org/Images/034189.png', 4.7),
  (17, 5323, 'Mario & Luigi: Bowser''s Inside Story', 'Nintendo DS', 18, 2410, 2410, 2410, 109, 0, 'Turn-Based RPG', 'AlphaDream', 'Nintendo', '2009-02-11', 'Mario & Luigi: Bowser''s Inside Story is a 2009 role-playing video game developed by AlphaDream and published by Nintendo for the Nintendo DS. It is the third game in the Mario & Luigi series, following Partners in Time (2005). It uses the interactive screens of the DS in some of its gameplay mechanics while also introducing several elements that would be used in the series'' future gameplay.', 'https://media.retroachievements.org/Images/112160.png', 'https://media.retroachievements.org/Images/030585.png', 'https://media.retroachievements.org/Images/031522.png', 'https://media.retroachievements.org/Images/044708.png', 4.7),
  (18, 5853, 'Pokémon Black Version 2', 'Nintendo DS', 18, 2391, 2391, 2391, 187, 0, 'Turn-Based RPG', 'Game Freak', 'Nintendo, The Pokémon Company', '2012-06-23', 'Pokémon Black Version 2 and Pokémon White Version 2 are 2012 role-playing video games developed by Game Freak, published by The Pokémon Company and Nintendo for the Nintendo DS. Part of the fifth generation of the Pokémon video game series, the games are direct sequels to Pokémon Black and Pokémon White, being the first sequels in the series. They were first released in Japan in June 2012, with a worldwide release following in October 2012, as the last first-party games for the system. The games feature the legendary Pokémon identified by Junichi Masuda as Black Kyurem and White Kyurem. The games were first revealed on February 26, 2012, in the episode of the Japanese television program Pokémon Smash!, followed by an international confirmation on the Pokémon official website.', 'https://media.retroachievements.org/Images/105979.png', 'https://media.retroachievements.org/Images/062584.png', 'https://media.retroachievements.org/Images/080689.png', 'https://media.retroachievements.org/Images/073466.png', 4.7),
  (19, 9594, 'Animal Crossing: Wild World', 'Nintendo DS', 18, 2175, 2175, 2175, 157, 0, 'Life Simulation', NULL, 'Nintendo', '2005-11-23', 'Animal Crossing: Wild World is a 2005 social simulation video game developed and published by Nintendo for the Nintendo DS handheld game console. It was released in Japan in November 2005, in North America and Australia in December 2005, and in Europe in March 2006. It is the second installment in the Animal Crossing series, and the sequel to Animal Crossing on the GameCube.', 'https://media.retroachievements.org/Images/071904.png', 'https://media.retroachievements.org/Images/039333.png', 'https://media.retroachievements.org/Images/039293.png', 'https://media.retroachievements.org/Images/042440.png', 4.6),
  (20, 14811, 'Sonic & Sega All-Stars Racing', 'Nintendo DS', 18, 2130, 2130, 2130, 99, 0, 'Kart Racing', 'Sumo Digital', 'Sega', '2010-02-23', 'Sonic & Sega All-Stars Racing is a 2010 kart racing video game developed by Sumo Digital and published by Sega. It was released for Wii, Xbox 360, PlayStation 3, Nintendo DS, and Windows, featuring characters from multiple Sega franchises. The game is the third title in the Sega All-Stars series, preceded by Sega Superstars Tennis. A mobile version was developed by Gameloft, and released for iOS in June 2011, as a paid download. A version for OS X was released by Feral Interactive in April 2013.', 'https://media.retroachievements.org/Images/038912.png', 'https://media.retroachievements.org/Images/028987.png', 'https://media.retroachievements.org/Images/028915.png', 'https://media.retroachievements.org/Images/042193.png', 4.6),
  (21, 14323, 'The Legend of Zelda: Phantom Hourglass', 'Nintendo DS', 18, 2048, 2048, 2048, 67, 0, 'Action-Adventure', NULL, 'Nintendo', '2007-06-23', 'The Legend of Zelda: Phantom Hourglass is a 2007 action-adventure game developed and published by Nintendo for the Nintendo DS handheld game console. It is the fourteenth installment in The Legend of Zelda series and the direct sequel to the 2002 GameCube game The Wind Waker. Phantom Hourglass was released worldwide in 2007, with the exception of South Korea in April 2008. It was re-released for the Wii U via the Virtual Console service in the PAL region in November 2015, in North America in May 2016, and in Japan in August 2016.', 'https://media.retroachievements.org/Images/109728.png', 'https://media.retroachievements.org/Images/067328.png', 'https://media.retroachievements.org/Images/029210.png', 'https://media.retroachievements.org/Images/042344.png', 4.6),
  (22, 9852, 'Pokémon Diamond Version', 'Nintendo DS', 18, 1902, 1902, 1902, 121, 0, NULL, NULL, NULL, '2006-09-28', 'Pokémon is a Japanese series of creature collector role-playing video games developed by Game Freak and published by Nintendo and The Pokémon Company under the Pokémon franchise. It was created by Satoshi Tajiri with assistance from Ken Sugimori. The first games, Pocket Monsters Red and Green, were released in 1996 in Japan for the Game Boy, later released outside of Japan as Pokémon Red Version and Blue Version. The main series of role-playing video games (RPGs), referred as the "core series" by their developers, has continued on each generation of Nintendo''s handhelds. The most recently released core series game, Pokémon Legends: Z-A was released on October 16, 2025 for both the Nintendo Switch and the Nintendo Switch 2.', 'https://media.retroachievements.org/Images/104785.png', 'https://media.retroachievements.org/Images/027617.png', 'https://media.retroachievements.org/Images/027622.png', 'https://media.retroachievements.org/Images/027623.png', 4.6),
  (23, 14808, 'Sonic Colors', 'Nintendo DS', 18, 1896, 1896, 1896, 42, 0, '2D Platforming', 'Sega, Dimps, Sonic Team', 'Sega', '2010-11-11', 'Sonic Colors is a 2010 platform game developed by Sonic Team and published by Sega. It follows Sonic''s quest to stop his nemesis Doctor Eggman from enslaving an alien race and taking over the world. The gameplay is similar to prior Sonic games, with players collecting rings and defeating enemies; the camera perspective often switches from third-person to side-scrolling perspectives. The game also introduces Wisps, power-ups the player can use to increase attack power and reach new areas.', 'https://media.retroachievements.org/Images/114272.png', 'https://media.retroachievements.org/Images/028990.png', 'https://media.retroachievements.org/Images/045152.png', 'https://media.retroachievements.org/Images/045153.png', 4.6),
  (24, 16197, 'Pokémon White Version 2', 'Nintendo DS', 18, 1863, 1863, 1863, 151, 0, NULL, NULL, NULL, '2012-06-23', 'Pokémon Black Version 2 and Pokémon White Version 2 are 2012 role-playing video games developed by Game Freak, published by The Pokémon Company and Nintendo for the Nintendo DS. Part of the fifth generation of the Pokémon video game series, the games are direct sequels to Pokémon Black and Pokémon White, being the first sequels in the series. They were first released in Japan in June 2012, with a worldwide release following in October 2012, as the last first-party games for the system. The games feature the legendary Pokémon identified by Junichi Masuda as Black Kyurem and White Kyurem. The games were first revealed on February 26, 2012, in the episode of the Japanese television program Pokémon Smash!, followed by an international confirmation on the Pokémon official website.', 'https://media.retroachievements.org/Images/105970.png', 'https://media.retroachievements.org/Images/042704.png', 'https://media.retroachievements.org/Images/042702.png', 'https://media.retroachievements.org/Images/042703.png', 4.6),
  (25, 1199, 'WarioWare: Touched!', 'Nintendo DS', 18, 1828, 1828, 1828, 45, 0, 'Minigames', 'Intelligent Systems', 'Nintendo', '2004-12-02', 'WarioWare: Touched! is a 2004 action game developed by Nintendo SPD and Intelligent Systems and published by Nintendo for the Nintendo DS. The fourth installment of the WarioWare series, and the first of three on the Nintendo DS, the game involves rapidly completing "microgames" — simple minigames lasting extremely short periods of time — as quickly as possible. The microgames are exclusively controlled with the Nintendo DS''s touchscreen and microphone.', 'https://media.retroachievements.org/Images/039657.png', 'https://media.retroachievements.org/Images/028502.png', 'https://media.retroachievements.org/Images/028505.png', 'https://media.retroachievements.org/Images/028504.png', 4.6),
  (26, 16298, 'Ace Attorney Investigations: Miles Edgeworth', 'Nintendo DS', 18, 1766, 1766, 1766, 91, 0, 'Visual Novel', 'Capcom', 'Capcom', '2009-05-28', 'Ace Attorney Investigations: Miles Edgeworth is a 2009 adventure video game developed and published by Capcom. It was originally released for the Nintendo DS in Japan in 2009, and internationally in 2010, and later for iOS and Android in 2017. It is the fifth game in the Ace Attorney series, and is set between the events of the third and fourth games, Phoenix Wright: Ace Attorney – Trials and Tribulations and Apollo Justice: Ace Attorney.', 'https://media.retroachievements.org/Images/086579.png', 'https://media.retroachievements.org/Images/035149.png', 'https://media.retroachievements.org/Images/035147.png', 'https://media.retroachievements.org/Images/040243.png', 4.6),
  (27, 16196, '~Hack~ Pokémon Renegade Platinum', 'Nintendo DS', 18, 1699, 1699, 1699, 109, 0, 'Turn-Based RPG', 'Hacker - Drayano', 'Hack - Pokemon Platinum Version', '2019-04-18', 'The Pokémon Trading Card Game collectible card game was released in Japan in 1996. As of December 2025, there are 126 card sets for the game released in English and as of April 2022, there are 91 released in Japan, including special sets. As of September 2017, collectively, there are 6,959 cards in Japanese sets and 9,110 cards in English sets. As of March 2017, 23.6 billion cards have been shipped worldwide.', 'https://media.retroachievements.org/Images/066999.png', 'https://media.retroachievements.org/Images/067000.png', 'https://media.retroachievements.org/Images/067074.png', 'https://media.retroachievements.org/Images/067073.png', 4.6),
  (28, 16274, 'Resident Evil: Deadly Silence', 'Nintendo DS', 18, 1676, 1676, 1676, 150, 0, 'Survival Horror', 'Capcom', 'Capcom', '2006-01-19', 'Resident Evil is a 1996 survival horror video game developed and published by Capcom for the PlayStation. It is the first main installment in Capcom''s Resident Evil series. Set in the fictional Arklay mountain region in the Midwest, players control Chris Redfield and Jill Valentine, members of the elite task force S.T.A.R.S., who must escape a mansion infested with zombies and other monsters.', 'https://media.retroachievements.org/Images/047094.png', 'https://media.retroachievements.org/Images/047487.png', 'https://media.retroachievements.org/Images/034463.png', 'https://media.retroachievements.org/Images/034466.png', 4.6),
  (29, 17492, 'Pokémon Mystery Dungeon: Blue Rescue Team', 'Nintendo DS', 18, 1474, 1474, 1474, 149, 0, 'Roguelike', 'Chunsoft', 'Nintendo, The Pokémon Company', '2005-11-17', 'Pokémon Mystery Dungeon: Blue Rescue Team and Pokémon Mystery Dungeon: Red Rescue Team are a matched pair of Pokémon video games for the Nintendo DS and Game Boy Advance, respectively. The games were developed by Chunsoft and published by The Pokémon Company and Nintendo. Red Rescue Team was the last Pokémon game released for the Game Boy Advance. The two versions are mostly identical, with Blue Rescue Team taking advantage of the dual-screen features and increased graphical and sound capabilities of the Nintendo DS. The game has six Pokémon exclusive to each version. Mystery Dungeon is quite different than the main-line games, as in the Mystery Dungeon games, you play as a Pokémon, as opposed to playing as a trainer.', 'https://media.retroachievements.org/Images/044315.png', 'https://media.retroachievements.org/Images/044314.png', 'https://media.retroachievements.org/Images/047785.png', 'https://media.retroachievements.org/Images/044707.png', 4.5),
  (30, 9093, 'Dragon Quest IX: Sentinels of the Starry Skies', 'Nintendo DS', 18, 1425, 1425, 1425, 161, 0, 'Turn-Based RPG', 'Level-5', 'Nintendo', '2009-07-11', 'Dragon Quest IX: Sentinels of the Starry Skies is a 2009 role-playing video game developed by Level-5 and Square Enix for the Nintendo DS. Published by Square Enix in Japan in July 2009 and by Nintendo overseas the following year, it is the ninth mainline entry in the Dragon Quest series. The storyline follows the protagonist, a member of the angelic Celestrian race, after a disaster in their home scatters magical fruits across the mortal realm. While carrying over traditional gameplay from the rest of the series with turn-based battles, the game is the first Dragon Quest entry to feature a customizable player character, and the first to include a multiplayer mode, with the option of trading treasure maps and loaning player characters through Nintendo Wi-Fi. Online functions ended in 2014 when it ceased operations.', 'https://media.retroachievements.org/Images/038654.png', 'https://media.retroachievements.org/Images/041699.png', 'https://media.retroachievements.org/Images/043271.png', 'https://media.retroachievements.org/Images/041702.png', 4.5),
  (31, 17565, 'Drawn To Life: SpongeBob SquarePants Edition', 'Nintendo DS', 18, 1422, 1422, 1422, 42, 0, '2D Platforming, Sandbox', 'Altron', 'THQ', '2008-09-15', ' The SpongeBob SquarePants video game series is a collection of video games and arcade games based on the Nickelodeon animated television series SpongeBob SquarePants and its film series with the same name. The television series'' massive rise in popularity during the 2000s led to a myriad of video games that span different genres. Several of these games are based on concepts from specific episodes, two of which are based on theatrical releases. Some of these titles had multiple different versions developed for a variety of home consoles and handheld consoles. Until 2013, the vast majority of titles were published by THQ. From 2013 to 2015, the license for most titles was handed to Activision. The license is currently held by THQ Nordic. Video games based on the series have often received mixed reviews from critics, yet many of these titles have performed well in sales.', 'https://media.retroachievements.org/Images/124718.png', 'https://media.retroachievements.org/Images/051188.png', 'https://media.retroachievements.org/Images/077702.png', 'https://media.retroachievements.org/Images/077701.png', 4.5),
  (32, 14807, 'Sonic Rush Adventure', 'Nintendo DS', 18, 1390, 1390, 1390, 48, 0, '2D Platforming', 'Sega, Dimps, Sonic Team', 'Sega', '2007-09-13', 'Sonic Rush Adventure is a 2007 platform game developed by Dimps and Sonic Team and published by Sega for the Nintendo DS. The sequel to 2005''s Sonic Rush, it follows Sonic the Hedgehog and Tails, who are teleported to an alternate dimension and seek the help of Blaze the Cat, while battling a band of robot pirates. Gameplay is similar to prior installments in the Sonic the Hedgehog franchise, with players controlling Sonic or Blaze through a series of side-scrolling levels while collecting rings and defeating enemies. Sonic Rush Adventure deviates from prior games with its elements of sea travel, featuring boating minigames that take advantage of the DS''s touchscreen.', 'https://media.retroachievements.org/Images/063480.png', 'https://media.retroachievements.org/Images/028974.png', 'https://media.retroachievements.org/Images/028911.png', 'https://media.retroachievements.org/Images/040595.png', 4.5),
  (33, 16153, 'Digimon World DS', 'Nintendo DS', 18, 1372, 1372, 1372, 49, 0, NULL, 'BEC', 'Bandai Namco', '2006-06-15', 'Digimon World DS, known in Japan as Digimon Story , is a role-playing video game for the Nintendo DS developed by BEC and published by Bandai Namco Games. The game was released in Japan on June 15, 2006, and in North America later that year on November 8. Despite its localized title, the game shares no relation to the separate Digimon World series.', 'https://media.retroachievements.org/Images/073614.png', 'https://media.retroachievements.org/Images/045221.png', 'https://media.retroachievements.org/Images/047116.png', 'https://media.retroachievements.org/Images/047120.png', 4.5),
  (34, 14860, 'Pokémon Conquest', 'Nintendo DS', 18, 1188, 1188, 1188, 61, 0, 'Tactical RPG', 'Koei', 'The Pokémon Company', '2012-03-17', ' Pokémon Conquest, known in Japan as Pokémon + Nobunaga''s Ambition , is a 2012 tactical role-playing video game developed by Tecmo Koei and published by The Pokémon Company and Nintendo for the Nintendo DS. The game is a crossover between the Pokémon and Nobunaga''s Ambition video game series. The game was released in Japan on March 17, 2012 and was released in North America, Australia, and Europe later that year.', 'https://media.retroachievements.org/Images/035990.png', 'https://media.retroachievements.org/Images/028993.png', 'https://media.retroachievements.org/Images/028995.png', 'https://media.retroachievements.org/Images/028996.png', 4.5),
  (35, 9252, 'Super Princess Peach', 'Nintendo DS', 18, 1151, 1151, 1151, 61, 0, '2D Platforming', 'TOSE', 'Nintendo', '2005-10-20', 'Super Princess Peach is a 2005 platform game developed by Tose and published by Nintendo for the Nintendo DS. It was released in Japan in October 2005 and worldwide the following year. Super Princess Peach is the first game to feature Princess Peach as the main protagonist on a dedicated video game console and the second overall after Princess Toadstool''s Castle Run released in 1990 on the Nelsonic Game Watch.', 'https://media.retroachievements.org/Images/087666.png', 'https://media.retroachievements.org/Images/113282.png', 'https://media.retroachievements.org/Images/029111.png', 'https://media.retroachievements.org/Images/029112.png', 4.5),
  (36, 9770, 'Dragon Quest IV: Chapters of the Chosen', 'Nintendo DS', 18, 1147, 1147, 1147, 80, 0, 'Turn-Based RPG', 'ArtePiazza', 'Square Enix', '2008-09-16', 'Dragon Quest IV: Chapters of the Chosen, titled Dragon Warrior IV when initially localized to North America, is a 1990 role-playing video game, the fourth installment of the Dragon Quest video game series developed by Chunsoft and published by Enix, and the first of the Zenithian Trilogy. It was originally released for the Famicom on 11 February 1990 in Japan. A North American NES version followed in October 1992, and would be the last Dragon Quest game localized and published by Enix''s Enix America Corporation subsidiary prior to its closure in November 1995, as well as the last Dragon Quest game to be localized into English prior to the localization of Dragon Warrior Monsters in December 1999. The game was remade by Heartbeat for the PlayStation, which eventually was available as an Ultimate Hits game. The remake was ported by ArtePiazza to the Nintendo DS, released in Japan November 2007 and worldwide in September 2008. A mobile version based on the Nintendo DS remake was released in 2014 for Android and iOS.', 'https://media.retroachievements.org/Images/073137.png', 'https://media.retroachievements.org/Images/034164.png', 'https://media.retroachievements.org/Images/034165.png', 'https://media.retroachievements.org/Images/038385.png', 4.5),
  (37, 9232, 'Elite Beat Agents', 'Nintendo DS', 18, 1125, 1125, 1125, 86, 0, 'Rhythm', 'iNiS', 'Nintendo', '2006-11-06', 'Elite Beat Agents is a rhythm video game developed by iNiS and published by Nintendo for the Nintendo DS. It was released in North America, Europe and South Korea. As the second of three rhythm games developed by iNiS specifically for the DS, it is the follow-up and international counterpart to Osu! Tatakae! Ouendan, a Japanese rhythm game released in 2005, sharing many common elements with it.', 'https://media.retroachievements.org/Images/038909.png', 'https://media.retroachievements.org/Images/040339.png', 'https://media.retroachievements.org/Images/040337.png', 'https://media.retroachievements.org/Images/040338.png', 4.5),
  (38, 25369, 'Pokémon Pearl Version', 'Nintendo DS', 18, 1081, 1081, 1081, 210, 0, 'Turn-Based RPG', 'Game Freak', 'Nintendo, The Pokémon Company', '2006-09-28', 'Pokémon is a Japanese series of creature collector role-playing video games developed by Game Freak and published by Nintendo and The Pokémon Company under the Pokémon franchise. It was created by Satoshi Tajiri with assistance from Ken Sugimori. The first games, Pocket Monsters Red and Green, were released in 1996 in Japan for the Game Boy, later released outside of Japan as Pokémon Red Version and Blue Version. The main series of role-playing video games (RPGs), referred as the "core series" by their developers, has continued on each generation of Nintendo''s handhelds. The most recently released core series game, Pokémon Legends: Z-A was released on October 16, 2025 for both the Nintendo Switch and the Nintendo Switch 2.', 'https://media.retroachievements.org/Images/104840.png', 'https://media.retroachievements.org/Images/112817.png', 'https://media.retroachievements.org/Images/080725.png', 'https://media.retroachievements.org/Images/080726.png', 4.5),
  (39, 16618, 'Doodle Jump Journey', 'Nintendo DS', 18, 1058, 1058, 1058, 12, 0, 'Endless Runner', 'Smoking Gun Interactive', 'GameMill Entertainment', '2013-10-29', 'Doodle Jump is a 2009 platformer video game developed and published by Igor and Marko Pušenjak, who make up the Lima Sky LLC. The game was released for Windows Phone, iOS, BlackBerry, Android, Java Mobile, Nokia Symbian, and Xbox 360 for the Kinect. It was released worldwide for iOS in March 2009, Android and Blackberry on March 2, 2010, Symbian on May 1, 2010, Windows Phone 7 on June 1, 2011, the iPad on September 1, 2011, and Windows Phone 8 on August 21, 2013. Since its release, the game has been generally well received.', 'https://media.retroachievements.org/Images/043333.png', 'https://media.retroachievements.org/Images/037708.png', 'https://media.retroachievements.org/Images/043331.png', 'https://media.retroachievements.org/Images/043332.png', 4.5),
  (40, 4958, 'Final Fantasy Tactics A2: Grimoire of the Rift', 'Nintendo DS', 18, 1051, 1051, 1051, 185, 0, 'Tactical RPG', 'Square Enix', 'Square Enix', '2008-06-24', 'Final Fantasy Tactics A2: Grimoire of the Rift is a 2007 tactical role-playing game developed and published by Square Enix for the Nintendo DS. Releasing in 2007 in Japan and 2008 in the West, the game is a sequel to Final Fantasy Tactics Advance and forms part of the Ivalice Alliance, a group of games set in the titular fictional universe. The game features cameo appearances from central and supporting characters from Final Fantasy XII, a title set in Ivalice.', 'https://media.retroachievements.org/Images/070806.png', 'https://media.retroachievements.org/Images/030588.png', 'https://media.retroachievements.org/Images/036020.png', 'https://media.retroachievements.org/Images/036021.png', 4.5),
  (41, 14809, 'Sonic Chronicles: The Dark Brotherhood', 'Nintendo DS', 18, 1036, 1036, 1036, 68, 0, 'Turn-Based RPG', 'BioWare', 'Sega', '2008-09-25', 'Sonic Chronicles: The Dark Brotherhood is a 2008 role-playing video game developed by BioWare and published by Sega for the Nintendo DS. It is a part of the Sonic the Hedgehog series, and is its only RPG entry. Sonic Chronicles initially focuses on the events surrounding the kidnapping of Knuckles and the disappearance of the Chaos Emeralds after the defeat of Doctor Eggman, before moving on to follow the cast of characters across two dimensions as they encounter a new ally, Shade the Echidna, and seek to stop the invasion of their world by Ix, the leader of Shade''s tribe, the Nocturnus. The game is mainly played using the DS stylus, with players either exploring the overworld, or attacking with multiple characters in combat.', 'https://media.retroachievements.org/Images/038176.png', 'https://media.retroachievements.org/Images/028975.png', 'https://media.retroachievements.org/Images/086252.png', 'https://media.retroachievements.org/Images/086253.png', 4.5),
  (42, 14786, 'Yoshi''s Island DS', 'Nintendo DS', 18, 1025, 1025, 1025, 95, 0, '2D Platforming', 'Artoon', 'Nintendo', '2006-11-13', 'Yoshi''s Island DS, known in Japan as Yoshi Island DS, is a 2006 platform game developed by Artoon and published by Nintendo for the Nintendo DS. It was released in North America and Australia in November 2006, in Europe in December 2006, and in Japan in March 2007. It is a sequel to the 1995 SNES game, Super Mario World 2: Yoshi''s Island. Announced at Nintendo''s E3 press conference in May 2006, the game was well received by critics. The game was originally to be titled Yoshi''s Island 2, though its name was changed one month before its North American release. In April and May 2015, the game was made available for the Wii U via the Virtual Console service, shortly after a Nintendo Direct presentation.', 'https://media.retroachievements.org/Images/035024.png', 'https://media.retroachievements.org/Images/028968.png', 'https://media.retroachievements.org/Images/028754.png', 'https://media.retroachievements.org/Images/034937.png', 4.5),
  (43, 9617, 'Picross 3D', 'Nintendo DS', 18, 994, 994, 994, 44, 0, 'Nonogram', 'HAL Laboratory', 'Nintendo', '2009-03-12', 'Picross 3D, known in Japan as Rittai Picross , is a puzzle video game developed by HAL Laboratory and published by Nintendo for the Nintendo DS. It was released in Japan in March 2009, in Europe in March 2010, and in North America in May 2010. It uses similar nonogram mechanics to Picross DS, but adapted to a three-dimensional environment by adding an extra axis blocks can go on. Outside Japan, the game is part of Nintendo''s Touch! Generations brand. It was also released for the Wii U''s Virtual Console in Europe and Japan in 2016 and North America in 2017. A sequel, Picross 3D: Round 2, was released for the Nintendo 3DS in Japan in October 2015, in North America in September 2016, and in Europe and Australia in December 2016.', 'https://media.retroachievements.org/Images/115219.png', 'https://media.retroachievements.org/Images/112818.png', 'https://media.retroachievements.org/Images/028736.png', 'https://media.retroachievements.org/Images/028740.png', 4.4),
  (44, 11730, 'Mario Party DS', 'Nintendo DS', 18, 982, 982, 982, 112, 0, 'Board Game, Party', 'Hudson Soft', 'Nintendo', '2007-11-08', 'Mario Party DS is a 2007 party video game developed by Hudson Soft and published by Nintendo for the Nintendo DS. It is the second handheld game in the Mario Party series, the only one to be released for the DS, and the last to be developed by Hudson Soft, as all subsequent titles have been developed by Nintendo Cube. The game was re-released on the Virtual Console for the Wii U in 2016.', 'https://media.retroachievements.org/Images/115417.png', 'https://media.retroachievements.org/Images/019596.png', 'https://media.retroachievements.org/Images/033275.png', 'https://media.retroachievements.org/Images/036078.png', 4.4),
  (45, 9537, 'Phoenix Wright: Ace Attorney - Justice for All', 'Nintendo DS', 18, 969, 969, 969, 66, 0, 'Visual Novel', 'Capcom', 'Capcom', '2007-01-16', 'Phoenix Wright: Ace Attorney – Justice for All is a visual novel adventure video game developed and published by Capcom. It was originally released for the Game Boy Advance in 2002 in Japan, and has since been released on multiple platforms. The Nintendo DS version, initially released in 2006 in Japan, was released in English in the West in 2007. The game is the second entry in the Ace Attorney series, following Phoenix Wright: Ace Attorney.', 'https://media.retroachievements.org/Images/086532.png', 'https://media.retroachievements.org/Images/030582.png', 'https://media.retroachievements.org/Images/033186.png', 'https://media.retroachievements.org/Images/033187.png', 4.4),
  (46, 1172, 'Retro Game Challenge', 'Nintendo DS', 18, 967, 967, 967, 76, 0, NULL, 'indieszero', 'XSEED Games', '2009-02-10', 'Retro Game Challenge is a minigame compilation video game developed by indieszero and published by Namco Bandai Games for the Nintendo DS. It is based on the television series GameCenter CX, with host Shinya Arino providing significant input into the game creation process. The game was released on November 15, 2007 in Japan and February 10, 2009 in North America by Xseed Games.', 'https://media.retroachievements.org/Images/099080.png', 'https://media.retroachievements.org/Images/028632.png', 'https://media.retroachievements.org/Images/028635.png', 'https://media.retroachievements.org/Images/028636.png', 4.4),
  (47, 4911, 'Ghost Trick: Phantom Detective', 'Nintendo DS', 18, 954, 954, 954, 33, 0, 'Adventure', 'Capcom', 'Capcom', '2011-01-11', 'Ghost Trick: Phantom Detective is a 2010 puzzle adventure video game developed and published by Capcom. The story follows Sissel, an amnesiac ghost with supernatural powers, and his journey to rediscover his identity. Players solve environmental puzzles, interact with eccentric characters, and uncover the truth of Sissel''s death over the course of one night. Gameplay is split into two sections: gathering information by navigating through the city, and saving lives by traveling back in time.', 'https://media.retroachievements.org/Images/060996.png', 'https://media.retroachievements.org/Images/028650.png', 'https://media.retroachievements.org/Images/028647.png', 'https://media.retroachievements.org/Images/028648.png', 4.4),
  (48, 999, '999: Nine Hours, Nine Persons, Nine Doors', 'Nintendo DS', 18, 907, 907, 907, 23, 0, 'Visual Novel', 'Chunsoft', 'Spike, Aksys Games', '2009-12-10', '999: Nine Hours, Nine Persons, Nine Doors is a visual novel and adventure video game developed by Chunsoft. It is the first installment in the Zero Escape series, and was released in Japan in December 2009 and in North America in November 2010 for the Nintendo DS. The story follows Junpei, a college student who is abducted along with eight other people and forced to play the "Nonary Game", which puts its participants in a life-or-death situation, to escape from a sinking cruise liner. The gameplay alternates between two types of sections: Escape sections, where the player completes puzzles in escape-the-room scenarios; and Novel sections, where the player reads the game''s narrative and makes decisions that influence the story toward one of six different endings.', 'https://media.retroachievements.org/Images/093358.png', 'https://media.retroachievements.org/Images/027500.png', 'https://media.retroachievements.org/Images/029800.png', 'https://media.retroachievements.org/Images/029802.png', 4.4),
  (49, 16254, 'Dragon Quest Heroes: Rocket Slime', 'Nintendo DS', 18, 891, 891, 891, 89, 0, 'Action-Adventure', 'TOSE', 'Square Enix', '2006-09-19', 'Dragon Quest Heroes: Rocket Slime is an action-adventure game developed by Tose and published by Square Enix for the Nintendo DS handheld video game console. It is the sequel to Slime Mori Mori Dragon Quest: Shōgeki no Shippo Dan for the Game Boy Advance. It was first released in Japan, and later in North America. It is a spin-off of the Dragon Quest series.', 'https://media.retroachievements.org/Images/055622.png', 'https://media.retroachievements.org/Images/037738.png', 'https://media.retroachievements.org/Images/037737.png', 'https://media.retroachievements.org/Images/037740.png', 4.4),
  (50, 6616, 'Scribblenauts', 'Nintendo DS', 18, 863, 863, 863, 311, 0, 'Puzzle, Action', '5th Cell', 'Warner Bros. Interactive Entertainment', '2009-09-15', 'Scribblenauts is a video game series developed by 5th Cell and Shiver Entertainment and published by Warner Bros. Interactive Entertainment.', 'https://media.retroachievements.org/Images/107693.png', 'https://media.retroachievements.org/Images/045398.png', 'https://media.retroachievements.org/Images/056147.png', 'https://media.retroachievements.org/Images/056148.png', 4.4),
  (51, 15429, 'Dragon Ball Z: Supersonic Warriors 2', 'Nintendo DS', 18, 852, 852, 852, 153, 0, '2D Fighting', 'Arc System Works', 'Atari', '2005-11-20', 'Dragon Ball Z: Supersonic Warriors  is a series of fighting games based on the Dragon Ball franchise. The first game was developed by Arc System Works and Cavia and was released for the Game Boy Advance on June 22, 2004. A sequel, Supersonic Warriors 2, was released in 2005 for the Nintendo DS.', 'https://media.retroachievements.org/Images/110471.png', 'https://media.retroachievements.org/Images/054427.png', 'https://media.retroachievements.org/Images/054500.png', 'https://media.retroachievements.org/Images/054498.png', 4.4),
  (52, 16363, 'Game & Watch Collection', 'Nintendo DS', 18, 833, 833, 833, 12, 0, 'Compilation', 'Nintendo', 'Nintendo', '2006-06-28', '  This is a list of Game & Watch games released by Nintendo. Several were collected and remade as part for the Game & Watch Gallery series for Game Boy, Game Boy Color, and Game Boy Advance. They were re-released in the Nintendo Mini Classics series in the late 1990s. Digital recreations in DSiWare were released for Nintendo DSi in 2009 and for Nintendo 3DS in 2011.', 'https://media.retroachievements.org/Images/112770.png', 'https://media.retroachievements.org/Images/035123.png', 'https://media.retroachievements.org/Images/035128.png', 'https://media.retroachievements.org/Images/035129.png', 4.4),
  (53, 14829, '~Hack~ Newer Super Mario Bros. DS', 'Nintendo DS', 18, 831, 831, 831, 50, 0, '2D Platforming', 'Hacker - Newer Team', 'Hack - New Super Mario Bros.', '2017-12-25', 'Super Mario 64 DS is an enhanced remake of the 1996 platform game Super Mario 64, developed and published by Nintendo for the Nintendo DS handheld game console. As with the original title, the game''s plot centers on rescuing Princess Peach from Bowser. Players start the game with Yoshi as the playable character and gain access to Mario, Luigi, and Wario as the story progresses.', 'https://media.retroachievements.org/Images/124219.png', 'https://media.retroachievements.org/Images/041242.png', 'https://media.retroachievements.org/Images/042111.png', 'https://media.retroachievements.org/Images/028781.png', 4.4),
  (54, 5291, 'Tomodachi Collection', 'Nintendo DS', 18, 826, 826, 826, 49, 0, 'Life Simulation', 'Nintendo', 'Nintendo', '2009-06-18', 'Tomodachi Collection is a 2009 social simulation video game developed and published by Nintendo for the Nintendo DS solely in Japan. Directed by Ryutaro Takahashi, the game follows the daily interactions between user-created Miis, all of whom reside on a remote island overseen by the player.', 'https://media.retroachievements.org/Images/047122.png', 'https://media.retroachievements.org/Images/054638.png', 'https://media.retroachievements.org/Images/053979.png', 'https://media.retroachievements.org/Images/053978.png', 4.4),
  (55, 9985, 'Rhythm Heaven', 'Nintendo DS', 18, 816, 816, 816, 46, 0, 'Rhythm', NULL, 'Nintendo', '2008-07-31', 'Rhythm Heaven, known as Rhythm Paradise in PAL regions, and Rhythm World in South Korea, is a rhythm game developed and published by Nintendo for the Nintendo DS. It is the second game in Nintendo''s Rhythm Heaven series, following the Japan-only Rhythm Tengoku (2006) for the Game Boy Advance. The game was first released in Japan in July 2008, and in North America, Europe, Oceania, and South Korea throughout 2009. It is the first game in the Rhythm Heaven series to be localized outside of Japan.', 'https://media.retroachievements.org/Images/060997.png', 'https://media.retroachievements.org/Images/032533.png', 'https://media.retroachievements.org/Images/032529.png', 'https://media.retroachievements.org/Images/032530.png', 4.4),
  (56, 5626, 'Advance Wars: Dual Strike', 'Nintendo DS', 18, 805, 805, 805, 126, 0, 'Turn-Based Strategy', 'Intelligent Systems', 'Nintendo', '2005-06-23', 'Advance Wars: Dual Strike, known as Famicom Wars DS in Japan, is a turn-based strategy video game developed by Intelligent Systems and published by Nintendo for the Nintendo DS handheld game console. It is the third installment in the Advance Wars series and was released in 2005 for Japan on June 23, in North America on August 22, in Europe on September 30 and in Australia on March 22, 2006.', 'https://media.retroachievements.org/Images/033351.png', 'https://media.retroachievements.org/Images/032609.png', 'https://media.retroachievements.org/Images/032610.png', 'https://media.retroachievements.org/Images/033354.png', 4.4),
  (57, 16295, 'Pokémon Ranger', 'Nintendo DS', 18, 804, 804, 804, 58, 0, 'Action RPG', 'APE | Creatures, HAL Laboratory', 'Nintendo', '2006-03-23', 'Pokémon Ranger is an action role-playing video game developed by HAL Laboratory and Creatures Inc. and published by The Pokémon Company and Nintendo for the Nintendo DS video game console. The game was released in Japan, North America, and Australia in 2006 before releasing in Europe in 2007.', 'https://media.retroachievements.org/Images/077490.png', 'https://media.retroachievements.org/Images/040529.png', 'https://media.retroachievements.org/Images/045155.png', 'https://media.retroachievements.org/Images/040530.png', 4.4),
  (58, 17844, '~Hack~ CTGP: Nitro', 'Nintendo DS', 18, 787, 787, 787, 168, 0, 'Kart Racing', 'CTGP Nitro Team', 'Hack - Mario Kart DS', '2022-02-05', '  Unlicensed developers and fans have created unofficial media relating to the Mario franchise. Such media include video games, ROM hacks, level editors, live action adaptations, and animations.', 'https://media.retroachievements.org/Images/065335.png', 'https://media.retroachievements.org/Images/060473.png', 'https://media.retroachievements.org/Images/060481.png', 'https://media.retroachievements.org/Images/060480.png', 4.4),
  (59, 16279, '~Homebrew~ Bubble Wrap DS', 'Nintendo DS', 18, 745, 745, 745, 7, 0, 'Simulation', 'Prodigy Games', 'Prodigy Games', '2012-01-01', 'Ghost Trick: Phantom Detective is a 2010 puzzle adventure video game developed and published by Capcom. The story follows Sissel, an amnesiac ghost with supernatural powers, and his journey to rediscover his identity. Players solve environmental puzzles, interact with eccentric characters, and uncover the truth of Sissel''s death over the course of one night. Gameplay is split into two sections: gathering information by navigating through the city, and saving lives by traveling back in time.', 'https://media.retroachievements.org/Images/034527.png', 'https://media.retroachievements.org/Images/034528.png', 'https://media.retroachievements.org/Images/034525.png', 'https://media.retroachievements.org/Images/034526.png', 4.4),
  (60, 4655, 'Dragon Quest V: Hand of the Heavenly Bride', 'Nintendo DS', 18, 741, 741, 741, 74, 0, 'Turn-Based RPG', 'Chunsoft', 'Square Enix', '2008-07-17', 'Dragon Quest V: Hand of the Heavenly Bride, known in Europe as Dragon Quest: The Hand of the Heavenly Bride and in Japan as Dragon Quest V: Bride of Heaven, is a 1992 role-playing video game developed by Chunsoft and published by Enix for the Super Famicom. The fifth main installment in the Dragon Quest series, the game was the first title in the franchise to not be initially localized in North America due to programming issues.', 'https://media.retroachievements.org/Images/038655.png', 'https://media.retroachievements.org/Images/043944.png', 'https://media.retroachievements.org/Images/043946.png', 'https://media.retroachievements.org/Images/043945.png', 4.4),
  (61, 9898, 'The Legend of Zelda: Spirit Tracks', 'Nintendo DS', 18, 731, 731, 731, 70, 0, 'Action-Adventure', NULL, 'Nintendo', '2009-12-07', 'The Legend of Zelda: Spirit Tracks is a 2009 action-adventure game developed and published by Nintendo for the Nintendo DS handheld game console. Set a century after The Wind Waker and its sequel Phantom Hourglass, the storyline follows the current incarnations of Link and Princess Zelda as they explore the land of New Hyrule to prevent the awakening of the Demon King Malladus. Players navigate New Hyrule, completing quests that advance the story and solving environmental and dungeon-based puzzles, many requiring use of the DS''s touchscreen and other hardware features. Navigation between towns and dungeons is done using a train, which features its own set of mechanics and puzzles.', 'https://media.retroachievements.org/Images/046401.png', 'https://media.retroachievements.org/Images/067329.png', 'https://media.retroachievements.org/Images/034047.png', 'https://media.retroachievements.org/Images/034050.png', 4.4),
  (62, 17484, '42 All-Time Classics', 'Nintendo DS', 18, 692, 692, 692, 64, 0, 'Card Game', 'Agenda', 'Nintendo', '2005-11-03', 'Clubhouse Games is a party video game developed by Agenda and published by Nintendo for the Nintendo DS. It consists of board, card, and tabletop games from around the world. It was released across 2005 and 2006, with some games included varying between regions. A follow-up for the Nintendo Switch, Clubhouse Games: 51 Worldwide Classics, was developed by NDcube and released worldwide in June 2020.', 'https://media.retroachievements.org/Images/042422.png', 'https://media.retroachievements.org/Images/042425.png', 'https://media.retroachievements.org/Images/042423.png', 'https://media.retroachievements.org/Images/042424.png', 4.4),
  (63, 4887, 'The World Ends with You', 'Nintendo DS', 18, 691, 691, 691, 98, 0, 'Action RPG', 'Jupiter', 'Square Enix', '2007-07-26', 'The World Ends with You is an action role-playing game co-developed by Square Enix and Jupiter for the Nintendo DS. Set in the modern-day Shibuya shopping district of Tokyo, The World Ends with You features a distinctive art style and urban fantasy elements inspired by Shibuya and its youth culture. Development was inspired by elements of Jupiter''s previous handheld game, Kingdom Hearts: Chain of Memories. It was released in Japan in July 2007, and in PAL regions and North America in April 2008. Later, an enhanced port by h.a.n.d. for mobile devices was released in 2012 under the title The World Ends with You: Solo Remix, while another enhanced port for the Nintendo Switch was released worldwide in 2018 under the title The World Ends with You: Final Remix.', 'https://media.retroachievements.org/Images/077187.png', 'https://media.retroachievements.org/Images/033387.png', 'https://media.retroachievements.org/Images/036167.png', 'https://media.retroachievements.org/Images/036168.png', 4.4),
  (64, 16622, 'Inazuma Eleven', 'Nintendo DS', 18, 656, 656, 656, 71, 0, 'Role-Playing Game', 'Level-5', 'Nintendo', '2011-01-21', 'Inazuma Eleven  is a football themed media franchise created by Level-5. The franchise began with the release of Inazuma Eleven in 2008, with the game series selling over 8 million copies worldwide by 2016. In addition to video games, the franchise also includes a manga series and several anime television series and films. Most media in the franchise are not released in the Americas; exceptions include a Nintendo 3DS port of the original game, three of the anime series, and the latest game Inazuma Eleven: Victory Road.', 'https://media.retroachievements.org/Images/107150.png', 'https://media.retroachievements.org/Images/077268.png', 'https://media.retroachievements.org/Images/107108.png', 'https://media.retroachievements.org/Images/108741.png', 4.3),
  (65, 4663, 'Final Fantasy III', 'Nintendo DS', 18, 654, 654, 654, 162, 0, NULL, 'Matrix Software, Square Enix', 'Square Enix', '2007-05-04', 'Final Fantasy III is a 1990 role-playing video game developed and published by Square for the Family Computer. The third installment in the Final Fantasy series, it follows four orphans from the village of Ur who are chosen by the world''s crystals to defeat a great evil and return balance to the world. The gameplay returns to the traditional combat system of the original game, and adds a job system allowing players to switch between character classes with unique abilities.', 'https://media.retroachievements.org/Images/089330.png', 'https://media.retroachievements.org/Images/034315.png', 'https://media.retroachievements.org/Images/034314.png', 'https://media.retroachievements.org/Images/034313.png', 4.3),
  (66, 11644, 'Shin Megami Tensei: Strange Journey', 'Nintendo DS', 18, 648, 648, 648, 243, 0, 'Turn-Based RPG', 'Atlus', 'Atlus', '2009-10-08', 'Shin Megami Tensei: Strange Journey is a role-playing video game developed by Atlus and Lancarse for the Nintendo DS. It is the sixth mainline game in the Shin Megami Tensei series, which forms the core of the Megami Tensei franchise. It was released in Japan in 2009, and in North America in 2010. The story follows a special task force sent by the United Nations to investigate the Schwarzwelt, a spatial distortion that appears in Antarctica and threatens to engulf the world. Players take control of an unnamed protagonist, navigating the environments of the Schwarzwelt in first-person. Combat involves the player and recruited demons fighting against various enemies, with the protagonist having the option of talking with and recruiting enemies. Depending on choices taken in the story, multiple endings are unlocked.', 'https://media.retroachievements.org/Images/067523.png', 'https://media.retroachievements.org/Images/033533.png', 'https://media.retroachievements.org/Images/084195.png', 'https://media.retroachievements.org/Images/084196.png', 4.3),
  (67, 6102, 'Kirby: Canvas Curse', 'Nintendo DS', 18, 624, 624, 624, 56, 0, '2D Platforming', 'HAL Laboratory', 'Nintendo', '2005-03-24', 'Kirby: Canvas Curse, known in Europe as Kirby: Power Paintbrush, is a 2005 platform game developed by HAL Laboratory and published by Nintendo for the Nintendo DS.', 'https://media.retroachievements.org/Images/120700.png', 'https://media.retroachievements.org/Images/114161.png', 'https://media.retroachievements.org/Images/035567.png', 'https://media.retroachievements.org/Images/035569.png', 4.3),
  (68, 15542, 'Metroid Prime Pinball', 'Nintendo DS', 18, 619, 619, 619, 88, 0, 'Pinball', 'Fuse Games | Silverball Studios', 'Nintendo', '2005-10-24', 'Metroid Prime Pinball is a pinball video game developed by Fuse Games and published by Nintendo for the Nintendo DS. It is a spin-off of the Metroid series, using the graphical style and various story elements from Metroid Prime. It was released in North America and Australia in 2005, in Japan in 2006, and in Europe in 2007. Metroid Prime Pinball uses the basic mechanics of pinball, along with typical pinball items. New mechanics are introduced, such as wall jumping and the ability to fire weapons. The Nintendo DS''s touchscreen can be nudged with a finger to alter the pinball''s trajectory while in motion.', 'https://media.retroachievements.org/Images/061655.png', 'https://media.retroachievements.org/Images/030244.png', 'https://media.retroachievements.org/Images/030242.png', 'https://media.retroachievements.org/Images/030243.png', 4.3),
  (69, 2642, 'Kingdom Hearts: 358/2 Days', 'Nintendo DS', 18, 611, 611, 611, 41, 0, 'Action RPG', 'h.a.n.d.', 'Square Enix', '2009-05-30', 'Kingdom Hearts 358/2 Days is an action role-playing video game developed by h.a.n.d. and Square Enix in collaboration with Disney Interactive Studios for the Nintendo DS. It is the fifth installment in the Kingdom Hearts series, and takes place near the end of the first game in parallel to Kingdom Hearts: Chain of Memories, leading directly into the events of Kingdom Hearts II. The game was released worldwide in 2009. The story is told from the perspective of Roxas, and follows his daily life within Organization XIII and his relationship with fellow Organization member Axel; it also introduces a fourteenth member, Xion, who befriends them.', 'https://media.retroachievements.org/Images/112158.png', 'https://media.retroachievements.org/Images/028678.png', 'https://media.retroachievements.org/Images/028680.png', 'https://media.retroachievements.org/Images/028679.png', 4.3),
  (70, 3103, 'Phoenix Wright: Ace Attorney - Trials and Tribulations', 'Nintendo DS', 18, 607, 607, 607, 75, 0, 'Visual Novel', 'Capcom', 'Capcom', '2007-10-23', 'Phoenix Wright: Ace Attorney – Trials and Tribulations is a visual novel adventure video game developed and published by Capcom. It was originally released for the Game Boy Advance in 2004 in Japan, and has since been released for several platforms, including a Nintendo DS version that was released in 2007 in Japan and North America and in 2008 in Europe. It is the third game in the Ace Attorney series, following Phoenix Wright: Ace Attorney (2001) and Justice for All (2002).', 'https://media.retroachievements.org/Images/060428.png', 'https://media.retroachievements.org/Images/030583.png', 'https://media.retroachievements.org/Images/090004.png', 'https://media.retroachievements.org/Images/090005.png', 4.3),
  (71, 16364, 'Game & Watch Collection 2', 'Nintendo DS', 18, 605, 605, 605, 12, 0, 'Compilation', 'Nintendo', 'Nintendo', '2008-12-15', '  This is a list of Game & Watch games released by Nintendo. Several were collected and remade as part for the Game & Watch Gallery series for Game Boy, Game Boy Color, and Game Boy Advance. They were re-released in the Nintendo Mini Classics series in the late 1990s. Digital recreations in DSiWare were released for Nintendo DSi in 2009 and for Nintendo 3DS in 2011.', 'https://media.retroachievements.org/Images/112697.png', 'https://media.retroachievements.org/Images/035124.png', 'https://media.retroachievements.org/Images/035130.png', 'https://media.retroachievements.org/Images/035131.png', 4.3),
  (72, 14813, 'Mario & Sonic at the Olympic Winter Games', 'Nintendo DS', 18, 591, 591, 591, 239, 0, NULL, NULL, NULL, '2009-10-13', 'Mario & Sonic at the Olympic Winter Games is a 2009 crossover sports video game developed and published by Sega for the Wii and Nintendo DS. Like its predecessor, it was published by Nintendo for Japan and Korea and by Sega elsewhere. Officially licensed by the International Olympic Committee (IOC) through exclusive license International Sports Multimedia, it is the first official video game of the 2010 Winter Olympic Games.', 'https://media.retroachievements.org/Images/069064.png', 'https://media.retroachievements.org/Images/028973.png', 'https://media.retroachievements.org/Images/028917.png', 'https://media.retroachievements.org/Images/029995.png', 4.3),
  (73, 16236, 'The Sims 2', 'Nintendo DS', 18, 576, 576, 576, 57, 0, 'Life Simulation', 'Amaze Entertainment, Maxis', 'Electronic Arts', '2005-10-24', 'The Sims 2 is a 2004 social simulation video game developed by Maxis and published by Electronic Arts. It is the second major title in The Sims series, and is the sequel to The Sims. The game was released for Microsoft Windows on September 14, 2004, and a port for MacOS by Aspyr was released on June 17, 2005. Eight expansion packs and nine "stuff packs" were subsequently released between 2005 and 2008. In addition, versions of The Sims 2 were released on various video game consoles, including the PlayStation 2, Xbox, Nintendo DS, and GameCube, and mobile platforms, including the Nokia Ovi Store. Unlike the original, the handheld and console versions are more storyline-based. The three handheld versions of the game are completely different among themselves, unlike the home console versions of the game, which are virtually identical to each other. A sequel, The Sims 3, was released in June 2009.', 'https://media.retroachievements.org/Images/047391.png', 'https://media.retroachievements.org/Images/047395.png', 'https://media.retroachievements.org/Images/051298.png', 'https://media.retroachievements.org/Images/051299.png', 4.3),
  (74, 9546, 'Diddy Kong Racing DS', 'Nintendo DS', 18, 559, 559, 559, 166, 0, 'Kart Racing, Collect-a-thon', 'Rare', 'Nintendo', '2007-02-05', 'Diddy Kong Racing is a 1997 kart racing game developed and published by Rare for the Nintendo 64. The game revolves around Diddy Kong and his friends'' attempt to defeat the intergalactic antagonist, a wizard pig named Wizpig, through winning a series of races. The player takes control of any of the featured characters throughout the game. Diddy Kong Racing features five worlds with four racetracks each, and the ability to drive a car, hovercraft, or pilot an aeroplane.', 'https://media.retroachievements.org/Images/047184.png', 'https://media.retroachievements.org/Images/041308.png', 'https://media.retroachievements.org/Images/041309.png', 'https://media.retroachievements.org/Images/041310.png', 4.3),
  (75, 18664, 'Big Brain Academy', 'Nintendo DS', 18, 555, 555, 555, 96, 0, 'Educational', NULL, 'Nintendo', '2005-06-30', 'Big Brain Academy is a series of puzzle video games developed and published by Nintendo. Similar to the Brain Age series, each game features a number of activities designed to test, measure, and improve the player''s mental skills. The first two games were released under the Touch! Generations brand, which has since been discontinued.', 'https://media.retroachievements.org/Images/121642.png', 'https://media.retroachievements.org/Images/053982.png', 'https://media.retroachievements.org/Images/053980.png', 'https://media.retroachievements.org/Images/053981.png', 4.3),
  (76, 15981, 'LEGO Rock Band', 'Nintendo DS', 18, 554, 554, 554, 92, 0, 'Rhythm', 'Backbone Entertainment', 'Warner Bros. Interactive Entertainment', '2009-11-03', 'Lego Rock Band is a 2009 rhythm game developed by TT Fusion in partnership with Harmonix and published by Warner Bros. Interactive Entertainment. It is the fifth console installment in the Rock Band series, while it incorporates elements from Lego video games. The game was released on 3 November 2009 for Xbox 360, PlayStation 3, and Wii home consoles in the United States. A Nintendo DS version was also developed by Backbone Entertainment.', 'https://media.retroachievements.org/Images/041002.png', 'https://media.retroachievements.org/Images/041477.png', 'https://media.retroachievements.org/Images/039326.png', 'https://media.retroachievements.org/Images/039325.png', 4.3),
  (77, 17633, 'Peggle: Dual Shot', 'Nintendo DS', 18, 539, 539, 539, 49, 0, 'Action, Pachinko', 'Q Entertainment, PopCap Games', 'PopCap Games', '2009-03-03', 'Peggle: Dual Shot is the fourth game in the Peggle series, developed by Q Entertainment and published by PopCap Games for Nintendo DS in March 2009. It is a compilation game including content from both Peggle (2007) and Peggle Nights (2008). This version of the game awards the player a star each time a purple bonus peg is hit, activating a new bonus minigame upon collecting five stars. The minigame requires that the player continually bounce a ball with pinball-like bumpers to collect diamonds and extra balls.', 'https://media.retroachievements.org/Images/108430.png', 'https://media.retroachievements.org/Images/043657.png', 'https://media.retroachievements.org/Images/043658.png', 'https://media.retroachievements.org/Images/043659.png', 4.3),
  (78, 9954, 'Grand Theft Auto: Chinatown Wars', 'Nintendo DS', 18, 507, 507, 507, 150, 0, 'Action-Adventure, Sandbox', 'Rockstar Leeds', 'Rockstar Games', '2009-03-17', 'Grand Theft Auto: Chinatown Wars is a 2009 action-adventure game developed by Rockstar Leeds in conjunction with Rockstar North and published by Rockstar Games. The game was released for the Nintendo DS in March 2009, PlayStation Portable in October 2009, iOS in January 2010, and Android and Fire OS devices in December 2014. It is the thirteenth game in the Grand Theft Auto series and a follow-up to Grand Theft Auto IV, and is the first entry to be released for handheld consoles since 2006''s Vice City Stories. Set within modern-day Liberty City, the single-player story follows young Triad member Huang Lee and his efforts to recover a sword gifted by his late father after it is stolen from him, while inadvertently becoming caught in a power struggle amongst Liberty City''s Triads.', 'https://media.retroachievements.org/Images/089902.png', 'https://media.retroachievements.org/Images/031313.png', 'https://media.retroachievements.org/Images/040552.png', 'https://media.retroachievements.org/Images/040553.png', 4.3),
  (79, 8572, 'Fire Emblem: Shadow Dragon', 'Nintendo DS', 18, 489, 489, 489, 93, 0, 'Tactical RPG', 'Intelligent Systems', 'Nintendo', '2009-02-16', 'Fire Emblem: Shadow Dragon is a tactical role-playing video game developed by Intelligent Systems and published by Nintendo for the Nintendo DS. It is the eleventh installment in the Fire Emblem series and a remake of the Famicom title Fire Emblem: Shadow Dragon and the Blade of Light, the first entry in the series. It released in 2008 in Japan and Europe, and 2009 in North America and Australia.', 'https://media.retroachievements.org/Images/089609.png', 'https://media.retroachievements.org/Images/036221.png', 'https://media.retroachievements.org/Images/036219.png', 'https://media.retroachievements.org/Images/080682.png', 4.3),
  (80, 9424, 'Radiant Historia', 'Nintendo DS', 18, 482, 482, 482, 120, 0, 'Turn-Based RPG', 'Atlus, Headlock', 'Atlus', '2010-11-03', 'Radiant Historia is a role-playing video game developed by Atlus and Headlock and published by Atlus for the Nintendo DS. It was released in Japan in 2010 and in North America in 2011. An expanded remake for the Nintendo 3DS, titled Radiant Historia: Perfect Chronology, was released in Japan in 2017 and in North America and Europe the following year, with the European version being published by Deep Silver.', 'https://media.retroachievements.org/Images/034477.png', 'https://media.retroachievements.org/Images/031540.png', 'https://media.retroachievements.org/Images/031542.png', 'https://media.retroachievements.org/Images/031545.png', 4.3),
  (81, 12704, 'Rune Factory: A Fantasy Harvest Moon', 'Nintendo DS', 18, 479, 479, 479, 140, 0, 'Life Simulation', 'Neverland', 'Marvelous Interactive, Natsume', '2006-08-24', 'Rune Factory: A Fantasy Harvest Moon is a 2006 role-playing simulation game developed by Neverland and published by Marvelous Interactive Inc., Natsume Inc., and Rising Star Games for the Nintendo DS handheld video game console.', 'https://media.retroachievements.org/Images/107474.png', 'https://media.retroachievements.org/Images/016533.png', 'https://media.retroachievements.org/Images/016542.png', 'https://media.retroachievements.org/Images/016532.png', 4.3),
  (82, 14812, 'Mario & Sonic at the Olympic Games', 'Nintendo DS', 18, 472, 472, 472, 100, 0, 'Sports', 'Sega', 'Sega, Nintendo', '2008-01-17', 'Mario & Sonic at the Olympic Games is a 2007 crossover sports video game developed and published by Sega for the Wii, with Nintendo publishing it in Japan. It was released for the Nintendo DS the following year. It is the first installment in the Mario & Sonic series, a crossover between Nintendo''s Mario and Sega''s Sonic the Hedgehog series, and the first licensed crossover game to feature characters from both franchises. The first official video game of the 2008 Summer Olympic Games, it is licensed by the International Olympic Committee (IOC) through exclusive licensee International Sports Multimedia (ISM).', 'https://media.retroachievements.org/Images/108382.png', 'https://media.retroachievements.org/Images/028972.png', 'https://media.retroachievements.org/Images/029991.png', 'https://media.retroachievements.org/Images/029990.png', 4.3),
  (83, 12917, 'Contra 4', 'Nintendo DS', 18, 470, 470, 470, 45, 0, 'Run & Gun', 'WayForward', 'Konami', '2007-11-13', 'Contra 4 is a run and gun video game developed by WayForward Technologies and published by Konami for the Nintendo DS. It is the eleventh overall installment of the Contra series, and was released in North America on November 13, 2007. A mobile port was released six days later on November 19, 2007. A rerelease, called Contra 4: Redux, was released for Android in 2011.', 'https://media.retroachievements.org/Images/093937.png', 'https://media.retroachievements.org/Images/028756.png', 'https://media.retroachievements.org/Images/030850.png', 'https://media.retroachievements.org/Images/030853.png', 4.3),
  (84, 17140, 'Rock Band 3', 'Nintendo DS', 18, 455, 455, 455, 122, 0, 'Rhythm', 'Backbone Entertainment', 'MTV Games', '2010-10-26', 'Rock Band 3 is a 2010 rhythm game developed by Harmonix. The game was initially published and distributed by MTV Games and Electronic Arts, respectively, on October 26, 2010. Mad Catz took over both roles and re-released the title on November 23, 2011. It is the third main installment and the seventh console release in the Rock Band series. As with the previous titles, Rock Band 3 allows players to simulate the playing of rock music and many other subgenres using special instrument controllers mimicking lead and bass guitar, keyboard, drums, and vocals. Rock Band 3 expands upon previous games by including three-part vocal harmonies — previously used in The Beatles: Rock Band and Green Day: Rock Band — plus support for MIDI-compatible keyboards, electronic drumkits, and even use of a real guitar in "Pro" mode.', 'https://media.retroachievements.org/Images/041006.png', 'https://media.retroachievements.org/Images/040967.png', 'https://media.retroachievements.org/Images/040992.png', 'https://media.retroachievements.org/Images/040968.png', 4.3),
  (85, 9404, 'Solatorobo: Red the Hunter', 'Nintendo DS', 18, 450, 450, 450, 133, 0, 'Action RPG', 'CyberConnect2 | CyberConnect', 'XSEED Games', '2011-09-27', 'Solatorobo: Red the Hunter, originally released in Japan as Soratorobo -Sore Kara Kōda e-, is an action role-playing video game developed by CyberConnect2 and published by Namco Bandai Games for the Nintendo DS. Originally released in Japan in October 2010, an English version was released in Europe in July 2011 and Australia the following November, with a North American release in September by Xseed Games. It is the spiritual sequel to Tail Concerto, and, like its predecessor, features artwork and character designs by manga artist Nobuteru Yūki and music by Chikayo Fukuda. The game includes animated cutscenes produced by Madhouse, as well as vocal themes performed by Tomoyo Mitani.', 'https://media.retroachievements.org/Images/088320.png', 'https://media.retroachievements.org/Images/028653.png', 'https://media.retroachievements.org/Images/073286.png', 'https://media.retroachievements.org/Images/073287.png', 4.3),
  (86, 16621, 'Adventure Time: Hey Ice King! Why''d You Steal Our Garbage?!!', 'Nintendo DS', 18, 446, 446, 446, 57, 0, '2D Platforming, Metroidvania', 'WayForward', 'Bandai Namco, D3 Publisher', '2012-11-20', 'Adventure Time: Hey Ice King! Why''d You Steal Our Garbage?!! is a 2012 action-adventure game developed by WayForward Technologies and published by D3 Publisher for the Nintendo DS and Nintendo 3DS. It is based on the animated television series Adventure Time.', 'https://media.retroachievements.org/Images/112623.png', 'https://media.retroachievements.org/Images/063133.png', 'https://media.retroachievements.org/Images/063130.png', 'https://media.retroachievements.org/Images/063131.png', 4.3),
  (87, 15351, 'LEGO Star Wars: The Complete Saga', 'Nintendo DS', 18, 444, 444, 444, 50, 0, 'Action-Adventure', 'TT Fusion', 'LucasArts | Lucasfilm', '2007-11-06', 'Lego Star Wars: The Complete Saga is a 2007 Lego-themed action-adventure video game based on the Lego Star Wars line of construction toys. The game was developed by Traveller''s Tales and announced by LucasArts on 25 May 2007 at Celebration IV. It was released on 6 November 2007 in North America. The Complete Saga is a combination of its predecessors in the Lego Star Wars series,  Lego Star Wars: The Video Game (2005) and its sequel, Lego Star Wars II: The Original Trilogy (2006). The Complete Saga follows the events of the first six episodes of the Skywalker Saga.', 'https://media.retroachievements.org/Images/102668.png', 'https://media.retroachievements.org/Images/072067.png', 'https://media.retroachievements.org/Images/041475.png', 'https://media.retroachievements.org/Images/041240.png', 4.3),
  (88, 4667, 'Dementium: The Ward', 'Nintendo DS', 18, 441, 441, 441, 24, 0, 'Survival Horror', 'Renegade Kid', 'Gamecock Media Group, SouthPeak Games', '2007-10-31', 'Dementium: The Ward is a survival horror first-person shooter video game developed by Renegade Kid for the Nintendo DS. The game was released in North America on October 31, 2007, published by Gamecock Media Group. After Renegade Kid gained back the rights to the title, an enhanced version of the game was announced under the title of Dementium Remastered for the Nintendo 3DS. The remastered version was released in North America on December 3, 2015, and Europe on February 11, 2016, with the company''s successor Atooi developing remasters for additional platforms.', 'https://media.retroachievements.org/Images/053418.png', 'https://media.retroachievements.org/Images/042328.png', 'https://media.retroachievements.org/Images/048655.png', 'https://media.retroachievements.org/Images/049117.png', 4.2),
  (89, 16713, 'MapleStory DS', 'Nintendo DS', 18, 441, 441, 441, 95, 0, '2D Platforming, Action RPG', 'Nexon', 'Nexon, Nintendo', '2010-04-15', 'MapleStory DS is a role-playing video game for the Nintendo DS. It is an adaptation of the original MMORPG game for Windows titled MapleStory. The game was released on April 15, 2010 in Korea, and was developed by Nexon and published by Nexon and Nintendo of Korea. Unlike the PC version, MapleStory DS is a solely single-player game.', 'https://media.retroachievements.org/Images/073715.png', 'https://media.retroachievements.org/Images/073444.png', 'https://media.retroachievements.org/Images/073445.png', 'https://media.retroachievements.org/Images/060631.png', 4.2),
  (90, 15375, '~Hack~ Another Super Mario 3D', 'Nintendo DS', 18, 437, 437, 437, 65, 0, '3D Platforming, Collect-a-thon', 'Hacker - Newer Team', 'Hack - Super Mario 64 DS', '2014-06-26', 'Super Mario 64 DS is an enhanced remake of the 1996 platform game Super Mario 64, developed and published by Nintendo for the Nintendo DS handheld game console. As with the original title, the game''s plot centers on rescuing Princess Peach from Bowser. Players start the game with Yoshi as the playable character and gain access to Mario, Luigi, and Wario as the story progresses.', 'https://media.retroachievements.org/Images/029572.png', 'https://media.retroachievements.org/Images/029569.png', 'https://media.retroachievements.org/Images/029539.png', 'https://media.retroachievements.org/Images/029540.png', 4.2),
  (91, 14815, 'Mario vs. Donkey Kong: Mini-Land Mayhem!', 'Nintendo DS', 18, 437, 437, 437, 49, 0, 'Puzzle', NULL, 'Nintendo', '2010-11-14', 'Mario vs. Donkey Kong: Mini-Land Mayhem! is a 2010 puzzle-platform game developed by Nintendo Software Technology for the Nintendo DS. The game was released in North America on November 14, 2010 and is the fourth entry in the Mario vs. Donkey Kong series.', 'https://media.retroachievements.org/Images/045305.png', 'https://media.retroachievements.org/Images/028991.png', 'https://media.retroachievements.org/Images/028919.png', 'https://media.retroachievements.org/Images/045239.png', 4.2),
  (92, 18333, 'TrackMania DS', 'Nintendo DS', 18, 433, 433, 433, 230, 0, 'Arcade Racing', 'Firebrand Games', 'Focus Home Interactive', '2008-11-14', 'TrackMania DS is a racing video game developed by Firebrand Games. It was published by Focus Home Interactive in Europe and released for the Nintendo DS on November 14, 2008, and in the United States by Atlus USA on March 17, 2009. The game received generally favorable reviews from critics.', 'https://media.retroachievements.org/Images/109540.png', 'https://media.retroachievements.org/Images/051651.png', 'https://media.retroachievements.org/Images/051642.png', 'https://media.retroachievements.org/Images/051643.png', 4.2),
  (93, 16152, 'Digimon World Dusk', 'Nintendo DS', 18, 418, 418, 418, 75, 0, NULL, 'BEC', 'Bandai Namco', '2007-03-29', 'Digimon World Dawn and Digimon World Dusk, originally released as Digimon Story Sunburst & Moonlight  in Japan, are two role-playing video games for the Nintendo DS handheld game console released in Japan on March 29, 2007 and North America on September 18, 2007. Together, they serve as the second installment of the Digimon Story series, part of the larger Digimon franchise. Despite their western title, the games are not part of the Digimon World series.', 'https://media.retroachievements.org/Images/102521.png', 'https://media.retroachievements.org/Images/073175.png', 'https://media.retroachievements.org/Images/077203.png', 'https://media.retroachievements.org/Images/083520.png', 4.2),
  (94, 1378, 'Metroid Prime: Hunters', 'Nintendo DS', 18, 409, 409, 409, 50, 0, 'First-Person Shooter', NULL, 'Nintendo', '2006-03-20', 'Metroid Prime Hunters is a 2006 action-adventure game developed by Nintendo Software Technology and published by Nintendo for the Nintendo DS. It was released in North America in March 2006, with other territories later. The story takes place in between the events of Metroid Prime and Metroid Prime 2: Echoes. Players assume the role of series protagonist Samus Aran, who investigates a mysterious message that originated from the Alimbic Cluster and comes into contact with a legion of bounty hunters.', 'https://media.retroachievements.org/Images/107022.png', 'https://media.retroachievements.org/Images/030590.png', 'https://media.retroachievements.org/Images/036792.png', 'https://media.retroachievements.org/Images/036790.png', 4.2),
  (95, 15350, 'LEGO Star Wars II: The Original Trilogy', 'Nintendo DS', 18, 408, 408, 408, 28, 0, NULL, NULL, NULL, '2006-09-12', 'Lego Star Wars II: The Original Trilogy is a 2006 Lego-themed action-adventure game developed by Traveller''s Tales and published by LucasArts and TT Games Publishing, and is the sequel to Lego Star Wars: The Video Game (2005). Part of the Lego Star Wars series, it is based on George Lucas''s movie franchise of the same name and The Lego Group''s Lego Star Wars construction toy line. It follows the events of the first three original Star Wars films: A New Hope (1977), The Empire Strikes Back (1980), and Return of the Jedi (1983). The game allows players to assume the roles of over 50 Lego versions of characters from the film series; customized characters can also be created. Camera movement was improved from its predecessor, and the concept of "vehicle levels" was explored more thoroughly. The game was revealed at American International Toy Fair. Promotions for the game were set up at chain stores across the United States.', 'https://media.retroachievements.org/Images/069680.png', 'https://media.retroachievements.org/Images/068681.png', 'https://media.retroachievements.org/Images/068683.png', 'https://media.retroachievements.org/Images/068682.png', 4.2),
  (96, 9105, 'Advance Wars: Days of Ruin', 'Nintendo DS', 18, 404, 404, 404, 119, 0, 'Turn-Based Strategy', 'Intelligent Systems', 'Nintendo', '2008-01-21', 'Advance Wars: Days of Ruin, released as Advance Wars: Dark Conflict in Europe and Australia, is a turn-based strategy video game developed by Intelligent Systems and published by Nintendo for the Nintendo DS handheld game console. It is the fourth installment in the Advance Wars series after Advance Wars: Dual Strike and was released in 2008 for North America on January 21; in Europe on January 25; and in Australia on February 21. A Japanese release was planned under the title of Famicom Wars DS: Lost Light, but was canceled after a series of delays. It finally became available in Japan through Club Nintendo in October 2013 as a downloadable platinum status reward for the DSiWare service on the Nintendo 3DS family of systems.', 'https://media.retroachievements.org/Images/043961.png', 'https://media.retroachievements.org/Images/043223.png', 'https://media.retroachievements.org/Images/043953.png', 'https://media.retroachievements.org/Images/043952.png', 4.2),
  (97, 14816, 'WarioWare: D.I.Y.', 'Nintendo DS', 18, 392, 392, 392, 90, 0, 'Minigames', NULL, 'Nintendo', '2009-04-29', 'WarioWare D.I.Y.,, also known as WarioWare: Do It Yourself in Europe and Australia, is a minigame compilation and game creation system developed by Nintendo SPD and Intelligent Systems and published by Nintendo for the Nintendo DS. It is the seventh title in the WarioWare series and the last to be developed for the Nintendo DS family of systems. Formally revealed at Nintendo''s conference in October 2008, the game was released in Japan on April 29, 2009. It was released in 2010 in North America, Europe, and Australia respectively and was accompanied by a separate WiiWare title, WarioWare: D.I.Y. Showcase.', 'https://media.retroachievements.org/Images/059844.png', 'https://media.retroachievements.org/Images/028984.png', 'https://media.retroachievements.org/Images/028920.png', 'https://media.retroachievements.org/Images/042254.png', 4.2),
  (98, 6091, 'Bejeweled 3', 'Nintendo DS', 18, 391, 391, 391, 76, 0, 'Tile Matching', 'PopCap Games, Griptonite Games', 'PopCap Games', '2011-10-19', 'Bejeweled 3 is a tile-matching puzzle video game developed and published by PopCap Games. It is the fifth game in the Bejeweled series following Bejeweled Blitz (2010) and succeeds Bejeweled 2 (2004) as the latest mainline title in the Bejeweled series. It was released for Windows and Mac OS X on December 7, 2010, as part of the 10 Years of Bejeweled celebration, which celebrated the 10th anniversary of the original Bejeweled (2000); it was ported to several other consoles afterward.', 'https://media.retroachievements.org/Images/089483.png', 'https://media.retroachievements.org/Images/038508.png', 'https://media.retroachievements.org/Images/038507.png', 'https://media.retroachievements.org/Images/089944.png', 4.2),
  (99, 9496, 'Flower, Sun, and Rain: Murder and Mystery in Paradise', 'Nintendo DS', 18, 385, 385, 385, 51, 0, 'Adventure', 'h.a.n.d., Grasshopper Manufacture', 'Rising Star Games', '2008-03-06', 'Flower, Sun, and Rain is an adventure video game developed by Grasshopper Manufacture and published by Victor Interactive Software for the PlayStation 2 in 2001. It was initially only released in Japan. A port for the Nintendo DS (DS) was developed by h.a.n.d. under supervision by Grasshopper Manufacture. It was published by Marvelous Entertainment in Japan (2008) and North America (2009) and Rising Star Games in Europe (2008).', 'https://media.retroachievements.org/Images/051467.png', 'https://media.retroachievements.org/Images/029061.png', 'https://media.retroachievements.org/Images/029062.png', 'https://media.retroachievements.org/Images/029063.png', 4.2),
  (100, 6907, 'Trauma Center: Under the Knife', 'Nintendo DS', 18, 372, 372, 372, 51, 0, 'Simulation', 'Atlus', 'Atlus', '2005-10-04', 'Trauma Center: Under the Knife is a simulation video game developed by Atlus for the Nintendo DS. The debut entry in the Trauma Center series, it was published in Japan and North America by Atlus in 2005, and by Nintendo in Europe in 2006. Set in a near future where medical science can cure previously incurable diseases, the world''s population panics when a new manmade disease called GUILT begins to spread. Doctor Derek Stiles, a surgeon possessing a mystical "Healing Touch", works with the medical research organization Caduceus to find a cure to GUILT. The gameplay combines surgery-based simulation relying on the DS''s touchscreen controls with a story told as a visual novel.', 'https://media.retroachievements.org/Images/107314.png', 'https://media.retroachievements.org/Images/028419.png', 'https://media.retroachievements.org/Images/028421.png', 'https://media.retroachievements.org/Images/028420.png', 4.2),
  (101, 17216, 'N+', 'Nintendo DS', 18, 370, 370, 370, 255, 0, '2D Platforming', 'Metanet Software, SilverBirch Studios', 'Atari', '2008-08-26', 'N+ is the console and handheld version of the Adobe Flash game N, which was developed by Metanet Software. N+ for Xbox Live Arcade was developed by Slick Entertainment and published by Metanet Software. Unique versions of the game were also ported separately to the PlayStation Portable and Nintendo DS by developers SilverBirch Studios and Atari. Metanet Software licensed their N IP for this deal, provided single player level design for both versions, and consulted on the project.', 'https://media.retroachievements.org/Images/084364.png', 'https://media.retroachievements.org/Images/081771.png', 'https://media.retroachievements.org/Images/081796.png', 'https://media.retroachievements.org/Images/081797.png', 4.2),
  (102, 14835, '~Homebrew~ EunHye DS', 'Nintendo DS', 18, 368, 368, 368, 6, 0, 'Jigsaw Puzzle', 'Ryu Seung-Ryul', 'Ryu Seung-Ryul', '2007-10-01', 'Sayaka Ohara  is a Japanese voice actress affiliated with Haikyō. Her major roles include Alicia Florence in Aria, Milly Ashford in Code Geass, Erza Scarlet in Fairy Tail, Irisviel in the Fate/Zero and Fate/kaleid liner Prisma Illya series, Layla Hamilton in Kaleido Star, Michiru Kaiou/Sailor Neptune in Sailor Moon Crystal, Beatrice in Umineko no Naku Koro ni, Yūko Ichihara in xxxHolic and Tsubasa Reservoir Chronicle, and the initial voice of Gammisers in episode 27-34 of Kamen Rider Ghost. She has also voiced in a variety of video games and live-action overseas dubs, and hosts a number of radio shows, many of which are related to her voice projects. In 2013, she received a Best Supporting Actress award at the 7th Seiyu Awards.', 'https://media.retroachievements.org/Images/028844.png', 'https://media.retroachievements.org/Images/028794.png', 'https://media.retroachievements.org/Images/041813.png', 'https://media.retroachievements.org/Images/041814.png', 4.2),
  (103, 9831, 'Professor Layton and the Unwound Future', 'Nintendo DS', 18, 366, 366, 366, 28, 0, NULL, NULL, NULL, '2008-11-27', 'Professor Layton and the Unwound Future, known in Europe and Australia as Professor Layton and the Lost Future, is the third game in the first trilogy of the Professor Layton puzzle game series by Level-5 and in conclusion the final game of the first trilogy. It was first released in Japan in November 2008 and was later released in North America in September 2010 and in Europe and Australia in October 2010. In the game, Layton meets an older version of his apprentice, Luke, who brings him to a terrible future he wishes him to help fix. The game received critical acclaim by critics, praise for its story, puzzles, characters, soundtrack, and has since been cited as one of the best games of the series. An enhanced mobile port of Unwound Future, subtitled "HD for Mobile", was released on July 13, 2020.', 'https://media.retroachievements.org/Images/068338.png', 'https://media.retroachievements.org/Images/033473.png', 'https://media.retroachievements.org/Images/033336.png', 'https://media.retroachievements.org/Images/033472.png', 4.2),
  (104, 17744, 'Yu-Gi-Oh! GX Spirit Caller', 'Nintendo DS', 18, 366, 366, 366, 149, 0, 'Collectible Card Game', 'Konami', 'Konami', '2006-11-30', '   The following is a list of video games developed and published by Konami, based on Kazuki Takahashi''s Yu-Gi-Oh! manga and anime franchise, along with its spin-off series. With some exceptions, the majority of the games follow the card battle gameplay of the real-life Yu-Gi-Oh! Trading Card Game. There are 59 in total.', 'https://media.retroachievements.org/Images/084156.png', 'https://media.retroachievements.org/Images/065084.png', 'https://media.retroachievements.org/Images/067113.png', 'https://media.retroachievements.org/Images/067207.png', 4.2),
  (105, 11788, 'Golden Sun: Dark Dawn', 'Nintendo DS', 18, 364, 364, 364, 151, 0, 'Turn-Based RPG', 'Camelot Software Planning', 'Nintendo', '2010-11-29', 'Golden Sun: Dark Dawn is a 2010 role-playing video game developed by Camelot Software Planning and published by Nintendo for the Nintendo DS. The third entry in the Golden Sun series, it is set thirty years after the events of the first two games and follows the descendants of the earlier games'' heroes. Players control characters as they travel through the fictional world of Weyard. The game utilizes gameplay elements pioneered by its predecessors, primarily the use of magic called "Psynergy" to defeat enemies and discover new locations, help local populations, and find elemental djinn which can augment the player''s powers.', 'https://media.retroachievements.org/Images/102698.png', 'https://media.retroachievements.org/Images/053945.png', 'https://media.retroachievements.org/Images/031546.png', 'https://media.retroachievements.org/Images/039348.png', 4.2),
  (106, 16297, 'Ace Attorney Investigations 2: Prosecutor''s Gambit', 'Nintendo DS', 18, 361, 361, 361, 78, 0, 'Visual Novel', 'Capcom', 'Capcom', '2011-02-03', 'Ace Attorney Investigations 2: Prosecutor''s Gambit is an adventure video game developed by Capcom. It was released in Japan for the Nintendo DS in 2011 and for Android and iOS in 2017. It is the sixth entry in the Ace Attorney series, and the sequel to Ace Attorney Investigations: Miles Edgeworth (2009).', 'https://media.retroachievements.org/Images/076922.png', 'https://media.retroachievements.org/Images/040457.png', 'https://media.retroachievements.org/Images/043170.png', 'https://media.retroachievements.org/Images/043173.png', 4.2),
  (107, 9734, 'Cartoon Network Racing', 'Nintendo DS', 18, 357, 357, 357, 44, 0, 'Kart Racing', 'Firebrand Games', 'The Game Factory', '2006-12-04', 'Cartoon Network Racing is a racing video game developed by Eutechnyx for PlayStation 2 and Firebrand Games for Nintendo DS, published by Danish video game developer The Game Factory, and released on December 4, 2006, in North America, and on February 9, 2007, in Europe. The gameplay is similar to Nintendo''s 2003 game Mario Kart: Double Dash, but the characters and racetracks are all from six of Cartoon Network''s original animated television series: Courage the Cowardly Dog, Cow and Chicken, Dexter''s Laboratory, I Am Weasel, Johnny Bravo, and The Powerpuff Girls.', 'https://media.retroachievements.org/Images/110039.png', 'https://media.retroachievements.org/Images/054253.png', 'https://media.retroachievements.org/Images/053631.png', 'https://media.retroachievements.org/Images/053632.png', 4.2),
  (108, 1226, 'Osu! Tatakae! Ouendan', 'Nintendo DS', 18, 350, 350, 350, 70, 0, 'Rhythm', 'iNiS', 'Nintendo', '2005-07-28', 'Osu! Tatakae! Ouendan, or Ouendan, is a rhythm video game developed by iNiS and published by Nintendo for the Nintendo DS handheld game console in 2005, for release only in Japan. Ouendan stars a cheer squad rhythmically cheering for various troubled people, presented in-game in the style of a manga comic. In each stage, players use the DS touchscreen to tap specifically marked spots that appear in rhythm to various Japanese pop songs, scoring points for accurate timing and avoiding a poor performance which can cause the stage to end prematurely. Though never released in Western markets, it was a popular import to these regions, leading to the development of the Westernized Elite Beat Agents, as well as a Japan-only sequel Moero! Nekketsu Rhythm Damashii Osu! Tatakae! Ouendan 2.', 'https://media.retroachievements.org/Images/028617.png', 'https://media.retroachievements.org/Images/028618.png', 'https://media.retroachievements.org/Images/028616.png', 'https://media.retroachievements.org/Images/028619.png', 4.2),
  (109, 15428, 'Jump Ultimate Stars', 'Nintendo DS', 18, 345, 345, 345, 54, 0, NULL, NULL, NULL, '2006-11-23', 'Jump Ultimate Stars is a 2006 crossover fighting video game developed by Ganbarion and published by Nintendo for the Nintendo DS. It is the sequel to Jump Super Stars and adds numerous more features. The game boasts 305 characters from 41 different Shōnen manga series. Jump Ultimate Stars was released in Japan on November 23, 2006.', 'https://media.retroachievements.org/Images/041849.png', 'https://media.retroachievements.org/Images/041846.png', 'https://media.retroachievements.org/Images/041847.png', 'https://media.retroachievements.org/Images/041848.png', 4.2),
  (110, 9914, 'Etrian Odyssey', 'Nintendo DS', 18, 344, 344, 344, 70, 0, 'Dungeon Crawl, Turn-Based RPG', 'Atlus', 'Atlus, Nintendo', '2007-01-18', 'Etrian Odyssey is a dungeon crawler role-playing video game series. It is primarily developed and published by Atlus and currently owned by Sega. By 2016, the series had sold a combined total of 1.5 million copies worldwide.', 'https://media.retroachievements.org/Images/086308.png', 'https://media.retroachievements.org/Images/030447.png', 'https://media.retroachievements.org/Images/030448.png', 'https://media.retroachievements.org/Images/030449.png', 4.2),
  (111, 9260, 'Club Penguin: Elite Penguin Force', 'Nintendo DS', 18, 341, 341, 341, 29, 0, 'Point-and-Click Adventure', '1st Playable Productions', 'Disney Interactive Studios', '2008-11-25', 'Club Penguin: Elite Penguin Force is a point-and-click adventure game for the Nintendo DS based on Disney''s massively multiplayer online game Club Penguin. It was released in North America on November 25, 2008, in Europe on March 13, 2009, and in Australia on April 16, 2009. In September 2009, a Collector''s Edition was released which included upgrades to the game and extras. On June 10, 2010, Thrustmaster, a video game accessories manufacturer, created a "Full Spy Pack" inspired by the games. On March 8, 2012, a German regionalization of the Collector''s Edition was released in Germany.', 'https://media.retroachievements.org/Images/037186.png', 'https://media.retroachievements.org/Images/037187.png', 'https://media.retroachievements.org/Images/040983.png', 'https://media.retroachievements.org/Images/040984.png', 4.2),
  (112, 3110, 'Retro Game Challenge 2', 'Nintendo DS', 18, 336, 336, 336, 189, 0, 'Minigames', 'Indies Zero', 'Bandai Namco', '2009-02-26', 'Retro Game Challenge 2 is a 2009 minigame compilation video game developed by indieszero and published by Namco Bandai Games for the Nintendo DS. It is the sequel to Retro Game Challenge. Unlike its predecessor, it never saw an official Western release due to low sales. It received a fan translation to English that was released in 2014. A remaster of the first two games, named GameCenter CX: Arino no Chousenjou 1+2 REPLAY, was announced for Nintendo Switch and set to be released on February 22, 2024. At the time of the announcement, no news of English localization was announced.', 'https://media.retroachievements.org/Images/080514.png', 'https://media.retroachievements.org/Images/028981.png', 'https://media.retroachievements.org/Images/041325.png', 'https://media.retroachievements.org/Images/041326.png', 4.2),
  (113, 9443, 'Digimon World Dawn', 'Nintendo DS', 18, 332, 332, 332, 74, 0, NULL, 'BEC', 'Bandai Namco', '2007-03-29', 'Digimon World Dawn and Digimon World Dusk, originally released as Digimon Story Sunburst & Moonlight  in Japan, are two role-playing video games for the Nintendo DS handheld game console released in Japan on March 29, 2007 and North America on September 18, 2007. Together, they serve as the second installment of the Digimon Story series, part of the larger Digimon franchise. Despite their western title, the games are not part of the Digimon World series.', 'https://media.retroachievements.org/Images/102520.png', 'https://media.retroachievements.org/Images/073176.png', 'https://media.retroachievements.org/Images/072700.png', 'https://media.retroachievements.org/Images/072702.png', 4.2),
  (114, 2141, 'Brain Age: Train Your Brain in Minutes a Day!', 'Nintendo DS', 18, 331, 331, 331, 66, 0, 'Educational, Sudoku', 'Nintendo', 'Nintendo', '2005-05-19', 'Brain Age: Train Your Brain in Minutes a Day!, known as Dr Kawashima''s Brain Training: How Old Is Your Brain? in the PAL regions, is a 2005 edutainment puzzle video game by Nintendo for the Nintendo DS. It is inspired by the work of Japanese neuroscientist Ryuta Kawashima, who appears as a caricature of himself guiding the player.', 'https://media.retroachievements.org/Images/115159.png', 'https://media.retroachievements.org/Images/096950.png', 'https://media.retroachievements.org/Images/046002.png', 'https://media.retroachievements.org/Images/118206.png', 4.2),
  (115, 9994, 'Final Fantasy IV', 'Nintendo DS', 18, 325, 325, 325, 110, 0, NULL, 'Matrix Software', 'Square Enix', '2007-12-20', 'Final Fantasy IV, titled Final Fantasy II in its initial North American release, is a 1991 role-playing video game developed and published by Square for the Super Nintendo Entertainment System. It is the fourth main installment of the Final Fantasy series. The game''s story follows Cecil Harvey, a dark knight, as he tries to prevent the sorcerer Golbez from seizing powerful crystals and destroying the world. He is joined on this quest by a frequently changing group of allies. Final Fantasy IV introduced innovations that became staples of the Final Fantasy series and role-playing games in general. Its "Active Time Battle" system was used in five subsequent Final Fantasy games, and unlike prior games in the series, Final Fantasy IV gave each character their own unchangeable character class — although at a few points in the story, members of the cast change or evolve their vocation to suit the narrative.', 'https://media.retroachievements.org/Images/070791.png', 'https://media.retroachievements.org/Images/042247.png', 'https://media.retroachievements.org/Images/042249.png', 'https://media.retroachievements.org/Images/042248.png', 4.2),
  (116, 7601, 'Professor Layton and the Last Specter', 'Nintendo DS', 18, 325, 325, 325, 40, 0, 'Mystery, Logic Puzzle', 'Level-5', 'Nintendo', '2009-11-26', 'Professor Layton and the Last Specter, known in Europe as Professor Layton and the Spectre''s Call, is a puzzle adventure video game produced by Level-5 for the Nintendo DS handheld game console. Last Specter is the fourth game in the Professor Layton series, and is a prequel that takes place three years before the first trilogy, detailing how Professor Layton met his apprentice, Luke Triton, as well as introducing Layton''s assistant Emmy Altava.', 'https://media.retroachievements.org/Images/040979.png', 'https://media.retroachievements.org/Images/069270.png', 'https://media.retroachievements.org/Images/040901.png', 'https://media.retroachievements.org/Images/040902.png', 4.2),
  (117, 9119, 'The Legendary Starfy', 'Nintendo DS', 18, 317, 317, 317, 58, 0, '2D Platforming', 'TOSE', 'Nintendo', '2008-07-10', 'The Legendary Starfy is a video game series developed by Tose and published by Nintendo. The series began in 2002 with Densetsu no Starfy for the Game Boy Advance, and four sequels were released. For its first seven years, Starfy games were not released outside Japan. The fifth and latest game in the series was released as The Legendary Starfy in North America on June 8, 2009. In July 2024, the first three titles were officially released via the Nintendo Classics service.', 'https://media.retroachievements.org/Images/088303.png', 'https://media.retroachievements.org/Images/046595.png', 'https://media.retroachievements.org/Images/046596.png', 'https://media.retroachievements.org/Images/046597.png', 4.2),
  (118, 15740, 'Donkey Kong: Jungle Climber', 'Nintendo DS', 18, 316, 316, 316, 71, 0, '2D Platforming', 'Paon', 'Nintendo', '2007-09-10', 'Donkey Kong: Jungle Climber, also stylised as DK: Jungle Climber, is a 2007 puzzle-platform game developed by Paon and published by Nintendo for the Nintendo DS handheld video game console. It was released in Japan on August 9, 2007, and in western territories later that year. It was re-released for the Wii U''s Virtual Console in Japan and North America in July 2015 and in Europe and Australia in August.', 'https://media.retroachievements.org/Images/048774.png', 'https://media.retroachievements.org/Images/053836.png', 'https://media.retroachievements.org/Images/051668.png', 'https://media.retroachievements.org/Images/051669.png', 4.2),
  (119, 20052, 'Kikansha Thomas: DS de Hajimeru Chiiku Gakushuu', 'Nintendo DS', 18, 311, 311, 311, 21, 0, 'Minigames', 'Rocket Company', 'Rocket Company', '2008-07-24', 'This is a list of physical video games for the Nintendo DS, DS Lite, and DSi handheld game consoles. It does not include games released on DSiWare or the iQue DS. The last game for the Nintendo DS, Big Hero 6: Battle in the Bay, was released on October 28, 2014.', 'https://media.retroachievements.org/Images/109095.png', 'https://media.retroachievements.org/Images/059863.png', 'https://media.retroachievements.org/Images/109382.png', 'https://media.retroachievements.org/Images/109109.png', 4.2),
  (120, 14906, 'Adventures of Pinocchio', 'Nintendo DS', 18, 310, 310, 310, 18, 0, 'Jigsaw Puzzle, Sliding Puzzle', 'Phoenix Games', 'Phoenix Games', '2008-01-01', 'The Adventures of Pinocchio, commonly shortened to Pinocchio, is an 1883 children''s fantasy novel by Italian author Carlo Collodi. It is about the mischievous adventures of an animated marionette named Pinocchio. He faces many perils and temptations, meets characters who teach him about life, and learns goodness before he achieves his heart''s desire to become a real boy.', 'https://media.retroachievements.org/Images/036186.png', 'https://media.retroachievements.org/Images/029454.png', 'https://media.retroachievements.org/Images/029457.png', 'https://media.retroachievements.org/Images/029458.png', 4.2),
  (121, 17554, '~Hack~ Castlevania: Dawn of Dissonance - A Juste Story Mode Hack', 'Nintendo DS', 18, 309, 309, 309, 72, 0, 'Metroidvania', 'Serbagz', 'Hack - Castlevania: Dawn of Sorrow', '2021-04-04', NULL, 'https://media.retroachievements.org/Images/045746.png', 'https://media.retroachievements.org/Images/045747.png', 'https://media.retroachievements.org/Images/046526.png', 'https://media.retroachievements.org/Images/043139.png', 4.2),
  (122, 1284, 'Yu-Gi-Oh! 5D''s Stardust Accelerator: World Championship 2009', 'Nintendo DS', 18, 309, 309, 309, 163, 0, 'Collectible Card Game', 'Konami', 'Konami', '2009-03-26', '   The following is a list of video games developed and published by Konami, based on Kazuki Takahashi''s Yu-Gi-Oh! manga and anime franchise, along with its spin-off series. With some exceptions, the majority of the games follow the card battle gameplay of the real-life Yu-Gi-Oh! Trading Card Game. There are 59 in total.', 'https://media.retroachievements.org/Images/069152.png', 'https://media.retroachievements.org/Images/069151.png', 'https://media.retroachievements.org/Images/065869.png', 'https://media.retroachievements.org/Images/086001.png', 4.2),
  (123, 22037, 'Peppa Pig: The Game', 'Nintendo DS', 18, 308, 308, 308, 11, 0, NULL, 'Asylum Entertainment', 'Pinnacle Software', '2009-08-07', 'This is a list of physical video games for the Nintendo DS, DS Lite, and DSi handheld game consoles. It does not include games released on DSiWare or the iQue DS. The last game for the Nintendo DS, Big Hero 6: Battle in the Bay, was released on October 28, 2014.', 'https://media.retroachievements.org/Images/120855.png', 'https://media.retroachievements.org/Images/066199.png', 'https://media.retroachievements.org/Images/066111.png', 'https://media.retroachievements.org/Images/066110.png', 4.2),
  (124, 9751, 'Super Robot Taisen OG Saga: Endless Frontier', 'Nintendo DS', 18, 298, 298, 298, 62, 0, 'Role-Playing Game', 'Monolith Soft', 'Atlus', '2009-04-29', 'Super Robot Taisen OG Saga: Endless Frontier  is a video game developed by Monolith Soft and published by Namco Bandai Games. It is a spin-off of the Super Robot Taisen: Original Generation series. Released on May 29, 2008 on the Nintendo DS, the title departs from the traditional tactical role-playing game elements for which the Super Robot Wars franchise is known and opts for turn-based role-playing gameplay instead.', 'https://media.retroachievements.org/Images/031614.png', 'https://media.retroachievements.org/Images/031618.png', 'https://media.retroachievements.org/Images/031616.png', 'https://media.retroachievements.org/Images/031617.png', 4.2),
  (125, 9931, 'Ragnarok DS', 'Nintendo DS', 18, 294, 294, 294, 43, 0, 'Action RPG', 'GungHo Online Entertainment', 'GungHo Online Entertainment, XSEED Games', '2008-12-18', 'Ragnarok DS, known in Japan as Ragnarok Online DS , is a Nintendo DS video game based on the MMORPG Ragnarok Online and was released in Japan on December 18, 2008. Xseed Games published the game in North America on February 16, 2010. The game was also released in South Korea in June 2009.', 'https://media.retroachievements.org/Images/040295.png', 'https://media.retroachievements.org/Images/040294.png', 'https://media.retroachievements.org/Images/041112.png', 'https://media.retroachievements.org/Images/041113.png', 4.2),
  (126, 9817, 'Mystery Dungeon: Shiren the Wanderer', 'Nintendo DS', 18, 292, 292, 292, 65, 0, 'Roguelike', 'Chunsoft', 'Sega', '2006-12-14', 'Mystery Dungeon: Shiren the Wanderer, originally released in Japan as Fushigi no Dungeon 2: Fūrai no Shiren, is a roguelike video game developed and published by Chunsoft. It is the second entry in the Mystery Dungeon series, following 1993''s Torneko no Daibōken. It was originally released for the Super Famicom in 1995 in Japan. Sega published a Nintendo DS remake in 2006 in Japan and in 2008 internationally. The remake was later ported to iOS and Android and published by Spike Chunsoft in 2019.', 'https://media.retroachievements.org/Images/071733.png', 'https://media.retroachievements.org/Images/071540.png', 'https://media.retroachievements.org/Images/028660.png', 'https://media.retroachievements.org/Images/028661.png', 4.2),
  (127, 22036, 'Peppa Pig: Fun and Games', 'Nintendo DS', 18, 290, 290, 290, 13, 0, 'Minigames', 'Asylum Entertainment', 'P2 Games', '2010-03-26', 'This is a list of physical video games for the Nintendo DS, DS Lite, and DSi handheld game consoles. It does not include games released on DSiWare or the iQue DS. The last game for the Nintendo DS, Big Hero 6: Battle in the Bay, was released on October 28, 2014.', 'https://media.retroachievements.org/Images/120856.png', 'https://media.retroachievements.org/Images/066116.png', 'https://media.retroachievements.org/Images/066117.png', 'https://media.retroachievements.org/Images/066118.png', 4.1),
  (128, 8376, 'Mega Man Zero Collection', 'Nintendo DS', 18, 289, 289, 289, 279, 0, 'Action, 2D Platforming, Compilation', 'Inti Creates', 'Capcom', '2010-06-08', 'Mega Man Zero Collection is a compilation of all four Mega Man Zero video games, which were originally released for the Game Boy Advance between 2002 and 2005. It was developed by Inti Creates and published by Capcom, and was made available worldwide in June 2010 for the Nintendo DS. The collection contains new features such as a beginner-friendly "Easy Scenario" that grants power-up items and abilities from the beginning of each game, as well as unlockable character art and the ability to display artwork on the Nintendo DS''s bottom screen as the game is played.', 'https://media.retroachievements.org/Images/053731.png', 'https://media.retroachievements.org/Images/050613.png', 'https://media.retroachievements.org/Images/052160.png', 'https://media.retroachievements.org/Images/052161.png', 4.1),
  (129, 17434, 'Nintendogs: Labrador & Friends', 'Nintendo DS', 18, 288, 288, 288, 54, 0, 'Pet Simulation', NULL, 'Nintendo', '2005-10-07', 'Nintendogs is a 2005 pet simulation video game developed and published by Nintendo for the Nintendo DS handheld video game console. It was released in Japan, and was later released in: North America, Australia, New Zealand, Europe and other regions. It was originally released in three different versions: Dachshund & Friends, Lab & Friends and Chihuahua & Friends. It has been re-released twice, first as a bundled release with a special edition Nintendo DS with a new version called Nintendogs: Best Friends and later with Nintendogs: Dalmatian & Friends.', 'https://media.retroachievements.org/Images/041959.png', 'https://media.retroachievements.org/Images/041829.png', 'https://media.retroachievements.org/Images/041831.png', 'https://media.retroachievements.org/Images/041845.png', 4.1),
  (130, 15915, 'Lost in Blue', 'Nintendo DS', 18, 284, 284, 284, 65, 0, 'Survival', 'Konami', 'Konami', '2005-08-25', 'Lost in Blue is a series of survival video games developed and published by Konami. They revolve around the main characters being castaways on a desert island and being forced to scavenge for survival. The series saw two Game Boy Color releases starting in 1999, only one of which was localized, before going on a five-year hiatus. It then saw several Nintendo DS installments, adopting a new localized name, Lost in Blue. Following the release of a Wii installment of the series, it went on hiatus until the announcement of a new entry on Nintendo Switch 2.', 'https://media.retroachievements.org/Images/120662.png', 'https://media.retroachievements.org/Images/058920.png', 'https://media.retroachievements.org/Images/058915.png', 'https://media.retroachievements.org/Images/058916.png', 4.1),
  (131, 16296, 'Pokémon Ranger: Shadows of Almia', 'Nintendo DS', 18, 284, 284, 284, 125, 0, 'Action RPG', 'APE | Creatures', 'Nintendo, The Pokémon Company', '2008-03-20', 'Pokémon Ranger: Shadows of Almia  is an action role-playing video game developed by Creatures Inc. and published by The Pokémon Company and Nintendo for the Nintendo DS video game console.', 'https://media.retroachievements.org/Images/044836.png', 'https://media.retroachievements.org/Images/045311.png', 'https://media.retroachievements.org/Images/045314.png', 'https://media.retroachievements.org/Images/045312.png', 4.1),
  (132, 17513, 'Taiko no Tatsujin DS: Touch de Dokodon!', 'Nintendo DS', 18, 283, 283, 283, 182, 0, 'Rhythm', 'Namco', 'Bandai Namco', '2007-07-26', 'Taiko no Tatsujin  is a Japanese video game series developed and published by Namco. In the games, players simulate playing a taiko drum in rhythm with music. The series has released titles for the arcade as well as for console and mobile platforms, including PlayStation 2, Advanced Pico Beena, PlayStation Portable, Nintendo DS, Wii, Nintendo 3DS, Wii U, PlayStation Vita, PlayStation 4, PlayStation 5, Nintendo Switch, Xbox One, Xbox Series X/S, Microsoft Windows, iOS, Android, and Japanese feature phones.', 'https://media.retroachievements.org/Images/056370.png', 'https://media.retroachievements.org/Images/056371.png', 'https://media.retroachievements.org/Images/042923.png', 'https://media.retroachievements.org/Images/042925.png', 4.1),
  (133, 16633, 'Final Fantasy Fables: Chocobo Tales', 'Nintendo DS', 18, 275, 275, 275, 155, 0, 'Minigames, Collectible Card Game', 'h.a.n.d.', 'Square Enix', '2007-04-03', 'Final Fantasy Fables: Chocobo Tales is a Nintendo DS adventure game developed by h.a.n.d. and published by Square Enix. It was first launched in Japan on December 14, 2006 and was released in the North American and PAL regions in the spring of 2007. A spin-off of the Final Fantasy franchise, Chocobo Tales stars a Chocobo and features a setting with common elements and creatures from its parent series.', 'https://media.retroachievements.org/Images/087757.png', 'https://media.retroachievements.org/Images/050460.png', 'https://media.retroachievements.org/Images/087754.png', 'https://media.retroachievements.org/Images/087755.png', 4.1),
  (134, 18541, '~Hack~ Box Adventure', 'Nintendo DS', 18, 273, 273, 273, 11, 0, '3D Platforming', NULL, 'Hack - Super Mario 64 DS', '2021-07-12', 'Rango is a 2011 action-adventure video game developed by Behaviour Interactive and published by Electronic Arts and Paramount Digital Entertainment for the Nintendo DS, PlayStation 3, Wii, & Xbox 360. It is a video game sequel to the 2011 movie of the same name.', 'https://media.retroachievements.org/Images/053419.png', 'https://media.retroachievements.org/Images/086298.png', 'https://media.retroachievements.org/Images/053221.png', 'https://media.retroachievements.org/Images/053220.png', 4.1),
  (135, 15736, 'Yu-Gi-Oh! Nightmare Troubadour', 'Nintendo DS', 18, 269, 269, 269, 48, 0, 'Collectible Card Game', 'Konami', 'Konami', '2005-07-21', 'Yu-Gi-Oh! Nightmare Troubadour is a 2005 video game developed and published by Konami for the Nintendo DS. It is the first game based on the Yu-Gi-Oh! trading card game and franchise released on the system.', 'https://media.retroachievements.org/Images/060125.png', 'https://media.retroachievements.org/Images/032051.png', 'https://media.retroachievements.org/Images/031988.png', 'https://media.retroachievements.org/Images/031987.png', 4.1),
  (136, 9462, 'Meteos', 'Nintendo DS', 18, 266, 266, 266, 80, 0, NULL, 'Q Entertainment', NULL, '2005-03-10', 'Meteos is a 2005 tile-matching video game developed by Q Entertainment and published by Bandai for the Nintendo DS. Nintendo released the game outside Japan. It was produced by Q Entertainment founder Tetsuya Mizuguchi and designed by Masahiro Sakurai. Meteos was inspired by the video game Missile Command (1980), the film The Matrix (1999) and the television series 24 (2001-2010).', 'https://media.retroachievements.org/Images/061688.png', 'https://media.retroachievements.org/Images/041635.png', 'https://media.retroachievements.org/Images/041636.png', 'https://media.retroachievements.org/Images/041637.png', 4.1),
  (137, 23701, '~Hack~ Mega Man Star Force DX', 'Nintendo DS', 18, 251, 251, 251, 79, 0, 'Action RPG', 'The Rockman EXE Zone', 'Hack - Mega Man Star Force', '2021-05-29', 'Mega Man Battle Network 6: Cybeast Gregar and Mega Man Battle Network 6: Cybeast Falzar are 2005 tactical role-playing games developed and published by Capcom for the Game Boy Advance (GBA) handheld game console. They are the sixth and final game in the Mega Man Battle Network series, and involves Lan Hikari''s family and MegaMan.EXE moving to Cyber City, only to need to once again stop the returning WWW and their plans to re-awaken the Cybeasts.', 'https://media.retroachievements.org/Images/125158.png', 'https://media.retroachievements.org/Images/070202.png', 'https://media.retroachievements.org/Images/077871.png', 'https://media.retroachievements.org/Images/077872.png', 4.1),
  (138, 7370, 'Viva Piñata: Pocket Paradise', 'Nintendo DS', 18, 249, 249, 249, 87, 0, 'Life Simulation', 'Rare', 'THQ', '2008-09-05', 'Viva Piñata: Pocket Paradise is a life simulation game developed by Rare, for the Nintendo DS video game console and based on Viva Piñata. Released days after Viva Piñata: Trouble in Paradise for the Xbox 360 in the fall of 2008, Pocket Paradise was developed by Rare''s handheld team, as opposed to Viva Piñata: Party Animals and the PC version of the original game, which were developed by separate third-party developers. It is currently the latest game Rare developed for a Nintendo system, as well as currently the final game in the series and is also the only game of the series as a whole to be handheld.', 'https://media.retroachievements.org/Images/046859.png', 'https://media.retroachievements.org/Images/046861.png', 'https://media.retroachievements.org/Images/046853.png', 'https://media.retroachievements.org/Images/046854.png', 4.1),
  (139, 14907, 'Peter Pan''s Playground', 'Nintendo DS', 18, 245, 245, 245, 8, 0, 'Jigsaw Puzzle, Sliding Puzzle', 'Phoenix Games', 'Phoenix Games', '2008-01-01', 'Peter Pan''s Playground was an amusement park in the coastal resort of Worthing, West Sussex, England for young children under 11 years of age', 'https://media.retroachievements.org/Images/029367.png', 'https://media.retroachievements.org/Images/029368.png', 'https://media.retroachievements.org/Images/029369.png', 'https://media.retroachievements.org/Images/029366.png', 4.1),
  (140, 16710, 'Ketsui Death Label: Kizuna Jigoku Tachi', 'Nintendo DS', 18, 242, 242, 242, 54, 0, 'Shoot ''em Up, Bullet Hell', 'CAVE Interactive', 'Arika', '2008-10-23', 'Ketsui: Kizuna Jigoku Tachi  is a 2003 vertical shoot ''em up arcade game by Cave, released in Japanese arcades. A Nintendo DS boss rush version was released in October 2008 in Japan. It included a Superplay DVD featuring a world record scoring run by a top ranked player. The arcade game was ported to the Xbox 360 and released in 2010. A special version of Dodonpachi Daifukkatsu Black Label was released on the Xbox 360 in 2011, which is a crossover with Ketsui, featuring the ship, re-arranged music and scoring system from Ketsui on top of the Dodonpachi Daifukkatsu Black Label scoring system.', 'https://media.retroachievements.org/Images/038001.png', 'https://media.retroachievements.org/Images/038000.png', 'https://media.retroachievements.org/Images/037996.png', 'https://media.retroachievements.org/Images/037997.png', 4.1),
  (141, 6032, 'Hotel Dusk: Room 215', 'Nintendo DS', 18, 236, 236, 236, 20, 0, 'Point-and-Click Adventure', 'Cing', 'Nintendo', '2007-01-22', 'Hotel Dusk: Room 215 (known in Japan as Wish Room: Angel''s Memory  is a point-and-click adventure game for the Nintendo DS. Originally called Wish Room, the game debuted at E3 on May 9, 2006. It was initially released in North America on January 22, 2007, and later internationally. The game supports the Nintendo DS Rumble Pak accessory.', 'https://media.retroachievements.org/Images/117254.png', 'https://media.retroachievements.org/Images/098885.png', 'https://media.retroachievements.org/Images/036351.png', 'https://media.retroachievements.org/Images/036352.png', 4.1),
  (142, 16383, 'Super Scribblenauts', 'Nintendo DS', 18, 235, 235, 235, 26, 0, 'Puzzle, Action', '5th Cell', 'Warner Bros. Interactive Entertainment', '2010-10-12', 'Super Scribblenauts is an emergent action puzzle game developed by 5th Cell and published by Warner Bros. Interactive Entertainment for the Nintendo DS handheld game console. The game was released on October 12, 2010. It is the sequel to the Nintendo DS game Scribblenauts.', 'https://media.retroachievements.org/Images/107694.png', 'https://media.retroachievements.org/Images/043377.png', 'https://media.retroachievements.org/Images/049251.png', 'https://media.retroachievements.org/Images/049250.png', 4.1),
  (143, 33170, '~Prototype~ Crash Landed', 'Nintendo DS', 18, 230, 230, 230, 6, 0, NULL, NULL, NULL, '2009-07-31', '"Crash Landed" is the second single from pop music project Sweetbox on the album The Next Generation, featuring Jamie Pineda as frontwoman. Georgie Dennis, Tom Barnes, Gavin Jones, Ben Kohn and Peter Kelleher co-wrote the song with Jamie.', 'https://media.retroachievements.org/Images/112694.png', 'https://media.retroachievements.org/Images/118901.png', 'https://media.retroachievements.org/Images/121244.png', 'https://media.retroachievements.org/Images/116565.png', 4.1),
  (144, 22844, 'Arkanoid DS', 'Nintendo DS', 18, 229, 229, 229, 133, 0, 'Brick Breakers', 'Taito', 'Taito, Square Enix', '2008-07-17', 'Arkanoid DS is a breakout video game developed and published by Taito for the Nintendo DS, with Square Enix handling publication outside Japan. It was released on December 6, 2007.', 'https://media.retroachievements.org/Images/069512.png', 'https://media.retroachievements.org/Images/069510.png', 'https://media.retroachievements.org/Images/069508.png', 'https://media.retroachievements.org/Images/069509.png', 4.1),
  (145, 5656, 'Batman: The Brave and The Bold - The Videogame', 'Nintendo DS', 18, 229, 229, 229, 69, 0, 'Beat ''em Up', 'WayForward', 'Warner Bros. Interactive Entertainment', '2010-09-07', 'Batman: The Brave and the Bold – The Videogame is a video game based on the comic book character Batman and the television cartoon series Batman: The Brave and the Bold. It was developed by WayForward Technologies and distributed by Warner Bros. Interactive Entertainment. It was released on September 7, 2010, for the Wii and Nintendo DS, and is the only non-Lego Batman video game released for those platforms.', 'https://media.retroachievements.org/Images/111019.png', 'https://media.retroachievements.org/Images/111013.png', 'https://media.retroachievements.org/Images/111010.png', 'https://media.retroachievements.org/Images/111011.png', 4.1),
  (146, 22038, 'Peppa Pig: Theme Park Fun', 'Nintendo DS', 18, 229, 229, 229, 26, 0, NULL, 'Strawdog Studios', 'P2 Games', '2011-03-25', 'Peppa Pig is a British preschool animated children''s television series created by Neville Astley and Mark Baker. Produced by Hasbro Entertainment and Karrot Animation and formerly Astley Baker Davies, the series follows Peppa, an anthropomorphic piglet, and her family and friends portrayed as other animals. The show first aired on 31 May 2004. The ninth series began broadcasting in summer 2025. Peppa Pig has been broadcast in over 180 countries.', 'https://media.retroachievements.org/Images/120857.png', 'https://media.retroachievements.org/Images/066198.png', 'https://media.retroachievements.org/Images/066122.png', 'https://media.retroachievements.org/Images/066121.png', 4.1),
  (147, 1409, 'Spider-Man: Shattered Dimensions', 'Nintendo DS', 18, 228, 228, 228, 45, 0, 'Beat ''em Up, Metroidvania', 'Griptonite Games', 'Activision', '2010-09-07', 'Spider-Man: Shattered Dimensions is a 2010 action-adventure video game based on the Marvel Comics superhero Spider-Man, developed by Beenox and published by Activision. Players control four different versions of Spider-Man, each originating from a different universe in the Marvel Comics multiverse. Previous Spider-Man voice actors Neil Patrick Harris, Christopher Daniel Barnes, Dan Gilvezan, and Josh Keaton each voice one of the four Spider-Men. The Nintendo DS version of the game was developed by Griptonite Games and features only three Spider-Man variants.', 'https://media.retroachievements.org/Images/051178.png', 'https://media.retroachievements.org/Images/028870.png', 'https://media.retroachievements.org/Images/028883.png', 'https://media.retroachievements.org/Images/051156.png', 4.1),
  (148, 7062, 'Giana Sisters DS', 'Nintendo DS', 18, 226, 226, 226, 56, 0, '2D Platforming', 'Bitfield', 'DTP Entertainment', '2009-04-03', 'Giana Sisters DS, also known on other handheld platforms as Giana Sisters, is a platform game developed by Spellbound Entertainment in cooperation with Bitfield GmbH for the Nintendo DS, iPad, iPhone, and Android. It was published by DTP Entertainment in Europe and Destineer in North America. It is a spiritual sequel to the 1987 Commodore 64 release The Great Giana Sisters. A version for Microsoft Windows, re-titled Giana Sisters 2D, was also released.', 'https://media.retroachievements.org/Images/039629.png', 'https://media.retroachievements.org/Images/039729.png', 'https://media.retroachievements.org/Images/039631.png', 'https://media.retroachievements.org/Images/039630.png', 4.1),
  (149, 19773, 'Hidden Objects: Mystery Stories', 'Nintendo DS', 18, 224, 224, 224, 43, 0, 'Hidden Object, Mystery', 'cerasus.media', 'GSP Software, Knowledge Adventure', '2009-05-29', 'This is a list of physical video games for the Nintendo DS, DS Lite, and DSi handheld game consoles. It does not include games released on DSiWare or the iQue DS. The last game for the Nintendo DS, Big Hero 6: Battle in the Bay, was released on October 28, 2014.', 'https://media.retroachievements.org/Images/069120.png', 'https://media.retroachievements.org/Images/058334.png', 'https://media.retroachievements.org/Images/069118.png', 'https://media.retroachievements.org/Images/069119.png', 4.1),
  (150, 15653, 'Phantasy Star 0', 'Nintendo DS', 18, 224, 224, 224, 131, 0, 'Action RPG', 'Sonic Team', 'Sega', '2008-12-25', 'Phantasy Star 0, also known in Australia and Europe as Phantasy Star: ZERO and sometimes in North America as Phantasy Star Ø, is a Nintendo DS game in the Phantasy Star series, developed by Sonic Team and published by Sega. The game was released in Japan on December 25, 2008; in North America on November 10, 2009; and in Europe on February 12, 2010. The game expands on the gameplay mechanics of Phantasy Star Online, partly by borrowing some elements from fellow online Phantasy Star title Phantasy Star Universe, such as a fully realized story mode for offline play.', 'https://media.retroachievements.org/Images/030820.png', 'https://media.retroachievements.org/Images/030706.png', 'https://media.retroachievements.org/Images/030707.png', 'https://media.retroachievements.org/Images/030708.png', 4.1),
  (151, 25351, '~Homebrew~ The Search Master: Metal Gear Solid Edition', 'Nintendo DS', 18, 223, 223, 223, 6, 0, 'Puzzle', 'Multiple:Option', 'Multiple:Option', '2008-12-24', '2008 saw many new installments in established video game franchises, such as Grand Theft Auto IV, Fallout 3, Metal Gear Solid 4: Guns of the Patriots, Gears of War 2, Super Smash Bros. Brawl, Persona 4, Fable II, Call of Duty: World at War, Mario Kart Wii, Madden NFL 09, NBA Live 09, NBA 2K9, and WWE Smackdown vs. Raw 2009. New intellectual properties included Army of Two, Dead Space, Left 4 Dead, LittleBigPlanet, Mirror''s Edge, iRacing, Race Driver: Grid, and Spore, De Blob, Meat Boy.', 'https://media.retroachievements.org/Images/080987.png', 'https://media.retroachievements.org/Images/109202.png', 'https://media.retroachievements.org/Images/080323.png', 'https://media.retroachievements.org/Images/080324.png', 4.1),
  (152, 12712, 'Cory in the House', 'Nintendo DS', 18, 220, 220, 220, 32, 0, 'Action-Adventure', 'Handheld Games', 'Disney Interactive Studios', '2008-04-15', 'Cory in the House is an American television sitcom which aired on the Disney Channel from January 12, 2007, to September 12, 2008, and was a spin-off from the Disney Channel series That''s So Raven. The show focuses on Cory Baxter, who moves from San Francisco, California, to Washington, D.C. with his father, Victor Baxter, who gets a new job as the White House executive chef. The series was the first Disney Channel spin-off series, as well as the final Disney Channel series overall to be both shot and broadcast in standard definition for the entire run of the show. Reruns of the series have aired on Disney Channel and Disney XD, it also aired on the Family Channel in Canada. Raven-Symoné guest-starred in one episode, reprising her role as Raven Baxter.', 'https://media.retroachievements.org/Images/083680.png', 'https://media.retroachievements.org/Images/016550.png', 'https://media.retroachievements.org/Images/052325.png', 'https://media.retroachievements.org/Images/083722.png', 4.1),
  (153, 15614, 'Mario Hoops 3-on-3', 'Nintendo DS', 18, 220, 220, 220, 34, 0, NULL, 'Nintendo, Square Enix', 'Nintendo', '2006-07-27', 'Mario Hoops 3-on-3, known in Europe as Mario Slam Basketball, is a 2006 sports game developed by Square Enix and published by Nintendo for the Nintendo DS. The game is the first in which Mario and Final Fantasy characters appear together as playable characters, and the second Mario game developed by Square Enix, after Super Mario RPG (1996). It is the only dedicated basketball game in the Mario series. The game was released in Japan on July 27, 2006, North America on September 11, 2006, Australia on October 26, 2006, and Europe on February 16, 2007.', 'https://media.retroachievements.org/Images/072680.png', 'https://media.retroachievements.org/Images/114135.png', 'https://media.retroachievements.org/Images/029992.png', 'https://media.retroachievements.org/Images/029993.png', 4.1),
  (154, 16155, 'Digimon Story: Lost Evolution', 'Nintendo DS', 18, 218, 218, 218, 118, 0, NULL, 'BEC', 'Bandai Namco', '2010-07-01', 'Digimon Story: Lost Evolution is a role-playing video game published by Bandai Namco Games for the Nintendo DS. It is the third game in the Digimon Story series, part of the greater Digimon franchise. The title was released exclusively in Japan on July 1, 2010.', 'https://media.retroachievements.org/Images/073852.png', 'https://media.retroachievements.org/Images/049241.png', 'https://media.retroachievements.org/Images/049237.png', 'https://media.retroachievements.org/Images/049238.png', 4.1),
  (155, 3529, 'Nanashi no Geemu', 'Nintendo DS', 18, 218, 218, 218, 24, 0, 'Horror', 'Epics', 'Square Enix', '2008-07-03', 'epics Inc.  is a Japanese video game software developer located in Tokyo, Japan. Originally established as Gen Creative House Co., Ltd. in February 1987, changed company name to G-Artists Inc. in March 1991, then to epics Inc. in June 2006.', 'https://media.retroachievements.org/Images/036071.png', 'https://media.retroachievements.org/Images/069176.png', 'https://media.retroachievements.org/Images/036145.png', 'https://media.retroachievements.org/Images/036146.png', 4.1),
  (156, 20916, '101 in 1 Explosive Megamix', 'Nintendo DS', 18, 216, 216, 216, 107, 0, NULL, 'Nordcurrent', NULL, '2008-11-28', '101-in-1 Explosive Megamix is a video game developed by Nordcurrent and published by Atlus for the Nintendo DS. It was released in Europe on November 28, 2008 and on April 21, 2009 in North America and features 10 hours'' worth of 101 minigames. A version for the WiiWare service was released on September 22, 2011 in Europe and on October 13 in North America.', 'https://media.retroachievements.org/Images/073517.png', 'https://media.retroachievements.org/Images/073016.png', 'https://media.retroachievements.org/Images/073514.png', 'https://media.retroachievements.org/Images/073515.png', 4.1),
  (157, 15357, 'LEGO Harry Potter: Years 1-4', 'Nintendo DS', 18, 215, 215, 215, 30, 0, 'Action-Adventure', 'TT Fusion', 'Warner Bros. Interactive Entertainment', '2010-06-29', 'Lego Harry Potter: Years 1–4 is an action-adventure game developed by Traveller''s Tales and published by Warner Bros. Interactive Entertainment. The game is based on the Lego Harry Potter toy line, and its storyline covers the first four books by J. K. Rowling and its film adaptations in the Harry Potter film series, Philosopher''s Stone (2001), Chamber of Secrets (2002), Prisoner of Azkaban (2004), and Goblet of Fire (2005).', 'https://media.retroachievements.org/Images/118071.png', 'https://media.retroachievements.org/Images/043580.png', 'https://media.retroachievements.org/Images/043581.png', 'https://media.retroachievements.org/Images/043582.png', 4.1),
  (158, 15737, 'Yu-Gi-Oh! World Championship 2007', 'Nintendo DS', 18, 214, 214, 214, 52, 0, 'Collectible Card Game', 'Konami', 'Konami', '2007-03-20', '   The following is a list of video games developed and published by Konami, based on Kazuki Takahashi''s Yu-Gi-Oh! manga and anime franchise, along with its spin-off series. With some exceptions, the majority of the games follow the card battle gameplay of the real-life Yu-Gi-Oh! Trading Card Game. There are 59 in total.', 'https://media.retroachievements.org/Images/058712.png', 'https://media.retroachievements.org/Images/031846.png', 'https://media.retroachievements.org/Images/031847.png', 'https://media.retroachievements.org/Images/031845.png', 4.1),
  (159, 17087, '~Homebrew~ Sushi the Cat DS', 'Nintendo DS', 18, 211, 211, 211, 10, 0, '2D Platforming', 'N3TKaT, Kamui', 'N3TKaT, Kamui', '2005-01-01', 'This is a list of physical video games for the Nintendo DS, DS Lite, and DSi handheld game consoles. It does not include games released on DSiWare or the iQue DS. The last game for the Nintendo DS, Big Hero 6: Battle in the Bay, was released on October 28, 2014.', 'https://media.retroachievements.org/Images/093303.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/093367.png', 'https://media.retroachievements.org/Images/093366.png', 4.1),
  (160, 20362, 'Assassin''s Creed: Altair''s Chronicles', 'Nintendo DS', 18, 209, 209, 209, 28, 0, 'Action-Adventure', 'Gameloft', NULL, '2008-02-05', 'Assassin''s Creed: Altaïr''s Chronicles is a 2008 action-adventure video game developed by Gameloft and published by Ubisoft. It is the first spin-off installment in the Assassin''s Creed franchise, and a prequel to 2007''s Assassin''s Creed. Taking place in the year 1190 AD, one year prior to the events of Assassin''s Creed, the game revolves around Altaïr Ibn-LaʼAhad''s search for an artifact called the Chalice, which brings him into conflict with the Templar Order. Altaïr travels to several cities in the Middle East during the game, including Jerusalem, Acre, and Damascus, as well as Tyre and Aleppo, which are new to the series.', 'https://media.retroachievements.org/Images/122975.png', 'https://media.retroachievements.org/Images/061172.png', 'https://media.retroachievements.org/Images/098693.png', 'https://media.retroachievements.org/Images/098694.png', 4.1),
  (161, 15356, 'LEGO Pirates of the Caribbean: The Video Game', 'Nintendo DS', 18, 203, 203, 203, 33, 0, 'Action-Adventure', 'TT Fusion', 'Disney Interactive Studios', '2011-05-13', 'Lego Pirates of the Caribbean: The Video Game is a 2011 Lego-themed action-adventure video game, based on the Pirates of the Caribbean film series, developed by Traveller''s Tales and published by Disney Interactive Studios for Xbox 360, PlayStation 3, PlayStation Portable, Wii, Nintendo DS, Nintendo 3DS, Microsoft Windows, and Mac OS X. The game was released to coincide with the release of Pirates of the Caribbean: On Stranger Tides, and retells the plot of the first four films in the Pirates Of The Caribbean series.', 'https://media.retroachievements.org/Images/043024.png', 'https://media.retroachievements.org/Images/043020.png', 'https://media.retroachievements.org/Images/043431.png', 'https://media.retroachievements.org/Images/043421.png', 4.1),
  (162, 17232, 'Another Code: Two Memories', 'Nintendo DS', 18, 202, 202, 202, 22, 0, 'Point-and-Click Adventure', 'Cing', 'Nintendo', '2005-02-24', 'Another Code: Two Memories, known as Trace Memory in North America, is a 2005 point-and-click adventure game developed by Cing and published by Nintendo for the Nintendo DS. The game was first released in Japan on February 24, 2005, with releases in Europe, Australia, and North America, following later the same year.', 'https://media.retroachievements.org/Images/057826.png', 'https://media.retroachievements.org/Images/057833.png', 'https://media.retroachievements.org/Images/057834.png', 'https://media.retroachievements.org/Images/057835.png', 4.1),
  (163, 16717, 'Cooking Mama 3: Shop & Chop', 'Nintendo DS', 18, 198, 198, 198, 39, 0, 'Cooking Simulation', 'Cooking Mama Limited', 'Majesco Entertainment', '2009-10-20', 'Cooking Mama 3: Shop & Chop released as Cooking Mama 3 in Japan, Europe and Australia, is the sequel to the Nintendo DS video game Cooking Mama 2: Dinner with Friends and the third installment in the Cooking Mama series. Developed by 505 Games, Majesco Entertainment, and Taito, Shop & Chop features five different game modes, including two new ones, over 80 different recipes, 200 unique mini-games, four-player multiplayer, and the classic gameplay.', 'https://media.retroachievements.org/Images/086682.png', 'https://media.retroachievements.org/Images/053229.png', 'https://media.retroachievements.org/Images/086700.png', 'https://media.retroachievements.org/Images/086701.png', 4.1),
  (164, 15352, 'LEGO Indiana Jones: The Original Adventures', 'Nintendo DS', 18, 197, 197, 197, 30, 0, 'Action-Adventure', 'TT Fusion', 'LucasArts | Lucasfilm', '2008-06-17', 'Lego Indiana Jones: The Original Adventures is a 2008 Lego-themed action-adventure video game developed by Traveller''s Tales and published by LucasArts. Based on the Indiana Jones franchise and the eponymous Lego Indiana Jones toy line, it follows the events of the first three Indiana Jones films: Raiders of the Lost Ark (1981), Temple of Doom (1984), and the Last Crusade (1989). The game includes local co-op mode gameplay, as well as puzzle and platformer aspects, and 84 playable characters with a variety of special abilities. As the players go through the stages, they collect the currency of Lego games known as Studs, avoid traps, assemble Lego constructions, and engage in combat. Climbing, swinging, and throwing objects as weapons were new inclusions not seen in previous Lego video games by Traveller''s Tales.', 'https://media.retroachievements.org/Images/044390.png', 'https://media.retroachievements.org/Images/044227.png', 'https://media.retroachievements.org/Images/044228.png', 'https://media.retroachievements.org/Images/044229.png', 4.1),
  (165, 3140, 'Izuna 2: The Unemployed Ninja Returns', 'Nintendo DS', 18, 195, 195, 195, 40, 0, 'Roguelike', 'Success, Ninja Studio', 'Atlus', '2007-11-29', 'Izuna 2: The Unemployed Ninja Returns, released in Japan as Gōma Reifu Den Izuna Ni , is a dungeon crawler video game developed by Ninja Studio and published in Japan by Success and in North America by Atlus for the Nintendo DS handheld game console. It is the sequel to Izuna: Legend of the Unemployed Ninja and was released in Japan on November 29, 2007 and in North America on July 22, 2008.', 'https://media.retroachievements.org/Images/063014.png', 'https://media.retroachievements.org/Images/062514.png', 'https://media.retroachievements.org/Images/062633.png', 'https://media.retroachievements.org/Images/062632.png', 4.1),
  (166, 1741, 'Space Invaders Extreme 2', 'Nintendo DS', 18, 193, 193, 193, 97, 0, 'Shoot ''em Up', 'Taito', 'Square Enix', '2009-03-26', 'Space Invaders Extreme 2  is the sequel to Space Invaders Extreme. Space Invaders Extreme 2 features new content compared to its predecessor. A cut-down version of the game called Space Invaders Extreme Z has been made available on DSiWare for 500 Points.', 'https://media.retroachievements.org/Images/104937.png', 'https://media.retroachievements.org/Images/029075.png', 'https://media.retroachievements.org/Images/104913.png', 'https://media.retroachievements.org/Images/104915.png', 4.1),
  (167, 1204, 'Chibi-Robo! Park Patrol', 'Nintendo DS', 18, 192, 192, 192, 48, 0, 'Park Ranger Simulator', NULL, 'Nintendo', '2007-07-05', 'Chibi-Robo! Park Patrol is a platform-adventure video game for the Nintendo DS. Developed by Skip Ltd. and published by Nintendo, it is the second installment in the Chibi-Robo series and the sequel to the original Chibi-Robo! for the GameCube. It was released in July 2007 in Japan, followed by a North American release the following October exclusive to Walmart stores.', 'https://media.retroachievements.org/Images/107401.png', 'https://media.retroachievements.org/Images/078931.png', 'https://media.retroachievements.org/Images/042473.png', 'https://media.retroachievements.org/Images/042472.png', 4),
  (168, 9489, 'The Dark Spire', 'Nintendo DS', 18, 192, 192, 192, 74, 0, NULL, 'Success', 'Atlus', '2009-04-14', 'The Dark Spire, known as Genmu no Tō to Tsurugi no Okite in Japan, is a role-playing game developed by Success for the Nintendo DS. It was released on May 22, 2008 in Japan and April 14, 2009 in North America which was published by Atlus.', 'https://media.retroachievements.org/Images/118824.png', 'https://media.retroachievements.org/Images/057394.png', 'https://media.retroachievements.org/Images/028644.png', 'https://media.retroachievements.org/Images/057392.png', 4),
  (169, 16716, 'Cooking Mama 2: Dinner with Friends', 'Nintendo DS', 18, 190, 190, 190, 25, 0, 'Cooking Simulation', 'Cooking Mama Limited', NULL, '2007-11-13', 'Cooking Mama 2: Dinner with Friends is the sequel to the Nintendo DS video game Cooking Mama and its Wii spin off, Cooking Mama: Cook Off. The game has twice as many minigames as the original, new recipes, and a new multiplayer "Cook Off" mode. The game includes voice clips similar to the ones used in Cooking Mama: Cook Off.', 'https://media.retroachievements.org/Images/071848.png', 'https://media.retroachievements.org/Images/051582.png', 'https://media.retroachievements.org/Images/049649.png', 'https://media.retroachievements.org/Images/049648.png', 4),
  (170, 14789, 'Tingle''s Balloon Fight DS', 'Nintendo DS', 18, 190, 190, 190, 26, 0, '2D Platforming', 'Vanpool', 'Nintendo', '2007-04-12', 'Balloon Fight is a 1984 action video game developed by Nintendo and HAL Laboratory and published by Nintendo for the Nintendo Entertainment System. It was originally released for arcades as VS. Balloon Fight, with the console version releasing in Japan in 1985 and internationally in 1986.', 'https://media.retroachievements.org/Images/115558.png', 'https://media.retroachievements.org/Images/028970.png', 'https://media.retroachievements.org/Images/028732.png', 'https://media.retroachievements.org/Images/061563.png', 4),
  (171, 25801, '~Homebrew~ Fishing the Deep', 'Nintendo DS', 18, 187, 187, 187, 6, 0, 'Sports - Fishing', 'SurrealCubeMedia', 'SurrealCubeMedia', '2021-04-27', 'This is a list of physical video games for the Nintendo DS, DS Lite, and DSi handheld game consoles. It does not include games released on DSiWare or the iQue DS. The last game for the Nintendo DS, Big Hero 6: Battle in the Bay, was released on October 28, 2014.', 'https://media.retroachievements.org/Images/082612.png', 'https://media.retroachievements.org/Images/082611.png', 'https://media.retroachievements.org/Images/082609.png', 'https://media.retroachievements.org/Images/082610.png', 4),
  (172, 18612, 'Thomas & Friends: Hero of the Rails', 'Nintendo DS', 18, 183, 183, 183, 20, 0, 'Educational, Racing', 'Fuse Games | Silverball Studios', 'Barnstorm Games', '2010-08-20', 'Thomas & Friends: Hero of the Rails is a 2009 British animated adventure film and the third feature-length special based on the British television series Thomas & Friends. The film was produced and distributed by HIT Entertainment with animation production by Canadian-based Nitrogen Studios. The movie centres on Thomas finding a long-lost engine from Japan named Hiro and attempting to repair him, opposed by malicious private engine Spencer.', 'https://media.retroachievements.org/Images/121437.png', 'https://media.retroachievements.org/Images/053572.png', 'https://media.retroachievements.org/Images/053570.png', 'https://media.retroachievements.org/Images/053571.png', 4),
  (173, 15453, 'One Piece: Gigant Battle!', 'Nintendo DS', 18, 182, 182, 182, 67, 0, '2D Fighting', 'Ganbarion', 'Bandai Namco', '2011-07-01', 'The One Piece video games are based on Eiichiro Oda''s manga and anime series of the same name. Most games are published by Bandai Namco Entertainment, formerly Bandai and Banpresto. The games take place in the fictional world of One Piece, and the stories revolve around the adventures of Monkey D. Luffy and his Straw Hat Pirates, the franchise''s protagonists.', 'https://media.retroachievements.org/Images/068220.png', 'https://media.retroachievements.org/Images/057781.png', 'https://media.retroachievements.org/Images/057783.png', 'https://media.retroachievements.org/Images/057782.png', 4),
  (174, 30328, '~Prototype~ Nicktoons: Android Invasion', 'Nintendo DS', 18, 181, 181, 181, 8, 0, '2D Platforming, Educational', 'WayForward', NULL, '2007-01-01', ' The SpongeBob SquarePants video game series is a collection of video games and arcade games based on the Nickelodeon animated television series SpongeBob SquarePants and its film series with the same name. The television series'' massive rise in popularity during the 2000s led to a myriad of video games that span different genres. Several of these games are based on concepts from specific episodes, two of which are based on theatrical releases. Some of these titles had multiple different versions developed for a variety of home consoles and handheld consoles. Until 2013, the vast majority of titles were published by THQ. From 2013 to 2015, the license for most titles was handed to Activision. The license is currently held by THQ Nordic. Video games based on the series have often received mixed reviews from critics, yet many of these titles have performed well in sales.', 'https://media.retroachievements.org/Images/099895.png', 'https://media.retroachievements.org/Images/099894.png', 'https://media.retroachievements.org/Images/099900.png', 'https://media.retroachievements.org/Images/099901.png', 4),
  (175, 17066, 'Ben 10: Alien Force', 'Nintendo DS', 18, 176, 176, 176, 33, 0, 'Beat ''em Up', 'Vicious Cycle Software', 'D3 Publisher', '2008-10-28', 'Ben 10: Alien Force is an American animated television series created by team Man of Action, and produced by Cartoon Network Studios. It is the sequel to Ben 10 (2005–2008), set five years later and taking a darker turn than its predecessor.', 'https://media.retroachievements.org/Images/039586.png', 'https://media.retroachievements.org/Images/039510.png', 'https://media.retroachievements.org/Images/039513.png', 'https://media.retroachievements.org/Images/039512.png', 4),
  (176, 16299, 'Yu-Gi-Oh! World Championship 2008', 'Nintendo DS', 18, 176, 176, 176, 141, 0, 'Collectible Card Game', 'Konami', 'Konami', '2007-12-04', '   The following is a list of video games developed and published by Konami, based on Kazuki Takahashi''s Yu-Gi-Oh! manga and anime franchise, along with its spin-off series. With some exceptions, the majority of the games follow the card battle gameplay of the real-life Yu-Gi-Oh! Trading Card Game. There are 59 in total.', 'https://media.retroachievements.org/Images/084155.png', 'https://media.retroachievements.org/Images/039366.png', 'https://media.retroachievements.org/Images/083464.png', 'https://media.retroachievements.org/Images/083466.png', 4),
  (177, 16240, 'The Urbz: Sims in the City', 'Nintendo DS', 18, 175, 175, 175, 89, 0, 'Life Simulation, Strategy', 'Griptonite Games, Maxis', 'Electronic Arts', '2004-11-17', 'The Urbz: Sims in the City is a 2004 life simulation video game developed by Maxis and published by Electronic Arts for the Game Boy Advance, GameCube, PlayStation 2, Xbox, and Nintendo DS. It is the third Sims game for consoles, and the second not to be released for Microsoft Windows, after a planned PC port and sequel were both cancelled due to mediocre sales. The next release for consoles and handhelds was the console port of The Sims 2.', 'https://media.retroachievements.org/Images/088902.png', 'https://media.retroachievements.org/Images/059984.png', 'https://media.retroachievements.org/Images/041852.png', 'https://media.retroachievements.org/Images/041853.png', 4),
  (178, 26532, 'Dora the Explorer: Dora Saves the Mermaids', 'Nintendo DS', 18, 173, 173, 173, 6, 0, 'Adventure, Educational', 'Black Lantern Studios', '2K Games', '2007-11-05', 'Multiple video games based on the 2000 Nick Jr. television show Dora the Explorer have been released. Most of these games have received a mixed critical reception. Unlike other video games, these were not released in Asia, due to the TV show having less interest in that continent than North America and Europe. A number of other video games were released exclusively for the Nick Jr. website, such as Dora''s 3D Driving Adventure, and Dora''s 3D Pyramid Adventure.', 'https://media.retroachievements.org/Images/121220.png', 'https://media.retroachievements.org/Images/087508.png', 'https://media.retroachievements.org/Images/113489.png', 'https://media.retroachievements.org/Images/113490.png', 4),
  (179, 17320, 'MySims', 'Nintendo DS', 18, 173, 173, 173, 63, 0, 'Life Simulation', 'TOSE', 'Electronic Arts', '2007-09-18', 'MySims is a video game developed by EA Redwood Shores and published by Electronic Arts as a spin-off to Maxis''s The Sims franchise for the Wii and Nintendo DS in September 2007, re-released for Microsoft Windows and mobile phones in 2008, and for BlackBerry in 2009. The game sold over 4 million units as of 2008.', 'https://media.retroachievements.org/Images/120893.png', 'https://media.retroachievements.org/Images/042824.png', 'https://media.retroachievements.org/Images/042822.png', 'https://media.retroachievements.org/Images/086706.png', 4),
  (180, 31371, 'Pass the Pigs: Let the Good Swines Roll!', 'Nintendo DS', 18, 172, 172, 172, 31, 0, 'Board Game', 'AWE Games', 'THQ', '2008-10-21', ' This is a list of video games that were published or distributed by THQ.', 'https://media.retroachievements.org/Images/107289.png', 'https://media.retroachievements.org/Images/103946.png', 'https://media.retroachievements.org/Images/103949.png', 'https://media.retroachievements.org/Images/103950.png', 4),
  (181, 20077, 'Puzzler World 2011', 'Nintendo DS', 18, 172, 172, 172, 82, 0, 'Puzzle', 'Ideas Pad', 'UFO Interactive', '2010-10-10', 'This is a list of physical video games for the Nintendo DS, DS Lite, and DSi handheld game consoles. It does not include games released on DSiWare or the iQue DS. The last game for the Nintendo DS, Big Hero 6: Battle in the Bay, was released on October 28, 2014.', 'https://media.retroachievements.org/Images/060150.png', 'https://media.retroachievements.org/Images/060146.png', 'https://media.retroachievements.org/Images/060145.png', 'https://media.retroachievements.org/Images/059924.png', 4),
  (182, 9701, 'Touch the Dead | Dead ''n'' Furious', 'Nintendo DS', 18, 172, 172, 172, 56, 0, 'Rail Shooter, Survival Horror', 'Dream On Studio', 'Eidos Interactive, Virgin Interactive', '2007-05-16', 'Touch the Dead is a rail shooter/survival horror game for the Nintendo DS developed by French company Dream On Studio. The game was originally published by Virgin Play in Europe as one of their first published games, and was later co-published by Eidos Interactive and V.2 Play in North America. The game''s North American box art was created by artist Arthur Suydam, famous for his work on the Marvel Zombies line of comics.', 'https://media.retroachievements.org/Images/070109.png', 'https://media.retroachievements.org/Images/077273.png', 'https://media.retroachievements.org/Images/102454.png', 'https://media.retroachievements.org/Images/102455.png', 4),
  (183, 16154, 'Digimon World Championship', 'Nintendo DS', 18, 170, 170, 170, 46, 0, 'Life Simulation, Real-Time Strategy', 'Epics', 'Bandai Namco', '2008-02-14', 'Digimon World Championship is a life simulation video game developed by Epics and published by Bandai Namco Games for the Nintendo DS, as part of the Digimon franchise. It was released in Japan in February 2008 and North America in August 2008. Despite its localized title in North America, the game is not part of the Digimon World sub-series of role-playing games.', 'https://media.retroachievements.org/Images/107265.png', 'https://media.retroachievements.org/Images/067729.png', 'https://media.retroachievements.org/Images/067730.png', 'https://media.retroachievements.org/Images/067731.png', 4),
  (184, 20263, 'Diner Dash: Flo on the Go', 'Nintendo DS', 18, 169, 169, 169, 92, 0, 'Job Simulation', 'PlayFirst', 'Zoo Digital Publishing | Zushi Games', '2009-10-27', 'Diner Dash: Flo on the Go is the third installment to the game series Diner Dash. It is published by PlayFirst and was released in October 2006.', 'https://media.retroachievements.org/Images/061085.png', 'https://media.retroachievements.org/Images/060595.png', 'https://media.retroachievements.org/Images/060975.png', 'https://media.retroachievements.org/Images/060974.png', 4),
  (185, 16755, 'Orcs and Elves', 'Nintendo DS', 18, 168, 168, 168, 66, 0, 'CRPG, Dungeon Crawl', 'Fountainhead Entertainment, id Software', 'Electronic Arts', '2007-11-13', 'Orcs & Elves is a 2006 role-playing video game for the mobile phone and Nintendo DS. It was developed by id Software and Fountainhead Entertainment and published by EA Mobile and licensed by Nintendo for the DS version. It was released for mobile phones in May 2006 before being ported to the Nintendo DS in November 2007. The game is based on Doom RPG''s engine and is id''s first original intellectual property since Quake. The DS port of the game included graphical enhancements, such as 3D environments and camera cutscenes, along with improved character sprites, two new levels and the use of the touchscreen feature.', 'https://media.retroachievements.org/Images/056285.png', 'https://media.retroachievements.org/Images/056286.png', 'https://media.retroachievements.org/Images/056284.png', 'https://media.retroachievements.org/Images/056485.png', 4),
  (186, 14974, '~Homebrew~ New Zelda', 'Nintendo DS', 18, 166, 166, 166, 8, 0, '2D Platforming', 'Lupi', 'Lupi', '2006-08-02', 'The Nintendo DS is a foldable handheld game console developed by Nintendo and released worldwide in 2004 and 2005. The "DS" in the name is an initialism for "Dual Screen", reflecting the system''s most distinctive feature: two LCD screens working in tandem, with the lower screen functioning as a touchscreen. Both screens are housed in a clamshell design similar to that of the Game Boy Advance SP and some models of the Game & Watch series. The DS was among the first portable consoles to support wireless connectivity for local multiplayer over short distances, as well as online play through the now-defunct Nintendo Wi-Fi Connection service. Its primary competitor during the seventh generation of video game consoles was Sony''s PlayStation Portable.', 'https://media.retroachievements.org/Images/111719.png', 'https://media.retroachievements.org/Images/035045.png', 'https://media.retroachievements.org/Images/035125.png', 'https://media.retroachievements.org/Images/035126.png', 4),
  (187, 16300, 'Yu-Gi-Oh! 5D''s World Championship 2011: Over the Nexus', 'Nintendo DS', 18, 164, 164, 164, 92, 0, 'Collectible Card Game, Racing', 'Konami', 'Konami', '2011-03-25', '   The following is a list of video games developed and published by Konami, based on Kazuki Takahashi''s Yu-Gi-Oh! manga and anime franchise, along with its spin-off series. With some exceptions, the majority of the games follow the card battle gameplay of the real-life Yu-Gi-Oh! Trading Card Game. There are 59 in total.', 'https://media.retroachievements.org/Images/049794.png', 'https://media.retroachievements.org/Images/073263.png', 'https://media.retroachievements.org/Images/099870.png', 'https://media.retroachievements.org/Images/099871.png', 4),
  (188, 11637, 'Harvest Moon DS', 'Nintendo DS', 18, 163, 163, 163, 224, 0, 'Life Simulation', 'Marvelous Interactive', 'Natsume', '2005-03-17', 'Harvest Moon DS, known in Japan as Bokujō Monogatari: Colobocle Station , is a farm simulation role-playing video game for the Nintendo DS, part of the Story of Seasons series. It was published and developed by Marvelous Interactive Inc., and released in Japan on March 17, 2005, and in North America on September 12, 2006. It is the first entry in the series without series creator Yasuhiro Wada heavily involved, though it borrows many assets from Harvest Moon: Friends of Mineral Town and Harvest Moon: A Wonderful Life, such as the graphical style from the former and setting of the latter.', 'https://media.retroachievements.org/Images/061248.png', 'https://media.retroachievements.org/Images/067505.png', 'https://media.retroachievements.org/Images/060946.png', 'https://media.retroachievements.org/Images/060947.png', 4),
  (189, 17155, 'eSMART', 'Nintendo DS', 18, 161, 161, 161, 16, 0, 'Job Simulation', NULL, 'McDonald''s', '2010-01-01', 'The Nintendo DS is a foldable handheld game console developed by Nintendo and released worldwide in 2004 and 2005. The "DS" in the name is an initialism for "Dual Screen", reflecting the system''s most distinctive feature: two LCD screens working in tandem, with the lower screen functioning as a touchscreen. Both screens are housed in a clamshell design similar to that of the Game Boy Advance SP and some models of the Game & Watch series. The DS was among the first portable consoles to support wireless connectivity for local multiplayer over short distances, as well as online play through the now-defunct Nintendo Wi-Fi Connection service. Its primary competitor during the seventh generation of video game consoles was Sony''s PlayStation Portable.', 'https://media.retroachievements.org/Images/048969.png', 'https://media.retroachievements.org/Images/046340.png', 'https://media.retroachievements.org/Images/040179.png', 'https://media.retroachievements.org/Images/040180.png', 4),
  (190, 15334, 'Mega Man Star Force: Leo', 'Nintendo DS', 18, 160, 160, 160, 64, 0, 'Action RPG', 'Capcom', 'Capcom', '2006-12-14', 'Mega Man Star Force: Leo, Mega Man Star Force: Dragon, and Mega Man Star Force: Pegasus, are 2006 action role-playing games developed and published by Capcom for the Nintendo DS handheld video game console; combined, they are the first game in the Mega Man Star Force series, a sub-series of the Mega Man franchise—and a follow-up to the Mega Man Battle Network series. It takes place in the years of 220X, in which technology has advanced to the point where the world is now connected through EM waves. The game follows Geo Stelar, an 11-year-old fifth-grader in Echo Ridge who merges with an FM-ian alien named Omega-Xis after mourning the supposed death of his father Kelvin Stelar.', 'https://media.retroachievements.org/Images/121809.png', 'https://media.retroachievements.org/Images/050334.png', 'https://media.retroachievements.org/Images/030379.png', 'https://media.retroachievements.org/Images/030380.png', 4),
  (191, 17674, 'Need for Speed: Carbon - Own the City', 'Nintendo DS', 18, 160, 160, 160, 40, 0, NULL, NULL, NULL, '2006-10-31', 'Need for Speed: Carbon – Own the City is a 2006 racing video game and the third portable installment in the Need for Speed series. Developed by Team Fusion and published by Electronic Arts, it was released on October 31, 2006, for the PlayStation Portable, Game Boy Advance, Nintendo DS and on May 25, 2009 as a pack-in title for the Zeebo. The game, a companion title to Need for Speed: Carbon, includes new or modified gameplay elements, a different setting and storyline, and a different selection of teammates. It is the final installment in the series to be released for Game Boy Advance.', 'https://media.retroachievements.org/Images/069477.png', 'https://media.retroachievements.org/Images/057794.png', 'https://media.retroachievements.org/Images/069476.png', 'https://media.retroachievements.org/Images/062525.png', 4),
  (192, 1983, 'Elf Bowling 1 & 2', 'Nintendo DS', 18, 159, 159, 159, 13, 0, 'Sports - Bowling', 'Black Lantern Studios', 'Ignition Entertainment', '2005-12-01', 'Elf Bowling is a bowling video game developed by NStorm and released in 1998 for Windows Computers. In the game  the player, as Santa Claus, attempts to knock down elves who are arranged like bowling pins. A later release of the game, by Ignition Entertainment, was released on the Nintendo handheld consoles Nintendo DS and Game Boy Advance, and received overwhelmingly negative reviews from critics. In Elf Bowling, the elves of Santa''s Workshop are on strike due to overwork from the huge demand for Christmas toys, so Santa Claus has decided to whip them into shape by using them as bowling pins.', 'https://media.retroachievements.org/Images/075759.png', 'https://media.retroachievements.org/Images/033053.png', 'https://media.retroachievements.org/Images/033050.png', 'https://media.retroachievements.org/Images/033051.png', 4),
  (193, 8705, 'Point Blank DS', 'Nintendo DS', 18, 159, 159, 159, 54, 0, 'Arcade, Minigames', 'TOSE', 'Bandai Namco', '2006-06-13', 'Point Blank DS is a 2006 lightgun shooter video game developed and published for the Nintendo DS by Namco Bandai Games. It is the fourth entry in the Point Blank series, comprising both new stages and ones taken from the first three games. Players use the touch screen to complete a number of different minigames that vary in terms of mechanics, such as protecting an on-screen character or shooting down a specific target.', 'https://media.retroachievements.org/Images/084348.png', 'https://media.retroachievements.org/Images/084347.png', 'https://media.retroachievements.org/Images/084350.png', 'https://media.retroachievements.org/Images/084351.png', 4),
  (194, 15521, 'Bleach: Dark Souls', 'Nintendo DS', 18, 158, 158, 158, 62, 0, '2D Fighting', 'Treasure', 'Sega', '2008-10-07', 'Bleach: Dark Souls, known in Japan as Bleach DS 2nd Kokui Hirameku Chinkonka is a fighting game developed by Treasure and published by Sega for the Nintendo DS. It is the second Bleach game released for the console. The game introduces new characters, and adds new moves for the older characters as well as introducing new game modes. Bleach: Dark Souls also includes Hollows of varying sizes, for players to fight. The number of Reifu cards in-game are also increased from the original, and more cards are displayed on the touch screen during battle. The Wi-Fi battle mode has been improved to make it easier to play online. The game''s theme song is "Resistance" by High and Mighty Color.', 'https://media.retroachievements.org/Images/049469.png', 'https://media.retroachievements.org/Images/049562.png', 'https://media.retroachievements.org/Images/049560.png', 'https://media.retroachievements.org/Images/049561.png', 4),
  (195, 14826, 'Bomberman', 'Nintendo DS', 18, 158, 158, 158, 54, 0, NULL, NULL, NULL, '2005-06-21', 'Bomberman  is a video game franchise created by Shinichi Nakamoto and Shigeki Fujiwara, originally developed by Hudson Soft and currently owned by Konami. The original game, also known as Bakudan Otoko, was released in Japan in July 1983 and has since spawned multiple sequels and spin-offs released on numerous platforms, as well as several anime and manga adaptations.', 'https://media.retroachievements.org/Images/120409.png', 'https://media.retroachievements.org/Images/041415.png', 'https://media.retroachievements.org/Images/028928.png', 'https://media.retroachievements.org/Images/074977.png', 4),
  (196, 12700, 'Rune Factory 3: A Fantasy Harvest Moon', 'Nintendo DS', 18, 158, 158, 158, 108, 0, 'Life Simulation', 'Neverland', 'Marvelous Entertainment, Natsume', '2009-10-22', 'Rune Factory 3: A Fantasy Harvest Moon is a 2009 simulation role-playing video game developed by Neverland for the Nintendo DS. It was published in Japan by Marvelous Entertainment, in North America by Natsume Inc. in 2010, and in Europe by Rising Star Games in 2011. It is the fourth game in the Rune Factory series.', 'https://media.retroachievements.org/Images/107476.png', 'https://media.retroachievements.org/Images/016530.png', 'https://media.retroachievements.org/Images/016540.png', 'https://media.retroachievements.org/Images/016534.png', 4),
  (197, 20897, 'TrackMania Turbo', 'Nintendo DS', 18, 158, 158, 158, 252, 0, 'Arcade Racing', 'Firebrand Games', 'Focus Home Interactive', '2010-09-24', 'TrackMania Turbo is a racing video game developed by Firebrand Games. The successor to TrackMania DS, it was released on September 24, 2010 in Europe by Focus Home Interactive, and on April 19, 2011 in the US by City Interactive. It was released at the same time as TrackMania: Build to Race for the Wii. It received generally favorable reviews from critics.', 'https://media.retroachievements.org/Images/113401.png', 'https://media.retroachievements.org/Images/106879.png', 'https://media.retroachievements.org/Images/106875.png', 'https://media.retroachievements.org/Images/106878.png', 4),
  (198, 4593, 'Dementium II', 'Nintendo DS', 18, 157, 157, 157, 40, 0, 'Survival Horror', 'Renegade Kid', 'SouthPeak Games', '2010-05-04', 'Dementium II is a 2010 survival horror first-person shooter video game developed by Renegade Kid and published by SouthPeak Games for the Nintendo DS. It is the sequel to 2007''s Dementium: The Ward. A remastered version of the game without involvement from Renegade Kid was released for Microsoft Windows and Mac OS X on December 17, 2013 to negative reviews.', 'https://media.retroachievements.org/Images/077965.png', 'https://media.retroachievements.org/Images/042329.png', 'https://media.retroachievements.org/Images/053283.png', 'https://media.retroachievements.org/Images/053284.png', 4),
  (199, 11734, 'Contact', 'Nintendo DS', 18, 156, 156, 156, 156, 0, 'Action RPG', 'Grasshopper Manufacture', 'Atlus', '2006-10-17', 'Contact is a role-playing video game developed by Grasshopper Manufacture for the Nintendo DS handheld game console. It was published by Marvelous Entertainment in Japan on March 30, 2006, by Atlus USA in North America on October 18, and by Rising Star Games in Australia, Asia and Europe on January 25, 2007 and February 2, respectively.', 'https://media.retroachievements.org/Images/070782.png', 'https://media.retroachievements.org/Images/028642.png', 'https://media.retroachievements.org/Images/028643.png', 'https://media.retroachievements.org/Images/028641.png', 4),
  (200, 15380, 'Postman Pat', 'Nintendo DS', 18, 156, 156, 156, 24, 0, 'Minigames', 'The Code Monkeys', 'Blast! Entertainment', '2008-03-14', 'Postman Pat is a British stop motion animated children''s television series first produced by Woodland Animations. The series follows the adventures of Pat Clifton, a postman who works for the Royal Mail postal service in the fictional village of Greendale.', 'https://media.retroachievements.org/Images/085718.png', 'https://media.retroachievements.org/Images/085547.png', 'https://media.retroachievements.org/Images/085964.png', 'https://media.retroachievements.org/Images/085963.png', 4);
INSERT INTO games (rank, id, title, consoleName, consoleId, totalPlayers, casualPlayers, hardcorePlayers, numAchievements, points, genre, developer, publisher, released, description, icon, boxArt, titleScreen, screenshot, rating) VALUES
  (1, 1446, 'Super Mario Bros.', 'NES/Famicom', 7, 68830, 68830, 68830, 77, 0, '2D Platforming', NULL, 'Nintendo', '1985-09-13', 'Super Mario Bros. is a 1985 platform game developed and published by Nintendo for the Nintendo Entertainment System (NES). Directed and produced by Shigeru Miyamoto, it is the successor to the 1983 arcade game Mario Bros. and the first game in the Super Mario series. Players control Mario, or his brother Luigi in the multiplayer mode, to traverse the Mushroom Kingdom to rescue Princess Toadstool from King Koopa. They traverse side-scrolling stages while avoiding hazards such as enemies and pits and collecting power-ups such as the Super Mushroom, Fire Flower, and Starman.', 'https://media.retroachievements.org/Images/036035.png', 'https://media.retroachievements.org/Images/013238.png', 'https://media.retroachievements.org/Images/079350.png', 'https://media.retroachievements.org/Images/000387.png', 5),
  (2, 1995, 'Super Mario Bros. 3', 'NES/Famicom', 7, 44962, 44962, 44962, 89, 0, '2D Platforming', NULL, 'Nintendo', '1988-10-23', 'Super Mario Bros. 3 is a 1988 platform game developed and published by Nintendo for the Nintendo Entertainment System (NES). It was released in Japan on October 23, 1988, in North America on February 12, 1990, and in Europe on August 29, 1991. It was developed by Nintendo Entertainment Analysis and Development, led by Shigeru Miyamoto and Takashi Tezuka.', 'https://media.retroachievements.org/Images/120885.png', 'https://media.retroachievements.org/Images/120292.png', 'https://media.retroachievements.org/Images/079347.png', 'https://media.retroachievements.org/Images/000743.png', 4.9),
  (3, 1454, 'The Legend of Zelda', 'NES/Famicom', 7, 31457, 31457, 31457, 69, 0, 'Action-Adventure', NULL, 'Nintendo', '1986-02-21', 'The Legend of Zelda is a video game series created by Japanese game designers Shigeru Miyamoto and Takashi Tezuka. It is primarily developed and published by Nintendo, but some installments and re-releases have been outsourced to Flagship, Grezzo, and Tantalus Media.', 'https://media.retroachievements.org/Images/059053.png', 'https://media.retroachievements.org/Images/012434.png', 'https://media.retroachievements.org/Images/072708.png', 'https://media.retroachievements.org/Images/072709.png', 4.8),
  (4, 1462, 'Castlevania', 'NES/Famicom', 7, 22950, 22950, 22950, 74, 0, '2D Platforming', 'Konami', 'Konami', '1987-05-01', 'Castlevania, known in Japan as Akumajō Dracula, is a gothic horror action-adventure video game series and media franchise created by Hitoshi Akamatsu and published by Konami. The series is largely set in the castle of Count Dracula, who wages an eternal war against humanity and comes into conflict with the world''s vampire hunters, principally including the Belmont clan, wielders of the mystical whip known as the Vampire Killer.', 'https://media.retroachievements.org/Images/070132.png', 'https://media.retroachievements.org/Images/071768.png', 'https://media.retroachievements.org/Images/039452.png', 'https://media.retroachievements.org/Images/039453.png', 4.7),
  (5, 1447, 'Contra', 'NES/Famicom', 7, 20059, 20059, 20059, 40, 0, 'Run & Gun', 'Konami', 'Konami', '1988-02-09', 'Contra is a 1987 run and gun game developed and published by Konami for arcades. A home version was released for the Nintendo Entertainment System in 1988, along with ports for various home computer formats, including the MSX2. The arcade and computer versions were localized as Gryzor in Europe, and the NES version as Probotector in the PAL region.', 'https://media.retroachievements.org/Images/079383.png', 'https://media.retroachievements.org/Images/011874.png', 'https://media.retroachievements.org/Images/035408.png', 'https://media.retroachievements.org/Images/035409.png', 4.7),
  (6, 1994, 'Super Mario Bros. 2', 'NES/Famicom', 7, 17089, 17089, 17089, 51, 0, '2D Platforming', NULL, 'Nintendo', '1988-10-09', 'Super Mario Bros. 2 is a 1988 platform game developed and published by Nintendo for the Nintendo Entertainment System. After the smash hit Super Mario Bros. in 1985, Nintendo quickly released a minor adaptation of the original with advanced difficulty titled Super Mario Bros. 2, for its mature market in Japan in 1986. However, Nintendo of America found this sequel too similar to its predecessor, and its difficulty too frustrating, for the nascent American market. This prompted a second Super Mario Bros. sequel based on Yume Kōjō: Doki Doki Panic, Nintendo''s 1987 Family Computer Disk System game which had been based on a prototype platforming game and released as an advergame for Fuji Television''s Yume Kōjō ''87 media technology expo. The characters, enemies, and themes in Doki Doki Panic have the mascots and theme of the festival, and were adapted into the Super Mario theme to make a Western Super Mario Bros. sequel.', 'https://media.retroachievements.org/Images/085238.png', 'https://media.retroachievements.org/Images/109857.png', 'https://media.retroachievements.org/Images/079348.png', 'https://media.retroachievements.org/Images/079349.png', 4.7),
  (7, 1489, 'Mike Tyson''s Punch-Out!!', 'NES/Famicom', 7, 15079, 15079, 15079, 28, 0, 'Sports - Boxing', 'Nintendo', 'Nintendo', '1987-10-18', 'Punch-Out!!, originally titled Mike Tyson''s Punch-Out!!, is a 1987 boxing video game developed and published by Nintendo for the Nintendo Entertainment System (NES). Part of the Punch-Out!! series, it is an adaptation of the arcade video games Punch-Out!! (1984) and Super Punch-Out!! (1984). Differences from the arcades include the addition of former undisputed world heavyweight champion Mike Tyson as the final boss. It received critical acclaim, and is retrospectively considered one of the greatest video games of all time.', 'https://media.retroachievements.org/Images/112224.png', 'https://media.retroachievements.org/Images/012758.png', 'https://media.retroachievements.org/Images/001913.png', 'https://media.retroachievements.org/Images/002118.png', 4.6),
  (8, 1451, 'Mega Man 2', 'NES/Famicom', 7, 13789, 13789, 13789, 84, 0, '2D Platforming', 'Capcom', 'Capcom', '1988-12-24', 'Mega Man 2, known in Japan as Rockman 2: The Mystery of Dr. Wily, is a 1988 platform game developed and published by Capcom for the Nintendo Entertainment System (NES). It was released in Japan in 1988 and in North America and PAL regions the following years. Mega Man 2 continues Mega Man''s battle against the evil Dr. Wily and his rogue Robot Masters. It introduced graphical and gameplay changes, many of which became series staples.', 'https://media.retroachievements.org/Images/082481.png', 'https://media.retroachievements.org/Images/012787.png', 'https://media.retroachievements.org/Images/038665.png', 'https://media.retroachievements.org/Images/038666.png', 4.6),
  (9, 1859, 'Ninja Gaiden', 'NES/Famicom', 7, 13457, 13457, 13457, 35, 0, '2D Platforming', 'Tecmo', 'Koei | Tecmo', '1988-01-01', 'Ninja Gaiden  is an action game franchise created by Tecmo and featuring the ninja Ryu Hayabusa as its protagonist. The series was originally known as Ninja Ryukenden  in Japan. The word gaiden in the North American Ninja Gaiden title means side story in Japanese. The original arcade version, first two Nintendo Entertainment System games and Game Boy game were released as Shadow Warriors in PAL regions. As of 2008, the series had shipped over 7.7 million units worldwide.', 'https://media.retroachievements.org/Images/120891.png', 'https://media.retroachievements.org/Images/012659.png', 'https://media.retroachievements.org/Images/035352.png', 'https://media.retroachievements.org/Images/002148.png', 4.6),
  (10, 1448, 'Mega Man', 'NES/Famicom', 7, 13058, 13058, 13058, 50, 0, '2D Platforming', 'Capcom', 'Capcom', '1987-12-17', 'Mega Man is a video game franchise developed and published by Capcom, featuring the protagonist of the same name. The original game was released for the Nintendo Entertainment System in 1987, and spawned a franchise that expanded to over 50 games on multiple systems. As of March 2025, the series had sold 43 million units worldwide. Mega Man has been popular among gamers and has been reimagined and evolved as a video game character for over 30 years.', 'https://media.retroachievements.org/Images/024519.png', 'https://media.retroachievements.org/Images/070293.png', 'https://media.retroachievements.org/Images/000445.png', 'https://media.retroachievements.org/Images/034071.png', 4.6),
  (11, 1487, 'Metroid', 'NES/Famicom', 7, 12667, 12667, 12667, 25, 0, '2D Platforming, Metroidvania', NULL, 'Nintendo', '1987-08-01', 'Metroid is an action-adventure game franchise created by Nintendo. The player controls the bounty hunter Samus Aran, who protects the galaxy from Space Pirates and their attempts to harness the power of the parasitic Metroid creatures. Metroid combines the platforming of Super Mario Bros. and the exploration of The Legend of Zelda with a science fiction setting and an emphasis on nonlinear gameplay. Most Metroid games are side-scrolling, while the 3D games use a first-person perspective. Players battle hostile alien enemies and obtain power-ups as they progress through the game world, with few non-player characters.', 'https://media.retroachievements.org/Images/060606.png', 'https://media.retroachievements.org/Images/012774.png', 'https://media.retroachievements.org/Images/037030.png', 'https://media.retroachievements.org/Images/037031.png', 4.6),
  (12, 1472, 'DuckTales', 'NES/Famicom', 7, 11872, 11872, 11872, 63, 0, '2D Platforming', 'Capcom', 'Capcom, Disney Interactive Studios', '1989-09-01', 'DuckTales is a 1989 platform game developed and published by Capcom and based on the Disney animated TV series of the same name. It was first released in North America for the Nintendo Entertainment System in 1989 and was later ported to the Game Boy in 1990. The story involves Scrooge McDuck traveling around the globe collecting treasure and outwitting his rival Flintheart Glomgold to become the world''s richest duck.', 'https://media.retroachievements.org/Images/112003.png', 'https://media.retroachievements.org/Images/012036.png', 'https://media.retroachievements.org/Images/113639.png', 'https://media.retroachievements.org/Images/113640.png', 4.6),
  (13, 1469, 'Dr. Mario', 'NES/Famicom', 7, 11681, 11681, 11681, 70, 0, NULL, NULL, 'Nintendo', '1990-07-27', 'Dr. Mario is a 1990 puzzle video game developed and published by Nintendo for the Nintendo Entertainment System and Game Boy. A spin-off of the Mario series, it is a falling block puzzle game in which the player''s objective is to destroy the viruses populating the on-screen playing field by using colored capsules that are automatically tossed into the field by Dr. Mario. The player manipulates the falling capsules, to align the same colors, which destroys viruses. The player progresses through the game by eliminating all the viruses on the screen in each level. The game was produced by Gunpei Yokoi and programmed by Takahiro Harada, with the soundtrack composed by Hirokazu Tanaka.', 'https://media.retroachievements.org/Images/116885.png', 'https://media.retroachievements.org/Images/012014.png', 'https://media.retroachievements.org/Images/002004.png', 'https://media.retroachievements.org/Images/002005.png', 4.6),
  (14, 1466, 'Donkey Kong', 'NES/Famicom', 7, 9822, 9822, 9822, 25, 0, '2D Platforming, Arcade', NULL, 'Nintendo', '1983-07-15', 'Donkey Kong is a video game series and media franchise created by the Japanese game designer Shigeru Miyamoto for Nintendo. It follows the adventures of Donkey Kong, a large, powerful gorilla, and other members of the Kong family of apes. Donkey Kong games include the original arcade game trilogy by Nintendo R&D1; the Donkey Kong Country series by Rare and Retro Studios; and the Mario vs. Donkey Kong series by Nintendo Software Technology. Various studios have developed spin-offs in genres such as edutainment, puzzle, racing, and rhythm. The franchise also incorporates animation, printed media, theme parks, and merchandise.', 'https://media.retroachievements.org/Images/024799.png', 'https://media.retroachievements.org/Images/013231.png', 'https://media.retroachievements.org/Images/082064.png', 'https://media.retroachievements.org/Images/082065.png', 4.5),
  (15, 1473, 'Excitebike', 'NES/Famicom', 7, 9596, 9596, 9596, 17, 0, 'Extreme Sports - Motocross', NULL, 'Nintendo', '1984-11-30', 'Excitebike is a 1984 racing video game developed and published by Nintendo for the Nintendo Entertainment System. It was ported to arcades for the Nintendo VS. System later that year and Famicom Disk System in 1988. In North America, it became one of the best-selling games on the console. It is the first game in the Excite series.', 'https://media.retroachievements.org/Images/104983.png', 'https://media.retroachievements.org/Images/012108.png', 'https://media.retroachievements.org/Images/004720.png', 'https://media.retroachievements.org/Images/004721.png', 4.5),
  (16, 1515, '1942', 'NES/Famicom', 7, 8790, 8790, 8790, 27, 0, 'Shoot ''em Up', 'Capcom, Micronics', 'Capcom', '1985-12-11', '1942 (MCMXLII) was a common year starting on Thursday of the Gregorian calendar, the 1942nd year of the Common Era (CE) and Anno Domini (AD) designations, the 942nd year of the 2nd millennium, the 42nd year of the 20th century, and the 3rd year of the 1940s decade.', 'https://media.retroachievements.org/Images/043934.png', 'https://media.retroachievements.org/Images/011488.png', 'https://media.retroachievements.org/Images/000549.png', 'https://media.retroachievements.org/Images/000550.png', 4.5),
  (17, 2016, 'Teenage Mutant Ninja Turtles', 'NES/Famicom', 7, 8717, 8717, 8717, 24, 0, '2D Platforming, Action', 'Konami', 'Ultra Games', '1989-06-01', 'Teenage Mutant Ninja Turtles (TMNT) is an American media franchise created by comic book artists Kevin Eastman and Peter Laird. It follows Leonardo, Donatello, Raphael and Michelangelo, four anthropomorphic turtle brothers trained in ninjutsu who fight evil in New York City. The franchise encompasses printed media, television series, feature films, video games, and merchandise.', 'https://media.retroachievements.org/Images/104331.png', 'https://media.retroachievements.org/Images/013119.png', 'https://media.retroachievements.org/Images/002942.png', 'https://media.retroachievements.org/Images/002943.png', 4.5),
  (18, 1509, 'Battletoads', 'NES/Famicom', 7, 7920, 7920, 7920, 20, 0, 'Beat ''em Up', 'Rare', 'Tradewest', '1991-06-01', 'Battletoads is a video game franchise by Rare that began with the original beat ''em up game Battletoads in 1991. Starring three anthropomorphic toads named after skin conditions, Rash, Zitz, and Pimple, the series was created to rival the Teenage Mutant Ninja Turtles games series. The original Battletoads game for the NES was renowned for its extreme difficulty, but still received a cult following, spawning sequels for various platforms including a crossover with the Double Dragon series and a modern reboot after a 25-year gap in releases. In each of the games, the objective is to defeat the toads'' nemesis the Dark Queen and her army of space mutants.', 'https://media.retroachievements.org/Images/103430.png', 'https://media.retroachievements.org/Images/011661.png', 'https://media.retroachievements.org/Images/000756.png', 'https://media.retroachievements.org/Images/000757.png', 4.5),
  (19, 1556, 'Balloon Fight', 'NES/Famicom', 7, 7419, 7419, 7419, 25, 0, '2D Platforming', 'HAL Laboratory, Nintendo', 'Nintendo', '1985-01-22', 'Balloon Fight is a 1984 action video game developed by Nintendo and HAL Laboratory and published by Nintendo for the Nintendo Entertainment System. It was originally released for arcades as VS. Balloon Fight, with the console version releasing in Japan in 1985 and internationally in 1986.', 'https://media.retroachievements.org/Images/123704.png', 'https://media.retroachievements.org/Images/011594.png', 'https://media.retroachievements.org/Images/000441.png', 'https://media.retroachievements.org/Images/000442.png', 4.4),
  (20, 2221, 'Castlevania III: Dracula''s Curse', 'NES/Famicom', 7, 7230, 7230, 7230, 55, 0, '2D Platforming', 'Konami', 'Konami', '1989-12-22', 'Castlevania III: Dracula''s Curse is a 1989 platform game developed and published by Konami for the Nintendo Entertainment System. It was released on December 22, 1989 in Japan, September 19, 1990 in North America and in May 1992 in PAL regions by Konami''s Palcom publishing label.', 'https://media.retroachievements.org/Images/079969.png', 'https://media.retroachievements.org/Images/071771.png', 'https://media.retroachievements.org/Images/002622.png', 'https://media.retroachievements.org/Images/002623.png', 4.4),
  (21, 2032, 'Tiny Toon Adventures', 'NES/Famicom', 7, 7148, 7148, 7148, 54, 0, '2D Platforming', 'Konami', 'Konami', '1991-12-01', 'Tiny Toon Adventures, also known simply as Tiny Toons, is an American animated comedy television series created by animator Tom Ruegger and produced by Warner Bros. Animation and Amblin Entertainment. The series follows the adventures of a group of young cartoon characters who attend Acme Looniversity to become the next generation of characters from the Looney Tunes series.', 'https://media.retroachievements.org/Images/015367.png', 'https://media.retroachievements.org/Images/017003.png', 'https://media.retroachievements.org/Images/016800.png', 'https://media.retroachievements.org/Images/016802.png', 4.4),
  (22, 1471, 'Dragon Quest', 'NES/Famicom', 7, 6799, 6799, 6799, 33, 0, NULL, 'Chunsoft', 'Enix, Nintendo', '1986-05-27', 'Dragon Quest, previously published as Dragon Warrior in North America until 2005, is a series of role-playing video games created by Japanese game designer Yuji Horii, character designer Akira Toriyama, and composer Koichi Sugiyama and published by Square Enix. Since its inception, development of games in the series have been outsourced to a plethora of external companies until the tenth installment, with localized remakes and ports of later installments for the Nintendo DS, Nintendo 3DS, and Nintendo Switch being published by Nintendo outside of Japan. With its first game published in 1986, there are eleven main-series games, along with numerous spin-off games. In addition, there have been numerous manga, anime and novels published under the franchise, with nearly every game in the main series having a related adaptation.', 'https://media.retroachievements.org/Images/026797.png', 'https://media.retroachievements.org/Images/012023.png', 'https://media.retroachievements.org/Images/002863.png', 'https://media.retroachievements.org/Images/002864.png', 4.4),
  (23, 1483, 'Mega Man 3', 'NES/Famicom', 7, 6773, 6773, 6773, 83, 0, '2D Platforming', 'Capcom', 'Capcom', '1990-09-28', 'Mega Man 3 is a 1990 platform game developed and published by Capcom for the Nintendo Entertainment System. It is the third installment of the original Mega Man series and was originally released in Japan on September 28, 1990. The game was released in North America later in 1990 and in European regions by Nintendo a year later. Taking place after the events of Mega Man 2, the plot follows the titular hero as he helps his creator, Dr. Light, and a supposedly former enemy, Dr. Wily, collect parts for a peace-keeping robot by defeating several Robot Masters that have gone haywire.', 'https://media.retroachievements.org/Images/082508.png', 'https://media.retroachievements.org/Images/012786.png', 'https://media.retroachievements.org/Images/038663.png', 'https://media.retroachievements.org/Images/038664.png', 4.4),
  (24, 6070, '~Homebrew~ 2048', 'NES/Famicom', 7, 6723, 6723, 6723, 12, 0, 'Sliding Puzzle', 'tsone', 'Homebrew - NES/Famicom', '2014-03-09', '2048 is a single-player sliding tile puzzle video game written by Italian web developer Gabriele Cirulli and published on GitHub. The objective of the game is to slide numbered tiles on a grid to combine them to create a tile with the number 2048; however, one can continue to play the game after reaching the goal, creating tiles with larger numbers. It was originally written in JavaScript and CSS over a weekend, and released on 9 March 2014 as free and open-source software subject to the MIT License. Versions for iOS and Android followed in May 2014.', 'https://media.retroachievements.org/Images/066649.png', 'https://media.retroachievements.org/Images/008453.png', 'https://media.retroachievements.org/Images/008378.png', 'https://media.retroachievements.org/Images/008379.png', 4.4),
  (25, 1458, 'Batman: The Video Game', 'NES/Famicom', 7, 6701, 6701, 6701, 41, 0, '2D Platforming', 'Sunsoft', 'Sunsoft', '1989-12-22', 'Batman: The Video Game is a platformer developed by Sunsoft for the Nintendo Entertainment System featuring the DC Comics character Batman, tying into the 1989 film of the same name.', 'https://media.retroachievements.org/Images/039041.png', 'https://media.retroachievements.org/Images/011643.png', 'https://media.retroachievements.org/Images/035572.png', 'https://media.retroachievements.org/Images/035573.png', 4.4),
  (26, 1526, 'Adventure Island', 'NES/Famicom', 7, 6597, 6597, 6597, 15, 0, '2D Platforming', 'Hudson Soft', 'Hudson Soft', '1988-09-01', 'Hudson''s Adventure Island, known as Takahashi Meijin no Bōken Jima  in Japan and also known as Adventure Island, is a platform game produced by Hudson Soft that was released in Japan for the Famicom and MSX on September 12, 1986. It was released in North America for the Nintendo Entertainment System in 1988 and in the PAL region in 1992.', 'https://media.retroachievements.org/Images/119053.png', 'https://media.retroachievements.org/Images/011439.png', 'https://media.retroachievements.org/Images/007290.png', 'https://media.retroachievements.org/Images/007292.png', 4.4),
  (27, 1460, 'Bubble Bobble', 'NES/Famicom', 7, 6571, 6571, 6571, 75, 0, '2D Platforming', 'Taito', 'Taito', '1988-01-01', 'Bubble Bobble is a platform game series originally developed and published by Taito. The first entry in the series, Bubble Bobble, was released in 1986 as an arcade cabinet. In most entries in the series, players control two dragons named Bub and Bob. This was followed by many sequels in both the main Bubble Bobble series, as well as the spin-off Rainbow Islands and Puzzle Bobble series. They were published for and ported to a wide variety of arcade and home video game consoles. The most recent release in the series is Bubble Bobble Sugar Dungeons in 2025.', 'https://media.retroachievements.org/Images/051196.png', 'https://media.retroachievements.org/Images/011730.png', 'https://media.retroachievements.org/Images/005294.png', 'https://media.retroachievements.org/Images/005295.png', 4.4),
  (28, 1524, 'Adventure Island II', 'NES/Famicom', 7, 6495, 6495, 6495, 35, 0, '2D Platforming', 'Now Production', 'Hudson Soft', '1991-02-01', 'Adventure Island II is a 1991 platform game developed by Now Production and published by Hudson Soft for the Nintendo Entertainment System. It is the sequel to Adventure Island and the second game in the series for the NES. While the first game was an adaptation of Sega''s Wonder Boy, Adventure Island II is an original work, as were most of the subsequent Adventure Island games. A portable version was also released for the Game Boy in 1992, titled Takahashi Meijin no Bouken Jima II or Adventure Island outside of Japan.', 'https://media.retroachievements.org/Images/101101.png', 'https://media.retroachievements.org/Images/011517.png', 'https://media.retroachievements.org/Images/007293.png', 'https://media.retroachievements.org/Images/007294.png', 4.4),
  (29, 1463, 'Chip ''n Dale: Rescue Rangers', 'NES/Famicom', 7, 6421, 6421, 6421, 60, 0, '2D Platforming', 'Capcom', 'Capcom', '1990-06-08', 'Chip ''n Dale Rescue Rangers is a platform video game developed and published by Capcom for the Nintendo Entertainment System. It is based on the Disney animated series of the same name. It was released in North America and Japan in 1990, and Europe in 1991. An arcade version was released by Nintendo in 1990. It sold approximately 1.2 million copies worldwide.', 'https://media.retroachievements.org/Images/104957.png', 'https://media.retroachievements.org/Images/011803.png', 'https://media.retroachievements.org/Images/067422.png', 'https://media.retroachievements.org/Images/067423.png', 4.4),
  (30, 1453, 'Zelda II: The Adventure of Link', 'NES/Famicom', 7, 6241, 6241, 6241, 44, 0, 'Action RPG', NULL, 'Nintendo', '1988-09-26', 'Zelda II: The Adventure of Link is a 1987 action role-playing game developed and published by Nintendo. It is the second installment in the Legend of Zelda series, and was released in Japan for the Famicom Disk System on January 14, 1987, less than a year after the Japanese release and seven months before the North American release of the original The Legend of Zelda. Zelda II was released in North America and the PAL region for the Nintendo Entertainment System in late 1988, almost two years after its initial release in Japan.', 'https://media.retroachievements.org/Images/069648.png', 'https://media.retroachievements.org/Images/012472.png', 'https://media.retroachievements.org/Images/106032.png', 'https://media.retroachievements.org/Images/106033.png', 4.4),
  (31, 1683, 'Felix the Cat', 'NES/Famicom', 7, 5977, 5977, 5977, 65, 0, '2D Platforming', 'Hudson Soft', 'Hudson Soft', '1992-10-01', 'Felix the Cat is a cartoon character created in 1919 by Otto Messmer and Pat Sullivan during the silent film era. An anthropomorphic young black cat with white eyes, a black body, and a giant grin, he is often considered one of the most recognized cartoon characters in history. Felix was the first fully realized recurring animal character in the history of American film animation.', 'https://media.retroachievements.org/Images/064424.png', 'https://media.retroachievements.org/Images/012128.png', 'https://media.retroachievements.org/Images/001946.png', 'https://media.retroachievements.org/Images/003891.png', 4.4),
  (32, 1461, 'Castlevania II: Simon''s Quest', 'NES/Famicom', 7, 5856, 5856, 5856, 44, 0, 'Metroidvania, 2D Platforming', 'Konami', 'Konami', '1987-08-28', 'Castlevania II: Simon''s Quest is a 1987 action role-playing game developed and published by Konami. It was originally released in Japan in 1987 for the Famicom Disk System, and in North America in 1988 for the Nintendo Entertainment System. It is the second Castlevania game released for the NES, following the original Castlevania (1986). Set seven years after the events of the first installment, the player once again assumes the role of vampire hunter Simon Belmont, who is on a journey to undo a curse placed on him by Dracula at the end of their previous encounter. Dracula''s body was split into five parts, which Simon must find and bring to the ruins of Castle Dracula in order to defeat him. The game deviates from the traditional platforming of its predecessor, incorporating role-playing and open world elements.', 'https://media.retroachievements.org/Images/079970.png', 'https://media.retroachievements.org/Images/071770.png', 'https://media.retroachievements.org/Images/039560.png', 'https://media.retroachievements.org/Images/039561.png', 4.4),
  (33, 4568, 'Bomberman', 'NES/Famicom', 7, 5627, 5627, 5627, 48, 0, 'Action', 'Hudson Soft', 'Hudson Soft', '1985-12-19', 'Bomberman  is a video game franchise created by Shinichi Nakamoto and Shigeki Fujiwara, originally developed by Hudson Soft and currently owned by Konami. The original game, also known as Bakudan Otoko, was released in Japan in July 1983 and has since spawned multiple sequels and spin-offs released on numerous platforms, as well as several anime and manga adaptations.', 'https://media.retroachievements.org/Images/034605.png', 'https://media.retroachievements.org/Images/011705.png', 'https://media.retroachievements.org/Images/004958.png', 'https://media.retroachievements.org/Images/004959.png', 4.4),
  (34, 1516, '1943: The Battle of Midway', 'NES/Famicom', 7, 5468, 5468, 5468, 30, 0, 'Shoot ''em Up', 'Capcom', 'Capcom', '1987-06-01', '1943: The Battle of Midway is a 1987 vertically scrolling shooter video game developed and published by Capcom for arcades. It was the first follow-up to Capcom''s earlier 1942. Like 1942, the player controls Americans attacking the Japanese air fleet; this was due to being one of the first Capcom games designed with Western markets in mind. The game''s name is a reference to the Battle of Midway, which occurred in June 1942.', 'https://media.retroachievements.org/Images/045843.png', 'https://media.retroachievements.org/Images/011489.png', 'https://media.retroachievements.org/Images/035322.png', 'https://media.retroachievements.org/Images/035323.png', 4.4),
  (35, 1710, 'Ghosts ''n Goblins', 'NES/Famicom', 7, 5342, 5342, 5342, 26, 0, '2D Platforming', 'Micronics', 'Capcom', '1986-06-13', 'Ghosts ''n Goblins, known in Japan as Makaimura , is a series of run-and-gun platform video games developed and owned by Capcom. The first entry in the series was Ghosts ''n Goblins, released in arcades on July 7, 1985. The series has subsequently been ported to and released on a variety of personal computers, game consoles and mobile platforms and spawned several sequels and spin-offs.', 'https://media.retroachievements.org/Images/042742.png', 'https://media.retroachievements.org/Images/012198.png', 'https://media.retroachievements.org/Images/113641.png', 'https://media.retroachievements.org/Images/113642.png', 4.4),
  (36, 1491, 'Pac-Man', 'NES/Famicom', 7, 5277, 5277, 5277, 12, 0, NULL, 'Namco', 'Namco', '1984-11-02', 'Pac-Man, originally titled Puck Man in Japan, is a 1980 maze video game developed and published by Namco for arcades. It was released in Japan on May 22, 1980 and by Midway Manufacturing in North America in August 1980. The player controls Pac-Man, who must eat all the dots inside an enclosed maze while avoiding four colored ghosts. Eating large flashing dots called Power Pellets causes the ghosts to temporarily turn blue and vulnerable, allowing Pac-Man to eat the ghosts for bonus points.', 'https://media.retroachievements.org/Images/039727.png', 'https://media.retroachievements.org/Images/115585.png', 'https://media.retroachievements.org/Images/001776.png', 'https://media.retroachievements.org/Images/001777.png', 4.4),
  (37, 1480, 'Kung Fu', 'NES/Famicom', 7, 4759, 4759, 4759, 22, 0, 'Beat ''em Up', 'Nintendo', 'Nintendo', '1985-06-21', 'Chinese martial arts, commonly referred to with umbrella terms kung fu, kuoshu or wushu, are multiple fighting styles that have developed over the centuries in Greater China. These fighting styles are often classified according to common traits, identified as families of martial arts. Examples of such traits include Shaolinquan (少林拳) physical exercises involving Five Animals (五形) mimicry or training methods inspired by Old Chinese philosophies, religions and legends. Styles that focus on qi manipulation are called internal, while others that concentrate on improving muscle and cardiovascular fitness are called external. Geographical associations, as in northern and southern, is another popular classification method.', 'https://media.retroachievements.org/Images/049484.png', 'https://media.retroachievements.org/Images/012383.png', 'https://media.retroachievements.org/Images/000686.png', 'https://media.retroachievements.org/Images/000685.png', 4.3),
  (38, 1478, 'Kid Icarus', 'NES/Famicom', 7, 4724, 4724, 4724, 33, 0, '2D Platforming', NULL, 'Nintendo', '1986-12-19', 'Kid Icarus is a 1986 action-platform game developed and published by Nintendo for the Family Computer Disk System in Japan and the Nintendo Entertainment System in Europe and North America. It was released in Japan in December 1986, in Europe in February 1987, and in North America in July.', 'https://media.retroachievements.org/Images/099524.png', 'https://media.retroachievements.org/Images/012373.png', 'https://media.retroachievements.org/Images/073052.png', 'https://media.retroachievements.org/Images/002161.png', 4.3),
  (39, 1989, 'Super Contra', 'NES/Famicom', 7, 4506, 4506, 4506, 43, 0, '2D Platforming, Run & Gun', 'Konami', 'Konami', '1990-02-02', 'Super Contra, known as Super Contra: The Alien Strikes Back in Japan, is a 1988 run and gun game developed and published by Konami for arcades. It is the sequel to the original Contra and part of the Contra series. The game stars Bill Rizer and Lance Bean as they are sent to thwart another alien invasion from the vicious Red Falcon.', 'https://media.retroachievements.org/Images/125066.png', 'https://media.retroachievements.org/Images/013083.png', 'https://media.retroachievements.org/Images/124970.png', 'https://media.retroachievements.org/Images/124968.png', 4.3),
  (40, 1838, 'Mighty Final Fight', 'NES/Famicom', 7, 4496, 4496, 4496, 45, 0, 'Beat ''em Up', 'Capcom', 'Capcom', '1993-06-11', 'Mighty Final Fight is a 1993 beat ''em up game developed and published by Capcom for the Nintendo Entertainment System. It is a spinoff of Capcom''s 1989 arcade game Final Fight, which was previously ported to the Super NES. Unlike the CP System arcade classic and its SNES ports, the characters in this edition are depicted in a comical childlike super deformed or chibi art style in the same spirit as Famicom games such as both Konami''s Kid Dracula and Namco''s Splatterhouse: Wanpaku Graffiti.', 'https://media.retroachievements.org/Images/076392.png', 'https://media.retroachievements.org/Images/014613.png', 'https://media.retroachievements.org/Images/035310.png', 'https://media.retroachievements.org/Images/014614.png', 4.3),
  (41, 1586, 'Bomberman II', 'NES/Famicom', 7, 4469, 4469, 4469, 33, 0, 'Action', 'Hudson Soft', 'Hudson Soft', '1991-06-28', 'Bomberman II, released in Europe and Australia as Dynablaster, is a maze video game developed and published by Hudson Soft for the Nintendo Entertainment System originally in Japan and Europe in 1991 and later in North America in February 1993. The Japanese version was re-released in 2026 as part of the Super Bomberman Collection compilation.', 'https://media.retroachievements.org/Images/060230.png', 'https://media.retroachievements.org/Images/011706.png', 'https://media.retroachievements.org/Images/005457.png', 'https://media.retroachievements.org/Images/005458.png', 4.3),
  (42, 1464, 'Darkwing Duck', 'NES/Famicom', 7, 4444, 4444, 4444, 56, 0, '2D Platforming', 'Capcom', 'Capcom', '1992-06-01', 'Darkwing Duck is an American animated superhero comedy television series produced by Disney Television Animation that first ran from 1991 to 1992 on both the syndicated programming block The Disney Afternoon and Saturday mornings on ABC. A total of ninety-one episodes were aired. It features the adventures of Darkwing Duck, who is the superheroic alter-ego of ordinary suburban duck Drake Mallard.', 'https://media.retroachievements.org/Images/043239.png', 'https://media.retroachievements.org/Images/011901.png', 'https://media.retroachievements.org/Images/039563.png', 'https://media.retroachievements.org/Images/039564.png', 4.3),
  (43, 1518, 'Abadox: The Deadly Inner War', 'NES/Famicom', 7, 4363, 4363, 4363, 28, 0, 'Shoot ''em Up', 'Natsume', 'Natsume, Milton Bradley', '1989-12-15', 'Abadox: The Deadly Inner War  is a horizontally scrolling shooter for the Nintendo Entertainment System published in Japan in 1989 by Natsume and North America in 1990 by Milton Bradley Company. It is in the vein of Gradius and R-Type, taking place inside the intestinal tract of a giant alien organism. Abadox has a high difficulty, and it takes one hit from an enemy projectile to be killed and restart from a checkpoint passed before death.', 'https://media.retroachievements.org/Images/047160.png', 'https://media.retroachievements.org/Images/016785.png', 'https://media.retroachievements.org/Images/016787.png', 'https://media.retroachievements.org/Images/016788.png', 4.3),
  (44, 2420, 'Battle City', 'NES/Famicom', 7, 4338, 4338, 4338, 18, 0, NULL, 'Namco', 'Namco', '1985-09-09', 'Battle City is a 1985 multidirectional shooter video game developed and published by Namco for the Family Computer. Released only in Japan, it is the sequel to the arcade game Tank Battalion.', 'https://media.retroachievements.org/Images/047830.png', 'https://media.retroachievements.org/Images/113995.png', 'https://media.retroachievements.org/Images/113994.png', 'https://media.retroachievements.org/Images/113993.png', 4.3),
  (45, 1669, 'Duck Hunt', 'NES/Famicom', 7, 4328, 4328, 4328, 31, 0, 'Gallery Shooter, Sports - Hunting', 'Nintendo, Intelligent Systems', 'Nintendo', '1984-04-21', 'Duck Hunt is a 1984 light gun shooter video game developed and published by Nintendo for the Nintendo Entertainment System (NES). The game was first released in April 1984 in Japan for the Family Computer (Famicom) console and in North America as an arcade game for the Nintendo VS. System. It became a launch game for the NES in North America in October 1985, and was re-released in Europe two years later. Players fire the NES Zapper at a CRT television, with three attempts per round to shoot ducks and clay pigeons.', 'https://media.retroachievements.org/Images/121810.png', 'https://media.retroachievements.org/Images/101226.png', 'https://media.retroachievements.org/Images/109505.png', 'https://media.retroachievements.org/Images/109506.png', 4.3),
  (46, 1449, 'Final Fantasy', 'NES/Famicom', 7, 4320, 4320, 4320, 40, 0, NULL, 'Square', 'Squaresoft, Nintendo', '1987-12-18', 'Final Fantasy is a Japanese fantasy anthology media franchise created by Hironobu Sakaguchi which is owned, developed, and published by Square Enix. The franchise centers on a series of fantasy role-playing video games. The first game in the series was released in 1987, with 16 numbered main entries having been released to date.', 'https://media.retroachievements.org/Images/113206.png', 'https://media.retroachievements.org/Images/012134.png', 'https://media.retroachievements.org/Images/000525.png', 'https://media.retroachievements.org/Images/000526.png', 4.3),
  (47, 1824, 'Mario Bros.', 'NES/Famicom', 7, 4297, 4297, 4297, 20, 0, '2D Platforming', 'Intelligent Systems', 'Nintendo', '1983-09-09', 'Mario Bros. is a 1983 platform game developed and published by Nintendo for arcades. It was designed by Shigeru Miyamoto and Gunpei Yokoi, Nintendo''s chief engineer. Players control Italian twin brother plumbers Mario and Luigi as they exterminate turtle-like creatures, giant flies, and crabs emerging from the sewers of New York City by knocking them upside-down and kicking them away. The Famicom/NES version was the first game to be developed by Intelligent Systems. It is part of the Mario franchise and the first spin-off of the Donkey Kong series.', 'https://media.retroachievements.org/Images/117055.png', 'https://media.retroachievements.org/Images/065277.png', 'https://media.retroachievements.org/Images/001924.png', 'https://media.retroachievements.org/Images/001925.png', 4.3),
  (48, 1823, 'Marble Madness', 'NES/Famicom', 7, 4290, 4290, 4290, 15, 0, 'Puzzle, Action', 'Rare', 'Milton Bradley', '1989-03-01', 'Marble Madness is a 1984 platform game designed by Mark Cerny and published by Atari Games Inc. for arcades. Set in an isometric perspective, the game tasks the player with guiding a marble through six courses, populated with obstacles and enemies, within a time limit. The player controls the marble by using a trackball. Marble Madness is known for using innovative game technologies: it was Atari''s first to use the Atari System 1 hardware, the first to be programmed in the C programming language, and one of the first to use true stereo sound.', 'https://media.retroachievements.org/Images/004707.png', 'https://media.retroachievements.org/Images/012793.png', 'https://media.retroachievements.org/Images/002014.png', 'https://media.retroachievements.org/Images/002015.png', 4.3),
  (49, 1452, 'River City Ransom', 'NES/Famicom', 7, 4278, 4278, 4278, 48, 0, 'Action RPG, Beat ''em Up', 'Technōs Japan', 'Infogrames, Technōs Japan', '1989-04-25', 'Downtown Nekketsu Monogatari, released as River City Ransom in North America and Street Gangs in PAL regions, is a 1989 action-adventure beat ''em up video game developed and published by Technōs Japan for the Nintendo Entertainment System. It is the third installment of the Kunio-kun series released for the NES, preceded by Renegade and Super Dodge Ball, and the first to be developed specifically for the system.', 'https://media.retroachievements.org/Images/072198.png', 'https://media.retroachievements.org/Images/012929.png', 'https://media.retroachievements.org/Images/004350.png', 'https://media.retroachievements.org/Images/004351.png', 4.3),
  (50, 1661, 'Double Dragon II: The Revenge', 'NES/Famicom', 7, 4274, 4274, 4274, 28, 0, 'Beat ''em Up', 'Technōs Japan', 'Acclaim, Technōs Japan', '1989-12-22', 'Double Dragon II: The Revenge is a 1988 beat ''em up video game developed and published by Technōs Japan for arcades. It is the first sequel to Double Dragon, released during the previous year. The sequel involves Billy and Jimmy Lee in a mission to avenge Billy''s girlfriend Marian after she is shot to death by the Black Warriors leader Willy, who is retaliating against the Lee brothers after his defeat at the end of the previous game.', 'https://media.retroachievements.org/Images/077320.png', 'https://media.retroachievements.org/Images/011923.png', 'https://media.retroachievements.org/Images/039553.png', 'https://media.retroachievements.org/Images/039554.png', 4.3),
  (51, 1627, 'Color a Dinosaur', 'NES/Famicom', 7, 4074, 4074, 4074, 19, 0, 'Other', 'FarSight Studios', 'Virgin Interactive', '1993-07-01', 'Color a Dinosaur is a 1993 coloring book video game developed by FarSight Studios for the Nintendo Entertainment System. It was created with a budget of $30,000 and produced on the cheapest cartridge that Nintendo made, and only sold in Walmart.', 'https://media.retroachievements.org/Images/089844.png', 'https://media.retroachievements.org/Images/011850.png', 'https://media.retroachievements.org/Images/011851.png', 'https://media.retroachievements.org/Images/011852.png', 4.3),
  (52, 2115, 'Teenage Mutant Ninja Turtles III: The Manhattan Project', 'NES/Famicom', 7, 4014, 4014, 4014, 30, 0, 'Beat ''em Up', 'Konami', 'Konami', '1991-12-13', 'Teenage Mutant Ninja Turtles III: The Manhattan Project is a 1991 beat ''em up game developed and published by Konami for the Family Computer (Famicom) in Japan and for the Nintendo Entertainment System in North America in 1992. It is the third video game iteration of the Teenage Mutant Ninja Turtles for the NES. The game features play mechanics similar to the previous game, Teenage Mutant Ninja Turtles II: The Arcade Game, but it is an original title for the NES without any preceding arcade version. It is based on the 1987 Teenage Mutant Ninja Turtles animated series, being released after the show''s 5th season. The game was re-released as part of Teenage Mutant Ninja Turtles: The Cowabunga Collection in 2022.', 'https://media.retroachievements.org/Images/104332.png', 'https://media.retroachievements.org/Images/013121.png', 'https://media.retroachievements.org/Images/003126.png', 'https://media.retroachievements.org/Images/003127.png', 4.3),
  (53, 1829, 'Mega Man 4', 'NES/Famicom', 7, 3978, 3978, 3978, 80, 0, '2D Platforming', 'Capcom', 'Capcom', '1991-12-06', 'Mega Man 4 is a 1991 platform game developed and published by Capcom for the Nintendo Entertainment System. It is the fourth installment of the original Mega Man series and was originally released in Japan on December 6, 1991. The game was released in North America the following January, and in Europe in August 1993 by Nintendo.', 'https://media.retroachievements.org/Images/082509.png', 'https://media.retroachievements.org/Images/012785.png', 'https://media.retroachievements.org/Images/038661.png', 'https://media.retroachievements.org/Images/038662.png', 4.3),
  (54, 2023, '~Unlicensed~ Tetris (Tengen)', 'NES/Famicom', 7, 3969, 3969, 3969, 51, 0, NULL, 'Tengen', 'Tengen', '1989-01-01', 'Tetris is a puzzle video game created in 1985 by Alexey Pajitnov, a Soviet software engineer. In the game, falling tetromino shapes must be neatly sorted into a pile. Once a horizontal line of the board is filled in, the line disappears, granting points and preventing the pile from overflowing. Since its initial creation, this gameplay has been used in over 220 versions, released for over 70 platforms. Newer versions frequently implement additional game mechanics, some of which have become standard over time. As of December 2024, these versions collectively serve as the second-best-selling video game series with over 520 million sales, mostly on mobile devices.', 'https://media.retroachievements.org/Images/105570.png', 'https://media.retroachievements.org/Images/013577.png', 'https://media.retroachievements.org/Images/013574.png', 'https://media.retroachievements.org/Images/013576.png', 4.3),
  (55, 2114, 'Teenage Mutant Ninja Turtles II: The Arcade Game', 'NES/Famicom', 7, 3935, 3935, 3935, 28, 0, 'Beat ''em Up', 'Konami', 'Konami, Ultra Games', '1990-12-07', 'Teenage Mutant Ninja Turtles, released in Japan as Teenage Mutant Ninja Turtles: Super Kame Ninja and in Europe as Teenage Mutant Hero Turtles, is a 1989 beat ''em up video game developed and published by Konami for arcades. It is based on the Teenage Mutant Ninja Turtles franchise, including the first animated series that began airing two years earlier. In the game, up to four players control the titular Ninja Turtles, fighting through various levels to defeat the turtles'' enemies, including the Shredder, Krang and the Foot Clan. Released during a high point in popularity for the Teenage Mutant Ninja Turtles franchise, the arcade game was a worldwide hit, becoming the highest-grossing dedicated arcade game of 1990 in the United States and Konami''s highest-grossing arcade game. Versions for various home systems soon followed, including the Nintendo Entertainment System. A sequel, Teenage Mutant Ninja Turtles: Turtles in Time, was released in 1991.', 'https://media.retroachievements.org/Images/076385.png', 'https://media.retroachievements.org/Images/013120.png', 'https://media.retroachievements.org/Images/000747.png', 'https://media.retroachievements.org/Images/000748.png', 4.3),
  (56, 1877, 'Pinball', 'NES/Famicom', 7, 3766, 3766, 3766, 21, 0, 'Pinball', 'HAL Laboratory, Nintendo', 'Nintendo', '1984-02-02', 'Pinball games are a family of games in which a ball is propelled into a specially designed table where it bounces off various obstacles, scoring points either en-route or when it comes to rest. Historically the board was studded with nails called ''pins'' and had hollows or pockets which scored points if the ball came to rest in them. Today, pinball is most commonly an arcade game in which the ball is fired into a specially designed cabinet known as a pinball machine, hitting various lights, bumpers, ramps, and other targets depending on its design.', 'https://media.retroachievements.org/Images/074947.png', 'https://media.retroachievements.org/Images/013235.png', 'https://media.retroachievements.org/Images/004812.png', 'https://media.retroachievements.org/Images/004813.png', 4.3),
  (57, 1873, 'Paperboy', 'NES/Famicom', 7, 3739, 3739, 3739, 32, 0, 'Action', 'Eastridge Technology', 'Mindscape', '1988-12-01', 'A paperboy is someone – often an older child or adolescent – who distributes printed newspapers to homes or offices on a regular route, usually by bicycle or automobile. In Western nations during the heyday of print newspapers during the early 20th century, this was often a young person''s first job, perhaps undertaken before or after school. This contrasts with the newsboy or newspaper hawker, now extremely rare in Western nations, who would sell newspapers to passersby on the street, often with very vocal promotion. They were common when multiple daily papers in every city – as many as 50 in New York City alone – competed.', 'https://media.retroachievements.org/Images/079494.png', 'https://media.retroachievements.org/Images/012825.png', 'https://media.retroachievements.org/Images/044122.png', 'https://media.retroachievements.org/Images/044123.png', 4.3),
  (58, 1574, 'Battletoads and Double Dragon: The Ultimate Team', 'NES/Famicom', 7, 3651, 3651, 3651, 20, 0, 'Beat ''em Up', 'Rare', 'Tradewest, Nintendo', '1993-06-01', 'Battletoads/Double Dragon is a 1993 beat ''em up developed by Rare and published by Tradewest. It was originally released for the Nintendo Entertainment System and later ported to the Mega Drive/Genesis, Super NES, and Game Boy. The SNES version was released on the Nintendo Classics service in September 2024; it was the game''s first re-release as it was not released on the Rare Replay collection.', 'https://media.retroachievements.org/Images/053940.png', 'https://media.retroachievements.org/Images/011660.png', 'https://media.retroachievements.org/Images/006931.png', 'https://media.retroachievements.org/Images/006934.png', 4.3),
  (59, 1858, 'Ninja Gaiden III: The Ancient Ship of Doom', 'NES/Famicom', 7, 3628, 3628, 3628, 37, 0, '2D Platforming', 'Tecmo', 'Koei | Tecmo', '1991-08-01', 'Ninja Gaiden III: The Ancient Ship of Doom is a 1991 platform game developed and published by Tecmo for the Nintendo Entertainment System (NES). It was later ported to the Atari Lynx by Atari Corporation in 1993, and was also re-released as part of Tecmo''s Ninja Gaiden Trilogy Super NES compilation in 1995. Long after, it was released for the Virtual Console service in North America in 2008 for the Wii and in 2013 for the Nintendo 3DS. It was designed by Masato Kato, who took over for Hideo Yoshizawa, the designer of the first two games in the NES series.', 'https://media.retroachievements.org/Images/120888.png', 'https://media.retroachievements.org/Images/012661.png', 'https://media.retroachievements.org/Images/002632.png', 'https://media.retroachievements.org/Images/002631.png', 4.3),
  (60, 1857, 'Ninja Gaiden II: The Dark Sword of Chaos', 'NES/Famicom', 7, 3614, 3614, 3614, 59, 0, '2D Platforming', 'Tecmo', 'Koei | Tecmo', '1990-04-06', 'Ninja Gaiden II: The Dark Sword of Chaos, known in Europe as Shadow Warriors II: The Dark Sword of Chaos, is a 1990 hack and slash platform game developed and published by Tecmo for the Nintendo Entertainment System. It is the second installment in the Ninja Gaiden trilogy for the NES and was released in North America and Japan in 1990, and in Europe in 1992. An arcade version was released by Nintendo for their PlayChoice-10 system in 1990.', 'https://media.retroachievements.org/Images/120887.png', 'https://media.retroachievements.org/Images/012660.png', 'https://media.retroachievements.org/Images/035305.png', 'https://media.retroachievements.org/Images/031448.png', 4.3),
  (61, 1940, 'Shatterhand', 'NES/Famicom', 7, 3575, 3575, 3575, 53, 0, '2D Platforming, Action', 'Natsume', 'Jaleco', '1991-12-01', 'Shatterhand is a side-scrolling action game for the Nintendo Entertainment System developed by Natsume and published by Jaleco in North America in 1991 and in Europe in 1992. Shatterhand was originally released by Angel (Bandai) in Japan in 1991 as a licensed game for the Family Computer based on the live-action superhero series Super Rescue Solbrain .', 'https://media.retroachievements.org/Images/076867.png', 'https://media.retroachievements.org/Images/059634.png', 'https://media.retroachievements.org/Images/035571.png', 'https://media.retroachievements.org/Images/035570.png', 4.3),
  (62, 1800, 'Life Force', 'NES/Famicom', 7, 3462, 3462, 3462, 44, 0, 'Shoot ''em Up', 'Konami', 'Konami', '1987-08-01', 'Salamander, released as Life Force in North America and in the Japanese arcade re-release, is a 1986 scrolling shooter video game developed and published by Konami for arcades. A spin-off of the Gradius series, Salamander introduced a simplified power-up system, two-player cooperative gameplay and both horizontally and vertically scrolling stages. Some of these later became normal for future Gradius games. In Japanese, the title is written using ateji, which are kanji used for spelling foreign words that has been supplanted in everyday use by katakana. Contra, another game by Konami was also given this treatment, with its title written in Japanese as 魂斗羅.', 'https://media.retroachievements.org/Images/076911.png', 'https://media.retroachievements.org/Images/012449.png', 'https://media.retroachievements.org/Images/006096.png', 'https://media.retroachievements.org/Images/006097.png', 4.3),
  (63, 4720, 'Shadow of the Ninja', 'NES/Famicom', 7, 3415, 3415, 3415, 44, 0, '2D Platforming, Action', 'Natsume', 'Natsume, Taito', '1990-08-10', 'Shadow of the Ninja, originally released in Japan as Yami no Shigotonin Kage  and later released in Europe and Australia as Blue Shadow, is a 1990 hack and slash platform game developed and published by Natsume for the Nintendo Entertainment System. The game revolves around a pair of ninja sent to assassinate a dictator in a futuristic version of New York City. A port was planned for the Game Boy, but was released in a rebranded form as Ninja Gaiden Shadow. A remake, Shadow of the Ninja: Reborn, was released in 2024.', 'https://media.retroachievements.org/Images/060033.png', 'https://media.retroachievements.org/Images/124207.png', 'https://media.retroachievements.org/Images/048967.png', 'https://media.retroachievements.org/Images/048968.png', 4.2),
  (64, 13393, '~Homebrew~ Cookie Clicker', 'NES/Famicom', 7, 3381, 3381, 3381, 10, 0, 'Incremental', 'Damian Yerrick', 'Damian Yerrick', '2014-04-23', 'Cookie Clicker is a 2013 video game created by French programmer Julien Orteil Thiennot. It is an incremental game in which the user initially clicks a big cookie on the screen, earning 1 cookie per click. They can use earned cookies to purchase buildings that automatically produce cookies, alongside upgrades which can improve the efficiency of clicks and buildings. There are other mechanics allowing the user to earn cookies in various ways. The game lacks a conventional ending.', 'https://media.retroachievements.org/Images/109375.png', 'https://media.retroachievements.org/Images/019696.png', 'https://media.retroachievements.org/Images/109234.png', 'https://media.retroachievements.org/Images/109235.png', 4.2),
  (65, 1616, 'Chip ''n Dale: Rescue Rangers 2', 'NES/Famicom', 7, 3358, 3358, 3358, 48, 0, '2D Platforming', 'Capcom', 'Capcom', '1993-12-10', 'Chip ''n Dale Rescue Rangers 2 is a platform game released in December 1993 in Japan, and the following month in the United States. It is based on the Disney cartoon Chip ''n Dale Rescue Rangers, about Chip and Dale, two crime-fighting chipmunks. It is a sequel to the 1990 video game.', 'https://media.retroachievements.org/Images/104958.png', 'https://media.retroachievements.org/Images/011804.png', 'https://media.retroachievements.org/Images/005685.png', 'https://media.retroachievements.org/Images/005686.png', 4.2),
  (66, 1881, 'Popeye', 'NES/Famicom', 7, 3352, 3352, 3352, 40, 0, '2D Platforming, Maze Chase', NULL, 'Nintendo', '1983-07-15', 'Popeye the Sailor Man is a cartoon character created by Elzie Crisler Segar, first appearing on January 17, 1929, in the daily King Features comic strip Thimble Theatre. The strip was in its tenth year when Popeye made his debut, but the one-eyed sailor quickly became the lead character, and Thimble Theatre became one of King Features'' most popular properties during the early 1930s. Popeye became the suitor of longtime Thimble Theatre star Olive Oyl, and Segar introduced new supporting characters such as adopted son Swee''Pea and friend J. Wellington Wimpy, as well as foes like the Sea Hag and Bluto.', 'https://media.retroachievements.org/Images/065073.png', 'https://media.retroachievements.org/Images/013236.png', 'https://media.retroachievements.org/Images/003043.png', 'https://media.retroachievements.org/Images/003044.png', 4.2),
  (67, 1465, 'Donkey Kong Jr.', 'NES/Famicom', 7, 3300, 3300, 3300, 18, 0, '2D Platforming', NULL, 'Nintendo', '1983-07-15', 'Donkey Kong Jr. is a 1982 platform game developed and published by Nintendo for arcades. It is the sequel to 1981''s Donkey Kong, but with the roles reversed compared to its predecessor: Mario is now the villain and Donkey Kong Jr. is trying to save his kidnapped father. After its initial release in arcades, the game was ported to a variety of home consoles, including the Famicom/Nintendo Entertainment System. The game''s title is written as Donkey Kong Junior in the North American arcade version and various conversions to non-Nintendo systems.', 'https://media.retroachievements.org/Images/024531.png', 'https://media.retroachievements.org/Images/013233.png', 'https://media.retroachievements.org/Images/004983.png', 'https://media.retroachievements.org/Images/004984.png', 4.2),
  (68, 1486, 'Metal Gear', 'NES/Famicom', 7, 3261, 3261, 3261, 97, 0, 'Stealth', 'Konami', 'Ultra Games, Konami', '1988-06-01', 'Metal Gear  is a Japanese franchise of action-adventure stealth games created by Hideo Kojima. Developed and published by Konami, the first game, Metal Gear, was released in 1987 for MSX home computers. The player often takes control of a special forces operative, usually Solid Snake, who is typically assigned the task of finding the titular superweapon, Metal Gear, a bipedal walking tank (mecha) with the ability to launch nuclear weapons.', 'https://media.retroachievements.org/Images/048932.png', 'https://media.retroachievements.org/Images/012780.png', 'https://media.retroachievements.org/Images/009667.png', 'https://media.retroachievements.org/Images/118022.png', 4.2),
  (69, 4812, 'Circus Charlie', 'NES/Famicom', 7, 3228, 3228, 3228, 16, 0, '2D Platforming', 'Soft Pro', 'Konami', '1986-03-04', 'Circus Charlie is a 1984 action video game developed and published by Konami for arcades. It was released in North America by Centuri in March 1984 and in Japan in April 1984. The player controls a circus clown named Charlie in six different circus-themed minigames. It was released for MSX in the same year, followed by ports to the Famicom in 1986 by Soft Pro and the Commodore 64 in 1987.', 'https://media.retroachievements.org/Images/062600.png', 'https://media.retroachievements.org/Images/013737.png', 'https://media.retroachievements.org/Images/073455.png', 'https://media.retroachievements.org/Images/073456.png', 4.2),
  (70, 1636, 'Crystalis', 'NES/Famicom', 7, 3212, 3212, 3212, 43, 0, 'Action RPG', 'SNK', 'SNK', '1990-04-13', 'Crystalis is a 1990 action role-playing video game developed and published by SNK for the Nintendo Entertainment System. A port for the Game Boy Color developed by Nintendo Software Technology and published by Nintendo was released in 2000.', 'https://media.retroachievements.org/Images/123056.png', 'https://media.retroachievements.org/Images/115487.png', 'https://media.retroachievements.org/Images/001890.png', 'https://media.retroachievements.org/Images/001891.png', 4.2),
  (71, 2045, 'Track & Field', 'NES/Famicom', 7, 3205, 3205, 3205, 46, 0, 'Sports - Track & Field', 'Konami', 'Konami', '1987-04-01', 'Track and field is a sport that includes many different kinds of athletic contests that are based on running, jumping, and throwing. The name used in North America is derived from where the sport takes place, a running track and a grass field for the throwing and some of the jumping events. Track and field is categorized under the umbrella sport of athletics, which also includes road running, cross country running and race walking. Though the sense of athletics as a broader sport is not used in American English, outside of the United States the term athletics can either be used to mean just its track and field component or the entirety of the sport based on context.', 'https://media.retroachievements.org/Images/081063.png', 'https://media.retroachievements.org/Images/013170.png', 'https://media.retroachievements.org/Images/082761.png', 'https://media.retroachievements.org/Images/082762.png', 4.2),
  (72, 1477, 'Jackal', 'NES/Famicom', 7, 3137, 3137, 3137, 50, 0, NULL, 'Konami', 'Konami', '1988-09-01', 'Jackals are canids native to Africa and Eurasia. While the word jackal has historically been used for many canines of the subtribe canina, in modern use it most commonly refers to three species: the closely related black-backed jackal and side-striped jackal of Central and Southern Africa, and the golden jackal of south-central Europe and Asia. The African golden wolf was also formerly considered a jackal.', 'https://media.retroachievements.org/Images/063214.png', 'https://media.retroachievements.org/Images/012319.png', 'https://media.retroachievements.org/Images/035312.png', 'https://media.retroachievements.org/Images/035313.png', 4.2),
  (73, 1802, 'The Little Mermaid', 'NES/Famicom', 7, 3131, 3131, 3131, 17, 0, '2D Platforming', 'Capcom', 'Capcom', '1991-07-01', 'The Little Mermaid, sometimes translated in English as The Little Sea Maid, is a literary fairy tale written by Danish author Hans Christian Andersen. Originally published in 1837 as part of a collection of fairy tales for children, the story follows the journey of a young mermaid princess who is willing to give up her life in the sea as a mermaid to gain a human soul.', 'https://media.retroachievements.org/Images/043888.png', 'https://media.retroachievements.org/Images/012454.png', 'https://media.retroachievements.org/Images/002608.png', 'https://media.retroachievements.org/Images/002607.png', 4.2),
  (74, 1485, 'Mega Man 6', 'NES/Famicom', 7, 3108, 3108, 3108, 92, 0, '2D Platforming', 'Capcom', 'Capcom, Nintendo', '1993-11-05', 'Mega Man 6, known in Japan as Rockman 6: The Greatest Battle in History!!, is a 1993 platform game developed and published by Capcom for the Nintendo Entertainment System. It is the sixth installment in the original Mega Man series. It was originally released in Japan by Capcom in 1993, and in North America by Nintendo in 1994. It was included in the Mega Man Anniversary Collection released in 2004. Its first release in Europe and PAL region was June 11, 2013, for the Virtual Console on the Nintendo 3DS, nearly twenty years after the game''s initial release.', 'https://media.retroachievements.org/Images/082511.png', 'https://media.retroachievements.org/Images/116245.png', 'https://media.retroachievements.org/Images/038575.png', 'https://media.retroachievements.org/Images/038576.png', 4.2),
  (75, 1582, 'Blades of Steel', 'NES/Famicom', 7, 3077, 3077, 3077, 47, 0, NULL, 'Konami, Novotrade', 'Konami', '1988-12-01', 'Blades of Steel, later released in Japan as Konamic Ice Hockey , is an ice hockey video game released by Konami for North American arcades in 1987, and ported to the Family Computer Disk System and Nintendo Entertainment System in 1988. All teams are fictional but based out of real Canadian and American cities. The game is known for its fast-paced hockey action and especially for the fighting. It is a one or two player game. When playing against the computer, there are three difficulty levels to choose from: Junior, College, and Pro. Each team consists of three forwards, two defencemen, and a goaltender.', 'https://media.retroachievements.org/Images/054335.png', 'https://media.retroachievements.org/Images/011690.png', 'https://media.retroachievements.org/Images/002180.png', 'https://media.retroachievements.org/Images/002181.png', 4.2),
  (76, 1533, 'Adventures of Lolo', 'NES/Famicom', 7, 3045, 3045, 3045, 24, 0, 'Action, Puzzle', 'HAL Laboratory', 'HAL Laboratory', '1989-04-20', 'Adventures of Lolo is a 1989 puzzle video game developed and published by HAL Laboratory for the Nintendo Entertainment System. It is a compilation of puzzles from Eggerland: Meikyū no Fukkatsu and Eggerland: Sōzō he no Tabidachi. It is the fifth game in the Eggerland series, the third one released in Europe, but the first one released in North America. It was available on the Wii''s and Wii U''s Virtual Console in North America and in PAL regions, as well as on the Nintendo Switch''s Nintendo Classics service.', 'https://media.retroachievements.org/Images/116061.png', 'https://media.retroachievements.org/Images/011525.png', 'https://media.retroachievements.org/Images/004917.png', 'https://media.retroachievements.org/Images/004918.png', 4.2),
  (77, 1511, '3-D World Runner', 'NES/Famicom', 7, 3022, 3022, 3022, 30, 0, 'Action, Rail Shooter', 'Square', 'Acclaim', '1987-09-01', 'The 3-D Battles of WorldRunner, originally released in Japan as Tobidase Daisakusen, is a 1987 third-person rail shooter platform video game developed and published by Square for the Family Computer Disk System. It was later ported to cartridge format and published by Acclaim for the Nintendo Entertainment System.', 'https://media.retroachievements.org/Images/043935.png', 'https://media.retroachievements.org/Images/003503.png', 'https://media.retroachievements.org/Images/002044.png', 'https://media.retroachievements.org/Images/002043.png', 4.2),
  (78, 1729, 'Gun.Smoke', 'NES/Famicom', 7, 2978, 2978, 2978, 16, 0, 'Shoot ''em Up', 'Capcom', 'Capcom', '1985-11-01', 'Gun.Smoke is a 1985 vertically scrolling shooter video game developed and published by Capcom for arcades. Unique from other scrolling shooters games, Gun.Smoke features a human as the shooter instead of a spacecraft, in this case a character named Billie Bob, a bounty hunter going after the criminals of the Wild West. It was designed by Yoshiki Okamoto.', 'https://media.retroachievements.org/Images/063188.png', 'https://media.retroachievements.org/Images/012234.png', 'https://media.retroachievements.org/Images/004155.png', 'https://media.retroachievements.org/Images/004156.png', 4.2),
  (79, 1674, 'Elevator Action', 'NES/Famicom', 7, 2931, 2931, 2931, 9, 0, NULL, 'Micronics', 'Taito', '1987-08-01', 'Elevator Action is a 1983 shooter platform video game developed and published by Taito for arcades. The player assumes the role of a secret agent infiltrating a 30-story building from the roof, then descending to ground level via elevators and stairways. Enemy agents emerge from closed doors and shoot at the player. The goal is to collect secret documents from specially marked rooms, then exit to a waiting getaway car. It runs on the Taito SJ System arcade system.', 'https://media.retroachievements.org/Images/045957.png', 'https://media.retroachievements.org/Images/012103.png', 'https://media.retroachievements.org/Images/007313.png', 'https://media.retroachievements.org/Images/007314.png', 4.2),
  (80, 1758, 'Jackie Chan''s Action Kung Fu', 'NES/Famicom', 7, 2915, 2915, 2915, 24, 0, '2D Platforming', 'Now Production', 'Hudson Soft', '1990-12-01', 'Jackie Chan''s Action Kung Fu  is an action-platform video game developed by Now Production and published by Hudson Soft. It was released for the Nintendo Entertainment System in 1990 and for the TurboGrafx-16 in 1991.', 'https://media.retroachievements.org/Images/076909.png', 'https://media.retroachievements.org/Images/012320.png', 'https://media.retroachievements.org/Images/001743.png', 'https://media.retroachievements.org/Images/001744.png', 4.2),
  (81, 1722, 'Gradius', 'NES/Famicom', 7, 2897, 2897, 2897, 37, 0, 'Shoot ''em Up', 'Konami', 'Konami', '1986-01-01', 'Gradius  is a series of shooter video games, introduced in 1985, developed and published by Konami for a variety of portable, console and arcade platforms. In many games in the series, the player controls a ship known as the Vic Viper.', 'https://media.retroachievements.org/Images/063179.png', 'https://media.retroachievements.org/Images/012218.png', 'https://media.retroachievements.org/Images/001865.png', 'https://media.retroachievements.org/Images/001866.png', 4.2),
  (82, 4036, 'Road Fighter', 'NES/Famicom', 7, 2896, 2896, 2896, 61, 0, 'Arcade Racing', 'Konami', 'Konami', '1985-07-11', 'Road Fighter is a 1984 racing video game developed and published by Konami for arcades. The goal is to reach the finish line within the stages without running out of time, hitting other cars or running out of fuel. The game spawned a spiritual successor, Konami GT (1986), and two sequels, Midnight Run: Road Fighter 2 (1995) and Winding Heat (1996). A Japan-only sequel was also released 14 years later, Road Fighters (2010).', 'https://media.retroachievements.org/Images/077447.png', 'https://media.retroachievements.org/Images/013855.png', 'https://media.retroachievements.org/Images/002955.png', 'https://media.retroachievements.org/Images/002956.png', 4.2),
  (83, 1662, 'Double Dragon III: The Sacred Stones', 'NES/Famicom', 7, 2749, 2749, 2749, 30, 0, 'Beat ''em Up', 'Technōs Japan', 'Acclaim, Technōs Japan', '1991-02-01', 'Double Dragon III: The Sacred Stones, released in Japan as Double Dragon III: The Rosetta Stone (ダブルドラゴンIII　ザ・ロゼッタストーン), is a 1991 beat ''em up video game developed by Technōs Japan for the Nintendo Entertainment System. It was the third Double Dragon game for the NES, and was published in North America and Europe by Acclaim Entertainment. Although it loosely based on the similarly titled arcade game Double Dragon 3: The Rosetta Stone, it is not a port, but a parallel project that was developed at the same time.', 'https://media.retroachievements.org/Images/035269.png', 'https://media.retroachievements.org/Images/012005.png', 'https://media.retroachievements.org/Images/035318.png', 'https://media.retroachievements.org/Images/035317.png', 4.2),
  (84, 1705, 'Gauntlet', 'NES/Famicom', 7, 2727, 2727, 2727, 17, 0, 'Action', 'Tengen', 'Tengen', '1988-07-01', 'Gauntlet is a 1985 hack and slash video game developed and published by Atari Games for arcades. It is one of the first multiplayer dungeon crawl arcade games. The core design of Gauntlet comes from the 1983 game Dandy for the Atari 8-bit computers, which resulted in a threat of legal action. It also has similarities to the 1983 maze game Time Bandit.', 'https://media.retroachievements.org/Images/048455.png', 'https://media.retroachievements.org/Images/012180.png', 'https://media.retroachievements.org/Images/002293.png', 'https://media.retroachievements.org/Images/002294.png', 4.2),
  (85, 1474, 'Friday the 13th', 'NES/Famicom', 7, 2698, 2698, 2698, 23, 0, 'Survival Horror', 'Atlus', 'LJN Entertainment', '1989-02-01', 'Friday the 13th is considered an unlucky day in Western superstition. It occurs when the 13th day of the month in the Gregorian calendar falls on a Friday, which happens at least once every year but can occur up to three times in the same year. For a month to have a Friday the 13th, the first day of the month must be a Sunday.', 'https://media.retroachievements.org/Images/062848.png', 'https://media.retroachievements.org/Images/012166.png', 'https://media.retroachievements.org/Images/018308.png', 'https://media.retroachievements.org/Images/000402.png', 4.2),
  (86, 2175, 'Dig Dug', 'NES/Famicom', 7, 2670, 2670, 2670, 30, 0, 'Arcade', 'Namco', 'Namco', '1985-06-04', 'Dig Dug is a 1982 maze video game developed and published by Namco for Japanese and European arcades; it was distributed by Atari, Inc. in North America. The player digs underground tunnels to attack enemies in each level, by either inflating them to bursting or crushing them underneath rocks.', 'https://media.retroachievements.org/Images/079387.png', 'https://media.retroachievements.org/Images/115469.png', 'https://media.retroachievements.org/Images/078836.png', 'https://media.retroachievements.org/Images/078837.png', 4.2),
  (87, 5783, 'Akumajou Densetsu', 'NES/Famicom', 7, 2636, 2636, 2636, 80, 0, '2D Platforming', 'Konami', 'Konami', '1989-12-22', 'Castlevania III: Dracula''s Curse is a 1989 platform game developed and published by Konami for the Nintendo Entertainment System. It was released on December 22, 1989 in Japan, September 19, 1990 in North America and in May 1992 in PAL regions by Konami''s Palcom publishing label.', 'https://media.retroachievements.org/Images/088318.png', 'https://media.retroachievements.org/Images/070749.png', 'https://media.retroachievements.org/Images/035703.png', 'https://media.retroachievements.org/Images/035705.png', 4.2),
  (88, 1600, 'BurgerTime', 'NES/Famicom', 7, 2589, 2589, 2589, 20, 0, NULL, 'Data East', 'Data East, Namco', '1985-11-27', 'BurgerTime is an arcade video game by Data East released in 1982. According to a former Data East programmer, the game was designed in-house but the development itself was outsourced to another company.', 'https://media.retroachievements.org/Images/050769.png', 'https://media.retroachievements.org/Images/011740.png', 'https://media.retroachievements.org/Images/004672.png', 'https://media.retroachievements.org/Images/004673.png', 4.2),
  (89, 1525, 'Adventure Island III', 'NES/Famicom', 7, 2567, 2567, 2567, 42, 0, '2D Platforming', 'Now Production', 'Hudson Soft', '1992-09-01', 'Adventure Island 3 is a side-scrolling platform game published by Hudson Soft that was originally released for the Nintendo Entertainment System in 1992. It is the third game in the Adventure Island series released for the NES. Like Adventure Island II (1991), it was developed by Now Production. Adventure Island 3 involves Master Higgins rescuing Jeannie Jungle who has been captured by Aliens. He seeks the kidnappers out through various islands with the help of his dinosaur friends.', 'https://media.retroachievements.org/Images/045847.png', 'https://media.retroachievements.org/Images/011518.png', 'https://media.retroachievements.org/Images/001608.png', 'https://media.retroachievements.org/Images/001609.png', 4.2),
  (90, 1670, 'DuckTales 2', 'NES/Famicom', 7, 2562, 2562, 2562, 74, 0, '2D Platforming', 'Capcom', 'Capcom', '1993-04-23', 'DuckTales 2 is a 1993 platform game developed and published by Capcom for the Nintendo Entertainment System. The game was ported to the Game Boy handheld system in Japan and North America the same year. DuckTales 2 is a sequel to DuckTales, and is based on the Disney''s animated TV series of the same name. Just like in the 1989 predecessor, the story involves Scrooge McDuck traveling around the globe collecting treasure. The player can freely choose levels to explore, similar to Mega Man series. The game also features new elements like option to revisit a level or additional collecting pieces of a map of the lost treasure of McDuck.', 'https://media.retroachievements.org/Images/112004.png', 'https://media.retroachievements.org/Images/012037.png', 'https://media.retroachievements.org/Images/003906.png', 'https://media.retroachievements.org/Images/003907.png', 4.2),
  (91, 1985, 'StarTropics', 'NES/Famicom', 7, 2544, 2544, 2544, 28, 0, 'Action-Adventure', NULL, 'Nintendo', '1990-12-01', 'StarTropics is a 1990 action-adventure video game developed and published by Nintendo for the Nintendo Entertainment System. Unlike most of Nintendo''s games, it was never released in Japan, and was released only in North America and Europe. The story follows teenager Mike Jones as he embarks on a quest to rescue his uncle. Gameplay involves exploring settlements and navigating dungeons to progress.', 'https://media.retroachievements.org/Images/074641.png', 'https://media.retroachievements.org/Images/013071.png', 'https://media.retroachievements.org/Images/001546.png', 'https://media.retroachievements.org/Images/001547.png', 4.2),
  (92, 1553, 'Bad Dudes', 'NES/Famicom', 7, 2543, 2543, 2543, 30, 0, 'Beat ''em Up', 'Data East', 'Data East, Imagine Software', '1990-07-01', 'Bad Dudes Vs. DragonNinja, also known simply as either Bad Dudes or DragonNinja, is a side-scrolling cooperative beat ''em up developed and released by Data East as an arcade video game in 1988. It was ported to computer and game console home systems.', 'https://media.retroachievements.org/Images/080013.png', 'https://media.retroachievements.org/Images/042109.png', 'https://media.retroachievements.org/Images/000763.png', 'https://media.retroachievements.org/Images/035321.png', 4.2),
  (93, 2101, 'Yoshi''s Cookie', 'NES/Famicom', 7, 2458, 2458, 2458, 43, 0, 'Tile Matching', 'TOSE', 'Nintendo', '1992-11-21', 'Yoshi''s Cookie is a 1992 tile-matching puzzle video game developed by Tose and published by Nintendo for the NES and Game Boy platforms in 1992. A Super NES version was released the following year, developed and published by Bullet-Proof Software.', 'https://media.retroachievements.org/Images/049673.png', 'https://media.retroachievements.org/Images/012479.png', 'https://media.retroachievements.org/Images/000286.png', 'https://media.retroachievements.org/Images/000289.png', 4.2),
  (94, 2140, 'Splatterhouse: Wanpaku Graffiti', 'NES/Famicom', 7, 2426, 2426, 2426, 20, 0, '2D Platforming, Action', 'Now Production', 'Namco', '1989-07-01', 'Splatterhouse: Wanpaku Graffiti is a 1989 action-platform video game developed by Now Production and published by Namco for the Family Computer. It was originally released only in Japan, although it saw a localized Western release in 2020 as part of the Namco Museum Archives Vol. 1 compilation. It is the second game in the Splatterhouse series, and the first to be released for a home console. The game is a parody of the original Splatterhouse, and takes a comical approach to its presentation, featuring super deformed characters as well as parodies of horror films and other pop culture references related to the genre.', 'https://media.retroachievements.org/Images/065136.png', 'https://media.retroachievements.org/Images/000708.png', 'https://media.retroachievements.org/Images/000873.png', 'https://media.retroachievements.org/Images/000874.png', 4.2),
  (95, 1760, 'Jaws', 'NES/Famicom', 7, 2384, 2384, 2384, 24, 0, 'Action', 'Westone Bit Entertainment', 'LJN Entertainment', '1987-01-01', 'Jaws is a video game for the Nintendo Entertainment System that is loosely based on the film franchise of the same name, specifically Jaws: The Revenge, the fourth and final film in the series. The box art is modeled heavily after the theatrical poster, and the back of the box mentions ...like it''s personal, perhaps as a reference to said movie''s tagline. However, the game does take elements from the first film. It is one of several LJN-published titles produced by the Japanese company Atlus, although Westone was subcontracted to actually develop it.', 'https://media.retroachievements.org/Images/059290.png', 'https://media.retroachievements.org/Images/012324.png', 'https://media.retroachievements.org/Images/002539.png', 'https://media.retroachievements.org/Images/003447.png', 4.2),
  (96, 1768, 'Journey to Silius', 'NES/Famicom', 7, 2384, 2384, 2384, 11, 0, 'Run & Gun', 'Tokai Engineering', 'Sunsoft', '1990-08-10', 'Journey to Silius, known in Japan as Rough World , is a side-scrolling run and gun video game developed and published by Sunsoft for the Nintendo Entertainment System in 1990.', 'https://media.retroachievements.org/Images/113370.png', 'https://media.retroachievements.org/Images/012355.png', 'https://media.retroachievements.org/Images/000674.png', 'https://media.retroachievements.org/Images/000673.png', 4.2),
  (97, 2060, 'Vice: Project Doom', 'NES/Famicom', 7, 2375, 2375, 2375, 23, 0, '2D Platforming, Run & Gun', 'Aicom', 'Sammy', '1991-04-26', 'Vice: Project Doom is a 1991 action video game developed by Aicom and published by Sammy Corporation for the Nintendo Entertainment System. The game was released in Japan on April 26, 1991, and in North America in November 1991. Vice: Project Doom is a side-scrolling platformer with noticeable similarities to the Ninja Gaiden series for the NES, with the addition of gun shooting and driving segments as well. The player assumes the role of a secret agent who must uncover a conspiracy involving a new kind of alien substance. A Sega Mega Drive conversion titled Deep Scanner was in development, but never released. It was released on the Nintendo Classics service in August 2019 by Sega, as Sammy had retained the rights to the game prior to merging with Sega.', 'https://media.retroachievements.org/Images/004279.png', 'https://media.retroachievements.org/Images/012497.png', 'https://media.retroachievements.org/Images/035359.png', 'https://media.retroachievements.org/Images/035361.png', 4.2),
  (98, 1580, 'Bionic Commando', 'NES/Famicom', 7, 2253, 2253, 2253, 39, 0, '2D Platforming', 'Capcom', 'Capcom', '1988-07-01', 'Bionic Commando is a series of platform video games developed and owned by Capcom. Unique from other platformers, the player character is unable to jump, instead using a bionic arm to cross gaps and climb ledges. The player character, Nathan Rad Spencer, uses this as a grappling gun/hook to swing, climb and descend through levels. Seven games have been released, from the original 1987 Bionic Commando to 2011''s Bionic Commando Rearmed 2. The series is based in an alternate timeline in which Nazism is not completely eradicated following World War II.', 'https://media.retroachievements.org/Images/049930.png', 'https://media.retroachievements.org/Images/011684.png', 'https://media.retroachievements.org/Images/005492.png', 'https://media.retroachievements.org/Images/005493.png', 4.1),
  (99, 1657, 'Donkey Kong 3', 'NES/Famicom', 7, 2243, 2243, 2243, 29, 0, NULL, 'Nintendo', 'Nintendo', '1984-07-04', 'Donkey Kong 3 is a 1983 shoot ''em up video game developed and published by Nintendo for arcades. It is the third installment in the Donkey Kong series, following 1982''s Donkey Kong Jr. It was ported to the Family Computer in 1984, then in North America for the Nintendo Entertainment System in 1986. The gameplay departs from previous Donkey Kong games, and it stars an exterminator named Stanley instead of Mario. The game was a modest financial success in Japan, but its commercial failure in the United States was later cited by commentators as contributing to a period of reduced activity for the series until the release of Donkey Kong (1994) and Donkey Kong Country.', 'https://media.retroachievements.org/Images/024530.png', 'https://media.retroachievements.org/Images/013232.png', 'https://media.retroachievements.org/Images/010141.png', 'https://media.retroachievements.org/Images/010142.png', 4.1),
  (100, 2073, 'Where''s Waldo?', 'NES/Famicom', 7, 2200, 2200, 2200, 28, 0, 'Hidden Object', 'Bethesda Softworks', 'THQ', '1991-09-01', 'Where''s Wally? is a series of children''s puzzle books created by the English illustrator Martin Handford, first published on 25 June 1987. The books consist of a series of detailed double-page spread illustrations each depicting hundreds of people doing a variety of amusing things at a location. Readers are challenged to find a character named Wally and his friends hidden throughout the pages.', 'https://media.retroachievements.org/Images/059162.png', 'https://media.retroachievements.org/Images/012571.png', 'https://media.retroachievements.org/Images/012572.png', 'https://media.retroachievements.org/Images/012570.png', 4.1),
  (101, 1481, 'Lode Runner', 'NES/Famicom', 7, 2194, 2194, 2194, 64, 0, NULL, 'Brøderbund Software', 'Broderbund Software, Hudson Soft', '1984-07-31', 'Lode Runner is a puzzle-platform game developed by Doug Smith and published by Broderbund in 1983. Its gameplay mechanics are similar to Space Panic from 1980. The player controls a character who must collect all the gold pieces in a level and reach the end while being chased by a number of enemies. It is one of the first games to include a level editor.', 'https://media.retroachievements.org/Images/035825.png', 'https://media.retroachievements.org/Images/011277.png', 'https://media.retroachievements.org/Images/011275.png', 'https://media.retroachievements.org/Images/011276.png', 4.1),
  (102, 1547, 'Astyanax', 'NES/Famicom', 7, 2193, 2193, 2193, 35, 0, 'Action, 2D Platforming', 'Aicom', 'Jaleco', '1989-12-21', 'In Greek mythology, Astyanax was the son of Hector, the crown prince of Troy, and of his wife, Princess Andromache of Cilician Thebe. His birth name was Scamandrius, but the people of Troy nicknamed him Astyanax, because he was the son of the city''s great defender and the heir apparent''s firstborn son.', 'https://media.retroachievements.org/Images/048382.png', 'https://media.retroachievements.org/Images/011576.png', 'https://media.retroachievements.org/Images/039556.png', 'https://media.retroachievements.org/Images/039557.png', 4.1),
  (103, 1597, 'The Bugs Bunny Crazy Castle', 'NES/Famicom', 7, 2138, 2138, 2138, 39, 0, NULL, 'Kotobuki System', 'Kemco', '1989-08-01', 'The Bugs Bunny Crazy Castle, also known as simply Bugs Bunny, is a 1989 puzzle video game developed by Kemco for the Nintendo Entertainment System and Game Boy. It is the first puzzle game in Kemco''s Crazy Castle series.', 'https://media.retroachievements.org/Images/045914.png', 'https://media.retroachievements.org/Images/011734.png', 'https://media.retroachievements.org/Images/005106.png', 'https://media.retroachievements.org/Images/005107.png', 4.1),
  (104, 5790, 'Astérix', 'NES/Famicom', 7, 2114, 2114, 2114, 61, 0, '2D Platforming', 'Bit Managers', 'Infogrames', '1993-01-01', 'Asterix is a French comic album series about a Gaulish village which, thanks to a magic potion that enhances strength, resists the forces of Julius Caesar''s Roman Republic Army in the time after the Gallic Wars. Many adventures take the titular hero Asterix and his friend Obelix to Rome and beyond.', 'https://media.retroachievements.org/Images/085604.png', 'https://media.retroachievements.org/Images/013250.png', 'https://media.retroachievements.org/Images/008454.png', 'https://media.retroachievements.org/Images/008457.png', 4.1),
  (105, 1728, 'Gun Nac', 'NES/Famicom', 7, 2114, 2114, 2114, 23, 0, 'Shoot ''em Up', 'Compile', 'ASCII Entertainment', '1990-01-01', 'Gun-Nac  is a 1990 scrolling shooter video game developed by Compile for the Nintendo Entertainment System. The game was released in Japan by Tonkin House on October 5, 1990 and in North America by ASCII Corporation in September 1991.', 'https://media.retroachievements.org/Images/064470.png', 'https://media.retroachievements.org/Images/012233.png', 'https://media.retroachievements.org/Images/002175.png', 'https://media.retroachievements.org/Images/002176.png', 4.1),
  (106, 4559, 'Batman: Return of the Joker', 'NES/Famicom', 7, 2105, 2105, 2105, 21, 0, '2D Platforming, Run & Gun', 'Sunsoft', 'Sunsoft', '1991-12-20', 'Batman: Return of the Joker is a 1991 run and gun video game, the follow-up to Sunsoft''s first Batman game on the Nintendo Entertainment System. Unlike that game, which was based on the 1989 Batman film directed by Tim Burton, Return of the Joker is entirely self-contained and based more on the modern comic book iteration of Batman, but the Batmobile and the Batwing are featured from the 1989 film. A remake of Return of the Joker, titled Batman: Revenge of the Joker, was released on the Sega Genesis by Ringler Studios in 1992. A Super NES version of Revenge of the Joker was completed but never officially released; a ROM image surfaced online in later years.', 'https://media.retroachievements.org/Images/053392.png', 'https://media.retroachievements.org/Images/011642.png', 'https://media.retroachievements.org/Images/035320.png', 'https://media.retroachievements.org/Images/038026.png', 4.1),
  (107, 1843, 'Monster In My Pocket', 'NES/Famicom', 7, 2094, 2094, 2094, 25, 0, '2D Platforming', 'Konami', 'Konami', '1992-01-01', 'Monster in My Pocket is a media franchise developed by American company Morrison Entertainment Group, headed by Joe Morrison and John Weems, two former senior executives at Mattel.', 'https://media.retroachievements.org/Images/065582.png', 'https://media.retroachievements.org/Images/012741.png', 'https://media.retroachievements.org/Images/002231.png', 'https://media.retroachievements.org/Images/002232.png', 4.1),
  (108, 1682, 'Faxanadu', 'NES/Famicom', 7, 2091, 2091, 2091, 75, 0, NULL, 'Hudson Soft', 'Nintendo', '1987-11-16', 'Faxanadu is an action role-playing platform video game for the Nintendo Entertainment System. The name was licensed by computer game developer Falcom and was developed and released in Japan by Hudson Soft in 1987. Nintendo released the game in the United States and Europe as a first-party title under license from Hudson Soft.', 'https://media.retroachievements.org/Images/012127.png', 'https://media.retroachievements.org/Images/012126.png', 'https://media.retroachievements.org/Images/004179.png', 'https://media.retroachievements.org/Images/004180.png', 4.1),
  (109, 16549, 'Pac-Man: Championship Edition', 'NES/Famicom', 7, 2089, 2089, 2089, 20, 0, 'Maze Chase', 'M2', 'Bandai Namco', '2020-06-18', 'Pac-Man Championship Edition is a 2007 maze video game developed and published by Namco Bandai Games for the Xbox 360. It has since been released on several other platforms, including iOS, Android, and the PlayStation Portable as a PSP mini title available on the PlayStation Store. It is an HD reimagining of Namco''s original Pac-Man arcade game; players navigate Pac-Man through an enclosed maze, eating pellets and avoiding four ghosts that pursue him. Clearing an entire side of the maze of dots will cause a fruit item to appear, and eating it will cause a new maze to appear on the opposite side.', 'https://media.retroachievements.org/Images/088217.png', 'https://media.retroachievements.org/Images/036644.png', 'https://media.retroachievements.org/Images/043242.png', 'https://media.retroachievements.org/Images/043243.png', 4.1),
  (110, 1459, 'Blaster Master', 'NES/Famicom', 7, 2066, 2066, 2066, 25, 0, '2D Platforming', 'Tokai Engineering', 'Sunsoft', '1988-06-01', 'Blaster Master is a video game series that was originally developed and published by Sunsoft. It began with the 1988 video game Blaster Master for the Nintendo Entertainment System, and the series has been rebooted twice. The first reboot, Blaster Master: Overdrive, was released in 2010 and intended to rebuild the Sunsoft brand in North America, but it received mediocre reception from critics and did not see a follow-up.', 'https://media.retroachievements.org/Images/054344.png', 'https://media.retroachievements.org/Images/011692.png', 'https://media.retroachievements.org/Images/004923.png', 'https://media.retroachievements.org/Images/017224.png', 4.1),
  (111, 1470, 'Dragon Quest II', 'NES/Famicom', 7, 2064, 2064, 2064, 69, 0, NULL, 'Chunsoft', 'Enix', '1987-01-26', 'Dragon Quest II: Luminaries of the Legendary Line, titled Dragon Warrior II when initially localized to North America, is a 1987 role-playing video game developed by Chunsoft and published by Enix for the Nintendo Entertainment System as a part of the Dragon Quest series. Enix''s U.S. subsidiary published the American release, Dragon Warrior II, for the Nintendo Entertainment System in 1990. Dragon Quest II is set one hundred years after the events of the first game.', 'https://media.retroachievements.org/Images/026798.png', 'https://media.retroachievements.org/Images/012024.png', 'https://media.retroachievements.org/Images/007612.png', 'https://media.retroachievements.org/Images/012027.png', 4.1),
  (112, 1871, 'Panic Restaurant', 'NES/Famicom', 7, 2063, 2063, 2063, 28, 0, '2D Platforming', 'EIM', 'Taito', '1992-10-01', 'Panic Restaurant, known in Japan as Wanpaku Kokkun no Gourmet World (わんぱくコックンのグルメワールド), is a 1992 platform game developed by EIM and published by Taito for the Nintendo Entertainment System.', 'https://media.retroachievements.org/Images/076908.png', 'https://media.retroachievements.org/Images/077335.png', 'https://media.retroachievements.org/Images/001372.png', 'https://media.retroachievements.org/Images/001371.png', 4.1),
  (113, 2014, 'Tecmo Super Bowl', 'NES/Famicom', 7, 2056, 2056, 2056, 130, 0, 'Sports - American Football', 'Tecmo', 'Koei | Tecmo', '1991-12-13', 'Tecmo Super Bowl is a 1991 American football video game developed and published by Tecmo for the Nintendo Entertainment System (NES). It is the sequel to 1987''s Tecmo Bowl, as well as the first video game to be licensed by both the National Football League and the National Football League Players Association, thus allowing the game to use the names and attributes of real NFL teams and players. Prior games used either the real teams, the real players, or fictional substitutes, but not real teams and players together.', 'https://media.retroachievements.org/Images/117653.png', 'https://media.retroachievements.org/Images/013206.png', 'https://media.retroachievements.org/Images/059028.png', 'https://media.retroachievements.org/Images/006920.png', 4.1),
  (114, 1552, 'Back to the Future', 'NES/Famicom', 7, 2050, 2050, 2050, 50, 0, 'Shoot ''em Up', 'Beam Software', 'LJN Entertainment', '1989-09-01', 'Back to the Future is a 1985 American science fiction film directed by Robert Zemeckis and written by Zemeckis and Bob Gale. It stars Michael J. Fox, Christopher Lloyd, Lea Thompson, Crispin Glover, and Thomas F. Wilson. Set in 1985, it follows Marty McFly (Fox), a teenager accidentally sent back to 1955 in a time-traveling DeLorean automobile built by his eccentric scientist friend Emmett Doc Brown (Lloyd), where he inadvertently prevents his future parents from falling in love – threatening his own existence – and is forced to reconcile them and somehow get back to the future.', 'https://media.retroachievements.org/Images/044096.png', 'https://media.retroachievements.org/Images/011587.png', 'https://media.retroachievements.org/Images/009659.png', 'https://media.retroachievements.org/Images/009660.png', 4.1),
  (115, 1632, 'Contra Force', 'NES/Famicom', 7, 2045, 2045, 2045, 32, 0, NULL, 'Konami', 'Konami', '1992-09-30', 'Contra Force is a 1992 run and gun game developed and published by Konami for the Nintendo Entertainment System in North America. It is a spinoff of the Contra series, being the third game in the series released for the NES following the original Contra and Super Contra. However, the game''s plot and setting are unrelated to both previous and succeeding entries, as the villains in the game are human terrorists instead of an alien menace. The game was scheduled to be released in Japan under the title of Arc Hound , with no ties to the Contra series, but was cancelled.', 'https://media.retroachievements.org/Images/121557.png', 'https://media.retroachievements.org/Images/011875.png', 'https://media.retroachievements.org/Images/004889.png', 'https://media.retroachievements.org/Images/004890.png', 4.1),
  (116, 1654, 'Dig Dug II: Trouble In Paradise', 'NES/Famicom', 7, 2027, 2027, 2027, 26, 0, 'Arcade', 'Namco', 'Bandai', '1989-12-01', 'Dig Dug II is a 1985 action video game developed and published by Namco for Japanese arcades. It is a sequel to 1982''s Dig Dug. Pookas and fire-breathing Fygars return as the enemies, but the side view tunneling of the original is replaced with an overhead view of an island maze.', 'https://media.retroachievements.org/Images/061521.png', 'https://media.retroachievements.org/Images/011917.png', 'https://media.retroachievements.org/Images/008145.png', 'https://media.retroachievements.org/Images/008146.png', 4.1),
  (117, 8617, '~Test Kit~ NES Control Deck Test Cartridge', 'NES/Famicom', 7, 2005, 2005, 2005, 10, 0, NULL, 'Nintendo', 'Nintendo', NULL, 'The Nintendo Entertainment System (NES) is a home video game console developed and marketed by Nintendo. It was released as the  Family Computer (Famicom), in Japan on July 15, 1983, and as the NES in test markets in the United States on October 18, 1985, followed by a nationwide launch on September 27, 1986. The NES was distributed in Europe, Australia, and parts of Asia throughout the 1980s. It was Nintendo''s first programmable home console, succeeding the Color TV-Game line of dedicated consoles, and primarily competed with Sega''s Master System in the third generation of video game consoles.', 'https://media.retroachievements.org/Images/051151.png', 'https://media.retroachievements.org/Images/014866.png', 'https://media.retroachievements.org/Images/014865.png', 'https://media.retroachievements.org/Images/008670.png', 4.1),
  (118, 1527, 'Adventures in the Magic Kingdom', 'NES/Famicom', 7, 1992, 1992, 1992, 23, 0, '2D Platforming', 'Capcom', 'Capcom', '1990-06-01', 'Adventures in the Magic Kingdom is an action video game released in 1990 by Capcom for the Nintendo Entertainment System. Its soundtrack was composed by Yoko Shimomura. The game was released in five different regions, using three different retail covers. The game places the player as a nameless main character, for whom the player can enter a name at the start of the game, into a hub-and-spoke Disney park heavily based on the company''s Disneyland, Magic Kingdom, and Tokyo Disneyland parks. Goofy left the golden key for the castle gate inside, and Mickey Mouse asks for the player''s help to find six silver keys needed to open the Cinderella Castle gate and allow the Disney parade to begin. After completing this task, Mickey congratulates the player and the parade begins.', 'https://media.retroachievements.org/Images/094569.png', 'https://media.retroachievements.org/Images/011471.png', 'https://media.retroachievements.org/Images/005619.png', 'https://media.retroachievements.org/Images/005621.png', 4.1),
  (119, 2863, 'Kid Dracula', 'NES/Famicom', 7, 1992, 1992, 1992, 52, 0, '2D Platforming', 'Konami', 'Konami', '1990-10-19', 'Castlevania, known in Japan as Akumajō Dracula, is a 1986 platform game developed and published by Konami. It was originally released in Japan for the Famicom Disk System in September 1986, before being ported to cartridge format and released in North America for the Nintendo Entertainment System (NES) in 1987 and in Europe in 1988. It was also re-issued for the Family Computer in cartridge format in 1993. It is the first installment in the Castlevania series.', 'https://media.retroachievements.org/Images/083727.png', 'https://media.retroachievements.org/Images/070755.png', 'https://media.retroachievements.org/Images/070757.png', 'https://media.retroachievements.org/Images/070756.png', 4.1),
  (120, 1476, 'Gyruss', 'NES/Famicom', 7, 1963, 1963, 1963, 49, 0, 'Shoot ''em Up', 'Konami', 'Konami', '1988-01-01', 'Gyruss  is a 1983 tube shooter video game developed and published by Konami for Japanese arcades. It was initially licensed to Centuri in North America for dedicated machines before Konami released their own self-distributed conversion kits for the game. Parker Brothers released ports for the Atari 2600, Atari 5200, Atari 8-bit computers, ColecoVision and Commodore 64 in 1984. An enhanced version for the Famicom Disk System was released in 1988, followed by the Nintendo Entertainment System in 1989.', 'https://media.retroachievements.org/Images/034697.png', 'https://media.retroachievements.org/Images/012235.png', 'https://media.retroachievements.org/Images/003786.png', 'https://media.retroachievements.org/Images/003787.png', 4.1),
  (121, 1723, 'The Great Waldo Search', 'NES/Famicom', 7, 1920, 1920, 1920, 12, 0, 'Hidden Object', 'Radiance Software', 'THQ', '1992-12-01', 'Where''s Wally? The Fantastic Journey is the third Where''s Wally? book, first released in 1989. In the book Wally travels to fantasy lands in search of Wizard Whitebeard''s magical scrolls. The book introduces the second recurring Where''s Wally character, Wizard Whitebeard. Readers are also asked for the first time to find the Wizard''s scrolls.', 'https://media.retroachievements.org/Images/073201.png', 'https://media.retroachievements.org/Images/016142.png', 'https://media.retroachievements.org/Images/012221.png', 'https://media.retroachievements.org/Images/012223.png', 4.1),
  (122, 2139, 'Gimmick!', 'NES/Famicom', 7, 1908, 1908, 1908, 29, 0, '2D Platforming', 'Sunsoft', 'Sunsoft', '1992-01-01', 'Gimmick!, released in Scandinavia as Mr. Gimmick, is a platform video game developed and published by Sunsoft, and originally released in Japan for the Nintendo Entertainment System in 1992. The story follows a small green creature named Yumetaro who was mistakenly given as a toy to a young girl. After the girl''s toys come to life and whisk the girl away to another dimension, Yumetaro gives chase to save her. Playing as Yumetaro, the player must maneuver through a variety of levels, using the protagonist''s star-shooting power to defeat enemies and progress through the game.', 'https://media.retroachievements.org/Images/061856.png', 'https://media.retroachievements.org/Images/006310.png', 'https://media.retroachievements.org/Images/000697.png', 'https://media.retroachievements.org/Images/000698.png', 4.1),
  (123, 2058, 'Urban Champion', 'NES/Famicom', 7, 1904, 1904, 1904, 47, 0, '2D Fighting', NULL, 'Nintendo', '1984-11-14', 'Urban Champion is a fighting video game developed and published by Nintendo for the Nintendo Entertainment System. It was first released for the Famicom and Nintendo VS. System for arcades in 1984, and later released for the NES in North America and Europe in 1986. It is Nintendo''s first 2D fighting game, eventually followed by the 1993 Famicom game Joy Mech Fight. The game was poorly received, and has been retroactively regarded as one of the weaker Nintendo-published games for the NES.', 'https://media.retroachievements.org/Images/042747.png', 'https://media.retroachievements.org/Images/013239.png', 'https://media.retroachievements.org/Images/113397.png', 'https://media.retroachievements.org/Images/113398.png', 4.1),
  (124, 2062, 'Wacky Races', 'NES/Famicom', 7, 1900, 1900, 1900, 24, 0, '2D Platforming', 'Atlus', 'Atlus', '1991-12-25', 'Wacky Races is a media franchise containing five animated series, several video games, and a comic book, with most centered on the theme of various Hanna-Barbera cartoon characters primarily engaged in over-the-top auto racing with odd vehicles and absurd plot developments.', 'https://media.retroachievements.org/Images/122806.png', 'https://media.retroachievements.org/Images/012522.png', 'https://media.retroachievements.org/Images/097483.png', 'https://media.retroachievements.org/Images/006765.png', 4.1),
  (125, 8754, '~Unlicensed~ Microsoft Windows 98', 'NES/Famicom', 7, 1898, 1898, 1898, 20, 0, 'Simulation', 'Bei Tongfang', 'Bei Tongfang', '2002-01-01', 'Windows 98 is a consumer-oriented operating system developed by Microsoft as part of its Windows 9x line of Microsoft Windows, a family of operating systems. It was the second operating system in the 9x line, as the successor to Windows 95. It was released to manufacturing on May 15, 1998, and generally to retail on June 25, 1998. Like its predecessor, it is a hybrid 16-bit and 32-bit monolithic product with the boot stage based on MS-DOS.', 'https://media.retroachievements.org/Images/027797.png', 'https://media.retroachievements.org/Images/066493.png', 'https://media.retroachievements.org/Images/028588.png', 'https://media.retroachievements.org/Images/028587.png', 4.1),
  (126, 1719, 'The Goonies II', 'NES/Famicom', 7, 1888, 1888, 1888, 38, 0, '2D Platforming, Metroidvania', 'Konami', 'Konami', '1987-03-18', 'The Goonies II  is a 1987 action-adventure game developed and published by Konami for the Nintendo Entertainment System. It is a sequel to a prior Goonies video game released on the Family Computer in Japan, which was only available in North America on Nintendo VS. System arcade units. The Goonies II was released on March 18, 1987 in Japan, November in North America, and on December 19, 1988 in Europe.', 'https://media.retroachievements.org/Images/049486.png', 'https://media.retroachievements.org/Images/012217.png', 'https://media.retroachievements.org/Images/001620.png', 'https://media.retroachievements.org/Images/018595.png', 4.1),
  (127, 1692, 'The Flintstones: The Rescue of Dino and Hoppy', 'NES/Famicom', 7, 1877, 1877, 1877, 23, 0, '2D Platforming', 'Sol', 'Taito', '1991-12-01', 'The Flintstones: The Rescue of Dino & Hoppy is a 1991 platform video game by Taito for the Nintendo Entertainment System and based on the animated series The Flintstones. Taito would later release another Flintstones game for the NES titled The Flintstones: The Surprise at Dinosaur Peak in 1993.', 'https://media.retroachievements.org/Images/024373.png', 'https://media.retroachievements.org/Images/012155.png', 'https://media.retroachievements.org/Images/111602.png', 'https://media.retroachievements.org/Images/111603.png', 4.1),
  (128, 1744, 'Ice Hockey', 'NES/Famicom', 7, 1876, 1876, 1876, 21, 0, NULL, NULL, 'Nintendo', '1988-01-01', 'Ice hockey, known simply as hockey in North America and parts of Europe, is a team sport played on ice skates, usually on an ice skating rink with lines and markings specific to the sport. It belongs to a family of sports called hockey. The two opposing teams score by using their sticks to control and advance a vulcanized rubber hockey puck, and then shooting it into the net of the other team. Each goal is worth one point. The team with the highest score after an hour of gameplay is declared the winner; ties are broken in overtime or a shootout. In a formal game, each team has six skaters on the ice at a time, barring any penalties, including a goaltender. It is a full contact game and one of the more physically demanding team sports.', 'https://media.retroachievements.org/Images/063206.png', 'https://media.retroachievements.org/Images/012273.png', 'https://media.retroachievements.org/Images/008973.png', 'https://media.retroachievements.org/Images/008974.png', 4.1),
  (129, 1961, 'Snow Bros.', 'NES/Famicom', 7, 1867, 1867, 1867, 57, 0, '2D Platforming', 'Sol', 'Capcom', '1991-01-01', 'Snow Bros. is a 1990 platform video game developed and published by Toaplan for Japanese arcades; it was distributed by Romstar in North America and Europe. Players control snowman twins Nick and Tom as they travel through 50 stages, using snowballs as weapons while navigating obstacles and battling monsters in order to rescue the princesses Puripuri and Puchipuchi. The game was later ported to multiple platforms, each one by different third-party developers and featuring several changes or additions. Versions for various microcomputers were in development, but were never officially released.', 'https://media.retroachievements.org/Images/025040.png', 'https://media.retroachievements.org/Images/013020.png', 'https://media.retroachievements.org/Images/002996.png', 'https://media.retroachievements.org/Images/002997.png', 4.1),
  (130, 1900, 'Rad Racer', 'NES/Famicom', 7, 1858, 1858, 1858, 20, 0, 'Racing', 'Square', 'Nintendo', '1987-08-01', 'Rad Racer, known as Highway Star in Japan, is a racing video game developed and published by Square for the Nintendo Entertainment System (NES) in 1987. In this game, players drive a Ferrari 328 or a generic Formula One racing machine through a racecourse. The game was released in North America and Europe months after its debut. The title became well known for being one of two titles from Square that made use of stereoscopic 3D, which was made possible by wearing a pair of anaglyph glasses. Square president Masafumi Miyamoto initially conceived the game as an opportunity for developer Nasir Gebelli to demonstrate his 3D programming skills. Gebelli developed, and often drew by hand, the graphics for the game''s 3D mode.', 'https://media.retroachievements.org/Images/072535.png', 'https://media.retroachievements.org/Images/012892.png', 'https://media.retroachievements.org/Images/005433.png', 'https://media.retroachievements.org/Images/005435.png', 4.1),
  (131, 1628, 'Commando', 'NES/Famicom', 7, 1834, 1834, 1834, 33, 0, NULL, 'Capcom', 'Capcom', '1986-11-01', 'A commando is a combatant, or operative of an elite light infantry or special operations force, specially trained for carrying out raids and operating in small teams behind enemy lines.', 'https://media.retroachievements.org/Images/049185.png', 'https://media.retroachievements.org/Images/011854.png', 'https://media.retroachievements.org/Images/009497.png', 'https://media.retroachievements.org/Images/009498.png', 4.1),
  (132, 1883, 'Power Blade', 'NES/Famicom', 7, 1812, 1812, 1812, 28, 0, '2D Platforming', 'Natsume', 'Taito', '1991-03-01', 'Power Blade, known in Japan as Power Blazer , is an action platform video game published by Taito for the Nintendo Entertainment System. It was released in Japan on April 20, 1990, North America in March 1991, and in Europe on January 23, 1992 . The game spawned a sequel, Power Blade 2, released in 1992.', 'https://media.retroachievements.org/Images/064757.png', 'https://media.retroachievements.org/Images/012849.png', 'https://media.retroachievements.org/Images/035353.png', 'https://media.retroachievements.org/Images/035354.png', 4.1),
  (133, 1520, 'The Addams Family', 'NES/Famicom', 7, 1788, 1788, 1788, 22, 0, '2D Platforming', 'Ocean Software', 'Ocean Software', '1991-01-01', 'The Addams Family is a fictional family created by American cartoonist Charles Addams. The Addams are an eccentric old-money clan who delight in the macabre and the grotesque and are seemingly unaware or unconcerned that other people find them bizarre or frightening. The Addams'' view in seeing their family life and interests as normal was a basis for the satire and comedy. They originally appeared in a series of 150 standalone single-panel comics, about half of which were originally published in The New Yorker between 1938 and their creator''s death in 1988. They have since appeared in other media, such as television, film, video games, comic books, a musical, and merchandise.', 'https://media.retroachievements.org/Images/048740.png', 'https://media.retroachievements.org/Images/011495.png', 'https://media.retroachievements.org/Images/035413.png', 'https://media.retroachievements.org/Images/035414.png', 4.1),
  (134, 1776, 'Kick Master', 'NES/Famicom', 7, 1752, 1752, 1752, 26, 0, '2D Platforming', 'KID', 'Taito', '1992-01-01', 'Kick Master is an action game developed by KID and published by Taito for the Nintendo Entertainment System in 1992. The game has some role-play elements, such as leveling up.', 'https://media.retroachievements.org/Images/064829.png', 'https://media.retroachievements.org/Images/012371.png', 'https://media.retroachievements.org/Images/039193.png', 'https://media.retroachievements.org/Images/039194.png', 4.1),
  (135, 2006, 'Taboo: The Sixth Sense', 'NES/Famicom', 7, 1728, 1728, 1728, 26, 0, 'Other', 'Rare', 'Tradewest', '1989-04-01', 'Taboo: The Sixth Sense is a tarot card reading simulation developed by Rare and published by Tradewest for the Nintendo Entertainment System (NES) in 1989.', 'https://media.retroachievements.org/Images/072247.png', 'https://media.retroachievements.org/Images/013108.png', 'https://media.retroachievements.org/Images/010286.png', 'https://media.retroachievements.org/Images/010287.png', 4.1),
  (136, 1497, 'RoboCop', 'NES/Famicom', 7, 1725, 1725, 1725, 30, 0, 'Run & Gun', 'Ocean Software', 'Data East', '1989-01-01', 'RoboCop is a 1987 American science fiction action film directed by Paul Verhoeven and written by Edward Neumeier and Michael Miner. The film stars Peter Weller, Nancy Allen, Daniel O''Herlihy, Ronny Cox, Kurtwood Smith, and Miguel Ferrer. Set in a crime-ridden Detroit in the near future, RoboCop centers on police officer Alex Murphy (Weller) who is murdered by a gang of criminals and revived by the megacorporation Omni Consumer Products as the cyborg law enforcer RoboCop. Unaware of his former life, RoboCop executes a campaign against crime while coming to terms with the lingering fragments of his humanity.', 'https://media.retroachievements.org/Images/064968.png', 'https://media.retroachievements.org/Images/016172.png', 'https://media.retroachievements.org/Images/005199.png', 'https://media.retroachievements.org/Images/005200.png', 4.1),
  (137, 1726, 'The Guardian Legend', 'NES/Famicom', 7, 1721, 1721, 1721, 100, 0, 'Action-Adventure, Shoot ''em Up', 'Compile', 'Broderbund Software', '1988-02-05', 'The Guardian Legend is a 1988 hybrid action-adventure/shoot ''em up video game developed by Compile for the Nintendo Entertainment System (NES). It is the sequel to the 1986 MSX game Guardic, and was published and released in Japan by Irem in 1988, in North America by Broderbund in 1989, and in Europe by Nintendo in 1990.', 'https://media.retroachievements.org/Images/076137.png', 'https://media.retroachievements.org/Images/116785.png', 'https://media.retroachievements.org/Images/067385.png', 'https://media.retroachievements.org/Images/067386.png', 4.1),
  (138, 2017, 'Tennis', 'NES/Famicom', 7, 1720, 1720, 1720, 20, 0, 'Sports - Tennis', 'Nintendo', 'Nintendo', '1984-01-14', 'Tennis is a racket sport that is played either individually against a single opponent (singles) or between two teams of two players each (doubles). Each player uses a tennis racket strung with a cord to strike a hollow rubber ball covered with felt over or around a net and into the opponent''s court. The object is to manoeuvre the ball in such a way that the opponent is not able to play a valid return. If a player is unable to return the ball successfully, the opponent scores a point.', 'https://media.retroachievements.org/Images/079204.png', 'https://media.retroachievements.org/Images/013122.png', 'https://media.retroachievements.org/Images/005747.png', 'https://media.retroachievements.org/Images/005748.png', 4.1),
  (139, 1492, 'Pinball Quest', 'NES/Famicom', 7, 1705, 1705, 1705, 28, 0, 'Pinball', 'TOSE', 'Jaleco', '1989-12-15', 'Pinball Quest is a 1989 pinball video game developed by Tose and published by Jaleco. Released for the Nintendo Entertainment System, Pinball Quest was unusual at the time of its release for its unique mash-up of pinball and role-playing game (RPG) mechanics, and it is considered the first ever RPG pinball game.', 'https://media.retroachievements.org/Images/011326.png', 'https://media.retroachievements.org/Images/004826.png', 'https://media.retroachievements.org/Images/011325.png', 'https://media.retroachievements.org/Images/011327.png', 4.1),
  (140, 1774, 'The Karate Kid', 'NES/Famicom', 7, 1697, 1697, 1697, 31, 0, 'Beat ''em Up, 2D Platforming', 'Atlus', 'LJN Entertainment', '1987-11-01', 'The Karate Kid is a 1984 American martial arts drama film directed by John G. Avildsen and written by Robert Mark Kamen. It is the first film in The Karate Kid franchise. The film stars Ralph Macchio, Pat Morita, Elisabeth Shue and William Zabka. The story follows Daniel LaRusso (Macchio), an Italian-American teenager from New Jersey who moves with his widowed mother to the Reseda neighborhood of Los Angeles. There, LaRusso encounters harassment from bullies, one of whom is Johnny Lawrence (Zabka), the ex-boyfriend of LaRusso''s love interest, Ali Mills (Shue). LaRusso is taught karate by handyman and war veteran Mr. Miyagi (Morita) to help LaRusso defend himself and compete in a karate tournament against his bullies.', 'https://media.retroachievements.org/Images/054404.png', 'https://media.retroachievements.org/Images/012370.png', 'https://media.retroachievements.org/Images/002951.png', 'https://media.retroachievements.org/Images/002952.png', 4.1),
  (141, 2360, 'Bucky O''Hare', 'NES/Famicom', 7, 1694, 1694, 1694, 24, 0, '2D Platforming', 'Konami', 'Konami', '1992-01-01', 'Bucky O''Hare is a fictional character and the hero of an eponymous comic book series and spin-off media, including an animated TV series and various toys and video games. He was created by comic book writer Larry Hama and comic book artist Michael Golden between 1977 and 1978 and made its publishing debut in Echo of Futurepast #1 in May 1984 Continuity Comics.', 'https://media.retroachievements.org/Images/053969.png', 'https://media.retroachievements.org/Images/011731.png', 'https://media.retroachievements.org/Images/035348.png', 'https://media.retroachievements.org/Images/035349.png', 4.1),
  (142, 1569, 'Batman Returns', 'NES/Famicom', 7, 1686, 1686, 1686, 26, 0, 'Beat ''em Up', 'Konami', 'Konami', '1993-01-01', 'Batman Returns is a 1992 American superhero film directed by Tim Burton and written by Daniel Waters. Based on the DC Comics character Batman, it is the sequel to Batman (1989), also directed by Burton, and the second installment in the Batman film series (1989–1997). The cast includes Michael Keaton, Danny DeVito, Michelle Pfeiffer, Christopher Walken, Michael Gough, Pat Hingle, and Michael Murphy. Set during Christmas in Gotham City, the film follows Batman (Keaton) as he confronts corrupt businessman Max Shreck (Walken) and deformed crime boss Oswald Cobblepot / the Penguin (DeVito), whose bid for power threatens the city. Their schemes are further complicated by Shreck''s former secretary Selina Kyle (Pfeiffer), who seeks revenge against him as Catwoman.', 'https://media.retroachievements.org/Images/011645.png', 'https://media.retroachievements.org/Images/011644.png', 'https://media.retroachievements.org/Images/005767.png', 'https://media.retroachievements.org/Images/005768.png', 4.1),
  (143, 1958, 'Snake Rattle N Roll', 'NES/Famicom', 7, 1686, 1686, 1686, 42, 0, '2.5D Platforming', 'Rare', 'Nintendo', '1990-07-01', 'Snake Rattle ''n'' Roll is a platform video game developed by Rare and published by Nintendo for the Nintendo Entertainment System. It was originally released in North America in July 1990 and in Europe on 27 March 1991. The game features two snakes, Rattle and Roll, as they make their way through eleven 3D isometric levels. A port to the Mega Drive with an extra level was released by Sega in June 1993 exclusively in Europe. Snake Rattle ''n'' Roll was developed by Rare members Tim Stamper and Mark Betteridge. The music was composed by David Wise and was inspired by Shake, Rattle and Roll and other 1950s-era songs.', 'https://media.retroachievements.org/Images/070463.png', 'https://media.retroachievements.org/Images/013011.png', 'https://media.retroachievements.org/Images/003546.png', 'https://media.retroachievements.org/Images/003708.png', 4.1),
  (144, 4094, 'Antarctic Adventure', 'NES/Famicom', 7, 1671, 1671, 1671, 20, 0, 'Racing, Arcade', 'Konami', 'Konami', '1985-04-22', 'Antarctic Adventure  is a video game developed by Konami in 1983 for the MSX, and later for video game consoles, such as the Family Computer and ColecoVision. The player takes the role of an Antarctic penguin, racing to various research stations owned by different countries in Antarctica.', 'https://media.retroachievements.org/Images/048629.png', 'https://media.retroachievements.org/Images/014099.png', 'https://media.retroachievements.org/Images/003993.png', 'https://media.retroachievements.org/Images/003994.png', 4.1),
  (145, 1626, 'Code Name: Viper', 'NES/Famicom', 7, 1633, 1633, 1633, 39, 0, '2D Platforming', 'Arc System Works, Capcom', 'Capcom', '1990-03-01', 'Code Name: Viper, known in Japan as Ningen Heiki Dead Fox, is an action-platform video game developed by Arc System Works and published by Capcom in 1990 for the Nintendo Entertainment System. The player takes control of a special forces operative who must combat a drug syndicate in South America.', 'https://media.retroachievements.org/Images/047154.png', 'https://media.retroachievements.org/Images/011848.png', 'https://media.retroachievements.org/Images/034783.png', 'https://media.retroachievements.org/Images/039552.png', 4.1),
  (146, 1588, 'Bonk''s Adventure', 'NES/Famicom', 7, 1619, 1619, 1619, 17, 0, '2D Platforming', 'AI', NULL, '1994-01-01', 'Bonk''s Adventure, known as PC Genjin in Japan, PC Kid and B.C. Kid in Europe, is a scrolling platform game for the PC Engine/TurboGrafx-16 released in 1989 in Japan by Hudson Soft and 1990 in North America by NEC.', 'https://media.retroachievements.org/Images/061141.png', 'https://media.retroachievements.org/Images/011707.png', 'https://media.retroachievements.org/Images/007297.png', 'https://media.retroachievements.org/Images/007299.png', 4.1),
  (147, 1505, 'Trojan', 'NES/Famicom', 7, 1618, 1618, 1618, 31, 0, 'Beat ''em Up', 'Capcom', 'Capcom', '1986-12-24', 'Trojan, released in Japan as Tatakai no Banka, is a 1986 hack and slash video game developed and published by Capcom for arcades; it was released in North America by Romstar. Directed by Takashi Nishiyama, it is a spiritual successor to the beat ''em up Kung-Fu Master (1984), which was designed by Nishiyama at Irem before he left for Capcom, where he evolved its gameplay concepts with Trojan. It has also been likened to Capcom''s Ghosts ''n Goblins (1985), which has similar side-scrolling action gameplay elements.', 'https://media.retroachievements.org/Images/073344.png', 'https://media.retroachievements.org/Images/013168.png', 'https://media.retroachievements.org/Images/039444.png', 'https://media.retroachievements.org/Images/039445.png', 4.1),
  (148, 1725, 'Gremlins 2: The New Batch', 'NES/Famicom', 7, 1607, 1607, 1607, 17, 0, '2D Platforming', 'Sunsoft', 'Sunsoft', '1990-10-01', 'Gremlins 2: The New Batch is a 1990 American comedy horror film and the sequel to Gremlins (1984). It was directed by Joe Dante, written by Charles S. Haas and features creature designs by Rick Baker. Zach Galligan and Phoebe Cates reprise their roles from the first film, with John Glover, Robert Prosky, Robert Picardo and Christopher Lee joining the cast. It continues the story of Billy Peltzer and the mogwai Gizmo, who spawns more of his kind when wet that eventually become imp-like monsters and proceed to wreak havoc within a skyscraper in New York City.', 'https://media.retroachievements.org/Images/076982.png', 'https://media.retroachievements.org/Images/012228.png', 'https://media.retroachievements.org/Images/000679.png', 'https://media.retroachievements.org/Images/000681.png', 4.1),
  (149, 2238, 'Pin Bot', 'NES/Famicom', 7, 1602, 1602, 1602, 40, 0, 'Pinball', 'Rare', 'Nintendo', '1990-04-01', 'Pin-Bot is a pinball machine released by Williams in October 1986. It was designed by Python Anghelo and Barry Oursler.', 'https://media.retroachievements.org/Images/072258.png', 'https://media.retroachievements.org/Images/012839.png', 'https://media.retroachievements.org/Images/072158.png', 'https://media.retroachievements.org/Images/003902.png', 4.1),
  (150, 4618, 'The Flintstones: The Surprise at Dinosaur Peak!', 'NES/Famicom', 7, 1592, 1592, 1592, 45, 0, '2D Platforming', 'Taito', 'Taito', '1994-02-24', 'The Flintstones: The Surprise at Dinosaur Peak is a platform game for the Nintendo Entertainment System released by Taito in 1993. The game was never released in Japan unlike its predecessor The Flintstones: The Rescue of Dino & Hoppy.', 'https://media.retroachievements.org/Images/110963.png', 'https://media.retroachievements.org/Images/012156.png', 'https://media.retroachievements.org/Images/012157.png', 'https://media.retroachievements.org/Images/012158.png', 4.1),
  (151, 3814, 'EarthBound Beginnings', 'NES/Famicom', 7, 1589, 1589, 1589, 47, 0, 'Turn-Based RPG', 'APE | Creatures, Nintendo, Pax Softnica', 'Nintendo', '1989-07-27', 'EarthBound Beginnings, originally released in Japan as Mother, is a 1989 role-playing video game developed by Ape Inc. and Nintendo and published by Nintendo for the Family Computer. It is the first entry in the Mother series and was first released in Japan on July 27, 1989. The game was re-released in Japan along with its sequel on the single-cartridge compilation Mother 1+2 for the Game Boy Advance in 2003. The game follows a young American boy named Ninten as he uses his great-grandfather''s studies on psychic powers to put an end to the paranormal phenomena spiraling the country into disarray.', 'https://media.retroachievements.org/Images/079668.png', 'https://media.retroachievements.org/Images/028137.png', 'https://media.retroachievements.org/Images/001785.png', 'https://media.retroachievements.org/Images/001786.png', 4.1),
  (152, 2432, 'Gradius II', 'NES/Famicom', 7, 1578, 1578, 1578, 18, 0, 'Shoot ''em Up', 'Konami', 'Konami', '1988-12-16', 'Gradius II, retitled Vulcan Venture in North American arcades, is a 1988 horizontally scrolling shooter video game developed and published by Konami. It is the sequel to Gradius and was succeeded by Gradius III. Initially released in arcades, ports of Gradius II were released for the Family Computer, PC Engine Super CD-ROM², and the X68000 in Japan. The original arcade version is also included in the Gradius Deluxe Pack compilation for the PlayStation and Sega Saturn and in Gradius Collection for the PlayStation Portable.', 'https://media.retroachievements.org/Images/063180.png', 'https://media.retroachievements.org/Images/001938.png', 'https://media.retroachievements.org/Images/001935.png', 'https://media.retroachievements.org/Images/001936.png', 4.1),
  (153, 2361, '~Unlicensed~ Action 52', 'NES/Famicom', 7, 1563, 1563, 1563, 109, 0, 'Minigames', 'Active Enterprises', 'Active Enterprises', '1991-01-01', 'Action 52 is an unlicensed multicart video game compilation developed by Active Enterprises for the Nintendo Entertainment System and by FarSight Technologies for the Sega Genesis. The NES version was released in 1992, followed by the Genesis version in 1993. The multicart consists of 52 games in a variety of genres, mostly scrolling shooters and platformers. The featured game is The Cheetahmen, which was part of Active''s failed attempt to create a franchise similar to the Teenage Mutant Ninja Turtles.', 'https://media.retroachievements.org/Images/071673.png', 'https://media.retroachievements.org/Images/118424.png', 'https://media.retroachievements.org/Images/004027.png', 'https://media.retroachievements.org/Images/004028.png', 4.1),
  (154, 2090, 'Wrecking Crew', 'NES/Famicom', 7, 1550, 1550, 1550, 81, 0, NULL, 'Intelligent Systems', 'Nintendo', '1985-06-18', 'Wrecking Crew is an action game developed and published by Nintendo. It was first released for arcades for the Nintendo VS. System in 1984, titled VS. Wrecking Crew with a simultaneous two-player mode. It was released as a single-player game for the Family Computer (Famicom) console in 1985, and as a launch game for the Nintendo Entertainment System (NES) later that year.', 'https://media.retroachievements.org/Images/064469.png', 'https://media.retroachievements.org/Images/013240.png', 'https://media.retroachievements.org/Images/004086.png', 'https://media.retroachievements.org/Images/004087.png', 4.1),
  (155, 5060, 'Gargoyle''s Quest II: The Demon Darkness', 'NES/Famicom', 7, 1544, 1544, 1544, 23, 0, 'Action Adventure/Horror', 'Capcom', 'Capcom', '1992-07-17', 'Gargoyle''s Quest II: The Demon Darkness is a 1992 action-adventure platform game developed and published by Capcom for the Nintendo Entertainment System. It is the prequel to Gargoyle''s Quest and features a similar gameplay style, which combines adventure elements with side-scrolling action in a macabre fantasy setting. It was followed by Demon''s Crest for the Super Nintendo Entertainment System in 1994.', 'https://media.retroachievements.org/Images/113202.png', 'https://media.retroachievements.org/Images/012178.png', 'https://media.retroachievements.org/Images/003112.png', 'https://media.retroachievements.org/Images/033492.png', 4.1),
  (156, 1535, 'Air Fortress', 'NES/Famicom', 7, 1543, 1543, 1543, 37, 0, NULL, 'HAL Laboratory', 'HAL Laboratory', '1989-09-01', 'Air Fortress  is an action-adventure video game developed and published by HAL Laboratory for the Nintendo Entertainment System. It was released in Japan in August 1987, in North America in September 1989 after an initial test release of 385 copies in 1987, and an Australian release in 1989.', 'https://media.retroachievements.org/Images/011535.png', 'https://media.retroachievements.org/Images/011534.png', 'https://media.retroachievements.org/Images/011536.png', 'https://media.retroachievements.org/Images/011537.png', 4.1),
  (157, 1908, 'Renegade', 'NES/Famicom', 7, 1537, 1537, 1537, 42, 0, 'Beat ''em Up', 'Technōs Japan', 'Taito, Technōs Japan', '1987-04-01', 'Nekketsu Kōha Kunio-kun, released as Renegade in the West, is a 1986 beat ''em up video game developed by Technōs Japan and published by Taito for arcades. In the original Japanese version, the game revolves around Kunio, a high school delinquent who must stand up against a series of rival gangs that are targeting his classmate Hiroshi. In the Western version, the player controls a street brawler who must face four different gangs in order to rescue his girlfriend, who is being held captive by a mob boss.', 'https://media.retroachievements.org/Images/054767.png', 'https://media.retroachievements.org/Images/012923.png', 'https://media.retroachievements.org/Images/006186.png', 'https://media.retroachievements.org/Images/006187.png', 4),
  (158, 4829, 'Kyatto Ninden Teyandee', 'NES/Famicom', 7, 1536, 1536, 1536, 66, 0, '2D Platforming', 'Tecmo', 'Koei | Tecmo', '1991-07-19', 'Samurai Pizza Cats  is a Japanese anime series produced by Tatsunoko Production. The series originally aired in Japan on TV Tokyo from February 1, 1990, to February 12, 1991, for a total of 54 episodes. The creators stated that there was going to be a spin-off series, Kyatto Keisatsu Beranmee . The series is known for its cultural humor consisting of Japanese puns, pop culture, and fourth-wall breaking.', 'https://media.retroachievements.org/Images/111254.png', 'https://media.retroachievements.org/Images/002443.png', 'https://media.retroachievements.org/Images/002442.png', 'https://media.retroachievements.org/Images/002441.png', 4),
  (159, 1772, 'Kabuki: Quantum Fighter', 'NES/Famicom', 7, 1528, 1528, 1528, 30, 0, '2D Platforming', 'Human Entertainment', 'HAL Laboratory', '1991-01-01', 'Kabuki: Quantum Fighter  is a 2D platform game developed by Human Entertainment and published by HAL Laboratory for the Nintendo Entertainment System. It was originally released on December 21, 1990, in Japan and was released in January 1991 for the North American market before being released in Europe on February 20, 1992.', 'https://media.retroachievements.org/Images/022052.png', 'https://media.retroachievements.org/Images/012365.png', 'https://media.retroachievements.org/Images/004303.png', 'https://media.retroachievements.org/Images/004306.png', 4),
  (160, 1969, 'Spider-Man: Return of the Sinister Six', 'NES/Famicom', 7, 1518, 1518, 1518, 15, 0, 'Action', 'Bits Studios', 'LJN Entertainment', '1992-10-01', 'Spider-Man: Return of the Sinister Six is a 1992 action-adventure video game featuring the Marvel Comics characters Spider-Man and the Sinister Six. It was developed by Bits Studios and published by Acclaim Entertainment under the LJN banner for the Nintendo Entertainment System in 1992. Versions of the game were also released for the Master System and Game Gear by Acclaim''s Flying Edge division. The game is loosely based on the story arc of the same name, which was published in The Amazing Spider-Man #334-339 in the early 1990s.', 'https://media.retroachievements.org/Images/073574.png', 'https://media.retroachievements.org/Images/013034.png', 'https://media.retroachievements.org/Images/013036.png', 'https://media.retroachievements.org/Images/013037.png', 4),
  (161, 4756, 'Mappy', 'NES/Famicom', 7, 1517, 1517, 1517, 35, 0, NULL, 'Namco', 'Namco', '1984-11-14', 'Mappy is a 1983 platform video game developed and published by Namco for arcades. It was released in Japan in March 1983 and in North America by Bally Midway in April 1983. It runs on Namco''s Super Pac-Man hardware modified to support horizontal scrolling. The name Mappy is likely derived from mappo (マッポ), a slightly pejorative Japanese slang term for policeman. The game has been re-released in several Namco arcade compilations. It spawned a handful of sequels and a 2013 animated web series developed by cartoonists Scott Kurtz and Kris Straub.', 'https://media.retroachievements.org/Images/065576.png', 'https://media.retroachievements.org/Images/008026.png', 'https://media.retroachievements.org/Images/008025.png', 'https://media.retroachievements.org/Images/008027.png', 4),
  (162, 1777, 'Kickle Cubicle', 'NES/Famicom', 7, 1512, 1512, 1512, 23, 0, NULL, 'Irem', 'Irem', '1990-09-01', 'Kickle Cubicle is a puzzle game developed by Irem for the arcades in 1988 and then ported to Nintendo Entertainment System in 1990.', 'https://media.retroachievements.org/Images/001481.png', 'https://media.retroachievements.org/Images/012372.png', 'https://media.retroachievements.org/Images/001468.png', 'https://media.retroachievements.org/Images/001469.png', 4),
  (163, 2142, 'Crisis Force', 'NES/Famicom', 7, 1507, 1507, 1507, 31, 0, 'Shoot ''em Up', 'Konami', 'Konami', '1991-08-01', 'Crisis Force is a 1991 vertically scrolling shooter video game developed and published by Konami for the Family Computer. It was only released in Japan. The player controls one of two fighter ships piloted by Asuka and Maya, a pair of twin siblings descended from the ancient civilizations of Mu, who must save the world from a breed of artificial monsters from the lost civilization of Atlantis. The main feature of the game system is the player''s ability to transform its ship in one of three different forms, each with its unique attack method.', 'https://media.retroachievements.org/Images/113703.png', 'https://media.retroachievements.org/Images/000722.png', 'https://media.retroachievements.org/Images/000721.png', 'https://media.retroachievements.org/Images/000720.png', 4),
  (164, 1861, 'Nintendo World Cup', 'NES/Famicom', 7, 1498, 1498, 1498, 31, 0, NULL, NULL, 'Nintendo', '1990-12-01', 'Nintendo World Cup, released in Japan as Nekketsu High School Dodgeball Club: Soccer Story, is a 1990 soccer video game developed by Technōs Japan for the Nintendo Entertainment System. It was localized and released outside Japan by Nintendo, with a Game Boy port also being released. It is the fourth installment of the Kunio-kun series. Ports for the PC Engine and Mega Drive were also released in Japan.', 'https://media.retroachievements.org/Images/091551.png', 'https://media.retroachievements.org/Images/012657.png', 'https://media.retroachievements.org/Images/069343.png', 'https://media.retroachievements.org/Images/069344.png', 4),
  (165, 4542, '~Unlicensed~ Bubble Bath Babes', 'NES/Famicom', 7, 1488, 1488, 1488, 15, 0, NULL, 'C&E', 'Panesian', '1991-01-01', 'Bubble Bath Babes is a 1991 adult-oriented puzzle video game developed by C&E for the NES. Due to its adult nature, it was not licensed by Nintendo, and released via mail-order by Panesian—along with Hot Slots and Peek-A-Boo Poker.', 'https://media.retroachievements.org/Images/051198.png', 'https://media.retroachievements.org/Images/013337.png', 'https://media.retroachievements.org/Images/110460.png', 'https://media.retroachievements.org/Images/110461.png', 4),
  (166, 1604, 'Captain America and the Avengers', 'NES/Famicom', 7, 1487, 1487, 1487, 53, 0, 'Beat ''em Up', 'Data East', 'Data East', '1991-12-01', 'Captain America and the Avengers is a 1991 beat ''em up video game developed and published by Data East for arcades. It features the Avengers team of Marvel Comics characters in a side-scrolling brawling and shooting adventure to defeat the evil Red Skull. The game received ports for the Sega Genesis/Mega Drive, Super Nintendo Entertainment System, Game Boy and Game Gear. A different Data East game was released for the Nintendo Entertainment System.', 'https://media.retroachievements.org/Images/057421.png', 'https://media.retroachievements.org/Images/011298.png', 'https://media.retroachievements.org/Images/026397.png', 'https://media.retroachievements.org/Images/026398.png', 4),
  (167, 4658, 'Moon Crystal', 'NES/Famicom', 7, 1473, 1473, 1473, 32, 0, 'Action', 'Hect', 'Hect', '1992-08-28', 'Moon Crystal (ムーンクリスタル) is a 1992 video game for the Family Computer. It is a side scrolling action game, published and developed by Hect. It was well received by critics, who praised the smooth animations and graphics, however it sold poorly. It has never been released outside of Japan.', 'https://media.retroachievements.org/Images/057259.png', 'https://media.retroachievements.org/Images/004380.png', 'https://media.retroachievements.org/Images/004378.png', 'https://media.retroachievements.org/Images/004379.png', 4),
  (168, 1517, 'A Nightmare on Elm Street', 'NES/Famicom', 7, 1462, 1462, 1462, 33, 0, '2D Platforming', 'Rare', 'LJN Entertainment', '1990-10-01', 'A Nightmare on Elm Street is a 1984 American supernatural slasher film written and directed by Wes Craven and produced by Robert Shaye. It is the first installment in the A Nightmare on Elm Street franchise and stars Heather Langenkamp, John Saxon, Ronee Blakley, Robert Englund as Freddy Krueger, and Johnny Depp in his film debut. The film''s plot concerns a group of teenagers who are targeted by Krueger, an undead child killer who murders teenagers through their dreams, as retribution against their parents who burned him alive.', 'https://media.retroachievements.org/Images/061836.png', 'https://media.retroachievements.org/Images/012665.png', 'https://media.retroachievements.org/Images/006080.png', 'https://media.retroachievements.org/Images/006081.png', 4),
  (169, 1623, 'Clu Clu Land', 'NES/Famicom', 7, 1462, 1462, 1462, 30, 0, 'Action', NULL, 'Nintendo', '1984-11-22', 'Clu Clu Land is a 1984 puzzle video game developed and published by Nintendo for the Nintendo Entertainment System. It was released in 1984 in Japan for the Family Computer, in North America in 1985 as a launch title for the NES, and in Europe in 1987. It was ported to the Famicom Disk System in Japan and to arcades via the Nintendo VS. System as VS. Clu Clu Land. The game was later re-released on the Virtual Console for the Nintendo 3DS and Wii U, as well as the Nintendo Classics service.', 'https://media.retroachievements.org/Images/042746.png', 'https://media.retroachievements.org/Images/013230.png', 'https://media.retroachievements.org/Images/008053.png', 'https://media.retroachievements.org/Images/008054.png', 4),
  (170, 5083, '~Unlicensed~ Micro Machines', 'NES/Famicom', 7, 1459, 1459, 1459, 26, 0, 'Arcade Racing', 'Codemasters', 'Camerica', '1991-01-01', 'Micro Machines are a line of toys originally made by Galoob from 1987 and throughout the 1990s. Micro Machines are tiny scale component style playsets and vehicles that are slightly larger than N scale.', 'https://media.retroachievements.org/Images/064499.png', 'https://media.retroachievements.org/Images/013661.png', 'https://media.retroachievements.org/Images/004089.png', 'https://media.retroachievements.org/Images/004096.png', 4),
  (171, 1929, 'Rush ''n Attack', 'NES/Famicom', 7, 1459, 1459, 1459, 25, 0, 'Action', 'Konami', 'Konami', '1987-01-01', 'Rush''n Attack, also known as Green Beret in Japan and Europe, is a 1985 action-platform video game developed and published by Konami for arcades. It was later ported to the Nintendo Entertainment System and various home computers. Its North American title is a play on the phrase Russian attack due to its Cold War setting. It became a critical and commercial success for arcades and home computers. It was followed by a sequel, Rush''n Attack: Ex-Patriot, in 2010.', 'https://media.retroachievements.org/Images/081396.png', 'https://media.retroachievements.org/Images/012875.png', 'https://media.retroachievements.org/Images/003083.png', 'https://media.retroachievements.org/Images/003084.png', 4),
  (172, 1971, 'Spy Hunter', 'NES/Famicom', 7, 1448, 1448, 1448, 13, 0, 'Vehicular Combat', 'Sunsoft', 'Sunsoft', '1987-09-01', 'Spy Hunter is a 1983 vehicular combat video game developed and published by Bally Midway for arcades. The game draws inspiration from the James Bond films and was originally supposed to carry the James Bond brand. The object of the game is to drive down roads in the technologically advanced Interceptor car and destroy various enemy vehicles with a variety of onboard weapons. The game was produced in both sit-down and standard upright versions, with the latter being more common. The controls consist of a steering wheel in the form of a futuristic aircraft-style yoke with several special-purpose buttons, a two-position stick shift, and a pedal used for acceleration.', 'https://media.retroachievements.org/Images/072154.png', 'https://media.retroachievements.org/Images/013041.png', 'https://media.retroachievements.org/Images/005907.png', 'https://media.retroachievements.org/Images/005908.png', 4),
  (173, 2444, 'Yie Ar Kung-Fu', 'NES/Famicom', 7, 1427, 1427, 1427, 22, 0, '2D Fighting', 'Konami', 'Konami', '1985-04-22', 'Yie Ar Kung-Fu  is a fighting game developed and published by Konami for arcades. It first had a limited Japanese release in October 1984, before having a wide release nationwide in January 1985 and then internationally in March. Along with Data East''s Karate Champ (1984), which influenced Yie-Ar Kung Fu, it is one of the games that established the basis for modern fighting games.', 'https://media.retroachievements.org/Images/088302.png', 'https://media.retroachievements.org/Images/011482.png', 'https://media.retroachievements.org/Images/002739.png', 'https://media.retroachievements.org/Images/002738.png', 4),
  (174, 4767, 'F-1 Race', 'NES/Famicom', 7, 1418, 1418, 1418, 43, 0, 'Racing', 'HAL Laboratory', 'Nintendo', '1984-11-02', 'F1 Race is a racing video game developed by HAL Laboratory and published by Nintendo for the Famicom in 1984. A version was released in 1990 for the Game Boy in Japan and in 1991 in Europe and North America, including the Four Player Adapter for four-player gameplay.', 'https://media.retroachievements.org/Images/093946.png', 'https://media.retroachievements.org/Images/011189.png', 'https://media.retroachievements.org/Images/011186.png', 'https://media.retroachievements.org/Images/011187.png', 4),
  (175, 1769, 'Joust', 'NES/Famicom', 7, 1409, 1409, 1409, 10, 0, '2D Platforming, Arcade', 'HAL Laboratory', 'HAL Laboratory', '1987-10-30', 'Jousting is a medieval and renaissance martial game or hastilude between two combatants either on horse or on foot. The joust became an iconic characteristic of the knight in Romantic medievalism.', 'https://media.retroachievements.org/Images/113441.png', 'https://media.retroachievements.org/Images/012356.png', 'https://media.retroachievements.org/Images/115003.png', 'https://media.retroachievements.org/Images/115004.png', 4),
  (176, 1957, 'Smash T.V.', 'NES/Famicom', 7, 1409, 1409, 1409, 25, 0, 'Twin Stick Shooter', 'William, Ported by Beam Software', 'Acclaim', '1991-09-01', 'Smash TV is a 1990 twin-stick shooter video game developed and published by Williams Electronics for arcades. It was designed by Eugene Jarvis and programmed by Mark Turmell, with similar gameplay to Jarvis'' earlier game Robotron: 2084 (1982). The Super Nintendo Entertainment System, Sega Genesis, Master System and Game Gear versions are titled Super Smash TV.', 'https://media.retroachievements.org/Images/013010.png', 'https://media.retroachievements.org/Images/013007.png', 'https://media.retroachievements.org/Images/013008.png', 'https://media.retroachievements.org/Images/013009.png', 4),
  (177, 1991, 'Super Dodge Ball', 'NES/Famicom', 7, 1405, 1405, 1405, 22, 0, 'Sports - Dodgeball', 'Technōs Japan', 'Sony Imagesoft', '1989-06-01', 'Super Dodge Ball is a 1987 dodgeball video game developed and published by Technōs Japan for arcades. It is the second installment of the Kunio-kun series, with this connection not being present in international versions. It was released in North America by Leland Corporation. It was followed by a Nintendo Entertainment System version with various modifications; a remake for SNK''s Neo Geo arcade system was released in 1996 as Technōs Japan''s final game.', 'https://media.retroachievements.org/Images/117035.png', 'https://media.retroachievements.org/Images/013088.png', 'https://media.retroachievements.org/Images/004664.png', 'https://media.retroachievements.org/Images/004665.png', 4),
  (178, 1732, 'Heavy Barrel', 'NES/Famicom', 7, 1403, 1403, 1403, 31, 0, 'Run and Gun Shooter', 'Sakata SAS', 'Data East', '1990-03-01', 'Heavy Barrel is an overhead run and gun video game released for arcades in 1987 by Data East.', 'https://media.retroachievements.org/Images/063193.png', 'https://media.retroachievements.org/Images/012245.png', 'https://media.retroachievements.org/Images/035332.png', 'https://media.retroachievements.org/Images/035333.png', 4),
  (179, 3614, 'Galaxian', 'NES/Famicom', 7, 1388, 1388, 1388, 21, 0, 'Shoot ''em Up', 'Namco', 'Namco', '1984-09-07', 'Galaxian is a 1979 fixed shooter video game developed and published by Namco for arcades during early video games'' golden age. The player assumes control of the Galaxip starfighter in its mission to protect Earth from waves of aliens. Gameplay involves destroying each formation of aliens, who dive down towards the player in an attempt to hit them.', 'https://media.retroachievements.org/Images/114061.png', 'https://media.retroachievements.org/Images/013834.png', 'https://media.retroachievements.org/Images/001870.png', 'https://media.retroachievements.org/Images/001871.png', 4),
  (180, 2099, 'Yo! Noid', 'NES/Famicom', 7, 1388, 1388, 1388, 19, 0, '2D Platforming', 'Now Production', 'Capcom', '1990-11-01', 'Yo! Noid, known in Japan as Kamen no Ninja Hanamaru, is a platform video game developed by Now Production and published by Capcom for the Nintendo Entertainment System. The game was first released in Japan on March 16, 1990, and was localized in the United States to promote the Noid, the mascot of Domino''s Pizza. The game is in Nintendo''s PlayChoice-10 arcade series and was featured in the Japanese TV show GameCenter CX.', 'https://media.retroachievements.org/Images/113109.png', 'https://media.retroachievements.org/Images/012474.png', 'https://media.retroachievements.org/Images/039442.png', 'https://media.retroachievements.org/Images/039443.png', 4),
  (181, 4804, 'TwinBee', 'NES/Famicom', 7, 1382, 1382, 1382, 23, 0, 'Shoot ''em Up', 'Konami', 'Konami', '1986-01-04', 'TwinBee is a 1985 vertically scrolling shooter video game developed and published by Konami for arcades. Along with Sega''s Fantasy Zone (1986), it is credited as an early archetype of the cute ''em up subgenre. It was the first game to run on Konami''s Bubble System hardware. TwinBee was ported to the Family Computer and MSX in 1986, and has been included in numerous compilations released in later years. The original arcade game was released outside Japan for the first time as part of the Nintendo DS compilation Konami Classics Series: Arcade Hits. A mobile phone version with edited graphics was released for Japanese i-mode mobile phones in 2003.', 'https://media.retroachievements.org/Images/043626.png', 'https://media.retroachievements.org/Images/003864.png', 'https://media.retroachievements.org/Images/003862.png', 'https://media.retroachievements.org/Images/003863.png', 4),
  (182, 1717, 'Golf', 'NES/Famicom', 7, 1381, 1381, 1381, 17, 0, 'Sports - Golf', 'HAL Laboratory', 'Nintendo', '1984-05-01', 'Golf is a club-and-ball sport in which players use various clubs to hit a ball into a series of holes on a course in as few strokes as possible.', 'https://media.retroachievements.org/Images/061329.png', 'https://media.retroachievements.org/Images/012208.png', 'https://media.retroachievements.org/Images/001971.png', 'https://media.retroachievements.org/Images/001972.png', 4),
  (183, 1737, 'Home Alone', 'NES/Famicom', 7, 1380, 1380, 1380, 11, 0, 'Action', 'Bethesda Softworks', 'THQ', '1991-01-01', 'Home Alone is a 1990 American Christmas comedy film directed by Chris Columbus, and written and produced by John Hughes. The first film in the Home Alone franchise, the film stars Macaulay Culkin as Kevin McCallister, an eight-year-old boy who defends his suburban Chicago home from a home invasion by a pair of robbers after his family accidentally leaves him behind on their Christmas vacation to Paris. The cast also features Joe Pesci, Daniel Stern, John Heard, and Catherine O''Hara.', 'https://media.retroachievements.org/Images/063204.png', 'https://media.retroachievements.org/Images/012251.png', 'https://media.retroachievements.org/Images/006863.png', 'https://media.retroachievements.org/Images/006864.png', 4),
  (184, 1528, 'The Adventures of Bayou Billy', 'NES/Famicom', 7, 1337, 1337, 1337, 50, 0, 'Beat ''em Up', 'Konami', 'Konami', '1989-06-01', 'The Adventures of Bayou Billy, known in Japan as Mad City (マッド・シティ), is a 1988 beat ''em up video game developed and published by Konami for the Nintendo Entertainment System.', 'https://media.retroachievements.org/Images/120005.png', 'https://media.retroachievements.org/Images/011519.png', 'https://media.retroachievements.org/Images/008258.png', 'https://media.retroachievements.org/Images/008259.png', 4),
  (185, 1482, 'Maniac Mansion', 'NES/Famicom', 7, 1335, 1335, 1335, 36, 0, 'Point-and-Click Adventure', 'Realtime Associates', 'LucasArts | Lucasfilm', '1990-09-18', 'Maniac Mansion is a 1987 graphic adventure video game developed and published by Lucasfilm Games. It follows teenage protagonist Dave Miller as he attempts to rescue his girlfriend Sandy Pantz from a mad scientist, whose mind has been enslaved by a sentient meteor. The player uses a point-and-click interface to guide Dave and two of his six playable friends through the scientist''s mansion while solving puzzles and avoiding dangers. Gameplay is non-linear, and the game must be completed in different ways based on the player''s choice of characters. Initially released for the Commodore 64 and Apple II, Maniac Mansion was Lucasfilm Games'' first self-published product.', 'https://media.retroachievements.org/Images/048846.png', 'https://media.retroachievements.org/Images/012798.png', 'https://media.retroachievements.org/Images/005812.png', 'https://media.retroachievements.org/Images/005854.png', 4),
  (186, 1667, 'Dragon Quest III', 'NES/Famicom', 7, 1331, 1331, 1331, 50, 0, NULL, 'Chunsoft', 'Enix', '1988-02-10', 'Dragon Quest III: The Seeds of Salvation, titled Dragon Warrior III when initially localized to North America, is a 1988 role-playing video game developed by Chunsoft and published by Enix. It is the third installment in the Dragon Quest series and was first released for the Family Computer (Famicom) in Japan and later for the Nintendo Entertainment System (NES) in North America. The game saw an enhanced remake for the Super Famicom in 1996 and the Game Boy Color in 2001, and a port to mobile phones and the Wii in 2009 and 2011. A version of the game for Android and iOS was released in Japan on September 25, 2014, and worldwide as Dragon Quest III: The Seeds of Salvation on December 4, 2014. It was the first time the game was given an official English subtitle. Later in 2021, another remake of the game titled Dragon Quest III HD-2D Remake, based on the HD-2D graphical style of Octopath Traveler (2018), was announced during the franchise''s 35th anniversary livestream. The remake was released on November 14th, 2024 for Nintendo Switch, PlayStation 5, Windows, and Xbox Series consoles.', 'https://media.retroachievements.org/Images/026799.png', 'https://media.retroachievements.org/Images/012028.png', 'https://media.retroachievements.org/Images/072705.png', 'https://media.retroachievements.org/Images/072707.png', 4),
  (187, 1977, 'Star Force', 'NES/Famicom', 7, 1328, 1328, 1328, 33, 0, 'Shoot ''em Up', 'Tecmo', 'Koei | Tecmo', '1985-06-25', 'Star Force, released in North America as Mega Force, is a 1984 vertically scrolling shooter video game developed and published by Tehkan for arcades. It was ported to the Famicom by Hudson Soft, with Tehkan''s successor Tecmo releasing a different version for the Nintendo Entertainment System outside of Japan.', 'https://media.retroachievements.org/Images/064411.png', 'https://media.retroachievements.org/Images/013047.png', 'https://media.retroachievements.org/Images/035342.png', 'https://media.retroachievements.org/Images/035343.png', 4),
  (188, 1846, 'Ms. Pac-Man (Namco)', 'NES/Famicom', 7, 1327, 1327, 1327, 15, 0, NULL, 'Now Production', 'Namco', '1993-11-01', 'Ms. Pac-Man is a 1982 maze video game developed by General Computer Corporation (GCC) and published by Midway Manufacturing for arcades. It is a sequel to Pac-Man (1980), and the first entry in the series to not be made by Namco. Controlling the title character, Pac-Man''s wife, the player is tasked with eating all of the pellets in an enclosed maze while avoiding four colored ghosts. Eating the larger power pellets lets the player eat the ghosts, which turn blue and flee.', 'https://media.retroachievements.org/Images/039740.png', 'https://media.retroachievements.org/Images/012731.png', 'https://media.retroachievements.org/Images/010866.png', 'https://media.retroachievements.org/Images/010864.png', 4),
  (189, 2208, 'Holy Diver', 'NES/Famicom', 7, 1320, 1320, 1320, 29, 0, '2D Platforming', 'Irem', 'Irem', '1989-04-01', 'Holy Diver is the debut studio album by the American heavy metal band Dio, released in 1983. The album was acclaimed by the music press and is the band''s most successful album.', 'https://media.retroachievements.org/Images/109831.png', 'https://media.retroachievements.org/Images/000878.png', 'https://media.retroachievements.org/Images/000877.png', 'https://media.retroachievements.org/Images/000875.png', 4),
  (190, 1868, 'P.O.W.: Prisoners of War', 'NES/Famicom', 7, 1303, 1303, 1303, 25, 0, 'Beat ''em Up', 'SNK', 'SNK', '1989-06-30', 'P.O.W.: Prisoners of War, released in Japan as Prisoners of War, is a 1988 beat ''em up video game developed and published by SNK for arcades. A port to the Nintendo Entertainment System on June 30, 1989, in Japan and in September in North America. The game takes place during the Cold War where the player or players control a duo of military prisoners, Snake and Bart, who break free from their cell to relentlessly fight their way into the main base of their adversaries in order to eliminate their enemy''s general and escape with their lives.', 'https://media.retroachievements.org/Images/057865.png', 'https://media.retroachievements.org/Images/012813.png', 'https://media.retroachievements.org/Images/011345.png', 'https://media.retroachievements.org/Images/019149.png', 4),
  (191, 5527, 'Final Fantasy II', 'NES/Famicom', 7, 1291, 1291, 1291, 64, 0, 'Turn-Based RPG', 'Square', 'Squaresoft', '1988-12-17', 'Final Fantasy II is a 1988 role-playing video game developed and published by Square for the Family Computer as the second installment of the Final Fantasy series. It was ported to and remade for WonderSwan Color, PlayStation, Game Boy Advance, PlayStation Portable, and mobile phones. Originally exclusive to Japan, later versions were released internationally, including the 2021 Final Fantasy Pixel Remaster version. The story follows the warrior Firion and his allies as they join a rebellion against the expanding Palamecian Empire. The gameplay is similar to the original game with an overworld and dungeon exploration, but its combat design is changed to a usage-based growth system where characters'' statistics increase according to how they are used or acquired.', 'https://media.retroachievements.org/Images/089327.png', 'https://media.retroachievements.org/Images/005506.png', 'https://media.retroachievements.org/Images/005507.png', 'https://media.retroachievements.org/Images/005645.png', 4),
  (192, 2075, 'Whomp ''Em', 'NES/Famicom', 7, 1287, 1287, 1287, 32, 0, '2D Platforming', 'Jaleco', 'Jaleco', '1990-12-07', 'Whomp ''Em, also known in Japan as Saiyūki World 2: Tenjōkai no Majin  is a platform game released by Jaleco for the Nintendo Entertainment System in December 1990 in Japan and March 1991 in North America. It is named after Wampum.', 'https://media.retroachievements.org/Images/109017.png', 'https://media.retroachievements.org/Images/012574.png', 'https://media.retroachievements.org/Images/001442.png', 'https://media.retroachievements.org/Images/001440.png', 4),
  (193, 1596, 'The Bugs Bunny Birthday Blowout', 'NES/Famicom', 7, 1285, 1285, 1285, 80, 0, '2D Platforming', 'Kemco', 'Kemco', '1990-08-03', 'The Bugs Bunny Birthday Blowout, known in Japan and on the title screen as Happy Birthday Bugs (ハッピーバースディ・バッグス) and in Europe as The Bugs Bunny Blowout, is a platform video game developed and published by Kemco for the Nintendo Entertainment System in 1990.', 'https://media.retroachievements.org/Images/122702.png', 'https://media.retroachievements.org/Images/011732.png', 'https://media.retroachievements.org/Images/005112.png', 'https://media.retroachievements.org/Images/005113.png', 4),
  (194, 1601, 'Cabal', 'NES/Famicom', 7, 1279, 1279, 1279, 55, 0, 'Gallery Shooter', 'Rare', 'Milton Bradley', '1990-01-01', 'A cabal is a group of people who are united in some close design, usually to promote their private views or interests in an ideology, a state, or another community, often by intrigue and usually without the knowledge of those who are outside their group. The use of this term usually carries negative connotations of political purpose, conspiracy and secrecy. It can also refer to a secret plot or a clique, or it may be used as a verb.', 'https://media.retroachievements.org/Images/080010.png', 'https://media.retroachievements.org/Images/011223.png', 'https://media.retroachievements.org/Images/011226.png', 'https://media.retroachievements.org/Images/011225.png', 4),
  (195, 1700, 'G.I. Joe: A Real American Hero', 'NES/Famicom', 7, 1279, 1279, 1279, 49, 0, '2D Platforming', 'KID', 'Taxan', '1991-01-01', 'G.I. Joe: A Real American Hero is a military-themed line of action figures and toys in Hasbro''s G.I. Joe franchise. The toyline lasted from 1982 to 1994, producing well over 500 figures and 250 vehicles and playsets. The line reappeared in 1997 and has continued in one form or another to the present day. It was supported by two animated series as well as a major comic series published by Marvel Comics.', 'https://media.retroachievements.org/Images/063165.png', 'https://media.retroachievements.org/Images/012171.png', 'https://media.retroachievements.org/Images/007339.png', 'https://media.retroachievements.org/Images/007340.png', 4),
  (196, 1720, 'The Goonies', 'NES/Famicom', 7, 1279, 1279, 1279, 50, 0, '2D Platforming', 'Konami', 'Konami', '1986-02-01', 'The Goonies is a 1985 American adventure comedy film directed by Richard Donner from a screenplay by Chris Columbus based on a story by Steven Spielberg. The film stars Sean Astin, Josh Brolin, Jeff Cohen, Corey Feldman, Kerri Green, Martha Plimpton, and Ke Huy Quan with John Matuszak, Robert Davi, Joe Pantoliano, and Anne Ramsey in supporting roles. In the film, a group of children who live in the Goon Docks neighborhood of Astoria, Oregon attempt to save their homes from foreclosure. In doing so, they discover an old treasure map which takes them on an adventure to unearth the long-lost fortune of One-Eyed Willy, a legendary 17th-century pirate, while being pursued by a family of criminals who are after the treasure as well.', 'https://media.retroachievements.org/Images/024810.png', 'https://media.retroachievements.org/Images/013843.png', 'https://media.retroachievements.org/Images/013845.png', 'https://media.retroachievements.org/Images/013844.png', 4),
  (197, 5553, 'Final Fantasy III', 'NES/Famicom', 7, 1273, 1273, 1273, 90, 0, NULL, 'Square', 'Squaresoft', '1990-04-27', 'Final Fantasy III is a 1990 role-playing video game developed and published by Square for the Family Computer. The third installment in the Final Fantasy series, it follows four orphans from the village of Ur who are chosen by the world''s crystals to defeat a great evil and return balance to the world. The gameplay returns to the traditional combat system of the original game, and adds a job system allowing players to switch between character classes with unique abilities.', 'https://media.retroachievements.org/Images/089329.png', 'https://media.retroachievements.org/Images/005697.png', 'https://media.retroachievements.org/Images/006579.png', 'https://media.retroachievements.org/Images/008389.png', 4),
  (198, 1498, 'Rygar', 'NES/Famicom', 7, 1266, 1266, 1266, 22, 0, '2D Platforming, Metroidvania', 'Tecmo', 'Koei | Tecmo', '1987-04-17', 'Rygar is a 1986 platform game developed and published by Tecmo for arcades. The player assumes the role of a Legendary Warrior who must navigate numerous levels and defeat enemies with a weapon called the Diskarmor, a razor-sharp shield with a long chain attached to it that operates like a yo-yo. The warrior intends to defeat Ligar, an evil dominator. Later ports, particularly the NES and Lynx versions, expanded on the near non-existent story from the original.', 'https://media.retroachievements.org/Images/065137.png', 'https://media.retroachievements.org/Images/012874.png', 'https://media.retroachievements.org/Images/035328.png', 'https://media.retroachievements.org/Images/035327.png', 4),
  (199, 1591, 'Bram Stoker''s Dracula', 'NES/Famicom', 7, 1259, 1259, 1259, 91, 0, '2D Platforming', 'Probe Entertainment', 'Sony Imagesoft', '1993-09-01', 'Bram Stoker''s Dracula is a 1993 video game released for the Mega Drive/Genesis, Nintendo Entertainment System, Super NES, Master System, Sega CD, Game Gear, MS-DOS, and Amiga. It is based on the 1992 film of the same name, which in turn is based on the 1897 novel Dracula by Bram Stoker. Most versions are platform games, while the Sega CD and Amiga releases are beat ''em ups, and the MS-DOS version is a first-person shooter. A separate version for the Game Boy was released in 1993, followed by an Amiga version in 1994 for North America and Europe. A CD-ROM version for MS-DOS compatible operating systems was released in 1995.', 'https://media.retroachievements.org/Images/011417.png', 'https://media.retroachievements.org/Images/011415.png', 'https://media.retroachievements.org/Images/011416.png', 'https://media.retroachievements.org/Images/011445.png', 4),
  (200, 2078, 'Willow', 'NES/Famicom', 7, 1259, 1259, 1259, 59, 0, 'Action RPG', 'Capcom', 'Capcom', '1989-12-01', 'Willows, also called sallows and osiers, of the genus Salix, comprise around 350 species of typically deciduous trees and shrubs. They are primarily found on moist soils in cold and temperate regions.', 'https://media.retroachievements.org/Images/109466.png', 'https://media.retroachievements.org/Images/012580.png', 'https://media.retroachievements.org/Images/002749.png', 'https://media.retroachievements.org/Images/002750.png', 4);
INSERT INTO games (rank, id, title, consoleName, consoleId, totalPlayers, casualPlayers, hardcorePlayers, numAchievements, points, genre, developer, publisher, released, description, icon, boxArt, titleScreen, screenshot, rating) VALUES
  (1, 3537, 'God of War: Chains of Olympus', 'PlayStation Portable', 41, 9797, 9797, 9797, 39, 0, 'Hack & Slash', 'Ready at Dawn', 'Sony Computer Entertainment', '2008-03-04', 'God of War: Chains of Olympus is a 2008 action-adventure game developed by Ready at Dawn, and published by Sony Computer Entertainment (SCE). It was first released for the PlayStation Portable (PSP) handheld console on March 4, 2008. The game is the fourth installment in the God of War series, the third chronologically, and a prequel to the original God of War. It is loosely based on Greek mythology and set in ancient Greece, with vengeance as its central motif. The player controls Kratos, a Spartan warrior who serves the Olympian gods. Kratos is guided by the goddess Athena, who instructs him to find the Sun God Helios, as the Dream God Morpheus has caused many of the gods to slumber in Helios'' absence. With the power of the Sun and the aid of the Titan Atlas, Morpheus and the Queen of the Underworld Persephone intend to destroy the Pillar of the World and in turn Olympus.', 'https://media.retroachievements.org/Images/120499.png', 'https://media.retroachievements.org/Images/047385.png', 'https://media.retroachievements.org/Images/085036.png', 'https://media.retroachievements.org/Images/085037.png', 5),
  (2, 17976, 'Monster Hunter Portable 3rd', 'PlayStation Portable', 41, 7450, 7450, 7450, 506, 0, 'Action RPG', 'Capcom', 'Capcom', '2010-12-01', 'Monster Hunter Portable 3rd is a 2010 action role-playing game developed and published by Capcom for the PlayStation Portable. It is the third handheld installment in the Monster Hunter franchise. Like its predecessor, Monster Hunter Freedom 2, Portable 3rd is an original title that adapts the core content of Monster Hunter Tri into a new single player campaign, adding supplemental original content. The game introduces regions, monsters, and a revised Felyne combat system.', 'https://media.retroachievements.org/Images/107426.png', 'https://media.retroachievements.org/Images/077217.png', 'https://media.retroachievements.org/Images/048874.png', 'https://media.retroachievements.org/Images/063063.png', 4.9),
  (3, 3727, 'Dante''s Inferno', 'PlayStation Portable', 41, 6538, 6538, 6538, 63, 0, 'Action-Adventure', 'Artificial Mind and Movement', 'Electronic Arts', '2010-02-25', 'Inferno is the first part of the Italian writer Dante Alighieri''s 14th-century narrative poem The Divine Comedy, followed by Purgatorio and Paradiso. The Inferno describes the journey of a fictionalised version of Dante himself through Hell, guided by the ancient Roman poet Virgil. In the poem, Hell is depicted as nine concentric circles of torment located within the Earth; it is the realm [...] of those who have rejected spiritual values by yielding to bestial appetites or violence, or by perverting their human intellect to fraud or malice against their fellowmen. As an allegory, the Divine Comedy represents the journey of the soul toward God, with the Inferno describing the recognition and rejection of sin.', 'https://media.retroachievements.org/Images/089534.png', 'https://media.retroachievements.org/Images/095582.png', 'https://media.retroachievements.org/Images/048592.png', 'https://media.retroachievements.org/Images/048594.png', 4.9),
  (4, 3538, 'God of War: Ghost of Sparta', 'PlayStation Portable', 41, 5720, 5720, 5720, 50, 0, 'Hack & Slash', 'Ready at Dawn', 'Sony Computer Entertainment', '2010-11-02', 'God of War: Ghost of Sparta is a 2010 action-adventure game developed by Ready at Dawn and published by Sony Computer Entertainment (SCE). It was first released for the PlayStation Portable (PSP) handheld console on November 2, 2010. The game is the sixth installment in the God of War series and the fifth chronologically. Loosely based on Greek mythology, Ghost of Sparta is set in ancient Greece with vengeance as its central motif. The player controls the protagonist Kratos, the God of War. Kratos is still haunted by the visions of his mortal past and decides to explore his origins. In Atlantis, he finds his mother Callisto, who claims that his brother Deimos is still alive. Kratos journeys to the Domain of Death to rescue his brother. After initial resentment from Deimos, the brothers team up to battle the God of Death, Thanatos, Deimos'' captor.', 'https://media.retroachievements.org/Images/120500.png', 'https://media.retroachievements.org/Images/047382.png', 'https://media.retroachievements.org/Images/085039.png', 'https://media.retroachievements.org/Images/085038.png', 4.9),
  (5, 3161, 'LittleBigPlanet', 'PlayStation Portable', 41, 5045, 5045, 5045, 173, 0, '2.5D Platforming', NULL, 'Sony Computer Entertainment', '2009-11-17', 'LittleBigPlanet is a puzzle platform video game series created and produced by British developer Media Molecule and published by Sony Interactive Entertainment. Most games in the series put a strong emphasis on user-generated content and are based on the series'' tagline Play, Create, Share. The tagline represents the three core elements of the series: playing alone or with others locally or online, creating new content using the in-game creation tools, and sharing creations and discoveries online with other players.', 'https://media.retroachievements.org/Images/093947.png', 'https://media.retroachievements.org/Images/046833.png', 'https://media.retroachievements.org/Images/032912.png', 'https://media.retroachievements.org/Images/032913.png', 4.8),
  (6, 3582, 'Mega Man: Powered Up', 'PlayStation Portable', 41, 4564, 4564, 4564, 143, 0, NULL, 'Capcom', 'Capcom', '2006-03-02', 'Mega Man Powered Up is a 2006 platform game developed and published by Capcom. It was released for the PlayStation Portable (PSP) handheld game console in March 2006. It is a remake of the original Mega Man game, released in 1987 for the Nintendo Entertainment System (NES). Players control the eponymous star Mega Man, who must stop Dr. Wily from conquering the world using eight robots called Robot Masters.', 'https://media.retroachievements.org/Images/047296.png', 'https://media.retroachievements.org/Images/048162.png', 'https://media.retroachievements.org/Images/046678.png', 'https://media.retroachievements.org/Images/046679.png', 4.8),
  (7, 3515, 'Dissidia 012: Duodecim Final Fantasy', 'PlayStation Portable', 41, 4403, 4403, 4403, 195, 0, 'Arena Fighting', 'Square Enix', 'Square Enix', '2011-03-03', 'This is a list of games for Sony''s PlayStation Portable (PSP) handheld game console made available to download from the PlayStation Store. The ability to download and play these titles has varied among titles between the platforms of PSP, PlayStation Vita (PSV), PlayStation TV (PSTV), PlayStation 4 (PS4), and PlayStation 5 (PS5). Titles released on the latter two are the original games software emulated. If a downloadable PSP game has been purchased for a device released prior to the PS4, the title is automatically added to the user''s library on all devices for which there is a release.', 'https://media.retroachievements.org/Images/049140.png', 'https://media.retroachievements.org/Images/049156.png', 'https://media.retroachievements.org/Images/049307.png', 'https://media.retroachievements.org/Images/049308.png', 4.8),
  (8, 10387, 'Crisis Core: Final Fantasy VII', 'PlayStation Portable', 41, 4092, 4092, 4092, 238, 0, 'Action RPG', 'Square Enix', 'Square Enix', '2007-09-13', 'Crisis Core: Final Fantasy VII is a 2007 action role-playing game developed and published by Square Enix for the PlayStation Portable. The game serves as a prequel to the 1997 title Final Fantasy VII and is part of the metaseries Compilation of Final Fantasy VII, which includes other products related to the original game.', 'https://media.retroachievements.org/Images/056892.png', 'https://media.retroachievements.org/Images/047808.png', 'https://media.retroachievements.org/Images/047806.png', 'https://media.retroachievements.org/Images/048168.png', 4.8),
  (9, 3732, 'Monster Hunter Freedom Unite', 'PlayStation Portable', 41, 3767, 3767, 3767, 242, 0, 'Action RPG', 'Capcom', 'Capcom', '2008-03-27', 'Monster Hunter Freedom 2 is a 2007 action role-playing game developed and published by Capcom for the PlayStation Portable. It is the second handheld installment in the Monster Hunter franchise. Marketed as a sequel to Monster Hunter Freedom, Freedom 2 is an original title that adapts the core content of Monster Hunter 2 into a new single player campaign, adding supplemental original content.', 'https://media.retroachievements.org/Images/047405.png', 'https://media.retroachievements.org/Images/043631.png', 'https://media.retroachievements.org/Images/043628.png', 'https://media.retroachievements.org/Images/043629.png', 4.8),
  (10, 3219, 'Mega Man Maverick Hunter X', 'PlayStation Portable', 41, 3715, 3715, 3715, 59, 0, NULL, 'Capcom', 'Capcom', '2005-12-15', 'This is a list of video game remakes and remasters and includes remakes as well as remasters of video games. It does not include clones and enhanced ports.', 'https://media.retroachievements.org/Images/047042.png', 'https://media.retroachievements.org/Images/046646.png', 'https://media.retroachievements.org/Images/054839.png', 'https://media.retroachievements.org/Images/046937.png', 4.8),
  (11, 3186, 'Tekken 6', 'PlayStation Portable', 41, 3649, 3649, 3649, 65, 0, '3D Fighting', NULL, 'Bandai Namco', '2009-11-24', 'Tekken 6  is a 2007 fighting game developed and published by Namco Bandai Games. It is the sixth main and seventh overall installment in the Tekken franchise. It was released on arcades in November 2007 as the first game running on the PlayStation 3-based System 357 arcade board. A year later, the game received an update, subtitled Bloodline Rebellion; both versions also saw a limited release in North America. A home version based on the update was released for the PlayStation 3 and Xbox 360 in October 2009; this was the first time a main installment was produced for a non-Sony console. A port to the PlayStation Portable was also released shortly after.', 'https://media.retroachievements.org/Images/086823.png', 'https://media.retroachievements.org/Images/065820.png', 'https://media.retroachievements.org/Images/065819.png', 'https://media.retroachievements.org/Images/065818.png', 4.7),
  (12, 3471, 'Metal Slug: Anthology', 'PlayStation Portable', 41, 3574, 3574, 3574, 94, 0, 'Run & Gun', 'Terminal Reality', 'SNK', '2007-02-09', 'Metal Slug is a series of run and gun video games first released on Neo-Geo arcade machines and game consoles created by SNK. It was also ported to other consoles, such as the Sega Saturn, the PlayStation, the Neo-Geo Pocket Color and more recently, the Game Boy Advance, PlayStation 2, iPhone, iPod Touch, Xbox, Xbox 360 and Nintendo DS. There is also an anthology of the first 7 games in the main series available for the Wii, PlayStation Portable, PlayStation 2 and Windows. In 2009, the first three games were officially ported by Games Load to Windows.', 'https://media.retroachievements.org/Images/048777.png', 'https://media.retroachievements.org/Images/048770.png', 'https://media.retroachievements.org/Images/048772.png', 'https://media.retroachievements.org/Images/116696.png', 4.7),
  (13, 3910, 'Dragon Ball Z: Shin Budokai', 'PlayStation Portable', 41, 3509, 3509, 3509, 70, 0, '3D Fighting', 'Dimps', 'Atari, Bandai', '2006-03-07', 'Dragon Ball Z: Shin Budokai is a fighting video game part of the Dragon Ball Z franchise, and was released on March 7, 2006, developed by Dimps. The story mode is based on the events of the Dragon Ball Z movie Fusion Reborn. The players follow the events of the story in which they encounter many Dragon Ball Z characters, including Goku and Vegeta. The choices that you make determine how the story evolves.', 'https://media.retroachievements.org/Images/104258.png', 'https://media.retroachievements.org/Images/049707.png', 'https://media.retroachievements.org/Images/049708.png', 'https://media.retroachievements.org/Images/049772.png', 4.7),
  (14, 3185, 'Burnout Legends', 'PlayStation Portable', 41, 3496, 3496, 3496, 118, 0, 'Arcade Racing', 'Criterion Games', 'Electronic Arts', '2005-09-13', 'This is a list of video game remakes and remasters and includes remakes as well as remasters of video games. It does not include clones and enhanced ports.', 'https://media.retroachievements.org/Images/059681.png', 'https://media.retroachievements.org/Images/048414.png', 'https://media.retroachievements.org/Images/059709.png', 'https://media.retroachievements.org/Images/059711.png', 4.7),
  (15, 3891, 'Shin Megami Tensei: Persona', 'PlayStation Portable', 41, 3222, 3222, 3222, 118, 0, 'Turn-Based RPG', 'Atlus', 'Atlus', '2009-04-29', 'Persona, previously marketed as Shin Megami Tensei: Persona outside of Japan, is a video game franchise primarily developed by Atlus and owned by Sega. Centered around a series of Japanese role-playing video games, Persona is a spin-off from Atlus'' Megami Tensei franchise. The first entry in the series, Revelations: Persona, was released in 1996 for the PlayStation. The series has seen several more games since, with the most recent main entry being 2024''s Persona 3 Reload, a remake of the 2006 game Persona 3.', 'https://media.retroachievements.org/Images/077388.png', 'https://media.retroachievements.org/Images/053386.png', 'https://media.retroachievements.org/Images/053385.png', 'https://media.retroachievements.org/Images/053384.png', 4.7),
  (16, 3509, 'Jeanne D''Arc', 'PlayStation Portable', 41, 2964, 2964, 2964, 90, 0, 'Tactical RPG', 'Level-5', 'Sony Computer Entertainment', '2006-11-22', 'Joan of Arc is a patron saint of France, honored as a defender of the French nation for her role in the siege of Orléans and her insistence on the coronation of Charles VII of France during the Hundred Years'' War. Claiming to be acting under divine guidance, she became a military leader who gained recognition as a savior of France.', 'https://media.retroachievements.org/Images/049641.png', 'https://media.retroachievements.org/Images/046840.png', 'https://media.retroachievements.org/Images/046843.png', 'https://media.retroachievements.org/Images/046841.png', 4.7),
  (17, 10533, 'Metal Gear Solid: Peace Walker', 'PlayStation Portable', 41, 2918, 2918, 2918, 106, 0, 'Action-Adventure', 'Kojima Productions', 'Konami', '2010-04-29', 'Metal Gear Solid: Peace Walker is a 2010 stealth game developed by Kojima Productions and published by Konami. It is the seventh Metal Gear game written, directed, and designed by Hideo Kojima, and the fifth installment of the Metal Gear Solid series, as well as the fourth Metal Gear game made specifically for the PlayStation Portable, following Metal Gear Solid: Portable Ops. A remastered version of the game titled Metal Gear Solid: Peace Walker — HD Edition was later released for the PlayStation 3 and Xbox 360 as part of the Metal Gear Solid HD Collection in North America and Europe and as a stand-alone retail release in Japan. The HD Edition of the game will be included in the Metal Gear Solid: Master Collection Vol. 2 compilation for Nintendo Switch, Nintendo Switch 2, PlayStation 5, Windows, and Xbox Series X/S on August 27, 2026.', 'https://media.retroachievements.org/Images/103151.png', 'https://media.retroachievements.org/Images/046912.png', 'https://media.retroachievements.org/Images/046915.png', 'https://media.retroachievements.org/Images/118054.png', 4.7),
  (18, 3215, 'Final Fantasy', 'PlayStation Portable', 41, 2896, 2896, 2896, 57, 0, NULL, 'Square Enix', 'Square Enix', '2007-04-19', 'Final Fantasy is a 1987 role-playing video game developed and published by Square for the Nintendo Entertainment System. It is the first game in Square''s Final Fantasy series, created by Hironobu Sakaguchi. The story follows four youths called the Warriors of Light, who each carry one of their world''s four elemental crystals which have been darkened by the four Elemental Fiends. Together, they quest to defeat these evil forces, restore light to the crystals, and save their world.', 'https://media.retroachievements.org/Images/070784.png', 'https://media.retroachievements.org/Images/047908.png', 'https://media.retroachievements.org/Images/048785.png', 'https://media.retroachievements.org/Images/048786.png', 4.7),
  (19, 3971, 'Grand Theft Auto: Vice City Stories', 'PlayStation Portable', 41, 2757, 2757, 2757, 189, 0, 'Action-Adventure, Sandbox', 'Rockstar Leeds, Rockstar North', 'Rockstar Games', '2006-10-31', 'Grand Theft Auto: Vice City Stories is a 2006 action-adventure game developed by Rockstar Leeds and Rockstar North, and published by Rockstar Games. The tenth entry in the Grand Theft Auto series, the game was initially released as a PlayStation Portable exclusive in October 2006. A PlayStation 2 port was released in March 2007. Set within the fictional Vice City in 1984, the game is a prequel to 2002''s Grand Theft Auto: Vice City and follows the exploits of ex-soldier Victor Vic Vance, a minor character originally featured in said game. The story centres around Vic''s attempts to build up a criminal empire alongside his brother Lance. With the initial intention of raising money for his sick brother Pete''s medication, Vic comes into conflict with rival gangs, drug lords and other enemies.', 'https://media.retroachievements.org/Images/089903.png', 'https://media.retroachievements.org/Images/048648.png', 'https://media.retroachievements.org/Images/064345.png', 'https://media.retroachievements.org/Images/050445.png', 4.7),
  (20, 10525, 'Patapon', 'PlayStation Portable', 41, 2695, 2695, 2695, 75, 0, 'Rhythm', 'Pyramid', 'Sony Computer Entertainment', '2007-09-20', 'Patapon is a 2007 rhythm video game developed by Pyramid and Japan Studio and published by Sony Computer Entertainment for the PlayStation Portable. The game''s unique genre was described to be a combination of rhythm and strategy. Its concept and design were conceived when game designer Hiroyuki Kotani discovered the Patapon designs from French artist Rolito''s personal website. The name Patapon was created by Rolito and was inspired by an old French song for children. Kotani chose the name because it sounded similar to marching and drumming. The game was released in Japan in December 2007 and in February 2008 in North America and Europe.', 'https://media.retroachievements.org/Images/047445.png', 'https://media.retroachievements.org/Images/047378.png', 'https://media.retroachievements.org/Images/058365.png', 'https://media.retroachievements.org/Images/058367.png', 4.7),
  (21, 3164, 'Shin Megami Tensei: Persona 3 Portable', 'PlayStation Portable', 41, 2646, 2646, 2646, 139, 0, 'Turn-Based RPG', 'Atlus', 'Atlus', '2010-07-06', 'Persona 3, released outside Japan as Shin Megami Tensei: Persona 3, is a 2006 role-playing video game developed by Atlus. It is the fourth main installment in the Persona series, which is part of the larger Megami Tensei franchise. It was originally released for the PlayStation 2 in Japan in 2006 and in North America in 2007. It has received several enhanced re-releases and ports: Persona 3 FES, an extended version featuring a new playable epilogue and other changes, was released for the PlayStation 2 in Japan in 2007 and worldwide in 2008. A PlayStation Portable version, Persona 3 Portable, was released in Japan in 2009, North America in 2010, and Europe in 2011, and ported to the Nintendo Switch, PlayStation 4, Windows, Xbox One and Xbox Series X/S in 2023. Persona 3 Reload, a remake of the core game and epilogue, was released in February 2024 for Windows, PlayStation 4, PlayStation 5, Xbox One and Xbox Series X/S, with a Nintendo Switch 2 release occurring in October 2025.', 'https://media.retroachievements.org/Images/123004.png', 'https://media.retroachievements.org/Images/046681.png', 'https://media.retroachievements.org/Images/036344.png', 'https://media.retroachievements.org/Images/036345.png', 4.7),
  (22, 15626, 'Gran Turismo: The Real Driving Simulator', 'PlayStation Portable', 41, 2580, 2580, 2580, 229, 0, 'Racing Simulation', 'Polyphony Digital', 'Sony Computer Entertainment', '2009-10-01', 'Gran Turismo is a 1997 sim racing video game developed and published by Sony Computer Entertainment for the PlayStation. It was directed by Kazunori Yamauchi and produced by Shuhei Yoshida. It is the first game in the Gran Turismo series.', 'https://media.retroachievements.org/Images/115804.png', 'https://media.retroachievements.org/Images/054876.png', 'https://media.retroachievements.org/Images/054877.png', 'https://media.retroachievements.org/Images/054875.png', 4.7),
  (23, 3738, 'Phantasy Star Portable', 'PlayStation Portable', 41, 2539, 2539, 2539, 86, 0, 'Action RPG', 'Sega, Alfa System, Sonic Team', 'Sega', '2008-07-31', 'Phantasy Star Portable is an action role-playing game co-developed by Sonic Team and Alfa System, and published by Sega for the PlayStation Portable. Sega released the game to Japan in July 2008, and to other markets in 2009.', 'https://media.retroachievements.org/Images/053525.png', 'https://media.retroachievements.org/Images/053523.png', 'https://media.retroachievements.org/Images/049244.png', 'https://media.retroachievements.org/Images/053526.png', 4.7),
  (24, 18128, 'Dragon Ball Z: Shin Budokai 2 - Another Road', 'PlayStation Portable', 41, 2520, 2520, 2520, 86, 0, '3D Fighting', 'Dimps', 'Atari, Bandai Namco', '2007-03-20', 'This is a list of games for Sony''s PlayStation Portable (PSP) handheld game console made available to download from the PlayStation Store. The ability to download and play these titles has varied among titles between the platforms of PSP, PlayStation Vita (PSV), PlayStation TV (PSTV), PlayStation 4 (PS4), and PlayStation 5 (PS5). Titles released on the latter two are the original games software emulated. If a downloadable PSP game has been purchased for a device released prior to the PS4, the title is automatically added to the user''s library on all devices for which there is a release.', 'https://media.retroachievements.org/Images/089994.png', 'https://media.retroachievements.org/Images/050045.png', 'https://media.retroachievements.org/Images/049887.png', 'https://media.retroachievements.org/Images/049982.png', 4.7),
  (25, 3165, 'Castlevania: The Dracula X Chronicles', 'PlayStation Portable', 41, 2494, 2494, 2494, 191, 0, 'Metroidvania, 2D Platforming', 'Konami', 'Konami', '2007-11-23', 'Castlevania: The Dracula X Chronicles is a 2007 platform game developed and published by Konami for the PlayStation Portable. The game is a remake of Castlevania: Rondo of Blood (1993) with 2.5D graphics, and marks the first time that Rondo of Blood was released outside of Japan. The game includes the original Rondo of Blood localized into English, as well as a remastered version of Castlevania: Symphony of the Night (1997). The game was released in North America on October 23, 2007.', 'https://media.retroachievements.org/Images/085805.png', 'https://media.retroachievements.org/Images/072411.png', 'https://media.retroachievements.org/Images/072410.png', 'https://media.retroachievements.org/Images/072409.png', 4.6),
  (26, 3236, 'Final Fantasy Tactics: The War of the Lions', 'PlayStation Portable', 41, 2407, 2407, 2407, 172, 0, 'Tactical RPG', 'TOSE', 'Square Enix', '2007-05-10', 'Final Fantasy Tactics: The War of the Lions  is a 2007 tactical role-playing game developed and published by Square Enix for the PlayStation Portable (PSP). The game is an updated version of Final Fantasy Tactics made for the PlayStation, which was released in 1997.', 'https://media.retroachievements.org/Images/074335.png', 'https://media.retroachievements.org/Images/047083.png', 'https://media.retroachievements.org/Images/047085.png', 'https://media.retroachievements.org/Images/047084.png', 4.6),
  (27, 18160, 'Crash of the Titans', 'PlayStation Portable', 41, 2346, 2346, 2346, 76, 0, '3D Platforming, Beat ''em Up', 'Radical Entertainment', 'Sierra Entertainment', '2007-10-16', 'Crash of the Titans is a 2007 platform game developed by Radical Entertainment and published by Vivendi Games for the PlayStation 2, PlayStation Portable, Wii and Xbox 360. The sixth mainline game in the Crash Bandicoot series, it was the last to be published by Vivendi Games before Activision merged with the company the following year. Amaze Entertainment developed two separate versions of the game: one for the Nintendo DS and one for the Game Boy Advance. The game is the fourteenth installment in the Crash Bandicoot video game series, and the sixth game in the main franchise.', 'https://media.retroachievements.org/Images/081112.png', 'https://media.retroachievements.org/Images/053808.png', 'https://media.retroachievements.org/Images/057912.png', 'https://media.retroachievements.org/Images/057911.png', 4.6),
  (28, 17978, 'Ben 10: Protector of Earth', 'PlayStation Portable', 41, 2227, 2227, 2227, 86, 0, NULL, 'High Voltage Software, 1st Playable Productions', 'D3 Publisher', '2007-10-30', 'Ben 10: Protector of Earth is an action-adventure video game developed by High Voltage Software and published by D3 Publisher and is based on the animated television series Ben 10. This is the second Ben 10 game following the HyperScan game, is the first official game in the franchise, and it was released for the PlayStation 2, PlayStation Portable, the Nintendo DS and the Nintendo Wii in late 2007.', 'https://media.retroachievements.org/Images/123052.png', 'https://media.retroachievements.org/Images/050414.png', 'https://media.retroachievements.org/Images/048603.png', 'https://media.retroachievements.org/Images/049525.png', 4.6),
  (29, 6580, 'Jetpack Joyride', 'PlayStation Portable', 41, 2184, 2184, 2184, 37, 0, 'Endless Runner', 'Beatshapers', 'Beatshapers', '2012-11-20', 'Jetpack Joyride is a 2011 endless runner action game created by Halfbrick Studios. It was released for iOS devices on the App Store on September 1, 2011 and has been ported to other systems. It was released online as a Flash version on May 11, 2012; on Android on September 28; on PlayStation Portable on November 20 in North America and November 21 in Europe; on BlackBerry PlayBook on December 13, 2012; on PlayStation 3 and PlayStation Vita on December 21 in Europe and December 31 in North America; on BlackBerry 10 on March 6, 2013; and on Windows Phone 8 and Windows 8 on June 5. It was also released on PlayStation 4 on April 26, 2016. A mobile version using the keypad was released in 2021 for KaiOS devices.', 'https://media.retroachievements.org/Images/049686.png', 'https://media.retroachievements.org/Images/059897.png', 'https://media.retroachievements.org/Images/047051.png', 'https://media.retroachievements.org/Images/047065.png', 4.6),
  (30, 3556, 'Kingdom Hearts: Birth by Sleep -Final Mix-', 'PlayStation Portable', 41, 2165, 2165, 2165, 132, 0, 'Action RPG', 'Square Enix', 'Square Enix', '2011-01-20', 'Hikari  is a song recorded by Japanese–American recording artist Hikaru Utada for their fourth studio and third Japanese language album, Deep River (2002). It was released on March 20, 2002, as the third single from the album in Japan. It was written and composed by Utada, whilst production and arrangement was handled by Utada, Teruzane Utada, and long-time collaborator Miyake Akira. The single, and a remix by Russell McNamara, was used as the official Japanese theme song for the 2002 action role-playing video game Kingdom Hearts, and appeared on its original soundtrack. Musically, Hikari is a pop folk song with lyrics about mysteries in life and human activities.', 'https://media.retroachievements.org/Images/111025.png', 'https://media.retroachievements.org/Images/051027.png', 'https://media.retroachievements.org/Images/051025.png', 'https://media.retroachievements.org/Images/051026.png', 4.6),
  (31, 3169, 'Final Fantasy IV: The Complete Collection', 'PlayStation Portable', 41, 2108, 2108, 2108, 306, 0, NULL, 'Square Enix', 'Square Enix', '2011-03-24', 'Final Fantasy IV: The Complete Collection is a 2011 role-playing video game compilation co-developed by Square Enix and Bullets and published by Square Enix for the PlayStation Portable. The collection consists of enhanced ports of Final Fantasy IV (1991) and Final Fantasy IV: The After Years (2008), as well as a new scenario called Final Fantasy IV Interlude, which is set between the two games. It was released in Japan on March 24, 2011, before being released to other markets in April. It was also released as digital download.', 'https://media.retroachievements.org/Images/093953.png', 'https://media.retroachievements.org/Images/046881.png', 'https://media.retroachievements.org/Images/046886.png', 'https://media.retroachievements.org/Images/046884.png', 4.6),
  (32, 3199, 'Tony Hawk''s Underground 2: Remix', 'PlayStation Portable', 41, 2104, 2104, 2104, 147, 0, 'Extreme Sports - Skateboarding', 'Neversoft, Shaba Games', 'Activision', '2005-03-24', 'Tony Hawk''s is a series of skateboarding video games published by Activision and endorsed by the American professional skateboarder of the same name. From 1999 to 2007, the series was primarily developed for home consoles by Neversoft with generally annual releases. In 2008, Activision transferred the franchise to Robomodo, which released several additions before Activision and Hawk''s license expired in 2015, leaving the future of the series uncertain. In 2020, the series returned under Activision with a remake of the original two games in the series, and a remake of the third and fourth games in 2025 developed by Vicarious Visions and Iron Galaxy respectively.', 'https://media.retroachievements.org/Images/082839.png', 'https://media.retroachievements.org/Images/047104.png', 'https://media.retroachievements.org/Images/080317.png', 'https://media.retroachievements.org/Images/080318.png', 4.6),
  (33, 3214, 'Assassin''s Creed: Bloodlines', 'PlayStation Portable', 41, 1928, 1928, 1928, 36, 0, NULL, 'Griptonite Games', 'Ubisoft', '2009-11-17', 'This is a list of video games considered controversial. The list includes games that have earned controversies for violence, sexual content, racism, and review bombing from fans. Some of the video games on this list have been banned or regionally censored.', 'https://media.retroachievements.org/Images/089689.png', 'https://media.retroachievements.org/Images/046657.png', 'https://media.retroachievements.org/Images/064365.png', 'https://media.retroachievements.org/Images/064364.png', 4.6),
  (34, 3203, 'Tekken: Dark Resurrection', 'PlayStation Portable', 41, 1870, 1870, 1870, 92, 0, '3D Fighting', 'Bandai Namco', 'Bandai Namco', '2006-07-25', 'Tekken 5: Dark Resurrection , Tekken: Dark Resurrection for the PlayStation Portable version, is a 2005 fighting game and a standalone update to Tekken 5 (2004). The arcade version was released in Japan in December 2005 and later worldwide in February of 2006, while the PlayStation Portable version was released later that year in July 2006. It was also released as a downloadable game on the PlayStation 3 via the PlayStation Network online service in Japan in 2006 and the rest of the world in 2007. A sequel, Tekken 6 was released in 2007.', 'https://media.retroachievements.org/Images/086827.png', 'https://media.retroachievements.org/Images/048531.png', 'https://media.retroachievements.org/Images/090768.png', 'https://media.retroachievements.org/Images/090769.png', 4.6),
  (35, 3222, 'Grand Theft Auto: Chinatown Wars', 'PlayStation Portable', 41, 1821, 1821, 1821, 105, 0, 'Action-Adventure, Sandbox', 'Rockstar Leeds, Rockstar North', 'Rockstar Games', '2009-10-20', 'Grand Theft Auto (GTA) is an action-adventure video game series created by David Jones and Mike Dailly. Later titles were developed under the oversight of brothers Dan and Sam Houser, Leslie Benzies and Aaron Garbut. It is primarily developed by British development house Rockstar North, and published by its American parent company, Rockstar Games. The name of the series is a term for motor vehicle theft in the United States.', 'https://media.retroachievements.org/Images/098730.png', 'https://media.retroachievements.org/Images/048650.png', 'https://media.retroachievements.org/Images/081633.png', 'https://media.retroachievements.org/Images/081635.png', 4.6),
  (36, 18010, 'LEGO Batman: The Videogame', 'PlayStation Portable', 41, 1813, 1813, 1813, 45, 0, 'Action-Adventure', 'Traveller''s Tales', 'Warner Bros. Interactive Entertainment', '2008-09-23', 'Lego Batman: The Videogame is a 2008 action-adventure video game developed by Traveller''s Tales and published by Warner Bros. Interactive Entertainment, released for the Xbox 360, PlayStation 3, PlayStation 2, PlayStation Portable, Wii, Nintendo DS, Microsoft Windows, and Mac OS X. The game is based on the DC Comics character Batman, as well as the eponymous Lego Batman toyline.', 'https://media.retroachievements.org/Images/063673.png', 'https://media.retroachievements.org/Images/051654.png', 'https://media.retroachievements.org/Images/051653.png', 'https://media.retroachievements.org/Images/051655.png', 4.6),
  (37, 5360, 'Angry Birds', 'PlayStation Portable', 41, 1765, 1765, 1765, 36, 0, 'Physics Puzzle', 'Rovio Entertainment, Abstraction Games', 'Rovio Entertainment, Chillingo', '2011-01-05', 'The Angry Birds Movie is a 2016 animated comedy film based on the Angry Birds video game series. It was directed by Clay Kaytis and Fergal Reilly, and written by Jon Vitti. It features the voices of Jason Sudeikis, Josh Gad, Danny McBride, Maya Rudolph, Kate McKinnon, Sean Penn, Tony Hale, Keegan-Michael Key, Bill Hader, and Peter Dinklage. The film follows Red, an outcast on an island of anthropomorphic flightless birds, as he suspects a newly arrived crew of pigs, led by Leonard, of plotting an evil plan, and attempts to put a stop to them with the help of his newfound friends Chuck and Bomb.', 'https://media.retroachievements.org/Images/062993.png', 'https://media.retroachievements.org/Images/063458.png', 'https://media.retroachievements.org/Images/063456.png', 'https://media.retroachievements.org/Images/063457.png', 4.6),
  (38, 18080, 'Ridge Racer 2', 'PlayStation Portable', 41, 1713, 1713, 1713, 88, 0, 'Arcade Racing', 'Bandai Namco', 'Bandai Namco', '2006-09-14', 'Ridge Racer 2 is a 1994 arcade racing game developed and published by Namco for arcades. A sequel to Ridge Racer, it features more quality-of-life changes than substantial new content. One major addition is the ability to play with up to eight human players.', 'https://media.retroachievements.org/Images/086289.png', 'https://media.retroachievements.org/Images/050683.png', 'https://media.retroachievements.org/Images/050681.png', 'https://media.retroachievements.org/Images/050682.png', 4.6),
  (39, 3465, 'Manhunt 2', 'PlayStation Portable', 41, 1708, 1708, 1708, 95, 0, 'Psychological Horror, Stealth', 'Rockstar Leeds', 'Rockstar Games', '2007-10-30', 'Manhunt 2 is a 2007 stealth game by Rockstar Games. It was developed by Rockstar London for Microsoft Windows and PlayStation 2, Rockstar Leeds for the PlayStation Portable, and Rockstar Toronto for the Wii. It is the sequel to 2003''s Manhunt and was released in North America on 29 October 2007, and in PAL territories from 31 October 2008. The game follows Daniel Lamb, a mental patient suffering from amnesia as he tries to uncover his identity, and Leo Kasper, a sociopathic assassin who guides Daniel in his journey.', 'https://media.retroachievements.org/Images/107696.png', 'https://media.retroachievements.org/Images/053187.png', 'https://media.retroachievements.org/Images/081962.png', 'https://media.retroachievements.org/Images/081963.png', 4.6),
  (40, 12798, 'Tetris', 'PlayStation Portable', 41, 1698, 1698, 1698, 36, 0, NULL, 'EA Mobile', 'Electronic Arts', '2009-10-01', 'Tetris is a puzzle video game created in 1985 by Alexey Pajitnov, a Soviet software engineer. In the game, falling tetromino shapes must be neatly sorted into a pile. Once a horizontal line of the board is filled in, the line disappears, granting points and preventing the pile from overflowing. Since its initial creation, this gameplay has been used in over 220 versions, released for over 70 platforms. Newer versions frequently implement additional game mechanics, some of which have become standard over time. As of December 2024, these versions collectively serve as the second-best-selling video game series with over 520 million sales, mostly on mobile devices.', 'https://media.retroachievements.org/Images/069977.png', 'https://media.retroachievements.org/Images/069628.png', 'https://media.retroachievements.org/Images/069622.png', 'https://media.retroachievements.org/Images/069626.png', 4.5),
  (41, 3224, 'Wipeout Pure', 'PlayStation Portable', 41, 1693, 1693, 1693, 237, 0, 'Arcade Racing', 'Psygnosis | Studio Liverpool', 'Sony Computer Entertainment', '2005-03-16', 'Wipeout Pure is a 2005 racing video game developed by Studio Liverpool and published by Sony Computer Entertainment for the PlayStation Portable. It was released as a launch title for the platform in North America and PAL territories, in March and September respectively. The sixth installment of the Wipeout series, following Wipeout Fusion (2002), the game takes place in the year 2197, exactly 100 years after the events of Wipeout 2097 (1996), and revolves around players competing in the FX300 anti-gravity racing league.', 'https://media.retroachievements.org/Images/049610.png', 'https://media.retroachievements.org/Images/053039.png', 'https://media.retroachievements.org/Images/049725.png', 'https://media.retroachievements.org/Images/049726.png', 4.5),
  (42, 3192, 'Crash Tag Team Racing', 'PlayStation Portable', 41, 1690, 1690, 1690, 75, 0, '3D Platforming, Kart Racing, Vehicular Combat', 'Radical Entertainment', 'Sierra Entertainment', '2005-11-10', 'Crash Tag Team Racing is a 2005 kart racing and platform game developed by Radical Entertainment and published by Vivendi Universal Games for the PlayStation 2 (PS2), Xbox, GameCube, and PlayStation Portable (PSP). A version for the Nintendo DS by Sensory Sweep Studios was cancelled near its completion. It is the third racing game in the Crash Bandicoot video game series, following Crash Nitro Kart (2003). The game''s story takes place in a racing-based theme park, in which Crash Bandicoot must recover its missing Power Gems to claim the park''s ownership.', 'https://media.retroachievements.org/Images/074990.png', 'https://media.retroachievements.org/Images/053807.png', 'https://media.retroachievements.org/Images/053958.png', 'https://media.retroachievements.org/Images/053957.png', 4.5),
  (43, 7532, 'Yu-Gi-Oh! GX Tag Force', 'PlayStation Portable', 41, 1681, 1681, 1681, 203, 0, 'Collectible Card Game', 'Konami', 'Konami', '2006-09-14', 'The following is a list of video games developed and published by Konami, based on Kazuki Takahashi''s Yu-Gi-Oh! manga and anime franchise, along with its spin-off series. With some exceptions, the majority of the games follow the card battle gameplay of the real-life Yu-Gi-Oh! Trading Card Game. There are 59 in total.', 'https://media.retroachievements.org/Images/048254.png', 'https://media.retroachievements.org/Images/047370.png', 'https://media.retroachievements.org/Images/047371.png', 'https://media.retroachievements.org/Images/047483.png', 4.5),
  (44, 3476, 'SoulCalibur: Broken Destiny', 'PlayStation Portable', 41, 1665, 1665, 1665, 47, 0, '3D Fighting', 'Project Soul', 'Bandai Namco', '2009-09-01', 'Soulcalibur: Broken Destiny is a 2009 fighting game developed by Project Soul and published by Namco Bandai Games for the PlayStation Portable. A spin-off of the Soulcalibur series, the game uses many of the features of Soulcalibur IV, including its character customization mode. One of the goals of the game is to target beginners and novice players with Soulcalibur IV''s content. It introduces two new characters to the series: Kratos from the God of War series and Dampierre, a new original character. In December 2023, the game was released digitally on PlayStation 4 and PlayStation 5.', 'https://media.retroachievements.org/Images/109974.png', 'https://media.retroachievements.org/Images/062777.png', 'https://media.retroachievements.org/Images/062769.png', 'https://media.retroachievements.org/Images/062770.png', 4.5),
  (45, 3517, 'Dissidia: Final Fantasy', 'PlayStation Portable', 41, 1663, 1663, 1663, 152, 0, 'Arena Fighting', 'Square Enix', 'Square Enix', '2009-08-25', 'Dissidia Final Fantasy is a 2008 fighting game developed and published by Square Enix for the PlayStation Portable. It was released in Japan on December 18, 2008, in North America on August 25, 2009, and in Australia and Europe in September, as part of the campaign for the Final Fantasy series''s 20th anniversary. It was then re-released in Japan, based on the North American version, as Dissidia Final Fantasy: Universal Tuning, on November 1, 2009.', 'https://media.retroachievements.org/Images/049135.png', 'https://media.retroachievements.org/Images/047368.png', 'https://media.retroachievements.org/Images/047366.png', 'https://media.retroachievements.org/Images/047367.png', 4.5),
  (46, 3737, 'Shin Megami Tensei: Persona 2: Innocent Sin', 'PlayStation Portable', 41, 1584, 1584, 1584, 96, 0, 'Turn-Based RPG', 'Atlus', 'Atlus', '2011-04-14', 'Persona 2: Innocent Sin is a 1999 role-playing video game developed and published by Atlus for the PlayStation. It is the second entry in the Persona series, itself a subseries of the Megami Tensei franchise, and acts as a sequel to the original Persona. The game was re-released in 2011 for the PlayStation Portable. The original version was not localized for western territories; however, the PSP version was released in North America and Europe under the title Shin Megami Tensei: Persona 2 – Innocent Sin.', 'https://media.retroachievements.org/Images/115940.png', 'https://media.retroachievements.org/Images/053389.png', 'https://media.retroachievements.org/Images/075419.png', 'https://media.retroachievements.org/Images/075420.png', 4.5),
  (47, 3160, 'Ys Seven', 'PlayStation Portable', 41, 1575, 1575, 1575, 202, 0, 'Action RPG', 'Nihon Falcom', 'Nihon Falcom, XSEED Games', '2009-09-17', 'Ys Seven is a 2009 action role-playing game developed by Nihon Falcom. An installment in the Ys series, it was first released in Japan for the PlayStation Portable in September 2009. Xseed Games released the game in 2010 in North America in August, and Europe in November. The game was later released in Australia in February 2013. It was also released for Windows in China in June 2012, and worldwide by Xseed Games in August 2017.', 'https://media.retroachievements.org/Images/047359.png', 'https://media.retroachievements.org/Images/041065.png', 'https://media.retroachievements.org/Images/041063.png', 'https://media.retroachievements.org/Images/041064.png', 4.5),
  (48, 10477, 'Daxter', 'PlayStation Portable', 41, 1554, 1554, 1554, 83, 0, '3D Platforming', 'Ready at Dawn', 'Sony Computer Entertainment', '2006-03-14', 'Daxter is a 2006 platform video game developed by Ready at Dawn and published by Sony Computer Entertainment for the PlayStation Portable. A spin-off of the Jak and Daxter series, Daxter takes place during the two-year timeskip occurring during the opening cutscene of Jak II; unlike the other installments of the franchise focusing primarily on Jak, the game focuses on the adventures of his sidekick Daxter while Jak is imprisoned.', 'https://media.retroachievements.org/Images/122563.png', 'https://media.retroachievements.org/Images/047005.png', 'https://media.retroachievements.org/Images/047007.png', 'https://media.retroachievements.org/Images/047006.png', 4.5),
  (49, 3539, 'Half-Minute Hero', 'PlayStation Portable', 41, 1545, 1545, 1545, 110, 0, 'Action RPG', 'Marvelous Entertainment', 'XSEED Games', '2009-10-13', 'Half-Minute Hero: The Second Coming is a 2011 action role-playing game developed by Opus and published by Marvelous. It is the sequel to Half-Minute Hero. It was released in Japan for the PlayStation Portable before being localized in English for Windows in 2014.', 'https://media.retroachievements.org/Images/047362.png', 'https://media.retroachievements.org/Images/060895.png', 'https://media.retroachievements.org/Images/060887.png', 'https://media.retroachievements.org/Images/060888.png', 4.5),
  (50, 3993, 'LEGO Indiana Jones: The Original Adventures', 'PlayStation Portable', 41, 1541, 1541, 1541, 53, 0, 'Action-Adventure', 'Traveller''s Tales', 'LucasArts | Lucasfilm', '2008-06-03', 'Lego Indiana Jones: The Original Adventures is a 2008 Lego-themed action-adventure video game developed by Traveller''s Tales and published by LucasArts. Based on the Indiana Jones franchise and the eponymous Lego Indiana Jones toy line, it follows the events of the first three Indiana Jones films: Raiders of the Lost Ark (1981), Temple of Doom (1984), and the Last Crusade (1989). The game includes local co-op mode gameplay, as well as puzzle and platformer aspects, and 84 playable characters with a variety of special abilities. As the players go through the stages, they collect the currency of Lego games known as Studs, avoid traps, assemble Lego constructions, and engage in combat. Climbing, swinging, and throwing objects as weapons were new inclusions not seen in previous Lego video games by Traveller''s Tales.', 'https://media.retroachievements.org/Images/123775.png', 'https://media.retroachievements.org/Images/047008.png', 'https://media.retroachievements.org/Images/047010.png', 'https://media.retroachievements.org/Images/047011.png', 4.5),
  (51, 3159, 'Ys I & II Chronicles', 'PlayStation Portable', 41, 1492, 1492, 1492, 182, 0, 'Action RPG', 'Nihon Falcom', 'XSEED Games', '2009-07-16', 'Ys I & II  is an action role-playing game compilation released by Hudson Soft for the PC Engine CD-ROM² in 1989 and by NEC for the TurboGrafx-CD in 1990. It consists of enhanced remakes of the first two Ys games by Nihon Falcom for the PC-8801 home computer in Japan. It was released as Ys Book I & II for the TurboGrafx-CD in North America in 1990, and was a pack-in title for the TurboDuo in 1992. Ys I & II was released on the Wii Virtual Console in Japan in October 2007, and worldwide the following year. A port to X68000 was released in 2021.', 'https://media.retroachievements.org/Images/057456.png', 'https://media.retroachievements.org/Images/055343.png', 'https://media.retroachievements.org/Images/055345.png', 'https://media.retroachievements.org/Images/055346.png', 4.5),
  (52, 18163, 'Toy Story 3', 'PlayStation Portable', 41, 1477, 1477, 1477, 90, 0, '3D Platforming, Action', 'Asobo Studio', 'Disney Interactive Studios', '2010-06-15', 'Toy Story 3 is a 2010 American animated adventure and comedy-drama film produced by Pixar Animation Studios for Walt Disney Pictures. Directed by Lee Unkrich and written by Michael Arndt, it is the third installment in the Toy Story film series and the sequel to Toy Story 2 (1999). The film features the voices of Tom Hanks, Tim Allen, Joan Cusack, Don Rickles, Wallace Shawn, John Ratzenberger, Estelle Harris, Jodi Benson, and John Morris. In the film, Andy Davis, now a teenager, is going to college. Woody, Buzz Lightyear and the other toys are accidentally donated to the Sunnyside Daycare center by Andy''s mother, and the toys must decide where their loyalties lie.', 'https://media.retroachievements.org/Images/082679.png', 'https://media.retroachievements.org/Images/082677.png', 'https://media.retroachievements.org/Images/082680.png', 'https://media.retroachievements.org/Images/082681.png', 4.5),
  (53, 3970, 'Grand Theft Auto: Liberty City Stories', 'PlayStation Portable', 41, 1473, 1473, 1473, 93, 0, 'Action-Adventure, Sandbox', 'Rockstar Leeds', 'Rockstar Games', '2005-10-24', 'Grand Theft Auto: Liberty City Stories is a 2005 action-adventure game developed in a collaboration between Rockstar Leeds and Rockstar North, and published by Rockstar Games. The ninth installment in the Grand Theft Auto series, it was initially released as a PlayStation Portable exclusive in October 2005. A port for the PlayStation 2 was later released in June 2006. At the time of release, the recommended retail price of the PS2 port was around half the price of the PSP version, because the PS2 version does not feature the custom soundtrack ripping capability of the PSP version. Ports for iOS, Android and Fire OS devices were also released in December 2015, February 2016, and March 2016, respectively.', 'https://media.retroachievements.org/Images/048626.png', 'https://media.retroachievements.org/Images/048646.png', 'https://media.retroachievements.org/Images/048597.png', 'https://media.retroachievements.org/Images/048598.png', 4.5),
  (54, 10523, 'LocoRoco', 'PlayStation Portable', 41, 1458, 1458, 1458, 101, 0, '2D Platforming, Physics Puzzle', 'Japan Studio', 'Sony Computer Entertainment', '2006-06-23', 'LocoRoco is a 2006 platform video game developed and published by Sony Computer Entertainment for the PlayStation Portable. The game was conceived by Tsutomu Kouno, who strived to create a game that was different from other titles being released for the PSP at the time. After demonstrating a prototype of the core gameplay to his management, Kouno was able to complete development over the course of a year and a half. In LocoRoco, the player must tilt the environment by using the shoulder buttons on the PSP in order to maneuver the LocoRoco, multi-colored jelly-like characters, through each level, being aided by other odd residents while avoiding hazards and the deadly Moja Troop, to reach an end goal.', 'https://media.retroachievements.org/Images/079490.png', 'https://media.retroachievements.org/Images/040023.png', 'https://media.retroachievements.org/Images/040024.png', 'https://media.retroachievements.org/Images/040025.png', 4.5),
  (55, 29730, '~Homebrew~ Cave Story', 'PlayStation Portable', 41, 1438, 1438, 1438, 183, 0, '2D Platforming, Metroidvania, Run & Gun', 'ufo_z', 'ufo_z', '2007-07-08', 'Cave Story is a 2004 Metroidvania game for Microsoft Windows. It was developed over five years by Japanese independent developer Daisuke Pixel Amaya in his free time. Cave Story features 2D platform mechanics and is reminiscent of the games Amaya played in his youth, such as Metroid and Castlevania. After its initial self-published release, the game slowly gained popularity on the internet. It received widespread critical acclaim for many polished aspects of its design, such as its compelling characters, setting, story, and gameplay. Cave Story is considered by many as a quintessential indie game because of its one-person development team and influence on the video gaming world.', 'https://media.retroachievements.org/Images/118843.png', 'https://media.retroachievements.org/Images/107290.png', 'https://media.retroachievements.org/Images/095735.png', 'https://media.retroachievements.org/Images/106160.png', 4.5),
  (56, 3995, 'Initial D: Street Stage', 'PlayStation Portable', 41, 1403, 1403, 1403, 40, 0, 'Arcade Racing', 'TOSE', 'Sega', '2006-02-23', 'The Initial D video game series, known in Japan as Initial D Arcade Stage, is an arcade racing game series developed by Sega, based on the anime and manga series Initial D. In the United States and Europe, the game series is simply known as Initial D.', 'https://media.retroachievements.org/Images/047610.png', 'https://media.retroachievements.org/Images/046911.png', 'https://media.retroachievements.org/Images/046913.png', 'https://media.retroachievements.org/Images/046909.png', 4.5),
  (57, 14204, 'Midnight Club: L.A. Remix', 'PlayStation Portable', 41, 1403, 1403, 1403, 59, 0, 'Arcade Racing', 'Rockstar San Diego', 'Rockstar Games', '2008-10-21', 'Midnight Club: Los Angeles is a 2008 racing video game developed by Rockstar San Diego and published by Rockstar Games. It is the fourth installment in the Midnight Club series before it was discontinued in January 2010. The game features 43 cars and 3 motorcycles. The open world map of Los Angeles is the size of all three cities from Midnight Club 3: DUB Edition combined. After several delays, Midnight Club: Los Angeles was released in October 2008.', 'https://media.retroachievements.org/Images/105220.png', 'https://media.retroachievements.org/Images/116057.png', 'https://media.retroachievements.org/Images/100183.png', 'https://media.retroachievements.org/Images/100182.png', 4.5),
  (58, 3511, 'The 3rd Birthday', 'PlayStation Portable', 41, 1398, 1398, 1398, 74, 0, 'Action RPG, Third-Person Shooter', 'Square Enix, HexaDrive', 'Square Enix', '2010-12-22', 'The 3rd Birthday  is a 2010 action role-playing game developed by HexaDrive and published by Square Enix for the PlayStation Portable. It was released in Japan in 2010 and in North America and Europe in 2011. The game is the third entry in the Parasite Eve video game series, based on the titular Japanese novel, and a spin-off, having only a loose connection to events from past games. The game features a third-person shooter-based combat system with role-playing mechanics. A key mechanic is the Overdive ability, which allows the player to possess pre-positioned human allies and inflict damage upon enemies.', 'https://media.retroachievements.org/Images/114692.png', 'https://media.retroachievements.org/Images/046661.png', 'https://media.retroachievements.org/Images/055680.png', 'https://media.retroachievements.org/Images/055679.png', 4.5),
  (59, 18158, 'Dragon Ball Z: Tenkaichi Tag Team', 'PlayStation Portable', 41, 1378, 1378, 1378, 83, 0, 'Arena Fighting', 'Spike', 'Bandai Namco', '2010-09-30', 'PlayStation Hits is a branding used by Sony Interactive Entertainment for discounted reprints of PlayStation video games. The branding is used for reprints of popular, top-selling games for each console in the PlayStation family, which are deliberately sold with a lower MSRP than the original production runs of a game, and feature special branding—colored in red since PlayStation 2—on their box art, as well as red-colored cases on PlayStation Portable, PlayStation Vita, PlayStation 3, PlayStation 4, and PlayStation 5 releases.', 'https://media.retroachievements.org/Images/104588.png', 'https://media.retroachievements.org/Images/050074.png', 'https://media.retroachievements.org/Images/050075.png', 'https://media.retroachievements.org/Images/050100.png', 4.5),
  (60, 3888, 'Midnight Club 3: DUB Edition', 'PlayStation Portable', 41, 1352, 1352, 1352, 94, 0, 'Arcade Racing', 'Rockstar San Diego', 'Rockstar Games', '2005-06-28', 'The following is a list of notable vehicle racing video games. The genre first emerged in the mid- to late 1970s.', 'https://media.retroachievements.org/Images/047360.png', 'https://media.retroachievements.org/Images/047361.png', 'https://media.retroachievements.org/Images/047744.png', 'https://media.retroachievements.org/Images/047743.png', 4.5),
  (61, 3187, 'LEGO Star Wars II: The Original Trilogy', 'PlayStation Portable', 41, 1299, 1299, 1299, 41, 0, 'Action-Adventure', 'Traveller''s Tales', 'LucasArts | Lucasfilm', '2006-09-12', 'Lego Star Wars II: The Original Trilogy is a 2006 Lego-themed action-adventure game developed by Traveller''s Tales and published by LucasArts and TT Games Publishing, and is the sequel to Lego Star Wars: The Video Game (2005). Part of the Lego Star Wars series, it is based on George Lucas''s movie franchise of the same name and The Lego Group''s Lego Star Wars construction toy line. It follows the events of the first three original Star Wars films: A New Hope (1977), The Empire Strikes Back (1980), and Return of the Jedi (1983). The game allows players to assume the roles of over 50 Lego versions of characters from the film series; customized characters can also be created. Camera movement was improved from its predecessor, and the concept of vehicle levels was explored more thoroughly. The game was revealed at American International Toy Fair. Promotions for the game were set up at chain stores across the United States.', 'https://media.retroachievements.org/Images/064176.png', 'https://media.retroachievements.org/Images/052466.png', 'https://media.retroachievements.org/Images/052470.png', 'https://media.retroachievements.org/Images/052471.png', 4.5),
  (62, 3822, 'Final Fantasy II', 'PlayStation Portable', 41, 1295, 1295, 1295, 115, 0, NULL, 'Square Enix', 'Square Enix', '2007-06-07', 'Final Fantasy II is a 1988 role-playing video game developed and published by Square for the Family Computer as the second installment of the Final Fantasy series. It was ported to and remade for WonderSwan Color, PlayStation, Game Boy Advance, PlayStation Portable, and mobile phones. Originally exclusive to Japan, later versions were released internationally, including the 2021 Final Fantasy Pixel Remaster version. The story follows the warrior Firion and his allies as they join a rebellion against the expanding Palamecian Empire. The gameplay is similar to the original game with an overworld and dungeon exploration, but its combat design is changed to a usage-based growth system where characters'' statistics increase according to how they are used or acquired.', 'https://media.retroachievements.org/Images/070786.png', 'https://media.retroachievements.org/Images/049847.png', 'https://media.retroachievements.org/Images/068024.png', 'https://media.retroachievements.org/Images/084411.png', 4.5),
  (63, 3572, 'MediEvil: Resurrection', 'PlayStation Portable', 41, 1258, 1258, 1258, 51, 0, 'Action-Adventure', NULL, 'Sony Computer Entertainment', '2005-09-13', 'MediEvil: Resurrection is a 2005 action-adventure game developed by SCEE Cambridge Studio and published by Sony Computer Entertainment for the PlayStation Portable. It is a re-imagining of the first installment in the series, MediEvil. It was first released as a launch title in September 2005 in North America and Europe. The game is set in the medieval Kingdom of Gallowmere and centres around the charlatan protagonist, Sir Daniel Fortesque, as he makes an attempt to stop antagonist Zarok''s invasion of the kingdom whilst simultaneously redeeming himself. The game also features a variety of voice talents, including Tom Baker as the narrator and the Grim Reaper.', 'https://media.retroachievements.org/Images/075441.png', 'https://media.retroachievements.org/Images/114356.png', 'https://media.retroachievements.org/Images/076993.png', 'https://media.retroachievements.org/Images/076992.png', 4.5),
  (64, 3589, 'Metal Gear Solid: Portable Ops', 'PlayStation Portable', 41, 1241, 1241, 1241, 54, 0, 'Action-Adventure, Stealth', 'Kojima Productions', 'Konami', '2006-12-05', 'Metal Gear Solid: Portable Ops, officially abbreviated MPO, is a 2006 action-adventure stealth game developed and published by Konami for the PlayStation Portable. The game was directed by Masahiro Yamamoto and written by Gakuto Mikumo, with series creator Hideo Kojima acting as producer.', 'https://media.retroachievements.org/Images/047374.png', 'https://media.retroachievements.org/Images/046894.png', 'https://media.retroachievements.org/Images/046896.png', 'https://media.retroachievements.org/Images/118047.png', 4.5),
  (65, 14662, 'Valkyria Chronicles 2', 'PlayStation Portable', 41, 1204, 1204, 1204, 314, 0, 'Tactical RPG', 'Sega CS3', 'Sega', '2010-01-21', 'Valkyria Chronicles II is a tactical role-playing video game developed and published by Sega for the PlayStation Portable. Released in 2010, it is the second game in the Valkyria Chronicles series of games and the sequel to Valkyria Chronicles.', 'https://media.retroachievements.org/Images/047365.png', 'https://media.retroachievements.org/Images/046783.png', 'https://media.retroachievements.org/Images/046785.png', 'https://media.retroachievements.org/Images/046784.png', 4.5),
  (66, 3929, 'PaRappa the Rapper', 'PlayStation Portable', 41, 1187, 1187, 1187, 34, 0, 'Rhythm', 'epics', 'Sony Computer Entertainment', '2006-12-07', 'PaRappa the Rapper is a rhythm video game developed by NanaOn-Sha and published by Sony Computer Entertainment for the PlayStation. It was originally released in Japan in 1996 and worldwide in 1997. Created by music producer Masaya Matsuura in collaboration with artist Rodney Greenblat, the game features unique visual design and rap-based gameplay and is considered to be the first true rhythm game. It was ported to the PlayStation Portable in 2006 in celebration of its 10-year anniversary. A remastered version of the original PlayStation game was released for PlayStation 4 in 2017 for the game''s twentieth anniversary.', 'https://media.retroachievements.org/Images/123526.png', 'https://media.retroachievements.org/Images/048596.png', 'https://media.retroachievements.org/Images/048608.png', 'https://media.retroachievements.org/Images/048607.png', 4.5),
  (67, 3587, 'Ultimate Ghosts ''n Goblins', 'PlayStation Portable', 41, 1184, 1184, 1184, 42, 0, '2D Platforming, Action', 'Tose', 'Capcom', '2006-08-13', 'Ultimate Ghosts ''n Goblins is a video game in Capcom''s Ghosts ''n Goblins series, developed by Tose and published by Capcom. It was released for the PlayStation Portable on August 3, 2006, in Japan and August 29, 2006, in North America. Ultimate Ghosts ''n Goblins is the first game in the main series to employ 3D graphics, while maintaining much of the 2D gameplay mechanics of the earlier games. It also marks the return of the series'' project head, Tokuro Fujiwara.', 'https://media.retroachievements.org/Images/052631.png', 'https://media.retroachievements.org/Images/040564.png', 'https://media.retroachievements.org/Images/040572.png', 'https://media.retroachievements.org/Images/040578.png', 4.5),
  (68, 4004, 'Metal Slug XX', 'PlayStation Portable', 41, 1170, 1170, 1170, 52, 0, 'Run & Gun', 'SNK', 'SNK, Atlus', '2009-12-23', 'Metal Slug 7 is a run and gun video game developed by SNK Playmore for the Nintendo DS. It is the seventh and final title in the main Metal Slug series. It marks the first game in the main series that would be released without an arcade version. The game was released in 2008 for Japan on July 22 and North America on November 28 by Ignition Entertainment.', 'https://media.retroachievements.org/Images/065558.png', 'https://media.retroachievements.org/Images/054830.png', 'https://media.retroachievements.org/Images/049508.png', 'https://media.retroachievements.org/Images/116697.png', 4.5),
  (69, 3514, 'Ape Escape: On the Loose', 'PlayStation Portable', 41, 1164, 1164, 1164, 93, 0, '3D Platforming', 'SIMS | Sanritsu', 'Sony Computer Entertainment', '2005-03-22', 'Ape Escape is a 1999 platform game developed and published by Sony Computer Entertainment for the PlayStation. The first game in the Ape Escape series, the game tells the story of an ape named Specter who gains enhanced intelligence and a malevolent streak through the use of an experimental helmet. Specter produces an army of apes, which he sends through time in an attempt to rewrite history. Spike, the player character, sets out to capture the apes with the aid of special gadgets.', 'https://media.retroachievements.org/Images/100514.png', 'https://media.retroachievements.org/Images/058233.png', 'https://media.retroachievements.org/Images/053090.png', 'https://media.retroachievements.org/Images/053088.png', 4.5),
  (70, 3951, 'Mortal Kombat: Unchained', 'PlayStation Portable', 41, 1161, 1161, 1161, 74, 0, '3D Fighting', 'JGI Entertainment', 'Midway', '2006-11-13', 'Mortal Kombat is an American media franchise centered on a series of fighting video games originally developed by Midway Games in 1992.', 'https://media.retroachievements.org/Images/124121.png', 'https://media.retroachievements.org/Images/046925.png', 'https://media.retroachievements.org/Images/083096.png', 'https://media.retroachievements.org/Images/083097.png', 4.5),
  (71, 3591, 'Monster Hunter Freedom', 'PlayStation Portable', 41, 1159, 1159, 1159, 199, 0, 'Action RPG', 'Capcom', 'Capcom', '2005-12-01', 'Monster Hunter Freedom is a 2005 action role-playing game developed and published by Capcom for the PlayStation Portable. The first handheld installment in the Monster Hunter franchise, the game is an enhanced port of Monster Hunter G, rebalanced to allow for easier solo quest completion and game progression.', 'https://media.retroachievements.org/Images/085841.png', 'https://media.retroachievements.org/Images/089055.png', 'https://media.retroachievements.org/Images/043632.png', 'https://media.retroachievements.org/Images/043634.png', 4.5),
  (72, 3733, 'N+', 'PlayStation Portable', 41, 1148, 1148, 1148, 109, 0, '2D Platforming', 'Metanet Software & SilverBirch Studios', 'Atari', '2008-08-26', 'N+ is the console and handheld version of the Adobe Flash game N, which was developed by Metanet Software. N+ for Xbox Live Arcade was developed by Slick Entertainment and published by Metanet Software. Unique versions of the game were also ported separately to the PlayStation Portable and Nintendo DS by developers SilverBirch Studios and Atari. Metanet Software licensed their N IP for this deal, provided single player level design for both versions, and consulted on the project.', 'https://media.retroachievements.org/Images/052253.png', 'https://media.retroachievements.org/Images/052449.png', 'https://media.retroachievements.org/Images/052248.png', 'https://media.retroachievements.org/Images/052249.png', 4.4),
  (73, 2970, 'Street Fighter Alpha 3 Max', 'PlayStation Portable', 41, 1131, 1131, 1131, 83, 0, '2D Fighting', 'Capcom', 'Capcom', '2006-01-19', 'Street Fighter Alpha 3, released as Street Fighter Zero 3 in Japan, Asia, South America, and Oceania, is a 1998 fighting game developed and published by Capcom for arcades. It is the third and final installment in the Street Fighter Alpha series, and runs on the same CP System II hardware as previous Alpha games. Alpha 3 further expanded the playable fighter roster from Street Fighter Alpha 2 and added new features such as selectable fighting styles called isms.', 'https://media.retroachievements.org/Images/060818.png', 'https://media.retroachievements.org/Images/053894.png', 'https://media.retroachievements.org/Images/057693.png', 'https://media.retroachievements.org/Images/057692.png', 4.4),
  (74, 3921, 'Hatsune Miku: Project DIVA', 'PlayStation Portable', 41, 1130, 1130, 1130, 95, 0, 'Rhythm', 'Dingo', 'Sega', '2009-07-02', 'This is a list of games for the Sony PlayStation Portable handheld console. It does not include PSOne classics, PS minis, or NEOGEO Station. Games have been released in several regions around the world; North America (NA), Japan (JP), Europe (EU), and Australia (AUS).', 'https://media.retroachievements.org/Images/061882.png', 'https://media.retroachievements.org/Images/046939.png', 'https://media.retroachievements.org/Images/046940.png', 'https://media.retroachievements.org/Images/046941.png', 4.4),
  (75, 2971, 'Peggle', 'PlayStation Portable', 41, 1118, 1118, 1118, 47, 0, 'Action, Pachinko', 'PopCap Games', 'Electronic Arts, PopCap Games', '2010-11-15', 'Peggle is a casual puzzle video game developed by PopCap Games. Initially released for Microsoft Windows and Mac OS X systems in 2007, it has since had versions released for Xbox Live Arcade, PlayStation Network, the Nintendo DS, Windows Mobile, iOS, Zeebo, and Android; the game has also been ported as a Java application, and an extended minigame incorporated into the massively multiplayer online game World of Warcraft. A sequel was released in September 2008, titled Peggle Nights. PopCap, a subsidiary of Electronic Arts, announced Peggle 2 at E3 2013.', 'https://media.retroachievements.org/Images/048181.png', 'https://media.retroachievements.org/Images/114136.png', 'https://media.retroachievements.org/Images/048184.png', 'https://media.retroachievements.org/Images/048185.png', 4.4),
  (76, 18185, 'Williams Pinball Classics | Pinball Hall of Fame: The Williams Collection', 'PlayStation Portable', 41, 1074, 1074, 1074, 116, 0, 'Pinball', 'Farsight Studios', 'Crave Entertainment, System 3 | Play It', '2008-02-26', 'This is a list of games for the Sony PlayStation Portable handheld console. It does not include PSOne classics, PS minis, or NEOGEO Station. Games have been released in several regions around the world; North America (NA), Japan (JP), Europe (EU), and Australia (AUS).', 'https://media.retroachievements.org/Images/050312.png', 'https://media.retroachievements.org/Images/050440.png', 'https://media.retroachievements.org/Images/050311.png', 'https://media.retroachievements.org/Images/050310.png', 4.4),
  (77, 18009, 'Ben 10: Alien Force', 'PlayStation Portable', 41, 1060, 1060, 1060, 43, 0, 'Beat ''em Up', 'Vicious Cycle Software | Monkey Bar Games', 'D3 Publisher', '2008-10-28', 'Ben 10: Alien Force is an American animated television series created by team Man of Action, and produced by Cartoon Network Studios. It is the sequel to Ben 10 (2005–2008), set five years later and taking a darker turn than its predecessor.', 'https://media.retroachievements.org/Images/059702.png', 'https://media.retroachievements.org/Images/059643.png', 'https://media.retroachievements.org/Images/059641.png', 'https://media.retroachievements.org/Images/063502.png', 4.4),
  (78, 20495, 'Naruto Shippuden: Ultimate Ninja Heroes 3', 'PlayStation Portable', 41, 1056, 1056, 1056, 56, 0, '2D Fighting', 'CyberConnect2 | CyberConnect', 'Bandai Namco', '2009-12-10', 'This is a list of games for the Sony PlayStation Portable handheld console. It does not include PSOne classics, PS minis, or NEOGEO Station. Games have been released in several regions around the world; North America (NA), Japan (JP), Europe (EU), and Australia (AUS).', 'https://media.retroachievements.org/Images/124567.png', 'https://media.retroachievements.org/Images/063353.png', 'https://media.retroachievements.org/Images/063350.png', 'https://media.retroachievements.org/Images/063351.png', 4.4),
  (79, 18067, 'The Sims 2', 'PlayStation Portable', 41, 1026, 1026, 1026, 39, 0, 'Life Simulation', 'Amaze Entertainment', 'Electronic Arts', '2005-12-07', 'The Sims is a 2000 social simulation video game developed by Maxis and published by Electronic Arts. The game allows players to create and control virtual people, called Sims, and manage their daily lives in a suburban setting. The game features open-ended gameplay where players can choose their own goals and objectives, and customize their Sims'' appearance, personality, skills, relationships, and environment. A series of expansion packs were also released that add new content and features to the game, such as new careers, items, locations, and scenarios.', 'https://media.retroachievements.org/Images/064779.png', 'https://media.retroachievements.org/Images/064729.png', 'https://media.retroachievements.org/Images/064734.png', 'https://media.retroachievements.org/Images/064735.png', 4.4),
  (80, 2973, 'Medal of Honor: Heroes', 'PlayStation Portable', 41, 1010, 1010, 1010, 40, 0, 'First-Person Shooter', 'Team Fusion', 'Electronic Arts', '2006-10-23', 'This is a list of games for the Sony PlayStation Portable handheld console. It does not include PSOne classics, PS minis, or NEOGEO Station. Games have been released in several regions around the world; North America (NA), Japan (JP), Europe (EU), and Australia (AUS).', 'https://media.retroachievements.org/Images/048163.png', 'https://media.retroachievements.org/Images/048125.png', 'https://media.retroachievements.org/Images/047911.png', 'https://media.retroachievements.org/Images/047912.png', 4.4),
  (81, 22484, 'Naruto Shippuden: Ultimate Ninja Impact', 'PlayStation Portable', 41, 994, 994, 994, 157, 0, 'Hack & Slash', 'CyberConnect2 | CyberConnect, Racjin', 'Bandai Namco', '2011-10-18', 'Naruto: Ultimate Ninja, known in Japan as the Naruto: Narutimate Series , is a series of fighting video games, based on the popular manga and anime series Naruto by Masashi Kishimoto. It was developed by CyberConnect2, and published by Bandai and later Bandai Namco Games. The first game was released in 2004 for the PlayStation 2, and was followed by four more titles for the system, as well as five spinoffs for the PlayStation Portable. A follow-up for the PlayStation 3, titled Naruto: Ultimate Ninja Storm, was the first to feature three-dimensional battles, and began the long-running Storm sub-series. While starting out as a series exclusive to the PlayStation family of systems, the series has also been present on Xbox and PC platforms since the release of Naruto Shippuden: Ultimate Ninja Storm 2 for the Xbox 360 and Naruto Shippuden: Ultimate Ninja Storm 3 Full Burst for Windows, respectively. Latest releases were also ported to the Nintendo Switch. The Naruto: Ultimate Ninja series sold over 20 million copies worldwide as of December 2019. And in 2024 Ultimate Ninja Storm series sold over 30 Million copies and Bandai namco posted a congratulatory art from the author, Masashi Kishimoto, as a celebration of 30 million units sold worldwide.', 'https://media.retroachievements.org/Images/079890.png', 'https://media.retroachievements.org/Images/095357.png', 'https://media.retroachievements.org/Images/095358.png', 'https://media.retroachievements.org/Images/095359.png', 4.4),
  (82, 3914, 'The Simpsons Game', 'PlayStation Portable', 41, 971, 971, 971, 53, 0, '3D Platforming', 'Electronic Arts, Rebellion', 'Electronic Arts', '2007-11-06', 'The Simpsons Game is a 2007 platform game based on the animated television series The Simpsons made for the Nintendo DS, Wii, Xbox 360, PlayStation 2, PlayStation 3 and PlayStation Portable. The game was developed by EA Redwood Shores and published by Electronic Arts. It was released in North America in October 2007 and worldwide in November 2007, a few months after The Simpsons Movie. It features an original storyline, not related to the movie, written by Simpsons writers Tim Long and Matt Warburton. In the self-referential plot, the family discovers that they are forced to participate in another The Simpsons video game. Similar to the show, the game pokes fun at popular culture, many other video games, and EA, its publisher.', 'https://media.retroachievements.org/Images/079434.png', 'https://media.retroachievements.org/Images/048767.png', 'https://media.retroachievements.org/Images/048764.png', 'https://media.retroachievements.org/Images/048765.png', 4.4),
  (83, 3037, 'LEGO Harry Potter: Years 1-4', 'PlayStation Portable', 41, 944, 944, 944, 54, 0, 'Action-Adventure', 'TT Fusion', 'Warner Bros. Interactive Entertainment', '2010-06-25', 'Lego Harry Potter: Years 1–4 is an action-adventure game developed by Traveller''s Tales and published by Warner Bros. Interactive Entertainment. The game is based on the Lego Harry Potter toy line, and its storyline covers the first four books by J. K. Rowling and its film adaptations in the Harry Potter film series, Philosopher''s Stone (2001), Chamber of Secrets (2002), Prisoner of Azkaban (2004), and Goblet of Fire (2005).', 'https://media.retroachievements.org/Images/107797.png', 'https://media.retroachievements.org/Images/073233.png', 'https://media.retroachievements.org/Images/074078.png', 'https://media.retroachievements.org/Images/074080.png', 4.4),
  (84, 6352, '20Q', 'PlayStation Portable', 41, 931, 931, 931, 17, 0, 'Trivia', 'doublesix Video Games', '20Q.net', '2011-04-20', '20Q is a computerized game of twenty questions that began as a test in artificial intelligence (AI). It was invented by Robin Burgener in 1988. The game was made handheld by Radica in 2003, but was discontinued in 2011 because Techno Source took the license for 20Q handheld devices.', 'https://media.retroachievements.org/Images/104385.png', 'https://media.retroachievements.org/Images/048435.png', 'https://media.retroachievements.org/Images/048436.png', 'https://media.retroachievements.org/Images/048437.png', 4.4),
  (85, 3571, 'Me & My Katamari', 'PlayStation Portable', 41, 905, 905, 905, 177, 0, 'Action, Puzzle', 'Namco', 'Namco', '2005-12-22', 'Me & My Katamari is a 2005 action-puzzle video game developed and published by Namco for the PlayStation Portable. It is the third game in the Katamari series, the first game on a portable system and the first game produced without the involvement of series creator Keita Takahashi. It is also the last Katamari game to be published by Namco as an independent company, which merged with Bandai after its release to form Namco Bandai Games in 2006.', 'https://media.retroachievements.org/Images/047357.png', 'https://media.retroachievements.org/Images/047567.png', 'https://media.retroachievements.org/Images/047674.png', 'https://media.retroachievements.org/Images/047673.png', 4.4),
  (86, 10479, 'The Legend of Heroes: Trails in the Sky FC', 'PlayStation Portable', 41, 902, 902, 902, 150, 0, 'Turn-Based RPG', 'Nihon Falcom', 'XSEED Games', '2006-09-28', 'This is a list of games for the PlayStation 5. Physical games are sold on Ultra HD Blu-ray and digital games can be purchased through the PlayStation Store. The PlayStation 5 is backwards compatible with all but nine PlayStation 4 games. This list only includes games that are released natively for PlayStation 5. PlayStation VR2 and backwards compatible games are excluded.', 'https://media.retroachievements.org/Images/038832.png', 'https://media.retroachievements.org/Images/048169.png', 'https://media.retroachievements.org/Images/029555.png', 'https://media.retroachievements.org/Images/046812.png', 4.4),
  (87, 6427, 'Yu-Gi-Oh! ARC-V Tag Force Special', 'PlayStation Portable', 41, 895, 895, 895, 245, 0, 'Collectible Card Game', 'Konami', 'Konami', '2015-01-22', 'This is a list of games for the Sony PlayStation Portable handheld console. It does not include PSOne classics, PS minis, or NEOGEO Station. Games have been released in several regions around the world; North America (NA), Japan (JP), Europe (EU), and Australia (AUS).', 'https://media.retroachievements.org/Images/048259.png', 'https://media.retroachievements.org/Images/047864.png', 'https://media.retroachievements.org/Images/075585.png', 'https://media.retroachievements.org/Images/075586.png', 4.4),
  (88, 3223, 'Lumines', 'PlayStation Portable', 41, 890, 890, 890, 110, 0, NULL, 'Q Entertainment', 'Bandai Namco, Ubisoft', '2004-12-12', 'Lumines is a puzzle video game series developed by Q Entertainment. The core objective of the games is to survive by rotating and aligning 2×2 blocks varying between two colors to form 2×2 squares of a single color which will be erased when the Time Line passes over them. The game is lost when the blocks reach the top of the playing field.', 'https://media.retroachievements.org/Images/086705.png', 'https://media.retroachievements.org/Images/081489.png', 'https://media.retroachievements.org/Images/081490.png', 'https://media.retroachievements.org/Images/081491.png', 4.4),
  (89, 3506, 'Patapon 2', 'PlayStation Portable', 41, 859, 859, 859, 111, 0, 'Rhythm', 'Pyramid, Japan Studio', 'Sony Computer Entertainment', '2008-11-27', 'Patapon 2 is a 2008 rhythm video game developed by Pyramid and Japan Studio and published by Sony Computer Entertainment for the PlayStation Portable. It is a direct sequel to Patapon, and like its predecessor, uses the same unique genre that combines rhythm and strategy. The game was released in Japan in November 2008, in PAL regions in March 2009, in North America in May 2009, and a port for the PlayStation 4 was released on January 30, 2020. A remaster of the game is included in the compilation Patapon 1+2 Replay, released on July 11, 2025, for Nintendo Switch, PlayStation 5 and Windows.', 'https://media.retroachievements.org/Images/047446.png', 'https://media.retroachievements.org/Images/047379.png', 'https://media.retroachievements.org/Images/062812.png', 'https://media.retroachievements.org/Images/062813.png', 4.4),
  (90, 2759, 'WTF: Work Time Fun', 'PlayStation Portable', 41, 852, 852, 852, 275, 0, 'Minigames', 'Sony Computer Entertainment', 'D3 Publisher', '2005-12-22', 'This is a list of games for the Sony PlayStation Portable handheld console. It does not include PSOne classics, PS minis, or NEOGEO Station. Games have been released in several regions around the world; North America (NA), Japan (JP), Europe (EU), and Australia (AUS).', 'https://media.retroachievements.org/Images/053435.png', 'https://media.retroachievements.org/Images/044373.png', 'https://media.retroachievements.org/Images/044371.png', 'https://media.retroachievements.org/Images/053434.png', 4.4),
  (91, 18142, 'Digimon Adventure', 'PlayStation Portable', 41, 834, 834, 834, 140, 0, 'Turn-Based RPG', 'Prope', 'Bandai Namco', '2013-01-17', 'Digimon Adventure  is a 2013 role-playing video game developed by Prope and published by Bandai Namco Games under the Bandai label for the PlayStation Portable. The story of the game is based on the 1999 Digimon anime series of the same name. It includes dialogue with voice acting from the main voice acting team of the anime. The opening theme song for the anime, Butter-Fly by Kōji Wada, and the insert song used for digivolutions, Brave Heart by Ayumi Miyazaki, are also featured. The game is part of the series'' 15th anniversary celebration and was released in Japan on January 13, 2013.', 'https://media.retroachievements.org/Images/082874.png', 'https://media.retroachievements.org/Images/092946.png', 'https://media.retroachievements.org/Images/092944.png', 'https://media.retroachievements.org/Images/092945.png', 4.4),
  (92, 3519, 'K-ON! Ho-kago Live!!', 'PlayStation Portable', 41, 826, 826, 826, 189, 0, 'Rhythm', 'xeen', 'Sega', '2010-09-30', 'There are currently 2402 games in this table across all pages: A to C, D to I, J to P, and Q to Z. It does not include PlayStation minis, PS one Classics or PS2 Classics.', 'https://media.retroachievements.org/Images/047661.png', 'https://media.retroachievements.org/Images/070829.png', 'https://media.retroachievements.org/Images/046903.png', 'https://media.retroachievements.org/Images/046904.png', 4.4),
  (93, 14205, 'Age of Zombies', 'PlayStation Portable', 41, 774, 774, 774, 37, 0, NULL, NULL, 'Halfbrick Studios', '2010-02-25', 'Age of Zombies is an action-adventure survival horror video game developed and published by Halfbrick Studios. It was released for PlayStation Portable, PlayStation 3 and iOS in 2010, for Android in 2011, for PlayStation Vita in 2013, and for Ouya in 2014.', 'https://media.retroachievements.org/Images/099896.png', 'https://media.retroachievements.org/Images/078935.png', 'https://media.retroachievements.org/Images/078937.png', 'https://media.retroachievements.org/Images/078938.png', 4.3),
  (94, 3729, 'Danganronpa: Kibou no Gakuen to Zetsubou no Koukousei', 'PlayStation Portable', 41, 754, 754, 754, 90, 0, 'Visual Novel', 'Spike', 'Spike', '2010-11-25', 'Danganronpa: Trigger Happy Havoc is a visual novel adventure game developed and published by Spike. The first installment in the Danganronpa series, it was originally released for the PlayStation Portable in Japan in November 2010. It was ported to Android and iOS in August 2012. NIS America localized and published the game internationally on PlayStation consoles, with the first release of the game in English occurring in 2014.', 'https://media.retroachievements.org/Images/049283.png', 'https://media.retroachievements.org/Images/048658.png', 'https://media.retroachievements.org/Images/048659.png', 'https://media.retroachievements.org/Images/048660.png', 4.3),
  (95, 2735, 'One Piece: Romance Dawn - Bouken no Yoake', 'PlayStation Portable', 41, 754, 754, 754, 70, 0, 'Turn-Based RPG', 'Three Rings', 'Bandai Namco', '2012-12-20', 'This is a list of games for the Sony PlayStation Portable handheld console. It does not include PSOne classics, PS minis, or NEOGEO Station. Games have been released in several regions around the world; North America (NA), Japan (JP), Europe (EU), and Australia (AUS).', 'https://media.retroachievements.org/Images/063134.png', 'https://media.retroachievements.org/Images/054852.png', 'https://media.retroachievements.org/Images/054850.png', 'https://media.retroachievements.org/Images/054851.png', 4.3),
  (96, 18159, 'Fate/Extra', 'PlayStation Portable', 41, 751, 751, 751, 90, 0, 'Turn-Based RPG', 'Type-Moon, Imageepoch', 'Marvelous Interactive, Aksys Games, Ghostlight', '2010-07-22', 'Fate/Extra is a dungeon crawler role-playing game developed by Type-Moon and Imageepoch and published by Marvelous Entertainment for the PlayStation Portable. The game takes place in a parallel universe to the visual novel Fate/stay night. It was released in Japan on July 22, 2010. Aksys Games localized the game for North America and released it on November 21, 2011. Three editions of the game were released in North America: a Limited Edition, a retail standard edition, and a PlayStation Network downloadable version. On May 4, 2012, Ghostlight released the game in PAL territories.', 'https://media.retroachievements.org/Images/087496.png', 'https://media.retroachievements.org/Images/051911.png', 'https://media.retroachievements.org/Images/051909.png', 'https://media.retroachievements.org/Images/087350.png', 4.3),
  (97, 18455, 'Spider-Man: Web of Shadows - Amazing Allies Edition', 'PlayStation Portable', 41, 741, 741, 741, 42, 0, 'Beat ''em Up', 'Amaze Entertainment', 'Activision', '2008-10-21', 'Spider-Man: Web of Shadows is a 2008 action-adventure video game based on the Marvel Comics character Spider-Man. The game was released in October 2008 across multiple platforms, and encompasses three drastically different versions: one released for Microsoft Windows, the PlayStation 3, Wii, and Xbox 360, which features an open world and non-linear gameplay; one for the PlayStation 2 and PlayStation Portable, which is a 2.5D side-scrolling beat ''em up; and one for the Nintendo DS, a Metroidvania-style beat ''em up. All three versions have several common elements, such as moral choices that alter the narrative, the ability to summon allies during fights, and a similar plot, despite different characters being featured. Web of Shadows'' storyline is significantly darker than most previous Spider-Man games, as it revolves around a symbiote invasion threatening Manhattan, which Spider-Man must stop with the help of several unlikely allies.', 'https://media.retroachievements.org/Images/067440.png', 'https://media.retroachievements.org/Images/062107.png', 'https://media.retroachievements.org/Images/062106.png', 'https://media.retroachievements.org/Images/062105.png', 4.3),
  (98, 3040, 'LEGO Pirates of the Caribbean: The Video Game', 'PlayStation Portable', 41, 739, 739, 739, 30, 0, 'Action-Adventure', 'TT Fusion', 'Disney Interactive Studios', '2011-05-10', 'Lego Pirates of the Caribbean: The Video Game is a 2011 Lego-themed action-adventure video game, based on the Pirates of the Caribbean film series, developed by Traveller''s Tales and published by Disney Interactive Studios for Xbox 360, PlayStation 3, PlayStation Portable, Wii, Nintendo DS, Nintendo 3DS, Microsoft Windows, and Mac OS X. The game was released to coincide with the release of Pirates of the Caribbean: On Stranger Tides, and retells the plot of the first four films in the Pirates Of The Caribbean series.', 'https://media.retroachievements.org/Images/125060.png', 'https://media.retroachievements.org/Images/072682.png', 'https://media.retroachievements.org/Images/081957.png', 'https://media.retroachievements.org/Images/081956.png', 4.3),
  (99, 22488, 'Sword Art Online: Infinity Moment', 'PlayStation Portable', 41, 734, 734, 734, 174, 0, NULL, 'Aquria', 'Bandai Namco', '2013-03-14', 'This is a list of games for the Sony PlayStation Portable handheld console. It does not include PSOne classics, PS minis, or NEOGEO Station. Games have been released in several regions around the world; North America (NA), Japan (JP), Europe (EU), and Australia (AUS).', 'https://media.retroachievements.org/Images/084566.png', 'https://media.retroachievements.org/Images/068853.png', 'https://media.retroachievements.org/Images/068854.png', 'https://media.retroachievements.org/Images/068855.png', 4.3),
  (100, 2388, 'Canabalt', 'PlayStation Portable', 41, 725, 725, 725, 7, 0, 'Endless Runner', 'Finji', 'Beatshapers', '2012-03-15', 'Canabalt is a one-button endless runner designed by Adam Saltsman for the Experimental Gameplay Project in 2009. The 2D side-scrolling video game was originally written as a Flash game, then ported to iOS, Android, PlayStation Portable, Ouya, and HTML5. An authorized version for the Commodore 64 called C64anabalt was released on cartridge. Canabalt has been credited with popularizing the endless runner subgenre.', 'https://media.retroachievements.org/Images/061568.png', 'https://media.retroachievements.org/Images/052056.png', 'https://media.retroachievements.org/Images/052057.png', 'https://media.retroachievements.org/Images/052058.png', 4.3),
  (101, 18088, 'Bleach: Heat the Soul', 'PlayStation Portable', 41, 710, 710, 710, 60, 0, '3D Fighting', NULL, 'Sony Computer Entertainment', '2005-03-24', 'Bleach: Heat the Soul is a series of fighting games developed by Eighting and published by Sony Computer Entertainment for the PlayStation Portable. They are based on the manga and anime series Bleach by Tite Kubo. All installments have been released only in Japan.', 'https://media.retroachievements.org/Images/049501.png', 'https://media.retroachievements.org/Images/049462.png', 'https://media.retroachievements.org/Images/049493.png', 'https://media.retroachievements.org/Images/049494.png', 4.3),
  (102, 14169, 'Valkyrie Profile: Lenneth', 'PlayStation Portable', 41, 702, 702, 702, 161, 0, 'Turn-Based RPG', NULL, 'Square Enix', '2006-07-18', 'Valkyrie Profile is a role-playing video game developed by tri-Ace and published by Enix for the PlayStation. It was released on December 22, 1999 in Japan and on August 29, 2000 in North America. Inspired by Norse mythology, Valkyrie Profile follows the titular valkyrie, Lenneth, as she travels through Midgard, collecting the souls of slain heroes to serve either as einherjar or her personal companions for Ragnarok - the battle to decide the fate of all creation - and trains them by fighting monsters and performing additional quests. As she journeys, she learns more about her original human life, removed from her memory upon becoming a Valkyrie.', 'https://media.retroachievements.org/Images/059812.png', 'https://media.retroachievements.org/Images/056420.png', 'https://media.retroachievements.org/Images/056418.png', 'https://media.retroachievements.org/Images/056428.png', 4.3),
  (103, 18133, 'Diner Dash', 'PlayStation Portable', 41, 683, 683, 683, 83, 0, 'Job Simulation', 'Climax London, PlayFirst', 'Eidos Interactive', '2007-05-11', 'Diner Dash is a strategy and time management video game initially developed by Gamelab and published by PlayFirst. It is now owned and published by Glu Mobile. It was one of the top-selling downloadable games of all time, available in multiple platforms such as PC, Mac, consoles, and mobile.', 'https://media.retroachievements.org/Images/050365.png', 'https://media.retroachievements.org/Images/049967.png', 'https://media.retroachievements.org/Images/049968.png', 'https://media.retroachievements.org/Images/049969.png', 4.3),
  (104, 3726, 'Tactics Ogre: Let Us Cling Together', 'PlayStation Portable', 41, 680, 680, 680, 148, 0, 'Tactical RPG', 'Square Enix', 'Square Enix', '2011-02-15', 'Tactics Ogre: Let Us Cling Together is a 1995 tactical role-playing game developed and published by Quest Corporation for the Super Famicom. It was later ported to the Sega Saturn (1996) and the PlayStation (1997), the latter released in North America in 1998 by Atlus USA. The second entry in the Ogre Battle series, the story takes place in the war-torn kingdom of Valeria, where protagonist Denim Powell works in a local resistance force against occupying powers, ending up caught in the ethnic conflicts driving the war. Battles are turn-based, taking place on grid-based maps from an overhead perspective with a focus on positioning and using character class abilities.', 'https://media.retroachievements.org/Images/085080.png', 'https://media.retroachievements.org/Images/066069.png', 'https://media.retroachievements.org/Images/063938.png', 'https://media.retroachievements.org/Images/063940.png', 4.3),
  (105, 18350, 'SpongeBob''s Truth or Square', 'PlayStation Portable', 41, 675, 675, 675, 52, 0, '3D Platforming', 'Barking Lizards', 'THQ', '2009-10-26', 'SpongeBob''s Truth or Square is a 2009 made-for-television comedy film and an hour-long episode of the American animated television series SpongeBob SquarePants that was produced as the 123rd and 124th episodes of the series. The special originally aired on Nickelodeon in the United States on November 6, 2009, celebrating the tenth anniversary of the television series. This is the second SpongeBob SquarePants television film, following SpongeBob''s Atlantis SquarePantis (2007). Its animation was directed by supervising director Alan Smart, Andrew Overtoom and Tom Yasumi.', 'https://media.retroachievements.org/Images/069963.png', 'https://media.retroachievements.org/Images/051845.png', 'https://media.retroachievements.org/Images/051844.png', 'https://media.retroachievements.org/Images/051843.png', 4.3),
  (106, 20095, 'Michael Jackson: The Experience', 'PlayStation Portable', 41, 666, 666, 666, 91, 0, 'Rhythm', 'Ubisoft', 'Ubisoft', '2010-11-23', 'Michael Jackson: The Experience is a music video game based on Michael Jackson''s songs. It was developed and published by Ubisoft, and was released on 23 November 2010 in North America, 25 November 2010 in Australia and 26 November 2010 in Europe for the Nintendo DS, PlayStation Portable, and Wii. It was also released on 12 April 2011 in North America, 14 April 2011 in Australia and 15 April 2011 in Europe for PlayStation 3''s PlayStation Move and Xbox 360''s Kinect. The Japanese release on 8 December 2011 only revised the PlayStation 3, Xbox 360, and Wii consoles. The game features many of Michael Jackson''s hits, such as Bad, Thriller, Beat It, Billie Jean, Smooth Criminal, Black or White, The Way You Make Me Feel, etc. However, some songs like Man in the Mirror and P.Y.T.  are excluded, and there are no songs from the Motown era. Initial launches of the game included a limited edition replica of Jackson''s sequined glove. It was later released for the Nintendo 3DS on 7 November 2011 in North America and 11 November 2011 in Europe, for iPhone and iPad on 7 December 2011 in North America and for PlayStation Vita on 15 February 2012 in North America, 22 February 2012 in Europe and 23 February 2012 in Australia. It was announced that the game would be released on Mac OS X, and iPad 2. The game sold 2 million units in two months, not including Japanese sales, making it one of the best-selling Wii title games.', 'https://media.retroachievements.org/Images/104673.png', 'https://media.retroachievements.org/Images/060042.png', 'https://media.retroachievements.org/Images/060040.png', 'https://media.retroachievements.org/Images/060041.png', 4.3),
  (107, 3999, 'Nayuta no Kiseki', 'PlayStation Portable', 41, 663, 663, 663, 249, 0, 'Action RPG', 'Nihon Falcom', 'Nihon Falcom', '2012-07-26', 'The Legend of Nayuta: Boundless Trails is a 2012 action role-playing game developed by Nihon Falcom. The game is a part of the Trails series, itself a part of the larger The Legend of Heroes series. It was first released in Japan for PlayStation Portable. A high-definition remaster was released in Japan for PlayStation 4 and Windows in 2021 and for Nintendo Switch in 2022. This version was localized in English by NIS America and released in September 2023.', 'https://media.retroachievements.org/Images/057745.png', 'https://media.retroachievements.org/Images/038824.png', 'https://media.retroachievements.org/Images/038822.png', 'https://media.retroachievements.org/Images/038823.png', 4.3),
  (108, 18173, 'Spider-Man 2', 'PlayStation Portable', 41, 644, 644, 644, 100, 0, 'Action-Adventure', 'Vicarious Visions', 'Activision', '2005-03-23', 'Spider-Man 2 is a 2004 American superhero film based on the Marvel Comics character Spider-Man. Directed by Sam Raimi and written by Alvin Sargent from a story conceived by Michael Chabon and the writing team of Alfred Gough and Miles Millar, it is the second installment in Raimi''s Spider-Man trilogy, following the 2002 film. The film stars Tobey Maguire as Peter Parker / Spider-Man, alongside Kirsten Dunst, James Franco, Alfred Molina, Rosemary Harris, and Donna Murphy. Peter Parker fights to stop scientist Dr. Otto Octavius from recreating a dangerous experiment, while also dealing with a personal crisis.', 'https://media.retroachievements.org/Images/084493.png', 'https://media.retroachievements.org/Images/061802.png', 'https://media.retroachievements.org/Images/061803.png', 'https://media.retroachievements.org/Images/061801.png', 4.3),
  (109, 28296, '~Homebrew~ Fruit Ninja', 'PlayStation Portable', 41, 610, 610, 610, 13, 0, 'Arcade', 'yokaai', 'yokaai', '2023-09-01', 'Fruit Ninja is a video game developed by Halfbrick Studios originally released on April 20, 2010. In the game, the player must slice fruit that is thrown into the air by swiping the device''s touch screen with their finger(s) or the player''s arms and hands, and must not slice bombs. It features multiple gameplay modes, leaderboards and multiplayer.', 'https://media.retroachievements.org/Images/088422.png', 'https://media.retroachievements.org/Images/088410.png', 'https://media.retroachievements.org/Images/088441.png', 'https://media.retroachievements.org/Images/088440.png', 4.3),
  (110, 3541, 'Corpse Party', 'PlayStation Portable', 41, 609, 609, 609, 33, 0, 'Adventure', '5pb., Team GrisGris', 'XSEED Games', '2010-08-12', 'Corpse Party  is a horror video game series originally created by Makoto Kedōin and eventually developed by Team GrisGris. Blending elements and genres of supernatural horror, survival horror, adventure, and doujin soft, the video game series often features a group of Japanese high school students who attempt to escape after becoming trapped in an abandoned, parallel school; haunted by a vengeful spirit in a red dress.', 'https://media.retroachievements.org/Images/114111.png', 'https://media.retroachievements.org/Images/029548.png', 'https://media.retroachievements.org/Images/029545.png', 'https://media.retroachievements.org/Images/029546.png', 4.3),
  (111, 18712, 'Def Jam: Fight for NY - The Takeover', 'PlayStation Portable', 41, 593, 593, 593, 42, 0, 'Arena Fighting', 'EA Studios Japan, AKI | syn Sophia', 'Electronic Arts', '2006-08-31', 'This is a list of games for the Sony PlayStation Portable handheld console. It does not include PSOne classics, PS minis, or NEOGEO Station. Games have been released in several regions around the world; North America (NA), Japan (JP), Europe (EU), and Australia (AUS).', 'https://media.retroachievements.org/Images/112295.png', 'https://media.retroachievements.org/Images/111895.png', 'https://media.retroachievements.org/Images/123181.png', 'https://media.retroachievements.org/Images/111749.png', 4.3),
  (112, 3908, 'Star Ocean: First Departure', 'PlayStation Portable', 41, 589, 589, 589, 115, 0, 'Action RPG', 'tri-Ace, TOSE', 'Square Enix', '2007-12-27', 'Star Ocean is a 1996 action role-playing game developed by tri-Ace and published by Enix for the Super Famicom. The first game in the Star Ocean series, it was released only in Japan in July 1996, and was the first game developed by tri-Ace, consisting of staff that had previously left Wolf Team due to being unhappy with the development process for Tales of Phantasia with Namco in 1995. The game used a special compression chip in its cartridge to compress and store all of the game''s data due to possessing graphics that pushed the limits of the Super Famicom. Additionally, the game had voice acting for the game''s intro and voice clips that played during the game''s battle gameplay, a rarity for games on the system.', 'https://media.retroachievements.org/Images/103361.png', 'https://media.retroachievements.org/Images/054827.png', 'https://media.retroachievements.org/Images/065949.png', 'https://media.retroachievements.org/Images/101962.png', 4.3),
  (113, 3255, 'Twisted Metal: Head-On', 'PlayStation Portable', 41, 563, 563, 563, 73, 0, 'Vehicular Combat', 'Incognito Entertainment', 'Sony Computer Entertainment', '2005-03-24', 'Twisted Metal: Head-On is a 2005 vehicular combat video game developed by Incognito Entertainment and published by Sony Computer Entertainment for the PlayStation Portable. A port developed by Eat Sleep Play for the PlayStation 2 was released in 2008. Head-On is the seventh installment of the Twisted Metal series, and the first game in the series to ship fully online-enabled.', 'https://media.retroachievements.org/Images/059674.png', 'https://media.retroachievements.org/Images/069988.png', 'https://media.retroachievements.org/Images/048640.png', 'https://media.retroachievements.org/Images/048641.png', 4.3),
  (114, 18161, 'Crash: Mind Over Mutant', 'PlayStation Portable', 41, 552, 552, 552, 76, 0, '3D Platforming, Beat ''em Up', 'Virtuos', 'Activision', '2008-10-23', 'Crash: Mind over Mutant is a 2008 platform game developed by Radical Entertainment for the PlayStation 2, PlayStation Portable, Wii and Xbox 360. It was released in North America on October 7, 2008, and was later released in Europe and Australia on October 30 and October 31, respectively. A separate version for the Nintendo DS was developed by Tose. It is the second game in the series not to have a Japanese release,, the first to be published by Activision following its merging with the series'' previous publisher Vivendi Games, and the last major console entry as a whole until 2017''s Crash Bandicoot N. Sane Trilogy — a remaster of the first three Crash games.', 'https://media.retroachievements.org/Images/081068.png', 'https://media.retroachievements.org/Images/053809.png', 'https://media.retroachievements.org/Images/083214.png', 'https://media.retroachievements.org/Images/083215.png', 4.3),
  (115, 18116, 'Naruto: Ultimate Ninja Heroes', 'PlayStation Portable', 41, 543, 543, 543, 42, 0, '2D Fighting', 'CyberConnect2 | CyberConnect', 'Bandai Namco', '2007-08-28', 'Naruto: Ultimate Ninja Heroes is a North America and PAL region-exclusive fighting game developed by CyberConnect2 and MiCROViSion and published by Namco Bandai Games for PlayStation Portable in 2007. It is the first installment of the Heroes series in the west; it is also essentially an edited version of Naruto: Ultimate Ninja Heroes 2: The Phantom Fortress, serving as a prequel to the next game, as the Japanese dub is not included in this game, essentially turning the game into a scaled down version of Naruto: Ultimate Ninja 2.', 'https://media.retroachievements.org/Images/080234.png', 'https://media.retroachievements.org/Images/049709.png', 'https://media.retroachievements.org/Images/049712.png', 'https://media.retroachievements.org/Images/049711.png', 4.3),
  (116, 3974, 'Pangya Fantasy Golf', 'PlayStation Portable', 41, 542, 542, 542, 283, 0, 'Sports - Golf', 'Ntreev Soft', 'Tomy', '2009-06-23', 'This is a list of games for the Sony PlayStation Portable handheld console. It does not include PSOne classics, PS minis, or NEOGEO Station. Games have been released in several regions around the world; North America (NA), Japan (JP), Europe (EU), and Australia (AUS).', 'https://media.retroachievements.org/Images/047346.png', 'https://media.retroachievements.org/Images/047064.png', 'https://media.retroachievements.org/Images/048434.png', 'https://media.retroachievements.org/Images/048433.png', 4.3),
  (117, 3516, 'Hatsune Miku: Project DIVA Extend', 'PlayStation Portable', 41, 535, 535, 535, 107, 0, 'Rhythm', 'Dingo', 'Sega', '2011-11-10', 'Hatsune Miku: Project Diva  is a series of rhythm games created by Sega and Crypton Future Media. The series currently consists of 6 main titles, released on various PlayStation consoles, the Nintendo Switch, Microsoft Windows, and in arcades, the 2 Project Mirai games for the Nintendo 3DS, and 4 spin-offs for mobile and VR platforms. The series primarily makes use of Vocaloids, a series of singing synthesizer software developed by the Yamaha Corporation, and the songs created using these Vocaloids, most notably the virtual-diva Vocaloid Hatsune Miku.', 'https://media.retroachievements.org/Images/061884.png', 'https://media.retroachievements.org/Images/047572.png', 'https://media.retroachievements.org/Images/047885.png', 'https://media.retroachievements.org/Images/047883.png', 4.3),
  (118, 10481, 'The Legend of Heroes: Trails in the Sky SC', 'PlayStation Portable', 41, 530, 530, 530, 245, 0, 'Turn-Based RPG', 'Nihon Falcom', 'Nihon Falcom, XSEED Games', '2007-09-27', 'The Legend of Heroes: Trails in the Sky SC is a 2006 role-playing video game developed by Nihon Falcom. The game is the second installment of the Trails series, itself a part of the larger The Legend of Heroes series, and follows Trails in the Sky (2004). It was first released in Japan for Windows in 2006 before releasing for the PlayStation Portable the following year.', 'https://media.retroachievements.org/Images/051354.png', 'https://media.retroachievements.org/Images/047174.png', 'https://media.retroachievements.org/Images/029558.png', 'https://media.retroachievements.org/Images/029559.png', 4.2),
  (119, 3717, 'Puzzle Quest: Challenge of the Warlords', 'PlayStation Portable', 41, 523, 523, 523, 56, 0, 'Tile Matching, Turn-Based RPG', 'Vicious Cycle Software | Monkey Bar Games', 'D3 Publisher', '2007-03-16', 'Puzzle Quest: Challenge of the Warlords is a puzzle video game designed by Steve Fawkner for Australian game developer Infinite Interactive and published by D3 Publisher in 2007. The game combines role-playing with tile-matching elements. Taking place in a high fantasy setting, the player moves their character around the game''s world and encounters monsters and other enemies to fight so as to gain experience and acquire treasure as in a typical role-playing game. Combat takes place on a board similar to Bejeweled, and by making matches of coloured gems, the combatants can cause damage to their opponents, cast spells, or perform other abilities that affect the flow of the game.', 'https://media.retroachievements.org/Images/047372.png', 'https://media.retroachievements.org/Images/047404.png', 'https://media.retroachievements.org/Images/047419.png', 'https://media.retroachievements.org/Images/047420.png', 4.2),
  (120, 2923, 'Black Rock Shooter: The Game', 'PlayStation Portable', 41, 513, 513, 513, 105, 0, 'Action RPG', 'Imageepoch', 'Nippon Ichi Software', '2013-04-25', 'Black Rock Shooter: The Game  is an action role-playing game developed by Imageepoch for the PlayStation Portable. It is based on the Black Rock Shooter franchise created by Huke. The game was released in Japan on August 25, 2011. NIS America published the game digitally on the PlayStation Store in the United States and Europe in April 2013, respectively.', 'https://media.retroachievements.org/Images/047115.png', 'https://media.retroachievements.org/Images/047111.png', 'https://media.retroachievements.org/Images/047112.png', 'https://media.retroachievements.org/Images/047113.png', 4.2),
  (121, 18066, 'Pac-Man: Championship Edition', 'PlayStation Portable', 41, 505, 505, 505, 25, 0, 'Maze Chase', 'Bandai Namco Games', 'Bandai Namco Games', '2010-12-01', 'Pac-Man Championship Edition is a 2007 maze video game developed and published by Namco Bandai Games for the Xbox 360. It has since been released on several other platforms, including iOS, Android, and the PlayStation Portable as a PSP mini title available on the PlayStation Store. It is an HD reimagining of Namco''s original Pac-Man arcade game; players navigate Pac-Man through an enclosed maze, eating pellets and avoiding four ghosts that pursue him. Clearing an entire side of the maze of dots will cause a fruit item to appear, and eating it will cause a new maze to appear on the opposite side.', 'https://media.retroachievements.org/Images/068128.png', 'https://media.retroachievements.org/Images/068125.png', 'https://media.retroachievements.org/Images/068127.png', 'https://media.retroachievements.org/Images/068126.png', 4.2),
  (122, 3585, 'Metal Gear Acid', 'PlayStation Portable', 41, 494, 494, 494, 85, 0, 'Collectible Card Game, Stealth, Tactical RPG', 'Konami', 'Konami', '2004-12-16', 'Metal Gear  is a Japanese franchise of action-adventure stealth games created by Hideo Kojima. Developed and published by Konami, the first game, Metal Gear, was released in 1987 for MSX home computers. The player often takes control of a special forces operative, usually Solid Snake, who is typically assigned the task of finding the titular superweapon, Metal Gear, a bipedal walking tank (mecha) with the ability to launch nuclear weapons.', 'https://media.retroachievements.org/Images/047343.png', 'https://media.retroachievements.org/Images/053977.png', 'https://media.retroachievements.org/Images/046889.png', 'https://media.retroachievements.org/Images/046921.png', 4.2),
  (123, 26046, '~Homebrew~ Five Nights at Freddy''s 2', 'PlayStation Portable', 41, 489, 489, 489, 16, 0, 'Survival Horror', 'AlexDev2', 'AlexDev2', '2014-11-11', 'Five Nights at Freddy''s 2 is a 2014 point-and-click survival horror game developed and published by Scott Cawthon. It is the second main installment in the Five Nights at Freddy''s series. Set in a fictional pizzeria, the player takes on the role of night security guards Jeremy Fitzgerald and Fritz Smith, who must defend themselves from the restaurant''s hostile animatronic mascots. The player cannot leave their office, but has access to a flashlight and security cameras throughout the restaurant to monitor animatronic activity. Wearing a mask that looks like one of the animatronics allows the player to avoid being detected in most cases, though some animatronics are repelled via other methods. If the player is detected, they will be jumpscared and experience a game over. As the game progresses, Atari-styled minigames and phone calls provide insight into the history of the restaurant.', 'https://media.retroachievements.org/Images/123227.png', 'https://media.retroachievements.org/Images/083546.png', 'https://media.retroachievements.org/Images/083496.png', 'https://media.retroachievements.org/Images/083497.png', 4.2),
  (124, 3132, 'Ys: The Oath in Felghana', 'PlayStation Portable', 41, 489, 489, 489, 95, 0, 'Action RPG', 'Nihon Falcom', 'Nihon Falcom, XSEED Games', '2010-04-22', 'Ys: The Oath in Felghana is a 2005 action role-playing game developed by Nihon Falcom. A part of the Ys series, it is a remake of Ys III: Wanderers from Ys (1989). The Oath in Felghana was first released for Windows in Japan in June 2005, with an English localization by Xseed Games in March 2012. A PlayStation Portable version was also released in Japan in April 2010 and later in North America and Europe. A remaster, Ys Memoire: The Oath in Felghana, released in Japan in April 2023 for the Nintendo Switch and in May 2024 for PlayStation 4 and PlayStation 5. Memoire was later released internationally in January 2025.', 'https://media.retroachievements.org/Images/124081.png', 'https://media.retroachievements.org/Images/041075.png', 'https://media.retroachievements.org/Images/041072.png', 'https://media.retroachievements.org/Images/041073.png', 4.2),
  (125, 10478, 'Dynasty Warriors', 'PlayStation Portable', 41, 479, 479, 479, 113, 0, 'Hack & Slash', 'Omega Force', 'Koei | Tecmo', '2004-12-16', 'Dynasty Warriors  is a series of Japanese hack and slash action video games created by Omega Force and Koei. The series is a spin-off of Koei''s turn-based strategy Romance of the Three Kingdoms series, based upon the Chinese novel of the same name, which is a romanticised retelling of the Chinese Three Kingdoms period.', 'https://media.retroachievements.org/Images/047317.png', 'https://media.retroachievements.org/Images/046892.png', 'https://media.retroachievements.org/Images/046887.png', 'https://media.retroachievements.org/Images/046890.png', 4.2),
  (126, 18068, 'Gladiator Begins', 'PlayStation Portable', 41, 476, 476, 476, 60, 0, 'Action RPG, Arena Fighting', 'Goshow', 'Aksys Games', '2010-09-14', 'Gladiator Begins  is a fighting game developed by Japanese studio GOSHOW and published in Japan by Acquire on January 14, 2010, and in North America by Aksys Games on September 14. It is the prequel to the 2005 video game Colosseum: Road to Freedom, which was originally released for the PlayStation 2.', 'https://media.retroachievements.org/Images/099589.png', 'https://media.retroachievements.org/Images/049309.png', 'https://media.retroachievements.org/Images/049568.png', 'https://media.retroachievements.org/Images/049569.png', 4.2),
  (127, 3549, 'Gurumin: A Monstrous Adventure', 'PlayStation Portable', 41, 476, 476, 476, 146, 0, 'Action RPG', 'Nihon Falcom', 'Nihon Falcom, Mastiff, 505 Games', '2006-06-29', 'This is a list of games for the Sony PlayStation Portable handheld console. It does not include PSOne classics, PS minis, or NEOGEO Station. Games have been released in several regions around the world; North America (NA), Japan (JP), Europe (EU), and Australia (AUS).', 'https://media.retroachievements.org/Images/047074.png', 'https://media.retroachievements.org/Images/088076.png', 'https://media.retroachievements.org/Images/088077.png', 'https://media.retroachievements.org/Images/088078.png', 4.2),
  (128, 6964, 'The Impossible Game', 'PlayStation Portable', 41, 474, 474, 474, 12, 0, 'Rhythm', 'Grip Digital', 'Grip Digital', '2009-11-23', 'The Impossible Game is a 2009 one-button platform game developed and published by Fluke Games. The Windows, macOS and Linux port was developed by Grip Games.', 'https://media.retroachievements.org/Images/048430.png', 'https://media.retroachievements.org/Images/048431.png', 'https://media.retroachievements.org/Images/047682.png', 'https://media.retroachievements.org/Images/047683.png', 4.2),
  (129, 18002, 'Obscure: The Aftermath', 'PlayStation Portable', 41, 466, 466, 466, 47, 0, NULL, 'Hydravision Entertainment', 'Playlogic', '2009-09-29', 'Obscure II, known in North America as Obscure: The Aftermath, is a survival horror video game developed by Hydravision Entertainment and published by Playlogic in PAL regions and Ignition in North America for Microsoft Windows, PlayStation 2 and Wii. It is the sequel to the 2004 video game Obscure. A PlayStation Portable version was released in 2009. The game was later released on Steam in 2014.', 'https://media.retroachievements.org/Images/108985.png', 'https://media.retroachievements.org/Images/094947.png', 'https://media.retroachievements.org/Images/094945.png', 'https://media.retroachievements.org/Images/094946.png', 4.2),
  (130, 3512, 'Ape Escape Academy', 'PlayStation Portable', 41, 464, 464, 464, 42, 0, 'Party', 'Shift', 'Sony Computer Entertainment', '2004-12-30', 'Ape Escape Academy, also known as Ape Academy in Europe and Piposaru Academia: Dossari! Sarugē Daizenshū in Japan, is a party video game developed by Shift and Alvion and published by Sony Computer Entertainment for the PlayStation Portable. It consists of a collection of 47 mini-games, many of which borrow from elements of Ape Escape 2. The game was first released in Japan in 2004, in Europe in 2005 and North America in 2006. By utilizing the PSP''s Wi-Fi capabilities, up to 4 players can play at a time. The North American release was on the same day as Ape Escape 3.', 'https://media.retroachievements.org/Images/102908.png', 'https://media.retroachievements.org/Images/046652.png', 'https://media.retroachievements.org/Images/102847.png', 'https://media.retroachievements.org/Images/103252.png', 4.2),
  (131, 2343, 'Bejeweled 2', 'PlayStation Portable', 41, 460, 460, 460, 60, 0, NULL, 'PopCap Games', 'Sony Online Entertainment', '2010-06-29', 'Bejeweled 2 is a tile-matching puzzle video game developed and published by PopCap Games. Released as a sequel to Bejeweled (2000), Bejeweled 2 introduces new game mechanics, such as Special Gems and extra game modes, along with new visuals and sounds.', 'https://media.retroachievements.org/Images/089841.png', 'https://media.retroachievements.org/Images/052128.png', 'https://media.retroachievements.org/Images/052131.png', 'https://media.retroachievements.org/Images/052129.png', 4.2),
  (132, 18355, 'Fate/unlimited codes', 'PlayStation Portable', 41, 459, 459, 459, 60, 0, '3D Fighting', NULL, 'Capcom', '2009-06-18', 'Fate/stay night is a Japanese visual novel game developed by Type-Moon. It was first released for Windows on January 30, 2004. The story takes place over three distinct routes: Fate, Unlimited Blade Works, and Heaven''s Feel. It focuses on a young mage named Shirou Emiya, who becomes a warrior in a battle between mages called Masters and their Servants known as the Holy Grail War. In each route, Shirou bonds with a heroine and confronts different adversaries participating in the war.', 'https://media.retroachievements.org/Images/086681.png', 'https://media.retroachievements.org/Images/051907.png', 'https://media.retroachievements.org/Images/051905.png', 'https://media.retroachievements.org/Images/051904.png', 4.2),
  (133, 3969, 'Hot Shots Golf: Open Tee', 'PlayStation Portable', 41, 451, 451, 451, 95, 0, 'Sports - Golf', 'Clap Hanz', 'Sony Computer Entertainment', '2004-12-12', 'This is a list of games for the Sony PlayStation Portable handheld console. It does not include PSOne classics, PS minis, or NEOGEO Station. Games have been released in several regions around the world; North America (NA), Japan (JP), Europe (EU), and Australia (AUS).', 'https://media.retroachievements.org/Images/114266.png', 'https://media.retroachievements.org/Images/053729.png', 'https://media.retroachievements.org/Images/050003.png', 'https://media.retroachievements.org/Images/050004.png', 4.2),
  (134, 24908, 'Planetarian: Chiisa na Hoshi no Yume', 'PlayStation Portable', 41, 439, 439, 439, 12, 0, 'Visual Novel', 'Key', 'Prototype', '2009-02-28', NULL, 'https://media.retroachievements.org/Images/075587.png', 'https://media.retroachievements.org/Images/075584.png', 'https://media.retroachievements.org/Images/075589.png', 'https://media.retroachievements.org/Images/075590.png', 4.2),
  (135, 18344, 'Bleach: Heat the Soul 7', 'PlayStation Portable', 41, 438, 438, 438, 43, 0, '3D Fighting', NULL, 'Sony Computer Entertainment', '2010-02-02', 'Bleach: Heat the Soul is a series of fighting games developed by Eighting and published by Sony Computer Entertainment for the PlayStation Portable. They are based on the manga and anime series Bleach by Tite Kubo. All installments have been released only in Japan.', 'https://media.retroachievements.org/Images/052525.png', 'https://media.retroachievements.org/Images/051799.png', 'https://media.retroachievements.org/Images/053776.png', 'https://media.retroachievements.org/Images/053777.png', 4.2),
  (136, 18157, 'DJ Max Fever', 'PlayStation Portable', 41, 436, 436, 436, 467, 0, 'Rhythm', 'Pentavision', 'PM Studios', '2009-01-27', 'DJ Max Fever is a music game for the PlayStation Portable developed by Pentavision and PM Studios. It was released in 2009. Although the franchise has made several appearances in Asia, DJ Max Fever is the first DJMax released in the United States and Europe. The game is a compilation of DJMax Portable (2006) and DJMax Portable 2 (2007) along with additional features. By decision of PM Studios, it is the only title in the DJMax series with a space between words DJ and Max. A digital version of the game was released in 2010 on PlayStation Network, but later removed due to licensing expiration.', 'https://media.retroachievements.org/Images/080862.png', 'https://media.retroachievements.org/Images/061827.png', 'https://media.retroachievements.org/Images/061824.png', 'https://media.retroachievements.org/Images/068346.png', 4.2),
  (137, 17988, 'Pac-Man World Rally', 'PlayStation Portable', 41, 433, 433, 433, 91, 0, 'Kart Racing', 'Smart Bomb Interactive', 'Bandai Namco', '2006-08-22', 'Pac-Man World Rally, known in Europe as Pac-Man Rally, is a kart racing game in the Pac-Man series. It was published by Bandai Namco Games, and released on August 22, 2006, for the PlayStation 2, GameCube, PlayStation Portable, and Microsoft Windows. An Xbox version of the game was cancelled, though a preview of the game can be found in the Xbox release of Pac-Man World 3.', 'https://media.retroachievements.org/Images/070160.png', 'https://media.retroachievements.org/Images/049457.png', 'https://media.retroachievements.org/Images/056789.png', 'https://media.retroachievements.org/Images/056790.png', 4.2),
  (138, 18363, 'Star Wars: The Force Unleashed', 'PlayStation Portable', 41, 433, 433, 433, 57, 0, 'Action-Adventure, Hack & Slash', 'Krome Studios', 'LucasArts | Lucasfilm', '2008-09-16', 'Star Wars: The Force Unleashed is a 2008 action-adventure game developed and published by LucasArts, and part of The Force Unleashed multimedia project. It was initially developed for the PS2, PS3, Wii, and Xbox 360 consoles and on iOS, second-generation N-Gage, NDS, PSP, and Java-equipped mobile phone handhelds. The game was released in North America on September 16, 2008, in Australia and Southeast Asia on September 17, and in Europe on September 19. LucasArts released downloadable content for the PS3 and Xbox 360 consoles. An Ultimate Sith Edition of the game, containing both new and previously released downloadable content, was released in November 2009, and later ported to Mac OS X and Windows. An enhanced remaster of the Wii version, developed by Aspyr, was released for the Nintendo Switch on April 20, 2022.', 'https://media.retroachievements.org/Images/113878.png', 'https://media.retroachievements.org/Images/051924.png', 'https://media.retroachievements.org/Images/085592.png', 'https://media.retroachievements.org/Images/085593.png', 4.2),
  (139, 14201, 'Lunar: Silver Star Harmony', 'PlayStation Portable', 41, 432, 432, 432, 95, 0, 'JRPG', 'Game Arts', NULL, '2009-01-01', 'Lunar: Silver Star Harmony, known in Japan as Lunar: Harmony of Silver Star, is the third remake of the 1992 role-playing video game Lunar: The Silver Star. It was developed by Game Arts in 2009 and released exclusively for the PlayStation Portable by GungHo Works in Japan, by Xseed Games North America, and by Game Arts in Europe and Australia.', 'https://media.retroachievements.org/Images/089013.png', 'https://media.retroachievements.org/Images/089012.png', 'https://media.retroachievements.org/Images/089010.png', 'https://media.retroachievements.org/Images/089011.png', 4.2),
  (140, 3939, 'Sonic Rivals', 'PlayStation Portable', 41, 432, 432, 432, 58, 0, '2D Platforming, Racing', 'Backbone Entertainment', 'Sega', '2006-11-21', 'Sonic Rivals is a 2006 action-racing video game developed by Backbone Entertainment and Sega Studio USA, and published by Sega for the PlayStation Portable (PSP); it is a game in the Sonic the Hedgehog series, and follows the heroes needing to stop Doctor Eggman Nega from turning everyone and the world into cards. The gameplay involves racing against other characters to get to the goal before them, as well as defeating the boss before the opponent does.', 'https://media.retroachievements.org/Images/112775.png', 'https://media.retroachievements.org/Images/047316.png', 'https://media.retroachievements.org/Images/047319.png', 'https://media.retroachievements.org/Images/047320.png', 4.2),
  (141, 15419, 'Dungeon Siege: Throne of Agony', 'PlayStation Portable', 41, 429, 429, 429, 82, 0, 'Action RPG', 'SuperVillain Studios', '2K Games', '2006-10-30', 'Dungeon Siege: Throne of Agony is a role-playing video game for PlayStation Portable developed by SuperVillain Studios and published by 2K in the U.S. in 2006, and by Take-Two Interactive in the PAL region in 2007.', 'https://media.retroachievements.org/Images/050791.png', 'https://media.retroachievements.org/Images/050792.png', 'https://media.retroachievements.org/Images/050786.png', 'https://media.retroachievements.org/Images/050787.png', 4.2),
  (142, 17995, 'Hello Kitty: Puzzle Party', 'PlayStation Portable', 41, 416, 416, 416, 16, 0, NULL, 'Ubisoft', 'Ubisoft', '2010-02-19', 'This is a list of games for the Sony PlayStation Portable handheld console. It does not include PSOne classics, PS minis, or NEOGEO Station. Games have been released in several regions around the world; North America (NA), Japan (JP), Europe (EU), and Australia (AUS).', 'https://media.retroachievements.org/Images/048848.png', 'https://media.retroachievements.org/Images/048849.png', 'https://media.retroachievements.org/Images/048851.png', 'https://media.retroachievements.org/Images/048850.png', 4.2),
  (143, 3284, 'Hysteria Project', 'PlayStation Portable', 41, 416, 416, 416, 6, 0, 'Survival Horror', NULL, 'Sanuk Games', '2010-04-15', 'Hysteria Project is a 2009 FMV adventure game developed and published by French studio BulkyPix for iOS and first released on the App Store on April 7, 2009. It was released as a PlayStation mini available for play on the PlayStation 3 and PlayStation Portable on April 15, 2010 in Europe and April 22, 2010 in North America. The port was published by Sanuk Games. A sequel was released on the App Store in 2011, Hysteria Project 2.', 'https://media.retroachievements.org/Images/048482.png', 'https://media.retroachievements.org/Images/048479.png', 'https://media.retroachievements.org/Images/048486.png', 'https://media.retroachievements.org/Images/048485.png', 4.2),
  (144, 3261, 'Route 66', 'PlayStation Portable', 41, 415, 415, 415, 9, 0, 'Hidden Object', 'Gameshastra', 'Gameshastra', '2010-01-28', 'U.S. Route 66 or U.S. Highway 66 was one of the original highways in the United States Numbered Highway System. It was established on November 11, 1926, with road signs erected the following year. The highway ran from Chicago, Illinois, through Missouri, Kansas, Oklahoma, Texas, New Mexico and Arizona before terminating in Santa Monica, California, covering a total of 2,448 miles (3,940 km).', 'https://media.retroachievements.org/Images/048536.png', 'https://media.retroachievements.org/Images/048528.png', 'https://media.retroachievements.org/Images/048532.png', 'https://media.retroachievements.org/Images/048535.png', 4.2),
  (145, 17984, 'Dr. Mini Games', 'PlayStation Portable', 41, 412, 412, 412, 29, 0, 'Minigames', 'StormBASIC S.L.', 'StormBASIC S.L.', '2010-12-21', 'Dr. Mario is a 1990 puzzle video game developed and published by Nintendo for the Nintendo Entertainment System and Game Boy. A spin-off of the Mario series, it is a falling block puzzle game in which the player''s objective is to destroy the viruses populating the on-screen playing field by using colored capsules that are automatically tossed into the field by Dr. Mario. The player manipulates the falling capsules, to align the same colors, which destroys viruses. The player progresses through the game by eliminating all the viruses on the screen in each level. The game was produced by Gunpei Yokoi and programmed by Takahiro Harada, with the soundtrack composed by Hirokazu Tanaka.', 'https://media.retroachievements.org/Images/048676.png', 'https://media.retroachievements.org/Images/048669.png', 'https://media.retroachievements.org/Images/048672.png', 'https://media.retroachievements.org/Images/048674.png', 4.2),
  (146, 3467, 'Death Jr.', 'PlayStation Portable', 41, 401, 401, 401, 56, 0, '3D Platforming', 'Backbone Entertainment', 'Konami', '2005-08-16', 'Death Jr. is a 2005 video game for the PlayStation Portable. The PSP iteration was the first PSP game shown publicly and advertised as a killer-app. It was released to a mixed reception and noted for many problems with the camera, gameplay and uninspiring graphics, but was praised for its Tim Burton themes and quirky characters. Slightly better received was the comic book adaptation by Gary Whitta and Ted Naifeh, which includes two three-issue miniseries. The game was followed by Death Jr. II: Root of Evil in 2006 and Death Jr. and the Science Fair of Doom in 2007.', 'https://media.retroachievements.org/Images/125174.png', 'https://media.retroachievements.org/Images/049340.png', 'https://media.retroachievements.org/Images/048127.png', 'https://media.retroachievements.org/Images/048128.png', 4.2),
  (147, 36934, '~Homebrew~ Cookie Clicker PSP', 'PlayStation Portable', 41, 396, 396, 396, 11, 0, NULL, 'XD', 'XD', '2021-01-01', 'PangYa was a free-to-play MMO casual golf simulation video game, designed by South Korean development company Ntreev Soft for Microsoft Windows. Although the game was a realistic simulator, it had fantasy-themed courses and anime-style characters, and the game made use of microtransactions to customize characters. Released in its home country in 2004 before expanding to Japan and other territories, it was released the following year in North America published by GameFactory, where it was initially titled Albatross18. PangYa servers were discontinued in most territories as of 2017, and the last official server, serving Thailand, was shut in 2024. Other PangYa games were also made for the Wii and PlayStation Portable game consoles, as well as a mobile game on Android and iOS.', 'https://media.retroachievements.org/Images/124635.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/124637.png', 'https://media.retroachievements.org/Images/124636.png', 4.2),
  (148, 18043, '~Prototype~ The Elder Scrolls Travels: Oblivion', 'PlayStation Portable', 41, 390, 390, 390, 17, 0, 'Action RPG', 'Climax Studios', 'Bethesda Softworks', '2006-05-02', 'This is a list of video game remakes and remasters and includes remakes as well as remasters of video games. It does not include clones and enhanced ports.', 'https://media.retroachievements.org/Images/049974.png', 'https://media.retroachievements.org/Images/049113.png', 'https://media.retroachievements.org/Images/049928.png', 'https://media.retroachievements.org/Images/049929.png', 4.2),
  (149, 3923, 'Hatsune Miku: Project DIVA 2nd', 'PlayStation Portable', 41, 387, 387, 387, 108, 0, 'Rhythm', 'Dingo', 'Sega', '2010-07-29', 'This is a list of games for the Sony PlayStation Portable handheld console. It does not include PSOne classics, PS minis, or NEOGEO Station. Games have been released in several regions around the world; North America (NA), Japan (JP), Europe (EU), and Australia (AUS).', 'https://media.retroachievements.org/Images/061883.png', 'https://media.retroachievements.org/Images/047133.png', 'https://media.retroachievements.org/Images/047135.png', 'https://media.retroachievements.org/Images/047137.png', 4.2),
  (150, 6710, 'Yu-Gi-Oh! 5D''s Tag Force 5', 'PlayStation Portable', 41, 384, 384, 384, 440, 0, 'Collectible Card Game', 'Konami', 'Konami', '2010-09-16', 'The following is a list of video games developed and published by Konami, based on Kazuki Takahashi''s Yu-Gi-Oh! manga and anime franchise, along with its spin-off series. With some exceptions, the majority of the games follow the card battle gameplay of the real-life Yu-Gi-Oh! Trading Card Game. There are 59 in total.', 'https://media.retroachievements.org/Images/048258.png', 'https://media.retroachievements.org/Images/047860.png', 'https://media.retroachievements.org/Images/053433.png', 'https://media.retroachievements.org/Images/053432.png', 4.2),
  (151, 2135, 'Gottlieb Pinball Classics', 'PlayStation Portable', 41, 380, 380, 380, 131, 0, 'Pinball', 'Farsight Studios', 'System 3 | Play It', '2006-02-10', 'This is a list of games for the Sony PlayStation Portable handheld console. It does not include PSOne classics, PS minis, or NEOGEO Station. Games have been released in several regions around the world; North America (NA), Japan (JP), Europe (EU), and Australia (AUS).', 'https://media.retroachievements.org/Images/087235.png', 'https://media.retroachievements.org/Images/087216.png', 'https://media.retroachievements.org/Images/087219.png', 'https://media.retroachievements.org/Images/087220.png', 4.2),
  (152, 3038, 'LEGO Harry Potter: Years 5-7', 'PlayStation Portable', 41, 376, 376, 376, 29, 0, 'Action-Adventure', 'TT Fusion', 'Warner Bros. Interactive Entertainment', '2011-11-11', 'Lego Harry Potter: Years 5–7 is an action-adventure game developed by Traveller''s Tales and published by Warner Bros. Interactive Entertainment. The sequel to Lego Harry Potter: Years 1–4 (2010), it was released on 11 November 2011 in North America and November 18 in Europe. The game is based on the Lego Harry Potter toy line and is based on the final three books and four films in the Harry Potter film series: Order of the Phoenix (2007), Half-Blood Prince (2009), Deathly Hallows - Part 1 (2010), and Deathly Hallows - Part 2 (2011). The game was initially released for PlayStation 3, Xbox 360, PlayStation Portable, PlayStation Vita, Wii, Nintendo DS, Nintendo 3DS, and Microsoft Windows. The first of three trailers was released 6 October 2011, and the demo was released on 1 November.', 'https://media.retroachievements.org/Images/074128.png', 'https://media.retroachievements.org/Images/073235.png', 'https://media.retroachievements.org/Images/074179.png', 'https://media.retroachievements.org/Images/074180.png', 4.2),
  (153, 3944, 'Wild Arms XF', 'PlayStation Portable', 41, 376, 376, 376, 92, 0, 'Strategy, Turn-Based RPG', 'Media.Vision', 'XSEED Games', '2008-03-11', 'Wild Arms XF is a game in the Wild Arms series, the first for the PlayStation Portable. The game was unveiled at a Media.Vision fan event on September 2, 2006, and was released in Japan in 2007, and in North America and Europe in 2008.', 'https://media.retroachievements.org/Images/100972.png', 'https://media.retroachievements.org/Images/046877.png', 'https://media.retroachievements.org/Images/047003.png', 'https://media.retroachievements.org/Images/046878.png', 4.2),
  (154, 18440, 'Shrek the Third', 'PlayStation Portable', 41, 375, 375, 375, 52, 0, 'Action-Adventure, Beat ''em Up', 'Amaze Entertainment', 'Activision', '2007-06-05', 'Shrek the Third is a 2007 American animated fantasy comedy film loosely based on the 1990 children''s picture book Shrek! by William Steig. Directed by Chris Miller and co-directed by Raman Hui from a screenplay by Jeffrey Price, Peter S. Seaman, Miller, and producer Aron Warner, and a story conceived by Andrew Adamson, co-director of the previous two installments, it is the sequel to Shrek 2 (2004) and the third installment in the Shrek film series. The film features Mike Myers, Eddie Murphy, Cameron Diaz, Antonio Banderas, Rupert Everett, Julie Andrews, and John Cleese reprising their voice roles from the previous films, along with new additions Justin Timberlake as Arthur Pendragon and Eric Idle as Merlin. In the film, Prince Charming is plotting to overthrow Shrek and Fiona, who have inherited the throne following King Harold''s death. Shrek has no interest in ruling the kingdom and attempts to convince Fiona''s underachieving 16-year-old cousin Artie to reign instead.', 'https://media.retroachievements.org/Images/092790.png', 'https://media.retroachievements.org/Images/092694.png', 'https://media.retroachievements.org/Images/092692.png', 'https://media.retroachievements.org/Images/092693.png', 4.2),
  (155, 18382, 'Kurohyou: Ryu ga Gotoku Shinshou', 'PlayStation Portable', 41, 373, 373, 373, 95, 0, 'Action-Adventure', 'AKI | syn Sophia', 'Sega', '2010-09-22', 'Kurohyō: Ryū ga Gotoku Shinshō , codenamed Project K, is a 2010 video game developed by Sega along with syn Sophia and released by Sega for the PlayStation Portable (PSP) in 2010. The game was introduced on April 21, 2010 by Famitsu and is a spin-off of Sega''s Yakuza series. An adaptation of the game was televised from October 5 to December 21, 2010, on MBS and TBS.', 'https://media.retroachievements.org/Images/087735.png', 'https://media.retroachievements.org/Images/054137.png', 'https://media.retroachievements.org/Images/054134.png', 'https://media.retroachievements.org/Images/054138.png', 4.2),
  (156, 3979, 'Disgaea: Afternoon of Darkness', 'PlayStation Portable', 41, 360, 360, 360, 82, 0, NULL, 'Nippon Ichi Software', 'Nippon Ichi Software', '2007-10-30', 'Disgaea: Hour of Darkness is a tactical role-playing video game developed and published by Nippon Ichi Software for the PlayStation 2. Set in a world full of demons and angels, the story follows Laharl, the son of a demon overlord, who upon being awakened after a two-year slumber, aspires to succeed his father''s place while also fighting rival demons in the process.', 'https://media.retroachievements.org/Images/061059.png', 'https://media.retroachievements.org/Images/051662.png', 'https://media.retroachievements.org/Images/051660.png', 'https://media.retroachievements.org/Images/051661.png', 4.1),
  (157, 18529, 'Namco Museum Battle Collection', 'PlayStation Portable', 41, 359, 359, 359, 383, 0, 'Compilation', 'Namco', 'Namco', '2005-02-24', 'Namco Museum Battle Collection is a 2005 video game compilation developed and published by Namco for the PlayStation Portable. It is the first Namco Museum title since the original PlayStation series to be developed in Japan. It includes 21 games - four of these are brand-new arrangement remakes of older Namco games, while the rest are emulated ports of Namco arcade games from the 1970s and 1980s. These ports include an options menu that allows the player to modify the in-game settings, such as the screen orientation and number of lives. Players can send one-level demos to a friend''s console via the Game Sharing option in the main menu.', 'https://media.retroachievements.org/Images/106827.png', 'https://media.retroachievements.org/Images/087936.png', 'https://media.retroachievements.org/Images/115096.png', 'https://media.retroachievements.org/Images/115095.png', 4.1),
  (158, 20273, 'Naruto: Ultimate Ninja Heroes 2 - The Phantom Fortress', 'PlayStation Portable', 41, 356, 356, 356, 55, 0, '2D Fighting', 'Artdink, CyberConnect2 | CyberConnect', 'Bandai Namco', '2006-03-30', 'This is a list of games for the Sony PlayStation Portable handheld console. It does not include PSOne classics, PS minis, or NEOGEO Station. Games have been released in several regions around the world; North America (NA), Japan (JP), Europe (EU), and Australia (AUS).', 'https://media.retroachievements.org/Images/080233.png', 'https://media.retroachievements.org/Images/060700.png', 'https://media.retroachievements.org/Images/060697.png', 'https://media.retroachievements.org/Images/060698.png', 4.1),
  (159, 3053, 'Dynasty Warriors: Strikeforce', 'PlayStation Portable', 41, 355, 355, 355, 266, 0, NULL, NULL, NULL, '2009-02-26', 'Dynasty Warriors: Strikeforce, originally released in Japan as Shin Sangokumusou Multi Raid , is a hack and slash video game for the PlayStation Portable. It is based on Dynasty Warriors 6. It was released in February 2009 in Japan and Q2 2009 in North America, Europe, and Australia. A console release of the game for the PlayStation 3 and Xbox 360 was released in Japan on October 1, 2009. American and European versions followed in February 2010. Its sequel, Shin Sangokumusou Multi Raid 2, was released in Japan on March 11, 2010 for the PlayStation Portable, and on July 26, 2012 for PlayStation 3.', 'https://media.retroachievements.org/Images/107404.png', 'https://media.retroachievements.org/Images/047321.png', 'https://media.retroachievements.org/Images/047322.png', 'https://media.retroachievements.org/Images/047323.png', 4.1),
  (160, 3474, 'Gitaroo Man Lives!', 'PlayStation Portable', 41, 355, 355, 355, 30, 0, 'Rhythm', 'iNiS', 'Koei | Tecmo', '2006-11-15', 'Gitaroo Man is a rhythm video game developed by iNiS and published by Koei for PlayStation 2. The game features visual production by Mitsuru Nakamura and an original soundtrack by Japanese band COIL. The game was released in Japan on June 21, 2001, in North America on February 18, 2002 and in Europe on June 21, 2002. A port of the game for PlayStation Portable, titled Gitaroo Man Lives!, was released in 2006.', 'https://media.retroachievements.org/Images/071889.png', 'https://media.retroachievements.org/Images/047524.png', 'https://media.retroachievements.org/Images/047526.png', 'https://media.retroachievements.org/Images/047525.png', 4.1),
  (161, 14498, 'Cladun: This Is An RPG', 'PlayStation Portable', 41, 354, 354, 354, 50, 0, 'Action RPG', 'System Prisma', 'Nippon Ichi Software', '2010-09-20', '2017 saw the release of numerous video games as well as other developments in the video game industry. The Nintendo Switch console was released in 2017, which sold more than 14 million units by the end of the year, exceeding the under-performing Wii U lifetime sales. This has helped to revitalize Nintendo, along with the retro Super NES Classic Edition console, the refreshed New Nintendo 2DS XL handheld and a strategy for mobile gaming. Microsoft also released the higher-powered Xbox One X targeted for 4K resolutions and virtual reality support.', 'https://media.retroachievements.org/Images/052377.png', 'https://media.retroachievements.org/Images/052638.png', 'https://media.retroachievements.org/Images/052279.png', 'https://media.retroachievements.org/Images/052277.png', 4.1),
  (162, 19924, 'Dead or Alive: Paradise', 'PlayStation Portable', 41, 350, 350, 350, 204, 0, 'Minigames', 'Project Venus', 'Koei | Tecmo', '2010-03-30', 'Dead or Alive Paradise is a 2010 video game developed by Project Venus and published by Tecmo Koei for the PlayStation Portable as part of the Dead or Alive series. It is a PSP port of Dead or Alive Xtreme 2 for the Xbox 360, expanding upon the activities available in the original which consisted of mainly beach-related minigames.', 'https://media.retroachievements.org/Images/070006.png', 'https://media.retroachievements.org/Images/071034.png', 'https://media.retroachievements.org/Images/071032.png', 'https://media.retroachievements.org/Images/071033.png', 4.1),
  (163, 7047, 'Dragon Quest & Final Fantasy in Itadaki Street Portable', 'PlayStation Portable', 41, 350, 350, 350, 51, 0, 'Board Game', 'Think Garage', 'Square Enix', '2006-05-25', 'This is a list of games for the Sony PlayStation Portable handheld console. It does not include PSOne classics, PS minis, or NEOGEO Station. Games have been released in several regions around the world; North America (NA), Japan (JP), Europe (EU), and Australia (AUS).', 'https://media.retroachievements.org/Images/077730.png', 'https://media.retroachievements.org/Images/048547.png', 'https://media.retroachievements.org/Images/048545.png', 'https://media.retroachievements.org/Images/048546.png', 4.1),
  (164, 18538, 'Pursuit Force', 'PlayStation Portable', 41, 347, 347, 347, 153, 0, 'Racing, Vehicular Combat', 'BigBig Studios', 'Sony Computer Entertainment', '2006-03-07', 'Pursuit Force is a 2005 vehicular combat and third-person shooter video game developed by Bigbig Studios and published by Sony Computer Entertainment for the PlayStation Portable. The game places the player in the role of a police agent who is a member of the titular elite law enforcement agency that specialises in direct armed encounters with adversaries, whether it be on foot or on the hood of a speeding car. The player has to try to seize cars and motorbikes while engaging in high-speed chases and gun battles against heavily armed gangs.', 'https://media.retroachievements.org/Images/104477.png', 'https://media.retroachievements.org/Images/082694.png', 'https://media.retroachievements.org/Images/053163.png', 'https://media.retroachievements.org/Images/053164.png', 4.1),
  (165, 3884, 'Ace Combat X: Skies of Deception', 'PlayStation Portable', 41, 346, 346, 346, 144, 0, 'Combat Flight Simulation', 'Access Games, Bandai Namco', 'Bandai Namco', '2006-10-23', 'Ace Combat X: Skies of Deception is a 2006 combat flight simulation video game for the PlayStation Portable. It is the first installment of the Ace Combat franchise for the PlayStation Portable, and the second for a handheld game system.', 'https://media.retroachievements.org/Images/117973.png', 'https://media.retroachievements.org/Images/096126.png', 'https://media.retroachievements.org/Images/096123.png', 'https://media.retroachievements.org/Images/096124.png', 4.1),
  (166, 16227, 'Bloons', 'PlayStation Portable', 41, 344, 344, 344, 28, 0, 'Puzzle', 'Hands-On Mobile', 'Digital Goldfish', '2009-11-24', 'Bloons is a video game franchise developed by Ninja Kiwi. The games involve players using monkeys, often armed with various tools, weapons, and machines, to pop as many bloons (balloons) as possible. They include the Bloons series, the Bloons Tower Defense series, and several other spin-offs. Most of the earlier Bloons games are browser-based games that use Adobe Flash Player, although some are available on other platforms. Mobile games based on the Bloons series are distributed through the App Store, Google Play, and some through Steam. Although now unavailable on Ninja Kiwi''s website, Flash-based games older than BTD6 are available on the Ninja Kiwi Archive.', 'https://media.retroachievements.org/Images/080697.png', 'https://media.retroachievements.org/Images/080334.png', 'https://media.retroachievements.org/Images/080335.png', 'https://media.retroachievements.org/Images/080336.png', 4.1),
  (167, 18760, 'Fate/Extra CCC', 'PlayStation Portable', 41, 344, 344, 344, 101, 0, 'Turn-Based RPG', 'Type-Moon, Imageepoch', 'Marvelous Interactive, Aksys Games, Ghostlight', '2013-03-28', 'Fate/Extra is a dungeon crawler role-playing game developed by Type-Moon and Imageepoch and published by Marvelous Entertainment for the PlayStation Portable. The game takes place in a parallel universe to the visual novel Fate/stay night. It was released in Japan on July 22, 2010. Aksys Games localized the game for North America and released it on November 21, 2011. Three editions of the game were released in North America: a Limited Edition, a retail standard edition, and a PlayStation Network downloadable version. On May 4, 2012, Ghostlight released the game in PAL territories.', 'https://media.retroachievements.org/Images/096942.png', 'https://media.retroachievements.org/Images/097911.png', 'https://media.retroachievements.org/Images/073299.png', 'https://media.retroachievements.org/Images/073300.png', 4.1),
  (168, 27302, '~Homebrew~ Geometry Dash', 'PlayStation Portable', 41, 339, 339, 339, 6, 0, '2D Platforming', 'Yerson Games', 'Homebrew - PlayStation Portable', '2023-06-29', 'Geometry Dash is a 2013 side-scrolling rhythm platform video game developed by Swedish game developer Robert Topala and published by his company RobTop Games. It was released for iOS and Android on 13 August 2013, Windows Phone on 12 June 2014, and on Steam on 22 December 2014. The player controls an icon and must navigate through levels while avoiding obstacles. The game includes 26 full-length levels created by the developer: 22 are auto-scrolling, and 4 are platformer levels. The game includes a level editor, enabling players to design custom levels, share them online, and play levels created by other users. Players can collect in-game currencies from official and user-generated levels or chests to unlock customization options for their icon.', 'https://media.retroachievements.org/Images/085537.png', 'https://media.retroachievements.org/Images/085536.png', 'https://media.retroachievements.org/Images/085508.png', 'https://media.retroachievements.org/Images/085509.png', 4.1),
  (169, 3463, 'Cho Aniki Zero: Muscle Brothers', 'PlayStation Portable', 41, 335, 335, 335, 32, 0, 'Shoot ''em Up', 'extreme Co.', 'Aksys Games', '2009-03-19', 'Cho Aniki  is a Japanese video game series originally developed by Masaya and published by NCS Corp. The first game was released in 1992 for the PC Engine system. The game''s sequels and spin-offs later appeared on the Super Famicom, PlayStation, Sega Saturn, WonderSwan, PlayStation 2 and PlayStation Portable. Mainly consisting of side-scrolling shoot ''em ups in the vein of Gradius, the Cho Aniki series is best known for its homoerotic overtones, wacky humor and vivid, surreal imagery. Most of the games have never seen release outside Japan.', 'https://media.retroachievements.org/Images/049000.png', 'https://media.retroachievements.org/Images/048999.png', 'https://media.retroachievements.org/Images/048997.png', 'https://media.retroachievements.org/Images/048998.png', 4.1),
  (170, 2758, 'Secret Agent Clank', 'PlayStation Portable', 41, 332, 332, 332, 189, 0, '3D Platforming, Stealth', 'High Impact Games', 'Sony Computer Entertainment', '2008-06-17', 'This is a list of games for the Sony PlayStation Portable handheld console. It does not include PSOne classics, PS minis, or NEOGEO Station. Games have been released in several regions around the world; North America (NA), Japan (JP), Europe (EU), and Australia (AUS).', 'https://media.retroachievements.org/Images/071043.png', 'https://media.retroachievements.org/Images/112654.png', 'https://media.retroachievements.org/Images/051827.png', 'https://media.retroachievements.org/Images/051828.png', 4.1),
  (171, 18072, 'Super Dangan-Ronpa 2: Sayonara Zetsubou Gakuen', 'PlayStation Portable', 41, 330, 330, 330, 162, 0, 'Visual Novel', 'Spike', 'Spike', '2012-07-26', 'Danganronpa 2: Goodbye Despair is a 2012 visual novel developed by Spike Chunsoft. It is the second game in the Danganronpa franchise following Danganronpa: Trigger Happy Havoc (2010). It was first released in Japan for PlayStation Portable in July 2012, and a port for PlayStation Vita was released in Japan in October 2013. NIS America released the game worldwide in September 2014; a port for PC was released in April 2016 and a bundle for PlayStation 4 and PlayStation Vita called Danganronpa 1-2 Reload, also containing the first Danganronpa game, was released in March 2017. An enhanced version with the subtitle Anniversary Edition was released for Android and iOS in August 2020, for Nintendo Switch in November 2021, and for Microsoft Windows and Xbox One May 2022.', 'https://media.retroachievements.org/Images/049300.png', 'https://media.retroachievements.org/Images/049303.png', 'https://media.retroachievements.org/Images/049301.png', 'https://media.retroachievements.org/Images/049302.png', 4.1),
  (172, 14502, 'Brandish: The Dark Revenant', 'PlayStation Portable', 41, 319, 319, 319, 121, 0, NULL, NULL, NULL, '2009-03-19', 'Brandish is a series of action role-playing video games by Nihon Falcom.', 'https://media.retroachievements.org/Images/088290.png', 'https://media.retroachievements.org/Images/055492.png', 'https://media.retroachievements.org/Images/088377.png', 'https://media.retroachievements.org/Images/055493.png', 4.1),
  (173, 22454, 'I Must Run!', 'PlayStation Portable', 41, 309, 309, 309, 18, 0, 'Endless Runner', 'Gamelion Studios', 'Gamelion Studios', '2010-12-14', 'Suikoden  is a role-playing video game published by Konami. It is the first installment of the Suikoden series. Developed by Konami Computer Entertainment Tokyo, it was released initially in 1995 for the PlayStation in Japan. A North American release followed one year later, and a mainland European release came the following April. The game was also released for Windows and Sega Saturn in 1998, but only in Japan.', 'https://media.retroachievements.org/Images/068496.png', 'https://media.retroachievements.org/Images/067650.png', 'https://media.retroachievements.org/Images/067653.png', 'https://media.retroachievements.org/Images/067651.png', 4.1),
  (174, 18090, 'Pac-Man World 3', 'PlayStation Portable', 41, 304, 304, 304, 62, 0, '3D Platforming', 'Blitz Games', 'Namco', '2005-12-06', 'This is a list of games for the Sony PlayStation Portable handheld console. It does not include PSOne classics, PS minis, or NEOGEO Station. Games have been released in several regions around the world; North America (NA), Japan (JP), Europe (EU), and Australia (AUS).', 'https://media.retroachievements.org/Images/049835.png', 'https://media.retroachievements.org/Images/049455.png', 'https://media.retroachievements.org/Images/049816.png', 'https://media.retroachievements.org/Images/049817.png', 4.1),
  (175, 14494, 'Tomb Raider: Anniversary', 'PlayStation Portable', 41, 297, 297, 297, 78, 0, 'Action-Adventure, Cinematic Platforming', 'Crystal Dynamics', 'Eidos Interactive', '2007-10-26', 'Tomb Raider is a 1996 action-adventure video game developed by Core Design and published by Eidos Interactive as the debut entry in the Tomb Raider media franchise. It was first released on the Sega Saturn, followed shortly by versions for MS-DOS and the PlayStation. Later releases came for Mac OS (1999), Pocket PC (2002), N-Gage (2003), iOS (2013) and Android (2015). The game follows archaeologist-adventurer Lara Croft, who is hired by businesswoman Jacqueline Natla to find an artefact called the Scion of Atlantis. Gameplay features Lara navigating levels split into multiple areas and room complexes while fighting enemies and solving puzzles to progress.', 'https://media.retroachievements.org/Images/049125.png', 'https://media.retroachievements.org/Images/051711.png', 'https://media.retroachievements.org/Images/048788.png', 'https://media.retroachievements.org/Images/048795.png', 4.1),
  (176, 10846, 'Prinny: Can I Really Be the Hero?', 'PlayStation Portable', 41, 292, 292, 292, 98, 0, NULL, 'Nippon Ichi Software', 'Nippon Ichi Software', '2009-02-17', 'Prinnies  are a fictional race of creatures primarily in Nippon Ichi''s Disgaea series of role-playing games. First appearing in Disgaea: Hour of Darkness, they have appeared in all later titles by the company, as well as on various merchandise such as hats and plush toys. With a few notable exceptions, they are voiced by Junji Majima in Japanese releases and Grant George in the English releases from Disgaea: Hour of Darkness to Disgaea 4: A Promise Unforgotten. The Prinnies are regarded as the mascots for the Disgaea series and have received generally positive reception.', 'https://media.retroachievements.org/Images/047369.png', 'https://media.retroachievements.org/Images/048901.png', 'https://media.retroachievements.org/Images/048902.png', 'https://media.retroachievements.org/Images/048904.png', 4.1),
  (177, 18136, 'LEGO Star Wars III: The Clone Wars', 'PlayStation Portable', 41, 286, 286, 286, 85, 0, 'Action-Adventure', 'TT Fusion', 'LucasArts | Lucasfilm', '2011-03-22', 'This is a list of games for the Sony PlayStation Portable handheld console. It does not include PSOne classics, PS minis, or NEOGEO Station. Games have been released in several regions around the world; North America (NA), Japan (JP), Europe (EU), and Australia (AUS).', 'https://media.retroachievements.org/Images/071274.png', 'https://media.retroachievements.org/Images/051304.png', 'https://media.retroachievements.org/Images/051302.png', 'https://media.retroachievements.org/Images/051303.png', 4.1),
  (178, 3928, 'Mr. Karoshi', 'PlayStation Portable', 41, 286, 286, 286, 15, 0, NULL, 'Yoyo Games', 'Yoyo Games', '2011-04-06', NULL, 'https://media.retroachievements.org/Images/101614.png', 'https://media.retroachievements.org/Images/047053.png', 'https://media.retroachievements.org/Images/075792.png', 'https://media.retroachievements.org/Images/075793.png', 4.1),
  (179, 16423, 'Bloons TD', 'PlayStation Portable', 41, 284, 284, 284, 40, 0, 'Tower Defense', 'Digital Goldfish', 'Digital Goldfish', '2011-02-22', 'Bloons Tower Defense is a series of tower defense games under the Bloons series created and produced by Ninja Kiwi. The game was initially developed as a browser game, built upon the Adobe Flash platform and released in mid 2007. Later games in the series expanded to support various mobile platforms, including Android, iOS, Windows Phone, PlayStation Portable, Nintendo DSi, Windows, Linux and MacOS. Games in the Bloons series older than Bloons TD 6 are available through the Ninja Kiwi Archive on Steam. In the game, players attempt to prevent Bloons from reaching the end of a set course by placing towers or road items along it that can pop the bloons in a variety of ways, typically by using the power of monkeys, magic, or technology. A handful of towers can stall the bloons and give the other towers more time to pop them by freezing and gluing the bloons. Money is gained by popping bloons, completing rounds, and collecting bananas from existing banana farms which can be spent on new towers, upgrades for existing ones, or temporary items such as exploding pineapples and road spikes. They also need to make sure that they do not lose all of their lives.', 'https://media.retroachievements.org/Images/062994.png', 'https://media.retroachievements.org/Images/080482.png', 'https://media.retroachievements.org/Images/080481.png', 'https://media.retroachievements.org/Images/080480.png', 4.1),
  (180, 18153, 'DJMax Portable', 'PlayStation Portable', 41, 284, 284, 284, 419, 0, 'Rhythm', 'Pentavision', 'Pentavision', '2006-01-14', 'This is a list of games for the Sony PlayStation Portable handheld console. It does not include PSOne classics, PS minis, or NEOGEO Station. Games have been released in several regions around the world; North America (NA), Japan (JP), Europe (EU), and Australia (AUS).', 'https://media.retroachievements.org/Images/067955.png', 'https://media.retroachievements.org/Images/067956.png', 'https://media.retroachievements.org/Images/067957.png', 'https://media.retroachievements.org/Images/067958.png', 4.1),
  (181, 3562, 'The Legend of Heroes: A Tear of Vermillion', 'PlayStation Portable', 41, 273, 273, 273, 76, 0, NULL, 'Nihon Falcom', 'Bandai', '2005-06-02', 'The Legend of Heroes: A Tear of Vermillion is a 1996 role-playing video game developed by Nihon Falcom. It is the fourth game in The Legend of Heroes series, and the second in the Gagharv trilogy. Originally released for the NEC PC-9801 in 1996, it was later released for the PlayStation in 1998 and Windows in 2000. A remake was released for the PlayStation Portable in 2005, which was the first North American release of a Legend of Heroes game since Dragon Slayer: The Legend of Heroes for the TurboGrafx-16. The North American release dropped the number from the title.', 'https://media.retroachievements.org/Images/100541.png', 'https://media.retroachievements.org/Images/046659.png', 'https://media.retroachievements.org/Images/052529.png', 'https://media.retroachievements.org/Images/052530.png', 4.1),
  (182, 26048, '~Homebrew~ Five Nights at Freddy''s', 'PlayStation Portable', 41, 272, 272, 272, 10, 0, 'Survival Horror', 'BasDEV', 'BasDEV', '2014-08-08', 'Five Nights at Freddy''s 2 is a 2025 American supernatural horror film based on the video game series Five Nights at Freddy''s created by Scott Cawthon and the sequel to the 2023 film adaptation. The film was directed by Emma Tammi and written by Cawthon. Josh Hutcherson, Elizabeth Lail, Piper Rubio, and Matthew Lillard reprise their roles from the previous film, with Mckenna Grace, Wayne Knight, and Skeet Ulrich joining the cast. Set a year and a half after the previous film, it follows Abby Schmidt (Rubio) as she gets manipulated by the Marionette, an animatronic from the original Freddy Fazbear''s Pizza who aims to plot revenge against parents.', 'https://media.retroachievements.org/Images/122701.png', 'https://media.retroachievements.org/Images/083463.png', 'https://media.retroachievements.org/Images/083461.png', 'https://media.retroachievements.org/Images/083462.png', 4.1),
  (183, 18121, 'Bleach: Heat the Soul 2', 'PlayStation Portable', 41, 269, 269, 269, 105, 0, '3D Fighting', 'Raizing | Eighting', 'Sony Computer Entertainment', '2005-11-01', 'This is a list of games for the Sony PlayStation Portable handheld console. It does not include PSOne classics, PS minis, or NEOGEO Station. Games have been released in several regions around the world; North America (NA), Japan (JP), Europe (EU), and Australia (AUS).', 'https://media.retroachievements.org/Images/049781.png', 'https://media.retroachievements.org/Images/049735.png', 'https://media.retroachievements.org/Images/049777.png', 'https://media.retroachievements.org/Images/049778.png', 4.1),
  (184, 26060, '~Homebrew~ Five Nights at Freddy''s 3', 'PlayStation Portable', 41, 266, 266, 266, 7, 0, 'Survival Horror', 'AlexDev2', 'AlexDev2', '2015-03-02', 'Five Nights at Freddy''s 3 is a 2015 point-and-click survival horror video game developed and published by Scott Cawthon. It is the third main installment in the Five Nights at Freddy''s series, and takes place in a horror-themed attraction based on the restaurant chain featured in the first two games. The player takes on the role of an unnamed security guard who must defend themself from a decrepit animatronic called Springtrap that roams the attraction, while facing phantom hallucinations of other animatronics. To survive, the player must monitor the building''s security cameras while maintaining systems that occasionally shut down. If the player encounters a phantom animatronic, they are jumpscared and one of these systems fails. If Springtrap reaches the office, the player experiences a game over.', 'https://media.retroachievements.org/Images/123100.png', 'https://media.retroachievements.org/Images/083518.png', 'https://media.retroachievements.org/Images/083516.png', 'https://media.retroachievements.org/Images/083517.png', 4.1),
  (185, 18141, 'Sonic Rivals 2', 'PlayStation Portable', 41, 264, 264, 264, 36, 0, NULL, 'Backbone Entertainment', NULL, '2007-11-13', 'Sonic Rivals 2 is a 2007 racing video game, the sequel to the 2006 game Sonic Rivals. The game was developed by Backbone Entertainment and supervised by Sega Studio USA, for the PlayStation Portable handheld video game console. Sonic Rivals 2 was released across November and December 2007. It received mixed or average reviews from critics.', 'https://media.retroachievements.org/Images/109502.png', 'https://media.retroachievements.org/Images/050022.png', 'https://media.retroachievements.org/Images/050023.png', 'https://media.retroachievements.org/Images/050024.png', 4.1),
  (186, 18149, 'Need for Speed: Carbon - Own the City', 'PlayStation Portable', 41, 262, 262, 262, 93, 0, 'Arcade Racing', 'Team Fusion', 'Electronic Arts', '2006-10-31', 'This is a list of games for the Sony PlayStation Portable handheld console. It does not include PSOne classics, PS minis, or NEOGEO Station. Games have been released in several regions around the world; North America (NA), Japan (JP), Europe (EU), and Australia (AUS).', 'https://media.retroachievements.org/Images/114277.png', 'https://media.retroachievements.org/Images/050106.png', 'https://media.retroachievements.org/Images/123434.png', 'https://media.retroachievements.org/Images/123436.png', 4.1),
  (187, 15395, 'Brick Breaker', 'PlayStation Portable', 41, 260, 260, 260, 30, 0, NULL, 'Hydravision Entertainment', 'Bigben Interactive', '2011-06-21', 'This is part of the list of Nintendo Switch games.', 'https://media.retroachievements.org/Images/082085.png', 'https://media.retroachievements.org/Images/082086.png', 'https://media.retroachievements.org/Images/082088.png', 'https://media.retroachievements.org/Images/082089.png', 4.1),
  (188, 3139, 'The Warriors', 'PlayStation Portable', 41, 257, 257, 257, 47, 0, 'Action-Adventure, Beat ''em Up', NULL, 'Rockstar Games', '2007-02-12', 'The Warriors is a 1979 American action thriller film directed by Walter Hill from a screenplay by Hill and David Shaber and based on the 1965 novel of the same name by Sol Yurick, in-turn inspired by Xenophon''s Anabasis. The film features an ensemble cast which includes Michael Beck, James Remar, Deborah Van Valkenburgh, Marcelino Sánchez, David Harris, Tom McKitterick, Brian Tyler, Dorsey Wright, Terry Michos, David Patrick Kelly, Roger Hill, Edward Sewer, and Lynne Thigpen. In the film, a street gang must escape from the Bronx back to their home turf on Coney Island after being framed for the murder of a respected gang leader.', 'https://media.retroachievements.org/Images/110427.png', 'https://media.retroachievements.org/Images/054692.png', 'https://media.retroachievements.org/Images/054691.png', 'https://media.retroachievements.org/Images/054693.png', 4.1),
  (189, 18063, 'LEGO Indiana Jones 2: The Adventure Continues', 'PlayStation Portable', 41, 254, 254, 254, 63, 0, 'Action-Adventure', 'TT Fusion', 'LucasArts | Lucasfilm', '2009-11-20', 'Lego Indiana Jones 2: The Adventure Continues is a 2009 action-adventure video game developed by Traveller''s Tales and published by LucasArts. Based on the Indiana Jones franchise, it is the sequel to the 2008 video game Lego Indiana Jones: The Original Adventures. It was released for the Wii, Xbox 360, PlayStation 3, and Microsoft Windows; Feral Interactive published a version for Mac OS X in 2011. TT Fusion developed a handheld version for the Nintendo DS and PlayStation Portable that, although released under the same name, is different in gameplay and amount of content.', 'https://media.retroachievements.org/Images/124080.png', 'https://media.retroachievements.org/Images/062269.png', 'https://media.retroachievements.org/Images/062266.png', 'https://media.retroachievements.org/Images/062267.png', 4.1),
  (190, 20509, 'The Haunted Zone', 'PlayStation Portable', 41, 250, 250, 250, 6, 0, 'Horror, Visual Novel', 'FromSoftware', 'FromSoftware', '2005-06-30', 'This is a list of games for the Sony PlayStation video game system, organized alphabetically by name. There are often different names for the same game in different regions. The final licensed PlayStation game released in Japan was Black/Matrix 00 on May 13, 2004; counting re-releases, the final licensed game released in Japan was Strider Hiryū on October 24, 2006. The final licensed game released in North America was FIFA Football 2005 on October 12, 2004, and the final licensed game released in Europe was either Schnappi das kleine Krokodil – 3 Fun-Games on July 18, 2005, or Moorhuhn X on July 20, 2005. Additionally, homebrew games were created using the Sony PlayStation Net Yaroze. Games were being reprinted as late as 2008 with Metal Gear Solid in Metal Gear Solid: The Essential Collection.', 'https://media.retroachievements.org/Images/119739.png', 'https://media.retroachievements.org/Images/119741.png', 'https://media.retroachievements.org/Images/119738.png', 'https://media.retroachievements.org/Images/119740.png', 4.1),
  (191, 11141, 'Zenonia', 'PlayStation Portable', 41, 249, 249, 249, 41, 0, NULL, 'Gamevil', 'Gamevil', '2010-10-12', 'This is a list of games and applications, collectively known as DSiWare, for the Nintendo DSi handheld game console, available for download via the DSi Shop and unplayable on earlier DS models. An update released for the Nintendo 3DS in June 2011 added support for the Nintendo eShop service, which contained nearly the entire DSi Shop library of DSiWare games at the time, with the exception of certain games and applications. DSiWare games and applications typically have animated icons, but some of them, such as Bejeweled Twist, have static icons. The DSi Shop ceased activity on March 31, 2017. Despite the fact that the DSiWare games and apps on the Nintendo eShop were not affected, they became publicly unavailable due to the eShop''s closure on March 27, 2023. The last DSiWare software title was WarioWare: Touched! DL which was released in the United States on March 31, 2016.', 'https://media.retroachievements.org/Images/050904.png', 'https://media.retroachievements.org/Images/050896.png', 'https://media.retroachievements.org/Images/050894.png', 'https://media.retroachievements.org/Images/050895.png', 4.1),
  (192, 3551, 'Steins;Gate', 'PlayStation Portable', 41, 233, 233, 233, 32, 0, NULL, '5pb., Nitroplus', 'Kadokawa Shoten', '2011-06-23', 'Steins;Gate is a Japanese anime television series produced by White Fox, based on 5pb. and Nitroplus''s 2009 visual novel of the same name. The series aired for 24 episodes, from April to September 2011. It is set in 2010 and follows 18-year-old Rintaro Okabe, who, together with his friends, accidentally discovers a method of time travel through which they can send text messages to the past, thereby changing the present.', 'https://media.retroachievements.org/Images/121107.png', 'https://media.retroachievements.org/Images/064250.png', 'https://media.retroachievements.org/Images/064260.png', 'https://media.retroachievements.org/Images/064261.png', 4),
  (193, 13173, 'Crush', 'PlayStation Portable', 41, 232, 232, 232, 90, 0, NULL, 'Zoë Mode, Kuju', 'Sega', '2007-05-25', 'Crush is a 2007 puzzle-platform video game developed by Zoë Mode and published by Sega for the PlayStation Portable. Its protagonist is Danny, a young man suffering from insomnia, who uses an experimental device to explore his mind and discover the cause of his sleeplessness. Each level of the game, representing events from Danny''s life and inspired by artists such as Tim Burton and M.C. Escher, requires the player to control Danny as he collects his lost marbles and other thoughts.', 'https://media.retroachievements.org/Images/076659.png', 'https://media.retroachievements.org/Images/062693.png', 'https://media.retroachievements.org/Images/062696.png', 'https://media.retroachievements.org/Images/062695.png', 4),
  (194, 3940, 'Metal Gear Acid 2', 'PlayStation Portable', 41, 225, 225, 225, 80, 0, 'Collectible Card Game, Stealth, Tactical RPG', 'Kojima Productions', 'Konami', '2006-03-21', 'Metal Gear Acid 2 is a turn-based collectible card stealth game developed and published by Konami for the PlayStation Portable in 2005. A Java ME version for mobile phones was released by Glu Mobile in 2008 titled Metal Gear Acid 2 Mobile.', 'https://media.retroachievements.org/Images/051474.png', 'https://media.retroachievements.org/Images/051473.png', 'https://media.retroachievements.org/Images/051490.png', 'https://media.retroachievements.org/Images/118057.png', 4),
  (195, 18474, 'Split/Second', 'PlayStation Portable', 41, 223, 223, 223, 84, 0, 'Arcade Racing', 'Black Rock Studios', 'Disney Interactive Studios', '2010-11-17', 'Split/Second: Velocity is a racing video game developed by Black Rock Studio and published by Disney Interactive Studios for Windows, PlayStation 3 and Xbox 360. The game was released in May 2010 and was later released for OnLive in June 2011.', 'https://media.retroachievements.org/Images/119182.png', 'https://media.retroachievements.org/Images/101989.png', 'https://media.retroachievements.org/Images/101987.png', 'https://media.retroachievements.org/Images/101988.png', 4),
  (196, 2915, 'BlazBlue: Calamity Trigger', 'PlayStation Portable', 41, 219, 219, 219, 102, 0, NULL, 'Arc System Works', 'PQube', '2010-10-29', 'BlazBlue: Calamity Trigger is a 2D fighting game developed by Arc System Works. Its name is a combination of the words blaze and blue when the title is rendered in rōmaji, and of the words brave and blue when rendered in katakana. As Japanese people usually follow the katakana rendering, the Japanese pronunciation is made similar to the word bray, entirely omitting the z sound. The game was released for the arcade in 2008, and for the PlayStation 3 and Xbox 360 in 2009, and Microsoft Windows in 2010. A port for the PlayStation Portable, titled BlazBlue: Calamity Trigger Portable, was also released in 2010. It is the first game of the main series.', 'https://media.retroachievements.org/Images/053079.png', 'https://media.retroachievements.org/Images/053078.png', 'https://media.retroachievements.org/Images/053076.png', 'https://media.retroachievements.org/Images/053679.png', 4),
  (197, 5967, 'Flying Hamster', 'PlayStation Portable', 41, 214, 214, 214, 32, 0, 'Shoot ''em Up', 'The Game Atelier', 'The Game Atelier', '2010-12-07', 'Nekketsu Kōha Kunio-kun, released as Renegade in the West, is a 1986 beat ''em up video game developed by Technōs Japan and published by Taito for arcades. In the original Japanese version, the game revolves around Kunio, a high school delinquent who must stand up against a series of rival gangs that are targeting his classmate Hiroshi. In the Western version, the player controls a street brawler who must face four different gangs in order to rescue his girlfriend, who is being held captive by a mob boss.', 'https://media.retroachievements.org/Images/061905.png', 'https://media.retroachievements.org/Images/077974.png', 'https://media.retroachievements.org/Images/077976.png', 'https://media.retroachievements.org/Images/077977.png', 4),
  (198, 21453, 'Soul Eater: Battle Resonance', 'PlayStation Portable', 41, 209, 209, 209, 40, 0, NULL, 'BEC', NULL, '2009-01-29', 'Soul Eater  is a Japanese manga series written and illustrated by Atsushi Ohkubo. Set at the Death Weapon Meister Academy, the series revolves around three teams, each consisting of a weapon meister and at least one human that can transform into a weapon. Trying to make the latter a Death Scythe and thus fit for use by the academy''s headmaster Shinigami, the personification of death, they must collect the souls of 99 evil humans and one witch, in that order; otherwise, they will have to start all over again.', 'https://media.retroachievements.org/Images/088024.png', 'https://media.retroachievements.org/Images/104317.png', 'https://media.retroachievements.org/Images/086844.png', 'https://media.retroachievements.org/Images/086843.png', 4),
  (199, 3909, 'Star Ocean: Second Evolution', 'PlayStation Portable', 41, 204, 204, 204, 125, 0, 'Action RPG', 'TOSE, tri-Ace', 'Square Enix', '2009-01-19', 'Star Ocean: The Second Story is an action role-playing video game developed by tri-Ace and published by Enix for the PlayStation. It is the second game in the Star Ocean series and the first game in the series to be released outside Japan, arriving in North America in June 1999 and Europe in April 2000, by Sony Computer Entertainment. Taking place in a science fantasy universe, the story centers around a young man named Claude C. Kenny, an officer from a space-faring Earth organization who is stranded on an undeveloped, medieval-level planet where he meets a girl named Rena Lanford. There, they both meet several companions and must stop a plot from an evil group that spans multiple worlds. The game was the basis of manga and anime adaptations.', 'https://media.retroachievements.org/Images/080070.png', 'https://media.retroachievements.org/Images/080067.png', 'https://media.retroachievements.org/Images/080068.png', 'https://media.retroachievements.org/Images/080069.png', 4),
  (200, 2922, 'Evangelion New Theatrical Edition: 3nd Impact', 'PlayStation Portable', 41, 201, 201, 201, 34, 0, 'Rhythm', 'Grasshopper Manufacture', 'CyberFront Corporation', '2011-09-28', 'Neon Genesis Evangelion  is a Japanese media franchise created by Hideaki Anno, originally owned by Gainax and currently owned by Khara. Most of the franchise features an apocalyptic mecha action story, which revolves around the paramilitary organization NERV and their efforts in fighting hostile beings called Angels, using giant humanoids called Evangelions that are piloted by select teenagers. Subsequent works deviate from this theme to varying degrees, focusing more on romantic interactions between the characters, plotlines not present in the original works, and reimaginings of the conflicts from the original works.', 'https://media.retroachievements.org/Images/047933.png', 'https://media.retroachievements.org/Images/047665.png', 'https://media.retroachievements.org/Images/047666.png', 'https://media.retroachievements.org/Images/047667.png', 4);
INSERT INTO games (rank, id, title, consoleName, consoleId, totalPlayers, casualPlayers, hardcorePlayers, numAchievements, points, genre, developer, publisher, released, description, icon, boxArt, titleScreen, screenshot, rating) VALUES
  (1, 11240, 'Castlevania: Symphony of the Night', 'PlayStation', 12, 55208, 55208, 55208, 105, 0, 'Metroidvania, 2D Platforming', 'Konami', 'Konami', '1997-03-20', 'Castlevania: Symphony of the Night is a 1997 action role-playing game developed and published by Konami for the PlayStation and Sega Saturn. It is a direct sequel to Castlevania: Rondo of Blood, set four years after its events. It was directed and produced by Toru Hagihara, with Koji Igarashi acting as assistant director.', 'https://media.retroachievements.org/Images/085764.png', 'https://media.retroachievements.org/Images/072390.png', 'https://media.retroachievements.org/Images/072391.png', 'https://media.retroachievements.org/Images/072392.png', 5),
  (2, 10434, 'Crash Bandicoot', 'PlayStation', 12, 41694, 41694, 41694, 46, 0, '3D Platforming', 'Naughty Dog', 'Sony Computer Entertainment', '1996-09-09', 'Crash Bandicoot is a video game franchise created by Naughty Dog as a flagship title for Sony''s PlayStation console. The series began with the development of the first game in 1994, inspired by the emerging capabilities of 3D consoles and games like Donkey Kong Country (1994). The protagonist, initially conceived as Willy the Wombat, evolved into Crash Bandicoot, a goofy, genetically mutated eastern barred bandicoot who escapes the clutches of the mad scientist Doctor Neo Cortex. The original trilogy—completed by Cortex Strikes Back (1997) and Warped (1998)—along with the kart racing game Crash Team Racing (1999), received critical praise for their vibrant visuals and polished gameplay. After Naughty Dog''s departure following Crash Team Racing due to creative exhaustion and ownership issues, the franchise transitioned from Sony exclusivity to multiplatform releases under multiple developers and publishers, including Universal Interactive, Vivendi Games, and Activision.', 'https://media.retroachievements.org/Images/081157.png', 'https://media.retroachievements.org/Images/027330.png', 'https://media.retroachievements.org/Images/026513.png', 'https://media.retroachievements.org/Images/026512.png', 4.9),
  (3, 11252, 'Silent Hill', 'PlayStation', 12, 29602, 29602, 29602, 66, 0, 'Survival Horror', 'Team Silent', 'Konami', '1999-02-24', 'Haunted PS1 is a community of video game developers, known for their compilations in collaboration with independent developers on the indie games website itch.io. The most notable releases, Demo Discs, are annual compilations of independent games from various genres influenced by the graphics and visual presentation of the PlayStation as well as menus inspired by actual PS1 demo discs or other PlayStation games such as Namco Museum releases on the platform. The Demo Discs series received praise from several websites for their niche theme, variety of titles and novel method of distribution, with a number of games from the releases receiving sufficient attention to lead to further development and commercial release on their own merit.', 'https://media.retroachievements.org/Images/099257.png', 'https://media.retroachievements.org/Images/045302.png', 'https://media.retroachievements.org/Images/017729.png', 'https://media.retroachievements.org/Images/017730.png', 4.8),
  (4, 11259, 'Tekken 3', 'PlayStation', 12, 29459, 29459, 29459, 81, 0, '3D Fighting', 'Namco', 'Namco', '1998-03-26', 'Tekken 3 (鉄拳3) is a 1997 fighting game developed and published by Namco. It is the third installment in the Tekken series and the first game built on the Namco System 12 arcade hardware. The game takes place nineteen years after Tekken 2 (1995) and features a largely new cast of characters, including the debut of several staple characters such as Jin Kazama, Ling Xiaoyu and Bryan Fury, and adds a sidestepping ability to every character. Tekken 3 was ported to the PlayStation in 1998 with additional content, including a beat ''em up mode called Tekken Force.', 'https://media.retroachievements.org/Images/086821.png', 'https://media.retroachievements.org/Images/022420.png', 'https://media.retroachievements.org/Images/022423.png', 'https://media.retroachievements.org/Images/085035.png', 4.8),
  (5, 11244, 'Metal Gear Solid', 'PlayStation', 12, 24328, 24328, 24328, 111, 0, 'Stealth', 'Konami', 'Konami', '1998-09-03', 'Metal Gear  is a Japanese franchise of action-adventure stealth games created by Hideo Kojima. Developed and published by Konami, the first game, Metal Gear, was released in 1987 for MSX home computers. The player often takes control of a special forces operative, usually Solid Snake, who is typically assigned the task of finding the titular superweapon, Metal Gear, a bipedal walking tank (mecha) with the ability to launch nuclear weapons.', 'https://media.retroachievements.org/Images/109501.png', 'https://media.retroachievements.org/Images/046645.png', 'https://media.retroachievements.org/Images/051525.png', 'https://media.retroachievements.org/Images/118033.png', 4.8),
  (6, 11277, 'Parasite Eve', 'PlayStation', 12, 14482, 14482, 14482, 64, 0, 'Action RPG, Survival Horror', 'Square', 'Squaresoft', '1998-03-29', 'Parasite Eve is a 1998 role-playing video game developed and published by Square. The game is a sequel to the novel Parasite Eve, written by Hideaki Sena; it is the first game in the Parasite Eve video game series. The story follows New York City police officer Aya Brea over a six-day span in 1997 as she attempts to stop the Eve, a woman who plans to destroy the human race through spontaneous human combustion. Players explore levels set in areas of New York while utilizing a pausable real-time combat system along with several role-playing elements.', 'https://media.retroachievements.org/Images/108237.png', 'https://media.retroachievements.org/Images/041333.png', 'https://media.retroachievements.org/Images/019094.png', 'https://media.retroachievements.org/Images/032363.png', 4.7),
  (7, 11279, 'Spyro the Dragon', 'PlayStation', 12, 14367, 14367, 14367, 65, 0, NULL, 'Insomniac Games', 'Sony Computer Entertainment', '1998-09-09', 'Spyro the Dragon is a 1998 platform game originally developed by Insomniac Games and published by Sony Computer Entertainment for the PlayStation. The first game in the Spyro series, it stars the title character, a young purple dragon named Spyro, and his dragonfly friend, Sparx, who must journey across the Dragon Kingdom to defeat Gnasty Gnorc, who has overtaken the five dragon Homeworlds by trapping the other dragons in crystal and turning their hoard of gems into an army of minions. Spyro the Dragon is an open-ended 3D platformer, featuring large, sprawling levels in which the player must locate collectable items, among which are gemstones, crystallized dragons, and stolen dragon eggs. Spyro''s abilities as a dragon include fire breath, a head-on charging attack, and a mid-air glide which he can use to scale large distances, all of which must be used strategically to find items and defeat enemies.', 'https://media.retroachievements.org/Images/089382.png', 'https://media.retroachievements.org/Images/027325.png', 'https://media.retroachievements.org/Images/107461.png', 'https://media.retroachievements.org/Images/107462.png', 4.7),
  (8, 10433, 'Crash Bandicoot 3: Warped', 'PlayStation', 12, 14063, 14063, 14063, 112, 0, '3D Platforming', 'Naughty Dog', 'Sony Computer Entertainment', '1998-11-03', 'Crash Bandicoot: Warped, known in Europe as Crash Bandicoot 3: Warped, is a 1998 platform game developed by Naughty Dog and published by Sony Computer Entertainment for the PlayStation. It is the third game in the Crash Bandicoot video game series following Crash Bandicoot 2: Cortex Strikes Back.', 'https://media.retroachievements.org/Images/081159.png', 'https://media.retroachievements.org/Images/064575.png', 'https://media.retroachievements.org/Images/064990.png', 'https://media.retroachievements.org/Images/064992.png', 4.7),
  (9, 10438, 'Crash Team Racing', 'PlayStation', 12, 13436, 13436, 13436, 117, 0, 'Kart Racing', 'Naughty Dog', 'Sony Computer Entertainment', '1999-10-19', 'Crash Team Racing is a 1999 kart racing game developed by Naughty Dog and published by Sony Computer Entertainment for the PlayStation. It is the fourth installment in the Crash Bandicoot series and the final Crash Bandicoot game to be developed by Naughty Dog. The game''s story focuses on the efforts of Crash Bandicoot, Doctor Neo Cortex, and other ragtag team of characters in the Crash Bandicoot series, who must race against the egomaniacal Nitros Oxide to save the Earth from destruction. In the game, players can take control of one of fifteen Crash Bandicoot series characters, though only eight are available at first. During the races, offensive and speed boosting power-ups can be used to gain an advantage.', 'https://media.retroachievements.org/Images/081550.png', 'https://media.retroachievements.org/Images/052415.png', 'https://media.retroachievements.org/Images/084044.png', 'https://media.retroachievements.org/Images/084045.png', 4.6),
  (10, 10432, 'Crash Bandicoot 2: Cortex Strikes Back', 'PlayStation', 12, 12604, 12604, 12604, 80, 0, '3D Platforming', 'Naughty Dog', 'Sony Computer Entertainment', '1997-11-06', 'Crash Bandicoot is a 1996 platform game developed by Naughty Dog and published by Sony Computer Entertainment for the PlayStation. The player controls Crash, a genetically enhanced bandicoot created by the mad scientist Doctor Neo Cortex. The story follows Crash as he aims to foil Cortex''s plans for world domination and rescue his girlfriend Tawna, a female bandicoot also created by Cortex. The game is played from a third-person perspective in which the camera trails behind Crash, though some levels feature forward-scrolling and side-scrolling perspectives.', 'https://media.retroachievements.org/Images/081158.png', 'https://media.retroachievements.org/Images/057655.png', 'https://media.retroachievements.org/Images/015079.png', 'https://media.retroachievements.org/Images/015078.png', 4.6),
  (11, 11353, 'Mega Man X4', 'PlayStation', 12, 11214, 11214, 11214, 58, 0, '2D Platforming', 'Capcom', 'Capcom', '1997-08-01', 'Mega Man X4, originally released in Japan as Rockman X4 (ロックマンX4), is a 1997 platform game developed and published by Capcom. It is the fourth game in the Mega Man X series and the second game in the series to be released on the Sega Saturn and PlayStation. The two versions were released simultaneously in Japan in 1997. A North America release followed sometime thereafter, while Europe received only the PlayStation version in 1997. Mega Man X4 allows the player to choose between the two mechanoid Reploids protagonists at the beginning of the game: X, who uses an arm cannon; or Zero, who wields an energy blade.', 'https://media.retroachievements.org/Images/044075.png', 'https://media.retroachievements.org/Images/039480.png', 'https://media.retroachievements.org/Images/015231.png', 'https://media.retroachievements.org/Images/039481.png', 4.6),
  (12, 11388, 'Yu-Gi-Oh! Forbidden Memories', 'PlayStation', 12, 11142, 11142, 11142, 216, 0, 'Collectible Card Game', 'Konami', 'Konami', '1999-12-09', 'Yu-Gi-Oh! Forbidden Memories, known in Japan as Yu-Gi-Oh! Shin Duel Monsters (遊☆戯☆王真デュエルモンスターズ封印されし記憶), is a video game loosely based on the Yu-Gi-Oh! manga and anime series. The game was released exclusively for the PlayStation console in December 1999 in Japan and in 2002 in other regions.', 'https://media.retroachievements.org/Images/027033.png', 'https://media.retroachievements.org/Images/046985.png', 'https://media.retroachievements.org/Images/026494.png', 'https://media.retroachievements.org/Images/027028.png', 4.6),
  (13, 11265, 'Resident Evil 3: Nemesis', 'PlayStation', 12, 11093, 11093, 11093, 119, 0, 'Survival Horror', 'Capcom', 'Capcom', '1999-09-22', 'Resident Evil 3: Nemesis is a 1999 survival horror video game developed and published by Capcom originally for the PlayStation. It is the third main installment in the Resident Evil series and takes place almost concurrently with the events of Resident Evil 2. The player must control former elite agent Jill Valentine as she escapes from Raccoon City, which has been overrun by zombies. The game uses the same engine as its predecessors and features 3D models over pre-rendered backgrounds with fixed camera angles. Choices through the game affect how the story unfolds and which ending is achieved.', 'https://media.retroachievements.org/Images/107651.png', 'https://media.retroachievements.org/Images/047497.png', 'https://media.retroachievements.org/Images/027431.png', 'https://media.retroachievements.org/Images/027432.png', 4.6),
  (14, 11245, 'Resident Evil 2: DualShock Ver.', 'PlayStation', 12, 10442, 10442, 10442, 131, 0, 'Survival Horror', 'Capcom', 'Capcom', '1998-08-06', 'Resident Evil is a 1996 survival horror video game developed and published by Capcom for the PlayStation. It is the first main installment in Capcom''s Resident Evil series. Set in the fictional Arklay mountain region in the Midwest, players control Chris Redfield and Jill Valentine, members of the elite task force S.T.A.R.S., who must escape a mansion infested with zombies and other monsters.', 'https://media.retroachievements.org/Images/027365.png', 'https://media.retroachievements.org/Images/047496.png', 'https://media.retroachievements.org/Images/027287.png', 'https://media.retroachievements.org/Images/027291.png', 4.6),
  (15, 11242, 'Final Fantasy VII', 'PlayStation', 12, 9700, 9700, 9700, 207, 0, 'Turn-Based RPG', 'Square', 'Squaresoft', '1997-01-31', 'Final Fantasy VII is a 1997 role-playing video game developed and published by Square for the PlayStation. The seventh main installment in the Final Fantasy series, it was released in Japan by Square and internationally by Sony Computer Entertainment, becoming the first game in the main series to have a PAL release. The game''s story follows Cloud Strife, a mercenary who joins an eco-terrorist organization to stop a world-controlling megacorporation from using the planet''s life essence as an energy source. Ensuing events send Cloud and his allies in pursuit of Sephiroth, a superhuman who seeks to wound the planet and harness its healing power in order to be reborn as a god. Throughout their journey, Cloud bonds with his party members, including Aerith Gainsborough, who holds the secret to saving their world.', 'https://media.retroachievements.org/Images/070798.png', 'https://media.retroachievements.org/Images/046651.png', 'https://media.retroachievements.org/Images/015658.png', 'https://media.retroachievements.org/Images/015659.png', 4.6),
  (16, 11317, 'MediEvil', 'PlayStation', 12, 9543, 9543, 9543, 50, 0, 'Action-Adventure', NULL, 'Sony Computer Entertainment', '1998-10-09', 'MediEvil is a 1998 action-adventure game developed and published by Sony Computer Entertainment for the PlayStation. The game is set in the medieval Kingdom of Gallowmere and centers around the charlatan protagonist, Sir Daniel Fortesque, as he makes an attempt to stop antagonist Zarok''s invasion of the kingdom whilst simultaneously redeeming himself.', 'https://media.retroachievements.org/Images/114756.png', 'https://media.retroachievements.org/Images/046632.png', 'https://media.retroachievements.org/Images/026486.png', 'https://media.retroachievements.org/Images/026485.png', 4.6),
  (17, 11268, 'Resident Evil: Director''s Cut', 'PlayStation', 12, 8690, 8690, 8690, 115, 0, 'Survival Horror', 'Capcom', 'Capcom', '1997-09-25', 'Resident Evil Requiem is a 2026 survival horror game developed and published by Capcom. It is the ninth main Resident Evil game, following Resident Evil Village (2021). It features a new protagonist, FBI analyst Grace Ashcroft, who investigates the remains of Raccoon City with the help of the federal agent and returning protagonist Leon S. Kennedy.', 'https://media.retroachievements.org/Images/079667.png', 'https://media.retroachievements.org/Images/046238.png', 'https://media.retroachievements.org/Images/100819.png', 'https://media.retroachievements.org/Images/100820.png', 4.5),
  (18, 11305, 'R4: Ridge Racer Type 4', 'PlayStation', 12, 8163, 8163, 8163, 44, 0, 'Arcade Racing', 'Namco', 'Namco, Sony Computer Entertainment', '1998-12-03', 'R4: Ridge Racer Type 4, released without the ''R4'' prefix in PAL territories, is a 1998 racing video game developed and published by Namco for the PlayStation. It is the fourth home title in the Ridge Racer series after Rage Racer (1996) and was initially released on December 3, 1998 in Japan, with global releases following in 1999.', 'https://media.retroachievements.org/Images/059562.png', 'https://media.retroachievements.org/Images/022414.png', 'https://media.retroachievements.org/Images/022416.png', 'https://media.retroachievements.org/Images/022429.png', 4.5),
  (19, 13444, 'Pepsiman: The Running Hero', 'PlayStation', 12, 8078, 8078, 8078, 40, 0, 'Action', 'KID', 'KID', '1999-03-04', 'Angry Video Game Nerd is an American web series of comedy-themed retrogaming reviews, created by and starring James Rolfe. The show revolves around reviews that involve acerbic rants about low quality video games. From the beginning of season 2, new episodes were aired first on GameTrailers.com, but are since now aired at Cinemassacre.com, with episodes later being re-aired on Rolfe''s own YouTube channel. Episodes are usually scheduled for release on the first or second Wednesday of each month; originally, Rolfe''s early work schedule allowed for two episodes per month, but other work commitments changed this to its present arrangement.', 'https://media.retroachievements.org/Images/066590.png', 'https://media.retroachievements.org/Images/046411.png', 'https://media.retroachievements.org/Images/022626.png', 'https://media.retroachievements.org/Images/022627.png', 4.5),
  (20, 11368, 'PaRappa the Rapper', 'PlayStation', 12, 7805, 7805, 7805, 27, 0, 'Rhythm', 'NanaOn-Sha', 'Sony Computer Entertainment', '1996-12-06', 'PaRappa the Rapper is a rhythm video game developed by NanaOn-Sha and published by Sony Computer Entertainment for the PlayStation. It was originally released in Japan in 1996 and worldwide in 1997. Created by music producer Masaya Matsuura in collaboration with artist Rodney Greenblat, the game features unique visual design and rap-based gameplay and is considered to be the first true rhythm game. It was ported to the PlayStation Portable in 2006 in celebration of its 10-year anniversary. A remastered version of the original PlayStation game was released for PlayStation 4 in 2017 for the game''s twentieth anniversary.', 'https://media.retroachievements.org/Images/073081.png', 'https://media.retroachievements.org/Images/026973.png', 'https://media.retroachievements.org/Images/026974.png', 'https://media.retroachievements.org/Images/026972.png', 4.5),
  (21, 11311, 'Medal of Honor', 'PlayStation', 12, 7657, 7657, 7657, 42, 0, 'First-Person Shooter', 'DreamWorks Interactive', 'Electronic Arts', '1999-11-10', 'The Medal of Honor (MOH) is the highest military decoration of the United States Armed Forces and is awarded to recognize American soldiers, sailors, marines, airmen, guardians, and coast guardsmen who have distinguished themselves by acts of valor. The medal is normally awarded by the president of the United States and is presented in the name of Congress. It is often referred to as the Congressional Medal of Honor, though the official name of the award is simply Medal of Honor.', 'https://media.retroachievements.org/Images/054360.png', 'https://media.retroachievements.org/Images/055749.png', 'https://media.retroachievements.org/Images/026897.png', 'https://media.retroachievements.org/Images/026896.png', 4.5),
  (22, 14631, 'Jackie Chan Stuntmaster', 'PlayStation', 12, 7477, 7477, 7477, 65, 0, '3D Platforming, Beat ''em Up', 'Radical Entertainment', 'Midway', '2000-03-28', 'Jackie Chan Stuntmaster is a 2000 beat ''em up platform video game developed by Radical Entertainment for the PlayStation. Midway Games released it in North America while Sony Computer Entertainment released it in Europe.', 'https://media.retroachievements.org/Images/052906.png', 'https://media.retroachievements.org/Images/106194.png', 'https://media.retroachievements.org/Images/106193.png', 'https://media.retroachievements.org/Images/106192.png', 4.5),
  (23, 11260, 'Spyro 2: Ripto''s Rage!', 'PlayStation', 12, 7416, 7416, 7416, 54, 0, '3D Platforming, Collect-a-thon', 'Insomniac Games', 'Sony Computer Entertainment', '1999-11-02', 'Spyro 2: Ripto''s Rage!, known as Spyro 2: Gateway to Glimmer in PAL regions, is a 1999 platform game developed by Insomniac Games and published by Sony Computer Entertainment for the PlayStation. It is the second installment in the Spyro series and a direct sequel to Spyro the Dragon (1998).', 'https://media.retroachievements.org/Images/089383.png', 'https://media.retroachievements.org/Images/074749.png', 'https://media.retroachievements.org/Images/107463.png', 'https://media.retroachievements.org/Images/107464.png', 4.5),
  (24, 11280, 'Mega Man Legends', 'PlayStation', 12, 7361, 7361, 7361, 48, 0, 'Action-Adventure, Third-Person Shooter', 'Capcom', 'Capcom', '1997-12-18', 'Mega Man Legends is a sub-series in the Mega Man franchise. While the main series is known for its 2D side-scrolling platformer gameplay with story that is told through cutscenes, this series instead features 3D action-adventure gameplay and a more detailed story.', 'https://media.retroachievements.org/Images/051475.png', 'https://media.retroachievements.org/Images/035690.png', 'https://media.retroachievements.org/Images/035688.png', 'https://media.retroachievements.org/Images/035689.png', 4.5),
  (25, 11329, 'Einhänder', 'PlayStation', 12, 7167, 7167, 7167, 49, 0, 'Shoot ''em Up', 'Square', 'Squaresoft', '1997-11-20', 'Einhänder is a 1997 scrolling shooter video game developed and published by Square for the PlayStation. It was released in Japan on November 20, 1997 and in North America on May 5, 1998 by Sony Computer Entertainment. It was also re-released for the Japanese PlayStation Network on June 25, 2008. The name Einhänder is German and denotes a type of sword that is wielded with one hand, here used to refer to the single manipulator arm possessed by the player''s spacecraft.', 'https://media.retroachievements.org/Images/113439.png', 'https://media.retroachievements.org/Images/057157.png', 'https://media.retroachievements.org/Images/031417.png', 'https://media.retroachievements.org/Images/031415.png', 4.5),
  (26, 11346, 'Rayman', 'PlayStation', 12, 7139, 7139, 7139, 58, 0, '2D Platforming', 'Ubisoft', 'Ubisoft', '1995-09-09', 'Rayman is a franchise of platformer video games, created by video game designer Michel Ancel for Ubisoft. Since the release of Rayman in 1995, the series has produced a total of 45 games across multiple platforms.', 'https://media.retroachievements.org/Images/109943.png', 'https://media.retroachievements.org/Images/050881.png', 'https://media.retroachievements.org/Images/035151.png', 'https://media.retroachievements.org/Images/035152.png', 4.5),
  (27, 11278, 'Gran Turismo 2', 'PlayStation', 12, 6902, 6902, 6902, 124, 0, 'Racing Simulation', 'Polyphony Digital', 'Sony Computer Entertainment', '1999-12-11', 'Gran Turismo 2 is a 1999 sim racing video game developed by Polyphony Digital and published by Sony Computer Entertainment for the PlayStation. It is the sequel to Gran Turismo, the second installment of the Gran Turismo series, and the first video game to be developed by Polyphony Digital.', 'https://media.retroachievements.org/Images/086178.png', 'https://media.retroachievements.org/Images/057332.png', 'https://media.retroachievements.org/Images/015662.png', 'https://media.retroachievements.org/Images/015663.png', 4.5),
  (28, 11264, 'The Legend of Dragoon', 'PlayStation', 12, 6746, 6746, 6746, 108, 0, 'Turn-Based RPG', 'Japan Studio', 'Sony Computer Entertainment', '1999-12-02', 'The Legend of Dragoon is a role-playing video game developed and published by Sony Computer Entertainment for the PlayStation. It was released in December 1999 in Japan, June 2000 in North America, and January 2001 in Europe. Set in a high fantasy fictional world called Endiness, the game follows a group of warriors led by the protagonist, Dart, as they attempt to stop the destruction of the world. The player controls a party of three-dimensional (3D) character models through pre-rendered, linear environments. Combat uses a combination of turn-based mechanics and real-time commands. The game includes a quick time event called addition during each attack, requiring the player to press a button when prompted in order to continue inflicting damage.', 'https://media.retroachievements.org/Images/035804.png', 'https://media.retroachievements.org/Images/046705.png', 'https://media.retroachievements.org/Images/029832.png', 'https://media.retroachievements.org/Images/029833.png', 4.5),
  (29, 11320, 'Gran Turismo', 'PlayStation', 12, 6583, 6583, 6583, 68, 0, 'Racing Simulation', 'Polyphony Digital', 'Sony Computer Entertainment', '1997-12-23', 'Gran Turismo (GT) is a series of sim racing video games developed by Polyphony Digital. Released for PlayStation systems, Gran Turismo games are intended to emulate the appearance and performance of a large selection of vehicles, most of which are licensed reproductions of real-world automobiles. Since the franchise''s debut in 1997, over 100 million units have been sold worldwide, making it the highest selling video game franchise under the PlayStation brand.', 'https://media.retroachievements.org/Images/101538.png', 'https://media.retroachievements.org/Images/029894.png', 'https://media.retroachievements.org/Images/029895.png', 'https://media.retroachievements.org/Images/029896.png', 4.5),
  (30, 11404, 'Harry Potter and the Sorcerer''s Stone', 'PlayStation', 12, 6542, 6542, 6542, 61, 0, 'Action-Adventure', 'Argonaut Games', 'Electronic Arts', '2001-11-16', 'Harry Potter and the Philosopher''s Stone is a fantasy novel by British author J. K. Rowling. It is the first novel in the Harry Potter series and was Rowling''s debut novel. It follows Harry Potter, a young wizard who discovers his magical heritage on his eleventh birthday when he receives a letter of acceptance from Hogwarts School of Witchcraft and Wizardry. With the help of his friends, Ron Weasley and Hermione Granger, Harry unravels a mystery involving the dark wizard Lord Voldemort.', 'https://media.retroachievements.org/Images/080437.png', 'https://media.retroachievements.org/Images/040400.png', 'https://media.retroachievements.org/Images/076012.png', 'https://media.retroachievements.org/Images/076009.png', 4.5),
  (31, 11344, 'Diablo', 'PlayStation', 12, 6405, 6405, 6405, 80, 0, 'CRPG, Roguelike', 'Blizzard Entertainment', 'Electronic Arts', '1998-03-30', 'This is a list of video games considered controversial. The list includes games that have earned controversies for violence, sexual content, racism, and review bombing from fans. Some of the video games on this list have been banned or regionally censored.', 'https://media.retroachievements.org/Images/049224.png', 'https://media.retroachievements.org/Images/026789.png', 'https://media.retroachievements.org/Images/026788.png', 'https://media.retroachievements.org/Images/030073.png', 4.5),
  (32, 11327, 'Digimon World', 'PlayStation', 12, 6397, 6397, 6397, 219, 0, 'Turn-Based RPG', 'BEC, Flying Tiger Development', 'Bandai', '1999-01-28', 'Digimon World  is a role-playing video game developed by BEC and published by Bandai for the PlayStation. It''s the first game in the Digimon World series, followed by various sequels released for the PlayStation and other platforms. The story focuses on a human brought to File City on File Island by Jijimon to save the island. Digimon have been losing their memories and becoming feral and the city has fallen into disarray. The goal of the player, who is represented by an unnamed young boy, is to save the island by helping Digimon recover their memory and return to the city.', 'https://media.retroachievements.org/Images/103674.png', 'https://media.retroachievements.org/Images/070317.png', 'https://media.retroachievements.org/Images/077303.png', 'https://media.retroachievements.org/Images/077302.png', 4.5),
  (33, 11319, 'Spider-Man', 'PlayStation', 12, 6289, 6289, 6289, 60, 0, '3D Platforming, Beat ''em Up', 'Neversoft', 'Activision', '2000-08-30', 'Spider-Man is a superhero in American comic books published by Marvel Comics. Created by writer-editor Stan Lee and artist Steve Ditko, he first appeared in the anthology comic book Amazing Fantasy #15 in the Silver Age of Comic Books. Widely regarded as one of the most popular and commercially successful superheroes, he has been featured in comic books, television shows, films, video games, novels, and plays.', 'https://media.retroachievements.org/Images/101496.png', 'https://media.retroachievements.org/Images/045566.png', 'https://media.retroachievements.org/Images/036055.png', 'https://media.retroachievements.org/Images/036056.png', 4.5),
  (34, 11276, 'Tomba!', 'PlayStation', 12, 6237, 6237, 6237, 53, 0, '2.5D Platforming, Metroidvania', 'Whoopee Camp', 'Sony Computer Entertainment', '1997-12-25', 'Tomba! is a 1997 action-adventure platform video game developed and published by Whoopee Camp for the PlayStation. It was released in Japan in 1997 and internationally by Sony Computer Entertainment the following year. The game centers on the eponymous feral child as he attempts to recover his grandfather''s bracelet from an evil race of anthropomorphic pigs.', 'https://media.retroachievements.org/Images/120712.png', 'https://media.retroachievements.org/Images/120713.png', 'https://media.retroachievements.org/Images/026481.png', 'https://media.retroachievements.org/Images/026537.png', 4.5),
  (35, 11359, 'Metal Slug X', 'PlayStation', 12, 6167, 6167, 6167, 58, 0, 'Run & Gun', 'Hamster', 'Agetec, SNK', '2001-01-25', 'This is a list of games for the Sony PlayStation video game system, organized alphabetically by name. There are often different names for the same game in different regions. The final licensed PlayStation game released in Japan was Black/Matrix 00 on May 13, 2004; counting re-releases, the final licensed game released in Japan was Strider Hiryū on October 24, 2006. The final licensed game released in North America was FIFA Football 2005 on October 12, 2004, and the final licensed game released in Europe was either Schnappi das kleine Krokodil – 3 Fun-Games on July 18, 2005, or Moorhuhn X on July 20, 2005. Additionally, homebrew games were created using the Sony PlayStation Net Yaroze. Games were being reprinted as late as 2008 with Metal Gear Solid in Metal Gear Solid: The Essential Collection.', 'https://media.retroachievements.org/Images/034709.png', 'https://media.retroachievements.org/Images/069382.png', 'https://media.retroachievements.org/Images/040981.png', 'https://media.retroachievements.org/Images/032833.png', 4.5),
  (36, 11331, 'Tony Hawk''s Pro Skater', 'PlayStation', 12, 6077, 6077, 6077, 85, 0, 'Extreme Sports - Skateboarding', 'Neversoft', 'Activision', '1999-09-29', 'Tony Hawk''s Pro Skater, released as Tony Hawk''s Skateboarding in the United Kingdom, Australia, New Zealand, and parts of Europe, is a 1999 skateboarding video game developed by Neversoft and published by Activision. It is the first installment in the Tony Hawk''s series. It was released for the PlayStation on September 29, 1999 and was later ported to the Nintendo 64, Game Boy Color, Dreamcast, and N-Gage.', 'https://media.retroachievements.org/Images/033510.png', 'https://media.retroachievements.org/Images/031280.png', 'https://media.retroachievements.org/Images/031277.png', 'https://media.retroachievements.org/Images/031278.png', 4.5),
  (37, 11316, 'Tekken 2', 'PlayStation', 12, 5911, 5911, 5911, 93, 0, '3D Fighting', 'Namco', 'Namco', '1996-03-29', 'Tekken Tag Tournament 2 is a 2011 fighting game, the eighth installment in the Tekken fighting game series and the sequel to Tekken Tag Tournament. It was released for the arcades in September 2011. It received an update, subtitled Unlimited, in March 2012. A console version based on the update was released for PlayStation 3 and Xbox 360 in September 2012. It was ported to the Wii U as one of the system''s launch titles in November 2012, subtitled Wii U Edition.', 'https://media.retroachievements.org/Images/086820.png', 'https://media.retroachievements.org/Images/057399.png', 'https://media.retroachievements.org/Images/029790.png', 'https://media.retroachievements.org/Images/085034.png', 4.4),
  (38, 11296, 'Dino Crisis 2', 'PlayStation', 12, 5897, 5897, 5897, 52, 0, 'Action-Adventure', 'Capcom', 'Capcom', '2000-09-13', 'Dino Crisis 2 is a 2000 action-adventure game developed by Capcom Production Studio 4 and published by Capcom for the PlayStation. It is the second installment in the Dino Crisis series, with designer Takumi Shu taking over as game-director from Mikami Shinji from the first game. The narrative continues the story of special operative Regina, who must deal with the fallout of a time-distorting event which transports a research-base and the surrounding area through time. Regina and team-leader Dylan Morton must battle against dinosaurs in order to find a way to get back to the present.', 'https://media.retroachievements.org/Images/054357.png', 'https://media.retroachievements.org/Images/046550.png', 'https://media.retroachievements.org/Images/027000.png', 'https://media.retroachievements.org/Images/026999.png', 4.4),
  (39, 11401, 'Tekken', 'PlayStation', 12, 5789, 5789, 5789, 43, 0, '3D Fighting', 'Namco', 'Namco', '1995-03-31', 'Tekken  is a Japanese media franchise centred on a series of fighting games developed and published by Bandai Namco Entertainment. The franchise also includes film and print adaptations.', 'https://media.retroachievements.org/Images/086819.png', 'https://media.retroachievements.org/Images/046924.png', 'https://media.retroachievements.org/Images/028583.png', 'https://media.retroachievements.org/Images/085033.png', 4.4),
  (40, 11354, 'Mortal Kombat Trilogy', 'PlayStation', 12, 5767, 5767, 5767, 129, 0, '2D Fighting', 'Midway', 'Midway', '1996-10-11', 'Jade is a fictional character in the Mortal Kombat fighting game franchise by Midway Games and NetherRealm Studios. She debuted in Mortal Kombat II (1993) as a hidden opponent and first became playable in Ultimate Mortal Kombat 3 (1995). Her primary weapon is a steel bō staff.', 'https://media.retroachievements.org/Images/030382.png', 'https://media.retroachievements.org/Images/030384.png', 'https://media.retroachievements.org/Images/030387.png', 'https://media.retroachievements.org/Images/030390.png', 4.4),
  (41, 11314, 'Marvel vs. Capcom: Clash of Super Heroes', 'PlayStation', 12, 5593, 5593, 5593, 75, 0, '2D Fighting', 'Capcom', 'Capcom, Virgin Interactive', '1999-11-11', '1998 saw many sequels and prequels in video games, such as The Legend of Zelda: Ocarina of Time, Metal Gear Solid, Resident Evil 2, Crash Bandicoot: Warped, F-Zero X, Fallout 2, Gex: Enter the Gecko, Marvel vs. Capcom: Clash of Super Heroes, Panzer Dragoon Saga, Return to Krondor, Sonic Adventure, Soulcalibur, Street Fighter Alpha 3, and Tomb Raider III, along with new titles such as Banjo-Kazooie, Dance Dance Revolution, Half-Life, MediEvil, Parasite Eve, Radiant Silvergun, Spyro the Dragon, StarCraft and Xenogears. In Japan, Sega released the Dreamcast which was the first console of the sixth generation and also the company''s last major console.', 'https://media.retroachievements.org/Images/106813.png', 'https://media.retroachievements.org/Images/034564.png', 'https://media.retroachievements.org/Images/034566.png', 'https://media.retroachievements.org/Images/034676.png', 4.4),
  (42, 11350, 'Bloody Roar II', 'PlayStation', 12, 5564, 5564, 5564, 58, 0, '3D Fighting', 'Hudson Soft, Raizing | Eighting', 'Sony Computer Entertainment', '1999-01-28', 'The following is a list of video games published by Sony Interactive Entertainment, formerly known as Sony Computer Entertainment.', 'https://media.retroachievements.org/Images/107173.png', 'https://media.retroachievements.org/Images/045298.png', 'https://media.retroachievements.org/Images/038350.png', 'https://media.retroachievements.org/Images/038351.png', 4.4),
  (43, 11256, 'Doom', 'PlayStation', 12, 5343, 5343, 5343, 215, 0, 'First-Person Shooter', 'Williams Entertainment', 'Williams Entertainment', '1995-11-16', 'Doom is an American media franchise created by John Carmack, John Romero, Adrian Carmack, Kevin Cloud, and Tom Hall. The series usually focuses on the exploits of an unnamed space marine operating under the auspices of the Union Aerospace Corporation (UAC), who fights hordes of demons and the undead to save Earth from an apocalyptic invasion.', 'https://media.retroachievements.org/Images/076981.png', 'https://media.retroachievements.org/Images/046230.png', 'https://media.retroachievements.org/Images/026639.png', 'https://media.retroachievements.org/Images/026547.png', 4.4),
  (44, 11247, 'Final Fantasy IX', 'PlayStation', 12, 5291, 5291, 5291, 104, 0, NULL, 'Square', 'Squaresoft', '2000-07-07', 'Final Fantasy IX is a 2000 role-playing video game developed and published by Square for the PlayStation video game console. It is the ninth game in the main Final Fantasy series. The plot focuses on a war between nations in a medieval fantasy world called Gaia. Players follow a thief named Zidane Tribal who kidnaps princess Garnet Til Alexandros XVII as part of a ploy by the neighboring nation of Lindblum. He joins Garnet and a growing cast of characters on a quest to take down her mother, Queen Brahne of Alexandria, who started the war.', 'https://media.retroachievements.org/Images/070800.png', 'https://media.retroachievements.org/Images/034704.png', 'https://media.retroachievements.org/Images/034698.png', 'https://media.retroachievements.org/Images/027026.png', 4.4),
  (45, 11269, 'Breath of Fire III', 'PlayStation', 12, 5285, 5285, 5285, 99, 0, NULL, 'Capcom', 'Capcom', '1997-09-11', 'Breath of Fire III is a role-playing video game developed and published by Capcom originally for the PlayStation console as part of the Breath of Fire series. It was released in Japan on September 11, 1997, and in North America and Europe in 1998. It is the first game in the franchise to feature three-dimensional graphics and voice acting. On August 25, 2005, the game was ported and released for the PlayStation Portable handheld system in Japan, and was also released in Europe on February 3, 2006.', 'https://media.retroachievements.org/Images/019054.png', 'https://media.retroachievements.org/Images/053050.png', 'https://media.retroachievements.org/Images/019052.png', 'https://media.retroachievements.org/Images/019053.png', 4.4),
  (46, 11365, 'Mega Man 8', 'PlayStation', 12, 5216, 5216, 5216, 31, 0, '2D Platforming', 'Capcom', 'Capcom', '1996-12-17', 'Zero  is a fictional character present throughout much of Capcom''s Mega Man franchise. He is an android and the final creation of the original series'' main antagonist, Dr. Wily. Zero debuts in the Mega Man X series as an elite member of the Maverick Hunters, an organization dedicated to defending humanity and good Reploids from evil Reploids known as Mavericks. Zero also acts as a mentor and longtime friend to X, the main protagonist of the X series. He is also the titular main protagonist of the Mega Man Zero series, and has a supporting role in other series in the franchise, such as the Mega Man ZX series. He has also appeared in crossover video games as a guest character.', 'https://media.retroachievements.org/Images/054970.png', 'https://media.retroachievements.org/Images/071141.png', 'https://media.retroachievements.org/Images/026464.png', 'https://media.retroachievements.org/Images/026465.png', 4.4),
  (47, 11258, 'Chrono Cross', 'PlayStation', 12, 5211, 5211, 5211, 138, 0, 'Turn-Based RPG', 'Square', 'Squaresoft', '1999-11-18', 'Chrono Cross is a 1999 role-playing video game developed and published by Square for the PlayStation video game console. It is set in the same world as Chrono Trigger, which was released in 1995 for the Super Nintendo Entertainment System. Chrono Cross was designed primarily by scenarist and director Masato Kato, who had help from other designers who also worked on Chrono Trigger, including art director Yasuyuki Honne and composer Yasunori Mitsuda. Nobuteru Yūki designed the characters of the game.', 'https://media.retroachievements.org/Images/121514.png', 'https://media.retroachievements.org/Images/033101.png', 'https://media.retroachievements.org/Images/033100.png', 'https://media.retroachievements.org/Images/033102.png', 4.4),
  (48, 11261, 'Klonoa: Door to Phantomile', 'PlayStation', 12, 5109, 5109, 5109, 46, 0, '2.5D Platforming', 'Namco', 'Namco', '1997-12-11', 'Klonoa: Door to Phantomile is a 1997 platform game developed and published by Namco for the PlayStation. It is the first game in the Klonoa series. The story follows Klonoa and his friend Huepow in their efforts to save the dream world of Phantomile from an evil spirit intent on turning it into a world of nightmares. The player controls Klonoa through a 2.5D perspective; the stages are rendered in three dimensions but the player moves along a 2D path. Klonoa can grab enemies and throw them as projectiles, or use them as a jump boost to navigate through the stages.', 'https://media.retroachievements.org/Images/085294.png', 'https://media.retroachievements.org/Images/045909.png', 'https://media.retroachievements.org/Images/026637.png', 'https://media.retroachievements.org/Images/026638.png', 4.4),
  (49, 11267, 'Spyro: Year of the Dragon', 'PlayStation', 12, 5097, 5097, 5097, 67, 0, '3D Platforming, Collect-a-thon', 'Insomniac Games', 'Sony Computer Entertainment', '2000-10-10', 'Spyro is a platform game series originally created by Insomniac Games as an exclusive for Sony''s PlayStation console. The series features the adventures of the titular character, a young purple dragon. Since the series'' introduction in 1998, there have been numerous sequels and a reboot trilogy. The series was originally produced by Universal Interactive, later became known as Vivendi Games; the rights to the intellectual property were acquired by Activision after its merge with Vivendi in 2008.', 'https://media.retroachievements.org/Images/089453.png', 'https://media.retroachievements.org/Images/027327.png', 'https://media.retroachievements.org/Images/107465.png', 'https://media.retroachievements.org/Images/107466.png', 4.4),
  (50, 11290, 'Brave Fencer Musashi', 'PlayStation', 12, 4893, 4893, 4893, 146, 0, 'Action RPG', 'Square', 'Squaresoft', '1998-07-16', 'Brave Fencer Musashi  is a 1998 action-platform video game developed and published by Square for the PlayStation. The game involves real-time sword-based combat in a 3D environment; it also features segments of voiced over dialogue and role-playing game elements such as a day-night cycle and resting to restore energy.', 'https://media.retroachievements.org/Images/026882.png', 'https://media.retroachievements.org/Images/046305.png', 'https://media.retroachievements.org/Images/026883.png', 'https://media.retroachievements.org/Images/026885.png', 4.4),
  (51, 2873, 'Donald Duck: Goin'' Quackers', 'PlayStation', 12, 4767, 4767, 4767, 65, 0, '3D Platforming', 'Ubisoft', 'Ubisoft', '2000-11-14', 'Donald Duck: Goin'' Quackers is a 2000 platform game developed and published by Ubi Soft for various consoles and Windows-based personal computers. A version with the same title was released for the Game Boy Color, before it was retitled Donald Duck Advance for the Game Boy Advance. Reviews praised the music, backgrounds and animations, noting the short length and low difficulty as more fun for children.', 'https://media.retroachievements.org/Images/113907.png', 'https://media.retroachievements.org/Images/096299.png', 'https://media.retroachievements.org/Images/032748.png', 'https://media.retroachievements.org/Images/050578.png', 4.4),
  (52, 14415, 'JoJo''s Bizarre Adventure', 'PlayStation', 12, 4694, 4694, 4694, 40, 0, '2D Fighting', 'Capcom', 'Capcom', '1999-10-14', 'This is a list of games released on the Game Boy Advance handheld video game system. The number of licensed games in this list is 1538, organized alphabetically by the games'' localized English titles, or, when Japan-exclusive, their rōmaji transliterations. This list does not include Game Boy Advance Video releases.', 'https://media.retroachievements.org/Images/102615.png', 'https://media.retroachievements.org/Images/049130.png', 'https://media.retroachievements.org/Images/026478.png', 'https://media.retroachievements.org/Images/026479.png', 4.4),
  (53, 11330, 'Blood Omen: Legacy of Kain', 'PlayStation', 12, 4470, 4470, 4470, 90, 0, 'Action-Adventure', 'Silicon Knights', 'Crystal Dynamics', '1996-11-01', 'Blood Omen: Legacy of Kain is a 1996 action-adventure video game developed by Silicon Knights and published by Crystal Dynamics for the PlayStation. A Windows port developed by Semi Logic Entertainments was released by Activision under license from Crystal Dynamics in 1997, which was re-released digitally via GOG.com in 2021. The game is the first title in the Legacy of Kain series.', 'https://media.retroachievements.org/Images/019050.png', 'https://media.retroachievements.org/Images/052417.png', 'https://media.retroachievements.org/Images/019048.png', 'https://media.retroachievements.org/Images/019049.png', 4.4),
  (54, 11246, 'Final Fantasy Tactics', 'PlayStation', 12, 4444, 4444, 4444, 121, 0, 'Tactical RPG', 'Square', 'Squaresoft', '1997-06-20', 'Final Fantasy Tactics is a 1997 tactical role-playing game developed and published by Square for the PlayStation. It was released in Japan in June 1997 and in North America in January 1998 by Sony Computer Entertainment. It is the first game of the Tactics sub-series within the Final Fantasy franchise, and the first entry set in the fictional world later known as Ivalice. The story follows Ramza Beoulve, a highborn cadet placed in the middle of a military conflict known as The Lion War, where two opposing noble factions are coveting the throne of the kingdom.', 'https://media.retroachievements.org/Images/070804.png', 'https://media.retroachievements.org/Images/057555.png', 'https://media.retroachievements.org/Images/019090.png', 'https://media.retroachievements.org/Images/019091.png', 4.4),
  (55, 11335, 'Mega Man X5', 'PlayStation', 12, 4285, 4285, 4285, 53, 0, '2D Platforming', 'Capcom', 'Capcom', '2000-11-30', 'Mega Man X5, known as Rockman X5 (ロックマンX5) in Japan, is a 2000 action-platform game and the fifth main installment in the Mega Man X series. Developed by Capcom, it was first released for the PlayStation in Japan on November 30, 2000, and in North America and PAL territories the following year. In 2002, the game was ported to Microsoft Windows as retail packages in both Japan and North America.', 'https://media.retroachievements.org/Images/056204.png', 'https://media.retroachievements.org/Images/026552.png', 'https://media.retroachievements.org/Images/026551.png', 'https://media.retroachievements.org/Images/027473.png', 4.4),
  (56, 11318, 'Dino Crisis', 'PlayStation', 12, 4059, 4059, 4059, 65, 0, 'Survival Horror', 'Capcom', 'Capcom', '1999-07-01', 'Dino Crisis 2 is a 2000 action-adventure game developed by Capcom Production Studio 4 and published by Capcom for the PlayStation. It is the second installment in the Dino Crisis series, with designer Takumi Shu taking over as game-director from Mikami Shinji from the first game. The narrative continues the story of special operative Regina, who must deal with the fallout of a time-distorting event which transports a research-base and the surrounding area through time. Regina and team-leader Dylan Morton must battle against dinosaurs in order to find a way to get back to the present.', 'https://media.retroachievements.org/Images/029487.png', 'https://media.retroachievements.org/Images/029470.png', 'https://media.retroachievements.org/Images/077220.png', 'https://media.retroachievements.org/Images/077221.png', 4.4),
  (57, 11382, 'Mega Man X6', 'PlayStation', 12, 4037, 4037, 4037, 65, 0, '2D Platforming', 'Capcom', 'Capcom', '2001-11-29', 'Mega Man X is a series of action-platform games released by Capcom. It is a sub-series of the Mega Man franchise previously developed by the same group, with Keiji Inafune acting as one of the main staff members. The first game was released on 17 December 1993 in Japan on the Super Famicom and the following month on the Super NES in North America. Most of the sequels were ported to Microsoft Windows. The gameplay introduces new elements to the Mega Man franchise in the form of Mega Man''s successor X, including his new skills and power-ups in the form of armors while retaining the ability to decide which boss to fight first. The franchise is also known for its replay value, in which certain choices and optional content can influence both gameplay and storylines, allowing the player to experience alternate scenarios.', 'https://media.retroachievements.org/Images/032736.png', 'https://media.retroachievements.org/Images/027234.png', 'https://media.retroachievements.org/Images/027231.png', 'https://media.retroachievements.org/Images/027340.png', 4.3),
  (58, 29328, 'Resident Evil', 'PlayStation', 12, 3961, 3961, 3961, 64, 0, 'Survival Horror', 'Capcom', 'Capcom', '1996-03-22', 'Resident Evil, known as Biohazard  in Japan, is a Japanese horror game series and media franchise created by Capcom. It consists of survival horror, third-person shooter and first-person games, with players typically surviving in environments inhabited by zombies and other mutated creatures. The franchise has expanded into media including a live-action film series, animated films, television series, comic books, novels, audiobooks, and merchandise. Resident Evil is among the highest-grossing horror franchises of all time, and is Capcom''s best-selling franchise, with over 170 million copies sold worldwide as of March 2025. Individual installments of the series have been critically acclaimed and have received several awards, and many characters from the series such as Leon S. Kennedy and Albert Wesker have been described as video game icons.', 'https://media.retroachievements.org/Images/103090.png', 'https://media.retroachievements.org/Images/100816.png', 'https://media.retroachievements.org/Images/100817.png', 'https://media.retroachievements.org/Images/100818.png', 4.3),
  (59, 11309, 'Parasite Eve II', 'PlayStation', 12, 3954, 3954, 3954, 77, 0, 'Survival Horror', 'Square', 'Squaresoft', '1999-12-16', 'Parasite Eve II is a 1999 action role-playing game released for the PlayStation. The game was developed and published by Square, published in Japan in 1999 and in both North America and, unlike the previous game, in PAL regions in 2000. It is the sequel to Parasite Eve and the second game in the series of the same name.', 'https://media.retroachievements.org/Images/112210.png', 'https://media.retroachievements.org/Images/105817.png', 'https://media.retroachievements.org/Images/105814.png', 'https://media.retroachievements.org/Images/105815.png', 4.3),
  (60, 11248, 'Xenogears', 'PlayStation', 12, 3825, 3825, 3825, 81, 0, 'Turn-Based RPG', 'Square', 'Squaresoft', '1998-02-11', 'Xenogears is a 1998 role-playing video game developed and published by Square for the PlayStation. It is the debut entry in the larger Xeno franchise. The gameplay of Xenogears revolves around navigating 3D environments both on-foot and using humanoid mecha dubbed Gears. Combat is governed by a version of the turn-based Active Time Battle system. The story follows protagonist Fei Fong Wong and several others as they journey across the world to overthrow the all-powerful rule of Solaris and uncover mysteries concerning their world. The story incorporates Jungian psychology, Freudian thought, and religious symbolism.', 'https://media.retroachievements.org/Images/118168.png', 'https://media.retroachievements.org/Images/046554.png', 'https://media.retroachievements.org/Images/031151.png', 'https://media.retroachievements.org/Images/031155.png', 4.3),
  (61, 11379, 'Digimon Rumble Arena', 'PlayStation', 12, 3781, 3781, 3781, 55, 0, 'Platform Fighting', 'CAProduction, Hudson Soft', 'Bandai', '2001-12-06', 'Digimon Rumble Arena is a 2001 fighting video game developed and published by Bandai. It is part of a video game series connected to the Digimon franchise and showcases the titular creatures within the context of a fighting video game. The player controls one of several Digimon and engages in combat with other Digimon within a variety of settings. Apart from the central fighting gameplay, a trio of mini-games are available upon the single-player campaign''s completion.', 'https://media.retroachievements.org/Images/103153.png', 'https://media.retroachievements.org/Images/102635.png', 'https://media.retroachievements.org/Images/032100.png', 'https://media.retroachievements.org/Images/032101.png', 4.3),
  (62, 11255, 'Suikoden', 'PlayStation', 12, 3746, 3746, 3746, 92, 0, 'Turn-Based RPG', 'Konami', 'Konami', '1995-12-15', 'Suikoden  is a role-playing video game published by Konami. It is the first installment of the Suikoden series. Developed by Konami Computer Entertainment Tokyo, it was released initially in 1995 for the PlayStation in Japan. A North American release followed one year later, and a mainland European release came the following April. The game was also released for Windows and Sega Saturn in 1998, but only in Japan.', 'https://media.retroachievements.org/Images/054686.png', 'https://media.retroachievements.org/Images/045588.png', 'https://media.retroachievements.org/Images/017571.png', 'https://media.retroachievements.org/Images/017575.png', 4.3),
  (63, 11357, 'Toy Story 2: Buzz Lightyear to the Rescue!', 'PlayStation', 12, 3705, 3705, 3705, 90, 0, '3D Platforming, Collect-a-thon', 'Traveller''s Tales', 'Activision', '1999-11-16', 'Toy Story 2: Buzz Lightyear to the Rescue is a 1999 platform game developed by Traveller''s Tales and published by Activision and Disney Interactive. Based on Disney/Pixar''s 1999 computer animated film Toy Story 2, it was released for the Nintendo 64, PlayStation, Microsoft Windows, and Macintosh in late 1999, while a Dreamcast version followed in 2000. The computer versions were released under the title Disney/Pixar''s Action Game, Toy Story 2. A different version, a side-scrolling platform game titled Toy Story 2, was also released for the Game Boy Color in 1999.', 'https://media.retroachievements.org/Images/060240.png', 'https://media.retroachievements.org/Images/045463.png', 'https://media.retroachievements.org/Images/039470.png', 'https://media.retroachievements.org/Images/039469.png', 4.3),
  (64, 11282, 'Tony Hawk''s Pro Skater 2', 'PlayStation', 12, 3623, 3623, 3623, 56, 0, 'Extreme Sports - Skateboarding', 'Neversoft', 'Activision', '2000-09-19', 'Tony Hawk''s Pro Skater 2 is a 2000 skateboarding video game developed by Neversoft for PlayStation and Natsume for Game Boy Color. Published by Activision, it is the second installment in the Tony Hawk''s series of sports games, and was released for the PlayStation in 2000, with subsequent ports to Windows and Dreamcast alongside a distinct version for Game Boy Color the same year. In 2001, the game was ported to Mac OS, Mac OS X, Nintendo 64, and Xbox, alongside a separate version for Game Boy Advance by Vicarious Visions. The game was later ported to Windows Mobile and Windows Phone devices in 2006 and to iPhone OS devices in 2010.', 'https://media.retroachievements.org/Images/107023.png', 'https://media.retroachievements.org/Images/052419.png', 'https://media.retroachievements.org/Images/026500.png', 'https://media.retroachievements.org/Images/026580.png', 4.3),
  (65, 13431, 'Bugs Bunny: Lost in Time', 'PlayStation', 12, 3597, 3597, 3597, 56, 0, '3D Platforming', 'Behaviour Interactive', 'Infogrames', '1999-06-29', 'Bugs Bunny: Lost in Time is a 1999 platform video game developed by Behaviour Interactive, published by Infogrames, and released for the PlayStation and Windows. It is based on Bugs Bunny and other Looney Tunes characters by Warner Bros. Entertainment. The game follows the titular character, who finds himself in a time slip and is tasked with gathering clocks in order to return to the present.', 'https://media.retroachievements.org/Images/116769.png', 'https://media.retroachievements.org/Images/031427.png', 'https://media.retroachievements.org/Images/031429.png', 'https://media.retroachievements.org/Images/031428.png', 4.3),
  (66, 11275, 'Vagrant Story', 'PlayStation', 12, 3576, 3576, 3576, 200, 0, 'Action RPG', 'Square', 'Squaresoft', '2000-02-10', 'The year 2000 saw the release of numerous video games as well as the launch of the PlayStation 2. Critically acclaimed games originally released in 2000 include sequels such as Madden NFL 2001, NBA Live 2001, NBA 2K1, WWF SmackDown! 2: Know Your Role, Baldur''s Gate II, Diablo II, Dragon Quest VII, Final Fantasy IX, Metal Gear: Ghost Babel, NFL 2K1, Resident Evil – Code: Veronica, Spyro: Year of the Dragon, The Legend of Zelda: Majora''s Mask, and Tony Hawk''s Pro Skater 2, along with new intellectual properties such as Deus Ex, Hitman, Jet Set Radio, Perfect Dark, Skies of Arcadia, The Sims, SSX, Vagrant Story, and Sin and Punishment. The year''s best-selling home video games worldwide were Pokémon games for the third year in a row, while the highest-grossing arcade game in Japan was Virtua Striker 2.', 'https://media.retroachievements.org/Images/054471.png', 'https://media.retroachievements.org/Images/061540.png', 'https://media.retroachievements.org/Images/032582.png', 'https://media.retroachievements.org/Images/033104.png', 4.3),
  (67, 10437, 'Grand Theft Auto', 'PlayStation', 12, 3551, 3551, 3551, 122, 0, 'Action-Adventure, Sandbox', 'Rockstar North', 'Rockstar Games', '1997-12-12', 'Grand Theft Auto (GTA) is an action-adventure video game series created by David Jones and Mike Dailly. Later titles were developed under the oversight of brothers Dan and Sam Houser, Leslie Benzies and Aaron Garbut. It is primarily developed by British development house Rockstar North, and published by its American parent company, Rockstar Games. The name of the series is a term for motor vehicle theft in the United States.', 'https://media.retroachievements.org/Images/109939.png', 'https://media.retroachievements.org/Images/052896.png', 'https://media.retroachievements.org/Images/034245.png', 'https://media.retroachievements.org/Images/034247.png', 4.3),
  (68, 11391, 'Driver: You Are The Wheelman', 'PlayStation', 12, 3527, 3527, 3527, 72, 0, 'Action, Arcade Racing', 'Reflections Interactive', 'Atari', '1999-06-25', 'Driver is an action driving video game and the first installment in the Driver series. Developed by Reflections Interactive and published by GT Interactive, it was released on the PlayStation on 25 June 1999, and was ported to Microsoft Windows on 1 October 1999, and to Classic Mac OS on 12 December 2000 by Abersoft Limited.', 'https://media.retroachievements.org/Images/052905.png', 'https://media.retroachievements.org/Images/052423.png', 'https://media.retroachievements.org/Images/027228.png', 'https://media.retroachievements.org/Images/027229.png', 4.3),
  (69, 11406, 'Mortal Kombat 4', 'PlayStation', 12, 3527, 3527, 3527, 131, 0, '3D Fighting', 'Midway', 'Midway', '1998-06-23', 'Mortal Kombat 4 is a 1997 fighting game developed and published by Midway for arcades. It is the fourth main installment in the Mortal Kombat franchise, and a sequel to 1995''s Mortal Kombat 3. It is also the first title in the series to use 3D computer graphics, as well as the last in the series to have an arcade release. The game was ported to the PlayStation, Nintendo 64, Microsoft Windows, and Game Boy Color in 1998, followed by an updated version, titled Mortal Kombat Gold, for the Dreamcast in 1999.', 'https://media.retroachievements.org/Images/123571.png', 'https://media.retroachievements.org/Images/054400.png', 'https://media.retroachievements.org/Images/042107.png', 'https://media.retroachievements.org/Images/042151.png', 4.3),
  (70, 11398, 'Grand Theft Auto 2', 'PlayStation', 12, 3503, 3503, 3503, 104, 0, 'Action-Adventure, Sandbox', 'Rockstar North', 'Rockstar Games', '1999-10-22', 'Grand Theft Auto 2 is a 1999 action-adventure game developed by DMA Design and published by Rockstar Games. It is the sequel to 1997''s Grand Theft Auto, and the second main entry in the Grand Theft Auto series. Set within a retrofuturistic metropolis known as Anywhere City, the game focuses on players taking the role of a criminal as they roam an open world, conducting jobs for various crime syndicates and having free rein to do whatever they wish to achieve their goal. The game''s intro is unique for a title in the series, as it involves live-action scenes filmed by Rockstar Games. The game was released for the PlayStation and Windows in October 1999 and for the Dreamcast and Game Boy Color in 2000.', 'https://media.retroachievements.org/Images/114109.png', 'https://media.retroachievements.org/Images/053169.png', 'https://media.retroachievements.org/Images/041095.png', 'https://media.retroachievements.org/Images/097250.png', 4.3),
  (71, 11419, 'Resident Evil: Survivor', 'PlayStation', 12, 3503, 3503, 3503, 45, 0, 'First-Person Shooter, Survival Horror', 'TOSE', 'Capcom', '2000-01-27', 'This is a list of video game remakes and remasters and includes remakes as well as remasters of video games. It does not include clones and enhanced ports.', 'https://media.retroachievements.org/Images/102291.png', 'https://media.retroachievements.org/Images/045505.png', 'https://media.retroachievements.org/Images/027606.png', 'https://media.retroachievements.org/Images/027607.png', 4.3),
  (72, 11399, 'Croc: Legend of the Gobbos', 'PlayStation', 12, 3462, 3462, 3462, 66, 0, '3D Platforming', 'Argonaut Games', 'Fox Interactive', '1997-09-29', 'Croc: Legend of the Gobbos is a 1997 platform game developed by Argonaut Software and published by Fox Interactive. An early example of a 3D platform game, Croc was released for the PlayStation, Sega Saturn and Windows. Taking place in the fictional setting of the Gobbo Valley, Croc: Legend of the Gobbos follows a young crocodile named Croc, who sets out to rescue his adoptive family from the evil magician Baron Dante.', 'https://media.retroachievements.org/Images/121670.png', 'https://media.retroachievements.org/Images/048985.png', 'https://media.retroachievements.org/Images/027659.png', 'https://media.retroachievements.org/Images/032523.png', 4.3),
  (73, 11292, 'Breath of Fire IV', 'PlayStation', 12, 3451, 3451, 3451, 129, 0, NULL, 'Capcom', 'Capcom', '2000-04-27', 'This is a list of games released on the Game Boy Advance handheld video game system. The number of licensed games in this list is 1538, organized alphabetically by the games'' localized English titles, or, when Japan-exclusive, their rōmaji transliterations. This list does not include Game Boy Advance Video releases.', 'https://media.retroachievements.org/Images/051208.png', 'https://media.retroachievements.org/Images/046368.png', 'https://media.retroachievements.org/Images/019056.png', 'https://media.retroachievements.org/Images/019057.png', 4.3),
  (74, 11328, 'Digimon World 2003', 'PlayStation', 12, 3344, 3344, 3344, 137, 0, 'Turn-Based RPG', 'BEC, Boom', 'Bandai', '2002-06-06', 'Digimon World 3 , also known as Digimon World 2003 in Europe and Australia, is a role-playing video game for the PlayStation developed by BEC and Boom Corp, and published by Bandai. It is the third installment in the Digimon World series and it was first released in June 2002 in North America and then in July 2002 in Japan and November 2002 in Europe. The game tells the story of Junior, who begins playing an MMORPG called Digimon Online with his friends, but when terrorists attack, Junior and the other players are trapped within the game and must find a way out using his Digimon partners.', 'https://media.retroachievements.org/Images/069935.png', 'https://media.retroachievements.org/Images/077305.png', 'https://media.retroachievements.org/Images/026444.png', 'https://media.retroachievements.org/Images/026443.png', 4.3),
  (75, 11383, 'Twisted Metal', 'PlayStation', 12, 3321, 3321, 3321, 43, 0, 'Vehicular Combat', 'SingleTrac', 'Sony Computer Entertainment', '1995-11-10', 'Twisted Metal is a 2012 vehicular combat video game developed by Eat Sleep Play and published by Sony Computer Entertainment for the PlayStation 3. It is the second reboot of the Twisted Metal series, following Twisted Metal: Black. The game was originally planned to be released in October 2011, but was delayed to early 2012.', 'https://media.retroachievements.org/Images/059514.png', 'https://media.retroachievements.org/Images/053349.png', 'https://media.retroachievements.org/Images/026573.png', 'https://media.retroachievements.org/Images/026574.png', 4.3),
  (76, 13897, 'Looney Tunes: Sheep Raider', 'PlayStation', 12, 3254, 3254, 3254, 42, 0, '3D Platforming, Puzzle, Stealth', 'Infogrames', 'Infogrames', '2001-05-23', 'Sheep, Dog ''n'' Wolf is a puzzle-platformer stealth video game developed by Infogrames Lyon House and published by Infogrames for Microsoft Windows and PlayStation.', 'https://media.retroachievements.org/Images/088380.png', 'https://media.retroachievements.org/Images/049223.png', 'https://media.retroachievements.org/Images/044209.png', 'https://media.retroachievements.org/Images/044208.png', 4.3),
  (77, 11369, 'Koudelka', 'PlayStation', 12, 3232, 3232, 3232, 110, 0, 'Survival Horror, Turn-Based RPG', 'Sacnoth | Nautilus', 'Infogrames', '1999-12-16', 'Koudelka  is a role-playing video game developed by Sacnoth for the PlayStation. The game was published by SNK in Japan in 1999, and by Infogrames internationally in 2000. Set in the haunted Nemeton Monastery in Wales, the plot follows protagonists Koudelka Iasant, Edward Plunkett and Bishop James O''Flaherty as they uncover Nemeton''s secrets and confront monsters created from its dark past. Its gameplay blends exploration and puzzle elements with turn-based battles waged on a grid.', 'https://media.retroachievements.org/Images/048738.png', 'https://media.retroachievements.org/Images/046425.png', 'https://media.retroachievements.org/Images/017620.png', 'https://media.retroachievements.org/Images/017616.png', 4.3),
  (78, 11378, 'Wipeout', 'PlayStation', 12, 3229, 3229, 3229, 44, 0, 'Arcade Racing', 'Psygnosis | Studio Liverpool', 'Psygnosis', '1995-09-29', 'Wipeout is a 1995 racing video game developed and published by Psygnosis for the PlayStation. The first installment in the Wipeout series, it was a launch title for the PlayStation in Europe. It was ported to DOS, followed by Sega Saturn the next year. Psygnosis'' parent company, Sony Computer Entertainment, re-released the game for the PlayStation 3 and PlayStation Portable via the PlayStation Network in 2007.', 'https://media.retroachievements.org/Images/063354.png', 'https://media.retroachievements.org/Images/090212.png', 'https://media.retroachievements.org/Images/018262.png', 'https://media.retroachievements.org/Images/018261.png', 4.3),
  (79, 14635, 'Disney''s Hercules Action Game', 'PlayStation', 12, 3081, 3081, 3081, 44, 0, 'Action-Adventure', 'Eurocom', 'Disney Interactive Studios, Virgin Interactive', '1997-07-03', 'Below is a list of video games based on Walt Disney Animation Studios shorts and features.', 'https://media.retroachievements.org/Images/040456.png', 'https://media.retroachievements.org/Images/097608.png', 'https://media.retroachievements.org/Images/097606.png', 'https://media.retroachievements.org/Images/097607.png', 4.3),
  (80, 13437, 'LSD: Dream Emulator', 'PlayStation', 12, 3051, 3051, 3051, 156, 0, 'Adventure, Simulation', 'OutSide Directors Company', 'Asmik Ace Entertainment', '1998-10-22', 'ENA: Dream BBQ is a 2025 episodic exploration adventure game developed by ENA Team and published by Joel Guerra. It follows ENA, a humanoid being who explores various environments while interacting with other characters, completing in-game tasks, navigating mazes, and solving puzzles in an effort to reach the Boss, a mysterious figure central to the narrative.', 'https://media.retroachievements.org/Images/092964.png', 'https://media.retroachievements.org/Images/068825.png', 'https://media.retroachievements.org/Images/092979.png', 'https://media.retroachievements.org/Images/092978.png', 4.3),
  (81, 11297, 'Legacy of Kain: Soul Reaver', 'PlayStation', 12, 3018, 3018, 3018, 50, 0, 'Action-Adventure', 'Crystal Dynamics', 'Eidos Interactive', '1999-08-16', 'Legacy of Kain: Soul Reaver is a 1999 action-adventure video game developed by Crystal Dynamics and published by Eidos Interactive for the PlayStation and Windows. A port to the Dreamcast developed by Nixxes Software was released in 2000, serving as Nixxes'' first project. The second game in the Legacy of Kain series, Soul Reaver is the sequel to Blood Omen: Legacy of Kain. Soul Reaver was followed by three games, one of which, Soul Reaver 2, is a direct sequel.', 'https://media.retroachievements.org/Images/033305.png', 'https://media.retroachievements.org/Images/052418.png', 'https://media.retroachievements.org/Images/033301.png', 'https://media.retroachievements.org/Images/033304.png', 4.3),
  (82, 11299, 'Legend of Legaia', 'PlayStation', 12, 3012, 3012, 3012, 82, 0, NULL, 'Prokion', 'Sony Computer Entertainment', '1998-10-29', 'Legend of Legaia is a role-playing video game developed by Prokion and published by Sony Computer Entertainment for the PlayStation. Contrail handled the game''s production. It was released in Japan in October 1998, North America in March 1999 and Europe in May 2000. A sequel, Legaia 2: Duel Saga, was released for the PlayStation 2.', 'https://media.retroachievements.org/Images/044670.png', 'https://media.retroachievements.org/Images/030944.png', 'https://media.retroachievements.org/Images/030946.png', 'https://media.retroachievements.org/Images/030947.png', 4.3),
  (83, 11310, 'Wild Arms', 'PlayStation', 12, 2985, 2985, 2985, 155, 0, 'Turn-Based RPG', 'Media.Vision', 'Sony Computer Entertainment', '1996-12-20', 'Wild Arms , stylized as Wild ARMs, is a media franchise developed by Media.Vision and owned by Sony Computer Entertainment. The franchise consists of several role-playing video games and related media. Since the launch of the original Wild Arms title in 1996, the series has gone on to encompass several media, including toys, manga, mobile phone applications, and a 22-episode anime.', 'https://media.retroachievements.org/Images/058584.png', 'https://media.retroachievements.org/Images/015390.png', 'https://media.retroachievements.org/Images/019083.png', 'https://media.retroachievements.org/Images/045507.png', 4.3),
  (84, 14629, 'Quake II', 'PlayStation', 12, 2945, 2945, 2945, 50, 0, 'First-Person Shooter', 'HammerHead, id Software', 'Activision', '1999-10-05', 'Quake is a series of first-person shooter video games, developed by id Software and, as of 2010, published by Bethesda Softworks. The series is composed of Quake and its nonlinear, standalone sequels, which vary in setting and plot.', 'https://media.retroachievements.org/Images/047484.png', 'https://media.retroachievements.org/Images/046263.png', 'https://media.retroachievements.org/Images/047462.png', 'https://media.retroachievements.org/Images/047461.png', 4.3),
  (85, 11342, 'Tomb Raider', 'PlayStation', 12, 2934, 2934, 2934, 85, 0, 'Action-Adventure, Cinematic Platforming', 'Core Design', 'Eidos Interactive', '1996-11-14', 'Tomb Raider, known as Lara Croft: Tomb Raider from 1996 to 2008, is a media franchise that originated with an action-adventure video game series created by British video game developer Core Design. The franchise is currently owned by CDE Entertainment; it was formerly owned by Eidos Interactive, then by Square Enix Europe after Square Enix''s acquisition of Eidos in 2009 until Embracer Group purchased the intellectual property alongside Eidos in 2022. The franchise focuses on the fictional British archaeologist Lara Croft, who travels around the world searching for lost artefacts and infiltrating dangerous tombs and ruins. Gameplay generally focuses on exploration, solving puzzles, navigating hostile environments filled with traps, and fighting enemies. Additional media has been developed for the franchise in the form of film adaptations, comics and novels.', 'https://media.retroachievements.org/Images/050017.png', 'https://media.retroachievements.org/Images/026539.png', 'https://media.retroachievements.org/Images/026528.png', 'https://media.retroachievements.org/Images/035983.png', 4.3),
  (86, 11294, 'Medal of Honor: Underground', 'PlayStation', 12, 2913, 2913, 2913, 76, 0, 'First-Person Shooter', 'DreamWorks Interactive', 'Electronic Arts', '2000-10-24', 'Medal of Honor: Underground is a 2000 first-person shooter video game developed by DreamWorks Interactive and published by Electronic Arts. It is the second installment in the Medal of Honor series and was released for the PlayStation with an adapted port later for the Game Boy Advance, developed by Rebellion Developments.', 'https://media.retroachievements.org/Images/040941.png', 'https://media.retroachievements.org/Images/045553.png', 'https://media.retroachievements.org/Images/039070.png', 'https://media.retroachievements.org/Images/039069.png', 4.3),
  (87, 11249, 'Valkyrie Profile', 'PlayStation', 12, 2836, 2836, 2836, 174, 0, 'Turn-Based RPG', 'tri-Ace', 'Enix', '1999-12-22', 'Valkyrie Profile  or Valkyrie  is a series of role-playing video games created by Masaki Norimoto and Yoshiharu Gotanda, primarily developed by tri-Ace and published by Square Enix. The series is notable for featuring elements from Norse mythology.', 'https://media.retroachievements.org/Images/048353.png', 'https://media.retroachievements.org/Images/048357.png', 'https://media.retroachievements.org/Images/048355.png', 'https://media.retroachievements.org/Images/048354.png', 4.3),
  (88, 11250, 'Harvest Moon: Back to Nature', 'PlayStation', 12, 2829, 2829, 2829, 183, 0, 'Life Simulation', 'TOSE', 'Natsume', '1999-12-16', 'Harvest Moon: Back to Nature is a 1999 video game in the farm simulation series Story of Seasons developed by Victor Interactive Software and published outside of Japan by Natsume. It is the first Harvest Moon game for a non-Nintendo console. Characters from Harvest Moon 64 were transferred to be the characters in this game, although with new lifestyles, personalities, and relatives.', 'https://media.retroachievements.org/Images/059687.png', 'https://media.retroachievements.org/Images/065961.png', 'https://media.retroachievements.org/Images/035723.png', 'https://media.retroachievements.org/Images/035722.png', 4.3),
  (89, 14377, 'King''s Field II', 'PlayStation', 12, 2783, 2783, 2783, 177, 0, 'Action RPG', 'FromSoftware', 'ASCII Entertainment', '1995-07-21', 'FromSoftware, Inc. is a Japanese video game developer and publisher. Founded by Naotoshi Zin on November 1, 1986 as a business software developer, the company released their first video game, King''s Field, for the PlayStation in 1994. Its success shifted FromSoftware to focus fully on games, with them producing two more King''s Field games before the first release of the mecha shooter series Armored Core in 1997.', 'https://media.retroachievements.org/Images/112034.png', 'https://media.retroachievements.org/Images/046495.png', 'https://media.retroachievements.org/Images/032957.png', 'https://media.retroachievements.org/Images/032958.png', 4.3),
  (90, 11332, 'Final Fantasy Origins', 'PlayStation', 12, 2748, 2748, 2748, 119, 0, NULL, 'TOSE, Square', 'Square Enix', '2002-10-31', 'Final Fantasy is a 1987 role-playing video game developed and published by Square for the Nintendo Entertainment System. It is the first game in Square''s Final Fantasy series, created by Hironobu Sakaguchi. The story follows four youths called the Warriors of Light, who each carry one of their world''s four elemental crystals which have been darkened by the four Elemental Fiends. Together, they quest to defeat these evil forces, restore light to the crystals, and save their world.', 'https://media.retroachievements.org/Images/060249.png', 'https://media.retroachievements.org/Images/046257.png', 'https://media.retroachievements.org/Images/026707.png', 'https://media.retroachievements.org/Images/026708.png', 4.3),
  (91, 11396, 'Ridge Racer', 'PlayStation', 12, 2739, 2739, 2739, 38, 0, 'Arcade Racing', 'Namco', 'Namco', '1994-12-03', 'Ridge Racer is a series of racing video games created by Namco and owned by Bandai Namco Entertainment. The first game, Ridge Racer (1993), was originally released in arcades for the Namco System 22 hardware, later ported to the PlayStation one year later as a launch title. It was met with several sequels and spin-off games for multiple platforms, the latest being the mobile game Ridge Racer Draw & Drift (2016) and the latest mainline game, developed in-house, was Ridge Racer 7 (2006). Gameplay involves the player racing against computer-controlled opponents to be the first to finish in a race. Drifting is a core aspect of the series and is used to keep speed while turning corners; Ridge Racer pioneered the real-life technique in video games. The series is considered influential to the racing game genre. On June 5, 2025, the arcade version of the first game was added to the Arcade Archives and Arcade Archives 2.', 'https://media.retroachievements.org/Images/049667.png', 'https://media.retroachievements.org/Images/046232.png', 'https://media.retroachievements.org/Images/020794.png', 'https://media.retroachievements.org/Images/020795.png', 4.3),
  (92, 11360, 'Digimon World 2', 'PlayStation', 12, 2730, 2730, 2730, 111, 0, NULL, 'BEC', 'Bandai', '2000-07-27', 'Digimon World  is a role-playing video game developed by BEC and published by Bandai for the PlayStation. It''s the first game in the Digimon World series, followed by various sequels released for the PlayStation and other platforms. The story focuses on a human brought to File City on File Island by Jijimon to save the island. Digimon have been losing their memories and becoming feral and the city has fallen into disarray. The goal of the player, who is represented by an unnamed young boy, is to save the island by helping Digimon recover their memory and return to the city.', 'https://media.retroachievements.org/Images/103705.png', 'https://media.retroachievements.org/Images/050504.png', 'https://media.retroachievements.org/Images/077304.png', 'https://media.retroachievements.org/Images/038049.png', 4.3),
  (93, 11411, 'Fighting Force', 'PlayStation', 12, 2716, 2716, 2716, 65, 0, 'Beat ''em Up', 'Core Design', 'Eidos Interactive', '1997-11-05', 'Fighting Force is a beat ''em up video game developed by Core Design and published in 1997 by Eidos Interactive for PlayStation and Windows. A Nintendo 64 version was published by Crave Entertainment in 1999. The Japanese version for the PlayStation was published by Electronic Arts Victor. Announced by Core shortly after the success of Tomb Raider, Fighting Force was highly anticipated but met with mixed reviews. It was followed by Fighting Force 2.', 'https://media.retroachievements.org/Images/046228.png', 'https://media.retroachievements.org/Images/046229.png', 'https://media.retroachievements.org/Images/046226.png', 'https://media.retroachievements.org/Images/046227.png', 4.3),
  (94, 11400, 'Duke Nukem: Time to Kill', 'PlayStation', 12, 2709, 2709, 2709, 51, 0, 'Third-Person Shooter', 'n-Space', 'GT Interactive, Take-Two Interactive', '1998-10-15', 'This is a list of video games considered controversial. The list includes games that have earned controversies for violence, sexual content, racism, and review bombing from fans. Some of the video games on this list have been banned or regionally censored.', 'https://media.retroachievements.org/Images/055929.png', 'https://media.retroachievements.org/Images/034777.png', 'https://media.retroachievements.org/Images/055930.png', 'https://media.retroachievements.org/Images/055931.png', 4.2),
  (95, 11424, 'Um Jammer Lammy', 'PlayStation', 12, 2627, 2627, 2627, 86, 0, 'Rhythm', 'NanaOn-Sha', 'Sony Computer Entertainment', '1999-03-18', 'NanaOn-Sha  is a Japanese video game developer founded by Masaya Matsuura in 1993.', 'https://media.retroachievements.org/Images/074323.png', 'https://media.retroachievements.org/Images/046306.png', 'https://media.retroachievements.org/Images/040345.png', 'https://media.retroachievements.org/Images/040346.png', 4.2),
  (96, 16225, 'Tarzan', 'PlayStation', 12, 2586, 2586, 2586, 80, 0, '2.5D Platforming', 'Eurocom', 'Sony Computer Entertainment', '1999-06-30', 'Tarzan is a fictional character, a feral child raised in the Congo Basin by the Mangani great apes; he later experiences civilization, only to reject it and return to the wild as a heroic adventurer.', 'https://media.retroachievements.org/Images/106450.png', 'https://media.retroachievements.org/Images/045376.png', 'https://media.retroachievements.org/Images/077247.png', 'https://media.retroachievements.org/Images/077246.png', 4.2),
  (97, 11262, 'Mega Man Legends 2', 'PlayStation', 12, 2571, 2571, 2571, 97, 0, 'Action-Adventure, Third-Person Shooter', 'Capcom', 'Capcom', '2000-04-20', 'Mega Man Legends 2 is a 2000 action-adventure game released by Capcom, acting as the sequel to Mega Man Legends. It was released for the PlayStation in 2000 for Japan and North America, and 2001 in Europe. Unchanged Japanese ports of the game were also released for the PC in Japan and parts of Asia in 2003 and for the PlayStation Portable in 2005. The game features Mega Man Volnutt''s quest to find four keys hidden in the planet in order to aid in the search of the Mother Lode, a legendary treasure thought to be an infinite energy source.', 'https://media.retroachievements.org/Images/051644.png', 'https://media.retroachievements.org/Images/045290.png', 'https://media.retroachievements.org/Images/026497.png', 'https://media.retroachievements.org/Images/026499.png', 4.2),
  (98, 17309, 'Harry Potter and the Chamber of Secrets', 'PlayStation', 12, 2564, 2564, 2564, 47, 0, 'Action-Adventure', 'Argonaut Games', 'Electronic Arts', '2002-11-15', 'Harry Potter and the Chamber of Secrets is a fantasy novel by British author J. K. Rowling. The second novel in the Harry Potter series, it chronicles Harry Potter''s second year at Hogwarts School of Witchcraft and Wizardry. After several residents of the school are attacked and magically immobilised, Harry and his friends Ron and Hermione investigate.', 'https://media.retroachievements.org/Images/067463.png', 'https://media.retroachievements.org/Images/076014.png', 'https://media.retroachievements.org/Images/076010.png', 'https://media.retroachievements.org/Images/076011.png', 4.2),
  (99, 11300, 'Tenchu: Stealth Assassins', 'PlayStation', 12, 2489, 2489, 2489, 120, 0, 'Stealth', 'Acquire', 'Activision', '1998-02-26', 'Tenchu: Stealth Assassins is a 1998 stealth video game developed by Acquire and published by Sony Music Entertainment Japan for the PlayStation. It is the first installment in the Tenchu series, with Activision releasing the game outside Japan. Following Rikimaru and Ayame of the Azuma ninja clan as they complete missions for their employer Lord Gohda in Sengoku-era Japan, the gameplay involves the player guiding their chosen character through missions, the aim being to remain undetected while either avoiding or quietly killing enemies.', 'https://media.retroachievements.org/Images/032019.png', 'https://media.retroachievements.org/Images/031836.png', 'https://media.retroachievements.org/Images/031838.png', 'https://media.retroachievements.org/Images/031839.png', 4.2),
  (100, 11326, 'WWF SmackDown! 2: Know Your Role', 'PlayStation', 12, 2482, 2482, 2482, 126, 0, 'Sports - Wrestling', 'Yuke''s', 'THQ', '2000-11-20', 'WWE 2K, formerly released as WWF SmackDown!, WWE SmackDown!, WWE SmackDown! vs. Raw, WWE SmackDown vs. Raw, WWE, and Exciting Pro Wrestling in Japan, is a series of professional wrestling sports simulation video games that launched in 2000. The premise of the series is to emulate professional wrestling, specifically that of WWE, formerly known as the World Wrestling Federation (WWF). The series began with WWF SmackDown! on the original PlayStation and has continued as an annual release. It was originally exclusive to PlayStation platforms until 2006''s WWE SmackDown vs. Raw 2007, which expanded the series to other platforms. In 2013, the series was rebranded as WWE 2K, beginning with WWE 2K14.', 'https://media.retroachievements.org/Images/109249.png', 'https://media.retroachievements.org/Images/043027.png', 'https://media.retroachievements.org/Images/043028.png', 'https://media.retroachievements.org/Images/060919.png', 4.2),
  (101, 11409, 'Gex', 'PlayStation', 12, 2448, 2448, 2448, 41, 0, '2D Platforming, Action', 'Crystal Dynamics', 'Crystal Dynamics', '1995-12-18', 'Gex 3: Deep Cover Gecko is a 1999 platform game developed by Crystal Dynamics and published by Eidos Interactive for the PlayStation. It is part of the Gex video game series, and was released in 1999, followed by ports for the Nintendo 64. Its protagonist, Gex, is a wisecracking, pop culture enthusiast voiced by Danny John-Jules in the UK and European releases and comedian Dana Gould, reprising his role from former Gex games, for the American release. The gameplay is set in Gex''s secret hideout, Mission Control a overworld, which is overseen by Gex''s butler, Alfred the Turtle. Playboy model Marliece Andrada plays Gex''s kidnapped companion, Agent Xtra, the only live-action character, who is featured in brief full-motion video sequences on the PlayStation version. The plot follows Gex''s return to the Media Dimension to rescue Agent Xtra from Rez, Gex''s arch-nemesis from the previous games.', 'https://media.retroachievements.org/Images/109674.png', 'https://media.retroachievements.org/Images/047782.png', 'https://media.retroachievements.org/Images/018361.png', 'https://media.retroachievements.org/Images/018362.png', 4.2),
  (102, 3145, 'Tetris Plus', 'PlayStation', 12, 2357, 2357, 2357, 31, 0, NULL, 'Natsume', 'Jaleco', '1996-09-06', 'Tetris Plus  is a 1995 puzzle video game developed and published by Jaleco for arcades. An entry in the Tetris series, it was ported to the Sega Saturn, PlayStation, and Game Boy in 1996, and was followed by the arcade sequel Tetris Plus 2 in 1997.', 'https://media.retroachievements.org/Images/027014.png', 'https://media.retroachievements.org/Images/027015.png', 'https://media.retroachievements.org/Images/027012.png', 'https://media.retroachievements.org/Images/027013.png', 4.2),
  (103, 11303, 'Need for Speed: High Stakes', 'PlayStation', 12, 2285, 2285, 2285, 50, 0, 'Arcade Racing', 'EA Canada | EA Vancouver', 'Electronic Arts', '1999-03-24', 'Need for Speed: High Stakes, released as Need for Speed: Road Challenge in Europe, is a 1999 racing video game developed by EA Canada and EA Seattle and published by Electronic Arts for the PlayStation and Microsoft Windows. It is the fourth game in the Need for Speed series and a follow-up to Need for Speed III: Hot Pursuit. The game features more realistic elements than its predecessors and introduced a damage system that allows cars to take damage when colliding with objects, affecting their appearance and performance. It also introduced a series of economy-based tournaments, awarding players with a cash prize that can be spent on repairing, purchasing, or upgrading cars for subsequent races. The game''s Hot Pursuit mode, which was introduced in Hot Pursuit, was expanded with more options, allowing players to control police pursuits attempting to stop racers.', 'https://media.retroachievements.org/Images/116504.png', 'https://media.retroachievements.org/Images/055539.png', 'https://media.retroachievements.org/Images/028497.png', 'https://media.retroachievements.org/Images/028498.png', 4.2),
  (104, 15934, 'NASCAR Rumble', 'PlayStation', 12, 2283, 2283, 2283, 116, 0, 'Arcade Racing', 'EA Redwood Shores', 'Electronic Arts', '2000-02-03', 'NASCAR Rumble is a racing video game created by Electronic Arts for the PlayStation. The player races through 18 courses set in six different areas collecting power-ups along the way. The game is a departure from many NASCAR games, as it is an arcade racer featuring various tracks and power-ups. A non-NASCAR licensed sequel was made for the PlayStation 2, called Rumble Racing. There are drivers from the then Winston Cup Series and Craftsman Truck Series, as well as legend racers and bonus vehicles.', 'https://media.retroachievements.org/Images/115969.png', 'https://media.retroachievements.org/Images/031861.png', 'https://media.retroachievements.org/Images/031863.png', 'https://media.retroachievements.org/Images/031860.png', 4.2),
  (105, 11301, 'Tales of Phantasia', 'PlayStation', 12, 2244, 2244, 2244, 313, 0, 'Action RPG', 'Wolf Team', 'Namco', '1998-12-23', 'Tales of Phantasia is an action role-playing video game developed by Wolf Team and published by Namco for the Super Famicom. Originally released only in Japan in December 1995, it is the first title in the Tales series. It was later ported to a number of other platforms, including a Japan-exclusive version for the PlayStation in December 1998 and a Game Boy Advance version published by Namco in Japan in August 2003 and later published by Nintendo in North America and Europe in March 2006, which marked the first time the game was officially available in English. A PlayStation Portable remake known as Tales of Phantasia Full Voice Edition followed in September 2006, featuring full voice acting during story scenes, which was later included with further enhancements as part of Tales of Phantasia: Narikiri Dungeon X in June 2010. The game''s producers have given it the characteristic genre name Legendary RPG beginning with the PlayStation version, with the Full Voice Edition given the moniker Legendary RPG Embellished with Voices. An unofficial fan translation of the original Super Famicom version was released on February 12, 2001 by Dejap.', 'https://media.retroachievements.org/Images/075413.png', 'https://media.retroachievements.org/Images/046307.png', 'https://media.retroachievements.org/Images/036073.png', 'https://media.retroachievements.org/Images/036074.png', 4.2),
  (106, 11298, 'Twisted Metal 2', 'PlayStation', 12, 2188, 2188, 2188, 43, 0, 'Vehicular Combat', 'SingleTrac', 'Sony Computer Entertainment', '1996-11-08', 'Twisted Metal 2 is a vehicular combat video game developed by SingleTrac and published by Sony Computer Entertainment. The second game in the Twisted Metal series, it was originally released in 1996 for PlayStation and Windows.', 'https://media.retroachievements.org/Images/059515.png', 'https://media.retroachievements.org/Images/015656.png', 'https://media.retroachievements.org/Images/015654.png', 'https://media.retroachievements.org/Images/015655.png', 4.2),
  (107, 8953, 'Vib-Ribbon', 'PlayStation', 12, 2177, 2177, 2177, 18, 0, 'Rhythm', 'NanaOn-Sha', 'Sony Computer Entertainment', '1999-12-09', 'Vib-Ripple is a 2004 video game developed by NanaOn-Sha and published by Sony Computer Entertainment for the PlayStation 2. It was designed by Masaya Matsuura, who also led the development the 1999 PlayStation game Vib-Ribbon, to which Vib-Ripple is a sequel. It was released exclusively in Japan.', 'https://media.retroachievements.org/Images/040514.png', 'https://media.retroachievements.org/Images/040109.png', 'https://media.retroachievements.org/Images/040517.png', 'https://media.retroachievements.org/Images/040516.png', 4.2),
  (108, 14457, 'Monsters, Inc. Scream Team', 'PlayStation', 12, 2123, 2123, 2123, 31, 0, '3D Platforming, Collect-a-thon', 'Artificial Mind and Movement', 'Sony Computer Entertainment, Tomy', '2001-11-06', 'This is a list of games released on the Game Boy Advance handheld video game system. The number of licensed games in this list is 1538, organized alphabetically by the games'' localized English titles, or, when Japan-exclusive, their rōmaji transliterations. This list does not include Game Boy Advance Video releases.', 'https://media.retroachievements.org/Images/063933.png', 'https://media.retroachievements.org/Images/044011.png', 'https://media.retroachievements.org/Images/083288.png', 'https://media.retroachievements.org/Images/083289.png', 4.2),
  (109, 11306, 'Tomba! 2: The Evil Swine Return', 'PlayStation', 12, 2117, 2117, 2117, 45, 0, '2.5D Platforming, Metroidvania', 'Whoopee Camp', 'Sony Computer Entertainment', '1999-10-28', 'The Nintendo Switch 2 is a video game console developed by Nintendo that serves as the successor to the Nintendo Switch. Like the original Switch, games are released both in physical and digital formats. Physical games are sold on cartridges that slot into the Switch 2 console unit. Digital games are purchased through the Nintendo eShop and stored either in the Switch 2''s internal 256 GB of storage or on a microSD Express card. In addition to being backward compatible with most of the Switch games, the Switch 2 also supports Game-Key Cards, which require Internet connection for download before they can be played, as well as Nintendo Switch 2 Edition games, enhanced ports of Switch games that make use of the Switch 2''s features.', 'https://media.retroachievements.org/Images/124477.png', 'https://media.retroachievements.org/Images/097460.png', 'https://media.retroachievements.org/Images/050910.png', 'https://media.retroachievements.org/Images/050909.png', 4.2),
  (110, 3595, 'Time Crisis', 'PlayStation', 12, 2093, 2093, 2093, 26, 0, 'Rail Shooter', 'Namco', 'Namco', '1997-06-27', 'Time Crisis is a first-person on-rails light gun shooter series of arcade video games by Namco, introduced in 1995. It is focused on the exploits of a fictional international intelligence agency who assigns its best agents to deal with a major threat by a hostile organisation, which has ranged from criminals, terrorists and hostile military outfits, and mostly take place within fictional locations across the world. The arcade series differed from other light gun shooters of its time by incorporating unique mechanics, including the ability to duck into cover to dodge attacks and reload the player''s weapon, and forcing players to complete battles in each level within an allotted amount of time.', 'https://media.retroachievements.org/Images/032393.png', 'https://media.retroachievements.org/Images/032017.png', 'https://media.retroachievements.org/Images/032018.png', 'https://media.retroachievements.org/Images/032020.png', 4.2),
  (111, 16192, 'Scooby-Doo and the Cyber Chase', 'PlayStation', 12, 2073, 2073, 2073, 35, 0, 'Action-Adventure', 'ART', 'THQ', '2001-10-02', 'Scooby-Doo and the Cyber Chase is a 2001 American direct-to-video animated science fiction comedy film, and the fourth in a series of direct-to-video animated films based on the Scooby-Doo franchise. The film was produced by Hanna-Barbera Cartoons in collaboration with Warner Bros. Animation, and released on October 9, 2001.', 'https://media.retroachievements.org/Images/082475.png', 'https://media.retroachievements.org/Images/065175.png', 'https://media.retroachievements.org/Images/032865.png', 'https://media.retroachievements.org/Images/032864.png', 4.2),
  (112, 11257, 'Street Fighter Alpha 3', 'PlayStation', 12, 2063, 2063, 2063, 104, 0, '2D Fighting', 'Capcom', 'Capcom', '1998-12-23', 'Street Fighter Alpha 3, released as Street Fighter Zero 3 in Japan, Asia, South America, and Oceania, is a 1998 fighting game developed and published by Capcom for arcades. It is the third and final installment in the Street Fighter Alpha series, and runs on the same CP System II hardware as previous Alpha games. Alpha 3 further expanded the playable fighter roster from Street Fighter Alpha 2 and added new features such as selectable fighting styles called isms.', 'https://media.retroachievements.org/Images/045596.png', 'https://media.retroachievements.org/Images/045917.png', 'https://media.retroachievements.org/Images/045915.png', 'https://media.retroachievements.org/Images/045916.png', 4.2),
  (113, 11367, 'Street Fighter EX Plus Alpha', 'PlayStation', 12, 2026, 2026, 2026, 98, 0, '3D Fighting', 'Arika', 'Capcom', '1997-07-17', 'Street Fighter EX is a 1996 fighting game originally released as a coin-operated arcade game for the Sony ZN hardware. It is a spin-off of the Street Fighter series co-produced by Capcom with Arika and was the first game in the series to feature 3D polygon graphics, although it retains the 2D plane gameplay. An updated arcade version was released subtitled Plus, as well as a PlayStation-exclusive home console version titled Street Fighter EX Plus α, both released in 1997. The game received a sequel, Street Fighter EX2, in 1998.', 'https://media.retroachievements.org/Images/123997.png', 'https://media.retroachievements.org/Images/092797.png', 'https://media.retroachievements.org/Images/084047.png', 'https://media.retroachievements.org/Images/084048.png', 4.2),
  (114, 14379, 'Super Puzzle Fighter II Turbo', 'PlayStation', 12, 2020, 2020, 2020, 48, 0, 'Falling Block Puzzle', 'Capcom', 'Capcom', '1996-12-06', 'Super Puzzle Fighter II Turbo, released in Japan as Super Puzzle Fighter II X, is a 1996 tile-matching puzzle video game developed and published by Capcom for arcades. The game''s title is a play on Super Street Fighter II Turbo, as there were no other Puzzle Fighter games at the time, and the game includes music and interface elements spoofing the Street Fighter Alpha and Darkstalkers games. It was a response to Compile and Sega''s Puyo Puyo 2 that had been sweeping the Japanese arcade scene.', 'https://media.retroachievements.org/Images/121937.png', 'https://media.retroachievements.org/Images/033236.png', 'https://media.retroachievements.org/Images/033233.png', 'https://media.retroachievements.org/Images/033235.png', 4.2),
  (115, 2163, 'Pocket Fighter', 'PlayStation', 12, 1995, 1995, 1995, 55, 0, '2D Fighting', 'Capcom', 'Capcom', '1998-06-11', 'The King of Fighters (KOF) is a series of fighting games by SNK. It is a crossover featuring characters from various video game series created by the company, as well as original characters created specifically for the series. The series began with the release of The King of Fighters ''94 in 1994, which was initially developed for SNK''s Neo Geo MVS arcade hardware and received yearly installments up until its tenth entry, The King of Fighters 2003 — thereafter, SNK moved away from annual The King of Fighters releases and games adopted a Roman numbered format, while simultaneously retiring the use of Neo Geo. The first major installment after this change was The King of Fighters XI (2005) on the Atomiswave arcade board. The series'' most recent arcade hardware is the Taito Type X2, first used with the release of The King of Fighters XII (2009) and continues with the latest entry in the series, The King of Fighters XV (2022).', 'https://media.retroachievements.org/Images/074452.png', 'https://media.retroachievements.org/Images/051797.png', 'https://media.retroachievements.org/Images/032486.png', 'https://media.retroachievements.org/Images/032487.png', 4.2),
  (116, 11389, 'Gex: Enter the Gecko', 'PlayStation', 12, 1984, 1984, 1984, 62, 0, '3D Platforming, Collect-a-thon', 'Crystal Dynamics', 'Midway', '1998-02-24', 'Gex is a platform game series, developed by Crystal Dynamics, that details the adventures of an anthropomorphic gecko named Gex. He has served as the mascot of Crystal Dynamics, appearing on their company logo for several years up until the year 2000. In the North American version, Gex is voiced by the comedian Dana Gould; the United Kingdom version features Gould as well as Leslie Phillips and Danny John-Jules as the voice of Gex. Gex was voiced by Mitsuo Senda in the Japanese release of the second game.', 'https://media.retroachievements.org/Images/109675.png', 'https://media.retroachievements.org/Images/026717.png', 'https://media.retroachievements.org/Images/120878.png', 'https://media.retroachievements.org/Images/120879.png', 4.2),
  (117, 11338, 'MediEvil II', 'PlayStation', 12, 1912, 1912, 1912, 56, 0, 'Action-Adventure', NULL, 'Sony Computer Entertainment', '2000-04-21', 'MediEvil 2 is a 2000 action-adventure game developed and published by Sony Computer Entertainment for the PlayStation. It is the second instalment of the MediEvil series and a sequel to MediEvil. Taking place 500 years after the events of the first game, it follows series'' protagonist Sir Daniel Fortesque''s revival in Victorian-era London as he attempts to stop sorcerer Lord Palethorn and Jack the Ripper''s plans to terrorise the city by raising the dead.', 'https://media.retroachievements.org/Images/114757.png', 'https://media.retroachievements.org/Images/048870.png', 'https://media.retroachievements.org/Images/026568.png', 'https://media.retroachievements.org/Images/026567.png', 4.2),
  (118, 11288, 'Legend of Mana', 'PlayStation', 12, 1910, 1910, 1910, 253, 0, 'Action RPG', 'Square', 'Squaresoft', '1999-07-15', 'Legend of Mana is a 1999 action role-playing game developed and published by Square for the PlayStation. It is a spin-off of the Mana series. Set in a high fantasy universe, the game follows an unnamed hero as they restore the land of Fa''Diel by creating the world around them and completing a number of interrelated quests in order to restore the Tree of Mana.', 'https://media.retroachievements.org/Images/074533.png', 'https://media.retroachievements.org/Images/015283.png', 'https://media.retroachievements.org/Images/015285.png', 'https://media.retroachievements.org/Images/015286.png', 4.2),
  (119, 14383, 'Rapid Reload', 'PlayStation', 12, 1902, 1902, 1902, 55, 0, 'Run & Gun', 'Media.Vision', 'Sony Computer Entertainment', '1995-04-28', 'Rapid Reload, known in Japan as Gunners Heaven (ガンナーズヘヴン), is a 1995 run and gun video game developed by Media.Vision and published by Sony Computer Entertainment for the PlayStation. It was released in both Japan and Europe in 1995. The game was re-released on the PlayStation Network in Japan in 2007 and in Asia in 2010.', 'https://media.retroachievements.org/Images/036663.png', 'https://media.retroachievements.org/Images/036664.png', 'https://media.retroachievements.org/Images/036661.png', 'https://media.retroachievements.org/Images/036662.png', 4.2),
  (120, 11295, 'Oddworld: Abe''s Oddysee', 'PlayStation', 12, 1898, 1898, 1898, 83, 0, 'Cinematic Platforming', 'Oddworld Inhabitants', 'GT Interactive Software, Atari', '1997-09-18', 'Oddworld: Abe''s Oddysee is a platform video game developed by Oddworld Inhabitants and published by GT Interactive. It was released in 1997 for the PlayStation game console, and computers running MS-DOS and Windows. A Game Boy version was released as Oddworld Adventures in 1998.', 'https://media.retroachievements.org/Images/082751.png', 'https://media.retroachievements.org/Images/096245.png', 'https://media.retroachievements.org/Images/031525.png', 'https://media.retroachievements.org/Images/031526.png', 4.2),
  (121, 4534, 'Road Rash', 'PlayStation', 12, 1895, 1895, 1895, 46, 0, 'Arcade Racing', 'Electronic Arts', 'Electronic Arts', '1996-02-01', 'Road Rash is a motorcycle racing video game series by Electronic Arts in which the player participates in violent, illegal street races. The series started on the Sega Genesis/Mega Drive and was released on various other systems over the years. The game''s title is based on the slang term for the severe abrasive injuries that can occur in a motorcycle fall where skin comes into contact with the ground at high speed.', 'https://media.retroachievements.org/Images/041748.png', 'https://media.retroachievements.org/Images/035647.png', 'https://media.retroachievements.org/Images/035646.png', 'https://media.retroachievements.org/Images/035648.png', 4.2),
  (122, 10675, 'Syphon Filter', 'PlayStation', 12, 1870, 1870, 1870, 50, 0, 'Stealth, Third-Person Shooter', 'Big Bend Studio', 'Sony Computer Entertainment', '1999-02-16', 'The PlayStation is a home video game console developed and marketed by Sony Computer Entertainment. It was released in Japan on 3 December 1994, followed by North America on 9 September 1995, Europe on 29 September 1995, and other regions following thereafter. As a fifth-generation console, the PlayStation primarily competed with the Nintendo 64 and the Sega Saturn.', 'https://media.retroachievements.org/Images/064832.png', 'https://media.retroachievements.org/Images/057523.png', 'https://media.retroachievements.org/Images/115459.png', 'https://media.retroachievements.org/Images/115460.png', 4.2),
  (123, 11423, 'Ace Combat', 'PlayStation', 12, 1866, 1866, 1866, 80, 0, 'Combat Flight Simulation', 'Namco', 'Namco', '1995-06-30', 'Ace Combat 3: Electrosphere is a combat flight simulation video game developed and published by Namco for the PlayStation. The third game in the Ace Combat franchise, it was released in Japan on May 27, 1999, and internationally the following year. Players fly fighter aircraft and must complete a variety of mission objectives, such as destroying squadrons of enemy planes or protecting a base from an invading unit.', 'https://media.retroachievements.org/Images/037408.png', 'https://media.retroachievements.org/Images/037407.png', 'https://media.retroachievements.org/Images/037405.png', 'https://media.retroachievements.org/Images/037406.png', 4.2),
  (124, 14048, 'Jumping Flash!', 'PlayStation', 12, 1856, 1856, 1856, 45, 0, '3D Platforming, First-Person Shooter', 'Exact', 'Sony Computer Entertainment', '1995-04-28', 'Jumping Flash! 2: Big Trouble in Little Muu, known in Japan as Jumping Flash! 2: The Tale of the Greatly Troubled Baron Aloha, is a 1996 platform video game developed by Exact and MuuMuu and published by Sony Computer Entertainment for the PlayStation. It is the direct sequel to Jumping Flash!, which was released the previous year. It was later re-released for the PlayStation 3 and PlayStation Portable via the PlayStation Network in 2009.', 'https://media.retroachievements.org/Images/025411.png', 'https://media.retroachievements.org/Images/023736.png', 'https://media.retroachievements.org/Images/023734.png', 'https://media.retroachievements.org/Images/023735.png', 4.2),
  (125, 16124, 'Street Fighter EX2 Plus', 'PlayStation', 12, 1833, 1833, 1833, 87, 0, '3D Fighting', 'Arika, Capcom', 'Capcom, Virgin Interactive', '1999-12-24', 'Street Fighter EX2 is a 2D head-to-head fighting game with 3D graphics co-produced by Capcom and Arika and originally released in 1998 as a coin-operated arcade game for the Sony ZN-2 hardware. It is the sequel to the original Street Fighter EX, and the second spin-off game of the Street Fighter series. An updated version of the game titled Street Fighter EX2 Plus was released in 1999 in arcades as well and subsequently ported to the PlayStation the same year. Its sequel, Street Fighter EX3, was released in 2000.', 'https://media.retroachievements.org/Images/123999.png', 'https://media.retroachievements.org/Images/052495.png', 'https://media.retroachievements.org/Images/084049.png', 'https://media.retroachievements.org/Images/084050.png', 4.2),
  (126, 14050, 'King''s Field', 'PlayStation', 12, 1805, 1805, 1805, 105, 0, 'Action RPG', 'FromSoftware', 'FromSoftware', '1994-12-16', 'King''s Field  is an action role-playing game series developed by FromSoftware. Titles have been released for the PlayStation, PlayStation 2, PlayStation Portable, Microsoft Windows, and various mobile phone platforms.', 'https://media.retroachievements.org/Images/105573.png', 'https://media.retroachievements.org/Images/046494.png', 'https://media.retroachievements.org/Images/032954.png', 'https://media.retroachievements.org/Images/032955.png', 4.1),
  (127, 11322, 'Metal Gear Solid: VR Missions', 'PlayStation', 12, 1801, 1801, 1801, 229, 0, 'Stealth', 'Konami', 'Konami', '1999-10-12', 'Metal Gear Solid is a 1998 action-adventure stealth game developed and published by Konami for the PlayStation. It was directed, produced, and written by Hideo Kojima, and follows the MSX2 games Metal Gear and Metal Gear 2: Solid Snake.', 'https://media.retroachievements.org/Images/113103.png', 'https://media.retroachievements.org/Images/046172.png', 'https://media.retroachievements.org/Images/026599.png', 'https://media.retroachievements.org/Images/026598.png', 4.1),
  (128, 16524, 'Strider 2', 'PlayStation', 12, 1772, 1772, 1772, 53, 0, 'Hack & Slash, 2D Platforming', 'Capcom', 'Capcom', '2000-02-24', 'This is a list of games for the Sony PlayStation video game system, organized alphabetically by name. There are often different names for the same game in different regions. The final licensed PlayStation game released in Japan was Black/Matrix 00 on May 13, 2004; counting re-releases, the final licensed game released in Japan was Strider Hiryū on October 24, 2006. The final licensed game released in North America was FIFA Football 2005 on October 12, 2004, and the final licensed game released in Europe was either Schnappi das kleine Krokodil – 3 Fun-Games on July 18, 2005, or Moorhuhn X on July 20, 2005. Additionally, homebrew games were created using the Sony PlayStation Net Yaroze. Games were being reprinted as late as 2008 with Metal Gear Solid in Metal Gear Solid: The Essential Collection.', 'https://media.retroachievements.org/Images/061308.png', 'https://media.retroachievements.org/Images/056289.png', 'https://media.retroachievements.org/Images/036239.png', 'https://media.retroachievements.org/Images/036238.png', 4.1),
  (129, 11336, 'Alundra', 'PlayStation', 12, 1771, 1771, 1771, 76, 0, 'Action-Adventure', 'Matrix Software', 'Working Designs', '1997-04-11', 'Alundra , released in Europe as The Adventures of Alundra, is an open-world action-adventure video game developed by Matrix Software and published by Sony Computer Entertainment for the PlayStation. It was originally released in 1997 in Japan, January 1998 in North America by Working Designs and June 1998 in PAL territories by Sony-owned Psygnosis. A standalone sequel, Alundra 2, was released in 1999.', 'https://media.retroachievements.org/Images/049400.png', 'https://media.retroachievements.org/Images/046255.png', 'https://media.retroachievements.org/Images/044019.png', 'https://media.retroachievements.org/Images/044020.png', 4.1),
  (130, 11281, 'Grandia', 'PlayStation', 12, 1752, 1752, 1752, 160, 0, 'Turn-Based RPG', 'Game Arts', 'Sony Computer Entertainment', '1999-06-24', 'Grandia  is a series of role-playing video games developed by Game Arts and published over the years by Entertainment Software Publishing, Sony Computer Entertainment, Ubisoft, Hudson Soft, Enix, Square Enix and GungHo Online Entertainment. Games in the Grandia series have been released for the Sega Saturn, PlayStation, Dreamcast, Game Boy Color, PlayStation 2, PlayStation 3, Nintendo Switch and Microsoft Windows.', 'https://media.retroachievements.org/Images/107572.png', 'https://media.retroachievements.org/Images/046613.png', 'https://media.retroachievements.org/Images/019060.png', 'https://media.retroachievements.org/Images/019061.png', 4.1),
  (131, 11416, 'A Bug''s Life', 'PlayStation', 12, 1749, 1749, 1749, 95, 0, '3D Platforming', 'Traveller''s Tales', 'Sony Computer Entertainment', '1998-11-18', 'A Bug''s Life is a 1998 American animated comedy film produced by Pixar Animation Studios for Walt Disney Pictures. It was directed by John Lasseter, written by Andrew Stanton, Donald McEnery, and Bob Shaw, from a story conceived by Lasseter, Stanton, and Joe Ranft, and stars the voices of Dave Foley, Kevin Spacey, Julia Louis-Dreyfus, and Hayden Panettiere. In the film, a misfit anthropomorphic ant named Flik looks for tough warriors to save his ant colony from a protection racket run by a gang of grasshoppers. However, the warriors he brings back are a troupe of Circus Bugs. The film''s plot was initially inspired by Aesop''s fable The Ant and the Grasshopper.', 'https://media.retroachievements.org/Images/032672.png', 'https://media.retroachievements.org/Images/049178.png', 'https://media.retroachievements.org/Images/031117.png', 'https://media.retroachievements.org/Images/031118.png', 4.1),
  (132, 14630, 'SpongeBob SquarePants: SuperSponge', 'PlayStation', 12, 1714, 1714, 1714, 43, 0, '2D Platforming', 'Climax Development', 'THQ', '2001-09-20', 'SpongeBob SquarePants: SuperSponge is a 2001 platform game based on the Nickelodeon animated television series SpongeBob SquarePants. Developed by Climax Development and published by THQ, it was released for the PlayStation on September 20, 2001, and for the Game Boy Advance on November 8, 2001.', 'https://media.retroachievements.org/Images/108661.png', 'https://media.retroachievements.org/Images/052441.png', 'https://media.retroachievements.org/Images/035179.png', 'https://media.retroachievements.org/Images/035180.png', 4.1),
  (133, 13904, 'I.Q.: Intelligent Qube', 'PlayStation', 12, 1691, 1691, 1691, 29, 0, 'Falling Block Puzzle', 'G-Artists', 'Sony Computer Entertainment', '1997-01-31', 'Intelligent Qube, also known as IQ Final in Japan and Kurushi in Europe, is a 1997 puzzle video game developed by G-Artists and published by Sony Computer Entertainment for the PlayStation. In the game, the player controls a character who must run around a platform made of cubes, clearing certain cubes as they approach. Cubes are cleared by marking a spot on the stage, waiting for the cube to roll on top of it, and then deactivating the marked spot.', 'https://media.retroachievements.org/Images/022766.png', 'https://media.retroachievements.org/Images/092901.png', 'https://media.retroachievements.org/Images/029665.png', 'https://media.retroachievements.org/Images/029663.png', 4.1),
  (134, 6808, 'Toy Story Racer', 'PlayStation', 12, 1657, 1657, 1657, 126, 0, 'Kart Racing', 'Traveller''s Tales', 'Activision, Disney Interactive Studios', '2001-03-02', 'This is a list of video games featuring various Disney properties.', 'https://media.retroachievements.org/Images/049219.png', 'https://media.retroachievements.org/Images/045297.png', 'https://media.retroachievements.org/Images/039373.png', 'https://media.retroachievements.org/Images/039177.png', 4.1),
  (135, 11307, 'Digimon: Digital Card Battle', 'PlayStation', 12, 1649, 1649, 1649, 115, 0, 'Collectible Card Game, Strategy', 'BEC', 'Bandai', '2000-12-21', 'This is a list of video games with mechanics based on collectible card games. It includes games which directly simulate collectible card games, arcade games integrated with physical collectible card games, and video games in other genres which utilize elements of deck-building or card battling as a significant portion of their game mechanics. It does not include games which only feature card collecting or card battling as a minigame, nor does it include games which simulate traditional card games such as solitaire or poker.', 'https://media.retroachievements.org/Images/102777.png', 'https://media.retroachievements.org/Images/056312.png', 'https://media.retroachievements.org/Images/019443.png', 'https://media.retroachievements.org/Images/019444.png', 4.1),
  (136, 11334, 'Rayman 2: The Great Escape', 'PlayStation', 12, 1593, 1593, 1593, 69, 0, '3D Platforming, Collect-a-thon', 'Ubisoft', 'Ubisoft', '2000-01-01', 'Rayman 2: The Great Escape is a 1999 platform game developed by Ubi Pictures and published by Ubi Soft for the Nintendo 64, Windows, Dreamcast and PlayStation. The game centers on the titular character Rayman, who is tasked with saving the fantastical land of the Fairy Glade from an army of robotic pirates led by Admiral Razorbeard.', 'https://media.retroachievements.org/Images/082262.png', 'https://media.retroachievements.org/Images/091522.png', 'https://media.retroachievements.org/Images/091521.png', 'https://media.retroachievements.org/Images/091520.png', 4.1),
  (137, 11374, 'Pac-Man World', 'PlayStation', 12, 1585, 1585, 1585, 50, 0, '3D Platforming, Collect-a-thon', 'Namco', 'Namco', '1999-10-15', 'Pac-Man World is a 1999 platform video game developed and published by Namco Hometek for the PlayStation. Controlling Pac-Man, the player must complete each of the game''s six worlds by collecting keys to free his captive family members, and reaching the end of each stage. The plot follows Pac-Man on a journey to Ghost Island, where his family is being held hostage by someone claiming to be the real Pac-Man.', 'https://media.retroachievements.org/Images/039422.png', 'https://media.retroachievements.org/Images/030586.png', 'https://media.retroachievements.org/Images/031789.png', 'https://media.retroachievements.org/Images/031790.png', 4.1),
  (138, 14738, 'Mega Man X3', 'PlayStation', 12, 1576, 1576, 1576, 74, 0, '2D Platforming', 'Capcom', 'Capcom', '1996-04-26', 'Mega Man X is a series of action-platform games released by Capcom. It is a sub-series of the Mega Man franchise previously developed by the same group, with Keiji Inafune acting as one of the main staff members. The first game was released on 17 December 1993 in Japan on the Super Famicom and the following month on the Super NES in North America. Most of the sequels were ported to Microsoft Windows. The gameplay introduces new elements to the Mega Man franchise in the form of Mega Man''s successor X, including his new skills and power-ups in the form of armors while retaining the ability to decide which boss to fight first. The franchise is also known for its replay value, in which certain choices and optional content can influence both gameplay and storylines, allowing the player to experience alternate scenarios.', 'https://media.retroachievements.org/Images/056201.png', 'https://media.retroachievements.org/Images/046780.png', 'https://media.retroachievements.org/Images/041920.png', 'https://media.retroachievements.org/Images/041921.png', 4.1),
  (139, 3708, 'Star Wars: Dark Forces', 'PlayStation', 12, 1566, 1566, 1566, 76, 0, NULL, 'LucasArts | Lucasfilm', 'LucasArts | Lucasfilm', '1996-11-26', 'Star Wars: Dark Forces is a first-person shooter video game developed and published by LucasArts. It was released in 1995 for MS-DOS and Macintosh, and in 1996 for the PlayStation. The story is set in the Star Wars expanded universe and begins shortly before the original Star Wars film, before flashing forward to a year after the film''s events. The game''s protagonist and playable character is Kyle Katarn, a mercenary working on behalf of the Rebel Alliance who discovers the Galactic Empire''s secret Dark Trooper Project, which involves the development of a series of powerful new battle droids and power-armored stormtroopers.', 'https://media.retroachievements.org/Images/048315.png', 'https://media.retroachievements.org/Images/055378.png', 'https://media.retroachievements.org/Images/048314.png', 'https://media.retroachievements.org/Images/048313.png', 4.1),
  (140, 826, 'Rugrats: Search for Reptar', 'PlayStation', 12, 1557, 1557, 1557, 24, 0, 'Adventure', 'n-Space', 'THQ', '1998-10-31', 'Rugrats: Search for Reptar is a 1998 platform video game developed by n-Space and published by THQ. It was released in North America in October or November 1998 and in Europe in November 1998, exclusively for PlayStation. Based on the television show Rugrats, the game follows the show''s main character, Tommy Pickles, who has lost his Reptar puzzle. It features stages based on episodes from the television show and minigames. Its sequel was Rugrats: Studio Tour.', 'https://media.retroachievements.org/Images/116407.png', 'https://media.retroachievements.org/Images/095864.png', 'https://media.retroachievements.org/Images/113566.png', 'https://media.retroachievements.org/Images/113567.png', 4.1),
  (141, 11561, 'Road Rash: Jailbreak', 'PlayStation', 12, 1523, 1523, 1523, 102, 0, 'Arcade Racing', 'EA Redwood Shores', 'Electronic Arts', '2000-02-04', 'Road Rash: Jailbreak is a racing video game developed by EA Redwood Shores for the PlayStation and Magic Pockets for the Game Boy Advance, and published by Electronic Arts for PlayStation in 2000 and for Game Boy Advance in 2003. It is the sixth and final game in the Road Rash series.', 'https://media.retroachievements.org/Images/108522.png', 'https://media.retroachievements.org/Images/055748.png', 'https://media.retroachievements.org/Images/031631.png', 'https://media.retroachievements.org/Images/031632.png', 4.1),
  (142, 14634, 'Colin McRae Rally 2.0', 'PlayStation', 12, 1519, 1519, 1519, 144, 0, 'Racing Simulation', 'Codemasters', 'Codemasters', '2000-06-09', 'Colin McRae Rally 2.0 is a racing video game developed and published by Codemasters for PlayStation, Microsoft Windows and Game Boy Advance.', 'https://media.retroachievements.org/Images/036793.png', 'https://media.retroachievements.org/Images/065055.png', 'https://media.retroachievements.org/Images/036686.png', 'https://media.retroachievements.org/Images/036688.png', 4.1),
  (143, 16686, 'Lilo and Stitch: Trouble in Paradise', 'PlayStation', 12, 1516, 1516, 1516, 18, 0, '3D Platforming', 'Blitz Games', 'Sony Computer Entertainment', '2002-06-18', 'Below is a list of video games based on Walt Disney Animation Studios shorts and features.', 'https://media.retroachievements.org/Images/080436.png', 'https://media.retroachievements.org/Images/096225.png', 'https://media.retroachievements.org/Images/041663.png', 'https://media.retroachievements.org/Images/041664.png', 4.1),
  (144, 11351, 'Azure Dreams', 'PlayStation', 12, 1471, 1471, 1471, 115, 0, 'Roguelike', 'Konami', 'Konami', '1997-11-13', 'Azure Dreams is a roguelike role-playing video game developed by Konami Computer Entertainment Tokyo and published by Konami for the PlayStation. A Game Boy Color game with the same name was developed by Konami Computer Entertainment Nagoya and released two years later. A spiritual sequel, Tao''s Adventure: Curse of the Demon Seal, was released on the Nintendo DS in 2005.', 'https://media.retroachievements.org/Images/042114.png', 'https://media.retroachievements.org/Images/041945.png', 'https://media.retroachievements.org/Images/047286.png', 'https://media.retroachievements.org/Images/047287.png', 4.1),
  (145, 4631, 'Shin Megami Tensei', 'PlayStation', 12, 1470, 1470, 1470, 115, 0, 'Dungeon Crawl, Turn-Based RPG', 'Atlus', 'Atlus', '2001-05-31', 'Megami Tensei, marketed internationally as Shin Megami Tensei, is a Japanese media franchise created by Aya Nishitani, Kouji Cozy Okada, Ginichiro Suzuki, and Kazunari Suzuki. Primarily developed and published by Atlus, the franchise consists of multiple subseries and covers multiple role-playing video game genres including tactical role-playing, action role-playing, and massively multiplayer online role-playing. The first two titles in the series were published by Namco, but have been almost always published by Atlus in Japan and North America since the release of Shin Megami Tensei. For Europe, Atlus publishes the games through third-party companies.', 'https://media.retroachievements.org/Images/068628.png', 'https://media.retroachievements.org/Images/059440.png', 'https://media.retroachievements.org/Images/060420.png', 'https://media.retroachievements.org/Images/060421.png', 4.1),
  (146, 16544, 'Mortal Kombat Mythologies: Sub-Zero', 'PlayStation', 12, 1449, 1449, 1449, 56, 0, 'Action-Adventure, 2D Fighting', 'Midway', 'Midway', '1997-10-01', 'Mortal Kombat Mythologies: Sub-Zero is a 1997 action-adventure game developed and published by Midway for the PlayStation and Nintendo 64. A spin-off of the Mortal Kombat franchise, it is the first installment not to be a fighting game. Set before the first game in the series, it follows Bi-Han, the elder Sub-Zero, in his quest to find Shinnok''s amulet. It also serves as a prequel to Mortal Kombat 4, which was released the same year, introducing characters and story elements that would be used by the fourth main installment. Mythologies is the final game in the series to use digitized actors.', 'https://media.retroachievements.org/Images/036517.png', 'https://media.retroachievements.org/Images/066792.png', 'https://media.retroachievements.org/Images/036521.png', 'https://media.retroachievements.org/Images/038036.png', 4.1),
  (147, 6766, 'Croc 2', 'PlayStation', 12, 1447, 1447, 1447, 98, 0, '3D Platforming, Collect-a-thon', 'Argonaut Games', 'Fox Interactive', '1999-08-03', 'Croc 2 is a 1999 platform game developed by Argonaut Software and published by Fox Interactive. The sequel to Croc: Legend of the Gobbos, it revolves around the title character going on a quest to search for his missing parents, as well as saving the Inventor Gobbo from a revived Baron Dante.', 'https://media.retroachievements.org/Images/121888.png', 'https://media.retroachievements.org/Images/048984.png', 'https://media.retroachievements.org/Images/031084.png', 'https://media.retroachievements.org/Images/031085.png', 4.1),
  (148, 8081, 'Armored Core: Project Phantasma', 'PlayStation', 12, 1432, 1432, 1432, 40, 0, 'Third-Person Shooter', 'FromSoftware', 'ASCII Entertainment', '1997-12-04', 'Armored Core: Project Phantasma is a 1997 third-person shooter mecha video game developed and published by FromSoftware for the PlayStation. Project Phantasma is the second entry in the Armored Core series and a prequel to the original Armored Core. The game was not released in Europe.', 'https://media.retroachievements.org/Images/059787.png', 'https://media.retroachievements.org/Images/060663.png', 'https://media.retroachievements.org/Images/059771.png', 'https://media.retroachievements.org/Images/059773.png', 4.1),
  (149, 11386, 'Bloody Roar', 'PlayStation', 12, 1431, 1431, 1431, 44, 0, '3D Fighting', 'Hudson Soft', 'Eighting, Sony Computer Entertainment', '1997-11-06', 'Bloody Roar  is a series of 3D fighting games developed by Eighting and primarily published by Hudson Soft, centering on characters known as zoanthropes who possess the ability to transform into anthropomorphic beasts during combat to unleash enhanced attacks and abilities. The franchise began with the original Bloody Roar, released in Japanese arcades in 1997 and subsequently ported to the PlayStation. Hudson Soft''s merger into Konami in 2012 transferred ownership of the intellectual property to the latter.', 'https://media.retroachievements.org/Images/043185.png', 'https://media.retroachievements.org/Images/038203.png', 'https://media.retroachievements.org/Images/038201.png', 'https://media.retroachievements.org/Images/038202.png', 4.1),
  (150, 14414, 'The Adventure of Little Ralph', 'PlayStation', 12, 1421, 1421, 1421, 47, 0, '2D Platforming, Action', 'NEW Corporation, Studio Alex', 'Ertain Corporation, NEW Corporation', '1999-06-03', 'The Adventure of Little Ralph is a 1999 platform video game developed and published by New Corporation for the PlayStation. It was released only in Japan.', 'https://media.retroachievements.org/Images/031708.png', 'https://media.retroachievements.org/Images/031709.png', 'https://media.retroachievements.org/Images/067785.png', 'https://media.retroachievements.org/Images/067786.png', 4.1),
  (151, 11362, 'Spider-Man 2 - Enter: Electro', 'PlayStation', 12, 1419, 1419, 1419, 66, 0, '3D Platforming, Beat ''em Up', 'Vicarious Visions', 'Activision', '2001-10-18', 'Spider-Man is a 2000 action-adventure game based on the Marvel Comics character of the same name. It was developed by Neversoft and published by Activision for the PlayStation. The game was later ported by different developers to various systems, including the Game Boy Color and Nintendo 64 that same year, the Dreamcast and Microsoft Windows in 2001, and Mac OS in 2002.', 'https://media.retroachievements.org/Images/124158.png', 'https://media.retroachievements.org/Images/030591.png', 'https://media.retroachievements.org/Images/036155.png', 'https://media.retroachievements.org/Images/036156.png', 4.1),
  (152, 11341, 'Tomb Raider II', 'PlayStation', 12, 1419, 1419, 1419, 109, 0, 'Action-Adventure, Cinematic Platforming', 'Core Design', 'Eidos Interactive', '1997-11-21', 'Tomb Raider is a 2013 action-adventure game developed by Crystal Dynamics and published by Square Enix''s European branch. It is the tenth main entry and a reboot of the Tomb Raider series, acting as the first instalment in the Survivor trilogy that reconstructs the origins of Lara Croft. The game was released for PlayStation 3, Windows, and Xbox 360 on 5 March 2013. Gameplay focuses on survival, with exploration when traversing the island and visiting various optional tombs. It is the first game in the main series to have multiplayer and the first game in the series to be published by Square Enix after the latter''s acquisition of Eidos Interactive in 2009.', 'https://media.retroachievements.org/Images/040161.png', 'https://media.retroachievements.org/Images/069466.png', 'https://media.retroachievements.org/Images/040158.png', 'https://media.retroachievements.org/Images/040157.png', 4.1),
  (153, 11284, 'Soul Blade', 'PlayStation', 12, 1400, 1400, 1400, 59, 0, '3D Fighting', 'Namco', 'Namco', '1996-12-20', 'Soul Edge is a 1996 fighting game developed and published by Namco for arcades. It is the first installment in the Soulcalibur series. Introduced at the JAMMA trade show in November 1995, the full arcade game was released on February 20, 1996 and May 16, 1996 on System 11 hardware, the same board used by Tekken and Tekken 2. Later in December, an upgraded and expanded version of the game was ported to the PlayStation; this version was renamed Soul Blade outside Japan and released in 1997.', 'https://media.retroachievements.org/Images/025358.png', 'https://media.retroachievements.org/Images/025359.png', 'https://media.retroachievements.org/Images/025356.png', 'https://media.retroachievements.org/Images/025357.png', 4.1),
  (154, 11243, 'Final Fantasy Chronicles: Chrono Trigger', 'PlayStation', 12, 1376, 1376, 1376, 141, 0, NULL, 'TOSE', 'Electronic Arts, Squaresoft', '2001-07-02', 'Chrono Trigger is a 1995 role-playing video game developed and published by Square for the Super Nintendo Entertainment System. It is the first installment of the Chrono series. The game''s plot follows a group of adventurers who travel through time to prevent a global catastrophe.', 'https://media.retroachievements.org/Images/020229.png', 'https://media.retroachievements.org/Images/049566.png', 'https://media.retroachievements.org/Images/066055.png', 'https://media.retroachievements.org/Images/066056.png', 4.1),
  (155, 8900, 'Ghost in the Shell', 'PlayStation', 12, 1375, 1375, 1375, 15, 0, 'Third-Person Shooter', 'Exact, Production I.G', 'Sony Computer Entertainment, THQ', '1997-07-17', 'Ghost in the Shell is a Japanese cyberpunk military science fiction media franchise that began with the eponymous manga series, written and illustrated by Masamune Shirow. The manga, first serialized from 1989 to 1991, is set in mid-21st-century Hong Kong and follows the fictional counter-cyberterrorist organization Public Security Section 9, led by protagonist Major Motoko Kusanagi.', 'https://media.retroachievements.org/Images/060837.png', 'https://media.retroachievements.org/Images/053131.png', 'https://media.retroachievements.org/Images/059765.png', 'https://media.retroachievements.org/Images/059809.png', 4.1),
  (156, 16698, 'Bust A Groove', 'PlayStation', 12, 1366, 1366, 1366, 21, 0, 'Rhythm', 'Metro Graphics', 'Enix', '1998-01-29', 'The year 2000 saw the release of numerous video games as well as the launch of the PlayStation 2. Critically acclaimed games originally released in 2000 include sequels such as Madden NFL 2001, NBA Live 2001, NBA 2K1, WWF SmackDown! 2: Know Your Role, Baldur''s Gate II, Diablo II, Dragon Quest VII, Final Fantasy IX, Metal Gear: Ghost Babel, NFL 2K1, Resident Evil – Code: Veronica, Spyro: Year of the Dragon, The Legend of Zelda: Majora''s Mask, and Tony Hawk''s Pro Skater 2, along with new intellectual properties such as Deus Ex, Hitman, Jet Set Radio, Perfect Dark, Skies of Arcadia, The Sims, SSX, Vagrant Story, and Sin and Punishment. The year''s best-selling home video games worldwide were Pokémon games for the third year in a row, while the highest-grossing arcade game in Japan was Virtua Striker 2.', 'https://media.retroachievements.org/Images/122762.png', 'https://media.retroachievements.org/Images/037979.png', 'https://media.retroachievements.org/Images/037977.png', 'https://media.retroachievements.org/Images/037978.png', 4.1),
  (157, 7115, 'Bust A Groove 2', 'PlayStation', 12, 1363, 1363, 1363, 73, 0, 'Rhythm', 'Metro', 'Enix', '1999-04-15', 'This is a list of games for the Sony PlayStation video game system, organized alphabetically by name. There are often different names for the same game in different regions. The final licensed PlayStation game released in Japan was Black/Matrix 00 on May 13, 2004; counting re-releases, the final licensed game released in Japan was Strider Hiryū on October 24, 2006. The final licensed game released in North America was FIFA Football 2005 on October 12, 2004, and the final licensed game released in Europe was either Schnappi das kleine Krokodil – 3 Fun-Games on July 18, 2005, or Moorhuhn X on July 20, 2005. Additionally, homebrew games were created using the Sony PlayStation Net Yaroze. Games were being reprinted as late as 2008 with Metal Gear Solid in Metal Gear Solid: The Essential Collection.', 'https://media.retroachievements.org/Images/122706.png', 'https://media.retroachievements.org/Images/063396.png', 'https://media.retroachievements.org/Images/031701.png', 'https://media.retroachievements.org/Images/031700.png', 4.1),
  (158, 14345, 'Apocalypse', 'PlayStation', 12, 1359, 1359, 1359, 43, 0, 'Third-Person Shooter', 'Neversoft', 'Activision', '1998-11-17', 'Apocalypse is a literary genre originating in Judaism in the centuries following the Babylonian exile but persisting in Christianity and Islam. In apocalypse, a supernatural being reveals cosmic mysteries or the past to a human intermediary. The means of mediation include dreams, visions and heavenly journeys, and they typically feature symbolic imagery drawn from the Jewish Bible, cosmological and (pessimistic) historical surveys, the division of time into periods, esoteric numerology, and claims of ecstasy and inspiration. Almost all are written under pseudonyms, claiming as author a venerated hero from previous centuries, as with the Book of Daniel, composed during the 2nd century BCE but bearing the name of the legendary Daniel from the 6th century BCE.', 'https://media.retroachievements.org/Images/028065.png', 'https://media.retroachievements.org/Images/064893.png', 'https://media.retroachievements.org/Images/028063.png', 'https://media.retroachievements.org/Images/028064.png', 4.1),
  (159, 11373, 'Rival Schools: United by Fate', 'PlayStation', 12, 1351, 1351, 1351, 105, 0, '3D Fighting', 'Capcom', 'Capcom', '1998-07-30', 'Rival Schools: United by Fate, known in Japan as Private Justice Academy: Legion of Heroes, is a 1997 3D fighting game produced by Capcom originally released as an arcade game on Sony ZN-2 hardware. Rival Schools revolves around tag team battles between groups of students from various schools in a Japanese city, and uses a comical and humorous style. Sakura Kasugano from Capcom''s Street Fighter series also appears as a character in the game.', 'https://media.retroachievements.org/Images/086572.png', 'https://media.retroachievements.org/Images/053604.png', 'https://media.retroachievements.org/Images/026259.png', 'https://media.retroachievements.org/Images/026260.png', 4.1),
  (160, 11254, 'Lunar: Silver Star Story Complete', 'PlayStation', 12, 1342, 1342, 1342, 107, 0, 'Turn-Based RPG', 'Game Arts', 'Working Designs', '1998-05-28', 'Lunar: Silver Star Story Complete, originally released in Japan as simply Lunar: Silver Star Story, is a 1996 role-playing video game developed by Game Arts and Japan Art Media and published by Kadokawa Shoten. It is a remake of 1992''s Lunar: The Silver Star. While the overall plot remains true to the original, accommodations are made to the game''s story to allow for a larger, richer cast, as well as additional scenarios.', 'https://media.retroachievements.org/Images/017724.png', 'https://media.retroachievements.org/Images/056825.png', 'https://media.retroachievements.org/Images/019068.png', 'https://media.retroachievements.org/Images/019069.png', 4.1),
  (161, 16230, 'Shadow Tower', 'PlayStation', 12, 1342, 1342, 1342, 137, 0, 'Action RPG', 'FromSoftware', 'Agetec', '1998-06-25', 'Shadow Tower is a 1998 action role-playing video game developed by FromSoftware for the PlayStation. The game was originally released in Japan by FromSoftware on June 25, 1998 and in North America by Agetec on November 23, 1999. Shadow Tower shares many similarities with the King''s Field series of video games. A sequel, Shadow Tower Abyss, was released for the PlayStation 2 exclusively in Japan.', 'https://media.retroachievements.org/Images/033335.png', 'https://media.retroachievements.org/Images/033334.png', 'https://media.retroachievements.org/Images/033327.png', 'https://media.retroachievements.org/Images/033328.png', 4.1),
  (162, 11333, 'Vandal Hearts', 'PlayStation', 12, 1335, 1335, 1335, 98, 0, 'Tactical RPG', 'Konami', 'Konami', '1996-10-25', 'Vandal Hearts, known in Japan as Vandal Hearts: The Lost Ancient Civilization  is a turn-based tactical role-playing video game developed by Konami Computer Entertainment Tokyo for the PlayStation and later ported to the Sega Saturn by Konami Computer Entertainment Nagoya. The PlayStation version was distributed in Japan, North America, and Europe. The Saturn version was only released in Japan. There was also a Microsoft Windows version which was released only in Japan and South Korea, with Software renderer and Direct3D Support.', 'https://media.retroachievements.org/Images/089915.png', 'https://media.retroachievements.org/Images/066070.png', 'https://media.retroachievements.org/Images/017679.png', 'https://media.retroachievements.org/Images/017668.png', 4.1),
  (163, 11364, 'Tony Hawk''s Pro Skater 3', 'PlayStation', 12, 1328, 1328, 1328, 23, 0, 'Extreme Sports - Skateboarding', 'Neversoft, Shaba Games', 'Activision', '2001-10-30', 'Tony Hawk''s is a series of skateboarding video games published by Activision and endorsed by the American professional skateboarder of the same name. From 1999 to 2007, the series was primarily developed for home consoles by Neversoft with generally annual releases. In 2008, Activision transferred the franchise to Robomodo, which released several additions before Activision and Hawk''s license expired in 2015, leaving the future of the series uncertain. In 2020, the series returned under Activision with a remake of the original two games in the series, and a remake of the third and fourth games in 2025 developed by Vicarious Visions and Iron Galaxy respectively.', 'https://media.retroachievements.org/Images/108606.png', 'https://media.retroachievements.org/Images/028161.png', 'https://media.retroachievements.org/Images/031362.png', 'https://media.retroachievements.org/Images/031363.png', 4.1),
  (164, 11361, 'Heart of Darkness', 'PlayStation', 12, 1310, 1310, 1310, 21, 0, 'Cinematic Platforming', 'Amazing Studio', 'Ocean Software', '1998-07-03', 'Heart of Darkness is a cinematic platform video game developed by French developer Amazing Studio for the PlayStation and Microsoft Windows.', 'https://media.retroachievements.org/Images/125175.png', 'https://media.retroachievements.org/Images/087927.png', 'https://media.retroachievements.org/Images/019065.png', 'https://media.retroachievements.org/Images/019066.png', 4.1),
  (165, 11397, 'Twisted Metal 4', 'PlayStation', 12, 1307, 1307, 1307, 36, 0, 'Vehicular Combat', 'Sony Interactive Studios America | 989 Studios', 'Sony Computer Entertainment', '1999-11-16', 'Twisted Metal 4 is a vehicular combat video game developed and published by 989 Studios for the PlayStation. The game was released only in North America on November 16, 1999, and was re-released for the Sony Greatest Hits line-up in 2000. Like the previous installment, it was not released in PAL regions.', 'https://media.retroachievements.org/Images/059517.png', 'https://media.retroachievements.org/Images/057402.png', 'https://media.retroachievements.org/Images/028059.png', 'https://media.retroachievements.org/Images/029358.png', 4.1),
  (166, 11405, 'Ehrgeiz: God Bless the Ring', 'PlayStation', 12, 1300, 1300, 1300, 86, 0, NULL, 'DreamFactory', 'Squaresoft', '1998-12-17', 'Ehrgeiz , fully titled Ehrgeiz: God Bless the Ring, is a 1998 fighting game developed by DreamFactory and published by Namco for arcades. It was developed as a partnership between Square and DreamFactory. It was ported to the PlayStation, where Square released it internationally while Sony Computer Entertainment published it in Japan, a direct inversion of the companies'' usual publishing deal.', 'https://media.retroachievements.org/Images/123221.png', 'https://media.retroachievements.org/Images/047102.png', 'https://media.retroachievements.org/Images/036833.png', 'https://media.retroachievements.org/Images/036834.png', 4.1),
  (167, 14461, 'Tony Hawk''s Pro Skater 4', 'PlayStation', 12, 1286, 1286, 1286, 139, 0, 'Extreme Sports - Skateboarding', 'Vicarious Visions', 'Activision', '2002-10-23', 'Tony Hawk''s is a series of skateboarding video games published by Activision and endorsed by the American professional skateboarder of the same name. From 1999 to 2007, the series was primarily developed for home consoles by Neversoft with generally annual releases. In 2008, Activision transferred the franchise to Robomodo, which released several additions before Activision and Hawk''s license expired in 2015, leaving the future of the series uncertain. In 2020, the series returned under Activision with a remake of the original two games in the series, and a remake of the third and fourth games in 2025 developed by Vicarious Visions and Iron Galaxy respectively.', 'https://media.retroachievements.org/Images/107428.png', 'https://media.retroachievements.org/Images/049997.png', 'https://media.retroachievements.org/Images/038353.png', 'https://media.retroachievements.org/Images/038354.png', 4.1),
  (168, 11253, 'Star Ocean: The Second Story', 'PlayStation', 12, 1285, 1285, 1285, 92, 0, 'Action RPG', 'tri-Ace', 'Enix', '1998-07-30', 'Star Ocean is a franchise of science fantasy Action role-playing video games developed by the Japanese company tri-Ace and published by Square Enix.', 'https://media.retroachievements.org/Images/094986.png', 'https://media.retroachievements.org/Images/046254.png', 'https://media.retroachievements.org/Images/031249.png', 'https://media.retroachievements.org/Images/031250.png', 4.1),
  (169, 13899, 'Tom and Jerry in House Trap', 'PlayStation', 12, 1249, 1249, 1249, 39, 0, 'Arena Fighting', 'Warthog Games', 'NewKidCo, Ubisoft, Success', '2000-11-20', 'This is a list of games released on the Game Boy Advance handheld video game system. The number of licensed games in this list is 1538, organized alphabetically by the games'' localized English titles, or, when Japan-exclusive, their rōmaji transliterations. This list does not include Game Boy Advance Video releases.', 'https://media.retroachievements.org/Images/022763.png', 'https://media.retroachievements.org/Images/025403.png', 'https://media.retroachievements.org/Images/025401.png', 'https://media.retroachievements.org/Images/025402.png', 4.1),
  (170, 8422, 'RayStorm', 'PlayStation', 12, 1246, 1246, 1246, 43, 0, 'Shoot ''em Up', 'Taito', 'Taito, Working Designs', '1997-01-10', 'RayStorm is a 1996 vertically scrolling shooter arcade video game developed and published by Taito. It has been ported to several consoles, including the PlayStation, Sega Saturn, and Xbox 360. Players control a starship, the R-Gray, in its mission to destroy the Secilia Federation before it destroys Earth.', 'https://media.retroachievements.org/Images/031329.png', 'https://media.retroachievements.org/Images/031326.png', 'https://media.retroachievements.org/Images/031327.png', 'https://media.retroachievements.org/Images/031328.png', 4.1),
  (171, 11371, 'Revelations: Persona', 'PlayStation', 12, 1239, 1239, 1239, 85, 0, 'Turn-Based RPG', 'Atlus', 'Atlus', '1996-09-20', 'The PlayStation Classic is a dedicated video game console by Sony Interactive Entertainment that emulates games originally released on its 1994 PlayStation console. It was announced in September 2018 at the Tokyo Game Show, and released on December 3, 2018, the 24th anniversary of the release of the original. The console has been compared to competitor Nintendo''s prior releases of the NES Classic Edition and Super NES Classic Edition mini consoles. The console received generally negative reviews from critics, with criticism for its weak game library, inclusion of the original PlayStation controller instead of later, upgraded revisions, use of PAL versions for certain games, and high price tag, though the console''s design did attract praise.', 'https://media.retroachievements.org/Images/047338.png', 'https://media.retroachievements.org/Images/029156.png', 'https://media.retroachievements.org/Images/017633.png', 'https://media.retroachievements.org/Images/027132.png', 4.1),
  (172, 7896, 'Nightmare Creatures', 'PlayStation', 12, 1226, 1226, 1226, 48, 0, 'Action, Survival Horror', 'Kalisto Entertainment', 'Activision', '1997-10-31', 'Nightmare Creatures is a 1997 survival horror video game developed by Kalisto Entertainment for PlayStation, Windows, and Nintendo 64. A sequel, Nightmare Creatures II, was released three years later. A mobile phone version of Nightmare Creatures was developed and published by Gameloft in 2003. A third sequel, Nightmare Creatures III: Angel of Darkness, was cancelled in 2004.', 'https://media.retroachievements.org/Images/048101.png', 'https://media.retroachievements.org/Images/045300.png', 'https://media.retroachievements.org/Images/048099.png', 'https://media.retroachievements.org/Images/048100.png', 4.1),
  (173, 11384, 'Gex 3: Deep Cover Gecko', 'PlayStation', 12, 1225, 1225, 1225, 89, 0, '3D Platforming, Collect-a-thon', 'Crystal Dynamics', 'Eidos Interactive', '1999-03-23', 'Gex 3: Deep Cover Gecko is a 1999 platform game developed by Crystal Dynamics and published by Eidos Interactive for the PlayStation. It is part of the Gex video game series, and was released in 1999, followed by ports for the Nintendo 64. Its protagonist, Gex, is a wisecracking, pop culture enthusiast voiced by Danny John-Jules in the UK and European releases and comedian Dana Gould, reprising his role from former Gex games, for the American release. The gameplay is set in Gex''s secret hideout, Mission Control a overworld, which is overseen by Gex''s butler, Alfred the Turtle. Playboy model Marliece Andrada plays Gex''s kidnapped companion, Agent Xtra, the only live-action character, who is featured in brief full-motion video sequences on the PlayStation version. The plot follows Gex''s return to the Media Dimension to rescue Agent Xtra from Rez, Gex''s arch-nemesis from the previous games.', 'https://media.retroachievements.org/Images/109676.png', 'https://media.retroachievements.org/Images/053188.png', 'https://media.retroachievements.org/Images/112059.png', 'https://media.retroachievements.org/Images/026722.png', 4.1),
  (174, 15634, 'Rage Racer', 'PlayStation', 12, 1199, 1199, 1199, 49, 0, 'Arcade Racing', 'Namco', 'Namco', '1996-12-03', 'R4: Ridge Racer Type 4, released without the ''R4'' prefix in PAL territories, is a 1998 racing video game developed and published by Namco for the PlayStation. It is the fourth home title in the Ridge Racer series after Rage Racer (1996) and was initially released on December 3, 1998 in Japan, with global releases following in 1999.', 'https://media.retroachievements.org/Images/049670.png', 'https://media.retroachievements.org/Images/030374.png', 'https://media.retroachievements.org/Images/030376.png', 'https://media.retroachievements.org/Images/030377.png', 4),
  (175, 6800, 'Spyro the Dragon (Japan)', 'PlayStation', 12, 1197, 1197, 1197, 49, 0, '3D Platforming, Collect-a-thon', 'Insomniac Games', 'Sony Computer Entertainment, Universal Interactive', '1999-04-01', 'Spyro the Dragon is a 1998 platform game originally developed by Insomniac Games and published by Sony Computer Entertainment for the PlayStation. The first game in the Spyro series, it stars the title character, a young purple dragon named Spyro, and his dragonfly friend, Sparx, who must journey across the Dragon Kingdom to defeat Gnasty Gnorc, who has overtaken the five dragon Homeworlds by trapping the other dragons in crystal and turning their hoard of gems into an army of minions. Spyro the Dragon is an open-ended 3D platformer, featuring large, sprawling levels in which the player must locate collectable items, among which are gemstones, crystallized dragons, and stolen dragon eggs. Spyro''s abilities as a dragon include fire breath, a head-on charging attack, and a mid-air glide which he can use to scale large distances, all of which must be used strategically to find items and defeat enemies.', 'https://media.retroachievements.org/Images/089906.png', 'https://media.retroachievements.org/Images/069030.png', 'https://media.retroachievements.org/Images/070425.png', 'https://media.retroachievements.org/Images/070443.png', 4),
  (176, 11588, 'Driver 2: The Wheelman Is Back', 'PlayStation', 12, 1187, 1187, 1187, 90, 0, 'Action, Arcade Racing', 'Reflections Interactive', 'Infogrames', '2000-11-14', 'Driver 2 is a 2000 action driving video game and the second installment of the Driver series. It was developed by Reflections Interactive and published by Infogrames for PlayStation. A port to the Game Boy Advance, titled Driver 2 Advance, was released in 2002, developed by Sennari Interactive and released under Infogrames'' Atari range of products.', 'https://media.retroachievements.org/Images/046592.png', 'https://media.retroachievements.org/Images/046279.png', 'https://media.retroachievements.org/Images/076158.png', 'https://media.retroachievements.org/Images/076160.png', 4),
  (177, 476, 'Incredible Crisis', 'PlayStation', 12, 1187, 1187, 1187, 66, 0, 'Minigames', 'Polygon Magic', 'Titus Software', '1999-06-24', 'Incredible Crisis, known in Japan as Tondemo Crisis! , is a PlayStation video game developed by Polygon Magic. The game was published in Japan by Tokuma Shoten on June 24, 1999. Translated versions were released by Titus Interactive in North America and Europe throughout November 2000.', 'https://media.retroachievements.org/Images/101901.png', 'https://media.retroachievements.org/Images/049167.png', 'https://media.retroachievements.org/Images/037291.png', 'https://media.retroachievements.org/Images/037292.png', 4),
  (178, 5927, 'Bomberman Fantasy Race', 'PlayStation', 12, 1154, 1154, 1154, 52, 0, 'Kart Racing', 'Graphic Research', 'Atlus', '1998-01-29', 'Bomberman Fantasy Race is a racing video game developed by GraphicResearch Inc., released for PlayStation in Japan by publisher Hudson Soft in 1998, in North America by Atlus USA in 1999, and in Europe by Virgin Interactive in 2000. It is a spin-off of the Bomberman series.', 'https://media.retroachievements.org/Images/069067.png', 'https://media.retroachievements.org/Images/046922.png', 'https://media.retroachievements.org/Images/033173.png', 'https://media.retroachievements.org/Images/033174.png', 4),
  (179, 11355, 'Persona 2: Innocent Sin', 'PlayStation', 12, 1152, 1152, 1152, 85, 0, 'Turn-Based RPG', 'Atlus', 'Atlus', '1999-06-24', 'Persona 2: Innocent Sin is a 1999 role-playing video game developed and published by Atlus for the PlayStation. It is the second entry in the Persona series, itself a subseries of the Megami Tensei franchise, and acts as a sequel to the original Persona. The game was re-released in 2011 for the PlayStation Portable. The original version was not localized for western territories; however, the PSP version was released in North America and Europe under the title Shin Megami Tensei: Persona 2 – Innocent Sin.', 'https://media.retroachievements.org/Images/053893.png', 'https://media.retroachievements.org/Images/019082.png', 'https://media.retroachievements.org/Images/027133.png', 'https://media.retroachievements.org/Images/027699.png', 4),
  (180, 14865, 'Kula World', 'PlayStation', 12, 1134, 1134, 1134, 95, 0, '3D Platforming, Physics Puzzle', 'Game Design Sweden AB', 'Sony Computer Entertainment', '1998-07-15', 'This is a list of commercial video games with available source code. The source code of these commercially developed and distributed video games is available to the public or the games'' communities.', 'https://media.retroachievements.org/Images/124146.png', 'https://media.retroachievements.org/Images/060714.png', 'https://media.retroachievements.org/Images/060616.png', 'https://media.retroachievements.org/Images/060617.png', 4),
  (181, 17042, 'Sled Storm', 'PlayStation', 12, 1126, 1126, 1126, 63, 0, 'Racing', 'Electronic Arts', 'Electronic Arts', '1999-08-17', 'Sled Storm is a snowmobile racing video game published and developed by Electronic Arts. It gained critical acclaim due to its original concept of being one of the first snowmobile racing titles.', 'https://media.retroachievements.org/Images/065790.png', 'https://media.retroachievements.org/Images/065796.png', 'https://media.retroachievements.org/Images/065791.png', 'https://media.retroachievements.org/Images/065793.png', 4),
  (182, 13440, 'Galerians', 'PlayStation', 12, 1114, 1114, 1114, 36, 0, 'Survival Horror', 'Polygon Magic', 'ASCII Entertainment', '1999-08-26', 'Galerians  is a 1999 survival horror video game developed by Polygon Magic for the PlayStation. The game follows a boy named Rion who discovers he has psychic powers. He has amnesia, and in the process of learning his identity, he discovers that he is humanity''s last hope for survival against the Galerians, genetically enhanced humans. The game has a sequel, Galerians: Ash on PlayStation 2.', 'https://media.retroachievements.org/Images/122263.png', 'https://media.retroachievements.org/Images/025391.png', 'https://media.retroachievements.org/Images/093265.png', 'https://media.retroachievements.org/Images/093266.png', 4),
  (183, 5332, 'Ridge Racer Revolution', 'PlayStation', 12, 1111, 1111, 1111, 46, 0, 'Arcade Racing', 'Namco', 'Namco', '1995-12-03', 'Ridge Racer Revolution is a racing video game developed and published by Namco for the PlayStation. It is the sequel to the PlayStation version of Ridge Racer. Like the original Ridge Racer, the player races computer-controlled cars with the objective of winning a series of races, and supports Namco''s NeGcon controller. Ridge Racer Revolution adds two hidden cars, and two-player support via the PlayStation Link cable, and took roughly the same time to develop as the first. The intention was to increase the depth and add features.', 'https://media.retroachievements.org/Images/049669.png', 'https://media.retroachievements.org/Images/030967.png', 'https://media.retroachievements.org/Images/030968.png', 'https://media.retroachievements.org/Images/030965.png', 4),
  (184, 12760, 'Tail Concerto', 'PlayStation', 12, 1107, 1107, 1107, 36, 0, 'Action-Adventure, 3D Platforming', 'CyberConnect2 | CyberConnect', 'Atlus', '1998-04-16', 'Tail Concerto is an action-adventure platform video game developed by CyberConnect and published by Bandai for the PlayStation. It is the first game to be developed by CyberConnect, as well as the first installment in the Little Tail Bronx series, which takes place in a steampunk fantasy world of floating islands populated by anthropomorphic dogs and cats. The game revolves around a teenaged canine police officer named Waffle Ryebread and his encounters with the Black Cats Gang, a group of sky pirates who aim to steal magic crystals. Though it received a generally positive response from critics, the title was met with low sales in Japan, falling short of the publisher''s expectations.', 'https://media.retroachievements.org/Images/042241.png', 'https://media.retroachievements.org/Images/045520.png', 'https://media.retroachievements.org/Images/041605.png', 'https://media.retroachievements.org/Images/041607.png', 4),
  (185, 14385, 'Omega Boost', 'PlayStation', 12, 1098, 1098, 1098, 39, 0, 'Rail Shooter', 'Polyphony Digital', 'Sony Computer Entertainment', '1999-04-22', 'Omega Boost is a 1999 shoot ''em up video game developed by Polyphony Digital and published by Sony Computer Entertainment for the PlayStation. It is the first game to be developed by Polyphony Digital, formed after the success of Gran Turismo which was developed under Sony Computer Entertainment Japan, and their only game that is not in the Gran Turismo series as well as their sole non-racing video game.', 'https://media.retroachievements.org/Images/057329.png', 'https://media.retroachievements.org/Images/057328.png', 'https://media.retroachievements.org/Images/057331.png', 'https://media.retroachievements.org/Images/057330.png', 4),
  (186, 17528, 'Need for Speed II', 'PlayStation', 12, 1097, 1097, 1097, 40, 0, 'Arcade Racing', NULL, 'Electronic Arts', '1997-03-31', 'Need for Speed (NFS) is a racing game franchise published by Electronic Arts and currently developed by Criterion Games. Most entries in the series are generally arcade racing games centered around illegal street racing, and task players with completing races of various types while evading police pursuit. Some entries also do not follow the basic setup of most titles and are instead simulation racers, focus on legal circuit races, feature kart racing game elements, or feature illegal street racing but do not also feature police pursuits. Need for Speed is one of EA''s oldest franchises not published under their EA Sports brand.', 'https://media.retroachievements.org/Images/119713.png', 'https://media.retroachievements.org/Images/051561.png', 'https://media.retroachievements.org/Images/042896.png', 'https://media.retroachievements.org/Images/042897.png', 4),
  (187, 11392, 'Die Hard Trilogy', 'PlayStation', 12, 1089, 1089, 1089, 76, 0, 'Third-Person Shooter, Rail Shooter, Racing', 'Probe Entertainment', 'Fox Interactive', '1996-09-18', 'Die Hard Trilogy is an action video game developed by Probe Entertainment, published by Fox Interactive and distributed by 20th Century Fox Home Entertainment in North America for the PlayStation, Sega Saturn and Microsoft Windows. The game is based on the first three installments of the Die Hard series of action movies, with each film entry being represented through a different gameplay genre.', 'https://media.retroachievements.org/Images/080512.png', 'https://media.retroachievements.org/Images/019437.png', 'https://media.retroachievements.org/Images/019439.png', 'https://media.retroachievements.org/Images/019440.png', 4),
  (188, 14683, '007 Racing', 'PlayStation', 12, 1073, 1073, 1073, 49, 0, 'Racing, Vehicular Combat', 'Eutechnyx', 'Electronic Arts', '2000-11-17', '007 Racing is a 2000 racing video game based on the James Bond license. It was developed by Eutechnyx, published by Electronic Arts, and released for the PlayStation console system. This game marks the seventh appearance of Pierce Brosnan''s James Bond; the game included his likeness but not his voice, which is provided by Tim Bentinck. Including many revived characters from previous entries, the game is considered to be a spin-off of the original chronicles.', 'https://media.retroachievements.org/Images/108608.png', 'https://media.retroachievements.org/Images/050423.png', 'https://media.retroachievements.org/Images/027715.png', 'https://media.retroachievements.org/Images/027716.png', 4),
  (189, 14732, 'Need for Speed: Porsche Unleashed', 'PlayStation', 12, 1061, 1061, 1061, 74, 0, 'Racing', 'Eden Games', 'Electronic Arts', '2000-03-29', 'Need for Speed: Porsche Unleashed is a 2000 racing video game published by Electronic Arts for PlayStation and Microsoft Windows. It is the fifth installment in the Need for Speed series. Unlike other NFS titles, Porsche Unleashed centers on racing Porsche sports cars, with models ranging from years 1950 to 2000.', 'https://media.retroachievements.org/Images/116507.png', 'https://media.retroachievements.org/Images/064685.png', 'https://media.retroachievements.org/Images/087734.png', 'https://media.retroachievements.org/Images/087733.png', 4),
  (190, 14691, 'World''s Scariest Police Chases', 'PlayStation', 12, 1061, 1061, 1061, 60, 0, 'Vehicular Combat', 'Unique Development Studios', 'Activision, Fox Interactive', '2001-06-07', 'World''s Wildest Police Videos is an American reality television series that ran on Fox from 1998 to 2001. In 2012, Spike announced that it had commissioned 13 new episodes with the revival of the original name and John Bunnell returning as host, which premiered on May 7, 2012, and ended on August 13, 2012. The series deals with police videos from across the world. Video footage of car chases, subsequent arrests, robberies, riots and other crimes appear on the show.', 'https://media.retroachievements.org/Images/117619.png', 'https://media.retroachievements.org/Images/053802.png', 'https://media.retroachievements.org/Images/041265.png', 'https://media.retroachievements.org/Images/031806.png', 4),
  (191, 14051, 'Policenauts', 'PlayStation', 12, 1059, 1059, 1059, 51, 0, 'Adventure', 'Konami', 'Konami', '1996-01-19', 'Policenauts is a graphic adventure game developed and published by Konami. It was written and directed by Hideo Kojima, and originally released for the PC-9821 in 1994. A hard science fiction story, Policenauts is set in the mid 21st century and follows Jonathan Ingram, an astronaut recently recovered floating in space in cryosleep after an accident at a space colony sent him drifting into space for 24 years. Now a detective in Los Angeles, Ingram travels back to the colony to investigate the murder of his ex-wife and her husband''s disappearance. As he begins his investigation, he starts to uncover an illegal organ trafficking ring.', 'https://media.retroachievements.org/Images/048286.png', 'https://media.retroachievements.org/Images/023727.png', 'https://media.retroachievements.org/Images/023724.png', 'https://media.retroachievements.org/Images/023725.png', 4),
  (192, 11417, '007: Tomorrow Never Dies', 'PlayStation', 12, 1054, 1054, 1054, 41, 0, 'Third-Person Shooter', 'Black Ops Entertainment', 'Electronic Arts', '1999-11-16', 'Tomorrow Never Dies is a 1997 action spy film, the eighteenth in the James Bond series produced by Eon Productions and the second to star Pierce Brosnan as fictional MI6 agent James Bond. Directed by Roger Spottiswoode from a screenplay by Bruce Feirstein, it follows Bond as he attempts to prevent Elliot Carver, a power-mad media mogul, from engineering world events to initiate World War III.', 'https://media.retroachievements.org/Images/054256.png', 'https://media.retroachievements.org/Images/054258.png', 'https://media.retroachievements.org/Images/077193.png', 'https://media.retroachievements.org/Images/034843.png', 4),
  (193, 11289, 'Dragon Quest VII', 'PlayStation', 12, 1048, 1048, 1048, 80, 0, 'Turn-Based RPG', 'Heartbeat', 'Enix', '2000-08-26', 'Dragon Quest VII: Fragments of the Forgotten Past, known in Japan as Dragon Quest VII: Warriors of Eden, is a 2000 role-playing video game developed by Heartbeat and ArtePiazza, and published by Enix for the PlayStation. The game was produced by Yuji Horii, who has presided over the Dragon Quest series since its inception. Artwork and character designs were once again provided by Dragon Ball creator Akira Toriyama, the artist responsible for all previous Dragon Quest games. It was released in North America in 2001 under the title Dragon Warrior VII. The game received a remake on the Nintendo 3DS in Japan in 2013; the remake was released in English under the title Dragon Quest VII: Fragments of the Forgotten Past in 2016. A version of the game for Android and iOS was released in Japan in 2015. Another remake, entitled Dragon Quest VII Reimagined, was released for Nintendo Switch, Nintendo Switch 2, PlayStation 5, Xbox Series X/S, and PC on February 5, 2026.', 'https://media.retroachievements.org/Images/102807.png', 'https://media.retroachievements.org/Images/056841.png', 'https://media.retroachievements.org/Images/026504.png', 'https://media.retroachievements.org/Images/026505.png', 4),
  (194, 18260, 'Dance Dance Revolution (USA)', 'PlayStation', 12, 1034, 1034, 1034, 68, 0, 'Rhythm', 'Konami', 'Konami', '2001-05-09', 'Dance Dance Revolution  (DDR) is a music video game series produced by Konami. Introduced in Japan in 1998 as part of the Bemani series, and released in North America and Europe in 1999, Dance Dance Revolution is the pioneering series of the rhythm and dance genre in video games. Players stand on a dance platform or stage and hit colored arrows laid out in a cross with their feet to musical and visual cues. Players are judged by how well they time their dance to the patterns presented to them and are allowed to choose more music to play to if they receive a passing score.', 'https://media.retroachievements.org/Images/058138.png', 'https://media.retroachievements.org/Images/050837.png', 'https://media.retroachievements.org/Images/058136.png', 'https://media.retroachievements.org/Images/058137.png', 4),
  (195, 16308, 'Pandemonium!', 'PlayStation', 12, 1032, 1032, 1032, 128, 0, '2.5D Platforming', 'Toys for Bob', 'Crystal Dynamics', '1996-11-05', 'Pandemonium! is a 1996 platform video game developed by Toys for Bob and published by Crystal Dynamics for the PlayStation, Sega Saturn, Microsoft Windows, N-Gage, mobile and iOS. Pandemonium! features Fargus, a jester, and Nikki, an acrobat, who unwittingly cast a spell that destroys the town. The goal of the game is to reach the Wishing Engine, where they can wish the town back to normal. For each level, the player can choose which character to be. Each has a special move – Fargus can deliver a special spinning attack, and Nikki can double jump. The game consists of a great variety of unique gameplay objects, such as watermelons, clouds, spider webs and logs. A sequel, Pandemonium 2, was released in 1997 for PlayStation and Microsoft Windows.', 'https://media.retroachievements.org/Images/089232.png', 'https://media.retroachievements.org/Images/093814.png', 'https://media.retroachievements.org/Images/083287.png', 'https://media.retroachievements.org/Images/083292.png', 4),
  (196, 16599, 'Pink Panther: Pinkadelic Pursuit', 'PlayStation', 12, 1018, 1018, 1018, 38, 0, '2D Platforming', 'Étranges Libellules', 'DreamCatcher Interactive', '2002-11-29', 'The Pink Panther is an American media franchise primarily focusing on a series of comedy-mystery films featuring an inept French police detective, Inspector Jacques Clouseau, as well as an animated series created by DePatie–Freleng about the titular Pink Panther character. The franchise began with the release of the film The Pink Panther in 1963 and the animated cartoons began in 1964 with the short film The Pink Phink. The role of Clouseau was first acted by and is most closely associated with Peter Sellers. Most of the films were written and directed by Blake Edwards, with theme music composed by Henry Mancini. Elements and characters inspired by the films were adapted into other media, including books, comic books, video games and animated series.', 'https://media.retroachievements.org/Images/037326.png', 'https://media.retroachievements.org/Images/037327.png', 'https://media.retroachievements.org/Images/037324.png', 'https://media.retroachievements.org/Images/037325.png', 4),
  (197, 11313, 'Wild Arms 2', 'PlayStation', 12, 1014, 1014, 1014, 216, 0, 'Turn-Based RPG', 'Media.Vision', 'Sony Computer Entertainment', '1999-09-02', 'Wild Arms 2, known in Japan as Wild Arms: 2nd Ignition, is a 1999 role-playing video game developed by Media.Vision and published by Sony Computer Entertainment for the PlayStation. It is the second installment in the Wild Arms series.', 'https://media.retroachievements.org/Images/033495.png', 'https://media.retroachievements.org/Images/065778.png', 'https://media.retroachievements.org/Images/033487.png', 'https://media.retroachievements.org/Images/035954.png', 4),
  (198, 11291, 'Need for Speed III: Hot Pursuit', 'PlayStation', 12, 1010, 1010, 1010, 43, 0, 'Arcade Racing', 'EA Canada | EA Vancouver', 'Electronic Arts', '1998-03-25', 'Need for Speed III: Hot Pursuit is a 1998 racing video game developed for PlayStation by EA Canada and Microsoft Windows by EA Seattle, and published by Electronic Arts. It is the third major installment in the Need for Speed franchise, incorporating police pursuits as a major part of gameplay. Hot Pursuit remains focused on racing using exotic sports cars, but features races that primarily take place in locations within North America, including varied settings and climates. Police AI is improved over the first game, utilizing several tactics to stop both the player and opponent. The PlayStation version was released on March 25, 1998, while the Windows version was released on October 12 the same year. The game received critical success, with praise for its graphics and customization options. It received a direct sequel in 2002 and a reboot in 2010.', 'https://media.retroachievements.org/Images/116506.png', 'https://media.retroachievements.org/Images/028094.png', 'https://media.retroachievements.org/Images/028092.png', 'https://media.retroachievements.org/Images/028093.png', 4),
  (199, 16721, 'Xena: Warrior Princess', 'PlayStation', 12, 1010, 1010, 1010, 57, 0, 'Hack & Slash', 'Universal Studios Digital Arts', 'Electronic Arts', '1999-10-05', 'Xena: Warrior Princess is an American sword-and-sorcery television series filmed in New Zealand, which aired in first-run syndication from September 4, 1995, to June 18, 2001. Critics have praised the series for its strong female protagonist, and it has acquired a strong cult following, attention in fandom, parody, and academia, and has influenced the direction of other television series.', 'https://media.retroachievements.org/Images/045514.png', 'https://media.retroachievements.org/Images/056990.png', 'https://media.retroachievements.org/Images/038006.png', 'https://media.retroachievements.org/Images/046120.png', 4),
  (200, 11147, 'Warcraft II: The Dark Saga', 'PlayStation', 12, 995, 995, 995, 85, 0, 'Real-Time Strategy', 'Blizzard Entertainment', 'Electronic Arts', '1997-08-20', 'Warcraft II: Tides of Darkness is a fantasy real-time strategy (RTS) computer game developed by Blizzard Entertainment and released for MS-DOS and Microsoft Windows in 1995 and Mac OS in 1996 by Blizzard''s parent, Davidson & Associates. A sequel to Warcraft: Orcs & Humans, the game was met with positive reviews and won most of the major PC gaming awards in 1996. In 1996, Blizzard released an expansion pack, Warcraft II: Beyond the Dark Portal, for DOS and Mac OS, and a compilation, Warcraft II: The Dark Saga, for the PlayStation and Sega Saturn. The Battle.net edition, released in 1999, included Warcraft II: Beyond the Dark Portal, provided Blizzard''s online gaming service, and replaced the MS-DOS version with a Windows one.', 'https://media.retroachievements.org/Images/113850.png', 'https://media.retroachievements.org/Images/057062.png', 'https://media.retroachievements.org/Images/034483.png', 'https://media.retroachievements.org/Images/034484.png', 4);
INSERT INTO games (rank, id, title, consoleName, consoleId, totalPlayers, casualPlayers, hardcorePlayers, numAchievements, points, genre, developer, publisher, released, description, icon, boxArt, titleScreen, screenshot, rating) VALUES
  (1, 1, 'Sonic the Hedgehog', 'Genesis/Mega Drive', 1, 53953, 53953, 53953, 35, 0, '2D Platforming', 'Sonic Team', 'Sega', '1991-06-11', 'Sonic the Hedgehog is a Japanese video game series and media franchise created by the Japanese developers Yuji Naka, Naoto Ohshima, and Hirokazu Yasuhara for Sega. The franchise follows Sonic, an anthropomorphic blue hedgehog with supersonic speed, who battles the mad scientist Doctor Eggman and his robot army. The main Sonic the Hedgehog games are platformers mostly developed by Sonic Team; other games, developed by various studios, include spin-offs in the racing, fighting, party and sports genres. The franchise also incorporates printed media, animations, films, and merchandise.', 'https://media.retroachievements.org/Images/085573.png', 'https://media.retroachievements.org/Images/112941.png', 'https://media.retroachievements.org/Images/054993.png', 'https://media.retroachievements.org/Images/000010.png', 5),
  (2, 10, 'Sonic the Hedgehog 2', 'Genesis/Mega Drive', 1, 19942, 19942, 19942, 32, 0, NULL, NULL, NULL, '1992-11-21', 'Sonic the Hedgehog 2 is a 1992 platform game developed by Sega Technical Institute (STI) for the Sega Genesis. Players control Sonic as he attempts to stop Doctor Robotnik from stealing the Chaos Emeralds to power his space station, the Death Egg. Like the first Sonic the Hedgehog (1991), players traverse side-scrolling levels at high speeds while collecting rings, defeating enemies, and fighting bosses. Sonic 2 introduces Sonic''s sidekick Miles Tails Prower and features faster gameplay, larger levels, a multiplayer mode, and special stages featuring pre-rendered 3D graphics.', 'https://media.retroachievements.org/Images/121647.png', 'https://media.retroachievements.org/Images/084488.png', 'https://media.retroachievements.org/Images/054994.png', 'https://media.retroachievements.org/Images/001366.png', 4.8),
  (3, 55, 'Streets of Rage', 'Genesis/Mega Drive', 1, 18521, 18521, 18521, 53, 0, 'Beat ''em Up', 'Sega', 'Sega', '1991-08-02', 'Streets of Rage is a series of side-scrolling beat ''em up video games. It centers on the efforts of several ex-police vigilantes trying to rid the fictional American metropolis of Wood Oak City of a crime syndicate that has corrupted its local government. The first three games in the franchise were developed and released by Sega for the Sega Genesis in the early 1990s and have since been ported and re-released on various platforms. A fourth entry was also released in 2020.', 'https://media.retroachievements.org/Images/110823.png', 'https://media.retroachievements.org/Images/123452.png', 'https://media.retroachievements.org/Images/107662.png', 'https://media.retroachievements.org/Images/107663.png', 4.8),
  (4, 3, 'Streets of Rage 2', 'Genesis/Mega Drive', 1, 18286, 18286, 18286, 22, 0, 'Beat ''em Up', 'Ancient, Sega', 'Sega', '1992-12-15', 'Streets of Rage 2, known as Bare Knuckle II in Japan, is a 1992 beat ''em up video game developed and published by Sega for the Sega Genesis. The sequel to Streets of Rage (1991), the characters Axel Stone and Blaze Fielding return while the game also introduces two new characters: Max Thunder, and Eddie Skate Hunter, the younger brother of Adam Hunter from the first game.', 'https://media.retroachievements.org/Images/120551.png', 'https://media.retroachievements.org/Images/051871.png', 'https://media.retroachievements.org/Images/000212.png', 'https://media.retroachievements.org/Images/000213.png', 4.8),
  (5, 4874, 'Sonic 3 & Knuckles', 'Genesis/Mega Drive', 1, 12975, 12975, 12975, 53, 0, '2D Platforming', 'Sega, Sonic Team', 'Sega', '1994-10-18', 'Sonic the Hedgehog 3 is a 1994 platform game developed by Sega Technical Institute and published by Sega for the Sega Genesis. Like previous Sonic games, players traverse side-scrolling levels while collecting rings and defeating enemies. They control Sonic and Tails, who attempt to retrieve the Chaos Emeralds to stop Doctor Robotnik from relaunching his space station, the Death Egg, after it crash-lands on a mysterious floating island. Sonic 3 introduces Knuckles the Echidna, the island guardian, who lays traps for Sonic and Tails.', 'https://media.retroachievements.org/Images/110373.png', 'https://media.retroachievements.org/Images/116311.png', 'https://media.retroachievements.org/Images/003796.png', 'https://media.retroachievements.org/Images/003797.png', 4.7),
  (6, 69, 'Castlevania: Bloodlines', 'Genesis/Mega Drive', 1, 11750, 11750, 11750, 54, 0, '2D Platforming', 'Konami', 'Konami', '1994-03-17', 'Castlevania: Bloodlines, known in Japan as Vampire Killer and in PAL regions as Castlevania: The New Generation, is a 1994 platform game developed and published by Konami for the Sega Genesis as part of the Castlevania series. A vampire named Elizabeth Bartley is orchestrating the beginning of World War I to serve as the catalyst for the resurrection of her uncle, Dracula. Players take on the role of Quincey Morris'' son, John, and his friend Eric Lecarde to take up the fight against evil.', 'https://media.retroachievements.org/Images/060798.png', 'https://media.retroachievements.org/Images/071778.png', 'https://media.retroachievements.org/Images/067931.png', 'https://media.retroachievements.org/Images/067932.png', 4.6),
  (7, 2, 'Aladdin', 'Genesis/Mega Drive', 1, 11575, 11575, 11575, 21, 0, NULL, NULL, NULL, '1993-10-19', 'Aladdin is a Middle-Eastern folk tale. It is one of the best-known tales associated with One Thousand and One Nights, despite not being part of the original text; it was added by the Frenchman Antoine Galland, based on a folk tale that he heard from the Syrian storyteller Hanna Diyab.', 'https://media.retroachievements.org/Images/123777.png', 'https://media.retroachievements.org/Images/051848.png', 'https://media.retroachievements.org/Images/039378.png', 'https://media.retroachievements.org/Images/000123.png', 4.6),
  (8, 53, 'Comix Zone', 'Genesis/Mega Drive', 1, 11520, 11520, 11520, 41, 0, 'Beat ''em Up', 'Sega', 'Sega', '1995-07-01', 'Comix Zone is a 1995 beat ''em up game developed by Sega Technical Institute (STI) and published by Sega for the Sega Genesis. Set within the panels of a comic book, it follows the comic writer/artist Sketch Turner who, after being transported into the comic by one of his creations, attempts to escape while contending with various threats. The game sees the player traversing six levels, where they interact with the comic world and must defeat enemies, or occasionally solve puzzles, to progress.', 'https://media.retroachievements.org/Images/111299.png', 'https://media.retroachievements.org/Images/046942.png', 'https://media.retroachievements.org/Images/000892.png', 'https://media.retroachievements.org/Images/001373.png', 4.6),
  (9, 282, 'Teenage Mutant Ninja Turtles: The Hyperstone Heist', 'Genesis/Mega Drive', 1, 10670, 10670, 10670, 25, 0, 'Beat ''em Up', 'Konami', 'Konami', '1992-12-01', 'Teenage Mutant Ninja Turtles: The Hyperstone Heist, released in Europe as Teenage Mutant Hero Turtles: The Hyperstone Heist and in Japan as Teenage Mutant Ninja Turtles: Return of the Shredder, is a 1992 beat ''em up game developed and published by Konami for the Sega Genesis, based on the Teenage Mutant Ninja Turtles comic book characters. It was Konami''s debut title for the Genesis. The game was re-released as part of Teenage Mutant Ninja Turtles: The Cowabunga Collection in 2022.', 'https://media.retroachievements.org/Images/123099.png', 'https://media.retroachievements.org/Images/116471.png', 'https://media.retroachievements.org/Images/048578.png', 'https://media.retroachievements.org/Images/048579.png', 4.6),
  (10, 18, 'Golden Axe', 'Genesis/Mega Drive', 1, 10320, 10320, 10320, 24, 0, 'Beat ''em Up', 'Sega', 'Sega', '1989-12-23', 'Golden Axe  is a series of side-scrolling beat ''em up arcade video games developed by Sega. The series takes place in a medieval fantasy world where several heroes have the task of recovering the legendary Golden Axe, the mainstay element of the series.', 'https://media.retroachievements.org/Images/016753.png', 'https://media.retroachievements.org/Images/051935.png', 'https://media.retroachievements.org/Images/048564.png', 'https://media.retroachievements.org/Images/048565.png', 4.6),
  (11, 21, 'Sonic the Hedgehog 3', 'Genesis/Mega Drive', 1, 9605, 9605, 9605, 29, 0, '2D Platforming', 'Sega, Sonic Team', 'Sega', '1994-02-02', 'Sonic the Hedgehog 3 is a 1994 platform game developed by Sega Technical Institute and published by Sega for the Sega Genesis. Like previous Sonic games, players traverse side-scrolling levels while collecting rings and defeating enemies. They control Sonic and Tails, who attempt to retrieve the Chaos Emeralds to stop Doctor Robotnik from relaunching his space station, the Death Egg, after it crash-lands on a mysterious floating island. Sonic 3 introduces Knuckles the Echidna, the island guardian, who lays traps for Sonic and Tails.', 'https://media.retroachievements.org/Images/110369.png', 'https://media.retroachievements.org/Images/051937.png', 'https://media.retroachievements.org/Images/054995.png', 'https://media.retroachievements.org/Images/119270.png', 4.6),
  (12, 263, 'Michael Jackson''s Moonwalker', 'Genesis/Mega Drive', 1, 9288, 9288, 9288, 50, 0, 'Beat ''em Up', 'Sega', 'Sega', '1990-08-25', 'In 1990, several video games based on the 1988 Michael Jackson film Moonwalker, all named Michael Jackson''s Moonwalker, were released. Sega developed two beat ''em ups, one released in arcades and another released for the Sega Genesis and Master System consoles. U.S. Gold also published various games for home computers. Each of the games'' plots loosely follows the Smooth Criminal segment of the film, in which Jackson rescues kidnapped children from the evil Mr. Big, and incorporates synthesized versions of some of the musician''s songs. Following Moonwalker, Jackson collaborated with Sega on several other video games.', 'https://media.retroachievements.org/Images/047868.png', 'https://media.retroachievements.org/Images/014236.png', 'https://media.retroachievements.org/Images/040977.png', 'https://media.retroachievements.org/Images/048231.png', 4.6),
  (13, 9, 'Castle of Illusion starring Mickey Mouse', 'Genesis/Mega Drive', 1, 8104, 8104, 8104, 20, 0, NULL, 'Sega', 'Sega', '1990-11-21', 'Castle of Illusion Starring Mickey Mouse is a 1990 platform game developed and published by Sega and released for the Sega Genesis. An 8-bit version of the game was later released for the Master System and Game Gear. The game follows Mickey Mouse on a quest to save Minnie Mouse from the evil witch Mizrabel. It is the first game in Sega''s Illusion video game series starring Mickey.', 'https://media.retroachievements.org/Images/048628.png', 'https://media.retroachievements.org/Images/051879.png', 'https://media.retroachievements.org/Images/000776.png', 'https://media.retroachievements.org/Images/000777.png', 4.6),
  (14, 24, 'Altered Beast', 'Genesis/Mega Drive', 1, 7644, 7644, 7644, 26, 0, 'Beat ''em Up', 'Sega', 'Sega', '1988-11-27', 'Altered Beast is a 1988 beat ''em up video game developed by Team Shinobi and published by Sega for arcades. Set in Ancient Greece, the game follows a Roman centurion who is resurrected by the Olympian god Zeus to rescue his daughter Athena from Neff, the demonic ruler of the underworld. By collecting three power-ups in a level, the player character can transform into one of five mythical beasts.', 'https://media.retroachievements.org/Images/088907.png', 'https://media.retroachievements.org/Images/051941.png', 'https://media.retroachievements.org/Images/039525.png', 'https://media.retroachievements.org/Images/039526.png', 4.6),
  (15, 168, 'The Adventures of Batman & Robin', 'Genesis/Mega Drive', 1, 6442, 6442, 6442, 13, 0, 'Run & Gun', 'Clockwork Tortoise', 'Sega', '1995-08-02', 'Batman: The Animated Series is an American animated superhero television series based on the DC Comics superhero Batman. Developed by Bruce Timm and Eric Radomski, and produced by Warner Bros. Animation, it originally aired on Fox Kids from September 5, 1992, to September 15, 1995, with a total of 85 episodes. Mid-way through the series'' run, it was re-titled The Adventures of Batman & Robin.', 'https://media.retroachievements.org/Images/061855.png', 'https://media.retroachievements.org/Images/121188.png', 'https://media.retroachievements.org/Images/039423.png', 'https://media.retroachievements.org/Images/039424.png', 4.5),
  (16, 169, 'Sonic & Knuckles', 'Genesis/Mega Drive', 1, 6243, 6243, 6243, 20, 0, '2D Platforming', 'Sega, Sonic Team', 'Sega', '1994-10-18', 'Sonic & Knuckles is a 1994 platform game developed by Sega Technical Institute and published by Sega for the Sega Genesis. Players control Sonic the Hedgehog or Knuckles the Echidna in their quests to save Angel Island; Sonic tries to stop Doctor Robotnik from re-launching his orbital weapon, the Death Egg, while Knuckles scuffles with Robotnik''s minion, EggRobo. Like previous Sonic games, players traverse side-scrolling levels at high speeds while collecting rings and defeating enemies.', 'https://media.retroachievements.org/Images/110372.png', 'https://media.retroachievements.org/Images/116310.png', 'https://media.retroachievements.org/Images/000125.png', 'https://media.retroachievements.org/Images/119269.png', 4.5),
  (17, 11, 'Earthworm Jim', 'Genesis/Mega Drive', 1, 6242, 6242, 6242, 117, 0, NULL, NULL, NULL, '1994-10-01', 'Earthworm Jim is a series of platform games featuring an earthworm named Jim who wears a robotic suit and battles the forces of evil. The series is noted for its platforming and shooting gameplay, surreal humor, and edgy art style. Four games were released in the series: Earthworm Jim, Earthworm Jim 2, Earthworm Jim 3D, and Earthworm Jim: Menace 2 the Galaxy, with the first game released in 1994. The series had lain dormant for almost a decade before Gameloft remade the original game in HD for PlayStation Network and Xbox Live Arcade in 2010. Interplay announced Earthworm Jim 4 in 2008; little to no information surfaced until May 2019 and August 2020, and development was believed cancelled by the rights owners by 2023, as it had never left pre-planning stages.', 'https://media.retroachievements.org/Images/115155.png', 'https://media.retroachievements.org/Images/051915.png', 'https://media.retroachievements.org/Images/000888.png', 'https://media.retroachievements.org/Images/000889.png', 4.5),
  (18, 7, 'Gunstar Heroes', 'Genesis/Mega Drive', 1, 6214, 6214, 6214, 54, 0, NULL, NULL, NULL, '1993-09-09', 'Gunstar Heroes is a 1993 run and gun video game developed by Treasure and published by Sega for the Sega Genesis. It was Treasure''s first developed video game. The premise is centered around a pair of characters, the Gunstars, in their efforts to stop an evil empire from recovering four powerful gems. The characters can fire guns and perform a series of acrobatic maneuvers to fight enemies across each stage. There are four weapons which can be combined with one another to create different shot types.', 'https://media.retroachievements.org/Images/044564.png', 'https://media.retroachievements.org/Images/051875.png', 'https://media.retroachievements.org/Images/000183.png', 'https://media.retroachievements.org/Images/000184.png', 4.5),
  (19, 54, 'Streets of Rage 3', 'Genesis/Mega Drive', 1, 6187, 6187, 6187, 48, 0, 'Beat ''em Up', 'Sega', 'Sega', '1994-06-01', 'Streets of Rage 3 is a 1994 beat ''em up game developed and published by Sega for the Genesis. It is the third installment of the Streets of Rage series and the last game in the original trilogy. The game includes several changes over Streets of Rage and Streets of Rage 2, such as a more complex plot, inclusion of character dialogue, longer levels, more in-depth scenarios and faster gameplay. Weapons can be integrated with unique moves with certain characters, hidden characters were added, and a few cutscenes were included to give the story greater depth.', 'https://media.retroachievements.org/Images/110827.png', 'https://media.retroachievements.org/Images/000598.png', 'https://media.retroachievements.org/Images/053237.png', 'https://media.retroachievements.org/Images/000596.png', 4.5),
  (20, 15, 'Sonic the Hedgehog Spinball', 'Genesis/Mega Drive', 1, 6068, 6068, 6068, 68, 0, NULL, NULL, NULL, '1993-11-15', 'Sonic Spinball, also known as Sonic the Hedgehog Spinball, is a 1993 pinball video game developed by Sega Technical Institute and published by Sega for the Sega Genesis. It is a spin-off of the Sonic the Hedgehog series. Players control Sonic the Hedgehog, who must stop Doctor Robotnik from enslaving the population in a giant pinball-like mechanism. The game is set in a series of pinball machine-like environments with Sonic acting as the pinball.', 'https://media.retroachievements.org/Images/077489.png', 'https://media.retroachievements.org/Images/051932.png', 'https://media.retroachievements.org/Images/000703.png', 'https://media.retroachievements.org/Images/000702.png', 4.5),
  (21, 120, 'Contra: Hard Corps', 'Genesis/Mega Drive', 1, 6063, 6063, 6063, 80, 0, 'Run & Gun', 'Konami', 'Konami', '1994-09-15', 'Contra: Hard Corps, released as Contra: The Hard Corps in Japan and Probotector in Europe and Australia, is a 1994 run and gun game developed and published by Konami for the Sega Genesis, making it the first game in the Contra series released for a Sega platform.', 'https://media.retroachievements.org/Images/093812.png', 'https://media.retroachievements.org/Images/046239.png', 'https://media.retroachievements.org/Images/001098.png', 'https://media.retroachievements.org/Images/001099.png', 4.5),
  (22, 64, 'Shinobi III: Return of the Ninja Master', 'Genesis/Mega Drive', 1, 6009, 6009, 6009, 49, 0, 'Action', 'Sega', 'Sega', '1993-07-23', 'Shinobi III: Return of the Ninja Master, released in Japan as The Super Shinobi II, is a 1993 hack and slash platform game developed and published by Sega for the Sega Genesis. It is the direct sequel to the previous The Revenge of Shinobi. Shinobi III received critical acclaim and has been ranked among the greatest Genesis games.', 'https://media.retroachievements.org/Images/087670.png', 'https://media.retroachievements.org/Images/064148.png', 'https://media.retroachievements.org/Images/064151.png', 'https://media.retroachievements.org/Images/064150.png', 4.5),
  (23, 212, 'Ghouls ''n Ghosts', 'Genesis/Mega Drive', 1, 5788, 5788, 5788, 23, 0, NULL, 'Capcom', 'Capcom', '1989-08-03', 'Ghouls ''n Ghosts, known as Dai Makaimura in Japan, is a 1988 platform game developed and published by Capcom for arcades. It is the sequel to 1985''s Ghosts ''n Goblins, and the second game in the Ghosts ''n Goblins series.', 'https://media.retroachievements.org/Images/119071.png', 'https://media.retroachievements.org/Images/000176.png', 'https://media.retroachievements.org/Images/048561.png', 'https://media.retroachievements.org/Images/048562.png', 4.5),
  (24, 480, 'Alien Soldier', 'Genesis/Mega Drive', 1, 5493, 5493, 5493, 40, 0, 'Run & Gun', 'Treasure', 'Sega', '1995-02-24', 'Alien Soldier is a 1995 run and gun video game developed by Treasure and published by Sega for the Mega Drive. Retail copies were released in Japan and PAL territories while in North America it was only available exclusively via the Sega Channel cable service. The story follows a powerful being named Epsilon-Eagle, who after being nearly killed becomes determined to avenge his near death and save his planet. The character has a variety of weapons and moves that the player must master to complete the game. Many gameplay ideas are borrowed from Treasure''s earlier Mega Drive release, Gunstar Heroes (1993). However, Alien Soldier puts an emphasis on challenging boss fights with short and easy levels serving as downtime in-between.', 'https://media.retroachievements.org/Images/073853.png', 'https://media.retroachievements.org/Images/001072.png', 'https://media.retroachievements.org/Images/001069.png', 'https://media.retroachievements.org/Images/001070.png', 4.5),
  (25, 87, 'Golden Axe II', 'Genesis/Mega Drive', 1, 5417, 5417, 5417, 32, 0, 'Beat ''em Up', 'Sega', 'Sega', '1991-12-27', 'Golden Axe II is a 1991 beat ''em up video game developed and published by Sega for the Sega Genesis. It is a sequel to 1989''s Golden Axe, and the second installment of the Golden Axe series. The player controls one of three warriors as they attempt to recover the Golden Axe by slaying Dark Guld and his loyal followers. Much like its predecessor, the gameplay is based around side-scrolling levels where the player fights enemies by using their melee weapon, while riding a beast, or utilizing elemental magic. The game revamps and introduces various gameplay mechanics from its contemporary including the ability to select the level of magic used and an attack that hits all around the player’s character.', 'https://media.retroachievements.org/Images/016754.png', 'https://media.retroachievements.org/Images/048566.png', 'https://media.retroachievements.org/Images/048567.png', 'https://media.retroachievements.org/Images/048568.png', 4.5),
  (26, 145, 'Columns', 'Genesis/Mega Drive', 1, 5347, 5347, 5347, 24, 0, NULL, 'Sega', 'Sega', '1990-06-30', 'A column or pillar in architecture and structural engineering is a structural element that transmits, through compression, the weight of the structure above to other structural elements below. In other words, a column is a compression member. The term column applies especially to a large round support with a capital and a base or pedestal, which is made of stone, or appearing to be so. A small wooden or metal support is typically called a post. Supports with a rectangular or other non-round section are usually called piers. Throughout architectural history, especially in Classical and Rennaisance styles, the column has been central to building design.', 'https://media.retroachievements.org/Images/049263.png', 'https://media.retroachievements.org/Images/001479.png', 'https://media.retroachievements.org/Images/001477.png', 'https://media.retroachievements.org/Images/001478.png', 4.5),
  (27, 209, 'Dr. Robotnik''s Mean Bean Machine', 'Genesis/Mega Drive', 1, 5344, 5344, 5344, 34, 0, 'Falling Block Puzzle', 'Compile', 'Sega', '1993-11-26', 'Dr. Robotnik''s Mean Bean Machine is a falling block puzzle video game developed by Compile and published by Sega. It was released for the Sega Genesis / Mega Drive and Game Gear in 1993 and ported to the Master System in 1994.', 'https://media.retroachievements.org/Images/108516.png', 'https://media.retroachievements.org/Images/075913.png', 'https://media.retroachievements.org/Images/075911.png', 'https://media.retroachievements.org/Images/075912.png', 4.5),
  (28, 218, 'QuackShot starring Donald Duck', 'Genesis/Mega Drive', 1, 5309, 5309, 5309, 31, 0, '2D Platforming', 'Sega', 'Sega', '1991-12-19', 'QuackShot Starring Donald Duck, known in Japan as I Love Donald Duck: The Treasure of King Garuzia, is a 1991 platform game developed and published by Sega for the Sega Genesis. The player controls Donald Duck as he, alongside his three nephews Huey, Dewey and Louie, attempt to track down a lost artifact which was treasured by King Garuzia. The game was influenced by the Indiana Jones film series.', 'https://media.retroachievements.org/Images/114167.png', 'https://media.retroachievements.org/Images/116307.png', 'https://media.retroachievements.org/Images/000971.png', 'https://media.retroachievements.org/Images/000972.png', 4.5),
  (29, 45, 'Batman: The Video Game', 'Genesis/Mega Drive', 1, 5258, 5258, 5258, 17, 0, '2D Platforming', 'Sunsoft', 'Sega', '1990-07-27', 'Batman: The Video Game is a platformer developed by Sunsoft for the Nintendo Entertainment System featuring the DC Comics character Batman, tying into the 1989 film of the same name.', 'https://media.retroachievements.org/Images/053393.png', 'https://media.retroachievements.org/Images/048583.png', 'https://media.retroachievements.org/Images/048584.png', 'https://media.retroachievements.org/Images/048585.png', 4.5),
  (30, 8, 'Ecco the Dolphin', 'Genesis/Mega Drive', 1, 4926, 4926, 4926, 41, 0, NULL, NULL, NULL, '1992-12-01', 'Ecco the Dolphin is a series of action-adventure video games developed by Appaloosa Interactive and published by Sega.', 'https://media.retroachievements.org/Images/117042.png', 'https://media.retroachievements.org/Images/051877.png', 'https://media.retroachievements.org/Images/051878.png', 'https://media.retroachievements.org/Images/001120.png', 4.5),
  (31, 68, 'Kid Chameleon', 'Genesis/Mega Drive', 1, 4843, 4843, 4843, 65, 0, '2D Platforming', 'Sega', 'Sega', '1992-05-29', 'Kid Chameleon is a 1992 platform game developed and published by Sega for the Sega Genesis. The player controls the Kid Chameleon and attempts to save his peers from a virtual reality video game''s rogue artificial intelligence. The gameplay involves the player going through a series of levels, in which the goal is to reach a flag at the end. The central mechanic revolves around different forms, obtained from masks, which are used to progress through levels.', 'https://media.retroachievements.org/Images/113104.png', 'https://media.retroachievements.org/Images/041967.png', 'https://media.retroachievements.org/Images/001136.png', 'https://media.retroachievements.org/Images/041968.png', 4.4),
  (32, 293, 'Thunder Force IV', 'Genesis/Mega Drive', 1, 4834, 4834, 4834, 36, 0, 'Shoot ''em Up', 'Technosoft | Tecno Soft', 'Sega', '1992-07-24', 'Thunder Force IV, known in North America as Lightening Force: Quest for the Darkstar, is a 1992 shoot ''em up video game developed and published by Technosoft for the Mega Drive/Genesis. It is the fourth installment in Technosoft''s Thunder Force series, and the third and final one created for the Mega Drive. It was developed by the team at Technosoft that ported Devil''s Crush to the Mega Drive rather than the team that developed the previous Thunder Force games. Like its predecessors, it is a horizontally scrolling shooter, but it also features extensive vertical scrolling with large playing fields.', 'https://media.retroachievements.org/Images/004975.png', 'https://media.retroachievements.org/Images/005003.png', 'https://media.retroachievements.org/Images/004974.png', 'https://media.retroachievements.org/Images/005002.png', 4.4),
  (33, 326, 'Sonic 3D Blast', 'Genesis/Mega Drive', 1, 4710, 4710, 4710, 85, 0, '2.5D Platforming', 'Sonic Team, Traveller''s Tales', 'Sega', '1996-01-01', 'Sonic 3D Blast, known in regions outside North America as Sonic 3D: Flickies'' Island, is a 1996 platform game in the Sonic the Hedgehog series for the Sega Genesis and Sega Saturn. As Sonic the Hedgehog, the player embarks on a journey to save the Flickies, birds enslaved by Doctor Robotnik. The player must guide Sonic through a series of themed levels to collect Flickies and defeat Robotnik. Though it retains game mechanics from prior Sonic games, Sonic 3D Blast is differentiated by its 2D isometric perspective, with pre-rendered 3D models converted into sprites.', 'https://media.retroachievements.org/Images/098168.png', 'https://media.retroachievements.org/Images/120745.png', 'https://media.retroachievements.org/Images/120743.png', 'https://media.retroachievements.org/Images/120744.png', 4.4),
  (34, 66, 'Splatterhouse 2', 'Genesis/Mega Drive', 1, 4350, 4350, 4350, 20, 0, 'Beat ''em Up', 'Now Production', 'Namco', '1992-08-03', 'Splatterhouse 2, known in Japan as Splatterhouse Part 2, is a 1992 beat ''em up video game developed by Now Production and published by Namco for the Sega Genesis. It is the sequel to the 1988 arcade game Splatterhouse, and the third installment in the Splatterhouse series, following Splatterhouse: Wanpaku Graffiti.', 'https://media.retroachievements.org/Images/048203.png', 'https://media.retroachievements.org/Images/003605.png', 'https://media.retroachievements.org/Images/003606.png', 'https://media.retroachievements.org/Images/003607.png', 4.4),
  (35, 79, 'Mortal Kombat', 'Genesis/Mega Drive', 1, 4246, 4246, 4246, 39, 0, '2D Fighting', 'Probe Entertainment', 'Midway, Arena Entertainment', '1993-09-13', 'Mortal Kombat is an American media franchise centered on a series of fighting video games originally developed by Midway Games in 1992.', 'https://media.retroachievements.org/Images/054555.png', 'https://media.retroachievements.org/Images/060065.png', 'https://media.retroachievements.org/Images/036199.png', 'https://media.retroachievements.org/Images/036201.png', 4.4),
  (36, 40, 'World of Illusion starring Mickey Mouse and Donald Duck', 'Genesis/Mega Drive', 1, 4243, 4243, 4243, 36, 0, '2D Platforming', 'Sega', 'Sega', '1992-12-14', 'Castle of Illusion Starring Mickey Mouse is a 1990 platform game developed and published by Sega and released for the Sega Genesis. An 8-bit version of the game was later released for the Master System and Game Gear. The game follows Mickey Mouse on a quest to save Minnie Mouse from the evil witch Mizrabel. It is the first game in Sega''s Illusion video game series starring Mickey.', 'https://media.retroachievements.org/Images/116068.png', 'https://media.retroachievements.org/Images/000319.png', 'https://media.retroachievements.org/Images/000316.png', 'https://media.retroachievements.org/Images/005364.png', 4.4),
  (37, 644, 'M.U.S.H.A.: Metallic Uniframe Super Hybrid Armor', 'Genesis/Mega Drive', 1, 4117, 4117, 4117, 30, 0, 'Shoot ''em Up', 'Compile', 'Toaplan, Seismic', '1990-12-21', 'MUSHA is a vertically scrolling shooter video game developed by Compile for the Sega Genesis. An entry in Compile''s shooter series, Aleste, MUSHA places the player in the role of a flying mecha pilot who must destroy a large super intelligent computer threatening planet Earth. The game had a working title of Aleste 2 and originally featured a style similar to the first game, but this was changed to a more original Japanese aesthetic and speed metal soundtrack.', 'https://media.retroachievements.org/Images/047648.png', 'https://media.retroachievements.org/Images/047599.png', 'https://media.retroachievements.org/Images/000666.png', 'https://media.retroachievements.org/Images/000667.png', 4.4),
  (38, 20, 'Alex Kidd in the Enchanted Castle', 'Genesis/Mega Drive', 1, 4082, 4082, 4082, 66, 0, '2D Platforming', 'Overworks', 'Sega', '1989-02-10', 'Alex Kidd in the Enchanted Castle is a 1989 platform game developed and published by Sega for the Genesis. It is the only 16-bit platform game starring Alex Kidd, and the fifth game in the Alex Kidd series.', 'https://media.retroachievements.org/Images/047131.png', 'https://media.retroachievements.org/Images/051936.png', 'https://media.retroachievements.org/Images/000492.png', 'https://media.retroachievements.org/Images/000493.png', 4.4),
  (39, 494, 'Mega Bomberman', 'Genesis/Mega Drive', 1, 4025, 4025, 4025, 40, 0, 'Action', NULL, 'Sega', '1994-11-01', 'Bomberman ''94  is an action maze video game in the Bomberman series developed and published by Hudson Soft for the PC Engine and released on December 10, 1993, in Japan. It was later re-developed by Westone and re-published by Sega as Mega Bomberman on the Sega Mega Drive/Genesis in 1994 in other areas. The PC Engine Bomberman ''94 was later released outside Japan through the Virtual Console and the PlayStation Network.', 'https://media.retroachievements.org/Images/114059.png', 'https://media.retroachievements.org/Images/114051.png', 'https://media.retroachievements.org/Images/082568.png', 'https://media.retroachievements.org/Images/006752.png', 4.4),
  (40, 42, 'Tiny Toon Adventures: Buster''s Hidden Treasure', 'Genesis/Mega Drive', 1, 3975, 3975, 3975, 98, 0, '2D Platforming', 'Konami', 'Konami', '1993-01-01', 'Tiny Toon Adventures: Buster''s Hidden Treasure is the first Tiny Toon Adventures-based game released on the Sega Genesis. It was released in 1993 and developed and published by Konami. The game was not released in Japan, but was released in South Korea, where it was simply called Tiny Toons Adventures.', 'https://media.retroachievements.org/Images/023861.png', 'https://media.retroachievements.org/Images/001213.png', 'https://media.retroachievements.org/Images/001210.png', 'https://media.retroachievements.org/Images/001211.png', 4.4),
  (41, 94, 'The Revenge of Shinobi', 'Genesis/Mega Drive', 1, 3974, 3974, 3974, 44, 0, '2D Platforming, Action', 'Sega', 'Sega', '1989-12-02', 'The Revenge of Shinobi, released in Japan as The Super Shinobi, is a hack-and-slash action video game developed and published by Sega in 1989. It was the first Shinobi game developed for the Sega Genesis, and was later released on the coin-operated version of that console, the Mega-Tech.', 'https://media.retroachievements.org/Images/072086.png', 'https://media.retroachievements.org/Images/054914.png', 'https://media.retroachievements.org/Images/019748.png', 'https://media.retroachievements.org/Images/000197.png', 4.4),
  (42, 93, 'The Lion King', 'Genesis/Mega Drive', 1, 3917, 3917, 3917, 24, 0, '2D Platforming', 'Westwood Studios | Westwood Associates', 'Virgin Interactive', '1994-12-08', 'The Lion King is a 1994 American animated musical drama film directed by Roger Allers and Rob Minkoff, produced by Don Hahn, and written by Irene Mecchi, Jonathan Roberts, and Linda Woolverton. It was produced by Walt Disney Feature Animation, and features an ensemble voice cast consisting of Matthew Broderick, James Earl Jones, Jeremy Irons, Jonathan Taylor Thomas, Moira Kelly, Niketa Calame, Nathan Lane, Ernie Sabella, Whoopi Goldberg, Cheech Marin, Rowan Atkinson, and Robert Guillaume. The story follows a young lion prince named Simba, who is exiled from his kingdom after his father Mufasa is murdered by his uncle Scar to seize the throne. As he grows up, Simba must decide whether to return home to confront Scar and reclaim his place as king.', 'https://media.retroachievements.org/Images/115225.png', 'https://media.retroachievements.org/Images/000326.png', 'https://media.retroachievements.org/Images/115122.png', 'https://media.retroachievements.org/Images/115123.png', 4.4),
  (43, 102, 'X-Men', 'Genesis/Mega Drive', 1, 3828, 3828, 3828, 32, 0, 'Action, Platforming', 'Western Technologies', 'Sega', '1993-01-01', 'The X-Men are a superhero team in American comic books published by Marvel Comics. Created by writer/editor Stan Lee and artist/co-plotter Jack Kirby, the team first appeared in The X-Men #1. Although initially cancelled in 1970 due to low sales, following its 1975 revival and subsequent direction under writer Chris Claremont, it became one of Marvel Comics''s most recognizable and successful franchises. They have appeared in numerous books, television shows, 20th Century Fox''s X-Men films, and video games. The X-Men title may refer to the superhero team itself, the eponymous comic series, or the broader franchise, which includes various solo titles and team books, such as the New Mutants, Excalibur, and X-Force.', 'https://media.retroachievements.org/Images/125065.png', 'https://media.retroachievements.org/Images/020589.png', 'https://media.retroachievements.org/Images/020587.png', 'https://media.retroachievements.org/Images/020588.png', 4.4),
  (44, 110, 'Sunset Riders', 'Genesis/Mega Drive', 1, 3677, 3677, 3677, 15, 0, NULL, 'Konami', 'Konami', '1993-01-01', 'Sunset Riders is a 1991 run and gun video game developed and published by Konami for arcades. It was released in North America in October 1991 and Japan in November 1991. It is set in the American Old West, where the player(s) take control of bounty hunters who are seeking the rewards offered for various criminals.', 'https://media.retroachievements.org/Images/052907.png', 'https://media.retroachievements.org/Images/000195.png', 'https://media.retroachievements.org/Images/000192.png', 'https://media.retroachievements.org/Images/000193.png', 4.4),
  (45, 211, 'Alien Storm', 'Genesis/Mega Drive', 1, 3662, 3662, 3662, 12, 0, 'Rail Shooter, Run & Gun', 'Overworks', 'Sega', '1991-06-28', 'Alien Storm (エイリアンストーム) is a beat ''em up shooter released as an arcade video game by Sega in 1990. It was ported to the Genesis/Mega Drive and Master System. The Mega Drive version was re-released on Wii''s Virtual Console in 2007 and was also included on Sonic''s Ultimate Genesis Collection for Xbox 360 and PlayStation 3. The game was also re-released on the Nintendo Classics service in 2022.', 'https://media.retroachievements.org/Images/089349.png', 'https://media.retroachievements.org/Images/003500.png', 'https://media.retroachievements.org/Images/000545.png', 'https://media.retroachievements.org/Images/000542.png', 4.4),
  (46, 39, 'Alisia Dragoon', 'Genesis/Mega Drive', 1, 3608, 3608, 3608, 39, 0, '2D Platforming', 'Game Arts', NULL, '1992-03-30', 'Alisia Dragoon is a 1992 platform game developed by Game Arts and published by Sega for the Sega Genesis. The player controls Alisia, a young woman who is on a quest to avenge her father and save the world. She can fire lightning from her hands and summon four faithful beasts to aid her. The game was later made available on the Sega Genesis Mini and Nintendo Classics service.', 'https://media.retroachievements.org/Images/005880.png', 'https://media.retroachievements.org/Images/028450.png', 'https://media.retroachievements.org/Images/048204.png', 'https://media.retroachievements.org/Images/049852.png', 4.4),
  (47, 6312, 'Knuckles the Echidna in Sonic the Hedgehog 2', 'Genesis/Mega Drive', 1, 3570, 3570, 3570, 26, 0, '2D Platforming', 'Sega, Sonic Team', 'Sega', '1994-10-18', 'Sonic the Hedgehog 2 is a 1992 platform game developed by Sega Technical Institute (STI) for the Sega Genesis. Players control Sonic as he attempts to stop Doctor Robotnik from stealing the Chaos Emeralds to power his space station, the Death Egg. Like the first Sonic the Hedgehog (1991), players traverse side-scrolling levels at high speeds while collecting rings, defeating enemies, and fighting bosses. Sonic 2 introduces Sonic''s sidekick Miles Tails Prower and features faster gameplay, larger levels, a multiplayer mode, and special stages featuring pre-rendered 3D graphics.', 'https://media.retroachievements.org/Images/121673.png', 'https://media.retroachievements.org/Images/009353.png', 'https://media.retroachievements.org/Images/009350.png', 'https://media.retroachievements.org/Images/009352.png', 4.4),
  (48, 2166, 'Thunder Force III', 'Genesis/Mega Drive', 1, 3561, 3561, 3561, 28, 0, 'Shoot ''em Up', NULL, 'Sega', '1990-06-08', 'Thunder Force III (サンダーフォースIII) is a 1990 scrolling shooter game developed by Technosoft for the Sega Genesis. It is the third chapter in the Thunder Force series. It was then retooled into an arcade game named Thunder Force AC. In 1991, Thunder Force AC was ported to the Super Nintendo Entertainment System under the title Thunder Spirits.', 'https://media.retroachievements.org/Images/078307.png', 'https://media.retroachievements.org/Images/000831.png', 'https://media.retroachievements.org/Images/000829.png', 'https://media.retroachievements.org/Images/000830.png', 4.4),
  (49, 98, 'Shadow Dancer: The Secret of Shinobi', 'Genesis/Mega Drive', 1, 3533, 3533, 3533, 19, 0, '2D Platforming', 'Sega', 'Sega', '1990-12-01', 'Shadow Dancer: The Secret of Shinobi , also known simply as Shadow Dancer, is a side-scrolling action game developed and published by Sega for the Sega Genesis in 1990. It is the second game in the Shinobi series released for the Mega Drive, following The Revenge of Shinobi. However, it is not a continuation of the previous game, but rather a loose adaptation of the 1989 arcade game Shadow Dancer. Like in the original arcade game, the player controls a ninja followed by a canine companion. The Secret of Shinobi was well received by critics.', 'https://media.retroachievements.org/Images/085627.png', 'https://media.retroachievements.org/Images/034046.png', 'https://media.retroachievements.org/Images/001185.png', 'https://media.retroachievements.org/Images/001186.png', 4.4),
  (50, 137, 'Battletoads', 'Genesis/Mega Drive', 1, 3490, 3490, 3490, 33, 0, 'Beat ''em Up', 'Arc System Works', 'Sega', '1991-06-01', 'Battletoads is a video game franchise by Rare that began with the original beat ''em up game Battletoads in 1991. Starring three anthropomorphic toads named after skin conditions, Rash, Zitz, and Pimple, the series was created to rival the Teenage Mutant Ninja Turtles games series. The original Battletoads game for the NES was renowned for its extreme difficulty, but still received a cult following, spawning sequels for various platforms including a crossover with the Double Dragon series and a modern reboot after a 25-year gap in releases. In each of the games, the objective is to defeat the toads'' nemesis the Dark Queen and her army of space mutants.', 'https://media.retroachievements.org/Images/050770.png', 'https://media.retroachievements.org/Images/000556.png', 'https://media.retroachievements.org/Images/000553.png', 'https://media.retroachievements.org/Images/042715.png', 4.4),
  (51, 1373, 'RoboCop Versus The Terminator', 'Genesis/Mega Drive', 1, 3378, 3378, 3378, 32, 0, NULL, 'Virgin Interactive', 'Virgin Interactive', '1994-01-01', 'RoboCop Versus The Terminator is a run and gun game released for the Sega Genesis, Super Nintendo Entertainment System, Master System, and Game Gear in 1993, with a port to the Game Boy in 1994. It is based on the 1992 four-issue comic book mini-series of the same name, which is a crossover between the RoboCop and Terminator franchises. Despite their likenesses being shown on packaging, the actors who portrayed the titular characters did not reprise their roles in this game.', 'https://media.retroachievements.org/Images/077449.png', 'https://media.retroachievements.org/Images/009175.png', 'https://media.retroachievements.org/Images/009172.png', 'https://media.retroachievements.org/Images/009173.png', 4.4),
  (52, 140, 'Wonder Boy in Monster World', 'Genesis/Mega Drive', 1, 3365, 3365, 3365, 49, 0, 'Metroidvania', 'Westone', 'Sega', '1991-10-25', 'Wonder Boy in Monster World, known in Japan as Wonder Boy V: Monster World III, is a side-scrolling action role-playing game originally developed by Westone and published by Sega for the Mega Drive/Genesis in 1991. It is the fifth game in the Wonder Boy series and the third game in the Monster World sub-series, following Wonder Boy in Monster Land and Wonder Boy III: The Dragon''s Trap.', 'https://media.retroachievements.org/Images/034382.png', 'https://media.retroachievements.org/Images/001400.png', 'https://media.retroachievements.org/Images/001399.png', 'https://media.retroachievements.org/Images/001401.png', 4.4),
  (53, 14, 'Alien 3', 'Genesis/Mega Drive', 1, 3233, 3233, 3233, 44, 0, NULL, NULL, 'Acclaim', '1992-06-09', 'Alien 3 (stylized as ALIEN3) is a 1992 American science fiction horror film directed by David Fincher and written by David Giler, Walter Hill, and Larry Ferguson, from a story by Vincent Ward. Starring Sigourney Weaver reprising her role as Ellen Ripley, it is the third installment of the Alien franchise.', 'https://media.retroachievements.org/Images/055716.png', 'https://media.retroachievements.org/Images/051921.png', 'https://media.retroachievements.org/Images/001065.png', 'https://media.retroachievements.org/Images/001066.png', 4.4),
  (54, 82, 'Road Rash', 'Genesis/Mega Drive', 1, 3223, 3223, 3223, 24, 0, 'Arcade Racing', 'Electronic Arts', 'Electronic Arts', '1991-01-01', 'Road Rash is a motorcycle racing video game series by Electronic Arts in which the player participates in violent, illegal street races. The series started on the Sega Genesis/Mega Drive and was released on various other systems over the years. The game''s title is based on the slang term for the severe abrasive injuries that can occur in a motorcycle fall where skin comes into contact with the ground at high speed.', 'https://media.retroachievements.org/Images/077797.png', 'https://media.retroachievements.org/Images/001174.png', 'https://media.retroachievements.org/Images/001170.png', 'https://media.retroachievements.org/Images/001171.png', 4.4),
  (55, 22, 'ToeJam & Earl', 'Genesis/Mega Drive', 1, 3150, 3150, 3150, 56, 0, 'Roguelike', NULL, 'Sega', '1991-10-01', 'ToeJam & Earl is a 1991 action video game developed by Johnson Voorsanger Productions and published by Sega for the Genesis console. It centers on ToeJam and Earl—alien rappers who have crash-landed on Earth—as they attempt to escape the planet, players assume the role of either character and collect pieces of their wrecked spacecraft. It references and parodies 1980s and early-''90s urban culture and is set to a funk soundtrack. ToeJam & Earl''s design was heavily influenced by the role-playing video game Rogue (1980) and derived various features from the game, such as the random generation of levels and items. As such, ToeJam & Earl is often considered to be an example of a roguelike game.', 'https://media.retroachievements.org/Images/107617.png', 'https://media.retroachievements.org/Images/051939.png', 'https://media.retroachievements.org/Images/001217.png', 'https://media.retroachievements.org/Images/001218.png', 4.3),
  (56, 109, 'After Burner II', 'Genesis/Mega Drive', 1, 3092, 3092, 3092, 25, 0, NULL, 'Sega', 'Sega', '1990-03-23', 'After Burner II is an combat flight simulator released as an arcade video game by Sega in 1987. It is the second game in the After Burner series, and was released for the Sega X Board arcade system. In the game, players fly an F-14 Tomcat jet fighter, gunning down enemies while avoiding incoming fire. After Burner II came both a standard arcade cabinet and a servo actuated, sit-down motion simulator version which moved according to the motion of the plane onscreen. The cockpit would bank in the same direction the on-screen aircraft was banking. It is an updated version of After Burner, with the addition of throttle controls. It was a commercial success, becoming Japan''s highest-grossing arcade game of 1988.', 'https://media.retroachievements.org/Images/038433.png', 'https://media.retroachievements.org/Images/000271.png', 'https://media.retroachievements.org/Images/000268.png', 'https://media.retroachievements.org/Images/000269.png', 4.3),
  (57, 2182, 'Earthworm Jim 2', 'Genesis/Mega Drive', 1, 2989, 2989, 2989, 55, 0, NULL, 'Shiny Entertainment', 'Virgin Interactive', '1995-11-15', 'Earthworm Jim 2 is a 1995 run and gun platform game. It is the sequel to Earthworm Jim, and the second and final game in the Earthworm Jim series developed by original creators Doug TenNapel, David Perry, and Shiny Entertainment. It was released in late 1995 and early 1996 depending on the region and video game console, initially for the Sega Genesis and Super Nintendo Entertainment System, before being ported to other platforms.', 'https://media.retroachievements.org/Images/118354.png', 'https://media.retroachievements.org/Images/001525.png', 'https://media.retroachievements.org/Images/001523.png', 'https://media.retroachievements.org/Images/001524.png', 4.3),
  (58, 34, 'Rocket Knight Adventures', 'Genesis/Mega Drive', 1, 2958, 2958, 2958, 36, 0, '2D Platforming', 'Konami', 'Konami', '1993-01-01', 'Rocket Knight Adventures is a 1993 platform game developed and published by Konami for the Sega Genesis. The player controls Sparkster, a possum knight who wields a rocket pack and sword, who battles the evil Devotindos Empire.', 'https://media.retroachievements.org/Images/058017.png', 'https://media.retroachievements.org/Images/001184.png', 'https://media.retroachievements.org/Images/001181.png', 'https://media.retroachievements.org/Images/001182.png', 4.3),
  (59, 6, 'Desert Strike: Return to the Gulf', 'Genesis/Mega Drive', 1, 2948, 2948, 2948, 27, 0, NULL, NULL, NULL, '1992-03-01', 'Desert Strike: Return to the Gulf is a shoot ''em up video game released by Electronic Arts (EA) in 1992 for the Sega Genesis. The game was released on several other formats such as the Super Nintendo Entertainment System, including a much upgraded version for the Amiga home computer. The game was inspired by the Gulf War and depicts a conflict between an insane Middle Eastern dictator, General Kilbaba, and the United States. The player controls an Apache helicopter and attempts to destroy enemy weapons and installations, rescue hostages and capture enemy personnel, while managing supplies of fuel and ammunition.', 'https://media.retroachievements.org/Images/062615.png', 'https://media.retroachievements.org/Images/051874.png', 'https://media.retroachievements.org/Images/001106.png', 'https://media.retroachievements.org/Images/001107.png', 4.3),
  (60, 88, 'Golden Axe III', 'Genesis/Mega Drive', 1, 2945, 2945, 2945, 31, 0, 'Beat ''em Up', 'Sega', 'Sega', '1993-06-25', 'Golden Axe III is a 1993 beat ''em up game developed and published by Sega for the Sega Genesis. Originally exclusive to Japan, it was made available in North America via the Sega Channel online service in 1995. In this sequel to Golden Axe II, the player controls one of four warriors as they attempt to defeat the evil Damud Hellstrike, who has stolen the Golden Axe and kidnapped the princess of Yuria. Much like its predecessors, the game is based around side-scrolling levels where the player defeats enemies with their melee weapon or fists, while riding creatures known as Bizarrians, or through elemental magic. Several new offensive and defensive moves, like blocking and projectile attacks, can also be used.', 'https://media.retroachievements.org/Images/123486.png', 'https://media.retroachievements.org/Images/000308.png', 'https://media.retroachievements.org/Images/000309.png', 'https://media.retroachievements.org/Images/000311.png', 4.3),
  (61, 116, 'Mega Man: The Wily Wars', 'Genesis/Mega Drive', 1, 2816, 2816, 2816, 214, 0, '2D Platforming', 'Capcom', 'Capcom', '1994-10-21', 'Mega Man: The Wily Wars is a 1994 platform game compilation developed by Minakuchi Engineering and published by Capcom for the Sega Genesis; the compilation features remakes of the first three Mega Man games which were originally released on the Nintendo Entertainment System, alongside a new game called Wily Tower, only unlockable with a completed save file.', 'https://media.retroachievements.org/Images/120056.png', 'https://media.retroachievements.org/Images/002729.png', 'https://media.retroachievements.org/Images/002727.png', 'https://media.retroachievements.org/Images/002728.png', 4.3),
  (62, 16, 'Super Hang-On', 'Genesis/Mega Drive', 1, 2763, 2763, 2763, 21, 0, NULL, NULL, NULL, '1989-10-06', 'Super Hang-On is a 1987 racing video game developed and published by Sega for arcades. It is the sequel to 1985''s Hang-On, and uses a simulated motorcycle arcade cabinet, like the original game. An updated version was released for arcades as Limited Edition Hang-On in 1991.', 'https://media.retroachievements.org/Images/000860.png', 'https://media.retroachievements.org/Images/051933.png', 'https://media.retroachievements.org/Images/000712.png', 'https://media.retroachievements.org/Images/000713.png', 4.3),
  (63, 12, 'The Addams Family', 'Genesis/Mega Drive', 1, 2629, 2629, 2629, 69, 0, NULL, NULL, NULL, '1993-10-01', 'The Addams Family is a fictional family created by American cartoonist Charles Addams. The Addams are an eccentric old-money clan who delight in the macabre and the grotesque and are seemingly unaware or unconcerned that other people find them bizarre or frightening. The Addams'' view in seeing their family life and interests as normal was a basis for the satire and comedy. They originally appeared in a series of 150 standalone single-panel comics, about half of which were originally published in The New Yorker between 1938 and their creator''s death in 1988. They have since appeared in other media, such as television, film, video games, comic books, a musical, and merchandise.', 'https://media.retroachievements.org/Images/099515.png', 'https://media.retroachievements.org/Images/051919.png', 'https://media.retroachievements.org/Images/001049.png', 'https://media.retroachievements.org/Images/001050.png', 4.3),
  (64, 294, 'Mega Turrican', 'Genesis/Mega Drive', 1, 2625, 2625, 2625, 24, 0, NULL, 'Factor 5', 'Sony Imagesoft', '1994-06-07', 'Mega Turrican is a run and gun video game developed by Factor 5 in 1993 and published by Data East in 1994. Part of the Turrican series, it was released for the Mega Drive/Genesis, and later followed by an Amiga port converted by Kaiko and Neon Studios under the title of Turrican 3: Payment Day. Despite not being the original, the Amiga version was the one that was first commercially released in 1993, published by Rainbow Arts in Germany and Renegade in the rest of Europe. The Mega Drive version did not have a publisher and stayed unreleased from spring 1993 until 1994, when Data East took over its worldwide distribution. Data East itself released the game in North America, and contracted Sony Imagesoft for the game''s distribution in Europe.', 'https://media.retroachievements.org/Images/076399.png', 'https://media.retroachievements.org/Images/000351.png', 'https://media.retroachievements.org/Images/000347.png', 'https://media.retroachievements.org/Images/000348.png', 4.3),
  (65, 16210, 'Bare Knuckle III', 'Genesis/Mega Drive', 1, 2612, 2612, 2612, 48, 0, 'Beat ''em Up', 'Sega', 'Sega', '1994-03-01', 'Streets of Rage 3 is a 1994 beat ''em up game developed and published by Sega for the Genesis. It is the third installment of the Streets of Rage series and the last game in the original trilogy. The game includes several changes over Streets of Rage and Streets of Rage 2, such as a more complex plot, inclusion of character dialogue, longer levels, more in-depth scenarios and faster gameplay. Weapons can be integrated with unique moves with certain characters, hidden characters were added, and a few cutscenes were included to give the story greater depth.', 'https://media.retroachievements.org/Images/110828.png', 'https://media.retroachievements.org/Images/032984.png', 'https://media.retroachievements.org/Images/032981.png', 'https://media.retroachievements.org/Images/032982.png', 4.3),
  (66, 180, 'Battletoads and Double Dragon: The Ultimate Team', 'Genesis/Mega Drive', 1, 2482, 2482, 2482, 21, 0, 'Beat ''em Up', 'Rare', 'Tradewest', '1993-01-01', 'Battletoads/Double Dragon is a 1993 beat ''em up developed by Rare and published by Tradewest. It was originally released for the Nintendo Entertainment System and later ported to the Mega Drive/Genesis, Super NES, and Game Boy. The SNES version was released on the Nintendo Classics service in September 2024; it was the game''s first re-release as it was not released on the Rare Replay collection.', 'https://media.retroachievements.org/Images/053395.png', 'https://media.retroachievements.org/Images/001080.png', 'https://media.retroachievements.org/Images/001077.png', 'https://media.retroachievements.org/Images/001078.png', 4.3),
  (67, 36, 'Double Dragon', 'Genesis/Mega Drive', 1, 2455, 2455, 2455, 15, 0, 'Beat ''em Up', 'Technōs Japan', 'Taito', '1993-01-01', 'Double Dragon  is a beat ''em up video game series originally developed and published by Technōs Japan. It began with the release of the arcade game Double Dragon in 1987. The series features twin martial artists, Billy and Jimmy Lee, as they fight against various adversaries and rivals.', 'https://media.retroachievements.org/Images/055048.png', 'https://media.retroachievements.org/Images/050394.png', 'https://media.retroachievements.org/Images/004167.png', 'https://media.retroachievements.org/Images/000336.png', 4.3),
  (68, 119, 'Road Rash II', 'Genesis/Mega Drive', 1, 2415, 2415, 2415, 50, 0, 'Arcade racing', 'Electronic Arts', 'Electronic Arts', '1993-01-01', 'Road Rash is a motorcycle racing video game series by Electronic Arts in which the player participates in violent, illegal street races. The series started on the Sega Genesis/Mega Drive and was released on various other systems over the years. The game''s title is based on the slang term for the severe abrasive injuries that can occur in a motorcycle fall where skin comes into contact with the ground at high speed.', 'https://media.retroachievements.org/Images/006316.png', 'https://media.retroachievements.org/Images/001165.png', 'https://media.retroachievements.org/Images/001179.png', 'https://media.retroachievements.org/Images/001164.png', 4.3),
  (69, 2235, '~Hack~ Sonic the Hedgehog: Classic Heroes', 'Genesis/Mega Drive', 1, 2379, 2379, 2379, 42, 0, '2D Platforming', 'Flamewing, ColinC10', 'Hack - Sonic the Hedgehog 2', '2012-07-20', 'Sonic the Hedgehog is a Japanese video game series and media franchise created by the Japanese developers Yuji Naka, Naoto Ohshima, and Hirokazu Yasuhara for Sega. The franchise follows Sonic, an anthropomorphic blue hedgehog with supersonic speed, who battles the mad scientist Doctor Eggman and his robot army. The main Sonic the Hedgehog games are platformers mostly developed by Sonic Team; other games, developed by various studios, include spin-offs in the racing, fighting, party and sports genres. The franchise also incorporates printed media, animations, films, and merchandise.', 'https://media.retroachievements.org/Images/123772.png', 'https://media.retroachievements.org/Images/019963.png', 'https://media.retroachievements.org/Images/115472.png', 'https://media.retroachievements.org/Images/111810.png', 4.3),
  (70, 6718, 'Barney''s Hide and Seek Game', 'Genesis/Mega Drive', 1, 2352, 2352, 2352, 17, 0, 'Educational, 2D Platforming', 'Realtime Associates', 'Sega', '1993-06-01', 'Barney''s Hide & Seek Game is a 1993 licensed edutainment video game developed by Realtime Associates and published by Sega for the Sega Genesis exclusivly in North America. It was based on the children''s television series Barney & Friends. Educational concepts taught in the game include counting, matching, and problem solving. There is a self-play feature that guides the player to the objective without input from the player.', 'https://media.retroachievements.org/Images/042059.png', 'https://media.retroachievements.org/Images/015820.png', 'https://media.retroachievements.org/Images/015818.png', 'https://media.retroachievements.org/Images/015819.png', 4.3),
  (71, 4726, 'Trouble Shooter', 'Genesis/Mega Drive', 1, 2311, 2311, 2311, 27, 0, 'Shoot ''em Up', 'Vic Tokai', 'Vic Tokai', '1991-01-01', 'Trouble Shooter, originally released in Japan as Battle Mania, is a horizontally scrolling shooter developed and published by Vic Tokai for the Mega Drive/Genesis. It was released in November 1991 in North America and March 6, 1992 in Japan. It was directed by designer Fujito Takayan Takada, who at first was primarily responsible for every aspect of the game''s development due to a lack of support from Vic Tokai. Over time, however, more people joined the project, and he took on a supervisory role for much of the game''s design.', 'https://media.retroachievements.org/Images/078313.png', 'https://media.retroachievements.org/Images/048580.png', 'https://media.retroachievements.org/Images/048581.png', 'https://media.retroachievements.org/Images/002367.png', 4.3),
  (72, 65, 'Shining Force', 'Genesis/Mega Drive', 1, 2299, 2299, 2299, 70, 0, 'Tactical RPG', 'Camelot Software Planning', 'Sega', '1992-03-20', 'Shining Force: The Legacy of Great Intention, commonly referred to as Shining Force, is a 1992 turn-based tactical role-playing game developed by Climax Entertainment and Sonic! Software Planning and published by Sega for the Sega Genesis. It is the second entry of the Shining series, following 1991''s Shining in the Darkness. While primarily a traditional fantasy-themed game, it contains some science fiction elements.', 'https://media.retroachievements.org/Images/067488.png', 'https://media.retroachievements.org/Images/004187.png', 'https://media.retroachievements.org/Images/004188.png', 'https://media.retroachievements.org/Images/004189.png', 4.3),
  (73, 3108, 'Battle Mania Daiginjou', 'Genesis/Mega Drive', 1, 2223, 2223, 2223, 35, 0, 'Shoot ''em Up', 'Vic Tokai', 'Vic Tokai', '1993-12-24', 'Battle Mania Daiginjō is a 1993 horizontally scrolling shooter developed and published by Vic Tokai for the Mega Drive. It serves as a sequel to the original Battle Mania, which was released in North America under the title Trouble Shooter. Unlike the original Battle Mania, Daginjō was released exclusively for the Japanese and South Korean markets.', 'https://media.retroachievements.org/Images/119819.png', 'https://media.retroachievements.org/Images/002380.png', 'https://media.retroachievements.org/Images/070602.png', 'https://media.retroachievements.org/Images/002378.png', 4.3),
  (74, 156, 'Boogerman: A Pick and Flick Adventure', 'Genesis/Mega Drive', 1, 2128, 2128, 2128, 30, 0, '2D Platforming', 'Interplay Entertainment', 'Interplay Entertainment', '1994-11-18', 'Boogerman: A Pick and Flick Adventure is a 2D platform video game created by Interplay Productions and released for the Sega Genesis in 1994 and on the Super NES in 1995. The Genesis version was also released on the Wii Virtual Console in North America on November 24, 2008 and in Europe on December 12, 2008. The game''s lead character also appears as a playable character and the rival of Earthworm Jim in Interplay''s ClayFighter 63⅓.', 'https://media.retroachievements.org/Images/113925.png', 'https://media.retroachievements.org/Images/026861.png', 'https://media.retroachievements.org/Images/020615.png', 'https://media.retroachievements.org/Images/020616.png', 4.3),
  (75, 50, 'Phantasy Star IV: The End of the Millennium', 'Genesis/Mega Drive', 1, 2105, 2105, 2105, 93, 0, NULL, 'Sega', 'Sega', '1993-12-17', 'Phantasy Star IV: The End of the Millennium is a 1993 role-playing video game developed and published by Sega for the Sega Genesis. The fourth main installment in the Phantasy Star series, it is the final title in the original tetralogy and is currently the last traditional role-playing game in the franchise. The game''s plot follows the hunters Alys and Chaz, as well as their traveling party, attempting to stop an ecological crisis from destroying their solar system. Phantasy Star IV kept many of the gameplay elements of the previous game, including turn-based battles, overhead exploration, and magic spells. It received mixed reviews upon its release but now it is widely considered the greatest role-playing game ever made for the Sega Genesis and regarded as one of the greatest video games of all time.', 'https://media.retroachievements.org/Images/045807.png', 'https://media.retroachievements.org/Images/000642.png', 'https://media.retroachievements.org/Images/000639.png', 'https://media.retroachievements.org/Images/000640.png', 4.3),
  (76, 221, 'Dynamite Headdy', 'Genesis/Mega Drive', 1, 2088, 2088, 2088, 39, 0, '2D Platforming', 'Treasure', 'Sega', '1994-09-01', 'Ristar is a 1995 platform game developed and published by Sega for the Sega Genesis. The game stars an anthropomorphic cartoon star who uses his hands and long, stretchable arms to both move and fight enemies. Reception for the game was generally positive, but the game''s initial release was overshadowed due to the imminent ending of the Genesis''s lifecycle and the succession of the Sega Saturn and other fifth generation video game consoles.', 'https://media.retroachievements.org/Images/117781.png', 'https://media.retroachievements.org/Images/003528.png', 'https://media.retroachievements.org/Images/002798.png', 'https://media.retroachievements.org/Images/002799.png', 4.3),
  (77, 10229, 'Street Fighter II: Special Champion Edition', 'Genesis/Mega Drive', 1, 2079, 2079, 2079, 26, 0, '2D Fighting', 'Capcom', 'Capcom', '1993-09-18', 'Street Fighter II: Champion Edition, released as Street Fighter II Dash in Japan, is a 1992 fighting game developed and published by Capcom for arcades. It is the first of several updated versions of Street Fighter II (1991), and part of the Street Fighter series. The main changes are the addition of the four grand masters as playable characters and mirror matches. The fighting techniques of the eight main characters from the original game were further balanced for competitive play.', 'https://media.retroachievements.org/Images/115806.png', 'https://media.retroachievements.org/Images/050810.png', 'https://media.retroachievements.org/Images/014415.png', 'https://media.retroachievements.org/Images/014416.png', 4.3),
  (78, 295, 'Bishoujo Senshi Sailor Moon', 'Genesis/Mega Drive', 1, 2063, 2063, 2063, 13, 0, 'Beat ''em Up', 'Arc System Works, TNS', 'Ma-Ba', '1994-07-08', 'Sailor Moon  is a Japanese manga series written and illustrated by Naoko Takeuchi. It was originally serialized in Kodansha''s shōjo manga magazine Nakayoshi from 1991 to 1997; the 60 individual chapters and several side stories were compiled into 18 tankōbon volumes. Set in Tokyo in the 1990s, the series follows the adventures of a schoolgirl named Usagi Tsukino as she transforms into the eponymous character to search for a magical artifact, the Legendary Silver Crystal . She leads a group of comrades, the Sailor Soldiers, called Sailor Guardians in later editions, as they battle against villains to prevent the theft of the Silver Crystal and the destruction of the Solar System.', 'https://media.retroachievements.org/Images/068546.png', 'https://media.retroachievements.org/Images/000586.png', 'https://media.retroachievements.org/Images/000583.png', 'https://media.retroachievements.org/Images/000584.png', 4.3),
  (79, 26, 'Cool Spot', 'Genesis/Mega Drive', 1, 2035, 2035, 2035, 40, 0, '2D Platforming', 'Virgin Interactive', 'Virgin Interactive', '1994-02-18', 'Cool Spot is a 1993 platform game developed by Virgin Games for the Sega Genesis, Super Nintendo Entertainment System, Master System, Game Gear, Game Boy, Amiga, and MS-DOS. The title character is Spot, a mascot for the soft drink brand 7 Up. Spot''s appearance in his own video game came at a time when other brand mascots were appearing in their own video games.', 'https://media.retroachievements.org/Images/054362.png', 'https://media.retroachievements.org/Images/051943.png', 'https://media.retroachievements.org/Images/000466.png', 'https://media.retroachievements.org/Images/000467.png', 4.2),
  (80, 4247, 'Elemental Master', 'Genesis/Mega Drive', 1, 2014, 2014, 2014, 45, 0, 'Shoot ''em Up', 'Technosoft | Tecno Soft', 'Renovation Products', '1993-01-01', 'The Sega Genesis, known as the Mega Drive in regions outside of North America, is a 16-bit video game console that was designed and produced by Sega. First released in Japan on October 29, 1988, in North America on August 1989, and in PAL regions in 1990, the Genesis is Sega''s third console and the successor to the Master System. The system supports a library of 881 officially licensed games created both by Sega and a wide array of third-party publishers and delivered on ROM cartridges. It can also play Master System games when the separately sold Power Base Converter is installed. The Sega Genesis also sported numerous peripherals, including the Sega CD and 32X, several network services, and multiple first-party and third-party variations of the console that focused on extending its functionality. The console and its games continue to be popular among fans, collectors, video game music fans, and emulation enthusiasts. Licensed third party re-releases of the console are still being produced, and several indie game developers continue to produce games for it. Many games have also been re-released in compilations for newer consoles and offered for download on various digital distribution services, such as Virtual Console, Xbox Live Arcade, PlayStation Network, and Steam.', 'https://media.retroachievements.org/Images/110097.png', 'https://media.retroachievements.org/Images/004562.png', 'https://media.retroachievements.org/Images/005011.png', 'https://media.retroachievements.org/Images/005019.png', 4.2),
  (81, 4, 'Zero Tolerance', 'Genesis/Mega Drive', 1, 1989, 1989, 1989, 95, 0, 'First-Person Shooter', 'Technopop', 'Accolade', '1994-10-01', 'A zero-tolerance policy is one which imposes a punishment for every infraction of a stated rule. Zero-tolerance policies forbid people in positions of authority from exercising discretion or changing punishments to fit the circumstances subjectively; they are required to impose a predetermined punishment regardless of individual culpability, extenuating circumstances, or history. This predetermined punishment, whether mild or severe, is always meted out.', 'https://media.retroachievements.org/Images/064502.png', 'https://media.retroachievements.org/Images/051873.png', 'https://media.retroachievements.org/Images/001227.png', 'https://media.retroachievements.org/Images/002230.png', 4.2),
  (82, 501, 'DEcapAttack', 'Genesis/Mega Drive', 1, 1984, 1984, 1984, 109, 0, NULL, 'Vic Tokai', 'Sega', '1991-09-01', 'The Sega Genesis, known as the Mega Drive in regions outside of North America, is a 16-bit video game console that was designed and produced by Sega. First released in Japan on October 29, 1988, in North America on August 1989, and in PAL regions in 1990, the Genesis is Sega''s third console and the successor to the Master System. The system supports a library of 881 officially licensed games created both by Sega and a wide array of third-party publishers and delivered on ROM cartridges. It can also play Master System games when the separately sold Power Base Converter is installed. The Sega Genesis also sported numerous peripherals, including the Sega CD and 32X, several network services, and multiple first-party and third-party variations of the console that focused on extending its functionality. The console and its games continue to be popular among fans, collectors, video game music fans, and emulation enthusiasts. Licensed third party re-releases of the console are still being produced, and several indie game developers continue to produce games for it. Many games have also been re-released in compilations for newer consoles and offered for download on various digital distribution services, such as Virtual Console, Xbox Live Arcade, PlayStation Network, and Steam.', 'https://media.retroachievements.org/Images/043814.png', 'https://media.retroachievements.org/Images/000323.png', 'https://media.retroachievements.org/Images/000320.png', 'https://media.retroachievements.org/Images/000321.png', 4.2),
  (83, 170, 'Columns III: Revenge of Columns', 'Genesis/Mega Drive', 1, 1974, 1974, 1974, 45, 0, NULL, 'Minato Giken', 'Vic Tokai', '1993-10-15', 'Columns III: Revenge of Columns  is a puzzle arcade game published by Sega in Japan in 1993 and by Vic Tokai in North America in 1994 as a sequel to Columns II: The Voyage Through Time.', 'https://media.retroachievements.org/Images/121630.png', 'https://media.retroachievements.org/Images/007915.png', 'https://media.retroachievements.org/Images/020629.png', 'https://media.retroachievements.org/Images/020628.png', 4.2),
  (84, 80, 'X-Men 2: Clone Wars', 'Genesis/Mega Drive', 1, 1951, 1951, 1951, 42, 0, 'Beat ''em Up', 'Headgames', 'Sega', '1995-01-01', 'X-Men 2: Clone Wars is a 1995 2D action-platformer video game developed by Headgames and released by Sega of America for the Mega Drive/Genesis as a sequel to the 1993''s X-Men. The game is based on the adventures of the Marvel Comics superhero team, the X-Men. A sequel, titled X-Women, was cancelled.', 'https://media.retroachievements.org/Images/024366.png', 'https://media.retroachievements.org/Images/015001.png', 'https://media.retroachievements.org/Images/009188.png', 'https://media.retroachievements.org/Images/009186.png', 4.2),
  (85, 2367, 'Valis', 'Genesis/Mega Drive', 1, 1932, 1932, 1932, 51, 0, 'Action', 'Telenet Japan', 'Sega', '1991-12-27', 'The Sega Genesis, known as the Mega Drive in regions outside of North America, is a 16-bit video game console that was designed and produced by Sega. First released in Japan on October 29, 1988, in North America on August 1989, and in PAL regions in 1990, the Genesis is Sega''s third console and the successor to the Master System. The system supports a library of 881 officially licensed games created both by Sega and a wide array of third-party publishers and delivered on ROM cartridges. It can also play Master System games when the separately sold Power Base Converter is installed. The Sega Genesis also sported numerous peripherals, including the Sega CD and 32X, several network services, and multiple first-party and third-party variations of the console that focused on extending its functionality. The console and its games continue to be popular among fans, collectors, video game music fans, and emulation enthusiasts. Licensed third party re-releases of the console are still being produced, and several indie game developers continue to produce games for it. Many games have also been re-released in compilations for newer consoles and offered for download on various digital distribution services, such as Virtual Console, Xbox Live Arcade, PlayStation Network, and Steam.', 'https://media.retroachievements.org/Images/042685.png', 'https://media.retroachievements.org/Images/001465.png', 'https://media.retroachievements.org/Images/001462.png', 'https://media.retroachievements.org/Images/001463.png', 4.2),
  (86, 19, 'Ghostbusters', 'Genesis/Mega Drive', 1, 1929, 1929, 1929, 58, 0, '2D Platforming', 'Compile', 'Sega', '1990-06-30', 'Ghostbusters is a 1984 American supernatural comedy film directed by Ivan Reitman and written by Dan Aykroyd and Harold Ramis. It stars Bill Murray, Aykroyd, and Ramis as Peter Venkman, Ray Stantz, and Egon Spengler, three eccentric parapsychologists who start a ghost-catching business in New York City. It also stars Sigourney Weaver and Rick Moranis, and features Annie Potts, Ernie Hudson, and William Atherton in supporting roles.', 'https://media.retroachievements.org/Images/050351.png', 'https://media.retroachievements.org/Images/000847.png', 'https://media.retroachievements.org/Images/050330.png', 'https://media.retroachievements.org/Images/050331.png', 4.2),
  (87, 125, 'Show do Milhão', 'Genesis/Mega Drive', 1, 1926, 1926, 1926, 21, 0, 'Game Show', 'Tectoy', 'Tectoy', '2001-01-01', 'The Sega Genesis, known as the Mega Drive in regions outside of North America, is a 16-bit video game console that was designed and produced by Sega. First released in Japan on October 29, 1988, in North America on August 1989, and in PAL regions in 1990, the Genesis is Sega''s third console and the successor to the Master System. The system supports a library of 881 officially licensed games created both by Sega and a wide array of third-party publishers and delivered on ROM cartridges. It can also play Master System games when the separately sold Power Base Converter is installed. The Sega Genesis also sported numerous peripherals, including the Sega CD and 32X, several network services, and multiple first-party and third-party variations of the console that focused on extending its functionality. The console and its games continue to be popular among fans, collectors, video game music fans, and emulation enthusiasts. Licensed third party re-releases of the console are still being produced, and several indie game developers continue to produce games for it. Many games have also been re-released in compilations for newer consoles and offered for download on various digital distribution services, such as Virtual Console, Xbox Live Arcade, PlayStation Network, and Steam.', 'https://media.retroachievements.org/Images/024734.png', 'https://media.retroachievements.org/Images/023478.png', 'https://media.retroachievements.org/Images/014537.png', 'https://media.retroachievements.org/Images/014538.png', 4.2),
  (88, 70, 'Ultimate Mortal Kombat 3', 'Genesis/Mega Drive', 1, 1922, 1922, 1922, 43, 0, '2D Fighting', 'Avalanche Software', 'Acclaim, Williams Entertainment', '1995-01-01', 'Ultimate Mortal Kombat 3 is a 1995 fighting game developed and published by Midway for arcades. Part of the Mortal Kombat series, it is a standalone update of 1995''s earlier Mortal Kombat 3 with an altered gameplay system and some new features, as well as additional characters like the returning favorites Reptile, Kitana, Jade and Scorpion, who were missing from Mortal Kombat 3.', 'https://media.retroachievements.org/Images/105572.png', 'https://media.retroachievements.org/Images/081473.png', 'https://media.retroachievements.org/Images/081475.png', 'https://media.retroachievements.org/Images/081485.png', 4.2),
  (89, 67, 'Splatterhouse 3', 'Genesis/Mega Drive', 1, 1914, 1914, 1914, 32, 0, 'Beat ''em Up', 'Now Production', 'Namco', '1993-03-19', 'Splatterhouse is a 1988 beat ''em up video game developed and published by Namco for Japanese arcades. It was the first in a series of games released in home console and personal computer formats. This game would later spawn the parody Splatterhouse: Wanpaku Graffiti, the sequels Splatterhouse 2, Splatterhouse 3, and the 2010 remake Splatterhouse, with the classic games being added to Namco Museum since 2017.', 'https://media.retroachievements.org/Images/048187.png', 'https://media.retroachievements.org/Images/006036.png', 'https://media.retroachievements.org/Images/006033.png', 'https://media.retroachievements.org/Images/006034.png', 4.2),
  (90, 1438, 'Crusader of Centy', 'Genesis/Mega Drive', 1, 1885, 1885, 1885, 79, 0, 'Action RPG', 'Nex Entertainment', 'Atlus', '1994-06-17', 'The Sega Genesis, known as the Mega Drive in regions outside of North America, is a 16-bit video game console that was designed and produced by Sega. First released in Japan on October 29, 1988, in North America on August 1989, and in PAL regions in 1990, the Genesis is Sega''s third console and the successor to the Master System. The system supports a library of 881 officially licensed games created both by Sega and a wide array of third-party publishers and delivered on ROM cartridges. It can also play Master System games when the separately sold Power Base Converter is installed. The Sega Genesis also sported numerous peripherals, including the Sega CD and 32X, several network services, and multiple first-party and third-party variations of the console that focused on extending its functionality. The console and its games continue to be popular among fans, collectors, video game music fans, and emulation enthusiasts. Licensed third party re-releases of the console are still being produced, and several indie game developers continue to produce games for it. Many games have also been re-released in compilations for newer consoles and offered for download on various digital distribution services, such as Virtual Console, Xbox Live Arcade, PlayStation Network, and Steam.', 'https://media.retroachievements.org/Images/064348.png', 'https://media.retroachievements.org/Images/004921.png', 'https://media.retroachievements.org/Images/004946.png', 'https://media.retroachievements.org/Images/004947.png', 4.2),
  (91, 574, 'The Punisher', 'Genesis/Mega Drive', 1, 1815, 1815, 1815, 30, 0, 'Beat ''em Up', 'Capcom', 'Capcom', '1995-02-01', 'The Sega Genesis, known as the Mega Drive in regions outside of North America, is a 16-bit video game console that was designed and produced by Sega. First released in Japan on October 29, 1988, in North America on August 1989, and in PAL regions in 1990, the Genesis is Sega''s third console and the successor to the Master System. The system supports a library of 881 officially licensed games created both by Sega and a wide array of third-party publishers and delivered on ROM cartridges. It can also play Master System games when the separately sold Power Base Converter is installed. The Sega Genesis also sported numerous peripherals, including the Sega CD and 32X, several network services, and multiple first-party and third-party variations of the console that focused on extending its functionality. The console and its games continue to be popular among fans, collectors, video game music fans, and emulation enthusiasts. Licensed third party re-releases of the console are still being produced, and several indie game developers continue to produce games for it. Many games have also been re-released in compilations for newer consoles and offered for download on various digital distribution services, such as Virtual Console, Xbox Live Arcade, PlayStation Network, and Steam.', 'https://media.retroachievements.org/Images/064882.png', 'https://media.retroachievements.org/Images/015476.png', 'https://media.retroachievements.org/Images/009212.png', 'https://media.retroachievements.org/Images/009213.png', 4.2),
  (92, 226, 'Arrow Flash', 'Genesis/Mega Drive', 1, 1787, 1787, 1787, 20, 0, 'Shoot ''em Up', 'ITL', 'Renovation Products, Sega', '1990-10-20', 'Arrow Flash  is a horizontally scrolling shooter video game developed by I.T.L and published by Sega in Japan and Europe and by Renovation Products in the United States for the Mega Drive / Genesis in 1990. The game''s main character pilots a prototype transformable fighter-mecha left from her grandfather to fight against an alien attack on humankind. The game is mostly a horizontal shooter, with one down scrolling stage.', 'https://media.retroachievements.org/Images/049213.png', 'https://media.retroachievements.org/Images/004328.png', 'https://media.retroachievements.org/Images/070037.png', 'https://media.retroachievements.org/Images/004327.png', 4.2),
  (93, 587, 'Zero Wing', 'Genesis/Mega Drive', 1, 1779, 1779, 1779, 34, 0, 'Shoot ''em Up', 'Toaplan', 'Toaplan, Sega', '1991-05-31', 'Zero Wing is a 1989 horizontally scrolling shooter video game developed by Toaplan and published by Namco for Japanese arcades; in North America, it was distributed by Williams Electronics. Controlling the ZIG space fighter craft, players assume the role of protagonist Trent in a last-ditch effort to overthrow the alien space pirate organization CATS. It was the eighth shoot ''em up game from Toaplan, and their fourteenth video game overall.', 'https://media.retroachievements.org/Images/113701.png', 'https://media.retroachievements.org/Images/009226.png', 'https://media.retroachievements.org/Images/103482.png', 'https://media.retroachievements.org/Images/103483.png', 4.2),
  (94, 583, 'Snow Bros.: Nick & Tom', 'Genesis/Mega Drive', 1, 1778, 1778, 1778, 11, 0, '2D Platforming', 'Toaplan', 'Tengen', '1993-05-28', 'Snow Bros. is a 1990 platform video game developed and published by Toaplan for Japanese arcades; it was distributed by Romstar in North America and Europe. Players control snowman twins Nick and Tom as they travel through 50 stages, using snowballs as weapons while navigating obstacles and battling monsters in order to rescue the princesses Puripuri and Puchipuchi. The game was later ported to multiple platforms, each one by different third-party developers and featuring several changes or additions. Versions for various microcomputers were in development, but were never officially released.', 'https://media.retroachievements.org/Images/064810.png', 'https://media.retroachievements.org/Images/117391.png', 'https://media.retroachievements.org/Images/000643.png', 'https://media.retroachievements.org/Images/000644.png', 4.2),
  (95, 60, 'Mortal Kombat II', 'Genesis/Mega Drive', 1, 1777, 1777, 1777, 35, 0, '2D Fighting', 'Probe Entertainment', 'Acclaim', '1994-09-09', 'Mortal Kombat II is a 1993 fighting game developed and published by Midway for arcades. It was later ported to multiple home systems, including MS-DOS, Amiga, Game Boy, Game Gear, Sega Genesis, 32X, Sega Saturn, Super NES, and PlayStation, by Probe Software and Sculptured Software, and published by Acclaim Entertainment.', 'https://media.retroachievements.org/Images/054556.png', 'https://media.retroachievements.org/Images/011786.png', 'https://media.retroachievements.org/Images/011789.png', 'https://media.retroachievements.org/Images/011790.png', 4.2),
  (96, 2364, 'Gargoyles', 'Genesis/Mega Drive', 1, 1747, 1747, 1747, 37, 0, '2D Platforming', 'Disney Interactive Studios', 'Disney Interactive Studios', '1995-05-15', 'The Sega Genesis, known as the Mega Drive in regions outside of North America, is a 16-bit video game console that was designed and produced by Sega. First released in Japan on October 29, 1988, in North America on August 1989, and in PAL regions in 1990, the Genesis is Sega''s third console and the successor to the Master System. The system supports a library of 881 officially licensed games created both by Sega and a wide array of third-party publishers and delivered on ROM cartridges. It can also play Master System games when the separately sold Power Base Converter is installed. The Sega Genesis also sported numerous peripherals, including the Sega CD and 32X, several network services, and multiple first-party and third-party variations of the console that focused on extending its functionality. The console and its games continue to be popular among fans, collectors, video game music fans, and emulation enthusiasts. Licensed third party re-releases of the console are still being produced, and several indie game developers continue to produce games for it. Many games have also been re-released in compilations for newer consoles and offered for download on various digital distribution services, such as Virtual Console, Xbox Live Arcade, PlayStation Network, and Steam.', 'https://media.retroachievements.org/Images/049829.png', 'https://media.retroachievements.org/Images/009332.png', 'https://media.retroachievements.org/Images/017953.png', 'https://media.retroachievements.org/Images/017954.png', 4.2),
  (97, 289, 'Last Battle', 'Genesis/Mega Drive', 1, 1702, 1702, 1702, 30, 0, 'Beat ''em Up', 'Sega', 'Sega', '1989-01-01', 'Last Battle: Legend of the Final Hero is a side-scrolling martial arts beat ''em up released for the Mega Drive/Genesis in 1989 by Sega. It was one of the six games that were available as part of the Genesis launch lineup in the U.S. The Japanese version, titled Hokuto no Ken: Shinseikimatsu Kyūseishu Densetsu , is based on the manga and anime series Fist of the North Star. Since the international version did not retain the Hokuto no Ken license, the graphics and characters'' names were altered. It was the second Hokuto no Ken game released by Sega, following the Mark III original, released internationally as Black Belt. Versions for the Commodore 64 and Amiga based upon Last Battle were developed and released by Elite in Europe in 1991.', 'https://media.retroachievements.org/Images/064828.png', 'https://media.retroachievements.org/Images/028720.png', 'https://media.retroachievements.org/Images/001143.png', 'https://media.retroachievements.org/Images/001144.png', 4.2),
  (98, 1404, 'Steel Empire', 'Genesis/Mega Drive', 1, 1702, 1702, 1702, 26, 0, 'Shoot ''em Up', 'HOT B', 'HOT B, Flying Edge', '1992-03-13', 'Steel Empire is a horizontally scrolling shooter released on the Sega Genesis in 1992. Versions for the Game Boy Advance and Nintendo 3DS were released in 2004 and 2014, respectively. The game was released on the Nintendo Switch at the end of July 2025.', 'https://media.retroachievements.org/Images/073608.png', 'https://media.retroachievements.org/Images/000267.png', 'https://media.retroachievements.org/Images/000105.png', 'https://media.retroachievements.org/Images/000106.png', 4.2),
  (99, 4228, 'Devil Crash MD', 'Genesis/Mega Drive', 1, 1667, 1667, 1667, 39, 0, 'Pinball', 'Technosoft | Tecno Soft', 'Tengen', '1991-10-10', 'The Sega Genesis, known as the Mega Drive in regions outside of North America, is a 16-bit video game console that was designed and produced by Sega. First released in Japan on October 29, 1988, in North America on August 1989, and in PAL regions in 1990, the Genesis is Sega''s third console and the successor to the Master System. The system supports a library of 881 officially licensed games created both by Sega and a wide array of third-party publishers and delivered on ROM cartridges. It can also play Master System games when the separately sold Power Base Converter is installed. The Sega Genesis also sported numerous peripherals, including the Sega CD and 32X, several network services, and multiple first-party and third-party variations of the console that focused on extending its functionality. The console and its games continue to be popular among fans, collectors, video game music fans, and emulation enthusiasts. Licensed third party re-releases of the console are still being produced, and several indie game developers continue to produce games for it. Many games have also been re-released in compilations for newer consoles and offered for download on various digital distribution services, such as Virtual Console, Xbox Live Arcade, PlayStation Network, and Steam.', 'https://media.retroachievements.org/Images/061849.png', 'https://media.retroachievements.org/Images/017233.png', 'https://media.retroachievements.org/Images/017232.png', 'https://media.retroachievements.org/Images/017231.png', 4.2),
  (100, 1426, 'Burning Force', 'Genesis/Mega Drive', 1, 1606, 1606, 1606, 40, 0, 'Rail Shooter', 'Namco', 'Namco', '1990-01-01', 'Burning Force is a 1989 third-person shooter arcade game developed and published by Namco in Japan. A home conversion for the Sega Genesis was released worldwide a year later. The player assumes control of the woman space cadet Hiromi Tengenji, a pilot training to become a member of the Space Force, who must complete each level by shooting down enemies with her airbike and avoiding projectiles. Gameplay is similar to Space Harrier, featuring a fixed camera position behind the player and having similar mechanics. It runs on the Namco System 2 arcade hardware.', 'https://media.retroachievements.org/Images/033988.png', 'https://media.retroachievements.org/Images/008388.png', 'https://media.retroachievements.org/Images/008383.png', 'https://media.retroachievements.org/Images/008384.png', 4.2),
  (101, 15387, '~Homebrew~ Xeno Crisis', 'Genesis/Mega Drive', 1, 1595, 1595, 1595, 54, 0, 'Twin Stick Shooter', 'Bitmap Bureau', 'Homebrew - Genesis/Mega Drive', '2019-10-28', 'Xeno Crisis is a 2019 multidirectional shooter homebrew video game developed and published by Bitmap Bureau for the Sega Mega Drive/Genesis, Linux, macOS, Microsoft Windows, Nintendo Switch, PlayStation 4, and Xbox One. It was later ported to Dreamcast, PlayStation Vita, Neo Geo, Neo Geo CD, Nintendo 64, GameCube, Super Nintendo Entertainment System, and Game Boy Advance. The premise takes place in Outpost 88, a scientific research facility overrun by aliens. The facility sent a distress signal, leading Commander Darius dispatching space marines John Marsh and Sarah Ridley to confront the aliens. Gameplay revolves around players defeating enemies, rescuing survivors, collecting in-game currency for upgrades, and facing against bosses.', 'https://media.retroachievements.org/Images/043219.png', 'https://media.retroachievements.org/Images/043220.png', 'https://media.retroachievements.org/Images/043217.png', 'https://media.retroachievements.org/Images/043218.png', 4.2),
  (102, 59, 'Flicky', 'Genesis/Mega Drive', 1, 1591, 1591, 1591, 20, 0, NULL, 'Sega', 'Sega', '1991-01-01', 'Flicky is a platform game developed by Sega and released as an arcade video game in May 1984. It was licensed to Bally Midway for distribution in the United States. In Flicky, the player controls the eponymous blue bird and must gather all the small birds called Chirps in each round and bring them safely to the exit. There are cat and lizard enemies which can disperse the Chirps and kill the player, but Flicky can use items on the playing field to protect herself and the Chirps from danger.', 'https://media.retroachievements.org/Images/110362.png', 'https://media.retroachievements.org/Images/111743.png', 'https://media.retroachievements.org/Images/000767.png', 'https://media.retroachievements.org/Images/000768.png', 4.2),
  (103, 4123, 'Bonanza Bros.', 'Genesis/Mega Drive', 1, 1566, 1566, 1566, 27, 0, 'Stealth', 'Sega', 'Sega', '1991-05-17', 'Bonanza Bros. is a 3D-style, 2D side-scrolling stealth action game developed and released by Sega in 1990. It is one of the earliest arcade games powered by the Sega System 24 arcade system board. It was ported to various home systems, including the Mega Drive/Genesis, Master System, PC-Engine/TurboGrafx-CD, and several home computers.', 'https://media.retroachievements.org/Images/064552.png', 'https://media.retroachievements.org/Images/001977.png', 'https://media.retroachievements.org/Images/001974.png', 'https://media.retroachievements.org/Images/001975.png', 4.2),
  (104, 52, 'Super Street Fighter II: The New Challengers', 'Genesis/Mega Drive', 1, 1558, 1558, 1558, 24, 0, '2D Fighting', 'Capcom', 'Capcom', '1994-06-25', 'Super Street Fighter II: The New Challengers is a 1993 fighting game developed and published by Capcom for arcades. It is the fourth game in the Street Fighter II sub-series of Street Fighter games, following Street Fighter II Turbo (1992). It refines and balances the existing character roster from the previous versions, and introduces four new characters, including Fei Long, Cammy, T. Hawk, and Dee Jay. It is the first game on Capcom''s CP System II hardware, with more sophisticated graphics and audio over the original CP System hardware used in previous versions of Street Fighter II.', 'https://media.retroachievements.org/Images/119922.png', 'https://media.retroachievements.org/Images/000630.png', 'https://media.retroachievements.org/Images/000627.png', 'https://media.retroachievements.org/Images/000628.png', 4.2),
  (105, 99, 'Fatal Labyrinth', 'Genesis/Mega Drive', 1, 1554, 1554, 1554, 89, 0, 'Roguelike', 'Sega', 'Sega', '1990-11-21', 'Fatal Labyrinth, titled Shi no Meikyuu: Labyrinth of Death (死の迷宮) in Japan, is a 1990 roguelike role-playing video game developed and published by Sega for the Sega Genesis. Originally available exclusively on the Sega Meganet multiplayer gaming service in Japan, it was later released physically in 1991. The game is similar to and shares assets with Dragon Crystal, which was released around that time.', 'https://media.retroachievements.org/Images/046427.png', 'https://media.retroachievements.org/Images/046426.png', 'https://media.retroachievements.org/Images/005217.png', 'https://media.retroachievements.org/Images/005218.png', 4.2),
  (106, 4102, 'Aero the Acro-Bat', 'Genesis/Mega Drive', 1, 1549, 1549, 1549, 85, 0, '2D Platforming', 'Iguana Entertainment', 'Sunsoft', '1993-08-01', 'Aero the Acro-Bat is a 1993 platform video game developed by Iguana Entertainment and published by Sunsoft for the Super Nintendo Entertainment System and Sega Genesis. Aero the Acro-Bat, a red anthropomorphic bat, was created by David Siller. In 2002, Metro 3D released a version of the game for the Game Boy Advance, with a battery back-up. The GBA version was titled Aero The Acro-Bat - Rascal Rival Revenge in Europe and Acrobat Kid in Japan. The Super NES version of the game was released on the Wii''s Virtual Console in the PAL region and North America in July 2010. In 2024, the Super NES version was re-released in August for Nintendo Switch, PlayStation 4, PlayStation 5, Xbox One, and Xbox Series X/S, alongside a new localization in Japanese made by Shinyuden as Aero: Acrobat Kid for the Nintendo Switch users in Japan, while the GBA version was re-released for the same platforms in November.', 'https://media.retroachievements.org/Images/039587.png', 'https://media.retroachievements.org/Images/033704.png', 'https://media.retroachievements.org/Images/033702.png', 'https://media.retroachievements.org/Images/033703.png', 4.2),
  (107, 536, 'Super Smash T.V.', 'Genesis/Mega Drive', 1, 1542, 1542, 1542, 14, 0, 'Twin Stick Shooter', 'Probe Entertainment', 'Flying Edge', '1992-01-01', 'Smash TV is a 1990 twin-stick shooter video game developed and published by Williams Electronics for arcades. It was designed by Eugene Jarvis and programmed by Mark Turmell, with similar gameplay to Jarvis'' earlier game Robotron: 2084 (1982). The Super Nintendo Entertainment System, Sega Genesis, Master System and Game Gear versions are titled Super Smash TV.', 'https://media.retroachievements.org/Images/110681.png', 'https://media.retroachievements.org/Images/001209.png', 'https://media.retroachievements.org/Images/001206.png', 'https://media.retroachievements.org/Images/001207.png', 4.2),
  (108, 290, 'Captain America and the Avengers', 'Genesis/Mega Drive', 1, 1534, 1534, 1534, 11, 0, 'Beat ''em Up', 'Data East', 'Mindscape', '1992-01-01', 'Captain America and the Avengers is a 1991 beat ''em up video game developed and published by Data East for arcades. It features the Avengers team of Marvel Comics characters in a side-scrolling brawling and shooting adventure to defeat the evil Red Skull. The game received ports for the Sega Genesis/Mega Drive, Super Nintendo Entertainment System, Game Boy and Game Gear. A different Data East game was released for the Nintendo Entertainment System.', 'https://media.retroachievements.org/Images/057420.png', 'https://media.retroachievements.org/Images/001093.png', 'https://media.retroachievements.org/Images/001090.png', 'https://media.retroachievements.org/Images/001091.png', 4.2),
  (109, 262, 'Wonder Boy III: Monster Lair', 'Genesis/Mega Drive', 1, 1534, 1534, 1534, 29, 0, NULL, 'Westone', 'Sega', '1990-12-22', 'Wonder Boy III: Monster Lair  is a 1988 platform game developed by Westone and published by Sega for arcades. It is the third game in the Wonder Boy series and the last one released for arcades. A console adaptation was made by Hudson Soft and released in 1989 in Japan for the PC Engine CD-ROM² System; the subsequent North American release on the TurboGrafx-CD dropped the Wonder Boy III title. It was also converted and released by Sega for the Mega Drive in Japan in 1990 and Europe in 1991. Both the TurboGrafx-CD and Mega Drive versions were later re-released for the Wii Virtual Console.', 'https://media.retroachievements.org/Images/055398.png', 'https://media.retroachievements.org/Images/005273.png', 'https://media.retroachievements.org/Images/005271.png', 'https://media.retroachievements.org/Images/005272.png', 4.2),
  (110, 240, 'Truxton', 'Genesis/Mega Drive', 1, 1531, 1531, 1531, 31, 0, 'Shoot ''em Up', 'Toaplan', 'Taito, Romstar, Midway', '1989-12-09', 'Truxton is a 1988 vertically scrolling shooter video game developed by Toaplan and published by Taito for Japanese and European arcades; in North America, it was distributed by Midway. It is set in a future where the Gidans alien race, led by Dogurava, have invaded the fictional planet Borogo. Players assume the role of fighter pilot Tatsuo taking control of the Super Fighter ship on a last-ditch effort to overthrow the alien invaders.', 'https://media.retroachievements.org/Images/078315.png', 'https://media.retroachievements.org/Images/006114.png', 'https://media.retroachievements.org/Images/006112.png', 'https://media.retroachievements.org/Images/006113.png', 4.2),
  (111, 4239, 'DUNE: The Battle for Arrakis', 'Genesis/Mega Drive', 1, 1526, 1526, 1526, 51, 0, 'Real-Time Strategy', NULL, 'Virgin Interactive', '1993-01-01', 'Dune II: The Building of a Dynasty is a 1992 real-time strategy game developed by Westwood Studios and published by Virgin Games. It serves as the sequel to Dune, which came out earlier that same year.', 'https://media.retroachievements.org/Images/062625.png', 'https://media.retroachievements.org/Images/056130.png', 'https://media.retroachievements.org/Images/017959.png', 'https://media.retroachievements.org/Images/017960.png', 4.2),
  (112, 2545, 'Mickey Mania: The Timeless Adventures of Mickey Mouse', 'Genesis/Mega Drive', 1, 1522, 1522, 1522, 20, 0, '2D Platforming', 'Traveller''s Tales', 'Sony Imagesoft', '1994-01-01', 'Mickey Mania: The Timeless Adventures of Mickey Mouse is a 1994 platform video game developed by Traveller''s Tales and published by Sony Imagesoft for the Super NES, Sega Genesis, and Sega CD. In the game, the player controls Mickey Mouse, who must navigate through various side-scrolling levels, each designed and based on classic Mickey Mouse cartoons.', 'https://media.retroachievements.org/Images/087830.png', 'https://media.retroachievements.org/Images/004723.png', 'https://media.retroachievements.org/Images/004724.png', 'https://media.retroachievements.org/Images/004725.png', 4.2),
  (113, 75, 'Shining Force II', 'Genesis/Mega Drive', 1, 1516, 1516, 1516, 98, 0, 'Tactical RPG', 'Climax Entertainment, Camelot Software Planning', 'Sega', '1993-10-01', 'Shining Force II  is a 1993 tactical role-playing game developed by Sonic! Software Planning and published by Sega for the Sega Genesis. Its storyline is not directly connected to the original Shining Force, although the Game Gear title Shining Force Gaiden: Final Conflict links the two games'' plots. The game is much longer than Shining Force, and contains more free roaming. There is no chapter system, so the player can return to previously visited parts of the world. There are also two different ways of promoting certain characters.', 'https://media.retroachievements.org/Images/067487.png', 'https://media.retroachievements.org/Images/000174.png', 'https://media.retroachievements.org/Images/000173.png', 'https://media.retroachievements.org/Images/000090.png', 4.2),
  (114, 2439, 'Gaiares', 'Genesis/Mega Drive', 1, 1504, 1504, 1504, 29, 0, 'Shoot ''em Up', 'Telenet Japan', 'Renovation Products', '1990-01-01', 'Gaiares  is a horizontally scrolling shooter developed by Telenet Japan and published by Renovation for the Sega Genesis in 1990. It was one of the first 8Mb cartridge games on the Genesis. Its title combined Gaia and the suffix less (Res), as the Earth has been lost to pollution in the far future according to the game''s plot.', 'https://media.retroachievements.org/Images/063167.png', 'https://media.retroachievements.org/Images/007912.png', 'https://media.retroachievements.org/Images/029700.png', 'https://media.retroachievements.org/Images/029699.png', 4.2),
  (115, 3684, 'Advanced Busterhawk: Gley Lancer', 'Genesis/Mega Drive', 1, 1495, 1495, 1495, 44, 0, 'Shoot ''em Up', NULL, NULL, '1992-07-17', 'Gley Lancer is a 1992 scrolling shooter video game originally developed by NCS Corporation, published in Japan by Masaya and in South Korea by Samsung for the Sega Mega Drive/Genesis. It was re-released in 2019 by Japanese publisher Columbus Circle. It follows Lucia Cabrock, daughter of Earth Federation Navy admiral Ken, who disappeared while fighting in a war between humans and an unknown alien race that possess the ability to teleport, joined by her friend Teim on a journey to save her father by stealing a starfighter. Controlling the titular fighter ship, the player must fight waves of enemies and bosses, while avoiding collision with their projectiles and other obstacles. The Gley Lancer ship is equipped with two satellites options, whose positions and formations are determined by the player.', 'https://media.retroachievements.org/Images/020895.png', 'https://media.retroachievements.org/Images/050812.png', 'https://media.retroachievements.org/Images/004954.png', 'https://media.retroachievements.org/Images/004968.png', 4.2),
  (116, 205, '~Hack~ Sonic the Hedgehog: Megamix', 'Genesis/Mega Drive', 1, 1490, 1490, 1490, 18, 0, '2D Platforming', 'Team Megamix', 'Hack - Sonic the Hedgehog', '2005-11-15', 'Sonic the Hedgehog is a Japanese video game series and media franchise created by the Japanese developers Yuji Naka, Naoto Ohshima, and Hirokazu Yasuhara for Sega. The franchise follows Sonic, an anthropomorphic blue hedgehog with supersonic speed, who battles the mad scientist Doctor Eggman and his robot army. The main Sonic the Hedgehog games are platformers mostly developed by Sonic Team; other games, developed by various studios, include spin-offs in the racing, fighting, party and sports genres. The franchise also incorporates printed media, animations, films, and merchandise.', 'https://media.retroachievements.org/Images/123774.png', 'https://media.retroachievements.org/Images/003772.png', 'https://media.retroachievements.org/Images/003769.png', 'https://media.retroachievements.org/Images/003770.png', 4.2),
  (117, 166, 'Road Rash 3: Tour de Force', 'Genesis/Mega Drive', 1, 1487, 1487, 1487, 22, 0, 'Racing', 'Electronic Arts', 'Electronic Arts', '1995-05-15', 'The Sega Genesis, known as the Mega Drive in regions outside of North America, is a 16-bit video game console that was designed and produced by Sega. First released in Japan on October 29, 1988, in North America on August 1989, and in PAL regions in 1990, the Genesis is Sega''s third console and the successor to the Master System. The system supports a library of 881 officially licensed games created both by Sega and a wide array of third-party publishers and delivered on ROM cartridges. It can also play Master System games when the separately sold Power Base Converter is installed. The Sega Genesis also sported numerous peripherals, including the Sega CD and 32X, several network services, and multiple first-party and third-party variations of the console that focused on extending its functionality. The console and its games continue to be popular among fans, collectors, video game music fans, and emulation enthusiasts. Licensed third party re-releases of the console are still being produced, and several indie game developers continue to produce games for it. Many games have also been re-released in compilations for newer consoles and offered for download on various digital distribution services, such as Virtual Console, Xbox Live Arcade, PlayStation Network, and Steam.', 'https://media.retroachievements.org/Images/077798.png', 'https://media.retroachievements.org/Images/001178.png', 'https://media.retroachievements.org/Images/001175.png', 'https://media.retroachievements.org/Images/001176.png', 4.2),
  (118, 225, 'Turbo OutRun', 'Genesis/Mega Drive', 1, 1467, 1467, 1467, 24, 0, 'Arcade Racing', NULL, 'Sega', '1992-03-27', 'Turbo OutRun (ターボアウトラン) is a 1989 racing game developed and published by Sega for arcades. A follow-up to 1986''s Out Run, it was released as a dedicated game, as well as an upgrade kit for the original Out Run board. Like its predecessor, Turbo OutRun has players driving a Ferrari, this time a Ferrari F40. Players traverse a set route across the continental United States from New York City to Los Angeles. In addition to a time limit, Turbo OutRun also adds a computer-controlled opponent driving a Porsche 959. The Turbo in the title plays a factor as players can press a button to receive a brief turbo boost of speed. Various power-ups which increase the vehicle''s attributes can be chosen at various stages of the game.', 'https://media.retroachievements.org/Images/072199.png', 'https://media.retroachievements.org/Images/005361.png', 'https://media.retroachievements.org/Images/001803.png', 'https://media.retroachievements.org/Images/001804.png', 4.2),
  (119, 4418, 'Rock n'' Roll Racing', 'Genesis/Mega Drive', 1, 1464, 1464, 1464, 41, 0, 'Racing', 'Silicon & Synapse', 'Interplay Entertainment', '1994-01-01', 'Rock n'' Roll Racing is a vehicular combat-based racing video game developed by Silicon & Synapse and published by Interplay Productions for the Super Nintendo Entertainment System in 1993 and the Mega Drive/Genesis in 1994. The game prominently features a number of popular heavy metal and rock songs in its soundtrack, hence the game''s title. After Silicon & Synapse rebranded into Blizzard Entertainment, a port to the Game Boy Advance was released in 2003. In celebration of the company''s 30th anniversary, a new version titled Definitive Edition alongside emulated re-releases of the original game were re-released for Nintendo Switch, PlayStation 4, Windows, and Xbox One as part of the Blizzard Arcade Collection in February 2021.', 'https://media.retroachievements.org/Images/052342.png', 'https://media.retroachievements.org/Images/006317.png', 'https://media.retroachievements.org/Images/006318.png', 'https://media.retroachievements.org/Images/006326.png', 4.2),
  (120, 143, 'Beyond Oasis', 'Genesis/Mega Drive', 1, 1463, 1463, 1463, 33, 0, 'Action RPG', 'Ancient', 'Sega', '1994-12-09', 'Beyond Oasis is a 1994 action-adventure game developed by Ancient and published by Sega for the Sega Genesis. The game has also been re-released in various emulated collections. A prequel to the game, The Legend of Oasis, was released for the Sega Saturn in 1996.', 'https://media.retroachievements.org/Images/054047.png', 'https://media.retroachievements.org/Images/001085.png', 'https://media.retroachievements.org/Images/001081.png', 'https://media.retroachievements.org/Images/001082.png', 4.2),
  (121, 11185, '~Hack~ Sonic 3D Blast: Director''s Cut', 'Genesis/Mega Drive', 1, 1416, 1416, 1416, 50, 0, '2.5D Platforming', 'Jon Burton', 'Hack - Sonic 3D Blast', '2017-12-23', 'Sonic 3D Blast, known in regions outside North America as Sonic 3D: Flickies'' Island, is a 1996 platform game in the Sonic the Hedgehog series for the Sega Genesis and Sega Saturn. As Sonic the Hedgehog, the player embarks on a journey to save the Flickies, birds enslaved by Doctor Robotnik. The player must guide Sonic through a series of themed levels to collect Flickies and defeat Robotnik. Though it retains game mechanics from prior Sonic games, Sonic 3D Blast is differentiated by its 2D isometric perspective, with pre-rendered 3D models converted into sprites.', 'https://media.retroachievements.org/Images/109358.png', 'https://media.retroachievements.org/Images/015262.png', 'https://media.retroachievements.org/Images/120741.png', 'https://media.retroachievements.org/Images/120742.png', 4.2),
  (122, 178, 'Mighty Morphin Power Rangers', 'Genesis/Mega Drive', 1, 1389, 1389, 1389, 53, 0, '2D Fighting', 'Banpresto', 'Sega', '1994-01-01', 'Mighty Morphin Power Rangers (MMPR) is an American superhero television series produced by Saban Entertainment, which aired from August 28, 1993 to November 27, 1995, on the Fox Kids programming block, lasting three seasons. The series drew elements and stock footage from Super Sentai, a Japanese television series by Toei Company. Each season was inspired by Kyoryu Sentai Zyuranger, Gosei Sentai Dairanger, and Ninja Sentai Kakuranger, respectively. The series is the first entry of the Power Rangers franchise.', 'https://media.retroachievements.org/Images/043830.png', 'https://media.retroachievements.org/Images/010954.png', 'https://media.retroachievements.org/Images/010948.png', 'https://media.retroachievements.org/Images/010949.png', 4.2),
  (123, 4169, 'Bio-Hazard Battle', 'Genesis/Mega Drive', 1, 1386, 1386, 1386, 31, 0, 'Shoot ''em Up', 'Sega', 'Sega', '1992-10-30', 'Bio-Hazard Battle, released in Japan as Crying: Aseimei Sensou , is a 1992 scrolling shooter released for the Sega Genesis and Sega Mega Play arcade platform. It was made available on the Wii''s Virtual Console in February 2007. The game was also re-released on the Steam platform in October 2010. An unreleased X68000 version exists currently under ownership of M2 CEO Naoki Horii.', 'https://media.retroachievements.org/Images/047715.png', 'https://media.retroachievements.org/Images/047716.png', 'https://media.retroachievements.org/Images/047717.png', 'https://media.retroachievements.org/Images/047718.png', 4.2),
  (124, 571, 'Midnight Resistance', 'Genesis/Mega Drive', 1, 1380, 1380, 1380, 27, 0, NULL, 'Data East', 'Sega', '1991-03-29', 'Midnight Resistance  is a side-scrolling run and gun game produced by Data East and released in arcades in 1989. Midnight Resistance is set in a dystopian future where the player controls a member of a resistance movement who goes on a mission to rescue his kidnapped family from a drug kingpin.', 'https://media.retroachievements.org/Images/047930.png', 'https://media.retroachievements.org/Images/047852.png', 'https://media.retroachievements.org/Images/000296.png', 'https://media.retroachievements.org/Images/000297.png', 4.2),
  (125, 46, 'Atomic Runner', 'Genesis/Mega Drive', 1, 1373, 1373, 1373, 33, 0, NULL, 'Data East', 'Data East', '1992-10-16', 'Fighter''s History: Mizoguchi Kiki Ippatsu!! is a 1995 fighting game developed and published by Data East for the Super Famicom. It is the third game in the Fighter''s History series, and the last one published by Data East. The gameplay system is largely unchanged from its predecessor, Karnov''s Revenge, but a few new additions made it to the game, including a new game mode where Mizoguchi is the protagonist, and the new character Chelnov, the hero of Data East''s action game Atomic Runner Chelnov.', 'https://media.retroachievements.org/Images/049849.png', 'https://media.retroachievements.org/Images/088601.png', 'https://media.retroachievements.org/Images/001073.png', 'https://media.retroachievements.org/Images/001074.png', 4.2),
  (126, 302, 'ESWAT: City Under Siege', 'Genesis/Mega Drive', 1, 1368, 1368, 1368, 42, 0, NULL, 'Sega', 'Sega', '1990-10-01', 'ESWAT: City Under Siege, released in Japan as Cyber Police ESWAT , is a 1990 action-platform video game developed and published by Sega for the Sega Genesis and Master System. It is based on the arcade game Cyber Police ESWAT, released a year earlier in 1989. The console game maintains the main characters, plot and some of its enemies from the arcade game, but features some different levels, weapons, and bonuses.', 'https://media.retroachievements.org/Images/009455.png', 'https://media.retroachievements.org/Images/000232.png', 'https://media.retroachievements.org/Images/000229.png', 'https://media.retroachievements.org/Images/000230.png', 4.2),
  (127, 176, 'Marble Madness', 'Genesis/Mega Drive', 1, 1360, 1360, 1360, 19, 0, 'Action/Puzzle', 'Atari, Electronic Arts', 'Electronic Arts', '1991-11-01', 'Marble Madness is a 1984 platform game designed by Mark Cerny and published by Atari Games Inc. for arcades. Set in an isometric perspective, the game tasks the player with guiding a marble through six courses, populated with obstacles and enemies, within a time limit. The player controls the marble by using a trackball. Marble Madness is known for using innovative game technologies: it was Atari''s first to use the Atari System 1 hardware, the first to be programmed in the C programming language, and one of the first to use true stereo sound.', 'https://media.retroachievements.org/Images/044625.png', 'https://media.retroachievements.org/Images/020638.png', 'https://media.retroachievements.org/Images/020636.png', 'https://media.retroachievements.org/Images/020637.png', 4.2),
  (128, 31, 'Fantastic Dizzy', 'Genesis/Mega Drive', 1, 1315, 1315, 1315, 31, 0, 'Action-Adventure, 2D Platforming', 'Codemasters', 'Camerica', '1993-09-21', 'Fantastic Dizzy is a 1991 video game developed by Codemasters. It is part of the Dizzy series. It was published on several platforms, including Mega Drive/Genesis, Master System, Game Gear, Nintendo Entertainment System, Amiga, and MS-DOS.', 'https://media.retroachievements.org/Images/000400.png', 'https://media.retroachievements.org/Images/051951.png', 'https://media.retroachievements.org/Images/105334.png', 'https://media.retroachievements.org/Images/105335.png', 4.1),
  (129, 25, 'Vectorman', 'Genesis/Mega Drive', 1, 1281, 1281, 1281, 47, 0, NULL, 'BlueSky Software', 'Sega', '1995-10-25', 'Vectorman is a 2D action platformer video game developed by BlueSky Software and published by Sega. The game was released for the Sega Genesis in late 1995 in North America and Europe. It was considered a critical and commercial success, achieving its dual goal of retaining interest in the aging Sega Genesis platform in face of the increasingly popular new technology of the next generation of video game consoles and providing competition to industry competitor Nintendo''s popular Donkey Kong Country video game. In subsequent decades, the game was re-released across many Sega-themed video game compilations, and on its own across the Wii Virtual Console, Steam, Sega Forever, and Nintendo Classics digital platforms. A sequel, Vectorman 2, was released in 1996, but despite several abandoned attempts at making a Vectorman 3, no further games have been released.', 'https://media.retroachievements.org/Images/025038.png', 'https://media.retroachievements.org/Images/051942.png', 'https://media.retroachievements.org/Images/000557.png', 'https://media.retroachievements.org/Images/000558.png', 4.1),
  (130, 807, 'Jurassic Park: Rampage Edition', 'Genesis/Mega Drive', 1, 1273, 1273, 1273, 38, 0, 'Action', 'BlueSky Software', 'Sega', '1994-10-01', 'Jurassic Park: Rampage Edition is a 1994 action-platform video game developed by BlueSky Software and published by Sega for the Sega Genesis. It is the sequel to Sega''s previous Jurassic Park video game, based on the 1993 film of the same name and also released for the Genesis. Rampage Edition is a revamped version of its predecessor, featuring similar gameplay with several changes, and a new story that continues from where the previous game ended.', 'https://media.retroachievements.org/Images/022748.png', 'https://media.retroachievements.org/Images/022747.png', 'https://media.retroachievements.org/Images/022746.png', 'https://media.retroachievements.org/Images/022745.png', 4.1),
  (131, 4266, 'The Great Waldo Search', 'Genesis/Mega Drive', 1, 1268, 1268, 1268, 12, 0, 'Hidden Object', 'Radiance Software', 'THQ', '1992-06-01', 'Where''s Wally? The Fantastic Journey is the third Where''s Wally? book, first released in 1989. In the book Wally travels to fantasy lands in search of Wizard Whitebeard''s magical scrolls. The book introduces the second recurring Where''s Wally character, Wizard Whitebeard. Readers are also asked for the first time to find the Wizard''s scrolls.', 'https://media.retroachievements.org/Images/113710.png', 'https://media.retroachievements.org/Images/065255.png', 'https://media.retroachievements.org/Images/112235.png', 'https://media.retroachievements.org/Images/112236.png', 4.1),
  (132, 4237, 'Dragon''s Revenge', 'Genesis/Mega Drive', 1, 1264, 1264, 1264, 25, 0, 'Pinball', 'Tengen', 'Tengen', '1993-12-10', 'Dragon''s Revenge (ドラゴンズ・リベンジ) is a pinball video game by Tengen, released for Sega Genesis in 1993. It is a follow-up to Devil''s Crush, a pinball game set in sword and sorcery scenario, wherein the player has to defeat a dragon and a witch. The game was released to generally positive reviews.', 'https://media.retroachievements.org/Images/027512.png', 'https://media.retroachievements.org/Images/056129.png', 'https://media.retroachievements.org/Images/004817.png', 'https://media.retroachievements.org/Images/004818.png', 4.1),
  (133, 4521, 'Yuu Yuu Hakusho: Makyo Toitsusen', 'Genesis/Mega Drive', 1, 1262, 1262, 1262, 33, 0, '2D Fighting', 'Treasure', 'Treasure, Tectoy', '1994-01-01', 'There are numerous video games based on the YuYu Hakusho manga and anime series created by Yoshihiro Togashi. The Japanese name of the series is romanized as Yū Yū Hakusho and the anime is officially titled Yu Yu Hakusho in North America. The games primarily revolve around the protagonist Yusuke Urameshi, a delinquent junior high school student who is killed while trying to save a young boy from being hit by a car. Yusuke is brought back to life and is promptly given the task of solving cases involving ghosts and demons in the human world.', 'https://media.retroachievements.org/Images/067622.png', 'https://media.retroachievements.org/Images/005853.png', 'https://media.retroachievements.org/Images/005851.png', 'https://media.retroachievements.org/Images/005852.png', 4.1),
  (134, 1360, 'The Flintstones', 'Genesis/Mega Drive', 1, 1255, 1255, 1255, 21, 0, '2D Platforming', 'Taito', 'Taito', '1993-10-22', 'The Flintstones is an American animated sitcom produced by Hanna-Barbera Productions. It was originally broadcast on ABC from September 30, 1960, to April 1, 1966 as the first animated series with a prime-time slot on television, as well as the first animated sitcom. The series takes place in a romanticized Stone Age setting and follows the lives of the titular Fred and Wilma Flintstone and their pet dinosaur, Dino, along with the saber-toothed cat Baby Puss, and Fred and Wilma''s eventual baby girl Pebbles. It also focuses on the Flintstones'' neighbors and best friends Barney and Betty Rubble, and later their adopted baby boy Bamm-Bamm and pet hopparoo (kangaroo) Hoppy.', 'https://media.retroachievements.org/Images/123952.png', 'https://media.retroachievements.org/Images/001131.png', 'https://media.retroachievements.org/Images/010290.png', 'https://media.retroachievements.org/Images/000110.png', 4.1),
  (135, 305, 'Toki: Going Ape Spit', 'Genesis/Mega Drive', 1, 1238, 1238, 1238, 29, 0, '2D Platforming', 'Santos', 'Sega', '1991-01-01', 'The Sega Genesis, known as the Mega Drive in regions outside of North America, is a 16-bit video game console that was designed and produced by Sega. First released in Japan on October 29, 1988, in North America on August 1989, and in PAL regions in 1990, the Genesis is Sega''s third console and the successor to the Master System. The system supports a library of 881 officially licensed games created both by Sega and a wide array of third-party publishers and delivered on ROM cartridges. It can also play Master System games when the separately sold Power Base Converter is installed. The Sega Genesis also sported numerous peripherals, including the Sega CD and 32X, several network services, and multiple first-party and third-party variations of the console that focused on extending its functionality. The console and its games continue to be popular among fans, collectors, video game music fans, and emulation enthusiasts. Licensed third party re-releases of the console are still being produced, and several indie game developers continue to produce games for it. Many games have also been re-released in compilations for newer consoles and offered for download on various digital distribution services, such as Virtual Console, Xbox Live Arcade, PlayStation Network, and Steam.', 'https://media.retroachievements.org/Images/116531.png', 'https://media.retroachievements.org/Images/009930.png', 'https://media.retroachievements.org/Images/020671.png', 'https://media.retroachievements.org/Images/020672.png', 4.1),
  (136, 7682, '~Homebrew~ CrazyBus', 'Genesis/Mega Drive', 1, 1215, 1215, 1215, 13, 0, 'Racing', 'Tom Scripts', 'Devster Specialties', '2005-09-09', 'Crazy Bus is a 2004 unlicensed bus simulator video game. Originally created as a tech demo, it was subsequently put on a ROM cartridge and published by an unauthorized 3rd party for the Sega Genesis. The game was developed by Venezuelan game developer Tom Maneiro under the alias Tom Scripts.', 'https://media.retroachievements.org/Images/089846.png', 'https://media.retroachievements.org/Images/010175.png', 'https://media.retroachievements.org/Images/007933.png', 'https://media.retroachievements.org/Images/007934.png', 4.1),
  (137, 51, 'Bubsy in Claws Encounters of the Furred Kind', 'Genesis/Mega Drive', 1, 1204, 1204, 1204, 20, 0, '2D Platforming', 'Accolade', 'Al Baker & Associates', '1993-07-01', 'Bubsy in: Claws Encounters of the Furred Kind, often shortened to Bubsy, is a 1993 platform game developed and published by Accolade for the Super Nintendo Entertainment System. A port to the Sega Genesis was released months later. It is the first entry in the Bubsy series of video games. The game''s title is a play on words in reference to the film Close Encounters of the Third Kind, with the game revolving around Bubsy defending the planet''s supply of yarn balls from alien invaders.', 'https://media.retroachievements.org/Images/117696.png', 'https://media.retroachievements.org/Images/116809.png', 'https://media.retroachievements.org/Images/103133.png', 'https://media.retroachievements.org/Images/000502.png', 4.1),
  (138, 2348, 'Super Fantasy Zone', 'Genesis/Mega Drive', 1, 1192, 1192, 1192, 45, 0, 'Shoot ''em Up', 'Sunsoft', 'Sega', '1992-01-14', 'Super Fantasy Zone  is a 1992 scrolling shooter video game developed and published by Sunsoft for the Mega Drive. Part of Sega''s Fantasy Zone series, it was released only in Japan and Europe. Players control the character Opa-Opa on his quest to defeat Dark Menon, and the game plays similarly to previous Fantasy Zone entries. The game plays similarly to Defender, where the screen scrolls in the direction that Opa-Opa is going. The player shoots at enemies to defeat them, collecting gold coins that are used to purchase temporary upgrades that improve Opa-Opa''s offensive capabilities and speed, among other things.', 'https://media.retroachievements.org/Images/066090.png', 'https://media.retroachievements.org/Images/001422.png', 'https://media.retroachievements.org/Images/001419.png', 'https://media.retroachievements.org/Images/001420.png', 4.1),
  (139, 4270, 'Frogger', 'Genesis/Mega Drive', 1, 1190, 1190, 1190, 21, 0, 'Arcade', 'Morning Star Multimedia', 'Majesco Entertainment', '1998-01-01', 'Frogger is a 1981 action video game developed by Konami and published by Sega for arcades. It was released in North America by Sega/Gremlin. The object of the game is to direct five frogs to their homes by dodging traffic on a busy road, then crossing a river by jumping on floating logs, turtles, and alligators.', 'https://media.retroachievements.org/Images/073195.png', 'https://media.retroachievements.org/Images/073418.png', 'https://media.retroachievements.org/Images/015124.png', 'https://media.retroachievements.org/Images/015125.png', 4.1),
  (140, 1443, 'Vectorman 2', 'Genesis/Mega Drive', 1, 1188, 1188, 1188, 38, 0, NULL, 'BlueSky Software', 'Sega', '1996-11-08', 'Vectorman 2 is a 1996 action-platform video game developed by BlueSky Software and published by Sega for the Sega Genesis. Released a year after the original Vectorman, the game retains the game''s core gameplay while expanding its mechanics. Multiple attempts to create a Vectorman 3 were proposed to Sega, with none of them coming to fruition.', 'https://media.retroachievements.org/Images/046319.png', 'https://media.retroachievements.org/Images/017479.png', 'https://media.retroachievements.org/Images/017478.png', 'https://media.retroachievements.org/Images/017480.png', 4.1),
  (141, 5902, 'Side Pocket', 'Genesis/Mega Drive', 1, 1171, 1171, 1171, 16, 0, 'Sports - Billiards', 'Data East', 'Data East', '1992-01-01', 'Side Pocket is a pocket billiards simulation released as an arcade video game by Data East in 1986. It was ported to the Nintendo Entertainment System and Game Boy, while an enhanced remake was later released on the Sega Genesis, Super Nintendo Entertainment System, and Game Gear. The game spawned two sequels, as well as arcade spin-off series titled Pocket Gal.', 'https://media.retroachievements.org/Images/077460.png', 'https://media.retroachievements.org/Images/007527.png', 'https://media.retroachievements.org/Images/009224.png', 'https://media.retroachievements.org/Images/009225.png', 4.1),
  (142, 12933, 'Pac-Mania', 'Genesis/Mega Drive', 1, 1168, 1168, 1168, 60, 0, 'Maze Chase', 'Namco', 'Tengen', '1991-01-01', 'Pac-Mania is a 1987 maze video game developed and published by Namco for Japanese arcades; it was licensed to Atari Games for release in North America. In the game, the player controls Pac-Man as he must eat all of the dots while avoiding the colored ghosts that chase him in the maze. Eating large flashing Power Pellets will allow Pac-Man to eat the ghosts for bonus points, which lasts for a short period of time. A new feature to this game allows Pac-Man to jump over the ghosts to evade capture. It is the ninth title in the Pac-Man video game series and was the last one developed for arcades up until the release of Pac-Man Arrangement in 1996. Development was directed by Pac-Man creator Tōru Iwatani.', 'https://media.retroachievements.org/Images/099195.png', 'https://media.retroachievements.org/Images/050647.png', 'https://media.retroachievements.org/Images/050391.png', 'https://media.retroachievements.org/Images/050392.png', 4.1),
  (143, 313, 'The Immortal', 'Genesis/Mega Drive', 1, 1168, 1168, 1168, 19, 0, 'CRPG', 'Electronic Arts', 'Electronic Arts', '1993-08-09', 'The Immortal is an isometric action-adventure game created by Will Harvey and released by Electronic Arts in 1990 for the Apple IIGS. It was ported to the Amiga, Atari ST, MS-DOS, Nintendo Entertainment System, and Genesis. A wizard is attempting to find his mentor in a large and dangerous labyrinth. The game has a high degree of graphic violence.', 'https://media.retroachievements.org/Images/063208.png', 'https://media.retroachievements.org/Images/009928.png', 'https://media.retroachievements.org/Images/009940.png', 'https://media.retroachievements.org/Images/009941.png', 4.1),
  (144, 303, 'Mercs', 'Genesis/Mega Drive', 1, 1141, 1141, 1141, 22, 0, NULL, 'Sega', 'Sega', '1991-09-27', 'Mercs, released as Senjō no Ōkami II in Japan, is a 1990 run and gun video game developed and published by Capcom for arcades. It is a sequel to the 1985 arcade video game Commando. While not as successful as its predecessor, Mercs was well received by critics and was a moderate commercial success. It was followed by Wolf of the Battlefield: Commando 3 in 2008, a downloadable game.', 'https://media.retroachievements.org/Images/064450.png', 'https://media.retroachievements.org/Images/051185.png', 'https://media.retroachievements.org/Images/051184.png', 'https://media.retroachievements.org/Images/051183.png', 4.1),
  (145, 4462, 'Chase H.Q. II', 'Genesis/Mega Drive', 1, 1140, 1140, 1140, 29, 0, 'Racing', 'ITL', 'Taito', '1992-10-23', 'Special Criminal Investigation, also known as S.C.I. for short or as Chase HQ II: Special Criminal Investigation in some home versions, is a 1989 vehicular combat racing game developed and published by Taito for arcades. It is the sequel to the 1988 game Chase H.Q.', 'https://media.retroachievements.org/Images/054933.png', 'https://media.retroachievements.org/Images/054916.png', 'https://media.retroachievements.org/Images/054917.png', 'https://media.retroachievements.org/Images/054918.png', 4.1),
  (146, 1436, 'Phantasy Star II', 'Genesis/Mega Drive', 1, 1134, 1134, 1134, 69, 0, 'Turn-Based RPG', 'Sega', 'Sega', '1990-03-01', 'Phantasy Star II is a science fantasy role-playing video game developed and published by Sega for the Sega Genesis. It was released in Japan in 1989 and North America and Europe in 1990. It was later ported to a variety of different platforms. An updated remake, Phantasy Star Generation 2, was released for the PlayStation 2 in 2005 in Japan.', 'https://media.retroachievements.org/Images/076388.png', 'https://media.retroachievements.org/Images/014323.png', 'https://media.retroachievements.org/Images/007993.png', 'https://media.retroachievements.org/Images/008539.png', 4.1),
  (147, 126, 'Show do Milhão: Volume 2', 'Genesis/Mega Drive', 1, 1130, 1130, 1130, 14, 0, 'Game Show', 'Tectoy', 'Tectoy', '2002-01-01', 'The Sega Genesis, known as the Mega Drive in regions outside of North America, is a 16-bit video game console that was designed and produced by Sega. First released in Japan on October 29, 1988, in North America on August 1989, and in PAL regions in 1990, the Genesis is Sega''s third console and the successor to the Master System. The system supports a library of 881 officially licensed games created both by Sega and a wide array of third-party publishers and delivered on ROM cartridges. It can also play Master System games when the separately sold Power Base Converter is installed. The Sega Genesis also sported numerous peripherals, including the Sega CD and 32X, several network services, and multiple first-party and third-party variations of the console that focused on extending its functionality. The console and its games continue to be popular among fans, collectors, video game music fans, and emulation enthusiasts. Licensed third party re-releases of the console are still being produced, and several indie game developers continue to produce games for it. Many games have also been re-released in compilations for newer consoles and offered for download on various digital distribution services, such as Virtual Console, Xbox Live Arcade, PlayStation Network, and Steam.', 'https://media.retroachievements.org/Images/024873.png', 'https://media.retroachievements.org/Images/044541.png', 'https://media.retroachievements.org/Images/014735.png', 'https://media.retroachievements.org/Images/014736.png', 4.1),
  (148, 349, 'Spider-Man & Venom: Maximum Carnage', 'Genesis/Mega Drive', 1, 1112, 1112, 1112, 29, 0, 'Beat ''em Up', 'Software Creations', 'Acclaim', '1994-09-16', 'Spider-Man and Venom: Maximum Carnage is a 1994 beat ''em up video game developed by Software Creations and published by Acclaim Entertainment and its subsidiary LJN for the Super Nintendo Entertainment System and Sega Genesis. The game, based on the comic book story arc of the same name, features numerous heroes, including Spider-Man, Venom, and their allies from the Marvel Comics fictional universe like Captain America, Black Cat, Iron Fist, Cloak and Dagger, Deathlok, Morbius and Firestar, all teaming up to battle an onslaught of villains led by Carnage, including Shriek, Doppelganger, Demogoblin and Carrion.', 'https://media.retroachievements.org/Images/071510.png', 'https://media.retroachievements.org/Images/071511.png', 'https://media.retroachievements.org/Images/020689.png', 'https://media.retroachievements.org/Images/020690.png', 4.1),
  (149, 230, 'Phelios', 'Genesis/Mega Drive', 1, 1099, 1099, 1099, 50, 0, 'Shoot ''em Up', 'Namco', 'Namco', '1990-07-20', 'Phelios is a 1989 arcade scrolling shooter video game developed and published by Namco exclusively in Japan. Loosely based on elements from Greek mythology, it follows the sun god Apollo, mounted atop the winged horse Pegasus, fighting through various locales as they attempt to rescue the moon goddess Artemis from the titan Typhon. The gameplay is based around a series of vertically scrolling levels, which are split up into sections and contain enemies and bosses that must be dealt with in order to progress. Additionally, players can charge up their shots in order to deal more damage to foes.', 'https://media.retroachievements.org/Images/004945.png', 'https://media.retroachievements.org/Images/095886.png', 'https://media.retroachievements.org/Images/004943.png', 'https://media.retroachievements.org/Images/004944.png', 4.1),
  (150, 4148, 'The Jungle Book', 'Genesis/Mega Drive', 1, 1078, 1078, 1078, 31, 0, '2D Platforming', 'Eurocom, Virgin Interactive', 'Virgin Interactive', '1994-07-01', 'The Jungle Book is an 1894 collection of stories by the English author Rudyard Kipling. Most of the characters are animals such as Shere Khan the tiger and Baloo the bear, though a principal character is the boy or man-cub Mowgli, who is raised in the jungle by wolves. Most stories are set in a forest in India; one place mentioned repeatedly is Seeonee (Seoni), in the central state of Madhya Pradesh.', 'https://media.retroachievements.org/Images/025711.png', 'https://media.retroachievements.org/Images/005207.png', 'https://media.retroachievements.org/Images/005209.png', 'https://media.retroachievements.org/Images/005208.png', 4.1),
  (151, 2268, 'Valis III', 'Genesis/Mega Drive', 1, 1073, 1073, 1073, 43, 0, 'Action', 'Telenet Japan', 'Sega, Renovation', '1991-03-22', 'Valis III is a 1990 action-platform video game originally developed by Laser Soft, published by Telenet Japan and NEC for the TurboGrafx-CD. A Sega Genesis version was released in 1991. It is the third entry in the Valis series. It stars Yuko Asou, a Japanese teenage schoolgirl chosen as the Valis warrior and wielder of the mystical Valis sword after the events of Valis II. King Glames, wielder of the sword Leethus, leads denizens of the dark world to conquer both Vecanti and Earth, seeking refuge for his people amid the destruction of their planet. Together with the demon warrior-maiden Cham and her sister Valna, Yuko must prevent Glames from destroying both worlds. Through the journey, the player explores and searches for items and power-ups while fighting enemies and defeating bosses.', 'https://media.retroachievements.org/Images/039835.png', 'https://media.retroachievements.org/Images/001418.png', 'https://media.retroachievements.org/Images/001415.png', 'https://media.retroachievements.org/Images/001416.png', 4.1),
  (152, 330, 'Wings of Wor', 'Genesis/Mega Drive', 1, 1071, 1071, 1071, 29, 0, 'Shoot ''em Up', 'NCS', 'DreamWorks, Masaya | NCS, Sega', '1991-01-25', 'Cho Aniki  is a Japanese video game series originally developed by Masaya and published by NCS Corp. The first game was released in 1992 for the PC Engine system. The game''s sequels and spin-offs later appeared on the Super Famicom, PlayStation, Sega Saturn, WonderSwan, PlayStation 2 and PlayStation Portable. Mainly consisting of side-scrolling shoot ''em ups in the vein of Gradius, the Cho Aniki series is best known for its homoerotic overtones, wacky humor and vivid, surreal imagery. Most of the games have never seen release outside Japan.', 'https://media.retroachievements.org/Images/055296.png', 'https://media.retroachievements.org/Images/124239.png', 'https://media.retroachievements.org/Images/000343.png', 'https://media.retroachievements.org/Images/000344.png', 4.1),
  (153, 8393, '~Homebrew~ Fix-it Felix Jr.', 'Genesis/Mega Drive', 1, 1062, 1062, 1062, 8, 0, 'Arcade', 'TobiKomi, Airwalk Studios', 'TobiKomi', '2014-03-25', 'The Sega Genesis, known as the Mega Drive outside North America, is a 16-bit fourth generation home video game console developed and sold by Sega. It was Sega''s third console and the successor to the Master System. Sega released it in October 1988 in Japan as the Mega Drive, and in August 1989 in North America as the Genesis. In 1990, it was distributed as the Mega Drive by Virgin Mastertronic in Europe, Ozisoft in Australasia, and Tectoy in Brazil. In South Korea, it was distributed by Samsung Electronics as the Super Gam*Boy and later the Super Aladdin Boy.', 'https://media.retroachievements.org/Images/121539.png', 'https://media.retroachievements.org/Images/010167.png', 'https://media.retroachievements.org/Images/099181.png', 'https://media.retroachievements.org/Images/099182.png', 4.1),
  (154, 33403, '~Homebrew~ Old Towers', 'Genesis/Mega Drive', 1, 1061, 1061, 1061, 16, 0, 'Puzzle Platforming', 'RetroSouls', 'RetroSouls', '2019-02-28', 'Sonic Spinball, also known as Sonic the Hedgehog Spinball, is a 1993 pinball video game developed by Sega Technical Institute and published by Sega for the Sega Genesis. It is a spin-off of the Sonic the Hedgehog series. Players control Sonic the Hedgehog, who must stop Doctor Robotnik from enslaving the population in a giant pinball-like mechanism. The game is set in a series of pinball machine-like environments with Sonic acting as the pinball.', 'https://media.retroachievements.org/Images/110192.png', 'https://media.retroachievements.org/Images/110191.png', 'https://media.retroachievements.org/Images/110171.png', 'https://media.retroachievements.org/Images/110172.png', 4.1),
  (155, 44, 'Air Buster', 'Genesis/Mega Drive', 1, 1029, 1029, 1029, 17, 0, 'Shoot ''em Up', 'Kaneko', 'Namco', '1991-01-31', 'This is a list of cast members of the television series MythBusters on the Discovery Channel. In addition to the core cast members, the MythBusters team includes several honorary MythBusters, and some recurring guests.', 'https://media.retroachievements.org/Images/029533.png', 'https://media.retroachievements.org/Images/056471.png', 'https://media.retroachievements.org/Images/001061.png', 'https://media.retroachievements.org/Images/001062.png', 4.1),
  (156, 317, 'Rolling Thunder 2', 'Genesis/Mega Drive', 1, 1017, 1017, 1017, 24, 0, NULL, 'Namco', 'Namco', '1991-01-01', 'Rolling Thunder 2 is a 1991 run and gun video game developed and published by Namco for arcades. The game is the sequel to 1986''s Rolling Thunder, retaining the same gameplay of its predecessor while adding cooperative gameplay for two players and improved graphics. Unlike the original, which was set in 1968, Rolling Thunder 2 has a more contemporary setting to go with its more futuristic design, as well as an optionally playable female character.', 'https://media.retroachievements.org/Images/054353.png', 'https://media.retroachievements.org/Images/005873.png', 'https://media.retroachievements.org/Images/005871.png', 'https://media.retroachievements.org/Images/005872.png', 4.1),
  (157, 203, 'Toy Story', 'Genesis/Mega Drive', 1, 1013, 1013, 1013, 32, 0, '2D Platforming', 'Traveller''s Tales', 'Disney Interactive Studios', '1995-01-01', 'Toy Story is a 1995 American animated adventure comedy film produced by Pixar Animation Studios for Walt Disney Pictures. The first entirely computer-animated feature film, as well as the first feature film from Pixar, it was directed by John Lasseter and written by Joss Whedon, Andrew Stanton, Joel Cohen, and Alec Sokolow. The film features the voices of Tom Hanks, Tim Allen, Annie Potts, John Ratzenberger, Don Rickles, Wallace Shawn, and Jim Varney. Taking place in a world where toys come to life when humans are not present, Toy Story follows an old-fashioned pullstring cowboy doll named Woody (Hanks), and a modern space cadet action figure, Buzz Lightyear (Allen), as Woody develops jealousy towards Buzz when he becomes their owner Andy''s favorite toy.', 'https://media.retroachievements.org/Images/065387.png', 'https://media.retroachievements.org/Images/015495.png', 'https://media.retroachievements.org/Images/015493.png', 'https://media.retroachievements.org/Images/015494.png', 4.1),
  (158, 29, 'James Pond II - Codename: RoboCod', 'Genesis/Mega Drive', 1, 1009, 1009, 1009, 27, 0, '2D Platforming', 'Vectordean', 'Electronic Arts', '1991-01-01', 'James Pond 2: Codename: RoboCod, also known as Super James Pond on Super NES and Game Boy in North America and Super James Pond 2 in Europe, is a 1991 platform video game. It is the second installment in the James Pond series after James Pond: Underwater Agent and was developed by the same British teams as the original. The title music by Richard Joseph is a marimba-heavy rendition of the RoboCop film theme.', 'https://media.retroachievements.org/Images/108488.png', 'https://media.retroachievements.org/Images/051949.png', 'https://media.retroachievements.org/Images/010853.png', 'https://media.retroachievements.org/Images/010854.png', 4.1),
  (159, 2413, 'Mazin Saga: Mutant Fighter', 'Genesis/Mega Drive', 1, 1002, 1002, 1002, 38, 0, 'Beat ''em Up', 'Almanic | Givro', 'Vic Tokai, Sega', '1993-01-01', 'Mazin Saga: Mutant Fighter is a 1993 hybrid beat ''em up/fighting video game developed by Almanic Corporation, in conjunction with ALU and Team "Saga", and published by Sega for the Sega Genesis/Mega Drive in Japan and Europe and later in North America by Vic Tokai. Based upon Go Nagai''s MazinSaga mecha manga, which is considered a combination of Nagai''s Mazinger and Devilman franchises, players assume the role of Koji Kabuto wielding the Mazinger Z armor to fight against powerful ''Bio Beasts'' led by God Kaiser Hell. Co-directed by Satsuki Mizuno, Takashi Yoneda and "Tommy Bon Bon", the title was created by most of the same team that worked on previous projects at Almanic such as E.V.O.: Search for Eden. It was met with mostly positive reception from critics since its release.', 'https://media.retroachievements.org/Images/064349.png', 'https://media.retroachievements.org/Images/006873.png', 'https://media.retroachievements.org/Images/009064.png', 'https://media.retroachievements.org/Images/009066.png', 4.1),
  (160, 2415, 'McDonald''s Treasure Land Adventure', 'Genesis/Mega Drive', 1, 1001, 1001, 1001, 27, 0, '2D Platforming', 'Treasure', 'Sega, Tectoy', '1993-09-23', 'McDonald''s Treasure Land Adventure is a 1993 platform game developed by Treasure and published by Sega for the Sega Genesis. Based on the McDonald''s fast food restaurant chain, specifically its McDonaldland marketing campaign, players control Ronald McDonald in his efforts to retrieve the missing pieces of a map that lead to the location of a buried treasure from a group of villains. Ronald can defeat enemies by using a magic attack and can latch onto hooks with his scarf to reach higher platforms.', 'https://media.retroachievements.org/Images/106816.png', 'https://media.retroachievements.org/Images/006270.png', 'https://media.retroachievements.org/Images/043060.png', 'https://media.retroachievements.org/Images/043061.png', 4.1),
  (161, 556, 'Ranger-X', 'Genesis/Mega Drive', 1, 979, 979, 979, 20, 0, 'Run & Gun', 'GAU Entertainment', 'Sega', '1993-05-28', 'Ranger X is a side scrolling run and gun video game for the Sega Genesis. Developed by GAU Entertainment and published by Sega, the game was released in 1993.', 'https://media.retroachievements.org/Images/113698.png', 'https://media.retroachievements.org/Images/003954.png', 'https://media.retroachievements.org/Images/003952.png', 'https://media.retroachievements.org/Images/003958.png', 4.1),
  (162, 165, 'Flashback: The Quest for Identity', 'Genesis/Mega Drive', 1, 975, 975, 975, 42, 0, 'Cinematic Platforming', 'Delphine Software International', 'U.S. Gold', '1993-02-20', 'The Sega Genesis, known as the Mega Drive in regions outside of North America, is a 16-bit video game console that was designed and produced by Sega. First released in Japan on October 29, 1988, in North America on August 1989, and in PAL regions in 1990, the Genesis is Sega''s third console and the successor to the Master System. The system supports a library of 881 officially licensed games created both by Sega and a wide array of third-party publishers and delivered on ROM cartridges. It can also play Master System games when the separately sold Power Base Converter is installed. The Sega Genesis also sported numerous peripherals, including the Sega CD and 32X, several network services, and multiple first-party and third-party variations of the console that focused on extending its functionality. The console and its games continue to be popular among fans, collectors, video game music fans, and emulation enthusiasts. Licensed third party re-releases of the console are still being produced, and several indie game developers continue to produce games for it. Many games have also been re-released in compilations for newer consoles and offered for download on various digital distribution services, such as Virtual Console, Xbox Live Arcade, PlayStation Network, and Steam.', 'https://media.retroachievements.org/Images/055707.png', 'https://media.retroachievements.org/Images/008412.png', 'https://media.retroachievements.org/Images/008410.png', 'https://media.retroachievements.org/Images/008411.png', 4.1),
  (163, 4222, 'Dahna: Megami Tanjou', 'Genesis/Mega Drive', 1, 966, 966, 966, 18, 0, 'Action', 'Information Global Service', 'Information Global Service', '1991-12-20', 'Dahna: Megami Tanjō  is a 1991 platform action game developed by and published by IGS for the Mega Drive exclusively in Japan and South Korea. The player controls the woman warrior-esque title character who struggles against the powers of an evil sorceress raiding her village. The story is told through cut scenes as Dahna is helped along the way by various mythical beasts.', 'https://media.retroachievements.org/Images/006212.png', 'https://media.retroachievements.org/Images/006211.png', 'https://media.retroachievements.org/Images/006208.png', 'https://media.retroachievements.org/Images/006210.png', 4.1),
  (164, 13943, '~Homebrew~ Cave Story MD', 'Genesis/Mega Drive', 1, 962, 962, 962, 84, 0, '2D Platforming', 'andwn', 'andwn', '2020-07-29', 'M2 Co., Ltd.  is a Japanese video game developer and publisher, best known for handling emulation of re-released games, such as some Sega Ages titles, Virtual Console titles for Nintendo systems, the 3D Classics series for the Nintendo 3DS and their ShotTriggers range of classic STG games. M2 has also created entirely new titles such as WiiWare games for Konami under the ReBirth moniker and more recently a new GG Aleste game. In addition, M2 currently holds the rights of Aleste series, all of SPS game plus software and all NEC Avenue and NEC Interchannel games on TurboGrafx-16 and variants, previously owned by Lightweight.', 'https://media.retroachievements.org/Images/066684.png', 'https://media.retroachievements.org/Images/067936.png', 'https://media.retroachievements.org/Images/117339.png', 'https://media.retroachievements.org/Images/117340.png', 4.1),
  (165, 81, 'Space Harrier II', 'Genesis/Mega Drive', 1, 957, 957, 957, 30, 0, 'Rail Shooter', 'Sega', 'Sega', '1988-10-29', 'Space Harrier II  is a 1988 rail shooter video game developed and published by Sega. The sequel to 1985''s Space Harrier, it was one of the original launch titles released for the Mega Drive in Japan and one of the six Sega Genesis launch titles in the United States the following year. It was later released on the Wii''s Virtual Console in December 2006, and also on the Nintendo Classics service in April 2022. Like Altered Beast, another launch title for the Mega Drive, Space Harrier II features digitized voice recordings during gameplay, and is also an example of some of the Mega Drive''s early sound, with music composed by Tokuhiko Uwabo. A graphically enhanced version included with the Sega Genesis Mini 2 was released in October 2022.', 'https://media.retroachievements.org/Images/072195.png', 'https://media.retroachievements.org/Images/000228.png', 'https://media.retroachievements.org/Images/000225.png', 'https://media.retroachievements.org/Images/000226.png', 4.1),
  (166, 1432, 'Monster World IV', 'Genesis/Mega Drive', 1, 953, 953, 953, 84, 0, 'Metroidvania', 'Westone', 'Sega', '1994-04-01', 'Monster World IV is an action-adventure platform game developed by Westone and released in Japan by Sega for the Mega Drive in April 1994. The game title is slightly confusing: It is the sixth game in the Wonder Boy series and the fourth game in the Monster World subseries. It was later released for the PlayStation 2 on March 8, 2007, as part of the Sega Ages 2500 series under the name Sega Ages 2500 Series Vol. 29: Monster World Complete Collection. It was released on the Wii''s Virtual Console service in Japan on January 15, 2008. An English-language version was released in North America and Europe for Virtual Console on May 10, 2012, with a release on Xbox Live Arcade and PlayStation Network to come on May 22, 2012. Monster World IV was the last Wonder Boy game to both be published by Sega and developed by Westone Bit Entertainment. A remake by Artdink, titled Wonder Boy: Asha in Monster World, was released in May 2021.', 'https://media.retroachievements.org/Images/020058.png', 'https://media.retroachievements.org/Images/009518.png', 'https://media.retroachievements.org/Images/017194.png', 'https://media.retroachievements.org/Images/017195.png', 4.1),
  (167, 5855, 'Shadow of the Beast', 'Genesis/Mega Drive', 1, 951, 951, 951, 30, 0, '2D Platforming, Action-Adventure', 'Reflections, WJS Design', 'Psygnosis', '1991-01-01', 'Shadow of the Beast is a 1989 platform game developed by Reflections and published by Psygnosis for the Amiga. It was later ported to several other systems. The game was known for its graphics, with many colours on screen and up to twelve levels of parallax scrolling backdrops, and for its atmospheric score composed by David Whittaker that used high-quality instrument samples.', 'https://media.retroachievements.org/Images/032134.png', 'https://media.retroachievements.org/Images/032130.png', 'https://media.retroachievements.org/Images/032132.png', 'https://media.retroachievements.org/Images/032181.png', 4.1),
  (168, 1439, 'Daze Before Christmas', 'Genesis/Mega Drive', 1, 940, 940, 940, 27, 0, '2D Platforming', 'Funcom', 'Sunsoft', '1994-01-01', 'David Martin Ruprecht is an American television and stage actor and game show host, primarily known for his work as host of the Lifetime/PAX game show Supermarket Sweep.', 'https://media.retroachievements.org/Images/063153.png', 'https://media.retroachievements.org/Images/006812.png', 'https://media.retroachievements.org/Images/006809.png', 'https://media.retroachievements.org/Images/006811.png', 4.1),
  (169, 288, '~Prototype~ Ninja Gaiden', 'Genesis/Mega Drive', 1, 937, 937, 937, 22, 0, 'Beat ''em Up', 'Opus', 'Sega', '1992-08-06', 'Ninja Gaiden  is an action game franchise created by Tecmo and featuring the ninja Ryu Hayabusa as its protagonist. The series was originally known as Ninja Ryukenden  in Japan. The word gaiden in the North American Ninja Gaiden title means side story in Japanese. The original arcade version, first two Nintendo Entertainment System games and Game Boy game were released as Shadow Warriors in PAL regions. As of 2008, the series had shipped over 7.7 million units worldwide.', 'https://media.retroachievements.org/Images/047618.png', 'https://media.retroachievements.org/Images/010120.png', 'https://media.retroachievements.org/Images/006686.png', 'https://media.retroachievements.org/Images/006685.png', 4.1),
  (170, 184, 'Art of Fighting', 'Genesis/Mega Drive', 1, 929, 929, 929, 35, 0, '2D Fighting', 'SNK', 'SNK', '1994-01-14', 'Art of Fighting, known in Japan as Dragon & Tiger Fist, is a 1992 fighting game developed and published by SNK for the Neo Geo MVS arcade system. It is the first game in the Art of Fighting series. It was eventually ported to the Neo Geo AES, Neo Geo CD, PC Engine CD-ROM², Sega Genesis, and Super Nintendo Entertainment System. The game follows Kyokugenryu Karate users Ryo Sakazaki and Robert Garcia as they travel to fight criminals from South Town in order to find Ryo''s missing sister Yuri. The game employs special moves and stronger Desperation Moves that can be performed strategically by filling the player''s energy bar and removing enemies by taunting them.', 'https://media.retroachievements.org/Images/071350.png', 'https://media.retroachievements.org/Images/011952.png', 'https://media.retroachievements.org/Images/000575.png', 'https://media.retroachievements.org/Images/000576.png', 4.1),
  (171, 311, 'Gain Ground', 'Genesis/Mega Drive', 1, 916, 916, 916, 101, 0, NULL, 'SIMS | Sanritsu', 'Sega', '1991-01-03', 'Gain Ground is a 1988 action arcade video game developed and published by Sega. It is set within a supercomputer''s simulation of war, and follows up to three players traversing through a series of forty levels themed after select periods of human history. The goal of each level, depending on the player''s choice, is either to guide at least one player character safely to an exit point or to destroy all enemies within them, both of which must be completed before a given time limit elapses.', 'https://media.retroachievements.org/Images/069979.png', 'https://media.retroachievements.org/Images/053577.png', 'https://media.retroachievements.org/Images/000191.png', 'https://media.retroachievements.org/Images/000190.png', 4.1),
  (172, 74, 'Top Gear 2', 'Genesis/Mega Drive', 1, 916, 916, 916, 68, 0, 'Racing', 'Gremlin Graphics', 'Vic Tokai', '1994-06-02', 'Top Gear 2 is a racing video game developed and published by Gremlin Interactive. A direct sequel to the 1992 game Top Gear, it was first released by Kemco for the SNES in North America in September 1993, and then the Super Famicom in Japan on December 22. It was later ported to the Amiga and Amiga CD32 in September 1994 by Gremlin Interactive, and to the Sega Genesis in September by Vic Tokai. While more realistic than its predecessor, Top Gear 2 maintained the arcade-style gameplay the series is known for.', 'https://media.retroachievements.org/Images/046589.png', 'https://media.retroachievements.org/Images/046493.png', 'https://media.retroachievements.org/Images/046492.png', 'https://media.retroachievements.org/Images/001483.png', 4.1),
  (173, 619, 'Ultimate Qix', 'Genesis/Mega Drive', 1, 906, 906, 906, 49, 0, 'Puzzle, Action', 'Taito', 'Taito', '1991-01-25', 'The Sega Genesis, known as the Mega Drive in regions outside of North America, is a 16-bit video game console that was designed and produced by Sega. First released in Japan on October 29, 1988, in North America on August 1989, and in PAL regions in 1990, the Genesis is Sega''s third console and the successor to the Master System. The system supports a library of 881 officially licensed games created both by Sega and a wide array of third-party publishers and delivered on ROM cartridges. It can also play Master System games when the separately sold Power Base Converter is installed. The Sega Genesis also sported numerous peripherals, including the Sega CD and 32X, several network services, and multiple first-party and third-party variations of the console that focused on extending its functionality. The console and its games continue to be popular among fans, collectors, video game music fans, and emulation enthusiasts. Licensed third party re-releases of the console are still being produced, and several indie game developers continue to produce games for it. Many games have also been re-released in compilations for newer consoles and offered for download on various digital distribution services, such as Virtual Console, Xbox Live Arcade, PlayStation Network, and Steam.', 'https://media.retroachievements.org/Images/017439.png', 'https://media.retroachievements.org/Images/017440.png', 'https://media.retroachievements.org/Images/017437.png', 'https://media.retroachievements.org/Images/017438.png', 4.1),
  (174, 287, 'Rambo III', 'Genesis/Mega Drive', 1, 895, 895, 895, 14, 0, 'Run & Gun', 'Sega', 'Sega', '1989-01-01', 'Rambo III is a 1988 American war action film starring Sylvester Stallone as Vietnam War veteran John Rambo. Directed by Peter MacDonald, the script was co-written by Stallone and Sheldon Lettich. It is a sequel to Rambo: First Blood Part II (1985) and the third installment in the Rambo film series. Richard Crenna reprises his role as Colonel Sam Trautman.', 'https://media.retroachievements.org/Images/004297.png', 'https://media.retroachievements.org/Images/048236.png', 'https://media.retroachievements.org/Images/048237.png', 'https://media.retroachievements.org/Images/004323.png', 4.1),
  (175, 24453, '~Homebrew~ Mega Man: The Sequel Wars - Episode Red', 'Genesis/Mega Drive', 1, 892, 892, 892, 135, 0, '2D Platforming', 'Woodfrog and the Sequel Wars Team', 'Woodfrog and the Sequel Wars Team', '2023-05-23', 'The Sega Genesis, known as the Mega Drive in regions outside of North America, is a 16-bit video game console that was designed and produced by Sega. First released in Japan on October 29, 1988, in North America on August 1989, and in PAL regions in 1990, the Genesis is Sega''s third console and the successor to the Master System. The system supports a library of 881 officially licensed games created both by Sega and a wide array of third-party publishers and delivered on ROM cartridges. It can also play Master System games when the separately sold Power Base Converter is installed. The Sega Genesis also sported numerous peripherals, including the Sega CD and 32X, several network services, and multiple first-party and third-party variations of the console that focused on extending its functionality. The console and its games continue to be popular among fans, collectors, video game music fans, and emulation enthusiasts. Licensed third party re-releases of the console are still being produced, and several indie game developers continue to produce games for it. Many games have also been re-released in compilations for newer consoles and offered for download on various digital distribution services, such as Virtual Console, Xbox Live Arcade, PlayStation Network, and Steam.', 'https://media.retroachievements.org/Images/074329.png', 'https://media.retroachievements.org/Images/073781.png', 'https://media.retroachievements.org/Images/074467.png', 'https://media.retroachievements.org/Images/073753.png', 4.1),
  (176, 4509, 'Wiz ''n'' Liz: The Frantic Wabbit Wescue', 'Genesis/Mega Drive', 1, 892, 892, 892, 55, 0, NULL, 'Bizarre Creations', 'Psygnosis', '1993-01-01', 'Wiz ''n'' Liz: The Frantic Wabbit Wescue is a platform game developed by Raising Hell Software for the Sega Mega Drive and published by Psygnosis in 1993. An Amiga port was developed by Lunatic Software. It is a humorous, cutesy platform game. With the exception of some end-of-level bosses, the game contains no enemies.', 'https://media.retroachievements.org/Images/078319.png', 'https://media.retroachievements.org/Images/059358.png', 'https://media.retroachievements.org/Images/003058.png', 'https://media.retroachievements.org/Images/003059.png', 4.1),
  (177, 402, 'Thunder Force II', 'Genesis/Mega Drive', 1, 891, 891, 891, 50, 0, NULL, 'Technosoft | Tecno Soft', 'Sega', '1989-06-15', 'Thunder Force II is a scrolling shooter developed by Technosoft. It was first released in Japan on October 15, 1988 for the X68000 computer. A year later, it was ported to the Sega Mega Drive/Genesis game console and released in Japan, Europe, and the United States. Thunder Force II was one of the six launch titles for the U.S. Genesis release. The Genesis port was later included in Thunder Force Gold Pack Volume 1 for the Sega Saturn. It was also re-released via the Nintendo Classics service on December 16, 2021. It is the second chapter of the Thunder Force series.', 'https://media.retroachievements.org/Images/078805.png', 'https://media.retroachievements.org/Images/007939.png', 'https://media.retroachievements.org/Images/020775.png', 'https://media.retroachievements.org/Images/020774.png', 4.1),
  (178, 4372, 'The Ooze', 'Genesis/Mega Drive', 1, 884, 884, 884, 27, 0, 'Action', 'Sega', 'Sega', '1995-09-22', 'The Ooze is a video game developed by Sega Technical Institute and released in 1995 for the Sega Genesis. In the game, players take the role of a slimy puddle of liquid and face off against various enemies and obstacles.', 'https://media.retroachievements.org/Images/039511.png', 'https://media.retroachievements.org/Images/009946.png', 'https://media.retroachievements.org/Images/009942.png', 'https://media.retroachievements.org/Images/009943.png', 4.1),
  (179, 157, 'Double Dragon 3: The Arcade Game', 'Genesis/Mega Drive', 1, 877, 877, 877, 12, 0, 'Beat ''em Up', 'East Technology', 'Flying Edge', '1992-01-01', 'Double Dragon 3: The Rosetta Stone is a side-scrolling beat ''em up arcade video game produced by Technōs Japan in 1990. It is the third arcade game in the Double Dragon series. Unlike its predecessors, Double Dragon 3 was not developed internally at Technōs, but was contracted to the company East Technology, resulting in a game that looks and plays differently.', 'https://media.retroachievements.org/Images/062619.png', 'https://media.retroachievements.org/Images/000742.png', 'https://media.retroachievements.org/Images/053235.png', 'https://media.retroachievements.org/Images/053236.png', 4.1),
  (180, 485, 'Arcus Odyssey', 'Genesis/Mega Drive', 1, 869, 869, 869, 24, 0, 'Shoot ''em Up', 'Wolf Team', 'Renovation Products', '1991-06-14', 'Arcus Odyssey is a 1991 action game developed by Wolf Team and released by Renovation Products for the Sega Genesis and X68000 and in 1993 for the Super Nintendo Entertainment System. The game features an isometric perspective and cooperative gameplay with hack and slash elements. It tells the story of four heroes trying to thwart the return of an evil sorceress.', 'https://media.retroachievements.org/Images/050154.png', 'https://media.retroachievements.org/Images/011944.png', 'https://media.retroachievements.org/Images/049875.png', 'https://media.retroachievements.org/Images/049876.png', 4.1),
  (181, 154, 'Doom Troopers', 'Genesis/Mega Drive', 1, 867, 867, 867, 35, 0, NULL, 'Adrenalin Entertainment', 'Playmates Interactive Entertainment', '1995-01-01', 'Mutant Chronicles: Doom Troopers is a video game released in 1995 by Adrenalin Entertainment for the Sega Genesis and Super NES gaming systems.', 'https://media.retroachievements.org/Images/008527.png', 'https://media.retroachievements.org/Images/008528.png', 'https://media.retroachievements.org/Images/008526.png', 'https://media.retroachievements.org/Images/008525.png', 4.1),
  (182, 4291, 'High Seas Havoc', 'Genesis/Mega Drive', 1, 866, 866, 866, 27, 0, '2D Platforming', 'Data East', 'Codemasters', '1993-01-01', 'Maneater is an action role-playing game developed and published by Tripwire Interactive. The player assumes control of a female bull shark who must evolve and survive in an open world so she can take revenge on a fisherman who disfigured her as a pup and killed her mother.', 'https://media.retroachievements.org/Images/063200.png', 'https://media.retroachievements.org/Images/014714.png', 'https://media.retroachievements.org/Images/014716.png', 'https://media.retroachievements.org/Images/014717.png', 4.1),
  (183, 113, 'Hellfire', 'Genesis/Mega Drive', 1, 854, 854, 854, 23, 0, 'Shoot ''em Up', 'Toaplan', 'Seismic', '1990-09-28', 'Hellfire is a 1989 horizontally scrolling shooter video game developed by Toaplan and published by Taito for Japanese arcades; in North America, it was distributed by U.S.A. Games. The first horizontal shoot ''em up title to be created by Toaplan, the game takes place in the year 2998, where a space matter known as Black Nebula, created by robot dictator Super Mech, spreads and threatens to engulf human-controlled galaxies. Players assume the role of Space Federation member Captain Lancer, taking control of the CNCS1 spacecraft in a surprise attack to overthrow the enemies using the spacecraft''s titular weapon.', 'https://media.retroachievements.org/Images/063196.png', 'https://media.retroachievements.org/Images/000330.png', 'https://media.retroachievements.org/Images/000327.png', 'https://media.retroachievements.org/Images/000328.png', 4),
  (184, 603, 'Chiki Chiki Boys', 'Genesis/Mega Drive', 1, 832, 832, 832, 30, 0, NULL, 'Capcom, Visco', 'Sega', '1992-10-16', 'Mega Twins, known as Chiki Chiki Boys in Japan and Europe is a 1990 platform video game developed and published by Capcom for arcades.', 'https://media.retroachievements.org/Images/023143.png', 'https://media.retroachievements.org/Images/005268.png', 'https://media.retroachievements.org/Images/005269.png', 'https://media.retroachievements.org/Images/005270.png', 4),
  (185, 338, 'DJ Boy', 'Genesis/Mega Drive', 1, 815, 815, 815, 17, 0, 'Beat ''em Up', 'Kaneko', 'Kaneko', '1990-05-19', 'DJ Boy (DJボーイ) is a 1989 beat ''em up arcade video game developed and published in Japan by Kaneko and in North America by Sammy. DJ Boy, also known as DJ Kid, was partially based on the hip hop culture of the U.S. cities. Many of the characters ride around on roller skates rather than walking or running.', 'https://media.retroachievements.org/Images/113699.png', 'https://media.retroachievements.org/Images/125098.png', 'https://media.retroachievements.org/Images/000579.png', 'https://media.retroachievements.org/Images/000580.png', 4),
  (186, 524, '~Prototype~ Tetris', 'Genesis/Mega Drive', 1, 810, 810, 810, 21, 0, NULL, NULL, NULL, '1989-01-01', 'Tetris is a puzzle video game created in 1985 by Alexey Pajitnov, a Soviet software engineer. In the game, falling tetromino shapes must be neatly sorted into a pile. Once a horizontal line of the board is filled in, the line disappears, granting points and preventing the pile from overflowing. Since its initial creation, this gameplay has been used in over 220 versions, released for over 70 platforms. Newer versions frequently implement additional game mechanics, some of which have become standard over time. As of December 2024, these versions collectively serve as the second-best-selling video game series with over 520 million sales, mostly on mobile devices.', 'https://media.retroachievements.org/Images/069976.png', 'https://media.retroachievements.org/Images/112015.png', 'https://media.retroachievements.org/Images/033573.png', 'https://media.retroachievements.org/Images/033574.png', 4),
  (187, 4346, 'The Lost Vikings', 'Genesis/Mega Drive', 1, 810, 810, 810, 68, 0, 'Puzzle Platforming', 'Silicon & Synapse', 'Interplay Entertainment', '1993-01-01', 'The Lost Vikings is a 1993 puzzle-platform game developed by Silicon & Synapse and published by Interplay Productions. In the game, the player controls three separate vikings with different abilities. The three vikings must work together to finish each level and find their way back home.', 'https://media.retroachievements.org/Images/071851.png', 'https://media.retroachievements.org/Images/017327.png', 'https://media.retroachievements.org/Images/017324.png', 'https://media.retroachievements.org/Images/017325.png', 4),
  (188, 41, 'Tiny Toon Adventures: ACME All-Stars', 'Genesis/Mega Drive', 1, 799, 799, 799, 39, 0, 'Sports', 'Konami', 'Konami', '1994-01-01', 'Tiny Toon Adventures: ACME All-Stars is a Tiny Toon Adventures-based sports video game released on the Sega Genesis video game console. The game was developed and published by Konami in 1994.', 'https://media.retroachievements.org/Images/055629.png', 'https://media.retroachievements.org/Images/010957.png', 'https://media.retroachievements.org/Images/010952.png', 'https://media.retroachievements.org/Images/010955.png', 4),
  (189, 105, 'Jurassic Park', 'Genesis/Mega Drive', 1, 788, 788, 788, 42, 0, 'Action Adventure', 'BlueSky Software', 'Sega', '1993-08-10', 'Jurassic Park, later referred to as Jurassic World, is an American science fiction media franchise created by Michael Crichton, centered on a disastrous attempt to create a theme park of cloned dinosaurs. It began in 1990 when Universal Pictures and Amblin Entertainment bought the rights to Crichton''s novel Jurassic Park before it was published. The book was successful, as was Steven Spielberg''s 1993 film adaptation. The film received a theatrical 3D re-release in 2013, and was selected in 2018 for preservation in the United States National Film Registry by the Library of Congress as being culturally, historically, or aesthetically significant. Crichton''s 1995 sequel novel, The Lost World, was followed by a 1997 film adaptation, also directed by Spielberg. Crichton did not write any further sequels in the series, although Spielberg would return as executive producer for each subsequent film, starting with Jurassic Park III (2001).', 'https://media.retroachievements.org/Images/045406.png', 'https://media.retroachievements.org/Images/005639.png', 'https://media.retroachievements.org/Images/005640.png', 'https://media.retroachievements.org/Images/005641.png', 4),
  (190, 8474, 'Cannon Fodder', 'Genesis/Mega Drive', 1, 783, 783, 783, 61, 0, 'Action, Shooter, Shoot-''Em-Up, Top-Down', 'Panelcomp', 'Virgin Interactive', '1994-01-01', 'Cannon Fodder is a series of war themed action games developed by Sensible Software, initially released as Cannon Fodder for the Amiga. Only two games in the series were created by Sensible, but were converted to most active systems at the time of release. A sequel, Cannon Fodder 2, was released in 1994 for Amiga and MS-DOS. A third game, Cannon Fodder 3, was made by a Russian developer and released in English in 2012.', 'https://media.retroachievements.org/Images/053306.png', 'https://media.retroachievements.org/Images/053307.png', 'https://media.retroachievements.org/Images/053304.png', 'https://media.retroachievements.org/Images/053305.png', 4),
  (191, 4377, 'OutRun 2019', 'Genesis/Mega Drive', 1, 778, 778, 778, 43, 0, NULL, 'SIMS | Sanritsu', 'Sega', '1993-03-26', 'OutRun 2019  is a 1993 racing video game for the Sega Genesis, serving as a pseudo-sequel to Out Run (1986) that takes place in the (then) future: 2019, hence the name. The object is to race against a time limit in a rocket-boosted car across four different stages around the world. Like the original Out Run, there is a fork in the road before each checkpoint, but there can also be forks within a single route.', 'https://media.retroachievements.org/Images/069356.png', 'https://media.retroachievements.org/Images/069369.png', 'https://media.retroachievements.org/Images/069366.png', 'https://media.retroachievements.org/Images/069365.png', 4),
  (192, 561, 'Landstalker: The Treasures of King Nole', 'Genesis/Mega Drive', 1, 769, 769, 769, 50, 0, 'Action-Adventure', 'Climax Entertainment', 'Sega', '1992-10-30', 'Landstalker: The Treasures of King Nole is a 1992 action role-playing video game developed by Climax Entertainment and published by Sega for the Sega Genesis. The player takes on the role of the treasure hunter Nigel as they navigate a three-dimensional world through an isometric viewpoint, solving puzzles and fighting enemies.', 'https://media.retroachievements.org/Images/079386.png', 'https://media.retroachievements.org/Images/003943.png', 'https://media.retroachievements.org/Images/003941.png', 'https://media.retroachievements.org/Images/003942.png', 4),
  (193, 25807, '~Hack~ Teenage Mutant Ninja Turtles: Shredder''s Re-Revenge', 'Genesis/Mega Drive', 1, 762, 762, 762, 25, 0, 'Beat ''em Up', 'savok', 'Hack - Streets of Rage 2', '2022-12-26', 'Video games based on the Teenage Mutant Ninja Turtles franchise have been produced since 1989, largely by Japanese video game manufacturer Konami.', 'https://media.retroachievements.org/Images/120841.png', 'https://media.retroachievements.org/Images/112426.png', 'https://media.retroachievements.org/Images/082662.png', 'https://media.retroachievements.org/Images/082663.png', 4),
  (194, 177, 'Paperboy', 'Genesis/Mega Drive', 1, 754, 754, 754, 9, 0, 'Action', 'Motivetime', 'Atari, Tengen', '1990-01-01', 'A paperboy is someone – often an older child or adolescent – who distributes printed newspapers to homes or offices on a regular route, usually by bicycle or automobile. In Western nations during the heyday of print newspapers during the early 20th century, this was often a young person''s first job, perhaps undertaken before or after school. This contrasts with the newsboy or newspaper hawker, now extremely rare in Western nations, who would sell newspapers to passersby on the street, often with very vocal promotion. They were common when multiple daily papers in every city – as many as 50 in New York City alone – competed.', 'https://media.retroachievements.org/Images/065591.png', 'https://media.retroachievements.org/Images/000395.png', 'https://media.retroachievements.org/Images/000392.png', 'https://media.retroachievements.org/Images/000393.png', 4),
  (195, 160, 'Mutant League Hockey', 'Genesis/Mega Drive', 1, 726, 726, 726, 40, 0, NULL, 'Electronic Arts', 'Electronic Arts', '1994-03-01', 'Mutant League Hockey is an ice hockey video game that was released in 1994 for the Sega Genesis. It is the follow up to Mutant League Football (1993).', 'https://media.retroachievements.org/Images/078871.png', 'https://media.retroachievements.org/Images/010150.png', 'https://media.retroachievements.org/Images/010170.png', 'https://media.retroachievements.org/Images/010171.png', 4),
  (196, 18481, '~Unlicensed~ Bomber', 'Genesis/Mega Drive', 1, 723, 723, 723, 8, 0, 'Action', 'Tectoy', 'AtGames, KDS', '2008-01-01', 'A bomber is a military combat aircraft that utilizes air-to-ground weaponry to drop bombs, launch torpedoes, or deploy air-launched cruise missiles.', 'https://media.retroachievements.org/Images/102648.png', 'https://media.retroachievements.org/Images/052740.png', 'https://media.retroachievements.org/Images/052741.png', 'https://media.retroachievements.org/Images/052742.png', 4),
  (197, 4140, 'Batman Returns', 'Genesis/Mega Drive', 1, 721, 721, 721, 23, 0, 'Beat ''em Up', 'Malibu Interactive', 'Sega', '1992-01-01', 'Batman Returns is a 1992 American superhero film directed by Tim Burton and written by Daniel Waters. Based on the DC Comics character Batman, it is the sequel to Batman (1989), also directed by Burton, and the second installment in the Batman film series (1989–1997). The cast includes Michael Keaton, Danny DeVito, Michelle Pfeiffer, Christopher Walken, Michael Gough, Pat Hingle, and Michael Murphy. Set during Christmas in Gotham City, the film follows Batman (Keaton) as he confronts corrupt businessman Max Shreck (Walken) and deformed crime boss Oswald Cobblepot / the Penguin (DeVito), whose bid for power threatens the city. Their schemes are further complicated by Shreck''s former secretary Selina Kyle (Pfeiffer), who seeks revenge against him as Catwoman.', 'https://media.retroachievements.org/Images/107705.png', 'https://media.retroachievements.org/Images/086507.png', 'https://media.retroachievements.org/Images/010917.png', 'https://media.retroachievements.org/Images/010918.png', 4),
  (198, 622, 'Space Invaders ''91', 'Genesis/Mega Drive', 1, 712, 712, 712, 22, 0, 'Shoot ''em Up', 'Taito', 'Taito', '1991-01-01', 'The Sega Genesis, known as the Mega Drive in regions outside of North America, is a 16-bit video game console that was designed and produced by Sega. First released in Japan on October 29, 1988, in North America on August 1989, and in PAL regions in 1990, the Genesis is Sega''s third console and the successor to the Master System. The system supports a library of 881 officially licensed games created both by Sega and a wide array of third-party publishers and delivered on ROM cartridges. It can also play Master System games when the separately sold Power Base Converter is installed. The Sega Genesis also sported numerous peripherals, including the Sega CD and 32X, several network services, and multiple first-party and third-party variations of the console that focused on extending its functionality. The console and its games continue to be popular among fans, collectors, video game music fans, and emulation enthusiasts. Licensed third party re-releases of the console are still being produced, and several indie game developers continue to produce games for it. Many games have also been re-released in compilations for newer consoles and offered for download on various digital distribution services, such as Virtual Console, Xbox Live Arcade, PlayStation Network, and Steam.', 'https://media.retroachievements.org/Images/041389.png', 'https://media.retroachievements.org/Images/041388.png', 'https://media.retroachievements.org/Images/041386.png', 'https://media.retroachievements.org/Images/041387.png', 4),
  (199, 10340, '~Hack~ Sonic the Hedgehog 2 XL', 'Genesis/Mega Drive', 1, 704, 704, 704, 33, 0, '2D Platforming', 'Captain Bozo, Ranger', 'Hack - Sonic the Hedgehog 2', '2010-07-12', 'Homebrew is a term for software produced by hobbyists for proprietary video game consoles, which are not intended to be user-programmable.', 'https://media.retroachievements.org/Images/092254.png', 'https://media.retroachievements.org/Images/116695.png', 'https://media.retroachievements.org/Images/043847.png', 'https://media.retroachievements.org/Images/043848.png', 4),
  (200, 4382, 'Panorama Cotton', 'Genesis/Mega Drive', 1, 694, 694, 694, 65, 0, 'Rail Shooter', 'Success', 'Sunsoft', '1994-08-12', 'Panorama Cotton is a 1994 rail shooter video game developed by Success and published by Sunsoft for the Mega Drive exclusively in Japan on August 12, 1994. Panorama Cotton is the third entry in the Cotton series and made a major departure from the original gameplay formula of prior Cotton entries; instead of being a side-scrolling shooter like the others, it is a pseudo-3D shooter in the style of Sega''s Space Harrier.', 'https://media.retroachievements.org/Images/028281.png', 'https://media.retroachievements.org/Images/028279.png', 'https://media.retroachievements.org/Images/028271.png', 'https://media.retroachievements.org/Images/028272.png', 4);
INSERT INTO games (rank, id, title, consoleName, consoleId, totalPlayers, casualPlayers, hardcorePlayers, numAchievements, points, genre, developer, publisher, released, description, icon, boxArt, titleScreen, screenshot, rating) VALUES
  (1, 228, 'Super Mario World', 'SNES/Super Famicom', 3, 95174, 95174, 95174, 89, 0, '2D Platforming', NULL, 'Nintendo', '1990-11-21', 'Super Mario World is a platform game developed and published by Nintendo for the Super Nintendo Entertainment System (SNES). It was released in Japan in 1990, in North America in 1991 and PAL territories in 1992. The player controls Mario on his quest to save Princess Peach and Dinosaur Land from the series'' antagonist Bowser and the Koopalings. The gameplay is similar to that of earlier Super Mario games; players control Mario through a series of levels in which the goal is to reach the goalpost at the end. Super Mario World introduces Yoshi, a ridable dinosaur who can eat enemies and spit some of them out as projectiles.', 'https://media.retroachievements.org/Images/112443.png', 'https://media.retroachievements.org/Images/109856.png', 'https://media.retroachievements.org/Images/110144.png', 'https://media.retroachievements.org/Images/110145.png', 5),
  (2, 355, 'The Legend of Zelda: A Link to the Past', 'SNES/Super Famicom', 3, 41287, 41287, 41287, 109, 0, 'Action-Adventure', NULL, 'Nintendo', '1991-11-21', 'The Legend of Zelda: A Link to the Past is a 1991 action-adventure game developed and published by Nintendo for the Super Nintendo Entertainment System (SNES). It is the third game in The Legend of Zelda series, following 1987''s Zelda II: The Adventure of Link, and is the first entry in the series to be released for the SNES.', 'https://media.retroachievements.org/Images/059119.png', 'https://media.retroachievements.org/Images/022504.png', 'https://media.retroachievements.org/Images/072051.png', 'https://media.retroachievements.org/Images/072052.png', 4.8),
  (3, 466, 'Donkey Kong Country 2: Diddy''s Kong Quest', 'SNES/Super Famicom', 3, 26782, 26782, 26782, 80, 0, '2D Platforming', 'Rare', 'Nintendo', '1995-11-21', 'Donkey Kong Country 2: Diddy''s Kong Quest  is a 1995 platform game developed by Rare and published by Nintendo for the Super Nintendo Entertainment System (SNES). It was released on 21 November 1995 in Japan, 4 December in North America, and 14 December in Europe. It is the second installment of the Donkey Kong Country series and the sequel to Donkey Kong Country (1994).', 'https://media.retroachievements.org/Images/107029.png', 'https://media.retroachievements.org/Images/060825.png', 'https://media.retroachievements.org/Images/000162.png', 'https://media.retroachievements.org/Images/000163.png', 4.7),
  (4, 236, 'Super Metroid', 'SNES/Super Famicom', 3, 25802, 25802, 25802, 52, 0, 'Metroidvania', 'Intelligent Systems', 'Nintendo', '1994-03-19', 'Super Metroid is a 1994 action-adventure game developed by Nintendo and Intelligent Systems and published by Nintendo for the Super Nintendo Entertainment System (SNES). It is the third Metroid game, following the Game Boy game Metroid II: Return of Samus (1991). The player controls bounty hunter Samus Aran, who travels to planet Zebes to retrieve an infant Metroid creature stolen by the Space Pirate leader Ridley.', 'https://media.retroachievements.org/Images/060989.png', 'https://media.retroachievements.org/Images/096236.png', 'https://media.retroachievements.org/Images/065700.png', 'https://media.retroachievements.org/Images/073825.png', 4.7),
  (5, 319, 'Chrono Trigger', 'SNES/Super Famicom', 3, 25040, 25040, 25040, 76, 0, 'Turn-Based RPG', 'Square', 'Squaresoft', '1995-03-11', 'Chrono Trigger is a 1995 role-playing video game developed and published by Square for the Super Nintendo Entertainment System. It is the first installment of the Chrono series. The game''s plot follows a group of adventurers who travel through time to prevent a global catastrophe.', 'https://media.retroachievements.org/Images/093950.png', 'https://media.retroachievements.org/Images/000222.png', 'https://media.retroachievements.org/Images/106517.png', 'https://media.retroachievements.org/Images/036180.png', 4.7),
  (6, 814, 'Kirby Super Star', 'SNES/Super Famicom', 3, 19509, 19509, 19509, 57, 0, '2D Platforming', 'HAL Laboratory', 'HAL Laboratory', '1996-03-21', 'Kirby Super Star, released as Kirby''s Fun Pak in PAL regions, is a 1996 anthology platform game developed by HAL Laboratory and published by Nintendo for the Super Nintendo Entertainment System. It is part of the Kirby series of video games by HAL Laboratory. The game was advertised as a compilation featuring eight games: seven short subsections with the same basic gameplay, and two minigames.', 'https://media.retroachievements.org/Images/076409.png', 'https://media.retroachievements.org/Images/003681.png', 'https://media.retroachievements.org/Images/004908.png', 'https://media.retroachievements.org/Images/004909.png', 4.6),
  (7, 637, 'Mega Man X', 'SNES/Super Famicom', 3, 19407, 19407, 19407, 57, 0, '2D Platforming', 'Capcom', 'Capcom', '1993-12-17', 'Mega Man X is a series of action-platform games released by Capcom. It is a sub-series of the Mega Man franchise previously developed by the same group, with Keiji Inafune acting as one of the main staff members. The first game was released on 17 December 1993 in Japan on the Super Famicom and the following month on the Super NES in North America. Most of the sequels were ported to Microsoft Windows. The gameplay introduces new elements to the Mega Man franchise in the form of Mega Man''s successor X, including his new skills and power-ups in the form of armors while retaining the ability to decide which boss to fight first. The franchise is also known for its replay value, in which certain choices and optional content can influence both gameplay and storylines, allowing the player to experience alternate scenarios.', 'https://media.retroachievements.org/Images/043274.png', 'https://media.retroachievements.org/Images/015026.png', 'https://media.retroachievements.org/Images/035379.png', 'https://media.retroachievements.org/Images/035387.png', 4.6),
  (8, 558, 'Super Mario World 2: Yoshi''s Island', 'SNES/Super Famicom', 3, 18799, 18799, 18799, 63, 0, '2D Platforming', NULL, 'Nintendo', '1995-08-05', 'Super Mario World 2: Yoshi''s Island is a 1995 platform game developed and published by Nintendo for the Super Nintendo Entertainment System (SNES). The player controls Yoshi dinosaurs on their quest to reunite baby Mario with his brother Luigi, who has been kidnapped by the wizard Kamek. Yoshi runs and jumps to reach the end of the level while solving puzzles and collecting items with Mario''s help.', 'https://media.retroachievements.org/Images/061087.png', 'https://media.retroachievements.org/Images/112063.png', 'https://media.retroachievements.org/Images/038811.png', 'https://media.retroachievements.org/Images/038813.png', 4.6),
  (9, 232, 'Super Mario Kart', 'SNES/Super Famicom', 3, 18229, 18229, 18229, 47, 0, 'Kart Racing', NULL, 'Nintendo', '1992-08-27', 'Super Mario Kart is a 1992 kart racing game developed and published by Nintendo for the Super Nintendo Entertainment System (SNES). The first game in the Mario Kart series, it was released in Japan on August 27, 1992, North America on September 1, 1992, the United Kingdom in October 1992, and Europe on January 21, 1993. Selling 8.76 million copies worldwide, the game went on to become the fourth best-selling SNES game of all time. Super Mario Kart was re-released on the Wii''s Virtual Console in 2009, on the Wii U''s Virtual Console in 2013, and on the New Nintendo 3DS''s Virtual Console in 2016. Nintendo re-released Super Mario Kart in 2017 as part of the company''s Super NES Classic Edition.', 'https://media.retroachievements.org/Images/069326.png', 'https://media.retroachievements.org/Images/053513.png', 'https://media.retroachievements.org/Images/070108.png', 'https://media.retroachievements.org/Images/000726.png', 4.6),
  (10, 471, 'Super Mario RPG: Legend of the Seven Stars', 'SNES/Super Famicom', 3, 16769, 16769, 16769, 100, 0, 'Turn-Based RPG', 'Square', 'Nintendo', '1996-03-09', 'Super Mario RPG: Legend of the Seven Stars is a 1996 role-playing video game developed by Square and published by Nintendo for the Super Nintendo Entertainment System (SNES). It was the final Mario game for the SNES, and was directed by Chihiro Fujioka and Yoshihiko Maekawa, produced by Shigeru Miyamoto, and scored by Yoko Shimomura.', 'https://media.retroachievements.org/Images/085860.png', 'https://media.retroachievements.org/Images/026395.png', 'https://media.retroachievements.org/Images/001537.png', 'https://media.retroachievements.org/Images/001538.png', 4.6),
  (11, 350, 'Teenage Mutant Ninja Turtles IV: Turtles in Time', 'SNES/Super Famicom', 3, 15931, 15931, 15931, 30, 0, 'Beat ''em Up', 'Konami', 'Konami', '1992-07-24', 'Teenage Mutant Ninja Turtles: Turtles in Time, released as Teenage Mutant Hero Turtles: Turtles in Time in Europe, is a 1991 beat ''em up game developed and published by Konami for arcades. A sequel to the original Teenage Mutant Ninja Turtles arcade game, it is a side-scrolling game based mainly on the 1987 TMNT animated series. Originally an arcade game, Turtles in Time was ported to the Super Nintendo Entertainment System in 1992 under the title Teenage Mutant Ninja Turtles IV: Turtles in Time, continuing the numbering from the earlier Turtles games released on the original NES. That same year, a game that borrowed many elements, Teenage Mutant Ninja Turtles: The Hyperstone Heist, was released for the Sega Genesis.', 'https://media.retroachievements.org/Images/044532.png', 'https://media.retroachievements.org/Images/120293.png', 'https://media.retroachievements.org/Images/035357.png', 'https://media.retroachievements.org/Images/053029.png', 4.6),
  (12, 264, 'EarthBound', 'SNES/Super Famicom', 3, 15391, 15391, 15391, 105, 0, 'Turn-Based RPG', 'APE | Creatures, HAL Laboratory, Pax Softnica', 'Nintendo', '1994-08-27', 'EarthBound, originally released in Japan as Mother 2: Gīgu no Gyakushū, is a 1994 role-playing video game developed by Ape Inc. and HAL Laboratory and published by Nintendo for the Super Nintendo Entertainment System. The second entry in the Mother series, it follows a young boy named Ness and his party of Paula, Jeff and Poo, as they travel the world to collect melodies from eight Sanctuaries in order to defeat the universal cosmic destroyer Giygas.', 'https://media.retroachievements.org/Images/100662.png', 'https://media.retroachievements.org/Images/001836.png', 'https://media.retroachievements.org/Images/002470.png', 'https://media.retroachievements.org/Images/002471.png', 4.6),
  (13, 379, 'Aladdin', 'SNES/Super Famicom', 3, 14302, 14302, 14302, 40, 0, '2D Platforming', 'Capcom', 'Capcom', '1993-11-26', 'Aladdin is a Middle-Eastern folk tale. It is one of the best-known tales associated with One Thousand and One Nights, despite not being part of the original text; it was added by the Frenchman Antoine Galland, based on a folk tale that he heard from the Syrian storyteller Hanna Diyab.', 'https://media.retroachievements.org/Images/096482.png', 'https://media.retroachievements.org/Images/096400.png', 'https://media.retroachievements.org/Images/000102.png', 'https://media.retroachievements.org/Images/000103.png', 4.6),
  (14, 473, 'Donkey Kong Country 3: Dixie Kong''s Double Trouble!', 'SNES/Super Famicom', 3, 13200, 13200, 13200, 84, 0, '2D Platforming', 'Rare', 'Nintendo', '1996-01-01', 'Donkey Kong Country 3: Dixie Kong''s Double Trouble!  is a 1996 platform Collectathon developed by Rare and published by Nintendo for the Super Nintendo Entertainment System (SNES). It is the third installment of the Donkey Kong Country series, and serves as a sequel to 1995''s Donkey Kong Country 2: Diddy''s Kong Quest. It was also re-released for the Game Boy Advance (GBA) in 2005. The game was made available to download on the Wii''s Virtual Console service in 2007, as well as for the Wii U''s Virtual Console in 2014.', 'https://media.retroachievements.org/Images/107030.png', 'https://media.retroachievements.org/Images/060826.png', 'https://media.retroachievements.org/Images/000139.png', 'https://media.retroachievements.org/Images/000140.png', 4.6),
  (15, 562, 'Super Castlevania IV', 'SNES/Super Famicom', 3, 12880, 12880, 12880, 36, 0, '2D Platforming', 'Konami', 'Konami', '1991-10-31', 'Super Castlevania IV is a 1991 platform game developed and published by Konami for the Super Nintendo Entertainment System. It has been re-released multiple times, including for the Super NES Classic Edition.', 'https://media.retroachievements.org/Images/072972.png', 'https://media.retroachievements.org/Images/072401.png', 'https://media.retroachievements.org/Images/000986.png', 'https://media.retroachievements.org/Images/034865.png', 4.6),
  (16, 539, 'Super Punch-Out!!', 'SNES/Super Famicom', 3, 12767, 12767, 12767, 74, 0, 'Sports - Boxing', 'Nintendo', 'Nintendo', '1994-10-24', 'Super Punch-Out!! is a boxing video game developed and published by Nintendo for the Super Nintendo Entertainment System (SNES). It was released on October 24, 1994 in North America and again in the same region in 1996. It was released in the United Kingdom on February 10, 1995 for the same console and in Japan in 1998 for the Super Famicom through the Nintendo Power flash RAM cartridge series. The game is also included in the GameCube version of Fight Night Round 2 as an extra game due to the inclusion of Little Mac in the game. The game was released for the Wii''s Virtual Console in Europe on March 20, 2009, in North America on March 30, 2009, and in Japan on July 7, 2009. The game was also released on the New Nintendo 3DS eShop on May 5, 2016. Nintendo re-released Super Punch-Out!! in the United States in September 2017 as part of the company''s Super NES Classic Edition. It is the fourth game in the Punch-Out!! series, taking place after the Punch-Out!! game for the Nintendo Entertainment System (NES).', 'https://media.retroachievements.org/Images/112176.png', 'https://media.retroachievements.org/Images/060910.png', 'https://media.retroachievements.org/Images/050219.png', 'https://media.retroachievements.org/Images/050220.png', 4.6),
  (17, 648, 'Street Fighter II Turbo: Hyper Fighting', 'SNES/Super Famicom', 3, 11003, 11003, 11003, 32, 0, '2D Fighting', 'Capcom', 'Capcom', '1993-07-11', 'Street Fighter II Turbo: Hyper Fighting, released as Street Fighter II Dash Turbo in Japan, is a 1992 fighting game developed and published by Capcom for arcades. It is the third arcade version of Street Fighter II, part of the Street Fighter franchise, following Street Fighter II: Champion Edition, and was initially released as an enhancement kit for that game. Released less than a year after the previous installment, Hyper Fighting introduced a faster playing speed and new special moves for certain characters, as well as further refinement to the character balance.', 'https://media.retroachievements.org/Images/117039.png', 'https://media.retroachievements.org/Images/044318.png', 'https://media.retroachievements.org/Images/044319.png', 'https://media.retroachievements.org/Images/000907.png', 4.5),
  (18, 405, 'Zombies Ate My Neighbors', 'SNES/Super Famicom', 3, 10897, 10897, 10897, 95, 0, 'Action', 'LucasArts | Lucasfilm', 'Konami', '1993-09-01', 'Zombies Ate My Neighbors is a 1993 run and gun video game developed by LucasArts and published by Konami for the Super Nintendo Entertainment System and Sega Genesis. The player controls the protagonists Zeke and Julie in order to rescue the titular neighbors from monsters often seen in horror films. Aiding them in this task are a variety of weapons and power-ups that can be used to battle the numerous enemies in each level. Various elements and aspects of horror movies are referenced in the game with some of its more violent content being censored in various territories such as Europe and Australia, where it is known only as Zombies.', 'https://media.retroachievements.org/Images/043812.png', 'https://media.retroachievements.org/Images/074446.png', 'https://media.retroachievements.org/Images/074447.png', 'https://media.retroachievements.org/Images/074448.png', 4.5),
  (19, 470, 'Super Bomberman', 'SNES/Super Famicom', 3, 10760, 10760, 10760, 54, 0, 'Action', 'Hudson Soft', 'Hudson Soft', '1993-04-28', 'Super Bomberman is a 1993 action maze video game developed by Produce! and published by Hudson Soft for the Super Nintendo Entertainment System. Part of the Bomberman series, it is the first game in the to retain the Bomberman title in Europe, instead of being renamed to Dynablaster or Eric and the Floaters.', 'https://media.retroachievements.org/Images/043551.png', 'https://media.retroachievements.org/Images/112595.png', 'https://media.retroachievements.org/Images/039426.png', 'https://media.retroachievements.org/Images/039427.png', 4.5),
  (20, 400, 'Secret of Mana', 'SNES/Super Famicom', 3, 10560, 10560, 10560, 85, 0, 'Action RPG', 'Square', 'Squaresoft', '1993-08-06', 'Secret of Mana, originally released in Japan as Seiken Densetsu 2, is a 1993 action role-playing game developed and published by Square for the Super Nintendo Entertainment System. It is the sequel to the 1991 game Seiken Densetsu which was released in North America as Final Fantasy Adventure and in Europe as Mystic Quest. Secret of Mana was the first Seiken Densetsu title to be marketed as part of the Mana series rather than the Final Fantasy series. Set in a high fantasy universe, the game follows three heroes as they attempt to prevent an empire from conquering the world with the power of an ancient flying fortress.', 'https://media.retroachievements.org/Images/099440.png', 'https://media.retroachievements.org/Images/067832.png', 'https://media.retroachievements.org/Images/000277.png', 'https://media.retroachievements.org/Images/000152.png', 4.5),
  (21, 813, 'Kirby''s Dream Land 3', 'SNES/Super Famicom', 3, 10462, 10462, 10462, 32, 0, '2D Platforming', 'HAL Laboratory', 'Nintendo', '1997-11-17', 'Kirby''s Dream Land 3 is a 1997 platform game developed by HAL Laboratory and published by Nintendo for the Super Nintendo Entertainment System. Starring Kirby, it is the fifth installment in the Kirby series and the third game under the Kirby''s Dream Land name. Although the first game was largely unrelated, Dream Land 3 features many similar characters to Dream Land 2. Dream Land 3 was followed by Kirby 64: The Crystal Shards in 2000.', 'https://media.retroachievements.org/Images/114700.png', 'https://media.retroachievements.org/Images/055863.png', 'https://media.retroachievements.org/Images/118726.png', 'https://media.retroachievements.org/Images/118727.png', 4.5),
  (22, 238, 'Goof Troop', 'SNES/Super Famicom', 3, 8682, 8682, 8682, 28, 0, NULL, 'Capcom', 'Capcom', '1993-07-11', 'Goof-Troop is an American animated sitcom produced by Walt Disney Television Animation. The series focuses on the relationship between single-father Goofy and his son, Max, as well as their neighbor Pete and his family. Created by Robert Taylor and Michael Peraza Jr., the main-series of 65 episodes aired in first-run-syndication from 1992 to 1993 on The Disney Afternoon programming block, while an additional thirteen episodes aired on Saturday mornings on ABC. A Christmas special was also produced and aired in syndication in late 1992.', 'https://media.retroachievements.org/Images/111712.png', 'https://media.retroachievements.org/Images/000371.png', 'https://media.retroachievements.org/Images/034926.png', 'https://media.retroachievements.org/Images/000369.png', 4.5),
  (23, 344, 'Contra III: The Alien Wars', 'SNES/Super Famicom', 3, 8596, 8596, 8596, 30, 0, '2D Platforming, Run & Gun', 'Konami', 'Konami', '1992-02-28', 'Contra III: The Alien Wars is a 1992 run and gun video game developed and published by Konami for the Super Nintendo Entertainment System (SNES). It is the third home console entry in the Contra series after Contra (1988) and Super Contra (1990) for the Nintendo Entertainment System (NES). In PAL regions, it was retitled Super Probotector: Alien Rebels and the player characters were replaced with robots. The player is tasked with fighting off an alien invasion of Earth across six stages. Four stages feature side-scrolling action traditional to the series while two are presented from an overhead perspective. It is the first Contra title to have been directed by Nobuya Nakazato who later directed other games in the series. He designed Contra III to feature more comical elements, a more cinematic soundtrack, and tighter stage design than its predecessors.', 'https://media.retroachievements.org/Images/110814.png', 'https://media.retroachievements.org/Images/000144.png', 'https://media.retroachievements.org/Images/038814.png', 'https://media.retroachievements.org/Images/068064.png', 4.5),
  (24, 889, 'Earthworm Jim', 'SNES/Super Famicom', 3, 8213, 8213, 8213, 35, 0, '2D Platforming', 'Shiny Entertainment', 'Virgin Interactive', '1994-10-01', 'Earthworm Jim is a series of platform games featuring an earthworm named Jim who wears a robotic suit and battles the forces of evil. The series is noted for its platforming and shooting gameplay, surreal humor, and edgy art style. Four games were released in the series: Earthworm Jim, Earthworm Jim 2, Earthworm Jim 3D, and Earthworm Jim: Menace 2 the Galaxy, with the first game released in 1994. The series had lain dormant for almost a decade before Gameloft remade the original game in HD for PlayStation Network and Xbox Live Arcade in 2010. Interplay announced Earthworm Jim 4 in 2008; little to no information surfaced until May 2019 and August 2020, and development was believed cancelled by the rights owners by 2023, as it had never left pre-planning stages.', 'https://media.retroachievements.org/Images/115156.png', 'https://media.retroachievements.org/Images/005599.png', 'https://media.retroachievements.org/Images/005597.png', 'https://media.retroachievements.org/Images/005598.png', 4.5),
  (25, 469, 'Mega Man 7', 'SNES/Super Famicom', 3, 7710, 7710, 7710, 49, 0, '2D Platforming', 'Capcom', 'Capcom', '1995-03-24', 'Mega Man 7, known in Japan as Rockman 7: Showdown of Destiny!, is a 1995 action game developed and published by Capcom for the Super Nintendo Entertainment System (SNES). It is the seventh game in the original Mega Man series. The game was released in Japan on March 24, 1995 and was localized later in the year in North America and Europe.', 'https://media.retroachievements.org/Images/105305.png', 'https://media.retroachievements.org/Images/000919.png', 'https://media.retroachievements.org/Images/035629.png', 'https://media.retroachievements.org/Images/035631.png', 4.4),
  (26, 629, 'Mega Man X2', 'SNES/Super Famicom', 3, 7681, 7681, 7681, 70, 0, '2D Platforming', 'Capcom', 'Capcom', '1994-12-16', 'Mega Man X2, known as Rockman X2 (ロックマンX2) in Japan, is a 1994 platform game developed and published by Capcom for the Super Nintendo Entertainment System (SNES). The game was released in Japan on December 16, 1994, and in North America and PAL regions in 1995. It is the direct sequel to Mega Man X, released one year prior. Mega Man X2 takes place in the near future in which humans try to peacefully coexist with intelligent robots called Reploids, with some of the Reploids going Maverick and threatening daily life. The plot follows the android protagonist X, a Maverick Hunter who saved humanity from the evil Sigma six months earlier. A trio of Mavericks calling themselves the X-Hunters has arisen, intent on destroying X by luring him with body parts of his comrade Zero, who died in the conflict with Sigma''s right-hand robot Vile.', 'https://media.retroachievements.org/Images/023582.png', 'https://media.retroachievements.org/Images/000929.png', 'https://media.retroachievements.org/Images/035388.png', 'https://media.retroachievements.org/Images/035380.png', 4.4),
  (27, 333, 'Sunset Riders', 'SNES/Super Famicom', 3, 7654, 7654, 7654, 36, 0, NULL, 'Konami', 'Konami', '1993-08-06', 'Sunset Riders is a 1991 run and gun video game developed and published by Konami for arcades. It was released in North America in October 1991 and Japan in November 1991. It is set in the American Old West, where the player(s) take control of bounty hunters who are seeking the rewards offered for various criminals.', 'https://media.retroachievements.org/Images/052084.png', 'https://media.retroachievements.org/Images/032880.png', 'https://media.retroachievements.org/Images/035384.png', 'https://media.retroachievements.org/Images/032886.png', 4.4),
  (28, 341, 'Final Fantasy VI', 'SNES/Super Famicom', 3, 7629, 7629, 7629, 115, 0, NULL, 'Square', 'Squaresoft', '1994-10-20', 'Final Fantasy VI, titled Final Fantasy III in its initial North American release, is a 1994 role-playing video game developed and published by Square for the Super Nintendo Entertainment System. It is the sixth main entry in the Final Fantasy series, the final to feature 2D sprite based graphics, and the first to be directed by someone other than series creator Hironobu Sakaguchi; the role was instead filled by Yoshinori Kitase and Hiroyuki Ito. Long-time collaborator Yoshitaka Amano returned as character designer and concept artist, while composer Nobuo Uematsu returned to compose the game''s score, which has been released on several soundtrack albums.', 'https://media.retroachievements.org/Images/070796.png', 'https://media.retroachievements.org/Images/001377.png', 'https://media.retroachievements.org/Images/001378.png', 'https://media.retroachievements.org/Images/034210.png', 4.4),
  (29, 323, 'Final Fight 3', 'SNES/Super Famicom', 3, 7474, 7474, 7474, 59, 0, NULL, 'Capcom', 'Capcom', '1995-12-22', 'Final Fight 3, released in Japan as Final Fight Tough , is a 1995 beat ''em up video game developed and published by Capcom for the Super Nintendo Entertainment System. It is the second sequel to Final Fight released for the Super NES, following Final Fight 2. Like its predecessor, it was produced by Capcom''s consumer division with no preceding arcade version released.', 'https://media.retroachievements.org/Images/101605.png', 'https://media.retroachievements.org/Images/006039.png', 'https://media.retroachievements.org/Images/036002.png', 'https://media.retroachievements.org/Images/036004.png', 4.4),
  (30, 392, 'Arkanoid: Doh It Again', 'SNES/Super Famicom', 3, 7215, 7215, 7215, 61, 0, 'Brick Breakers', 'Taito', 'Taito', '1997-01-15', 'Arkanoid: Doh It Again is a 1997 block breaker video game developed and published by Taito. It was first released in Japan for the Super Famicom and Windows, while Nintendo published the SNES version in Australia, North America and Europe. It is the third installment in the Arkanoid series after the original 1986 arcade game and its sequel Arkanoid: Revenge of Doh.', 'https://media.retroachievements.org/Images/008000.png', 'https://media.retroachievements.org/Images/007188.png', 'https://media.retroachievements.org/Images/007998.png', 'https://media.retroachievements.org/Images/007999.png', 4.4),
  (31, 270, 'ActRaiser', 'SNES/Super Famicom', 3, 6648, 6648, 6648, 66, 0, 'Action', 'Quintet', 'Enix, Squaresoft', '1990-12-16', 'ActRaiser is a 1990 video game developed by Quintet and published by Enix for the Super Nintendo Entertainment System. It combines traditional side-scrolling platforming and sections with city building elements. A sequel, ActRaiser 2, was released for the Super NES in 1993. In 2007, ActRaiser became available on the Wii''s Virtual Console download service in Europe, North America, and Japan. A version of the game was also released for European mobile phones in 2004. A remake, Actraiser Renaissance, was released for several platforms in 2021.', 'https://media.retroachievements.org/Images/110040.png', 'https://media.retroachievements.org/Images/001235.png', 'https://media.retroachievements.org/Images/004107.png', 'https://media.retroachievements.org/Images/028692.png', 4.4),
  (32, 1192, 'Street Fighter II: The World Warrior', 'SNES/Super Famicom', 3, 6170, 6170, 6170, 31, 0, '2D Fighting', 'Capcom', 'Capcom', '1991-02-06', 'Street Fighter II: The World Warrior is a 1991 fighting game developed and published by Capcom for arcades. It is the second installment in the Street Fighter series, and the sequel to 1987''s Street Fighter. Designed by Yoshiki Okamoto and Akira Yasuda, who had previously worked on the game Final Fight, it is the fourteenth game to use Capcom''s CP System arcade system board. Street Fighter II vastly improved many of the concepts introduced in the first game, including the use of special command-based moves, a combo system, a six-button configuration, and a wider selection of playable characters, each with a unique fighting style.', 'https://media.retroachievements.org/Images/117038.png', 'https://media.retroachievements.org/Images/006020.png', 'https://media.retroachievements.org/Images/006018.png', 'https://media.retroachievements.org/Images/006019.png', 4.4),
  (33, 1103, 'Pocky & Rocky', 'SNES/Super Famicom', 3, 6084, 6084, 6084, 36, 0, NULL, 'Natsume', 'Natsume', '1992-12-22', 'Pocky & Rocky, known in Japan as Kiki Kaikai , is a scrolling shooter video game series originating with the 1986 arcade game Kiki Kaikai by Taito. The game was adapted into a series of home console games mainly developed and published by Natsume which were titled Pocky & Rocky in the West. The games follow the adventures of a young Shinto shrine maiden, Pocky, and her tanuki companion, Rocky, as they fight against monsters from Japanese mythology.', 'https://media.retroachievements.org/Images/026005.png', 'https://media.retroachievements.org/Images/061348.png', 'https://media.retroachievements.org/Images/085738.png', 'https://media.retroachievements.org/Images/085739.png', 4.4),
  (34, 401, 'Super Star Wars', 'SNES/Super Famicom', 3, 5896, 5896, 5896, 31, 0, '2D Platforming', 'LucasArts | Lucasfilm', 'LucasArts | Lucasfilm', '1992-06-01', 'Super Star Wars is a 1992 run and gun video game based on the 1977 film Star Wars, developed by LucasArts and Sculptured Software and published by JVC Musical Industries for the Super Nintendo Entertainment System. The game features side-scrolling run and gun and platform gameplay, although it has stages which feature other challenges, such as driving a landspeeder or piloting an X-wing. It also features multiple playable characters with different abilities.', 'https://media.retroachievements.org/Images/072974.png', 'https://media.retroachievements.org/Images/005978.png', 'https://media.retroachievements.org/Images/005977.png', 'https://media.retroachievements.org/Images/005980.png', 4.4),
  (35, 300, 'Castlevania: Dracula X', 'SNES/Super Famicom', 3, 5814, 5814, 5814, 30, 0, NULL, 'Konami', 'Konami', '1995-07-21', 'Castlevania: Dracula X, titled Castlevania: Vampire''s Kiss in Europe and Akumajou Dracula XX in Japan, is a 1995 platform game developed and published by Konami for the Super Nintendo Entertainment System. It is the second Castlevania installment to be released for the Super NES. It is a remake of Castlevania: Rondo of Blood, which was previously released in Japan on the PC Engine Super CD-ROM2 in 1993. While the plot is similar to Rondo of Blood and it uses many of that game''s graphics, it features new levels and altered gameplay elements, rather than being a direct port because of the limits of the Super NES cartridge format and exclusivity agreements with PC Engine maker NEC. It was released on July 21, 1995 in Japan, in September 1995 in North America, February 22, 1996 in Europe, and on June 22, 1996, in Australia. The game received mixed reviews, with journalists considering it inferior to Rondo of Blood and criticizing its high difficulty.', 'https://media.retroachievements.org/Images/106341.png', 'https://media.retroachievements.org/Images/071788.png', 'https://media.retroachievements.org/Images/071787.png', 'https://media.retroachievements.org/Images/071786.png', 4.4),
  (36, 1216, 'Super Ghouls ''n Ghosts', 'SNES/Super Famicom', 3, 5797, 5797, 5797, 50, 0, '2D Platforming, Action', 'Capcom', 'Capcom', '1991-10-04', 'Super Ghouls ''n Ghosts, known as Chō Makaimura in Japan, is a 1991 platform video game developed and published by Capcom for the Super Nintendo Entertainment System. The third installment in the Ghosts ''n Goblins series and the first not to be released for arcades, it again depicts knight Arthur saving Princess Guinevere and the kingdom from Emperor Sardius, who has cast a spell that has revived the Ghoul Realm.', 'https://media.retroachievements.org/Images/119128.png', 'https://media.retroachievements.org/Images/000136.png', 'https://media.retroachievements.org/Images/000015.png', 'https://media.retroachievements.org/Images/000016.png', 4.4),
  (37, 582, 'Ultimate Mortal Kombat 3', 'SNES/Super Famicom', 3, 5742, 5742, 5742, 45, 0, '2D Fighting', 'Avalanche Software', 'Acclaim, Williams Entertainment', '1996-10-01', 'Ultimate Mortal Kombat 3 is a 1995 fighting game developed and published by Midway for arcades. Part of the Mortal Kombat series, it is a standalone update of 1995''s earlier Mortal Kombat 3 with an altered gameplay system and some new features, as well as additional characters like the returning favorites Reptile, Kitana, Jade and Scorpion, who were missing from Mortal Kombat 3.', 'https://media.retroachievements.org/Images/054585.png', 'https://media.retroachievements.org/Images/006697.png', 'https://media.retroachievements.org/Images/001355.png', 'https://media.retroachievements.org/Images/001356.png', 4.4),
  (38, 887, 'E.V.O.: Search for Eden', 'SNES/Super Famicom', 3, 5726, 5726, 5726, 59, 0, 'Action RPG', 'Almanic | Givro', 'Enix', '1993-01-01', 'E.V.O.: Search for Eden is a 1992 action-adventure game developed by Almanic Corporation and published by Enix for the Super NES. Combining traditional platforming mechanics with experience and leveling mechanics originating from role playing games, E.V.O.: Search for Eden involves the player navigating a creature through a number of side-scrolling levels while undergoing bodily evolution to cope with ever-changing environments. It is heavily based on Almanic''s original title, 46 Okunen Monogatari ~The Shinka Ron~, released in Japan in 1990 for the PC-9801.', 'https://media.retroachievements.org/Images/061403.png', 'https://media.retroachievements.org/Images/004293.png', 'https://media.retroachievements.org/Images/004294.png', 'https://media.retroachievements.org/Images/004295.png', 4.4),
  (39, 1034, 'Mighty Morphin Power Rangers', 'SNES/Super Famicom', 3, 5649, 5649, 5649, 21, 0, 'Beat ''em Up', 'Natsume', 'Bandai', '1994-09-01', 'Mighty Morphin Power Rangers (MMPR) is an American superhero television series produced by Saban Entertainment, which aired from August 28, 1993 to November 27, 1995, on the Fox Kids programming block, lasting three seasons. The series drew elements and stock footage from Super Sentai, a Japanese television series by Toei Company. Each season was inspired by Kyoryu Sentai Zyuranger, Gosei Sentai Dairanger, and Ninja Sentai Kakuranger, respectively. The series is the first entry of the Power Rangers franchise.', 'https://media.retroachievements.org/Images/103846.png', 'https://media.retroachievements.org/Images/001906.png', 'https://media.retroachievements.org/Images/035632.png', 'https://media.retroachievements.org/Images/035633.png', 4.4),
  (40, 468, 'Final Fight 2', 'SNES/Super Famicom', 3, 5583, 5583, 5583, 45, 0, 'Beat ''em Up', 'Capcom', 'Capcom', '1993-01-01', 'Final Fight 2  is a 1993 beat ''em up game released by Capcom for the Super Nintendo Entertainment System. It is the direct sequel to the 1989 arcade game Final Fight, which was previously also released for the SNES. Final Fight 2 was developed by Capcom''s consumer division with no preceding coin-op version. The game was re-released onto Wii''s Virtual Console service in 2009 worldwide.', 'https://media.retroachievements.org/Images/101604.png', 'https://media.retroachievements.org/Images/125189.png', 'https://media.retroachievements.org/Images/001260.png', 'https://media.retroachievements.org/Images/028603.png', 4.4),
  (41, 878, 'The Lion King', 'SNES/Super Famicom', 3, 5461, 5461, 5461, 33, 0, '2D Platforming', 'Westwood Studios | Westwood Associates', 'Virgin Interactive', '1994-12-08', 'The Lion King is a 1994 American animated musical drama film directed by Roger Allers and Rob Minkoff, produced by Don Hahn, and written by Irene Mecchi, Jonathan Roberts, and Linda Woolverton. It was produced by Walt Disney Feature Animation, and features an ensemble voice cast consisting of Matthew Broderick, James Earl Jones, Jeremy Irons, Jonathan Taylor Thomas, Moira Kelly, Niketa Calame, Nathan Lane, Ernie Sabella, Whoopi Goldberg, Cheech Marin, Rowan Atkinson, and Robert Guillaume. The story follows a young lion prince named Simba, who is exiled from his kingdom after his father Mufasa is murdered by his uncle Scar to seize the throne. As he grows up, Simba must decide whether to return home to confront Scar and reclaim his place as king.', 'https://media.retroachievements.org/Images/034930.png', 'https://media.retroachievements.org/Images/003100.png', 'https://media.retroachievements.org/Images/003101.png', 'https://media.retroachievements.org/Images/003102.png', 4.4),
  (42, 351, 'Star Fox', 'SNES/Super Famicom', 3, 5312, 5312, 5312, 39, 0, 'Rail Shooter', 'Argonaut Games', 'Nintendo', '1993-02-21', 'Star Fox is a rail shooter, space flight simulator, and third person action-adventure video game series created by the Japanese game designer Shigeru Miyamoto and developed and published by Nintendo. The games follow the Star Fox combat team of anthropomorphic animals, led by chief protagonist Fox McCloud. Gameplay involves missions around the Lylat planetary system in the futuristic Arwing fighter spacecraft, in other vehicles, and on foot. The original Star Fox (1993) is a forward-scrolling 3D rail shooter, but later games add more directional freedom.', 'https://media.retroachievements.org/Images/071849.png', 'https://media.retroachievements.org/Images/001342.png', 'https://media.retroachievements.org/Images/088715.png', 'https://media.retroachievements.org/Images/001340.png', 4.4),
  (43, 815, 'Tetris Attack', 'SNES/Super Famicom', 3, 5302, 5302, 5302, 50, 0, NULL, 'Intelligent Systems', 'Nintendo', '1995-10-27', 'Tetris Attack, also known as Panel de Pon in Japan, is a 1995 puzzle video game developed by Intelligent Systems and published by Nintendo for the Super Nintendo Entertainment System. A Game Boy version was released a year later. In the game, the player must arrange matching colored blocks in vertical or horizontal rows to clear them. The blocks steadily rise to the top of the playfield, with new blocks being added at the bottom. Several gameplay modes are present, including a time attack and multiplayer mode.', 'https://media.retroachievements.org/Images/112288.png', 'https://media.retroachievements.org/Images/000166.png', 'https://media.retroachievements.org/Images/000165.png', 'https://media.retroachievements.org/Images/000034.png', 4.4),
  (44, 945, 'Illusion of Gaia', 'SNES/Super Famicom', 3, 5020, 5020, 5020, 45, 0, 'Action RPG', 'Quintet', 'Enix', '1993-11-27', 'Illusion of Gaia, known in PAL territories as Illusion of Time, is an action role-playing video game developed by Quintet for the Super Nintendo Entertainment System. The game was released in Japan by Enix in 1993, and in North America and PAL territories by Nintendo in 1994 and 1995. Set in a fantasy reimagining of Earth, the game''s plot centers on a boy named Will who is chosen to save the world from an impending disaster. Throughout the game, the player guides Will through levels inspired by the ancient ruins of real-world civilizations and Wonders of the World, including the Great Pyramid and the Great Wall of China.', 'https://media.retroachievements.org/Images/063183.png', 'https://media.retroachievements.org/Images/066745.png', 'https://media.retroachievements.org/Images/004212.png', 'https://media.retroachievements.org/Images/004215.png', 4.3),
  (45, 237, 'Rock n'' Roll Racing', 'SNES/Super Famicom', 3, 4890, 4890, 4890, 35, 0, 'Racing', 'Blizzard Entertainment', 'Interplay Entertainment', '1993-04-06', 'Rock n'' Roll Racing is a vehicular combat-based racing video game developed by Silicon & Synapse and published by Interplay Productions for the Super Nintendo Entertainment System in 1993 and the Mega Drive/Genesis in 1994. The game prominently features a number of popular heavy metal and rock songs in its soundtrack, hence the game''s title. After Silicon & Synapse rebranded into Blizzard Entertainment, a port to the Game Boy Advance was released in 2003. In celebration of the company''s 30th anniversary, a new version titled Definitive Edition alongside emulated re-releases of the original game were re-released for Nintendo Switch, PlayStation 4, Windows, and Xbox One as part of the Blizzard Arcade Collection in February 2021.', 'https://media.retroachievements.org/Images/045856.png', 'https://media.retroachievements.org/Images/000870.png', 'https://media.retroachievements.org/Images/000869.png', 'https://media.retroachievements.org/Images/000119.png', 4.3),
  (46, 1374, 'Super Bomberman 4', 'SNES/Super Famicom', 3, 4800, 4800, 4800, 37, 0, 'Action', 'Produce!', 'Hudson Soft', '1996-04-26', 'Super Bomberman 4 is an action-party video game developed by Produce and published by Hudson Soft. It was developed for the Super Famicom, released on April 26, 1996, in Japan. Part of the Bomberman franchise, it is the fourth installment of the Super Bomberman series.', 'https://media.retroachievements.org/Images/043554.png', 'https://media.retroachievements.org/Images/038288.png', 'https://media.retroachievements.org/Images/001488.png', 'https://media.retroachievements.org/Images/034094.png', 4.3),
  (47, 1233, 'Super Smash T.V.', 'SNES/Super Famicom', 3, 4783, 4783, 4783, 21, 0, 'Twin Stick Shooter', 'Beam Software', 'Acclaim', '1992-01-01', 'Smash TV is a 1990 twin-stick shooter video game developed and published by Williams Electronics for arcades. It was designed by Eugene Jarvis and programmed by Mark Turmell, with similar gameplay to Jarvis'' earlier game Robotron: 2084 (1982). The Super Nintendo Entertainment System, Sega Genesis, Master System and Game Gear versions are titled Super Smash TV.', 'https://media.retroachievements.org/Images/072194.png', 'https://media.retroachievements.org/Images/002088.png', 'https://media.retroachievements.org/Images/002090.png', 'https://media.retroachievements.org/Images/002091.png', 4.3),
  (48, 1168, 'Soul Blazer', 'SNES/Super Famicom', 3, 4704, 4704, 4704, 80, 0, 'Action RPG', 'Quintet', 'Enix', '1992-01-31', 'Soul Blazer, released in Japan as Soul Blader, is an action role-playing video game developed by Quintet and published by Enix for the Super Nintendo Entertainment System. It was released in 1992 in Japan and North America, but not released in Europe until 1994. It was not released in the United Kingdom.', 'https://media.retroachievements.org/Images/035099.png', 'https://media.retroachievements.org/Images/052164.png', 'https://media.retroachievements.org/Images/005449.png', 'https://media.retroachievements.org/Images/005450.png', 4.3),
  (49, 242, 'Terranigma', 'SNES/Super Famicom', 3, 4569, 4569, 4569, 98, 0, 'Action RPG', 'Quintet', 'Enix', '1995-10-20', 'Terranigma is a 1995 action role-playing game developed by Quintet for the Super Nintendo Entertainment System (SNES), with manga artist Kamui Fujiwara acting as the character designer. The game tells the story of the Earth''s resurrection by the hands of a boy named Ark, and its progress from the evolution of life to the present day. The game is the third entry in an unofficial trilogy of action role-playing games created by Quintet, also including Soul Blazer (1992) and Illusion of Gaia (1993).', 'https://media.retroachievements.org/Images/035303.png', 'https://media.retroachievements.org/Images/028323.png', 'https://media.retroachievements.org/Images/002917.png', 'https://media.retroachievements.org/Images/002920.png', 4.3),
  (50, 830, 'The Adventures of Batman & Robin', 'SNES/Super Famicom', 3, 4500, 4500, 4500, 27, 0, 'Action', 'Konami', 'Konami', '1994-01-01', 'Batman: The Animated Series is an American animated superhero television series based on the DC Comics superhero Batman. Developed by Bruce Timm and Eric Radomski, and produced by Warner Bros. Animation, it originally aired on Fox Kids from September 5, 1992, to September 15, 1995, with a total of 85 episodes. Mid-way through the series'' run, it was re-titled The Adventures of Batman & Robin.', 'https://media.retroachievements.org/Images/048996.png', 'https://media.retroachievements.org/Images/005796.png', 'https://media.retroachievements.org/Images/035402.png', 'https://media.retroachievements.org/Images/035403.png', 4.3),
  (51, 436, 'Blackthorne', 'SNES/Super Famicom', 3, 4390, 4390, 4390, 26, 0, 'Action-Adventure', 'Blizzard Entertainment', 'Interplay Entertainment', '1994-01-01', 'Blackthorne is a cinematic platform game developed by Blizzard Entertainment. It was released for the Super NES and MS-DOS in 1994. The cover art for the SNES version was drawn by Jim Lee. The following year, Blackthorne was released for the Sega 32X with additional content. In 2013, Blizzard released the game for free on their Battle.net PC client. In celebration of the company''s 30th anniversary, Blackthorne was re-released for Nintendo Switch, PlayStation 4, Windows, and Xbox One as part of the Blizzard Arcade Collection in February 2021.', 'https://media.retroachievements.org/Images/045841.png', 'https://media.retroachievements.org/Images/004631.png', 'https://media.retroachievements.org/Images/030906.png', 'https://media.retroachievements.org/Images/030905.png', 4.3),
  (52, 2132, 'Doom', 'SNES/Super Famicom', 3, 4322, 4322, 4322, 57, 0, 'First-Person Shooter', 'Sculptured Software | Iguana West', 'Williams Entertainment', '1995-09-01', 'Doom is an American media franchise created by John Carmack, John Romero, Adrian Carmack, Kevin Cloud, and Tom Hall. The series usually focuses on the exploits of an unnamed space marine operating under the auspices of the Union Aerospace Corporation (UAC), who fights hordes of demons and the undead to save Earth from an apocalyptic invasion.', 'https://media.retroachievements.org/Images/076913.png', 'https://media.retroachievements.org/Images/077372.png', 'https://media.retroachievements.org/Images/007274.png', 'https://media.retroachievements.org/Images/007275.png', 4.3),
  (53, 340, 'Wild Guns', 'SNES/Super Famicom', 3, 4217, 4217, 4217, 87, 0, 'Gallery Shooter', 'Natsume', 'Natsume', '1994-08-12', 'Wild Guns is a 1994 shooting gallery video game developed and published by Natsume Co., Ltd. for the Super Nintendo Entertainment System. Set in the Wild West with steampunk and sci-fi influences, the story follows Annie and her bounty hunter Clint, seeking revenge for the death of her family. The player controls either Annie or Clint sidestepping and jumping in the foreground while shooting down enemy robots in the background and dodging enemy bullets. These gameplay mechanics combine elements from third-person shooters and light gun games.', 'https://media.retroachievements.org/Images/071911.png', 'https://media.retroachievements.org/Images/000911.png', 'https://media.retroachievements.org/Images/035393.png', 'https://media.retroachievements.org/Images/035394.png', 4.3),
  (54, 500, 'Super Bomberman 2', 'SNES/Super Famicom', 3, 4070, 4070, 4070, 63, 0, 'Action', 'Hudson Soft', 'Hudson Soft', '1994-04-28', 'Super Bomberman 2 is a 1994 action maze video game developed by Produce! and published by Hudson Soft for the Super Nintendo Entertainment System. It is the second installment of the Super Bomberman series, part of the larger Bomberman franchise, and the only installment without a two-player story mode. The game was re-released in 2026 as part of the Super Bomberman Collection compilation.', 'https://media.retroachievements.org/Images/043552.png', 'https://media.retroachievements.org/Images/112599.png', 'https://media.retroachievements.org/Images/015551.png', 'https://media.retroachievements.org/Images/015552.png', 4.3),
  (55, 821, 'Secret of Evermore', 'SNES/Super Famicom', 3, 3976, 3976, 3976, 41, 0, 'Action RPG', 'Square', 'Squaresoft', '1995-10-01', 'Secret of Evermore is an action role-playing game developed and published by Squaresoft for the Super Nintendo Entertainment System. It was released in North America on October 17, 1995, in Australia in February 1996, and in Europe in March 1996. A Japanese release was planned to follow the North American release by a few months but was ultimately cancelled.', 'https://media.retroachievements.org/Images/048277.png', 'https://media.retroachievements.org/Images/043435.png', 'https://media.retroachievements.org/Images/120996.png', 'https://media.retroachievements.org/Images/120998.png', 4.3),
  (56, 1143, 'R-Type III: The Third Lightning', 'SNES/Super Famicom', 3, 3884, 3884, 3884, 31, 0, 'Shoot ''em Up', 'Irem', 'Jaleco', '1993-12-10', 'R-Type III: The Third Lightning  is a 1993 side-scrolling shooter video game developed by Tamtex and first released in Japan by Irem in 1993 for the Super Famicom and in North America and Europe in 1994 for the SNES.', 'https://media.retroachievements.org/Images/064800.png', 'https://media.retroachievements.org/Images/064805.png', 'https://media.retroachievements.org/Images/035364.png', 'https://media.retroachievements.org/Images/035365.png', 4.3),
  (57, 3594, 'Super Bomberman 3', 'SNES/Super Famicom', 3, 3813, 3813, 3813, 31, 0, 'Action', 'Hudson Soft', 'Hudson Soft', '1995-04-28', 'Super Bomberman 3 is a game released for the Super Nintendo Entertainment System in 1995. It is the third installment in the Super Bomberman series, and the third Bomberman game to be released for the system. Up to five players can play at the same time. The game was released in Japan and the PAL region, but not in North America due to the closure of Hudson Soft USA.', 'https://media.retroachievements.org/Images/043553.png', 'https://media.retroachievements.org/Images/112600.png', 'https://media.retroachievements.org/Images/006603.png', 'https://media.retroachievements.org/Images/006604.png', 4.3),
  (58, 1179, 'Spider-Man & Venom: Maximum Carnage', 'SNES/Super Famicom', 3, 3801, 3801, 3801, 39, 0, 'Beat ''em Up', 'Software Creations, Acclaim', 'Acclaim, LJN Entertainment', '1994-09-16', 'Spider-Man and Venom: Maximum Carnage is a 1994 beat ''em up video game developed by Software Creations and published by Acclaim Entertainment and its subsidiary LJN for the Super Nintendo Entertainment System and Sega Genesis. The game, based on the comic book story arc of the same name, features numerous heroes, including Spider-Man, Venom, and their allies from the Marvel Comics fictional universe like Captain America, Black Cat, Iron Fist, Cloak and Dagger, Deathlok, Morbius and Firestar, all teaming up to battle an onslaught of villains led by Carnage, including Shriek, Doppelganger, Demogoblin and Carrion.', 'https://media.retroachievements.org/Images/105532.png', 'https://media.retroachievements.org/Images/039425.png', 'https://media.retroachievements.org/Images/003623.png', 'https://media.retroachievements.org/Images/003621.png', 4.3),
  (59, 1025, 'Metal Warriors', 'SNES/Super Famicom', 3, 3754, 3754, 3754, 25, 0, NULL, 'LucasArts | Lucasfilm', 'Konami', '1995-04-01', 'Metal Warriors is a side-scrolling action-platform run and gun video game developed by LucasArts and published by Konami exclusively for the Super Nintendo Entertainment System in North America in April 1995. It is often confused by many to be a direct sequel to Cybernator, which was created by NCS Corporation and released earlier in 1992 on the console. Set in the year 2102 where dictator Venkar Amon has waged a war against the United Earth Government for three years, players assume the role of lieutenant Stone from the titular freedom-fighting group taking control of several mecha suits in a last-ditch effort to overthrow the Dark Axis military force on Earth. Its gameplay mainly consists of action and shooting mixed with mission-based exploration using a main seven-button configuration.', 'https://media.retroachievements.org/Images/050328.png', 'https://media.retroachievements.org/Images/007437.png', 'https://media.retroachievements.org/Images/008308.png', 'https://media.retroachievements.org/Images/008309.png', 4.3),
  (60, 309, 'Super Street Fighter II: The New Challengers', 'SNES/Super Famicom', 3, 3717, 3717, 3717, 36, 0, '2D Fighting', 'Capcom', 'Capcom', '1994-06-01', 'Super Street Fighter II: The New Challengers is a 1993 fighting game developed and published by Capcom for arcades. It is the fourth game in the Street Fighter II sub-series of Street Fighter games, following Street Fighter II Turbo (1992). It refines and balances the existing character roster from the previous versions, and introduces four new characters, including Fei Long, Cammy, T. Hawk, and Dee Jay. It is the first game on Capcom''s CP System II hardware, with more sophisticated graphics and audio over the original CP System hardware used in previous versions of Street Fighter II.', 'https://media.retroachievements.org/Images/119921.png', 'https://media.retroachievements.org/Images/004903.png', 'https://media.retroachievements.org/Images/004900.png', 'https://media.retroachievements.org/Images/004901.png', 4.3),
  (61, 279, 'Killer Instinct', 'SNES/Super Famicom', 3, 3685, 3685, 3685, 53, 0, '2D Fighting', 'Rare', 'Nintendo', '1995-08-30', 'Killer Instinct is a series of fighting video games originally created by Rare and published by Midway, Nintendo, and later Xbox Game Studios since the remake. The original Killer Instinct was released for arcades in 1994; the game was then released for the Super NES and Game Boy in 1995. Its sequel, Killer Instinct 2, was released for arcades in 1996; the game was then released as Killer Instinct Gold for the Nintendo 64.', 'https://media.retroachievements.org/Images/045854.png', 'https://media.retroachievements.org/Images/000169.png', 'https://media.retroachievements.org/Images/000167.png', 'https://media.retroachievements.org/Images/000040.png', 4.3),
  (62, 1198, 'Super Adventure Island', 'SNES/Super Famicom', 3, 3648, 3648, 3648, 20, 0, '2D Platforming', 'Produce!', 'Hudson Soft', '1992-01-11', 'Super Adventure Island  is a 1992 platform game developed by Produce! and published by Hudson Soft for the Super Nintendo Entertainment System. It was the first Adventure Island game released for the SNES and came out between the releases of the NES games Adventure Island II and Adventure Island 3. It was later followed by Super Adventure Island II. The game''s soundtrack was composed by Yuzo Koshiro.', 'https://media.retroachievements.org/Images/106432.png', 'https://media.retroachievements.org/Images/006291.png', 'https://media.retroachievements.org/Images/104839.png', 'https://media.retroachievements.org/Images/006293.png', 4.3),
  (63, 985, 'Kirby''s Avalanche', 'SNES/Super Famicom', 3, 3625, 3625, 3625, 46, 0, NULL, 'HAL Laboratory', 'Nintendo', '1995-02-01', 'Kirby''s Avalanche, known in Europe as Kirby''s Ghost Trap, is a puzzle video game developed by Compile and HAL Laboratory and published by Nintendo for the Super Nintendo Entertainment System. It was released in North America and Europe in February 1995. It is a Western release of the Japanese Super Puyo Puyo featuring characters from the Kirby series. There was not a Japanese release, and the game remains the only Kirby title not released there. In Europe and Australia, the game was re-released on the Wii''s Virtual Console service on July 27, 2007, and in North America on September 24, 2007. The game was re-released for the Nintendo Classics service on July 21, 2022.', 'https://media.retroachievements.org/Images/124147.png', 'https://media.retroachievements.org/Images/026559.png', 'https://media.retroachievements.org/Images/005964.png', 'https://media.retroachievements.org/Images/005965.png', 4.3),
  (64, 645, 'Captain Commando', 'SNES/Super Famicom', 3, 3546, 3546, 3546, 20, 0, 'Beat ''em Up', 'Capcom', 'Capcom', '1995-03-17', 'Captain Commando is a 1991 beat ''em up game developed and published by Capcom for arcades. It was the seventeenth game produced for the company''s CP System hardware. The game stars the titular superhero, who was originally conceived as a fictional spokesman used by Capcom USA in the company''s console games during the late 1980s. The game was included in Capcom Beat ''Em Up Bundle compilation title, which was released digitally for Nintendo Switch, PlayStation 4, Xbox One, and Windows in September 2018.', 'https://media.retroachievements.org/Images/051801.png', 'https://media.retroachievements.org/Images/002427.png', 'https://media.retroachievements.org/Images/035370.png', 'https://media.retroachievements.org/Images/039565.png', 4.3),
  (65, 593, 'NBA Jam', 'SNES/Super Famicom', 3, 3540, 3540, 3540, 28, 0, 'Sports - Basketball', 'Iguana Entertainment', 'Acclaim', '1994-03-04', 'NBA Jam is a basketball video game series based on the National Basketball Association (NBA). Initially developed as arcade games by Midway, the game found popularity with its photorealistic digitized graphics, over-the-top presentation and exaggerated style of two-on-two basketball play. The successor to Midway''s Arch Rivals, the original 1993 NBA Jam allows players to jump many times above their own height, make slam dunks that defy human capabilities, and freely shove or elbow opponents out of the way without consequences. It also featured a variety of secret characters, as well as the ability to track player records and statistics between play sessions.', 'https://media.retroachievements.org/Images/065579.png', 'https://media.retroachievements.org/Images/004697.png', 'https://media.retroachievements.org/Images/004699.png', 'https://media.retroachievements.org/Images/004698.png', 4.3),
  (66, 1156, 'SimCity', 'SNES/Super Famicom', 3, 3497, 3497, 3497, 33, 0, 'Management Simulation', 'Intelligent Systems', 'Nintendo', '1991-08-13', 'SimCity is an open-ended city-building video game franchise originally designed by Will Wright. The first game in the series, SimCity, was published by Maxis in 1989 and was followed by several sequels and many other spin-off Sim titles, including 2000''s The Sims, which itself became a best-selling computer game and franchise. Maxis developed the series independently until 1997, and continued under the ownership of Electronic Arts (EA) until 2003. EA commissioned various spinoffs from other companies during the 2000s, focusing on console and mobile releases. A 2013 EA-Maxis reboot was subject to what has been described as one of the most disastrous launches in history, which may have triggered the 2015 shutdown of Maxis Emeryville and the end of the franchise.', 'https://media.retroachievements.org/Images/050147.png', 'https://media.retroachievements.org/Images/004574.png', 'https://media.retroachievements.org/Images/004575.png', 'https://media.retroachievements.org/Images/004576.png', 4.3),
  (67, 498, 'Ninja Gaiden Trilogy', 'SNES/Super Famicom', 3, 3493, 3493, 3493, 75, 0, 'Action Platforming', 'Team Ninja', 'Koei | Tecmo', '1995-01-01', 'Ninja Gaiden  is an action game franchise created by Tecmo and featuring the ninja Ryu Hayabusa as its protagonist. The series was originally known as Ninja Ryukenden  in Japan. The word gaiden in the North American Ninja Gaiden title means side story in Japanese. The original arcade version, first two Nintendo Entertainment System games and Game Boy game were released as Shadow Warriors in PAL regions. As of 2008, the series had shipped over 7.7 million units worldwide.', 'https://media.retroachievements.org/Images/085543.png', 'https://media.retroachievements.org/Images/050034.png', 'https://media.retroachievements.org/Images/001308.png', 'https://media.retroachievements.org/Images/001309.png', 4.3),
  (68, 982, 'The King of Dragons', 'SNES/Super Famicom', 3, 3473, 3473, 3473, 62, 0, 'Beat ''em Up', 'Prism Kikaku', 'Capcom', '1994-01-01', 'The King of Dragons is a 1991 beat ''em up game developed and published by Capcom for arcades. It follows players as they control characters through the kingdom of Malus to defeat monsters led by the dragon Gildiss. It features a level advancement system, allowing character attributes to be upgraded as players progress through the game. The game''s music was composed by Yoko Shimomura.', 'https://media.retroachievements.org/Images/101561.png', 'https://media.retroachievements.org/Images/035376.png', 'https://media.retroachievements.org/Images/081295.png', 'https://media.retroachievements.org/Images/081294.png', 4.3),
  (69, 385, 'Animaniacs', 'SNES/Super Famicom', 3, 3447, 3447, 3447, 98, 0, '2D Platforming', 'Konami', 'Konami', '1994-11-01', 'Animaniacs is an American animated comedy television series created by animator Tom Ruegger and produced by Amblin Entertainment and Warner Bros. Television Animation. It originally aired on Fox''s Fox Kids block in 1993 before moving to The WB in 1995 as part of its Kids'' WB afternoon programming block until the series ended on November 14, 1998. It initially ran a total of 99 episodes, along with a direct-to-video film, Wakko''s Wish.', 'https://media.retroachievements.org/Images/046586.png', 'https://media.retroachievements.org/Images/007078.png', 'https://media.retroachievements.org/Images/007079.png', 'https://media.retroachievements.org/Images/007080.png', 4.3),
  (70, 963, 'Joe & Mac: Caveman Ninja', 'SNES/Super Famicom', 3, 3364, 3364, 3364, 37, 0, '2D Platforming', 'Data East', 'Data East', '1992-01-01', 'Joe & Mac, also known as Caveman Ninja or Caveman Ninja: Joe & Mac, is a 1991 run and gun platform game developed and published by Data East for arcades. It was later ported to the Super Nintendo Entertainment System, MS-DOS, Amiga, Nintendo Entertainment System, Game Boy, Sega Genesis and Zeebo.', 'https://media.retroachievements.org/Images/114169.png', 'https://media.retroachievements.org/Images/055373.png', 'https://media.retroachievements.org/Images/002298.png', 'https://media.retroachievements.org/Images/002300.png', 4.3),
  (71, 3227, 'Mario no Super Picross', 'SNES/Super Famicom', 3, 3345, 3345, 3345, 77, 0, 'Nonogram', 'Jupiter', 'Nintendo', '1995-09-14', 'Mario''s Super Picross is a Super Famicom sequel to Mario''s Picross, and a part of Nintendo''s Picross video game franchise. The game is compatible with the Super Famicom Mouse. It is developed by Jupiter and Ape and published by Nintendo.', 'https://media.retroachievements.org/Images/003359.png', 'https://media.retroachievements.org/Images/003365.png', 'https://media.retroachievements.org/Images/003364.png', 'https://media.retroachievements.org/Images/003366.png', 4.3),
  (72, 1444, 'Super Bomberman 5: Gold Cartridge', 'SNES/Super Famicom', 3, 3341, 3341, 3341, 46, 0, 'Action', 'Hudson Soft', 'Hudson Soft', '1997-02-28', 'The Super Nintendo Entertainment System has a library of 1,749 official releases, of which 717 were released in North America plus 4 championship cartridges, 532 in Europe, 1,440 in Japan, 231 on Satellaview, and 13 on SuFami Turbo. 296 releases are common to all regions, 147 were released in Japan and the US only, 165 in Europe and the US, and 27 in Japan and Europe. There are 977 Japanese exclusives, 111 US exclusives, and 35 European exclusives. The Super NES was released in North America on August 23, 1991, with its launch titles being Super Mario World, F-Zero, Pilotwings, Gradius III, and SimCity. Despite the console''s relatively late start, and the fierce competition it faced in North America and Europe from Sega''s Genesis/Mega Drive console, it was the best-selling console of its era.', 'https://media.retroachievements.org/Images/043555.png', 'https://media.retroachievements.org/Images/124841.png', 'https://media.retroachievements.org/Images/124882.png', 'https://media.retroachievements.org/Images/008472.png', 4.3),
  (73, 934, 'Harvest Moon', 'SNES/Super Famicom', 3, 3282, 3282, 3282, 83, 0, 'Life Simulation', 'Pack-In-Video', 'Natsume', '1996-08-09', 'Harvest Moon, known in Japan as Bokujō Monogatari , is a farm simulation role-playing video game developed by Amccus for the Super Nintendo Entertainment System. The game was first released in Japan by Pack-In-Video in 1996, in North America by Natsume Inc. in 1997, and in Europe by Nintendo in 1998. It is the first game in the long-running Story of Seasons series.', 'https://media.retroachievements.org/Images/106361.png', 'https://media.retroachievements.org/Images/002106.png', 'https://media.retroachievements.org/Images/002108.png', 'https://media.retroachievements.org/Images/002107.png', 4.2),
  (74, 286, 'International Superstar Soccer Deluxe', 'SNES/Super Famicom', 3, 3255, 3255, 3255, 80, 0, 'Sports - Football | Soccer', 'Konami', 'Konami', '1995-01-01', 'International Superstar Soccer Deluxe, known as Jikkyou World Soccer 2: Fighting Eleven in Japan and also known as ISS Deluxe, is a football video game and the sequel to International Superstar Soccer developed and published by Konami. The Deluxe version was published first to the SNES in 1995, then the Mega Drive in 1996 and finally the PlayStation in 1997.', 'https://media.retroachievements.org/Images/064259.png', 'https://media.retroachievements.org/Images/001289.png', 'https://media.retroachievements.org/Images/001286.png', 'https://media.retroachievements.org/Images/001287.png', 4.2),
  (75, 292, 'Knights of the Round', 'SNES/Super Famicom', 3, 3193, 3193, 3193, 25, 0, 'Beat ''em Up', 'Capcom', 'Capcom', '1991-01-01', 'Knights of the Round is a 1991 beat ''em up game developed and published by Capcom for arcades. Based loosely on the legend of King Arthur and the Knights of the Round Table, the game features an action role-playing-like level advancement system, with fighters automatically being upgraded to new weapons and armor as they advance through the game. The arcade version of the game was included in the compilations Capcom Beat ''Em Up Bundle (2018) and Capcom Arcade 2nd Stadium (2022).', 'https://media.retroachievements.org/Images/101833.png', 'https://media.retroachievements.org/Images/001293.png', 'https://media.retroachievements.org/Images/001290.png', 'https://media.retroachievements.org/Images/001291.png', 4.2),
  (76, 867, 'Cybernator', 'SNES/Super Famicom', 3, 3192, 3192, 3192, 28, 0, NULL, 'NCS', 'Konami', '1992-12-18', 'Assault Suits Valken, also known as Cybernator, is a 2D mecha action game developed by Masaya and released in 1992 for the Super Nintendo Entertainment System. The second entry in the Assault Suit series, it is a prequel to the first game, Target Earth. The game was localized and published overseas by Konami. The story follows Jake Brain who pilots a giant mecha and fights in a war engulfing the entire world.', 'https://media.retroachievements.org/Images/113702.png', 'https://media.retroachievements.org/Images/008505.png', 'https://media.retroachievements.org/Images/008506.png', 'https://media.retroachievements.org/Images/008507.png', 4.2),
  (77, 342, 'Gradius III', 'SNES/Super Famicom', 3, 3174, 3174, 3174, 56, 0, 'Shoot ''em Up', 'Konami', 'Konami', '1990-12-21', 'Gradius III is a 1989 scrolling shooter video game developed and published by Konami for. arcades It was originally released only in Japan on December 11, 1989. It is the third game in the Gradius series. The game was ported to the Super Nintendo Entertainment System in Japan in 1990 and North America in 1991, and served as a launch title for the system in North America. The arcade version would never see the light of day in the West until it was included alongside Gradius IV in a two-in-one compilation for the PlayStation 2 and in the Gradius Collection for the PlayStation Portable.', 'https://media.retroachievements.org/Images/038427.png', 'https://media.retroachievements.org/Images/000574.png', 'https://media.retroachievements.org/Images/000571.png', 'https://media.retroachievements.org/Images/000572.png', 4.2),
  (78, 1032, 'Mighty Morphin Power Rangers: The Fighting Edition', 'SNES/Super Famicom', 3, 3083, 3083, 3083, 68, 0, '2D Fighting', 'Natsume', 'Bandai', '1995-09-01', 'Mighty Morphin Power Rangers: The Fighting Edition is a 2D competitive fighting video game based on the Mighty Morphin Power Rangers television series that was released exclusively for the Super Nintendo Entertainment System developed by Natsume Co., Ltd. and published by Bandai in 1995. Unlike previous Power Rangers video games, which had the player controlling the titular heroes, the player controls their giant robots in this title. A bootleg Genesis port is known to exist, though who actually made it is currently unknown.', 'https://media.retroachievements.org/Images/052154.png', 'https://media.retroachievements.org/Images/054265.png', 'https://media.retroachievements.org/Images/035622.png', 'https://media.retroachievements.org/Images/035623.png', 4.2),
  (79, 409, 'Hagane: The Final Conflict', 'SNES/Super Famicom', 3, 3069, 3069, 3069, 36, 0, '2D Platforming', NULL, 'Hudson Soft', '1995-06-01', 'Hagane: The Final Conflict is a 1994 action-platform video game developed by CAProduction and Red Entertainment and published by Hudson Soft for the Super Nintendo Entertainment System. The player takes on the role of a ninja cyborg named Hagane on his path to take revenge on an opposing ninja faction. The game combines traditional Japanese ninja and samurai aesthetics with a futuristic setting. The player has a wide variety of weapons, moves, and attacks at their disposal to defeat enemies and progress through the game. Hagane released to positive reception, and was compared favorably to classic side-scrolling action games. Reviewers praised the controls, art design, and challenge but criticized the quality of the graphics and sound.', 'https://media.retroachievements.org/Images/016965.png', 'https://media.retroachievements.org/Images/009302.png', 'https://media.retroachievements.org/Images/016921.png', 'https://media.retroachievements.org/Images/016923.png', 4.2),
  (80, 868, 'Darius Twin', 'SNES/Super Famicom', 3, 3049, 3049, 3049, 56, 0, 'Shoot ''em Up', 'Taito', 'Taito', '1991-11-01', 'Darius Twin is a 1991 horizontally scrolling shooter video game developed and published by Taito for the Super Nintendo Entertainment System. It is part of the Darius series. It was re-released for the Wii Virtual Console in Japan on April 13, 2010 and in North America on December 13, 2010.', 'https://media.retroachievements.org/Images/077806.png', 'https://media.retroachievements.org/Images/005312.png', 'https://media.retroachievements.org/Images/005310.png', 'https://media.retroachievements.org/Images/005311.png', 4.2),
  (81, 647, 'Mortal Kombat II', 'SNES/Super Famicom', 3, 2958, 2958, 2958, 42, 0, '2D Fighting', 'Midway', 'Acclaim', '1994-09-01', 'Mortal Kombat II is a 1993 fighting game developed and published by Midway for arcades. It was later ported to multiple home systems, including MS-DOS, Amiga, Game Boy, Game Gear, Sega Genesis, 32X, Sega Saturn, Super NES, and PlayStation, by Probe Software and Sculptured Software, and published by Acclaim Entertainment.', 'https://media.retroachievements.org/Images/054557.png', 'https://media.retroachievements.org/Images/042418.png', 'https://media.retroachievements.org/Images/003158.png', 'https://media.retroachievements.org/Images/000482.png', 4.2),
  (82, 518, 'The Ninja Warriors', 'SNES/Super Famicom', 3, 2871, 2871, 2871, 35, 0, 'Beat ''em Up', 'Natsume', 'Taito', '1994-01-28', 'The Ninja Warriors is a 1987 beat ''em up video game developed and published by Taito for arcades. The original arcade game situated one display in between projected images of two other displays, creating the appearance of a triple-wide screen. Ports were released for home systems including the Amiga, Atari ST, ZX Spectrum, Commodore 64, Amstrad CPC, PC Engine, and Mega-CD.', 'https://media.retroachievements.org/Images/087832.png', 'https://media.retroachievements.org/Images/064745.png', 'https://media.retroachievements.org/Images/035406.png', 'https://media.retroachievements.org/Images/035407.png', 4.2),
  (83, 1049, 'NBA Jam: Tournament Edition', 'SNES/Super Famicom', 3, 2859, 2859, 2859, 53, 0, NULL, 'Iguana Entertainment', 'Acclaim', '1995-02-23', 'NBA Jam is a 1993 basketball video game developed and published by Midway for arcades. It is the first entry in the NBA Jam series, and the third basketball video game released by Midway, after TV Basketball (1974) and Arch Rivals (1989). The gameplay of NBA Jam is based on Arch Rivals, which was also a 2-on-2 basketball game; however, it was the release of NBA Jam that brought mainstream success to the genre.', 'https://media.retroachievements.org/Images/004752.png', 'https://media.retroachievements.org/Images/004751.png', 'https://media.retroachievements.org/Images/004753.png', 'https://media.retroachievements.org/Images/004754.png', 4.2),
  (84, 467, 'The Magical Quest Starring Mickey Mouse', 'SNES/Super Famicom', 3, 2839, 2839, 2839, 35, 0, '2D Platforming', 'Capcom', 'Capcom', '1992-11-20', 'Disney''s Magical Quest is a Disney platform game trilogy released by Capcom. The games star Mickey Mouse and either Minnie Mouse or Donald Duck, who must defeat Pete. The gameplay is similar amongst all games in the series: the player must move as in a typical platform game, defeating enemies either by jumping on them or by grabbing and throwing blocks at them.', 'https://media.retroachievements.org/Images/113723.png', 'https://media.retroachievements.org/Images/000133.png', 'https://media.retroachievements.org/Images/000114.png', 'https://media.retroachievements.org/Images/000115.png', 4.2),
  (85, 1013, 'Mario Paint', 'SNES/Super Famicom', 3, 2831, 2831, 2831, 16, 0, 'Other', 'Nintendo', 'Nintendo', '1992-07-14', 'Mario Paint is a 1992 art creation video game developed by Nintendo Research & Development 1 (R&D1) and Intelligent Systems and published by Nintendo for the Super Nintendo Entertainment System. Mario Paint consists of a raster graphics editor, an animation program, a music composer, and a point and click minigame, all of which are designed to be used with the Super NES Mouse peripheral, which the game was packaged and sold with. Per its name, the game is Mario-themed, and features sprites and sound effects that are taken from or in the vein of Super Mario World.', 'https://media.retroachievements.org/Images/107044.png', 'https://media.retroachievements.org/Images/103319.png', 'https://media.retroachievements.org/Images/103317.png', 'https://media.retroachievements.org/Images/103318.png', 4.2),
  (86, 990, 'The Legend of the Mystical Ninja', 'SNES/Super Famicom', 3, 2829, 2829, 2829, 80, 0, NULL, 'Konami', 'Konami', '1991-07-19', 'The Legend of the Mystical Ninja is a 1991 action-adventure game released by Konami for the Super Nintendo Entertainment System. It was also ported to the Game Boy Advance along with Ganbare Goemon 2: Kiteretsu Shōgun McGuiness in 2005 only in Japan.', 'https://media.retroachievements.org/Images/094384.png', 'https://media.retroachievements.org/Images/067713.png', 'https://media.retroachievements.org/Images/002549.png', 'https://media.retroachievements.org/Images/006555.png', 4.2),
  (87, 1270, 'Tiny Toon Adventures: Buster Busts Loose!', 'SNES/Super Famicom', 3, 2820, 2820, 2820, 31, 0, '2D Platforming', 'Konami', 'Konami', '1992-12-18', 'Tiny Toon Adventures: Buster Busts Loose! is a video game for the Super NES console that is based on the animated TV series Tiny Toon Adventures. It was developed and published by Konami, released in 1992 in Japan and in 1993 in Europe and North America.', 'https://media.retroachievements.org/Images/084485.png', 'https://media.retroachievements.org/Images/044320.png', 'https://media.retroachievements.org/Images/000422.png', 'https://media.retroachievements.org/Images/000423.png', 4.2),
  (88, 1153, 'Side Pocket', 'SNES/Super Famicom', 3, 2815, 2815, 2815, 38, 0, 'Sports - Billiards', 'Iguana Entertainment', 'Data East', '1993-12-01', 'Side Pocket is a pocket billiards simulation released as an arcade video game by Data East in 1986. It was ported to the Nintendo Entertainment System and Game Boy, while an enhanced remake was later released on the Sega Genesis, Super Nintendo Entertainment System, and Game Gear. The game spawned two sequels, as well as arcade spin-off series titled Pocket Gal.', 'https://media.retroachievements.org/Images/075843.png', 'https://media.retroachievements.org/Images/007525.png', 'https://media.retroachievements.org/Images/007523.png', 'https://media.retroachievements.org/Images/007524.png', 4.2),
  (89, 829, 'The Addams Family', 'SNES/Super Famicom', 3, 2658, 2658, 2658, 46, 0, '2D Platforming', 'Ocean Software', 'Ocean Software', '1992-03-01', 'The Addams Family is a fictional family created by American cartoonist Charles Addams. The Addams are an eccentric old-money clan who delight in the macabre and the grotesque and are seemingly unaware or unconcerned that other people find them bizarre or frightening. The Addams'' view in seeing their family life and interests as normal was a basis for the satire and comedy. They originally appeared in a series of 150 standalone single-panel comics, about half of which were originally published in The New Yorker between 1938 and their creator''s death in 1988. They have since appeared in other media, such as television, film, video games, comic books, a musical, and merchandise.', 'https://media.retroachievements.org/Images/099516.png', 'https://media.retroachievements.org/Images/008297.png', 'https://media.retroachievements.org/Images/008295.png', 'https://media.retroachievements.org/Images/008296.png', 4.2),
  (90, 1004, 'Lufia & The Fortress of Doom', 'SNES/Super Famicom', 3, 2644, 2644, 2644, 47, 0, 'Turn-Based RPG', 'Neverland', 'Taito', '1993-12-01', 'Lufia & the Fortress of Doom, known as Estpolis Denki  in Japan, is a role-playing video game developed by Neverland and published by Taito in 1993, for the Super Nintendo Entertainment System. It is the first title in the Lufia series of video games and the only game from the series released under the Taito label in North America.', 'https://media.retroachievements.org/Images/036053.png', 'https://media.retroachievements.org/Images/051194.png', 'https://media.retroachievements.org/Images/002412.png', 'https://media.retroachievements.org/Images/002501.png', 4.2),
  (91, 274, 'U.N. Squadron', 'SNES/Super Famicom', 3, 2625, 2625, 2625, 28, 0, 'Shoot ''em Up', 'Capcom', 'Capcom', '1991-07-26', 'U.N. Squadron, released in Japan as Area 88, is a 1989 side-scrolling shooter video game developed and published by Capcom for arcades. It was based on the manga series of the same name, though the North American release omits all references to the manga. Their mission is to stop a terrorist group known as Project 4. It was ported to multiple platforms including the Super Nintendo Entertainment System and was followed by a spiritual successor, Carrier Air Wing.', 'https://media.retroachievements.org/Images/061111.png', 'https://media.retroachievements.org/Images/001354.png', 'https://media.retroachievements.org/Images/001351.png', 'https://media.retroachievements.org/Images/001352.png', 4.2),
  (92, 1405, 'Dragon Quest I & II', 'SNES/Super Famicom', 3, 2596, 2596, 2596, 68, 0, 'Compilation, Turn-Based RPG', 'Chunsoft', 'Enix', '1993-12-18', 'Dragon Quest, previously published as Dragon Warrior in North America until 2005, is a series of role-playing video games created by Japanese game designer Yuji Horii, character designer Akira Toriyama, and composer Koichi Sugiyama and published by Square Enix. Since its inception, development of games in the series have been outsourced to a plethora of external companies until the tenth installment, with localized remakes and ports of later installments for the Nintendo DS, Nintendo 3DS, and Nintendo Switch being published by Nintendo outside of Japan. With its first game published in 1986, there are eleven main-series games, along with numerous spin-off games. In addition, there have been numerous manga, anime and novels published under the franchise, with nearly every game in the main series having a related adaptation.', 'https://media.retroachievements.org/Images/038721.png', 'https://media.retroachievements.org/Images/009582.png', 'https://media.retroachievements.org/Images/009581.png', 'https://media.retroachievements.org/Images/009583.png', 4.2),
  (93, 1328, 'Wolfenstein 3D', 'SNES/Super Famicom', 3, 2593, 2593, 2593, 50, 0, 'First-Person Shooter', 'id Software', 'Imagineer', '1994-01-01', 'Wolfenstein 3D is a 1992 first-person shooter game developed by id Software and published by Apogee Software and FormGen for MS-DOS. It was inspired by the 1981 Muse Software video game Castle Wolfenstein, and is the third installment in the Wolfenstein series. In Wolfenstein 3D, the player assumes the role of Allied spy William B.J. Blazkowicz during World War II as he escapes from the Nazi German prison Castle Wolfenstein and carries out a series of crucial missions against the Nazis. The player traverses each of the game''s levels to find an elevator to the next level or kill a final boss, fighting Nazi soldiers, dogs, and other enemies with a knife and a variety of guns.', 'https://media.retroachievements.org/Images/064973.png', 'https://media.retroachievements.org/Images/030871.png', 'https://media.retroachievements.org/Images/035397.png', 'https://media.retroachievements.org/Images/035398.png', 4.2),
  (94, 1005, 'Lufia II: Rise of the Sinistrals', 'SNES/Super Famicom', 3, 2581, 2581, 2581, 64, 0, 'Turn-Based RPG', 'Neverland', 'Natsume, Taito', '1996-08-31', 'Lufia II: Rise of the Sinistrals, known as Estpolis Denki II  in Japan, and as Lufia in Europe and Australia, is a role-playing video game with puzzle elements developed by Neverland and published in Japan in 1995 by Taito, and in North America and Europe in 1996 by Natsume and Nintendo respectively, for the Super Nintendo Entertainment System. It is the second game in the Lufia series.', 'https://media.retroachievements.org/Images/048270.png', 'https://media.retroachievements.org/Images/048202.png', 'https://media.retroachievements.org/Images/003422.png', 'https://media.retroachievements.org/Images/003423.png', 4.2),
  (95, 3362, 'Picross NP Vol. 1', 'SNES/Super Famicom', 3, 2555, 2555, 2555, 27, 0, 'Nonogram', 'Jupiter', 'Nintendo', '1999-04-01', 'The Super Nintendo Entertainment System has a library of 1,749 official releases, of which 717 were released in North America plus 4 championship cartridges, 532 in Europe, 1,440 in Japan, 231 on Satellaview, and 13 on SuFami Turbo. 296 releases are common to all regions, 147 were released in Japan and the US only, 165 in Europe and the US, and 27 in Japan and Europe. There are 977 Japanese exclusives, 111 US exclusives, and 35 European exclusives. The Super NES was released in North America on August 23, 1991, with its launch titles being Super Mario World, F-Zero, Pilotwings, Gradius III, and SimCity. Despite the console''s relatively late start, and the fierce competition it faced in North America and Europe from Sega''s Genesis/Mega Drive console, it was the best-selling console of its era.', 'https://media.retroachievements.org/Images/024811.png', 'https://media.retroachievements.org/Images/024930.png', 'https://media.retroachievements.org/Images/002810.png', 'https://media.retroachievements.org/Images/008210.png', 4.2),
  (96, 1344, 'X-Men: Mutant Apocalypse', 'SNES/Super Famicom', 3, 2544, 2544, 2544, 47, 0, 'Action, Platforming', 'Capcom', 'Capcom', '1994-11-01', 'X-Men: Mutant Apocalypse is an action game developed and published by Capcom for the Super Nintendo Entertainment System in 1994. The game is based on the X-Men comic book franchise from Marvel Comics. It was the first game Capcom released based on the franchise, released a month before the fighting game titled X-Men: Children of the Atom, also released in 1994.', 'https://media.retroachievements.org/Images/074997.png', 'https://media.retroachievements.org/Images/004292.png', 'https://media.retroachievements.org/Images/035400.png', 'https://media.retroachievements.org/Images/039566.png', 4.2),
  (97, 241, 'Biker Mice From Mars', 'SNES/Super Famicom', 3, 2472, 2472, 2472, 40, 0, 'Kart Racing', 'Konami', 'Konami', '1994-12-01', 'Biker Mice from Mars is an American animated series created by Rick Ungar. The series premiered in syndication the week of September 19, 1993. It consists of three seasons of 65 episodes, with the final episode airing in syndication the week of February 24, 1996.', 'https://media.retroachievements.org/Images/052427.png', 'https://media.retroachievements.org/Images/002818.png', 'https://media.retroachievements.org/Images/002816.png', 'https://media.retroachievements.org/Images/002817.png', 4.2),
  (98, 566, 'Shadowrun', 'SNES/Super Famicom', 3, 2458, 2458, 2458, 92, 0, 'Action RPG', 'Beam Software', 'Data East, Laser Beam Entertainment', '1993-05-01', 'Shadowrun is a science fantasy tabletop role-playing game set in an alternate future in which cybernetics, magic and fantasy creatures co-exist. It combines genres of cyberpunk, urban fantasy, and crime, with occasional elements of conspiracy, horror, and detective fiction. From its inception in 1989, it has spawned a franchise that includes a series of novels, a collectible card game, two miniature-based tabletop wargames, and multiple video games.', 'https://media.retroachievements.org/Images/120102.png', 'https://media.retroachievements.org/Images/078301.png', 'https://media.retroachievements.org/Images/000510.png', 'https://media.retroachievements.org/Images/000451.png', 4.2),
  (99, 296, 'Mickey and Donald''s Magical Adventure 3', 'SNES/Super Famicom', 3, 2407, 2407, 2407, 38, 0, '2D Platforming', 'Capcom', 'Capcom', '1995-12-08', 'The Nintendo Entertainment System has a library of 1370 officially licensed games released during their lifespans, plus 7 official multicarts and 2 championship cartridges. Of these, 672 were released exclusively in Japan, 187 were released exclusively in North America, and 19 were released exclusively in PAL countries. Worldwide, 521 games were released.', 'https://media.retroachievements.org/Images/113716.png', 'https://media.retroachievements.org/Images/000864.png', 'https://media.retroachievements.org/Images/001303.png', 'https://media.retroachievements.org/Images/001302.png', 4.2),
  (100, 3438, 'Rockman & Forte', 'SNES/Super Famicom', 3, 2397, 2397, 2397, 37, 0, '2D Platforming', 'Capcom', 'Capcom', '1998-04-24', 'Mega Man & Bass is a 1998 action game developed and published by Capcom. It is a spin-off game in the original Mega Man series, and was originally released in Japan for the Super Famicom on April 24, 1998. It was later ported to the Game Boy Advance in 2002, and released internationally the following year.', 'https://media.retroachievements.org/Images/028133.png', 'https://media.retroachievements.org/Images/002189.png', 'https://media.retroachievements.org/Images/002188.png', 'https://media.retroachievements.org/Images/002187.png', 4.2),
  (101, 1277, 'Top Gear 2', 'SNES/Super Famicom', 3, 2376, 2376, 2376, 111, 0, 'Arcade Racing', 'Gremlin Graphics', 'Kemco', '1993-08-08', 'Top Gear 2 is a racing video game developed and published by Gremlin Interactive. A direct sequel to the 1992 game Top Gear, it was first released by Kemco for the SNES in North America in September 1993, and then the Super Famicom in Japan on December 22. It was later ported to the Amiga and Amiga CD32 in September 1994 by Gremlin Interactive, and to the Sega Genesis in September by Vic Tokai. While more realistic than its predecessor, Top Gear 2 maintained the arcade-style gameplay the series is known for.', 'https://media.retroachievements.org/Images/046591.png', 'https://media.retroachievements.org/Images/007505.png', 'https://media.retroachievements.org/Images/035389.png', 'https://media.retroachievements.org/Images/035390.png', 4.2),
  (102, 259, 'Final Fantasy II', 'SNES/Super Famicom', 3, 2341, 2341, 2341, 21, 0, NULL, 'Square', 'Squaresoft', '1991-11-23', 'Final Fantasy II is a 1988 role-playing video game developed and published by Square for the Family Computer as the second installment of the Final Fantasy series. It was ported to and remade for WonderSwan Color, PlayStation, Game Boy Advance, PlayStation Portable, and mobile phones. Originally exclusive to Japan, later versions were released internationally, including the 2021 Final Fantasy Pixel Remaster version. The story follows the warrior Firion and his allies as they join a rebellion against the expanding Palamecian Empire. The gameplay is similar to the original game with an overworld and dungeon exploration, but its combat design is changed to a usage-based growth system where characters'' statistics increase according to how they are used or acquired.', 'https://media.retroachievements.org/Images/074336.png', 'https://media.retroachievements.org/Images/049539.png', 'https://media.retroachievements.org/Images/000749.png', 'https://media.retroachievements.org/Images/000750.png', 4.2),
  (103, 2374, 'Clock Tower', 'SNES/Super Famicom', 3, 2333, 2333, 2333, 38, 0, 'Point-and-Click Adventure, Survival Horror', 'Human Entertainment', 'Human Entertainment', '1995-09-14', 'Clock Tower is a point-and-click survival horror video game developed and published by Human Entertainment for the Super Famicom in 1995. It is the first installment in the Clock Tower series. The story follows orphan Jennifer Simpson soon after she is adopted by the Barrows family along with other orphaned girls. Shortly after arriving at the Barrows family manor, one of the other children is killed by a stalker called Scissorman. Jennifer must then explore the Barrows Mansion to find a way to escape while evading Scissorman, leading to one of the game''s multiple endings. Clock Tower utilizes a point-and-click interface with the player controlling a cursor to direct Jennifer''s actions.', 'https://media.retroachievements.org/Images/042130.png', 'https://media.retroachievements.org/Images/096952.png', 'https://media.retroachievements.org/Images/003031.png', 'https://media.retroachievements.org/Images/003030.png', 4.2),
  (104, 423, 'Battletoads and Double Dragon: The Ultimate Team', 'SNES/Super Famicom', 3, 2332, 2332, 2332, 21, 0, 'Beat ''em Up', 'Rare', 'Tradewest', '1993-10-01', 'Battletoads/Double Dragon is a 1993 beat ''em up developed by Rare and published by Tradewest. It was originally released for the Nintendo Entertainment System and later ported to the Mega Drive/Genesis, Super NES, and Game Boy. The SNES version was released on the Nintendo Classics service in September 2024; it was the game''s first re-release as it was not released on the Rare Replay collection.', 'https://media.retroachievements.org/Images/083729.png', 'https://media.retroachievements.org/Images/003412.png', 'https://media.retroachievements.org/Images/003410.png', 'https://media.retroachievements.org/Images/003411.png', 4.2),
  (105, 2610, 'Parodius: Non-Sense Fantasy', 'SNES/Super Famicom', 3, 2266, 2266, 2266, 88, 0, 'Shoot ''em Up', 'Konami', 'Konami', '1992-04-07', 'Parodius! From Myth to Laughter, released in Japan as Parodius Da! Shinwa kara Owarai e and outside Japan as Parodius, is a shoot ''em up arcade video game and the second title in the Parodius series produced by Konami. The European SNES, Sega Saturn and PlayStation versions are also known as Parodius: Non-Sense Fantasy. The gameplay is stylistically very similar to the Gradius series, but the graphics and music are intentionally absurd.', 'https://media.retroachievements.org/Images/089920.png', 'https://media.retroachievements.org/Images/094940.png', 'https://media.retroachievements.org/Images/007388.png', 'https://media.retroachievements.org/Images/007389.png', 4.2),
  (106, 390, 'Ardy Lightfoot', 'SNES/Super Famicom', 3, 2247, 2247, 2247, 44, 0, '2D Platforming', 'ASCII Entertainment', 'Titus Interactive', '1993-11-26', 'Ardy Lightfoot is a 2D side-scrolling platform game released on the Super Nintendo Entertainment System in 1993 in Japan and 1994 in the west. It was developed by ASCII and published by Titus France in North America and Europe.', 'https://media.retroachievements.org/Images/111495.png', 'https://media.retroachievements.org/Images/004420.png', 'https://media.retroachievements.org/Images/004421.png', 'https://media.retroachievements.org/Images/004419.png', 4.2),
  (107, 986, 'Kirby''s Dream Course', 'SNES/Super Famicom', 3, 2232, 2232, 2232, 46, 0, 'Sports - Golf', 'HAL Laboratory', 'Nintendo', '1994-09-21', 'Kirby''s Dream Course is a 1994 miniature golf video game developed by HAL Laboratory and Nintendo EAD and published by Nintendo for the Super Nintendo Entertainment System (SNES). A spin-off of the Kirby series and the first released for the SNES, players control the pink spherical character Kirby through a series of courses by launching him towards the goal hole at the end. Kirby can hit enemies to collect power-ups that grant him unique abilities, such as those that allow him to destroy certain obstacles or fly around the level.', 'https://media.retroachievements.org/Images/105378.png', 'https://media.retroachievements.org/Images/065001.png', 'https://media.retroachievements.org/Images/002883.png', 'https://media.retroachievements.org/Images/002885.png', 4.2),
  (108, 2620, 'Skyblazer', 'SNES/Super Famicom', 3, 2222, 2222, 2222, 46, 0, '2D Platforming, Action', 'Ukiyotei', 'Sony Imagesoft', '1994-01-01', 'Skyblazer is a platform video game published by Sony Imagesoft, released in early 1994 for the Super Nintendo Entertainment System. It involves Sky, the Skyblazer hero searching for Ashura, the Lord of War, who had kidnapped the sorceress Ariana.', 'https://media.retroachievements.org/Images/124574.png', 'https://media.retroachievements.org/Images/124214.png', 'https://media.retroachievements.org/Images/035382.png', 'https://media.retroachievements.org/Images/035383.png', 4.2),
  (109, 1012, 'Magic Sword', 'SNES/Super Famicom', 3, 2194, 2194, 2194, 57, 0, 'Hack and Slash', 'Capcom', 'Capcom', '1992-05-29', 'Magic Sword: Heroic Fantasy (マジックソード) is a 1990 hack and slash video game developed and published by Capcom for arcades. The player is cast as a hero who fights through a mystical tower to save the world. The player can use a sword, axe or magic, and can also rescue and recruit potential allies of various character classes, each with special abilities.', 'https://media.retroachievements.org/Images/119073.png', 'https://media.retroachievements.org/Images/014991.png', 'https://media.retroachievements.org/Images/014988.png', 'https://media.retroachievements.org/Images/014989.png', 4.2),
  (110, 352, 'Final Fight Guy', 'SNES/Super Famicom', 3, 2181, 2181, 2181, 31, 0, NULL, 'Capcom', 'Capcom', '1992-03-20', 'Final Fight is a 1989 beat ''em up game developed and published by Capcom for arcades. It is the seventh title released for the CP System hardware. Set in the fictional Metro City, the player controls one of three street fighters: former pro wrestler and city mayor Mike Haggar, expert brawler Cody Travers, and modern-day ninja Guy. The trio set out to rescue Jessica when she is kidnapped by the Mad Gear Gang.', 'https://media.retroachievements.org/Images/014627.png', 'https://media.retroachievements.org/Images/125202.png', 'https://media.retroachievements.org/Images/001263.png', 'https://media.retroachievements.org/Images/001264.png', 4.2),
  (111, 424, 'Battletoads in Battlemaniacs', 'SNES/Super Famicom', 3, 2155, 2155, 2155, 23, 0, NULL, NULL, 'Tradewest', '1993-06-01', 'Battletoads in Battlemaniacs is a beat ''em up platform game developed by Rare for the Super Nintendo Entertainment System. Part of the Battletoads series, the game was released in North America by Tradewest in June 1993, in Europe by Nintendo in October 1993 and in Japan by Masaya on January 7, 1994. It was also ported for the Master System and released exclusively in Brazil. It was released around the same time as Battletoads/Double Dragon, another installment in the series. The game received its first official re-release on the Nintendo Classics service on February 21, 2024, as it was not included in the Rare Replay collection for the Xbox One.', 'https://media.retroachievements.org/Images/106494.png', 'https://media.retroachievements.org/Images/000647.png', 'https://media.retroachievements.org/Images/000689.png', 'https://media.retroachievements.org/Images/000690.png', 4.2),
  (112, 1134, 'RoboCop Versus The Terminator', 'SNES/Super Famicom', 3, 2072, 2072, 2072, 26, 0, 'Run & Gun', 'Interplay Entertainment', 'Virgin Interactive', '1993-01-01', 'RoboCop Versus The Terminator is a run and gun game released for the Sega Genesis, Super Nintendo Entertainment System, Master System, and Game Gear in 1993, with a port to the Game Boy in 1994. It is based on the 1992 four-issue comic book mini-series of the same name, which is a crossover between the RoboCop and Terminator franchises. Despite their likenesses being shown on packaging, the actors who portrayed the titular characters did not reprise their roles in this game.', 'https://media.retroachievements.org/Images/077330.png', 'https://media.retroachievements.org/Images/027611.png', 'https://media.retroachievements.org/Images/027608.png', 'https://media.retroachievements.org/Images/027609.png', 4.1),
  (113, 418, 'Batman Forever', 'SNES/Super Famicom', 3, 2059, 2059, 2059, 44, 0, 'Beat ''em Up', 'Probe Entertainment', 'Acclaim', '1995-08-01', 'Batman Forever is a 1995 American superhero film based on the DC Comics character Batman by Bob Kane and Bill Finger. It is the third installment of the Batman film series, acting as a standalone sequel to Batman Returns. Directed by Joel Schumacher and produced by Tim Burton and Peter MacGregor-Scott, it stars Val Kilmer as Bruce Wayne / Batman, replacing Michael Keaton, alongside Jim Carrey, Tommy Lee Jones, Nicole Kidman, and Chris O''Donnell. The film follows Batman as he attempts to prevent the Riddler (Carrey) and Two-Face (Jones) from uncovering his secret identity and extracting information from the minds of Gotham City''s residents, while at the same time navigating his feelings for psychologist Dr. Chase Meridian (Kidman) and adopting orphaned acrobat Dick Grayson (O''Donnell)—who becomes his partner and best friend, Robin.', 'https://media.retroachievements.org/Images/120214.png', 'https://media.retroachievements.org/Images/052554.png', 'https://media.retroachievements.org/Images/005801.png', 'https://media.retroachievements.org/Images/052555.png', 4.1),
  (114, 573, 'The Great Circus Mystery Starring Mickey & Minnie', 'SNES/Super Famicom', 3, 2040, 2040, 2040, 53, 0, '2D Platforming', 'Capcom', 'Capcom', '1994-10-01', 'Disney''s Magical Quest is a Disney platform game trilogy released by Capcom. The games star Mickey Mouse and either Minnie Mouse or Donald Duck, who must defeat Pete. The gameplay is similar amongst all games in the series: the player must move as in a typical platform game, defeating enemies either by jumping on them or by grabbing and throwing blocks at them.', 'https://media.retroachievements.org/Images/113713.png', 'https://media.retroachievements.org/Images/001269.png', 'https://media.retroachievements.org/Images/001266.png', 'https://media.retroachievements.org/Images/001267.png', 4.1),
  (115, 1274, 'Tom and Jerry', 'SNES/Super Famicom', 3, 2001, 2001, 2001, 33, 0, '2D Platforming', 'RSP', 'Hi-Tech Expressions', '1993-01-01', 'Tom and Jerry is an American animated media franchise and series of comedy short films created in 1940 by William Hanna and Joseph Barbera. Best known for its 161 theatrical short films produced by Metro-Goldwyn-Mayer, the series centers on the rivalry between a cat named Tom and a mouse named Jerry. Many shorts also feature several recurring characters.', 'https://media.retroachievements.org/Images/052088.png', 'https://media.retroachievements.org/Images/002603.png', 'https://media.retroachievements.org/Images/035561.png', 'https://media.retroachievements.org/Images/035562.png', 4.1),
  (116, 605, 'Street Fighter Alpha 2', 'SNES/Super Famicom', 3, 1977, 1977, 1977, 93, 0, '2D Fighting', 'Capcom', 'Capcom', '1996-11-01', 'Street Fighter Alpha 2, known as Street Fighter Zero 2 in Japan, Asia, South America, and Oceania, is a 1996 fighting game developed and published by Capcom for arcades. The game is the sequel to the previous year''s Street Fighter Alpha: Warriors'' Dreams and features a number of improvements, such as new attacks, stages, endings, and gameplay features. It was ported to the PlayStation, Sega Saturn and Super Nintendo home consoles globally in 1996, and later a Windows port. It was followed by Street Fighter Alpha 3 in 1998.', 'https://media.retroachievements.org/Images/049776.png', 'https://media.retroachievements.org/Images/006430.png', 'https://media.retroachievements.org/Images/001343.png', 'https://media.retroachievements.org/Images/001344.png', 4.1),
  (117, 1240, 'Super Tennis', 'SNES/Super Famicom', 3, 1977, 1977, 1977, 43, 0, 'Sports - Tennis', 'Tokyo Shoseki', 'Nintendo, Tonkin House', '1991-08-30', 'Super Tennis is a 1991 tennis video game developed by Tose and published by Tonkin House for the Super Nintendo Entertainment System. Nintendo localized the game and released it outside Japan. It utilizes mode 7 graphics.', 'https://media.retroachievements.org/Images/014908.png', 'https://media.retroachievements.org/Images/004701.png', 'https://media.retroachievements.org/Images/004703.png', 'https://media.retroachievements.org/Images/004702.png', 4.1),
  (118, 399, 'Super Double Dragon', 'SNES/Super Famicom', 3, 1973, 1973, 1973, 14, 0, 'Beat ''em Up', 'Technōs Japan', 'Tradewest', '1992-10-16', 'Super Double Dragon is a side-scrolling beat-''em-up video game released by Technōs Japan for the Super Nintendo Entertainment System in Japan in 1992. It was published by Tradewest in North America the same year and the PAL region in 1993. Super Double Dragon is the fourth console game in the Double Dragon series developed by Technōs Japan, following Double Dragon III: The Sacred Stones for the NES. The game did not have an arcade release and was made specifically for the home market.', 'https://media.retroachievements.org/Images/004120.png', 'https://media.retroachievements.org/Images/000590.png', 'https://media.retroachievements.org/Images/035659.png', 'https://media.retroachievements.org/Images/035660.png', 4.1),
  (119, 450, 'Breath of Fire II', 'SNES/Super Famicom', 3, 1957, 1957, 1957, 87, 0, NULL, 'Capcom', 'Capcom', '1995-01-01', 'Breath of Fire II is a role-playing video game developed and published by Capcom. First released in 1994, the game was licensed to Laguna for European release in 1996. It is the second entry in the Breath of Fire series. It was later ported to Game Boy Advance and re-released worldwide. The game was released on Wii''s Virtual Console in North America on August 27, 2007. Nintendo of Europe''s website mistakenly announced it for release on July 27, 2007, but it was in fact released two weeks later, on August 10, 2007. In 2013, it was released for the Wii U Virtual Console. In 2016, it was released for the New Nintendo 3DS Virtual Console. In 2019, it was released for the Nintendo Switch SNES games library.', 'https://media.retroachievements.org/Images/008647.png', 'https://media.retroachievements.org/Images/097753.png', 'https://media.retroachievements.org/Images/051035.png', 'https://media.retroachievements.org/Images/051034.png', 4.1),
  (120, 268, 'Toy Story', 'SNES/Super Famicom', 3, 1926, 1926, 1926, 31, 0, '2D Platforming', 'Traveller''s Tales', 'Disney Interactive Studios', '1995-12-01', 'Toy Story is a 1995 American animated adventure comedy film produced by Pixar Animation Studios for Walt Disney Pictures. The first entirely computer-animated feature film, as well as the first feature film from Pixar, it was directed by John Lasseter and written by Joss Whedon, Andrew Stanton, Joel Cohen, and Alec Sokolow. The film features the voices of Tom Hanks, Tim Allen, Annie Potts, John Ratzenberger, Don Rickles, Wallace Shawn, and Jim Varney. Taking place in a world where toys come to life when humans are not present, Toy Story follows an old-fashioned pullstring cowboy doll named Woody (Hanks), and a modern space cadet action figure, Buzz Lightyear (Allen), as Woody develops jealousy towards Buzz when he becomes their owner Andy''s favorite toy.', 'https://media.retroachievements.org/Images/065388.png', 'https://media.retroachievements.org/Images/002313.png', 'https://media.retroachievements.org/Images/002309.png', 'https://media.retroachievements.org/Images/002310.png', 4.1),
  (121, 1229, 'Super R-Type', 'SNES/Super Famicom', 3, 1923, 1923, 1923, 40, 0, 'Shoot ''em Up', 'Irem', 'Irem', '1991-09-01', 'Super R-Type is a scrolling shooter video game developed and published by Irem for the Super Nintendo Entertainment System. It was released in Japan and North America in 1991, Europe in 1992, and Brazil in 1993 by Nintendo. It is a partial port of R-Type II, borrowing stages and enemies, but introducing several of its own. The game has been re-released on the Wii Virtual Console in 2008, and on the Nintendo Classics service in 2024.', 'https://media.retroachievements.org/Images/087968.png', 'https://media.retroachievements.org/Images/007140.png', 'https://media.retroachievements.org/Images/007141.png', 'https://media.retroachievements.org/Images/007142.png', 4.1),
  (122, 3248, 'Run Saber', 'SNES/Super Famicom', 3, 1919, 1919, 1919, 22, 0, '2D Platforming', 'Horisoft', 'Atlus', '1993-06-08', 'Run Saber is a side-scrolling action game developed by Horisoft and published by Atlus for the Super Nintendo Entertainment System. The game was released in North America on June 8, 1993, and in Europe in 1993. Run Saber features side-scrolling fighting as the two main heroes, Allen and Sheena, the Run Sabers, fight to save the planet. The gameplay is similar to Strider, Valis and some elements of Psycho Dream.', 'https://media.retroachievements.org/Images/110732.png', 'https://media.retroachievements.org/Images/003599.png', 'https://media.retroachievements.org/Images/029127.png', 'https://media.retroachievements.org/Images/003596.png', 4.1),
  (123, 989, 'Lamborghini American Challenge', 'SNES/Super Famicom', 3, 1910, 1910, 1910, 76, 0, 'Racing', 'Titus Interactive', 'Titus Interactive', '1993-01-01', 'Lamborghini American Challenge is a 1992 racing video game developed and published by Titus France for the Amiga, Amstrad CPC, Atari ST, Commodore 64, MS-DOS, Super NES, Amiga CD32, and Game Boy.', 'https://media.retroachievements.org/Images/046979.png', 'https://media.retroachievements.org/Images/006024.png', 'https://media.retroachievements.org/Images/006022.png', 'https://media.retroachievements.org/Images/006023.png', 4.1),
  (124, 380, 'Alien vs. Predator', 'SNES/Super Famicom', 3, 1898, 1898, 1898, 23, 0, NULL, 'Jorudan', 'Activision', '1993-09-01', 'Alien vs. Predator is a science fiction action horror media franchise created by comic book writers Randy Stradley and Chris Warner. The series is a crossover between, and part of, the larger Alien and Predator franchises, depicting the two species — Xenomorph (Alien) and Yautja (Predator) — as being in conflict with one another.', 'https://media.retroachievements.org/Images/119886.png', 'https://media.retroachievements.org/Images/008158.png', 'https://media.retroachievements.org/Images/018426.png', 'https://media.retroachievements.org/Images/018427.png', 4.1),
  (125, 888, 'Earthworm Jim 2', 'SNES/Super Famicom', 3, 1876, 1876, 1876, 47, 0, '2D Platforming', 'Shiny Entertainment', 'Playmates Interactive Entertainment', '1995-11-15', 'Earthworm Jim 2 is a 1995 run and gun platform game. It is the sequel to Earthworm Jim, and the second and final game in the Earthworm Jim series developed by original creators Doug TenNapel, David Perry, and Shiny Entertainment. It was released in late 1995 and early 1996 depending on the region and video game console, initially for the Sega Genesis and Super Nintendo Entertainment System, before being ported to other platforms.', 'https://media.retroachievements.org/Images/118352.png', 'https://media.retroachievements.org/Images/055372.png', 'https://media.retroachievements.org/Images/006671.png', 'https://media.retroachievements.org/Images/006696.png', 4.1),
  (126, 7886, 'Cyber Citizen Shockman Zero', 'SNES/Super Famicom', 3, 1868, 1868, 1868, 34, 0, '2D Platforming', NULL, NULL, '1997-03-20', 'Cyber Citizen Shockman Zero  is a 1997 game for the Satellaview addon for the Super Famicom. It is a side-scrolling beat-''em-up developed by Masaya and published by NCS. It is the fourth and final game in the Cyber Citizen Shockman series, and the first on the SFC. The previous entries in the series were for the PC-Engine.', 'https://media.retroachievements.org/Images/052428.png', 'https://media.retroachievements.org/Images/052553.png', 'https://media.retroachievements.org/Images/052429.png', 'https://media.retroachievements.org/Images/052430.png', 4.1),
  (127, 3409, 'Raiden Trad', 'SNES/Super Famicom', 3, 1860, 1860, 1860, 64, 0, 'Shoot ''em Up', 'Seibu Kaihatsu', 'Electro Brain', '1992-04-01', 'Raiden is a 1990 vertically scrolling shooter video game developed by Seibu Kaihatsu and published by Tecmo for arcades. The game''s story takes place in the year 2090, when an alien species known as the Crystals invaded Earth. Players assume the roles of the Vanquish Crystal Defense pilot duo, taking control of two state of the art Fighting Thunders aircraft to defeat the Crystals and save the Earth.', 'https://media.retroachievements.org/Images/019717.png', 'https://media.retroachievements.org/Images/015101.png', 'https://media.retroachievements.org/Images/016806.png', 'https://media.retroachievements.org/Images/016807.png', 4.1),
  (128, 306, 'Mickey Mania: The Timeless Adventures of Mickey Mouse', 'SNES/Super Famicom', 3, 1820, 1820, 1820, 20, 0, '2D Platforming', 'Traveller''s Tales', 'Sony Imagesoft', '1994-01-01', 'Mickey Mania: The Timeless Adventures of Mickey Mouse is a 1994 platform video game developed by Traveller''s Tales and published by Sony Imagesoft for the Super NES, Sega Genesis, and Sega CD. In the game, the player controls Mickey Mouse, who must navigate through various side-scrolling levels, each designed and based on classic Mickey Mouse cartoons.', 'https://media.retroachievements.org/Images/059996.png', 'https://media.retroachievements.org/Images/026300.png', 'https://media.retroachievements.org/Images/001298.png', 'https://media.retroachievements.org/Images/001299.png', 4.1),
  (129, 1113, 'Prince of Persia', 'SNES/Super Famicom', 3, 1776, 1776, 1776, 40, 0, 'Cinematic Platforming', 'Arsys Software', 'Konami', '1992-01-11', 'Prince of Persia is a video game franchise created by Jordan Mechner. It is centered around a series of action-adventure games focused on various incarnations of the eponymous Prince, set in ancient and medieval Persia.', 'https://media.retroachievements.org/Images/094963.png', 'https://media.retroachievements.org/Images/048229.png', 'https://media.retroachievements.org/Images/039570.png', 'https://media.retroachievements.org/Images/039569.png', 4.1),
  (130, 1146, 'Saturday Night Slam Masters', 'SNES/Super Famicom', 3, 1776, 1776, 1776, 39, 0, 'Sports - Wrestling', 'Capcom', 'Capcom', '1994-03-30', 'Saturday Night Slam Masters, known in Japan as Muscle Bomber: The Body Explosion, is a 1993 pro wrestling fighting game developed and published by Capcom for arcades. The game features character designs by manga artist Tetsuo Hara, famous for Fist of the North Star.', 'https://media.retroachievements.org/Images/072539.png', 'https://media.retroachievements.org/Images/004750.png', 'https://media.retroachievements.org/Images/004742.png', 'https://media.retroachievements.org/Images/004743.png', 4.1),
  (131, 3228, 'Mario''s Early Years: Fun With Letters', 'SNES/Super Famicom', 3, 1775, 1775, 1775, 17, 0, 'Educational', 'The Software Toolworks', 'Nintendo', '1994-10-01', 'The Mario''s Early Years! series is a trilogy of point-and-click educational games released on MS-DOS and Super Nintendo Entertainment System developed and published by The Software Toolworks under license from Nintendo. The three games consist of Fun with Letters, Fun with Numbers and Preschool Fun.', 'https://media.retroachievements.org/Images/120937.png', 'https://media.retroachievements.org/Images/017202.png', 'https://media.retroachievements.org/Images/017203.png', 'https://media.retroachievements.org/Images/017204.png', 4.1),
  (132, 1016, 'Marvel Super Heroes: War of the Gems', 'SNES/Super Famicom', 3, 1773, 1773, 1773, 84, 0, '2D Platforming', 'Capcom', 'Capcom', '1996-11-01', 'Marvel Super Heroes in War of the Gems  is a 1996 beat-''em-up platform game developed by Capcom for the Super Nintendo Entertainment System, based on the events of Marvel Comics'' series The Infinity Gauntlet and The Infinity War. In the game''s plot, Adam Warlock calls upon Earth''s greatest superheroes to seek out the Infinity Gems before they fall into the wrong hands.', 'https://media.retroachievements.org/Images/075412.png', 'https://media.retroachievements.org/Images/006890.png', 'https://media.retroachievements.org/Images/035377.png', 'https://media.retroachievements.org/Images/035378.png', 4.1),
  (133, 3351, 'Panel de Pon', 'SNES/Super Famicom', 3, 1763, 1763, 1763, 51, 0, NULL, 'Intelligent Systems', 'Nintendo', '1995-10-27', 'Puzzle League, known as Panel de Pon in Japan, is a series of video games published by Nintendo for its various video game consoles. The series began with Panel de Pon in Japan, named Tetris Attack in North America, and has since been adapted to many other consoles. The core gameplay of each version is the same in each game, but branding, presentation details and console-specific features have varied.', 'https://media.retroachievements.org/Images/112289.png', 'https://media.retroachievements.org/Images/064929.png', 'https://media.retroachievements.org/Images/015296.png', 'https://media.retroachievements.org/Images/015297.png', 4.1),
  (134, 1278, 'Top Gear 3000', 'SNES/Super Famicom', 3, 1757, 1757, 1757, 40, 0, 'Racing', 'Gremlin Graphics', 'Kemco', '1995-02-01', 'Top Gear 3000, later released in Japan as The Planet''s Champ: TG3000 , is a racing video game developed by Gremlin Interactive and published by Kemco for the Super Nintendo Entertainment System. It is the third game in the original Top Gear trilogy, and the last in the series to be developed by Gremlin. 3000 heavily resembles the previous Top Gear 2, but is set in the distant future.', 'https://media.retroachievements.org/Images/052104.png', 'https://media.retroachievements.org/Images/000241.png', 'https://media.retroachievements.org/Images/035391.png', 'https://media.retroachievements.org/Images/035392.png', 4.1),
  (135, 12736, '~Hack~ Super Mario World: Learn 2 Kaizo', 'SNES/Super Famicom', 3, 1748, 1748, 1748, 76, 0, '2D Platforming, Educational', 'NeXuS15', 'Hack - Super Mario World', '2017-09-20', 'Kaizo Mario World, also known as Asshole Mario, is a series of three ROM hacks of the Super Nintendo Entertainment System video game Super Mario World, created by T. Takemoto. The term Kaizo Mario World is a shortened form of the title Jisaku no Kaizō Mario o Yūjin ni Play Saseru. The series was created by Takemoto for his friend R. Kiba.', 'https://media.retroachievements.org/Images/026449.png', 'https://media.retroachievements.org/Images/026469.png', 'https://media.retroachievements.org/Images/026447.png', 'https://media.retroachievements.org/Images/026448.png', 4.1),
  (136, 395, 'Axelay', 'SNES/Super Famicom', 3, 1662, 1662, 1662, 46, 0, 'Shoot ''em Up', 'Konami', 'Konami', '1992-09-11', 'Axelay is a 1992 scrolling shooter developed and published by Konami for the Super Nintendo Entertainment System. Set in the fictional solar system Illis where an alien empire known as Armada of Annihilation invades its planets including the Earth-like Corliss (Mother), players take control of the titular D117B space fighter craft as a last resort to stop the alien invasion by recovering its lost weaponry. The gameplay mainly consist of both vertical-scrolling and horizontal-scrolling stages in the same vein as Konami''s own Life Force, with players choosing three different weapon-types that increase in number as they progress through the game.', 'https://media.retroachievements.org/Images/050441.png', 'https://media.retroachievements.org/Images/006893.png', 'https://media.retroachievements.org/Images/035362.png', 'https://media.retroachievements.org/Images/035363.png', 4.1),
  (137, 440, 'Bonkers', 'SNES/Super Famicom', 3, 1651, 1651, 1651, 21, 0, '2D Platforming', 'Capcom', 'Capcom', '1994-12-15', 'The Super Nintendo Entertainment System has a library of 1,749 official releases, of which 717 were released in North America plus 4 championship cartridges, 532 in Europe, 1,440 in Japan, 231 on Satellaview, and 13 on SuFami Turbo. 296 releases are common to all regions, 147 were released in Japan and the US only, 165 in Europe and the US, and 27 in Japan and Europe. There are 977 Japanese exclusives, 111 US exclusives, and 35 European exclusives. The Super NES was released in North America on August 23, 1991, with its launch titles being Super Mario World, F-Zero, Pilotwings, Gradius III, and SimCity. Despite the console''s relatively late start, and the fierce competition it faced in North America and Europe from Sega''s Genesis/Mega Drive console, it was the best-selling console of its era.', 'https://media.retroachievements.org/Images/034929.png', 'https://media.retroachievements.org/Images/004423.png', 'https://media.retroachievements.org/Images/004422.png', 'https://media.retroachievements.org/Images/004424.png', 4.1),
  (138, 3229, 'Mario''s Early Years: Fun With Numbers', 'SNES/Super Famicom', 3, 1649, 1649, 1649, 12, 0, 'Educational', 'The Software Toolworks', 'Nintendo', '1994-09-01', 'The Mario''s Early Years! series is a trilogy of point-and-click educational games released on MS-DOS and Super Nintendo Entertainment System developed and published by The Software Toolworks under license from Nintendo. The three games consist of Fun with Letters, Fun with Numbers and Preschool Fun.', 'https://media.retroachievements.org/Images/120938.png', 'https://media.retroachievements.org/Images/070019.png', 'https://media.retroachievements.org/Images/017839.png', 'https://media.retroachievements.org/Images/017840.png', 4.1),
  (139, 393, 'Astérix & Obélix', 'SNES/Super Famicom', 3, 1641, 1641, 1641, 86, 0, '2D Platforming', 'Bit Managers', 'Infogrames', '1995-09-28', 'Asterix is a French comic album series about a Gaulish village which, thanks to a magic potion that enhances strength, resists the forces of Julius Caesar''s Roman Republic Army in the time after the Gallic Wars. Many adventures take the titular hero Asterix and his friend Obelix to Rome and beyond.', 'https://media.retroachievements.org/Images/120413.png', 'https://media.retroachievements.org/Images/119216.png', 'https://media.retroachievements.org/Images/017115.png', 'https://media.retroachievements.org/Images/017116.png', 4.1),
  (140, 929, 'The Great Waldo Search', 'SNES/Super Famicom', 3, 1617, 1617, 1617, 15, 0, 'Hidden Object', 'Radiance Software', 'THQ', '1992-01-01', 'Where''s Wally? The Fantastic Journey is the third Where''s Wally? book, first released in 1989. In the book Wally travels to fantasy lands in search of Wizard Whitebeard''s magical scrolls. The book introduces the second recurring Where''s Wally character, Wizard Whitebeard. Readers are also asked for the first time to find the Wizard''s scrolls.', 'https://media.retroachievements.org/Images/113709.png', 'https://media.retroachievements.org/Images/056179.png', 'https://media.retroachievements.org/Images/056182.png', 'https://media.retroachievements.org/Images/056183.png', 4.1),
  (141, 1386, 'Final Fantasy V', 'SNES/Super Famicom', 3, 1597, 1597, 1597, 116, 0, NULL, 'Square', 'Squaresoft', '1992-12-06', 'Final Fantasy V is a 1992 role-playing video game developed and published by Square for the Super Famicom. It is the fifth main installment of the Final Fantasy series. The game begins as a wanderer named Bartz investigates a fallen meteor. There, he encounters several characters, one of whom reveals the danger facing the four Crystals that control the world''s elements. These Crystals act as a seal on Exdeath, an evil sorcerer. Bartz and his party must keep the Crystals from being exploited by Exdeath''s influence and prevent his resurgence.', 'https://media.retroachievements.org/Images/070795.png', 'https://media.retroachievements.org/Images/003373.png', 'https://media.retroachievements.org/Images/003374.png', 'https://media.retroachievements.org/Images/003375.png', 4.1),
  (142, 1361, 'Ghost Sweeper Mikami: Joreishi wa Nice Body', 'SNES/Super Famicom', 3, 1596, 1596, 1596, 18, 0, '2D Platforming', 'Banirex', 'Natsume', '1993-09-23', 'The Super Nintendo Entertainment System has a library of 1,749 official releases, of which 717 were released in North America plus 4 championship cartridges, 532 in Europe, 1,440 in Japan, 231 on Satellaview, and 13 on SuFami Turbo. 296 releases are common to all regions, 147 were released in Japan and the US only, 165 in Europe and the US, and 27 in Japan and Europe. There are 977 Japanese exclusives, 111 US exclusives, and 35 European exclusives. The Super NES was released in North America on August 23, 1991, with its launch titles being Super Mario World, F-Zero, Pilotwings, Gradius III, and SimCity. Despite the console''s relatively late start, and the fierce competition it faced in North America and Europe from Sega''s Genesis/Mega Drive console, it was the best-selling console of its era.', 'https://media.retroachievements.org/Images/049699.png', 'https://media.retroachievements.org/Images/003349.png', 'https://media.retroachievements.org/Images/003346.png', 'https://media.retroachievements.org/Images/003347.png', 4.1),
  (143, 1174, 'Sparkster', 'SNES/Super Famicom', 3, 1571, 1571, 1571, 73, 0, NULL, 'Konami', 'Konami', '1994-09-15', 'Sparkster  is a 1994 platform game developed and published by Konami for the Super Nintendo Entertainment System. It is the only game in the Rocket Knight series to be released on a Nintendo console, and was directed by Hideo Ueda. Sparkster is a sequel to the original Rocket Knight Adventures for the Sega Genesis, though it is a different game than the similarly titled Genesis sequel, Sparkster: Rocket Knight Adventures 2.', 'https://media.retroachievements.org/Images/058016.png', 'https://media.retroachievements.org/Images/113875.png', 'https://media.retroachievements.org/Images/063318.png', 'https://media.retroachievements.org/Images/063319.png', 4.1),
  (144, 9784, '~Hack~ New Super Mario World 1: The Twelve Magic Orbs', 'SNES/Super Famicom', 3, 1545, 1545, 1545, 58, 0, '2D Platforming', 'Pink Gold Peach', 'Hack - Super Mario World', '2016-08-29', 'Dragon Quest, previously published as Dragon Warrior in North America until 2005, is a series of role-playing video games created by Japanese game designer Yuji Horii, character designer Akira Toriyama, and composer Koichi Sugiyama and published by Square Enix. Since its inception, development of games in the series have been outsourced to a plethora of external companies until the tenth installment, with localized remakes and ports of later installments for the Nintendo DS, Nintendo 3DS, and Nintendo Switch being published by Nintendo outside of Japan. With its first game published in 1986, there are eleven main-series games, along with numerous spin-off games. In addition, there have been numerous manga, anime and novels published under the franchise, with nearly every game in the main series having a related adaptation.', 'https://media.retroachievements.org/Images/022110.png', 'https://media.retroachievements.org/Images/020852.png', 'https://media.retroachievements.org/Images/015506.png', 'https://media.retroachievements.org/Images/015507.png', 4.1),
  (145, 1261, 'Thomas the Tank Engine & Friends', 'SNES/Super Famicom', 3, 1521, 1521, 1521, 8, 0, 'Educational', 'Software Creations', 'THQ', '1993-09-01', 'Thomas & Friends is a British children''s television series which aired from 9 October 1984 to 20 January 2021. Based on The Railway Series books by Wilbert and Christopher Awdry, the series was developed for television by Britt Allcroft. The series centers on various anthropomorphic steam locomotives as well as other vehicles living on the fictional Island of Sodor. The show was initially filmed in live action on model sets, whereas the latter half of its run was produced using CGI. Over 500 episodes were produced over the course of 24 series.', 'https://media.retroachievements.org/Images/089849.png', 'https://media.retroachievements.org/Images/034661.png', 'https://media.retroachievements.org/Images/006993.png', 'https://media.retroachievements.org/Images/006994.png', 4.1),
  (146, 4737, 'The Firemen', 'SNES/Super Famicom', 3, 1520, 1520, 1520, 16, 0, 'Action-Adventure', 'Human Entertainment', 'Human Entertainment', '1995-03-01', 'The Firemen is an action video game developed and published by Human Entertainment for the Super Nintendo Entertainment System. It was first released in Japan in 1994, and then in Europe and Australia in 1995. In The Firemen, the player controls firemen who fight fires and save civilians. A sequel was released for the PlayStation in 1995 titled The Firemen 2: Pete & Danny.', 'https://media.retroachievements.org/Images/087674.png', 'https://media.retroachievements.org/Images/007355.png', 'https://media.retroachievements.org/Images/002397.png', 'https://media.retroachievements.org/Images/002398.png', 4.1),
  (147, 1295, 'Uniracers', 'SNES/Super Famicom', 3, 1520, 1520, 1520, 24, 0, 'Racing', 'Rockstar North', 'Nintendo', '1994-06-01', 'Uniracers is a racing game developed by DMA Design and published by Nintendo for the Super Nintendo Entertainment System in North America in December 1994 and in the PAL territories on 27 April 1995.', 'https://media.retroachievements.org/Images/059040.png', 'https://media.retroachievements.org/Images/000814.png', 'https://media.retroachievements.org/Images/000815.png', 'https://media.retroachievements.org/Images/000813.png', 4.1),
  (148, 366, 'Addams Family Values', 'SNES/Super Famicom', 3, 1509, 1509, 1509, 57, 0, NULL, 'Ocean Software', 'Ocean Software', '1995-02-01', 'Addams Family Values is a 1993 American black comedy film, based on the comic strip characters created by Charles Addams. It is the sequel to The Addams Family (1991). Directed by Barry Sonnenfeld and written by Paul Rudnick, the film features most of the cast members from the original film, including Anjelica Huston, Raul Julia, Christopher Lloyd and Christina Ricci, with Joan Cusack and Carol Kane joining the cast.', 'https://media.retroachievements.org/Images/049184.png', 'https://media.retroachievements.org/Images/003730.png', 'https://media.retroachievements.org/Images/006358.png', 'https://media.retroachievements.org/Images/006359.png', 4.1),
  (149, 926, 'Gods', 'SNES/Super Famicom', 3, 1488, 1488, 1488, 32, 0, '2D Platforming', 'The Bitmap Brothers', 'Mindscape', '1992-12-01', 'A deity or god is a supernatural being considered to be sacred and worthy of worship due to having authority over some aspect of the universe and/or life. The Oxford Dictionary of English defines deity as a god or goddess, or anything revered as divine. C. Scott Littleton defines a deity as a being with powers greater than those of ordinary humans, but who interacts with humans, positively or negatively, in ways that carry humans to new levels of consciousness, beyond the grounded preoccupations of ordinary life.', 'https://media.retroachievements.org/Images/096087.png', 'https://media.retroachievements.org/Images/095890.png', 'https://media.retroachievements.org/Images/095888.png', 'https://media.retroachievements.org/Images/095889.png', 4.1),
  (150, 2905, 'Cannon Fodder', 'SNES/Super Famicom', 3, 1474, 1474, 1474, 52, 0, 'Action, Strategy', 'Sensible Software', 'Virgin Interactive', '1994-01-01', 'Cannon Fodder is a series of war themed action games developed by Sensible Software, initially released as Cannon Fodder for the Amiga. Only two games in the series were created by Sensible, but were converted to most active systems at the time of release. A sequel, Cannon Fodder 2, was released in 1994 for Amiga and MS-DOS. A third game, Cannon Fodder 3, was made by a Russian developer and released in English in 2012.', 'https://media.retroachievements.org/Images/089451.png', 'https://media.retroachievements.org/Images/009283.png', 'https://media.retroachievements.org/Images/035368.png', 'https://media.retroachievements.org/Images/035369.png', 4.1),
  (151, 2602, 'Majuuou', 'SNES/Super Famicom', 3, 1467, 1467, 1467, 46, 0, NULL, 'Nippon Ichi Software', 'KSS', '1995-08-25', NULL, 'https://media.retroachievements.org/Images/035557.png', 'https://media.retroachievements.org/Images/124235.png', 'https://media.retroachievements.org/Images/020873.png', 'https://media.retroachievements.org/Images/007482.png', 4.1),
  (152, 555, 'Shin Kidou Senki Gundam W: Endless Duel', 'SNES/Super Famicom', 3, 1451, 1451, 1451, 25, 0, '2D Fighting', 'Natsume', 'Bandai', '1996-01-01', 'The Super Nintendo Entertainment System has a library of 1,749 official releases, of which 717 were released in North America plus 4 championship cartridges, 532 in Europe, 1,440 in Japan, 231 on Satellaview, and 13 on SuFami Turbo. 296 releases are common to all regions, 147 were released in Japan and the US only, 165 in Europe and the US, and 27 in Japan and Europe. There are 977 Japanese exclusives, 111 US exclusives, and 35 European exclusives. The Super NES was released in North America on August 23, 1991, with its launch titles being Super Mario World, F-Zero, Pilotwings, Gradius III, and SimCity. Despite the console''s relatively late start, and the fierce competition it faced in North America and Europe from Sega''s Genesis/Mega Drive console, it was the best-selling console of its era.', 'https://media.retroachievements.org/Images/051792.png', 'https://media.retroachievements.org/Images/006510.png', 'https://media.retroachievements.org/Images/001304.png', 'https://media.retroachievements.org/Images/001305.png', 4.1),
  (153, 1215, 'Super E.D.F.: Earth Defense Force', 'SNES/Super Famicom', 3, 1430, 1430, 1430, 29, 0, 'Shoot ''em Up', 'Jaleco', 'Jaleco', '1991-10-25', 'E.D.F.: Earth Defense Force is a 1991 horizontally scrolling shooter video game developed and published by Jaleco for arcades. It was ported to the Super Nintendo Entertainment System as Super Earth Defense Force, dropping the two-player cooperative gaming mode while adding graphics and selectable weapons. The Super NES version was released in Japan on October 25, 1991, and in North America in January 1992. The Super NES version was eventually released on the Wii Virtual Console in Europe on October 29, 2010, and in 2011 for Japan on January 11, and North America on July 14. It was released on the Nintendo Classics service in September 2019.', 'https://media.retroachievements.org/Images/048925.png', 'https://media.retroachievements.org/Images/009242.png', 'https://media.retroachievements.org/Images/009243.png', 'https://media.retroachievements.org/Images/009244.png', 4.1),
  (154, 1244, 'Super Valis IV', 'SNES/Super Famicom', 3, 1422, 1422, 1422, 26, 0, 'Action', 'Telenet Japan', 'Razorsoft', '1992-03-27', 'Valis IV is a 1991 action-platform video game originally developed by Laser Soft and published by Telenet Japan for the PC Engine CD-ROM². A vastly different version titled Super Valis IV was published in Japan by Telenet in 1992 and in North America by Atlus Software in 1993 for the Super Nintendo Entertainment System. It is the fourth and final main entry in the eponymous series. Following on the events of Valis III, Yuko became a goddess and has watched over Vecanti since Glames'' defeat. The dark world prince Galgear, who lost self-control after acquiring a magical ring, broke from his fifteen-year imprisonment by the gods of Vecanti, kidnapping Valna and being pursued by troops led by Cham. Lena, a member of Cham''s band, is joined by her sister Amu and the prince''s father Asfal on a journey to retrieve the titular sword and defeat Galgear.', 'https://media.retroachievements.org/Images/027595.png', 'https://media.retroachievements.org/Images/001572.png', 'https://media.retroachievements.org/Images/035587.png', 'https://media.retroachievements.org/Images/035588.png', 4.1),
  (155, 3230, 'Mario''s Early Years: Preschool Fun', 'SNES/Super Famicom', 3, 1414, 1414, 1414, 15, 0, 'Educational', 'The Software Toolworks', 'Nintendo', '1994-11-01', 'The Mario''s Early Years! series is a trilogy of point-and-click educational games released on MS-DOS and Super Nintendo Entertainment System developed and published by The Software Toolworks under license from Nintendo. The three games consist of Fun with Letters, Fun with Numbers and Preschool Fun.', 'https://media.retroachievements.org/Images/120939.png', 'https://media.retroachievements.org/Images/052639.png', 'https://media.retroachievements.org/Images/019986.png', 'https://media.retroachievements.org/Images/019987.png', 4.1),
  (156, 2817, 'Super Buster Bros.', 'SNES/Super Famicom', 3, 1410, 1410, 1410, 66, 0, 'Action', 'Capcom', 'Capcom', '1992-01-01', 'Super Buster Bros., released as Super Pang outside of North America, is a cooperative two-player shooting puzzle arcade video game developed by Mitchell and released in the United States in 1990 by Capcom. It is the second game in the Pang series and was ported to the Super Nintendo Entertainment System in 1992. It is also featured in the compilations Buster Bros. Collection for the original PlayStation and Capcom Puzzle World for PlayStation Portable. It was the tenth game released for the CP System hardware.', 'https://media.retroachievements.org/Images/115462.png', 'https://media.retroachievements.org/Images/124243.png', 'https://media.retroachievements.org/Images/070948.png', 'https://media.retroachievements.org/Images/070949.png', 4.1),
  (157, 1037, 'Monopoly', 'SNES/Super Famicom', 3, 1405, 1405, 1405, 29, 0, 'Board Game', 'Sculptured Software | Iguana West', 'Parker Brothers', '1991-01-01', 'A monopoly is a market in which one person or company is the only supplier of a particular good or service. A monopoly is characterized by a lack of economic competition to produce a particular thing, a lack of viable substitute goods, and the possibility of a high monopoly price well above the seller''s marginal cost that leads to a high monopoly profit. The verb monopolise or monopolize refers to the process by which a company gains the ability to raise prices or exclude competitors. In economics, a monopoly is a single seller. In law, a monopoly is a business entity that has significant market power, that is, the power to charge overly high prices, which is associated with unfair price raises. Although monopolies may be big businesses, size is not a characteristic of a monopoly. A small business may still have the power to raise prices in a small industry.', 'https://media.retroachievements.org/Images/017240.png', 'https://media.retroachievements.org/Images/017238.png', 'https://media.retroachievements.org/Images/017239.png', 'https://media.retroachievements.org/Images/017365.png', 4.1),
  (158, 443, 'Brain Lord', 'SNES/Super Famicom', 3, 1404, 1404, 1404, 50, 0, 'Action RPG', 'Produce!', 'Enix', '1994-01-29', 'Brain Lord  is an action role-playing video game developed by Produce! and published by Enix for the Super NES. It was only released in Japan and North America.', 'https://media.retroachievements.org/Images/081733.png', 'https://media.retroachievements.org/Images/039064.png', 'https://media.retroachievements.org/Images/098317.png', 'https://media.retroachievements.org/Images/006261.png', 4.1),
  (159, 374, 'Aero the Acro-Bat', 'SNES/Super Famicom', 3, 1392, 1392, 1392, 126, 0, '2D Platforming', 'Iguana Entertainment', 'Sunsoft', '1993-10-01', 'Aero the Acro-Bat is a 1993 platform video game developed by Iguana Entertainment and published by Sunsoft for the Super Nintendo Entertainment System and Sega Genesis. Aero the Acro-Bat, a red anthropomorphic bat, was created by David Siller. In 2002, Metro 3D released a version of the game for the Game Boy Advance, with a battery back-up. The GBA version was titled Aero The Acro-Bat - Rascal Rival Revenge in Europe and Acrobat Kid in Japan. The Super NES version of the game was released on the Wii''s Virtual Console in the PAL region and North America in July 2010. In 2024, the Super NES version was re-released in August for Nintendo Switch, PlayStation 4, PlayStation 5, Xbox One, and Xbox Series X/S, alongside a new localization in Japanese made by Shinyuden as Aero: Acrobat Kid for the Nintendo Switch users in Japan, while the GBA version was re-released for the same platforms in November.', 'https://media.retroachievements.org/Images/075614.png', 'https://media.retroachievements.org/Images/006369.png', 'https://media.retroachievements.org/Images/006365.png', 'https://media.retroachievements.org/Images/006366.png', 4.1),
  (160, 1391, 'Trials of Mana', 'SNES/Super Famicom', 3, 1392, 1392, 1392, 100, 0, NULL, 'Square', 'Squaresoft', '1995-09-30', 'Trials of Mana, also known by its Japanese title Seiken Densetsu 3, is a 1995 action role-playing game developed and published by Square for the Super Famicom. It is the sequel to the 1993 game Secret of Mana, and is the third installment in the Mana series. Set in a high fantasy world, the game follows three heroes as they attempt to claim the legendary Mana Sword and prevent the Benevodons from being unleashed and destroying the world. It features three main plotlines and six different possible main characters, each with their own storylines, and allows two players to play simultaneously. Trials of Mana builds on the gameplay of its predecessor with multiple enhancements, including the use of a time progression system with transitions from day to night and weekday to weekday in game time, and a wide range of character classes to choose from, which provides each character with an exclusive set of skills and status progression.', 'https://media.retroachievements.org/Images/104864.png', 'https://media.retroachievements.org/Images/002847.png', 'https://media.retroachievements.org/Images/002848.png', 'https://media.retroachievements.org/Images/006100.png', 4.1),
  (161, 1150, 'Shaq-Fu', 'SNES/Super Famicom', 3, 1373, 1373, 1373, 31, 0, '2D Fighting', 'Delphine Software International', 'Electronic Arts, Playtronic', '1994-10-28', 'Shaq Fu is a 1994 fighting game developed by Delphine Software International and published by Electronic Arts for the Sega Genesis and Super Nintendo Entertainment System. Versions for the Game Gear, Game Boy, and Amiga followed in 1995. Professional basketball player Shaquille O''Neal is the player character.', 'https://media.retroachievements.org/Images/023579.png', 'https://media.retroachievements.org/Images/004850.png', 'https://media.retroachievements.org/Images/004853.png', 'https://media.retroachievements.org/Images/004852.png', 4.1),
  (162, 1099, 'Pitfall: The Mayan Adventure', 'SNES/Super Famicom', 3, 1353, 1353, 1353, 58, 0, '2D Platforming', 'Redline Games', 'Activision', '1994-11-01', 'Pitfall: The Mayan Adventure is a 1994 action-platform video game developed by Activision in conjunction with Kroyer Films. The fourth installment in the Pitfall! franchise, players assume the role of Pitfall Harry Jr. as he embarks on a journey through the Mayan jungles of Central America in an attempt to rescue Pitfall Harry, his father and the protagonist of previous entries in the series, from the evil Mayan warrior spirit Zakelua. Its gameplay mainly consists of action and platforming mixed with stage-based exploration using a main six-button configuration.', 'https://media.retroachievements.org/Images/092737.png', 'https://media.retroachievements.org/Images/096578.png', 'https://media.retroachievements.org/Images/007146.png', 'https://media.retroachievements.org/Images/007147.png', 4.1),
  (163, 1158, 'The Simpsons: Bart''s Nightmare', 'SNES/Super Famicom', 3, 1333, 1333, 1333, 25, 0, '2D Platforming', 'Sculptured Software | Iguana West', 'Acclaim', '1992-01-01', 'The Simpsons: Bart''s Nightmare is a 1992 platform video game based on the animated television series The Simpsons. Developed by Sculptured Software and published by Acclaim Entertainment, it was first released for the Super Nintendo Entertainment System in 1992, followed by the Sega Genesis in 1993. The first half of the game follows Bart Simpson as he tries to find his missing homework pages in order to escape a bizarre dream world, while the second half consists of minigames.', 'https://media.retroachievements.org/Images/109673.png', 'https://media.retroachievements.org/Images/003631.png', 'https://media.retroachievements.org/Images/003633.png', 'https://media.retroachievements.org/Images/003632.png', 4),
  (164, 9790, 'Dr. Mario', 'SNES/Super Famicom', 3, 1331, 1331, 1331, 78, 0, NULL, NULL, 'Nintendo', '1998-06-01', 'Dr. Mario is a 1990 puzzle video game developed and published by Nintendo for the Nintendo Entertainment System and Game Boy. A spin-off of the Mario series, it is a falling block puzzle game in which the player''s objective is to destroy the viruses populating the on-screen playing field by using colored capsules that are automatically tossed into the field by Dr. Mario. The player manipulates the falling capsules, to align the same colors, which destroys viruses. The player progresses through the game by eliminating all the viruses on the screen in each level. The game was produced by Gunpei Yokoi and programmed by Takahiro Harada, with the soundtrack composed by Hirokazu Tanaka.', 'https://media.retroachievements.org/Images/070808.png', 'https://media.retroachievements.org/Images/114804.png', 'https://media.retroachievements.org/Images/023464.png', 'https://media.retroachievements.org/Images/023465.png', 4),
  (165, 3234, 'The Mask', 'SNES/Super Famicom', 3, 1304, 1304, 1304, 26, 0, '2D Platforming', 'Black Pearl', 'Black Pearl', '1995-10-01', 'The Mask is a 1995 side-scrolling action video game developed and published by THQ subsidiary Black Pearl Software for the Super Nintendo Entertainment System which is based on the film of the same name. The film, in turn, was loosely based on the Dark Horse comic book series of the same name.', 'https://media.retroachievements.org/Images/121441.png', 'https://media.retroachievements.org/Images/007194.png', 'https://media.retroachievements.org/Images/035578.png', 'https://media.retroachievements.org/Images/035579.png', 4),
  (166, 412, 'Barbie: Super Model', 'SNES/Super Famicom', 3, 1302, 1302, 1302, 7, 0, 'Action', 'Tahoe Software Productions', 'Hi-Tech Expressions', '1993-12-01', 'Barbie: Super Model is a one or two-player educational action video game that allows the player to play as Barbie. It was released for the Genesis, Super NES, and MS-DOS in 1993.', 'https://media.retroachievements.org/Images/078520.png', 'https://media.retroachievements.org/Images/053617.png', 'https://media.retroachievements.org/Images/008710.png', 'https://media.retroachievements.org/Images/008716.png', 4),
  (167, 16121, '~Hack~ New Super Mario World 2: Around the World', 'SNES/Super Famicom', 3, 1298, 1298, 1298, 45, 0, '2D Platforming', 'Pink Gold Peach', 'Hack - Super Mario World', '2019-01-01', 'Super Mario Kart is a 1992 kart racing game developed and published by Nintendo for the Super Nintendo Entertainment System (SNES). The first game in the Mario Kart series, it was released in Japan on August 27, 1992, North America on September 1, 1992, the United Kingdom in October 1992, and Europe on January 21, 1993. Selling 8.76 million copies worldwide, the game went on to become the fourth best-selling SNES game of all time. Super Mario Kart was re-released on the Wii''s Virtual Console in 2009, on the Wii U''s Virtual Console in 2013, and on the New Nintendo 3DS''s Virtual Console in 2016. Nintendo re-released Super Mario Kart in 2017 as part of the company''s Super NES Classic Edition.', 'https://media.retroachievements.org/Images/063931.png', 'https://media.retroachievements.org/Images/032596.png', 'https://media.retroachievements.org/Images/032597.png', 'https://media.retroachievements.org/Images/032598.png', 4),
  (168, 967, 'Judge Dredd', 'SNES/Super Famicom', 3, 1295, 1295, 1295, 43, 0, '2D Platforming', 'Probe Entertainment', 'Acclaim', '1995-06-16', 'Judge Joseph Dredd is a fictional character created by writer John Wagner and artist Carlos Ezquerra. He first appeared in the second issue of the British weekly anthology comic 2000 AD (1977). He is the magazine''s longest-running character, and in 1990 he got his own title, the Judge Dredd Megazine. He also appears in a number of film and video game adaptations.', 'https://media.retroachievements.org/Images/062928.png', 'https://media.retroachievements.org/Images/015324.png', 'https://media.retroachievements.org/Images/015325.png', 'https://media.retroachievements.org/Images/015326.png', 4),
  (169, 993, 'Lemmings', 'SNES/Super Famicom', 3, 1280, 1280, 1280, 123, 0, 'Puzzle', 'Sunsoft', 'Sunsoft', '1991-12-18', 'A lemming is a small rodent, usually found in or near the Arctic in tundra biomes. Lemmings form the subfamily Arvicolinae together with voles and muskrats, which form part of the superfamily Muroidea, which also includes rats, mice, hamsters and gerbils. A longstanding myth claims that they exhibit herd mentality and jump off cliffs, committing mass suicide.', 'https://media.retroachievements.org/Images/041707.png', 'https://media.retroachievements.org/Images/002222.png', 'https://media.retroachievements.org/Images/085120.png', 'https://media.retroachievements.org/Images/085121.png', 4),
  (170, 2345, '~Hack~ The Legend of Zelda: Parallel Worlds', 'SNES/Super Famicom', 3, 1277, 1277, 1277, 100, 0, 'Action-Adventure', 'Seph, Euclid, Richyawyingtmv', 'Hack - The Legend of Zelda: A Link to the Past', '2006-12-31', 'A fan game is a video game that is created by fans of a certain topic or IP. They are usually based on one, or in some cases several, video game entries or franchises. Many fan games attempt to clone or remake the original game''s design, gameplay, and characters, but it is equally common for fans to develop a unique game using another as a template. Though the quality of fan games has always varied, recent advances in computer technology and in available tools, e.g. through open source software, have made creating high-quality games easier. Fan games can be seen as user-generated content, as part of the retrogaming phenomena, and as expression of the remix culture.', 'https://media.retroachievements.org/Images/052201.png', 'https://media.retroachievements.org/Images/022021.png', 'https://media.retroachievements.org/Images/023380.png', 'https://media.retroachievements.org/Images/005044.png', 4),
  (171, 3374, 'The Pirates of Dark Water', 'SNES/Super Famicom', 3, 1255, 1255, 1255, 21, 0, 'Beat ''em Up', 'Sunsoft', 'Sunsoft', '1994-05-01', 'The Pirates of Dark Water is an American fantasy animated television series created by David Kirschner and produced by Hanna-Barbera. It premiered as a five-part miniseries on Fox Kids in early 1991 titled Dark Water. The first season, consisting of 13 episodes including the original five-part miniseries, aired on ABC from September to December 1991. A second season, consisting of eight episodes, aired in syndication in the United States from 1992 to 1993.', 'https://media.retroachievements.org/Images/065466.png', 'https://media.retroachievements.org/Images/006442.png', 'https://media.retroachievements.org/Images/006443.png', 'https://media.retroachievements.org/Images/006444.png', 4),
  (172, 1302, 'Ys III: Wanderers from Ys', 'SNES/Super Famicom', 3, 1251, 1251, 1251, 46, 0, NULL, 'Nihon Falcom', 'Sammy', '1992-01-01', 'Ys III: Wanderers from Ys is a 1989 action role-playing game developed by Nihon Falcom. It is the third game in the Ys series.', 'https://media.retroachievements.org/Images/111797.png', 'https://media.retroachievements.org/Images/002507.png', 'https://media.retroachievements.org/Images/002509.png', 'https://media.retroachievements.org/Images/002508.png', 4),
  (173, 8702, 'Strike Gunner S.T.G', 'SNES/Super Famicom', 3, 1247, 1247, 1247, 21, 0, 'Shoot ''em Up', 'Athena', 'NTV International', '1992-01-01', 'Strike Gunner S.T.G (エス・ティー・ジー) is a 1991 vertically scrolling shooter arcade game developed by Athena and published by Tecmo.', 'https://media.retroachievements.org/Images/047001.png', 'https://media.retroachievements.org/Images/014759.png', 'https://media.retroachievements.org/Images/014761.png', 'https://media.retroachievements.org/Images/014762.png', 4),
  (174, 949, 'Inspector Gadget', 'SNES/Super Famicom', 3, 1242, 1242, 1242, 7, 0, '2D Platforming', NULL, 'Hudson Soft', '1993-12-01', 'Inspector Gadget is a media franchise that began in 1983 with the DIC Entertainment animated television series Inspector Gadget. Since the original series, there have been many spin-offs based on the show, including additional animated series, video games, and films.', 'https://media.retroachievements.org/Images/118599.png', 'https://media.retroachievements.org/Images/006455.png', 'https://media.retroachievements.org/Images/006457.png', 'https://media.retroachievements.org/Images/006456.png', 4),
  (175, 940, 'Hook', 'SNES/Super Famicom', 3, 1221, 1221, 1221, 21, 0, 'Action-adventure', 'Ukiyotei', 'Sony Imagesoft', '1992-07-17', 'A hook is a tool consisting of a length of material, typically metal, that contains a portion that is curved/bent back or has a deeply grooved indentation, which serves to grab, latch or in any way attach itself onto another object. The hook''s design allows traction forces to be relayed through the curved/indented portion to and from the proximal end of the hook, which is either a straight shaft or a ring for attachment to a thread, rope or chain, providing a reversible attachment between two objects.', 'https://media.retroachievements.org/Images/111494.png', 'https://media.retroachievements.org/Images/003163.png', 'https://media.retroachievements.org/Images/003164.png', 'https://media.retroachievements.org/Images/003165.png', 4),
  (176, 627, 'Dragon: The Bruce Lee Story', 'SNES/Super Famicom', 3, 1219, 1219, 1219, 38, 0, '2D Fighting', 'Virgin Interactive', 'Acclaim, Virgin Interactive', '1995-01-01', 'Dragon: The Bruce Lee Story is a 1993 American biographical drama film directed by Rob Cohen. The film stars Jason Scott Lee, with a supporting cast including Lauren Holly, Nancy Kwan, and Robert Wagner. The film follows the life of actor and martial artist Bruce Lee (Jason) from his relocation to the United States from Hong Kong to his career as a martial arts teacher, and then as a television and film actor. It also focuses on the relationship between Bruce and his wife Linda, and the racism to which Bruce was subjected.', 'https://media.retroachievements.org/Images/062623.png', 'https://media.retroachievements.org/Images/028543.png', 'https://media.retroachievements.org/Images/028541.png', 'https://media.retroachievements.org/Images/028542.png', 4),
  (177, 1392, 'Star Ocean', 'SNES/Super Famicom', 3, 1213, 1213, 1213, 67, 0, 'Action RPG', 'tri-Ace', 'Enix', '1996-07-19', 'Star Ocean is a franchise of science fantasy Action role-playing video games developed by the Japanese company tri-Ace and published by Square Enix.', 'https://media.retroachievements.org/Images/064813.png', 'https://media.retroachievements.org/Images/101305.png', 'https://media.retroachievements.org/Images/003573.png', 'https://media.retroachievements.org/Images/003575.png', 4),
  (178, 1424, 'Super Star Wars: The Empire Strikes Back', 'SNES/Super Famicom', 3, 1195, 1195, 1195, 46, 0, '2D Platforming, Action', 'LucasArts | Lucasfilm', 'JVC, THQ', '1993-06-01', 'Super Star Wars: The Empire Strikes Back, also known as Super Empire Strikes Back, is a 1993 action video game developed by LucasArts and Sculptured Software and published by JVC Musical Industries for the Super Nintendo Entertainment System. It is based on the 1980 film The Empire Strikes Back and is the sequel to Super Star Wars. The game was followed by a sequel, Super Star Wars: Return of the Jedi in 1994. Unlike its predecessor, Nintendo was not involved in its publishing. The game was re-released on the Wii''s Virtual Console in North America on August 24, 2009 and in the PAL regions on October 2, 2009, alongside the other games in the Super Star Wars series.', 'https://media.retroachievements.org/Images/061312.png', 'https://media.retroachievements.org/Images/045655.png', 'https://media.retroachievements.org/Images/006086.png', 'https://media.retroachievements.org/Images/006087.png', 4),
  (179, 1210, 'Super Bowling', 'SNES/Super Famicom', 3, 1186, 1186, 1186, 20, 0, 'Sports - Bowling', 'Athena, Technos Japan', 'Technos Japan', '1992-07-03', 'Super Bowling (スーパーボウリング) is a 1992 sports video game for the Super NES and the Nintendo 64. It was developed by KID and published by Athena, originally only for the SNES. It was later picked up by American Technōs and UFO Interactive and released for the N64 in 1999.', 'https://media.retroachievements.org/Images/066245.png', 'https://media.retroachievements.org/Images/005846.png', 'https://media.retroachievements.org/Images/005848.png', 'https://media.retroachievements.org/Images/005849.png', 4),
  (180, 1102, 'Pocky & Rocky 2', 'SNES/Super Famicom', 3, 1176, 1176, 1176, 85, 0, NULL, 'Natsume', 'Natsume', '1994-06-17', 'Pocky & Rocky 2, released in Japan as Kiki Kaikai: Tsukiyo Soushi , is a shoot ''em up video game developed and published by Natsume Co., Ltd. in Japan, published by Natsume Inc. in North America, and published in PAL regions by Ocean Software for the Super NES video game console. It is the sequel to Pocky & Rocky.', 'https://media.retroachievements.org/Images/037042.png', 'https://media.retroachievements.org/Images/006532.png', 'https://media.retroachievements.org/Images/006533.png', 'https://media.retroachievements.org/Images/006534.png', 4),
  (181, 429, 'Beethoven''s 2nd', 'SNES/Super Famicom', 3, 1169, 1169, 1169, 10, 0, '2D Platforming', 'Riedel Software Productions', 'Hi-Tech Expressions', '1993-12-01', 'The Symphony No. 2 in D major, Op. 36, is a symphony in four movements written by Ludwig van Beethoven between 1801 and 1802. The work is dedicated to Karl Alois, Prince Lichnowsky.', 'https://media.retroachievements.org/Images/052568.png', 'https://media.retroachievements.org/Images/017260.png', 'https://media.retroachievements.org/Images/017257.png', 'https://media.retroachievements.org/Images/017258.png', 4),
  (182, 8463, '~Hack~ Mega Man X3: Zero Project', 'SNES/Super Famicom', 3, 1168, 1168, 1168, 76, 0, 'Action / Platforming', 'Justin3009', 'Hack - Mega Man X3', '2012-01-31', 'Mega Man X is a series of action-platform games released by Capcom. It is a sub-series of the Mega Man franchise previously developed by the same group, with Keiji Inafune acting as one of the main staff members. The first game was released on 17 December 1993 in Japan on the Super Famicom and the following month on the Super NES in North America. Most of the sequels were ported to Microsoft Windows. The gameplay introduces new elements to the Mega Man franchise in the form of Mega Man''s successor X, including his new skills and power-ups in the form of armors while retaining the ability to decide which boss to fight first. The franchise is also known for its replay value, in which certain choices and optional content can influence both gameplay and storylines, allowing the player to experience alternate scenarios.', 'https://media.retroachievements.org/Images/056191.png', 'https://media.retroachievements.org/Images/016573.png', 'https://media.retroachievements.org/Images/008536.png', 'https://media.retroachievements.org/Images/008537.png', 4),
  (183, 2865, '~Hack~ A Plumber For All Seasons', 'SNES/Super Famicom', 3, 1165, 1165, 1165, 76, 0, '2D Platforming', 'WhiteYoshiEgg', 'Hack - Super Mario World', '2021-07-06', 'Super Mario Bros. is a 1985 platform game developed and published by Nintendo for the Nintendo Entertainment System (NES). Directed and produced by Shigeru Miyamoto, it is the successor to the 1983 arcade game Mario Bros. and the first game in the Super Mario series. Players control Mario, or his brother Luigi in the multiplayer mode, to traverse the Mushroom Kingdom to rescue Princess Toadstool from King Koopa. They traverse side-scrolling stages while avoiding hazards such as enemies and pits and collecting power-ups such as the Super Mushroom, Fire Flower, and Starman.', 'https://media.retroachievements.org/Images/047272.png', 'https://media.retroachievements.org/Images/051320.png', 'https://media.retroachievements.org/Images/045904.png', 'https://media.retroachievements.org/Images/045905.png', 4),
  (184, 1346, 'Yoshi''s Cookie', 'SNES/Super Famicom', 3, 1148, 1148, 1148, 77, 0, 'Tile Matching', 'TOSE', 'Bullet-Proof Software', '1993-06-01', 'Yoshi''s Cookie is a 1992 tile-matching puzzle video game developed by Tose and published by Nintendo for the NES and Game Boy platforms in 1992. A Super NES version was released the following year, developed and published by Bullet-Proof Software.', 'https://media.retroachievements.org/Images/075902.png', 'https://media.retroachievements.org/Images/007507.png', 'https://media.retroachievements.org/Images/046816.png', 'https://media.retroachievements.org/Images/046817.png', 4),
  (185, 3808, 'Super Off Road', 'SNES/Super Famicom', 3, 1147, 1147, 1147, 59, 0, 'Racing', 'Leland', 'Virgin Interactive', '1991-12-01', 'Ivan ''Ironman'' Stewart''s Super Off Road is a 1989 racing video game developed and published by Leland Corporation for arcades. It was designed and managed by John Morgan, who was also lead programmer, and endorsed by professional off-road racer Ivan Stewart. Virgin Games produced several home computer versions in 1990, with a version for the Nintendo Entertainment System released by Leland''s Tradewest subsidiary the same year. It was followed by versions for most major home consoles, including the Master System, Sega Genesis, and Super Nintendo Entertainment System. A port for the Atari Jaguar was announced but never released. Some ports lack the Ivan Stewart branding because of licensing issues, and are known simply as Super Off Road.', 'https://media.retroachievements.org/Images/109876.png', 'https://media.retroachievements.org/Images/032668.png', 'https://media.retroachievements.org/Images/032670.png', 'https://media.retroachievements.org/Images/032669.png', 4),
  (186, 6231, 'Dragon Quest III: Soshite Densetsu e...', 'SNES/Super Famicom', 3, 1143, 1143, 1143, 97, 0, 'Turn-Based RPG', 'Heartbeat', 'Enix', '1996-12-06', 'Dragon Quest III: The Seeds of Salvation, titled Dragon Warrior III when initially localized to North America, is a 1988 role-playing video game developed by Chunsoft and published by Enix. It is the third installment in the Dragon Quest series and was first released for the Family Computer (Famicom) in Japan and later for the Nintendo Entertainment System (NES) in North America. The game saw an enhanced remake for the Super Famicom in 1996 and the Game Boy Color in 2001, and a port to mobile phones and the Wii in 2009 and 2011. A version of the game for Android and iOS was released in Japan on September 25, 2014, and worldwide as Dragon Quest III: The Seeds of Salvation on December 4, 2014. It was the first time the game was given an official English subtitle. Later in 2021, another remake of the game titled Dragon Quest III HD-2D Remake, based on the HD-2D graphical style of Octopath Traveler (2018), was announced during the franchise''s 35th anniversary livestream. The remake was released on November 14th, 2024 for Nintendo Switch, PlayStation 5, Windows, and Xbox Series consoles.', 'https://media.retroachievements.org/Images/067893.png', 'https://media.retroachievements.org/Images/008405.png', 'https://media.retroachievements.org/Images/008395.png', 'https://media.retroachievements.org/Images/015363.png', 4),
  (187, 1353, 'Pinocchio', 'SNES/Super Famicom', 3, 1141, 1141, 1141, 37, 0, '2D Platforming', 'Virgin Interactive', 'Nintendo', '1996-11-01', 'Pinocchio is a fictional character and the protagonist of the children''s novel The Adventures of Pinocchio (1881) by Italian writer Carlo Collodi of Florence, Tuscany. Pinocchio was carved by a poor man named Geppetto in a Tuscan village. He is created as a wooden puppet, but he dreams of becoming a real boy. He is known for his long nose, which grows when he lies.', 'https://media.retroachievements.org/Images/062337.png', 'https://media.retroachievements.org/Images/008777.png', 'https://media.retroachievements.org/Images/027937.png', 'https://media.retroachievements.org/Images/027938.png', 4),
  (188, 968, 'The Jungle Book', 'SNES/Super Famicom', 3, 1125, 1125, 1125, 21, 0, '2D Platforming', 'Virgin Interactive', 'Virgin Interactive', '1994-07-15', 'The Jungle Book is an 1894 collection of stories by the English author Rudyard Kipling. Most of the characters are animals such as Shere Khan the tiger and Baloo the bear, though a principal character is the boy or man-cub Mowgli, who is raised in the jungle by wolves. Most stories are set in a forest in India; one place mentioned repeatedly is Seeonee (Seoni), in the central state of Madhya Pradesh.', 'https://media.retroachievements.org/Images/059503.png', 'https://media.retroachievements.org/Images/007096.png', 'https://media.retroachievements.org/Images/007094.png', 'https://media.retroachievements.org/Images/007095.png', 4),
  (189, 1213, 'Super Chase H.Q.', 'SNES/Super Famicom', 3, 1123, 1123, 1123, 28, 0, 'Racing', 'Taito', 'Taito', '1993-12-01', 'Super Chase H.Q. is a 1992 arcade racing game developed and published by Taito. It is the third release in the Chase H.Q. series, and the sequel to Special Criminal Investigation. After the initial release in Japanese arcades under the title Super Chase: Criminal Termination, it was re-released in North America in 1993 for the Super Nintendo.', 'https://media.retroachievements.org/Images/121621.png', 'https://media.retroachievements.org/Images/009726.png', 'https://media.retroachievements.org/Images/009730.png', 'https://media.retroachievements.org/Images/009731.png', 4),
  (190, 1354, 'Tiny Toon Adventures: Wacky Sports Challenge', 'SNES/Super Famicom', 3, 1123, 1123, 1123, 59, 0, 'Sports', 'Konami', 'Konami', '1994-09-30', 'Tiny Toon Adventures: Wacky Sports Challenge is a sports video game. The game was released in 1994 for the Super Nintendo Entertainment System and developed and published by Konami. It is based on the American children’s television series, Tiny Toon Adventures. It is one of the few SNES games to feature an SNES Multitap as a useable controller.', 'https://media.retroachievements.org/Images/073611.png', 'https://media.retroachievements.org/Images/002387.png', 'https://media.retroachievements.org/Images/002389.png', 'https://media.retroachievements.org/Images/002388.png', 4),
  (191, 1040, 'Mr. Do!', 'SNES/Super Famicom', 3, 1122, 1122, 1122, 20, 0, 'Maze Chase', 'C-Lab', 'Black Pearl', '1996-12-01', 'Mr. Do! is a 1982 maze video game developed by Universal. It is the first arcade video game to be released as a conversion kit for other cabinets; Taito published the conversion kit in Japan. The game was inspired by Namco''s Dig Dug, released earlier in 1982. Mr. Do! was a commercial success in Japan and North America, selling 30,000 arcade units in the US, and it was followed by several arcade sequels.', 'https://media.retroachievements.org/Images/119055.png', 'https://media.retroachievements.org/Images/009921.png', 'https://media.retroachievements.org/Images/009919.png', 'https://media.retroachievements.org/Images/009920.png', 4),
  (192, 1180, 'Venom and Spider-Man: Separation Anxiety', 'SNES/Super Famicom', 3, 1120, 1120, 1120, 50, 0, 'Beat ''em Up', 'Software Creations', 'Acclaim', '1995-11-01', 'The Super Nintendo Entertainment System has a library of 1,749 official releases, of which 717 were released in North America plus 4 championship cartridges, 532 in Europe, 1,440 in Japan, 231 on Satellaview, and 13 on SuFami Turbo. 296 releases are common to all regions, 147 were released in Japan and the US only, 165 in Europe and the US, and 27 in Japan and Europe. There are 977 Japanese exclusives, 111 US exclusives, and 35 European exclusives. The Super NES was released in North America on August 23, 1991, with its launch titles being Super Mario World, F-Zero, Pilotwings, Gradius III, and SimCity. Despite the console''s relatively late start, and the fierce competition it faced in North America and Europe from Sega''s Genesis/Mega Drive console, it was the best-selling console of its era.', 'https://media.retroachievements.org/Images/122977.png', 'https://media.retroachievements.org/Images/008041.png', 'https://media.retroachievements.org/Images/010315.png', 'https://media.retroachievements.org/Images/010316.png', 4),
  (193, 3226, 'Mario is Missing!', 'SNES/Super Famicom', 3, 1115, 1115, 1115, 36, 0, 'Educational', 'Software Toolworks', 'Mindscape, Software Toolworks', '1993-06-01', 'Mario Is Missing! is a 1993 educational game developed and published by The Software Toolworks for MS-DOS, Nintendo Entertainment System, and Super Nintendo Entertainment System, later released on Macintosh in 1994. The player controls Luigi, who must travel around the world to find and return stolen treasures as part of a quest to locate his brother, Mario, who has been captured by Bowser. Mario Is Missing!, part of a series of educational Mario games, was Luigi''s second starring role in a video game, following the 1990 Game Watch game Luigi''s Hammer Toss and preceding the 2001 GameCube game Luigi''s Mansion.', 'https://media.retroachievements.org/Images/117694.png', 'https://media.retroachievements.org/Images/070018.png', 'https://media.retroachievements.org/Images/004236.png', 'https://media.retroachievements.org/Images/004237.png', 4),
  (194, 3363, 'Picross NP Vol. 2', 'SNES/Super Famicom', 3, 1115, 1115, 1115, 27, 0, 'Nonogram', 'Jupiter', 'Nintendo', '1999-06-01', 'The Super Nintendo Entertainment System has a library of 1,749 official releases, of which 717 were released in North America plus 4 championship cartridges, 532 in Europe, 1,440 in Japan, 231 on Satellaview, and 13 on SuFami Turbo. 296 releases are common to all regions, 147 were released in Japan and the US only, 165 in Europe and the US, and 27 in Japan and Europe. There are 977 Japanese exclusives, 111 US exclusives, and 35 European exclusives. The Super NES was released in North America on August 23, 1991, with its launch titles being Super Mario World, F-Zero, Pilotwings, Gradius III, and SimCity. Despite the console''s relatively late start, and the fierce competition it faced in North America and Europe from Sega''s Genesis/Mega Drive console, it was the best-selling console of its era.', 'https://media.retroachievements.org/Images/024812.png', 'https://media.retroachievements.org/Images/024929.png', 'https://media.retroachievements.org/Images/008203.png', 'https://media.retroachievements.org/Images/008211.png', 4),
  (195, 3166, 'Krusty''s Super Fun House', 'SNES/Super Famicom', 3, 1113, 1113, 1113, 82, 0, NULL, 'Audiogenic', 'Acclaim', '1992-06-01', 'Krusty''s Fun House, also known as Krusty''s Super Fun House is a 1992 puzzle video game based on the animated sitcom The Simpsons. It was developed by Audiogenic and published by Acclaim Entertainment for the Nintendo Entertainment System (NES), Super Nintendo Entertainment System (SNES), Sega Genesis, Master System, Game Gear, and Game Boy; versions for the Amiga and MS-DOS computers were released by Virgin Games. In the game, players control Krusty the Clown as they attempt to exterminate all rats in the various levels, using objects to create a path for the rats towards the machine.', 'https://media.retroachievements.org/Images/064561.png', 'https://media.retroachievements.org/Images/057349.png', 'https://media.retroachievements.org/Images/008794.png', 'https://media.retroachievements.org/Images/008835.png', 4),
  (196, 1197, 'Super Adventure Island II', 'SNES/Super Famicom', 3, 1106, 1106, 1106, 49, 0, '2D Platforming', 'Make Software', 'Hudson Soft', '1995-01-03', 'Super Adventure Island II  is a platform video game released by Hudson Soft for the Super NES in 1994 in North America, with subsequent releases in Japan and Europe following in 1995. Unlike most of the previous games, it is a platformer with action-adventure elements that encourages exploration, similar to the later Wonder Boy games.', 'https://media.retroachievements.org/Images/028586.png', 'https://media.retroachievements.org/Images/007909.png', 'https://media.retroachievements.org/Images/008353.png', 'https://media.retroachievements.org/Images/008354.png', 4),
  (197, 911, 'Firepower 2000', 'SNES/Super Famicom', 3, 1102, 1102, 1102, 34, 0, 'Shoot ''em Up', 'SCi Games | Sales Curve Interactive', 'Sunsoft', '1992-01-01', 'Super SWIV is a top-down shoot ''em up released for the Super Nintendo Entertainment System in 1992. It was released as Mega SWIV on the Mega Drive in 1995. It is the sequel to the 1991 game SWIV. It was followed by SWIV 3D in 1996.', 'https://media.retroachievements.org/Images/063158.png', 'https://media.retroachievements.org/Images/005136.png', 'https://media.retroachievements.org/Images/005133.png', 'https://media.retroachievements.org/Images/005134.png', 4),
  (198, 8249, '~Hack~ Donkey Kong Country: Competition Edition [10 Minutes]', 'SNES/Super Famicom', 3, 1097, 1097, 1097, 38, 0, '2D Platforming', 'Hack', 'Hack - Donkey Kong Country', '1994-11-21', 'Donkey Kong is a video game series and media franchise created by the Japanese game designer Shigeru Miyamoto for Nintendo. It follows the adventures of Donkey Kong, a large, powerful gorilla, and other members of the Kong family of apes. Donkey Kong games include the original arcade game trilogy by Nintendo R&D1; the Donkey Kong Country series by Rare and Retro Studios; and the Mario vs. Donkey Kong series by Nintendo Software Technology. Various studios have developed spin-offs in genres such as edutainment, puzzle, racing, and rhythm. The franchise also incorporates animation, printed media, theme parks, and merchandise.', 'https://media.retroachievements.org/Images/116327.png', 'https://media.retroachievements.org/Images/060828.png', 'https://media.retroachievements.org/Images/024442.png', 'https://media.retroachievements.org/Images/009063.png', 4),
  (199, 1287, 'The Twisted Tales of Spike McFang', 'SNES/Super Famicom', 3, 1082, 1082, 1082, 46, 0, 'Action RPG', 'Red Company', 'Naxat Soft', '1994-06-01', 'The Twisted Tales of Spike McFang  is an action role-playing video game developed by Red Company for the Super Nintendo Entertainment System. It was released by Naxat Soft in Japan and by Bullet-Proof Software in North America. The game is the sequel to the TurboGrafx-16 game Makai Prince Dorabotchan, which was only released in Japan. The characters also appeared in the Japanese Super Naxat Open golf game for Super Famicom.', 'https://media.retroachievements.org/Images/026971.png', 'https://media.retroachievements.org/Images/005144.png', 'https://media.retroachievements.org/Images/005145.png', 'https://media.retroachievements.org/Images/005146.png', 4),
  (200, 3206, 'Magic Knight Rayearth', 'SNES/Super Famicom', 3, 1072, 1072, 1072, 17, 0, 'Turn-Based RPG', 'Pandora Box', 'Tomy', '1995-09-29', 'Magic Knight Rayearth  is a Japanese manga series written and illustrated by Clamp. Appearing as a serial in the manga magazine Nakayoshi from the November 1993 issue to the February 1995 issue, the chapters of Magic Knight Rayearth were collected into three bound volumes by Kodansha. They were published from July 1994 to March 1995. A sequel was serialized in the same manga magazine from the March 1995 issue to the April 1996 issue. It was published by Kodansha in three bound volumes from July 1995 to April 1996.', 'https://media.retroachievements.org/Images/112420.png', 'https://media.retroachievements.org/Images/112634.png', 'https://media.retroachievements.org/Images/053431.png', 'https://media.retroachievements.org/Images/053430.png', 4);
